/* AUTO-GENERATED by content-engine/import.cjs — subject:general — do not edit by hand.
   Replaces 457 upgraded questions in place, appends 24 new ones, fills en/ru/tr/es/hi.
   Idempotent: re-run import.cjs to regenerate. Safe to remove (just delete this file + its <script> tag). */
(function(){
  if(!window.CDL_DATA||!window.I18N){ return; }
  var SUBJ="general";
  var D=window.CDL_DATA, I=window.I18N;
  var cat=D.categories.filter(function(c){return c.id===SUBJ;})[0]; if(!cat) return;
  I.q=I.q||{}; ["ru","tr","es","hi"].forEach(function(L){ I.q[L]=I.q[L]||{}; I.q[L][SUBJ]=I.q[L][SUBJ]||{}; });
  var REPL={"0":{"q":"During your pre-trip inspection, you measure tread depth and find one of your steering-axle (front) tires has worn down to 3/32 inch, while your drive and trailer tires are all at 3/32 inch as well. Which statement correctly identifies whether your vehicle is legal to drive?","options":["The vehicle is NOT legal to drive, because steering-axle tires must have at least 4/32 inch of tread.","The vehicle is legal to drive, because all tires meet the 2/32 inch minimum for every tire.","The vehicle is legal to drive, because the front tires only need 2/32 inch and the rest are fine.","The vehicle is NOT legal to drive, because all tires on every axle must have at least 4/32 inch of tread."],"answer":0,"explanation":"Steering-axle tires must have at least 4/32 inch of tread, so a front tire at 3/32 inch is below the minimum and makes the vehicle illegal to drive.","handbook":"Steering axle tires must have at least 4/32 inch tread depth.","hbref":"§2.1 Inspection","qid":"GK-W3-001"},"1":{"q":"During your pre-trip inspection you run a tread-depth gauge across all your tires. The steering-axle tires measure a healthy 5/32 inch, but one of your rear drive tires is worn down to a noticeably thinner reading. What is the LEAST tread depth that rear (non-steering) tire can legally have and still pass inspection?","options":["1/32 inch","2/32 inch","4/32 inch","6/32 inch"],"answer":1,"explanation":"All tires except the front steering axle must have at least 2/32 inch of tread depth measured in a major groove.","handbook":"Tires other than the front must have at least 2/32 inch tread depth.","hbref":"§2.1 Inspection","qid":"GK-W2-017"},"2":{"q":"During your pre-trip inspection you grip the steering wheel and rock it back and forth before starting the engine. On your 20-inch diameter wheel, you can turn the rim a couple of inches in each direction before the front wheels begin to respond. At what point should this free play make you suspect a steering-system problem and pull the vehicle from service?","options":["When the wheel can be turned more than about 10 degrees (roughly 2 inches on a 20-inch wheel) before the front wheels move","Only when the wheel can be turned more than about 20 degrees before the front wheels move","When the wheel can be turned more than about 5 degrees, since any detectable play is unsafe","Only when free play exceeds about 45 degrees, since that is when steering becomes truly hard to control"],"answer":0,"explanation":"More than about 10 degrees of steering-wheel free play (roughly 2 inches on a 20-inch wheel) before the front wheels move is too much and signals a steering problem.","handbook":"More than 10 degrees of steering play may make it hard to steer.","hbref":"§2.1 Inspection","qid":"GK-W2-012"},"3":{"q":"Your tractor-trailer has stalled on the shoulder of a two-lane undivided highway and won't restart. You switch on your hazard flashers and reach for your emergency warning kit so you can set out reflective triangles at 100 ft behind, 100 ft ahead, and 10 ft to the rear of the vehicle. To be legally equipped to place warning devices in EVERY required position like this, what is the MINIMUM number of reflective triangles your truck must carry?","options":["Two triangles, since one is placed ahead and one behind the vehicle","Three triangles","One triangle placed 10 ft to the rear, plus your hazard flashers","Six triangles, to be sure you can cover both directions of traffic"],"answer":1,"explanation":"A commercial vehicle must carry at least three reflective warning triangles as emergency warning devices.","handbook":"Carry three red reflective triangles as warning devices.","hbref":"§2.1 Inspection","qid":"GK-W2-013"},"4":{"q":"It is the middle of your shift and a fitting on your diesel line has been weeping fuel near the engine wiring. Suddenly a small fire erupts there, fed by the leaking diesel and crackling around the live electrical harness. You reach for the extinguisher mounted in your cab. Which rating on that extinguisher tells you it is designed to fight BOTH this burning fuel and the energized electrical fire?","options":["A B:C extinguisher, rated for burning liquids and electrical fires","A Class A extinguisher, since it is the standard rating carried on commercial vehicles","A Water-type extinguisher, to cool the diesel and knock the fire down fast","It does not matter which rating you grab, as long as you discharge it at the base of the flames"],"answer":0,"explanation":"A burning flammable liquid is a Class B fire and energized electrical equipment is Class C, so a B:C-rated extinguisher is required for both.","handbook":"A B:C fire extinguisher works on electrical fires and burning liquids.","hbref":"§2.20 Fires","qid":"GK-W2-060"},"5":{"q":"It is 5:00 a.m. and you are finishing the pre-trip inspection on a tractor-trailer you were just assigned. Your dispatcher is rushing you to leave, but you remember that federal rules require you to carry certain emergency equipment before any trip. You did NOT find a kit of spare electrical fuses anywhere in the cab. Under what condition is it legal for you to drive away WITHOUT carrying spare fuses?","options":["Only if the truck is equipped with circuit breakers instead of fuses","Only if you are carrying a fully charged spare battery in the cab","Only if the trailer is fitted with LED clearance and marker lights","Only if the tractor has a backup (second) alternator for the electrical system"],"answer":0,"explanation":"Spare fuses aren't required when the electrical system is protected by circuit breakers, since breakers reset instead of needing replacement.","handbook":"Carry spare fuses unless the vehicle has circuit breakers.","hbref":"§2.1 Inspection","qid":"GK-W2-018"},"6":{"q":"It is early morning and you walk up to your rig to begin your pre-trip inspection. Your trainer reminds you to follow the seven-step inspection method in order. Before you climb into the cab, open the hood, or touch a single switch, what is the FIRST thing the seven-step method requires you to do?","options":["Start the engine and let it warm up while you watch the oil pressure and air gauges","Walk to the front and check that the headlights, turn signals, and four-way flashers all work","Do a general overview of the vehicle, reviewing the previous inspection report and looking over its overall condition and surroundings","Get under the front of the vehicle and confirm the steering-axle tires have at least 4/32 inch of tread"],"answer":2,"explanation":"Step one of the seven-step inspection is the vehicle overview: review the last inspection report and check the truck's overall condition and surroundings.","handbook":"The seven-step method begins with the vehicle overview.","hbref":"§2.1 Inspection","qid":"GK-W2-019"},"7":{"q":"It is a cold morning and you are about to begin your pre-trip inspection. Your truck's engine is shut OFF and the hood is raised. Which of the following is the group of items you can and should be inspecting RIGHT NOW, while the engine is not running?","options":["Steering-wheel free play and the operation of the low-air-pressure warning buzzer","Engine oil level, coolant level, and the condition of the drive belts","Air-compressor governor cut-in and cut-out pressures","Alternator output and the charging-system gauge under load"],"answer":1,"explanation":"With the engine off you open the hood to check engine oil level, coolant level, and the condition of the drive belts.","handbook":"Check engine oil, coolant, belts and hoses in the engine compartment.","hbref":"§2.1 Inspection","qid":"GK-W2-020"},"8":{"q":"It is just below freezing and a light glaze has formed on the on-ramp as you bring your loaded combination up to highway speed. You feel the tractor's drive wheels begin to spin and the rear of the cab twitch sideways. To get up to speed safely on this slick surface, what is the BEST way to handle the accelerator?","options":["Squeeze on power smoothly and gradually, easing off the instant the drive wheels start to spin","Press the throttle down hard so the spinning tires can grab and bite through the glaze","Pump the accelerator on and off rapidly to chop the power going to the drive wheels","Keep steady firm throttle and let the engine's power pull you through the slick patch"],"answer":0,"explanation":"On slippery surfaces apply power smoothly and gradually, easing off the moment the drive wheels begin to spin so they regain traction.","handbook":"Speed up smoothly so the drive wheels do not spin.","hbref":"§2.2 Basic Control","qid":"GK-W2-054"},"9":{"q":"You are alone and must back your tractor-trailer into a tight alley loading dock. You could approach the dock so that the rig backs toward your left (driver's) side, or so it backs toward your right side, which would be a slightly shorter maneuver. To stay as safe as possible, which approach should you choose, and why?","options":["Back toward the right side, because the shorter path means less time spent maneuvering blind","Back toward the right side, but lean out the passenger window and use a spotter to cover the blind area","Either side is equally safe, so pick the right side since it is the quicker maneuver","Back toward the driver's (left) side, even if longer, because you can watch the rear of the trailer through your side window instead of relying only on mirrors"],"answer":3,"explanation":"Back toward the driver's (left) side whenever possible so you can watch the rear of the trailer directly through your side window instead of relying only on mirrors.","handbook":"Back toward the driver's side so you can see, and use a helper.","hbref":"§2.2 Basic Control","qid":"GK-W2-055"},"10":{"q":"You are hauling a loaded trailer and approaching a long, steep downgrade that ends in a sharp curve at the bottom. Your transmission is currently in a high gear. When is the correct time to select the lower gear you will use to control your speed on this grade and through the curve?","options":["Before you start down the grade and before the curve, while you are still on level ground","Right as you enter the curve, so the engine is at its peak braking power exactly where you need it most","Partway down the grade once you feel the truck beginning to gain speed and your brakes start to fade","Only after you exit the curve, so the drive wheels keep full traction through the turn"],"answer":0,"explanation":"Select the proper gear before starting down a grade or entering a curve, while still on level ground, because shifting may not be possible once descending.","handbook":"Select the gear before starting down a hill or entering a curve.","hbref":"§2.3 Shifting","qid":"GK-W2-050"},"11":{"q":"You are driving on a dry highway at 55 mph when a tire blows out on a car far ahead and it suddenly stops in your lane. From the instant the hazard appears until your truck comes to a complete halt, your rig will have traveled roughly the length of a football field including both end zones (about 419 feet). Which set of factors fully accounts for that entire 419-foot total stopping distance?","options":["The distance your brakes physically slow the truck after the air brakes grab, plus the lag while air pressure builds in the system","The distance you cover while seeing and recognizing the hazard, plus the distance while moving your foot to the pedal, plus the distance the brakes take to stop you","The distance while you react and move to the pedal, plus the distance the brakes take to stop you","Only the distance the brakes need to bring the truck to a stop once they are applied"],"answer":1,"explanation":"Total stopping distance is perception distance plus reaction distance plus braking distance — seeing the hazard, moving your foot to the pedal, and the brakes stopping the rig.","handbook":"Total stopping distance equals perception plus reaction plus braking.","hbref":"§2.6 Speed","qid":"GK-W2-004"},"12":{"q":"You are running empty on a dry, level interstate at a steady 55 mph in good weather. The driver ahead suddenly stops, and you have to make a full emergency stop. From the moment a hazard first appears to the moment your truck is fully stopped, about how much total roadway distance will it take you to stop?","options":["About 60 ft, since that is the distance you cover before you can react","About 220 ft, roughly the length of the braking phase alone","About 320 ft, a little more than a single American football field","About 420 ft, roughly the length of an American football field plus both end zones"],"answer":3,"explanation":"At 55 mph in good conditions, total stopping distance is about 420 feet, roughly the length of a football field plus both end zones.","handbook":"At 55 mph a vehicle travels about 419 feet to stop.","hbref":"§2.6 Speed","qid":"GK-W2-005"},"13":{"q":"You normally drive a stretch of dry, level highway at 20 mph and you know your rig needs a certain braking distance to stop from that speed. Tonight, running late, you take that same road at 40 mph in the same good conditions. Compared with your braking distance at 20 mph, your braking distance at 40 mph will be about:","options":["2 times as long, because braking distance increases in direct proportion to speed","3 times as long, since you must add extra distance for reaction time as well","4 times as long, because braking distance grows with the square of your speed","Roughly the same, as long as the road is dry and level and the brakes are good"],"answer":2,"explanation":"Braking distance grows with the square of speed, so doubling your speed from 20 to 40 mph makes the braking distance about four times as long.","handbook":"Doubling speed about quadruples the braking distance.","hbref":"§2.6 Speed","qid":"GK-W2-006"},"14":{"q":"A steady rain has soaked the highway and you can see a thin film of water on the pavement, though it is well above freezing and there is no snow or ice. To keep a safe margin for the longer stopping distance these wet conditions create, about how much should you cut your speed below what you would drive on the same road when it is dry?","options":["By about one-tenth","By about one-third","By about one-half","By about three-quarters"],"answer":1,"explanation":"On wet roads, reduce your speed by about one-third compared to your safe dry-road speed to make up for lost traction and longer braking distance.","handbook":"Reduce speed by about one-third on a wet road.","hbref":"§2.6 Speed","qid":"GK-W2-007"},"15":{"q":"You just delivered your full load and your trailer is now completely empty. The road is dry and you are running at the same highway speed you drove all morning when fully loaded. Compared to when you were loaded, how should you adjust your expectation of how this empty rig will brake and handle?","options":["It will stop in a shorter distance because there is far less weight for the brakes to slow down","It will need a longer distance to stop because the light rear axles have less traction and the wheels can lock up and skid","Its stopping distance will be essentially the same, since braking distance depends on speed and not on the load","It cannot skid now because an empty trailer keeps the drive wheels from ever locking up"],"answer":1,"explanation":"An empty truck needs a longer stopping distance because the light rear axles have less traction, so the wheels lock up and skid more easily.","handbook":"An empty truck may require a greater stopping distance.","hbref":"§2.6 Speed","qid":"GK-W2-008"},"16":{"q":"You are running about 50 mph on an interstate when a heavy downpour starts. Your steering suddenly feels light and loose, the truck stops responding to small wheel inputs, and you realize the front tires have lifted onto a film of water and are no longer gripping the pavement. Which action gives you the best chance to regain control?","options":["Press firmly on the brake pedal to scrub off speed as quickly as possible","Ease off the accelerator (and push in the clutch) and let the vehicle slow on its own without braking hard","Steer sharply toward the shoulder so the tires bite into rougher pavement and regain traction","Maintain or add throttle to keep the drive wheels turning and 'power through' the water"],"answer":1,"explanation":"If you start to hydroplane, ease off the accelerator and push in the clutch without braking hard so the tires can slow and regain contact with the road.","handbook":"If your vehicle hydroplanes, release the accelerator.","hbref":"§2.6 Speed","qid":"GK-W3-002"},"17":{"q":"You are hauling a fully loaded trailer down a long, steep mountain grade. You selected a low gear at the top and have been riding the brakes lightly but almost continuously the whole way down. Partway down, you notice the brake pedal feels softer and the truck is no longer slowing the way it did at the top of the grade. What is the MOST likely cause of this loss of braking?","options":["The brake shoes and drums have overheated from being used too much instead of relying on engine and gear braking","The air pressure in the brake lines has dropped too low because the compressor cannot keep up on a downgrade","Cold mountain air at higher elevation has thickened the brake fluid and reduced pedal response","The trailer tires are under-inflated, reducing the contact patch and the braking force at each wheel"],"answer":0,"explanation":"Riding the brakes continuously down a long grade overheats the shoes and drums, causing brake fade; let engine and gear braking hold your speed instead.","handbook":"Brakes can fade from excessive heat caused by overuse.","hbref":"§2.15 Mountain","qid":"GK-W2-067"},"18":{"q":"You are driving a loaded tractor-trailer on a dry highway and approach a downhill exit ramp with a posted curve speed limit of 35 mph. The pavement is in good shape and traffic is light. Which statement best describes how you should treat that posted 35 mph figure?","options":["It is the safe speed for any vehicle in good conditions, so 35 mph is fine in your loaded rig","It is set for cars in good conditions, so you should enter the curve at a speed well below 35 mph","It applies only to empty trucks, so a loaded truck may legally exceed it","It already includes a safety margin for trucks, so holding exactly 35 mph is the safest choice"],"answer":1,"explanation":"Posted curve speeds are set for cars in good conditions, so a truck with its higher center of gravity must enter well below the posted speed.","handbook":"Take curves well below the posted speed limit.","hbref":"§2.6 Speed","qid":"GK-W2-009"},"19":{"q":"You are driving a 60-foot tractor-trailer on a dry highway, and your speedometer reads a steady 55 mph in light traffic. You want to set a safe following distance behind the car ahead of you. Based on your vehicle's length and your current speed, what is the minimum following distance you should keep?","options":["6 seconds, because a 60-foot vehicle needs 1 second for every 10 feet at any speed","A flat 4 seconds, the same as any heavy vehicle regardless of length","7 seconds, because a 60-foot vehicle needs 6 seconds plus 1 more for driving over 40 mph","About three car lengths, which is roughly enough cushion for a tractor-trailer"],"answer":2,"explanation":"Allow 1 second of following distance per 10 feet of vehicle length, plus 1 extra second above 40 mph, so a 60-foot vehicle at 55 mph needs 7 seconds.","handbook":"Allow one second per 10 feet of length, plus one over 40 mph.","hbref":"§2.7 Space","qid":"GK-W3-003"},"20":{"q":"You are running 60 mph on a wide-open rural highway with light traffic. The road ahead climbs gently and you want to manage your space and spot problems early. To scan correctly, where should your eyes be focused MOST of the time while driving at this speed?","options":["On the pavement just past the front of your hood, so you catch obstacles in the road immediately","About 4 to 6 seconds ahead, the same distance you would use to set a safe following gap","About 12 to 15 seconds ahead, roughly a quarter mile at highway speed","About 30 seconds ahead, as far down the road as your eyes can possibly reach"],"answer":2,"explanation":"Good drivers look 12 to 15 seconds ahead, which is about a quarter mile at highway speed.","handbook":"Look 12 to 15 seconds ahead of your vehicle.","hbref":"§2.4 Seeing","qid":"GK-W2-024"},"21":{"q":"You are approaching a right turn into a narrow alley on a congested city street. Traffic is heavy, a cyclist is in the bike lane on your right, and several drivers are stacked up close behind you. Regarding your turn signal, which action is the single best practice?","options":["Wait until you actually begin swinging the wheel to signal, so following drivers don't slow down too early and cause a backup","Signal only briefly, because in heavy traffic the drivers around you can already see your brake lights doing the communicating for you","Turn on your signal well before the turn and keep it flashing continuously through the entire maneuver","Skip the electric signal and use a hand signal instead, since it is more visible to the cyclist beside you"],"answer":2,"explanation":"Signal well before a turn and keep it flashing through the entire maneuver so others have maximum time to react and don't assume you've changed your mind.","handbook":"Signal early and continuously until the turn is finished.","hbref":"§2.5 Communicating","qid":"GK-W2-065"},"23":{"q":"You are driving a 70-foot tractor-trailer and need to make a right turn onto a narrow side street. Traffic is light, and you are worried about your trailer's rear wheels climbing the curb. To complete this turn safely and legally, which of the following should you NOT do?","options":["Drift left into the adjacent lane before turning so the trailer has more room to swing through","Begin the turn slowly and keep watching your mirrors to track the trailer's path","Keep the rear of the vehicle close to the curb so other drivers cannot squeeze past on your right","Swing wide only as you complete the turn, after the cab has cleared the corner"],"answer":0,"explanation":"Drifting left before a right turn opens a gap that invites vehicles to pass on your right, putting them in the path of your swinging trailer.","handbook":"Do not swing wide to the left as you start a right turn.","hbref":"§2.7 Space","qid":"GK-W2-038"},"24":{"q":"You are hauling an empty dry van and your route shows an overpass posted with a clearance of 13 feet 6 inches. Your trailer's listed height is 13 feet 4 inches, giving you a 2-inch margin. Earlier this winter the road crew repaved this stretch, and last night there was a light snow that has been packed down on the roadway. What is the most defensible way to treat that posted clearance sign before you commit to driving under the overpass?","options":["The sign is officially posted, so the 13 ft 6 in figure is exact and a 2-inch margin is legally sufficient to proceed.","Because clearance signs apply to loaded vehicles, an empty van sits lower than its listed height, so you have extra room and can proceed.","Treat the posted height as unreliable: repaving and packed snow can reduce real clearance, and your empty van actually rides higher, so find another route or verify before proceeding.","Add your 2-inch margin to the posted 13 ft 6 in, giving roughly 13 ft 8 in of usable clearance, which is plenty for your trailer."],"answer":2,"explanation":"Posted clearance signs can be wrong because repaving and packed snow reduce real clearance and an empty van rides higher, so verify or reroute before proceeding.","handbook":"Do not assume posted bridge heights are correct.","hbref":"§2.7 Space","qid":"GK-W2-039"},"25":{"q":"You are merging onto a busy freeway and glance at the large convex (curved) mirror mounted on your right door. A car you can see in that convex mirror appears small and far back, so you feel you have plenty of room to change lanes. Before you commit, what must you understand about what this convex mirror is telling you?","options":["It shows a wider area, but objects look smaller and farther away than they really are, so that car may be closer than it appears","It magnifies a narrow close-up, so the car is actually farther away than it looks and you have extra room","It shows the same true-size, true-distance image as a flat mirror, so the gap you see is accurate","It only reflects the side of your own cab and trailer, so any vehicle in it is not yet a hazard"],"answer":0,"explanation":"Convex mirrors show a wider area but make objects look smaller and farther away, so a vehicle may be closer than it appears.","handbook":"Convex mirrors show a wider area but objects appear farther away.","hbref":"§2.4 Seeing","qid":"GK-W2-025"},"26":{"q":"You are driving on a clear, dry highway when you notice a car parked on the right shoulder ahead with its hood up and a person standing near the rear bumper looking toward traffic. There is no crash, no bad weather, and traffic is flowing normally. For the purpose of seeing hazards, how should you classify this parked car and person?","options":["A hazard, because it is any road condition or road user that could become an emergency and require you to act","Not a hazard, because there is no crash or emergency happening yet and the roadway itself is clear","Not a hazard, because hazards only exist in bad weather, fog, ice, or other poor driving conditions","A hazard only if the parked car suddenly pulls back into your lane and forces you to brake hard"],"answer":0,"explanation":"A hazard is any road condition or road user that could become an emergency, recognized early so you have time to react.","handbook":"A hazard is any road condition or user that is a possible danger.","hbref":"§2.8 Hazards","qid":"GK-W2-046"},"27":{"q":"You are cruising in the right lane on a four-lane highway when a car races up behind you, tailgates within inches of your trailer, then swerves around, cuts in front of you, and brakes hard. Your CMV is fully loaded and your stopping distance is already long. Of the following, which is the BEST way to handle this aggressive driver?","options":["Flash your high beams and sound your horn to signal the driver to back off, then hold your lane position","Move into the left lane and pass the driver to put the conflict behind you","Maintain your speed and stay close behind so the driver cannot cut in on you again","Ease off the accelerator to open up space ahead, avoid eye contact, and let the aggressive driver get well in front of you"],"answer":3,"explanation":"The safe response to an aggressive driver is to ease off the accelerator to create space, avoid eye contact, and let them get well ahead of you.","handbook":"Stay out of an aggressive driver's way and do not challenge them.","hbref":"§2.9 Aggressive","qid":"GK-W2-070"},"29":{"q":"It is a dark, moonless night on a rural two-lane highway and you are running your low beams, which light the road about 250 feet ahead. There is no oncoming traffic. To avoid 'overdriving your headlights,' what is the single most important thing you must do?","options":["Switch to high beams and hold a steady 55 mph, since high beams reach about 350 feet and that is enough room to react","Close up on the taillights of a vehicle ahead and use its lights to extend how far down the road you can see","Keep your normal daytime speed because your headlights clearly illuminate the lane markings and the road ahead","Drive slowly enough that you can come to a complete stop within the distance your headlights actually light up"],"answer":3,"explanation":"Never overdrive your headlights: drive slowly enough to stop completely within the distance your headlights actually illuminate.","handbook":"Do not overdrive your headlights; stop within the distance you can see.","hbref":"§2.10 Night","qid":"GK-W3-004"},"30":{"q":"It is just after dark on a two-lane undivided highway and a line of oncoming vehicles is approaching with their headlights on. One driver fails to dim their high beams, and the glare is making it hard for you to see the road ahead. To keep your eyes adjusted and stay safely in your lane until the vehicles pass, where should you direct your gaze?","options":["Toward the right edge of your lane, using the painted line or road markings as a guide until the vehicles pass","Straight ahead at the oncoming headlights so you can judge the gap between you and the other vehicles","Down at the dashboard instruments to rest your eyes from the bright glare","Far down at the road well beyond the oncoming traffic to keep your speed within your headlight range"],"answer":0,"explanation":"When blinded by oncoming high beams, look toward the right edge of your lane and follow the painted line so your eyes stay adjusted to the dark.","handbook":"Do not look at oncoming headlights; look to the right edge of your lane.","hbref":"§2.10 Night","qid":"GK-W3-005"},"31":{"q":"You are running a delivery before dawn when a thick bank of fog rolls in and visibility drops to less than the length of your tractor-trailer. You decide it is safest to keep moving slowly to the next exit rather than stop on the travel lane. To see the road and be seen WITHOUT blinding yourself, which lighting and speed choice is the single best practice?","options":["Switch on your high beams for maximum reach and hold your speed so you do not block traffic","Use your low beams (and fog lights if equipped) and reduce your speed so you can stop within the distance you can see","Turn off your headlights and run only the four-way hazard flashers to mark your position","Keep high beams on but slow down, since the extra light matters more than the glare in fog"],"answer":1,"explanation":"In fog, use low beams (and fog lights if equipped) and slow down enough to stop within the distance you can see, since high beams reflect back and reduce visibility.","handbook":"Use low beams in fog and slow down.","hbref":"§2.11 Fog","qid":"GK-W2-031"},"32":{"q":"It is a clear morning about 31°F, and the open roadway ahead looks completely dry. You are hauling a loaded trailer toward a long bridge that spans a river valley, with a shaded overpass just beyond it. Where should you expect to lose traction FIRST and adjust your speed before you reach it?","options":["On the dry open road, because tractor weight presses the tires down and warms the pavement","On the bridge and the shaded overpass, because air circulates above and below the deck so it cools and freezes before the surrounding road","Nowhere yet, since the pavement looks dry it cannot be icy until the air temperature drops below freezing","Only after the overpass, where road salt and sun have already melted any ice on the elevated structures"],"answer":1,"explanation":"Bridges and overpasses are exposed to cold air above and below the deck, so they lose heat from all sides and freeze before the surrounding road.","handbook":"Bridges freeze before roads in cold weather.","hbref":"§2.12 Winter","qid":"GK-W3-006"},"33":{"q":"It is just below freezing on an early morning run. The pavement ahead looks dark and wet, but you notice the tires of the truck in front of you are throwing up no spray at all, and your mirrors and antenna have a thin glaze on them. What is the road surface MOST likely doing, and how should you respond?","options":["The pavement is simply wet from melted frost; maintain your speed since standing water provides normal traction.","The road is merely drying out; a quick stab of the brakes will confirm grip is fine and let you keep your following distance.","A thin, clear layer of black ice has formed; ease off the accelerator and avoid any sudden steering or braking.","It is fresh asphalt sealant making the surface look wet; tread lightly but normal speed is acceptable."],"answer":2,"explanation":"A wet-looking road with no tire spray near freezing signals black ice, so ease off the accelerator and avoid sudden steering or braking.","handbook":"If it is cold and the road looks wet with no spray, suspect black ice.","hbref":"§2.12 Winter","qid":"GK-W3-007"},"34":{"q":"It is mid-July in West Texas, with the outside temperature near 105 degrees and the asphalt visibly bleeding tar. You stopped two hours ago and your tires were running fine, but you have just merged onto a long stretch of interstate at highway speed. Which condition should you be MOST alert to monitoring during this run?","options":["Rising tire pressure that can lead to a blow-out as the heat builds","The horn becoming muffled by dust and heat","Falling tire pressure from cold air leaking out of the valves","Window tint darkening and reducing your forward visibility"],"answer":0,"explanation":"In extreme heat the air inside a tire expands and pressure rises, which combined with the heat can cause a blow-out.","handbook":"Heat raises tire pressure; check it in hot weather.","hbref":"§2.13 Hot Weather","qid":"GK-W2-056"},"35":{"q":"You are loaded near your GCWR and about to descend a long, steep mountain grade. Conditions are dry and clear. As you reach the crest, you start thinking about how you will keep your speed under control all the way down. Which approach is the BEST way to manage your speed on this downgrade?","options":["Stay in a high gear so the engine runs smoothly, and hold the service brakes down steadily the whole way to keep speed pinned at a safe level.","Shift into neutral and coast, applying the service brakes firmly each time your speed creeps up so the brakes stay cool between applications.","Keep the transmission in a normal road gear and rely on the parking (hand) brake to hold your speed back as you descend.","Select a low gear before you start down so engine and gear braking do most of the work, using only light, steady service braking to supplement it."],"answer":3,"explanation":"On a long, steep downgrade choose a low gear before starting down so engine and gear braking do most of the work, using only light, steady service braking.","handbook":"Use a low gear and engine braking as the main control on a downgrade.","hbref":"§2.15 Mountain","qid":"GK-W3-008"},"36":{"q":"You are hauling a loaded trailer down a long, steep mountain grade. You selected a low gear at the top and have been using light, steady brake applications, but the brake pedal is slowly going soft, your speed keeps creeping up, and you can smell burning. Ahead on the right you see a gravel escape ramp. Which of the following describes when you should steer onto that ramp?","options":["When your brakes have faded or failed and you can no longer control your speed on the grade","When you are only a few miles per hour over the posted truck speed for the grade","When traffic on the downgrade has become heavy and you want more room","When you want a short break to let the engine and brakes cool before continuing"],"answer":0,"explanation":"Use an escape ramp only when your brakes have faded or failed and you can no longer control your speed on the grade.","handbook":"Use an escape ramp if your brakes fail on a downgrade.","hbref":"§2.15 Mountain","qid":"GK-W3-009"},"37":{"q":"You are running empty on a hot summer afternoon at highway speed when you hear a loud bang and the steering suddenly pulls hard to the right -- a front tire has blown out. Your empty trailer-less rig is now harder to control. What is your FIRST correct action?","options":["Hold the steering wheel firmly, stay off the brake, and let the vehicle slow on its own before easing off the road","Brake firmly and steadily to scrub off speed before the truck can pull off the road","Steer sharply away from the pull to keep the truck centered in your lane","Push in the clutch and shift to a lower gear to use engine braking to slow down"],"answer":0,"explanation":"After a front-tire blowout, hold the wheel firmly and stay off the brake, letting the vehicle slow on its own before easing off the road.","handbook":"On a blowout, hold the wheel firmly and stay off the brake.","hbref":"§2.16 Emergencies","qid":"GK-W2-058"},"38":{"q":"You are descending a moderate grade in a straight truck with hydraulic brakes when you press the brake pedal and it sinks slowly toward the floor with almost no stopping power. Traffic is light and there is a runaway-truck escape ramp about a mile ahead. What should you try FIRST to slow the vehicle?","options":["Shut off the engine immediately so the drivetrain helps drag the truck to a stop","Apply the parking brake hard in one firm motion to lock the wheels","Pull the trailer air-supply (tractor protection) knob to set the trailer brakes","Rapidly pump the brake pedal to try to build up hydraulic pressure"],"answer":3,"explanation":"When the hydraulic brake pedal fades to the floor, rapidly pump it first to rebuild enough pressure to slow or stop the vehicle.","handbook":"Pumping the brake pedal can sometimes build enough pressure to stop.","hbref":"§2.16 Emergencies","qid":"GK-W2-059"},"39":{"q":"You are accelerating out of a curve on a wet two-lane highway when the rear of your tractor suddenly begins to slide out toward the shoulder and the drive wheels feel like they have lost their grip. Of the following, what is the BEST way to regain control of this drive-wheel skid?","options":["Press the brake pedal firmly and hold it to slow the rear of the vehicle back into line","Stop accelerating, push in the clutch, and steer in the direction you want the vehicle to go","Keep steady throttle and counter-steer hard so engine power pulls the drive wheels straight","Lock the wheels with the brakes to stop the slide as quickly as possible"],"answer":1,"explanation":"To correct a drive-wheel acceleration skid, stop accelerating, push in the clutch to cut engine power, and steer in the direction you want to go.","handbook":"To correct a drive-wheel skid, stop accelerating and steer.","hbref":"§2.18 Skids","qid":"GK-W3-010"},"40":{"q":"You are descending a long, curving mountain grade with a loaded trailer when the road surface ahead looks wet and shaded. You begin a turn, but the front of your truck keeps pushing straight ahead toward the outside of the curve and the steering feels light and unresponsive no matter how far you turn the wheel. Of the following, what is the MOST likely root cause of this front-wheel skid?","options":["You released the brakes too gently entering the curve, so the front tires never gripped the pavement","Too much of the load shifted to the rear axles, lifting weight off the steering axle","You are driving too fast for the slick, shaded conditions (and/or your front tires are worn or under-inflated)","Engine braking in a low gear locked the drive wheels and threw the front end off line"],"answer":2,"explanation":"A front-wheel skid is caused by driving too fast for conditions, along with worn or under-inflated front tires.","handbook":"Front-wheel skids are caused mostly by driving too fast for conditions.","hbref":"§2.18 Skids","qid":"GK-W3-011"},"41":{"q":"It is just below freezing and you are making a hard, emergency stop on a slick highway when a car cuts in front of you. Your tractor-trailer is equipped with anti-lock brakes (ABS), and you press the brake pedal firmly all the way down. In this situation, what is the MAIN benefit the ABS provides?","options":["It keeps the wheels from locking up so you can continue to steer around the hazard","It guarantees a noticeably shorter stopping distance than the same truck without ABS","It automatically steers the truck away from the car that cut in front of you","It lets you safely follow more closely because stopping is now quicker"],"answer":0,"explanation":"ABS keeps the wheels from locking up during hard braking so you can still steer around a hazard.","handbook":"ABS helps you keep steering control when braking hard.","hbref":"§2.17 ABS","qid":"GK-W2-071"},"42":{"q":"You are first on the scene of a crash on a busy two-lane highway. A car has rolled and is blocking your lane; the driver is conscious but slumped against the door, and traffic is still approaching from behind the wreck at highway speed. You have stopped safely and turned on your hazard flashers. What should you do FIRST?","options":["Carefully pull the injured driver out of the car and lay them on the shoulder, in case the vehicle catches fire","Drive on to the next exit to find a phone and call 911, since you cannot help on your own","Get out and push the wrecked car off to the side so the lane clears and traffic can keep moving","Set out reflective warning triangles to warn approaching traffic before doing anything else at the scene"],"answer":3,"explanation":"At a crash scene the first priority is protecting it, so set out reflective warning triangles to warn approaching traffic before doing anything else.","handbook":"At a crash, first keep another accident from happening.","hbref":"§2.19 Accidents","qid":"GK-W3-012"},"43":{"q":"You pull onto the shoulder after seeing smoke rising from your engine compartment. You have set the parking brake and grabbed your B:C fire extinguisher. Which of the following is the LEAST appropriate action as you prepare to fight this engine fire?","options":["Shut off the engine as soon as you can","Aim the extinguisher at the base of the fire, not at the top of the flames","Keep the hood down as much as possible and discharge the extinguisher through gaps or louvers","Throw open the hood fully so you can aim the extinguisher straight at the flames"],"answer":3,"explanation":"Throwing the hood wide open feeds fresh oxygen to the fire and can make it flare up violently; keep the hood down and aim through openings instead.","handbook":"For an engine fire, do not open the hood if you can avoid it.","hbref":"§2.20 Fires","qid":"GK-W2-061"},"44":{"q":"At a wedding reception the night before a long haul, you drink steadily but stop several hours before bedtime. The next morning you feel completely sober, eat a big breakfast, drink two cups of coffee, and take a brisk walk in the cold air before your pre-trip. As you climb into the cab, which statement best reflects the law and the facts about whether you are safe to drive your CMV?","options":["None of those steps lowered your blood alcohol concentration; only the passage of time does that, and you may not operate the CMV with a BAC of 0.04% or higher.","Because you are operating a CMV, the legal limit is 0.08%, so you are clearly fine as long as you stayed below that.","The coffee, food, and cold air have sped up the elimination of alcohol, so your BAC is now effectively zero and the limit no longer matters.","Feeling sober is the legal standard for a CMV driver, so if you no longer feel impaired you are under the limit and safe to drive."],"answer":0,"explanation":"Only the passage of time lowers blood alcohol concentration, and you may not operate a CMV with a BAC of 0.04% or higher.","handbook":"It is illegal to operate a CMV at 0.04% BAC or more.","hbref":"§2.21 Alcohol","qid":"GK-W3-013"},"45":{"q":"You finished your shift hours ago and had several drinks at dinner. A dispatcher calls and asks you to deadhead a tractor back to the yard right now. You drank coffee, took a brisk walk in the cold night air, and feel clear-headed. Which statement best reflects what actually governs whether you are legally fit to drive?","options":["The coffee and cold air have raised your alertness enough that your blood alcohol concentration is now below the 0.04% CDL limit.","Because you feel clear-headed and no longer impaired, you are safe and legal to operate the tractor.","Only the passage of time lowers your blood alcohol concentration; nothing you have done speeds up how fast alcohol leaves your body.","Since this is an empty deadhead move with no cargo, the 0.04% BAC limit does not apply to this trip."],"answer":2,"explanation":"Only time lowers your blood alcohol concentration, because the liver removes alcohol at a fixed rate that coffee, fresh air, or a cold shower cannot speed up.","handbook":"Only time can make a person sober.","hbref":"§2.21 Alcohol","qid":"GK-W2-068"},"46":{"q":"You are starting your shift when a roadside inspector administers a breath test and your result reads 0.02% BAC -- detectable alcohol, but below the 0.04% CDL limit. You feel completely sober and there is no crash or other violation involved. Under federal CDL rules, what happens to you next?","options":["Nothing changes -- because you are under the 0.04% limit you are cleared to keep driving as normal","You are placed out of service for 24 hours, even though your reading is below the 0.04% disqualifying level","You are treated the same as a 0.04% reading and charged with a DUI offense","You receive a written warning and are released to continue your trip once you sign it"],"answer":1,"explanation":"Any detectable alcohol below 0.04% places a CDL driver out of service for 24 hours, even though it is under the disqualifying level.","handbook":"Any detectable alcohol under 0.04% means 24 hours out of service.","hbref":"§2.21 Alcohol","qid":"GK-W3-014"},"47":{"q":"You loaded and secured a flatbed at the shipper, completed your pre-trip, and pulled onto the highway. Your trip is 280 miles with no scheduled breaks. Knowing that cargo settles and tie-downs can loosen soon after you start rolling, by what point must you make your FIRST stop to inspect the load and re-tighten the securement?","options":["Within the first 50 miles","Within the first 150 miles","After the first 3 hours of driving","Within the first 100 miles"],"answer":0,"explanation":"You must inspect cargo and its securement devices within the first 50 miles, because tie-downs loosen as the load settles during those early miles.","handbook":"Inspect cargo within the first 50 miles of a trip.","hbref":"§3.1 Cargo","qid":"GK-W2-072"},"48":{"q":"During your pre-trip you are securing a single steel beam that is 18 feet long and weighs 4,200 pounds on a flatbed. You want to use the fewest tie-downs that still meets federal securement rules. Which statement correctly describes the MINIMUM number of tie-downs you must use?","options":["At least two tie-downs, because you need one for every 10 feet of cargo and an 18-foot piece requires two","One tie-down is enough because the beam is a single, balanced piece resting flat on the deck","At least three tie-downs, because any piece longer than 5 feet always requires three separate anchor points","No fixed number applies; you only need enough tie-downs to reach 50% of the cargo weight as working load limit"],"answer":0,"explanation":"Cargo needs at least one tie-down per 10 feet of length, and any article over 5 feet long needs at least two, so an 18-foot piece requires two tie-downs.","handbook":"Use at least one tie-down per 10 feet of cargo, minimum two.","hbref":"§3.2 Cargo","qid":"GK-W2-062"},"49":{"q":"You are loading a flatbed at the dock and the only space left for several heavy steel coils is the upper level of a two-tier rack, while the lighter packaging could go on the deck below. A coworker says it makes no difference where the heavy coils ride as long as the total weight stays under your GVWR. As you head out, the route includes a winding two-lane road with several sharp curves. Compared with putting the heavy coils low on the deck, what is the MOST important consequence of stacking that heavy weight up high?","options":["It has no real effect on handling because you are still legally within the vehicle's GVWR","It makes the truck easier to bring to a stop because more weight presses the tires down","It raises the center of gravity, making the truck much more likely to roll over in the curves","It improves stability and tracking through the curves because the load is centered over the frame"],"answer":2,"explanation":"Loading heavy cargo high raises the center of gravity, making the truck top-heavy and far more likely to roll over in curves.","handbook":"A high center of gravity makes a rollover more likely.","hbref":"§3.1 Cargo","qid":"GK-W3-015"},"50":{"q":"You're standing in a Texas DPS yard looking at a rig you want to be licensed to drive: a tractor pulling a loaded trailer. The combined rating on the paperwork (GCWR) reads 33,000 lb, and the trailer alone is rated at 14,000 lb. A buddy with a Class B tells you his license covers this 'because the whole thing is over 26,001 lb.' Which statement correctly identifies the license you actually need and why?","options":["A Class B is enough, since the combination's total rating is 26,001 lb or more.","A Class A, but only because the combination's total rating reaches 16,001 lb or more.","A Class B is enough, because the towed trailer is rated under 16,000 lb.","A Class A, because the combination is rated 26,001 lb or more AND the towed unit is rated over 10,000 lb."],"answer":3,"explanation":"A Class A CDL is required when the combination GCWR is 26,001 lb or more and the towed unit is rated over 10,000 lb.","handbook":"Class A: GCWR 26,001 pounds or more, towed unit over 10,000 pounds.","hbref":"§1 CDL Classes","qid":"GK-W3-016"},"51":{"q":"You show up for your CDL skills test planning to drive a tractor-trailer for a living, where every rig you will ever operate has full air brakes. To save money, a friend lets you borrow his older straight truck that is equipped only with hydraulic brakes, and you pass the entire skills test in it with no errors. Based on how that choice affects your license, which statement is correct?","options":["Because you took the skills test in a vehicle that does NOT have air brakes, your CDL will carry an air-brake restriction barring you from driving any CMV equipped with air brakes.","Because you passed the skills test cleanly with no errors, you will receive a full, unrestricted CDL valid for air-brake vehicles.","Because the truck you tested in had working hydraulic brakes, the examiner can simply waive the air-brake portion and issue an unrestricted license.","Because you only intend to drive air-brake tractor-trailers for work, you will be issued a license restricted to nighttime operation until you re-test."],"answer":0,"explanation":"Taking the skills test in a vehicle without air brakes results in an air-brake restriction that bars you from driving any CMV equipped with air brakes.","handbook":"An air-brake restriction is added if you do not test on air brakes.","hbref":"§1 Restrictions","qid":"GK-W3-017"},"52":{"q":"You are driving a charter bus with 40 passengers aboard and approach a railroad crossing on a rural highway. The crossing is marked only with a crossbuck sign, the gates are up, no lights are flashing, you can see clearly in both directions, and there is no train anywhere in sight. What are you required to do before crossing?","options":["Slow down, look and listen, and proceed without stopping because the gates are up and no signals are active","Come to a complete stop, look and listen, and then cross only when you can fully clear the tracks without stopping","Maintain your speed so the bus has enough momentum to clear all the tracks without stalling","Stop only if you are also carrying placarded hazardous materials in addition to the passengers"],"answer":1,"explanation":"Buses and placarded HazMat vehicles must stop, look, and listen at every railroad crossing and cross only when they can fully clear the tracks without stopping.","handbook":"Buses with passengers and placarded hazmat must stop at crossings.","hbref":"§2.14 Railroad","qid":"GK-W3-018"},"53":{"q":"You are hauling a fully loaded 53-foot tractor-trailer and approaching an uncontrolled single-track railroad crossing on a rural two-lane road. There are no lights or gates, and your view down the tracks is partly blocked by brush. You know you must never start across unless you can completely clear the tracks without stopping. About how much time should you assume a rig like yours needs to fully clear a single track, so you can judge whether it is safe to begin crossing?","options":["About 3 seconds, since that is roughly your reaction time at highway speed","The exact time does not matter as long as no train is currently in sight","About 6 seconds, the same as your total stopping time from 55 mph","At least 14 seconds"],"answer":3,"explanation":"A typical tractor-trailer needs at least 14 seconds to fully clear a single railroad track, so allow that much time before committing to cross.","handbook":"A tractor-trailer needs at least 14 seconds to clear a single track.","hbref":"§2.14 Railroad","qid":"GK-W2-041"},"54":{"q":"It is mid-afternoon, but a heavy rain shower has cut visibility and the sky has gone dark gray. You can still see the road and other vehicles clearly enough to drive, so you wonder whether your headlights are even necessary right now. Why is turning on your LOW-beam headlights the BEST action in this situation?","options":["Running the headlights keeps the alternator under load, which helps charge the battery during a long, slow drive in the rain","Headlights cut through the rain and sharply improve how far ahead you personally can see the roadway","Headlights make your truck far easier for other drivers to see in the dim, rainy light, even though you can still see well enough yourself","Switching to high beams in rain throws the most light forward and is the surest way to be noticed by oncoming traffic"],"answer":2,"explanation":"In dim or rainy light the main purpose of headlights is to make your truck visible to other drivers, even when you can still see well enough yourself.","handbook":"Turn on headlights at dawn, dusk and in rain so others can see you.","hbref":"§2.5 Communicating","qid":"GK-W3-019"},"55":{"q":"During your pre-trip inspection you are walking around a flatbed loaded with steel pipe and you stop to check the header board (\"headache rack\") mounted on the front of the trailer behind the cab. A newer driver asks you why the company won't let the truck roll without one in good condition. Which answer best states the SAFETY purpose this device serves?","options":["It blocks loose gravel and road debris thrown up by the front tires from striking the load","It marks the load as oversized so following traffic keeps a safe distance","It serves as the rear anchor point that the tie-down chains must connect to for legal securement","It shields the driver by stopping the load from sliding forward into the cab during a hard stop or crash"],"answer":3,"explanation":"The header board, or headache rack, is a barrier that stops the load from sliding forward into the cab and injuring the driver during a hard stop or crash.","handbook":"Header boards protect the driver from cargo shifting forward.","hbref":"§3.2 Cargo","qid":"GK-W2-063"},"56":{"q":"It is early morning and you are doing a walk-around inspection of your tractor-trailer before a long haul. As you check the rear axles, you crouch down to look at the dual tires. Which of the following observations would require you to take the vehicle out of service before you can legally and safely drive?","options":["The steering-axle tires each measure 5/32 inch of tread depth","The two dual tires on the rear axle are pressed against each other and making contact","All four tires on the rear axle are the same size and brand","The rear drive tires measure 3/32 inch of tread depth"],"answer":1,"explanation":"Dual tires must never touch each other, as contact signals a mismatch or under-inflation that builds heat and can cause a blowout.","handbook":"Dual tires must not touch and radial/bias tires must not be mixed.","hbref":"§2.1 Inspection","qid":"GK-W2-014"},"58":{"q":"You are finishing the pre-trip inspection on your tractor-trailer before a 300-mile run. Your supervisor radios that a roadside officer will be checking your truck for the federally required emergency equipment. Glancing in the cab, you realize one item from your usual kit is missing and start to worry. Which of the following is the item you do NOT legally need on board to pass that check?","options":["A properly charged and rated fire extinguisher","An inflated spare tire stored on the rig","A set of three red reflective warning triangles","Spare electrical fuses, unless the truck uses circuit breakers"],"answer":1,"explanation":"Required emergency equipment is a fire extinguisher, spare fuses, and warning triangles; a spare tire is not required.","handbook":"Required: fire extinguisher, spare fuses, and warning devices.","hbref":"§2.1 Inspection","qid":"GK-W2-015"},"59":{"q":"It is just below freezing and you are pulling a loaded trailer up a slight grade on a bridge deck. You feel the rear drive wheels begin to spin and the back of the tractor starts swinging out to the left. To bring the rig back under control, which action would make the skid WORSE rather than help you recover?","options":["Press harder on the throttle to power the spinning drive wheels back into line","Ease off the accelerator and push in the clutch to let the drive wheels slow down","Steer in the direction you want the tractor to go down the lane","Be ready to counter-steer as the trailer begins to straighten out"],"answer":0,"explanation":"In a drive-wheel skid, stop feeding power: ease off the accelerator and push in the clutch so the drive wheels can regain traction.","handbook":"To recover from a drive-wheel skid, stop accelerating and steer.","hbref":"§2.18 Skids","qid":"GK-W2-064"},"60":{"q":"It is 5:00 a.m. and you are about to start a long haul. A coworker tells you the company already paid an inspection mechanic last week, so your own pre-trip walk-around this morning is really just about catching anything that could leave you stranded on the highway. Which statement BEST describes why Texas requires you to perform your own pre-trip inspection before EVERY trip?","options":["Its only legitimate purpose is to spot mechanical safety defects before they cause a crash on the road.","It is fundamentally a legal formality you must log to stay compliant with state and federal rules.","Its main value is preventing roadside breakdowns that cost the company time and money.","It serves all of these purposes together: finding safety defects, meeting your legal duty, and preventing breakdowns."],"answer":3,"explanation":"The pre-trip inspection serves three goals together: finding safety defects, meeting your legal duty as the driver, and preventing costly breakdowns.","handbook":"Inspections find defects, are required by law, and prevent breakdowns.","hbref":"§2.1 Inspection","qid":"GK-W3-020"},"61":{"q":"You are driving a loaded tractor-trailer at highway speed when a car suddenly cuts in front of you and brakes hard, leaving a hazard directly in your lane with the shoulder open to your right. Stopping in time is not possible. Which statement BEST explains why hard braking alone is not always the safest emergency response here?","options":["You can often steer around a hazard in less distance than it takes to stop, so countersteering into the open shoulder may avoid the crash when stopping cannot.","Stopping is never permitted in an emergency because it wastes reaction time that the law requires you to use for steering.","Hard braking should be avoided mainly because the brakes will overheat and fade within the first few seconds of any panic stop.","Because your trailer is loaded, your total stopping distance at 55 mph drops to about 60 feet, so braking is pointless at that range."],"answer":0,"explanation":"You can usually steer around a hazard in far less distance than it takes to stop, so countersteering into an open shoulder may avoid a crash when braking cannot.","handbook":"Stopping is not always safest; steering to miss may be quicker.","hbref":"§2.16 Emergencies","qid":"GK-W3-021"},"62":{"q":"You are driving a loaded tractor-trailer at 55 mph on a dry highway when a car suddenly stops in your lane far ahead. From the instant the hazard first appears to the instant your truck comes to a complete stop, your total stopping distance is built from three separate parts that occur one after another. Which sequence lists those three parts in the correct chronological order, from first to last?","options":["Reaction distance, then braking distance, then perception distance","Perception distance, then reaction distance, then braking distance","Braking distance, then reaction distance, then perception distance","Perception distance, then braking distance, then reaction distance"],"answer":1,"explanation":"Total stopping distance happens in sequence: first you perceive the hazard, then you react and move your foot to the brake, then the brakes slow the vehicle.","handbook":"Total stopping distance: perception, then reaction, then braking.","hbref":"§2.6 Speed","qid":"GK-W2-001"},"65":{"q":"You are hauling a loaded trailer down a long, steep mountain grade. Partway down, you press the brake pedal and it sinks to the floor with almost no resistance -- your service brakes have failed and the truck is gaining speed. A runaway escape ramp is signed about a half-mile ahead. What is the single BEST action to take?","options":["Shift the transmission into neutral so the engine is no longer fighting you and let the truck coast to a controlled stop","Pump the brake pedal rapidly and repeatedly to try to rebuild pressure while you continue down the grade","Steer onto the runaway escape ramp ahead, which is built to stop a vehicle with failed brakes","Throw open the driver's door and prepare to jump clear before the truck reaches the bottom"],"answer":2,"explanation":"Runaway escape ramps are built to safely stop a heavy vehicle whose brakes have failed on a downgrade, so use one whenever it is available.","handbook":"If your brakes fail on a downgrade, look for an escape ramp to stop the vehicle.","hbref":"§2.7","qid":"GK-W2-040"},"66":{"q":"It has been raining steadily for the last ten minutes and you are running a loaded combination at 60 mph on a smooth, well-paved interstate. You notice your steering feels light and the truck does not respond when you make a small wheel correction. Which factor is MOST responsible for this loss of road contact?","options":["The road surface is dry, so the front tires have lost their grip on hot pavement","There is water on the road and you are driving too fast, so the tires are riding on a film of water","You are driving very slowly, which lets the tires sink into standing water","Your tires are brand-new and the deep tread is channeling away too much water"],"answer":1,"explanation":"Hydroplaning happens when water on the road combined with too much speed lifts the tires so they ride on a film of water instead of the pavement.","handbook":"Hydroplaning can occur at higher speeds on wet roads, so reduce your speed.","hbref":"§2.6","qid":"GK-W3-022"},"67":{"q":"It is a hot summer afternoon and you have just pulled into a rest area after driving 120 miles on the highway. During a walk-around you want to confirm your drive-axle tires are properly inflated before continuing. Which method gives you an accurate, reliable inflation reading?","options":["Strike each tire with a tire thumper or mallet and judge inflation by the sound and bounce","Check the pressure right now with a gauge while the tires are still hot from the highway run, since that is their true working pressure","Let the tires cool first, then check each one with a properly calibrated tire pressure gauge","Look closely at how much each tire bulges at the bottom and compare it to the others"],"answer":2,"explanation":"Check tire pressure only with a properly calibrated gauge after the tires have cooled, since heat from driving raises pressure and gives a falsely high reading.","handbook":"Check tire pressure with a gauge; do not just look at or thump the tires.","hbref":"§2.1","qid":"GK-W3-023"},"68":{"q":"You are merging onto a busy interstate in your loaded tractor-trailer. A four-wheeler tucks in close behind your right rear and disappears from your mirrors, while another car rides just off your left fender. A coworker once told you to be most concerned about the 'No-Zone.' In this situation, what is the No-Zone you should be managing?","options":["The cushion of space you must keep ahead of you, equal to about 419 feet at 55 mph","The large blind-spot areas around your truck where other vehicles can vanish from your view","The no-parking zone along the right curb where you may not stop to set out warning triangles","The far-left high-occupancy lane that trucks are restricted from entering"],"answer":1,"explanation":"The No-Zone refers to the large blind-spot areas surrounding a truck on all four sides where other vehicles can disappear from view.","handbook":"The large blind spots around a commercial vehicle are called the No-Zone.","hbref":"§2.4","qid":"GK-W2-026"},"69":{"q":"You are alone in a crowded truck-stop lot and need to back your tractor-trailer into a tight space along a wall on your right. Your trailer is empty, the lot is busy with foot traffic, and you cannot clearly see the area behind your right rear. What is the safest way to complete this back?","options":["Back toward your right (blind) side so the wall stays in view through your windshield, and proceed slowly","Back quickly while you still have a gap, since lingering in the lane creates more risk to pedestrians","Rely on your right-side mirror alone and skip getting out, because stopping to look wastes time in a busy lot","Reposition if needed so you can back toward your left (driver's) side, and use a helper or spotter to watch your blind area"],"answer":3,"explanation":"Whenever possible back toward the driver's (left) side so you can see directly down the trailer, and use a helper or spotter to watch your blind area.","handbook":"Back toward the driver's side and use a helper so you can see down the side.","hbref":"§2.2","qid":"GK-W3-024"},"70":{"q":"You are driving a loaded tractor-trailer at 55 mph in good, dry conditions when a stalled car suddenly appears in your lane only a few truck-lengths ahead — far closer than your roughly 419 ft total stopping distance. The lane beside you is clear. Which action gives you the BEST chance of avoiding a crash?","options":["Steer around the hazard into the clear lane, since you can usually turn to miss an obstacle in less distance than it takes to stop","Brake as hard as you possibly can and lock the wheels, because maximum braking is always the safest emergency response","Keep your speed and drive straight through, trusting the truck's mass to push the obstacle aside","Stay in your lane and brake lightly, since at 55 mph your 419 ft stopping distance will bring you to a stop in time"],"answer":0,"explanation":"You can usually steer around an obstacle in less distance than it takes to brake to a stop, so use a clear lane to avoid the hazard.","handbook":"You can almost always turn to miss an obstacle more quickly than you can stop.","hbref":"§2.7","qid":"GK-W3-025"},"71":{"q":"You are approaching a busy intersection where you must turn right, and there is a line of vehicles behind you. To communicate your intentions safely and give other drivers the most time to react, when should you activate your turn signal?","options":["Tap your brakes a few times first, then signal just as you begin the turn so following drivers are not confused by an early signal","Signal well before the turn and keep the signal on until the turn is complete","Only after you have slowed and confirmed the intersection is clear, to avoid signaling too soon","Signal right after you have completed the turn to confirm the maneuver to drivers behind you"],"answer":1,"explanation":"Signal early, well before turning, and keep the signal on through the entire turn so other drivers have maximum time to react.","handbook":"Signal your intentions early and keep signaling through the turn.","hbref":"§2.4","qid":"GK-W2-027"},"72":{"q":"It is just below freezing and a light freezing drizzle has left the highway looking wet and shiny. Your loaded truck is equipped with an engine brake (retarder). As you approach a stretch of road where you may need to slow gradually, what is the SAFEST way to handle the retarder in these conditions?","options":["Leave the retarder fully engaged, since it reduces wear on your service brakes in bad weather","Switch the retarder OFF, because it can cause the drive wheels to lose traction and skid on the slick surface","Keep the retarder on its highest setting so you can slow down without touching the brake pedal","Use the retarder only when your speed climbs above 40 mph, then shut it off below that speed"],"answer":1,"explanation":"Turn the retarder off on wet, icy, or slick roads because it brakes only the drive wheels and can make them lose traction and skid.","handbook":"Turn off retarders on wet or icy roads because they can cause the drive wheels to skid.","hbref":"§2.6","qid":"GK-W2-010"},"73":{"q":"You are hauling a fully loaded trailer and have started climbing a long, steep upgrade in the mountains. Your tractor begins to lug, engine RPMs are dropping, and your road speed is bleeding off fast. Which action keeps you driving safely and maintains the most engine power on the climb?","options":["Keep the transmission in overdrive and press the accelerator to the floor to recover speed","Shift into a lower gear so the engine stays in its power range and pulls the load steadily","Put the transmission in neutral and let momentum carry you over the top of the grade","Hold your current gear and pump the service brakes lightly to keep the rig under control"],"answer":1,"explanation":"On a long, steep upgrade, shift into a lower gear to keep engine RPM in its power range so it pulls the load steadily.","handbook":"On an upgrade you may need to shift to a lower gear to keep enough power.","hbref":"§2.6","qid":"GK-W2-011"},"74":{"q":"You are running empty at 30 mph on a dry rural highway and have learned to leave yourself enough room to brake. Traffic ahead clears and you accelerate to 60 mph. Compared with the braking distance you needed at 30 mph, what should you now expect of the braking distance alone at 60 mph?","options":["It only doubles, since you doubled your speed -- so leaving twice the room is enough","It increases roughly four times, because braking distance grows with the square of speed","It stays about the same, because an empty truck stops in a shorter distance than a loaded one","It increases by about half, since total stopping distance also includes reaction distance"],"answer":1,"explanation":"Braking distance grows with the square of speed, so doubling your speed makes it roughly four times longer.","handbook":"When you double your speed, it takes about four times the distance to stop.","hbref":"§2.6","qid":"GK-W3-026"},"75":{"q":"It is 2 a.m. on a long overnight run and you notice your eyes feel heavy, you have drifted within your lane, and you cannot recall the last few miles. You still have several hours of legal driving time left on your log. Which action is the ONLY genuinely effective way to deal with this fatigue?","options":["Roll the window down and let cold air blow on your face to stay alert","Drink a large coffee and push on to finish the run while you still have hours available","Leave the highway at a safe place and stop to rest or sleep before continuing","Turn the radio up loud and lower the cab temperature to keep yourself awake"],"answer":2,"explanation":"The only sure cure for drowsiness is to stop driving and get rest or sleep, since nothing else truly restores alertness.","handbook":"The only sure way to overcome fatigue is to stop driving and sleep.","hbref":"§2.8","qid":"GK-W2-047"},"77":{"q":"You are driving a loaded tractor-trailer on a four-lane highway when orange signs warn of a work zone ahead. As you enter, the posted limit drops and a flagger and several workers are visible near the right travel lane. Traffic is moving freely and no one is directly behind you. Which action is the BEST choice as you pass through the zone?","options":["Maintain your highway speed since traffic is flowing and clearing the zone quickly reduces your exposure to the workers","Reduce your speed to the posted work-zone limit, increase your following distance, and stay alert for workers entering the lane","Move into the left lane at your current speed and accelerate to get past the flagger before conditions change","Keep close to the vehicle ahead so other drivers cannot merge between you and force you to brake near the workers"],"answer":1,"explanation":"In a work zone, slow to the posted limit, increase your following distance, and watch for workers entering the lane to keep enough stopping space.","handbook":"Slow down in work zones, watch for workers, and obey the reduced speed limits.","hbref":"§2.4","qid":"GK-W2-028"},"78":{"q":"During your pre-trip you supervise the loading of light but bulky crates into your dry van. To get them all to fit, the crew stacks them tall, leaving most of the weight high in the trailer rather than spread low across the floor. The total cargo weight is well within your axle limits and the load is centered side-to-side. As you pull out and approach the first highway on-ramp curve, what is the MOST important effect of how this load was stacked?","options":["Because the weight is centered and within axle limits, the trailer will actually corner more steadily than a low-stacked load.","The tall stacking has no real handling effect since the cargo weight is within your legal axle limits.","The high center of gravity makes the vehicle much more likely to tip or roll over in the curve, even though the load feels secure on the straightaway.","The main risk is a much longer stopping distance, because weight stacked high reduces braking traction."],"answer":2,"explanation":"Stacking light, bulky cargo tall raises the center of gravity, which sharply increases the risk of tipping or rolling over in a curve.","handbook":"A high center of gravity makes a vehicle more likely to tip over; keep the load low.","hbref":"§3.2","qid":"GK-W3-027"},"79":{"q":"During your pre-trip inspection, you are hauling a single steel coil that weighs 8,000 lb on your flatbed. You begin checking your tie-down chains and binders to confirm your load is legally secured. Aside from the requirement that the steel coil be blocked and braced, which statement correctly describes the MINIMUM combined (aggregate) working load limit your tie-downs must provide for this 8,000 lb load?","options":["The combined working load limit of the tie-downs must equal the full weight of the cargo, so at least 8,000 lb.","The combined working load limit of the tie-downs must be at least one-quarter of the cargo weight, so at least 2,000 lb.","The combined working load limit of the tie-downs must be at least twice the cargo weight, so at least 16,000 lb.","The combined working load limit of the tie-downs must be at least one-half of the cargo weight, so at least 4,000 lb."],"answer":3,"explanation":"The combined working load limit of all tie-downs must be at least one-half of the cargo weight.","handbook":"The combined working load limit of tie-downs must be at least one-half the weight of the cargo.","hbref":"§3.2","qid":"GK-W3-028"},"80":{"q":"You are approaching a tight right turn at a city intersection in your tractor-trailer. You know your trailer will track inside the path of your tractor (off-tracking), and you are worried the rear wheels may climb the curb. To keep the rear of the trailer from hitting the curb, what is the safest way to make this right turn?","options":["Begin the turn by swinging the front of the rig wide to the LEFT, then cut sharply right so the trailer clears the curb","Turn wide as you complete the turn while keeping the rear of your vehicle close to the curb, so other drivers cannot squeeze in on your right","Start the turn from the left lane and accelerate through it to shorten the time you block the intersection","Keep to the right and turn wide to the left only if absolutely necessary, accepting that traffic may pass you on the right"],"answer":1,"explanation":"Turn wide only as you complete a right turn while keeping the rear close to the curb, so no one can squeeze in on your right.","handbook":"Do not swing wide to the left before a right turn; keep the rear close to the curb.","hbref":"§2.4","qid":"GK-W2-029"},"81":{"q":"You are hauling a fully loaded trailer down a state highway and approach a sweeping curve. A roadside sign reads 'Curve — 45 MPH.' Your truck is heavy and rides high, but the pavement is dry and the weather is clear. Which statement BEST describes how you should treat that posted 45 MPH curve speed?","options":["Treat 45 MPH as a maximum for cars in good conditions, and slow below it because your loaded, high-riding truck needs a lower speed to avoid rollover.","Treat 45 MPH as the speed that was specifically calculated for loaded heavy trucks like yours, so you may safely take the curve at exactly 45 MPH.","Since the pavement is dry and the weather is clear, you may add a margin and take the curve slightly above 45 MPH.","The posted speed only applies at night, so in clear daylight you can ignore it and hold your highway speed through the curve."],"answer":0,"explanation":"Posted curve speeds are set for cars in good conditions, so a loaded, high-riding truck must slow below the sign to avoid rollover.","handbook":"Posted speeds for curves are set for cars; reduce your speed below them in a heavy vehicle.","hbref":"§2.6","qid":"GK-W3-029"},"82":{"q":"You are hauling a fully loaded trailer down a long, steep mountain grade. Partway down, you notice the brake pedal is getting softer and the truck is gradually picking up speed even though you have been pressing the brakes steadily the whole way down. Which of the following is the MOST likely cause of this loss of braking power?","options":["The brakes are still cold because you only just began the descent, so they have not yet gripped fully","The brakes have overheated from being ridden continuously, causing them to fade and lose stopping power","The trailer is too lightly loaded, so there is not enough weight pressing the brake shoes against the drums","The brake shoes are brand-new and need to wear in before they will hold the vehicle on a grade"],"answer":1,"explanation":"Riding the brakes down a long grade overheats them, causing brake fade and loss of stopping power.","handbook":"Using the brakes too much on a long downgrade overheats them and causes brake fade.","hbref":"§2.7","qid":"GK-W3-030"},"83":{"q":"You are loaded and rolling down a wet four-lane highway when a car suddenly cuts in front of you and brakes hard. Your dash ABS lamp is off, so the system is working. As you stomp the brake pedal to the floor and the ABS activates, what is the MAIN benefit you should expect from ABS in this hard stop?","options":["It guarantees you will stop in a noticeably shorter distance than a truck without ABS","It automatically pumps the brakes so you no longer have to use stab braking on dry pavement","It keeps your wheels from locking up so you can keep steering and stay in your lane while braking hard","It lets you skip checking brake adjustment during your pre-trip because the computer monitors the brakes"],"answer":2,"explanation":"ABS keeps the wheels from locking up during hard braking, so you retain steering control to stay in your lane or avoid a hazard.","handbook":"ABS helps you keep control and steer during hard braking by preventing wheel lockup.","hbref":"§5.3","qid":"GK-W3-031"},"84":{"q":"You just dropped your last load and are now hauling the empty trailer back to the yard on a wet two-lane road. A car ahead brakes hard and you have to stop quickly. Compared to when you were fully loaded earlier today, what should you expect from your empty rig in this situation?","options":["With no cargo weight pressing down, the tires grip the road better, so you will always stop in a shorter distance than when loaded.","An empty truck behaves exactly like a loaded one, so your stopping distance is unchanged either way.","Because there is so little weight, the wheels cannot lock up or skid, so hard braking is completely safe now.","The empty truck has less traction and can bounce, so it may actually take you longer to stop than when it was loaded."],"answer":3,"explanation":"An empty truck has less traction and tends to bounce, so it can take longer to stop than when fully loaded.","handbook":"An empty truck has less traction and may take longer to stop than a loaded one.","hbref":"§2.6","qid":"GK-W3-032"},"85":{"q":"It is about an hour before sunset and a light rain has started as you pull onto a two-lane highway. Visibility is still fairly good and you can see the road clearly without them, but oncoming cars are getting harder to pick out against the gray sky. What is the best practice for your headlights in this situation?","options":["Leave them off, because turning them on is only required once it is fully dark and you cannot see the road ahead","Turn them on now, because they help other drivers see you at dusk and in rain, fog, or other low-light conditions","Use only your high beams, since the rain and fading light mean you need the maximum forward lighting available","Wait until you reach a higher-speed divided highway, since headlights are mainly needed for highway speeds"],"answer":1,"explanation":"Turn headlights on at dusk and in rain or fog because they make your vehicle visible to other drivers in low-light conditions.","handbook":"Turn on your headlights at dusk and in rain, fog, or other low-visibility conditions.","hbref":"§2.11","qid":"GK-W2-032"},"86":{"q":"You are backing your trailer into a tight loading dock and you glance into the large convex (curved) spot mirror on the passenger side. A car that you know is parked only a few feet behind your rear bumper appears small and distant in that mirror. Before you continue backing, what should you understand about what this convex mirror is showing you?","options":["It is giving you a wider field of view, but objects in it look smaller and farther away than they really are, so that car is closer than it appears","It is magnifying the view, so objects in it look larger and closer than they really are, meaning that car is actually farther away than it looks","It shows the true size and distance of objects, so you can trust that the car is as far back as it appears in the mirror","It is malfunctioning, because a properly adjusted mirror would never make a nearby object look small, and convex mirrors are not legal on commercial vehicles anyway"],"answer":0,"explanation":"A convex mirror gives a wider field of view but makes objects look smaller and farther away, so they are actually closer than they appear.","handbook":"Convex mirrors show a wider area, but objects appear smaller and farther away.","hbref":"§2.4","qid":"GK-W3-033"},"87":{"q":"You are driving a loaded tractor-trailer at highway speed when, about 12 to 15 seconds ahead, you spot a stalled car partly blocking the right lane with its hazard lights flashing. Traffic around you is still moving normally and there is no immediate emergency yet. What should your FIRST action be?","options":["Hold your speed and position until the car is close enough to judge exactly how far it sticks into your lane","Begin getting ready to react now -- ease off the accelerator, check your mirrors, and plan an escape path so you can adjust smoothly before it becomes an emergency","Immediately apply hard, controlled stab braking to scrub off as much speed as possible right away","Steer into the left lane at once and accelerate to clear the area before other traffic reacts"],"answer":1,"explanation":"Spotting a hazard early buys time to react, so ease off the accelerator, check mirrors, and plan an escape path before it becomes an emergency.","handbook":"Recognizing a hazard early gives you time to act before it becomes an emergency.","hbref":"§2.5","qid":"GK-W3-034"},"88":{"q":"You are running an empty trailer at 55 mph on an interstate during a heavy downpour. You feel the steering go light and the truck begins to feel like it is floating, with the front tires no longer fully tracking the road. You realize you are starting to hydroplane. Which action gives you the BEST chance of regaining traction safely?","options":["Press firmly on the brake pedal to slow down quickly and force the tires back onto the pavement","Steer hard toward the shoulder so the front tires bite into the rougher surface and grab","Take your foot off the accelerator, keep the wheel pointed straight, and let the truck slow until the tires grip again","Downshift aggressively and use engine braking to drag the speed off as fast as possible"],"answer":2,"explanation":"When hydroplaning the tires lose road contact, so ease off the accelerator and hold the wheel straight until they slow and grip again.","handbook":"If you hydroplane, ease off the accelerator and do not brake hard.","hbref":"§2.6","qid":"GK-W3-035"},"89":{"q":"You have just driven your loaded combination vehicle slowly through a flooded low-water crossing, and water rose high enough to submerge your wheel hubs. As you accelerate back to road speed, you tap the brakes and feel them grab weakly and unevenly. Which action is the BEST way to restore safe braking?","options":["Pull onto the shoulder and wait for the brake drums to air-dry before continuing","Pump the brake pedal hard several times to force the water out of the linings","Downshift and rely only on engine braking, leaving the service brakes untouched for the next few miles","Keep driving slowly and apply light, steady pressure on the brakes to dry them out through friction heat"],"answer":3,"explanation":"Dry wet brakes by driving slowly while applying light, steady pressure so friction heat evaporates the water and you stay in control.","handbook":"Dry wet brakes by driving slowly while applying light pressure.","hbref":"§2.6","qid":"GK-W3-036"},"90":{"q":"You are running behind schedule on a rural two-lane highway with a posted limit of 55 mph. The vehicle ahead is moving slowly, and you are eager to pass. In which of the following situations would attempting to pass be the LEAST safe and therefore something you should NOT do?","options":["You are approaching the crest of a hill and cannot see whether any vehicle is coming toward you in the oncoming lane","You are on a long, flat, straight stretch where you can clearly see the road is empty for well over a quarter mile ahead","You have entered a marked passing zone with a broken yellow centerline on your side and clear visibility ahead","You can see the oncoming lane is clear and you have enough room to return to your lane with plenty of space before any oncoming traffic"],"answer":0,"explanation":"Never pass where you cannot see far enough ahead, such as near the crest of a hill, because oncoming vehicles stay hidden until it is too late.","handbook":"Do not pass on hills or curves or anywhere you cannot see far enough ahead.","hbref":"§2.4","qid":"GK-W3-037"},"91":{"q":"You are driving a loaded tractor-trailer on a short entrance ramp. The freeway to your left is moving at about 60 mph, and you see a usable gap opening between two cars in the right lane ahead. As you reach the end of the acceleration lane, what is the SAFEST way to enter traffic?","options":["Slow to a near stop at the end of the ramp and wait for an extra-large gap before pulling out","Use the acceleration lane to bring your speed up close to the flow of traffic, then merge smoothly into the open gap","Keep your speed low and ease into the lane, forcing the cars behind to brake and make room for you","Hold a slow, steady crawl down the ramp so you have more time to judge the traffic before merging"],"answer":1,"explanation":"Use the acceleration lane to reach a speed near the traffic flow, then merge into a gap so the speed difference with other vehicles is smallest.","handbook":"Match the speed of traffic and merge into a gap when entering a highway.","hbref":"§2.4","qid":"GK-W3-038"},"92":{"q":"You are driving a loaded tractor-trailer in the right lane of a four-lane divided highway when you hear a siren and see an ambulance approaching fast in your mirrors with lights flashing. Traffic is moderate and there is a paved shoulder on your right. Which action is the BEST response?","options":["Maintain your lane and speed so the ambulance can predict your path and pass you on the left","Accelerate to stay ahead of the ambulance until you reach the next exit, then leave the highway","Signal, steer toward the right shoulder, and bring your rig to a stop when it is safe to clear a path","Move left into the passing lane to open the right lane and shoulder for the emergency vehicle"],"answer":2,"explanation":"For an approaching emergency vehicle with lights and siren, signal, pull to the right shoulder, and stop when it is safe to yield and clear a path.","handbook":"Pull over and stop for an emergency vehicle using its lights and siren.","hbref":"§2.4","qid":"GK-W3-039"},"93":{"q":"A small electrical fire breaks out in the engine compartment of your tractor after you pull onto the shoulder. You grab your fire extinguisher, position yourself upwind, pull the pin, and aim the nozzle. Following the PASS method correctly, after you squeeze the handle, what is the final action you must take to put the fire out effectively?","options":["Hold the nozzle steady and aim directly at the top of the visible flames until they die down","Stop discharging immediately once smoke appears so you do not waste the extinguisher","Spin the extinguisher in a circular motion above the fire to spread the agent over a wide area","Sweep the nozzle from side to side, aiming at the base of the fire, until it is extinguished"],"answer":3,"explanation":"The final PASS step is to sweep the nozzle side to side at the base of the fire, where the fuel burns, to smother and extinguish it.","handbook":"Use PASS: Pull, Aim, Squeeze, and Sweep at the base of the fire.","hbref":"§2.9","qid":"GK-W3-040"},"94":{"q":"You are driving on a rural two-lane highway when another motorist pulls alongside, pointing and shouting that one of your trailer tires is on fire. You pull onto the shoulder, set your brakes, and grab your fire extinguisher and the road safety kit. As you approach the burning tire, what is the MOST appropriate action to control this fire?","options":["Douse the tire with plenty of water to cool it down, because a tire fire generates intense heat and needs continuous cooling to be put out","Aim your dry-chemical (B:C) fire extinguisher directly at the base of the flames and keep it there until the canister is empty","Leave it alone and let it burn out on its own from a safe distance, since smothering a rubber fire only makes it flare back up","Carefully add air to the tire to keep the casing from collapsing while the flames die down"],"answer":0,"explanation":"A tire fire holds intense heat in the rubber, so douse it with plenty of water for continuous cooling or it will reignite.","handbook":"Use plenty of water to cool a burning tire.","hbref":"§2.9","qid":"GK-W3-041"},"95":{"q":"It is just below freezing and a light rain is starting to glaze the road. While maintaining your normal highway pace through a sweeping curve, the rear of your tractor-trailer suddenly begins to slide out and you feel the trailer pushing the cab sideways. Looking back honestly at the moment the skid began, what was the single MOST likely cause?","options":["Your front steer-axle tires were worn down close to the 2/32 inch minimum and lost their grip first","You were traveling too fast for the slick, near-freezing road conditions","You used smooth, gentle steering inputs through the curve instead of sharp corrections","Your trailer was running empty, and empty trailers always grip the road better than loaded ones"],"answer":1,"explanation":"Most skids come from driving too fast for conditions, and near-freezing slick roads cut traction so a normally safe speed becomes excessive.","handbook":"Most skids are caused by driving too fast for conditions.","hbref":"§2.7","qid":"GK-W3-042"},"96":{"q":"It is just below freezing and a light rain has been falling. You are in the center lane of a three-lane highway when the trailer behind you begins to feel light and starts drifting toward the next lane. Of the actions below, which one gives you the BEST chance of keeping the vehicle under control and avoiding a full skid?","options":["Brake hard and hold the pedal down firmly to scrub off speed as quickly as possible","Make a quick, sharp steering correction back toward the center of your lane to stop the drift","Ease off the accelerator and make smooth, gentle steering and braking inputs to keep traction","Maintain your current speed and steer aggressively, since the tires still have grip in the center lane"],"answer":2,"explanation":"On slick, near-freezing roads reduce demand on the tires by easing off the accelerator and making smooth, gentle steering and braking inputs to keep traction.","handbook":"Smooth steering, braking, and acceleration help prevent skids.","hbref":"§2.7","qid":"GK-W3-043"},"97":{"q":"It is mid-afternoon in late July and you have been running loaded on hot asphalt for several hours. During a rest stop you decide to check your tires more frequently than usual on this trip. What is the BEST reason for doing so in these conditions?","options":["Hot pavement cools the air inside the tires, so they lose pressure and run under-inflated","Heat softens the tread rubber, which is the main cause of a blowout in summer","The tires physically contract in the heat, reducing the size of the contact patch","Heat raises the air pressure inside the tires, which can lead to a blowout"],"answer":3,"explanation":"In hot weather the air sealed inside the tires expands and pressure rises, which can lead to a blowout.","handbook":"In hot weather, check tires often because heat raises their pressure.","hbref":"§2.10","qid":"GK-W3-044"},"98":{"q":"You are hauling freight on a rural two-lane highway when you drive into a dense fog bank so thick you can no longer see the lane markings or any vehicle ahead, even after slowing down and switching to your low beams. Reducing speed further has not restored your ability to see a safe path. What is the safest action to take?","options":["Switch to high beams to push more light through the fog and keep creeping forward at a crawl","Slow to a near-stop in your lane, turn on your hazard flashers, and continue inching ahead","Pull completely off the roadway, get well clear of traffic, turn on your lights and flashers, and wait for the fog to lift","Maintain a slow steady speed and follow the taillights of the vehicle ahead to stay in your lane"],"answer":2,"explanation":"When fog is too thick to see a safe path even at low speed, pull completely off the road, get clear of traffic, turn on lights and flashers, and wait for it to lift.","handbook":"If fog is too thick to drive safely, pull off the road and wait.","hbref":"§2.11","qid":"GK-W2-033"},"99":{"q":"You completed a thorough pre-trip inspection this morning, secured your cargo, and everything checked out. Three hours into your run you stop for a meal break, and a fellow driver asks why you are walking around your rig and checking your load again when you already inspected it before leaving. What is the BEST reason to keep inspecting throughout the day?","options":["A proper inspection is an ongoing process performed before, during (en route), and after the trip, because the vehicle's condition and cargo securement can change while you drive.","Once a vehicle passes a complete pre-trip inspection, the law treats it as roadworthy for the rest of that trip, so the walk-around is only a personal habit, not a requirement.","Inspections en route are only needed if a warning light comes on or the vehicle actually breaks down, since a passed pre-trip already covers everything mechanical.","A re-check is required strictly because you must inspect cargo within the first 50 miles, and after that first check no further inspection of the vehicle is necessary for the day."],"answer":0,"explanation":"Inspection is ongoing — done before, during (en route), and after a trip — because tire pressure, cargo securement, and fluid levels all change while you drive.","handbook":"Inspect your vehicle before, during, and after every trip.","hbref":"§2.1","qid":"GK-W3-045"},"100":{"q":"You loaded a flatbed of steel coils this morning and pulled out of the yard onto the interstate. About 35 miles down the road you spot a wide rest area with room to walk all the way around your rig. Your trip is over 300 miles total. According to proper cargo procedure, what should you do about checking your load and securement?","options":["Keep rolling and make your first securement check at the 150-mile mark, since that is the standard re-check interval","Pull in and inspect your cargo and tie-downs now, because you must make your first check within the first 50 miles and then re-check every 3 hours or 150 miles","No inspection is needed until you stop for fuel, as long as the load looked secure during your pre-trip","Wait until you have driven the first 500 miles, then begin inspecting the load periodically"],"answer":1,"explanation":"You must check cargo and tie-downs within the first 50 miles, then re-check every 3 hours or 150 miles and after each break.","handbook":"Inspect your cargo and securing devices within the first 50 miles.","hbref":"§3.1","qid":"GK-W3-046"},"101":{"q":"During your pre-trip you are checking how a load of steel pipe was secured in the cargo area behind the cab. A coworker tells you the only real reason to tie cargo down tight is so it does not get scratched or look messy during the trip. Under Texas DPS cargo rules, what is the PRIMARY safety reason cargo must be properly secured?","options":["So the load stays neat and presentable when you arrive at the delivery point","So the cargo is protected from rain, road dust, and staying dry in bad weather","So the cargo cannot shift, fall off the vehicle, or move into and block the driver's controls","So the cargo does not get cold and freeze when you drive through winter conditions"],"answer":2,"explanation":"Cargo must be secured so it cannot shift, fall off the vehicle, or slide into the cab and block the driver's controls.","handbook":"Secure cargo so it cannot shift, fall, or block your controls.","hbref":"§3.2","qid":"GK-W3-047"},"102":{"q":"You are driving a loaded tractor-trailer westbound late in the afternoon. The sun has dropped low on the horizon directly ahead, and its glare is washing out the road and making it hard to judge how far you can see. Vehicles ahead keep appearing suddenly out of the bright wash. What is the best way to handle this situation?","options":["Lower the sun visor, put on sunglasses, and reduce your speed so you can stop within the distance you can actually see","Switch on your high beams so your own lighting cuts through the glare ahead","Maintain your speed but increase your following distance to 6 seconds to compensate","Move into the left lane and accelerate to get past the glare-affected stretch of road sooner"],"answer":0,"explanation":"With sun glare, lower the visor, wear sunglasses, and slow down so you can stop within the distance you can actually see.","handbook":"Reduce speed and use your visor when glare reduces your vision.","hbref":"§2.11","qid":"GK-W2-034"},"103":{"q":"You are hauling a loaded trailer up a long, steep grade on a two-lane rural highway. Your engine is straining and your speed has dropped to about 15 mph, well below the posted 55 mph limit, while cars stack up behind you. In which of these situations is turning on your four-way emergency flashers the MOST appropriate action?","options":["When you make a normal right turn at the next intersection, since your signal alone may not be seen","Once you reach the crest and resume cruising at the 55 mph speed limit to alert drivers you are a slow commercial vehicle","After you park the rig overnight in a well-lit truck stop so others can see your outline","Now, while you are crawling up the grade far below the flow of traffic, because you are moving much slower than the vehicles around you"],"answer":3,"explanation":"Turn on four-way flashers whenever you are moving much slower than surrounding traffic, such as crawling up a steep grade, to warn drivers behind you.","handbook":"Use four-way flashers when stopped or moving much slower than traffic.","hbref":"§2.4","qid":"GK-W3-048"},"105":{"q":"You are approaching a multi-lane roundabout in your loaded combination vehicle. A car is already circulating in the lane you intend to enter, and a gap is opening up just behind it. Which of the following is the correct and safest action?","options":["Yield to the vehicle already in the roundabout, wait for a safe gap, then enter and merge with the flow of traffic","Maintain your speed and enter immediately, since vehicles already in the roundabout are required to yield to entering trucks","Stop inside the circulating lane of the roundabout and wait there until all other traffic has cleared","If you misjudge the gap and start to enter too soon, back up to re-establish a safe following distance before merging"],"answer":0,"explanation":"Traffic already in a roundabout has the right-of-way, so yield, wait for a safe gap, then enter and merge with the flow.","handbook":"Yield to traffic already in a roundabout before entering.","hbref":"§2.4","qid":"GK-W3-049"},"106":{"q":"You are hauling a loaded trailer in the right lane at the posted limit when a driver behind you begins tailgating, flashing high beams, and gesturing angrily because you will not speed up. Traffic ahead prevents you from changing lanes immediately. Which response is the BEST way to manage this aggressive driver and protect your own safety?","options":["Lightly tap your brakes to flash your brake lights and warn the driver to back off","Maintain your speed and hold your lane firmly so the driver learns not to crowd large trucks","When it is safe, move over or ease off slightly to open space and let the angry driver pass without reacting to the gestures","Speed up above the posted limit until you have pulled far enough ahead that the driver stops tailgating"],"answer":2,"explanation":"With an aggressive driver behind you, don't engage; give them room to pass and stay calm to defuse the conflict.","handbook":"Do not respond to aggressive drivers; give them room and let them by.","hbref":"§2.8","qid":"GK-W2-048"},"107":{"q":"A heavy thunderstorm has left several inches of standing water pooling across the right lane of the highway you are driving on. You are running empty and traveling at 55 mph. As you approach the deep pooled area ahead, which action is the BEST way to keep your vehicle under control?","options":["Maintain 55 mph but steer toward the shoulder, since moving water away from your steering tires restores grip","Reduce your speed before reaching the water, because water trapped between your tires and the road can cause hydroplaning and loss of steering and braking control","Accelerate firmly through the water so your tire tread can channel it away and keep the tires biting the pavement","Keep your speed steady and lightly apply the brakes while in the water to test how much traction you still have"],"answer":1,"explanation":"Slow down before reaching standing water because water between your tires and the road can cause hydroplaning and loss of steering and braking control.","handbook":"Standing water can cause hydroplaning, so reduce your speed.","hbref":"§2.6","qid":"GK-W3-050"},"108":{"q":"You are running empty on a dry, clear interstate and decide to bump your cruising speed from 30 mph up to 60 mph to make up time. A trainee riding with you asks how this change affects the distance your rig will need to brake to a stop. Which response is the BEST description of what actually happens?","options":["Because the truck is empty, the lighter load lets it stop in roughly the same distance at 60 as it did at 30.","Doubling your speed only adds a little to the stop — braking distance grows in step with speed, so it just doubles.","Doubling your speed roughly quadruples the braking distance, so 60 mph needs about four times the room 30 mph did.","Wet pavement would matter, but on this dry road the higher speed barely changes how far you need to stop."],"answer":2,"explanation":"Braking distance grows with the square of speed, so doubling your speed roughly quadruples the distance needed to stop.","handbook":"The faster you drive, the much longer it takes to stop.","hbref":"§2.6","qid":"GK-W2-002"},"109":{"q":"It is just below freezing and a light rain has glazed the road. You are running empty and the truck's rear wheels begin to slide on a curve. Reviewing what put you into this skid, which one of the following actions you took is the LEAST likely to have caused it?","options":["Pressing the accelerator hard to power through the curve","Slamming on the brakes hard enough to lock the wheels when you felt the back end move","Keeping your steering input smooth and gradual through the turn","Carrying too much speed for the icy, wet conditions"],"answer":2,"explanation":"Smooth, gradual steering keeps tire forces within available traction, so it does not cause skids unlike excess speed, hard braking, or over-acceleration.","handbook":"Skids are caused by too much speed, braking, or acceleration — not smooth steering.","hbref":"§2.7","qid":"GK-W2-036"},"110":{"q":"It is well after dark on a two-lane rural highway and you see the headlights of an oncoming truck crest a hill about 400 feet ahead. You currently have your high beams on. What is the correct action?","options":["Leave your high beams on so the other driver can clearly see your large vehicle","Switch to your low beams now, before the vehicles are within 500 feet of each other","Briefly flash your high beams off and on to signal the other driver, then keep them on","Speed up slightly so you pass the oncoming truck before glare becomes a problem"],"answer":1,"explanation":"Dim to low beams within 500 feet of an oncoming vehicle so your high beams do not blind the other driver.","handbook":"Use low beams when meeting oncoming traffic at night.","hbref":"§2.11","qid":"GK-W2-030"},"111":{"q":"You're hauling a loaded flatbed on a rural two-lane highway when your engine starts losing power, forcing you down to about 30 mph on a 55-mph road. Traffic is stacking up behind you. As you nurse the truck toward the next exit so you can pull off and inspect the problem, which one of the following would be an IMPROPER use of your four-way hazard flashers?","options":["Leaving them on to warn faster traffic that you are moving well below the normal speed of the road","Switching them off and using only your right turn signal as you actually move into the exit ramp","Turning them on again once you are stopped on the shoulder while you inspect the engine","Using them in place of your turn signal to indicate you are about to make the right turn onto the ramp"],"answer":3,"explanation":"Hazard flashers warn of a stopped, disabled, or slow-moving vehicle and must never be used in place of your turn signal.","handbook":"Use four-way flashers to warn of a breakdown, a slow vehicle, or when stopped.","hbref":"§2.4","qid":"GK-W2-021"},"112":{"q":"You are hauling a 40-foot straight load down a dry, level state highway and your speedometer is steady at 45 mph in good daytime conditions. To keep a safe cushion in front of you, what is the LEAST following distance you should hold behind the vehicle ahead?","options":["4 seconds, because a 40-foot vehicle needs 1 second for every 10 feet of length","6 seconds, because anything over 40 mph automatically calls for at least 6 seconds","5 seconds, because 40 feet equals 4 seconds and you add 1 more second for being above 40 mph","3 seconds, since the road is dry, level, and visibility is good"],"answer":2,"explanation":"Allow 1 second per 10 feet of length, so a 40-foot vehicle needs 4 seconds, plus 1 more second above 40 mph, for a total of 5 seconds.","handbook":"Keep 1 second of following distance for every 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-051"},"113":{"q":"You are hauling a 50-foot tractor-trailer through a work zone where traffic has thinned out and the posted limit lets you settle in at a steady 35 mph. You want to set a safe following distance behind the pickup ahead of you. Using the rule of 1 second for every 10 feet of vehicle length, which following distance is correct for this exact situation?","options":["4 seconds, because in a slow work zone you can shorten the cushion by one second","7 seconds, taking 5 seconds for length plus 2 extra seconds for the work zone","6 seconds, because you must always add 1 extra second to the length-based count","5 seconds, because 50 feet divided by 10 is 5, and no second is added since you are under 40 mph"],"answer":3,"explanation":"Allow 1 second per 10 feet of length, so a 50-foot vehicle needs 5 seconds, with no extra second added because you are under 40 mph.","handbook":"Keep 1 second of following distance for every 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-052"},"114":{"q":"You are hauling a 60-foot tractor-trailer down a dry, level interstate at a steady 55 mph in clear daytime conditions. Traffic is light and you want to set a safe gap behind the car ahead. Based on the rule for following distance, what is the LEAST amount of following distance you should keep in this situation?","options":["7 seconds","6 seconds","8 seconds","5 seconds"],"answer":0,"explanation":"Allow 1 second per 10 feet of length, so a 60-foot vehicle needs 6 seconds, plus 1 more second above 40 mph, for a total of 7 seconds.","handbook":"Keep 1 second of following distance for every 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-053"},"115":{"q":"You are hauling a single straight truck that measures 30 feet from bumper to bumper. Traffic on the surface street is moving steadily at 30 mph, which keeps you just under the 40 mph mark. To leave a safe following distance for your rig in these conditions, the LEAST number of seconds you should keep between you and the vehicle ahead is:","options":["2 seconds, because at 30 mph you are well below highway speed and traffic is flowing smoothly","3 seconds, allowing 1 second for each 10 feet of your vehicle's length","4 seconds, because you must always add 1 extra second to your length-based count","6 seconds, matching the roughly 6 seconds it takes to make a full stop"],"answer":1,"explanation":"Allow 1 second per 10 feet of length, so a 30-foot vehicle needs 3 seconds, with no extra second added because you are under 40 mph.","handbook":"Keep 1 second of following distance for every 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-054"},"116":{"q":"You are hauling a 70-foot combination on a dry interstate, holding a steady 50 mph in light traffic. A four-wheeler keeps drifting in and out of the gap ahead of you, and you want to reset a safe following distance the moment the lane clears. Based on the rule of seconds for your vehicle length and speed, how many seconds of following distance should you re-establish?","options":["7 seconds, because a 70-foot vehicle needs 1 second for every 10 feet of length","6 seconds, because that is the total stopping-distance cushion recommended at highway speed","8 seconds, because the length calls for 7 seconds and you add 1 more second for being above 40 mph","9 seconds, because you should add 2 seconds above 40 mph for a vehicle this long"],"answer":2,"explanation":"Follow at one second per 10 feet of length below 40 mph, then add one second above 40 mph, so a 70-foot truck at 50 mph needs 8 seconds.","handbook":"Keep 1 second of following distance for every 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-055"},"117":{"q":"You are driving a 20-foot straight truck through a downtown business district. Traffic is steady at a posted 25 mph, the pavement is dry, and visibility is good. To keep a safe cushion in front of you, what is the LEAST following distance you should maintain behind the vehicle ahead?","options":["1 second, because the truck is only 20 feet long","4 seconds, adding 1 second to the base and 1 more for city traffic","3 seconds, since you must always add 1 second above the base figure","2 seconds, one second for each 10 feet of vehicle length"],"answer":3,"explanation":"Below 40 mph the following distance is one second for every 10 feet of vehicle length, so a 20-foot vehicle needs 2 seconds.","handbook":"Keep 1 second of following distance for every 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-056"},"118":{"q":"You are hauling an 80-foot combination on a dry interstate, holding a steady 60 mph in light traffic. A coworker tells you to just leave 'one second for every ten feet' and you'll be fine at any speed. Using the correct Texas DPS following-distance method for your length and speed, what is the LEAST amount of following distance you should keep behind the vehicle ahead?","options":["9 seconds — 8 seconds for the 80 feet of length, plus 1 additional second because you are traveling above 40 mph","8 seconds — 1 second for every 10 feet of your 80-foot vehicle, with no adjustment for speed","10 seconds — 8 seconds for length, plus 2 seconds because you are 20 mph over the 40 mph threshold","7 seconds — 1 second for every 10 feet, then drop 1 second because the dry pavement gives you good traction"],"answer":0,"explanation":"Allow one second per 10 feet of length below 40 mph and add one more second above 40 mph, so an 80-foot vehicle at 60 mph needs 9 seconds.","handbook":"Keep 1 second of following distance for every 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-057"},"119":{"q":"You are hauling a 50-foot tractor-trailer down a dry, level interstate and your speedometer reads a steady 45 mph in light traffic. A four-wheeler ahead of you keeps tapping its brakes, so you want to set a safe following distance using the rule of seconds. How many seconds of space should you keep behind that vehicle?","options":["5 seconds, because your rig is 50 feet long and that gives 1 second for every 10 feet","6 seconds, because 50 feet gives you 5 seconds and you add 1 more second for being above 40 mph","7 seconds, adding 2 extra seconds to your length-based figure because you are on an interstate","4 seconds, since 45 mph is only slightly over 40 mph and a shorter cushion is fine on dry pavement"],"answer":1,"explanation":"Use one second per 10 feet of length below 40 mph and add one second above 40 mph, so a 50-foot vehicle at 45 mph needs 6 seconds.","handbook":"Keep 1 second of following distance for every 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-058"},"120":{"q":"You are hauling a 60-foot tractor-trailer through town and settle in behind a slower delivery truck. Your speedometer reads a steady 35 mph on dry pavement. To keep a safe following distance for your rig at this speed, how many seconds of space should you leave between you and the vehicle ahead?","options":["5 seconds, because you subtract a second on dry pavement in good conditions","8 seconds, allowing one second per 10 feet plus two extra seconds for the trailer","6 seconds, one second for every 10 feet of vehicle length","7 seconds, one second per 10 feet plus one second because you are moving"],"answer":2,"explanation":"Below 40 mph the following distance is one second per 10 feet of length with no extra second added, so a 60-foot vehicle at 35 mph needs 6 seconds.","handbook":"Keep 1 second of following distance for every 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-059"},"121":{"q":"You are hauling a partial load on a two-lane highway when a light freezing drizzle begins and the pavement starts to look glossy. Over the next mile you do three things: you keep your cruising speed steady even though visibility and grip have dropped, you stab the brake pedal hard when a deer darts out, and moments later you press the accelerator firmly to get back up to speed on a slight upgrade. A coworker later argues that only ONE of these actions could realistically have put you into a skid. Which statement is correct?","options":["Only the hard panic braking could have caused a skid, because locking the wheels is the single way to lose traction.","Only driving too fast for the icy conditions could have caused a skid, since most skids come from excess speed.","Each of the three actions — excess speed for conditions, hard panic braking, and firm acceleration — could independently have caused a skid.","Only the firm acceleration could have caused a skid, because a partial (lighter) load gives the drive wheels too little weight for traction."],"answer":2,"explanation":"A skid happens whenever tires lose traction, and driving too fast for conditions, braking too hard, or accelerating too hard can each cause one independently.","handbook":"Skids are caused by driving too fast, braking too hard, or over-accelerating.","hbref":"§2.7","qid":"GK-W2-037"},"122":{"q":"You are hauling a loaded trailer on a rural two-lane highway. A light rain has just started and the pavement is glistening wet, you can see a sharp curve marked ahead, and a low patch of fog is settling into the dip beyond the curve so you cannot see far down the road. A coworker once told you that you only need to reduce speed for the single worst hazard you face at a time. Which action best reflects safe CDL practice in this situation?","options":["Maintain your highway speed through the wet stretch but slow down only once you actually reach the curve, since the curve is the most serious single hazard","Keep your speed steady because your following distance, not your speed, is what protects you when several minor hazards appear together","Slow down only for the fog in the dip, because reduced visibility is the one condition that legally requires a lower speed","Reduce your speed for all three conditions together, because wet pavement, the curve, and the limited visibility each independently call for a lower speed"],"answer":3,"explanation":"Wet pavement, curves, and limited visibility each cut your safe speed on their own, so reduce speed for all of them and even more when they combine.","handbook":"Reduce speed for wet roads, curves, and reduced visibility.","hbref":"§2.6","qid":"GK-W3-060"},"123":{"q":"It is 6:00 a.m. and you are doing the pre-trip inspection on a tractor-trailer before a long interstate run. You open the emergency equipment box behind the seat to confirm it is fully stocked in case you break down on the shoulder later. Which set of items represents the COMPLETE emergency equipment you are required to carry?","options":["Three reflective warning triangles, spare electrical fuses (unless equipped with circuit breakers), and a properly charged and rated fire extinguisher","Three reflective warning triangles and a properly charged and rated fire extinguisher, but spare fuses are optional","A properly charged and rated fire extinguisher and spare electrical fuses, plus a set of tire chains for winter routes","Three reflective warning triangles, a first-aid kit, and a properly charged and rated fire extinguisher"],"answer":0,"explanation":"Required emergency equipment is three reflective warning triangles, spare fuses unless circuit breakers are used, and a properly charged and rated fire extinguisher.","handbook":"Carry warning devices, spare fuses, and a fire extinguisher.","hbref":"§2.1","qid":"GK-W3-061"},"124":{"q":"You are running 30 minutes behind schedule on a divided highway posted at 65 mph. Traffic in all lanes is flowing at about 72 mph, the pavement is dry, and the road ahead is clear and empty for a quarter mile. Under Texas DPS rules, which of these conditions would make it acceptable for you to drive faster than the posted 65 mph limit?","options":["When the general flow of surrounding traffic is moving above the limit, so you keep pace to avoid being a hazard","When you are behind schedule and dry, clear pavement lets you safely make up lost time","None of these conditions justify exceeding the posted limit","When the road ahead is empty for a quarter mile, giving you full stopping distance"],"answer":2,"explanation":"The posted speed limit is the maximum legal speed for ideal conditions and may never be exceeded, regardless of traffic, schedule, or open road.","handbook":"Never drive faster than the posted speed limit.","hbref":"§2.6","qid":"GK-W2-003"},"125":{"q":"You are driving a loaded tractor-trailer on a two-lane highway behind a slow farm truck doing 40 mph in a 60 mph zone. You are anxious to get around it and you spot four upcoming opportunities. Which location is actually a SAFE place to complete the pass?","options":["On the long, gentle curve ahead where you can partly see around the bend","Just before the crest of the hill, while you still have some forward view","None of these locations gives you enough sight distance to pass safely","Through the upcoming rural intersection, since cross-traffic must yield to the highway"],"answer":2,"explanation":"Passing safely on a two-lane road requires enough clear sight distance ahead, which curves, hilltops, and intersections all block.","handbook":"Do not pass on curves, hills, or at intersections.","hbref":"§2.4","qid":"GK-W2-022"},"126":{"q":"You are running 40 minutes behind schedule on a tight delivery. The same tractor-trailer passed a full pre-trip inspection when you drove it yesterday, the weather is clear and dry, and a quick walk-around shows nothing obviously wrong. Under which of these circumstances are you legally and safely permitted to skip today's pre-trip inspection before driving?","options":["When you are behind schedule and a delay would risk a late delivery","When the vehicle passed inspection the previous day and has not been flagged since","None of these circumstances justify skipping the pre-trip inspection","When a brief walk-around shows nothing visibly wrong and conditions are good"],"answer":2,"explanation":"A pre-trip inspection is required before every trip without exception, since a vehicle's condition can change at any time.","handbook":"Always do a pre-trip inspection before driving.","hbref":"§2.1","qid":"GK-W2-016"},"127":{"q":"It is just after dark on a narrow, unlit two-lane farm road and you are hauling a loaded trailer. An oncoming car crests a rise about 400 feet ahead with its high beams blazing straight into your eyes, washing out everything in front of your hood. You have only a couple of seconds before the cars meet. Which action is the safest way to keep your rig under control until the vehicle passes?","options":["Switch your own headlights to high beam so their extra reach lets you see the roadway out past the other driver's glare.","Shift your eyes down toward the right edge of your lane and ease off until the oncoming car has gone by.","Quickly flash your high beams a few times so the other driver realizes the problem and dims down for you.","Fix your eyes on the center line straight ahead and hold your speed steady so you do not drift before the car clears."],"answer":1,"explanation":"When blinded by oncoming high beams, look toward the right edge of your lane as a guide and slow down until the vehicle passes.","handbook":"At night, look toward the right edge of the road to avoid being blinded by oncoming high beams.","hbref":"§2.11","qid":"GK-W3-062"},"131":{"q":"You are running about 55 mph on an interstate when a sudden heavy downpour leaves a film of standing water on the pavement. The steering wheel suddenly feels light and loose in your hands, and you realize the tractor's front tires have lost firm contact with the road and are riding up on the water. Which response gives you the best chance to regain traction safely?","options":["Apply firm, steady brake pressure and steer hard toward the shoulder to force the front tires back down onto the pavement.","Maintain your speed but pump the brakes rapidly so the tires bite through the water film without locking up.","Release the accelerator, hold the steering wheel straight, and allow the truck to slow gradually until the tires regain their grip.","Press the accelerator harder and keep the drive wheels spinning to push the standing water out from under the tires."],"answer":2,"explanation":"In a hydroplane the tires have lost grip, so ease off the accelerator, hold the wheel straight, and let the truck slow until traction returns.","handbook":"If you hydroplane, ease off the accelerator and keep the wheel straight.","hbref":"§2.6","qid":"GK-W3-063"},"133":{"q":"You are hauling a loaded trailer in the right lane of a four-lane divided highway, traveling at the posted 60 mph limit. A pickup truck has closed in behind you, riding only a few feet off your bumper, repeatedly flashing its high beams and swerving as if looking to pass. There is an empty lane to your left and steady traffic ahead. Which response is the safest and most legally sound?","options":["Lightly tap your brakes a few times to flash your brake lights and signal the tailgater to back off and create space behind you.","Maintain your current speed and lane position so the aggressive driver cannot force you to change what you are doing.","Accelerate to about 70 mph to open distance from the tailgater, since pulling ahead of an aggressive driver removes the conflict.","Ease off the accelerator to open up more following distance ahead of you, then signal and move into the left lane when it is clear so the driver can pass."],"answer":3,"explanation":"With an aggressive tailgater, ease off the accelerator to open space ahead, then signal and move over to let them pass safely.","handbook":"Do not respond to aggressive drivers; give them room and let them pass.","hbref":"§2.8","qid":"GK-W3-064"},"134":{"q":"You are hauling a loaded trailer down the interstate when you catch the sharp smell of burning rubber and notice gray smoke trailing from the rear of your unit in your right mirror. Traffic is moderate and there is a wide paved shoulder a few hundred feet ahead. What is the BEST course of action?","options":["Signal early, pull completely onto the shoulder away from other traffic, shut off the engine, and inspect the source of the smoke before it gets worse.","Maintain speed and continue to the next exit, since the airflow at highway speed will likely cool the area and clear the smoke on its own.","Stop on the shoulder but leave the engine running, then immediately swing open the rear trailer doors to let the trapped smoke and heat escape.","Slow down and keep rolling on the shoulder at low speed while a passenger pours water on the rear tires to cool them without fully stopping."],"answer":0,"explanation":"Smoke or a burning smell can mean a developing fire, so get fully off the road away from traffic, shut off the engine, and inspect before it worsens.","handbook":"If you suspect a fire, pull off the road, shut off the engine, and check.","hbref":"§2.14","qid":"GK-W3-065"},"135":{"q":"You are hauling a loaded trailer on a rural two-lane highway when you roll into a dense fog bank so thick you can barely make out the lane lines a short distance ahead. Traffic is light. Which action is the safest and most correct way to handle this stretch?","options":["Switch to your high beams so the stronger light punches through the fog and lets you read the lane lines sooner.","Reduce your speed, keep your low beams on, and if you still cannot see well enough, pull completely off the road and wait for the fog to lift.","Hold your normal highway speed but lock onto the tail lights of the vehicle ahead and follow them as your guide through the fog.","Accelerate to clear the foggy section as quickly as your loaded rig will safely allow, then resume cruising speed."],"answer":1,"explanation":"In fog, slow down and use low beams because high beams reflect off water droplets and worsen glare, and pull completely off the road if you still cannot see.","handbook":"In heavy fog, slow down, use low beams, and pull off if you cannot see safely.","hbref":"§2.11","qid":"GK-W3-066"},"136":{"q":"It is late in your shift and you must reverse your 53-foot trailer into a narrow loading dock at a yard you've never visited. No spotter is available, the dock is currently empty, and you are eager to finish. Which course of action is the safest and most correct?","options":["Since the area behind you is clear right now, back in promptly at a steady speed so you finish before any forklifts or workers arrive.","Flag down a worker walking nearby and have them stand directly behind the trailer to watch and wave you in as you reverse.","Get out and walk the full path behind the trailer to check for obstacles and clearance, then back slowly using your mirrors on both sides.","Trust your mirrors alone and back at a consistent speed without getting out, since stopping to look would only slow you down."],"answer":2,"explanation":"With no spotter, use the Get-Out-And-Look method: walk the full path behind the trailer to check obstacles and clearance, then back slowly using both mirrors.","handbook":"Before backing, get out and check your path; back slowly using your mirrors.","hbref":"§2.13","qid":"GK-W3-067"},"137":{"q":"You are hauling a loaded trailer at 55 mph on a dry interstate when a stalled car suddenly appears in your lane far ahead. Your instructor later asks you to account for EVERY part of the distance your rig actually traveled from the instant the hazard came into view until you came to a complete stop. Which breakdown correctly identifies the three separate parts that together make up your total stopping distance?","options":["The distance covered during your 3/4-second reaction plus the braking distance once the brakes grab — perception time is already included in reaction time, so it is not counted separately","Only the braking distance, because that is the part where the truck is physically slowing down and is the only portion you can control","Following distance, signaling distance, and the parking gap you leave at the curb","Perception distance, reaction distance, and braking distance"],"answer":3,"explanation":"Total stopping distance is the sum of three parts: perception distance, reaction distance, and braking distance.","handbook":"Total stopping distance is perception distance plus reaction distance plus braking distance.","hbref":"§2.6","qid":"GK-W3-068"},"138":{"q":"You stopped for lunch on a long haul and a friend offers you a single beer with your meal. You feel completely sober afterward and have no trouble walking a straight line. Before you climb back into your tractor-trailer, which statement about the legal blood alcohol concentration (BAC) limit for operating your commercial vehicle is correct?","options":["You are legally over the limit and may not drive the CMV at a BAC of 0.04 percent, which is half the limit that applies to a regular passenger car.","You are legally over the limit and may not drive the CMV at a BAC of 0.08 percent, the same limit that applies to a regular passenger car.","You are fine to drive as long as your BAC stays below 0.10 percent, because larger vehicles are held to a higher threshold.","Feeling sober is what matters, so you may drive once you no longer feel impaired, regardless of any specific BAC number."],"answer":0,"explanation":"The legal BAC limit for driving a CMV is 0.04 percent, exactly half the 0.08 percent limit for a passenger car, so at 0.04 you are over the limit.","handbook":"A CMV driver is legally over the limit at 0.04 percent BAC.","hbref":"§2.20","qid":"GK-W3-069"},"139":{"q":"You just completed 10 consecutive hours off duty in the sleeper berth and start a new shift. Your dispatcher says the run is long and asks how much actual driving you can legally do before federal hours-of-service rules require you to stop driving for the day. Treating this as pure driving (no excessive on-duty delays that would close your 14-hour window early), what is the maximum driving time allowed?","options":["Up to 8 hours of driving time, because you must take a 30-minute break first","Up to 11 hours of driving time","Up to 14 hours of driving time","Up to 16 hours of driving time"],"answer":1,"explanation":"After 10 consecutive hours off duty, federal hours-of-service rules allow a maximum of 11 hours of driving time.","handbook":"After 10 consecutive hours off duty, you may drive up to 11 hours.","hbref":"§2.20","qid":"GK-W3-070"},"140":{"q":"You have been driving since well before dawn and it is now mid-afternoon. You catch yourself drifting in the lane, your eyelids are heavy, and you cannot recall the last few miles. You still have hours left on your route and a delivery window to meet. Which of the following is the ONLY action that will actually restore your alertness and safely correct this condition?","options":["Stop at the next services, drink two strong cups of coffee, and push on to stay on schedule","Roll the windows down for cold fresh air and turn the radio up loud to keep your mind active","Get off the road as soon as it is safe, stop driving, and get enough real sleep before continuing","Open an energy drink, eat a heavy meal, and increase your following distance to compensate"],"answer":2,"explanation":"Only real, sufficient sleep repays a sleep debt, so when fatigued get off the road safely, stop driving, and sleep before continuing.","handbook":"The only sure cure for fatigue is sleep; coffee and fresh air are temporary.","hbref":"§2.18","qid":"GK-W3-071"},"141":{"q":"You are running loaded on a flat, open rural highway at 55 mph in clear, dry weather. Traffic is light and you have a long uninterrupted view of the road ahead. To manage your visual lead time correctly, how far ahead should you be steadily looking and scanning for hazards?","options":["Only at the vehicle directly ahead of you, since at 55 mph anything farther away is not yet a threat","About 30 to 40 seconds ahead, so you have the maximum possible reaction time on the open highway","About 1 to 2 seconds ahead, which is roughly your safe following distance at this speed","About 12 to 15 seconds ahead, which at 55 mph is roughly a quarter mile or about one city block in town"],"answer":3,"explanation":"Keep your eyes moving and look 12 to 15 seconds ahead, which is about a quarter mile at highway speed or one block in town, to spot hazards early.","handbook":"Good drivers look 12 to 15 seconds ahead in traffic.","hbref":"§2.2","qid":"GK-W3-072"},"142":{"q":"You are hauling a loaded trailer on a busy four-lane Texas interstate at highway speed. Traffic is heavy and vehicles keep moving into your blind spots and merging around you. To keep an accurate, up-to-date picture of what is happening behind and beside your rig, how should you be using your mirrors?","options":["Glance at your mirrors only right before you change lanes or merge, since that is when blind-spot traffic matters most","Check your mirrors about every 12 to 15 seconds, matching how far ahead you look down the road","Watch your mirrors continuously and steadily so your eyes never return to the road ahead","Scan your mirrors regularly, about every 5 to 8 seconds, in addition to checking before any lane change"],"answer":3,"explanation":"Scan your mirrors regularly, about every 5 to 8 seconds, in addition to checking before any lane change, to stay aware of traffic and blind spots.","handbook":"Check your mirrors regularly, about every 5 to 8 seconds.","hbref":"§2.2","qid":"GK-W2-053"},"143":{"q":"It is a wet, gray afternoon and you must back your tractor-trailer into a tight alley dock. Visibility is poor, the right side of your trailer disappears into shadow, and you have no spotter available. To keep the maneuver as safe as possible, you should set up so that you are backing toward which side?","options":["The right (blind) side, because swinging the trailer away from you gives the tractor more turning clearance","The side carrying the most traffic, so other drivers will see you and stop for the trailer","Whichever side puts the dock closest, to shorten the distance you must travel in reverse","The driver's (left) side, so you can watch down the length of the trailer through your own window"],"answer":3,"explanation":"Backing toward your left (driver's) side lets you watch the trailer's full length through your window, so the rear and its path stay in view the whole time.","handbook":"When you must back, back toward the driver's side so you can see.","hbref":"§2.13","qid":"GK-W2-057"},"144":{"q":"During your pre-trip you are securing a single 38-foot steel beam on a flatbed. You want to use the LEAST number of tie-downs that still meets the federal minimum for length-based securement (working load limit is already satisfied). What is the fewest tie-downs the rule allows for this load?","options":["2 tie-downs, because any piece over 5 feet always needs exactly two","3 tie-downs, because you re-check securement every 3 hours","8 tie-downs, because you need one for every 5 feet of cargo length","4 tie-downs, because you need one for every 10 feet of cargo length"],"answer":3,"explanation":"Cargo needs at least one tie-down for every 10 feet of length, so a 38-foot beam rounds up to four tie-downs.","handbook":"Use at least one tie-down for every 10 feet of cargo, and at least two.","hbref":"§3.3","qid":"GK-W2-066"},"145":{"q":"It is just below freezing and you are approaching a curve on a bridge in your loaded tractor-trailer. As you turn the steering wheel to follow the curve, the front wheels lose traction on the ice. What is the MOST likely result of this front-wheel skid, and how does the vehicle respond?","options":["The vehicle continues moving straight ahead and keeps going that way no matter which direction you steer, until the front tires regain traction.","The rear drive wheels swing out to one side and the trailer begins to jackknife behind the cab.","The vehicle turns more sharply into the curve than you intended, pulling the nose toward the inside of the turn.","The steering tightens up and the front wheels grip harder, forcing the truck to over-correct in the direction you steered."],"answer":0,"explanation":"In a front-wheel skid the front tires lose traction so steering has no effect, and the vehicle keeps going straight until the front tires regain grip.","handbook":"In a front-wheel skid the vehicle goes straight even if you steer.","hbref":"§2.7","qid":"GK-W3-073"},"146":{"q":"You are driving a loaded non-ABS tractor-trailer at highway speed when a car suddenly cuts in and stops short ahead of you. You need maximum braking but must keep the rig under control and be able to steer. Using the controlled braking method, what should you do with the brake pedal?","options":["Press the pedal all the way down to lock the wheels for the shortest possible stop","Apply firm, steady pressure on the pedal just short of locking the wheels, easing off only if the wheels start to lock","Pump the pedal hard and fast over and over to keep the wheels turning","Leave the foot brake alone and use only the trailer hand valve to slow the rig down"],"answer":1,"explanation":"Controlled braking means applying firm, steady pressure just short of locking the wheels, easing off only if they start to lock so you can still steer.","handbook":"Controlled braking applies steady pressure without locking the wheels.","hbref":"§2.7","qid":"GK-W3-074"},"147":{"q":"You are descending a long, steep mountain grade with a fully loaded trailer. You selected a low gear at the top, but partway down you smell something hot, your brake pedal feels softer with each press, and the truck is gradually picking up speed despite light, steady braking. A sign ahead reads 'RUNAWAY TRUCK RAMP 1 MILE.' Considering what that ramp is built to do, which statement is correct?","options":["It is a mandatory rest area where every loaded truck must pull off to let the brakes cool before continuing down the grade.","It is a maintained shortcut that lets you leave the grade and reach the bottom faster while your overheated brakes recover.","It is an emergency escape ramp engineered to safely bring a vehicle to a stop when its brakes have failed or faded from overheating.","It is a paved pullout where you can keep slowly rolling so the brakes shed heat without ever coming to a complete stop."],"answer":2,"explanation":"A runaway truck ramp is an emergency escape ramp engineered to safely stop a vehicle whose brakes have failed or faded from overheating.","handbook":"An escape ramp safely stops a truck that has lost its brakes.","hbref":"§2.16","qid":"GK-W3-075"},"148":{"q":"You are running 55 mph on a dry interstate when a car suddenly cuts in and brakes hard ahead of you. Your instructor later asks you to separate the parts of your total stopping distance. He reminds you that your TOTAL stopping distance at this speed is roughly 419 feet. Of that total, how far does your truck travel during JUST your reaction time -- the gap between seeing the hazard and your foot actually pushing the brake pedal, before the brakes have done any slowing at all?","options":["About 419 feet, because the truck keeps rolling at full speed the entire time until it finally stops","About 250 feet, since that is roughly how far your low-beam headlights reach and how far ahead you can react","About 6 feet, because at highway speed your trained reflexes move your foot almost instantly","About 60 feet, roughly the distance covered in the three-quarters of a second it takes an average driver to react"],"answer":3,"explanation":"Reaction distance is the travel after perceiving a hazard before braking begins, about 60 feet at 55 mph during the average three-quarter-second reaction time.","handbook":"Reaction distance at 55 mph is about 60 feet.","hbref":"§2.6","qid":"GK-W3-076"},"149":{"q":"You are approaching a city intersection in your loaded combination vehicle when the traffic signal turns to a steady (non-flashing) red light. Traffic is light and you see no cross-traffic or pedestrians at the moment. Which action is legally required of you as the CDL driver?","options":["Slow to a crawl and proceed through the intersection because no cross-traffic is present","Treat the steady red exactly as you would a flashing red, yielding but not necessarily stopping if the way is clear","Come to a complete stop and remain stopped until the signal turns green","Stop only if a vehicle or pedestrian is actually in your path, otherwise continue"],"answer":2,"explanation":"A steady red light requires you to come to a complete stop and remain stopped until the signal turns green.","handbook":"At a steady red light you must come to a complete stop and wait.","hbref":"§2.4","qid":"GK-W2-023"},"150":{"q":"You are driving a loaded tractor-trailer on a dry, open highway at 55 mph when you spot a stalled car with its hood up roughly a quarter mile (12-15 seconds) ahead in your lane. Traffic in the next lane is heavy, so you cannot yet change lanes. What is the BEST first action to take?","options":["Maintain your speed and wait until you are about 200 feet away before reacting, since that gives you plenty of room","Speed up briefly to create a gap and force your way into the next lane before reaching the stalled car","Brake hard immediately to bleed off as much speed as possible before you reach the hazard","Ease off the accelerator and cover the brake so you are ready to slow smoothly as the situation develops"],"answer":3,"explanation":"When a hazard is far ahead, ease off the accelerator and cover the brake so you can slow smoothly without a panic stop.","handbook":"When you see a hazard, ease off the gas and cover the brake.","hbref":"§2.8","qid":"GK-W2-049"},"151":{"q":"You are hauling a 60-foot combination on a dry, clear two-lane highway at 35 mph and want to leave a proper following distance behind the car ahead. Based on your vehicle's length, what is the MINIMUM safe following distance you should keep in these good conditions?","options":["About 6 seconds — one second for every 10 feet of your vehicle's length","About 7 seconds — one second for every 10 feet plus one extra second for the speed","A fixed 4 seconds, since 4 seconds is the standard gap for any vehicle in good weather","No measured gap is needed at 35 mph because that speed is low enough to stop quickly"],"answer":0,"explanation":"Allow one second of following distance for every 10 feet of vehicle length, so a 60-foot combination needs about 6 seconds at speeds of 40 mph or below.","handbook":"Keep at least one second of following distance per 10 feet of length.","hbref":"§2.6","qid":"GK-W3-077"},"152":{"q":"It is early morning during your pre-trip inspection. You start the engine and watch the gauges on the dash. Within the first few moments after start-up, what should the engine oil pressure gauge (or the oil pressure warning light) do before you decide the truck is safe to drive?","options":["The oil pressure should remain at zero while the engine is cold, then build only after you have been driving for several miles.","The oil pressure should come up to a normal reading within a short time after starting (and any oil pressure warning light should go out).","The oil pressure warning light should stay lit the entire time the engine runs; that is how you know the lubrication system is active.","The oil pressure should briefly spike well above the normal range and stay there, since a higher-than-normal reading means strong lubrication."],"answer":1,"explanation":"Oil pressure should rise to the normal range shortly after starting and any oil pressure warning light should go out, confirming the lubrication system is working.","handbook":"After starting, the oil pressure should come up to normal.","hbref":"§2.1","qid":"GK-W3-078"},"153":{"q":"It is a hot afternoon and you are pulling a heavy load up a long grade in low gear. Glancing at your instrument panel, you see the needle on the coolant temperature gauge climbing well above its normal range. Based on what this specific gauge is designed to tell you, what condition is it warning you about?","options":["The fuel level in your tank is getting dangerously low and you should refuel soon","Your headlights have dimmed because the alternator is no longer charging the battery","The engine is overheating and could be damaged if you keep climbing under this load","Engine oil pressure has dropped too low to properly lubricate the moving parts"],"answer":2,"explanation":"A coolant temperature needle climbing above the normal range means the engine is overheating and could be damaged if you keep driving under load.","handbook":"The coolant temperature gauge warns of engine overheating.","hbref":"§2.1","qid":"GK-W3-079"},"154":{"q":"During your pre-trip inspection on a cold morning, you start the engine and watch the air pressure gauge. You notice the air pressure in your tanks climbs very slowly toward operating range, taking much longer than usual to build up. The compressor governor has not yet cut out. Of the following, which is the MOST likely explanation for this slow buildup?","options":["The compressor is in excellent condition and is simply protecting the system by building pressure gradually","Your air tanks are already full, so the gauge is only showing residual pressure","Your service brakes are in very good condition, which slows the rate that air enters the tanks","There is an air leak in the system or the compressor is weak, so pressure builds slower than it should"],"answer":3,"explanation":"Air pressure that builds too slowly warns of an air leak in the system or a weak compressor that cannot keep up with demand.","handbook":"Slow air pressure buildup may mean a leak or a weak compressor.","hbref":"§2.1","qid":"GK-W3-080"},"155":{"q":"It is just below freezing on an early-morning pre-trip inspection. You raise the hood and run your hand along the engine's drive belts and the radiator and heater hoses. Which finding is the actual safety defect you are inspecting for, the one that should keep this truck from going into service?","options":["Cracks, fraying, soft spots, or signs of leaking on the belts and hoses","Belts and hoses that have lost their factory shine and now look dull and dusty","Hoses that no longer display a readable manufacturer brand-name tag","A belt that is colored a darker shade than the bright color it had when new"],"answer":0,"explanation":"Inspect belts and hoses for cracks, fraying, soft spots, or signs of leaking, since this deterioration can cause a breakdown or engine failure.","handbook":"Check the engine belts and hoses for cracks, wear, or leaks.","hbref":"§2.1","qid":"GK-W3-081"},"156":{"q":"During your pre-trip inspection on a cold morning, you find a hairline crack running across one of the steel wheel rims on a rear drive axle, and on a different wheel two of the lug nuts are noticeably loose. The tires themselves still hold air and have good tread. Your dispatcher is pushing you to make the run because the load is time-sensitive. What is the correct call about driving this vehicle?","options":["Because the tires hold air and have good tread, the wheels are safe enough; you may drive carefully to the shop and have it looked at after delivery.","The cracked rim and the loose lug nuts are out-of-service defects; the vehicle must not be driven until they are repaired.","Snug the loose lug nuts by hand and watch the cracked rim; if the crack does not grow within the first 50 miles, you may continue the trip.","It is only a problem on the steering axle; since these are rear drive wheels, a cracked rim and loose lugs there are minor wear and the vehicle is fine to operate."],"answer":1,"explanation":"Cracked rims and loose lug nuts are out-of-service defects, so the vehicle must not be driven until they are repaired.","handbook":"Cracked rims or loose lug nuts are out-of-service defects.","hbref":"§2.1","qid":"GK-W3-082"},"158":{"q":"During your pre-trip inspection in the yard, you find a fresh puddle of fluid on the pavement directly beneath the tractor. The reservoirs still read within their normal range and the truck starts and runs fine. You are already running behind schedule for your delivery window. What is the correct course of action?","options":["Note the fluid level, top off the reservoir to be safe, and continue the trip since the gauges read normal","Leave it alone for now and re-check the puddle at your first stop within the first 50 miles to see if it is getting worse","Do not drive until you locate the source of the leak and have it repaired, even if it makes you late","Wipe up the puddle, log the inspection as satisfactory, and monitor the gauges closely as you drive"],"answer":2,"explanation":"A known fluid leak is a defect that can fail catastrophically, so do not drive until you find the source and have it repaired, even if it makes you late.","handbook":"Find and fix any leaking fluids under the vehicle.","hbref":"§2.1","qid":"GK-W3-083"},"159":{"q":"It is just before dawn and you are doing your pre-trip walk-around. Several rear reflectors and two of your tail/clearance lamps are caked with dried road grime, and one tail lamp lens looks dim even when the lights are switched on. The truck is otherwise loaded and ready to roll. Which action best meets the inspection standard for lights and reflectors before you leave?","options":["Leave the reflectors alone since they are passive devices, but replace any tail lamp bulb that fails to light up","Wipe off only the lamps that are electrically powered, because reflectors do not need to be clean to do their job","Cover the dim or grimy lenses with tape so they are not mistaken for a burned-out lamp, then drive to a shop","Clean the grime off all lamps and reflectors and confirm each one is functioning before the trip"],"answer":3,"explanation":"All lamps and reflectors must be both clean and working before a trip, since dirt keeps a reflector from reflecting and a lamp from being seen.","handbook":"Check that all lights and reflectors are clean and working.","hbref":"§2.1","qid":"GK-W3-084"},"160":{"q":"You arrive at your truck in the yard to begin your pre-trip inspection. You are eager to get rolling, so you start mentally listing what to do first: warm up the engine, walk the area, test the brakes, check the lights. Before you touch anything on the vehicle, which action correctly belongs at the very FIRST step of the inspection method?","options":["Do a general overview by approaching the vehicle on foot, noting its general condition, posture/lean, fresh fluid puddles under it, and any hazards around it before you get in","Start the engine and let it warm to operating temperature so gauges read accurately while you walk around","Perform the applied-pressure service brake test by pulling forward at about 5 mph and pressing the brake pedal","Walk to the front and rear and confirm all exterior lights and reflectors are clean, the correct color, and working"],"answer":0,"explanation":"Start the pre-trip inspection with a walk-up overview, checking the vehicle's posture, fluid puddles, and surrounding hazards before getting in.","handbook":"The first step of a pre-trip inspection is the vehicle overview.","hbref":"§2.1","qid":"GK-W3-085"},"161":{"q":"You are driving a loaded tractor-trailer with a standard (non-synchronized) manual transmission and need to move from 5th gear up to 6th as you accelerate on a level highway. To make this upshift cleanly without grinding the gears, what is the correct technique for the type of transmission found in many trucks?","options":["Press the clutch only partway (\"clutch braking\") and force the lever into the next gear","Hold the clutch fully down through the entire shift while feathering the accelerator","Keep one hand firmly on the wheel and shift without using the clutch at all once you are rolling","Double-clutch: release the accelerator, push in the clutch, shift to neutral, release the clutch, then push in the clutch again and shift to the higher gear"],"answer":3,"explanation":"Double-clutch to upshift: release the accelerator, push in the clutch and shift to neutral, release the clutch, then push it in again and shift to the higher gear.","handbook":"Many trucks require double-clutching to shift gears.","hbref":"§2.3","qid":"GK-W2-051"},"162":{"q":"You are hauling a loaded trailer and the road ahead drops into a long, steep mountain grade. You want to control your speed safely on the way down without overheating your brakes. At which point should you complete your shift into a low gear?","options":["Before you start down the grade, while you are still on level ground at the top","While you are already descending, as soon as you feel the truck picking up speed","At the bottom of the grade, once the road flattens back out","Only after light, steady brake pressure stops slowing you down"],"answer":0,"explanation":"Shift into a low gear before starting down a long, steep grade while still on level ground, since engine braking is the main speed control and service brakes only supplement it.","handbook":"Shift to a lower gear before starting down a steep hill.","hbref":"§2.3","qid":"GK-W2-052"},"163":{"q":"You are hauling a loaded trailer down a long mountain grade. Your truck is equipped with a retarder, and you switch it on as you begin the descent. Which statement BEST describes what the retarder is doing for you here?","options":["It increases your engine power so you can pick up speed and clear the grade more quickly","It applies extra braking force to help slow the vehicle, which reduces wear and heat buildup on the service brakes","It tightens your steering response so the truck corners more easily through the curves on the grade","It is the primary control for the descent, so you no longer need to select a low gear before starting down"],"answer":1,"explanation":"A retarder applies extra braking force to slow the vehicle, reducing wear and heat buildup on the service brakes.","handbook":"A retarder helps you slow down and saves wear on the brakes.","hbref":"§2.3","qid":"GK-W3-086"},"164":{"q":"It is just below freezing and a light glaze has formed on the bridges along your route. Your tractor is equipped with an engine (speed) retarder that engages the drive axles when you let off the throttle. As you ease off the accelerator to slow for a curve on this slick surface, what is the correct way to manage that retarder?","options":["Leave the retarder switched fully on, since its braking acts only on the drive wheels and therefore cannot upset the steer axle","Apply the retarder hard and early so you can avoid touching the foot brake at all on the ice","Use it very carefully or switch it off, because on a slippery surface the retarder can cause the drive wheels to lose traction and skid","Remove or disable the retarder during your pre-trip whenever any ice is in the forecast"],"answer":2,"explanation":"On a slippery surface, use the retarder carefully or switch it off, because it can make the drive wheels lose traction and skid.","handbook":"On a slippery road, use a retarder carefully or turn it off.","hbref":"§2.3","qid":"GK-W3-087"},"165":{"q":"You are backing your trailer into a tight loading dock at night. There is no helper available to spot you, and the dock area is partly blocked from view by parked trailers. Which procedure is the safest and most correct way to complete the maneuver?","options":["Back as quickly as possible to spend the least time obstructing the lane, keeping the trip short","Rev the engine and ride the clutch so you can power straight in without rolling back","Fix your eyes only on the driver-side mirror, since the passenger side is your blind side and not worth checking","Back slowly, using both mirrors, and pull forward to reposition whenever you lose sight of where you are going"],"answer":3,"explanation":"Back slowly using both mirrors, and pull forward to reposition whenever you lose sight of where you are going.","handbook":"When backing, go slowly and use your mirrors.","hbref":"§2.13","qid":"GK-W3-088"},"167":{"q":"You are approaching a busy intersection where you intend to make a right turn into a loading dock. Traffic is heavy and a small car is beginning to creep up alongside your tractor on the right. To communicate your intentions safely and prevent that car from being squeezed against the curb, when should you activate your turn signal?","options":["Early, well before you begin the turn, so other drivers have time to react","As you start to swing the wheel into the turn, so the timing matches your movement","Only after you have completed the turn, to avoid confusing nearby drivers","Only at night or in low-visibility conditions, when signals are most needed"],"answer":0,"explanation":"Signal early, well before you begin the turn, so other drivers have time to react.","handbook":"Signal early, before you turn.","hbref":"§2.4","qid":"GK-W3-089"},"168":{"q":"You are making a slow, wide left turn from a city street into a loading dock driveway. Halfway through the turn, the steering wheel partially recenters and your turn signal clicks off on its own. There is a car waiting at the cross street and a cyclist approaching from behind. What is the correct way to handle your signal for the rest of this maneuver?","options":["Cancel the signal as soon as the front of your tractor has entered the driveway, since the turn is essentially committed","Re-activate the signal and keep it flashing until you have fully completed the turn and your vehicle is straight","Leave the signal off now and instead tap your brakes a couple of times to communicate your intention to the cyclist","Signal only for the first second of the turn, which is all the law requires before you commit to the maneuver"],"answer":1,"explanation":"Keep signaling continuously until the turn is fully completed and your vehicle is straight, since the trailer needs the whole arc to track through.","handbook":"Keep signaling through the entire turn.","hbref":"§2.4","qid":"GK-W3-090"},"169":{"q":"You are hauling a loaded trailer on a busy four-lane highway and you see slow traffic backing up about a quarter mile ahead. You will need to reduce speed soon, and a line of cars is following close behind you. Which action BEST communicates to the drivers behind that you are about to slow down?","options":["Quickly turn your headlights and tail lights off and back on to get their attention","Sound your horn two short times so following drivers know to expect a change","Lightly tap the brake pedal a few times to flash your brake lights early","Accelerate briefly to open space ahead, then brake hard once the gap closes"],"answer":2,"explanation":"To warn drivers behind that you are slowing, lightly tap the brake pedal a few times to flash your brake lights early.","handbook":"Tap the brake pedal to warn drivers behind that you will slow.","hbref":"§2.4","qid":"GK-W3-091"},"171":{"q":"It is just past dawn and the sun is low on the horizon. The light is dim and gray, and you notice other drivers and shapes are getting harder to pick out against the road. You are running on time and visibility is not yet completely gone. To both see the road and, just as importantly, be seen by other traffic in this twilight, which action is the single best choice?","options":["Switch on your interior cab dome light so the dim conditions outside are easier to judge from inside","Leave all exterior lights off, since there is still enough natural daylight to see the road ahead","Turn on only your four-way hazard flashers to alert other drivers that visibility is poor","Turn on your headlights so you can see ahead and other drivers can clearly see your vehicle"],"answer":3,"explanation":"At dawn or dusk, turn on your headlights so you can see the road ahead and other drivers can clearly see your vehicle.","handbook":"Turn on your headlights at dawn or dusk.","hbref":"§2.4","qid":"GK-W3-092"},"172":{"q":"You are hauling a loaded trailer in moderate traffic at 55 mph. A four-wheeler suddenly cuts in front of you and brakes hard, and you realize you have closed up the cushion of space ahead of your bumper. Why does keeping that space in front of you matter most in this moment?","options":["It gives you the room you need to either brake to a stop or steer around a hazard safely","It lets you maintain a higher cruising speed without using your brakes as much","It conserves fuel because you brake and accelerate less in steady traffic","It discourages other drivers from cutting in and crowding your lane"],"answer":0,"explanation":"Space ahead is your escape margin, giving you the room to either brake to a full stop or steer around a hazard safely.","handbook":"Keep space in front so you can stop or steer safely.","hbref":"§2.7","qid":"GK-W3-093"},"173":{"q":"You are driving a loaded combination on a busy two-lane highway at 50 mph when you notice a four-wheeler has pulled in close behind you and is tailgating, staying only a car length or two off your bumper. Traffic ahead is moving steadily but could slow at any time. Which of the following is the BEST way to manage this hazard?","options":["Lightly tap your brakes to flash your brake lights and signal the tailgater to back off","Open up more room ahead of you by gradually easing off the accelerator and increasing your following distance, so you can brake gently if traffic slows","Maintain your speed and hold your lane position, since the tailgater is responsible for the space behind your vehicle","Accelerate to pull away from the tailgater and re-establish a safe gap"],"answer":1,"explanation":"When tailgated, gradually ease off the accelerator to open more room ahead so you can brake gently instead of suddenly if traffic slows.","handbook":"If a tailgater follows too closely, increase your following space ahead.","hbref":"§2.7","qid":"GK-W3-094"},"174":{"q":"You are traveling at highway speed in the center lane of a three-lane interstate. A car has settled in beside your tractor on the right and is holding that position, neither passing nor dropping back, riding even with your cab. Why is staying in this side-by-side arrangement the LEAST desirable situation for you as the driver?","options":["Running parallel forces both vehicles to burn noticeably more fuel, so it raises your operating costs over a long trip","Texas law specifically prohibits two vehicles from traveling abreast in adjacent lanes on a controlled-access highway","The car is likely sitting in one of your blind spots, so if you needed to change lanes you might not see it and could merge into it","Holding even with another vehicle wastes your time because you cannot use the lane-change to make forward progress"],"answer":2,"explanation":"A vehicle riding alongside often sits in a side blind spot where you cannot see it, so you could merge into it during a lane change.","handbook":"Avoid driving alongside others because you may be in a blind spot.","hbref":"§2.7","qid":"GK-W3-095"},"175":{"q":"You are driving a loaded box truck on an unfamiliar route when you see a posted overpass clearance of 13 feet 2 inches just ahead. To safely decide whether you can pass under it without striking the structure, the single MOST important thing you must already know is:","options":["The gross vehicle weight rating (GVWR) stamped on your door, so you do not exceed a posted bridge weight limit","Your total stopping distance at this speed, which is about 419 feet at 55 mph","The length of your vehicle, so you can fully clear the structure before stopping","Your loaded vehicle height, including any cargo or equipment mounted on top"],"answer":3,"explanation":"You must know your actual loaded height, including roof-mounted cargo or equipment, to compare it against a posted overpass clearance.","handbook":"Know your vehicle's height before going under a low bridge.","hbref":"§2.7","qid":"GK-W3-096"},"176":{"q":"You are driving a 53-foot tractor-trailer and need to make a right turn from a city street onto a narrow side road. As you approach the corner, you realize the turn is sharper than you expected. What is the SAFEST way to keep enough space to complete this turn?","options":["Stay in your proper lane on the approach, then turn wide as you COMPLETE the turn so the off-tracking trailer can clear the corner, keeping the rear of the trailer close to the curb throughout","Swing into the left lane first and start the turn early so the rear of the trailer cuts the corner tightly and stays close to the curb","Speed up through the turn so you spend less time blocking the intersection and clear it quickly","Keep the truck tight to the right curb the entire time so no other vehicle can squeeze into the gap on your right"],"answer":0,"explanation":"Because the trailer's rear wheels off-track, stay in your lane on approach and turn wide as you complete the turn, keeping the trailer rear near the curb.","handbook":"Plan your turn and use enough room to make it.","hbref":"§2.7","qid":"GK-W3-097"},"177":{"q":"You are stopped at a stop sign in a fully loaded combination vehicle, waiting to cross a busy two-lane highway where traffic is moving at 55 mph in both directions. A gap is opening up in the cross traffic. Because your rig is heavy and accelerates slowly, what must that gap allow you to do before you commit to pulling out?","options":["Roll your front bumper just past the near edge so oncoming drivers can see you and slow down","Get your entire vehicle fully across the road, or up to the speed of traffic, before the next vehicle reaches you","Reach the center of the intersection and come to a complete stop to judge the second lane","Pull in and idle in the lane just long enough for the approaching driver to change lanes around you"],"answer":1,"explanation":"Choose a gap big enough to get your whole vehicle fully across or up to traffic speed before an approaching vehicle reaches you.","handbook":"Cross or enter traffic only with a gap big enough to get across or up to speed.","hbref":"§2.7","qid":"GK-W3-098"},"178":{"q":"You are merging your tractor-trailer onto a busy interstate during heavy afternoon traffic. A line of passenger cars keeps drifting along your right side, lingering near your rear wheels where your mirrors give you almost nothing. Several drivers seem comfortable settling into that pocket beside and behind your trailer. Regarding these blind-spot areas (the 'No-Zones') around your rig, which approach best reflects safe commercial driving practice?","options":["Treat the No-Zones as normal travel lanes and let cars sit there, since they chose to be there and the responsibility is theirs","Speed up sharply to push the cars out of the right-rear No-Zone, because clearing the pocket quickly is always the safest fix","Recognize that you cannot see vehicles in the No-Zones and manage your driving to keep those areas clear of traffic whenever possible","Drift slowly into the cars' blind spots in return so the risk is shared equally between you and the four-wheelers"],"answer":2,"explanation":"You cannot see vehicles in the No-Zones, so manage your speed, lane position, and spacing to keep those blind-spot areas clear of traffic.","handbook":"Blind-spot No-Zones around a truck should be avoided when possible.","hbref":"§2.7","qid":"GK-W3-099"},"179":{"q":"You are driving a fully loaded combination vehicle and merge onto a long, steep uphill grade in the right lane. As you climb, your engine is straining and your speed steadily drops well below the posted limit, while faster cars and lighter vehicles begin stacking up behind you. Which of the following is the BEST way to manage your truck on this upgrade?","options":["Move into the far left lane so the slower vehicles behind you can pass on the right without changing lanes","Downshift and accelerate hard to keep your speed at the posted limit so you do not impede the faster traffic behind you","Maintain your speed but pull onto the right shoulder and stop briefly to let the line of vehicles clear before continuing","Accept that the heavy load will slow you down, stay in the right lane, and let faster traffic pass you on the left"],"answer":3,"explanation":"A heavy load naturally slows you on a steep grade, so stay in the right lane and let faster traffic pass on the left.","handbook":"A heavy load on a long uphill grade slows you; keep to the right.","hbref":"§2.7","qid":"GK-W3-100"},"180":{"q":"You are driving a 53-foot tractor-trailer on a three-lane highway in moderate traffic. A car is riding alongside you in the left lane, and on your right an on-ramp is feeding vehicles onto the freeway. You cannot give up space on both sides at once. Which action BEST manages your space to the sides in this situation?","options":["Keep your rig centered in your lane so you preserve a cushion of space on both sides rather than committing all your room to one side","Move over and hug the left lane line to put maximum distance between your trailer and the merging on-ramp traffic","Straddle the lane line into the left lane briefly so no vehicle can pull up beside your blind spots","Ease onto the right shoulder until the on-ramp traffic has finished merging, then return to your lane"],"answer":0,"explanation":"Keeping your rig centered in the lane preserves a space cushion on both sides when threats come from the left and right at once.","handbook":"Stay centered in your lane to keep space to the sides.","hbref":"§2.7","qid":"GK-W3-101"},"181":{"q":"You are approaching a railroad crossing in heavy stop-and-go traffic. The crossing has no gate and no flashing signals, and the vehicles ahead are crawling forward slowly. Your 73-foot combination is the next vehicle to reach the tracks. What is the single best way to decide whether to proceed across the rails?","options":["Edge forward onto the tracks and wait there, since there is no gate and no signal warning of a train","Wait until there is a gap large enough to drive completely across without stopping, leaving room for your full length plus about 15 feet of clearance","Proceed onto the crossing as soon as the vehicle ahead moves, because keeping traffic flowing is the priority","Begin crossing and, if traffic stalls, shift into a lower gear on the rails to power across quickly"],"answer":1,"explanation":"Never start across tracks unless the gap lets you clear them fully without stopping, allowing for your full length plus about 15 feet.","handbook":"Cross railroad tracks only with a gap to clear them without stopping.","hbref":"§2.15","qid":"GK-W3-102"},"182":{"q":"You are driving a loaded combination vehicle on a dry two-lane highway and see a sharp curve posted ahead. You are currently traveling near the legal speed and feel your current speed might be a little too fast for the turn. To handle the curve safely, what should you do about your speed and braking?","options":["Maintain your speed up to the curve, then brake hard once you are in the middle of the curve where the turn is tightest.","Wait until you have exited the curve, then slow down so you are ready for the next one.","Reduce to a safe speed before you enter the curve, then accelerate gently through it to keep the vehicle stable.","Keep a steady speed into the curve and rely on light, steady brake pressure throughout the turn to control the truck."],"answer":2,"explanation":"Slow to a safe speed before entering a curve, then accelerate gently through it, since braking inside a curve can cause a skid or rollover.","handbook":"Slow down before you enter a curve.","hbref":"§2.6","qid":"GK-W3-103"},"183":{"q":"You are hauling a load on a rural two-lane highway when a steady rain begins and the pavement turns shiny and wet. Traffic is moving at the 55 mph posted limit, and you feel your steering go slightly light through a long sweeping curve. Which action is the single safest response to the reduced traction?","options":["Maintain 55 mph but increase your following distance to compensate, since the posted limit is still legal","Lightly accelerate through the curve to keep weight on the drive axles and improve grip","Keep your speed and pump the brakes rapidly to test how much traction remains","Reduce your speed below the posted limit because wet pavement cuts traction and lengthens stopping distance"],"answer":3,"explanation":"Traction, not the posted limit, sets a safe speed, and wet pavement cuts traction and lengthens stopping distance, so slow below the limit.","handbook":"On a wet road, slow down because traction is reduced.","hbref":"§2.6","qid":"GK-W3-104"},"184":{"q":"It is just below freezing and a light snow has begun sticking to the roadway. You are driving a loaded tractor-trailer at the same highway speed you held in clear, dry weather earlier today. Compared with those dry conditions, what is the MOST important change you should expect in how your vehicle handles, and why?","options":["Traction is greatly reduced, so your tires grip the road far less and you need much more distance to stop and steer","Traction is only slightly reduced, so keeping a normal following distance and a steady speed will be enough to stay safe","Traction stays about the same as on dry pavement because the weight of the loaded trailer presses the tires firmly onto the snow","Traction actually improves slightly because the thin snow layer fills surface gaps and gives the tires more to bite into"],"answer":0,"explanation":"Snow and ice sharply reduce traction, so your tires grip far less and you need much more distance to stop and steer.","handbook":"On snow or ice, traction is greatly reduced.","hbref":"§2.6","qid":"GK-W3-105"},"185":{"q":"You just dropped your full load at the dock and are now deadheading back to the yard with a completely empty trailer. On wet pavement, an SUV cuts in front of you and you have to brake hard. Compared with when you were fully loaded earlier, why might your truck actually need a LONGER distance to stop now that it is empty?","options":["An empty rig is heavier, so its added momentum carries it farther before it can stop","With little weight pressing the tires onto the road, the empty truck has less traction, so the wheels lock up more easily and braking distance increases","Empty trailers ride higher, raising the center of gravity and lengthening the braking distance","Empty brakes run cooler and fade, which adds about 60 feet to the stopping distance at 55 mph"],"answer":1,"explanation":"An empty truck has little weight pressing the tires down, so they grip less, lock up more easily, and the braking distance increases.","handbook":"Empty trucks have less traction and can take longer to stop.","hbref":"§2.6","qid":"GK-W3-106"},"186":{"q":"You are hauling a fully loaded trailer down a long, steep mountain grade. Halfway down, you notice you are riding the brake pedal continuously just to hold your speed, and the cab is starting to smell hot. Which statement BEST describes what is happening to your main service brakes and why?","options":["The brakes are gaining stopping power as they warm up, so you can safely apply them harder for the rest of the descent.","The brakes are cooling themselves through continuous airflow, so steady pedal pressure is the correct primary way to control your speed.","The brakes are overheating and beginning to fade, which is why low-gear engine braking should be the primary control and the brakes only a supplement.","The brakes are about to lock the trailer wheels, so you should pump the pedal rapidly to prevent the trailer from jackknifing."],"answer":2,"explanation":"On a long downgrade brakes can overheat and fade, so low-gear engine braking must do the primary work with brakes used only as a supplement.","handbook":"On a long downgrade, the main brakes can overheat and fade.","hbref":"§2.16","qid":"GK-W3-107"},"187":{"q":"You are at the top of a long, steep mountain grade hauling a heavy, fully loaded trailer. Rain is falling and the road curves sharply about halfway down. Before you release the brakes and begin your descent, you must decide on a safe speed for going down. Which of the following correctly describes what your safe descent speed should depend on?","options":["Only the steepness of the grade, since gravity is the single factor that controls how fast a truck will roll downhill","Mainly the engine RPM at the top of the hill, because matching the tachometer reading sets the correct speed for any grade","Almost entirely the posted speed limit, since that number is set specifically for fully loaded commercial vehicles on that grade","The total weight of your vehicle and cargo, the length and steepness of the grade, the road conditions, and the weather"],"answer":3,"explanation":"A safe descending speed depends on the total weight of the vehicle and cargo, the length and steepness of the grade, the road conditions, and the weather.","handbook":"Safe speed on a downgrade depends on weight, length, and the road.","hbref":"§2.16","qid":"GK-W3-108"},"188":{"q":"You are about to start down a long, steep mountain grade with a fully loaded trailer. You want to control your speed without overheating and fading your brakes on the way down. Which approach is the best way to decide what gear to use?","options":["Use the same low gear you would need to climb the grade, and select it before you start down.","Shift into a much higher gear than you climbed in so the engine runs easier on the descent.","Put the transmission in neutral and rely on steady brake pressure to hold your speed.","Stay in your normal highway gear and only downshift if the brakes start to fade."],"answer":0,"explanation":"Select the same low gear you would use to climb the grade, and choose it before you start down.","handbook":"Descend a grade in the same gear you would use to climb it.","hbref":"§2.16","qid":"GK-W3-109"},"189":{"q":"It is early morning and the outside temperature gauge reads just below freezing (about 30 F). The two-lane highway you are driving looks completely dry, and you have had no traction problems for the last hour. You are now approaching a long overpass that spans a river valley. Which of the following is the SAFEST assumption to make as you reach the overpass?","options":["Because the road surface has stayed dry and you have had good traction, the overpass deck will be no more slippery than the pavement you just left","The overpass may be icy even though the rest of the road is clear, because bridges and overpasses freeze before other parts of the road","The overpass will freeze last of all, so it is the safest place to brake or downshift if you need to slow down","Overpasses do not freeze any sooner than regular pavement, so you only need to watch for ice once the air warms in the afternoon"],"answer":1,"explanation":"Bridges and overpasses freeze before other parts of the road, so an overpass may be icy even when the rest of the pavement is clear.","handbook":"Bridges and overpasses freeze before other parts of the road.","hbref":"§2.6","qid":"GK-W3-110"},"190":{"q":"A steady rain has just begun after a long dry spell, and a thin film of water is collecting on the highway over the old oil and dust. Traffic is light, so you are tempted to hold a higher speed. To keep your tires gripping the road and avoid hydroplaning, at roughly what speed should you understand that hydroplaning can BEGIN, so you slow below it in these conditions?","options":["Hydroplaning cannot begin until you reach about 70 mph, so any highway speed under that is safe in the rain.","Hydroplaning only becomes a concern at very low speeds, around 5 mph, so it is mainly a parking-lot problem.","Hydroplaning can begin at speeds as low as about 30 mph, so you should reduce your speed below that on this wet, slick film.","Hydroplaning will not start until you are above about 90 mph, far higher than any legal truck speed."],"answer":2,"explanation":"Hydroplaning can begin at speeds as low as about 30 mph on a wet, slick film, so reduce your speed below that.","handbook":"Hydroplaning can happen at speeds as low as about 30 mph.","hbref":"§2.6","qid":"GK-W3-111"},"191":{"q":"You are running a loaded trailer at highway speed on a Texas interstate during a heavy summer downpour. Standing water has collected in the ruts of the travel lane. Suddenly the steering feels light and loose, your front tires seem to lose contact with the pavement, and your speedometer flickers even though you have not changed throttle. You realize you are starting to hydroplane. What is the correct first action?","options":["Press the brake pedal firmly and hold it to scrub off speed as quickly as possible, since stopping distance is what matters most on a wet road","Steer briskly toward the higher, drier crown of the lane to get your tires back onto pavement with better traction","Maintain your current speed but downshift to use engine braking, since the drive wheels still have grip on the wet surface","Release pressure on the accelerator, hold the steering wheel straight, and let the vehicle slow until the tires regain firm contact with the road"],"answer":3,"explanation":"When hydroplaning, ease off the accelerator, hold the wheel straight, and let the vehicle slow until the tires regain firm contact with the road.","handbook":"If you hydroplane, ease off the gas and keep the wheel straight.","hbref":"§2.6","qid":"GK-W3-112"},"192":{"q":"It is mid-July in West Texas and the pavement is shimmering with heat. You have been running at highway speed for two hours and pull over for your required cargo and securement check. While you are stopped, what tire condition is MOST important for you to be watching for in these conditions?","options":["Tread that has worn below 4/32 inch on your rear drive tires","Faded sidewall lettering and missing brand markings on the casing","Slightly low pressure that you should top off to the cold-inflation number right now","Tires running hot with pressure that has climbed above the cold setting, signaling blow-out risk"],"answer":3,"explanation":"In hot weather watch for tires running hot with pressure that has risen above the cold setting, since overheated, over-pressured tires are prone to blowouts.","handbook":"In hot weather, check tires for overheating and high pressure.","hbref":"§2.11","qid":"GK-W2-035"},"193":{"q":"It is 28 degrees F at the start of your shift and a wet overnight snow has frozen onto your tractor. During your pre-trip walk-around you find a thin glaze of ice over the lower half of the windshield and a crust of frozen snow on both West Coast mirrors. You are already running behind schedule. Before you pull out onto the highway, what does Texas DPS require you to do?","options":["Fully remove all ice and frozen snow so the windshield and both mirrors are completely clear before driving","Clear only the driver's-side area you look through and leave the mirrors, since the defroster will melt them once you are moving","Scrape a small viewing patch in the windshield and rely on your backing camera and shoulder checks instead of the iced mirrors","Leave the glaze in place because at 28 degrees it is above the point where ice affects traction, and drive at reduced speed"],"answer":0,"explanation":"Fully remove all ice and frozen snow so the windshield and both mirrors are completely clear before driving.","handbook":"Keep the windshield and mirrors clear of ice and snow in winter.","hbref":"§2.11","qid":"GK-W3-113"},"194":{"q":"It is just below freezing on a damp morning, and during your pre-trip walk-around the pavement under your tractor looks merely wet and shiny rather than icy. As you pull onto the highway you feel the steering go light and the truck drift slightly. Why is the 'black ice' you have likely driven onto so dangerous in exactly this kind of situation?","options":["It forms a visibly rough, crusted surface, so you can spot it early and brake hard before reaching it","It is a thin, clear layer that makes the road look only wet, so you cannot see it and may not realize the surface is frozen until you lose traction","It only collects on the crowns of hills, so the danger is limited to short, predictable sections of the route","It always appears as a thick white coating, giving you plenty of warning to slow down in advance"],"answer":1,"explanation":"Black ice is a thin, clear layer that makes the road look only wet, so you cannot see it and may not realize the surface is frozen until you lose traction.","handbook":"Black ice is dangerous because it is thin and nearly invisible.","hbref":"§2.11","qid":"GK-W3-114"},"195":{"q":"It is just after dawn and you are hauling a loaded trailer through a low river valley where dense, patchy fog has dropped visibility to roughly the length of your rig. You decide to keep moving slowly rather than stop on the traveled lane. Which lighting choice gives you the best vision and makes you most visible to others?","options":["Switch to high beams, since the brighter light will cut deeper into the fog ahead","Turn off your headlights and run only your four-way hazard flashers to avoid glare","Use your low beams (along with fog lights if equipped), because high beams reflect off the fog and bounce light back at you","Leave the high beams on but dim them only when you are within 500 feet of an oncoming vehicle"],"answer":2,"explanation":"Use low beams in fog because high beams reflect off the suspended water droplets and bounce glare back at you, reducing what you can see.","handbook":"Use low beams when driving in fog.","hbref":"§2.11","qid":"GK-W3-115"},"196":{"q":"It is a dark, moonless night on a rural two-lane highway with no streetlights. Your low beams light up roughly 250 feet of road ahead. To drive safely, how should you choose your speed?","options":["Match the posted daytime speed limit, since the limit is set for the road and does not change after dark","Pick a speed at which your total stopping distance equals twice the distance your headlights show, giving you a safety cushion","Hold a steady 55 mph and rely on your high beams to react in time to anything ahead","Drive slowly enough that you can come to a complete stop within the distance lit by your headlights"],"answer":3,"explanation":"Never overdrive your headlights; keep your speed low enough to stop within the distance your headlights actually light up ahead.","handbook":"At night, drive so you can stop within the range of your headlights.","hbref":"§2.11","qid":"GK-W3-116"},"197":{"q":"You are driving a loaded combination vehicle on a rural two-lane highway in the late afternoon when a sudden, heavy downpour cuts your visibility to a few hundred feet. Traffic is sparse but oncoming vehicles still appear from time to time, and you want both to see the road and to be seen. Which headlight setting is the best choice for these heavy-rain conditions?","options":["Low beams, because they help others see you without reflecting glare back off the heavy rain","High beams, because the extra distance they light up is needed to see through the heavy rain","Headlights off with only parking lights on, so the wet road surface does not create distracting reflections","High beams flashed on and off to warn oncoming traffic that visibility is poor"],"answer":0,"explanation":"Use low beams in heavy rain so other drivers can see you while avoiding the glare that high beams create when their light reflects off the rain.","handbook":"Use low-beam headlights in heavy rain.","hbref":"§2.11","qid":"GK-W3-117"},"198":{"q":"It is mid-afternoon in a Texas heat wave and the pavement temperature has been climbing all day. As you slow for a shaded intersection, you notice dark, shiny streaks of tar oozing up through the asphalt seams in the travel lane ahead. Based on how very hot weather affects the road surface, which hazard should you be MOST prepared for as you pass over these patches?","options":["The tar will have hardened into a rough, high-grip surface, so you can brake harder than normal","The bleeding tar can make the road surface slippery, so reduce speed and avoid hard braking or sharp steering over it","The patches are forming black ice, so the surface look that is wet means it is actually frozen","Heat will have raised tire pressure enough that traction over the tar is improved, so no speed change is needed"],"answer":1,"explanation":"In very hot weather tar bleeds to the surface and becomes slippery, so reduce speed and avoid hard braking or sharp steering across it.","handbook":"In very hot weather, tar in the road may bleed and become slippery.","hbref":"§2.11","qid":"GK-W3-118"},"199":{"q":"It is a gusty, windy afternoon and you are about to leave with a tall, lightly loaded box trailer on an exposed stretch of interstate. A coworker tells you not to worry because an empty, high trailer 'handles itself' better in wind. Considering how strong crosswinds act on a high-profile trailer, what should you actually expect about controlling your rig?","options":["The tall trailer will be easier to control, because its height keeps it planted against the wind","The tall trailer will come to a stop faster, since the wind helps push against your forward motion","The tall trailer will be harder to control, because strong winds push against its large, high surface area","The tall trailer will use less fuel, because the wind reduces the load on your drive axle"],"answer":2,"explanation":"Strong winds push against the large, high side surface of a tall trailer, making the rig harder to control, especially when it is empty or lightly loaded.","handbook":"Strong winds make a high trailer harder to control.","hbref":"§2.11","qid":"GK-W3-119"},"200":{"q":"It is just below freezing and a light rain has been falling. As you approach a shaded bridge, the pavement ahead suddenly looks wet and glossy even though your mirrors and antenna have started to ice over. Which action is the safest way to handle your loaded rig through this stretch?","options":["Keep your current speed but pump the brakes a few times now to test how much traction the surface still has","Maintain your speed and simply add extra following distance, since bridges thaw faster than the open road","Accelerate smoothly to get across the bridge quickly before the surface can freeze any harder","Reduce your speed well before the bridge and use smooth, gentle steering, braking, and acceleration"],"answer":3,"explanation":"A wet, glossy look with ice on mirrors and antenna signals black ice, and bridges freeze first, so slow down early and use smooth, gentle inputs.","handbook":"On a slippery road, slow down and act gently.","hbref":"§2.11","qid":"GK-W3-120"},"201":{"q":"It is a moonless night and you are about to leave a poorly lit truck stop for a 4-hour run on a rural two-lane highway. During your walk-around you notice both headlight lenses are coated with a film of road grime and dried bug splatter, cutting their brightness noticeably. What is the BEST action before you pull out?","options":["Clean the headlight lenses so they project their full light and you can see far enough ahead to stop in time","Leave for now and simply reduce your speed so your low beams still cover the road as you drive","Run your high beams the whole trip to make up for the dimmer dirty lenses","Skip cleaning them and rely on the marker and clearance lights to mark your path"],"answer":0,"explanation":"Dirty headlight lenses cut how far your low beams reach, so clean them to restore full light and see far enough ahead to stop in time.","handbook":"Clean dirty headlights so you can see at night.","hbref":"§2.11","qid":"GK-W3-121"},"202":{"q":"You are hauling a loaded trailer down a long, steep mountain grade. Partway down, you press the brake pedal and it sinks toward the floor with almost no slowing effect, and you can smell something burning. Your speed is starting to creep up. What is the BEST action to take?","options":["Pump the brake pedal hard and fast to build the pressure back up, then keep coasting in your current gear","Downshift to a lower gear to let engine braking slow you, and steer for the next escape ramp","Shift into neutral to protect the transmission and let the truck roll until the grade flattens out","Pull hard onto the left shoulder and set out three reflective triangles at 10, 100, and 200 feet"],"answer":1,"explanation":"When service brakes fade on a downgrade, downshift to a lower gear to use engine braking and steer for an escape ramp to slow safely.","handbook":"If brakes fail on a downgrade, downshift and use an escape ramp.","hbref":"§2.16","qid":"GK-W3-122"},"203":{"q":"You are driving a loaded tractor-trailer down a long, steep mountain grade. Despite selecting a low gear before the descent and using light, steady braking, you smell a faint burning odor and your brake pedal is starting to feel soft and spongy. Ahead on the right shoulder you see a sign for an escape ramp. Under these conditions, what is the correct understanding of when and why you should use that ramp?","options":["It is a designated pull-off where you can park overnight and let your overheated brakes cool down before continuing the descent","It is a rest area placed on steep grades so tired drivers can stop a while and recover before finishing a long downhill run","It is built to stop a runaway vehicle, so if your brakes have faded and you can no longer control your speed, you should use it to bring the truck to a safe stop","It is a designated lane where you may safely shift into a lower gear while the vehicle is still moving down the grade"],"answer":2,"explanation":"An escape ramp is built to stop a runaway vehicle whose brakes have faded, so use it to bring the truck to a safe stop when you can no longer control your speed.","handbook":"An escape ramp is for stopping a runaway vehicle.","hbref":"§2.16","qid":"GK-W3-123"},"204":{"q":"You are driving a loaded combination vehicle at highway speed on a dry two-lane road when the steering wheel suddenly goes loose and the truck stops responding normally to your steering inputs. Traffic is light and the shoulder ahead is clear. Which action is the BEST first response?","options":["Maintain your current speed and try to muscle the wheel back and forth until steering response returns","Release the wheel entirely and let the vehicle settle into its own path while you reach for the radio","Apply the brakes gently and smoothly to bring the vehicle to a controlled, safe stop","Press hard and lock up the brakes immediately to halt the vehicle in the shortest possible distance"],"answer":2,"explanation":"If steering fails suddenly, speed is all you can still control, so brake gently and smoothly to bring the vehicle to a safe, controlled stop.","handbook":"If steering fails, brake gently and stop safely.","hbref":"§2.14","qid":"GK-W2-042"},"205":{"q":"You are the first vehicle to come upon a two-car crash on a two-lane rural highway. One driver is slumped over the wheel and appears injured, and there is broken glass and fluid across both lanes. Other vehicles are still approaching from both directions. What is the FIRST thing you should do after stopping your truck safely?","options":["Protect the accident area and warn approaching traffic so no further crashes occur","Pull the injured driver out of the car and move them to the shoulder","Take photos of the scene to document the damage for the report","Begin checking each victim for injuries and provide first aid"],"answer":0,"explanation":"At any accident scene the first priority is preventing a second crash, so protect the area and warn approaching traffic before doing anything else.","handbook":"At an accident scene, protect the area and warn others first.","hbref":"§2.14","qid":"GK-W2-043"},"206":{"q":"You are hauling a dry van on a rural two-lane highway when you smell smoke and see flames flickering near the rear axle wheel area. You need to stop fast, but several stopping spots are coming up. Where is the BEST place to pull over and park to deal with the fire?","options":["Just past the entrance of the upcoming highway tunnel, so the structure shields the truck from wind","Into the gravel pull-out at the truck stop, parking close to the diesel pumps so an extinguisher is within reach","On the wide shoulder of an open stretch, well away from buildings and other vehicles, near a call box","Under the next concrete overpass, where the shade keeps the cargo from overheating further"],"answer":2,"explanation":"With a vehicle fire, stop on an open shoulder away from buildings, traffic, and flammables but near a call box so the fire is isolated and help stays reachable.","handbook":"If your vehicle catches fire, pull off away from others where help is available.","hbref":"§2.14","qid":"GK-W2-044"},"207":{"q":"You are driving a loaded tractor-trailer on a wet interstate when a car suddenly cuts in front of you and stops short. You brake hard, the ABS warning is off (system working), and you must swerve into the empty shoulder to avoid a collision. Counting on your ABS in this emergency, what is the MOST accurate thing it will actually do for you?","options":["It will cut your total stopping distance well below the roughly 419 feet a rig needs from 55 mph, so you can stop in time without swerving","It will automatically brake and steer the truck into the shoulder for you once it senses the obstacle ahead","It guarantees the wheels stay locked so the tires bite harder into the wet pavement for maximum grip","It will keep your wheels from locking up so you can maintain steering control and swerve onto the shoulder while braking hard"],"answer":3,"explanation":"ABS keeps the wheels from locking during hard braking so you retain steering control and can swerve onto the shoulder while braking.","handbook":"ABS helps you keep steering during hard braking.","hbref":"§2.6","qid":"GK-W3-124"},"208":{"q":"You are hauling a loaded trailer down a wet four-lane highway when a car cuts in front of you. You hit the brakes hard, your ABS activates, and you keep the rig under control and steer around the hazard. Afterward, a newer driver tells you that because your truck has ABS, you can now follow other vehicles more closely since ABS lets you stop in a much shorter distance. Why is this reasoning WRONG?","options":["ABS does not necessarily shorten your stopping distance; its main benefit is keeping the wheels from locking so you can steer while braking.","ABS only works when the road is dry, so on this wet highway it provided no braking help at all.","ABS shortens stopping distance only on the steering axle, so following distance can be cut in half but not fully.","ABS automatically applies the brakes for you, so you no longer need to leave any following distance at highway speed."],"answer":0,"explanation":"ABS does not necessarily shorten stopping distance; its main job is to keep the wheels from locking so you can keep steering while braking hard.","handbook":"ABS does not necessarily shorten your stopping distance.","hbref":"§2.6","qid":"GK-W3-125"},"209":{"q":"Your tractor-trailer is NOT equipped with anti-lock brakes (ABS). On a rural two-lane road, a car suddenly pulls out from a side street directly into your path and you must stop as quickly as possible while keeping the rig under control and in your lane. Which braking method gives you the shortest safe stop without losing steering control?","options":["Press the brake pedal to the floor and hold it so the wheels lock up for maximum braking force","Use controlled braking (apply firm steady pressure just short of lockup) or stab braking, releasing if the wheels lock","Pump the brakes rapidly and randomly the entire way down to a stop","Apply only the trailer hand valve so the trailer drags the rig to a halt"],"answer":1,"explanation":"Without ABS, prevent wheel lockup using controlled braking (firm steady pressure just short of lockup) or stab braking, releasing whenever the wheels lock.","handbook":"Without ABS, use controlled or stab braking for a hard stop.","hbref":"§2.6","qid":"GK-W3-126"},"210":{"q":"You are running loaded on a hot summer afternoon at about 60 mph on a divided highway. Suddenly you hear a loud bang and the front of your tractor lurches and pulls hard to one side -- a steer-axle tire has blown out. In that first instant, before you do anything else, which response gives you the BEST chance of keeping control of the vehicle?","options":["Brake hard and firmly right away to bring the truck down to a safe speed before it can pull further off course","Press the accelerator to add power to the drive wheels and pull the tractor straight, then ease off once it tracks true","Steer sharply away from the side that is pulling so the truck straightens back toward the center of your lane","Grip the steering wheel firmly with both hands, stay off the brake at first, hold your lane, and let the vehicle slow on its own before braking gently"],"answer":3,"explanation":"In a blowout, hold the wheel firmly with both hands, stay off the brake at first, keep your lane, and let the vehicle slow before braking gently.","handbook":"If a tire blows out, hold the wheel firmly and slow down gradually.","hbref":"§2.14","qid":"GK-W2-045"},"212":{"q":"During your pre-trip, the shipping papers show your trailer is loaded several thousand pounds over its GVWR. You are running late and the route ahead has a long downgrade and a couple of tight curves. A coworker tells you the extra weight will actually 'help you grip the road,' so it's no big deal. Based on how overloading affects vehicle control, which statement is correct?","options":["The added weight presses the tires down harder, so your braking distance will actually be shorter than if you ran legally loaded.","Because the load is over the axles, the extra weight lowers your center of gravity and reduces any rollover risk on the curves.","The excess weight makes the truck harder to stop and harder to steer, increasing your stopping distance and your risk of losing control on the grade and curves.","Overloading only matters for fuel economy and tire wear; it has no real effect on how the truck stops or steers."],"answer":2,"explanation":"Excess weight makes a truck harder to stop and harder to steer, increasing stopping distance and the risk of losing control on grades and curves.","handbook":"Overloading a truck makes it hard to stop and steer.","hbref":"§3.2","qid":"GK-W3-127"},"213":{"q":"During your pre-trip you load a flatbed and notice that nearly all of the heavy machinery has ended up piled together over the rear axle, sitting up high on a pallet stack. Before you pull out, what is the BEST way to handle this load so your rig drives safely?","options":["Leave the weight bunched at the rear over the drive axle, since extra weight there gives the drive tires more traction","Shove the entire load forward so all the weight sits over the front steering axle for better steering control","Keep it stacked tall and centered, because a high load that is centered left-to-right is already balanced enough","Redistribute the cargo so the weight is spread out and balanced fore-aft and side-to-side, keeping the center of gravity as low as possible"],"answer":3,"explanation":"Spread and balance cargo weight front-to-back and side-to-side, keeping the center of gravity as low as possible to avoid overloading an axle or causing a rollover.","handbook":"Cargo weight should be spread out and balanced.","hbref":"§3.2","qid":"GK-W3-128"},"214":{"q":"During your pre-trip you load a tanker partially full plus stack several pallets on top of the loaded deck, leaving the heaviest weight riding high. As you plan your route, which risk should concern you the MOST about how this truck will now handle?","options":["The high center of gravity makes the truck much more likely to roll over in a curve or sudden steering move.","The high load will make the truck stop in a much shorter distance because of the extra downward force.","The raised weight will improve your fuel economy on level highway because the load rides smoother.","The top-heavy load will make the steering noticeably easier and lighter at highway speed."],"answer":0,"explanation":"A high center of gravity puts more weight up high, making the truck much more likely to roll over in a curve or during a sudden steering move.","handbook":"A high center of gravity makes a vehicle more likely to tip over.","hbref":"§3.2","qid":"GK-W3-129"},"215":{"q":"During your pre-trip inspection you are checking your single straight truck (no trailer) and you find a metal certification plate on the driver's door frame stamped with the number 33,000 lb next to the letters 'GVWR.' Your dispatcher asks what that figure actually tells you about this vehicle. Which statement is correct?","options":["It is the combined maximum loaded weight allowed for this truck plus any trailer it tows together as a unit","It is the maximum loaded weight, set by the manufacturer, that this single vehicle is rated to weigh","It is the total weight of all cargo and tie-downs you may legally place in the cargo box","It is the maximum weight that may rest on any one individual axle of the truck"],"answer":1,"explanation":"GVWR is the maximum loaded weight, set by the manufacturer, that a single vehicle is rated to weigh.","handbook":"GVWR is the maximum weight rating of a single vehicle.","hbref":"§3.2","qid":"GK-W3-130"},"216":{"q":"During your pre-trip inspection you find a 12-foot steel beam riding on the flatbed held in place by two badly frayed, worn ropes, with no blocking against the headboard. You still have a long highway run ahead. Before you can legally and safely pull out, what does this load require?","options":["Nothing more is needed -- two separate ropes already meet the minimum of two tie-downs for a piece longer than 5 feet, so the beam is secured","Only re-tying the existing ropes tighter, since the headboard at the front of the trailer will stop the beam from sliding forward on its own","Enough proper tie-downs and bracing -- sound tie-downs with adequate working load limit plus blocking/bracing -- to actually hold the beam against shifting in any direction","A single chain across the center is enough, because one tie-down is all that is required for any piece of cargo on a flatbed"],"answer":2,"explanation":"Cargo needs enough sound tie-downs with adequate working load limit plus blocking and bracing to hold the load against shifting in any direction.","handbook":"Secure cargo with enough tie-downs and bracing.","hbref":"§3.3","qid":"GK-W3-131"},"217":{"q":"You are loading steel coils and heavy crates onto a flatbed trailer fitted with a header board (headache rack) directly behind the cab. Your coworker asks why your company spends money on these racks when proper tie-downs are already in use. Which answer correctly states the PRIMARY purpose this header board serves?","options":["It gives you a sturdy mounting point so your aggregate tie-down working load limit can be lowered to less than one-half of the cargo weight","It blocks wind turbulence and road spray off the front of the load so your fuel mileage and mirror visibility improve","It lets you legally skip the in-cab cargo re-check until you have driven the first 150 miles after loading","It shields you in the cab by stopping the load from shifting forward and crushing through into the driver's compartment during a hard stop"],"answer":3,"explanation":"A header board (headache rack) stops cargo from shifting forward into the cab during a hard stop, protecting the driver from being struck or crushed.","handbook":"A header board protects you from cargo sliding forward into the cab.","hbref":"§3.2","qid":"GK-W3-132"},"219":{"q":"You just had your loaded rig weighed at a roadside scale, and the officer hands you a printout listing several different numbers: a figure for each set of wheels on the ground, plus a single combined total. The officer points to the line labeled \"axle weight\" and asks you to confirm you understand what that specific number represents. To answer correctly, which of the following must you tell the officer that the axle weight figure means?","options":["The amount of weight that each individual axle is transmitting to the ground","The combined total weight of the entire loaded vehicle and all its cargo","The weight of only the cargo and securement equipment riding on the trailer","The maximum weight the manufacturer rates the vehicle to carry safely"],"answer":0,"explanation":"Axle weight is the amount of weight that one individual axle carries and transmits to the ground, not the whole vehicle's weight.","handbook":"Axle weight is the weight carried by each axle.","hbref":"§3.2","qid":"GK-W3-133"},"220":{"q":"It is 3 a.m. on a long overnight run and you catch yourself drifting in the lane and yawning repeatedly. You still have several hours of driving left on your trip plan. Which action will actually correct your fatigue so you can continue safely?","options":["Drink a large black coffee and turn the radio up loud to push through the remaining hours","Pull off at a safe rest area and stop driving to get real sleep before continuing","Roll down the side window for cold fresh air and eat some candy for a sugar boost","Keep driving but increase your following distance to one second per 10 feet of vehicle length to give yourself more reaction time"],"answer":1,"explanation":"Only real sleep cures fatigue, so pull off at a safe rest area and stop driving to sleep before continuing.","handbook":"The most effective way to deal with fatigue is enough sleep.","hbref":"§2.18","qid":"GK-W3-134"},"221":{"q":"It is allergy season and during your pre-trip walk-around you feel a head cold coming on. You take an over-the-counter cold-and-allergy tablet from your bag before climbing into the cab for a long daytime run. Which effect of this medication is the MOST important reason to reconsider driving right now?","options":["It will heighten your alertness, so you can safely extend your driving hours","It removes any alcohol still in your system, lowering your BAC before the trip","It can make you drowsy and impair your driving, so you should check the label before driving","It improves your reaction time and sharpens your focus on the road"],"answer":2,"explanation":"Many over-the-counter cold and allergy medicines cause drowsiness and impair driving, so always read the label and don't drive if it warns against operating machinery.","handbook":"Some cold or allergy medicines can make you drowsy.","hbref":"§2.18","qid":"GK-W3-135"},"222":{"q":"You finished two beers with dinner two hours ago and feel completely sober before climbing into your tractor-trailer for an overnight run. You tell yourself a strong coffee and the cold night air will keep you sharp. Which statement best explains the real risk you are taking by driving in this condition?","options":["Nothing significant -- after two hours and a coffee, alcohol no longer has any measurable effect on a driver of your size","The only real concern is staying under the 0.08% BAC limit that applies to your CDL while operating the rig","Coffee and cold air will speed up how fast your body clears the alcohol, so your skills will be restored before you reach the highway","Alcohol impairs your judgment and reaction time even when you feel fine, and only time -- not coffee or fresh air -- removes it from your body"],"answer":3,"explanation":"Alcohol impairs judgment and reaction time even when you feel fine, and only the passage of time -- not coffee or fresh air -- removes it from your body.","handbook":"Alcohol affects your judgment and reaction time.","hbref":"§2.20","qid":"GK-W3-136"},"224":{"q":"You finished a long shift at 2 a.m. and grabbed only about four hours of sleep before your next dispatch. Your dispatcher pressures you to roll out, and you tell yourself you can 'catch up' with coffee and an open window. Based on what the handbook says about preventing fatigue, which statement reflects what you actually need to be genuinely rested and safe to drive?","options":["Most adults need about 7 to 8 hours of sleep to be truly rested, and only real sleep — not coffee or fresh air — restores alertness.","About 4 to 5 hours of sleep is enough for an experienced driver, since coffee and fresh air can make up the rest.","Around 2 to 3 hours of sleep is acceptable as long as you take a break every 150 miles to recheck your alertness.","You need a full 12 to 14 hours of sleep before any commercial trip or you are legally unfit to drive."],"answer":0,"explanation":"Most adults need about 7 to 8 hours of sleep to be truly rested, and only real sleep -- not coffee or fresh air -- restores alertness.","handbook":"Most adults need about 7 to 8 hours of sleep to be rested.","hbref":"§2.18","qid":"GK-W3-137"},"225":{"q":"You have been driving for several hours on a long, monotonous stretch of highway and your eyelids are getting heavy. You roll down the window for fresh air and drink a large coffee to stay alert. Which statement about these methods is correct?","options":["Caffeine combined with cool fresh air permanently restores your alertness for the rest of the shift","They may help for a short time, but the only real cure for drowsiness is to stop and sleep","Fresh air and coffee are dangerous and will make your drowsiness worse","They fully reset your driving hours, so you can safely continue without stopping"],"answer":1,"explanation":"Caffeine and fresh air only mask drowsiness for a short time; the only real cure is to stop driving and sleep.","handbook":"Caffeine and fresh air are only temporary against drowsiness.","hbref":"§2.18","qid":"GK-W3-138"},"226":{"q":"You are cruising in the right lane of a divided highway when a driver races up behind you, tailgates closely, flashes high beams, then swerves into the left lane and gestures angrily as he tries to pass. Traffic ahead is moderate. Which action is the BEST and safest response?","options":["Speed up to match his pace so he can complete the pass quickly and stop crowding your bumper","Hold your lane position and slow only slightly, making him wait so he learns not to tailgate","Ease off the accelerator to make room, avoid eye contact, and let him get well ahead of you","Move left into his lane to block the pass until he calms down and backs off"],"answer":2,"explanation":"Give an aggressive driver plenty of room and don't engage -- ease off the accelerator, avoid eye contact, and let them get well ahead of you.","handbook":"Give an aggressive driver room and do not engage.","hbref":"§2.8","qid":"GK-W3-139"},"227":{"q":"You are merging onto a busy interstate with your loaded tractor-trailer when a four-wheeler cuts you off, forcing you to brake hard. Frustrated, the other driver then tailgates you, swerves around, brakes sharply in front of you, and makes obscene gestures. According to the handbook, which term BEST describes the other driver's behavior, and what is the safest way for you to think about your own conduct so you do not become guilty of the same thing?","options":["Aggressive merging — a normal part of heavy traffic that you should answer by accelerating to hold your position and not let cars take advantage of a slow truck","Defensive driving — the other driver is simply protecting space, so you should mirror the behavior by braking and blocking to teach four-wheelers to respect a large vehicle","Distracted driving — the driver is clearly not paying attention, so the correct response is to speed up and pass them quickly to remove yourself from the hazard","Road rage — angry, violent driving; you avoid committing it yourself by staying calm, not retaliating, and giving the angry driver room to leave"],"answer":3,"explanation":"Road rage is angry, violent driving, and you avoid committing it by staying calm, not retaliating, and giving the angry driver room to leave.","handbook":"Road rage means angry, violent driving.","hbref":"§2.8","qid":"GK-W3-140"},"228":{"q":"You are driving a loaded combination vehicle through dense afternoon traffic on a Texas interstate. A coworker tells you the best way to catch developing hazards early is to lock your focus on the bumper of the truck directly ahead so you never miss its brake lights. Which approach actually gives you the best chance of spotting hazards in time to react safely?","options":["Keep your eyes moving and scan continuously — sweep far ahead (12 to 15 seconds), then near, and check your mirrors every 5 to 8 seconds","Stare straight ahead and fix your eyes on the vehicle directly in front so its brake lights are always in clear view","Rely mainly on your mirrors, since most surprises in heavy traffic come from vehicles overtaking you from behind","Watch the radio dial and dashboard gauges between glances forward so you do not miss a mechanical warning developing"],"answer":0,"explanation":"Keep your eyes moving and scan continuously -- sweep far ahead 12 to 15 seconds, then back to the near scene, and check your mirrors every 5 to 8 seconds.","handbook":"To spot hazards, keep your eyes moving and scan the scene.","hbref":"§2.8","qid":"GK-W3-141"},"229":{"q":"You are driving through a downtown business district at 25 mph. Along the right curb you see a line of parallel-parked cars. As you scan ahead, you notice that one of those parked cars has its brake lights lit and exhaust coming from the tailpipe, and you can see the silhouette of a driver in the seat. Why should you treat THIS particular parked car as an active hazard and prepare to slow or change lane position?","options":["The brake lights mean the car is being held in place, so it cannot move and only the cars without lights ahead of it pose any threat","An occupied, running car can suddenly pull out into your lane or a door can swing open into your path, so you should cover the brake and give it extra space","A running engine warms the tires, which lengthens your own stopping distance to about 419 feet and forces you to back off","Exhaust and lit brake lights are normal for a parked car and signal nothing, so no change in speed or lane position is needed"],"answer":1,"explanation":"An occupied, running parked car may suddenly pull into your lane or open a door in your path, so cover the brake and give it extra space.","handbook":"A parked car with someone inside may open a door or pull out.","hbref":"§2.8","qid":"GK-W3-142"},"230":{"q":"You are driving your truck at 30 mph through a residential neighborhood on a warm afternoon. Ahead on the right you see several children playing with a ball near the curb, and one of them is looking down at the ball, not at your truck. Why does the handbook treat this situation as a special hazard that requires you to be ready to slow or stop immediately?","options":["Because at 30 mph your total stopping distance is already about 419 feet, so you cannot possibly stop in time for anything","Because children always stay on the sidewalk and will only become a hazard if an adult tells them to cross","Because children may act suddenly and unpredictably, such as darting into the road after the ball without checking for traffic","Because children move so slowly that they will still be in the roadway long after you expect them to clear it"],"answer":2,"explanation":"Children are a special hazard because they may act suddenly and unpredictably, such as darting into the road after a ball without checking for traffic.","handbook":"Children are a special hazard because they may act suddenly.","hbref":"§2.8","qid":"GK-W3-143"},"231":{"q":"You are hauling a loaded trailer on a four-lane divided highway at about 55 mph. A small car suddenly cuts in front of you from the right, then brakes hard to make an exit it almost missed. Your following distance has shrunk and you feel a surge of anger. Which response is the safest and most defensive?","options":["Hold your position close behind the car and flash your high beams so the driver understands the danger they created","Accelerate to pull alongside the car so you are no longer trapped behind an unpredictable driver","Tap your brakes lightly to send a quick warning, then move back up to your original 4-second following gap","Ease off the accelerator to rebuild a safe following distance, stay calm, and let the other driver have the room they need"],"answer":3,"explanation":"When another driver makes a mistake, ease off the accelerator to rebuild a safe following distance, stay calm, and give them the room they need.","handbook":"When another driver makes a mistake, give them room and stay calm.","hbref":"§2.8","qid":"GK-W3-144"},"233":{"q":"You are approaching an unfamiliar intersection at night when you notice the traffic signal overhead is flashing red in every direction. There is no police officer present and traffic from the cross street is light. To handle this intersection correctly and legally, what should you do?","options":["Come to a complete stop, then proceed through the intersection only when it is safe, just as you would at a STOP sign","Slow down, scan both directions, and roll through cautiously without coming to a complete stop","Treat the dead signal as a yield and merge through whenever a gap appears, keeping your momentum up","Maintain your speed through the intersection since a flashing signal means the light is malfunctioning and rules do not apply"],"answer":0,"explanation":"A flashing red signal means the same as a STOP sign: come to a complete stop and proceed only when it is safe.","handbook":"At a flashing red signal, stop and proceed when safe.","hbref":"§2.4","qid":"GK-W3-145"},"234":{"q":"You are approaching an intersection late at night in your loaded combination vehicle. The signal that has been steady green during the day is now showing a FLASHING YELLOW. There is no other traffic visible at the cross street. Which of the following is the correct way to handle this signal?","options":["Treat it exactly like a flashing red: come to a complete stop, then proceed when clear","Slow down, stay alert, and proceed through the intersection with caution after checking cross traffic","Maintain your highway speed because a yellow signal grants you the right-of-way over the cross street","Stop fully at the line and wait for the signal to change to a steady green before moving"],"answer":1,"explanation":"A flashing yellow signal is a warning, so slow down, stay alert, and proceed through the intersection with caution after checking cross traffic.","handbook":"A flashing yellow signal means slow down and proceed with caution.","hbref":"§2.4","qid":"GK-W3-146"},"235":{"q":"You are approaching a rural intersection with your loaded combination vehicle. There are no stop signs, yield signs, or traffic signals facing any direction, and brush partially blocks your view to the right. A pickup is approaching the crossing from your right at roughly the same time. What is the safest and most correct action for you to take?","options":["Maintain your speed and proceed first, since a loaded commercial vehicle has the legal right-of-way over smaller vehicles","Come to a complete stop in the center of the intersection and wait for the pickup to clear before moving","Slow down as you approach, cover your brake, and be prepared to yield to the pickup as needed before proceeding","Sound your horn and continue through at the same speed so the other driver knows you intend to cross first"],"answer":2,"explanation":"At an uncontrolled intersection no vehicle has automatic right-of-way, so slow down, cover your brake, and be ready to yield before proceeding.","handbook":"At an uncontrolled intersection, slow down and yield as needed.","hbref":"§2.4","qid":"GK-W3-147"},"237":{"q":"You are hauling a heavy load and approaching the top of a long, steep mountain grade. The grade is several miles long, the pavement is dry, and you want to keep your service brakes from fading on the way down. According to safe mountain-driving procedure, which action gives you the most reliable control of your speed during the descent?","options":["Stay in your normal highway gear and ride the service brakes lightly the whole way down to keep your speed steady","Wait until you feel the truck speeding up partway down, then shift into a lower gear to slow the rig back down","Keep the transmission in a high gear so the engine can rest, and rely mainly on hard, repeated brake applications to control speed","Select a low gear BEFORE you start down the grade so engine and gear braking do most of the work, using the service brakes only as a light, steady supplement"],"answer":3,"explanation":"Select a low gear before starting down a long grade so engine and gear braking do most of the work, using the service brakes only as a light, steady supplement.","handbook":"On a mountain road, use a lower gear going down a steep grade.","hbref":"§2.16","qid":"GK-W3-148"},"238":{"q":"You are hauling a fully loaded trailer through mountainous terrain when your GPS warns of an emergency escape ramp ahead. A newer driver riding with you asks why the highway department built a long gravel-filled ramp at this exact spot rather than somewhere else along the route. Based on how these ramps are intended to be used, which location is the department MOST likely to place one?","options":["Partway down a long, steep downgrade where heavy vehicles are most at risk of losing brakes to fade","On a flat, open stretch of highway where trucks routinely reach their highest cruising speeds","Just before a busy downtown intersection where city traffic forces frequent hard stops","At the entrance to a large rest-area parking lot where many trucks park overnight"],"answer":0,"explanation":"Runaway truck ramps are placed partway down long, steep downgrades where heavy vehicles are most likely to lose their brakes to fade from overheating.","handbook":"Runaway truck ramps are usually on long steep downgrades.","hbref":"§2.16","qid":"GK-W3-149"},"239":{"q":"It is well after dark on a rural two-lane highway and you are running on low beams, which light the road about 250 feet ahead. A sharp curve is coming up and you cannot see what lies on the road beyond it. Which action best fits the rule that you must never overdrive your headlights?","options":["Switch to high beams through the curve so you can see farther around the bend, then drop back to low beams once you are straight again","Reduce your speed before entering the curve so that you can stop within the distance your headlights actually light up","Keep your current speed but follow the vehicle ahead more closely so its taillights guide you through the curve","Maintain highway speed because at 55 mph your headlights still cover the full 419 feet of stopping distance you need"],"answer":1,"explanation":"Never overdrive your headlights: slow down before a curve so you can stop within the distance your headlights actually light up.","handbook":"Before a curve at night, slow down because you cannot see as far.","hbref":"§2.11","qid":"GK-W3-150"},"240":{"q":"You have finished walking around your tractor-trailer during the pre-trip inspection and everything visually checks out. Before you pull out onto the road and merge into traffic, what is the correct way to confirm that your service brakes are actually working?","options":["Skip the working test because the walk-around inspection already confirmed the brake components looked fine, and re-check only after the first 50 miles","Wait until you reach highway speed, then press the brakes firmly to feel whether the truck pulls evenly to one side","Begin moving at a low speed and gently apply the brakes to make sure the vehicle stops and does not pull to one side","Pump the brake pedal several times while parked and watch for the air pressure gauge to drop, which proves the brakes will stop you"],"answer":2,"explanation":"After the walk-around inspection, test the service brakes by moving slowly and gently braking to confirm the vehicle stops and does not pull to one side.","handbook":"Test that your brakes work at low speed before a trip.","hbref":"§2.1","qid":"GK-W3-151"},"241":{"q":"You are hauling a loaded trailer on a two-lane rural highway when a strong gust of crosswind suddenly pushes the front of your tractor toward the shoulder. To keep the best control of the vehicle as you correct your steering, what is the safest hand position on the steering wheel?","options":["Keep one hand low at the bottom of the wheel so you can make a quick, sweeping turn against the wind","Steer with one hand and keep the other ready on the trailer brake hand valve to slow the trailer","Briefly let the wheel slide freely through your hands so it self-centers after the gust passes","Keep both hands firmly on the wheel, on opposite sides, so you can react smoothly and maintain steady control"],"answer":3,"explanation":"Keep both hands firmly on the wheel on opposite sides so you can react smoothly and hold steady control during a sudden crosswind gust.","handbook":"Hold the wheel with both hands and a firm grip.","hbref":"§2.3","qid":"GK-W3-152"},"242":{"q":"You are alone at a crowded truck stop and the only way out of your space requires you to back up. You have a choice: you can set up your approach so you back toward your left (driver's) side, or back toward your right (blind) side, which would be a slightly shorter maneuver. Which approach is the safest and why?","options":["Back toward the driver's (left) side, because you can look out your window and directly watch the rear of your trailer the whole time.","Back toward the blind (right) side, because it is the shorter path and your mirrors give you full coverage of that side.","Either side is equally safe as long as you tap your horn twice before moving and turn on your four-way flashers.","Back straight only and never angle the trailer, because any sideways backing is prohibited at a truck stop."],"answer":0,"explanation":"Always back toward the driver's (left) side because you can look out your window and watch the rear of the trailer directly instead of relying only on mirrors.","handbook":"When backing, the safest direction is toward the driver's side.","hbref":"§2.13","qid":"GK-W3-153"},"243":{"q":"You are driving a loaded tractor-trailer on a dry, level interstate at 55 mph when you decide to pass another truck. To do so safely you accelerate up to 65 mph. Compared to your stop at 55 mph, what is the MOST important effect this speed change has on your ability to stop in an emergency?","options":["Stopping distance stays about the same because the road is dry and your brakes are good","Stopping distance increases sharply, because braking distance grows with roughly the square of your speed","Stopping distance decreases slightly because the faster moving wheels grip the road better","Stopping distance is unaffected by speed and depends only on the weight of your load"],"answer":1,"explanation":"Stopping distance increases sharply with higher speed because braking distance grows with roughly the square of speed.","handbook":"Stopping distance increases with higher speed.","hbref":"§2.6","qid":"GK-W3-154"},"244":{"q":"You are driving a loaded tractor-trailer up an entrance ramp onto a busy interstate. The acceleration lane is fairly short, traffic in the right lane is moving steadily at about 60 mph, and a tight gap is opening up just ahead of you. To complete the merge as safely as possible, what should you do?","options":["Come to a stop at the end of the ramp and wait for all traffic to clear before pulling out","Edge into the lane at a slow, cautious speed and let the faster traffic adjust around your rig","Use the acceleration lane to build up to the speed of the traffic flow, then move into the open gap","Hold your lane position and assert your right of way so vehicles in the through lane yield to you"],"answer":2,"explanation":"The acceleration lane is there to match the speed of highway traffic so you can blend smoothly into an open gap without forcing others to brake or swerve.","handbook":"To merge onto a freeway, match traffic speed and merge into a gap.","hbref":"§2.7","qid":"GK-W3-155"},"245":{"q":"You are driving a loaded tractor-trailer in heavy stop-and-go city traffic. A pedestrian distracted by their phone steps off the curb and begins to walk into your lane a short distance ahead. You have already eased off the accelerator and are covering your brake. Which use of your horn in this moment is the one that DPS considers appropriate?","options":["Tap the horn lightly and repeatedly to keep nearby drivers alert, since constant signaling in congestion prevents collisions","Avoid the horn entirely and rely only on braking, because sounding the horn near a pedestrian is never permitted in city traffic","Give a long, friendly honk to let the pedestrian and surrounding drivers know a big truck is approaching the intersection","Sound the horn to warn the pedestrian of the immediate danger, using it only to alert others to the hazard"],"answer":3,"explanation":"The horn is a warning device meant only to alert others to real, immediate danger, such as a distracted pedestrian entering your path.","handbook":"Use your horn only to warn others of danger.","hbref":"§2.4","qid":"GK-W3-156"},"246":{"q":"It is just below freezing and you must park your tractor-trailer on the right shoulder of a road that slopes steeply downhill. You set the parking brakes, but you know that on this icy grade the brakes alone may not hold the rig if it begins to creep. To use the curb as a final backstop in case the vehicle rolls, which way should you turn your front wheels?","options":["Turn the front wheels toward the curb (right), so any forward roll wedges a front tire against the curb","Turn the front wheels away from the curb (left, toward the road), so the rig drifts off the curb if it rolls","Leave the front wheels pointed straight ahead, since the parking brakes and chocks do all the holding","The direction does not matter on a downhill grade as long as the parking brakes are set"],"answer":0,"explanation":"When parked facing downhill, turn the front wheels toward the curb so that any forward roll wedges a tire against it and stops the vehicle.","handbook":"When parking downhill, turn your wheels toward the curb.","hbref":"§2.13","qid":"GK-W3-157"},"247":{"q":"You are driving a loaded tractor-trailer on a rural two-lane highway at 50 mph when you glance down to check a mirror. When you look up, your right-side wheels have drifted off the pavement onto a soft gravel shoulder, and your tractor is pulling slightly to the right. There is no obstacle immediately ahead. What is the BEST way to get back onto the roadway?","options":["Steer back onto the pavement immediately with a quick, firm turn of the wheel to correct your line before you lose more ground","Take your foot off the accelerator, keep a firm grip, and steer back onto the pavement gradually once the truck has slowed and is under control","Apply the brakes hard right away to scrub off speed before any part of the rig leaves the shoulder","Press down on the accelerator to power through the soft gravel and pull the rig back up onto the firmer pavement"],"answer":1,"explanation":"If your wheels drift onto the shoulder, ease off the accelerator without braking hard and steer back onto the pavement gradually after the truck has slowed.","handbook":"If you drift onto the shoulder, ease off the gas and steer back gently.","hbref":"§2.14","qid":"GK-W3-158"},"248":{"q":"You are driving a loaded tractor-trailer in the right lane of a two-lane highway at the posted 55 mph. For the last several minutes a pickup has been tailgating you so closely that you can no longer see its headlights in your mirrors, and there is no vehicle ahead of you. Traffic in the left lane is light. What is the SAFEST way to handle this tailgater?","options":["Tap your brakes lightly several times to flash your brake lights and warn the driver to back off","Maintain your speed but cut your following distance to the vehicles ahead so the tailgater has room","Increase your following space ahead, then move over and let the tailgater pass when it is safe","Gradually speed up well above 55 mph until the tailgater is no longer riding your bumper"],"answer":2,"explanation":"With a tailgater behind you, open up extra space ahead and then move over to let them pass safely.","handbook":"The safest way to handle a tailgater is to move over and let them pass.","hbref":"§2.7","qid":"GK-W3-159"},"249":{"q":"You are driving a loaded tractor-trailer on a multi-lane highway and you need to move into the right lane before your exit, which is coming up in about a mile. Traffic is moderate and a car is sitting somewhere back in your right-side blind spot. According to DPS guidance on communicating with other drivers, what is the single BEST way to let the drivers around you know what you intend to do?","options":["Tap your brakes a few times so the car behind sees your brake lights and understands you are about to slow and merge","Flash your high beams at the traffic in the right lane to alert them that you are moving over","Speed up and make the lane change quickly so you spend the least possible time beside the car in your blind spot","Turn on your right turn signal early and leave it on, signaling your intention to change lanes clearly and well in advance"],"answer":3,"explanation":"Communicate your intentions clearly by turning on your signal early and well in advance so other drivers have time to react.","handbook":"A good driver communicates by signaling intentions clearly.","hbref":"§2.4","qid":"GK-W3-160"},"250":{"q":"You are hauling a 30-foot straight truck on a dry interstate, cruising steadily at 50 mph in light traffic. A four-wheeler ahead of you keeps changing lanes, so you decide to set a safe following gap. Using the standard following-distance rule, what is the LEAST amount of following distance you should keep behind that vehicle?","options":["4 seconds","3 seconds","5 seconds","6 seconds"],"answer":0,"explanation":"Allow 1 second of following distance per 10 feet of length, then add 1 second above 40 mph: a 30-foot truck at 50 mph needs 3 + 1 = 4 seconds.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-161"},"251":{"q":"You are hauling a 40-foot straight truck through town and the speedometer reads a steady 35 mph on dry pavement. Traffic is light, but you want to set a safe gap behind the car in front so you can react if it brakes suddenly. Using the recommended following-distance rule for your vehicle's length and your current speed, what is the LEAST following distance you should keep?","options":["5 seconds, because a 40-foot vehicle automatically needs one extra second over the base figure","4 seconds, because you allow 1 second for each 10 feet of length and add nothing extra below 40 mph","3 seconds, because three seconds is the standard minimum gap for any commercial vehicle","6 seconds, because at this length you should always double the per-10-foot count for safety"],"answer":1,"explanation":"Allow 1 second of following distance per 10 feet of length and add nothing below 40 mph, so a 40-foot truck at 35 mph needs 4 seconds.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-162"},"252":{"q":"You are hauling a flatbed combination that measures 50 feet from bumper to bumper. Traffic on the interstate has picked up and your speedometer is holding steady at 55 mph in dry, clear conditions. As you settle in behind the vehicle ahead, what is the minimum following distance you should keep, counted in seconds, to stay within the safe gap the handbook recommends?","options":["5 seconds, because you allow 1 second for every 10 feet of vehicle length","7 seconds, adding 2 extra seconds because your speed is well over 40 mph","6 seconds, because 50 feet gives you 5 seconds and you add 1 more for being over 40 mph","4 seconds, since a steady highway speed in dry weather lets you shorten the gap"],"answer":2,"explanation":"Allow 1 second per 10 feet of length, then add 1 second above 40 mph: a 50-foot vehicle at 55 mph needs 5 + 1 = 6 seconds.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-163"},"253":{"q":"You are hauling a 60-foot tractor-trailer down a dry, flat interstate in good daylight conditions, holding a steady 45 mph. Traffic is light, but you want to set a safe following gap behind the car ahead. Which of the following correctly states the minimum following distance you should keep, in seconds?","options":["6 seconds, because you allow 1 second for every 10 feet of vehicle length","5 seconds, since a long combination vehicle only needs about half a second per 10 feet","8 seconds, adding 2 extra seconds because you are over 40 mph","7 seconds, because you allow 6 seconds for length plus 1 more second for being over 40 mph"],"answer":3,"explanation":"Allow 1 second per 10 feet of length, then add 1 second above 40 mph: a 60-foot vehicle at 45 mph needs 6 + 1 = 7 seconds.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-164"},"254":{"q":"You are hauling a 70-foot combination on a flat city arterial, holding a steady 35 mph in clear, dry conditions. Traffic ahead is moving smoothly and you want to set a safe following gap. Using the formula for judging following distance, the MINIMUM cushion you should keep behind the vehicle in front of you is:","options":["7 seconds","8 seconds","6 seconds","9 seconds"],"answer":0,"explanation":"Allow 1 second of following distance per 10 feet of vehicle length, and below 40 mph no extra second is added, so a 70-foot truck needs 7 seconds.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-165"},"255":{"q":"You are hauling a load on a dry interstate and your speedometer reads a steady 45 mph. Glancing at your mirrors, you estimate your tractor-trailer combination stretches a full 80 feet from front bumper to rear of the trailer. Traffic is moving smoothly and you want to set a safe gap behind the car ahead. Using the recommended following-distance rule, how many seconds of space should you keep?","options":["8 seconds, because the rule is simply 1 second for every 10 feet of vehicle length","9 seconds, because 80 feet gives 8 seconds and you add 1 second for traveling above 40 mph","7 seconds, since at this speed you can shave a second off the length-based count","10 seconds, because you should round the length up and add a full 2 seconds of cushion at highway speed"],"answer":1,"explanation":"Allow 1 second per 10 feet of length for a base of 8 seconds, then add 1 second for speeds above 40 mph, totaling 9 seconds.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-166"},"256":{"q":"You are hauling a 90-foot combination on a dry interstate, cruising at a steady 50 mph in light traffic. A four-wheeler merges in front of you and you need to re-establish a safe gap. Using the following-distance rule, what is the LEAST amount of space you should keep behind that vehicle?","options":["9 seconds, because the rule is simply 1 second for every 10 feet of vehicle length","8 seconds, since you can shave time off once you are rolling steadily on dry pavement","10 seconds of following distance","11 seconds, adding 2 extra seconds because you are well above 40 mph"],"answer":2,"explanation":"Allow 1 second per 10 feet of length for a base of 9 seconds, then add 1 second for speeds above 40 mph, totaling 10 seconds.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-167"},"257":{"q":"You are hauling a flatbed combination that measures 100 feet from front bumper to the end of your trailer. Traffic opens up and you accelerate to 60 mph on a dry interstate. Glancing in your mirror, you want to set a safe following distance behind the car you are trailing. Based on the following-distance rule, what is the MINIMUM number of seconds of space you should keep?","options":["10 seconds, because you allow 1 second for every 10 feet of vehicle length and 100 divided by 10 equals 10","12 seconds, allowing 1 second per 10 feet plus 2 extra seconds for the higher speed","9 seconds, since 60 mph is fast enough to subtract a second from the length-based count","11 seconds, because 100 feet gives 10 seconds and you add 1 more second for traveling above 40 mph"],"answer":3,"explanation":"Allow 1 second per 10 feet of length for a base of 10 seconds, then add 1 second for speeds above 40 mph, totaling 11 seconds.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-168"},"258":{"q":"You are hauling a 40-foot straight truck on a dry interstate, holding a steady 55 mph in good daylight conditions. Traffic ahead is moving freely. Applying the handbook rule for safe following distance, what is the MINIMUM gap you should keep behind the vehicle in front of you?","options":["5 seconds","4 seconds","6 seconds","3 seconds"],"answer":0,"explanation":"Allow 1 second per 10 feet of length for a base of 4 seconds, then add 1 second for speeds above 40 mph, totaling 5 seconds.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-169"},"259":{"q":"You are hauling a flatbed and, during your pre-trip walk-around, you measure your tractor-trailer at 50 feet bumper to bumper. Out on a dry rural highway your speedometer settles at a steady 50 mph in light traffic. Using the rule for judging a safe following distance behind the vehicle ahead, how many seconds of space should you keep at this speed and length?","options":["5 seconds, because you allow 1 second for each 10 feet of vehicle length","6 seconds, because you allow 1 second per 10 feet of length and add 1 more second for being above 40 mph","7 seconds, because you allow 1 second per 10 feet of length and add 2 more seconds for highway speed","4 seconds, because following distance is based on speed alone, not vehicle length"],"answer":1,"explanation":"Allow 1 second per 10 feet of length for a base of 5 seconds, then add 1 second for speeds above 40 mph, totaling 6 seconds.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-170"},"260":{"q":"You are hauling a 70-foot tractor-trailer down a dry, level interstate, holding a steady 45 mph in light traffic. Glancing at your mirrors, you decide to set your following gap by counting the seconds it takes you to reach a fixed object after the vehicle ahead passes it. Based on your vehicle's length and your current speed, what is the MINIMUM following distance you should keep?","options":["7 seconds, because the rule is simply 1 second for every 10 feet of vehicle length","6 seconds, since about 6 seconds of total stopping distance is enough at highway speed","8 seconds, because you need 1 second per 10 feet of length and 1 extra second for being above 40 mph","9 seconds, adding a second for the dry pavement on top of the length and speed seconds"],"answer":2,"explanation":"Allow 1 second per 10 feet of length for a base of 7 seconds, then add 1 second for speeds above 40 mph, totaling 8 seconds.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-171"},"261":{"q":"You are hauling a flatbed combination that measures 80 feet from front bumper to rear of the trailer. Traffic is flowing smoothly on a level two-lane highway and your speedometer is steady at 35 mph. To keep a safe following distance behind the truck ahead, which gap should you maintain?","options":["9 seconds, because you take 8 seconds for the length and add 1 more second for highway speed","7 seconds, since at slower speeds the cushion can be trimmed by one second","10 seconds, the maximum cushion any large combination should ever need","8 seconds, because each 10 feet of length needs 1 second and no extra second is added under 40 mph"],"answer":3,"explanation":"Allow 1 second per 10 feet of length for 8 seconds, and at 35 mph (under 40 mph) no extra second is added, so 8 seconds is the cushion.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-172"},"262":{"q":"During your pre-trip you are securing a single 15-foot length of steel pipe on a flatbed. The pipe is well within the working load limit of your straps. To meet the federal cargo securement minimum, what is the FEWEST number of tie-downs you may legally use on this one piece?","options":["2 tie-downs","1 tie-down","3 tie-downs","4 tie-downs"],"answer":0,"explanation":"Cargo needs at least 1 tie-down per 10 feet of length and at least 2 for any article over 5 feet, so a 15-foot pipe requires 2 tie-downs.","handbook":"Use one tie-down per 10 feet of cargo, and at least two.","hbref":"§3.3","qid":"GK-W3-173"},"263":{"q":"During your pre-trip walkaround you find a single 25-foot steel I-beam loaded flat on your trailer with only 2 chain tie-downs holding it. The beam is well within your weight limits and the deck is in good shape. Before you can legally roll, what is the MINIMUM number of tie-downs this piece must have?","options":["2 tie-downs, because any piece longer than 5 feet legally requires at least 2 securement devices","3 tie-downs, because you need at least one tie-down for every 10 feet of cargo and 25 feet rounds up to 3","4 tie-downs, because long heavy steel must be secured at every 5 feet of its length","1 tie-down, because the beam is a single rigid piece resting solidly on the deck"],"answer":1,"explanation":"Cargo needs at least 1 tie-down per 10 feet of length, rounding up, so a 25-foot beam requires 3 tie-downs.","handbook":"Use one tie-down per 10 feet of cargo, and at least two.","hbref":"§3.3","qid":"GK-W3-174"},"264":{"q":"During your pre-trip inspection you are securing a single steel beam that measures 35 feet long resting on the flatbed. Knowing the rule about how many tie-downs cargo of this length requires, what is the LEAST number of tie-downs you can legally use to secure this beam?","options":["3 tie-downs, since 35 feet divided by 10 gives you three full 10-foot sections","2 tie-downs, because any single piece simply needs one at each end","4 tie-downs, because you need at least one for every 10 feet and 35 feet rounds up","5 tie-downs, since a beam this long requires an extra one for safety margin"],"answer":2,"explanation":"Cargo securement requires at least one tie-down for every 10 feet of length, rounding any partial section up, so 35 feet needs 4.","handbook":"Use one tie-down per 10 feet of cargo, and at least two.","hbref":"§3.3","qid":"GK-W3-175"},"265":{"q":"During your pre-trip you are securing a single 45-foot steel beam on a flatbed. The beam weighs 9,000 lb and your chains each have a working load limit well above what the load requires, so weight rating is not your concern here. Based only on the minimum-number-of-tie-downs rule, what is the LEAST number of tie-downs you must use to legally haul this beam?","options":["4 tie-downs, because you count one for each full 10 ft of length and ignore the leftover 5 ft","3 tie-downs, since the working load limit is already high enough to hold the load","6 tie-downs, adding one extra beyond the length rule as a safety margin","5 tie-downs, because you need at least one per 10 ft and 45 ft rounds up to 5"],"answer":3,"explanation":"At least one tie-down is required for every 10 feet of cargo, with any leftover rounded up, so a 45-foot load needs 5.","handbook":"Use one tie-down per 10 feet of cargo, and at least two.","hbref":"§3.3","qid":"GK-W3-176"},"266":{"q":"During your pre-trip inspection you are securing a single 55-foot steel beam on a flatbed. You want to meet the minimum federal/Texas securement rule for the number of tie-downs based on cargo length. Counting only the by-length requirement, what is the FEWEST number of tie-downs you may legally use for this beam?","options":["6 tie-downs, because you need at least one per 10 feet of cargo and 55 feet rounds up to 6","5 tie-downs, because 55 divided by 10 equals 5 and you drop the remainder","7 tie-downs, because you need one per 10 feet plus one extra for any piece longer than 5 feet","4 tie-downs, because two tie-downs at each end are enough to immobilize any single beam"],"answer":0,"explanation":"One tie-down is required per 10 feet of cargo with any partial section rounded up, so a 55-foot load needs 6.","handbook":"Use one tie-down per 10 feet of cargo, and at least two.","hbref":"§3.3","qid":"GK-W3-177"},"267":{"q":"During your pre-trip inspection you are securing a single steel beam on your flatbed. It measures about 8 feet long and weighs roughly 3,000 pounds. You reason that since it is well under 10 feet, the \"one tie-down per 10 feet\" rule means a single tie-down is enough. Which statement correctly describes the MINIMUM number of tie-downs you must use?","options":["1 tie-down, because the beam is shorter than 10 feet and the per-10-foot rule controls","2 tie-downs, because any piece longer than 5 feet requires at least 2 regardless of the per-10-foot count","1 tie-down, because the beam weighs less than the 1,100-pound single tie-down threshold","No tie-downs are required for a single piece this short"],"answer":1,"explanation":"Any single article of cargo longer than 5 feet must have at least 2 tie-downs, regardless of the per-10-foot count.","handbook":"Cargo needs at least two tie-downs even when short.","hbref":"§3.3","qid":"GK-W3-178"},"268":{"q":"You normally run a stretch of rural highway at 25 mph, and from experience you know your loaded rig needs roughly 30 feet of braking distance there once the brakes take hold. Tonight you are running the same road, same load, same dry pavement, but at 50 mph. Compared with your usual 25 mph braking distance, your braking distance at 50 mph will be about:","options":["About the same, because the load and the pavement have not changed","About twice as long, because you have doubled your speed","About four times as long, because braking distance grows with the square of speed","About half as long, because the wheels turn faster and shed energy quicker"],"answer":2,"explanation":"Braking distance grows with the square of speed, so doubling your speed makes the braking distance about four times as long.","handbook":"Braking distance increases about four times when speed doubles.","hbref":"§2.6","qid":"GK-W3-179"},"269":{"q":"You are rolling along a dry, level highway at 55 mph in good weather when a stalled car suddenly appears in your lane far ahead. A passenger asks how much road it will actually take you to come to a complete stop from the moment you first spot the hazard. Counting perception, reaction, AND braking, which estimate of your total stopping distance is closest to correct?","options":["About 60 feet — roughly the distance your truck travels during reaction time alone","About 100 feet — a little more than one truck length","About 250 feet — the distance your low-beam headlights light up at night","About 419 feet — close to the length of a football field plus both end zones (around 6 seconds of travel)"],"answer":3,"explanation":"Total stopping distance is perception plus reaction plus braking distance, which at 55 mph adds up to about 419 feet (roughly 6 seconds).","handbook":"Total stopping distance at 55 mph is roughly 300 feet.","hbref":"§2.6","qid":"GK-W3-180"},"270":{"q":"You normally cruise at 30 mph on your in-town delivery route, but today a detour puts you on a 60 mph highway with the same dry pavement and the same loaded trailer. A new driver riding with you assumes that because you only doubled your speed, it will take about twice the distance to stop. How does roughly DOUBLING your speed actually change your braking distance?","options":["Braking distance increases by about four times, because it grows with the square of speed","Braking distance only about doubles, increasing in direct proportion to speed","Braking distance stays nearly the same because the loaded trailer adds traction","Braking distance increases only slightly, since reaction distance is what really grows with speed"],"answer":0,"explanation":"Braking distance increases with the square of speed, so doubling your speed makes it about four times longer, not just twice.","handbook":"Braking distance increases by the square of the speed.","hbref":"§2.6","qid":"GK-W3-181"},"271":{"q":"You are driving at highway speed when a deer suddenly steps onto the road well ahead of you. The very first phase of stopping is PERCEPTION: the time from the instant the deer first enters your field of view until your brain actually recognizes it as a hazard. This phase happens before you even begin to move your foot toward the brake. For an alert driver at about 55 mph, roughly how much TIME does this perception phase by itself take?","options":["About 3/4 of a second, which is actually the reaction time it takes to move your foot to the pedal after the hazard is already recognized","About 1.75 seconds, the time the handbook gives for perceiving and recognizing a hazard at highway speed before any reaction begins","About 6 seconds, which is really the total time to stop completely from 55 mph, not just the perception phase","About one-tenth of a second, since an alert professional driver perceives hazards almost instantly"],"answer":1,"explanation":"Perception is the time your brain needs to see and recognize a hazard, about 1.75 seconds at highway speed before any reaction begins.","handbook":"Perception plus reaction time totals roughly 1.75 seconds.","hbref":"§2.6","qid":"GK-W3-182"},"272":{"q":"You are rolling at 55 mph on a dry interstate when a stalled car suddenly appears in your lane far ahead. By the time you fully halt, your rig has traveled roughly the length of a football field plus both end zones (about 419 feet). Instructors break this total stopping distance into three parts: the distance your truck covers while you SEE the hazard (perception distance), the distance it covers while you move your foot to the pedal (reaction distance), and one more part. Which part completes total stopping distance?","options":["Steering distance — the distance traveled while you swing the wheel to go around the obstacle","Signaling distance — the distance covered while you activate your hazard flashers to warn traffic","Braking distance — the distance the truck travels after the brakes grab until it comes to a complete stop","Parking distance — the extra room you leave at the curb once you have safely pulled over"],"answer":2,"explanation":"The third component of total stopping distance is braking distance, how far the truck travels after the brakes are applied until it fully stops.","handbook":"Total stopping distance is perception plus reaction plus braking distance.","hbref":"§2.6","qid":"GK-W3-183"},"273":{"q":"You are driving your 20-foot straight truck on a level highway in good weather, holding a steady 35 mph through light traffic. You want to leave the correct minimum following distance behind the car ahead. Using the rule of 1 second for every 10 feet of vehicle length, how many seconds of following space should you keep at this speed?","options":["4 seconds, because you should always add a full extra second for every 10 feet of truck length","3 seconds, adding 1 second to the length-based figure because highway traffic is unpredictable","1 second, since at 35 mph you are below 40 mph and the extra-second rule does not apply","2 seconds, because 20 feet of length gives 2 seconds and no second is added below 40 mph"],"answer":3,"explanation":"Below 40 mph you need 1 second of following distance for every 10 feet of vehicle length, so a 20-foot vehicle needs 2 seconds.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-184"},"274":{"q":"You are hauling a 20-foot straight truck on a dry interstate at a steady 55 mph in clear weather. Traffic is light and you want to set a safe following distance behind the car ahead. Using the rule for judging following distance by vehicle length and speed, how many seconds of space should you keep?","options":["3 seconds","2 seconds","4 seconds","6 seconds"],"answer":0,"explanation":"Allow 1 second of following distance for every 10 feet of vehicle length, then add 1 more second when traveling above 40 mph.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-185"},"275":{"q":"You are driving a straight truck that measures 30 feet from bumper to bumper. Traffic is moving steadily through town and your speedometer reads 35 mph. To keep a safe cushion in front of you, what is the minimum following distance you should maintain behind the vehicle ahead?","options":["2 seconds, because the road is level and you are well below highway speed","3 seconds, because you allow 1 second for every 10 feet of your vehicle's length at this speed","4 seconds, adding 1 extra second to your length-based gap since you are in traffic","5 seconds, matching the cushion used at higher highway speeds for a vehicle this size"],"answer":1,"explanation":"Allow 1 second of following distance for every 10 feet of vehicle length, with no extra second added at speeds below 40 mph.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-186"},"276":{"q":"You are hauling a single 30-foot straight truck on a dry interstate, holding a steady 55 mph in light traffic. To keep a safe cushion behind the car ahead, you pick a fixed object on the roadside and count the seconds until your front bumper reaches it. How many seconds of following distance should you keep in this situation?","options":["3 seconds, because the rule is 1 second for every 10 feet of vehicle length","5 seconds, allowing 1 extra second beyond what the length-and-speed rule requires","4 seconds, because 30 feet gives 3 seconds and you add 1 more second for being above 40 mph","2 seconds, the same minimum gap a passenger car keeps at highway speed"],"answer":2,"explanation":"Allow 1 second of following distance for every 10 feet of vehicle length, then add 1 more second when traveling above 40 mph.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-187"},"277":{"q":"You are hauling a 40-foot straight load down a dry, level highway and your speedometer settles at 50 mph in light traffic. To leave yourself a safe cushion behind the vehicle ahead, how many seconds of following distance should you keep in this situation?","options":["4 seconds, because you allow 1 second for each 10 feet of your vehicle's length","6 seconds, since that matches the total stopping distance a truck needs at highway speed","3 seconds, following the standard 3-second rule that applies to all vehicles","5 seconds, because you add 1 extra second to the length-based count when you are going faster than 40 mph"],"answer":3,"explanation":"Allow 1 second of following distance for every 10 feet of vehicle length, then add 1 more second when traveling above 40 mph.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-188"},"278":{"q":"You are hauling a 60-foot combination on a dry interstate, holding a steady 50 mph in light traffic. A four-wheeler ahead is setting your pace, and you want to leave a safe gap. Using the basic following-distance rule from the handbook, how many seconds of space should you keep behind that vehicle?","options":["7 seconds, because 60 feet of length gives 6 seconds, plus 1 extra second for traveling above 40 mph","6 seconds, because you allow 1 second for every 10 feet of vehicle length","8 seconds, because you add 2 seconds for highway speed on top of the 6 seconds for length","5 seconds, because a 60-foot vehicle at moderate speed needs about half of one second per 5 feet"],"answer":0,"explanation":"Allow 1 second of following distance for every 10 feet of vehicle length, then add 1 more second when traveling above 40 mph.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-189"},"279":{"q":"You are hauling a 70-foot tractor-trailer on a dry interstate, cruising at a steady 55 mph in clear daytime conditions. The driver ahead of you brakes lightly and you realize you have drifted closer than you should be. Using the rule of thumb for following distance, what is the MINIMUM gap you should be keeping behind that vehicle?","options":["7 seconds, because you allow 1 second for every 10 feet of your vehicle's length","8 seconds, because you allow 1 second for every 10 feet of length and add 1 more second for traveling over 40 mph","6 seconds, because total stopping distance at 55 mph is about 6 seconds","9 seconds, allowing 1 second for every 10 feet plus 2 extra seconds for highway speed"],"answer":1,"explanation":"Allow 1 second of following distance for every 10 feet of vehicle length, then add 1 more second when traveling above 40 mph.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-190"},"280":{"q":"You are hauling a load through a 35 mph construction corridor in a combination rig that measures 90 feet from bumper to bumper. Traffic is steady, the pavement is dry, and you want to set a safe following distance using the rule of seconds for vehicle length. How many seconds of following distance should you keep behind the vehicle ahead in this situation?","options":["10 seconds, because any combination vehicle this long needs one extra second added regardless of speed","8 seconds, because you round the 90-foot length down to the nearest whole rule interval","9 seconds, because you allow 1 second for every 10 feet of vehicle length and your speed is under 40 mph","11 seconds, because you allow 1 second per 10 feet and add a full extra second for the work zone"],"answer":2,"explanation":"Allow 1 second of following distance for every 10 feet of vehicle length, with no extra second added at speeds below 40 mph.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-191"},"281":{"q":"You are hauling a 90-foot combination on a level interstate and your speedometer reads a steady 60 mph in clear, dry weather. Traffic ahead is moving freely. Using the handbook rule for judging a safe following gap, how many seconds of space should you keep between the front of your rig and the vehicle ahead?","options":["8 seconds, because at 60 mph you reduce the base figure to account for the higher highway speed","11 seconds, adding 2 extra seconds because you are well above 40 mph","9 seconds, since you simply count 1 second for each 10 feet of vehicle length","10 seconds, counting 1 second per 10 feet of length and adding 1 more second for speed above 40 mph"],"answer":3,"explanation":"Allow 1 second of following distance for every 10 feet of vehicle length, then add 1 more second when traveling above 40 mph.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-192"},"282":{"q":"You are hauling a 100-foot-long combination on a flat, dry rural highway and your speedometer is holding steady at 35 mph. A four-wheeler ahead of you is moving at the same speed, and you want to set a safe following distance. Counting the seconds it takes for your front bumper to reach a fixed marker the vehicle ahead just passed, what is the MINIMUM following distance you should keep?","options":["10 seconds","11 seconds","9 seconds","7 seconds"],"answer":0,"explanation":"Allow 1 second of following distance for every 10 feet of vehicle length, with no extra second added at speeds below 40 mph.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-193"},"283":{"q":"You are pulling a flatbed and your tractor-trailer measures right at 100 feet bumper to bumper. Traffic on the rural highway has settled in and your speedometer is holding steady at 45 mph in dry, clear conditions. Counting the seconds as a vehicle ahead passes a fixed marker, how many seconds of following distance should you be keeping behind that vehicle?","options":["10 seconds, since you allow 1 second for each 10 feet of your vehicle's length","11 seconds, because 100 feet calls for 10 seconds and you add 1 more second for being above 40 mph","12 seconds, allowing 1 second per 10 feet plus 2 extra seconds for highway speed","9 seconds, rounding the 100-foot rig down for the dry pavement"],"answer":1,"explanation":"Allow 1 second of following distance for every 10 feet of vehicle length, then add 1 more second when traveling above 40 mph.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-194"},"284":{"q":"You are hauling a 60-foot-long combination on a dry interstate, holding a steady 60 mph in light traffic. Recalling the following-distance rule from the handbook, what is the LEAST amount of space you should keep between yourself and the vehicle ahead?","options":["6 seconds, because a 60-foot vehicle needs 1 second for each 10 feet of length","5 seconds, since traffic is light and the road is dry","7 seconds, allowing 1 second per 10 feet of length plus 1 extra second for being above 40 mph","8 seconds, adding 2 seconds to the base figure because highway speed is involved"],"answer":2,"explanation":"Allow 1 second of following distance for every 10 feet of vehicle length, then add 1 more second when traveling above 40 mph.","handbook":"Keep 1 second per 10 feet of length, plus 1 more over 40 mph.","hbref":"§2.6","qid":"GK-W3-195"},"285":{"q":"You are driving a loaded tractor-trailer at highway speed on a dry two-lane road at dusk when a large deer bolts out of the tree line and freezes in your lane about 150 feet ahead. The left lane appears clear and there is a paved shoulder to your right. Which action is usually the SAFEST response?","options":["Quickly steer into the left lane to go around the animal, since it looks clear","Swerve onto the right shoulder and accelerate past the deer before it moves","Take your hands off the wheel and let the truck track straight on its own","Apply firm, controlled braking and stay in your lane"],"answer":3,"explanation":"Brake firmly and stay in your lane, since a sudden hard swerve can roll over or jackknife a high-center-of-gravity rig.","handbook":"Brake and stay in your lane rather than swerve a large truck.","hbref":"§2.8","qid":"GK-W3-196"},"286":{"q":"You are running a loaded combination on a divided highway when the lane funnels into a work zone. Orange signs drop the posted limit well below the highway speed, a flagger is positioned ahead, and workers are moving near the open lane. Traffic around you is still rolling at near-highway speed. Which action is the safest and legally correct response?","options":["Reduce your speed to the posted work-zone limit and stay alert for workers, equipment, and the flagger's signals","Hold your following-distance gap and maintain highway speed since you are already leaving 7 seconds of space ahead of you","Keep pace with the surrounding traffic so you do not create a dangerous speed difference between vehicles","Move into the faster lane and pass the slowing vehicles to clear the work zone as quickly as possible"],"answer":0,"explanation":"Slow to the posted work-zone limit and stay alert for workers, equipment, and the flagger who controls traffic in the zone.","handbook":"Slow to the work-zone speed limit and watch for workers.","hbref":"§2.6","qid":"GK-W3-197"},"287":{"q":"You are pulling out of a curve on a damp two-lane highway and you press the accelerator to regain highway speed. Your tachometer suddenly jumps and you feel the rear of your tractor start to swing out as the drive wheels lose traction and spin. Which action gives you the BEST chance to recover control?","options":["Apply the brakes firmly to slow the spinning drive wheels and tighten your line through the curve","Ease off the accelerator to let the drive wheels slow down and steer in the direction you want the truck to go","Steer sharply the opposite way from the curve to counter the swing as fast as you can","Keep steady pressure on the accelerator so the powered wheels pull you straight out of the slide"],"answer":1,"explanation":"To recover from a drive-wheel skid, ease off the accelerator so the wheels regain traction and steer where you want the truck to go.","handbook":"To recover from a drive-wheel skid, ease off the gas and steer where you want to go.","hbref":"§2.7","qid":"GK-W3-198"},"288":{"q":"You are hauling a partial load with a high center of gravity on a rural two-lane highway. Coming out of a hill you realize the upcoming curve is banking tighter than the sign warned, and you have entered it carrying more speed than is comfortable. Which action gives you the BEST chance of staying in your lane without a skid or rollover?","options":["Brake hard and firmly through the apex of the curve to scrub off the excess speed quickly","Shift into a higher gear and accelerate to push the truck through the turn before it can tip","Recognize you should have slowed before the curve, so ease off the throttle and use only light, gradual braking while keeping the truck steady through the turn","Press in the clutch and coast through the curve in neutral so the drive wheels cannot lose traction"],"answer":2,"explanation":"Inside a curve, ease off the throttle and use only light, gradual braking, since hard braking shifts weight and can break traction.","handbook":"Slow before a curve, not within it.","hbref":"§2.6","qid":"GK-W3-199"},"290":{"q":"You are driving a loaded combination at 60 mph on a dry interstate, staying close behind a box truck so cars cannot merge in front of you. The box truck's brake lights flash and it stops hard for stalled traffic; you stab the brakes and stop with only inches to spare. Reviewing the near-miss afterward, which action would have given you the time and space you actually needed to stop safely?","options":["Followed at 4 seconds, because that is the total stopping distance at 55 mph (about 419 feet)","Stayed exactly where you were but braked a half-second sooner the instant the brake lights flashed","Closed the gap even tighter so no car could cut in and force you to brake at all","Followed far enough back to keep a safe following distance, giving you time to perceive, react, and brake before reaching the truck"],"answer":3,"explanation":"Keep a safe following distance because total stopping distance is perception plus reaction plus braking distance, adding up to hundreds of feet.","handbook":"A safe following distance gives you time to react to sudden stops.","hbref":"§2.7","qid":"GK-W3-200"},"291":{"q":"It is well past dusk and you have turned onto a narrow two-lane country road you have never driven before. There are no streetlights, the shoulders are unmarked, and you cannot see far beyond your headlights. To drive this stretch most safely, what should you do?","options":["Reduce your speed so that you can always stop within the distance lit by your headlights, and use your high beams where no oncoming traffic is present","Keep up with the speed of the few cars ahead of you so you are not driving slower than the flow of traffic","Switch on your high beams and leave them on continuously so you can see as far down the road as possible","Maintain your normal daytime cruising speed since reducing speed at night makes you a hazard to faster traffic"],"answer":0,"explanation":"Never overdrive your headlights—keep your speed low enough to stop within the distance lit ahead, and use high beams where no oncoming traffic is present.","handbook":"Slow down on unfamiliar roads at night and use your headlights well.","hbref":"§2.11","qid":"GK-W3-201"},"293":{"q":"You are driving your tractor-trailer through a downtown business district at about 25 mph in light traffic. As you approach an unmarked mid-block area, a pedestrian who was standing on the curb suddenly steps off into the street several car-lengths ahead of you, looking down at a phone and not toward you. Your lane to the right is blocked by parked cars and there is oncoming traffic to your left. Which action is the safest and legally correct response?","options":["Sound your horn firmly and maintain your speed, since you have the right of way in your lane and the pedestrian will likely step back","Ease off the accelerator, cover the brake, slow down, and be prepared to stop for the pedestrian","Steer slightly into the oncoming lane to go around the pedestrian, then return to your lane once clear","Accelerate briefly to clear the area before the pedestrian fully enters your path"],"answer":1,"explanation":"For a pedestrian who has stepped into the roadway, ease off the accelerator, cover the brake, slow down, and be ready to stop.","handbook":"Slow down and be ready to stop for a pedestrian.","hbref":"§2.8","qid":"GK-W3-202"},"294":{"q":"You are driving a loaded combination vehicle on a four-lane interstate and need to move one lane to the left to set up for an exit about two miles ahead. You signal, check your left-side mirrors, and start to drift over, but as you do you realize a passenger car is riding alongside your tractor in the area your mirrors do not fully cover. Which action is the best and safest response?","options":["Maintain your drift into the lane while tapping your brakes, since your brake lights will alert the car to fall back and open the gap for you","Accelerate firmly to pull your tractor ahead of the car so it ends up behind your trailer, then complete the lane change before the next mirror check","Cancel the lane change, hold your position, wait for a clear gap, and re-check the mirror and that blind-spot area before attempting to move over again","Continue the lane change because you already signaled early and completed your mirror check, and a driver who is alongside is responsible for yielding to a signaling truck"],"answer":2,"explanation":"A vehicle in your blind spot means the lane is not clear, so cancel the lane change and re-check the mirror and blind spot before moving over.","handbook":"Do not change lanes until your blind spot is clear.","hbref":"§2.7","qid":"GK-W3-203"},"296":{"q":"You are driving a loaded tractor-trailer in the right lane of a busy four-lane highway at 55 mph. A slow-moving maintenance truck appears ahead in your lane, and you decide you need to move into the left lane to keep your speed. Traffic is heavy on both sides. Which sequence is the safest and correct way to complete this lane change?","options":["Speed up quickly to create a gap, then swing into the left lane before anyone can fill it","Brake hard first to open room behind you, then move into the left lane once you have slowed","Glance once at your left mirror and ease over smoothly, since signaling on a busy road only confuses other drivers","Turn on your left signal early, check your mirrors and your left blind spot (the 'No-Zone'), and move over only after you confirm the lane is clear"],"answer":3,"explanation":"Signal early, check your mirrors and the left blind spot (the No-Zone), and move over only after confirming the lane is clear.","handbook":"Signal, check mirrors and blind spots, then change lanes when clear.","hbref":"§2.7","qid":"GK-W3-204"},"297":{"q":"During your pre-trip inspection you discover the previous driver replaced a single damaged tire. The new tire is a radial, but the other tire next to it on the same axle is a bias-ply. The two remaining axle positions are matched. Which condition is the one you must correct before this truck is legal and safe to drive?","options":["Having a radial tire mounted next to a bias-ply tire on the same axle","A steering-axle tire showing 4/32 inch of tread depth","A rear (non-steering) tire showing 2/32 inch of tread depth","Having two tires of the same brand but different purchase dates on one axle"],"answer":0,"explanation":"Radial and bias-ply tires must never be mixed on the same axle because their different construction causes uneven, unpredictable traction and handling.","handbook":"Do not mix radial and bias-ply tires on the same axle.","hbref":"§2.1","qid":"GK-W3-205"},"298":{"q":"During your pre-trip inspection, you find that one of your drive-axle tires has a section where the tread is peeling away from the body of the tire, plus a long gash deep enough to expose the cord underneath. The tire still holds air and the tread depth elsewhere measures well above 2/32 inch. What is the correct call on this tire?","options":["It is legal to drive because the remaining tread depth is still above the 2/32 inch minimum for a non-steering tire","The tire is out of service and must be replaced before the vehicle is driven, regardless of tread depth or air pressure","It is acceptable for a short local trip as long as you keep your speed down and re-check it at the first stop","It is only a minor defect because the tire is on the drive axle and not the steering axle"],"answer":1,"explanation":"Tread separation or a deep cut exposing the ply is an out-of-service condition, so the tire must be replaced before driving regardless of tread depth or air pressure.","handbook":"A tire with tread separation or a large cut is out of service.","hbref":"§2.1","qid":"GK-W3-206"},"299":{"q":"During your pre-trip inspection you find a tire with a recapped (retreaded) surface and another with regrooved sidewall markings. You have a delivery deadline and want to keep these tires in service somewhere on your rig rather than replace them. On which single wheel position would mounting a regrooved or recapped tire be PROHIBITED, forcing you to put a proper new tire there instead?","options":["On a rear trailer axle, because trailer tires carry the heaviest load and wear fastest","On an inside dual position, because a hidden recap there is the hardest to inspect","On a front (steer) axle position, where a regrooved or recapped tire is not permitted","On the spare wheel, because a recap is never allowed to be carried as a backup"],"answer":2,"explanation":"Regrooved, recapped, or retreaded tires are prohibited on the front steer axle because a steer-tire failure there causes immediate loss of steering control.","handbook":"Regrooved or recapped tires are not allowed on the front steer axle.","hbref":"§2.1","qid":"GK-W3-207"},"300":{"q":"During your pre-trip inspection, you crouch down to examine the dual tires on your trailer's rear axle. Both tires appear to be the same size and brand, with good tread depth. As you look closely at the gap between them, you must decide which condition would make this dual set illegal and unsafe to drive on. Which of the following is the defect you must NOT allow?","options":["The two tires are the exact same size and have matching tread patterns","Both tires are inflated firm and hold roughly the same air pressure","Each tire shows well above the 2/32 inch minimum tread on the rear axle","The two tires are bulging inward and making contact with each other"],"answer":3,"explanation":"Dual tires must never touch each other or any part of the vehicle, since contact signals under-inflation or bad mounting and the rubbing heat can cause a blowout.","handbook":"Dual tires must not touch each other or any part.","hbref":"§2.1","qid":"GK-W3-208"},"301":{"q":"During your pre-trip inspection on a cold morning, you find a visible crack running across one of the wheel rims on your drive axle. The tire holds air, the tread is good, and you are already running late for a delivery. Which action is correct?","options":["Place the vehicle out of service and do not drive until the cracked rim is repaired or replaced","Drive carefully to the delivery since the tire still holds air and the tread depth is fine","Air the tire down a few pounds to relieve stress on the rim, then continue at reduced speed","It is only a minor cosmetic crack, so log it as normal wear and re-check it at your first 50-mile cargo stop"],"answer":0,"explanation":"A cracked or broken wheel rim is an automatic out-of-service condition because it can fail under load and separate the tire from the wheel at speed.","handbook":"Cracked or broken wheel rims are out of service.","hbref":"§2.1","qid":"GK-W3-209"},"302":{"q":"During your pre-trip inspection you crawl under the trailer and find that one leaf in the rear suspension's leaf spring is cracked through and a second leaf has shifted out of its mounting. The truck still sits level in the yard and rides fine on the short test loop. What is the correct way to classify and handle this finding before your run?","options":["Because the truck sits level and rides fine, the cracked leaf is cosmetic and you may run it and monitor it during the trip","It is a suspension defect that must be repaired before the vehicle is put in service","It is acceptable as long as you re-check the cargo securement within the first 50 miles","It is a normal condition that actually improves the ride and requires no action"],"answer":1,"explanation":"Cracked, broken, loose, missing, or shifted leaf springs are an out-of-service suspension defect that must be repaired before the vehicle goes into service.","handbook":"Loose, missing, or broken leaf springs are a defect.","hbref":"§2.1","qid":"GK-W3-210"},"303":{"q":"It is early morning and you are walking around your tractor-trailer during the pre-trip inspection. At the rear suspension you spot a wet, oily film coating one of the shock absorbers, and a thin trail of fluid running down to the dust shield. Everything else on that axle looks normal. What is the correct conclusion about this component, and what must you do?","options":["The oily film is just road grime thrown up from the tires, so the shock absorber is fine to leave as-is and you may proceed with the trip.","Shock absorbers are designed to weep a small amount of oil to stay lubricated, so a light film is acceptable and only a heavy, dripping leak would be a defect.","A leaking shock absorber is a defect; shock absorbers must be secure and free of leaks, so this must be repaired before the vehicle is safe to drive.","Shock absorbers carry no load and only affect ride comfort, so a leak is a minor cosmetic issue you can simply note and address at the next 150-mile cargo check."],"answer":2,"explanation":"Shock absorbers must be securely mounted and free of leaks, so a leaking shock is a reportable defect that must be repaired before the vehicle is safe to drive.","handbook":"Shock absorbers must be secure and not leaking.","hbref":"§2.1","qid":"GK-W3-211"},"304":{"q":"During your pre-trip inspection you crawl under the tractor and find a fresh crack running through a frame rail near a leaf-spring hanger, and one of the engine mounts is visibly loose. You are already running late for a short 40-mile local delivery on flat city streets. Which action is correct?","options":["Because it is only a short, low-speed trip on flat streets, you may drive it to the delivery and report the crack afterward","Wrap the cracked area tightly with heavy-duty tape and tighten what you can by hand so it holds until the end of the day","Drive at reduced speed and re-inspect the frame and mounts within the first 50 miles, since that is when securement must be checked","Place the vehicle out of service and have the cracked frame and loose mounts repaired before you drive it at all"],"answer":3,"explanation":"A cracked frame or loose mount is a structural out-of-service defect because the frame carries every load path and a crack can propagate and fail catastrophically.","handbook":"A cracked frame or loose mounts must be repaired before driving.","hbref":"§2.1","qid":"GK-W3-212"},"305":{"q":"It is just below freezing on an early-morning haul, so you keep the cab windows rolled up and the heater running. During your pre-trip you noticed a small leak where an exhaust pipe meets the muffler, but the engine still ran fine, so you decided to drive. An hour later you feel drowsy and slightly headachy. Which consequence of that exhaust leak is the MOST serious reason you should have fixed it before driving?","options":["Exhaust gases, including carbon monoxide, can seep into the closed cab and poison you","The leak lets cold outside air into the cab and overworks the heater","The escaping exhaust lowers engine power and wastes fuel on the grade","The leak makes the engine run louder and may mask other warning sounds"],"answer":0,"explanation":"A leaking exhaust system is dangerous because exhaust gases including carbon monoxide can seep into a closed cab and poison the driver.","handbook":"A leaking exhaust can let dangerous fumes into the cab.","hbref":"§2.1","qid":"GK-W3-213"},"306":{"q":"During your pre-trip inspection, you open the battery box and find the battery shifting slightly with a small puddle of fluid in the tray beneath it. The cables are connected and the truck cranks fine. Under Texas DPS inspection standards, what condition must the battery meet before you can legally take this vehicle on the road?","options":["It only needs to be charged enough to start the engine, since cranking power proves the battery is roadworthy","It must be held firmly in place by a hold-down so it cannot move, and it must not be leaking","Minor electrolyte leakage is acceptable as long as the fluid level stays above the plates","A loose battery is fine on short trips because the cables alone keep it from moving"],"answer":1,"explanation":"A battery must be held firmly by a hold-down so it cannot move and must show no leaks, since a shifting or leaking battery can short out, crack, or spill corrosive acid.","handbook":"The battery must be secure and not leaking.","hbref":"§2.1","qid":"GK-W3-214"},"307":{"q":"You pull into a fuel island at the end of a long haul. Your trailer reefer unit is still running, your phone is at 8% so you want to make a quick call, and a co-driver waiting nearby just lit a cigarette about 20 feet from the pumps. Before you begin putting diesel into the tank, which of the following is the correct action to take?","options":["Leave the engine idling so the air system and reefer stay charged, but keep the fuel nozzle steady and pump slowly","Keep the truck running but step away to take your phone call while the tank fills, since the auto shut-off nozzle will stop the flow","Shut off the engine, do not smoke and allow no smoking near the fuel point, and stay at the nozzle while fueling","Let the cigarette stay since it is more than 15 feet away, and rev the engine briefly first to clear the lines before fueling"],"answer":2,"explanation":"Diesel vapors ignite easily, so the engine must be off with no smoking at the fuel point and someone attending the nozzle the entire time.","handbook":"Turn off the engine and do not smoke while fueling.","hbref":"§2.1","qid":"GK-W3-215"},"309":{"q":"It is just below freezing on a winter morning and you are doing your pre-trip inspection before a long haul. You are working through the engine compartment and want to make sure your vehicle will not overheat or freeze up once you are rolling in the cold. Which check directly protects the cooling system against the winter conditions you are facing?","options":["Confirm the windshield washer reservoir is topped off so you can clear road slush from the glass","Top off the radiator with plain water so the coolant level reads full on the sight glass","Add extra engine oil because cold weather makes the oil thicken and burn off faster","Verify the coolant has enough antifreeze to keep it from freezing in low temperatures"],"answer":3,"explanation":"Antifreeze lowers the coolant's freezing point, so in cold weather you must confirm there is enough to keep the coolant from freezing and cracking the engine.","handbook":"In winter, make sure the coolant has enough antifreeze.","hbref":"§2.11","qid":"GK-W3-216"},"310":{"q":"It is just below freezing on a mountain pass, snow is falling, and a posted sign says chains are required beyond this point. You stop and mount tire chains on your drive tires. What is the PRIMARY reason the chains help you keep moving safely up the grade?","options":["They bite into the snow and ice, giving your drive tires the traction needed to grip a slick surface","They reduce rolling resistance, which lowers your fuel use on the long climb","They let you legally carry more weight over the drive axle on a snow-covered road","They cushion the ride and make the truck run quieter over packed snow"],"answer":0,"explanation":"Tire chains bite into snow and ice so the drive tires can grip a slick surface and transmit power without spinning.","handbook":"Tire chains add traction on snow or ice.","hbref":"§2.11","qid":"GK-W3-217"},"311":{"q":"You are driving a loaded combination vehicle on a divided highway at night and notice the passenger car ahead of you behaving strangely. Which observation is the STRONGEST sign that the driver ahead may be drunk or impaired, telling you to increase your following distance and prepare to let them get well ahead of you?","options":["The car maintains a steady speed and stays centered in its lane through a gentle curve","The car drifts back and forth across the lane lines and keeps speeding up and slowing down for no clear reason","The car signals its lane change early and waits for a clear gap before moving over","The car gradually slows and moves to the right shoulder with its hazard flashers on"],"answer":1,"explanation":"Drifting across lane lines along with erratic, unexplained speeding up and slowing down are classic signs of an impaired driver, so give them plenty of room.","handbook":"Weaving or erratic speed can be a sign of an impaired driver.","hbref":"§2.8","qid":"GK-W3-218"},"313":{"q":"You are driving a loaded tractor-trailer on a rural highway when your accelerator pedal suddenly sticks to the floor and the engine keeps racing even after you lift your foot. Traffic is light and there is a paved shoulder ahead. Which is your FIRST priority action to regain control of the vehicle?","options":["Pump the accelerator pedal rapidly with your foot to try to free it, keeping your gear engaged so you do not lose engine braking","Immediately switch off the engine with the ignition key while still in gear so the drive wheels stop pulling the truck forward","Shift to neutral to disconnect the engine from the drive wheels, then apply the brakes to slow and stop the vehicle safely","Stay in gear and rely only on steady, light brake pressure to overpower the engine until you reach the shoulder"],"answer":2,"explanation":"Shifting to neutral disconnects the engine from the drive wheels so the brakes can slow and stop the vehicle when the accelerator sticks.","handbook":"If the accelerator sticks, shift to neutral and brake.","hbref":"§2.14","qid":"GK-W3-219"},"314":{"q":"You smell something burning and pull over safely. When you open the cab, you see flames coming from behind the dashboard near the wiring, and the battery and alternator circuits appear to be involved. You have a fire extinguisher mounted in the cab. Which action gives you the BEST and safest chance of controlling this fire?","options":["Leave the power on so you can see the wiring, then aim a steady stream of water at the base of the flames to cool them down","Open the engine hood and rear doors wide to let the heat and smoke escape before doing anything else","Keep the engine running so the alternator keeps charging, and smother the flames with a damp rag from your cab","If you can, shut off the electrical power (disconnect the battery/turn off the ignition), then put it out with a B:C fire extinguisher"],"answer":3,"explanation":"For an electrical fire, first shut off the power if safe to remove the ignition source, then extinguish it with a B:C-rated extinguisher rather than water.","handbook":"For an electrical fire, disconnect power and use a B:C extinguisher.","hbref":"§2.14","qid":"GK-W3-220"},"315":{"q":"Just after you crest a hill, your engine loses power and you coast to a stop in the right lane of a two-lane rural highway. You switch on your hazard flashers and grab your emergency triangles. Your co-driver says there's no rush since traffic is light. According to the rules for stopping on the road, what is the LONGEST you should wait before your warning devices are placed?","options":["Within 10 minutes of stopping","Within 1 hour of stopping, as long as the flashers stay on","Within 1 minute of stopping","By the end of your driving day, since the hazards already warn traffic"],"answer":0,"explanation":"After stopping on a roadway or shoulder, turn on hazard flashers at once and place your three reflective warning triangles within 10 minutes.","handbook":"Put out warning devices within 10 minutes of stopping.","hbref":"§2.14","qid":"GK-W3-221"},"316":{"q":"Your rig has jackknifed on a rural two-lane and the driver of the car you clipped is slumped over, conscious but complaining of neck pain. Traffic is light, the weather is clear, and you can smell coolant but see no smoke or flames. Following Texas DPS guidance, when should you pull this injured person out of the vehicle?","options":["Right away, since a sore neck means a spinal injury that needs you to lay them flat on the ground","Only if a real danger such as fire develops; otherwise leave them where they are and wait for trained help","As soon as you have set out your three reflective triangles at 10, 100, and 200 feet","Whenever traffic starts backing up, so the lane can be reopened to keep other drivers safe"],"answer":1,"explanation":"Do not move an injured person unless a real danger like fire threatens them, since moving someone with neck or spine trauma can cause permanent paralysis.","handbook":"Do not move an injured person unless there is danger like fire.","hbref":"§2.14","qid":"GK-W3-222"},"317":{"q":"It is 5:30 a.m. and you have a delivery deadline. Last night you had several beers and stopped drinking about four hours ago. To feel ready to drive, you drink two large black coffees, take a brisk walk in the cold morning air, and check the cab thermometer. Which of these will actually lower the alcohol still in your bloodstream so you are safe and legal to operate your CMV?","options":["The cold morning air, because deep breathing of fresh air helps the body flush alcohol out faster","The two large black coffees, because the caffeine speeds up your metabolism and burns off the remaining alcohol","None of those actions; only the passage of enough time will remove the alcohol from your blood and bring your BAC under the 0.04% limit","All three together, since coffee, cold air, and being alert combine to sober you up before your shift"],"answer":2,"explanation":"Only time lets the liver metabolize alcohol and lower your BAC; coffee, fresh air, or feeling alert cannot speed up the process.","handbook":"Only time will sober up a person who has been drinking.","hbref":"§2.20","qid":"GK-W3-223"},"318":{"q":"You are 9 hours into a long haul and starting to feel drowsy. A fellow driver at the truck stop offers you caffeine pills and \"uppers\" (stimulants), claiming they will keep you sharp enough to finish your run safely. Which of the following is the BEST reason to refuse and instead stop to rest?","options":["Stimulants are fine as long as you also drink coffee and get some fresh air to balance them out","Stimulants sharpen your reaction time and improve your night vision, but they are illegal to carry in the cab","Stimulants are acceptable only on grades longer than 419 feet where you need extra alertness","Stimulants do not make you a safe driver; when their effect wears off you may be more tired and dangerous than before"],"answer":3,"explanation":"Stimulants only mask fatigue temporarily and do not make you safe; when they wear off you can become more tired and dangerous than before.","handbook":"Stimulant drugs do not make you a safe driver.","hbref":"§2.20","qid":"GK-W3-224"},"319":{"q":"You are driving in the right lane of a four-lane highway at 55 mph. About a quarter mile ahead, you see a disabled car pulled onto the right shoulder with its hazard flashers on, and a person standing beside it near the trunk. Why should you treat this as a hazard and begin adjusting now, rather than waiting until you are closer?","options":["The stopped car or the person beside it could suddenly move into your lane, so you should slow, increase your following space, and move left if it is safe.","The shoulder is the legal travel area for slow traffic, so you must move onto it to give the disabled car the full lane.","It is only a hazard if the driver has failed to place the three warning triangles at 10, 100, and 200 feet, otherwise you can maintain speed.","A disabled car on the shoulder poses no real risk as long as its flashers are on, so no change in speed or position is needed."],"answer":0,"explanation":"A stopped car or a person beside it can suddenly enter your lane, so slow down, increase your following space, and move left when safe.","handbook":"A disabled vehicle on the shoulder is a hazard because it or people may enter your path.","hbref":"§2.8","qid":"GK-W3-225"},"320":{"q":"You pull into a rest area mid-route, and before climbing back into the cab you crouch down and take a quick look underneath your tractor-trailer. Aside from confirming nothing is dragging, what is the MAIN safety reason the handbook recommends this brief ground-level glance under the vehicle at a stop?","options":["It lets you read the tire tread depth gauge to confirm the steer tires still have at least 4/32 inch remaining","It can reveal fresh fluid leaks, an underinflated or flat tire, and people or objects that may be under or behind the rig before you move","It satisfies the requirement to re-inspect and re-secure your cargo within the first 50 miles of the trip","It is how you place your three warning triangles at 10, 100, and 200 feet before pulling away"],"answer":1,"explanation":"A ground-level check before moving reveals fresh fluid leaks, a flat or underinflated tire, and people or objects under or behind the rig.","handbook":"A look under the vehicle can reveal leaks, low tires, or people.","hbref":"§2.8","qid":"GK-W3-226"},"321":{"q":"You are hauling a loaded trailer and reach the crest of a long, steep mountain downgrade. A posted sign warns of a 6% grade ahead. To keep your brakes from fading on the way down, when should you choose the low gear you will use for the descent?","options":["At the point where you first feel the brakes starting to overheat and fade","About halfway down the grade, once you can judge how steep it really is","Before you start down the grade, while you are still at the top","Only if the load shifts or your speed climbs above a safe level"],"answer":2,"explanation":"Select a low gear before starting down a long, steep grade, while you are still at the top.","handbook":"Select a low gear before starting down a long grade.","hbref":"§2.13","qid":"GK-W3-227"},"322":{"q":"You are hauling a loaded trailer down a long, steep mountain grade. About halfway down you notice the smell of hot brakes and the pedal is starting to feel softer than it did at the top. Of the following, which action gives you the safest control of your speed for the rest of the descent?","options":["Press and hold steady, firm pressure on the brake pedal the whole way down to keep the speed pinned","Shift into neutral so the engine cools off, then ride the brakes lightly to the bottom","Pump the brake pedal rapidly to build the air pressure back up and restore a firm pedal","Stay in a low gear so the engine helps hold you back, and use only light, intermittent brake applications"],"answer":3,"explanation":"Engine and gear braking are the primary speed control on a downgrade, so stay in a low gear and use only light, intermittent brake applications to let the brakes cool.","handbook":"Use a low gear with light, steady braking on long grades.","hbref":"§2.13","qid":"GK-W3-228"},"323":{"q":"You are hauling a loaded trailer down a long, steep mountain grade. To keep your speed under control, you hold steady, continuous pressure on the service brakes the entire way down rather than relying on a low gear. As you near the bottom, what is the MOST likely result of using your brakes this way?","options":["The brakes will overheat and fade, losing their stopping power when you need it most","The brakes will grip more firmly the longer they are applied, giving you extra control","The continuous airflow over the drums will keep the brakes cool and working normally","The brakes will wear evenly and last longer because the pressure is smooth and constant"],"answer":0,"explanation":"Steady, continuous braking on a long downgrade builds heat faster than it can dissipate, so the brakes overheat and fade, losing stopping power.","handbook":"Riding the brakes downhill overheats them and causes brake fade.","hbref":"§2.13","qid":"GK-W3-229"},"324":{"q":"You are descending a long, steep mountain grade with a fully loaded trailer. Partway down you smell a faint burning odor, your brake pedal is going soft, and the truck keeps gaining speed even though you are pressing the brakes. Ahead a sign reads \"RUNAWAY TRUCK RAMP 1 MILE.\" What is the PRIMARY purpose of that ramp, and why might you need it here?","options":["It is a designated pull-off where you must park and let your brakes cool for 30 minutes before continuing the descent.","It is built to safely stop a runaway vehicle that has lost braking ability, such as when brakes fade and overheat on a long downgrade.","It is a weigh-station bypass lane where descending trucks confirm their axle weights before reaching the bottom of the grade.","It is a turnaround for oversized trucks that cannot safely complete the rest of the steep grade."],"answer":1,"explanation":"An escape ramp is built to safely stop a runaway vehicle that has lost braking ability, such as from brakes overheating and fading on a long downgrade.","handbook":"Escape ramps safely stop runaway vehicles.","hbref":"§2.13","qid":"GK-W3-230"},"327":{"q":"You are stopped at a multi-track railroad crossing with no gates or signals. A freight train rumbles through on the near track and finally clears to your left. The view down both tracks is partly blocked by trees, and you can see you have room to fully clear all the tracks plus your full length and about 15 ft beyond. Before you release the brake and start across, what is the MOST important thing to do?","options":["Shift into your lowest gear so you have maximum pulling power while crossing the tracks","Confirm the crossing's painted gate arms are fully raised before proceeding","Check the second track in both directions for another train that the first one may have hidden","Wait a full 15 seconds after the train clears, then proceed without further checking"],"answer":2,"explanation":"A second train can be hidden behind the one that just passed, so look both directions on every track before crossing.","handbook":"After a train passes, check for a second train before crossing.","hbref":"§2.17","qid":"GK-W3-231"},"328":{"q":"It has not rained in your delivery area for nearly three weeks, and a light rain just began to fall as you pull onto a busy two-lane road. You immediately feel the trailer get squirrelly under light braking, even though the pavement looks barely wet. Why is this early light rain MORE dangerous to your traction than a steady downpour later in the same storm?","options":["The thin film of water cools the pavement, which hardens the rubber of your tires and reduces grip","Light rain cannot wash the road, so a heavy downpour later would actually give you better tire grip","Light rain raises tire pressure, and the over-inflated tires ride on a smaller contact patch","The first water mixes with built-up oil and dust on the dry road, floating them into a slick film before heavier rain can wash it away"],"answer":3,"explanation":"The first rain after a dry spell is slippery because the light water mixes with built-up oil and dust, forming a slick film before heavier rain can wash it away.","handbook":"The first rain after dry weather mixes with oil and dust and is very slippery.","hbref":"§2.11","qid":"GK-W3-232"},"329":{"q":"You just forded a flooded low-water crossing where the water was deep enough to reach your hubs. As you accelerate back onto the dry highway and approach an intersection a quarter mile ahead, your first stop reveals a soft, weak brake pedal. What is the correct action to restore braking before you rely on the brakes at speed?","options":["Drive at a slow speed while applying light, gentle pressure to the brakes to test and dry them with the friction heat","Pump the brake pedal hard and fast to force the water out of the drums before the next stop","Accelerate to highway speed so the wind and engine heat blow the brakes dry quickly","Shut the engine off and coast to let the brakes air-dry naturally before continuing"],"answer":0,"explanation":"After deep water wets the brake linings, drive slowly while applying light, gentle pressure so friction heat dries them and restores normal braking.","handbook":"After deep water, test the brakes and dry them with light pressure.","hbref":"§2.11","qid":"GK-W3-233"},"330":{"q":"You are hauling a partial load on an interstate during a steady rain at 50 mph. The road ahead looks like a continuous sheet of water and you feel a faint film building between your tires and the pavement. Suddenly the steering wheel feels different in your hands. Which change would be the clearest warning that your tires have lost their grip and you may be starting to hydroplane?","options":["The wheel suddenly resists you and feels heavy, stiff, and hard to turn","The wheel suddenly feels light and easy to turn, as if it has gone slack","You hear the engine grow noticeably louder even though your speed is steady","You notice a strong fuel odor coming through the cab vents"],"answer":1,"explanation":"When tires lose grip on a wet surface and ride on a film of water, the steering suddenly feels light and easy to turn.","handbook":"Steering that feels light can signal lost traction on wet roads.","hbref":"§2.11","qid":"GK-W3-234"},"331":{"q":"You went off duty at 6:00 p.m. and took a full 10-hour break, then came on duty at 4:00 a.m. and drove straight through. A dispatcher pressures you to keep rolling because, he says, you still have hours left in your 14-hour window. Setting aside the 14-hour on-duty window, what is the maximum number of hours you are actually permitted to spend DRIVING during this work shift?","options":["8 hours of driving, because that is when a 30-minute break becomes mandatory and your shift effectively ends","14 hours of driving, since the 14-hour window is what really controls how long you can stay behind the wheel","11 hours of driving, because after 10 consecutive hours off duty you may drive a maximum of 11 hours","16 hours of driving, as long as you remain within the 14-hour on-duty window"],"answer":2,"explanation":"After 10 consecutive hours off duty, you may drive a maximum of 11 hours, separate from the 14-hour on-duty window limit.","handbook":"After 10 hours off duty, you may drive up to 11 hours.","hbref":"§2.21","qid":"GK-W3-235"},"332":{"q":"You came on duty at 6:00 a.m. After loading and waiting, you finally started driving at 9:00 a.m. You have only driven about 5 hours total and have taken a 30-minute break, so you feel you still have plenty of legal driving time left in your day. As the clock approaches 8:00 p.m., which statement correctly describes when you must stop driving for this work shift?","options":["You may keep driving until you have logged 6 actual hours behind the wheel, since driving time is what the limit really controls.","You may keep driving as long as you have not exceeded 10 hours of on-duty time, because the on-duty clock is what shuts you down.","You may keep driving past 8:00 p.m. because your 30-minute break paused the clock and pushed your cutoff later in the evening.","You may not drive at all after 8:00 p.m., because that is the 14th hour after you came on duty, regardless of how few hours you have actually driven."],"answer":3,"explanation":"You may not drive after the 14th hour following the time you came on duty, no matter how little you have actually driven.","handbook":"You may not drive after the 14th hour after coming on duty.","hbref":"§2.21","qid":"GK-W3-236"},"333":{"q":"You are loading a flatbed for a 300-mile run. You've balanced the weight over the axles, tarped the load to keep it dry, and your tie-downs meet the working load limit. As you make a final walk-around, you remind yourself of the single most important reason cargo must be properly secured before you ever pull onto the highway. Which statement best captures that reason?","options":["Secured cargo must be prevented from shifting, falling off, or blocking your view of the road","Secured cargo must be kept fully hidden under a tarp so it cannot be seen from outside the vehicle","Secured cargo must be arranged so the load can be quickly weighed at the next inspection station","Secured cargo must be loaded so that the tie-downs are visible to officers from the passenger side"],"answer":0,"explanation":"Cargo must be secured so it cannot shift, fall off, or block your view of the road.","handbook":"Secure cargo so it cannot shift, fall, or block your view.","hbref":"§2.2","qid":"GK-W3-237"},"334":{"q":"You pick up a last-minute load and the shipper packs it heavier than your manifest shows, putting you slightly over your GVWR. The dispatcher says it's \"only a little over\" and tells you to run it. As you pull onto the highway, which effect of this overload should concern you MOST from a safety standpoint?","options":["The extra weight will press the tires down harder, giving you more traction and a shorter stopping distance","The vehicle will be harder to steer and will take longer to stop because the added weight works against your steering and brakes","The added weight lowers the center of gravity, so the truck becomes more stable and far less likely to roll over","Fuel economy improves because the engine runs at a steadier load when the truck is fully weighted"],"answer":1,"explanation":"Too much weight makes a vehicle harder to steer and increases stopping distance because the added mass works against the steering and brakes.","handbook":"Overloading makes a vehicle harder to steer and stop.","hbref":"§2.2","qid":"GK-W3-238"},"335":{"q":"During your pre-trip inspection at a Texas loading dock, you find that two lengths of steel pipe extend about four feet past the rear of your flatbed trailer. The load is properly secured with tie-downs, your paperwork is in order, and you are about to leave on a daytime run. Regarding the part of the load that sticks out past the rear, what does federal/Texas regulation require you to do before driving?","options":["Nothing extra is required, because the overhang is under five feet and the load is already secured with the correct number of tie-downs","Add one additional tie-down to the overhanging section and paint the protruding ends a dark color so they are less distracting to traffic","Mark the overhanging cargo so it is visible -- use flags (and lights if visibility is poor or at night) on the part that extends past the rear","Recheck the securement within the first 50 miles, but no marking of the overhang is needed since the cargo is fully tied down"],"answer":2,"explanation":"Cargo extending past the rear must be marked so it is visible — with flags by day and lights when visibility is poor or at night.","handbook":"Overhanging cargo must be flagged or lighted.","hbref":"§2.2","qid":"GK-W3-239"},"336":{"q":"At a shipping dock, the warehouse crew loads and chains down a flatbed of steel pipe for you, the dock supervisor signs the bill of lading, and a DOT officer happens to be standing nearby. You think a couple of the tie-downs look loose. Under federal and Texas rules, who is ultimately responsible for making sure this load is secured properly and is within legal weight limits before you pull out?","options":["The shipper and warehouse crew, because they physically loaded and chained the cargo","The dock supervisor, because their signature on the bill of lading certifies the load","The DOT officer standing nearby, since enforcement of securement is their job","You, the driver, because you are responsible for a secure and legal load regardless of who loaded it"],"answer":3,"explanation":"The driver is responsible for a secure and legal load regardless of who actually loaded it.","handbook":"The driver is responsible for a secure and legal load.","hbref":"§2.2","qid":"GK-W3-240"},"337":{"q":"You loaded steel coils at the yard and just pulled onto the interstate. The load felt solid when you secured it, but you know tie-downs and cargo can shift once the rig is rolling and the chains settle. To stay legal and safe, how soon should you make your FIRST stop to re-check the cargo securement?","options":["Within the first 50 miles after beginning the trip","Within the first 150 miles after beginning the trip","Within the first 3 hours of driving, regardless of distance","Only after your first rest break or fuel stop"],"answer":0,"explanation":"You must inspect the load and its securement within the first 50 miles after beginning a trip.","handbook":"Re-check cargo within the first 50 miles, then periodically.","hbref":"§2.2","qid":"GK-W3-241"},"339":{"q":"It is a moonless night and you are driving an empty flatbed on a rural two-lane highway with no streetlights. Your low beams illuminate roughly 250 feet of road ahead, but you cannot legally use high beams because oncoming traffic keeps appearing. To avoid running off the road or striking an unseen hazard, your speed must be governed by which single rule?","options":["You may maintain the posted speed limit as long as your headlights and brake lights are working properly","Your speed must be slow enough that you can stop within the distance your headlights light up ahead of you","You should keep your speed slow enough to read every road sign before you pass it","You can drive faster because an empty trailer gives you a shorter stopping distance than a loaded one"],"answer":1,"explanation":"Never overdrive your headlights — your speed must let you stop within the distance your lights reveal ahead.","handbook":"Do not drive faster than you can stop within your light range.","hbref":"§2.11","qid":"GK-W3-242"},"340":{"q":"You are driving a loaded tractor-trailer on a dark two-lane highway just after midnight. An oncoming car keeps its high beams on and refuses to dim them, and the glare is washing out your vision. You have already flashed your lights to remind the driver, with no result. Until that car passes, what is the BEST thing to do with your eyes to keep control of your lane?","options":["Stare straight at the oncoming headlights so you can judge exactly when the car will pass you","Glance up toward the sky above the headlights so the bright light is out of your direct line of sight","Shift your gaze down and toward the right edge of your own lane and use it to steer until the car is past","Drop your eyes to the dashboard and steady instruments until the headlights are no longer in front of you"],"answer":2,"explanation":"When blinded by oncoming high beams, look toward the right edge of your lane and use it to steer until the vehicle passes.","handbook":"Look to the right side of your lane to avoid oncoming glare.","hbref":"§2.11","qid":"GK-W3-243"},"341":{"q":"You just dropped your entire load at a warehouse and are now bobtailing the empty rig back to the yard. Approaching a red light, you brake the same way you did when fully loaded, and your wheels suddenly lock up and start to skid. Why does this empty truck handle braking WORSE than it did when it was loaded?","options":["The heavier the vehicle, the longer it takes to stop, so an empty truck should actually stop more easily than a loaded one","Empty trucks are fitted with smaller, weaker brakes that cannot generate enough force to slow the vehicle down","With no cargo, the higher center of gravity makes the truck roll forward and overload the front brakes","With little weight pressing the tires onto the road, the tires have less traction and are more likely to lock up and skid"],"answer":3,"explanation":"An empty truck has little weight pressing the tires onto the road, so they have less traction and lock up and skid more easily.","handbook":"Empty trucks have less traction and can stop poorly.","hbref":"§2.7","qid":"GK-W3-244"},"342":{"q":"A steady rain has been falling and the pavement is clearly wet but not yet covered with standing water or slush. Traffic around you is still moving near the posted 60 mph limit. To keep a safe margin of control on this wet surface, by about how much should you reduce your speed below what you would safely drive on the same road when it is dry?","options":["About one third slower than your safe dry-road speed","About one half slower than your safe dry-road speed","About three quarters slower than your safe dry-road speed","No reduction is needed as long as standing water and slush have not formed"],"answer":0,"explanation":"On wet roads, reduce your speed by about one third compared with your safe dry-road speed to keep enough traction.","handbook":"Reduce speed about one third on a wet road.","hbref":"§2.11","qid":"GK-W3-245"},"343":{"q":"You are running a loaded reefer on a rural two-lane highway when the temperature drops and a steady snow begins to stick, leaving a hard-packed white layer on the road. Traffic is moving fine, the road is not icy, and you can still see clearly. To keep a safe margin for this packed-snow surface, by about how much should you reduce your normal dry-road speed?","options":["Cut your speed by about one quarter","Cut your speed by about one half","Cut your speed by about one tenth","Hold your normal speed since the road is not icy and visibility is good"],"answer":1,"explanation":"On packed snow, cut your speed by about one half because traction is sharply reduced and stopping distance grows.","handbook":"Reduce speed by about half on packed snow.","hbref":"§2.11","qid":"GK-W3-246"},"344":{"q":"It is just below freezing at dawn and you are driving a loaded combination vehicle on a bridge. The pavement ahead looks dark, smooth, and wet, but you notice no spray coming off the tires of the car in front of you. Why is this kind of surface considered one of the most dangerous winter hazards?","options":["It is bright and obvious, so drivers brake too hard and lose traction on a clearly icy road","It only forms in the warmest part of a summer afternoon when tar bleeds up through the pavement","It looks like a harmless wet road but is actually a thin, clear layer of ice that gives almost no warning","It melts the road tar beneath it, leaving a slick oily film that is easy to see and steer around"],"answer":2,"explanation":"Black ice is a thin, clear layer of ice that makes the road look merely wet and gives almost no warning.","handbook":"Black ice looks like a wet road but is a thin layer of ice.","hbref":"§2.11","qid":"GK-W3-247"},"345":{"q":"You are driving a loaded tractor-trailer on a rural two-lane highway when a sudden, strong crosswind gust hits the side of your trailer and the steering wheel jerks in your grip. To keep the best control and be ready to counter-steer if the wind pushes you toward the shoulder, how should your hands be positioned on the steering wheel?","options":["Keep one hand at the top of the wheel for the most leverage and rest the other hand in your lap","Keep both hands close together near the top of the wheel so you can react in either direction quickly","Keep one hand near the bottom of the wheel and use the other only to brace against the door","Keep both hands firmly on the wheel on opposite sides of each other"],"answer":3,"explanation":"Hold the wheel firmly with both hands on opposite sides so you keep control and can counter-steer against sudden hazards.","handbook":"Hold the steering wheel with both hands on opposite sides.","hbref":"§2.3","qid":"GK-W3-248"},"346":{"q":"You pull into a crowded truck stop and must back your tractor-trailer into a tight parking slot. There is no spotter available and other rigs are parked close on both sides. To keep the maneuver as safe as possible, you should set up and back so that you are backing toward which side?","options":["Toward the driver's side, so you can look back along the trailer and watch your path through the side window","Toward the passenger side, because the trailer swings wider on that side and gives you more clearance","Toward whichever side lets you back in a straight line down the slope of the lot","Toward your blind side, then rely on your mirrors and a quick walk-around to cover what you cannot see"],"answer":0,"explanation":"Back toward the driver's side so you can look directly back along the trailer and see your path through the side window.","handbook":"Back toward the driver's side when possible.","hbref":"§2.3","qid":"GK-W3-249"},"348":{"q":"You need to back your 53-foot trailer into a tight loading dock on the blind (right) side, and a coworker is standing nearby offering to help. According to safe backing procedures, what is the single most important reason to use this person as a helper?","options":["They can give you hand signals so you do not have to use your mirrors at all","They can watch the areas behind and beside your trailer that you cannot see from the cab","They can stop oncoming traffic on the street so you can back without waiting","They can take over and back the trailer for you if the angle gets too difficult"],"answer":1,"explanation":"A helper can watch the blind-spot areas behind and beside the trailer that you cannot see from the cab.","handbook":"Use a helper to watch blind spots while backing.","hbref":"§2.3","qid":"GK-W3-250"},"349":{"q":"You are driving a 53-foot tractor-trailer approaching a tight right turn onto a narrow city street. You know the trailer will track inboard and may climb the curb if you turn too sharply. A car has just pulled up close behind you on your right side. To complete this turn safely and legally, what should you do?","options":["Swing wide to the left before starting the turn so the trailer has room to clear the curb","Speed up slightly through the turn so the trailer follows the tractor more tightly","Turn from as far right as is safe, keeping the rear of your vehicle close to the curb so no one can pass on your right","Move into the far left lane first, then make the right turn from there to give the trailer maximum room"],"answer":2,"explanation":"Turn from as far right as is safe and keep the rear close to the curb so no one can pass on your right.","handbook":"Do not swing wide to the left before a right turn.","hbref":"§2.3","qid":"GK-W3-251"},"350":{"q":"You are driving a 53-foot tractor-trailer and need to make a left turn at a busy four-way intersection. The light turns green and oncoming traffic has cleared. To complete this left turn safely and keep your trailer's rear wheels from cutting into the lane you are turning out of, what is the correct technique?","options":["Begin swinging the front of your tractor to the left as soon as you enter the intersection so the trailer follows a tighter path","Stay in the right-most lane through the turn so the trailer's rear wheels track wide and clear of the curb","Cut diagonally across the corner of the intersection to shorten the distance the trailer must travel","Drive your tractor forward and reach the center of the intersection before you begin turning the wheel to the left"],"answer":3,"explanation":"Drive forward to the center of the intersection before turning the wheel left so the trailer's rear wheels do not cut the corner.","handbook":"Reach the center of the intersection before turning left.","hbref":"§2.3","qid":"GK-W3-252"},"351":{"q":"It is early morning and you have just climbed into the cab to begin a long run. As you settle in, you realize the right-side mirror is angled too high to show the side of your trailer, and you want to fix it. When is the correct time to make this adjustment?","options":["Now, before you start the trip, while the vehicle is safely parked","Once you reach highway speed, so the mirror is set for the way the trailer rides under load","At your first required cargo check, within the first 50 miles of the run","Only after you finish driving and have pulled into the destination yard"],"answer":0,"explanation":"Adjust your mirrors before the trip while the vehicle is safely parked, since you cannot safely do it while moving.","handbook":"Adjust mirrors before starting the trip.","hbref":"§2.4","qid":"GK-W3-253"},"353":{"q":"You have just merged into the left lane to pass a slower vehicle on a multi-lane highway. The pass is complete and you are now settled in the new lane. Glancing at your dash, you realize your left turn signal is still blinking because, unlike a car, your truck's signal did not self-cancel. What should you do FIRST?","options":["Accelerate firmly to put more distance between you and the vehicle you just passed, then check the signal later","Manually turn off the turn signal so drivers around you are not misled about your intentions","Brake to recheck your mirrors before deciding whether the signal needs to be canceled","Leave the signal on until you change lanes again, since it shows you are still maneuvering"],"answer":1,"explanation":"Most large trucks lack self-canceling signals, so turn the signal off after the maneuver to avoid misleading other drivers.","handbook":"Turn off your turn signal after changing lanes.","hbref":"§2.4","qid":"GK-W3-254"},"355":{"q":"You are driving your tractor-trailer at night on a dark two-lane highway with your high beams on. You spot the headlights of a vehicle coming toward you in the opposite lane, still some distance ahead. At what point are you required to dim your high beams to low beams so you do not blind the oncoming driver?","options":["Within 250 feet of the oncoming vehicle, since that is the distance your low beams illuminate the road","Within 200 feet of the oncoming vehicle, the same distance you place your farthest warning triangle","Within 500 feet of the oncoming vehicle (and also when following another vehicle within 500 feet)","Only once the oncoming vehicle flashes its own lights at you to signal that your beams are too bright"],"answer":2,"explanation":"Dim your high beams within 500 feet of an oncoming vehicle and when following another vehicle within 500 feet to prevent blinding glare.","handbook":"Dim your high beams within 500 feet of oncoming vehicles.","hbref":"§2.11","qid":"GK-W3-255"},"356":{"q":"You are hauling a loaded trailer on a rural two-lane highway when a low-coolant warning forces you to shut down. There is no exit for several miles, but you spot a wide gravel shoulder ahead. Before you even reach for your warning triangles, what is the FIRST thing you should do to make the stop as safe as possible?","options":["Stop in your travel lane and immediately set out your three triangles at 10, 100, and 200 feet so traffic is warned before you do anything else","Coast to a stop on the next curve so your rig is visible from both directions, then turn on your headlights","Slow down and straddle the lane line so part of your truck stays on the pavement, keeping the shoulder clear for emergency vehicles","Pull completely off the pavement onto the gravel shoulder and turn on your four-way hazard flashers"],"answer":3,"explanation":"Get the vehicle completely off the traveled roadway onto the shoulder and turn on your four-way hazard flashers immediately to warn approaching traffic.","handbook":"Get completely off the road and turn on flashers if you must stop.","hbref":"§2.14","qid":"GK-W3-256"},"357":{"q":"You pull into a rest area on a slight downhill incline to do a quick walk-around and check your cargo securement. The engine is still running and you plan to be out of the cab for only a minute or two. Before you climb down to step outside, which action is the single most important one to take to keep the vehicle from rolling?","options":["Set the parking brake.","Shift the transmission into the lowest forward gear and leave it there.","Turn the front wheels sharply toward the curb and switch on the four-way hazard flashers.","Press and hold the service (foot) brake firmly until you are ready to return."],"answer":0,"explanation":"Always set the parking brake before leaving the cab, since it is the only device designed to hold a parked vehicle mechanically without the driver present.","handbook":"Set the parking brake before leaving the cab.","hbref":"§2.1","qid":"GK-W3-257"},"358":{"q":"You are driving a loaded tractor-trailer on a rural highway at 55 mph. Traffic is light and the road is straight, so you decide to consciously fix your eyes on a point far enough ahead that you can spot stalled vehicles, debris, or merging traffic in time to react smoothly instead of braking hard. In terms of TIME at this speed, how far ahead should you be looking?","options":["5 to 8 seconds ahead, which is the same interval you should use to check your mirrors","12 to 15 seconds ahead, which is roughly a quarter mile at highway speed","About 6 seconds ahead, which is your total stopping distance at 55 mph","A full quarter mile measured only in feet, not in seconds of travel"],"answer":1,"explanation":"Look 12 to 15 seconds ahead, roughly a quarter mile at highway speed, so you spot hazards early and respond gently instead of in a panic.","handbook":"Look 12 to 15 seconds ahead of your vehicle.","hbref":"§2.4","qid":"GK-W3-258"},"359":{"q":"You are hauling a flatbed load of steel coils on a busy interstate at highway speed. Traffic is heavy and vehicles keep moving in and out of the lanes around you. You want to stay aware of what is happening on all sides of your rig so you can react early to a car cutting in or a tire problem on your trailer. Which approach to using your mirrors best fits safe commercial driving practice?","options":["Glance at your mirrors once after each merge or lane change, since that is when other vehicles are most likely to be beside you","Wait until you feel the trailer pull or hear an unusual noise before checking, so you keep your eyes on the road ahead the rest of the time","Scan your mirrors regularly, about every 5 to 8 seconds, so you continuously track traffic and the condition of your vehicle on all sides","Check your mirrors only at the start and end of the trip, and otherwise focus entirely on the path 12 to 15 seconds ahead"],"answer":2,"explanation":"Scan your mirrors regularly, about every 5 to 8 seconds, to stay aware of traffic, blind spots, and the condition of your rig and cargo.","handbook":"Check your mirrors regularly while driving.","hbref":"§2.4","qid":"GK-W3-259"},"360":{"q":"You are driving a loaded tractor-trailer at a steady 55 mph in the right lane of a divided highway when a four-wheeler begins to overtake you on your left. Halfway through the pass, the car lingers in your left-side blind spot and seems hesitant to complete the maneuver. To give the passing driver the safest, most predictable situation, which action should you take?","options":["Ease off the accelerator and brake gently so the car can clear your front bumper sooner","Move slightly toward the right edge of your lane to open up more space on the driver's side","Accelerate briefly to help the car finish the pass and get back into your lane faster","Hold your position in the center of your lane and maintain a steady speed until the car has completely cleared and returned ahead of you"],"answer":3,"explanation":"When another vehicle is passing you, hold your lane and keep a steady speed so the passing driver can predictably judge the gap and complete the pass safely.","handbook":"When being passed, keep your lane and a steady speed.","hbref":"§2.4","qid":"GK-W3-260"},"361":{"q":"You're rolling toward an unfamiliar underpass marked with a posted clearance sign, and your trailer is loaded with a tall stack of crated machinery. Of the figures below, which one do you MOST need to know with certainty before you commit to driving under that bridge?","options":["The overall height of your loaded vehicle, measured from the ground to its highest point","The exact total weight of the loaded combination on the scale","The amount of fuel currently in your tanks","The brand and model of tires mounted on your drive axles"],"answer":0,"explanation":"Know the overall height of your loaded vehicle from the ground to its highest point and compare it to the posted clearance before passing under a bridge or underpass.","handbook":"Know your vehicle's height before low clearances.","hbref":"§2.2","qid":"GK-W3-261"},"362":{"q":"You are routing a low-boy trailer loaded with an excavator through an older industrial district. Coming up, the road dips under an aging rail bridge and several sagging overhead electrical lines cross the street. Before you commit to driving under them, which measurement is the MOST critical for you to verify against the posted and known limits to avoid a serious accident?","options":["Your steering-axle tire pressure, since a low front tire could let the rig sag and snag the wires","Your overhead clearance height, comparing the total loaded height of your rig to the posted bridge clearance and the wires above","Your gross combination weight rating (GCWR), to confirm the bridge and roadway can safely bear the loaded rig","Your following distance to the vehicle ahead, so you are not forced to brake hard beneath the structure"],"answer":1,"explanation":"Check your total loaded clearance height against the posted bridge clearance and the height of overhead wires to be sure the rig can pass safely underneath.","handbook":"Watch overhead clearance for wires and low structures.","hbref":"§2.2","qid":"GK-W3-262"},"363":{"q":"You are approaching a four-way intersection in your loaded combination vehicle when a passenger car on your left edges forward and aggressively claims the right of way that is legally yours. You have already begun to slow. Which action is the BEST choice in this situation?","options":["Maintain your speed and proceed, since the right of way is legally yours and the car must yield","Sound your horn repeatedly and continue into the intersection to assert your position","Yield and let the other driver go, even though you legally have the right of way, to avoid a collision","Accelerate to clear the intersection before the car can enter your path"],"answer":2,"explanation":"A professional driver's first duty is to avoid a crash, so yield and let the other driver go even when you legally have the right of way.","handbook":"Yield the right of way rather than risk a crash.","hbref":"§2.4","qid":"GK-W3-263"},"364":{"q":"You are routing your loaded combination vehicle to a delivery and the GPS sends you over a county bridge posted with a weight limit that is lower than your actual gross combination weight. There is a legal alternate route that adds 12 miles. What must you do?","options":["Cross the bridge but accelerate so your full weight rests on the structure for the shortest possible time","Cross at a slow, steady creep, since posted bridge limits are advisory and only enforced when the truck is empty","Stop on the bridge to verify your axle weights before continuing across","Do not cross the bridge; take the legal alternate route so you never exceed the posted weight limit"],"answer":3,"explanation":"A posted bridge weight limit is a hard legal maximum, so if your gross weight exceeds it, never cross and take the legal alternate route instead.","handbook":"Do not exceed the posted weight limit on a bridge.","hbref":"§2.2","qid":"GK-W3-264"},"365":{"q":"You are hauling a heavy load down a long, steep mountain grade. Even though it is a cold day, after several miles you press the brake pedal and notice the truck barely slows and the brakes feel weak and spongy. What is the MOST likely cause of this loss of braking power?","options":["The brakes overheated from being used too heavily for too long on the descent, causing brake fade","The cold outside air temperature froze moisture in the brake lines and reduced their grip","The brake linings are too new and have not yet been broken in to grip properly","You braked too lightly and carefully, so the linings never warmed up enough to hold"],"answer":0,"explanation":"Heavy, prolonged braking on a long downgrade overheats the brakes, causing them to lose friction and stopping power even with the pedal pressed.","handbook":"Brake fade comes from overheating during heavy use.","hbref":"§2.13","qid":"GK-W3-265"},"367":{"q":"You are hauling a loaded trailer in the right lane of a divided highway at the posted limit. A driver behind you has been tailgating for several miles, then swerves around you, cuts back in sharply, brakes, and keeps gesturing for you to speed up or move. Traffic ahead is moderate. Which action is the safest and best way to handle this aggressive driver?","options":["Speed up to match the other driver so they stop tailgating and merge away from you","Ease off the accelerator, increase your following distance, and let the aggressive driver get well ahead and away from you","Hold your exact position and lightly tap your brakes to signal the driver to back off","Move left to block the aggressive driver from passing again until they calm down"],"answer":1,"explanation":"The safest response to an aggressive driver is to stay out of their way by easing off the gas and increasing your following distance so they get well ahead.","handbook":"Stay out of the way of aggressive drivers and let them pass.","hbref":"§2.8","qid":"GK-W3-266"},"368":{"q":"You have just finished a 45-minute meal break at a truck stop and your loaded tractor-trailer is parked parallel along the right shoulder of a service road. Traffic is moving past you on your left. You are ready to re-enter the travel lane. Which action sequence is the safest and correct way to leave this parked position?","options":["Pull straight out promptly to merge with the gap in traffic, then turn on your left signal once you are already moving","Sound your horn to alert nearby drivers, release the brakes, and accelerate into the lane without delay","Turn on your left signal, check your mirrors and the area around the vehicle for traffic and blind spots, and pull out only when it is clear","Check only your driver-side mirror, and if it looks clear, ease out into the lane while watching for the gap"],"answer":2,"explanation":"Before leaving a parked position, signal first, then check mirrors and all areas around the vehicle for traffic and blind spots, and pull out only when clear.","handbook":"Check mirrors and signal before pulling out from a parked position.","hbref":"§2.4","qid":"GK-W3-267"},"370":{"q":"You are driving a loaded tractor-trailer at highway speed on a two-lane undivided road. An oncoming car has drifted across the center line and is now partly in your lane, closing fast. There is no time to stop before impact. To the right is a paved shoulder and a shallow grassy ditch; to your left is the oncoming lane with traffic. Which action gives you the best chance of avoiding a head-on collision?","options":["Steer left into the oncoming lane to swing around the drifting car","Hold your lane and brake as hard as you can, locking the wheels if needed","Stay centered and flash your high beams while keeping your speed","Steer right toward the shoulder, even if it means leaving the pavement"],"answer":3,"explanation":"When an oncoming vehicle drifts into your lane, steer right toward the shoulder, since the driver may correct back and steering left risks a head-on crash.","handbook":"If an oncoming vehicle enters your lane, steer right toward the shoulder.","hbref":"§2.14","qid":"GK-W3-268"},"371":{"q":"You are driving loaded at highway speed on a hot July afternoon when you suddenly hear a loud \"bang\" from the front of your tractor. You did not feel any thumping in the seat beforehand. As you grip the wheel, which of the following would MOST clearly tell you that it was a FRONT tire that blew out, rather than a rear one?","options":["The steering suddenly becomes very hard and the truck pulls strongly toward one side","You feel a heavy vibration or thumping coming up through the seat and cab floor","The back of the trailer begins to fishtail and sway from side to side","The engine temperature gauge climbs and the truck begins to lose power"],"answer":0,"explanation":"A front tire blowout makes the steering suddenly very hard and pulls the truck strongly toward the failed tire.","handbook":"A front-tire blowout makes steering suddenly hard.","hbref":"§2.14","qid":"GK-W3-269"},"372":{"q":"You are running loaded on a flat two-lane highway at about 50 mph when you suddenly feel the back end of your trailer start to swing and weave from side to side, even though your steering wheel still feels normal and you have not touched the brakes. Based on these symptoms, which conclusion is the MOST accurate about what has likely happened?","options":["A front (steering-axle) tire has lost air, which is why the rear is now wandering across the lane","A rear tire has failed, because a rear-tire blowout typically makes the vehicle sway or fishtail","Your trailer brakes have locked up, which is dragging the back end sideways","You have begun a drive-wheel acceleration skid and should immediately steer hard the other way"],"answer":1,"explanation":"A rear-tire failure makes the vehicle sway or fishtail while the steering still feels relatively normal.","handbook":"A rear-tire failure can cause the vehicle to sway or fishtail.","hbref":"§2.14","qid":"GK-W3-270"},"373":{"q":"You are hauling an empty trailer down a wet two-lane highway when a car suddenly pulls out from a side road ahead. You stomp hard on the brake pedal and feel the ABS activating. Which statement BEST describes what your antilock braking system is doing for you in this moment?","options":["It is cutting your total stopping distance to roughly half of what it would be without ABS, so you can stop well short of the car.","It is automatically downshifting and applying engine braking to bring the rig to a controlled stop.","It is keeping your wheels from locking up so you can keep steering and maintain control while you brake hard.","It is metering brake pressure so the empty trailer stops in a shorter distance than a loaded one would."],"answer":2,"explanation":"ABS keeps the wheels from locking up during hard braking so you can keep steering and maintain control to avoid the hazard.","handbook":"ABS keeps wheels from locking so you keep steering control.","hbref":"§2.14","qid":"GK-W3-271"},"374":{"q":"You are driving a loaded tractor-trailer equipped with anti-lock brakes (ABS) when a car suddenly cuts in front of you and stops short. You need to make a hard emergency stop in your lane on dry pavement. Knowing how ABS is designed to work, which braking action gives you the best control and shortest safe stop?","options":["Pump the brake pedal rapidly to keep the wheels from locking, the way you would without ABS","Apply controlled stab braking, releasing the pedal each time the wheels begin to lock","Press the brake just lightly and steer around the car, since ABS shortens your stopping distance","Press the brake pedal down firmly, hold steady pressure, and steer as needed while the ABS works"],"answer":3,"explanation":"With ABS, brake by pressing firmly and holding steady, continuous pressure while you steer, letting the system prevent wheel lockup.","handbook":"With ABS, apply firm steady pressure and hold it.","hbref":"§2.14","qid":"GK-W3-272"},"375":{"q":"You are hauling a partially loaded trailer (no ABS) down a state highway when a car suddenly pulls out of a side road directly in front of you. You must stop as fast as physically possible without losing your ability to steer around the danger if you cannot stop in time. Which braking method should you use?","options":["Apply controlled or stab braking, keeping the wheels just short of locking up","Press the brakes all the way down and hold them firmly to lock the wheels for the shortest distance","Pump the brakes lightly and steadily the way you would on a long downgrade","Apply only the trailer (hand) valve so the tractor wheels stay free to steer"],"answer":0,"explanation":"Without ABS, controlled or stab braking that keeps the wheels just short of locking up gives maximum stopping force while preserving steering.","handbook":"Without ABS, use controlled or stab braking.","hbref":"§2.14","qid":"GK-W3-273"},"376":{"q":"You are driving a loaded tractor-trailer with standard (non-ABS) brakes when a car suddenly cuts you off and you must brake hard to avoid a crash. You apply the brakes fully and feel the wheels lock up. To use stab braking correctly and keep the vehicle under control, what should you do the instant the wheels lock?","options":["Keep full, steady pressure on the pedal and hold the wheels locked until you come to a complete stop","Release the brakes until the wheels begin to roll again, then fully reapply the brakes","Pump the brake pedal as rapidly as possible, three to four times per second, until you stop","Take your foot off the brake entirely, shut down the engine, and coast to a stop"],"answer":1,"explanation":"In stab braking, you release the brakes until the locked wheels start rolling again to regain steering, then fully reapply the brakes.","handbook":"In stab braking, release until wheels roll, then brake again.","hbref":"§2.14","qid":"GK-W3-274"},"377":{"q":"You are following a loaded car-carrier on a dry four-lane highway at 55 mph, keeping several seconds of open road between you and the truck ahead. A merging pickup suddenly cuts into that gap, and the car-carrier's brake lights flash. Why was holding that space cushion the most important thing you did to handle this situation safely?","options":["It let you maintain 55 mph without lifting off the accelerator, so traffic kept flowing smoothly behind you","It guaranteed a complete stop within about 60 feet, which is the total stopping distance at 55 mph","It gave you extra room and time to perceive the hazard and react before you had to brake hard","It kept your following gap under one second, the spacing the handbook recommends for highway speeds"],"answer":2,"explanation":"A space cushion buys you extra room and time to spot a hazard and react before you must brake hard, since stopping distance at highway speed is far longer than it seems.","handbook":"A space cushion gives you room to react to problems.","hbref":"§2.5","qid":"GK-W3-275"},"378":{"q":"You are driving a fully loaded tractor-trailer at 55 mph in good, dry conditions when a passenger car in the next lane brakes hard for the same hazard you both see at the same instant. Knowing how a loaded truck behaves compared to that car, which statement should guide how much room you give yourself?","options":["The loaded truck and the car will stop in about the same distance, since both have good brakes","The loaded truck will stop in much less distance because its heavy weight presses the tires down for better grip","It makes no difference, because at 55 mph any vehicle needs roughly 60 feet to react and stop","The loaded truck needs much more distance to stop than the car, so you must allow far more room and start braking earlier"],"answer":3,"explanation":"A loaded truck's far greater mass and momentum make its total stopping distance much longer than a car's, so you must leave more room and begin braking earlier.","handbook":"Loaded trucks need much greater stopping distance than cars.","hbref":"§2.6","qid":"GK-W3-276"},"379":{"q":"You are traveling at highway speed on a two-lane road and a motorcyclist moves into the same lane just ahead of you, riding near the right edge of the lane. Traffic is moderate and there is a passing zone coming up. What is the safest way to manage your following position behind this motorcycle?","options":["Treat the motorcycle as a full-size vehicle: leave it the entire lane and follow with extra distance because it can stop much faster than you can","Move up close in your lane and share the open left portion of the lane with the motorcycle, since a bike only needs part of a lane","Tuck in behind it at your normal car-length following distance, because a motorcycle is smaller and needs less room than a car","Stay tight and prepare to pass immediately in the passing zone, since lingering behind a slow motorcycle is the real hazard"],"answer":0,"explanation":"A motorcycle is entitled to the full lane and can stop in much less distance than a heavy truck, so give it the whole lane and follow with extra space.","handbook":"Give motorcycles a full lane width and extra room.","hbref":"§2.4","qid":"GK-W3-277"},"380":{"q":"You are approaching a rural intersection in your loaded combination vehicle. The traffic signal is dark (completely out) and there are no stop or yield signs in any direction. As you near the intersection, you see a pickup truck that arrived a moment before you and is already stopped at the cross street to your right, waiting to proceed. What is the correct action?","options":["Proceed first, because a loaded combination vehicle needs more room and has the right-of-way over lighter vehicles","Yield to the pickup truck, because it arrived at the intersection first and is also on your right","Treat the dark signal as your green light and continue through without slowing","Stop in the center of the intersection so cross traffic can see you before you commit to the turn"],"answer":1,"explanation":"At an uncontrolled intersection you yield to the vehicle that arrived first, and if arrival is about the same, to the one on your right.","handbook":"At uncontrolled intersections, yield to traffic already there.","hbref":"§2.4","qid":"GK-W3-278"},"381":{"q":"It is 3:15 p.m. on a clear weekday and you are driving a loaded straight truck through a residential area when you see a flashing yellow beacon and a posted school-zone sign. Traffic around you is still moving at the normal 30 mph limit and the road ahead looks open. What is the BEST action to take?","options":["Maintain the posted 30 mph limit, since the lane ahead is clear and the other vehicles are not slowing","Move into the left lane and pass the slower cars quickly to clear the zone before children appear","Reduce your speed below the posted limit and scan the sidewalks and crosswalks carefully for children who may dart out","Keep your speed but switch on your high beams so drivers and pedestrians can see your truck more clearly"],"answer":2,"explanation":"A flashing beacon means the reduced-speed school zone is active, so slow below the limit and scan sidewalks and crosswalks for children who may dart out.","handbook":"Slow down and watch for children in a school zone.","hbref":"§2.6","qid":"GK-W3-279"},"382":{"q":"You are approaching a highway construction zone where the overhead lane signal shows a green arrow for your lane, but a flagger standing in the roadway is holding a STOP paddle directed at you. What should you do?","options":["Proceed slowly through the zone, since the green arrow signal legally authorizes your lane to continue","Stop only if the flagger also blows a whistle or waves both arms, otherwise follow the green arrow","Treat the conflict as a malfunction and proceed with caution at no more than 15 mph","Stop and obey the flagger, because a flagger's directions take priority even over the normal signals"],"answer":3,"explanation":"A flagger's directions take priority over all signs and signals because the flagger has real-time knowledge of work-zone hazards a fixed signal cannot reflect.","handbook":"Obey a flagger's directions even over regular traffic signals.","hbref":"§2.6","qid":"GK-W3-280"},"383":{"q":"You are driving your tractor-trailer in the right-hand lane of a four-lane undivided highway when you hear a siren and see an ambulance approaching from behind with its emergency lights flashing. Traffic ahead is light and the right shoulder is wide and clear. Which action is correct?","options":["Signal, move to the right edge of the road, and bring the vehicle to a stop until the ambulance has passed","Maintain your lane and speed so the ambulance can predict your path and steer around you","Move into the left lane and stop there to leave the right side fully open for the ambulance","Accelerate to stay ahead of traffic and find a side street to turn off onto"],"answer":0,"explanation":"When an emergency vehicle approaches with lights and siren, signal, pull to the right edge of the road, and stop until it has passed.","handbook":"Pull to the right and stop for emergency vehicles.","hbref":"§2.4","qid":"GK-W3-281"},"384":{"q":"You are assigned a loaded van trailer hauling lightweight boxes that are stacked floor-to-ceiling, filling the trailer to the roof. Compared with the same trailer hauling dense, heavy freight stacked only knee-high on the floor, which statement is the MOST accurate about how the tall, top-heavy load affects your driving?","options":["The taller stacking lowers the center of gravity, so you can safely take ramps and curves at posted truck speeds","The high center of gravity makes the trailer more likely to roll over in curves and on ramps, so you must slow down well before entering them","Because the cargo is lightweight, the center of gravity has no effect on rollover risk and only matters for braking distance","The high center of gravity mainly increases your stopping distance, so the real danger is rear-ending the vehicle ahead"],"answer":1,"explanation":"Stacking a load tall raises the center of gravity even when it is light, making the vehicle far more likely to roll over in curves and on ramps, so slow well before them.","handbook":"A high center of gravity increases rollover risk in curves.","hbref":"§2.2","qid":"GK-W3-282"},"385":{"q":"You are pulling a loaded tanker and approaching a clover-leaf exit ramp posted with a 35 mph advisory speed. Traffic behind you is heavy and you would like to keep moving. Reviewing what most often causes trucks to roll over, which factor is the single greatest contributor you should be most concerned about on this ramp?","options":["A load that is balanced too low, giving the trailer a center of gravity that is dangerously close to the road surface","Following the vehicle ahead a full second too closely as you enter the curve","Carrying your speed too high through the curve of the ramp instead of slowing down before you enter it","Braking too gently with the trailer brakes while still on the straight approach before the ramp"],"answer":2,"explanation":"The most common cause of truck rollover is taking a turn or ramp too fast, so slow to a safe speed before entering the curve, not while in it.","handbook":"Most rollovers are caused by going too fast in turns.","hbref":"§2.2","qid":"GK-W3-283"},"386":{"q":"You are hauling a tall load of stacked machine crates and you exit the interstate onto a curving entrance/exit ramp posted at 30 mph. Your truck is heavily loaded with a high center of gravity. Which action gives you the best protection against a rollover on the ramp?","options":["Hold a steady 30 mph because that is the posted ramp speed and the sign already accounts for trucks","Keep your highway speed until you feel the trailer start to lean, then brake hard in the curve","Coast through the curve in neutral so the engine does not push you faster","Slow to a speed well below the posted ramp speed before you enter the curve, since the posting is set for cars, not for a high, heavy load"],"answer":3,"explanation":"Ramp speed signs are set for cars, so a high, heavy load must slow to well below the posted ramp speed before entering the curve to avoid rolling over.","handbook":"Slow below posted ramp speeds, especially with a high load.","hbref":"§2.2","qid":"GK-W3-284"},"387":{"q":"You finish a delivery and park your loaded straight truck on a steep street that runs downhill, pulling up tight against the right-hand curb. Before you set the parking brake and leave the cab, you want the front wheels positioned so that if the brakes ever release, the truck rolls INTO the curb and is stopped by it rather than drifting into the downhill traffic lane. How should you leave the front wheels turned?","options":["Turned toward the curb (to the right), so a roll-away lets the curb block the front tire","Turned away from the curb (to the left), so the rear of the truck swings against the curb","Left straight ahead, since the set parking brake is what actually holds the truck on the grade","Turned toward the curb only if there is no curb present, otherwise straight ahead"],"answer":0,"explanation":"When parked downhill with a curb, turn the front wheels toward the curb so a roll-away wedges the tire against it and stops the truck.","handbook":"Park downhill with wheels turned toward the curb.","hbref":"§2.1","qid":"GK-W3-285"},"388":{"q":"You stop on a steep mountain road to check your load, parking your truck facing UPHILL with a curb on the right side. Before you walk away, you want the rig to roll into the curb and stop if the brakes ever release. To set the front wheels correctly for this uphill-with-curb situation, you should:","options":["Turn the front wheels toward the curb (to the right) so the tire backs into it","Turn the front wheels away from the curb (to the left) so the tire rolls back against it","Leave the front wheels pointed straight ahead and rely only on the parking brake","Turn the front wheels sharp right, the same as you would with no curb present"],"answer":1,"explanation":"When parked uphill with a curb, turn the front wheels away from the curb so a backward roll catches the tire against it and stops the rig.","handbook":"Park uphill with wheels turned away from the curb.","hbref":"§2.1","qid":"GK-W3-286"},"389":{"q":"You are following a motorcycle on a dry city street and you set your following distance based on how the rider has been moving. Which assumption about that motorcycle is the MOST important one to plan for so you do not rear-end it?","options":["It will always travel well below the speed limit, so a short gap is safe","It needs the space of two full lanes, so you should never pull alongside it","It can be easy to overlook in traffic and can stop much more quickly than your truck","It will hold one steady speed and will not slow suddenly"],"answer":2,"explanation":"Motorcycles are hard to see in traffic and can stop in a much shorter distance than a heavy truck, so allow extra following space.","handbook":"Motorcycles are hard to see and can stop quickly.","hbref":"§2.4","qid":"GK-W3-287"},"390":{"q":"You are hauling a loaded trailer and begin a long, steep downgrade in dry daytime conditions. A rookie riding with you asks how this descent affects the distance your rig will need to come to a complete stop compared to stopping on level pavement at the same speed. Which statement is correct?","options":["It makes no difference to your stopping distance, because total stopping distance is fixed at about 419 feet at 55 mph regardless of the road's slope.","Your stopping distance gets much shorter, because gravity pulling the truck downhill presses the tires harder into the road and improves braking traction.","Your stopping distance briefly drops toward zero once the engine and gears take over the braking on the grade.","Your stopping distance increases, because gravity adds to your momentum down the grade and the brakes must work harder over a longer distance to stop the rig."],"answer":3,"explanation":"On a downgrade gravity adds to your momentum, so the brakes must work harder over a longer distance and your stopping distance increases.","handbook":"Stopping distance increases going down a grade.","hbref":"§2.6","qid":"GK-W3-288"},"391":{"q":"You are hauling a loaded trailer on a rural highway and approach a sharp curve with a yellow advisory sign reading 'SAFE SPEED 40 MPH.' The pavement is dry and traffic is light. Which statement best describes how you, as a CDL driver, should treat that posted advisory speed?","options":["The 40 mph figure is calculated for passenger cars, so as a loaded truck with a higher center of gravity you should enter the curve below it to avoid rollover.","Because the sign is a legal advisory, 40 mph is the maximum lawful speed for all vehicles, and trucks may take the curve at exactly 40 mph as long as the road is dry.","The advisory applies only to empty trailers; since your trailer is loaded and stable, you may exceed 40 mph through the curve.","Advisory speeds are posted for trucks specifically, so 40 mph already includes a truck safety margin and you can match it without slowing further."],"answer":0,"explanation":"Curve advisory speeds are set for passenger cars, so a loaded truck with a higher center of gravity should enter below the posted speed to avoid rollover.","handbook":"Curve advisory speeds are set for cars; trucks should go slower.","hbref":"§2.6","qid":"GK-W3-289"},"393":{"q":"You finish a long delivery run and pull into the yard. Before your pre-trip inspection this morning everything checked out fine, and you also re-checked your cargo securement within the first 50 miles and again every 150 miles en route. Now that the trip is over and the truck is parked, which inspection should you perform to complete the full inspection cycle DPS expects of you?","options":["No further inspection is needed because your en-route checks every 150 miles already covered the vehicle for the day","A post-trip inspection, so any defects developed during the run are documented before the next driver or your next shift","A yearly inspection, since that is the only formal inspection required once the daily driving is finished","A monthly inspection of the brakes and tires to close out the trip's wear and tear"],"answer":1,"explanation":"A post-trip inspection is done at the end of the run so any defects that developed while driving are documented on a report before the next shift.","handbook":"Inspections are pre-trip, en route, and post-trip.","hbref":"§2.1","qid":"GK-W3-290"},"395":{"q":"You have just finished an 11-hour run and pulled into the yard. During the trip your brakes felt slightly soft and you noticed a marker light flickering out. As part of properly completing your post-trip inspection, which of the following are you generally expected to fill out and, where required, submit so the next driver and the carrier are warned of these conditions?","options":["The fuel-purchase and mileage receipt log you keep for IFTA tax reporting","Your personal trip diary noting how the day went and where you stopped to rest","A driver vehicle inspection report (DVIR) documenting any defects, such as the soft brakes and the failing marker light","A roadside weather and road-condition report for the dispatcher's records"],"answer":2,"explanation":"A post-trip inspection requires completing a driver vehicle inspection report (DVIR) that documents any safety defects, such as soft brakes and a failing marker light.","handbook":"A post-trip inspection includes a vehicle inspection report.","hbref":"§2.1","qid":"GK-W3-291"},"396":{"q":"It is a cold morning and you have just cranked the engine to begin your pre-trip warm-up. You are watching the dashboard gauges to make sure everything is working before you pull out. Which of the following is the correct expectation for the oil pressure gauge, and indicates the engine is safe to run?","options":["The needle should climb slowly and reach normal pressure after several minutes of idling, once the oil has warmed","Because the morning is cold, you should allow it about an hour of idling before the oil pressure becomes reliable","Oil pressure does not need to register until you are moving under load on the road","The needle should reach normal operating pressure within a few seconds of the engine starting"],"answer":3,"explanation":"Oil pressure should reach normal operating pressure within a few seconds of starting the engine, or you must shut it down to prevent damage.","handbook":"Oil pressure should come up within seconds of starting.","hbref":"§2.1","qid":"GK-W3-292"},"397":{"q":"You are 40 minutes into a run on a rural two-lane highway when you glance at your gauges and see the oil pressure gauge has dropped to zero, even though the engine still sounds and runs normally and no warning buzzer has sounded yet. What is the correct action?","options":["Pull off the road as soon as it is safe, stop, and shut the engine off","Keep driving normally to the next truck stop since the engine still sounds fine","Maintain speed but ease off the throttle and continue to your scheduled fuel stop","Turn off non-essential accessories like the radio and A/C to reduce engine load and keep going"],"answer":0,"explanation":"A loss of oil pressure means the engine is no longer being lubricated, so pull off as soon as it is safe and shut the engine off at once.","handbook":"If there is no oil pressure, stop and shut off the engine.","hbref":"§2.1","qid":"GK-W3-293"},"398":{"q":"You are climbing a long grade on a hot summer afternoon, fully loaded near your GVWR. As you near the top, one of your dash gauges begins to climb into the red. Before you decide how to react, which gauge is the one specifically designed to warn you that the engine itself is overheating?","options":["The oil pressure gauge, because hot weather thins the oil and the needle climbs to warn of high engine temperature","The coolant temperature gauge, because it reads the temperature of the engine coolant and warns you the engine is overheating","The pyrometer, because it reads exhaust gas heat, which on a hot day is the same as engine overheating","The voltmeter, because a long pull on a hot day overheats the charging system and signals engine overheating"],"answer":1,"explanation":"The coolant temperature gauge reads the engine coolant's temperature and warns you when the engine is overheating.","handbook":"The coolant temperature gauge warns of overheating.","hbref":"§2.1","qid":"GK-W3-294"},"399":{"q":"During your pre-trip inspection you start the engine and watch the dashboard gauges while the truck idles. You notice the ammeter (or voltmeter) needle is sitting steadily in the normal range and does not drop or swing erratically. What is this gauge actually telling you about your vehicle?","options":["The engine oil pressure is high enough to safely begin your trip","The coolant temperature is within the safe operating range","The charging system is working and keeping the battery properly charged","The battery has enough water in its cells and is securely bolted down"],"answer":2,"explanation":"A steady ammeter or voltmeter reading in the normal range confirms the alternator is generating current and keeping the battery properly charged.","handbook":"The ammeter/voltmeter shows whether the battery is charging.","hbref":"§2.1","qid":"GK-W3-295"},"400":{"q":"During your pre-trip inspection, you grab the steering wheel of your tractor and rock it back and forth without the front wheels moving. You feel a noticeable amount of looseness before the wheels begin to respond. To decide whether this free play is within safe limits and the vehicle is legal to drive, about how much steering wheel movement is the MOST you should have before the front wheels start to turn?","options":["Up to half a turn of the steering wheel, since some slack is normal in heavy trucks","Up to a full turn of the steering wheel before the wheels react","Up to 90 degrees, which is a quarter turn of the wheel","No more than about 10 degrees of movement before the wheels respond"],"answer":3,"explanation":"Steering wheel free play should be no more than about 10 degrees before the front wheels begin to respond; more signals worn or loose steering.","handbook":"Steering free play should not exceed about 10 degrees.","hbref":"§2.1","qid":"GK-W3-296"},"401":{"q":"During your pre-trip inspection you press the clutch pedal and find it has noticeably more free play (loose travel before resistance) than normal. You are already running late and the truck still drives. Which statement BEST describes what you have found and what you should do?","options":["Clutch free play that is too much or too little is a mechanical defect that must be repaired before the vehicle is safe to operate","Excess clutch free play is normal wear that only matters once the clutch begins to slip under load","It is a problem, but only the steering and brakes are inspection items that can keep a truck out of service","Loose clutch free play is actually a good sign that the linkage is properly lubricated and not binding"],"answer":0,"explanation":"Clutch free play that is too much or too little is a mechanical defect that must be repaired before the vehicle is safe to operate.","handbook":"Too much or too little clutch free play is a defect.","hbref":"§2.1","qid":"GK-W3-297"},"402":{"q":"You are hauling a loaded trailer down a long mountain grade. To save fuel and reduce wear, a fellow driver suggests you shift into neutral and let the truck roll down the hill, using the brakes only when your speed gets too high. Why is following this advice the wrong choice?","options":["It is acceptable on a short grade because the brakes alone can safely control the truck the entire way down","You lose engine and gear braking and vehicle control, your service brakes can overheat and fade, and coasting in neutral is illegal","It only becomes a problem if the grade is steeper than the low gear you would normally select before descending","Coasting saves so much fuel that the small loss of control is an acceptable trade-off on most downgrades"],"answer":1,"explanation":"Shifting into neutral on a long downgrade removes engine and gear braking, overheats and fades the service brakes, and coasting in neutral is illegal.","handbook":"Never coast in neutral; you lose engine braking and control.","hbref":"§2.13","qid":"GK-W3-298"},"403":{"q":"You are hauling a loaded trailer up a long grade in an older truck whose transmission has no gear indicator on the dash. The engine is starting to lug and lose power, and you know you need to drop to a lower gear to keep climbing. With no shift chart or gear display to rely on, which information should you actually use to decide which gear is correct for this moment?","options":["Only the reading from your right-side mirror as you watch the trailer track up the hill","The height of your driver's seat and how far down the grade looks from the cab","Your current road speed combined with the engine rpm shown on the tachometer","The position of the front door handle relative to your shoulder as a quick reference"],"answer":2,"explanation":"The right gear is chosen by matching your road speed to the engine rpm shown on the tachometer.","handbook":"Use road speed and engine rpm to select a gear.","hbref":"§2.3","qid":"GK-W3-299"},"404":{"q":"You are stopped at a red light on a steep uphill grade with a fully loaded trailer. The light turns green, and you need to get the rig moving smoothly without letting it drift toward the car stopped close behind you. As you prepare to release the service (foot) brake and bring up the engine, which technique BEST keeps the vehicle from creeping backward during the launch?","options":["Quickly pump the service brake several times to build extra air pressure before easing off the line","Shift into a higher gear so the engine has more pulling power to overcome the slope","Rev the engine and slip the clutch slowly so the truck eases forward on torque alone","Hold the parking brake on, then release it only as the engine takes hold and you begin to move forward"],"answer":3,"explanation":"When starting on an upgrade, hold the parking brake and release it only as the engine takes hold and you begin to move forward, preventing rollback.","handbook":"Use the parking brake on a hill start to avoid rolling back.","hbref":"§2.3","qid":"GK-W3-300"},"405":{"q":"It is just below freezing and a light glaze of ice covers the yard as you pull your loaded combination away from a stop sign at the warehouse exit. You feel the drive wheels begin to lose their grip. Which action gives you the BEST chance of moving off without spinning the drive wheels and triggering an acceleration skid?","options":["Ease onto the throttle and build speed gradually so the drive tires keep their grip on the slick surface","Press the accelerator firmly to the floor so the extra power pushes the truck through the slippery patch","Add an extra second of following distance for every 10 feet of vehicle length before you move","Keep the clutch partly engaged and rev the engine high, then let it out quickly to get a strong launch"],"answer":0,"explanation":"On a slick, near-freezing surface, ease onto the throttle and build speed gradually so the drive tires keep their grip and do not spin into a skid.","handbook":"Accelerate smoothly to avoid spinning the drive wheels.","hbref":"§2.3","qid":"GK-W3-301"},"406":{"q":"It is just after dawn and you are doing your pre-trip inspection. When you open the hood and look at the alternator and water pump drive belts, which condition tells you the belts need attention before you can safely take the truck out on the road?","options":["The belts have a dull, dark color instead of a bright, shiny finish","A belt is cracked and frayed, or it deflects more than it should when you press on it (improper tension)","The horn does not sound loud enough when you press it","The fuel gauge does not read full when the key is on"],"answer":1,"explanation":"Drive belts must be replaced if they are cracked or frayed or deflect more than they should, since improper tension or wear can cause the belt to fail.","handbook":"Check drive belts for proper tension and wear.","hbref":"§2.1","qid":"GK-W3-302"},"407":{"q":"During your pre-trip inspection you open the hood and run your hand along the radiator and heater hoses in the engine compartment. You are checking these hoses primarily for which condition?","options":["Whether the hoses feel warm, indicating the engine has reached operating temperature","A loud hissing or knocking sound coming from the belt and pulley area","Soft spots, leaks, and cracks that could cause a hose to fail","A bright, glossy finish showing the rubber has been recently cleaned and treated"],"answer":2,"explanation":"Engine hoses must be inspected for soft spots, leaks, and cracks, because a weakened hose can burst under heat and pressure and cause loss of coolant.","handbook":"Check hoses for leaks and cracks.","hbref":"§2.1","qid":"GK-W3-303"},"408":{"q":"It is just below freezing during your morning pre-trip, and as you walk around the engine compartment you decide to check the power steering system before a long day of mountain driving. Which of the following BEST describes what you should be inspecting on the power steering system?","options":["The steering wheel for no more than 10 degrees (about 2 inches on a 20-inch wheel) of free play before the wheels move","Loud whining or groaning noises from the pump, since sound is the only reliable sign of a power steering problem","Fresh, bright paint on the reservoir and lines to confirm the system was recently serviced","The power steering fluid level and any signs of leaks in the hoses, reservoir, and connections"],"answer":3,"explanation":"Check the power steering system for proper fluid level and any leaks in the hoses, reservoir, and connections, since a low level can cause sudden loss of power assist.","handbook":"Check power steering fluid level and for leaks.","hbref":"§2.1","qid":"GK-W3-304"},"409":{"q":"During your pre-trip inspection on a cold, bright morning, you walk up to the cab and notice a crack running across the lower edge of the windshield, plus a film of road grime and dried bug splatter over much of the glass. You will be driving into low morning sun for the first hour of your trip. What is the correct way to handle the windshield before you drive?","options":["Clean the windshield thoroughly and make sure the crack is not large enough or positioned to badly obstruct your view before driving","Leave the grime in place because a dirty, hazy windshield actually cuts glare from the low morning sun and improves your vision","Apply a dark tint film across the whole windshield to handle the sun glare, then drive without cleaning the glass","Ignore the windshield entirely since any crack, no matter how minor, automatically places the vehicle out of service and ends the inspection"],"answer":0,"explanation":"A windshield must be clean and free of any crack large enough or positioned to badly obstruct your view before you drive.","handbook":"The windshield must be clean and not badly cracked.","hbref":"§2.1","qid":"GK-W3-305"},"410":{"q":"It is a rainy morning and during your pre-trip inspection you discover that the driver-side wiper blade is torn and the washer reservoir is empty. You are already behind schedule and the rain is light right now. Which reason BEST explains why you should fix these items before you drive, rather than treating them as a minor convenience?","options":["They are needed mainly to keep road grime off the paint and preserve the truck's resale value","Working wipers and washers keep your vision clear in rain, and without clear vision you cannot safely judge distance, traffic, and hazards ahead","They are only required so the truck will pass the annual state safety sticker, not for day-to-day driving","They help defrost the windshield faster, which is the real reason they are an out-of-service item"],"answer":1,"explanation":"Wipers and washers keep your view clear in rain, and clear vision is essential to judge distance, traffic, and hazards ahead.","handbook":"Wipers and washers keep your vision clear in rain.","hbref":"§2.1","qid":"GK-W3-306"},"411":{"q":"You are backing your tractor-trailer out of a tight loading dock when a worker on foot suddenly steps into your blind spot near the rear. During your pre-trip you had confirmed your horn works. In this moment, what is the PRIMARY reason a working horn matters to you as a CDL driver?","options":["It lets you signal coworkers that you are finished and ready to leave the dock","It confirms your electrical system has enough charge to run accessories","It allows you to warn the worker and other people of immediate danger so they can move clear","It satisfies a comfort-and-convenience feature the inspector checks for ride quality"],"answer":2,"explanation":"The horn is a safety warning device used to alert workers, pedestrians, and drivers of immediate danger so they can move clear.","handbook":"The horn is used to warn others.","hbref":"§2.1","qid":"GK-W3-307"},"412":{"q":"It is just below freezing on an early-morning pre-trip, and your windshield keeps fogging and frosting over on the inside. You confirm the defroster and heater are running properly. What is the primary safety reason these systems must be working before you pull out onto the road?","options":["So the cab stays warm enough to keep you alert and comfortable on a long, cold shift","So you can quickly thaw any ice on the outside mirrors and antenna before driving","So warm air keeps the wiper blades from sticking and freezing to the glass","So you can keep the windshield clear and maintain an unobstructed view of the road in cold or wet weather"],"answer":3,"explanation":"The defroster and heater keep the windshield clear in cold or wet weather, preserving an unobstructed view of the road.","handbook":"The defroster keeps the windshield clear.","hbref":"§2.1","qid":"GK-W3-308"},"413":{"q":"It is just below freezing, you are only driving two miles to a nearby drop yard, and your seat belt feels stiff and uncomfortable against your winter coat. As you finish your pre-trip and prepare to pull out, which action is correct regarding your seat belt?","options":["Buckle and wear the seat belt for the entire trip, no matter how short the distance or how slow you plan to drive","Leave the belt unbuckled because the trip is under three miles and you will be driving slowly","Tuck the belt loosely behind you so the warning chime stops but your movement is not restricted by your coat","Skip the belt since low-speed yard and lot driving does not legally require restraint"],"answer":0,"explanation":"A commercial driver must wear the seat belt whenever the vehicle is in motion, no matter how short or slow the trip.","handbook":"Seat belts must be present and always worn.","hbref":"§2.1","qid":"GK-W3-309"},"414":{"q":"You are running a load on a rural two-lane highway when your engine loses power and you coast onto the right shoulder. You switch on your hazard flashers and you can already smell smoke from the engine compartment, so you grab your charged fire extinguisher. Before you start walking back to set out your warning devices, which other piece of emergency gear are you legally required to have carried on this truck so you can complete the warning setup?","options":["A backup CB radio so you can call for help and warn other truckers of the hazard","Reflective warning triangles to place on the road and alert approaching traffic","A high-visibility safety vest, which is the only device the rules require you to carry","A bag of road flares only, since triangles are optional once your flashers are on"],"answer":1,"explanation":"Every CMV must carry three reflective warning triangles to place on the road and alert approaching traffic when stopped.","handbook":"Carry a fire extinguisher and warning devices.","hbref":"§2.1","qid":"GK-W3-310"},"415":{"q":"You arrive for your shift and climb into a tractor that another driver dropped off two hours ago. You want to confirm the brakes, lights, and tires are roadworthy before you pull out of the yard. Which single action gives you the most reliable starting picture of any defects that were already discovered on this vehicle?","options":["Take the rig's word as roadworthy because the previous driver clearly finished a run in it without breaking down","Skip straight to a road test, since driving the truck a few miles is the fastest way to feel any real problem","Read the previous driver's last vehicle inspection (DVIR) report and verify any noted defects were certified as repaired","Call dispatch and ask whether any other driver has complained about this unit in the past week"],"answer":2,"explanation":"Before driving, review the previous driver's last inspection report (DVIR) and confirm any noted defects were certified as repaired.","handbook":"Review the last vehicle inspection report before a trip.","hbref":"§2.1","qid":"GK-W3-311"},"417":{"q":"You are three hours into a long, monotonous interstate run after an early start. Your speed has crept down without you noticing, you do not quite remember the last few miles, and you catch yourself rubbing your eyes. According to safe-driving guidance, which of these is the clearest warning that you are becoming too drowsy to keep driving safely?","options":["Your hands feel restless on the wheel and you keep wanting to check your mirrors more often","You feel sharply alert and your focus is locked in on the road ahead","Your reaction time at the brake pedal feels faster and crisper than usual","Your eyelids feel heavy and your thoughts keep wandering away from the road"],"answer":3,"explanation":"Heavy, drooping eyelids together with wandering thoughts are classic warning signs of dangerous driver fatigue.","handbook":"Heavy eyelids and wandering thoughts are signs of drowsiness.","hbref":"§2.20","qid":"GK-W3-312"},"418":{"q":"It is 2 a.m. and you are three hours into a long run when your eyes feel heavy, you catch yourself drifting toward the shoulder, and you cannot remember the last few miles. You still have over 100 miles to the terminal. Which action will actually restore your ability to drive safely?","options":["Pull off at a safe rest area and sleep or rest before continuing","Roll the windows down and turn the radio up loud to stay alert","Stop for a large coffee and keep pushing to reach the terminal","Increase your following distance and keep driving more cautiously"],"answer":0,"explanation":"The only real cure for drowsiness is sleep, so pull off at a safe rest area and rest before continuing.","handbook":"The only cure for fatigue is to stop and rest.","hbref":"§2.20","qid":"GK-W3-313"},"419":{"q":"It is 4:30 a.m. and you are about to begin a 9-hour run after sleeping poorly the night before. You feel groggy. Which of the following is the LEAST effective way to make sure fatigue does not cause you to drive impaired on this long trip?","options":["Schedule your trips so you do most of your driving during the hours you are normally awake","Drink a large coffee and keep the cab cold and the radio loud to stay alert instead of sleeping","Get a full night of sleep before the trip and plan to stop and rest when you feel drowsy","Avoid medications that cause drowsiness and recognize warning signs like heavy eyelids or wandering thoughts"],"answer":1,"explanation":"Coffee, cold air, and loud noise only mask drowsiness temporarily and never replace sleep, the only true cure for fatigue.","handbook":"Get enough sleep before a long trip.","hbref":"§2.20","qid":"GK-W3-314"},"421":{"q":"It is a 100-degree afternoon and you are about three hours into a long run across West Texas. You pull over to do a required en-route check of your cargo and tires. Two of your tires now read noticeably higher pressure than they did during your cool, early-morning pre-trip. What is the MOST likely reason, and what does it tell you about the risk you now face?","options":["The hot pavement has cooled the air inside the tires, lowering the pressure and raising your risk of a flat","The tar bleeding up from the hot road has been absorbed into the tires, adding weight and pressure","The heat has increased the air pressure inside the tires, which raises the risk of a blow-out","Nothing is wrong; tire pressure naturally drops in heat, so the higher reading means your gauge is faulty"],"answer":2,"explanation":"Hot weather makes the air inside tires expand and raises pressure, increasing the risk of a blow-out.","handbook":"Heat raises tire pressure, so check it in hot weather.","hbref":"§2.11","qid":"GK-W3-315"},"422":{"q":"It is mid-afternoon on a very hot summer day in Texas, and as you drive a loaded combination vehicle you notice shiny, dark patches of tar 'bleeding' up to the surface of the asphalt ahead. What should you expect this bleeding tar to do to the road, and why does it matter for your control of the vehicle?","options":["The tar will give the tires extra grip because it is sticky, so you can safely maintain your highway speed through the patches.","The main danger is that the heat will raise your tire pressure past its limit, so the tar itself has no effect on how the road feels under your tires.","It has no real effect on traction as long as your steering-axle tires still have at least 4/32 inch of tread.","It will make the road surface slippery and reduce your tire traction, so you should slow down and avoid hard steering or braking on those patches."],"answer":3,"explanation":"Bleeding tar makes the road slippery and cuts traction, so slow down and avoid hard steering or braking on those patches.","handbook":"Bleeding tar makes the road slippery in hot weather.","hbref":"§2.11","qid":"GK-W3-316"},"423":{"q":"It is mid-July in Texas and you are climbing a long grade fully loaded. The cab is hot, your engine is working hard, and you want an early warning that the engine is about to overheat before you get stranded or do damage. Which gauge gives you that warning?","options":["The coolant temperature gauge","The oil pressure gauge","The fuel gauge","The tachometer (engine RPM)"],"answer":0,"explanation":"The coolant temperature gauge is the primary, direct indicator of engine overheating, giving the earliest warning to act.","handbook":"Watch the coolant temperature gauge in hot weather.","hbref":"§2.11","qid":"GK-W3-317"},"424":{"q":"You are driving a loaded combination vehicle on a two-lane highway just after dawn when you roll into a stretch of thick fog so dense you can barely make out the lane lines ahead. You decide you must keep moving slowly until you can reach the next exit. To see the road as well as possible WITHOUT making your visibility worse, which headlight setting is the best choice?","options":["Switch on your high beams, since they throw light about 350 to 500 feet and let you see farther through the fog","Use your low beams, because high beams reflect off the fog back into your eyes and reduce what you can see","Turn off all forward lights and rely only on your four-way hazard flashers so oncoming drivers spot you","Run high beams now and dim them only when an oncoming vehicle comes within 500 feet"],"answer":1,"explanation":"In fog use low beams, because high beams reflect off the fog and bounce glare back into your eyes, reducing visibility.","handbook":"Use low beams in fog.","hbref":"§2.11","qid":"GK-W3-318"},"425":{"q":"You are driving a loaded tractor-trailer on a two-lane highway at night when you enter a bank of fog so thick you can no longer see the lane lines or taillights ahead of you. Which of the following is the SAFEST action to take?","options":["Switch to your high beams so the brighter light helps you see farther through the fog","Keep rolling at a reduced speed on your low beams, since stopping anywhere is more dangerous than continuing","Pull completely off the road, well clear of the travel lanes, turn on your flashers, and wait for the fog to lift","Slow to a crawl and stop in your lane with your four-way flashers on until visibility improves"],"answer":2,"explanation":"When fog is too thick to see, pull completely off the road clear of traffic lanes, turn on your flashers, and wait for it to lift.","handbook":"In very heavy fog, pull off the road and wait.","hbref":"§2.11","qid":"GK-W3-319"},"426":{"q":"You are dispatched on a windy day with steady crosswind gusts on an open stretch of highway. Four combination vehicles are leaving the yard at the same time as you. Based on how wind affects a vehicle, which driver should be MOST concerned about being pushed out of the lane or even tipped by the crosswind?","options":["The driver of a fully loaded tanker, because the surging liquid makes wind the biggest threat","The driver of a flatbed with a low, heavy, evenly distributed steel load","The driver of a loaded van trailer running at the legal weight limit, because heavier rigs catch more wind","The driver of a tall box trailer that is empty or lightly loaded, because it presents a large surface with little weight to resist the wind"],"answer":3,"explanation":"An empty or lightly loaded tall box trailer is most at risk in crosswinds because it presents a large surface with little weight to resist the wind.","handbook":"High, light, or empty trailers are most affected by strong wind.","hbref":"§2.11","qid":"GK-W3-320"},"427":{"q":"You are driving a loaded combination vehicle on a rural two-lane Texas highway and want to plan your trip so you spend the least time in the conditions when deer and other large animals are most likely to dart across the road. Which part of the day requires the highest level of alertness for animal crossings?","options":["The low-light periods around dawn and dusk","The middle of the day around high noon, when animals search for food","Late morning, after the sun has fully risen","Mid-afternoon, during the warmest part of the day"],"answer":0,"explanation":"Deer and large animals are most active at dawn and dusk, the low-light times when a driver's vision is also most compromised.","handbook":"Animals are most active at dawn and dusk.","hbref":"§2.8","qid":"GK-W3-321"},"429":{"q":"You are driving a loaded combination vehicle on a busy four-lane highway in moderate traffic. A digital billboard on the right shoulder is bright and animated, and you find your eyes locked onto it for several seconds as you roll past. Which consequence of this fixed stare is the MOST serious safety concern a CDL driver should recognize?","options":["Your eyes will adjust to the glare and you will momentarily lose your night vision","You stop scanning and fail to notice developing hazards in other parts of your field of view","You will subconsciously slow well below the flow of traffic and impede vehicles behind you","You will fixate so sharply on the sign that you actually see the road ahead more clearly"],"answer":1,"explanation":"Fixating on one object stops your eyes from scanning, so hazards developing elsewhere in your field of view go unnoticed until too late.","handbook":"Staring too long makes you miss other hazards.","hbref":"§2.4","qid":"GK-W3-322"},"430":{"q":"You are driving a loaded combination vehicle on a two-lane rural highway and you catch up to a slow tractor that is holding you 15 mph below the limit. You want to pass, but the road keeps changing. At which of the following locations would attempting to pass be the LEAST safe and most likely to put you in a head-on situation?","options":["On a long, flat straightaway where you can clearly see at least a quarter mile of empty oncoming lane","On a gentle downgrade where your speed naturally builds and you can complete the pass quickly","On the approach to a hill crest or a curve, where the road ahead bends or rises out of sight","On a straight stretch with a dashed center line and no oncoming traffic in view"],"answer":2,"explanation":"Never pass approaching a hill crest or curve, where the road rises or bends out of sight and oncoming traffic may be hidden.","handbook":"Do not pass on a hill or curve with limited sight.","hbref":"§2.4","qid":"GK-W3-323"},"431":{"q":"You are driving your loaded tractor-trailer on a two-lane highway and begin to pass a slower car. As you move alongside it, you realize you are spending several seconds traveling even with the car's rear door, sitting squarely in the driver's blind spot. To complete this maneuver as safely as DPS requires, what should you do?","options":["Ease off the accelerator and hold a position even with the car so the other driver has plenty of time to notice you before you move ahead","Stay beside the car at a matched speed until you are certain no oncoming traffic is approaching, then pull back into your lane","Maintain your current speed and drift gradually back toward your lane while still alongside the car to shorten the overall pass","Accelerate as needed to get through the other driver's blind spot and complete the pass promptly, then return to your lane without lingering beside the vehicle"],"answer":3,"explanation":"Complete a pass promptly and get clear of the other driver's blind spot, then return to your lane without lingering alongside.","handbook":"Complete a pass promptly without lingering alongside.","hbref":"§2.4","qid":"GK-W3-324"},"432":{"q":"You are approaching an intersection with a marked crosswalk. The light is green for you and you want to make a right turn, but a pedestrian has already stepped off the curb into the crosswalk you are about to cross. What should you do?","options":["Yield and let the pedestrian finish crossing, because pedestrians in a marked crosswalk have the right of way","Proceed with your turn since your green light gives you the right of way over the pedestrian","Tap your horn to alert the pedestrian and continue turning if they do not stop","Stop only if the pedestrian is directly in your lane of travel, otherwise keep moving"],"answer":0,"explanation":"Pedestrians lawfully in a marked crosswalk always have the right of way, so a turning driver must yield even on a green light.","handbook":"Pedestrians in a crosswalk have the right of way.","hbref":"§2.4","qid":"GK-W3-325"},"433":{"q":"You are driving your tractor-trailer on a two-lane city street and a bicyclist is riding ahead of you in the right portion of your lane. Traffic is moderate and you are approaching a parked-car zone where the cyclist may need to move left. Which action best reflects how you should treat this bicyclist?","options":["Stay close behind and give a long horn blast so the cyclist knows to pull to the shoulder","Treat the bicyclist as you would another vehicle, giving full room and a safe space before passing","Squeeze past in the same lane since a bicycle takes up far less space than a car","Move into the far left lane and remain there for the rest of the block"],"answer":1,"explanation":"A bicyclist has the same right to the road as any vehicle, so give full room and a safe passing space instead of crowding them.","handbook":"Give bicyclists room like any other vehicle.","hbref":"§2.4","qid":"GK-W3-326"},"434":{"q":"You are approaching a multi-lane roundabout in your loaded combination vehicle. Traffic is already circulating inside the roundabout, and a gap is opening on your left but a vehicle is still approaching that gap. Which action is the correct way to enter?","options":["Accelerate hard and merge before the approaching vehicle reaches your entry point, since the larger vehicle has the right-of-way","Roll into the circle and come to a full stop once inside, then wait there until all surrounding traffic clears around you","Yield to the traffic already circulating in the roundabout, and enter only when there is a gap large enough for your full vehicle length","Enter immediately and, if needed, travel against the flow to reach your exit by the shortest path"],"answer":2,"explanation":"Traffic already circulating in a roundabout has the right of way, so enter only when there is a gap big enough for your full vehicle length.","handbook":"Yield to traffic already in a roundabout.","hbref":"§2.4","qid":"GK-W3-327"},"435":{"q":"It has been raining steadily for the last twenty minutes and the pavement is fully wet. You are running at your normal dry-road highway speed and keeping your usual 6-second following gap behind the car ahead. Compared to driving this same stretch on dry pavement, what is the MOST important thing you must account for in how you operate right now?","options":["Nothing changes for stopping; the truck's brakes apply the same force, so your normal dry-road following gap is still adequate","Your reaction distance grows because wet roads slow your perception, but actual braking distance stays the same once the brakes grab","Stopping distance gets much shorter because a film of water lets the tires roll more freely and reduces drag on the truck","Your total stopping distance gets longer because reduced traction lengthens braking distance, so you must slow down and increase your following distance"],"answer":3,"explanation":"Wet pavement reduces traction and lengthens braking distance, increasing total stopping distance, so slow down and increase your following distance.","handbook":"Wet roads increase stopping distance.","hbref":"§2.11","qid":"GK-W3-328"},"437":{"q":"You are 90 minutes into a run when dispatch radios that your delivery address has changed and you need a new route in your GPS. Traffic is light and you are cruising at highway speed. Which action is the SAFEST way to handle the new destination?","options":["Wait until you can pull off the road and park in a safe spot, then enter and set the new route before driving again","Enter the new address at the next red light while you are stopped, then pull away as soon as it loads","Mount the unit low near the wheel and type the address there so your eyes stay close to the road","Keep driving and glance back and forth between the GPS and the road as you type in the new destination"],"answer":0,"explanation":"Always set the GPS before driving, never while moving, so pull off the road to a safe spot, enter the new route, then resume driving.","handbook":"Set your GPS before you start driving.","hbref":"§2.8","qid":"GK-W3-329"},"439":{"q":"Your tractor-trailer has just been involved in a collision and is stopped, blocking part of a two-lane undivided rural highway. Other drivers are approaching from both directions. After you have turned on your hazard flashers, what is the BEST way to warn the approaching traffic?","options":["Leave the hazard flashers on by themselves, since the law only requires flashers in a crash","Within 10 minutes, set out your reflective warning triangles -- one about 100 ft behind, one about 100 ft ahead, and one about 10 ft to the rear of the vehicle","Stand in the traffic lane and wave your arms so drivers can clearly see you and slow down","Keep sounding the horn continuously until all approaching vehicles have come to a stop"],"answer":1,"explanation":"Within 10 minutes of stopping on an undivided road, place warning triangles about 100 ft behind, 100 ft ahead, and 10 ft to the rear of the vehicle.","handbook":"Put out warning devices to warn other traffic after a crash.","hbref":"§2.14","qid":"GK-W3-330"},"441":{"q":"You are driving a loaded tractor-trailer at 60 mph on a rural two-lane highway when you notice in your mirrors that a pickup has been tailgating you closely for several miles. Traffic ahead is light and steady. Which action is the BEST way to reduce the danger this tailgater creates?","options":["Tap your brakes lightly several times to signal the pickup to back off and discourage it from following so close","Maintain your speed but move to the left edge of your lane so the pickup can see far enough ahead to pass you safely","Gradually increase your following distance to the vehicle ahead so you have extra room to slow down smoothly instead of braking hard","Speed up to open a gap between yourself and the pickup until it is no longer close enough to be a hazard"],"answer":2,"explanation":"When tailgated, open more space ahead so you can slow gradually instead of braking hard, giving the driver behind more time to react.","handbook":"Handle a tailgater by opening more space ahead.","hbref":"§2.7","qid":"GK-W3-331"},"442":{"q":"You are driving a loaded tractor-trailer at 55 mph on a dry two-lane highway when a passenger car begins tailgating you closely. The driver is impatient and clearly wants you out of the way. You want to reduce the danger this tailgater creates without making the situation worse. Which of the following is the WORST thing for you to do in response?","options":["Maintain a steady, consistent speed so the car behind can judge a safe gap and eventually pass","Ease off the accelerator gradually to open more space in front of you as a cushion","Keep to the right and avoid sudden moves so the tailgater has room to go around you","Increase your speed to pull away from the tailgater and put more distance between the two of you"],"answer":3,"explanation":"Speeding up to lose a tailgater is wrong because it keeps them following close while raising speed and stopping distance for both vehicles.","handbook":"Do not try to lose a tailgater by speeding up.","hbref":"§2.7","qid":"GK-W3-332"},"443":{"q":"It is just below freezing on a clear morning and you are hauling a load on a rural highway. The pavement ahead looks merely wet, but you are approaching a long overpass spanning a river. Which statement should MOST influence how you handle the overpass?","options":["The overpass deck can be frozen and icy before the surrounding roadway, because it loses heat from above and below.","The overpass will be the last surface to ice over, so it is the safest place to brake hard if needed.","Bridge and overpass surfaces only become slick in summer when tar bleeds up through the pavement.","Elevated decks never freeze as long as the approach road still appears wet rather than white."],"answer":0,"explanation":"Bridges and overpasses freeze before the road because they lose heat from both above and below, so they can be icy while the road is only wet.","handbook":"Bridges freeze before the rest of the road.","hbref":"§2.11","qid":"GK-W3-333"},"444":{"q":"It is a cool, damp autumn morning and you are driving a loaded combination vehicle on a two-lane rural road. Coming out of a curve, you see the pavement ahead is covered with a thick mat of wet, fallen leaves stretching across both lanes. Which statement best describes how you should treat this stretch of road?","options":["The leaves add grip the same way wet sand does, so you can maintain your current speed safely through the patch.","Treat the leaf-covered pavement as a slippery surface, easing off the accelerator and avoiding hard braking or steering until you are past it.","Because the leaves are organic and soft, they cushion the tires and have no real effect on traction or stopping distance.","Only the front (steering-axle) tires lose traction on leaves, so light braking with the drive wheels keeps you fully in control."],"answer":1,"explanation":"Wet leaves form a slick, low-traction layer like ice, so ease off the accelerator and avoid hard braking or steering until you are past them.","handbook":"Wet leaves on the road can be slippery.","hbref":"§2.11","qid":"GK-W3-334"},"445":{"q":"It is just below freezing and the sun is out as you drive a rural two-lane road. The open, sunlit stretches of pavement look dry, but the roadway repeatedly passes under tree canopy and alongside tall north-facing embankments that stay in shadow. As you approach one of these shaded sections, what is the GREATEST hazard you should expect the shade to be hiding?","options":["Bleeding tar that has softened in the sun and turned the surface slippery","Loose gravel that has been pushed into the shaded low spots by traffic","A patch of ice, because the shaded pavement never warmed above freezing even though the sunny stretches are dry","Fresh pavement-marking paint that has not yet fully cured in the cold"],"answer":2,"explanation":"Shaded pavement gets no direct sunlight, so moisture there stays frozen even when sunlit, dry stretches have warmed above freezing.","handbook":"Shaded spots may hide ice on cold days.","hbref":"§2.11","qid":"GK-W3-335"},"446":{"q":"You are driving your tractor-trailer on a wet interstate during a steady rain. A line of trucks is passing you in the left lane, and each one throws a heavy sheet of road spray across your windshield as it goes by. As you think about how this spray affects you and your ability to drive safely, which statement is the single best description of its MAIN effect?","options":["It cools your brake drums, so you can rely on them more heavily on the next downgrade","It increases your tire tread depth, helping you stay above the 4/32-inch front-tire minimum","It washes grime off the road, improving traction between your tires and the pavement","It briefly blinds you by cutting your visibility, so you should slow down and increase your following distance"],"answer":3,"explanation":"Road spray from passing trucks momentarily covers your windshield and sharply cuts visibility, so slow down and increase your following distance.","handbook":"Spray from other trucks reduces visibility in rain.","hbref":"§2.11","qid":"GK-W3-336"},"447":{"q":"You are driving a 53-foot tractor-trailer and need to make a sharp right turn from a city street into a narrow alley. You notice a parked car and a curb on the inside (right) of the turn. Because of off-tracking, which of the following BEST describes what you must plan for as you swing the rig through this turn?","options":["Your trailer's rear wheels will follow a path inside the path of your front wheels, so the rear tires may cut over the curb or strike the parked car on the inside of the turn","Your trailer's rear wheels will follow a wider path to the outside of the front wheels, so the rear of the trailer will swing toward oncoming traffic on the left","Your front and rear wheels will track in the exact same path, so if your steer tires clear the curb the trailer wheels will clear it too","Off-tracking only matters at highway speed, so at this low turning speed all four sets of wheels follow essentially the same line"],"answer":0,"explanation":"Due to off-tracking, a long trailer's rear wheels follow a path inside the front wheels, so swing wide enough to keep the rear tires off the inside curb or vehicles.","handbook":"In a turn, rear wheels off-track inside the front wheels' path.","hbref":"§2.3","qid":"GK-W3-337"},"448":{"q":"You are driving a 53-foot tractor-trailer and must make a tight right turn from a narrow two-lane street onto another narrow street. You know that because your trailer's rear wheels follow a shorter, tighter path than your tractor's front wheels (off-tracking), you have to plan your turn carefully. To complete this right turn safely without your trailer's rear wheels riding up over the curb, what must you account for?","options":["Because of off-tracking, the rear of the trailer swings wide, so you only need extra clearance on the outside (left) of the turn","Because of off-tracking, the trailer's rear wheels cut inside the path of the tractor, so you need extra room on the inside of the turn","Off-tracking does not affect a turn this sharp, so no extra room is needed in any direction","Because the vehicle is long, you need less room on the inside since the trailer tracks straight behind the tractor"],"answer":1,"explanation":"Off-tracking makes the trailer's rear wheels cut inside the tractor's path, so reserve extra room on the inside of the turn.","handbook":"Off-tracking requires extra room on the inside of turns.","hbref":"§2.3","qid":"GK-W3-338"},"449":{"q":"You are merging onto a busy interstate in your tractor-trailer and a small sedan disappears from view just behind your right-side mirror, where you can no longer see it at all. Before you change lanes, how should you correctly describe and treat this specific area around your truck?","options":["It is a low-traction zone, so I should brake gently before steering into the lane.","It is a buffer cushion that other drivers are responsible for keeping clear of my trailer.","It is one of my blind spots, also called a No-Zone, where other drivers are hard for me to see, so I must check carefully before moving over.","It is the danger zone created only by my high center of gravity when the trailer is loaded."],"answer":2,"explanation":"The areas around a truck where other drivers are hard to see are blind spots, called No-Zones, which must be checked carefully before changing lanes.","handbook":"A truck's blind spots are called No-Zones.","hbref":"§2.4","qid":"GK-W3-339"},"450":{"q":"You are merging your tractor-trailer onto a busy freeway. A passenger car that you clearly saw in your right-side mirror a moment ago has now completely vanished from that mirror, and you do not see it ahead of you either. Before you continue your lane change, what does this disappearance MOST likely mean?","options":["The car has accelerated and is now well off in the distance behind you, so the lane is clear","The car braked hard and pulled off onto the right shoulder, completely off the roadway","Your mirror is misadjusted and needs to be repositioned during your next stop","The car has moved into a blind spot (a 'No-Zone') alongside your trailer where your mirror can no longer show it"],"answer":3,"explanation":"A vehicle that vanishes from your mirror has likely entered a blind spot (No-Zone) alongside your trailer, so never change lanes until you can account for it again.","handbook":"A car that disappears in your mirror may be in a blind spot.","hbref":"§2.4","qid":"GK-W3-340"},"451":{"q":"You are driving a loaded tractor-trailer on a four-lane highway and decide to move from the right lane into the left lane to pass a slow vehicle. You check both your flat and convex (spot) mirrors, see they appear clear, and signal early. As you begin to ease over, the GREATEST danger to you is a vehicle located where?","options":["In the blind spot alongside your trailer, an area your mirrors do not show","Two lanes over in the far left lane, partially visible in your convex mirror","Directly behind your trailer where your brake lights are visible","Ahead of you in your own lane, the slow vehicle you intend to pass"],"answer":0,"explanation":"Large trucks have blind spots (No-Zones) along the sides and rear that mirrors cannot show, so a head check is needed before changing lanes.","handbook":"A vehicle in your blind spot is the main lane-change danger.","hbref":"§2.4","qid":"GK-W3-341"},"453":{"q":"You are about to leave the terminal for a 400-mile run that crosses a mountain pass, and you want to plan the trip the right way before you roll. Which of the following is the MOST important thing to check during your trip planning?","options":["Whether your favorite music playlist is downloaded so you stay alert on the long drive","Your planned route and the current weather conditions along the way","That your following-distance habits will give you 1 second per 10 feet of vehicle length","Whether the truck stops on your route serve the kind of food you like for lunch"],"answer":1,"explanation":"Good trip planning means knowing your route and the weather along it ahead of time, so you can choose gears, speed, and timing for conditions you cannot control.","handbook":"Plan your route and check the weather before a trip.","hbref":"§2.6","qid":"GK-W3-342"},"454":{"q":"It is just below freezing, a light rain has begun to glaze the bridges along your route, and the posted speed limit is 55 mph. Traffic is light and the pavement still looks merely wet. Under Texas DPS rules, in which of these situations are you REQUIRED to operate at a speed BELOW the posted limit?","options":["When the road ahead is clear and dry, because a clear lane lets you safely use the full posted 55 mph","When traffic around you is light, because fewer vehicles means there is less reason to reduce your speed","When conditions are poor — such as the wet, near-freezing surface and potentially icy bridges you now face — because the safe speed is determined by traction and visibility, not the posted number","When you are running behind schedule, because hurrying through bad weather lets you make up the lost time"],"answer":2,"explanation":"Safe speed is set by traction and visibility, not the posted limit, so reduce speed on wet, near-freezing roads and icy bridges where black ice can hide.","handbook":"Drive below the limit when conditions are poor.","hbref":"§2.6","qid":"GK-W3-343"},"455":{"q":"You are hauling a loaded trailer on a rural highway posted at 55 mph. A cold drizzle has begun and the pavement is glistening wet. You feel comfortable and traffic is light. Which statement BEST describes how the 55 mph posted limit applies to you right now?","options":["The 55 mph limit is a legal floor as well as a ceiling, so dropping much below it would itself be a violation in these conditions","Because your truck is loaded and has good traction, the posted 55 mph remains a safe target speed on the wet pavement","Posted limits already include a built-in safety margin for rain, so 55 mph stays appropriate until the road is fully flooded","The 55 mph posting is the maximum for ideal conditions only, so on the wet road a safe speed is below the posted limit"],"answer":3,"explanation":"A posted limit is the legal maximum for ideal conditions only, so on a wet road, where traction drops and stopping distance grows, drive below the posted speed.","handbook":"Posted limits are the maximum for ideal conditions.","hbref":"§2.6","qid":"GK-W3-344"},"456":{"q":"You are hauling a loaded trailer on a busy interstate during rush hour. Traffic is dense and moving steadily, with vehicles boxing you in on both sides. You want to reach your delivery on time but you also know your stopping distance is long. Which action gives you the BEST control and lowest crash risk in this heavy traffic?","options":["Hold a steady speed that matches the flow and keep good spacing in front of you so you have room to stop","Change lanes frequently to find the fastest-moving gap and make up lost time","Follow closely behind the vehicle ahead so other cars cannot cut into your space","Brake firmly and often to keep your speed well below the traffic flow"],"answer":0,"explanation":"In heavy traffic, keep a steady speed that matches the flow and maintain plenty of space ahead so you have room for your long stopping distance.","handbook":"Keep a steady speed and good spacing in heavy traffic.","hbref":"§2.6","qid":"GK-W3-345"},"458":{"q":"You are driving your tractor-trailer on a hilly two-lane undivided highway. You catch up to a slow farm tractor and want to pass it, but the road ahead crests a hill so you cannot see what is coming over the top. Which of the following best describes when you should NOT begin your pass?","options":["When you have a long, clear straightaway and oncoming lane is empty for a quarter mile","When the road crests a hill or curve and you cannot see far enough ahead to safely complete the pass","When there is plenty of open road and good visibility but the vehicle ahead is moving slowly","Only when an oncoming vehicle is already within 500 feet and flashing its high beams"],"answer":1,"explanation":"Never pass when a hill crest or curve blocks your view, because you cannot see whether the oncoming lane is clear for the entire maneuver.","handbook":"Do not pass when you cannot see far enough ahead.","hbref":"§2.4","qid":"GK-W3-346"},"459":{"q":"You have just hooked your trailer to a customer's loading dock in a tight, unfamiliar yard. The dock is partly hidden behind your trailer, there are pallets stacked nearby, and your mirrors do not show the lower few feet directly behind the rig. Before you put the truck in reverse, what should you do FIRST to back safely?","options":["Begin backing slowly while relying on your mirrors, since they give the widest and most reliable view of the area behind the trailer","Sound your horn three times and then back at a steady speed, trusting that the blasts will warn anyone in the path behind you","Get out of the cab and walk to the rear to inspect the path, clearances, and any blind areas before you start to move","Back up quickly to get through the blind spot before any pedestrian or forklift has a chance to move into your path"],"answer":2,"explanation":"Always Get Out And Look (G.O.A.L.) before backing to check the path, clearances, and blind areas that mirrors cannot show.","handbook":"Get out and check the area before backing.","hbref":"§2.3","qid":"GK-W3-347"},"460":{"q":"You are alone in a tight loading yard and must back your tractor-trailer into a dock that is set off to the passenger (right) side. To swing the rear of the trailer toward that right-side dock, you begin turning the steering wheel to the right. In the very first moment after you start backing with the wheel turned right, before any larger correction, which way does the rear of the trailer initially move?","options":["The rear of the trailer immediately swings to the right, the same direction you turned the wheel, so you steer straight toward the dock.","The trailer tracks straight back in line with the tractor and only begins to angle once you add throttle.","The rear of the trailer climbs up and to the right toward the dock approach as the tractor pushes it.","The rear of the trailer first moves to the left, the opposite of the way you turned the wheel, before you counter-steer to bring it right."],"answer":3,"explanation":"When backing, the trailer rear first moves opposite to your steering, so turning the wheel right sends the rear left before you counter-steer.","handbook":"When backing, the trailer first goes opposite the steering.","hbref":"§2.3","qid":"GK-W3-348"},"461":{"q":"You are hauling a 53-foot dry van on a busy three-lane interstate and you start drifting toward the next lane. Glancing at your mirrors you cannot see two cars that are pacing you. Based on the truck's No-Zones, which danger area are these vehicles most likely hiding in right now?","options":["In the blind spots running along the right and left sides of the trailer","Directly in front of the cab where the hood blocks your view","Close behind the rear of the trailer where your mirrors cannot reach","High overhead, in the area above the top of the trailer"],"answer":0,"explanation":"Vehicles traveling alongside you can hide in the side No-Zone blind spots running along the right and left of the trailer, with the right side largest.","handbook":"Side No-Zones run along the sides of the trailer.","hbref":"§2.4","qid":"GK-W3-349"},"462":{"q":"You are hauling a loaded trailer on a busy four-lane interstate at 60 mph. A line of cars has begun stacking up close behind you in the right lane, and you sense a couple of them are preparing to pass. To properly manage the space BEHIND your rig and stay aware of these vehicles, what should you do?","options":["Stop using your mirrors and focus only on the road far ahead, since what is behind you cannot affect your driving","Glance at your mirrors regularly (roughly every 5 to 8 seconds) to track the vehicles closing in behind and beside you","Speed up well above 60 mph so the cars behind fall back and the space opens up on its own","Apply your brakes frequently to force the tailgaters to back off and create a cushion behind you"],"answer":1,"explanation":"You cannot control the space behind you, so check your mirrors regularly, about every 5 to 8 seconds, to track vehicles closing in behind and beside you.","handbook":"Check mirrors often to manage the space behind.","hbref":"§2.5","qid":"GK-W3-350"},"463":{"q":"You are driving a loaded tractor-trailer at 55 mph on a level interstate when you see brake lights ripple across the lanes a quarter mile ahead and the traffic pack begins compressing toward you. Following distance is closing. Which response BEST manages your space and energy in this developing situation?","options":["Maintain your speed and steer toward the shoulder lane so you can swing around the slowing pack before it fully stops","Apply firm, hard braking now to scrub off speed quickly, since at 55 mph it already takes roughly 419 feet to stop","Ease off the accelerator and let your following distance open back up, braking gently only as needed as the gap ahead develops","Hold your speed for now and keep at least one second of following distance for every 10 feet of vehicle length until you are forced to react"],"answer":2,"explanation":"When traffic ahead slows, ease off the accelerator to let your following distance open back up, braking gently only as needed.","handbook":"When traffic ahead slows, ease off and add following distance.","hbref":"§2.7","qid":"GK-W3-351"},"464":{"q":"You are hauling an over-width load on a narrow two-lane rural road with no shoulder. Oncoming pickups keep crowding the center line, the pavement edge drops off sharply on your right, and mailboxes and parked cars sit close to the travel lane. To manage the greatest hazard your wide vehicle creates here, where must you focus most of your attention?","options":["On the road surface far ahead, so you can spot potholes before your front tires reach them","On the space above your trailer, watching for low branches and overhead wires","On the space beneath the trailer, checking that nothing is dragging under the chassis","On the space to your sides, because the width of your vehicle leaves little clearance from oncoming traffic, the drop-off, and roadside objects"],"answer":3,"explanation":"On a wide vehicle on a narrow road with no shoulder, watch your side clearance most, since oncoming traffic, drop-offs, and roadside objects crowd both sides.","handbook":"On narrow roads, watch your side space.","hbref":"§2.5","qid":"GK-W3-352"},"465":{"q":"You finish a long delivery run and stop at a roadside scale. An officer asks you to take a breath test. You had two beers with dinner about an hour ago and feel completely sober, and you know the limit for a regular passenger-car driver in your state is 0.08. What is the LOWEST blood alcohol concentration (BAC) at which you, operating your CDL vehicle, would be disqualified?","options":["0.04 or more","0.08 or more","0.10 or more","0.02 or more"],"answer":0,"explanation":"For a CDL driver operating a commercial vehicle, the legal limit is a blood alcohol concentration of 0.04 percent or more, half the limit for regular drivers.","handbook":"A CDL driver is disqualified for driving with a BAC of 0.04 or higher.","hbref":"§1.3","qid":"GK-W3-353"},"466":{"q":"You are pulled over at a roadside inspection while operating your CMV, and the officer has reasonable cause to ask you to submit to a test that measures your blood alcohol concentration. You feel certain you are under the 0.04% legal limit and you are worried the test could be inaccurate, so you tell the officer you would rather just refuse it. Under CDL rules, what is the consequence of that refusal?","options":["Nothing happens to your CDL as long as your actual BAC turns out to be under 0.04%","You are disqualified from operating a CMV, treated the same as if you had failed the test","You receive only a small administrative fine but keep full driving privileges","You get a written warning on the first refusal and are penalized only if you refuse again"],"answer":1,"explanation":"Refusing a lawfully required alcohol test disqualifies you from operating a CMV, the same penalty as failing the test.","handbook":"Refusing a required alcohol test results in disqualification.","hbref":"§1.3","qid":"GK-W3-354"},"467":{"q":"You are returning to your tractor after dinner during an overnight haul when a state trooper stops you at a roadside checkpoint. A chemical test shows your blood alcohol concentration is 0.06%, above the 0.04% CDL limit, and you are convicted of operating the CMV under the influence. This is the first such conviction on your record. Assuming no hazardous materials were involved, what is the MINIMUM period your CDL will be disqualified?","options":["60 days, the same period used for a serious traffic-violation pattern","90 days, the minimum out-of-service period for a logbook falsification","One year of disqualification","Three years, the same as a first offense while hauling hazardous materials"],"answer":2,"explanation":"A first conviction for driving a CMV with a BAC of 0.04% or higher carries a CDL disqualification of at least one year when no hazardous materials are involved.","handbook":"A first DUI conviction disqualifies a driver for at least one year.","hbref":"§1.3","qid":"GK-W3-355"},"469":{"q":"You are stopped at a Texas DPS weigh station during a roadside inspection. The officer has already confirmed your commercial driver license (CDL) is valid and your logbook is in order. He then asks you to produce one more document that federal rules require you to keep with you whenever you operate the vehicle, in order to prove you are physically qualified to drive. Which document must you hand him?","options":["Your CDL training-school graduation certificate, which proves you completed the required entry-level driver instruction","Your vehicle's certificate of title, which proves the truck is legally registered and authorized to be on the road","Your original birth certificate, which establishes your identity and lawful eligibility to hold the commercial license","Your medical examiner's certificate, which proves you are currently physically qualified to operate a commercial vehicle"],"answer":3,"explanation":"You must carry your medical examiner's certificate (med card) along with your CDL, as it proves you are currently physically qualified to drive a commercial vehicle.","handbook":"Carry your medical examiner's certificate along with your CDL.","hbref":"§1.2","qid":"GK-W3-356"},"470":{"q":"You are running about 30 minutes behind schedule on a four-lane divided highway. The driver in front of you is moving slower than you'd like, so you are weighing your options. Under Texas DPS rules, which of the following actions would count as a MAJOR traffic violation that could put your CDL at risk?","options":["Following the slower vehicle at a safe distance and waiting for a legal chance to pass","Briefly dropping below the posted minimum to check your mirrors before changing lanes","Weaving aggressively through traffic and tailgating to force the slow driver to move over","Signaling your lane change a little earlier than the vehicle directly ahead expects"],"answer":2,"explanation":"Weaving aggressively through traffic and tailgating to pressure another driver is reckless driving, a major violation that can lead to CDL disqualification.","handbook":"Reckless driving is a serious traffic violation.","hbref":"§1.3","qid":"GK-W2-069"},"471":{"q":"Your tractor-trailer stalls on the right shoulder of a level, straight, two-lane undivided highway. You switch on your hazard flashers and grab your reflective triangles to set them out before the 10-minute window closes. As you walk toward the rear of your rig to place the FIRST (closest) triangle, about how far back from the vehicle should you set it down?","options":["About 10 feet behind the vehicle, on the traffic side","About 100 feet behind the vehicle","About 200 feet behind the vehicle","Right at the rear bumper, touching the vehicle"],"answer":0,"explanation":"The closest warning triangle is placed about 10 feet behind the vehicle on the traffic side to mark the immediate rear of the rig.","handbook":"Place a warning device about 10 feet behind the vehicle.","hbref":"§2.14","qid":"GK-W3-357"},"472":{"q":"A wheel bearing fails and you coast your tractor-trailer onto the shoulder of a flat, straight two-lane undivided highway. After switching on your four-way flashers, you grab your emergency triangles and begin setting them out toward approaching traffic. You correctly drop the first triangle 10 feet to the rear. For the SECOND triangle you place behind your rig on this kind of road, about how far back from your vehicle should it go?","options":["About 200 feet behind, then a third another 200 feet past that","About 100 feet behind the vehicle","About 50 feet behind the vehicle","About 100 feet ahead of the vehicle, in the oncoming lane"],"answer":1,"explanation":"On a two-lane or undivided road, the second triangle goes about 100 feet behind the vehicle because traffic can approach from both directions.","handbook":"Place a warning device about 100 feet behind the vehicle.","hbref":"§2.14","qid":"GK-W3-358"},"473":{"q":"Your tractor-trailer breaks down in the right lane of a straight, level, DIVIDED highway (a one-way roadway with a median separating opposing traffic) in good visibility. You switch on your hazard flashers and grab your emergency triangle kit. As you walk back to set out the triangle that must be placed FARTHEST from the rear of your vehicle, about how far back should you put it?","options":["About 100 feet behind, since that is where the middle triangle goes","About half a mile back, to give fast traffic the most possible warning","About 200 feet behind the vehicle","About 10 feet behind, just past the rear bumper"],"answer":2,"explanation":"On a one-way or divided highway, all three triangles go behind the vehicle, with the farthest placed about 200 feet back toward approaching traffic.","handbook":"Place a warning device about 200 feet behind the vehicle.","hbref":"§2.14","qid":"GK-W3-359"},"474":{"q":"You have stopped on the right shoulder of a one-way (divided) highway just past the crest of a hill, where vehicles coming up behind you cannot see your rig until the last moment. You turn on your hazard flashers and begin setting out your three reflective triangles. When it comes time to place the farthest triangle that protects your rear from approaching traffic, what should you do to account for the hill blocking the view?","options":["Keep all three triangles within 10 feet of the truck so they stay grouped and visible together","Place the far triangle exactly 200 feet back, the same as on a flat, open stretch, since that distance is the legal standard","Skip the far triangle entirely and rely on your hazard flashers, which are brighter than a triangle on a hill","Move the far triangle back beyond its normal 200-foot spot (up to 500 feet) so drivers crest the hill with enough warning to react"],"answer":3,"explanation":"Near a hill or curve that blocks the line of sight, move the far triangle back beyond its normal spot (up to 500 feet) so approaching drivers get enough warning.","handbook":"On hills and curves, place warning devices farther back.","hbref":"§2.14","qid":"GK-W3-360"},"475":{"q":"During your pre-trip inspection at a rest stop, you smell smoke and find a small fire that has started in a pile of discarded cardboard boxes, shipping paper, and a stack of moving blankets near your trailer's rear doors. You reach for your fire extinguisher and check its rating before acting. Which class of extinguisher is specifically intended for the type of materials that are burning here?","options":["Class A, which is rated for ordinary combustibles such as wood, paper, and cloth","Class B, which is rated for burning liquids such as fuel, oil, and grease","Class C, which is rated for fires in live electrical wiring and energized equipment","Class D, which is rated for combustible metals such as magnesium and titanium"],"answer":0,"explanation":"Fires in ordinary combustibles such as wood, paper, and cloth are rated for a Class A extinguisher.","handbook":"A Class A extinguisher is for wood, paper, and cloth fires.","hbref":"§2.14","qid":"GK-W3-361"},"476":{"q":"During your pre-trip inspection you check the fire extinguisher mounted in your cab. You are hauling drums of diesel fuel, and you want to be sure the extinguisher could actually handle the most likely fire for this load. A small fuel leak ignites near the drums. Which type of fire extinguisher is rated to fight this burning-liquid fire?","options":["A Class A extinguisher, since it is the most common type and works on the wood pallets and paper packing slips also in the trailer","A Class B extinguisher, since it is rated for burning liquids such as fuel, oil, and grease","A Class C extinguisher, since the fire started near the truck's electrical and battery system","A Class D extinguisher, since it is intended for fires involving combustible cloth, rags, and shop towels"],"answer":1,"explanation":"Fires in flammable liquids such as fuel, oil, and grease are rated for a Class B extinguisher.","handbook":"A Class B extinguisher is for burning liquids.","hbref":"§2.14","qid":"GK-W3-362"},"477":{"q":"During your pre-trip inspection you smell something hot near the dashboard and discover smoke coming from behind the energized wiring panel of your tractor's electrical system. You reach for the fire extinguisher mounted in the cab. To safely fight this fire, which class of extinguisher must you use?","options":["A Class A extinguisher, because it is rated for the wood and paper trim around the panel","A Class B extinguisher, because it is rated for the flammable liquids that fuel most truck fires","A Class C extinguisher, because it is rated for fires in live electrical equipment","Any class will work as long as you cut the battery disconnect first"],"answer":2,"explanation":"Fires in live electrical equipment require a Class C extinguisher because its non-conductive agent will not carry current back to the operator.","handbook":"A Class C extinguisher is for electrical fires.","hbref":"§2.14","qid":"GK-W3-363"},"478":{"q":"It is just below freezing and you are pulling away from a stop on a glazed, icy ramp. You feel the truck shudder and the tachometer jumps as your drive wheels begin to spin without the vehicle moving forward. To get moving and regain traction, what is the BEST action?","options":["Press down harder on the accelerator to power the spinning wheels through the ice","Quickly pump the brake pedal to force the drive wheels to bite into the surface","Steer rapidly from side to side to let the tire edges dig in and find grip","Ease off the accelerator so the drive wheels slow down and regain traction"],"answer":3,"explanation":"In a drive-wheel skid, ease off the accelerator to reduce power so the spinning wheels slow to vehicle speed and regain traction.","handbook":"If the drive wheels spin on ice, ease off the accelerator.","hbref":"§2.7","qid":"GK-W3-364"},"479":{"q":"You are descending a long grade and notice smoke and then flames coming from one of your trailer's dual tires. You get safely stopped on the shoulder, place your warning triangles, and grab your supplies. With a tire actively burning, which of the following is the BEST way to cool and put out the fire?","options":["Douse it with plenty of water, since water cools the burning tire","Smother it by shoveling dry sand directly over the flames","Let the airflow from rolling slowly along the shoulder cool the tire down","Spray engine oil to coat and seal the tire surface from oxygen"],"answer":0,"explanation":"Douse a burning tire with plenty of water, because water cools the rubber and casing where heat is held and prevents reignition.","handbook":"Water can be used to cool a burning tire.","hbref":"§2.14","qid":"GK-W3-365"},"480":{"q":"It is a cold morning and you are letting your truck idle in an enclosed loading dock to warm up before your pre-trip. After a few minutes you start feeling dizzy and develop a headache, but you cannot see or smell anything unusual in the air. Based on how carbon monoxide behaves, what is the MOST likely reason you got little or no warning before these symptoms began?","options":["The gas would have given off a sharp, sweet odor first, so the exhaust system must be sealed and not the cause","Carbon monoxide is colorless and odorless, so your senses cannot detect it before it affects you","The gas turns a visible bright red as it builds up, but the dim dock lighting hid it from you","Carbon monoxide is heavier than air and stays near the floor, so standing up would have warned you in time"],"answer":1,"explanation":"Carbon monoxide is colorless and odorless, so your senses cannot detect it before it affects you in enclosed spaces.","handbook":"Carbon monoxide is a colorless, odorless gas.","hbref":"§2.1","qid":"GK-W3-366"},"481":{"q":"You are running a loaded combination vehicle on a rural Texas highway when you see a weigh station up ahead with its \"OPEN\" sign lit and a few four-wheelers driving past it without slowing. You are tired and only a couple of miles from your delivery. Which action is legally correct?","options":["Pass it like the four-wheelers did, since the station is clearly only screening passenger cars today","Treat the station as optional and pull in only if an officer waves you over or your gross weight feels high","Pull into the open weigh station, because trucks are required by law to stop at any open weigh station they pass","Skip it because you are within a couple miles of your final delivery and your load is already secured"],"answer":2,"explanation":"Trucks are required by law to stop at any open weigh station they pass, regardless of fatigue, load, or what cars do.","handbook":"Commercial vehicles must stop at open weigh stations.","hbref":"§2.2","qid":"GK-W3-367"},"482":{"q":"During your pre-trip inspection at a roadside scale, a Texas DPS inspector finds a brake defect on your tractor, writes it up, and places an out-of-service (OOS) order on the vehicle. The shop is 8 miles away and your delivery window closes in one hour. Which action is legally correct?","options":["Because the load is time-sensitive, you may drive the 8 miles directly to the repair shop at reduced speed","You may continue your route as long as you stay under 55 mph and use only light, steady braking","You may drive once you top off the fuel and your air-brake gauge reads full pressure","You may not drive the vehicle at all until the defect is repaired and the order is cleared"],"answer":3,"explanation":"An out-of-service order legally bars you from driving on a public road until the defect is repaired and the order is cleared.","handbook":"An out-of-service vehicle may not be driven until the defect is fixed.","hbref":"§2.1","qid":"GK-W3-368"},"483":{"q":"A roadside inspector at a weigh station asks to review your records of duty status from your ELD. Your dispatcher claims the device exists mainly to satisfy the IRS and your fleet's accounting department. Which statement best describes what your records of duty status are actually designed to document for this inspection?","options":["The number of hours you have driven and been on duty, so the officer can confirm you are within your legal hours-of-service limits","The fuel purchases and mileage by state, so the officer can verify your IFTA tax reporting is accurate","The maintenance and repair history of the vehicle, so the officer can confirm required inspections were performed","The cargo weight and securement checks, so the officer can confirm you re-checked your load every 150 miles"],"answer":0,"explanation":"Records of duty status document your driving and on-duty hours so an inspector can confirm you are within legal hours-of-service limits.","handbook":"Records of duty status track a driver's hours of service.","hbref":"§2.21","qid":"GK-W3-369"},"484":{"q":"You are merging onto a highway in your loaded tractor-trailer and want quick acceleration. The tachometer needle is climbing fast and is now touching the top of the red zone, but you still want more power to keep pace with traffic. To protect the diesel engine, which of the following should you NOT do?","options":["Let the engine warm up at idle before demanding heavy power from it","Push the engine past the red line on the tachometer to squeeze out more acceleration","Shift up so the engine speed drops back below the red zone before adding throttle","Use the engine's normal operating RPM range to build speed gradually"],"answer":1,"explanation":"Never push the engine past the tachometer red line, since the red line marks the maximum safe RPM and over-revving causes severe engine damage.","handbook":"Do not over-rev a diesel engine past the red line.","hbref":"§2.3","qid":"GK-W3-370"},"485":{"q":"You park your loaded tractor-trailer on a slight downhill slope at a customer's dock, set the parking brakes, and step out to begin unloading. The lot is not perfectly level and you will be away from the cab for a while. Under these conditions, which action is the single best practice before you leave the truck unattended?","options":["Nothing extra is needed because the spring parking brakes will hold a loaded trailer indefinitely on any slope","Leave the transmission in a low gear instead of chocking, since gear engagement fully replaces wheel chocks on a slope","Chock the wheels, because there is a chance the truck could roll away on the uneven, sloped surface","Skip the chocks since the grade is only slight, and chocks are required only on steep mountain downgrades"],"answer":2,"explanation":"Chock the wheels whenever there is any chance the truck could roll, as on a sloped, uneven surface where it sits loaded and unattended.","handbook":"Chock the wheels if the vehicle might roll.","hbref":"§2.1","qid":"GK-W3-371"},"486":{"q":"You finish a delivery and must park your tractor-trailer pointing DOWNHILL on a rural shoulder. There is NO curb on this stretch of road. As you set up to leave the vehicle, how should you position your front (steering-axle) wheels so that, if the rig were to roll, it moves AWAY from passing traffic rather than into the travel lane?","options":["Leave the front wheels pointed straight ahead, since on a downgrade the parking brake and chocks do all the holding","Turn the front wheels hard to the LEFT, the same way you would when parking uphill against a curb","Point the front wheels straight and set them only after you have checked tire tread is at least 4/32 inch on the steering axle","Turn the front wheels toward the edge of the road, so a rolling vehicle drifts off the pavement away from traffic"],"answer":3,"explanation":"When parking downhill with no curb, turn the front wheels toward the edge of the road so a rolling vehicle drifts off the pavement away from traffic.","handbook":"Park downhill with no curb by turning wheels toward the road edge.","hbref":"§2.1","qid":"GK-W3-372"},"487":{"q":"It is just below freezing during your pre-trip inspection, and you notice the steps and handholds on your tractor are caked with a thin film of ice and road grime. Federal and Texas regulations require you to inspect these items. According to the handbook, what is the PRIMARY reason you must check the condition of the steps and handholds before driving?","options":["So you can safely get in and out of the cab, especially using three points of contact when surfaces are slippery","So you can confirm the cab structure can support the rated cargo weight listed on the GVWR plate","So you can verify the frame and mounting brackets are not cracked, which would put the vehicle out of service","So you can keep your boots clean and avoid tracking mud onto the cab floor and pedals"],"answer":0,"explanation":"Secure, intact steps and handholds let you get in and out of the cab safely, keeping three points of contact when surfaces are slippery.","handbook":"Steps and handholds must be secure for safe entry and exit.","hbref":"§2.1","qid":"GK-W3-373"},"488":{"q":"It is the start of your shift and you are completing your pre-trip inspection. A DOT officer could stop you at a roadside check at any point on today's route and ask to see your vehicle registration and proof of insurance. To stay compliant and ready for that inspection, where should these documents be at this moment?","options":["Filed in a cabinet at your home or terminal office so they cannot be lost or stolen on the road","Inside the vehicle with you, so you can produce them for any officer during a roadside inspection","Mailed in to the Texas DPS so the state keeps the official copy on record for you","Uploaded to an online state portal, since a digital record replaces the need to carry paper copies"],"answer":1,"explanation":"Keep your registration and proof of insurance inside the vehicle so you can present them to an officer during any roadside inspection or stop.","handbook":"Keep registration and proof of insurance in the vehicle.","hbref":"§1.2","qid":"GK-W3-374"},"489":{"q":"You are approaching a rural intersection at night in your loaded combination vehicle when you see the traffic signal overhead is flashing red in your direction, with cross traffic facing a flashing yellow. Given how these signals legally differ, what is the correct action for you to take?","options":["Slow down and proceed through cautiously without stopping, since a flashing signal only warns you to be alert","Maintain your speed but be ready to yield, because the cross traffic facing flashing yellow must stop for you","Come to a complete stop as you would at a stop sign, then proceed only when the intersection is clear","Treat it as a stuck signal, stop briefly, then proceed before the light changes to solid red"],"answer":2,"explanation":"A flashing red signal means the same as a stop sign: stop completely, yield, and proceed only when the intersection is clear.","handbook":"A flashing red light means stop, then proceed when clear.","hbref":"§2.4","qid":"GK-W3-375"},"490":{"q":"You are approaching a busy intersection at night when the overhead traffic signal switches to a steady flashing yellow facing your lane, while the cross-street faces a flashing red. Several cars are waiting on the cross-street to enter. What is the correct way to proceed through this intersection?","options":["Treat the flashing yellow exactly like a steady red: come to a complete stop, then proceed when the intersection is clear","Maintain your highway speed because the flashing yellow gives you the absolute right-of-way and the cross-traffic must remain stopped","Stop, wait for the cross-street drivers to clear first because their flashing red works like a four-way stop that yields to them","Reduce your speed and proceed through the intersection with caution, staying alert for the cross-traffic that is stopped at the flashing red"],"answer":3,"explanation":"A flashing yellow signal is a caution signal, not a stop: slow down and proceed through the intersection carefully.","handbook":"A flashing yellow light means slow down and proceed with caution.","hbref":"§2.4","qid":"GK-W3-376"},"491":{"q":"You are approaching a busy intersection in your loaded combination vehicle when you notice the traffic signal facing you is completely dark, with no lights illuminated at all due to an apparent power outage. Cross traffic is also slowing. To proceed both legally and safely, how should you treat this intersection?","options":["As a four-way stop: come to a complete stop, then proceed in turn based on the order vehicles arrived, yielding to those who got there first","As a yield: slow down and only stop if another vehicle is already in the intersection, otherwise roll through","As a green light for the through street, since the larger commercial vehicle has the right of way over cross traffic","As a free pass: maintain your speed through the intersection because a dark signal is not a controlled intersection"],"answer":0,"explanation":"A dark or malfunctioning traffic signal must be treated as a four-way stop, with vehicles proceeding in order of arrival.","handbook":"Treat a dark traffic signal as a four-way stop.","hbref":"§2.4","qid":"GK-W3-377"},"492":{"q":"You are hauling a loaded trailer on a two-lane highway behind a slow farm tractor. The center of the road is marked with a double solid yellow line. You are losing time and would like to get around the tractor. Based on this pavement marking, which of the following is the correct action?","options":["You may cross the line to pass because the lane on your side is the faster lane","You must not pass, because a double solid yellow center line prohibits passing for both directions of travel","You may pass as long as no oncoming traffic is visible within 500 feet","The marking only restricts parking, so passing is permitted when the road is clear"],"answer":1,"explanation":"A double solid yellow center line prohibits passing for traffic in both directions, so you must not cross it to pass.","handbook":"A double solid yellow line means no passing.","hbref":"§2.4","qid":"GK-W3-378"},"493":{"q":"You are driving on a multilane Texas highway in moderate traffic when the lane markings change: the broken white line between your lane and the lane to your right becomes a single SOLID white line that continues for a long stretch. Traffic in your lane is moving a little slower than the lane beside you. What does this solid white line communicate, and how should you respond?","options":["It marks the edge of the roadway, so you should ease toward the shoulder to let faster traffic pass on your left","It is the same as a broken line, so you may move right whenever a gap appears to keep pace with the faster lane","It discourages crossing, so you should stay in your lane and only change lanes if it is truly necessary and safe to do so","It means passing is prohibited for everyone, so you must hold your exact position and may not change lanes under any circumstances"],"answer":2,"explanation":"A single solid white line separates lanes going the same direction and discourages lane changes, so cross only when necessary and safe.","handbook":"A solid white line means stay in your lane.","hbref":"§2.4","qid":"GK-W3-379"},"494":{"q":"You are driving your tractor-trailer on a two-lane undivided road in daylight when the school bus ahead of you activates its alternately flashing RED lights and extends its stop arm. You are following at a legal distance and traffic behind you is light. What are you required to do?","options":["Slow to about 15 mph, cover your brake, and ease past the bus only on its left side since you are on an undivided road","Keep rolling at a reduced creep speed while watching for children, because a full stop is required only when the bus shows yellow (amber) warning lights","Pull onto the shoulder, set out your reflective triangles, and wait for the bus driver to wave you forward","Come to a complete stop and remain stopped until the red lights stop flashing and the stop arm is withdrawn"],"answer":3,"explanation":"Flashing red lights with the stop arm extended mean traffic both directions on an undivided road must stop until the lights stop and the arm retracts.","handbook":"Stop for a school bus that has its red lights flashing.","hbref":"§2.4","qid":"GK-W3-380"},"495":{"q":"You are approaching a steel-plated road repair section and a metal-grated bridge deck on your route. Conditions have changed several times today. Under which of the following situations should you expect these metal surfaces to give you the LEAST traction and behave most like ice?","options":["A light rain has just begun and the steel plates and bridge grating are wet","The pavement and metal surfaces are completely dry under bright afternoon sun","The steel plates were installed only yesterday and still look brand new","A maintenance crew has just finished sweeping loose gravel and dust off the plates"],"answer":0,"explanation":"Steel plates and metal bridge decks offer little traction and become as slippery as ice when wet.","handbook":"Metal road surfaces are most slippery when wet.","hbref":"§2.11","qid":"GK-W3-381"},"496":{"q":"You exit a divided highway and turn onto a downtown commercial street at midday. Traffic is dense, parked cars line both curbs, delivery vans are double-parked, and you pass a bus stop and several storefronts. Compared with the open highway you just left, which hazard should now command the GREATEST share of your attention?","options":["Long, empty straightaways where you could safely increase your following distance","Pedestrians who may step out suddenly from between parked cars, buses, or storefronts","Wide-open fields beside the road that give you extra room to recover from a skid","Loose gravel and debris typical of rural shoulders far from this area"],"answer":1,"explanation":"In the city, watch closely for pedestrians who can step out suddenly from between parked cars, buses, or storefronts.","handbook":"In cities, watch carefully for pedestrians.","hbref":"§2.8","qid":"GK-W3-382"},"497":{"q":"It is mid-morning and you are driving a loaded combination vehicle on a narrow two-lane rural highway through farm country. The posted speed is 55 mph, but you crest a small rise and your vision opens up to roughly a quarter mile ahead. Of the following hazards, which one are you MOST likely to encounter moving far below the posted speed and forcing you to adjust your following distance and possibly change lanes to pass?","options":["A city transit bus stopping at marked passenger shelters","Light passenger cars merging from a freeway on-ramp","Slow-moving farm equipment such as a tractor or combine","A commuter subway train running parallel to the road"],"answer":2,"explanation":"On rural two-lane highways, watch for slow-moving farm equipment like tractors and combines traveling well below the posted speed.","handbook":"On rural roads, watch for slow farm equipment.","hbref":"§2.8","qid":"GK-W3-383"},"498":{"q":"You are stopped at the front of an intersection in your loaded combination vehicle, waiting to make a left turn across two lanes of oncoming traffic. The solid red arrow that was holding you switches to a steadily FLASHING yellow left-turn arrow. Oncoming vehicles are still approaching the intersection at speed. Which response is legally correct and safest for a driver of your size and length?","options":["Begin your turn immediately, because a flashing yellow arrow functions exactly like a green arrow and gives you a protected, right-of-way turn","Remain fully stopped and treat the flashing yellow arrow like a steady red arrow, waiting for a solid green arrow before you move","Proceed into the turn but plan to stop and hold in the middle of the intersection until the oncoming gap is clear","You may proceed into the turn, but you must yield to the oncoming traffic and complete the turn only when there is a gap large enough for your full length to clear safely"],"answer":3,"explanation":"A flashing yellow arrow permits the turn but does not give right-of-way, so yield to oncoming traffic and turn only when the gap is large enough to clear safely.","handbook":"A flashing yellow arrow means turn with caution and yield.","hbref":"§2.4","qid":"GK-W3-384"},"499":{"q":"You are forced to stop on the shoulder after a fitting fails and diesel begins pooling on the pavement around the rear of your trailer. You still have to mark your stopped rig for approaching traffic. Considering the fuel on the ground, which warning device is the safest choice to set out?","options":["A reflective triangle, because it warns traffic without any flame or heat that could ignite the spilled fuel","A lit flare, because flares are the most visible standard warning device and are required equipment on your truck","A burning signal flare placed upwind of the spill so the flame stays clear of the diesel vapors","A small lit candle set on the pavement, since its flame is too low to reach the fuel"],"answer":0,"explanation":"A reflective triangle produces no flame, spark, or heat, so it warns traffic safely without risking ignition of spilled fuel.","handbook":"Use reflective triangles, not flares, near flammable spills.","hbref":"§2.14","qid":"GK-W3-385"}};
  var APPEND=[{"idx":500,"obj":{"q":"During your pre-trip inspection you find the front steering tires worn unevenly. At the shallowest point the tread measures about 3/32 inch. What is the correct decision?","options":["Do not drive — steering-axle tires must have at least 4/32 inch of tread","Drive — 3/32 inch still clears the 2/32 inch minimum that applies to tires","Drive — uneven wear only matters on the drive and trailer tires","Do not drive — any tire below 6/32 inch is illegal on a commercial vehicle"],"answer":0,"explanation":"Steering-axle tires must have at least 4/32 inch of tread — a higher standard than the 2/32 inch required on all other tires.","handbook":"","hbref":"","qid":"GK-PR-001"}},{"idx":501,"obj":{"q":"You completed a full pre-trip, secured your load, and have now driven 45 miles on the interstate with everything feeling fine. Under the cargo inspection rules, what are you required to do?","options":["Nothing yet — the first required cargo re-check is at 150 miles or 3 hours","Nothing — once secured and pre-tripped, cargo need not be checked again until you fuel up","Stop within the next few miles — the first cargo re-check is required within the first 50 miles","Stop now — cargo must be re-inspected every 25 miles"],"answer":2,"explanation":"The first re-check of cargo and securing devices is required within the first 50 miles, because tie-downs settle and loads shift most early on.","handbook":"","hbref":"","qid":"GK-PR-002"}},{"idx":502,"obj":{"q":"While checking the steering, you find the wheel turns more than 10 degrees (about two inches of play at the rim of a 20-inch wheel) before the front tires begin to move. What does this mean?","options":["Normal free play that every heavy truck has — no action needed","Excessive steering play — the vehicle is unsafe to drive until it is repaired","The power steering is just warming up; it will tighten once you drive","A minor item you may note on the post-trip report and keep driving"],"answer":1,"explanation":"More than about 10 degrees of steering free play makes the vehicle hard to control and unsafe to drive until it is repaired.","handbook":"","hbref":"","qid":"GK-PR-003"}},{"idx":503,"obj":{"q":"At the end of your shift you discover a brake-adjustment problem. Regarding the Driver Vehicle Inspection Report (DVIR), which statement is correct?","options":["A DVIR is only required before a trip, never after one","A post-trip report is optional whenever you did a pre-trip that same morning","You may report the defect verbally only; no written record is needed","You must record the defect on a written post-trip report so it is repaired before the vehicle is used again"],"answer":3,"explanation":"Defects found during the trip must be recorded on a written post-trip inspection report so they are repaired before the vehicle is used again.","handbook":"","hbref":"","qid":"GK-PR-004"}},{"idx":504,"obj":{"q":"It is just below freezing. The pavement looks wet and shiny, yet you notice the tire spray you would normally see from vehicles ahead has stopped. What is the safest interpretation and action?","options":["Black ice is likely forming — reduce speed and avoid any sudden steering or braking","The road is simply wet from earlier rain — maintain your current speed","Your own tires are losing air — pull over to check their pressure","It is only windshield frost — turn on the defroster and keep going"],"answer":0,"explanation":"A wet, glossy road with no tire spray near freezing temperatures signals black ice, so reduce speed and avoid sudden steering or braking.","handbook":"","hbref":"","qid":"GK-SS-005"}},{"idx":505,"obj":{"q":"Your vehicle begins to hydroplane on a flooded stretch of highway. You should do all of the following EXCEPT:","options":["Ease off the accelerator to let the wheels slow down","Push in the clutch so the wheels can turn freely","Apply the brakes firmly to force the tires back onto the road","Keep the steering wheel straight until you feel traction return"],"answer":2,"explanation":"During a hydroplane never brake hard, as it locks the tires and worsens the slide; instead ease off the throttle and hold the wheel straight until grip returns.","handbook":"","hbref":"","qid":"GK-SS-006"}},{"idx":506,"obj":{"q":"You are driving a 60-foot combination at 60 mph on a dry road in good conditions. Using the Texas following-distance rule, the minimum gap you should keep is closest to:","options":["About 6 seconds","About 7 seconds","About 4 seconds","About 10 seconds"],"answer":1,"explanation":"Allow one second per 10 feet of length below 40 mph plus one extra second above 40 mph, so a 60-foot rig needs about 7 seconds of following distance.","handbook":"","hbref":"","qid":"GK-SS-007"}},{"idx":507,"obj":{"q":"It begins to rain hard after several dry weeks. Why is the first part of this rainfall especially dangerous, and how should you respond?","options":["The rain cools the engine, so you can safely travel a little faster","The only real hazard is the windshield — run the wipers and keep your speed","Fresh rain improves traction right away; only deep standing water is a concern","Oil and dust on the road rise into a slick film before being washed away — slow down and increase following distance"],"answer":3,"explanation":"When rain first begins, oil and dust float up into a slick film that makes the road most slippery, so slow down and increase following distance.","handbook":"","hbref":"","qid":"GK-SS-008"}},{"idx":508,"obj":{"q":"Driving at night on an unlit highway with low beams, you realize you cannot stop within the distance your headlights light up. The correct response is to:","options":["Slow down so that you can stop within the distance you can see ahead","Switch to high beams and hold your speed so you stay on schedule","Move in close behind another truck and drive by its lights","Keep your speed but watch the right edge line more closely"],"answer":0,"explanation":"Never overdrive your headlights — your speed must let you stop within the distance you can actually see ahead, which means slowing down on low beams.","handbook":"","hbref":"","qid":"GK-WX-009"}},{"idx":509,"obj":{"q":"You are about to enter a bank of dense fog. Which of the following is NOT a recommended practice?","options":["Slow down before you actually reach the fog","Use your low beams rather than high beams","Use your wipers and defroster to keep the windshield clear","Switch on your high beams so the brighter light cuts through the fog"],"answer":3,"explanation":"Use low beams in fog because high beams reflect off the water droplets and bounce glare back at you, reducing what you can see.","handbook":"","hbref":"","qid":"GK-WX-010"}},{"idx":510,"obj":{"q":"The air temperature is right at freezing and the roads look mostly clear. Which surface should you treat as icy first, even when the rest of the road seems fine?","options":["Straight, open stretches that sit in full sun","Uphill grades, because the engine warms the surface","Tunnels, which trap warm air and stay slick the longest","Bridges and overpasses, which freeze before the surrounding road"],"answer":3,"explanation":"Bridges and overpasses lose heat from above and below, so they ice over before the road on solid ground even when the rest of the pavement is still clear.","handbook":"","hbref":"","qid":"GK-WX-011"}},{"idx":511,"obj":{"q":"On a very hot day you stop and find your tires noticeably hot, reading higher than the normal cold pressure. What is the correct action?","options":["Bleed air out until the pressure returns to the normal cold setting","Drive faster so the airflow cools the tires","Pour water over the tires to cool them down quickly","Leave the tires alone; if one is too hot to touch, stop driving until it cools"],"answer":3,"explanation":"Heat normally raises tire pressure, so leave the tires alone; but a tire too hot to touch signals a problem, so stop driving until it cools to avoid a blowout.","handbook":"","hbref":"","qid":"GK-WX-012"}},{"idx":512,"obj":{"q":"You are crossing a railroad track with a manual transmission and a heavy load. The single most important rule about gear selection at the crossing is:","options":["Pick a gear before the tracks and do not change gears while any part of the vehicle is on the crossing","Downshift about halfway across to keep enough engine power","Shift into neutral and coast across to reduce vibration","Use the highest gear available to clear the tracks as fast as possible"],"answer":0,"explanation":"Choose a gear that will pull you all the way across before reaching the tracks and never shift while any part of the vehicle is on the crossing, so you do not stall on the rails.","handbook":"","hbref":"","qid":"GK-RM-013"}},{"idx":513,"obj":{"q":"You are approaching a long, steep downgrade. When and how should you choose your gear?","options":["Wait until the brakes begin to fade, then downshift to a lower gear","Shift to neutral to save fuel and control your speed with the brakes alone","Stay in a high gear and ride the brakes lightly the whole way down","Select a low gear before you start down — usually lower than the gear you would use to climb the same hill"],"answer":3,"explanation":"Select your low gear before the descent so engine and compression braking hold your speed; on modern trucks the safe descent gear is often lower than the climbing gear.","handbook":"","hbref":"","qid":"GK-RM-014"}},{"idx":514,"obj":{"q":"On a long downgrade you are already in the correct low gear and your safe speed is 35 mph. Which braking technique correctly controls your speed?","options":["Apply light, steady brake pressure continuously all the way down","Pump the brakes rapidly and constantly to keep them cool","Hold the brakes hard the entire way to the bottom","When you reach about 40 mph, brake firmly down to about 30 mph, release, and repeat"],"answer":3,"explanation":"Proper snub braking means letting speed rise about 5 mph over your safe speed, then braking firmly down to about 5 mph below it, releasing, and repeating so the brakes cool.","handbook":"","hbref":"","qid":"GK-RM-015"}},{"idx":515,"obj":{"q":"Your brakes have faded badly on a mountain downgrade and you are picking up speed. You should do all of the following EXCEPT:","options":["Look for and use an escape ramp if one is available","Shift into neutral so the truck can coast down more smoothly","If there is no ramp, look for an escape route such as an open field or side road","Stay in the lowest gear and use any braking you have left to slow as much as possible"],"answer":1,"explanation":"Never shift into neutral on a downgrade because it removes engine braking and lets you speed up; keep the vehicle in a low gear instead.","handbook":"","hbref":"","qid":"GK-RM-016"}},{"idx":516,"obj":{"q":"Your drive wheels start to skid on a slick road and the rear of your tractor begins sliding to the right. To regain control you should first:","options":["Stop accelerating (and push in the clutch), then steer the way you want the front of the vehicle to go","Brake hard to stop the slide right away","Steer sharply to the left, opposite the direction of the slide","Accelerate to pull the trailer back into line"],"answer":0,"explanation":"In a drive-wheel skid, first remove the cause by getting off the accelerator and pushing in the clutch so the wheels regain grip, then steer where you want the front to go.","handbook":"","hbref":"","qid":"GK-EM-017"}},{"idx":517,"obj":{"q":"On a sharp curve your front wheels lose traction and the truck keeps going straight even though the wheels are turned. The usual cause and correct response are:","options":["Cause: too little speed — accelerate to restore steering","Cause: over-inflated rear tires — pull over and let some air out","Cause: driving too fast for conditions — ease off, and the front wheels will grip again as you slow","Cause: the trailer pushing — apply the trailer hand valve hard"],"answer":2,"explanation":"A front-wheel skid is usually caused by driving too fast for conditions, and since steering does nothing you must ease off so the front tires can grip again as you slow.","handbook":"","hbref":"","qid":"GK-EM-018"}},{"idx":518,"obj":{"q":"A car suddenly stops in your lane and you do not have room to stop in time. In most cases the safer emergency action is to:","options":["Brake as hard as you can and hope to stop just short of it","Steer around the obstacle — you can usually turn to miss it in less distance than it takes to stop","Lock the brakes and hold the wheel rigidly straight","Brake hard and steer at the same time for maximum effect"],"answer":1,"explanation":"At highway speed you can usually change direction in less distance than it takes to stop, so steering around a hazard and then countersteering back often avoids a crash when stopping cannot.","handbook":"","hbref":"","qid":"GK-EM-019"}},{"idx":519,"obj":{"q":"At highway speed you hear a loud bang, the steering suddenly pulls hard to one side, and the vehicle thumps — signs of a front-tire blowout. Your immediate response should be to:","options":["Brake firmly right away to slow down before you lose control","Briefly accelerate to regain stability, then brake","Steer quickly onto the shoulder while braking hard","Hold the steering wheel firmly, stay off the brake, and let the vehicle slow before you ease off the road"],"answer":3,"explanation":"After a blowout, hold the steering wheel firmly and stay off the brake, letting the vehicle slow on its own before braking gently and easing onto the shoulder.","handbook":"","hbref":"","qid":"GK-EM-020"}},{"idx":520,"obj":{"q":"You are hauling a single 9-foot steel pipe. Using the cargo securement rules, the minimum number of tie-downs required is:","options":["Two — at least two tie-downs are required no matter how short the cargo is","One — it is under 10 feet, so one tie-down meets the one-per-10-feet rule","None — cargo shorter than 10 feet is exempt from tie-down rules","Four — one tie-down for each corner of the load"],"answer":0,"explanation":"At least two tie-downs are always required for any piece of cargo, no matter how short, plus one tie-down for every 10 feet of length.","handbook":"","hbref":"","qid":"GK-CG-021"}},{"idx":521,"obj":{"q":"Your cargo weighs 40,000 pounds. The combined working load limit (WLL) of all the tie-downs you use must be at least:","options":["10,000 pounds","20,000 pounds","40,000 pounds","80,000 pounds"],"answer":1,"explanation":"The combined working load limit of your tie-downs must equal at least one-half the weight of the cargo being secured.","handbook":"","hbref":"","qid":"GK-CG-022"}},{"idx":522,"obj":{"q":"You can place a heavy load either low and spread across the trailer floor, or stacked high and centered. Which is correct, and why?","options":["Stack it high and centered to keep weight off the edges of the axles","Stack it high so the load shifts less in turns","It makes no difference as long as the total weight is within legal limits","Load it low and spread out to keep the center of gravity low and reduce rollover risk"],"answer":3,"explanation":"Keeping the load low and evenly spread lowers the center of gravity, which is the biggest factor in resisting rollover and staying stable.","handbook":"","hbref":"","qid":"GK-CG-023"}},{"idx":523,"obj":{"q":"Poor weight distribution can cause problems at both extremes. Which statement about weight and vehicle control is correct?","options":["Overloading the drive axle always improves traction with no downside","Weight distribution affects only fuel economy, not how the vehicle handles","Too little weight on the steering axle can make the front tires lose grip and weaken your steering control","A heavier axle load always shortens your stopping distance"],"answer":2,"explanation":"Too little weight on the steering axle reduces front-tire grip and weakens steering control, so proper balance matters as much as total weight.","handbook":"","hbref":"","qid":"GK-CG-024"}}];
  var TR={"ru":{"0":{"q":"Во время предрейсового осмотра вы измеряете глубину протектора и обнаруживаете, что одна из шин управляемой (передней) оси износилась до 3/32 дюйма, при этом ведущие и прицепные шины тоже все на уровне 3/32 дюйма. Какое утверждение правильно определяет, разрешено ли эксплуатировать ваше транспортное средство?","options":["Транспортное средство НЕЛЬЗЯ эксплуатировать, потому что шины управляемой оси должны иметь не менее 4/32 дюйма протектора.","Транспортное средство можно эксплуатировать, потому что все шины соответствуют минимуму 2/32 дюйма для каждой шины.","Транспортное средство можно эксплуатировать, потому что передним шинам нужно только 2/32 дюйма, а остальные в порядке.","Транспортное средство НЕЛЬЗЯ эксплуатировать, потому что все шины на каждой оси должны иметь не менее 4/32 дюйма протектора."],"explanation":"Шины управляемой оси должны иметь глубину протектора не менее 4/32 дюйма, поэтому передняя шина с 3/32 дюйма ниже нормы и делает машину непригодной к эксплуатации."},"1":{"q":"Во время предрейсового осмотра вы проверяете глубину протектора измерителем на всех шинах. Шины передней управляемой оси показывают хорошие 5/32 дюйма, но одна из задних ведущих шин изношена заметно сильнее. Какова НАИМЕНЬШАЯ глубина протектора, при которой эта задняя (не управляемая) шина ещё законно проходит осмотр?","options":["1/32 дюйма","2/32 дюйма","4/32 дюйма","6/32 дюйма"],"explanation":"Все шины, кроме передней управляемой оси, должны иметь глубину протектора не менее 2/32 дюйма, измеренную в основной канавке."},"2":{"q":"Во время предрейсового осмотра вы беретесь за рулевое колесо и покачиваете его из стороны в сторону до запуска двигателя. На колесе диаметром 20 дюймов вы можете повернуть обод на пару дюймов в каждую сторону, прежде чем передние колеса начнут реагировать. При каком свободном ходе руля следует заподозрить неисправность рулевого управления и снять машину с эксплуатации?","options":["Когда колесо можно повернуть более чем примерно на 10 градусов (около 2 дюймов на 20-дюймовом колесе), прежде чем передние колеса сдвинутся","Только когда колесо можно повернуть более чем примерно на 20 градусов, прежде чем передние колеса сдвинутся","Когда колесо можно повернуть более чем примерно на 5 градусов, так как любой заметный люфт опасен","Только когда свободный ход превышает примерно 45 градусов, так как именно тогда рулем действительно трудно управлять"],"explanation":"Свободный ход рулевого колеса более примерно 10 градусов (около 2 дюймов на 20-дюймовом колесе) до начала поворота передних колёс недопустим и указывает на неисправность рулевого управления."},"3":{"q":"Ваш тягач с прицепом заглох на обочине двухполосного шоссе без разделительной полосы и не заводится снова. Вы включаете аварийную сигнализацию и берёте аварийный комплект, чтобы выставить светоотражающие треугольники в 100 футах позади, в 100 футах впереди и в 10 футах сзади машины. Чтобы по закону иметь возможность установить предупреждающие устройства во ВСЕХ требуемых местах, как здесь, каково МИНИМАЛЬНОЕ количество светоотражающих треугольников, которое должно быть в вашем грузовике?","options":["Два треугольника, поскольку один ставится впереди, а другой позади машины","Три треугольника","Один треугольник в 10 футах сзади плюс ваша аварийная сигнализация","Шесть треугольников, чтобы наверняка перекрыть оба направления движения"],"explanation":"Коммерческое транспортное средство должно иметь не менее трёх светоотражающих аварийных треугольников в качестве знаков аварийной остановки."},"4":{"q":"Середина вашей смены: фитинг на дизельной топливной магистрали подтекает рядом с проводкой двигателя. Внезапно там вспыхивает небольшой пожар, который питается вытекающим дизельным топливом и потрескивает вокруг находящейся под напряжением электропроводки. Вы хватаете огнетушитель, закрепленный в кабине. Какая маркировка на огнетушителе говорит о том, что он рассчитан на тушение И этого горящего топлива, И электрического пожара под напряжением?","options":["Огнетушитель класса B:C, предназначенный для тушения горючих жидкостей и электрооборудования","Огнетушитель класса A, так как это стандартная маркировка, которую возят на коммерческом транспорте","Водяной огнетушитель, чтобы быстро охладить дизельное топливо и сбить пламя","Маркировка не имеет значения, главное направить струю на основание пламени"],"explanation":"Горящая горючая жидкость — пожар класса B, а оборудование под напряжением — класса C, поэтому нужен огнетушитель с маркировкой B:C для обоих случаев."},"5":{"q":"Сейчас 5:00 утра, и вы заканчиваете предрейсовый осмотр тягача с прицепом, который вам только что назначили. Диспетчер торопит вас с выездом, но вы помните, что федеральные правила требуют возить определённое аварийное оборудование перед любым рейсом. Вы НЕ нашли в кабине комплекта запасных электрических предохранителей. При каком условии вам разрешено выехать БЕЗ запасных предохранителей?","options":["Только если грузовик оснащён автоматическими выключателями (прерывателями цепи) вместо предохранителей","Только если в кабине есть полностью заряженный запасной аккумулятор","Только если на прицепе установлены светодиодные габаритные и контурные огни","Только если на тягаче есть резервный (второй) генератор для электросистемы"],"explanation":"Запасные предохранители не требуются, если электросистема защищена автоматическими выключателями, так как они сбрасываются, а не требуют замены."},"6":{"q":"Раннее утро, вы подходите к своему тягачу, чтобы начать предрейсовый осмотр. Инструктор напоминает вам соблюдать порядок семишагового метода осмотра. Прежде чем забраться в кабину, открыть капот или коснуться хотя бы одного переключателя, что метод требует сделать ПЕРВЫМ?","options":["Запустить двигатель и дать ему прогреться, наблюдая за давлением масла и показаниями воздушных манометров","Подойти спереди и проверить, что фары, указатели поворота и аварийная сигнализация работают","Выполнить общий обзор транспортного средства: изучить предыдущий отчёт об осмотре и оценить общее состояние машины и обстановку вокруг неё","Залезть под переднюю часть машины и убедиться, что шины управляемой оси имеют протектор не менее 4/32 дюйма"],"explanation":"Первый шаг семиэтапного осмотра — общий обзор: проверить предыдущий отчёт об осмотре и оценить общее состояние грузовика и окружающую обстановку."},"7":{"q":"Холодное утро, и вы собираетесь начать предрейсовый осмотр. Двигатель вашего грузовика ВЫКЛЮЧЕН, капот поднят. Какую из перечисленных групп элементов вы можете и должны проверять ПРЯМО СЕЙЧАС, пока двигатель не работает?","options":["Свободный ход рулевого колеса и работу зуммера предупреждения о низком давлении воздуха","Уровень моторного масла, уровень охлаждающей жидкости и состояние приводных ремней","Давление включения и выключения регулятора воздушного компрессора","Выходную мощность генератора и показания зарядного прибора под нагрузкой"],"explanation":"При выключенном двигателе нужно открыть капот и проверить уровень масла, уровень охлаждающей жидкости и состояние приводных ремней."},"8":{"q":"Чуть ниже нуля, и на въезде на автомагистраль образовалась тонкая ледяная корка, когда вы разгоняете свой гружёный автопоезд до скорости потока. Вы чувствуете, что ведущие колёса тягача начинают буксовать, а задняя часть кабины слегка уводит вбок. Как ПРАВИЛЬНЕЕ всего работать педалью газа, чтобы безопасно набрать скорость на этой скользкой поверхности?","options":["Добавлять газ плавно и постепенно, сразу же отпуская педаль, как только ведущие колёса начинают буксовать","Сильно нажать на газ, чтобы буксующие колёса смогли зацепиться и пробить ледяную корку","Быстро нажимать и отпускать педаль газа, чтобы прерывать подачу мощности на ведущие колёса","Держать ровный уверенный газ и дать мощности двигателя протянуть вас через скользкий участок"],"explanation":"На скользкой поверхности добавляйте газ плавно и постепенно, отпуская его, как только ведущие колёса начнут буксовать, чтобы они восстановили сцепление."},"9":{"q":"Вы одни и должны задним ходом завести седельный тягач с прицепом к погрузочной платформе в узком переулке. Вы можете подъехать так, чтобы машина сдавала назад в сторону левого (водительского) борта, или в сторону правого борта, что было бы немного короче. Чтобы обеспечить максимальную безопасность, какой способ выбрать и почему?","options":["Сдавать назад вправо, потому что более короткий путь означает меньше времени маневрирования вслепую","Сдавать назад вправо, но высунуться из пассажирского окна и использовать помощника-наблюдателя, чтобы контролировать слепую зону","Обе стороны одинаково безопасны, поэтому выбирайте правую сторону, так как это более быстрый маневр","Сдавать назад в сторону водителя (влево), даже если это дольше, потому что вы можете наблюдать за задней частью прицепа через боковое окно, а не полагаться только на зеркала"],"explanation":"По возможности подавайте назад в сторону водителя (влево), чтобы видеть заднюю часть прицепа напрямую через боковое окно, а не полагаться только на зеркала."},"10":{"q":"Вы перевозите гружёный прицеп и приближаетесь к длинному крутому спуску, который заканчивается резким поворотом внизу. Сейчас коробка передач включена на высокой передаче. Когда правильно выбрать пониженную передачу, которой вы будете удерживать скорость на этом спуске и в повороте?","options":["До начала спуска и до поворота, пока вы ещё находитесь на ровной дороге","Прямо при въезде в поворот, чтобы двигатель давал максимальное торможение именно там, где это нужнее всего","На середине спуска, когда вы почувствуете, что машина разгоняется, а тормоза начинают терять эффективность","Только после выезда из поворота, чтобы ведущие колёса сохраняли полное сцепление в повороте"],"explanation":"Выбирайте нужную передачу до начала спуска или входа в поворот, пока ещё на ровной поверхности, так как при спуске переключение может оказаться невозможным."},"11":{"q":"Вы едете по сухому шоссе со скоростью 55 миль/ч, когда у машины далеко впереди лопается шина и она внезапно останавливается в вашей полосе. С момента появления опасности до полной остановки вашего грузовика он проедет примерно длину футбольного поля вместе с обеими зачётными зонами (около 419 футов). Какой набор факторов полностью составляет это общее тормозное расстояние в 419 футов?","options":["Расстояние, на котором тормоза физически замедляют грузовик после срабатывания пневмотормозов, плюс задержка, пока в системе нарастает давление воздуха","Расстояние, которое вы проезжаете, пока видите и распознаёте опасность, плюс расстояние, пока переносите ногу на педаль, плюс расстояние, которое требуется тормозам, чтобы вас остановить","Расстояние, пока вы реагируете и переносите ногу на педаль, плюс расстояние, которое требуется тормозам, чтобы вас остановить","Только расстояние, необходимое тормозам, чтобы остановить грузовик после того, как они применены"],"explanation":"Полный тормозной путь — это сумма дистанции восприятия, дистанции реакции и тормозной дистанции: заметить опасность, перенести ногу на педаль и остановка тормозами."},"12":{"q":"Вы едете порожняком по сухой, ровной автомагистрали с постоянной скоростью 55 миль/ч в хорошую погоду. Водитель впереди внезапно останавливается, и вам приходится выполнить полное экстренное торможение. С момента, когда впервые появляется опасность, до момента полной остановки грузовика — какое примерно общее расстояние по дороге вам потребуется для остановки?","options":["Около 60 футов, так как это расстояние, которое вы проезжаете, прежде чем успеваете отреагировать","Около 220 футов, примерно длина только фазы торможения","Около 320 футов, чуть больше одного поля для американского футбола","Около 420 футов, примерно длина поля для американского футбола плюс обе зачётные зоны"],"explanation":"При 55 милях в час в хороших условиях полный тормозной путь составляет около 420 футов — примерно длина футбольного поля с обеими зачётными зонами."},"13":{"q":"Обычно вы едете по сухому ровному участку шоссе со скоростью 20 миль/ч и знаете, что вашему тягачу нужна определенная тормозная дистанция, чтобы остановиться с этой скорости. Сегодня, опаздывая, вы едете по той же дороге со скоростью 40 миль/ч в тех же хороших условиях. По сравнению с тормозной дистанцией при 20 милях/ч ваша тормозная дистанция при 40 милях/ч будет примерно:","options":["В 2 раза длиннее, потому что тормозная дистанция увеличивается прямо пропорционально скорости","В 3 раза длиннее, так как нужно добавить дополнительное расстояние и на время реакции","В 4 раза длиннее, потому что тормозная дистанция растет пропорционально квадрату скорости","Примерно такой же, пока дорога сухая и ровная, а тормоза исправны"],"explanation":"Тормозной путь возрастает пропорционально квадрату скорости, поэтому удвоение скорости с 20 до 40 миль в час делает тормозной путь примерно в четыре раза длиннее."},"14":{"q":"Затяжной дождь промочил трассу, и вы видите тонкую плёнку воды на покрытии, хотя температура заметно выше нуля, снега и льда нет. Чтобы сохранить безопасный запас на увеличенный тормозной путь в таких мокрых условиях, примерно насколько следует снизить скорость по сравнению с той, с которой вы ехали бы по той же дороге в сухую погоду?","options":["Примерно на одну десятую","Примерно на одну треть","Примерно на половину","Примерно на три четверти"],"explanation":"На мокрой дороге снижайте скорость примерно на треть по сравнению с безопасной скоростью на сухой дороге, чтобы компенсировать потерю сцепления и увеличенный тормозной путь."},"15":{"q":"Вы только что выгрузили весь груз, и ваш прицеп теперь полностью пустой. Дорога сухая, и вы едете с той же скоростью по шоссе, что и всё утро при полной загрузке. По сравнению с загруженным состоянием, как следует скорректировать ожидания относительно того, как пустой автопоезд будет тормозить и управляться?","options":["Он остановится на более коротком расстоянии, потому что тормозам нужно замедлять гораздо меньший вес","Ему потребуется большее расстояние для остановки, потому что лёгкие задние оси имеют меньше сцепления, и колёса могут заблокироваться и пойти в занос","Тормозной путь будет практически таким же, поскольку он зависит от скорости, а не от загрузки","Теперь он не может пойти в занос, потому что пустой прицеп не даёт ведущим колёсам заблокироваться"],"explanation":"Пустой грузовик требует большего тормозного пути, так как лёгкие задние оси имеют меньшее сцепление, и колёса легче блокируются и идут в занос."},"16":{"q":"Вы едете со скоростью около 50 миль/ч по автомагистрали, когда начинается сильный ливень. Руль внезапно становится лёгким и 'пустым', грузовик перестаёт реагировать на небольшие повороты руля, и вы понимаете, что передние шины всплыли на плёнке воды и больше не сцепляются с дорогой. Какое действие даёт вам наилучший шанс восстановить управление?","options":["Сильно нажать на педаль тормоза, чтобы как можно быстрее сбросить скорость","Отпустить педаль газа (и выжать сцепление) и дать машине замедлиться самой, не тормозя резко","Резко повернуть руль в сторону обочины, чтобы шины зацепились за более грубое покрытие и восстановили сцепление","Сохранять или добавить газ, чтобы ведущие колёса продолжали вращаться и 'пробить' слой воды"],"explanation":"Если началось аквапланирование, отпустите газ и выжмите сцепление, не тормозя резко, чтобы шины замедлились и восстановили контакт с дорогой."},"17":{"q":"Вы спускаетесь по длинному крутому горному уклону с полностью загруженным прицепом. На вершине вы включили низкую передачу и всю дорогу вниз тормозили слегка, но почти непрерывно. На полпути вниз вы замечаете, что педаль тормоза стала мягче, а грузовик замедляется уже не так, как в начале спуска. Какова НАИБОЛЕЕ вероятная причина этой потери торможения?","options":["Тормозные колодки и барабаны перегрелись из-за слишком частого использования тормозов вместо торможения двигателем и передачей","Давление воздуха в тормозных магистралях упало слишком низко, потому что компрессор не успевает нагнетать его на спуске","Холодный горный воздух на большой высоте загустил тормозную жидкость и снизил отклик педали","Шины прицепа недостаточно накачаны, что уменьшает пятно контакта и тормозное усилие на каждом колесе"],"explanation":"Постоянное использование тормозов на длинном спуске перегревает колодки и барабаны, вызывая потерю их эффективности; вместо этого сдерживайте скорость двигателем и пониженной передачей."},"18":{"q":"Вы ведёте гружёный тягач с полуприцепом по сухому шоссе и приближаетесь к съезду под уклон с указанным ограничением скорости на повороте 35 миль/ч. Дорожное покрытие в хорошем состоянии, движение слабое. Какое утверждение лучше всего описывает, как вам следует относиться к этой указанной цифре 35 миль/ч?","options":["Это безопасная скорость для любого транспортного средства в хороших условиях, поэтому 35 миль/ч вполне допустимо для вашего гружёного тягача","Она рассчитана для легковых автомобилей в хороших условиях, поэтому вам следует входить в поворот на скорости значительно ниже 35 миль/ч","Она относится только к порожним грузовикам, поэтому гружёный грузовик может законно её превысить","Она уже включает запас безопасности для грузовиков, поэтому держать ровно 35 миль/ч — самый безопасный вариант"],"explanation":"Указанная на знаке скорость в повороте рассчитана для легковых автомобилей в хороших условиях, поэтому грузовик с более высоким центром тяжести должен входить в поворот заметно медленнее."},"19":{"q":"Вы ведёте автопоезд (тягач с прицепом) длиной 60 футов по сухому шоссе, и спидометр стабильно показывает 55 миль/ч при небольшом движении. Вы хотите выбрать безопасную дистанцию до идущего впереди автомобиля. Исходя из длины вашего транспортного средства и текущей скорости, какую минимальную дистанцию следования вам следует соблюдать?","options":["6 секунд, потому что транспортному средству длиной 60 футов нужна 1 секунда на каждые 10 футов при любой скорости","Ровно 4 секунды, как для любого тяжёлого транспортного средства независимо от длины","7 секунд, потому что транспортному средству длиной 60 футов нужно 6 секунд плюс ещё 1 секунда за движение со скоростью выше 40 миль/ч","Примерно три длины легкового автомобиля, чего ориентировочно достаточно для автопоезда"],"explanation":"Дистанция должна составлять 1 секунду на каждые 10 футов длины машины плюс 1 секунду при скорости выше 40 миль/ч, поэтому 60-футовому транспорту на 55 миль/ч нужно 7 секунд."},"20":{"q":"Вы едете со скоростью 60 миль/ч по широкому загородному шоссе с небольшим движением. Дорога впереди слегка идёт в гору, и вы хотите управлять своим пространством и заранее замечать проблемы. Чтобы правильно сканировать обстановку, на чём БОЛЬШУЮ часть времени должен быть сосредоточен ваш взгляд при такой скорости?","options":["На покрытии сразу за передней частью капота, чтобы мгновенно замечать препятствия на дороге","Примерно на 4–6 секунд вперёд — то же расстояние, что вы используете для безопасной дистанции следования","Примерно на 12–15 секунд вперёд, что на скорости шоссе составляет около четверти мили","Примерно на 30 секунд вперёд, настолько далеко по дороге, насколько вообще достаёт ваш взгляд"],"explanation":"Опытные водители смотрят на 12–15 секунд вперёд, что на шоссе составляет примерно четверть мили."},"21":{"q":"Вы приближаетесь к правому повороту в узкий переулок на оживленной городской улице. Движение плотное, справа в велосипедной полосе едет велосипедист, а сзади вплотную скопилось несколько машин. Как правильнее всего поступить с указателем поворота?","options":["Подождать, пока вы реально начнете выкручивать руль, и только тогда включить сигнал, чтобы едущие сзади не притормаживали слишком рано и не создавали затор","Включить сигнал лишь на короткое время, ведь в плотном потоке окружающие водители и так видят ваши стоп-сигналы, которые все сообщают за вас","Включить указатель поворота заблаговременно, задолго до поворота, и держать его мигающим непрерывно в течение всего маневра","Не пользоваться электрическим сигналом, а подать сигнал рукой, так как он заметнее для велосипедиста рядом с вами"],"explanation":"Включайте сигнал заблаговременно перед поворотом и держите его до конца манёвра, чтобы другие успели среагировать и не подумали, что вы передумали."},"23":{"q":"Вы управляете тягачом с прицепом длиной 70 футов и должны повернуть направо на узкую боковую улицу. Движение слабое, и вы опасаетесь, что задние колёса прицепа наедут на бордюр. Чтобы выполнить этот поворот безопасно и по правилам, чего из перечисленного вам делать НЕ следует?","options":["Сместиться влево в соседнюю полосу перед поворотом, чтобы у прицепа было больше места для разворота","Начать поворот медленно и постоянно следить в зеркала за траекторией прицепа","Держать заднюю часть машины близко к бордюру, чтобы другие водители не смогли проскочить справа","Выезжать на широкую дугу только при завершении поворота, после того как кабина прошла угол"],"explanation":"Смещение влево перед правым поворотом открывает справа промежуток, в который другие машины пытаются обогнать, и они попадают под траекторию заноса прицепа."},"24":{"q":"Вы перевозите пустой сухогрузный фургон, и на вашем маршруте есть путепровод с указанной высотой проезда 13 футов 6 дюймов. Заявленная высота вашего прицепа -- 13 футов 4 дюйма, то есть запас составляет 2 дюйма. Этой зимой дорожная бригада заново заасфальтировала этот участок, а прошлой ночью выпал лёгкий снег, который укатали на проезжей части. Как наиболее обоснованно отнестись к указанному на знаке габариту, прежде чем решиться проехать под путепроводом?","options":["Знак установлен официально, поэтому значение 13 футов 6 дюймов является точным, и запаса в 2 дюйма юридически достаточно, чтобы проехать.","Поскольку знаки высоты рассчитаны на гружёные машины, пустой фургон стоит ниже заявленной высоты, так что у вас есть дополнительный зазор, и можно проезжать.","Считайте указанную высоту ненадёжной: новое асфальтовое покрытие и укатанный снег уменьшают реальный габарит, а пустой фургон на самом деле едет выше, поэтому найдите другой маршрут или проверьте габарит, прежде чем ехать.","Прибавьте свой запас в 2 дюйма к указанным 13 футам 6 дюймам, получив около 13 футов 8 дюймов полезного габарита, чего более чем достаточно для прицепа."],"explanation":"Указанная высота проезда может быть неверной: новое покрытие и утрамбованный снег уменьшают реальный зазор, а пустой фургон стоит выше, поэтому проверьте или объедьте."},"25":{"q":"Вы выезжаете на оживлённую автомагистраль и смотрите в большое выпуклое (сферическое) зеркало на правой двери. Машина, которую вы видите в этом выпуклом зеркале, кажется маленькой и далеко позади, поэтому вам кажется, что места для перестроения достаточно. Прежде чем начать манёвр, что вы обязаны понимать о том, что показывает это выпуклое зеркало?","options":["Оно охватывает более широкую зону, но объекты выглядят меньше и дальше, чем на самом деле, поэтому та машина может быть ближе, чем кажется","Оно увеличивает узкий крупный план, поэтому машина на самом деле дальше, чем выглядит, и у вас есть запас места","Оно показывает изображение того же реального размера и расстояния, что и плоское зеркало, поэтому видимый промежуток точен","Оно отражает только бок вашей собственной кабины и прицепа, поэтому любой автомобиль в нём ещё не представляет опасности"],"explanation":"Выпуклые зеркала показывают более широкую зону, но объекты в них выглядят меньше и дальше, поэтому автомобиль может быть ближе, чем кажется."},"26":{"q":"Вы едете по сухому шоссе при ясной погоде и замечаете впереди на правой обочине автомобиль с поднятым капотом, рядом с задним бампером стоит человек и смотрит в сторону движения. Аварии нет, погода хорошая, поток машин нормальный. С точки зрения распознавания опасностей, как следует расценивать этот стоящий автомобиль и человека?","options":["Это опасность, потому что это любое дорожное условие или участник дорожного движения, который может превратиться в чрезвычайную ситуацию и потребовать от вас действий","Это не опасность, потому что аварии или чрезвычайной ситуации ещё не произошло, а сама проезжая часть свободна","Это не опасность, потому что опасности существуют только в плохую погоду, в туман, на льду или в других сложных условиях","Это опасность только в том случае, если стоящий автомобиль внезапно выедет обратно в вашу полосу и заставит вас резко затормозить"],"explanation":"Опасность — это любое дорожное условие или участник движения, которые могут перерасти в аварийную ситуацию; их распознают заранее, чтобы успеть среагировать."},"27":{"q":"Вы движетесь в правом ряду по четырёхполосному шоссе, когда сзади на огромной скорости подлетает легковой автомобиль, вплотную прижимается к вашему прицепу, затем резко обгоняет, подрезает вас и резко тормозит. Ваш грузовик полностью загружен, и тормозной путь и так велик. Как ЛУЧШЕ всего поступить с этим агрессивным водителем?","options":["Помигать дальним светом и посигналить, чтобы водитель отстал, и удерживать свою полосу","Перестроиться в левый ряд и обогнать водителя, чтобы оставить конфликт позади","Сохранять скорость и держаться вплотную сзади, чтобы водитель не смог снова вас подрезать","Сбросить газ, чтобы увеличить дистанцию впереди, избегать зрительного контакта и дать агрессивному водителю уехать далеко вперёд"],"explanation":"Безопасная реакция на агрессивного водителя — отпустить педаль газа, чтобы создать дистанцию, избегать зрительного контакта и дать ему уехать далеко вперед."},"29":{"q":"Тёмная безлунная ночь на сельском двухполосном шоссе, вы едете на ближнем свете, который освещает дорогу примерно на 250 футов вперёд. Встречного движения нет. Чтобы не «обгонять свет своих фар», что является единственным самым важным действием?","options":["Включить дальний свет и держать постоянные 55 миль/ч, ведь дальний свет достаёт примерно на 350 футов, и этого расстояния хватит для реакции","Подъехать ближе к задним фонарям идущей впереди машины и использовать её свет, чтобы видеть дальше по дороге","Сохранять обычную дневную скорость, потому что фары чётко освещают разметку и дорогу впереди","Ехать достаточно медленно, чтобы полностью остановиться в пределах того расстояния, которое реально освещают ваши фары"],"explanation":"Никогда не превышайте скорость, на которой вас «обгоняют» фары: двигайтесь настолько медленно, чтобы полностью остановиться в пределах освещенного фарами участка."},"30":{"q":"Только что стемнело, вы едете по двухполосной дороге без разделительной полосы, и навстречу приближается вереница автомобилей с включёнными фарами. Один из водителей не переключает дальний свет на ближний, и слепящий свет мешает вам видеть дорогу впереди. Куда следует направить взгляд, чтобы глаза оставались адаптированными и вы безопасно держались своей полосы, пока машины не проедут?","options":["На правый край своей полосы, ориентируясь по разметке или линии на дороге, пока встречные машины не проедут","Прямо на фары встречных машин, чтобы оценить расстояние между вами и ними","Вниз на приборную панель, чтобы дать глазам отдохнуть от яркого света","Далеко вперёд на дорогу за встречным транспортом, чтобы скорость соответствовала дальности света ваших фар"],"explanation":"Если вас слепит дальний свет встречных машин, смотрите на правый край своей полосы и следите за разметкой, чтобы глаза оставались привыкшими к темноте."},"31":{"q":"Вы выполняете доставку перед рассветом, когда наползает плотная полоса тумана и видимость падает до меньшей, чем длина вашего тягача с прицепом. Вы решаете, что безопаснее медленно двигаться до ближайшего съезда, а не останавливаться на полосе движения. Чтобы видеть дорогу и быть замеченным, НЕ ослепляя себя, какой выбор освещения и скорости является единственно лучшей практикой?","options":["Включить дальний свет для максимальной дальности и держать скорость, чтобы не мешать движению","Использовать ближний свет (и противотуманные фары при наличии) и снизить скорость так, чтобы успеть остановиться в пределах видимости","Выключить фары и включить только аварийную сигнализацию (четыре поворотника), чтобы обозначить своё положение","Оставить дальний свет включённым, но снизить скорость, поскольку в тумане дополнительный свет важнее, чем блики"],"explanation":"В тумане используйте ближний свет (и противотуманные фары при наличии) и снижайте скорость так, чтобы остановиться в пределах видимости, ведь дальний свет отражается и ухудшает обзор."},"32":{"q":"Ясное утро, около 31°F (примерно -1°C), и открытая проезжая часть впереди выглядит совершенно сухой. Вы везёте гружёный полуприцеп к длинному мосту через речную долину, а сразу за ним находится затенённая эстакада. Где вам следует ожидать потерю сцепления В ПЕРВУЮ ОЧЕРЕДЬ и снизить скорость, ещё не доехав до этого места?","options":["На сухой открытой дороге, потому что вес тягача прижимает шины и нагревает покрытие","На мосту и затенённой эстакаде, потому что воздух циркулирует над и под настилом, поэтому он остывает и замерзает раньше окружающей дороги","Пока нигде: раз покрытие выглядит сухим, оно не может обледенеть, пока температура воздуха не опустится ниже нуля","Только после эстакады, где дорожная соль и солнце уже растопили весь лёд на приподнятых конструкциях"],"explanation":"Мосты и эстакады обдуваются холодным воздухом сверху и снизу, поэтому теряют тепло со всех сторон и замерзают раньше окружающей дороги."},"33":{"q":"Ранним утром температура чуть ниже нуля. Дорога впереди выглядит тёмной и мокрой, но вы замечаете, что шины идущего впереди грузовика совсем не поднимают брызг, а на ваших зеркалах и антенне образовалась тонкая ледяная корка. Что, СКОРЕЕ ВСЕГО, происходит с дорожным покрытием и как вам следует реагировать?","options":["Покрытие просто мокрое от растаявшего инея; держите скорость, ведь стоячая вода обеспечивает нормальное сцепление.","Дорога просто подсыхает; короткое резкое нажатие на тормоз подтвердит, что сцепление в порядке, и позволит сохранить дистанцию.","Образовался тонкий прозрачный слой чёрного льда; плавно отпустите газ и избегайте любых резких поворотов руля или торможений.","Это свежий асфальтовый герметик делает поверхность похожей на мокрую; будьте аккуратны, но обычная скорость допустима."],"explanation":"Мокрый на вид асфальт без брызг из-под колёс при околонулевой температуре указывает на гололёд, поэтому плавно отпустите газ и избегайте резких манёвров и торможения."},"34":{"q":"Середина июля в Западном Техасе, температура воздуха около 105 градусов по Фаренгейту, на асфальте заметно выступает гудрон. Два часа назад вы делали остановку, и шины были в порядке, но вы только что выехали на длинный участок межштатной автомагистрали на высокой скорости. За каким состоянием вам следует следить НАИБОЛЕЕ внимательно во время этой поездки?","options":["Рост давления в шинах, который может привести к разрыву по мере нарастания жары","Звук клаксона, приглушаемый пылью и жарой","Падение давления в шинах из-за утечки холодного воздуха через клапаны","Потемнение тонировки стекол, ухудшающее обзор вперед"],"explanation":"В сильную жару воздух в шине расширяется и давление растёт, что в сочетании с нагревом может привести к разрыву шины."},"35":{"q":"Вы загружены почти до максимального полного веса автопоезда (GCWR) и готовитесь начать спуск по длинному крутому горному уклону. Дорога сухая, видимость хорошая. Поднявшись на вершину, вы обдумываете, как удержать скорость под контролем на всём спуске. Какой подход ЛУЧШЕ всего подходит для управления скоростью на этом уклоне?","options":["Оставаться на высокой передаче, чтобы двигатель работал плавно, и всю дорогу вниз постоянно держать рабочий тормоз нажатым, удерживая скорость на безопасном уровне.","Перейти в нейтраль и катиться накатом, энергично нажимая рабочий тормоз каждый раз, когда скорость растёт, чтобы тормоза успевали остыть между нажатиями.","Держать обычную дорожную передачу и сдерживать скорость на спуске с помощью стояночного (ручного) тормоза.","Выбрать низшую передачу ДО начала спуска, чтобы основную работу выполняли двигатель и торможение передачей, а рабочий тормоз использовать лишь как лёгкое, плавное дополнение."],"explanation":"На длинном крутом спуске выберите низкую передачу до начала спуска, чтобы основное торможение выполняли двигатель и передача, применяя лишь лёгкое равномерное рабочее торможение."},"36":{"q":"Вы спускаетесь с загруженным прицепом по длинному крутому горному спуску. На вершине вы включили низкую передачу и применяли лёгкое, равномерное торможение, но педаль тормоза постепенно становится мягкой, скорость продолжает расти, и вы чувствуете запах гари. Впереди справа вы видите гравийную аварийную полосу для съезда. Что из перечисленного описывает, когда вам следует свернуть на эту полосу?","options":["Когда тормоза перегрелись или отказали, и вы больше не можете контролировать скорость на спуске","Когда вы превышаете установленную для грузовиков скорость на спуске всего на несколько миль в час","Когда движение на спуске стало плотным и вам хочется больше пространства","Когда вы хотите ненадолго остановиться, чтобы дать двигателю и тормозам остыть перед продолжением пути"],"explanation":"Используйте аварийную полосу-улавливатель только тогда, когда тормоза перегрелись или отказали и вы больше не можете контролировать скорость на спуске."},"37":{"q":"Вы едете порожняком жарким летним днём на трассовой скорости, когда слышите громкий хлопок, и руль внезапно резко уводит вправо -- лопнула передняя шина. Вашим порожним тягачом теперь труднее управлять. Каково ваше ПЕРВОЕ правильное действие?","options":["Крепко держать руль, не нажимать на тормоз и дать машине замедлиться самой, а затем плавно съехать на обочину","Тормозить уверенно и плавно, чтобы сбросить скорость, прежде чем грузовик уведёт с дороги","Резко вывернуть руль в сторону, противоположную уводу, чтобы удержать грузовик по центру полосы","Выжать сцепление и перейти на пониженную передачу, чтобы тормозить двигателем"],"explanation":"После разрыва переднего колеса крепко держите руль и не нажимайте тормоз, давая машине замедлиться самостоятельно, прежде чем съехать с дороги."},"38":{"q":"Вы спускаетесь по умеренному уклону на одиночном грузовике с гидравлическими тормозами; вы нажимаете на педаль тормоза, и она медленно проваливается до пола, почти не давая торможения. Движение слабое, а примерно через милю впереди есть аварийная улавливающая полоса для грузовиков. Что следует попробовать ПЕРВЫМ, чтобы замедлить автомобиль?","options":["Немедленно заглушить двигатель, чтобы трансмиссия помогла затормозить грузовик","Резко и сильно дёрнуть стояночный тормоз одним движением, чтобы заблокировать колёса","Вытянуть кнопку подачи воздуха к прицепу (защиты тягача), чтобы включить тормоза прицепа","Быстро прокачать педаль тормоза, пытаясь восстановить гидравлическое давление"],"explanation":"Когда педаль гидравлических тормозов проваливается до пола, сначала быстро прокачайте её, чтобы восстановить давление и замедлить или остановить машину."},"39":{"q":"Вы ускоряетесь, выходя из поворота на мокрой двухполосной дороге, когда задняя часть тягача внезапно начинает заносить в сторону обочины, а ведущие колёса словно теряют сцепление с дорогой. Какой из перечисленных способов является ЛУЧШИМ для восстановления контроля при заносе ведущих колёс?","options":["Сильно нажать на педаль тормоза и удерживать её, чтобы замедлить заднюю часть и вернуть её в линию","Прекратить ускорение, выжать сцепление и рулить в том направлении, куда вы хотите ехать","Удерживать ровную подачу газа и резко выполнить контрруление, чтобы тяга двигателя выпрямила ведущие колёса","Заблокировать колёса тормозами, чтобы как можно быстрее остановить занос"],"explanation":"Чтобы устранить занос ведущих колёс при разгоне, перестаньте газовать, выжмите сцепление, чтобы отключить тягу двигателя, и поверните руль туда, куда хотите ехать."},"40":{"q":"Вы спускаетесь по длинному извилистому горному спуску с гружёным прицепом, и дорожное полотно впереди выглядит мокрым и затенённым. Вы начинаете поворот, но передняя часть грузовика продолжает двигаться прямо к внешней стороне поворота, а руль становится лёгким и не реагирует, насколько бы вы его ни поворачивали. Какова НАИБОЛЕЕ вероятная коренная причина этого заноса передних колёс?","options":["Вы слишком плавно отпустили тормоза при входе в поворот, поэтому передние шины так и не сцепились с покрытием","Слишком большая часть груза сместилась на задние оси, разгрузив управляемую (переднюю) ось","Вы едете слишком быстро для скользкого, затенённого покрытия (и/или ваши передние шины изношены или недокачаны)","Торможение двигателем на низкой передаче заблокировало ведущие колёса и сбило переднюю часть с траектории"],"explanation":"Занос передних колёс вызван слишком высокой скоростью для данных условий, а также изношенными или недокачанными передними шинами."},"41":{"q":"Чуть ниже нуля, дорога скользкая, и вы совершаете резкое экстренное торможение, когда легковой автомобиль внезапно подрезает вас. Ваш тягач с прицепом оснащён антиблокировочной системой тормозов (ABS), и вы сильно, до упора нажимаете на педаль тормоза. В этой ситуации, в чём состоит ГЛАВНОЕ преимущество ABS?","options":["Она не даёт колёсам заблокироваться, поэтому вы можете продолжать рулить, объезжая опасность","Она гарантирует заметно более короткий тормозной путь, чем у такого же грузовика без ABS","Она автоматически уводит грузовик в сторону от подрезавшего вас автомобиля","Она позволяет безопасно ехать ближе к впереди идущему, ведь теперь вы останавливаетесь быстрее"],"explanation":"АБS предотвращает блокировку колес при резком торможении, благодаря чему вы сохраняете управляемость и можете объехать опасность."},"42":{"q":"Вы первым прибыли на место аварии на оживлённом двухполосном шоссе. Машина перевернулась и перекрывает вашу полосу; водитель в сознании, но привалился к двери, а сзади к месту аварии на скоростном режиме продолжает приближаться транспорт. Вы безопасно остановились и включили аварийную сигнализацию. Что следует сделать В ПЕРВУЮ ОЧЕРЕДЬ?","options":["Осторожно вытащить пострадавшего водителя из машины и положить его на обочину на случай возгорания автомобиля","Доехать до следующего съезда, чтобы найти телефон и вызвать 911, так как в одиночку вы помочь не сможете","Выйти и оттолкнуть разбитую машину в сторону, чтобы освободить полосу и не задерживать движение","Выставить светоотражающие аварийные треугольники, чтобы предупредить приближающийся транспорт, прежде чем делать что-либо ещё на месте"],"explanation":"На месте ДТП первоочередная задача — обезопасить его, поэтому выставите светоотражающие аварийные треугольники, чтобы предупредить приближающийся транспорт, прежде чем делать что-либо ещё."},"43":{"q":"Заметив дым из моторного отсека, вы съезжаете на обочину. Вы поставили стояночный тормоз и взяли огнетушитель класса B:C. Какое из перечисленных действий НАИМЕНЕЕ уместно при подготовке к тушению пожара в двигателе?","options":["Как можно скорее заглушить двигатель","Направлять огнетушитель на основание огня, а не на верхушки языков пламени","Держать капот по возможности закрытым и подавать состав через щели или жалюзи","Полностью распахнуть капот, чтобы направить струю огнетушителя прямо на пламя"],"explanation":"Если распахнуть капот настежь, к огню поступит свежий кислород и пламя может резко вспыхнуть; держите капот опущенным и направляйте струю через щели."},"44":{"q":"На свадебном банкете накануне дальнего рейса вы пьёте размеренно, но прекращаете за несколько часов до сна. Утром вы чувствуете себя совершенно трезвым, плотно завтракаете, выпиваете две чашки кофе и совершаете бодрую прогулку на холодном воздухе перед предрейсовым осмотром. Забираясь в кабину, какое утверждение лучше всего отражает закон и факты относительно того, можете ли вы безопасно управлять своим коммерческим транспортным средством (CMV)?","options":["Ни один из этих шагов не снизил концентрацию алкоголя в вашей крови; это делает только время, и вам нельзя управлять CMV при содержании алкоголя в крови (BAC) 0,04% или выше.","Поскольку вы управляете CMV, законный предел составляет 0,08%, поэтому вы явно в порядке, если оставались ниже этого значения.","Кофе, еда и холодный воздух ускорили вывод алкоголя, поэтому ваш BAC теперь практически равен нулю и предел больше не имеет значения.","Ощущение трезвости и есть юридический критерий для водителя CMV, так что если вы больше не чувствуете опьянения, вы ниже предела и можете безопасно вести машину."],"explanation":"Снизить концентрацию алкоголя в крови может только время, и нельзя управлять коммерческим транспортом при уровне алкоголя 0,04 % и выше."},"45":{"q":"Ваша смена закончилась несколько часов назад, и за ужином вы выпили несколько порций спиртного. Звонит диспетчер и просит прямо сейчас перегнать порожний тягач обратно на базу. Вы выпили кофе, быстро прошлись по холодному ночному воздуху и чувствуете ясность в голове. Какое утверждение лучше всего отражает то, что на самом деле определяет, законно ли вы пригодны к управлению?","options":["Кофе и холодный воздух повысили вашу бодрость настолько, что концентрация алкоголя в крови теперь ниже предела 0,04% для водителей CDL.","Поскольку вы чувствуете ясность в голове и больше не ощущаете опьянения, вы безопасно и законно можете управлять тягачом.","Только течение времени снижает концентрацию алкоголя в крови; ничто из того, что вы сделали, не ускоряет выведение алкоголя из организма.","Так как это порожний перегон без груза, предел 0,04% содержания алкоголя в крови к этой поездке не применяется."],"explanation":"Только время снижает концентрацию алкоголя в крови, так как печень выводит алкоголь с постоянной скоростью, которую кофе, свежий воздух или холодный душ не ускоряют."},"46":{"q":"Вы начинаете смену, когда дорожный инспектор проводит тест дыхания, и результат показывает 0,02% содержания алкоголя в крови -- алкоголь обнаружен, но ниже предела 0,04% для CDL. Вы чувствуете себя полностью трезвым, ДТП или иных нарушений нет. Что произойдёт с вами дальше согласно федеральным правилам CDL?","options":["Ничего не меняется -- поскольку вы ниже предела 0,04%, вам разрешено продолжать движение в обычном режиме","Вас отстраняют от работы на 24 часа, хотя ваш показатель ниже дисквалифицирующего уровня 0,04%","С вами поступают так же, как при показателе 0,04%, и предъявляют обвинение в управлении в нетрезвом виде (DUI)","Вы получаете письменное предупреждение и можете продолжить рейс после того, как его подпишете"],"explanation":"Любое обнаруживаемое количество алкоголя ниже 0,04 % отстраняет водителя с CDL от работы на 24 часа, даже если оно ниже дисквалифицирующего порога."},"47":{"q":"Вы загрузили и закрепили груз на бортовой платформе у грузоотправителя, выполнили предрейсовый осмотр и выехали на трассу. Поездка составляет 280 миль без запланированных остановок. Зная, что груз усаживается, а крепления могут ослабнуть вскоре после начала движения, к какому моменту вы обязаны сделать ПЕРВУЮ остановку, чтобы осмотреть груз и подтянуть крепления?","options":["В пределах первых 50 миль","В пределах первых 150 миль","После первых 3 часов движения","В пределах первых 100 миль"],"explanation":"Груз и его крепления необходимо проверить в течение первых 50 миль, так как стяжки ослабевают по мере усадки груза на этих первых милях пути."},"48":{"q":"Во время предрейсового осмотра вы закрепляете на бортовой платформе одну стальную балку длиной 18 футов и весом 4 200 фунтов. Вы хотите использовать наименьшее число креплений, которое всё ещё соответствует федеральным правилам крепления груза. Какое утверждение верно описывает МИНИМАЛЬНОЕ число креплений, которое вы обязаны использовать?","options":["Не менее двух креплений, потому что требуется одно на каждые 10 футов груза, а 18-футовый предмет требует двух","Одного крепления достаточно, потому что балка — это единый, сбалансированный предмет, лежащий плашмя на платформе","Не менее трёх креплений, потому что любой предмет длиннее 5 футов всегда требует три отдельные точки крепления","Фиксированного числа нет; нужно лишь столько креплений, чтобы их рабочая нагрузка достигла 50% веса груза"],"explanation":"Груз требует минимум одной стяжки на каждые 10 футов длины, а любой предмет длиннее 5 футов — не менее двух, поэтому 18-футовая деталь требует двух стяжек."},"49":{"q":"Вы загружаете бортовую платформу на доке, и единственное оставшееся место для нескольких тяжёлых стальных рулонов -- верхний ярус двухъярусной стойки, тогда как более лёгкую упаковку можно положить на настил внизу. Коллега говорит, что неважно, где едут тяжёлые рулоны, пока общий вес не превышает ваш GVWR (полную разрешённую массу). На выезде маршрут включает извилистую двухполосную дорогу с несколькими крутыми поворотами. По сравнению с размещением тяжёлых рулонов низко на настиле, каково САМОЕ важное последствие укладки этого тяжёлого груза высоко?","options":["Это не влияет на управляемость, ведь вы всё равно остаётесь в пределах GVWR автомобиля","Грузовик станет легче остановить, потому что больший вес сильнее прижимает шины к дороге","Это поднимает центр тяжести, делая грузовик гораздо более склонным к опрокидыванию на поворотах","Это повышает устойчивость и курсовую устойчивость на поворотах, потому что груз отцентрован над рамой"],"explanation":"Загрузка тяжёлого груза высоко поднимает центр тяжести, делая грузовик неустойчивым и склонным к опрокидыванию на поворотах."},"50":{"q":"Вы стоите на площадке Техасского DPS и смотрите на состав, на право управления которым хотите получить лицензию: тягач с груженым прицепом. В документах указана полная масса автопоезда (GCWR) 33 000 фунтов, а сам прицеп имеет паспортную массу 14 000 фунтов. Приятель с категорией Class B говорит, что его лицензии достаточно, 'потому что всё вместе весит более 26 001 фунта.' Какое утверждение правильно определяет, какая лицензия вам действительно нужна и почему?","options":["Достаточно Class B, поскольку суммарная паспортная масса состава составляет 26 001 фунт или более.","Нужна Class A, но только потому, что суммарная паспортная масса состава достигает 16 001 фунта или более.","Достаточно Class B, поскольку буксируемый прицеп имеет паспортную массу менее 16 000 фунтов.","Нужна Class A, поскольку паспортная масса состава 26 001 фунт или более И буксируемая единица имеет паспортную массу свыше 10 000 фунтов."],"explanation":"Лицензия класса A требуется, когда полная масса автопоезда (GCWR) составляет 26 001 фунт и более, а буксируемый прицеп рассчитан более чем на 10 000 фунтов."},"51":{"q":"Вы приходите на экзамен по навыкам вождения CDL, планируя зарабатывать на жизнь управлением тягачом с полуприцепом, где каждая машина, которой вы когда-либо будете управлять, оснащена полноценными пневматическими (воздушными) тормозами. Чтобы сэкономить, друг одалживает вам свой старый одиночный грузовик, оборудованный только гидравлическими тормозами, и вы безошибочно сдаёте на нём весь экзамен по навыкам. Учитывая, как этот выбор повлияет на ваши права, какое утверждение верно?","options":["Поскольку вы сдавали экзамен по навыкам на транспортном средстве, которое НЕ оснащено пневматическими тормозами, в ваших правах CDL будет указано ограничение по пневматическим тормозам, запрещающее вам управлять любым коммерческим транспортным средством с пневматическими тормозами.","Поскольку вы сдали экзамен по навыкам чисто, без единой ошибки, вы получите полные права CDL без ограничений, действительные для транспортных средств с пневматическими тормозами.","Поскольку грузовик, на котором вы сдавали, имел исправные гидравлические тормоза, экзаменатор может просто отменить часть про пневматические тормоза и выдать права без ограничений.","Поскольку вы намерены управлять только тягачами с полуприцепом на пневматических тормозах по работе, вам выдадут права с ограничением вождения только в ночное время до повторной сдачи экзамена."],"explanation":"Сдача практического экзамена на транспортном средстве без пневматических тормозов влечёт ограничение, запрещающее управлять любым коммерческим ТС с пневмотормозами."},"52":{"q":"Вы ведете заказной автобус с 40 пассажирами и приближаетесь к железнодорожному переезду на сельском шоссе. Переезд обозначен только знаком «крест» (крестовиной), шлагбаумы подняты, сигнальные огни не мигают, обзор в обе стороны хороший, и поезда нигде не видно. Что вы обязаны сделать перед пересечением путей?","options":["Снизить скорость, посмотреть и прислушаться и проехать без остановки, поскольку шлагбаумы подняты и сигналы не активны","Полностью остановиться, посмотреть и прислушаться, а затем пересекать пути только тогда, когда вы сможете полностью их освободить без остановки","Сохранять скорость, чтобы у автобуса хватило инерции пересечь все пути и не заглохнуть","Останавливаться только в том случае, если вы вдобавок к пассажирам перевозите опасные грузы с табличками (плакардами)"],"explanation":"Автобусы и ТС с табличками опасных грузов обязаны останавливаться, смотреть и слушать на каждом ж/д переезде и пересекать его лишь полностью освободив пути без остановки."},"53":{"q":"Вы управляете полностью загруженным тягачом с полуприцепом длиной 53 фута и приближаетесь к нерегулируемому одноколейному железнодорожному переезду на сельской двухполосной дороге. Здесь нет ни светофоров, ни шлагбаумов, а обзор вдоль путей частично закрыт кустарником. Вы знаете, что нельзя начинать переезд, пока вы не сможете полностью пересечь пути без остановки. Сколько примерно времени следует закладывать на то, чтобы такой состав, как ваш, полностью освободил одну колею, чтобы решить, безопасно ли начинать движение?","options":["Около 3 секунд, так как это примерно ваше время реакции на скоростной трассе","Точное время не имеет значения, пока сейчас не видно ни одного поезда","Около 6 секунд — столько же, сколько полное время остановки при скорости 55 миль/ч","Не менее 14 секунд"],"explanation":"Обычному тягачу с прицепом требуется не менее 14 секунд, чтобы полностью пересечь один железнодорожный путь, поэтому выделите столько времени перед началом проезда."},"54":{"q":"Сейчас середина дня, но сильный ливень снизил видимость, и небо стало темно-серым. Дорогу и другие машины вы пока различаете достаточно, чтобы ехать, поэтому сомневаетесь, нужны ли вообще сейчас фары. Почему включить фары БЛИЖНЕГО света в этой ситуации — ЛУЧШЕЕ решение?","options":["Работающие фары нагружают генератор, что помогает заряжать аккумулятор во время долгой медленной поездки под дождём","Фары пробивают пелену дождя и заметно увеличивают расстояние, на котором вы сами видите дорогу впереди","Фары делают ваш грузовик гораздо заметнее для других водителей в тусклом дождливом свете, даже если вы сами ещё видите достаточно хорошо","Переключение на дальний свет в дождь даёт больше всего света вперёд и вернее всего привлекает внимание встречного транспорта"],"explanation":"В сумерках или дождь главная цель фар — сделать ваш грузовик заметным для других водителей, даже если вы сами видите дорогу достаточно хорошо."},"55":{"q":"Во время предрейсового осмотра вы обходите бортовую платформу, загруженную стальными трубами, и останавливаетесь, чтобы проверить переднюю защитную стенку груза (\"headache rack\", защитная решётка), установленную в передней части прицепа за кабиной. Новичок спрашивает, почему компания не выпускает грузовик в рейс без исправной стенки. Какой ответ лучше всего описывает БЕЗОПАСНОСТЬ, которую обеспечивает это устройство?","options":["Оно защищает груз от гравия и дорожного мусора, выбрасываемого передними колёсами","Оно обозначает груз как негабаритный, чтобы идущий сзади транспорт держал безопасную дистанцию","Оно служит задней точкой крепления, к которой по закону должны присоединяться крепёжные цепи","Оно защищает водителя, останавливая груз от смещения вперёд в кабину при резком торможении или столкновении"],"explanation":"Передний щит (защитная решётка) — это барьер, который не даёт грузу сместиться вперёд в кабину и травмировать водителя при резком торможении или аварии."},"56":{"q":"Раннее утро, и перед дальним рейсом вы выполняете наружный осмотр своего тягача с прицепом. Проверяя задние оси, вы приседаете, чтобы осмотреть сдвоенные шины. Какое из следующих наблюдений потребует снять автомобиль с эксплуатации, прежде чем вы сможете легально и безопасно продолжить движение?","options":["Шины на управляемой (передней) оси имеют глубину протектора по 5/32 дюйма каждая","Две сдвоенные шины на задней оси прижаты друг к другу и соприкасаются","Все четыре шины на задней оси одного размера и одной марки","Шины ведущей задней оси имеют глубину протектора 3/32 дюйма"],"explanation":"Спаренные колёса никогда не должны касаться друг друга, так как контакт указывает на несоответствие размеров или недостаточное давление, что вызывает перегрев и может привести к разрыву шины."},"58":{"q":"Вы завершаете предрейсовый осмотр своего тягача с прицепом перед поездкой на 300 миль. Диспетчер сообщает по рации, что инспектор на дороге проверит ваш грузовик на наличие аварийного оборудования, обязательного по федеральным нормам. Заглянув в кабину, вы понимаете, что одного предмета из вашего обычного набора не хватает, и начинаете волноваться. Какой из перечисленных предметов по закону НЕ обязан находиться на борту, чтобы пройти эту проверку?","options":["Исправный огнетушитель с надлежащей зарядкой и характеристиками","Накачанное запасное колесо, хранящееся на машине","Комплект из трёх красных светоотражающих аварийных треугольников","Запасные электрические предохранители, если только грузовик не оснащён автоматическими выключателями"],"explanation":"Обязательное аварийное оснащение включает огнетушитель, запасные предохранители и аварийные треугольники; запасное колесо не требуется."},"59":{"q":"Чуть ниже нуля, и вы тянете гружёный прицеп в небольшой подъём по настилу моста. Вы чувствуете, что задние ведущие колёса начинают пробуксовывать, а задняя часть тягача уходит влево. Чтобы вернуть автопоезд под контроль, какое действие УХУДШИТ занос, а не поможет выйти из него?","options":["Сильнее нажать на газ, чтобы буксующие ведущие колёса силой вернулись в линию","Отпустить педаль газа и выжать сцепление, чтобы ведущие колёса замедлились","Рулить в том направлении, куда вы хотите направить тягач по полосе","Быть готовым к встречному рулению, когда прицеп начнёт выравниваться"],"explanation":"При заносе ведущих колёс прекратите подачу газа: отпустите акселератор и выжмите сцепление, чтобы ведущие колёса восстановили сцепление с дорогой."},"60":{"q":"Сейчас 5:00 утра, и вы собираетесь отправиться в дальний рейс. Коллега говорит, что компания уже оплатила осмотр механиком на прошлой неделе, поэтому ваш собственный предрейсовый осмотр сегодня утром нужен лишь для того, чтобы выявить то, из-за чего вы можете застрять на трассе. Какое утверждение ЛУЧШЕ всего объясняет, почему штат Техас требует от вас проводить собственный предрейсовый осмотр перед КАЖДЫМ рейсом?","options":["Его единственная законная цель — обнаружить механические дефекты безопасности, прежде чем они приведут к аварии на дороге.","По сути это юридическая формальность, которую нужно фиксировать в журнале, чтобы соблюдать законы штата и федеральные правила.","Его главная ценность — предотвращение поломок в пути, которые стоят компании времени и денег.","Он служит всем этим целям одновременно: выявление дефектов безопасности, выполнение вашей юридической обязанности и предотвращение поломок."],"explanation":"Предрейсовый осмотр служит трём целям сразу: выявление дефектов безопасности, выполнение вашей юридической обязанности водителя и предотвращение дорогостоящих поломок."},"61":{"q":"Вы ведете груженый тягач с полуприцепом на скорости по шоссе, когда автомобиль внезапно подрезает вас и резко тормозит, оставляя препятствие прямо в вашей полосе, при этом обочина справа свободна. Остановиться вовремя невозможно. Какое утверждение ЛУЧШЕ всего объясняет, почему одно лишь резкое торможение не всегда является самым безопасным действием в этой аварийной ситуации?","options":["Зачастую объехать препятствие можно на меньшей дистанции, чем требуется для полной остановки, поэтому уход рулением (контррулением) на свободную обочину может предотвратить столкновение там, где торможение не успеет.","Останавливаться в аварийной ситуации запрещено никогда, потому что это тратит время реакции, которое закон обязывает использовать для маневра рулем.","Резкого торможения следует избегать главным образом потому, что тормоза перегреются и потеряют эффективность в первые же секунды любого экстренного торможения.","Поскольку ваш прицеп груженый, общий тормозной путь на скорости 55 миль/ч падает примерно до 60 футов, поэтому тормозить на таком расстоянии бессмысленно."],"explanation":"Объехать опасность рулём обычно можно на гораздо меньшем расстоянии, чем требуется для остановки, поэтому уход на свободную обочину может предотвратить аварию, когда торможение не успевает."},"62":{"q":"Вы ведёте гружёный тягач с прицепом со скоростью 55 миль/ч по сухой автомагистрали, когда далеко впереди в вашей полосе внезапно останавливается автомобиль. С момента, когда опасность впервые появляется, до момента полной остановки грузовика ваш общий тормозной путь складывается из трёх отдельных частей, следующих одна за другой. В какой последовательности эти три части перечислены в правильном хронологическом порядке, от первой к последней?","options":["Дистанция реакции, затем дистанция торможения, затем дистанция восприятия","Дистанция восприятия, затем дистанция реакции, затем дистанция торможения","Дистанция торможения, затем дистанция реакции, затем дистанция восприятия","Дистанция восприятия, затем дистанция торможения, затем дистанция реакции"],"explanation":"Полный тормозной путь складывается по порядку: сначала вы замечаете опасность, затем реагируете и переносите ногу на педаль, и только потом тормоза замедляют машину."},"65":{"q":"Вы спускаетесь с груженым прицепом по длинному крутому горному склону. На полпути вниз вы нажимаете на педаль тормоза, и она проваливается до пола почти без сопротивления -- рабочие тормоза отказали, и грузовик набирает скорость. Примерно через полмили впереди обозначен аварийный тормозной съезд (улавливающий карман). Какое единственное НАИЛУЧШЕЕ действие следует предпринять?","options":["Перевести коробку передач в нейтраль, чтобы двигатель больше не сдерживал движение, и дать грузовику накатом остановиться под контролем","Быстро и многократно нажимать на педаль тормоза, пытаясь восстановить давление, продолжая спуск по склону","Направить грузовик на аварийный тормозной съезд впереди, который специально построен для остановки транспортного средства с отказавшими тормозами","Распахнуть водительскую дверь и приготовиться выпрыгнуть, прежде чем грузовик достигнет подножия"],"explanation":"Аварийные тормозные съезды созданы для безопасной остановки тяжелого транспорта с отказавшими тормозами на спуске, поэтому используйте их при наличии."},"66":{"q":"Последние десять минут идёт непрерывный дождь, и вы ведёте гружёный автопоезд со скоростью 60 миль/ч по гладкому, хорошо заасфальтированному межштатному шоссе. Вы замечаете, что руль стал 'лёгким', и грузовик не реагирует на небольшую корректировку рулём. Какой фактор БОЛЬШЕ ВСЕГО отвечает за эту потерю сцепления с дорогой?","options":["Покрытие дороги сухое, поэтому передние шины потеряли сцепление с горячим асфальтом","На дороге есть вода, и вы едете слишком быстро, поэтому шины скользят по плёнке воды","Вы едете очень медленно, из-за чего шины проваливаются в стоячую воду","Ваши шины совершенно новые, и глубокий протектор отводит слишком много воды"],"explanation":"Аквапланирование возникает, когда вода на дороге в сочетании со слишком высокой скоростью приподнимает шины, и они скользят по водяной плёнке вместо покрытия."},"67":{"q":"Жаркий летний день, и вы только что заехали на площадку для отдыха, проехав 120 миль по шоссе. Во время осмотра вы хотите убедиться, что шины ведущей оси накачаны правильно, прежде чем продолжить путь. Какой способ даёт точное и надёжное измерение давления?","options":["Ударить по каждой шине молотком или специальной киянкой и оценить давление по звуку и отскоку","Проверить давление прямо сейчас манометром, пока шины ещё горячие после шоссе, ведь это их настоящее рабочее давление","Сначала дать шинам остыть, затем проверить каждую исправным (поверенным) манометром","Внимательно посмотреть, насколько каждая шина приплюснута снизу, и сравнить шины между собой"],"explanation":"Проверяйте давление в шинах только откалиброванным манометром после остывания шин, так как нагрев при движении повышает давление и даёт ложно завышенные показания."},"68":{"q":"Вы выезжаете на загруженную автомагистраль на гружёном тягаче с прицепом. Легковой автомобиль пристраивается вплотную сзади справа и пропадает из ваших зеркал, а другая машина едет прямо у вашего левого крыла. Коллега как-то сказал вам больше всего опасаться 'мёртвой зоны' (No-Zone). В этой ситуации, какую именно No-Zone вам нужно контролировать?","options":["Запас расстояния, который нужно держать впереди себя, равный примерно 419 футам на скорости 55 миль/ч","Большие зоны слепых пятен вокруг вашего грузовика, где другие машины могут исчезнуть из поля зрения","Зону запрета остановки у правого бордюра, где нельзя останавливаться, чтобы выставить аварийные знаки","Крайнюю левую полосу для машин с пассажирами, куда грузовикам въезд запрещён"],"explanation":"No-Zone — это большие слепые зоны со всех четырёх сторон грузовика, где другие транспортные средства могут исчезнуть из поля зрения."},"69":{"q":"Вы одни на переполненной стоянке для грузовиков, и вам нужно сдать назад ваш тягач с прицепом в узкое место вдоль стены справа от вас. Прицеп пустой, на стоянке много пешеходов, и вы не видите чётко зону позади правого заднего угла. Как безопаснее всего выполнить этот манёвр задним ходом?","options":["Сдавать назад в сторону правой (слепой) стороны, чтобы стена оставалась видна через лобовое стекло, и двигаться медленно","Сдавать назад быстро, пока есть промежуток, так как задержка в проезде создаёт больше риска для пешеходов","Полагаться только на правое боковое зеркало и не выходить из кабины, потому что остановка для осмотра тратит время на оживлённой стоянке","При необходимости перестроиться так, чтобы сдавать назад в сторону левой (водительской) стороны, и использовать помощника или сигнальщика для наблюдения за слепой зоной"],"explanation":"По возможности сдавайте назад в сторону водителя (влево), чтобы видеть вдоль прицепа напрямую, и используйте помощника или сигнальщика для контроля слепой зоны."},"70":{"q":"Вы ведёте гружёный тягач с полуприцепом со скоростью 55 миль/ч в хороших, сухих условиях, когда прямо в вашей полосе всего в нескольких длинах грузовика впереди внезапно появляется заглохший автомобиль — гораздо ближе, чем ваш общий тормозной путь около 419 футов. Соседняя полоса свободна. Какое действие даёт вам НАИЛУЧШИЙ шанс избежать столкновения?","options":["Объехать препятствие, перестроившись на свободную полосу, поскольку обычно можно увернуться от препятствия рулём на меньшем расстоянии, чем требуется для полной остановки","Тормозить изо всех сил и заблокировать колёса, потому что максимальное торможение всегда является самой безопасной экстренной реакцией","Сохранить скорость и проехать прямо насквозь, полагаясь на массу грузовика, чтобы оттолкнуть препятствие в сторону","Остаться в своей полосе и тормозить слегка, поскольку при 55 милях/ч ваш тормозной путь в 419 футов остановит вас вовремя"],"explanation":"Объехать препятствие обычно можно на меньшем расстоянии, чем требуется для полной остановки, поэтому используйте свободную полосу для ухода от опасности."},"71":{"q":"Вы приближаетесь к оживлённому перекрёстку, где вам нужно повернуть направо, и позади вас выстроилась колонна машин. Чтобы безопасно сообщить о своих намерениях и дать другим водителям максимум времени на реакцию, когда следует включить указатель поворота?","options":["Сначала несколько раз нажмите на тормоз, а затем включите сигнал прямо в момент начала поворота, чтобы ранний сигнал не сбил с толку едущих сзади","Включите сигнал заблаговременно, задолго до поворота, и не выключайте его, пока поворот не будет завершён","Только после того, как вы снизили скорость и убедились, что перекрёсток свободен, чтобы не подать сигнал слишком рано","Включите сигнал сразу после завершения поворота, чтобы подтвердить манёвр водителям позади вас"],"explanation":"Подавайте сигнал заранее, задолго до поворота, и держите его включённым до полного завершения манёвра, чтобы другие водители успели среагировать."},"72":{"q":"Температура чуть ниже нуля, и лёгкая ледяная морось оставила шоссе мокрым и блестящим. Ваш гружёный грузовик оснащён моторным тормозом (ретардером). Приближаясь к участку дороги, где может понадобиться плавно сбросить скорость, как БЕЗОПАСНЕЕ всего поступить с ретардером в таких условиях?","options":["Оставить ретардер полностью включённым, так как он снижает износ рабочих тормозов в плохую погоду","ВЫКЛЮЧИТЬ ретардер, потому что он может вызвать потерю сцепления ведущих колёс и занос на скользкой поверхности","Держать ретардер на максимальном режиме, чтобы замедляться, не нажимая на педаль тормоза","Использовать ретардер только когда скорость превышает 40 миль/ч, а ниже этого значения выключать его"],"explanation":"Отключайте ретардер на мокрой, обледенелой или скользкой дороге, так как он тормозит только ведущие колёса и может вызвать потерю сцепления и занос."},"73":{"q":"Вы везете полностью груженый прицеп и начали подъем на длинный крутой склон в горах. Тягач начинает «тянуть» с трудом, обороты двигателя падают, а скорость быстро снижается. Какое действие позволит безопасно продолжать движение и сохранить максимальную мощность двигателя на подъеме?","options":["Оставить коробку передач в режиме овердрайв и выжать педаль газа до пола, чтобы восстановить скорость","Переключиться на пониженную передачу, чтобы двигатель оставался в диапазоне мощности и ровно тянул груз","Поставить коробку передач в нейтраль и позволить инерции перенести вас через вершину склона","Удерживать текущую передачу и слегка подкачивать рабочими тормозами, чтобы держать машину под контролем"],"explanation":"На длинном крутом подъёме переключайтесь на пониженную передачу, чтобы обороты двигателя оставались в рабочем диапазоне и он ровно тянул груз."},"74":{"q":"Вы едете порожним со скоростью 30 миль/ч по сухой загородной трассе и привыкли оставлять себе достаточно места для торможения. Дорога впереди освобождается, и вы разгоняетесь до 60 миль/ч. По сравнению с тормозным путём, который требовался при 30 миль/ч, каким теперь следует ожидать сам тормозной путь при 60 миль/ч?","options":["Он лишь удваивается, ведь вы удвоили скорость -- значит, оставить вдвое больше места достаточно","Он увеличивается примерно в четыре раза, потому что тормозной путь растёт пропорционально квадрату скорости","Он остаётся примерно прежним, потому что порожний грузовик останавливается на более коротком расстоянии, чем гружёный","Он увеличивается примерно наполовину, так как общий остановочный путь включает ещё и путь реакции"],"explanation":"Тормозной путь растёт пропорционально квадрату скорости, поэтому при удвоении скорости он увеличивается примерно в четыре раза."},"75":{"q":"Сейчас 2 часа ночи во время длинного ночного рейса, и вы замечаете, что веки тяжелеют, вас увело в сторону внутри полосы, и вы не можете вспомнить последние несколько миль. По вашему путевому листу у вас ещё есть несколько часов разрешённого времени за рулём. Какое действие является ЕДИНСТВЕННЫМ по-настоящему действенным способом справиться с этой усталостью?","options":["Опустить стекло и направить холодный воздух в лицо, чтобы оставаться бодрым","Выпить большой кофе и продолжить ехать, чтобы завершить рейс, пока у вас ещё есть часы","Съехать с трассы в безопасном месте и остановиться, чтобы отдохнуть или поспать перед продолжением","Включить радио громче и понизить температуру в кабине, чтобы не уснуть"],"explanation":"Единственное надёжное средство от сонливости — съехать с дороги и отдохнуть или поспать, так как ничто другое по-настоящему не восстанавливает бдительность."},"77":{"q":"Вы ведёте гружёный седельный тягач с прицепом по четырёхполосному шоссе, когда оранжевые знаки предупреждают о зоне дорожных работ впереди. При въезде установленное ограничение скорости снижается, а у правой полосы движения видны регулировщик и несколько рабочих. Поток движется свободно, и прямо за вами никого нет. Какое действие является НАИЛУЧШИМ при проезде через эту зону?","options":["Сохранять шоссейную скорость, так как поток движется свободно, а быстрый проезд зоны сокращает время вашего нахождения рядом с рабочими","Снизить скорость до установленного для зоны работ ограничения, увеличить дистанцию до впереди идущего транспорта и быть внимательным к рабочим, выходящим на полосу","Перестроиться в левую полосу на текущей скорости и ускориться, чтобы проехать регулировщика до того, как обстановка изменится","Держаться вплотную к идущему впереди автомобилю, чтобы другие водители не вклинились между вами и не вынудили вас тормозить рядом с рабочими"],"explanation":"В зоне дорожных работ снижайте скорость до указанного предела, увеличивайте дистанцию и следите за рабочими, выходящими на полосу, сохраняя запас для торможения."},"78":{"q":"Во время предрейсового осмотра вы контролируете загрузку лёгких, но габаритных ящиков в свой сухогрузный фургон. Чтобы всё поместилось, бригада складывает их высокими штабелями, и основная масса груза оказывается вверху прицепа, а не распределена низко по полу. Общий вес груза находится в пределах ваших осевых нагрузок, и груз отцентрован по бокам. Когда вы выезжаете и приближаетесь к первому повороту въезда на шоссе, какое самое важное последствие имеет такой способ укладки груза?","options":["Поскольку вес отцентрован и находится в пределах осевых нагрузок, прицеп на самом деле пройдёт поворот устойчивее, чем при низкой укладке.","Высокая укладка не влияет на управляемость, ведь вес груза в пределах допустимых осевых нагрузок.","Высокий центр тяжести делает машину гораздо более склонной к опрокидыванию в повороте, даже если на прямой груз кажется надёжным.","Главный риск - значительно более длинный тормозной путь, потому что высоко уложенный груз снижает сцепление при торможении."],"explanation":"Высокая укладка лёгкого объёмного груза поднимает центр тяжести, что резко повышает риск опрокидывания на повороте."},"79":{"q":"Во время предрейсового осмотра вы перевозите на бортовой платформе один стальной рулон весом 8 000 фунтов. Вы начинаете проверять крепёжные цепи и стяжные устройства, чтобы убедиться, что груз закреплён в соответствии с законом. Помимо требования о том, что стальной рулон должен быть подклинен и зафиксирован распорками, какое утверждение правильно описывает МИНИМАЛЬНЫЙ суммарный (совокупный) предел рабочей нагрузки, который должны обеспечивать ваши крепления для этого груза весом 8 000 фунтов?","options":["Суммарный предел рабочей нагрузки креплений должен равняться полному весу груза, то есть не менее 8 000 фунтов.","Суммарный предел рабочей нагрузки креплений должен составлять не менее одной четверти веса груза, то есть не менее 2 000 фунтов.","Суммарный предел рабочей нагрузки креплений должен быть не менее двойного веса груза, то есть не менее 16 000 фунтов.","Суммарный предел рабочей нагрузки креплений должен составлять не менее половины веса груза, то есть не менее 4 000 фунтов."],"explanation":"Суммарный рабочий предел нагрузки всех креплений должен составлять не менее половины веса груза."},"80":{"q":"Вы приближаетесь к крутому правому повороту на городском перекрёстке на своём тягаче с прицепом. Вы знаете, что прицеп пойдёт по более короткой траектории, чем тягач (смещение траектории задних осей), и опасаетесь, что задние колёса могут наехать на бордюр. Чтобы задняя часть прицепа не задела бордюр, как безопаснее всего выполнить этот правый поворот?","options":["Начать поворот, выведя переднюю часть машины широко ВЛЕВО, а затем резко повернуть вправо, чтобы прицеп обошёл бордюр","Поворачивать широко уже при ЗАВЕРШЕНИИ поворота, держа заднюю часть автомобиля близко к бордюру, чтобы другие водители не смогли втиснуться справа от вас","Начать поворот из левого ряда и ускориться, чтобы меньше времени блокировать перекрёсток","Держаться правее и уходить широко влево только при крайней необходимости, смирившись с тем, что транспорт может объехать вас справа"],"explanation":"Поворачивайте широко только при завершении правого поворота, удерживая заднюю часть машины близко к бордюру, чтобы никто не вклинился справа."},"81":{"q":"Вы везёте полностью загруженный прицеп вниз по дороге штата и приближаетесь к плавному повороту. Дорожный знак показывает «Поворот — 45 миль/ч». Ваш грузовик тяжёлый и имеет высокую посадку, но покрытие сухое и погода ясная. Какое утверждение ЛУЧШЕ всего описывает, как вам следует относиться к этой указанной скорости 45 миль/ч на повороте?","options":["Считайте 45 миль/ч максимумом для легковых автомобилей в хороших условиях и снижайте скорость ниже этого значения, потому что вашему загруженному грузовику с высоким центром тяжести нужна меньшая скорость, чтобы избежать опрокидывания.","Считайте 45 миль/ч скоростью, рассчитанной специально для загруженных тяжёлых грузовиков, как ваш, поэтому вы можете безопасно проходить поворот ровно на 45 миль/ч.","Поскольку покрытие сухое и погода ясная, вы можете добавить запас и пройти поворот немного быстрее 45 миль/ч.","Указанная скорость действует только ночью, поэтому в ясный день вы можете её игнорировать и держать свою трассовую скорость на повороте."],"explanation":"Указанная на знаке скорость поворота рассчитана на легковые автомобили в хороших условиях, поэтому гружёный высокий грузовик должен снижать скорость ниже указанной во избежание опрокидывания."},"82":{"q":"Вы везете полностью загруженный прицеп вниз по длинному крутому горному спуску. На полпути вниз вы замечаете, что педаль тормоза становится мягче, а грузовик постепенно набирает скорость, хотя вы все время равномерно нажимали на тормоза на протяжении всего спуска. Что из перечисленного является НАИБОЛЕЕ вероятной причиной этой потери тормозной силы?","options":["Тормоза еще холодные, потому что вы только начали спуск, поэтому они пока не схватывают в полную силу","Тормоза перегрелись из-за непрерывного нажатия, что вызвало их выцветание (fade) и потерю тормозного усилия","Прицеп загружен слишком легко, поэтому недостаточно веса прижимает тормозные колодки к барабанам","Тормозные колодки совершенно новые, и им нужно приработаться, прежде чем они смогут удерживать машину на спуске"],"explanation":"Постоянное удержание тормозов на длинном спуске перегревает их, вызывая угасание тормозов и потерю тормозной силы."},"83":{"q":"Вы едете с грузом по мокрой четырёхполосной автомагистрали, когда легковой автомобиль внезапно подрезает вас и резко тормозит. Контрольная лампа ABS на панели не горит, значит система исправна. Вы выжимаете педаль тормоза до пола, и ABS срабатывает. Какую ГЛАВНУЮ пользу от ABS следует ожидать при этом экстренном торможении?","options":["Она гарантирует, что вы остановитесь на заметно более коротком расстоянии, чем грузовик без ABS","Она автоматически прокачивает тормоза, так что вам больше не нужно применять прерывистое (stab) торможение на сухом покрытии","Она не даёт колёсам заблокироваться, так что вы можете продолжать рулить и удерживать свою полосу при резком торможении","Она позволяет пропустить проверку регулировки тормозов на предрейсовом осмотре, ведь компьютер сам следит за тормозами"],"explanation":"АБС не даёт колёсам блокироваться при резком торможении, сохраняя управляемость, чтобы удержаться в полосе или объехать опасность."},"84":{"q":"Вы только что сбросили последний груз и теперь везёте пустой прицеп на базу по мокрой двухполосной дороге. Машина впереди резко тормозит, и вам нужно быстро остановиться. По сравнению с тем, когда вы были полностью загружены сегодня утром, чего следует ожидать от пустого тягача с прицепом в этой ситуации?","options":["Поскольку вес груза не давит вниз, шины лучше держат дорогу, поэтому вы всегда остановитесь на более коротком расстоянии, чем с грузом.","Пустой грузовик ведёт себя точно так же, как и загруженный, поэтому тормозной путь в любом случае одинаков.","Поскольку веса очень мало, колёса не могут заблокироваться или войти в занос, поэтому резкое торможение теперь полностью безопасно.","У пустого грузовика меньше сцепление с дорогой, и он может подпрыгивать, поэтому остановка может занять больше расстояния, чем когда он был загружен."],"explanation":"У пустого грузовика меньше сцепление и он склонен подпрыгивать, поэтому его тормозной путь может быть больше, чем у гружёного."},"85":{"q":"Примерно за час до заката начинается лёгкий дождь, когда вы выезжаете на двухполосное шоссе. Видимость пока неплохая, и вы хорошо видите дорогу без них, но встречные машины всё труднее различить на фоне серого неба. Как лучше всего поступить с фарами в этой ситуации?","options":["Оставить их выключенными, потому что включать фары нужно только когда станет совсем темно и вы перестанете видеть дорогу впереди","Включить их сейчас, потому что они помогают другим водителям видеть вас в сумерках, а также в дождь, туман или при слабом освещении","Использовать только дальний свет, поскольку дождь и угасающий свет означают, что вам нужно максимальное освещение впереди","Подождать, пока вы выедете на скоростное шоссе с разделёнными полосами, потому что фары нужны в основном на высокой скорости"],"explanation":"Включайте фары в сумерках, в дождь или туман, потому что они делают ваш автомобиль заметным для других водителей при слабом освещении."},"86":{"q":"Вы сдаёте назад прицепом в узкий погрузочный док и смотрите в большое выпуклое (сферическое) дополнительное зеркало со стороны пассажира. Автомобиль, который, как вы знаете, припаркован всего в нескольких футах позади вашего заднего бампера, в этом зеркале выглядит маленьким и далёким. Прежде чем продолжить движение назад, что вы должны понимать о том, что показывает вам это выпуклое зеркало?","options":["Оно даёт более широкий обзор, но объекты в нём кажутся меньше и дальше, чем на самом деле, поэтому тот автомобиль ближе, чем кажется","Оно увеличивает изображение, поэтому объекты выглядят крупнее и ближе, чем есть, а значит, тот автомобиль на самом деле дальше, чем кажется","Оно показывает истинный размер и расстояние до объектов, поэтому можно доверять тому, что автомобиль находится так далеко, как выглядит в зеркале","Оно неисправно, потому что правильно настроенное зеркало никогда не сделает близкий объект маленьким, и выпуклые зеркала в любом случае запрещены на коммерческих автомобилях"],"explanation":"Выпуклое зеркало даёт более широкий обзор, но объекты в нём кажутся меньше и дальше, поэтому на самом деле они ближе, чем выглядят."},"87":{"q":"Вы ведёте гружёный тягач с прицепом на трассе и примерно за 12-15 секунд впереди замечаете заглохший автомобиль, частично перекрывший правую полосу, с включённой аварийной сигнализацией. Поток вокруг вас пока движется нормально, и непосредственной угрозы ещё нет. Каким должно быть ваше ПЕРВОЕ действие?","options":["Сохранять скорость и положение, пока автомобиль не приблизится настолько, чтобы точно оценить, насколько он выступает в вашу полосу","Начать готовиться к реакции уже сейчас -- отпустить педаль газа, проверить зеркала и наметить путь объезда, чтобы плавно скорректировать движение до того, как ситуация станет аварийной","Немедленно применить жёсткое прерывистое (контролируемое) торможение, чтобы как можно быстрее сбросить максимум скорости","Сразу же перестроиться в левую полосу и ускориться, чтобы покинуть зону до того, как отреагируют другие водители"],"explanation":"Раннее обнаружение опасности даёт время на реакцию, поэтому отпустите педаль газа, проверьте зеркала и спланируйте путь ухода, пока ситуация не стала аварийной."},"88":{"q":"Вы едете с пустым прицепом со скоростью 55 миль/ч по межштатной автомагистрали во время сильного ливня. Вы чувствуете, что руль стал лёгким, и грузовик как будто начинает плыть, а передние колёса больше не держат дорогу полностью. Вы понимаете, что начинается аквапланирование. Какое действие даёт вам НАИЛУЧШИЙ шанс безопасно восстановить сцепление?","options":["Сильно нажать на педаль тормоза, чтобы быстро сбросить скорость и прижать шины обратно к покрытию","Резко вывернуть руль в сторону обочины, чтобы передние колёса зацепились за более грубую поверхность","Убрать ногу с педали газа, держать руль прямо и дать грузовику замедлиться, пока шины снова не схватятся","Резко понизить передачу и использовать торможение двигателем, чтобы как можно быстрее сбросить скорость"],"explanation":"При аквапланировании шины теряют сцепление с дорогой, поэтому отпустите педаль газа и держите руль прямо, пока скорость не упадёт и сцепление не восстановится."},"89":{"q":"Вы только что медленно проехали на груженом автопоезде через затопленный брод, и вода поднялась так высоко, что скрыла ступицы колёс. Разгоняясь до дорожной скорости, вы слегка нажимаете на тормоз и чувствуете, что они схватывают слабо и неравномерно. Какое действие является НАИЛУЧШИМ способом восстановить безопасное торможение?","options":["Съехать на обочину и подождать, пока тормозные барабаны высохнут на воздухе, прежде чем продолжить движение","Несколько раз сильно прокачать педаль тормоза, чтобы выдавить воду из накладок","Перейти на пониженную передачу и полагаться только на торможение двигателем, не трогая рабочие тормоза следующие несколько миль","Продолжать ехать медленно и слегка, равномерно нажимать на тормоза, чтобы высушить их теплом от трения"],"explanation":"Сушите мокрые тормоза, двигаясь медленно и слегка, равномерно нажимая на педаль, чтобы тепло от трения испарило воду, оставаясь под контролем."},"90":{"q":"Вы выбиваетесь из графика на сельском двухполосном шоссе с ограничением скорости 55 миль/ч. Машина впереди движется медленно, и вы хотите её обогнать. В какой из перечисленных ситуаций попытка обгона будет НАИМЕНЕЕ безопасной, то есть от обгона следует ОТКАЗАТЬСЯ?","options":["Вы приближаетесь к вершине холма и не видите, нет ли встречного транспорта на полосе встречного движения","Вы на длинном, ровном и прямом участке, где хорошо видно, что дорога свободна более чем на четверть мили вперёд","Вы въехали в обозначенную зону обгона с прерывистой жёлтой линией с вашей стороны и хорошей видимостью впереди","Вы видите, что встречная полоса свободна, и у вас достаточно места, чтобы вернуться в свою полосу задолго до встречного транспорта"],"explanation":"Никогда не обгоняйте там, где не видно дорогу достаточно далеко, например у вершины подъёма, так как встречный транспорт скрыт до последнего момента."},"91":{"q":"Вы ведёте гружёный тягач с полуприцепом по короткой полосе разгона при въезде на автомагистраль. Слева поток на шоссе движется со скоростью около 60 миль/ч, и впереди в правой полосе вы видите подходящий промежуток между двумя автомобилями. Подъезжая к концу полосы разгона, как БЕЗОПАСНЕЕ всего влиться в поток?","options":["Снизить скорость почти до остановки в конце полосы разгона и ждать очень большого промежутка, прежде чем выезжать","Использовать полосу разгона, чтобы разогнаться до скорости, близкой к потоку движения, и затем плавно влиться в свободный промежуток","Держать низкую скорость и медленно вдавливаться в полосу, заставляя машины сзади тормозить и уступать вам место","Двигаться по полосе разгона медленно и равномерно, чтобы было больше времени оценить поток перед перестроением"],"explanation":"Используйте полосу разгона, чтобы набрать скорость, близкую к потоку, затем вливайтесь в свободный промежуток, чтобы разница в скорости была минимальной."},"92":{"q":"Вы ведёте гружёный тягач с полуприцепом по правой полосе четырёхполосной разделённой автомагистрали, когда слышите сирену и видите в зеркалах быстро приближающуюся машину скорой помощи с мигающими огнями. Движение умеренное, справа есть асфальтированная обочина. Какое действие является НАИЛУЧШИМ?","options":["Сохранять свою полосу и скорость, чтобы машина скорой помощи могла предугадать ваш путь и обогнать вас слева","Ускориться, чтобы держаться впереди скорой помощи до ближайшего съезда, а затем покинуть автомагистраль","Включить сигнал поворота, направить машину к правой обочине и остановиться, когда это будет безопасно, чтобы освободить путь","Перестроиться влево в полосу обгона, чтобы освободить правую полосу и обочину для машины экстренной службы"],"explanation":"При приближении машины экстренной службы с маячками и сиреной включите сигнал, прижмитесь к правой обочине и остановитесь, когда это безопасно, уступая дорогу."},"93":{"q":"После того как вы съехали на обочину, в моторном отсеке вашего тягача вспыхивает небольшой электрический пожар. Вы хватаете огнетушитель, встаёте с наветренной стороны, выдёргиваете чеку и направляете раструб. Действуя правильно по методу PASS, какое заключительное действие вы должны выполнить после того, как нажали на рычаг, чтобы эффективно потушить огонь?","options":["Держать раструб неподвижно и направлять его прямо на верхнюю часть видимого пламени, пока оно не утихнет","Немедленно прекратить подачу состава, как только появится дым, чтобы не расходовать огнетушитель впустую","Вращать огнетушитель круговыми движениями над огнём, чтобы распылить состав на широкую площадь","Водить раструбом из стороны в сторону, направляя струю на основание огня, пока он не будет потушен"],"explanation":"Заключительный шаг метода PASS — водить раструбом из стороны в сторону у основания огня, где горит топливо, чтобы сбить пламя и потушить его."},"94":{"q":"Вы едете по двухполосному загородному шоссе, когда другой водитель поравнялся с вами, показывая рукой и крича, что одна из шин вашего прицепа горит. Вы съезжаете на обочину, ставите машину на тормоз и берёте огнетушитель и дорожный аварийный комплект. Подходя к горящей шине, какое действие БОЛЕЕ ВСЕГО подходит для тушения этого пожара?","options":["Обильно поливайте шину водой, чтобы охладить её, поскольку горящая шина выделяет сильный жар и требует непрерывного охлаждения для тушения","Направьте порошковый огнетушитель (класс B:C) прямо в основание пламени и держите его так, пока баллон полностью не опустеет","Оставьте её и дайте догореть самой на безопасном расстоянии, так как попытки сбить огонь только заставят резину разгораться сильнее","Осторожно подкачайте шину воздухом, чтобы каркас не сложился, пока пламя угасает"],"explanation":"Пожар в шине удерживает сильный жар в резине, поэтому залейте его большим количеством воды для непрерывного охлаждения, иначе он разгорится снова."},"95":{"q":"Температура чуть ниже нуля, и начинает идти лёгкий дождь, покрывающий дорогу ледяной коркой. Двигаясь со своей обычной скоростью по широкому повороту шоссе, вы вдруг чувствуете, как задняя часть вашего автопоезда заносит вбок, а прицеп толкает кабину в сторону. Если честно оценить момент начала заноса, какова была единственная НАИБОЛЕЕ вероятная причина?","options":["Шины передней управляемой оси были изношены почти до минимума 2/32 дюйма и первыми потеряли сцепление","Вы ехали слишком быстро для скользкой дороги при температуре около нуля","Вы рулили плавно и мягко в повороте, вместо резких корректировок","Прицеп шёл пустым, а пустые прицепы всегда держат дорогу лучше, чем гружёные"],"explanation":"Большинство заносов происходит из-за слишком высокой скорости для условий, а скользкая дорога у точки замерзания снижает сцепление, делая обычную скорость чрезмерной."},"96":{"q":"Температура чуть ниже нуля, и идёт слабый дождь. Вы движетесь в среднем ряду трёхполосной трассы, когда прицеп позади начинает становиться лёгким и уводить в соседнюю полосу. Какое из перечисленных действий даёт ЛУЧШИЙ шанс сохранить контроль над автомобилем и избежать полного заноса?","options":["Сильно нажать на тормоз и удерживать педаль, чтобы как можно быстрее сбросить скорость","Сделать резкий, рывковый поворот руля обратно к центру своей полосы, чтобы прекратить снос","Отпустить педаль газа и выполнять плавные, мягкие движения рулём и тормозом, чтобы сохранить сцепление","Сохранять текущую скорость и резко рулить, ведь в среднем ряду у шин ещё есть сцепление"],"explanation":"На скользкой дороге у точки замерзания снижайте нагрузку на шины: отпустите газ и делайте плавные, мягкие движения рулём и тормозом, чтобы сохранить сцепление."},"97":{"q":"Конец июля, разгар дня, и вы уже несколько часов едете с грузом по раскалённому асфальту. Во время остановки на отдых вы решаете в этой поездке проверять шины чаще обычного. Какова НАИЛУЧШАЯ причина так поступать в таких условиях?","options":["Горячее покрытие охлаждает воздух внутри шин, поэтому они теряют давление и едут спущенными","Жара размягчает резину протектора, и именно это является главной причиной разрыва шины летом","Шины физически сжимаются от жары, уменьшая площадь контакта с дорогой","Жара повышает давление воздуха внутри шин, что может привести к разрыву шины"],"explanation":"В жаркую погоду воздух внутри шин расширяется и давление растёт, что может привести к разрыву шины."},"98":{"q":"Вы перевозите груз по сельскому двухполосному шоссе и въезжаете в полосу густого тумана, настолько плотного, что вы больше не видите разметку полос или машину впереди, даже после того как сбавили скорость и переключились на ближний свет. Дальнейшее снижение скорости не вернуло вам возможность видеть безопасный путь. Какое действие самое безопасное?","options":["Включить дальний свет, чтобы пробить туман большим количеством света, и продолжать ползти вперёд черепашьим шагом","Сбавить почти до полной остановки в своей полосе, включить аварийную сигнализацию и продолжать медленно продвигаться вперёд","Полностью съехать с проезжей части, отъехать подальше от движения, включить фары и аварийную сигнализацию и ждать, пока туман рассеется","Держать медленную ровную скорость и следовать за задними огнями машины впереди, чтобы оставаться в своей полосе"],"explanation":"Если туман настолько густой, что даже на малой скорости не видно безопасного пути, полностью съезжайте с дороги, отойдите от движения, включите свет и аварийку и ждите его рассеивания."},"99":{"q":"Сегодня утром вы провели тщательный предрейсовый осмотр, закрепили груз, и всё было в порядке. Через три часа пути вы останавливаетесь на обеденный перерыв, и коллега-водитель спрашивает, зачем вы снова обходите тягач и проверяете груз, если уже осматривали его перед выездом. Какова НАИЛУЧШАЯ причина продолжать осмотры в течение дня?","options":["Правильный осмотр -- это непрерывный процесс, выполняемый до поездки, во время неё (в пути) и после неё, потому что состояние автомобиля и крепление груза могут измениться во время движения.","Как только автомобиль прошёл полный предрейсовый осмотр, закон считает его пригодным к эксплуатации до конца этой поездки, поэтому обход -- это лишь личная привычка, а не требование.","Осмотры в пути нужны только если загорелась сигнальная лампа или автомобиль действительно сломался, ведь пройденный предрейсовый осмотр уже охватывает всё механическое.","Повторная проверка требуется строго потому, что груз нужно осмотреть в течение первых 50 миль, а после этой первой проверки никакой дальнейший осмотр автомобиля в течение дня не нужен."],"explanation":"Осмотр проводится постоянно — до, во время (в пути) и после поездки, потому что давление в шинах, крепление груза и уровни жидкостей меняются во время движения."},"100":{"q":"Сегодня утром вы загрузили платформу стальными рулонами и выехали со двора на межштатную автомагистраль. Примерно через 35 миль вы видите просторную зону отдыха, где можно обойти весь автопоезд кругом. Общая длина рейса -- более 300 миль. Согласно правильной процедуре обращения с грузом, что вам следует сделать в отношении проверки груза и его крепления?","options":["Продолжать движение и сделать первую проверку крепления на отметке 150 миль, так как это стандартный интервал повторной проверки","Заехать и проверить груз и крепёжные ремни сейчас, потому что первую проверку нужно сделать в пределах первых 50 миль, а затем повторять каждые 3 часа или 150 миль","Проверка не нужна до остановки на заправку, если при предрейсовом осмотре груз выглядел надёжно закреплённым","Подождать, пока вы проедете первые 500 миль, а затем начать периодически осматривать груз"],"explanation":"Груз и крепления нужно проверить в первые 50 миль, затем каждые 3 часа или 150 миль и после каждого перерыва."},"101":{"q":"Во время предрейсового осмотра вы проверяете, как закреплён груз из стальных труб в грузовом отсеке за кабиной. Коллега говорит вам, что единственная реальная причина туго закреплять груз — чтобы он не поцарапался и не выглядел неаккуратно в пути. Согласно правилам перевозки грузов Техасского DPS, какова ГЛАВНАЯ причина безопасности, по которой груз должен быть надёжно закреплён?","options":["Чтобы груз оставался аккуратным и презентабельным по прибытии к месту разгрузки","Чтобы груз был защищён от дождя, дорожной пыли и оставался сухим в плохую погоду","Чтобы груз не мог сместиться, упасть с транспортного средства или сдвинуться и заблокировать органы управления водителя","Чтобы груз не замёрз и не обледенел при движении в зимних условиях"],"explanation":"Груз должен быть закреплён так, чтобы он не мог сместиться, упасть с машины или сдвинуться в кабину и заблокировать органы управления водителя."},"102":{"q":"Вы ведёте гружёный тягач с полуприцепом в западном направлении ближе к вечеру. Солнце опустилось низко к горизонту прямо перед вами, и его слепящий свет размывает дорогу, мешая оценить, насколько далеко вы видите. Машины впереди внезапно появляются из этой яркой пелены. Как лучше всего поступить в этой ситуации?","options":["Опустить солнцезащитный козырёк, надеть солнцезащитные очки и снизить скорость так, чтобы успевать остановиться в пределах фактически видимого расстояния","Включить дальний свет фар, чтобы собственное освещение пробивалось сквозь слепящий свет впереди","Сохранять скорость, но увеличить дистанцию до впереди идущего автомобиля до 6 секунд для компенсации","Перестроиться в левый ряд и ускориться, чтобы быстрее проехать ослеплённый солнцем участок дороги"],"explanation":"При ослеплении солнцем опустите козырёк, наденьте солнцезащитные очки и снизьте скорость, чтобы остановиться в пределах реально видимой дистанции."},"103":{"q":"Вы поднимаете гружёный прицеп по длинному крутому подъёму на двухполосном сельском шоссе. Двигатель работает на пределе, ваша скорость упала примерно до 15 миль/ч, что намного ниже установленного ограничения в 55 миль/ч, а сзади скапливаются автомобили. В какой из этих ситуаций включение аварийной сигнализации (четырёх указателей поворота) является НАИБОЛЕЕ уместным действием?","options":["Когда вы выполняете обычный правый поворот на следующем перекрёстке, поскольку одного указателя поворота может быть не видно","Как только вы достигнете вершины и снова поедете с разрешённой скоростью 55 миль/ч, чтобы предупредить водителей, что вы — медленный коммерческий транспорт","После того как вы оставите тягач на ночь на хорошо освещённой стоянке для грузовиков, чтобы другие видели его контур","Сейчас, пока вы ползёте вверх по подъёму намного медленнее потока, потому что вы движетесь гораздо медленнее окружающих вас машин"],"explanation":"Включайте аварийную сигнализацию, когда движетесь намного медленнее окружающего потока, например ползёте в крутой подъём, чтобы предупредить водителей сзади."},"105":{"q":"Вы приближаетесь к многополосному кольцевому перекрестку на груженом составном транспортном средстве. Автомобиль уже движется по полосе, на которую вы собираетесь въехать, и сразу позади него образуется промежуток. Какое из следующих действий является правильным и наиболее безопасным?","options":["Уступите дорогу транспортному средству, уже находящемуся на кольце, дождитесь безопасного промежутка, затем въезжайте и вливайтесь в поток движения","Сохраняйте скорость и въезжайте немедленно, так как транспортные средства, уже находящиеся на кольце, обязаны уступать дорогу въезжающим грузовикам","Остановитесь на полосе движения внутри кольца и ждите там, пока весь остальной транспорт не освободит дорогу","Если вы неправильно оцените промежуток и начнете въезжать слишком рано, сдайте назад, чтобы восстановить безопасную дистанцию перед вливанием в поток"],"explanation":"Транспорт, уже находящийся на круговом перекрёстке, имеет преимущество, поэтому уступите, дождитесь безопасного промежутка, затем въезжайте и вливайтесь в поток."},"106":{"q":"Вы везете груженый прицеп по правой полосе с разрешенной скоростью, когда водитель сзади начинает ехать вплотную, мигать дальним светом и злобно жестикулировать, потому что вы не ускоряетесь. Поток впереди не дает вам сразу сменить полосу. Какой способ ЛУЧШЕ всего подходит, чтобы справиться с этим агрессивным водителем и обеспечить собственную безопасность?","options":["Слегка нажать на тормоз, чтобы мигнуть стоп-сигналами и предупредить водителя, чтобы он отстал","Сохранять скорость и твердо держать свою полосу, чтобы водитель усвоил, что не нужно прижиматься к большим грузовикам","Когда это безопасно, перестроиться или слегка сбавить ход, чтобы освободить место и дать злому водителю проехать, не реагируя на его жесты","Ускориться выше разрешенной скорости, пока вы не оторветесь достаточно далеко, чтобы водитель перестал ехать вплотную"],"explanation":"При агрессивном водителе сзади не вступайте в конфликт; дайте ему место для обгона и сохраняйте спокойствие, чтобы разрядить ситуацию."},"107":{"q":"Сильная гроза оставила несколько дюймов стоячей воды, скопившейся в правой полосе шоссе, по которому вы едете. Вы едете порожняком со скоростью 55 миль/ч. Приближаясь к глубокой луже впереди, какое действие ЛУЧШЕ всего поможет сохранить контроль над автомобилем?","options":["Сохранять 55 миль/ч, но смещаться к обочине, поскольку отвод воды от рулевых шин восстанавливает сцепление","Снизить скорость ещё до въезда в воду, потому что вода, попавшая между шинами и дорогой, может вызвать аквапланирование и потерю управления рулём и тормозами","Уверенно прибавить газ и проехать воду, чтобы протектор шин отвёл её в сторону и шины продолжали цепляться за покрытие","Сохранять прежнюю скорость и слегка нажимать на тормоз, находясь в воде, чтобы проверить, сколько сцепления у вас осталось"],"explanation":"Снижайте скорость перед стоячей водой, потому что вода между шинами и дорогой может вызвать аквапланирование и потерю управления рулём и тормозами."},"108":{"q":"Вы едете порожняком по сухой и ясной межштатной трассе и решаете поднять крейсерскую скорость с 30 миль/ч до 60 миль/ч, чтобы наверстать время. Стажёр рядом спрашивает, как это повлияет на дистанцию, необходимую вашей фуре для торможения до полной остановки. Какой ответ ЛУЧШЕ всего описывает то, что происходит на самом деле?","options":["Поскольку грузовик порожний, более лёгкая загрузка позволит ему остановиться на 60 примерно за то же расстояние, что и на 30.","Удвоение скорости лишь немного увеличивает остановочный путь — тормозной путь растёт пропорционально скорости, поэтому он просто удваивается.","Удвоение скорости примерно вчетверо увеличивает тормозной путь, поэтому на 60 миль/ч нужно примерно в четыре раза больше места, чем на 30.","На мокром покрытии это было бы важно, но на сухой дороге более высокая скорость почти не меняет дистанцию остановки."],"explanation":"Тормозной путь возрастает пропорционально квадрату скорости, поэтому удвоение скорости увеличивает путь до остановки примерно в четыре раза."},"109":{"q":"Температура чуть ниже нуля, и лёгкий дождь покрыл дорогу ледяной коркой. Вы едете порожним, и задние колёса грузовика начинают скользить на повороте. Анализируя, что привело к этому заносу, какое из перечисленных ваших действий НАИМЕНЕЕ вероятно стало его причиной?","options":["Резкое нажатие на педаль газа, чтобы 'продавить' поворот силой тяги","Резкое торможение до блокировки колёс, как только вы почувствовали, что заднюю часть повело","Плавное и постепенное управление рулём на протяжении всего поворота","Слишком высокая скорость для обледенелых и мокрых условий"],"explanation":"Плавное, постепенное руление удерживает силы на шинах в пределах сцепления и потому не вызывает заноса, в отличие от избыточной скорости, резкого торможения или чрезмерного ускорения."},"110":{"q":"Глубокая ночь на двухполосной сельской трассе, и вы видите, как фары встречного грузовика появляются из-за подъёма примерно в 400 футах впереди. Сейчас у вас включён дальний свет. Какое действие правильное?","options":["Оставить дальний свет включённым, чтобы другой водитель лучше видел ваш крупный автомобиль","Переключиться на ближний свет сейчас же, пока расстояние между машинами не стало меньше 500 футов","Коротко мигнуть дальним светом, чтобы подать сигнал другому водителю, а затем снова оставить дальний","Слегка ускориться, чтобы разъехаться со встречным грузовиком до того, как ослепление станет проблемой"],"explanation":"Переключайтесь на ближний свет за 500 футов до встречного автомобиля, чтобы дальний свет не ослеплял другого водителя."},"111":{"q":"Вы везёте гружёную бортовую платформу по сельскому двухполосному шоссе, когда двигатель начинает терять мощность и вынуждает вас снизить скорость примерно до 30 миль/ч на дороге с разрешённой скоростью 55 миль/ч. Позади вас скапливается транспорт. Пока вы дотягиваете грузовик до ближайшего съезда, чтобы остановиться и осмотреть неисправность, какое из следующих действий было бы НЕПРАВИЛЬНЫМ использованием аварийной сигнализации (четырёх поворотников)?","options":["Оставить её включённой, чтобы предупредить более быстрый транспорт о том, что вы движетесь значительно медленнее обычной скорости потока","Выключить её и использовать только правый указатель поворота в тот момент, когда вы фактически въезжаете на съездную полосу","Снова включить её, когда вы уже остановились на обочине и осматриваете двигатель","Использовать её вместо указателя поворота, чтобы показать, что вы собираетесь повернуть направо на съезд"],"explanation":"Аварийная сигнализация предупреждает об остановленном, неисправном или медленно движущемся транспорте и никогда не заменяет указатель поворота."},"112":{"q":"Вы ведёте 40-футовый одиночный грузовик по сухой ровной автомагистрали штата, и спидометр стабильно показывает 45 миль/ч при хорошей видимости днём. Чтобы сохранить безопасный запас впереди, какова НАИМЕНЬШАЯ дистанция следования, которую вы должны выдерживать за идущим впереди транспортным средством?","options":["4 секунды, потому что для 40-футового транспортного средства нужна 1 секунда на каждые 10 футов длины","6 секунд, потому что при любой скорости выше 40 миль/ч автоматически требуется не менее 6 секунд","5 секунд, потому что 40 футов дают 4 секунды, и вы добавляете ещё 1 секунду за движение быстрее 40 миль/ч","3 секунды, поскольку дорога сухая, ровная и видимость хорошая"],"explanation":"Считайте 1 секунду на каждые 10 футов длины, поэтому 40-футовой машине нужно 4 секунды плюс ещё 1 секунда выше 40 миль/ч — всего 5 секунд."},"113":{"q":"Вы ведёте 50-футовый тягач с прицепом через дорожную зону работ, где поток поредел, а разрешённый знак позволяет двигаться с постоянной скоростью 35 миль/ч. Вы хотите выдержать безопасную дистанцию до пикапа впереди. Используя правило 1 секунда на каждые 10 футов длины транспортного средства, какая дистанция следования верна именно для этой ситуации?","options":["4 секунды, потому что в медленной зоне работ запас можно сократить на одну секунду","7 секунд: 5 секунд за длину плюс 2 дополнительные секунды за зону работ","6 секунд, потому что к расчёту по длине всегда нужно прибавлять 1 дополнительную секунду","5 секунд, потому что 50 футов разделить на 10 равно 5, и дополнительная секунда не добавляется, так как вы едете медленнее 40 миль/ч"],"explanation":"Считайте 1 секунду на каждые 10 футов длины, поэтому 50-футовой машине нужно 5 секунд, без дополнительной секунды, так как скорость ниже 40 миль/ч."},"114":{"q":"Вы ведёте 60-футовый тягач с прицепом по сухой, ровной автомагистрали с постоянной скоростью 55 миль/ч в ясную дневную погоду. Движение неплотное, и вы хотите выдержать безопасную дистанцию до автомобиля впереди. Согласно правилу дистанции следования, какую НАИМЕНЬШУЮ дистанцию следования вам следует соблюдать в этой ситуации?","options":["7 секунд","6 секунд","8 секунд","5 секунд"],"explanation":"Считайте 1 секунду на каждые 10 футов длины, поэтому 60-футовой машине нужно 6 секунд плюс ещё 1 секунда выше 40 миль/ч — всего 7 секунд."},"115":{"q":"Вы управляете одиночным прямым грузовиком длиной 30 футов от бампера до бампера. Поток на городской улице движется ровно со скоростью 30 миль/ч, что удерживает вас чуть ниже отметки 40 миль/ч. Чтобы сохранить безопасную дистанцию для вашего автомобиля в этих условиях, НАИМЕНЬШЕЕ число секунд, которое следует держать до едущего впереди транспортного средства, составляет:","options":["2 секунды, потому что при 30 милях/ч вы значительно ниже шоссейной скорости и поток движется плавно","3 секунды — по 1 секунде на каждые 10 футов длины вашего автомобиля","4 секунды, потому что к расчёту по длине всегда нужно добавлять 1 дополнительную секунду","6 секунд — столько же, сколько примерно занимает полная остановка"],"explanation":"Считайте 1 секунду на каждые 10 футов длины, поэтому 30-футовой машине нужно 3 секунды, без дополнительной секунды, так как скорость ниже 40 миль/ч."},"116":{"q":"Вы ведете автопоезд длиной 70 футов по сухой автомагистрали, держа ровную скорость 50 миль/ч при небольшом потоке. Легковой автомобиль постоянно влезает и выходит из промежутка перед вами, и вы хотите восстановить безопасную дистанцию следования, как только полоса освободится. Исходя из правила секунд для длины и скорости вашего транспортного средства, сколько секунд дистанции следования вы должны восстановить?","options":["7 секунд, потому что транспортному средству длиной 70 футов нужна 1 секунда на каждые 10 футов длины","6 секунд, потому что это рекомендуемый запас полной тормозной дистанции на скорости автомагистрали","8 секунд, потому что длина требует 7 секунд, и вы добавляете еще 1 секунду за скорость выше 40 миль/ч","9 секунд, потому что для такого длинного транспортного средства следует добавить 2 секунды при скорости выше 40 миль/ч"],"explanation":"Дистанция: 1 секунда на каждые 10 футов длины при скорости ниже 40 миль/ч, плюс 1 секунда при скорости выше 40 миль/ч, поэтому 70-футовому грузовику на 50 миль/ч нужно 8 секунд."},"117":{"q":"Вы ведёте 20-футовый одиночный грузовик через деловой центр города. Движение равномерное, разрешённая скорость 25 миль/ч, покрытие сухое, видимость хорошая. Чтобы сохранять безопасный запас впереди, какую НАИМЕНЬШУЮ дистанцию следования вы должны держать за идущим впереди транспортным средством?","options":["1 секунду, потому что длина грузовика всего 20 футов","4 секунды: 1 секунда добавлена к базовой и ещё 1 за городское движение","3 секунды, так как над базовым значением всегда нужно добавлять 1 секунду","2 секунды, по одной секунде на каждые 10 футов длины транспортного средства"],"explanation":"При скорости ниже 40 миль/ч дистанция составляет 1 секунду на каждые 10 футов длины автомобиля, поэтому 20-футовому автомобилю нужно 2 секунды."},"118":{"q":"Вы ведёте 80-футовый автопоезд по сухой автомагистрали, держа ровную скорость 60 миль/ч при небольшом трафике. Коллега говорит, что достаточно оставлять «одну секунду на каждые десять футов» при любой скорости. Используя правильный метод Texas DPS для расчёта дистанции с учётом вашей длины и скорости, какова МИНИМАЛЬНАЯ дистанция следования, которую вы должны сохранять за идущим впереди транспортом?","options":["9 секунд — 8 секунд за 80 футов длины плюс 1 дополнительная секунда, потому что вы едете быстрее 40 миль/ч","8 секунд — 1 секунда на каждые 10 футов вашего 80-футового автопоезда без поправки на скорость","10 секунд — 8 секунд за длину плюс 2 секунды, потому что вы на 20 миль/ч превышаете порог в 40 миль/ч","7 секунд — 1 секунда на каждые 10 футов, затем минус 1 секунда, потому что сухое покрытие даёт хорошее сцепление"],"explanation":"При скорости ниже 40 миль/ч давайте 1 секунду на каждые 10 футов длины и добавляйте 1 секунду при скорости выше 40 миль/ч, поэтому 80-футовому автомобилю на 60 миль/ч нужно 9 секунд."},"119":{"q":"Вы ведете 50-футовый тягач с прицепом по сухой ровной автомагистрали, и спидометр стабильно показывает 45 миль/ч при небольшом трафике. Легковой автомобиль впереди постоянно притормаживает, поэтому вы хотите выдержать безопасную дистанцию по правилу секунд. Сколько секунд интервала следует держать за этим автомобилем?","options":["5 секунд, потому что ваша машина длиной 50 футов, а это дает 1 секунду на каждые 10 футов","6 секунд, потому что 50 футов дают 5 секунд, и вы добавляете еще 1 секунду за скорость выше 40 миль/ч","7 секунд, добавляя 2 лишние секунды к расчету по длине, поскольку вы на автомагистрали","4 секунды, ведь 45 миль/ч лишь немного выше 40, и на сухом покрытии достаточно меньшего интервала"],"explanation":"Используйте 1 секунду на каждые 10 футов длины при скорости ниже 40 миль/ч и добавьте 1 секунду при скорости выше 40 миль/ч, поэтому 50-футовому автомобилю на 45 миль/ч нужно 6 секунд."},"120":{"q":"Вы ведете 60-футовый автопоезд (тягач с полуприцепом) через город и пристраиваетесь позади более медленного грузовика доставки. Спидометр устойчиво показывает 35 миль/ч по сухому покрытию. Какую дистанцию в секундах следует держать до идущего впереди транспортного средства, чтобы дистанция была безопасной для вашего автопоезда на этой скорости?","options":["5 секунд, потому что на сухом покрытии в хороших условиях вычитают одну секунду","8 секунд: одна секунда на каждые 10 футов плюс две дополнительные секунды за полуприцеп","6 секунд: одна секунда на каждые 10 футов длины транспортного средства","7 секунд: одна секунда на каждые 10 футов плюс одна секунда, потому что вы движетесь"],"explanation":"При скорости ниже 40 миль/ч дистанция составляет 1 секунду на каждые 10 футов длины без добавления дополнительной секунды, поэтому 60-футовому автомобилю на 35 миль/ч нужно 6 секунд."},"121":{"q":"Вы везёте неполный груз по двухполосному шоссе, когда начинается лёгкая ледяная морось и дорожное покрытие начинает блестеть. За следующую милю вы делаете три вещи: вы сохраняете прежнюю скорость, хотя видимость и сцепление ухудшились; вы резко жмёте на тормоз, когда на дорогу выбегает олень; и через мгновение резко жмёте на газ, чтобы набрать скорость на небольшом подъёме. Коллега потом утверждает, что только ОДНО из этих действий реально могло вызвать занос. Какое утверждение верное?","options":["Только резкое экстренное торможение могло вызвать занос, потому что блокировка колёс — единственный способ потерять сцепление.","Только слишком высокая скорость для обледенелой дороги могла вызвать занос, ведь большинство заносов вызваны избыточной скоростью.","Каждое из трёх действий — излишняя скорость для условий, резкое экстренное торможение и резкое ускорение — могло само по себе вызвать занос.","Только резкое ускорение могло вызвать занос, потому что при неполной (лёгкой) загрузке на ведущие колёса приходится слишком мало веса для сцепления."],"explanation":"Занос возникает при потере сцепления колес, и слишком высокая скорость для условий, слишком резкое торможение или слишком резкий разгон каждый по отдельности могут его вызвать."},"122":{"q":"Вы ведёте гружёный полуприцеп по сельской двухполосной автодороге. Только что начался лёгкий дождь, и покрытие блестит от влаги; впереди вы видите знак крутого поворота, а в низине за поворотом оседает полоса тумана, из-за которой дорогу далеко не видно. Один коллега как-то сказал вам, что снижать скорость нужно только из-за одной самой серьёзной опасности за раз. Какое действие лучше всего отражает безопасную практику вождения с CDL в этой ситуации?","options":["Сохранять скоростной режим на мокром участке и снизить скорость только когда вы фактически достигнете поворота, поскольку поворот — самая серьёзная отдельная опасность","Держать скорость постоянной, потому что вас защищает дистанция следования, а не скорость, когда несколько мелких опасностей возникают одновременно","Снизить скорость только из-за тумана в низине, потому что ограниченная видимость — единственное условие, которое юридически требует более низкой скорости","Снизить скорость с учётом всех трёх условий сразу, потому что мокрое покрытие, поворот и ограниченная видимость каждое по отдельности требуют более низкой скорости"],"explanation":"Мокрое покрытие, повороты и ограниченная видимость каждый по отдельности снижают безопасную скорость, поэтому снижайте скорость при всех этих условиях и ещё больше, когда они сочетаются."},"123":{"q":"Сейчас 6:00 утра, и вы проводите предрейсовый осмотр тягача с прицепом перед длительной поездкой по межштатной трассе. Вы открываете ящик с аварийным оборудованием за сиденьем, чтобы убедиться, что он полностью укомплектован на случай поломки на обочине. Какой набор предметов представляет ПОЛНЫЙ комплект аварийного оборудования, который вы обязаны иметь при себе?","options":["Три светоотражающих аварийных треугольника, запасные электрические предохранители (если только автомобиль не оснащён автоматическими выключателями) и исправный огнетушитель надлежащего класса","Три светоотражающих аварийных треугольника и исправный огнетушитель надлежащего класса, но запасные предохранители необязательны","Исправный огнетушитель надлежащего класса и запасные электрические предохранители, а также комплект цепей противоскольжения для зимних маршрутов","Три светоотражающих аварийных треугольника, аптечка первой помощи и исправный огнетушитель надлежащего класса"],"explanation":"Обязательное аварийное оборудование: три светоотражающих аварийных треугольника, запасные предохранители (если не используются автоматические выключатели) и заряженный огнетушитель надлежащего класса."},"124":{"q":"Вы отстаете от графика на 30 минут на разделенном шоссе с установленным ограничением 65 миль/ч. Поток во всех полосах движется со скоростью около 72 миль/ч, покрытие сухое, а дорога впереди свободна и пуста на четверть мили. По правилам DPS Техаса, какое из этих условий делало бы допустимым движение быстрее установленного ограничения в 65 миль/ч?","options":["Когда общий поток окружающего транспорта движется выше ограничения, и вы держите темп, чтобы не создавать помеху","Когда вы отстаете от графика, а сухое чистое покрытие позволяет безопасно наверстать потерянное время","Ни одно из этих условий не оправдывает превышение установленного ограничения","Когда дорога впереди свободна на четверть мили, что дает вам полную дистанцию торможения"],"explanation":"Установленное ограничение скорости — это максимально допустимая скорость для идеальных условий, и его нельзя превышать ни при каких обстоятельствах."},"125":{"q":"Вы ведёте гружёный тягач с полуприцепом по двухполосному шоссе позади медленного сельскохозяйственного грузовика, едущего со скоростью 40 миль/ч на участке с ограничением 60 миль/ч. Вам не терпится его обогнать, и вы видите впереди четыре возможности. Какое из этих мест действительно БЕЗОПАСНО для завершения обгона?","options":["На длинном пологом повороте впереди, где вы частично видите за изгиб дороги","Прямо перед вершиной холма, пока у вас ещё есть обзор впереди","Ни одно из этих мест не даёт достаточной видимости для безопасного обгона","Через приближающийся сельский перекрёсток, ведь поперечный поток обязан уступить дорогу шоссе"],"explanation":"Для безопасного обгона на двухполосной дороге нужна достаточная видимость впереди, которую перекрывают повороты, вершины холмов и перекрёстки."},"126":{"q":"Вы отстаёте от графика на 40 минут при срочной доставке. Тот же седельный тягач с прицепом прошёл полный предрейсовый осмотр, когда вы управляли им вчера, погода ясная и сухая, а беглый обход не выявил явных неисправностей. При каком из этих условий вам законно и безопасно разрешено пропустить сегодняшний предрейсовый осмотр перед выездом?","options":["Когда вы отстаёте от графика и задержка грозит сорвать срок доставки","Когда транспортное средство прошло осмотр накануне и с тех пор не было замечаний","Ни одно из этих условий не оправдывает пропуск предрейсового осмотра","Когда беглый обход не выявил видимых дефектов, а условия благоприятные"],"explanation":"Предрейсовый осмотр обязателен перед каждой поездкой без исключений, поскольку состояние транспортного средства может измениться в любой момент."},"127":{"q":"Только что стемнело, вы едете по узкой неосвещённой двухполосной просёлочной дороге с гружёным прицепом. Встречная машина выезжает на подъём примерно в 400 футах впереди с включённым дальним светом, который бьёт прямо вам в глаза и засвечивает всё перед капотом. До встречи остаётся всего пара секунд. Какое действие безопаснее всего, чтобы удержать тягач под контролем, пока машина не проедет?","options":["Включите собственный дальний свет, чтобы его большая дальность позволила вам разглядеть дорогу за пределами слепящего света встречного водителя.","Опустите взгляд к правому краю своей полосы и сбросьте скорость, пока встречная машина не проедет.","Несколько раз быстро моргните дальним светом, чтобы встречный водитель понял проблему и переключился на ближний.","Зафиксируйте взгляд на осевой линии прямо перед собой и держите скорость постоянной, чтобы не отклониться, пока машина не проедет."],"explanation":"Если вас слепит дальний свет встречного автомобиля, смотрите на правый край своей полосы как на ориентир и сбавьте скорость, пока автомобиль не проедет."},"131":{"q":"Вы едете со скоростью около 55 миль/ч по автомагистрали, когда внезапный сильный ливень оставляет плёнку стоячей воды на покрытии. Руль внезапно становится лёгким и слабым в ваших руках, и вы понимаете, что передние шины тягача потеряли плотный контакт с дорогой и всплывают на воде. Какое действие даёт вам наилучший шанс безопасно восстановить сцепление?","options":["Нажать на тормоз твёрдо и равномерно и резко повернуть руль к обочине, чтобы заставить передние шины вернуться на покрытие.","Сохранять скорость, но быстро прокачивать тормоза, чтобы шины пробились сквозь плёнку воды, не блокируясь.","Отпустить педаль газа, держать руль прямо и дать грузовику постепенно замедлиться, пока шины не восстановят сцепление.","Сильнее нажать на газ и держать ведущие колёса вращающимися, чтобы вытеснить стоячую воду из-под шин."],"explanation":"При аквапланировании шины теряют сцепление, поэтому отпустите педаль газа, держите руль прямо и дайте грузовику замедлиться, пока сцепление не восстановится."},"133":{"q":"Вы ведёте гружёный полуприцеп по правой полосе четырёхполосного шоссе с разделительной полосой, двигаясь с разрешённой скоростью 60 миль/ч. Пикап вплотную приблизился сзади, идёт всего в нескольких футах от вашего бампера, многократно мигает дальним светом и виляет, словно ищет возможность обогнать. Слева есть свободная полоса, а впереди плотный поток. Какая реакция самая безопасная и юридически верная?","options":["Слегка несколько раз нажать на тормоз, чтобы вспышками стоп-сигналов дать понять водителю сзади, что нужно отстать и создать дистанцию.","Сохранять текущую скорость и положение в полосе, чтобы агрессивный водитель не смог заставить вас изменить ваши действия.","Разогнаться примерно до 70 миль/ч, чтобы оторваться от того, кто едет вплотную, ведь уйдя вперёд от агрессивного водителя, вы устраняете конфликт.","Сбросить газ, чтобы увеличить дистанцию впереди себя, затем включить сигнал и перестроиться в левую полосу, если она свободна, чтобы пропустить этого водителя."],"explanation":"При агрессивном водителе, едущем вплотную сзади, отпустите газ, чтобы увеличить пространство впереди, затем включите сигнал и перестройтесь, чтобы дать ему безопасно проехать."},"134":{"q":"Вы везёте гружёный прицеп по автомагистрали и вдруг чувствуете резкий запах горелой резины, а в правом зеркале замечаете серый дым, тянущийся от задней части вашего состава. Движение умеренное, а в нескольких сотнях футов впереди есть широкая асфальтированная обочина. Каков НАИЛУЧШИЙ порядок действий?","options":["Заранее включите сигнал поворота, полностью съедьте на обочину подальше от другого транспорта, заглушите двигатель и осмотрите источник дыма, пока ситуация не ухудшилась.","Сохраняйте скорость и доезжайте до следующего съезда, ведь встречный поток воздуха на скорости магистрали, скорее всего, охладит участок и дым рассеется сам.","Остановитесь на обочине, но не глушите двигатель, а затем сразу же распахните задние двери прицепа, чтобы выпустить скопившийся дым и жар.","Сбавьте скорость и продолжайте медленно ехать по обочине, пока пассажир поливает водой задние шины, чтобы охладить их, не останавливаясь полностью."],"explanation":"Дым или запах гари может означать начинающийся пожар, поэтому полностью съезжайте с дороги в сторону от движения, заглушите двигатель и осмотрите источник, пока ситуация не ухудшилась."},"135":{"q":"Вы ведёте гружёный полуприцеп по сельской двухполосной трассе и въезжаете в густую полосу тумана, настолько плотного, что вы едва различаете дорожную разметку на небольшом расстоянии впереди. Движение слабое. Какое действие является самым безопасным и правильным на этом участке?","options":["Включить дальний свет, чтобы более яркий луч пробил туман и позволил раньше разглядеть разметку.","Снизить скорость, оставить включённым ближний свет, а если вы всё равно плохо видите дорогу — полностью съехать с проезжей части и подождать, пока туман рассеется.","Сохранять обычную скорость, но ориентироваться на задние фонари идущей впереди машины и следовать за ними как за ориентиром сквозь туман.","Ускориться, чтобы как можно быстрее и безопасно для гружёного тягача проехать туманный участок, а затем вернуться к крейсерской скорости."],"explanation":"В тумане снижайте скорость и используйте ближний свет, так как дальний свет отражается от капель воды и усиливает блики, а если видимости всё равно недостаточно — полностью съезжайте с дороги."},"136":{"q":"Конец вашей смены, и вам нужно задним ходом завести 53-футовый полуприцеп в узкий погрузочный док на складе, где вы никогда не были. Помощника-сигнальщика нет, док сейчас пуст, и вам не терпится закончить. Какие действия самые безопасные и правильные?","options":["Поскольку позади сейчас свободно, заезжайте задним ходом без промедления на ровной скорости, чтобы закончить до того, как появятся погрузчики или рабочие.","Подзовите проходящего рабочего и поставьте его прямо позади прицепа, чтобы он наблюдал и махал вам, пока вы сдаёте назад.","Выйдите из кабины и пройдите весь путь позади прицепа, проверяя препятствия и габариты, затем медленно сдавайте назад, используя зеркала с обеих сторон.","Полагайтесь только на зеркала и сдавайте назад на постоянной скорости, не выходя из кабины, ведь остановка для осмотра лишь замедлит вас."],"explanation":"Без помощника применяйте метод «выйди и посмотри»: пройдите весь путь позади прицепа, проверяя препятствия и габариты, затем медленно сдавайте назад, пользуясь обоими зеркалами."},"137":{"q":"Вы ведёте гружёный полуприцеп по сухой автостраде на скорости 55 миль/ч, когда далеко впереди в вашей полосе внезапно появляется заглохший автомобиль. Инструктор просит вас разложить КАЖДУЮ часть расстояния, которое ваш тягач фактически прошёл с момента, когда опасность попала в поле зрения, до полной остановки. Какое разложение правильно называет три отдельные части, из которых складывается общий тормозной путь?","options":["Расстояние, пройденное за вашу реакцию в 3/4 секунды, плюс тормозной путь после срабатывания тормозов — время восприятия уже входит в время реакции и отдельно не учитывается","Только тормозной путь, потому что именно на этом участке грузовик физически замедляется и это единственная часть, которую вы можете контролировать","Дистанция следования, расстояние подачи сигнала и зазор при парковке у обочины","Расстояние восприятия, расстояние реакции и тормозной путь"],"explanation":"Полный тормозной путь состоит из трёх частей: расстояния восприятия, расстояния реакции и тормозного пути."},"138":{"q":"Вы остановились пообедать во время дальнего рейса, и друг предлагает вам одно пиво к еде. После этого вы чувствуете себя совершенно трезвым и без труда проходите по прямой линии. Прежде чем снова сесть за руль вашего тягача с прицепом, какое утверждение о законном пределе концентрации алкоголя в крови (BAC) для управления вашим коммерческим транспортным средством верно?","options":["Вы юридически превышаете предел и не имеете права управлять коммерческим ТС при BAC 0,04 процента, что составляет половину предела, установленного для обычного легкового автомобиля.","Вы юридически превышаете предел и не имеете права управлять коммерческим ТС при BAC 0,08 процента — это тот же предел, что и для обычного легкового автомобиля.","Вы можете ехать, пока ваш BAC остаётся ниже 0,10 процента, потому что для крупных транспортных средств действует более высокий порог.","Главное — чувствовать себя трезвым, поэтому вы можете ехать, как только перестанете ощущать опьянение, независимо от какого-либо конкретного числа BAC."],"explanation":"Законный предел алкоголя в крови для управления коммерческим транспортом — 0,04 процента, ровно половина предела в 0,08 процента для легкового автомобиля, поэтому при 0,04 вы уже превысили норму."},"139":{"q":"Вы только что отдыхали 10 часов подряд в спальном отсеке и начинаете новую смену. Диспетчер говорит, что рейс длинный, и спрашивает, сколько фактического времени вы можете легально вести машину, прежде чем федеральные правила режима труда и отдыха (HOS) обяжут вас прекратить вождение на этот день. Считая, что это чистое вождение (без чрезмерных задержек на дежурстве, которые рано закрыли бы ваше 14-часовое окно), каково максимально разрешённое время вождения?","options":["До 8 часов вождения, потому что сначала нужно сделать 30-минутный перерыв","До 11 часов времени вождения","До 14 часов времени вождения","До 16 часов времени вождения"],"explanation":"После 10 часов подряд вне службы федеральные правила режима труда и отдыха разрешают максимум 11 часов времени за рулём."},"140":{"q":"Вы за рулём с самого раннего утра, ещё до рассвета, а сейчас уже середина дня. Вы замечаете, что машину уводит в полосе, веки тяжелеют, и вы не помните последние несколько миль пути. Впереди ещё несколько часов маршрута и жёсткое окно для доставки. Какое из перечисленных действий является ЕДИНСТВЕННЫМ, которое действительно вернёт вам бдительность и безопасно устранит это состояние?","options":["Остановиться на ближайшей стоянке, выпить две чашки крепкого кофе и ехать дальше, чтобы не выбиться из графика","Открыть окна, чтобы впустить холодный свежий воздух, и включить радио погромче, чтобы взбодрить себя","Съехать с дороги, как только это будет безопасно, прекратить движение и как следует выспаться, прежде чем продолжать путь","Открыть энергетический напиток, плотно поесть и увеличить дистанцию до впереди идущего транспорта в качестве компенсации"],"explanation":"Только настоящий, достаточный сон восполняет недостаток сна, поэтому при усталости безопасно съезжайте с дороги, прекращайте движение и выспитесь, прежде чем продолжить."},"141":{"q":"Вы едете с грузом по ровной открытой сельской автомагистрали со скоростью 55 миль/ч в ясную сухую погоду. Движение слабое, и впереди у вас длинный непрерывный обзор дороги. Чтобы правильно управлять временем визуального опережения, насколько далеко вперёд вы должны постоянно смотреть и сканировать дорогу на предмет опасностей?","options":["Только на транспортное средство прямо перед вами, поскольку на скорости 55 миль/ч всё, что дальше, пока не представляет угрозы","Примерно на 30–40 секунд вперёд, чтобы иметь максимально возможное время реакции на открытой автомагистрали","Примерно на 1–2 секунды вперёд, что приблизительно соответствует вашей безопасной дистанции следования на этой скорости","Примерно на 12–15 секунд вперёд, что на скорости 55 миль/ч составляет примерно четверть мили или около одного городского квартала в городе"],"explanation":"Держите взгляд в движении и смотрите на 12–15 секунд вперёд — это примерно четверть мили на трассе или один квартал в городе, чтобы заранее замечать опасности."},"142":{"q":"Вы ведёте гружёный полуприцеп по загруженному четырёхполосному техасскому шоссе на трассовой скорости. Движение плотное, машины постоянно заезжают в ваши слепые зоны и перестраиваются вокруг вас. Чтобы постоянно иметь точную, актуальную картину того, что происходит сзади и сбоку от вашего автопоезда, как вы должны пользоваться зеркалами?","options":["Смотреть в зеркала только непосредственно перед сменой полосы или перестроением, ведь именно тогда движение в слепых зонах важнее всего","Проверять зеркала примерно каждые 12–15 секунд, в соответствии с тем, как далеко вперёд вы смотрите по дороге","Смотреть в зеркала непрерывно и неотрывно, чтобы ваш взгляд никогда не возвращался на дорогу впереди","Регулярно просматривать зеркала, примерно каждые 5–8 секунд, в дополнение к проверке перед каждой сменой полосы"],"explanation":"Регулярно проверяйте зеркала, примерно каждые 5–8 секунд, в дополнение к проверке перед каждой сменой полосы, чтобы следить за движением и слепыми зонами."},"143":{"q":"Сырой пасмурный день, и вам нужно сдать тягач с прицепом задним ходом к погрузочной площадке в узком переулке. Видимость плохая, правая сторона прицепа уходит в тень, а помощника-сигнальщика у вас нет. Чтобы выполнить манёвр максимально безопасно, в сторону какой стороны вам следует сдавать назад?","options":["В сторону правой (слепой) стороны, потому что увод прицепа от себя даёт тягачу больше места для разворота","В сторону с наибольшим движением, чтобы другие водители видели вас и пропускали прицеп","В ту сторону, где площадка ближе, чтобы сократить расстояние, которое нужно проехать задним ходом","В сторону водителя (левую), чтобы вы могли наблюдать за всей длиной прицепа через своё боковое окно"],"explanation":"Сдавая назад в сторону водителя (влево), вы видите весь прицеп через своё окно, поэтому задняя часть и её траектория всё время остаются на виду."},"144":{"q":"Во время предрейсового осмотра вы закрепляете одну стальную балку длиной 38 футов на бортовой платформе. Вы хотите использовать НАИМЕНЬШЕЕ количество креплений (стяжек), которое всё ещё соответствует федеральному минимуму по закреплению в зависимости от длины (предел рабочей нагрузки уже обеспечен). Какое наименьшее количество стяжек допускает правило для этого груза?","options":["2 стяжки, потому что любой предмет длиннее 5 футов всегда требует ровно двух","3 стяжки, потому что вы перепроверяете крепление каждые 3 часа","8 стяжек, потому что нужна одна на каждые 5 футов длины груза","4 стяжки, потому что нужна одна на каждые 10 футов длины груза"],"explanation":"Груз требует минимум одной стяжки на каждые 10 футов длины, поэтому 38-футовая балка округляется до четырёх стяжек."},"145":{"q":"Температура чуть ниже нуля, и вы на груженом тягаче с прицепом приближаетесь к повороту на мосту. Когда вы поворачиваете рулевое колесо, чтобы вписаться в поворот, передние колёса теряют сцепление на льду. Каков НАИБОЛЕЕ вероятный результат этого заноса передних колёс и как поведёт себя автомобиль?","options":["Автомобиль продолжает двигаться прямо вперёд и едет так независимо от того, куда вы поворачиваете руль, пока передние шины не восстановят сцепление.","Задние ведущие колёса заносит в сторону, и прицеп начинает складываться позади кабины (джекнайф).","Автомобиль входит в поворот круче, чем вы рассчитывали, и его нос тянет к внутренней стороне поворота.","Руль становится тяжелее, передние колёса цепляются сильнее, и грузовик чрезмерно отклоняется в ту сторону, куда вы повернули."],"explanation":"При заносе передних колёс передние шины теряют сцепление, поэтому руление не действует, и машина продолжает двигаться прямо, пока передние шины не восстановят сцепление."},"146":{"q":"Вы ведёте гружёный тягач с прицепом без ABS на скорости по трассе, когда легковой автомобиль внезапно подрезает вас и резко тормозит впереди. Вам нужно максимальное торможение, но при этом сохранить контроль над автопоездом и возможность рулить. Применяя метод контролируемого торможения, что вы должны делать с педалью тормоза?","options":["Выжать педаль до упора, чтобы заблокировать колёса и остановиться как можно короче","Прикладывать твёрдое, ровное давление на педаль чуть ниже порога блокировки колёс, ослабляя нажим только если колёса начинают блокироваться","Быстро и сильно качать педаль снова и снова, чтобы колёса продолжали вращаться","Не трогать ножной тормоз и замедлять автопоезд только ручным краном прицепа"],"explanation":"Контролируемое торможение — это уверенное, ровное давление на педаль чуть ниже точки блокировки колёс, ослабляемое только если они начинают блокироваться, чтобы сохранить управление."},"147":{"q":"Вы спускаетесь по длинному крутому горному уклону с полностью загруженным прицепом. На вершине вы включили пониженную передачу, но на середине спуска чувствуете запах гари, педаль тормоза с каждым нажатием становится мягче, а грузовик постепенно набирает скорость, несмотря на лёгкое и равномерное торможение. Впереди знак: 'АВАРИЙНЫЙ СЪЕЗД ДЛЯ ГРУЗОВИКОВ 1 МИЛЯ'. Учитывая, для чего предназначен этот съезд, какое утверждение верно?","options":["Это обязательная зона отдыха, где каждый загруженный грузовик должен остановиться, чтобы тормоза остыли перед дальнейшим спуском.","Это обслуживаемый короткий путь, позволяющий покинуть уклон и быстрее добраться до подножия, пока перегретые тормоза восстанавливаются.","Это аварийный съезд (улавливающий тупик), спроектированный для безопасной остановки транспортного средства, у которого тормоза отказали или ослабли из-за перегрева.","Это асфальтированная площадка, где можно продолжать медленно катиться, чтобы тормоза отдавали тепло, ни разу не останавливаясь полностью."],"explanation":"Аварийный съезд для грузовиков — это специальная полоса экстренного торможения, рассчитанная на безопасную остановку машины при отказе или перегреве тормозов."},"148":{"q":"Вы едете со скоростью 55 миль/ч по сухой автомагистрали, когда впереди вас внезапно подрезает машина и резко тормозит. Позже инструктор просит вас разложить общий тормозной путь на составляющие. Он напоминает, что ваш ОБЩИЙ тормозной путь на этой скорости составляет примерно 419 футов. Какую часть этого пути ваш грузовик проезжает ТОЛЬКО за время реакции -- промежуток между моментом, когда вы увидели опасность, и моментом, когда ваша нога фактически нажимает на педаль тормоза, до того как тормоза начали хоть как-то замедлять машину?","options":["Около 419 футов, потому что грузовик продолжает катиться на полной скорости всё это время, пока наконец не остановится","Около 250 футов, поскольку примерно настолько добивает ближний свет фар и настолько далеко вы способны среагировать","Около 6 футов, потому что на скорости магистрали ваши натренированные рефлексы переносят ногу почти мгновенно","Около 60 футов -- примерно столько проезжает грузовик за три четверти секунды, которые требуются среднему водителю для реакции"],"explanation":"Дистанция реакции — это путь после обнаружения опасности до начала торможения: при 55 миль/ч за обычные три четверти секунды грузовик проезжает около 60 футов."},"149":{"q":"Вы приближаетесь к городскому перекрёстку на загруженном составном транспортном средстве, когда светофор переключается на постоянный (немигающий) красный сигнал. Движение слабое, и в данный момент вы не видите ни поперечного транспорта, ни пешеходов. Какое действие юридически обязательно для вас как для водителя с CDL?","options":["Снизить скорость почти до нуля и проехать перекрёсток, поскольку поперечного движения нет","Расценивать постоянный красный точно так же, как мигающий красный: уступить дорогу, но не обязательно останавливаться, если путь свободен","Полностью остановиться и оставаться на месте, пока сигнал не сменится на зелёный","Останавливаться, только если транспортное средство или пешеход реально на вашем пути, иначе продолжать движение"],"explanation":"Постоянный красный сигнал требует полной остановки и стоять, пока сигнал не сменится на зелёный."},"150":{"q":"Вы ведёте гружёный седельный тягач с прицепом по сухой открытой автомагистрали со скоростью 55 миль/ч и замечаете заглохший автомобиль с поднятым капотом примерно в четверти мили (12-15 секунд) впереди на вашей полосе. Движение на соседней полосе плотное, поэтому перестроиться вы пока не можете. Какое первое действие будет НАИЛУЧШИМ?","options":["Сохранять скорость и ждать, пока до препятствия не останется около 200 футов, прежде чем реагировать, ведь этого расстояния достаточно","Кратковременно ускориться, чтобы создать просвет и втиснуться в соседнюю полосу до того, как вы доедете до заглохшего автомобиля","Немедленно резко затормозить, чтобы сбросить как можно больше скорости до того, как вы достигнете препятствия","Отпустить педаль газа и держать ногу над тормозом, чтобы быть готовым плавно сбросить скорость по мере развития ситуации"],"explanation":"Когда опасность далеко впереди, отпустите педаль газа и держите ногу над тормозом, чтобы плавно замедлиться без резкой остановки."},"151":{"q":"Вы ведёте 60-футовый автопоезд по сухой, чистой двухполосной автомагистрали со скоростью 35 миль/ч и хотите сохранить правильную дистанцию до машины впереди. Исходя из длины вашего транспортного средства, какова МИНИМАЛЬНАЯ безопасная дистанция следования в этих хороших условиях?","options":["Около 6 секунд — одна секунда на каждые 10 футов длины вашего транспортного средства","Около 7 секунд — одна секунда на каждые 10 футов плюс одна дополнительная секунда за скорость","Фиксированные 4 секунды, поскольку 4 секунды — это стандартный интервал для любого транспортного средства в хорошую погоду","Никакой измеренной дистанции не требуется при 35 миль/ч, потому что эта скорость достаточно низкая, чтобы быстро остановиться"],"explanation":"На каждые 10 футов длины машины оставляйте одну секунду дистанции, поэтому 60-футовому автопоезду нужно около 6 секунд при скорости до 40 миль/ч."},"152":{"q":"Раннее утро, вы проводите предрейсовый осмотр. Вы запускаете двигатель и смотрите на приборы на панели. Что должно произойти с указателем давления масла (или контрольной лампой давления масла) в первые мгновения после запуска, прежде чем вы решите, что грузовик безопасен для движения?","options":["Давление масла должно оставаться на нуле, пока двигатель холодный, и подниматься только после нескольких миль езды.","Давление масла должно подняться до нормального значения вскоре после запуска (а контрольная лампа давления масла должна погаснуть).","Контрольная лампа давления масла должна гореть всё время работы двигателя; именно так вы понимаете, что система смазки работает.","Давление масла должно кратко подскочить значительно выше нормы и остаться там, ведь повышенное значение означает хорошую смазку."],"explanation":"Вскоре после запуска давление масла должно подняться до нормы, а контрольная лампа давления масла погаснуть, что подтверждает работу системы смазки."},"153":{"q":"Жаркий день, и вы тянете тяжёлый груз в гору по длинному подъёму на пониженной передаче. Взглянув на приборную панель, вы замечаете, что стрелка указателя температуры охлаждающей жидкости поднимается значительно выше нормального диапазона. Исходя из того, для чего именно предназначен этот прибор, о каком состоянии он вас предупреждает?","options":["Уровень топлива в баке становится опасно низким, и вам скоро нужно заправиться","Фары потускнели, потому что генератор перестал заряжать аккумулятор","Двигатель перегревается и может быть повреждён, если вы продолжите подъём с такой нагрузкой","Давление моторного масла упало слишком низко для нормальной смазки движущихся частей"],"explanation":"Стрелка температуры охлаждающей жидкости выше нормы означает, что двигатель перегревается и может выйти из строя при продолжении движения под нагрузкой."},"154":{"q":"Во время предрейсового осмотра холодным утром вы запускаете двигатель и смотрите на манометр давления воздуха. Вы замечаете, что давление воздуха в ресиверах поднимается очень медленно к рабочему диапазону, и на это уходит гораздо больше времени, чем обычно. Регулятор компрессора ещё не отключился. Какое из следующих объяснений НАИБОЛЕЕ вероятно для такого медленного нарастания давления?","options":["Компрессор в отличном состоянии и просто защищает систему, постепенно наращивая давление","Ваши ресиверы уже заполнены, поэтому манометр показывает лишь остаточное давление","Ваши рабочие тормоза в очень хорошем состоянии, что замедляет поступление воздуха в ресиверы","В системе есть утечка воздуха или компрессор слабый, поэтому давление нарастает медленнее, чем должно"],"explanation":"Слишком медленный набор давления воздуха указывает на утечку в системе или слабый компрессор, не справляющийся с потребностью."},"155":{"q":"Раннее утро, температура чуть ниже нуля, вы проводите предрейсовый осмотр. Вы поднимаете капот и проводите рукой по приводным ремням двигателя, а также по шлангам радиатора и отопителя. Какая находка является реальным дефектом безопасности, который вы ищете, тем, из-за которого этот грузовик нельзя выпускать в рейс?","options":["Трещины, разлохмачивание, мягкие участки или следы протечек на ремнях и шлангах","Ремни и шланги, утратившие заводской блеск и теперь выглядящие тусклыми и пыльными","Шланги, на которых больше не видна читаемая фирменная бирка производителя","Ремень, ставший темнее по сравнению с ярким цветом, который он имел, когда был новым"],"explanation":"Осматривайте ремни и шланги на трещины, потёртости, мягкие места и следы утечек, так как такие повреждения ведут к поломке или отказу двигателя."},"156":{"q":"Во время предрейсового осмотра холодным утром вы обнаруживаете тонкую трещину, проходящую через один из стальных дисков колеса на заднем ведущем мосту, а на другом колесе две гайки крепления заметно ослаблены. Сами шины держат давление и имеют хороший протектор. Диспетчер торопит вас выехать в рейс, потому что груз срочный. Как правильно поступить с этим автомобилем?","options":["Поскольку шины держат давление и имеют хороший протектор, колёса достаточно безопасны; можно осторожно доехать до мастерской и показать их после доставки.","Треснувший диск и ослабленные гайки крепления являются дефектами, требующими вывода из эксплуатации; автомобиль нельзя эксплуатировать, пока они не будут устранены.","Подтяните ослабленные гайки вручную и следите за треснувшим диском; если трещина не увеличится за первые 50 миль, можно продолжить рейс.","Это проблема только на управляемом мосту; так как это задние ведущие колёса, треснувший диск и ослабленные гайки там — мелкий износ, и автомобиль исправен."],"explanation":"Треснувшие диски и ослабленные колёсные гайки относятся к дефектам, запрещающим эксплуатацию, поэтому машину нельзя водить до их устранения."},"158":{"q":"Во время предрейсового осмотра во дворе вы обнаруживаете свежую лужу жидкости на асфальте прямо под тягачом. Уровни в бачках всё ещё в пределах нормы, двигатель заводится и работает нормально. Вы уже опаздываете к окну доставки. Каковы правильные действия?","options":["Отметить уровень жидкости, на всякий случай долить бачок и продолжить рейс, раз приборы показывают норму","Пока оставить как есть и перепроверить лужу на первой остановке в пределах первых 50 миль, чтобы увидеть, не усиливается ли течь","Не выезжать, пока вы не найдёте источник течи и не устраните неисправность, даже если из-за этого опоздаете","Вытереть лужу, записать осмотр как удовлетворительный и внимательно следить за приборами во время движения"],"explanation":"Известная утечка жидкости — это дефект, способный привести к серьёзному отказу, поэтому не выезжайте, пока не найдёте источник и не устраните его, даже с опозданием."},"159":{"q":"Перед самым рассветом вы выполняете предрейсовый осмотр, обходя машину. Несколько задних световозвращателей и два габаритных/задних фонаря покрыты засохшей дорожной грязью, а один задний фонарь светит тускло даже при включённых огнях. В остальном грузовик загружен и готов к выезду. Какое действие лучше всего соответствует стандарту проверки огней и световозвращателей перед выездом?","options":["Не трогать световозвращатели, так как они пассивные, но заменить любую лампу заднего фонаря, которая не загорается","Протереть только фонари, питающиеся от электричества, потому что световозвращателям не нужно быть чистыми, чтобы выполнять свою функцию","Заклеить тусклые или грязные рассеиватели лентой, чтобы их не приняли за перегоревшую лампу, и доехать до мастерской","Очистить грязь со всех фонарей и световозвращателей и убедиться, что каждый из них исправен, перед поездкой"],"explanation":"Перед поездкой все фонари и отражатели должны быть чистыми и исправными, так как грязь мешает отражателю отражать, а фонарю — быть заметным."},"160":{"q":"Вы подходите к своему грузовику на стоянке, чтобы начать предрейсовый осмотр. Вам не терпится отправиться в путь, и вы мысленно перечисляете, что сделать в первую очередь: прогреть двигатель, обойти территорию, проверить тормоза, проверить фары. Прежде чем прикоснуться к чему-либо на машине, какое действие правильно относится к самому ПЕРВОМУ шагу методики осмотра?","options":["Выполнить общий обзор, подойдя к машине пешком: оценить её общее состояние, наклон/посадку, свежие лужи жидкости под ней и любые опасности вокруг, прежде чем садиться в кабину","Запустить двигатель и дать ему прогреться до рабочей температуры, чтобы приборы показывали точно, пока вы делаете обход","Выполнить тормозной тест рабочей тормозной системы под давлением, проехав вперёд со скоростью около 5 миль/ч и нажав на педаль тормоза","Подойти к передней и задней частям и убедиться, что все внешние фонари и отражатели чистые, нужного цвета и исправны"],"explanation":"Предрейсовый осмотр начинайте с обхода машины пешком, проверяя её наклон, лужи жидкости под ней и опасности вокруг, прежде чем сесть за руль."},"161":{"q":"Вы ведёте гружёный седельный тягач с прицепом, оснащённый обычной (несинхронизированной) механической коробкой передач, и при разгоне на ровном шоссе вам нужно перейти с 5-й передачи на 6-ю. Какой приём правильный для коробки передач, которая стоит на многих грузовиках, чтобы переключиться вверх чисто, без скрежета?","options":["Выжать сцепление только наполовину («торможение сцеплением») и силой воткнуть рычаг в следующую передачу","Держать сцепление полностью выжатым в течение всего переключения, слегка подыгрывая педалью газа","Держать одну руку крепко на руле и переключаться вообще без сцепления, пока машина катится","Сделать двойной выжим сцепления: отпустить педаль газа, выжать сцепление, перейти в нейтраль, отпустить сцепление, затем снова выжать сцепление и включить более высокую передачу"],"explanation":"Для повышения передачи используйте двойное выжимание сцепления: отпустите газ, выжмите сцепление и включите нейтраль, отпустите сцепление, затем снова выжмите и включите высшую передачу."},"162":{"q":"Вы ведёте гружёный полуприцеп, и дорога впереди уходит в длинный крутой горный спуск. Вы хотите безопасно контролировать скорость при спуске, не перегревая тормоза. В какой момент вы должны завершить переключение на пониженную передачу?","options":["До начала спуска, пока вы ещё на ровной площадке наверху","Уже во время спуска, как только почувствуете, что грузовик набирает скорость","У подножия спуска, когда дорога снова станет ровной","Только после того, как лёгкое равномерное торможение перестанет вас замедлять"],"explanation":"Включайте низкую передачу до начала длинного крутого спуска, пока ещё на ровной поверхности, так как основное торможение — двигателем, а рабочие тормоза лишь дополняют его."},"163":{"q":"Вы спускаетесь с длинного горного уклона с гружёным прицепом. Ваш грузовик оборудован замедлителем (ретардером), и в начале спуска вы его включаете. Какое утверждение ЛУЧШЕ всего описывает, что замедлитель делает для вас в этой ситуации?","options":["Он увеличивает мощность двигателя, чтобы вы набрали скорость и быстрее преодолели уклон","Он создаёт дополнительное тормозное усилие, помогая замедлить транспортное средство, что снижает износ и перегрев рабочих тормозов","Он делает рулевое управление более отзывчивым, чтобы грузовик легче проходил повороты на уклоне","Он является основным средством управления на спуске, поэтому вам больше не нужно выбирать пониженную передачу перед началом спуска"],"explanation":"Замедлитель создаёт дополнительное тормозное усилие, снижая износ и перегрев рабочих тормозов."},"164":{"q":"Температура чуть ниже нуля, и на мостах по вашему маршруту образовалась тонкая ледяная корка. Ваш тягач оснащён моторным (скоростным) замедлителем (ретардером), который воздействует на ведущие оси, когда вы отпускаете педаль газа. Снижая скорость перед поворотом на этом скользком участке и отпуская акселератор, как правильно управлять этим замедлителем?","options":["Оставить замедлитель полностью включённым, так как его торможение действует только на ведущие колёса и поэтому не может нарушить устойчивость управляемой оси","Включить замедлитель сильно и заранее, чтобы вообще не касаться ножного тормоза на льду","Использовать его очень осторожно или выключить, потому что на скользкой поверхности замедлитель может привести к потере сцепления ведущих колёс и заносу","Снять или отключить замедлитель при предрейсовом осмотре всякий раз, когда в прогнозе есть лёд"],"explanation":"На скользкой дороге используйте замедлитель осторожно или выключите его, так как он может лишить ведущие колёса сцепления и вызвать занос."},"165":{"q":"Вы сдаёте задним ходом, заводя прицеп в тесный погрузочный док ночью. Помощника, который мог бы вас направлять, нет, а часть зоны дока закрыта от обзора стоящими прицепами. Какой способ выполнения этого манёвра самый безопасный и правильный?","options":["Сдавать назад как можно быстрее, чтобы меньше времени перекрывать полосу и сократить манёвр","Газовать и держать сцепление в полувыжатом положении, чтобы заехать прямо, не скатываясь назад","Смотреть только в зеркало со стороны водителя, ведь пассажирская сторона — ваша слепая зона, и её проверять не стоит","Сдавать назад медленно, используя оба зеркала, и подавать вперёд для перестроения каждый раз, когда теряете из виду траекторию движения"],"explanation":"Сдавайте назад медленно, используя оба зеркала, и подавайтесь вперёд для перестроения всякий раз, когда теряете обзор пути."},"167":{"q":"Вы приближаетесь к оживлённому перекрёстку, где собираетесь повернуть направо к погрузочной площадке. Движение плотное, и небольшой легковой автомобиль начинает подбираться вдоль вашего тягача справа. Чтобы безопасно сообщить о своих намерениях и не дать этому автомобилю оказаться прижатым к бордюру, когда следует включить указатель поворота?","options":["Заранее, задолго до начала поворота, чтобы у других водителей было время среагировать","В тот момент, когда вы начинаете выворачивать руль, чтобы сигнал совпал с манёвром","Только после того, как вы завершили поворот, чтобы не сбивать с толку находящихся рядом водителей","Только ночью или в условиях плохой видимости, когда сигналы наиболее нужны"],"explanation":"Подавайте сигнал заранее, задолго до начала поворота, чтобы другие водители успели среагировать."},"168":{"q":"Вы выполняете медленный, широкий левый поворот с городской улицы на въезд к погрузочной площадке. На середине поворота руль частично возвращается в центр, и указатель поворота сам выключается. На перекрёстке ждёт автомобиль, а сзади приближается велосипедист. Как правильно поступить с указателем поворота до конца этого манёвра?","options":["Выключить указатель, как только передняя часть тягача въехала на территорию, ведь поворот уже фактически совершён","Снова включить указатель и держать его включённым, пока вы полностью не завершите поворот и машина не выровняется","Оставить указатель выключенным и вместо этого пару раз нажать на тормоз, чтобы показать велосипедисту своё намерение","Сигналить только в первую секунду поворота — это всё, что требует закон, прежде чем вы начнёте манёвр"],"explanation":"Подавайте сигнал непрерывно, пока поворот не завершён полностью и машина не выпрямилась, ведь прицепу нужна вся дуга, чтобы пройти."},"169":{"q":"Вы ведёте гружёный прицеп по оживлённому четырёхполосному шоссе и видите, что примерно в четверти мили впереди начинает скапливаться медленный поток. Вскоре вам нужно будет снизить скорость, а сзади вплотную едет колонна машин. Какое действие ЛУЧШЕ всего сообщит водителям позади, что вы собираетесь замедлиться?","options":["Быстро выключить и снова включить фары и задние фонари, чтобы привлечь их внимание","Дважды коротко подать звуковой сигнал, чтобы едущие сзади ожидали изменения","Слегка несколько раз нажать на педаль тормоза, чтобы заранее помигать стоп-сигналами","Кратко ускориться, чтобы увеличить дистанцию впереди, а затем резко затормозить, когда разрыв сократится"],"explanation":"Чтобы предупредить водителей сзади о замедлении, слегка нажмите на педаль тормоза несколько раз, чтобы заранее мигнуть стоп-сигналами."},"171":{"q":"Только что рассвело, и солнце низко над горизонтом. Свет тусклый и серый, и вы замечаете, что других водителей и силуэты становится всё труднее различать на фоне дороги. Вы укладываетесь в график, и видимость ещё не полностью пропала. Чтобы и видеть дорогу, и, что не менее важно, быть замеченным другими участниками движения в эти сумерки, какое действие является единственным наилучшим выбором?","options":["Включить внутреннее освещение кабины (плафон), чтобы изнутри было легче оценивать сумеречные условия снаружи","Оставить все внешние огни выключенными, так как естественного дневного света ещё достаточно, чтобы видеть дорогу впереди","Включить только аварийную сигнализацию (четыре поворотника), чтобы предупредить других водителей о плохой видимости","Включить фары, чтобы вы видели дорогу впереди, а другие водители чётко видели ваше транспортное средство"],"explanation":"На рассвете или в сумерках включайте фары, чтобы видеть дорогу впереди и чтобы другие водители ясно видели вашу машину."},"172":{"q":"Вы перевозите гружёный прицеп в умеренном потоке на скорости 55 миль/ч. Легковой автомобиль внезапно вклинивается перед вами и резко тормозит, и вы понимаете, что сократили запас пространства перед своим бампером. Почему сохранение этого пространства впереди важнее всего именно в этот момент?","options":["Оно даёт вам необходимое место, чтобы либо затормозить до полной остановки, либо безопасно объехать препятствие рулём","Оно позволяет поддерживать более высокую крейсерскую скорость, реже пользуясь тормозами","Оно экономит топливо, потому что в ровном потоке вы меньше тормозите и разгоняетесь","Оно отбивает у других водителей желание вклиниваться и теснить вашу полосу"],"explanation":"Пространство впереди — это запас для манёвра, дающий место либо затормозить до полной остановки, либо безопасно объехать опасность."},"173":{"q":"Вы ведете загруженный автопоезд по оживленной двухполосной автомагистрали со скоростью 50 миль/ч и замечаете, что легковой автомобиль пристроился близко сзади и едет вплотную к вашему бамперу, на расстоянии всего одного-двух корпусов. Поток впереди движется ровно, но может замедлиться в любой момент. Какой из следующих способов ЛУЧШЕ всего подходит для управления этой опасностью?","options":["Слегка нажать на тормоз, чтобы мигнуть стоп-сигналами и подать сигнал тому, кто едет вплотную, отстать","Создать больше пространства впереди себя, постепенно отпуская педаль газа и увеличивая дистанцию следования, чтобы можно было плавно тормозить, если поток замедлится","Сохранять скорость и держать свою полосу, поскольку за пространство позади вашего автомобиля отвечает тот, кто едет сзади","Ускориться, чтобы оторваться от едущего вплотную автомобиля и восстановить безопасный интервал"],"explanation":"Когда вас подпирают сзади, плавно отпускайте газ, чтобы увеличить пространство впереди и тормозить мягко, а не резко, если поток замедлится."},"174":{"q":"Вы движетесь с магистральной скоростью по средней полосе трёхполосной автомагистрали. Легковой автомобиль пристроился справа рядом с вашим тягачом и удерживает эту позицию, не обгоняя и не отставая, держась вровень с вашей кабиной. Почему движение в таком положении бок о бок является НАИМЕНЕЕ желательной ситуацией для вас как водителя?","options":["Движение параллельно заставляет оба транспортных средства расходовать заметно больше топлива, поэтому это повышает ваши эксплуатационные затраты на длинном маршруте","Закон Техаса прямо запрещает двум транспортным средствам двигаться в ряд по соседним полосам на автомагистрали с ограниченным доступом","Этот автомобиль, скорее всего, находится в одной из ваших слепых зон, поэтому при необходимости сменить полосу вы можете его не увидеть и совершить наезд при перестроении","Движение вровень с другим транспортным средством тратит ваше время впустую, потому что вы не можете использовать смену полосы для продвижения вперёд"],"explanation":"Автомобиль, едущий рядом, часто находится в боковой слепой зоне, где вы его не видите, поэтому при смене полосы можно в него врезаться."},"175":{"q":"Вы ведёте гружёный фургон по незнакомому маршруту и видите впереди знак с указанием высоты проезда под путепроводом 13 футов 2 дюйма. Чтобы безопасно решить, сможете ли вы проехать под ним, не задев конструкцию, самое ВАЖНОЕ, что вы уже должны знать, это:","options":["Полную разрешённую массу (GVWR), указанную на двери, чтобы не превысить весовое ограничение на мосту","Полный тормозной путь на этой скорости, который составляет около 419 футов при 55 миль/ч","Длину вашего транспортного средства, чтобы полностью миновать конструкцию, прежде чем остановиться","Высоту вашего гружёного транспортного средства, включая груз или оборудование, установленное сверху"],"explanation":"Нужно знать фактическую высоту загруженного транспортного средства, включая груз или оборудование на крыше, чтобы сравнить её с указанным габаритом проезда."},"176":{"q":"Вы управляете автопоездом длиной 53 фута (16 м) и должны повернуть направо с городской улицы на узкую боковую дорогу. Приближаясь к повороту, вы понимаете, что он круче, чем вы ожидали. Как БЕЗОПАСНЕЕ всего сохранить достаточно места для завершения этого поворота?","options":["На подъезде оставайтесь в своей правильной полосе, а затем выезжайте шире, ЗАВЕРШАЯ поворот, чтобы прицеп (с уходом задних колёс внутрь) прошёл угол, удерживая заднюю часть прицепа близко к бордюру всё время","Сначала выехать в левую полосу и начать поворот рано, чтобы задняя часть прицепа срезала угол вплотную и держалась близко к бордюру","Ускориться на повороте, чтобы меньше времени блокировать перекрёсток и быстрее его освободить","Держать грузовик вплотную к правому бордюру всё время, чтобы ни одна машина не смогла протиснуться в зазор справа"],"explanation":"Поскольку задние колёса прицепа смещаются внутрь, держитесь своей полосы на подъезде и поворачивайте широко при завершении поворота, удерживая хвост прицепа у бордюра."},"177":{"q":"Вы остановились у знака \"STOP\" в полностью загруженном автопоезде, ожидая пересечения оживлённой двухполосной автомагистрали, где транспорт движется со скоростью 55 миль/ч в обоих направлениях. В поперечном потоке появляется просвет. Поскольку ваш состав тяжёлый и медленно разгоняется, что именно должен позволить вам этот просвет, прежде чем вы решитесь выехать?","options":["Выдвинуть передний бампер чуть за ближний край, чтобы встречные водители вас увидели и сбросили скорость","Полностью пересечь дорогу всем автомобилем или набрать скорость потока до того, как до вас доедет следующая машина","Доехать до середины перекрёстка и полностью остановиться, чтобы оценить вторую полосу","Выехать и постоять с работающим двигателем в полосе ровно столько, чтобы приближающийся водитель успел вас объехать"],"explanation":"Выбирайте интервал, достаточный, чтобы полностью пересечь дорогу или набрать скорость потока до того, как приближающийся автомобиль вас достигнет."},"178":{"q":"Вы выезжаете на загруженную автомагистраль на своём тягаче с прицепом в час пик во второй половине дня. Колонна легковых машин постоянно держится вдоль вашего правого борта, задерживаясь у задних колёс, где зеркала почти ничего вам не показывают. Несколько водителей, похоже, спокойно остаются в этом 'кармане' сбоку и позади прицепа. Как касательно этих слепых зон ('No-Zones') вокруг вашего автопоезда лучше всего отражает безопасную практику коммерческого вождения?","options":["Считать слепые зоны обычными полосами движения и позволять машинам там находиться, ведь они сами туда заехали и ответственность лежит на них","Резко ускориться, чтобы вытолкнуть машины из правой задней слепой зоны, поскольку быстро освободить 'карман' — всегда самое безопасное решение","Осознавать, что вы не видите транспорт в слепых зонах, и управлять движением так, чтобы по возможности держать эти участки свободными от машин","Самому медленно заехать в слепые зоны легковушек, чтобы риск распределялся поровну между вами и водителями легковых автомобилей"],"explanation":"В No-Zone (слепых зонах) вы не видите другие машины, поэтому управляйте скоростью, положением в полосе и дистанцией, чтобы эти зоны оставались свободными."},"179":{"q":"Вы ведёте полностью гружёный автопоезд и выезжаете на длинный крутой подъём, двигаясь по правой полосе. По мере подъёма двигатель работает с натугой, и ваша скорость стабильно падает значительно ниже разрешённого предела, а позади начинают скапливаться более быстрые легковые и лёгкие автомобили. Какой способ управления грузовиком на этом подъёме является НАИЛУЧШИМ?","options":["Перестроиться в крайнюю левую полосу, чтобы более медленные автомобили позади смогли обогнать вас справа, не меняя полосу","Понизить передачу и резко разогнаться, чтобы держать скорость на уровне разрешённого предела и не мешать более быстрому транспорту позади","Сохранять скорость, но съехать на правую обочину и ненадолго остановиться, чтобы пропустить колонну машин, прежде чем продолжить движение","Принять то, что тяжёлый груз будет замедлять вас, оставаться в правой полосе и позволять более быстрому транспорту обгонять вас слева"],"explanation":"Тяжёлый груз естественно замедляет вас на крутом подъёме, поэтому держитесь правой полосы и пропускайте более быстрый транспорт слева."},"180":{"q":"Вы ведете седельный тягач с полуприцепом длиной 53 фута по трехполосному шоссе в умеренном потоке. Слева от вас в соседней полосе едет легковой автомобиль, а справа выезд на трассу подает машины на шоссе. Вы не можете уступить пространство сразу с обеих сторон. Какое действие ЛУЧШЕ всего управляет вашим боковым пространством в этой ситуации?","options":["Держите тягач по центру своей полосы, чтобы сохранить запас пространства с обеих сторон, а не отдавать все свое место одной стороне","Сместитесь влево и прижмитесь к левой линии разметки, чтобы максимально увеличить расстояние между прицепом и въезжающим с пандуса потоком","Ненадолго встаньте на линию разметки, заехав в левую полосу, чтобы ни один автомобиль не смог встать рядом с вашими слепыми зонами","Съедьте на правую обочину, пока поток с пандуса не закончит вливаться, а затем вернитесь в свою полосу"],"explanation":"Удержание машины по центру полосы сохраняет запас пространства с обеих сторон, когда угрозы возникают слева и справа одновременно."},"181":{"q":"Вы приближаетесь к железнодорожному переезду в плотном потоке, где движение идёт рывками с частыми остановками. На переезде нет шлагбаума и нет мигающих сигналов, а автомобили впереди медленно ползут вперёд. Ваш автопоезд длиной 73 фута следующий, кто доедет до путей. Как правильнее всего решить, можно ли выезжать на рельсы?","options":["Выехать передними колёсами на пути и ждать там, ведь нет ни шлагбаума, ни сигнала, предупреждающего о поезде","Ждать, пока впереди не появится промежуток, достаточно большой, чтобы проехать переезд полностью без остановки, с запасом на всю длину автопоезда плюс около 15 футов","Выезжать на переезд сразу, как только тронется машина впереди, ведь главное — не задерживать поток","Начать переезжать, а если поток встанет, переключиться на пониженную передачу прямо на рельсах, чтобы быстро проскочить"],"explanation":"Не начинайте переезд через пути, пока интервал не позволит полностью их пересечь без остановки, с учётом всей длины машины плюс около 15 футов."},"182":{"q":"Вы ведёте загруженный автопоезд по сухому двухполосному шоссе и видите впереди обозначенный крутой поворот. Сейчас вы едете почти на разрешённой скорости и чувствуете, что текущая скорость, возможно, немного велика для этого поворота. Чтобы пройти поворот безопасно, что нужно сделать со скоростью и торможением?","options":["Сохранять скорость до самого поворота, а затем резко затормозить уже в середине поворота, там, где он самый крутой.","Подождать, пока вы выйдете из поворота, и только потом снизить скорость, чтобы быть готовым к следующему.","Снизить скорость до безопасной ДО въезда в поворот, а затем плавно набирать скорость в самом повороте, чтобы машина оставалась устойчивой.","Сохранять равномерную скорость на въезде в поворот и полагаться на лёгкое, постоянное нажатие тормоза на протяжении всего поворота для контроля над грузовиком."],"explanation":"Снижайте скорость до безопасной перед входом в поворот, затем плавно ускоряйтесь в нём, так как торможение внутри поворота может вызвать занос или опрокидывание."},"183":{"q":"Вы везете груз по сельской двухполосной автодороге, когда начинается ровный дождь и покрытие становится блестящим и мокрым. Поток движется с разрешенной скоростью 55 миль/ч, и в длинном плавном повороте вы чувствуете, что руль стал немного 'легким'. Какое действие является единственно самым безопасным ответом на снижение сцепления?","options":["Сохранять 55 миль/ч, но увеличить дистанцию до впереди идущего транспорта, ведь разрешенная скорость по-прежнему законна","Слегка ускориться в повороте, чтобы перенести вес на ведущие оси и улучшить сцепление","Сохранять скорость и быстро прерывисто нажимать на тормоз, чтобы проверить, сколько сцепления осталось","Снизить скорость ниже разрешенного предела, потому что мокрое покрытие уменьшает сцепление и увеличивает тормозной путь"],"explanation":"Безопасную скорость задаёт сцепление, а не указанный предел; мокрое покрытие снижает сцепление и удлиняет тормозной путь, поэтому снижайте скорость ниже лимита."},"184":{"q":"Температура чуть ниже нуля, и легкий снег начал прилипать к дорожному покрытию. Вы ведете груженый тягач с полуприцепом с той же скоростью на трассе, что и ранее сегодня в ясную сухую погоду. По сравнению с теми сухими условиями, какое САМОЕ важное изменение в управляемости вашего автомобиля вам следует ожидать и почему?","options":["Сцепление с дорогой резко снижается, поэтому шины держат дорогу гораздо хуже, и вам нужно намного большее расстояние, чтобы остановиться и совершить маневр","Сцепление снижается лишь незначительно, поэтому обычной дистанции следования и ровной скорости будет достаточно для безопасности","Сцепление остается примерно таким же, как на сухом покрытии, потому что вес груженого прицепа плотно прижимает шины к снегу","Сцепление даже немного улучшается, потому что тонкий слой снега заполняет неровности поверхности и дает шинам больше зацепа"],"explanation":"Снег и лёд резко снижают сцепление, поэтому шины держат дорогу гораздо хуже, и для остановки и управления нужна намного большая дистанция."},"185":{"q":"Вы только что сгрузили полный груз на складе и теперь возвращаетесь в парк с полностью пустым прицепом. На мокром покрытии внедорожник подрезает вас, и вам приходится резко тормозить. По сравнению с тем, когда вы были полностью загружены, почему вашему грузовику может фактически потребоваться БОЛЬШЕЕ расстояние для остановки теперь, когда он пуст?","options":["Пустой тягач тяжелее, поэтому из-за возросшей инерции он проезжает дальше, прежде чем остановиться","Поскольку малый вес слабо прижимает шины к дороге, у пустого грузовика меньше сцепление, поэтому колёса легче блокируются и тормозной путь увеличивается","Пустые прицепы стоят выше, что поднимает центр тяжести и удлиняет тормозной путь","У пустого грузовика тормоза работают холоднее и теряют эффективность, что добавляет около 60 футов к тормозному пути при 55 миль/ч"],"explanation":"У пустого грузовика мало веса прижимает шины к дороге, поэтому сцепление хуже, колёса легче блокируются, а тормозной путь увеличивается."},"186":{"q":"Вы спускаетесь с длинного крутого горного склона на полностью загруженном прицепе. На середине спуска вы замечаете, что постоянно держите ногу на педали тормоза, просто чтобы удерживать скорость, и в кабине начинает пахнуть перегретым. Какое утверждение ЛУЧШЕ ВСЕГО описывает, что происходит с вашими основными рабочими тормозами и почему?","options":["Тормоза становятся эффективнее по мере нагрева, поэтому остаток спуска вы можете безопасно нажимать на них сильнее.","Тормоза охлаждаются за счёт постоянного потока воздуха, поэтому равномерное давление на педаль — это правильный основной способ контролировать скорость.","Тормоза перегреваются и начинают терять эффективность (тормозной фейдинг), поэтому основным средством должно быть торможение двигателем на пониженной передаче, а тормоза — лишь дополнением.","Тормоза вот-вот заблокируют колёса прицепа, поэтому нужно быстро прокачивать педаль, чтобы прицеп не сложился."],"explanation":"На длинном спуске тормоза могут перегреться и потерять эффективность, поэтому основное торможение должно выполнять моторное торможение на низкой передаче, а тормоза — лишь дополнение."},"187":{"q":"Вы находитесь на вершине длинного крутого горного спуска и везёте тяжёлый, полностью загруженный прицеп. Идёт дождь, а примерно на середине спуска дорога резко поворачивает. Прежде чем отпустить тормоза и начать спуск, вы должны выбрать безопасную скорость для движения вниз. Что из перечисленного правильно описывает, от чего должна зависеть ваша безопасная скорость спуска?","options":["Только от крутизны спуска, поскольку гравитация — единственный фактор, определяющий, как быстро грузовик будет катиться вниз","Главным образом от оборотов двигателя на вершине холма, потому что соответствие показаниям тахометра задаёт правильную скорость для любого спуска","Почти полностью от установленного ограничения скорости, так как это значение задано специально для полностью загруженных коммерческих транспортных средств на этом спуске","От общей массы вашего транспортного средства и груза, длины и крутизны спуска, состояния дороги и погодных условий"],"explanation":"Безопасная скорость спуска зависит от общего веса машины и груза, длины и крутизны уклона, состояния дороги и погоды."},"188":{"q":"Вы собираетесь начать спуск по длинному крутому горному уклону с полностью загруженным прицепом. Вы хотите контролировать скорость, не перегревая тормоза и не доводя их до потери эффективности при спуске. Какой подход лучше всего для выбора передачи?","options":["Использовать ту же низкую передачу, на которой вы поднимались бы в этот подъём, и включить её ДО начала спуска.","Включить гораздо более высокую передачу, чем при подъёме, чтобы двигателю было легче на спуске.","Поставить коробку передач в нейтраль и удерживать скорость постоянным нажатием на тормоз.","Оставаться на обычной трассовой передаче и понижать её только если тормоза начнут терять эффективность."],"explanation":"Выберите ту же низкую передачу, которую использовали бы для подъёма на этот уклон, и включите её до начала спуска."},"189":{"q":"Раннее утро, датчик наружной температуры показывает чуть ниже нуля (около -1 C / 30 F). Двухполосное шоссе, по которому вы едете, выглядит совершенно сухим, и за последний час у вас не было никаких проблем со сцеплением. Сейчас вы приближаетесь к длинному путепроводу (эстакаде), перекинутому через речную долину. Какое из следующих предположений является САМЫМ БЕЗОПАСНЫМ при подъезде к эстакаде?","options":["Поскольку покрытие оставалось сухим и сцепление было хорошим, настил эстакады будет не более скользким, чем дорога, которую вы только что проехали","Эстакада может быть обледенелой, даже если остальная дорога чистая, потому что мосты и эстакады замерзают раньше других участков дороги","Эстакада замерзнет в самую последнюю очередь, поэтому это самое безопасное место для торможения или переключения на пониженную передачу, если нужно снизить скорость","Эстакады замерзают не раньше обычного покрытия, поэтому следить за льдом нужно только когда воздух прогреется во второй половине дня"],"explanation":"Мосты и эстакады замерзают раньше остальной дороги, поэтому эстакада может быть обледенелой, даже когда остальное покрытие чистое."},"190":{"q":"После долгой засухи только что начался ровный дождь, и на шоссе поверх старого масла и пыли скапливается тонкая плёнка воды. Движение слабое, поэтому возникает соблазн держать высокую скорость. Чтобы шины сохраняли сцепление с дорогой и не возникло аквапланирование, при какой примерно скорости вы должны понимать, что аквапланирование может НАЧАТЬСЯ, чтобы снизить скорость ниже неё в таких условиях?","options":["Аквапланирование не может начаться, пока вы не достигнете примерно 70 миль/ч, поэтому любая скорость на шоссе ниже этой безопасна под дождём.","Аквапланирование становится проблемой только на очень низкой скорости, около 5 миль/ч, поэтому это в основном проблема парковки.","Аквапланирование может начаться на скорости всего около 30 миль/ч, поэтому на этой мокрой скользкой плёнке следует снизить скорость ниже этого значения.","Аквапланирование не начнётся, пока вы не превысите примерно 90 миль/ч, что намного выше любой разрешённой скорости грузовика."],"explanation":"Аквапланирование может начаться уже при скорости около 30 миль/ч на мокрой скользкой плёнке, поэтому снижайте скорость ниже этого порога."},"191":{"q":"Вы ведёте гружёный полуприцеп на скорости автомагистрали по техасскому интерстейту во время сильного летнего ливня. В колеях полосы движения скопилась стоячая вода. Внезапно руль становится лёгким и слабым, передние шины словно теряют контакт с покрытием, а стрелка спидометра подрагивает, хотя вы не меняли подачу газа. Вы понимаете, что начинается аквапланирование. Какое первое действие будет правильным?","options":["Сильно нажать на педаль тормоза и удерживать её, чтобы как можно быстрее погасить скорость, ведь на мокрой дороге важнее всего тормозной путь","Резко вырулить к более высокой и сухой середине полосы, чтобы вернуть шины на покрытие с лучшим сцеплением","Сохранять текущую скорость, но переключиться на пониженную передачу для торможения двигателем, ведь ведущие колёса ещё имеют сцепление на мокрой поверхности","Отпустить педаль газа, держать руль прямо и дать машине замедлиться, пока шины не восстановят надёжный контакт с дорогой"],"explanation":"При аквапланировании отпустите газ, держите руль прямо и дайте машине замедлиться, пока шины снова не обретут надёжный контакт с дорогой."},"192":{"q":"Середина июля в Западном Техасе, асфальт раскалён и дрожит от жары. Вы два часа ехали с шоссейной скоростью и остановились для обязательной проверки груза и его крепления. Пока вы стоите, какое состояние шин в этих условиях ВАЖНЕЕ всего отслеживать?","options":["Протектор, износившийся ниже 4/32 дюйма на задних ведущих шинах","Выцветшие надписи на боковине и отсутствие маркировки бренда на каркасе","Слегка пониженное давление, которое нужно прямо сейчас довести до нормы для холодной шины","Перегрев шин и давление, поднявшееся выше холодной нормы, что указывает на риск разрыва"],"explanation":"В жару следите за перегретыми шинами, давление в которых поднялось выше холодной нормы, так как перегретые и перекачанные шины склонны к разрыву."},"193":{"q":"В начале вашей смены минус 2 градуса по Цельсию (28 F), и влажный ночной снег примёрз к вашему тягачу. Во время предрейсового осмотра вы обнаруживаете тонкую корку льда на нижней половине лобового стекла и налёт замёрзшего снега на обоих боковых зеркалах. Вы уже выбиваетесь из графика. Что требует от вас Техасский DPS, прежде чем вы выедете на шоссе?","options":["Полностью удалить весь лёд и замёрзший снег, чтобы лобовое стекло и оба зеркала были полностью чистыми перед поездкой","Очистить только участок со стороны водителя, через который вы смотрите, а зеркала оставить, так как обогреватель растопит их во время движения","Соскрести небольшой смотровой участок на лобовом стекле и положиться на камеру заднего вида и повороты головы вместо обледеневших зеркал","Оставить корку льда, потому что при минус 2 градусах температура выше точки, при которой лёд влияет на сцепление, и ехать на пониженной скорости"],"explanation":"Полностью удалите весь лёд и смёрзшийся снег, чтобы лобовое стекло и оба зеркала были совершенно чистыми перед поездкой."},"194":{"q":"Ранним сырым утром температура чуть ниже нуля, и во время предрейсового осмотра дорожное покрытие под тягачом выглядит просто мокрым и блестящим, а не обледенелым. Выезжая на трассу, вы чувствуете, что руль стал лёгким, а грузовик слегка повело в сторону. Почему 'чёрный лёд', на который вы, вероятнее всего, наехали, так опасен именно в такой ситуации?","options":["Он образует видимую шероховатую корку, поэтому вы можете заранее его заметить и резко затормозить, не доезжая до него","Это тонкий прозрачный слой, из-за которого дорога выглядит лишь мокрой, поэтому вы его не видите и можете не понять, что покрытие замёрзло, пока не потеряете сцепление","Он скапливается только на вершинах холмов, поэтому опасность ограничена короткими предсказуемыми участками маршрута","Он всегда выглядит как толстый белый налёт, давая вам достаточно времени, чтобы заранее снизить скорость"],"explanation":"Чёрный лёд — это тонкий прозрачный слой, из-за которого дорога выглядит лишь мокрой, поэтому его не видно, и о замёрзшем покрытии узнаёшь только при потере сцепления."},"195":{"q":"Сразу после рассвета вы ведете груженый прицеп через низкую речную долину, где густой клочковатый туман снизил видимость примерно до длины вашего автопоезда. Вы решаете медленно продолжать движение, а не останавливаться на проезжей полосе. Какой выбор освещения дает вам наилучшую видимость и делает вас наиболее заметным для других?","options":["Включить дальний свет, так как более яркий свет глубже пробьет туман впереди","Выключить фары и оставить только четырехстороннюю аварийную сигнализацию, чтобы избежать бликов","Использовать ближний свет (вместе с противотуманными фарами, если они есть), потому что дальний свет отражается от тумана и возвращает свет обратно к вам","Оставить дальний свет включенным, но переключать на ближний только когда вы находитесь в пределах 500 футов от встречного транспорта"],"explanation":"В тумане используйте ближний свет, потому что дальний свет отражается от взвешенных капель воды и слепит вас бликами, ухудшая видимость."},"196":{"q":"Темная безлунная ночь на сельской двухполосной трассе без уличного освещения. Ближний свет фар освещает примерно 250 футов дороги впереди. Как следует выбирать скорость, чтобы ехать безопасно?","options":["Держать дневное ограничение скорости, ведь лимит установлен для дороги и не меняется после наступления темноты","Выбрать такую скорость, при которой полный тормозной путь равен удвоенному расстоянию, освещаемому фарами, что даст запас безопасности","Держать постоянные 55 миль/ч и полагаться на дальний свет, чтобы успеть среагировать на препятствие впереди","Ехать достаточно медленно, чтобы суметь полностью остановиться в пределах расстояния, освещаемого фарами"],"explanation":"Никогда не превышайте скорость, на которую рассчитан свет фар; держите её достаточно низкой, чтобы остановиться в пределах освещённого фарами участка дороги."},"197":{"q":"Вы ведёте гружёный автопоезд по двухполосному загородному шоссе ближе к вечеру, когда внезапный сильный ливень снижает видимость до нескольких сотен футов. Движение слабое, но встречные машины всё же время от времени появляются, и вы хотите и видеть дорогу, и быть замеченным. Какое положение фар лучше всего подходит для условий сильного дождя?","options":["Ближний свет, потому что он помогает другим видеть вас и при этом не создаёт отражённого блика от сильного дождя","Дальний свет, потому что бóльшая дальность освещения нужна, чтобы видеть сквозь сильный дождь","Фары выключены, только габаритные огни, чтобы мокрое покрытие не давало отвлекающих отражений","Мигание дальним светом, чтобы предупредить встречный транспорт о плохой видимости"],"explanation":"В сильный дождь используйте ближний свет, чтобы другие водители вас видели, избегая бликов, которые создаёт дальний свет, отражаясь от дождя."},"198":{"q":"Середина дня во время аномальной жары в Техасе, и температура дорожного покрытия растёт весь день. Снижая скорость перед затенённым перекрёстком, вы замечаете тёмные блестящие полосы гудрона, выступающие из швов асфальта в полосе движения впереди. Учитывая, как очень жаркая погода влияет на дорожное покрытие, к какой опасности вам следует быть БОЛЕЕ ВСЕГО готовым, проезжая по этим участкам?","options":["Гудрон затвердеет в шероховатую поверхность с высоким сцеплением, поэтому можно тормозить сильнее обычного","Выступающий гудрон может сделать покрытие скользким, поэтому снизьте скорость и избегайте резкого торможения или резких поворотов руля на этом участке","На этих участках образуется чёрный лёд, поэтому покрытие, выглядящее мокрым, на самом деле замёрзшее","Жара достаточно повысит давление в шинах, так что сцепление с гудроном улучшится, и менять скорость не нужно"],"explanation":"В сильную жару гудрон выступает на поверхность и становится скользким, поэтому снижайте скорость и избегайте резкого торможения или поворотов руля на нём."},"199":{"q":"Ветреный день с порывами ветра, и вы собираетесь выехать на открытый участок автомагистрали с высоким, слабо загруженным фургоном-прицепом. Коллега говорит не беспокоиться, потому что пустой высокий прицеп якобы лучше 'держится сам' на ветру. Учитывая, как сильный боковой ветер действует на высокий прицеп с большой боковой поверхностью, чего вам на самом деле следует ожидать в плане управления автопоездом?","options":["Высоким прицепом будет легче управлять, потому что его высота прижимает его против ветра","Высокий прицеп остановится быстрее, поскольку ветер помогает тормозить, давя навстречу движению","Высоким прицепом будет труднее управлять, потому что сильный ветер давит на его большую высокую боковую поверхность","Высокий прицеп будет расходовать меньше топлива, потому что ветер снижает нагрузку на ведущую ось"],"explanation":"Сильный ветер давит на большую высокую боковую поверхность высокого прицепа, что затрудняет управление, особенно когда он пустой или слабо загружен."},"200":{"q":"Температура чуть ниже нуля, и идёт лёгкий дождь. Приближаясь к затенённому мосту, вы замечаете, что дорожное покрытие впереди вдруг выглядит мокрым и блестящим, хотя зеркала и антенна уже начали покрываться льдом. Какое действие безопаснее всего для проезда вашего гружёного автопоезда через этот участок?","options":["Сохранять текущую скорость, но несколько раз прокачать тормоза прямо сейчас, чтобы проверить, сколько сцепления ещё осталось у покрытия","Сохранять скорость и просто увеличить дистанцию, ведь мосты оттаивают быстрее, чем открытая дорога","Плавно ускориться, чтобы быстрее проехать мост, пока покрытие не замёрзло ещё сильнее","Снизить скорость заранее, до моста, и работать рулём, тормозами и газом плавно и мягко"],"explanation":"Влажный глянцевый вид с льдом на зеркалах и антенне указывает на гололёд, а мосты замерзают первыми, поэтому заранее снижайте скорость и работайте плавно и мягко."},"201":{"q":"Безлунная ночь, и вы собираетесь выехать со слабо освещённой стоянки грузовиков в 4-часовой рейс по сельской двухполосной дороге. Во время осмотра вы замечаете, что обе фары покрыты плёнкой дорожной грязи и засохших насекомых, что заметно снижает их яркость. Каково НАИЛУЧШЕЕ действие перед выездом?","options":["Очистить стёкла фар, чтобы они давали полный свет и вы могли видеть достаточно далеко, чтобы вовремя остановиться","Выехать сейчас и просто снизить скорость, чтобы ближний свет всё ещё освещал дорогу во время движения","Включить дальний свет на всю поездку, чтобы компенсировать тусклые грязные стёкла","Не чистить фары и полагаться на габаритные и контурные огни, чтобы обозначить свой путь"],"explanation":"Грязные стёкла фар сокращают дальность ближнего света, поэтому очистите их, чтобы вернуть полную яркость и видеть достаточно далеко для своевременной остановки."},"202":{"q":"Вы спускаетесь с длинного крутого горного склона с гружёным прицепом. На середине спуска вы нажимаете на педаль тормоза, но она почти проваливается до пола и почти не замедляет машину, и вы чувствуете запах гари. Скорость начинает расти. Какое действие будет НАИЛУЧШИМ?","options":["Резко и быстро прокачать педаль тормоза, чтобы восстановить давление, и продолжать катиться на текущей передаче","Переключиться на более низкую передачу, чтобы торможение двигателем замедлило машину, и направить грузовик к ближайшей аварийной (тормозной) полосе","Включить нейтраль, чтобы защитить коробку передач, и дать грузовику катиться, пока уклон не выровняется","Резко съехать на левую обочину и выставить три световозвращающих треугольника на 10, 100 и 200 футах"],"explanation":"Когда рабочие тормоза слабеют на спуске, переключитесь на низшую передачу для торможения двигателем и направляйтесь к аварийной полосе для безопасного снижения скорости."},"203":{"q":"Вы ведёте гружёный тягач с полуприцепом вниз по длинному крутому горному спуску. Несмотря на то что перед спуском вы включили низкую передачу и применяете лёгкое равномерное торможение, вы чувствуете слабый запах гари, а педаль тормоза становится мягкой и проваливается. Впереди справа на обочине вы видите знак противоаварийной (улавливающей) полосы. В этих условиях каково правильное понимание того, когда и зачем следует использовать эту полосу?","options":["Это обозначенный карман для остановки, где можно припарковаться на ночь и дать перегретым тормозам остыть перед продолжением спуска","Это зона отдыха, размещённая на крутых спусках, чтобы уставшие водители могли немного постоять и восстановиться перед завершением длинного спуска","Она создана для остановки неуправляемого автомобиля, поэтому если тормоза отказали из-за перегрева и вы больше не можете контролировать скорость, вам следует использовать её, чтобы безопасно остановить грузовик","Это специальная полоса, где можно безопасно переключиться на более низкую передачу, пока автомобиль ещё движется вниз по спуску"],"explanation":"Аварийная полоса предназначена для остановки неуправляемой машины с отказавшими тормозами, поэтому используйте её для безопасной остановки, когда не можете контролировать скорость."},"204":{"q":"Вы ведете груженый автопоезд на скорости по сухой двухполосной дороге, когда рулевое колесо внезапно становится свободным, и грузовик перестает нормально реагировать на повороты руля. Движение слабое, обочина впереди свободна. Какое действие является ЛУЧШИМ первым шагом?","options":["Сохранять текущую скорость и силой крутить руль из стороны в сторону, пока управление не восстановится","Полностью отпустить руль, дать машине самой выбрать траекторию, а самому потянуться за рацией","Плавно и мягко нажать на тормоза, чтобы контролируемо и безопасно остановить транспортное средство","Резко и до упора нажать на тормоза, заблокировав колеса, чтобы остановиться на кратчайшей дистанции"],"explanation":"При внезапном отказе рулевого управления вы можете контролировать только скорость, поэтому тормозите плавно и мягко до безопасной контролируемой остановки."},"205":{"q":"Вы первым подъезжаете к месту столкновения двух автомобилей на двухполосном сельском шоссе. Один водитель навалился на руль и, похоже, ранен, по обеим полосам разбросаны осколки стекла и разлита жидкость. С обеих сторон продолжают приближаться другие машины. Что вы должны сделать ПЕРВЫМ, безопасно остановив свой грузовик?","options":["Оградить место аварии и предупредить приближающийся транспорт, чтобы не допустить новых столкновений","Вытащить раненого водителя из машины и перенести его на обочину","Сфотографировать место происшествия, чтобы задокументировать повреждения для отчёта","Начать осматривать каждого пострадавшего на предмет травм и оказывать первую помощь"],"explanation":"На месте любого ДТП первоочередная задача — предотвратить вторую аварию, поэтому сначала оградите участок и предупредите приближающийся транспорт."},"206":{"q":"Вы перевозите сухой фургон по сельскому двухполосному шоссе, когда чувствуете запах дыма и видите языки пламени возле зоны колес задней оси. Нужно быстро остановиться, но впереди несколько мест для остановки. Где ЛУЧШЕ всего съехать и припарковаться, чтобы справиться с возгоранием?","options":["Сразу за въездом в приближающийся автомобильный тоннель, чтобы конструкция защищала грузовик от ветра","На гравийную площадку у стоянки для грузовиков, припарковавшись рядом с дизельными колонками, чтобы огнетушитель был под рукой","На широкой обочине открытого участка, вдали от зданий и других автомобилей, рядом с телефоном экстренного вызова","Под ближайшим бетонным путепроводом, где тень не даст грузу перегреться ещё больше"],"explanation":"При пожаре в транспорте остановитесь на открытой обочине вдали от зданий, движения и горючего, но рядом с телефоном вызова, чтобы изолировать огонь и иметь доступ к помощи."},"207":{"q":"Вы ведёте гружёный тягач с прицепом по мокрой автомагистрали, когда легковой автомобиль внезапно подрезает вас и резко тормозит. Вы жмёте на тормоз изо всех сил, индикатор ABS не горит (система исправна), и вам нужно увести машину на пустую обочину, чтобы избежать столкновения. Рассчитывая на ABS в этой аварийной ситуации, что она НА САМОМ ДЕЛЕ для вас сделает (наиболее точно)?","options":["Она сократит общий тормозной путь намного ниже примерно 419 футов, которые нужны фуре при 55 миль/ч, поэтому вы сможете остановиться вовремя без манёвра","Она автоматически затормозит и сама уведёт грузовик на обочину, как только распознает препятствие впереди","Она гарантирует, что колёса остаются заблокированными, чтобы шины сильнее вгрызались в мокрый асфальт для максимального сцепления","Она не даст колёсам заблокироваться, чтобы вы сохранили управляемость и смогли увести машину на обочину, продолжая сильно тормозить"],"explanation":"АБС не даёт колёсам блокироваться при резком торможении, благодаря чему вы сохраняете управление и можете уйти на обочину, продолжая тормозить."},"208":{"q":"Вы везете груженый прицеп под уклон по мокрой четырехполосной автомагистрали, когда легковой автомобиль резко подрезает вас. Вы резко тормозите, срабатывает ABS (антиблокировочная система), вы сохраняете управление тягачом и объезжаете препятствие. После этого менее опытный водитель говорит вам, что раз на вашем грузовике есть ABS, теперь можно держать меньшую дистанцию до впереди идущих машин, потому что ABS позволяет останавливаться на гораздо меньшем расстоянии. Почему это рассуждение НЕВЕРНО?","options":["ABS не обязательно сокращает тормозной путь; ее главная польза в том, что она не дает колесам заблокироваться, чтобы вы могли рулить во время торможения.","ABS работает только на сухой дороге, поэтому на этой мокрой автомагистрали она вообще не помогла при торможении.","ABS сокращает тормозной путь только на управляемой (передней) оси, поэтому дистанцию можно уменьшить наполовину, но не полностью.","ABS сама автоматически нажимает на тормоза за вас, поэтому на скорости автомагистрали дистанцию можно вообще не держать."],"explanation":"ABS не обязательно сокращает тормозной путь; её главная задача — не дать колёсам заблокироваться, чтобы вы могли управлять рулём при резком торможении."},"209":{"q":"Ваш тягач с полуприцепом НЕ оснащён антиблокировочной системой тормозов (ABS). На сельской двухполосной дороге автомобиль внезапно выезжает с боковой улицы прямо на ваш путь, и вы должны остановиться как можно быстрее, сохраняя контроль над автопоездом и оставаясь в своей полосе. Какой способ торможения обеспечит кратчайшую безопасную остановку без потери управляемости?","options":["Выжать педаль тормоза до пола и удерживать её, чтобы колёса заблокировались для максимального тормозного усилия","Применить контролируемое торможение (плавное устойчивое усилие чуть ниже порога блокировки) или прерывистое (stab) торможение, отпуская педаль при блокировке колёс","Часто и беспорядочно нажимать на тормоз вплоть до полной остановки","Использовать только ручной кран тормоза прицепа, чтобы прицеп остановил автопоезд"],"explanation":"Без ABS не давайте колёсам блокироваться, применяя контролируемое торможение (плавное усилие почти до блокировки) или прерывистое торможение, отпуская педаль при блокировке."},"210":{"q":"Вы едете гружёным жарким летним днём со скоростью около 60 миль/ч по автомагистрали с разделительной полосой. Внезапно вы слышите громкий хлопок, передняя часть тягача дёргается и сильно тянет в сторону -- лопнула шина на управляемой (передней) оси. В это первое мгновение, прежде чем сделать что-либо ещё, какая реакция даёт вам НАИЛУЧШИЙ шанс сохранить контроль над транспортным средством?","options":["Сразу же сильно и резко затормозить, чтобы снизить скорость до безопасной, пока машину не утянуло ещё дальше с курса","Нажать на газ, чтобы добавить мощности на ведущие колёса и вытянуть тягач прямо, а затем отпустить, когда он пойдёт ровно","Резко вывернуть руль в сторону, противоположную той, куда тянет, чтобы выровнять тягач обратно к центру полосы","Крепко удерживать руль обеими руками, сначала не трогать тормоз, держать свою полосу и дать машине замедлиться самостоятельно, прежде чем плавно притормаживать"],"explanation":"При разрыве шины крепко держите руль двумя руками, сначала не трогайте тормоз, держитесь полосы и дайте машине замедлиться, прежде чем мягко тормозить."},"212":{"q":"Во время предрейсового осмотра в товарно-транспортных документах указано, что ваш прицеп загружен на несколько тысяч фунтов сверх допустимой полной массы (GVWR). Вы опаздываете, а впереди по маршруту длинный спуск и пара крутых поворотов. Коллега говорит, что лишний вес наоборот 'поможет вам лучше держаться за дорогу', так что ничего страшного. Исходя из того, как перегруз влияет на управляемость, какое утверждение верно?","options":["Дополнительный вес сильнее прижимает шины к дороге, поэтому тормозной путь будет короче, чем при загрузке в пределах нормы.","Поскольку груз расположен над осями, лишний вес снижает центр тяжести и уменьшает риск опрокидывания на поворотах.","Избыточный вес делает грузовик более трудным для остановки и для управления рулём, увеличивая тормозной путь и риск потери контроля на спуске и поворотах.","Перегруз влияет только на расход топлива и износ шин; на торможение и управляемость он реального влияния не оказывает."],"explanation":"Избыточный вес затрудняет остановку и управление грузовиком, увеличивая тормозной путь и риск потери контроля на спусках и поворотах."},"213":{"q":"Во время предрейсового осмотра вы загружаете бортовую платформу и замечаете, что почти вся тяжёлая техника оказалась свалена в кучу над задней осью и стоит высоко на штабеле поддонов. Прежде чем тронуться, как ЛУЧШЕ всего поступить с этим грузом, чтобы машина шла безопасно?","options":["Оставить груз скученным сзади над ведущей осью, ведь дополнительный вес там даёт ведущим колёсам больше сцепления","Сдвинуть весь груз вперёд, чтобы весь вес лёг на переднюю управляемую ось для лучшего контроля рулём","Оставить груз сложенным высоко и по центру, ведь высокий груз, отцентрованный слева направо, уже достаточно сбалансирован","Перераспределить груз так, чтобы вес был распределён и сбалансирован спереди назад и из стороны в сторону, удерживая центр тяжести как можно ниже"],"explanation":"Распределяйте и балансируйте вес груза спереди-назад и из стороны в сторону, держа центр тяжести как можно ниже, чтобы не перегрузить ось и не опрокинуться."},"214":{"q":"Во время предрейсового осмотра вы частично заполняете автоцистерну, а сверху на загруженную платформу укладываете несколько поддонов, в результате чего самый тяжёлый груз оказывается высоко. Планируя маршрут, какой риск должен беспокоить вас БОЛЬШЕ всего в том, как теперь поведёт себя этот грузовик?","options":["Высокий центр тяжести делает грузовик гораздо более склонным к опрокидыванию на повороте или при резком манёвре рулём.","Высоко расположенный груз заставит грузовик останавливаться на гораздо более коротком расстоянии из-за дополнительной силы прижатия вниз.","Поднятый вес улучшит расход топлива на ровной трассе, потому что груз едет плавнее.","Высоко расположенный груз сделает рулевое управление заметно легче на скорости по трассе."],"explanation":"Высокий центр тяжести смещает больше веса вверх, из-за чего грузовик гораздо легче опрокидывается на повороте или при резком манёвре рулём."},"215":{"q":"Во время предрейсового осмотра вы проверяете свой одиночный грузовик без прицепа и обнаруживаете на дверной стойке со стороны водителя металлическую сертификационную табличку с выбитым числом 33 000 фунтов рядом с буквами 'GVWR'. Диспетчер спрашивает, что именно эта цифра говорит вам об этом транспортном средстве. Какое утверждение верно?","options":["Это совокупная максимальная снаряжённая масса, допустимая для этого грузовика вместе с любым прицепом, который он буксирует как единый состав","Это максимальная снаряжённая масса, установленная заводом-изготовителем, на которую рассчитано это одиночное транспортное средство","Это суммарная масса всего груза и креплений, которую вы вправе по закону разместить в грузовом отсеке","Это максимальная масса, которая может приходиться на любую отдельную ось грузовика"],"explanation":"GVWR — это максимальная полная масса, установленная производителем, на которую рассчитано одно отдельное транспортное средство."},"216":{"q":"Во время предрейсового осмотра вы обнаруживаете стальную балку длиной 12 футов на платформе, удерживаемую двумя сильно потёртыми, изношенными верёвками, без упора у переднего щита. Впереди вас ждёт долгий рейс по шоссе. Что требуется для этого груза, прежде чем вы сможете законно и безопасно выехать?","options":["Больше ничего не нужно -- две отдельные верёвки уже соответствуют минимуму в две стяжки для предмета длиннее 5 футов, поэтому балка закреплена","Достаточно лишь туже перевязать имеющиеся верёвки, ведь передний щит трейлера сам не даст балке съехать вперёд","Достаточное количество исправных стяжек и распорок -- надёжные стяжки с подходящим рабочим пределом нагрузки плюс упоры/распорки -- чтобы действительно удержать балку от смещения в любом направлении","Одной цепи поперёк по центру достаточно, ведь для любого груза на платформе требуется всего одна стяжка"],"explanation":"Груз должен крепиться достаточным числом исправных стяжек с надлежащим рабочим пределом нагрузки плюс упорами и распорками, чтобы удержать его от смещения в любом направлении."},"217":{"q":"Вы загружаете стальные рулоны и тяжёлые ящики на бортовую платформу, оборудованную защитным щитом за кабиной (передним ограждением груза, headache rack). Коллега спрашивает, зачем компания тратит деньги на такие щиты, если уже используются правильные крепёжные ремни. Какой ответ верно указывает ОСНОВНОЕ назначение этого защитного щита?","options":["Он даёт прочную точку крепления, поэтому суммарный рабочий предел нагрузки ваших креплений можно снизить до менее половины веса груза","Он блокирует завихрения ветра и дорожные брызги с передней части груза, улучшая расход топлива и видимость в зеркалах","Он позволяет законно пропустить повторную проверку крепления груза из кабины, пока вы не проедете первые 150 миль после погрузки","Он защищает вас в кабине, не давая грузу сместиться вперёд и проломиться в отделение водителя при резком торможении"],"explanation":"Передний щит (защитная решётка) не даёт грузу сместиться вперёд в кабину при резкой остановке, защищая водителя от удара или раздавливания."},"219":{"q":"Вы только что взвесили свой груженый автопоезд на придорожных весах, и инспектор протягивает вам распечатку с несколькими разными числами: значение для каждой группы колес на дороге плюс единый общий итог. Инспектор указывает на строку с надписью «осевая нагрузка» и просит подтвердить, что вы понимаете, что именно означает это конкретное число. Чтобы ответить правильно, что из перечисленного вы должны сказать инспектору об осевой нагрузке?","options":["Величину веса, которую каждая отдельная ось передает на дорогу","Суммарный общий вес всего груженого транспортного средства со всем грузом","Вес только груза и крепежного оборудования, находящихся на прицепе","Максимальный вес, который завод-изготовитель допускает для безопасной перевозки"],"explanation":"Осевая нагрузка — это вес, который несёт и передаёт на дорогу одна отдельная ось, а не вес всего транспортного средства."},"220":{"q":"Сейчас 3 часа ночи во время длинного ночного рейса, и вы замечаете, что уходите из своей полосы и постоянно зеваете. По плану поездки вам ещё ехать несколько часов. Какое действие действительно устранит вашу усталость, чтобы продолжить путь безопасно?","options":["Выпить большую чашку чёрного кофе и включить радио погромче, чтобы продержаться оставшиеся часы","Съехать на безопасную зону отдыха и прекратить движение, чтобы по-настоящему выспаться перед продолжением пути","Опустить боковое стекло ради холодного свежего воздуха и съесть конфету для прилива сахара","Продолжать ехать, но увеличить дистанцию до одной секунды на каждые 10 футов длины транспортного средства, чтобы дать себе больше времени на реакцию"],"explanation":"Усталость лечит только настоящий сон, поэтому остановитесь в безопасной зоне отдыха и поспите, прежде чем продолжить путь."},"221":{"q":"Сезон аллергии, и во время предрейсового осмотра вы чувствуете, что начинается простуда. Перед тем как сесть в кабину для длительного дневного рейса, вы принимаете безрецептурную таблетку от простуды и аллергии. Какой эффект этого лекарства является САМОЙ ВАЖНОЙ причиной пересмотреть решение садиться за руль прямо сейчас?","options":["Оно повысит вашу бдительность, поэтому вы сможете безопасно продлить часы вождения","Оно выводит весь оставшийся в организме алкоголь, снижая уровень BAC перед поездкой","Оно может вызвать сонливость и ухудшить вождение, поэтому перед поездкой следует прочитать инструкцию на упаковке","Оно улучшает вашу скорость реакции и обостряет концентрацию на дороге"],"explanation":"Многие безрецептурные средства от простуды и аллергии вызывают сонливость и ухудшают вождение, поэтому всегда читайте этикетку и не садитесь за руль, если есть предупреждение об управлении механизмами."},"222":{"q":"Два часа назад вы выпили за ужином два пива и перед тем, как сесть за руль своего тягача с прицепом для ночного рейса, чувствуете себя совершенно трезвым. Вы убеждаете себя, что крепкий кофе и холодный ночной воздух помогут вам сохранить ясность ума. Какое утверждение лучше всего объясняет реальный риск, которому вы себя подвергаете, садясь за руль в таком состоянии?","options":["Никакого существенного риска -- спустя два часа и после кофе алкоголь уже не оказывает заметного влияния на водителя вашей комплекции","Единственное, о чём действительно стоит беспокоиться, -- это не превысить предел содержания алкоголя в крови 0,08%, который действует для вашей категории CDL при управлении грузовиком","Кофе и холодный воздух ускорят выведение алкоголя из организма, поэтому ваши навыки восстановятся ещё до выезда на трассу","Алкоголь ухудшает рассудительность и время реакции даже тогда, когда вы чувствуете себя нормально, и только время -- а не кофе или свежий воздух -- выводит его из организма"],"explanation":"Алкоголь ухудшает рассудительность и время реакции, даже когда вы чувствуете себя нормально, и только время -- а не кофе или свежий воздух -- выводит его из организма."},"224":{"q":"Вы закончили долгую смену в 2 часа ночи и поспали всего около четырёх часов перед следующим рейсом. Диспетчер давит на вас, чтобы вы выезжали, и вы убеждаете себя, что 'наверстаете' кофе и открытым окном. Согласно тому, что руководство говорит о предотвращении усталости, какое утверждение отражает то, что вам действительно нужно, чтобы быть по-настоящему отдохнувшим и безопасно вести машину?","options":["Большинству взрослых нужно около 7–8 часов сна, чтобы по-настоящему отдохнуть, и только настоящий сон — а не кофе или свежий воздух — восстанавливает бдительность.","Около 4–5 часов сна достаточно для опытного водителя, поскольку кофе и свежий воздух могут восполнить остальное.","Около 2–3 часов сна допустимо, пока вы делаете перерыв каждые 150 миль, чтобы перепроверить свою бдительность.","Перед любым коммерческим рейсом вам нужно полных 12–14 часов сна, иначе вы юридически непригодны к вождению."],"explanation":"Большинству взрослых нужно около 7-8 часов сна, чтобы по-настоящему отдохнуть, и только настоящий сон -- а не кофе или свежий воздух -- восстанавливает бдительность."},"225":{"q":"Вы едете уже несколько часов по длинному, однообразному участку шоссе, и ваши веки тяжелеют. Вы открываете окно ради свежего воздуха и выпиваете большую чашку кофе, чтобы оставаться бодрым. Какое утверждение об этих способах верно?","options":["Кофеин в сочетании с прохладным свежим воздухом навсегда восстанавливает бодрость до конца смены","Они могут помочь ненадолго, но единственное настоящее средство от сонливости -- остановиться и поспать","Свежий воздух и кофе опасны и только усилят вашу сонливость","Они полностью обнуляют ваши часы вождения, так что вы можете безопасно продолжать путь без остановки"],"explanation":"Кофеин и свежий воздух лишь ненадолго маскируют сонливость; единственное настоящее средство -- прекратить движение и поспать."},"226":{"q":"Вы движетесь в правой полосе разделенного шоссе, когда сзади на большой скорости подлетает водитель, вплотную садится вам на бампер, мигает дальним светом, затем перестраивается в левую полосу и злобно жестикулирует, пытаясь вас обогнать. Впереди умеренный поток. Какое действие будет НАИЛУЧШИМ и самым безопасным?","options":["Прибавить скорость вровень с ним, чтобы он быстрее завершил обгон и перестал давить вам на бампер","Удерживать свою полосу и лишь слегка сбросить скорость, заставив его подождать, чтобы он усвоил урок","Отпустить педаль газа, освободив место, не встречаться с ним взглядом и дать ему уйти далеко вперед","Перестроиться влево в его полосу и блокировать обгон, пока он не успокоится и не отстанет"],"explanation":"Дайте агрессивному водителю много места и не вступайте в конфликт -- сбросьте газ, избегайте зрительного контакта и дайте ему уйти далеко вперёд."},"227":{"q":"Вы въезжаете на загруженную межштатную автомагистраль на груженом тягаче с прицепом, когда легковой автомобиль подрезает вас, вынуждая резко тормозить. Раздражённый водитель затем висит у вас на хвосте, обгоняет, резко тормозит перед вами и делает непристойные жесты. Согласно руководству, какой термин ЛУЧШЕ всего описывает поведение другого водителя, и как вам безопаснее всего относиться к собственному поведению, чтобы не стать виновным в том же самом?","options":["Агрессивное перестраивание — обычная часть плотного движения, на которую следует отвечать ускорением, чтобы удержать свою позицию и не дать легковым воспользоваться медлительностью грузовика","Оборонительное вождение — другой водитель просто защищает своё пространство, поэтому вам стоит повторить его поведение, тормозя и блокируя, чтобы приучить легковые уважать крупный транспорт","Отвлечённое вождение — водитель явно не следит за дорогой, поэтому правильно ускориться и быстро обогнать его, чтобы убрать себя от опасности","Дорожная агрессия (road rage) — злобное, агрессивное вождение; вы избегаете её сами, оставаясь спокойным, не отвечая на провокацию и давая разгневанному водителю место, чтобы уехать"],"explanation":"Дорожная ярость -- это злое, агрессивное вождение, и вы избегаете её, сохраняя спокойствие, не отвечая на провокации и давая разъярённому водителю место, чтобы уехать."},"228":{"q":"Вы ведёте гружёный состав в плотном дневном потоке по техасской межштатной автомагистрали. Коллега говорит, что лучший способ рано заметить опасность — это не отрываясь смотреть на бампер идущего впереди грузовика, чтобы никогда не пропустить его стоп-сигналы. Какой подход на самом деле даёт лучший шанс вовремя заметить опасность и безопасно отреагировать?","options":["Постоянно переводите взгляд и сканируйте обстановку — смотрите далеко вперёд (на 12–15 секунд), затем ближе, и проверяйте зеркала каждые 5–8 секунд","Смотрите прямо перед собой и фиксируйте взгляд на идущем впереди автомобиле, чтобы его стоп-сигналы всегда были на виду","Полагайтесь в основном на зеркала, ведь в плотном потоке большинство неожиданностей исходит от обгоняющих сзади машин","Поглядывайте на шкалу радио и приборы между взглядами вперёд, чтобы не пропустить нарастающую техническую неисправность"],"explanation":"Постоянно двигайте глазами и сканируйте обстановку -- смотрите далеко вперёд на 12-15 секунд, затем на ближнюю зону, и проверяйте зеркала каждые 5-8 секунд."},"229":{"q":"Вы едете через деловой центр города со скоростью 25 миль/ч. Вдоль правого бордюра вы видите ряд параллельно припаркованных автомобилей. Осматривая дорогу впереди, вы замечаете, что у одного из этих припаркованных автомобилей горят стоп-сигналы, из выхлопной трубы идёт дым, а на сиденье виден силуэт водителя. Почему именно ЭТОТ припаркованный автомобиль следует считать активной опасностью и быть готовым снизить скорость или изменить положение в полосе?","options":["Горящие стоп-сигналы означают, что автомобиль удерживается на месте, поэтому он не может тронуться, и угрозу представляют только машины без огней впереди него","Занятый автомобиль с работающим двигателем может внезапно выехать в вашу полосу, или дверь может распахнуться на вашем пути, поэтому держите ногу над тормозом и оставьте дополнительное расстояние","Работающий двигатель нагревает шины, что увеличивает ваш собственный тормозной путь примерно до 419 футов и вынуждает вас сбросить скорость","Выхлоп и горящие стоп-сигналы — это нормально для припаркованного автомобиля и ни о чём не сигнализируют, поэтому менять скорость или положение в полосе не нужно"],"explanation":"Припаркованная машина с человеком и работающим двигателем может внезапно выехать на вашу полосу или открыть дверь на вашем пути, поэтому держите ногу над тормозом и дайте ей больше места."},"230":{"q":"Вы ведёте грузовик со скоростью 30 миль/ч по жилому району тёплым днём. Впереди справа вы видите несколько детей, играющих с мячом у обочины, и один из них смотрит на мяч, а не на ваш грузовик. Почему руководство считает эту ситуацию особой опасностью, требующей готовности немедленно сбросить скорость или остановиться?","options":["Потому что на 30 милях/ч ваш общий тормозной путь уже составляет около 419 футов, поэтому вы в принципе не сможете вовремя остановиться","Потому что дети всегда остаются на тротуаре и станут опасностью только если взрослый велит им перейти дорогу","Потому что дети могут действовать внезапно и непредсказуемо, например выбежать на дорогу за мячом, не глядя на движение","Потому что дети движутся настолько медленно, что останутся на проезжей части ещё долго после того, как вы ожидаете их ухода"],"explanation":"Дети представляют особую опасность, потому что могут действовать внезапно и непредсказуемо, например выбежать на дорогу за мячом, не глядя на движение."},"231":{"q":"Вы ведёте гружёный полуприцеп по четырёхполосной разделённой автомагистрали со скоростью около 55 миль/ч. Маленький автомобиль внезапно подрезает вас справа, а затем резко тормозит, чтобы успеть на съезд, который чуть не пропустил. Ваша дистанция до него сократилась, и вы чувствуете прилив гнева. Какая реакция самая безопасная и оборонительная?","options":["Держаться вплотную за этим автомобилем и моргнуть дальним светом, чтобы водитель осознал созданную им опасность","Ускориться и поравняться с автомобилем, чтобы больше не оказаться в ловушке позади непредсказуемого водителя","Слегка нажать на тормоз, чтобы быстро предупредить, а затем снова приблизиться до исходного 4-секундного интервала","Отпустить педаль газа, чтобы восстановить безопасную дистанцию, сохранять спокойствие и дать другому водителю нужное ему пространство"],"explanation":"Когда другой водитель допускает ошибку, сбросьте газ, чтобы восстановить безопасную дистанцию, сохраняйте спокойствие и дайте ему необходимое место."},"233":{"q":"Ночью вы приближаетесь к незнакомому перекрёстку и замечаете, что светофор над дорогой мигает красным во всех направлениях. Полицейского рядом нет, а движение по пересекающей улице слабое. Как правильно и по закону проехать этот перекрёсток?","options":["Полностью остановиться, а затем проехать перекрёсток только тогда, когда это безопасно, точно так же, как у знака STOP (Стоп)","Снизить скорость, осмотреться в обе стороны и медленно прокатиться без полной остановки","Расценить неработающий светофор как знак «Уступи дорогу» и проехать при первом же разрыве в потоке, сохраняя скорость","Сохранять скорость при проезде перекрёстка, поскольку мигающий сигнал означает неисправность светофора и правила не действуют"],"explanation":"Мигающий красный сигнал означает то же, что и знак STOP: полностью остановитесь и продолжайте движение только тогда, когда это безопасно."},"234":{"q":"Поздно ночью вы приближаетесь к перекрёстку на своём гружёном составном транспортном средстве. Светофор, который днём горел постоянным зелёным, теперь показывает МИГАЮЩИЙ ЖЁЛТЫЙ. На пересекающей дороге транспорта не видно. Как правильно действовать при этом сигнале?","options":["Считать его как мигающий красный: полностью остановиться, затем проехать, когда путь свободен","Снизить скорость, сохранять бдительность и проехать перекрёсток с осторожностью, проверив поперечное движение","Сохранять скоростное движение по трассе, потому что жёлтый сигнал даёт вам преимущество над пересекающей дорогой","Полностью остановиться у линии и ждать, пока сигнал не переключится на постоянный зелёный, прежде чем двигаться"],"explanation":"Мигающий желтый сигнал — это предупреждение, поэтому снизьте скорость, будьте внимательны и проезжайте перекресток осторожно, проверив поперечное движение."},"235":{"q":"Вы приближаетесь к сельскому перекрёстку на своём гружёном составном автопоезде. Ни в одном направлении нет знаков \"Стоп\", знаков \"Уступи дорогу\" или светофоров, а кусты частично закрывают вам обзор справа. Справа к перекрёстку примерно в то же время приближается пикап. Какое действие будет самым безопасным и правильным?","options":["Сохранять скорость и проехать первым, так как у гружёного коммерческого транспортного средства есть преимущество перед более мелкими автомобилями","Полностью остановиться в центре перекрёстка и подождать, пока пикап проедет, прежде чем двигаться дальше","Снизить скорость при приближении, держать ногу наготове у тормоза и быть готовым уступить дорогу пикапу по мере необходимости, прежде чем продолжить движение","Подать звуковой сигнал и продолжить движение с той же скоростью, чтобы другой водитель понял, что вы намерены проехать первым"],"explanation":"На нерегулируемом перекрестке ни одно транспортное средство не имеет автоматического преимущества, поэтому снизьте скорость, держите ногу над тормозом и будьте готовы уступить, прежде чем продолжить движение."},"237":{"q":"Вы перевозите тяжёлый груз и приближаетесь к вершине длинного крутого горного спуска. Спуск тянется несколько миль, покрытие сухое, и вы хотите не допустить перегрева (отказа) рабочих тормозов на пути вниз. Согласно правилам безопасного вождения в горах, какое действие даёт вам наиболее надёжный контроль скорости во время спуска?","options":["Оставаться на обычной шоссейной передаче и всю дорогу вниз слегка притормаживать рабочими тормозами, чтобы держать скорость ровной","Дождаться, пока грузовик начнёт разгоняться на полпути вниз, а затем переключиться на пониженную передачу, чтобы снова замедлить машину","Держать коробку на высокой передаче, чтобы двигатель отдыхал, и полагаться в основном на сильные, многократные нажатия тормоза для контроля скорости","Выбрать пониженную передачу ДО начала спуска, чтобы торможение двигателем и передачей выполняло основную работу, а рабочие тормоза использовать лишь как лёгкое, ровное дополнение"],"explanation":"Выберите низкую передачу до начала спуска по длинному склону, чтобы основное торможение выполняли двигатель и передача, а рабочие тормоза использовались лишь как легкое, ровное дополнение."},"238":{"q":"Вы ведёте полностью загруженный прицеп по горной местности, когда навигатор предупреждает об аварийной тормозной площадке (улавливающем съезде) впереди. Едущий с вами новичок спрашивает, почему дорожная служба построила длинный заполненный гравием съезд именно в этом месте, а не где-то ещё на маршруте. Исходя из того, как эти съезды должны использоваться, где дорожная служба ВЕРОЯТНЕЕ всего разместит такой съезд?","options":["В середине длинного крутого спуска, где у тяжёлых машин выше всего риск потерять тормоза из-за их перегрева (увода тормозов)","На ровном открытом участке шоссе, где грузовики обычно развивают свою наибольшую крейсерскую скорость","Прямо перед оживлённым перекрёстком в центре города, где городское движение вынуждает к частым резким остановкам","У въезда на большую парковку зоны отдыха, где много грузовиков стоят на ночёвке"],"explanation":"Аварийные съезды для грузовиков размещают на середине длинных крутых спусков, где у тяжелых транспортных средств чаще всего отказывают тормоза из-за перегрева."},"239":{"q":"Глубокая ночь, вы едете по сельскому двухполосному шоссе на ближнем свете фар, который освещает дорогу примерно на 250 футов вперёд. Впереди крутой поворот, и вы не видите, что находится на дороге за ним. Какое действие лучше всего соответствует правилу, что нельзя ехать быстрее, чем позволяет видимость фар?","options":["Включить дальний свет на повороте, чтобы видеть дальше за изгибом дороги, а затем вернуться на ближний свет на прямом участке","Снизить скорость перед входом в поворот, чтобы успеть остановиться в пределах того расстояния, которое реально освещают ваши фары","Сохранить текущую скорость, но держаться ближе к идущему впереди автомобилю, чтобы его задние огни вели вас через поворот","Держать шоссейную скорость, потому что при 55 миль/ч ваши фары всё равно покрывают все необходимые 419 футов тормозного пути"],"explanation":"Никогда не ездите быстрее, чем светят фары: снижайте скорость перед поворотом, чтобы остановиться в пределах освещенного фарами расстояния."},"240":{"q":"Вы закончили обход тягача с прицепом во время предрейсового осмотра, и внешне всё в порядке. Прежде чем выехать на дорогу и влиться в поток, как правильно убедиться, что рабочие тормоза действительно работают?","options":["Пропустить проверку работы тормозов, поскольку обход уже подтвердил, что детали тормозов выглядят исправно, и перепроверить только после первых 50 миль","Дождаться выхода на шоссейную скорость и затем сильно нажать на тормоза, чтобы почувствовать, не уводит ли грузовик в сторону","Тронуться с места на низкой скорости и плавно нажать на тормоза, чтобы убедиться, что машина останавливается и не уводит в сторону","Несколько раз нажать на педаль тормоза на стоянке и смотреть, падает ли давление воздуха по манометру — это докажет, что тормоза остановят вас"],"explanation":"После наружного осмотра проверьте рабочие тормоза, медленно тронувшись и плавно затормозив, чтобы убедиться, что машина останавливается и не уводит в сторону."},"241":{"q":"Вы ведете гружёный полуприцеп по двухполосному сельскому шоссе, когда сильный порыв бокового ветра внезапно толкает переднюю часть тягача к обочине. Чтобы сохранить наилучший контроль над машиной при корректировке рулевого управления, какое положение рук на руле самое безопасное?","options":["Держите одну руку внизу руля, чтобы сделать быстрый размашистый поворот против ветра","Рулите одной рукой, а другую держите наготове на ручном кране тормоза прицепа, чтобы притормозить прицеп","На мгновение дайте рулю свободно проскользнуть в руках, чтобы он сам выровнялся после порыва","Держите обе руки крепко на руле, на противоположных сторонах, чтобы реагировать плавно и сохранять устойчивый контроль"],"explanation":"Держите обе руки крепко на руле с противоположных сторон, чтобы плавно реагировать и сохранять устойчивый контроль при внезапном порыве бокового ветра."},"242":{"q":"Вы одни на переполненной стоянке для грузовиков, и единственный способ выехать с места -- сдать назад. У вас есть выбор: подготовить заезд так, чтобы сдавать назад в сторону левого (водительского) борта, или в сторону правого (слепого) борта, что было бы немного короче. Какой подход безопаснее и почему?","options":["Сдавать назад в сторону водительского (левого) борта, потому что вы можете выглянуть в окно и всё время напрямую видеть заднюю часть прицепа.","Сдавать назад в сторону слепого (правого) борта, потому что путь короче, а зеркала дают полный обзор этой стороны.","Любая сторона одинаково безопасна, если вы дважды посигналите и включите аварийную сигнализацию перед началом движения.","Сдавать только строго прямо и никогда не разворачивать прицеп под углом, потому что любая боковая сдача назад на стоянке запрещена."],"explanation":"Всегда сдавайте назад в сторону водителя (влево), потому что можно высунуться в окно и напрямую видеть заднюю часть прицепа, а не полагаться только на зеркала."},"243":{"q":"Вы ведёте гружёный тягач с полуприцепом по сухой ровной автомагистрали со скоростью 55 миль/ч и решаете обогнать другой грузовик. Чтобы сделать это безопасно, вы разгоняетесь до 65 миль/ч. По сравнению с остановкой на скорости 55 миль/ч, какое САМОЕ важное влияние это изменение скорости оказывает на вашу способность остановиться в экстренной ситуации?","options":["Тормозной путь остаётся примерно прежним, потому что дорога сухая, а тормоза исправны","Тормозной путь резко увеличивается, потому что путь торможения растёт примерно пропорционально квадрату скорости","Тормозной путь немного сокращается, потому что быстрее вращающиеся колёса лучше сцепляются с дорогой","Тормозной путь не зависит от скорости и определяется только весом вашего груза"],"explanation":"Тормозной путь резко увеличивается с ростом скорости, поскольку дистанция торможения растет примерно пропорционально квадрату скорости."},"244":{"q":"Вы ведёте гружёный тягач с прицепом вверх по разгонной полосе при въезде на оживлённую автомагистраль. Разгонная полоса довольно короткая, транспорт в правом ряду движется равномерно со скоростью около 60 миль/ч, и прямо перед вами открывается небольшой просвет. Чтобы выполнить слияние с потоком максимально безопасно, что вам следует сделать?","options":["Остановиться в конце разгонной полосы и ждать, пока весь поток полностью проедет, прежде чем выезжать","Аккуратно въехать в ряд на медленной, осторожной скорости и позволить более быстрому потоку подстроиться вокруг вашего автопоезда","Использовать разгонную полосу, чтобы набрать скорость потока транспорта, а затем перестроиться в открывшийся просвет","Удерживать своё положение в ряду и настойчиво пользоваться правом проезда, чтобы машины в основном ряду уступали вам"],"explanation":"Полоса разгона нужна, чтобы набрать скорость потока на шоссе и плавно встроиться в свободный промежуток, не вынуждая других тормозить или отворачивать."},"245":{"q":"Вы ведёте гружёный седельный тягач с прицепом в плотном городском потоке с частыми остановками. Пешеход, отвлёкшийся на телефон, сходит с тротуара и начинает выходить на вашу полосу на небольшом расстоянии впереди. Вы уже отпустили педаль газа и держите ногу над тормозом. Какое использование звукового сигнала в этот момент DPS считает уместным?","options":["Слегка и многократно подавать короткие сигналы, чтобы держать ближайших водителей в напряжении, ведь постоянная сигнализация в заторе предотвращает столкновения","Полностью отказаться от сигнала и полагаться только на торможение, поскольку подавать сигнал рядом с пешеходом в городском потоке никогда не разрешается","Дать длинный дружелюбный гудок, чтобы пешеход и окружающие водители знали, что к перекрёстку приближается большой грузовик","Подать сигнал, чтобы предупредить пешехода о непосредственной опасности, используя его только для предупреждения других об угрозе"],"explanation":"Сигнал — это предупреждающее устройство, используемое только для оповещения о реальной непосредственной опасности, например о невнимательном пешеходе на вашем пути."},"246":{"q":"Температура чуть ниже нуля, и вам нужно припарковать тягач с прицепом на правой обочине дороги с крутым спуском под уклон. Вы ставите стояночный тормоз, но понимаете, что на этом обледеневшем склоне один тормоз может не удержать машину, если она начнёт скатываться. Чтобы бордюр служил последним упором на случай отката, в какую сторону следует повернуть передние колёса?","options":["Повернуть передние колёса к бордюру (вправо), чтобы при откате вперёд переднее колесо упёрлось в бордюр","Повернуть передние колёса от бордюра (влево, к проезжей части), чтобы при откате машина съехала с бордюра","Оставить передние колёса прямо, ведь стояночный тормоз и противооткатные упоры держат сами","Направление не имеет значения на спуске, если стояночный тормоз включён"],"explanation":"При парковке носом вниз по склону поверните передние колёса к бордюру, чтобы при откате вперёд колесо упёрлось в него и остановило машину."},"247":{"q":"Вы ведете груженый тягач с прицепом по сельскому двухполосному шоссе со скоростью 50 миль/ч и опускаете взгляд, чтобы проверить зеркало. Подняв глаза, вы видите, что колеса правой стороны съехали с покрытия на мягкую гравийную обочину, а тягач слегка тянет вправо. Прямо впереди препятствий нет. Как ЛУЧШЕ всего вернуться на проезжую часть?","options":["Немедленно вернитесь на покрытие быстрым, резким поворотом руля, чтобы выправить траекторию, пока не съехали еще дальше","Уберите ногу с педали газа, крепко держите руль и плавно вернитесь на покрытие после того, как грузовик замедлится и будет под контролем","Сразу сильно нажмите на тормоз, чтобы сбросить скорость, прежде чем какая-либо часть автопоезда покинет обочину","Нажмите на газ, чтобы пройти мягкий гравий на тяге и вытянуть автопоезд обратно на более твердое покрытие"],"explanation":"Если колёса съехали на обочину, отпустите газ без резкого торможения и плавно вернитесь на дорогу после того, как грузовик замедлится."},"248":{"q":"Вы ведете гружёный тягач с прицепом по правой полосе двухполосного шоссе со скоростью 55 миль/ч (разрешённая). Последние несколько минут пикап едет за вами так близко (\"на хвосте\"), что вы уже не видите его фар в зеркалах, а впереди вас нет машин. Движение в левой полосе слабое. Как БЕЗОПАСНЕЕ всего поступить с этим водителем, который едет вплотную сзади?","options":["Несколько раз слегка нажать на тормоз, чтобы мигнуть стоп-сигналами и предупредить водителя, чтобы он отстал","Сохранять скорость, но сократить дистанцию до машин впереди, чтобы у севшего на хвост водителя было больше места","Увеличить дистанцию до машин впереди, а затем перестроиться и пропустить севшего на хвост водителя, когда это будет безопасно","Постепенно разогнаться значительно выше 55 миль/ч, пока тот, кто сел на хвост, не перестанет ехать вплотную"],"explanation":"При наседающем сзади водителе увеличьте дистанцию впереди, а затем перестройтесь и дайте ему безопасно обогнать."},"249":{"q":"Вы ведёте гружёный тягач с прицепом по многополосной автомагистрали, и вам нужно перестроиться в правый ряд перед съездом, который будет примерно через милю. Движение умеренное, а где-то сзади в вашей правой слепой зоне находится легковой автомобиль. Согласно рекомендациям DPS по взаимодействию с другими водителями, какой ЕДИНСТВЕННЫЙ ЛУЧШИЙ способ дать понять окружающим водителям, что вы намереваетесь сделать?","options":["Несколько раз слегка нажать на тормоз, чтобы водитель позади увидел стоп-сигналы и понял, что вы собираетесь замедлиться и перестроиться","Поморгать дальним светом фар автомобилям в правом ряду, чтобы предупредить их, что вы перестраиваетесь","Ускориться и быстро совершить перестроение, чтобы провести как можно меньше времени рядом с машиной в слепой зоне","Заранее включить правый указатель поворота и оставить его включённым, чётко и заблаговременно сигнализируя о своём намерении сменить полосу"],"explanation":"Чётко сообщайте о своих намерениях, включая поворотник заранее и задолго до манёвра, чтобы у других водителей было время среагировать."},"250":{"q":"Вы ведёте 30-футовый одиночный грузовик по сухой автомагистрали, двигаясь равномерно со скоростью 50 миль/ч при небольшом потоке. Легковой автомобиль впереди постоянно перестраивается, поэтому вы решаете установить безопасную дистанцию следования. Согласно стандартному правилу дистанции следования, какую НАИМЕНЬШУЮ дистанцию следования вы должны держать за этим автомобилем?","options":["4 секунды","3 секунды","5 секунд","6 секунд"],"explanation":"Отсчитывайте 1 секунду дистанции на каждые 10 футов длины и добавляйте 1 секунду свыше 40 миль/ч: 30-футовый грузовик на 50 милях/ч требует 3 + 1 = 4 секунды."},"251":{"q":"Вы ведёте 40-футовый грузовик (одиночное транспортное средство) через город, и спидометр стабильно показывает 35 миль/ч по сухому покрытию. Движение слабое, но вы хотите выдержать безопасную дистанцию за идущей впереди машиной, чтобы успеть среагировать, если она резко затормозит. Применяя рекомендованное правило дистанции следования для длины вашего транспортного средства и текущей скорости, какую НАИМЕНЬШУЮ дистанцию следования вам следует держать?","options":["5 секунд, потому что 40-футовое транспортное средство автоматически требует на одну секунду больше базовой величины","4 секунды, потому что вы отводите 1 секунду на каждые 10 футов длины и ничего не добавляете при скорости ниже 40 миль/ч","3 секунды, потому что три секунды — это стандартный минимальный интервал для любого коммерческого транспортного средства","6 секунд, потому что при такой длине ради безопасности всегда нужно удваивать счёт на каждые 10 футов"],"explanation":"Отсчитывайте 1 секунду дистанции на каждые 10 футов длины и ничего не добавляйте ниже 40 миль/ч, поэтому 40-футовому грузовику на 35 милях/ч нужно 4 секунды."},"252":{"q":"Вы перевозите грузовой автопоезд с бортовой платформой, общая длина которого составляет 50 футов от бампера до бампера. Движение на автостраде стало плотнее, а ваш спидометр стабильно держится на отметке 55 миль/ч в сухую, ясную погоду. Пристроившись за идущим впереди транспортным средством, какую минимальную дистанцию следования в секундах вам следует соблюдать, чтобы оставаться в пределах безопасного промежутка, рекомендованного руководством?","options":["5 секунд, потому что вы отводите 1 секунду на каждые 10 футов длины транспортного средства","7 секунд, добавляя 2 дополнительные секунды, так как ваша скорость значительно превышает 40 миль/ч","6 секунд, потому что 50 футов дают вам 5 секунд, и вы добавляете еще 1 за превышение 40 миль/ч","4 секунды, поскольку стабильная скорость на трассе в сухую погоду позволяет сократить промежуток"],"explanation":"Отсчитывайте 1 секунду на каждые 10 футов длины и добавляйте 1 секунду свыше 40 миль/ч: 50-футовому транспортному средству на 55 милях/ч нужно 5 + 1 = 6 секунд."},"253":{"q":"Вы ведёте автопоезд (тягач с прицепом) длиной 60 футов по сухому, ровному межштатному шоссе при хорошей видимости днём, удерживая постоянную скорость 45 миль/ч. Движение слабое, но вы хотите установить безопасную дистанцию до идущего впереди автомобиля. В каком из вариантов правильно указана минимальная дистанция следования в секундах, которую вам следует выдерживать?","options":["6 секунд, потому что на каждые 10 футов длины транспортного средства отводится 1 секунда","5 секунд, так как длинному составному транспортному средству нужно лишь около половины секунды на каждые 10 футов","8 секунд, добавляя 2 дополнительные секунды, потому что вы едете быстрее 40 миль/ч","7 секунд, потому что вы отводите 6 секунд за длину плюс ещё 1 секунду за скорость выше 40 миль/ч"],"explanation":"Отсчитывайте 1 секунду на каждые 10 футов длины и добавляйте 1 секунду свыше 40 миль/ч: 60-футовому транспортному средству на 45 милях/ч нужно 6 + 1 = 7 секунд."},"254":{"q":"Вы ведете автопоезд длиной 70 футов по ровной городской магистрали, удерживая постоянную скорость 35 миль/ч в ясную, сухую погоду. Транспорт впереди движется плавно, и вы хотите установить безопасную дистанцию следования. Используя формулу для определения дистанции следования, МИНИМАЛЬНЫЙ интервал, который вы должны держать за идущим впереди транспортным средством, составляет:","options":["7 секунд","8 секунд","6 секунд","9 секунд"],"explanation":"Дистанция должна составлять 1 секунду на каждые 10 футов длины машины, а на скорости ниже 40 миль/ч дополнительная секунда не добавляется, поэтому 70-футовому грузовику нужно 7 секунд."},"255":{"q":"Вы перевозите груз по сухой автомагистрали, и спидометр стабильно показывает 45 миль/ч. Взглянув в зеркала, вы оцениваете, что ваш автопоезд (тягач с прицепом) растянулся на целых 80 футов от переднего бампера до задней части прицепа. Поток движется ровно, и вы хотите выдержать безопасную дистанцию до машины впереди. Согласно рекомендуемому правилу дистанции следования, сколько секунд интервала вам следует держать?","options":["8 секунд, потому что правило — это просто 1 секунда на каждые 10 футов длины транспортного средства","9 секунд, потому что 80 футов дают 8 секунд, и вы добавляете 1 секунду за движение со скоростью выше 40 миль/ч","7 секунд, поскольку на этой скорости можно убрать одну секунду из расчёта по длине","10 секунд, потому что длину следует округлить в большую сторону и добавить целых 2 секунды запаса на трассе"],"explanation":"Базовая дистанция — 1 секунда на каждые 10 футов длины, что даёт 8 секунд, плюс 1 секунда добавляется на скорости выше 40 миль/ч, итого 9 секунд."},"256":{"q":"Вы ведёте автопоезд длиной 90 футов по сухой автомагистрали с постоянной скоростью 50 миль/ч при слабом потоке. Легковой автомобиль перестраивается перед вами, и вам нужно восстановить безопасный интервал. Согласно правилу дистанции следования, какой НАИМЕНЬШИЙ интервал вы должны держать за этим автомобилем?","options":["9 секунд, потому что правило — это просто 1 секунда на каждые 10 футов длины транспортного средства","8 секунд, ведь можно сократить время, когда вы уже устойчиво едете по сухому покрытию","10 секунд дистанции следования","11 секунд, добавляя 2 дополнительные секунды, потому что вы значительно превышаете 40 миль/ч"],"explanation":"Базовая дистанция — 1 секунда на каждые 10 футов длины, что даёт 9 секунд, плюс 1 секунда добавляется на скорости выше 40 миль/ч, итого 10 секунд."},"257":{"q":"Вы управляете сцепкой с бортовой платформой, длина которой составляет 100 футов от переднего бампера до конца прицепа. Поток разрежается, и вы разгоняетесь до 60 миль/ч на сухой автомагистрали. Взглянув в зеркало, вы хотите установить безопасную дистанцию до автомобиля, за которым следуете. Согласно правилу дистанции следования, какое МИНИМАЛЬНОЕ количество секунд интервала вы должны сохранять?","options":["10 секунд, потому что вы выделяете 1 секунду на каждые 10 футов длины транспортного средства, а 100, делённое на 10, равно 10","12 секунд: 1 секунда на каждые 10 футов плюс 2 дополнительные секунды за более высокую скорость","9 секунд, так как 60 миль/ч достаточно много, чтобы вычесть одну секунду из расчёта по длине","11 секунд, потому что 100 футов дают 10 секунд, и вы добавляете ещё 1 секунду за движение со скоростью выше 40 миль/ч"],"explanation":"Базовая дистанция — 1 секунда на каждые 10 футов длины, что даёт 10 секунд, плюс 1 секунда добавляется на скорости выше 40 миль/ч, итого 11 секунд."},"258":{"q":"Вы ведете 40-футовый одиночный грузовик по сухой автомагистрали, удерживая постоянные 55 миль/ч при хорошей видимости днем. Движение впереди свободное. Применяя правило учебника о безопасной дистанции следования, какой МИНИМАЛЬНЫЙ интервал вы должны сохранять до идущего впереди транспортного средства?","options":["5 секунд","4 секунды","6 секунд","3 секунды"],"explanation":"Базовая дистанция — 1 секунда на каждые 10 футов длины, что даёт 4 секунды, плюс 1 секунда добавляется на скорости выше 40 миль/ч, итого 5 секунд."},"259":{"q":"Вы перевозите груз на бортовом полуприцепе и во время предрейсового осмотра измеряете свой автопоезд: от бампера до бампера он составляет 50 футов. На сухом загородном шоссе при слабом движении ваш спидометр стабильно держится на 50 милях в час. Применяя правило для определения безопасной дистанции до идущего впереди транспортного средства, сколько секунд дистанции вам следует сохранять при такой скорости и длине?","options":["5 секунд, потому что вы добавляете 1 секунду на каждые 10 футов длины транспортного средства","6 секунд, потому что вы добавляете 1 секунду на каждые 10 футов длины и прибавляете ещё 1 секунду за скорость выше 40 миль в час","7 секунд, потому что вы добавляете 1 секунду на каждые 10 футов длины и прибавляете ещё 2 секунды за скорость на шоссе","4 секунды, потому что дистанция зависит только от скорости, а не от длины транспортного средства"],"explanation":"Базовая дистанция — 1 секунда на каждые 10 футов длины, что даёт 5 секунд, плюс 1 секунда добавляется на скорости выше 40 миль/ч, итого 6 секунд."},"260":{"q":"Вы ведёте автопоезд длиной 70 футов (около 21 м) по сухой ровной автомагистрали, удерживая постоянную скорость 45 миль/ч при небольшом трафике. Взглянув в зеркала, вы решаете задать дистанцию следования, отсчитывая секунды, за которые вы доедете до неподвижного ориентира после того, как его проедет идущий впереди транспорт. Исходя из длины вашего транспортного средства и текущей скорости, какова МИНИМАЛЬНАЯ дистанция следования, которую вам следует выдерживать?","options":["7 секунд, потому что правило простое: 1 секунда на каждые 10 футов длины транспортного средства","6 секунд, так как около 6 секунд общего тормозного пути достаточно на скорости автомагистрали","8 секунд, потому что нужна 1 секунда на каждые 10 футов длины и 1 дополнительная секунда за скорость выше 40 миль/ч","9 секунд, добавляя секунду за сухое покрытие к секундам за длину и скорость"],"explanation":"Базовая дистанция — 1 секунда на каждые 10 футов длины, что даёт 7 секунд, плюс 1 секунда добавляется на скорости выше 40 миль/ч, итого 8 секунд."},"261":{"q":"Вы управляете сцепкой с бортовым прицепом длиной 80 футов от переднего бампера до задней части прицепа. Движение спокойное по ровному двухполосному шоссе, и спидометр устойчиво показывает 35 миль/ч. Какую дистанцию следования за грузовиком впереди вам следует выдерживать для безопасности?","options":["9 секунд, потому что берёте 8 секунд за длину и добавляете ещё 1 секунду за скорость на шоссе","7 секунд, поскольку на низкой скорости запас можно уменьшить на одну секунду","10 секунд — максимальный запас, который когда-либо нужен любой крупной сцепке","8 секунд, потому что каждые 10 футов длины требуют 1 секунду, и при скорости ниже 40 миль/ч дополнительная секунда не добавляется"],"explanation":"Дистанция — 1 секунда на каждые 10 футов длины, то есть 8 секунд, а на 35 миль/ч (ниже 40) дополнительная секунда не добавляется, поэтому запас составляет 8 секунд."},"262":{"q":"Во время предрейсового осмотра вы закрепляете одну стальную трубу длиной 15 футов на бортовой платформе. Труба полностью укладывается в рабочий предел нагрузки ваших ремней. Чтобы соблюсти федеральный минимум по креплению груза, какое НАИМЕНЬШЕЕ число креплений вы можете законно использовать на этой одной трубе?","options":["2 крепления","1 крепление","3 крепления","4 крепления"],"explanation":"Груз требует не менее 1 крепления на каждые 10 футов длины и не менее 2 для любого предмета длиннее 5 футов, поэтому 15-футовая труба требует 2 крепления."},"263":{"q":"Во время предрейсового осмотра вы обнаруживаете на прицепе одну стальную двутавровую балку длиной 25 футов, уложенную плашмя и закреплённую всего 2 цепными стяжками. Балка полностью укладывается в ваши весовые ограничения, а платформа в хорошем состоянии. Прежде чем вы сможете законно тронуться, каково МИНИМАЛЬНОЕ число стяжек, которое должно удерживать этот груз?","options":["2 стяжки, поскольку любой предмет длиннее 5 футов по закону требует не менее 2 крепёжных устройств","3 стяжки, поскольку нужна минимум одна стяжка на каждые 10 футов груза, а 25 футов округляются вверх до 3","4 стяжки, поскольку длинную тяжёлую сталь нужно крепить через каждые 5 футов её длины","1 стяжка, поскольку балка — это единый жёсткий предмет, прочно лежащий на платформе"],"explanation":"Груз требует не менее 1 крепления на каждые 10 футов длины с округлением вверх, поэтому 25-футовая балка требует 3 крепления."},"264":{"q":"Во время предрейсового осмотра вы закрепляете одну стальную балку длиной 35 футов, лежащую на бортовой платформе. Зная правило о том, сколько креплений требуется для груза такой длины, какое НАИМЕНЬШЕЕ число креплений вы можете законно использовать для закрепления этой балки?","options":["3 крепления, так как 35 футов, делённые на 10, дают три полных 10-футовых участка","2 крепления, потому что любому отдельному предмету достаточно по одному с каждого конца","4 крепления, потому что требуется минимум одно на каждые 10 футов, и 35 футов округляются в большую сторону","5 креплений, так как балка такой длины требует одно дополнительное для запаса безопасности"],"explanation":"Крепление груза требует минимум одной стяжки на каждые 10 футов длины, округляя любой неполный участок вверх, поэтому 35 футов требуют 4."},"265":{"q":"Во время предрейсового осмотра вы закрепляете одну стальную балку длиной 45 футов на платформе. Балка весит 9 000 фунтов, а рабочий предел нагрузки каждой цепи значительно превышает требования груза, поэтому весовой рейтинг здесь вас не беспокоит. Опираясь ТОЛЬКО на правило о минимальном количестве креплений, какое НАИМЕНЬШЕЕ число креплений вы обязаны использовать, чтобы законно перевозить эту балку?","options":["4 крепления, потому что вы считаете по одному на каждые полные 10 футов длины и не учитываете оставшиеся 5 футов","3 крепления, так как рабочий предел нагрузки и без того достаточно высок, чтобы удержать груз","6 креплений, добавляя одно сверх правила длины как запас прочности","5 креплений, потому что нужно как минимум одно на каждые 10 футов, а 45 футов округляются вверх до 5"],"explanation":"Требуется минимум одна стяжка на каждые 10 футов груза, любой остаток округляется вверх, поэтому 45-футовый груз требует 5."},"266":{"q":"Во время предрейсового осмотра вы закрепляете одну стальную балку длиной 55 футов на бортовой платформе. Вы хотите выполнить минимальное федеральное требование / требование штата Техас по количеству креплений в зависимости от длины груза. Учитывая только требование по длине, какое НАИМЕНЬШЕЕ число креплений вы можете законно использовать для этой балки?","options":["6 креплений, потому что нужно минимум одно на каждые 10 футов груза, а 55 футов округляются в большую сторону до 6","5 креплений, потому что 55 разделить на 10 равно 5, а остаток отбрасывается","7 креплений, потому что нужно по одному на каждые 10 футов плюс одно дополнительное для любого предмета длиннее 5 футов","4 крепления, потому что по два крепления на каждом конце достаточно, чтобы зафиксировать любую отдельную балку"],"explanation":"Требуется одна стяжка на каждые 10 футов груза, любой неполный участок округляется вверх, поэтому 55-футовый груз требует 6."},"267":{"q":"Во время предрейсового осмотра вы закрепляете одну стальную балку на бортовой платформе. Её длина около 8 футов, а вес примерно 3000 фунтов. Вы рассуждаете так: поскольку она заметно короче 10 футов, правило «одна стяжка на каждые 10 футов» означает, что достаточно одной стяжки. Какое утверждение верно описывает МИНИМАЛЬНОЕ число стяжек, которое вы обязаны использовать?","options":["1 стяжка, потому что балка короче 10 футов и действует правило «одна на 10 футов»","2 стяжки, потому что любой предмет длиннее 5 футов требует не менее 2 стяжек независимо от расчёта «на 10 футов»","1 стяжка, потому что балка весит меньше порога в 1100 фунтов для одной стяжки","Для одного столь короткого предмета стяжки не требуются"],"explanation":"Любой отдельный предмет груза длиной более 5 футов должен иметь минимум 2 стяжки, независимо от расчёта на каждые 10 футов."},"268":{"q":"Обычно вы проезжаете участок сельской трассы со скоростью 25 миль/ч, и по опыту знаете, что вашему гружёному автопоезду нужно примерно 30 футов тормозного пути после того, как тормоза сработали. Сегодня ночью вы едете по той же дороге, с тем же грузом, по тому же сухому покрытию, но со скоростью 50 миль/ч. По сравнению с обычным тормозным путём на 25 миль/ч ваш тормозной путь на 50 миль/ч составит примерно:","options":["Примерно столько же, ведь груз и покрытие не изменились","Примерно вдвое больше, ведь вы удвоили скорость","Примерно в четыре раза больше, потому что тормозной путь растёт пропорционально квадрату скорости","Примерно вдвое короче, ведь колёса вращаются быстрее и быстрее рассеивают энергию"],"explanation":"Тормозной путь растёт пропорционально квадрату скорости, поэтому удвоение скорости увеличивает тормозной путь примерно в четыре раза."},"269":{"q":"Вы едете по сухому ровному шоссе со скоростью 55 миль/ч в хорошую погоду, когда впереди на вашей полосе внезапно появляется заглохший автомобиль. Пассажир спрашивает, сколько на самом деле потребуется дороги, чтобы полностью остановиться с момента, как вы впервые заметили опасность. Учитывая время восприятия, реакции И торможения, какая оценка общего тормозного пути ближе всего к истине?","options":["Около 60 футов — примерно расстояние, которое грузовик проезжает только за время реакции","Около 100 футов — немного больше одной длины грузовика","Около 250 футов — расстояние, которое ночью освещают ваши фары ближнего света","Около 419 футов — почти длина футбольного поля с обеими зачётными зонами (около 6 секунд движения)"],"explanation":"Общий остановочный путь — это путь восприятия плюс путь реакции плюс тормозной путь, что при 55 миль/ч составляет около 419 футов (примерно 6 секунд)."},"270":{"q":"Обычно на городском маршруте доставки вы едете со скоростью 30 миль/ч, но сегодня объезд выводит вас на шоссе со скоростью 60 миль/ч при том же сухом покрытии и том же гружёном прицепе. Едущий с вами новичок считает, что раз вы лишь удвоили скорость, то и тормозной путь увеличится примерно вдвое. Как примерно УДВОЕНИЕ скорости на самом деле меняет ваш тормозной путь?","options":["Тормозной путь увеличивается примерно в четыре раза, потому что он растёт пропорционально квадрату скорости","Тормозной путь увеличивается лишь примерно вдвое, прямо пропорционально скорости","Тормозной путь остаётся почти прежним, потому что гружёный прицеп добавляет сцепление","Тормозной путь увеличивается лишь незначительно, ведь со скоростью на самом деле растёт расстояние реакции"],"explanation":"Тормозной путь увеличивается пропорционально квадрату скорости, поэтому удвоение скорости делает его примерно в четыре раза длиннее, а не вдвое."},"271":{"q":"Вы едете с шоссейной скоростью, когда впереди на дорогу внезапно выходит олень. Самая первая фаза остановки — это ВОСПРИЯТИЕ: время с момента, когда олень впервые попадает в ваше поле зрения, до момента, когда мозг действительно распознаёт его как опасность. Эта фаза происходит ещё до того, как вы начнёте двигать ногу к тормозу. Сколько примерно ВРЕМЕНИ занимает сама по себе эта фаза восприятия у внимательного водителя на скорости около 55 миль/ч?","options":["Около 3/4 секунды — но это на самом деле время реакции, нужное, чтобы перенести ногу на педаль уже после того, как опасность распознана","Около 1,75 секунды — время, которое в руководстве отводится на восприятие и распознавание опасности на шоссейной скорости, ещё до начала какой-либо реакции","Около 6 секунд — но это в действительности полное время остановки со скорости 55 миль/ч, а не только фаза восприятия","Около одной десятой секунды, ведь внимательный профессиональный водитель воспринимает опасность почти мгновенно"],"explanation":"Восприятие — это время, нужное мозгу, чтобы увидеть и распознать опасность, около 1,75 секунды на трассовой скорости до начала реакции."},"272":{"q":"Вы едете со скоростью 55 миль/ч по сухой автостраде, когда впереди на вашей полосе внезапно появляется заглохший автомобиль. К моменту полной остановки ваш грузовик проедет примерно длину футбольного поля с двумя зачётными зонами (около 419 футов). Инструкторы делят эту общую тормозную дистанцию на три части: расстояние, пройденное, пока вы УВИДИТЕ опасность (дистанция восприятия), расстояние, пройденное, пока вы переносите ногу на педаль (дистанция реакции), и ещё одну часть. Какая часть завершает общую тормозную дистанцию?","options":["Дистанция руления — расстояние, пройденное, пока вы поворачиваете руль, чтобы объехать препятствие","Дистанция подачи сигнала — расстояние, пройденное, пока вы включаете аварийную сигнализацию, чтобы предупредить движение","Тормозной путь — расстояние, которое грузовик проезжает после срабатывания тормозов до полной остановки","Дистанция парковки — дополнительное место у обочины, которое вы оставляете после безопасной остановки"],"explanation":"Третья составляющая общего остановочного пути — тормозной путь, то есть расстояние, которое грузовик проходит после нажатия на тормоза до полной остановки."},"273":{"q":"Вы ведёте свой прямой грузовик длиной 20 футов по ровной автомагистрали в хорошую погоду, удерживая постоянную скорость 35 миль/ч в небольшом потоке. Вы хотите оставить правильную минимальную дистанцию следования за впереди идущей машиной. Используя правило 1 секунда на каждые 10 футов длины транспортного средства, сколько секунд дистанции следования вам следует держать при этой скорости?","options":["4 секунды, потому что всегда нужно добавлять целую дополнительную секунду на каждые 10 футов длины грузовика","3 секунды, добавляя 1 секунду к значению по длине, потому что поток на автомагистрали непредсказуем","1 секунда, поскольку при 35 милях/ч вы движетесь ниже 40 миль/ч, и правило дополнительной секунды не применяется","2 секунды, потому что 20 футов длины дают 2 секунды, и ниже 40 миль/ч секунда не добавляется"],"explanation":"На скорости ниже 40 миль/ч нужна 1 секунда дистанции на каждые 10 футов длины машины, поэтому 20-футовому транспорту нужно 2 секунды."},"274":{"q":"Вы управляете 20-футовым (около 6 метров) бортовым грузовиком по сухому шоссе с постоянной скоростью 55 миль/ч в ясную погоду. Движение слабое, и вы хотите выдержать безопасную дистанцию до машины впереди. Используя правило определения дистанции по длине транспортного средства и скорости, сколько секунд интервала вам следует сохранять?","options":["3 секунды","2 секунды","4 секунды","6 секунд"],"explanation":"Соблюдайте 1 секунду дистанции на каждые 10 футов длины транспортного средства и добавляйте ещё 1 секунду при скорости выше 40 миль/ч."},"275":{"q":"Вы управляете одиночным грузовиком длиной 30 футов от бампера до бампера. Движение в городе плавное, и спидометр показывает 35 миль/ч. Чтобы сохранить безопасный запас впереди, какую минимальную дистанцию следования вы должны держать за идущим впереди транспортным средством?","options":["2 секунды, потому что дорога ровная и вы движетесь намного ниже шоссейной скорости","3 секунды, потому что при этой скорости вы отсчитываете 1 секунду на каждые 10 футов длины своего транспортного средства","4 секунды, добавляя 1 лишнюю секунду к дистанции по длине, так как вы движетесь в потоке","5 секунд, как запас, используемый на более высоких шоссейных скоростях для транспортного средства такой длины"],"explanation":"Соблюдайте 1 секунду дистанции на каждые 10 футов длины транспортного средства; при скорости ниже 40 миль/ч дополнительная секунда не добавляется."},"276":{"q":"Вы ведёте одиночный прямой грузовик длиной 30 футов по сухой автомагистрали, удерживая стабильную скорость 55 миль/ч при небольшом трафике. Чтобы сохранять безопасную дистанцию до машины впереди, вы выбираете неподвижный объект на обочине и считаете секунды, пока ваш передний бампер не поравняется с ним. Какую дистанцию следования в секундах вы должны держать в этой ситуации?","options":["3 секунды, потому что правило — 1 секунда на каждые 10 футов длины транспортного средства","5 секунд, добавляя 1 лишнюю секунду сверх того, что требует правило длины и скорости","4 секунды, потому что 30 футов дают 3 секунды, и вы добавляете ещё 1 секунду за скорость выше 40 миль/ч","2 секунды — тот же минимальный интервал, что держит легковой автомобиль на трассе"],"explanation":"Соблюдайте 1 секунду дистанции на каждые 10 футов длины транспортного средства и добавляйте ещё 1 секунду при скорости выше 40 миль/ч."},"277":{"q":"Вы везёте прямой груз на машине длиной 40 футов по сухому ровному шоссе, и при слабом движении ваш спидометр показывает 50 миль/ч. Какую дистанцию следования в секундах нужно сохранять в этой ситуации, чтобы оставить безопасный запас до едущего впереди транспортного средства?","options":["4 секунды, так как на каждые 10 футов длины вашего транспортного средства отводится 1 секунда","6 секунд, поскольку это соответствует полному тормозному пути, который нужен грузовику на скорости шоссе","3 секунды, по стандартному правилу трёх секунд, которое применяется ко всем транспортным средствам","5 секунд, потому что к расчёту по длине добавляется 1 дополнительная секунда, когда вы едете быстрее 40 миль/ч"],"explanation":"Соблюдайте 1 секунду дистанции на каждые 10 футов длины транспортного средства и добавляйте ещё 1 секунду при скорости выше 40 миль/ч."},"278":{"q":"Вы ведёте автопоезд длиной 60 футов по сухой автомагистрали и держите постоянную скорость 50 миль/ч при небольшом трафике. Легковой автомобиль впереди задаёт вам темп, и вы хотите оставить безопасный промежуток. Используя базовое правило дистанции следования из пособия, сколько секунд интервала вы должны держать позади этого автомобиля?","options":["7 секунд, потому что 60 футов длины дают 6 секунд, плюс 1 дополнительная секунда за движение со скоростью выше 40 миль/ч","6 секунд, потому что вы отводите 1 секунду на каждые 10 футов длины транспортного средства","8 секунд, потому что вы добавляете 2 секунды за скорость на автомагистрали поверх 6 секунд за длину","5 секунд, потому что 60-футовому транспортному средству на умеренной скорости нужно около половины секунды на каждые 5 футов"],"explanation":"Соблюдайте 1 секунду дистанции на каждые 10 футов длины транспортного средства и добавляйте ещё 1 секунду при скорости выше 40 миль/ч."},"279":{"q":"Вы ведёте автопоезд длиной 70 футов по сухой автомагистрали с постоянной скоростью 55 миль/ч в ясную дневную погоду. Водитель впереди слегка тормозит, и вы понимаете, что подъехали ближе, чем следует. Используя эмпирическое правило дистанции следования, какой МИНИМАЛЬНЫЙ интервал вы должны держать за этим транспортным средством?","options":["7 секунд, потому что вы отводите 1 секунду на каждые 10 футов длины вашего транспортного средства","8 секунд, потому что вы отводите 1 секунду на каждые 10 футов длины и добавляете ещё 1 секунду за движение со скоростью свыше 40 миль/ч","6 секунд, потому что полный тормозной путь при 55 милях/ч составляет около 6 секунд","9 секунд, отводя 1 секунду на каждые 10 футов плюс 2 дополнительные секунды за скорость на автомагистрали"],"explanation":"Соблюдайте 1 секунду дистанции на каждые 10 футов длины транспортного средства и добавляйте ещё 1 секунду при скорости выше 40 миль/ч."},"280":{"q":"Вы перевозите груз через зону дорожных работ с ограничением 35 миль/ч на автопоезде длиной 90 футов от бампера до бампера. Движение равномерное, покрытие сухое, и вы хотите выбрать безопасную дистанцию следования по правилу секунд для длины транспортного средства. Сколько секунд дистанции следования вам нужно держать за идущим впереди автомобилем в этой ситуации?","options":["10 секунд, потому что любой автопоезд такой длины требует добавления одной лишней секунды независимо от скорости","8 секунд, потому что длину 90 футов округляют вниз до ближайшего целого интервала правила","9 секунд, потому что вы отводите 1 секунду на каждые 10 футов длины транспортного средства, а ваша скорость менее 40 миль/ч","11 секунд, потому что вы отводите 1 секунду на каждые 10 футов и добавляете целую лишнюю секунду за зону дорожных работ"],"explanation":"Соблюдайте 1 секунду дистанции на каждые 10 футов длины транспортного средства; при скорости ниже 40 миль/ч дополнительная секунда не добавляется."},"281":{"q":"Вы ведете автопоезд длиной 90 футов по ровной автомагистрали, и спидометр стабильно показывает 60 миль/ч в ясную сухую погоду. Транспорт впереди движется свободно. Применяя правило руководства для оценки безопасной дистанции следования, сколько секунд интервала вы должны держать между передней частью своего автопоезда и автомобилем впереди?","options":["8 секунд, потому что при 60 милях/ч вы уменьшаете базовое значение с учетом более высокой скорости на трассе","11 секунд, добавляя 2 дополнительные секунды, потому что вы движетесь значительно выше 40 миль/ч","9 секунд, так как вы просто считаете 1 секунду на каждые 10 футов длины транспортного средства","10 секунд, считая 1 секунду на каждые 10 футов длины и добавляя еще 1 секунду за скорость выше 40 миль/ч"],"explanation":"Соблюдайте 1 секунду дистанции на каждые 10 футов длины транспортного средства и добавляйте ещё 1 секунду при скорости выше 40 миль/ч."},"282":{"q":"Вы ведёте автопоезд длиной 100 футов по ровной, сухой сельской автомагистрали, и спидометр устойчиво показывает 35 миль/ч. Легковой автомобиль впереди движется с той же скоростью, и вы хотите выдержать безопасную дистанцию. Отсчитывая секунды, за которые ваш передний бампер достигнет неподвижного ориентира, только что пройденного машиной впереди, какую МИНИМАЛЬНУЮ дистанцию следования вам следует держать?","options":["10 секунд","11 секунд","9 секунд","7 секунд"],"explanation":"Соблюдайте 1 секунду дистанции на каждые 10 футов длины транспортного средства; при скорости ниже 40 миль/ч дополнительная секунда не добавляется."},"283":{"q":"Вы ведёте автопоезд с бортовым полуприцепом, и от бампера до бампера он составляет ровно 100 футов (примерно 30 метров). Движение на загородном шоссе установилось, а спидометр устойчиво держит 45 миль/ч на сухом, чистом покрытии. Отсчитывая секунды по тому, как идущий впереди автомобиль проходит неподвижный ориентир, сколько секунд дистанции вам следует выдерживать позади него?","options":["10 секунд, так как вы отводите 1 секунду на каждые 10 футов длины своего транспортного средства","11 секунд, потому что 100 футов требуют 10 секунд, и вы добавляете ещё 1 секунду за скорость выше 40 миль/ч","12 секунд, отводя 1 секунду на каждые 10 футов плюс 2 дополнительные секунды за скорость на шоссе","9 секунд, округляя длину 100-футового автопоезда в меньшую сторону из-за сухого покрытия"],"explanation":"Соблюдайте 1 секунду дистанции на каждые 10 футов длины транспортного средства и добавляйте ещё 1 секунду при скорости выше 40 миль/ч."},"284":{"q":"Вы ведёте автопоезд длиной 60 футов по сухой автомагистрали, стабильно держа скорость 60 миль/ч при небольшом потоке. Вспоминая правило дистанции следования из руководства, какой МИНИМАЛЬНЫЙ интервал вы должны сохранять до идущего впереди транспортного средства?","options":["6 секунд, потому что транспортному средству длиной 60 футов нужна 1 секунда на каждые 10 футов длины","5 секунд, так как поток небольшой, а дорога сухая","7 секунд: 1 секунда на каждые 10 футов длины плюс 1 дополнительная секунда за скорость выше 40 миль/ч","8 секунд, прибавляя 2 секунды к базовому значению, потому что речь идёт о скорости автомагистрали"],"explanation":"Соблюдайте 1 секунду дистанции на каждые 10 футов длины транспортного средства и добавляйте ещё 1 секунду при скорости выше 40 миль/ч."},"285":{"q":"Вы ведете груженый тягач с полуприцепом на загородной двухполосной дороге с сухим покрытием в сумерках на скорости автомагистрали, когда крупный олень выскакивает из лесополосы и замирает в вашей полосе примерно в 150 футах впереди. Левая полоса кажется свободной, а справа есть мощеная обочина. Какое действие обычно является САМЫМ безопасным?","options":["Быстро перестроиться в левую полосу, чтобы объехать животное, ведь она выглядит свободной","Свернуть на правую обочину и ускориться, проскочив мимо оленя, прежде чем он сдвинется","Убрать руки с руля и позволить грузовику ехать прямо самостоятельно","Применить уверенное, контролируемое торможение и оставаться в своей полосе"],"explanation":"Тормозите уверенно и оставайтесь в своей полосе, так как резкий объезд может опрокинуть или сложить машину с высоким центром тяжести."},"286":{"q":"Вы ведёте гружёный автопоезд по автомагистрали с разделительной полосой, когда полоса сужается и переходит в зону дорожных работ. Оранжевые знаки снижают разрешённую скорость значительно ниже скорости движения по магистрали, впереди стоит сигнальщик, а рабочие перемещаются рядом с открытой полосой. Окружающий вас транспорт всё ещё движется почти с магистральной скоростью. Какое действие является самым безопасным и юридически правильным?","options":["Снизьте скорость до указанного на знаках ограничения в зоне работ и будьте внимательны к рабочим, технике и сигналам сигнальщика","Сохраняйте свой интервал дистанции и магистральную скорость, поскольку вы уже оставляете 7 секунд пространства впереди себя","Двигайтесь в одном темпе с окружающим потоком, чтобы не создавать опасной разницы в скорости между автомобилями","Перестройтесь в более быструю полосу и обгоните замедляющиеся машины, чтобы как можно быстрее проехать зону работ"],"explanation":"Снизьте скорость до установленного ограничения в рабочей зоне и следите за рабочими, техникой и сигнальщиком, который управляет движением в зоне."},"287":{"q":"Вы выходите из поворота на влажном двухполосном шоссе и нажимаете на газ, чтобы снова набрать скорость. Тахометр внезапно подскакивает, и вы чувствуете, как задняя часть тягача начинает заносить, потому что ведущие колёса теряют сцепление и буксуют. Какое действие даёт ЛУЧШИЙ шанс восстановить контроль?","options":["Резко нажать на тормоз, чтобы замедлить буксующие ведущие колёса и сократить траекторию в повороте","Отпустить педаль газа, чтобы ведущие колёса замедлились, и рулить в том направлении, куда вы хотите направить грузовик","Резко вывернуть руль в сторону, противоположную повороту, чтобы как можно быстрее погасить занос","Сохранять равномерное давление на газ, чтобы ведущие колёса вытянули вас прямо из заноса"],"explanation":"Чтобы выйти из заноса ведущих колёс, отпустите педаль газа, чтобы колёса восстановили сцепление, и рулите туда, куда нужно направить грузовик."},"288":{"q":"Вы перевозите неполный груз с высоким центром тяжести по сельскому двухполосному шоссе. Выезжая с холма, вы понимаете, что предстоящий поворот круче, чем предупреждал знак, и вы вошли в него на большей скорости, чем хотелось бы. Какое действие даёт ЛУЧШИЙ шанс остаться в своей полосе без заноса или опрокидывания?","options":["Тормозить сильно и резко в вершине поворота, чтобы быстро сбросить лишнюю скорость","Переключиться на повышенную передачу и ускориться, чтобы протолкнуть грузовик через поворот, пока он не опрокинулся","Признать, что нужно было сбавить скорость ДО поворота, поэтому отпустить педаль газа и применять только лёгкое, плавное торможение, удерживая грузовик ровно в повороте","Выжать сцепление и катиться через поворот на нейтрали, чтобы ведущие колёса не потеряли сцепление"],"explanation":"В повороте отпустите газ и применяйте только лёгкое плавное торможение, так как резкое торможение смещает вес и может сорвать сцепление."},"290":{"q":"Вы ведете гружёный автопоезд со скоростью 60 миль/ч по сухой автомагистрали, держась вплотную за фургоном, чтобы легковые машины не вклинивались перед вами. Загораются стоп-сигналы фургона, и он резко тормозит из-за затора; вы экстренно тормозите и останавливаетесь буквально в нескольких сантиметрах. Разбирая едва не случившееся столкновение, какое действие дало бы вам то время и пространство, которые на самом деле были нужны для безопасной остановки?","options":["Держать дистанцию в 4 секунды, потому что это полный тормозной путь на 55 миль/ч (около 419 футов)","Остаться на том же расстоянии, но затормозить на полсекунды раньше в тот же миг, как вспыхнули стоп-сигналы","Сократить разрыв ещё сильнее, чтобы ни одна машина не вклинилась и не заставила вас вообще тормозить","Держаться достаточно далеко позади, сохраняя безопасную дистанцию следования, чтобы у вас было время заметить опасность, среагировать и затормозить до того, как вы поравняетесь с фургоном"],"explanation":"Сохраняйте безопасную дистанцию, ведь полный тормозной путь складывается из расстояния восприятия, реакции и торможения и достигает сотен футов."},"291":{"q":"Уже давно стемнело, и вы свернули на узкую двухполосную просёлочную дорогу, по которой никогда раньше не ездили. Уличного освещения нет, обочины не размечены, и вы почти ничего не видите за пределами света фар. Как безопаснее всего проехать этот участок?","options":["Снизьте скорость так, чтобы всегда могли остановиться в пределах освещённого фарами расстояния, и используйте дальний свет там, где нет встречного транспорта","Держитесь скорости немногих машин впереди, чтобы не ехать медленнее общего потока","Включите дальний свет и держите его постоянно включённым, чтобы видеть дорогу как можно дальше","Сохраняйте обычную дневную крейсерскую скорость, поскольку снижение скорости ночью делает вас помехой для более быстрого транспорта"],"explanation":"Никогда не превышайте скорость, опережающую свет фар: держите её достаточно низкой, чтобы остановиться в освещённой зоне, и включайте дальний свет при отсутствии встречного транспорта."},"293":{"q":"Вы ведёте свой тягач с прицепом по деловому центру города со скоростью около 25 миль/ч в условиях слабого трафика. Приближаясь к нерегулируемому участку в середине квартала, вы видите, как пешеход, стоявший на тротуаре, внезапно сходит на проезжую часть в нескольких корпусах автомобиля впереди вас, глядя в телефон и не в вашу сторону. Правый ряд занят припаркованными машинами, а слева — встречный поток. Какое действие является самым безопасным и юридически правильным?","options":["Решительно подайте звуковой сигнал и сохраняйте скорость, поскольку в своём ряду у вас преимущество, а пешеход, скорее всего, отступит назад","Отпустите педаль газа, держите ногу над тормозом, снизьте скорость и будьте готовы остановиться перед пешеходом","Слегка выверните на встречную полосу, чтобы объехать пешехода, и вернитесь в свой ряд, как только проедете","Кратковременно ускорьтесь, чтобы проехать участок до того, как пешеход полностью выйдет на вашу траекторию"],"explanation":"При появлении пешехода на проезжей части отпустите газ, держите ногу над тормозом, снизьте скорость и будьте готовы остановиться."},"294":{"q":"Вы ведете гружёный автопоезд по четырёхполосной автомагистрали и вам нужно перестроиться на одну полосу левее, чтобы подготовиться к съезду примерно через две мили. Вы включаете указатель поворота, проверяете левые зеркала и начинаете смещаться, но в этот момент замечаете, что легковой автомобиль идёт рядом с вашим тягачом в зоне, которую зеркала не полностью охватывают. Какое действие является наилучшим и самым безопасным?","options":["Продолжайте смещение в полосу, подтормаживая, так как стоп-сигналы предупредят автомобиль, и он отстанет, открыв вам промежуток","Уверенно ускорьтесь, чтобы вывести тягач вперёд автомобиля, чтобы он оказался позади вашего прицепа, и завершите перестроение до следующей проверки зеркал","Отмените перестроение, сохраните своё положение в полосе, дождитесь свободного промежутка и снова проверьте зеркало и эту слепую зону, прежде чем повторно пытаться перестроиться","Завершите перестроение, поскольку вы уже заблаговременно включили сигнал и проверили зеркала, а водитель, идущий рядом, обязан уступить дорогу грузовику, подающему сигнал"],"explanation":"Транспорт в слепой зоне означает, что полоса не свободна, поэтому отмените перестроение и снова проверьте зеркало и слепую зону перед маневром."},"296":{"q":"Вы ведёте гружёный тягач с полуприцепом по правой полосе оживлённого четырёхполосного шоссе со скоростью 55 миль/ч. Впереди в вашей полосе появляется медленно движущийся ремонтный грузовик, и вы решаете, что нужно перестроиться в левую полосу, чтобы не терять скорость. Движение плотное с обеих сторон. Какая последовательность действий является самым безопасным и правильным способом завершить это перестроение?","options":["Резко ускориться, чтобы создать разрыв, и нырнуть в левую полосу прежде, чем кто-либо успеет её занять","Сначала резко затормозить, чтобы освободить место сзади, а затем перестроиться в левую полосу после того, как замедлитесь","Бросить один взгляд в левое зеркало и плавно сместиться, ведь сигнал поворота на оживлённой дороге только сбивает с толку других водителей","Заранее включить левый указатель поворота, проверить зеркала и левую слепую зону ('No-Zone'), и перестроиться только после того, как убедитесь, что полоса свободна"],"explanation":"Заранее включите сигнал, проверьте зеркала и левую слепую зону (No-Zone) и перестраивайтесь только после того, как убедитесь, что полоса свободна."},"297":{"q":"Во время предрейсового осмотра вы обнаруживаете, что предыдущий водитель заменил одну повреждённую шину. Новая шина — радиальная, но соседняя с ней шина на той же оси — диагональная (bias-ply). Две остальные позиции на осях укомплектованы одинаковыми шинами. Какое условие вы обязаны устранить, прежде чем этот грузовик можно будет считать законным и безопасным для движения?","options":["Радиальная шина установлена рядом с диагональной (bias-ply) шиной на одной и той же оси","Шина рулевой оси с глубиной протектора 4/32 дюйма","Задняя (нерулевая) шина с глубиной протектора 2/32 дюйма","Две шины одной марки, но с разными датами покупки на одной оси"],"explanation":"Радиальные и диагональные шины нельзя устанавливать на одной оси, так как их разная конструкция вызывает неравномерное и непредсказуемое сцепление и управляемость."},"298":{"q":"Во время предрейсового осмотра вы обнаруживаете, что на одной из шин ведущей оси протектор отслаивается от корпуса шины, а также имеется длинный глубокий порез, обнажающий корд внутри. Шина по-прежнему держит давление, а глубина протектора в других местах заметно превышает 2/32 дюйма. Какое решение по этой шине будет правильным?","options":["Ехать разрешено, потому что оставшаяся глубина протектора всё ещё выше минимума 2/32 дюйма для шины не управляемой оси","Шина выводится из эксплуатации и должна быть заменена до начала движения, независимо от глубины протектора или давления воздуха","Допустимо для короткой местной поездки, если держать низкую скорость и проверить шину на первой остановке","Это лишь незначительный дефект, потому что шина стоит на ведущей оси, а не на управляемой"],"explanation":"Отслоение протектора или глубокий порез, обнажающий корд, выводят шину из эксплуатации, поэтому её нужно заменить до поездки независимо от глубины протектора и давления."},"299":{"q":"Во время предрейсового осмотра вы находите одну шину с восстановленным (наварным) протектором и другую с маркировкой нарезанной боковины. У вас сжатые сроки доставки, и вы хотите оставить эти шины в работе где-нибудь на тягаче, а не менять их. На каком единственном положении колеса установка шины с нарезанным или восстановленным протектором БУДЕТ ЗАПРЕЩЕНА, вынуждая вас поставить туда нормальную новую шину?","options":["На задней оси прицепа, потому что шины прицепа несут наибольшую нагрузку и изнашиваются быстрее всего","На внутреннем сдвоенном колесе, потому что скрытый там наварной протектор труднее всего осмотреть","На положении передней (управляемой) оси, где шина с нарезанным или восстановленным протектором не допускается","На запасном колесе, потому что наварную шину никогда нельзя возить как резервную"],"explanation":"Шины с нарезанным протектором или восстановленные запрещены на передней управляемой оси, так как разрушение рулевой шины приводит к немедленной потере управления."},"300":{"q":"Во время предрейсового осмотра вы наклоняетесь, чтобы осмотреть сдвоенные шины на задней оси прицепа. Обе шины кажутся одинакового размера и марки, с хорошей глубиной протектора. Внимательно глядя на зазор между ними, вы должны решить, какое состояние сделает этот сдвоенный комплект незаконным и небезопасным для движения. Какой из перечисленных дефектов вы НЕ должны допускать?","options":["Обе шины абсолютно одинакового размера и имеют одинаковый рисунок протектора","Обе шины накачаны туго и держат примерно одинаковое давление воздуха","Каждая шина имеет протектор значительно выше минимума 2/32 дюйма на задней оси","Обе шины выпячиваются внутрь и соприкасаются друг с другом"],"explanation":"Сдвоенные шины не должны касаться друг друга или частей машины, так как это указывает на недокачку или неправильный монтаж, а трение и нагрев могут вызвать разрыв."},"301":{"q":"Во время предрейсового осмотра холодным утром вы обнаруживаете видимую трещину, проходящую через один из ободов колеса на ведущем мосту. Шина держит давление, протектор в хорошем состоянии, и вы уже опаздываете с доставкой. Какое действие правильное?","options":["Вывести транспортное средство из эксплуатации и не ехать, пока треснувший обод не будет отремонтирован или заменён","Ехать осторожно к месту доставки, ведь шина всё ещё держит давление, а глубина протектора в норме","Слегка спустить давление в шине, чтобы снять нагрузку с обода, и продолжить движение на пониженной скорости","Это всего лишь незначительная косметическая трещина, поэтому отметьте её как обычный износ и перепроверьте на первой остановке для проверки груза через 50 миль"],"explanation":"Треснутый или сломанный обод колеса автоматически выводит машину из эксплуатации, так как он может разрушиться под нагрузкой и сорвать шину на скорости."},"302":{"q":"Во время предрейсового осмотра вы залезаете под прицеп и обнаруживаете, что один лист рессоры задней подвески треснул насквозь, а второй лист сместился со своего крепления. Грузовик по-прежнему стоит ровно на площадке и нормально едет на коротком тестовом круге. Как правильно классифицировать эту неисправность и поступить перед рейсом?","options":["Поскольку грузовик стоит ровно и едет нормально, треснувший лист является косметическим дефектом, и вы можете ехать, наблюдая за ним в пути","Это дефект подвески, который необходимо устранить до выпуска транспортного средства на линию","Это допустимо, если вы повторно проверите крепление груза в течение первых 50 миль","Это нормальное состояние, которое фактически улучшает плавность хода и не требует никаких действий"],"explanation":"Треснувшие, сломанные, ослабленные, отсутствующие или смещённые рессоры — это дефект подвески, выводящий из эксплуатации, и его нужно устранить до выезда."},"303":{"q":"Раннее утро, вы обходите свой тягач с полуприцепом во время предрейсового осмотра. На задней подвеске вы замечаете влажную масляную плёнку, покрывающую один из амортизаторов, и тонкую струйку жидкости, стекающую к пыльнику. Всё остальное на этой оси выглядит нормально. Какой правильный вывод об этом узле и что вы должны сделать?","options":["Масляная плёнка — это просто дорожная грязь, забрасываемая колёсами, поэтому амортизатор в порядке, можно оставить как есть и отправляться в рейс.","Амортизаторы сконструированы так, чтобы слегка выпотевать масло для самосмазки, поэтому лёгкая плёнка допустима, и только обильная капающая течь считается дефектом.","Текущий амортизатор — это дефект; амортизаторы должны быть надёжно закреплены и не иметь течи, поэтому это необходимо устранить, прежде чем транспортное средство станет безопасным для движения.","Амортизаторы не несут нагрузки и влияют только на комфорт хода, поэтому течь — мелкий косметический недостаток, который можно просто отметить и устранить на следующей проверке груза через 150 миль."],"explanation":"Амортизаторы должны быть надёжно закреплены и не иметь течей, поэтому подтекающий амортизатор — это дефект, требующий устранения до безопасной эксплуатации."},"304":{"q":"Во время предрейсового осмотра вы залезаете под тягач и обнаруживаете свежую трещину, идущую через лонжерон рамы рядом с кронштейном рессоры, а одна из опор двигателя заметно ослаблена. Вы уже опаздываете на короткую местную доставку протяжённостью 40 миль по ровным городским улицам. Какое действие правильное?","options":["Поскольку это всего лишь короткая поездка на низкой скорости по ровным улицам, вы можете доехать до места доставки и сообщить о трещине после этого","Плотно обмотайте треснувший участок прочной лентой и затяните вручную всё, что можете, чтобы продержалось до конца дня","Двигайтесь на пониженной скорости и повторно осмотрите раму и опоры в течение первых 50 миль, так как именно тогда проверяется крепление груза","Выведите автомобиль из эксплуатации и отремонтируйте треснувшую раму и ослабленные опоры, прежде чем вообще трогаться с места"],"explanation":"Треснувшая рама или ослабленное крепление — это структурный дефект, выводящий из эксплуатации, так как рама несёт все нагрузки, а трещина может разрастись и привести к разрушению."},"305":{"q":"Ранним утром во время рейса чуть ниже нуля, поэтому вы держите окна кабины закрытыми, а отопитель включенным. Во время предрейсового осмотра вы заметили небольшую утечку в месте соединения выхлопной трубы с глушителем, но двигатель работал нормально, и вы решили ехать. Через час вы чувствуете сонливость и легкую головную боль. Какое последствие этой утечки выхлопа является НАИБОЛЕЕ серьезной причиной устранить ее до выезда?","options":["Выхлопные газы, включая угарный газ, могут проникнуть в закрытую кабину и отравить вас","Утечка впускает холодный наружный воздух в кабину и перегружает отопитель","Выходящий выхлоп снижает мощность двигателя и тратит топливо на подъеме","Из-за утечки двигатель работает громче и может заглушать другие предупреждающие звуки"],"explanation":"Негерметичная выхлопная система опасна, так как выхлопные газы, включая угарный газ, могут проникать в закрытую кабину и отравить водителя."},"306":{"q":"Во время предрейсового осмотра вы открываете отсек аккумулятора и обнаруживаете, что аккумулятор слегка сдвигается, а под ним в поддоне небольшая лужица жидкости. Клеммы подключены, и двигатель заводится нормально. Согласно стандартам осмотра Texas DPS, какому условию должен соответствовать аккумулятор, прежде чем вы сможете законно выехать на этом транспортном средстве на дорогу?","options":["Достаточно, чтобы он был заряжен для запуска двигателя, ведь способность завестись доказывает пригодность аккумулятора к эксплуатации","Он должен быть надёжно закреплён прижимом, чтобы не двигаться, и не должен протекать","Незначительная утечка электролита допустима, пока уровень жидкости остаётся выше пластин","Незакреплённый аккумулятор допустим в коротких поездках, потому что одни лишь клеммы удерживают его от смещения"],"explanation":"Аккумулятор должен быть надёжно закреплён прижимом, чтобы не двигаться, и не иметь течей, так как сдвиг или утечка могут вызвать замыкание, трещину или разлив кислоты."},"307":{"q":"Вы заезжаете на топливную колонку в конце дальнего рейса. Холодильная установка (рефрижератор) прицепа всё ещё работает, заряд телефона 8%, и вы хотите быстро позвонить, а напарник, ожидающий рядом, только что закурил сигарету примерно в 6 метрах от колонок. Прежде чем начать заливать дизель в бак, какое из следующих действий является правильным?","options":["Оставить двигатель работать на холостом ходу, чтобы пневмосистема и рефрижератор оставались под давлением и в холоде, но держать заправочный пистолет ровно и заливать медленно","Оставить грузовик работающим, но отойти, чтобы поговорить по телефону, пока бак наполняется, так как автоматический отсекатель пистолета остановит подачу","Заглушить двигатель, не курить и не допускать курения возле точки заправки, и оставаться у пистолета во время заправки","Оставить сигарету, раз она дальше 4,5 метров, и сначала немного газануть двигателем, чтобы прочистить магистрали перед заправкой"],"explanation":"Пары дизельного топлива легко воспламеняются, поэтому двигатель должен быть заглушен, курение у заправочной точки запрещено, а кто-то должен находиться у заправочного пистолета всё время."},"309":{"q":"Зимним утром температура чуть ниже нуля, и вы проводите предрейсовый осмотр перед дальним рейсом. Осматривая моторный отсек, вы хотите убедиться, что в холоде двигатель не перегреется и не замёрзнет, когда вы тронетесь. Какая проверка напрямую защищает систему охлаждения от зимних условий, с которыми вы столкнулись?","options":["Убедиться, что бачок омывателя лобового стекла полон, чтобы счищать дорожную слякоть со стекла","Долить в радиатор обычную воду, чтобы уровень охлаждающей жидкости показывал «полный» в смотровом окошке","Долить моторное масло, потому что в холод масло густеет и быстрее выгорает","Убедиться, что в охлаждающей жидкости достаточно антифриза, чтобы она не замёрзла при низких температурах"],"explanation":"Антифриз понижает точку замерзания охлаждающей жидкости, поэтому в холодную погоду нужно убедиться, что его достаточно, чтобы жидкость не замёрзла и не повредила двигатель."},"310":{"q":"Чуть ниже нуля на горном перевале, идёт снег, и установленный знак сообщает, что дальше этой точки требуются цепи противоскольжения. Вы останавливаетесь и надеваете цепи на ведущие колёса. Какова ГЛАВНАЯ причина, по которой цепи помогают вам безопасно двигаться вверх по подъёму?","options":["Они вгрызаются в снег и лёд, обеспечивая ведущим колёсам сцепление, необходимое для удержания на скользкой поверхности","Они снижают сопротивление качению, что уменьшает расход топлива на длинном подъёме","Они позволяют легально перевозить больший вес на ведущей оси по заснеженной дороге","Они смягчают ход и делают грузовик тише на укатанном снегу"],"explanation":"Цепи противоскольжения врезаются в снег и лёд, чтобы ведущие колёса могли сцепляться со скользкой поверхностью и передавать тягу без пробуксовки."},"311":{"q":"Вы ведёте гружёный автопоезд по разделённому шоссе ночью и замечаете, что легковой автомобиль впереди ведёт себя странно. Какое наблюдение является САМЫМ ВЕРНЫМ признаком того, что водитель впереди может быть пьян или находиться под воздействием веществ, и говорит вам увеличить дистанцию и дать ему уехать далеко вперёд?","options":["Автомобиль держит ровную скорость и остаётся по центру своей полосы на плавном повороте","Автомобиль виляет туда-сюда через линии разметки и постоянно то разгоняется, то сбрасывает скорость без видимой причины","Автомобиль заранее включает поворотник и ждёт свободного промежутка, прежде чем перестроиться","Автомобиль плавно замедляется и съезжает на правую обочину с включённой аварийной сигнализацией"],"explanation":"Виляние через линии разметки в сочетании с беспорядочным, необъяснимым ускорением и замедлением — классические признаки нетрезвого водителя, поэтому держитесь от него подальше."},"313":{"q":"Вы ведёте гружёный седельный тягач с прицепом по сельской автомагистрали, и вдруг педаль акселератора заклинивает в полу, а двигатель продолжает набирать обороты, даже когда вы убрали ногу. Движение слабое, впереди есть асфальтированная обочина. Какое ваше ПЕРВОЕ приоритетное действие, чтобы вернуть контроль над автомобилем?","options":["Быстро нажимать ногой на педаль акселератора, пытаясь её освободить, оставаясь на передаче, чтобы не потерять торможение двигателем","Немедленно выключить двигатель ключом зажигания, оставаясь на передаче, чтобы ведущие колёса перестали тянуть грузовик вперёд","Перевести коробку в нейтраль, чтобы отсоединить двигатель от ведущих колёс, а затем нажать на тормоза, чтобы безопасно замедлиться и остановиться","Остаться на передаче и полагаться только на ровное, лёгкое нажатие тормоза, чтобы пересилить двигатель, пока вы не доберётесь до обочины"],"explanation":"Переключение на нейтраль отсоединяет двигатель от ведущих колёс, чтобы тормоза могли замедлить и остановить машину при заклинившей педали газа."},"314":{"q":"Вы чувствуете запах гари и безопасно съезжаете на обочину. Открыв кабину, вы видите пламя, выходящее из-за приборной панели рядом с проводкой, и, похоже, затронуты цепи аккумулятора и генератора. У вас в кабине установлен огнетушитель. Какое действие даёт ЛУЧШИЙ и самый безопасный шанс справиться с этим пожаром?","options":["Оставить питание включённым, чтобы видеть проводку, и направить ровную струю воды на основание пламени, чтобы охладить его","Сначала широко открыть капот двигателя и задние двери, чтобы выпустить жар и дым, прежде чем что-либо делать","Оставить двигатель работать, чтобы генератор продолжал заряжать, и сбить пламя влажной тряпкой из кабины","Если возможно, отключить электропитание (отсоединить аккумулятор / выключить зажигание), затем потушить огонь огнетушителем класса B:C"],"explanation":"При электрическом возгорании сначала отключите питание, если это безопасно, чтобы убрать источник зажигания, затем тушите огнетушителем класса B:C, а не водой."},"315":{"q":"Сразу после того как вы перевалили через вершину холма, двигатель теряет мощность, и вы по инерции останавливаетесь в правой полосе двухполосного сельского шоссе. Вы включаете аварийную сигнализацию и берёте аварийные треугольники. Ваш сменщик говорит, что спешить некуда, ведь движение слабое. Согласно правилам остановки на дороге, каков САМЫЙ ДОЛГИЙ срок, в течение которого вы можете не выставлять предупреждающие устройства?","options":["В течение 10 минут после остановки","В течение 1 часа после остановки, пока включена аварийная сигнализация","В течение 1 минуты после остановки","До конца вашего рабочего дня, ведь аварийка уже предупреждает движение"],"explanation":"Остановившись на проезжей части или обочине, немедленно включите аварийную сигнализацию и в течение 10 минут выставьте три светоотражающих знака аварийной остановки."},"316":{"q":"Ваш автопоезд сложился пополам на сельской двухполосной дороге, и водитель машины, которую вы задели, обмяк за рулём - он в сознании, но жалуется на боль в шее. Движение слабое, погода ясная, вы чувствуете запах охлаждающей жидкости, но дыма и огня не видно. Согласно указаниям Техасского DPS, когда следует вытаскивать этого пострадавшего из автомобиля?","options":["Немедленно, ведь боль в шее означает травму позвоночника, и нужно уложить пострадавшего плашмя на землю","Только если возникнет реальная опасность, например пожар; в остальных случаях оставьте его на месте и дождитесь обученной помощи","Как только вы выставите три светоотражающих треугольника на 10, 100 и 200 футах","Как только начнёт скапливаться очередь, чтобы освободить полосу и обезопасить других водителей"],"explanation":"Не перемещайте пострадавшего, если ему не угрожает реальная опасность, например пожар, так как перемещение при травме шеи или позвоночника может вызвать стойкий паралич."},"317":{"q":"Сейчас 5:30 утра, и у вас крайний срок доставки. Вчера вечером вы выпили несколько кружек пива и перестали пить около четырёх часов назад. Чтобы почувствовать себя готовым к рейсу, вы выпиваете две большие чашки чёрного кофе, бодро прогуливаетесь по холодному утреннему воздуху и смотрите на термометр в кабине. Что из этого действительно снизит уровень алкоголя, оставшегося в вашей крови, чтобы вы могли безопасно и законно управлять своим грузовиком (CMV)?","options":["Холодный утренний воздух, потому что глубокое дыхание свежим воздухом помогает организму быстрее вывести алкоголь","Две большие чашки чёрного кофе, потому что кофеин ускоряет обмен веществ и сжигает оставшийся алкоголь","Ни одно из этих действий; только истечение достаточного времени выведет алкоголь из крови и снизит ваш уровень BAC ниже предела 0,04%","Все три вместе, так как кофе, холодный воздух и бодрость в сочетании отрезвят вас до начала смены"],"explanation":"Только время позволяет печени переработать алкоголь и снизить уровень BAC; кофе, свежий воздух или ощущение бодрости не ускоряют этот процесс."},"318":{"q":"Вы за рулём уже 9 часов в дальнем рейсе и начинаете чувствовать сонливость. Другой водитель на стоянке предлагает вам таблетки с кофеином и стимуляторы (\"допинг\"), уверяя, что они помогут вам сохранять бодрость и безопасно закончить рейс. Какая из причин является ЛУЧШИМ основанием отказаться и вместо этого остановиться на отдых?","options":["Стимуляторы допустимы, если вы заодно пьёте кофе и дышите свежим воздухом, чтобы уравновесить их действие","Стимуляторы обостряют реакцию и улучшают ночное зрение, но их запрещено перевозить в кабине","Стимуляторы допустимы только на спусках длиннее 419 футов, где требуется повышенная бдительность","Стимуляторы не делают вас безопасным водителем; когда их действие заканчивается, вы можете стать более уставшим и опасным, чем прежде"],"explanation":"Стимуляторы лишь временно маскируют усталость и не делают вас безопасным водителем; когда их действие проходит, вы можете стать ещё более уставшим и опасным."},"319":{"q":"Вы едете по правой полосе четырёхполосного шоссе со скоростью 55 миль/ч. Примерно в четверти мили впереди вы видите сломавшийся автомобиль, съехавший на правую обочину с включённой аварийной сигнализацией, и человека, стоящего рядом с ним возле багажника. Почему это следует считать опасностью и начать действовать уже сейчас, а не ждать, пока вы подъедете ближе?","options":["Стоящий автомобиль или человек рядом с ним может внезапно выехать или выйти на вашу полосу, поэтому следует снизить скорость, увеличить дистанцию и при безопасности перестроиться левее.","Обочина является разрешённой полосой движения для медленного транспорта, поэтому вы обязаны съехать на неё, чтобы освободить всю полосу для сломавшегося автомобиля.","Это опасность только в том случае, если водитель не выставил три знака аварийной остановки на 10, 100 и 200 футах; в противном случае можно сохранять скорость.","Сломавшийся автомобиль на обочине не представляет реальной опасности, пока включена аварийная сигнализация, поэтому менять скорость или положение не нужно."],"explanation":"Остановившаяся машина или человек рядом с ней может внезапно выехать на вашу полосу, поэтому снизьте скорость, увеличьте дистанцию и перестройтесь левее, когда это безопасно."},"320":{"q":"Вы заезжаете на площадку для отдыха в середине маршрута и, прежде чем снова сесть в кабину, приседаете и бегло осматриваете пространство под вашим тягачом с прицепом. Помимо проверки того, что ничего не волочится, какова ГЛАВНАЯ причина безопасности, по которой руководство рекомендует этот короткий взгляд под автомобиль на остановке?","options":["Это позволяет считать показания глубиномера протектора, чтобы убедиться, что у рулевых шин осталось не менее 4/32 дюйма","Это позволяет обнаружить свежую утечку жидкости, спущенную или приспущенную шину, а также людей или предметы, которые могут оказаться под машиной или позади неё, прежде чем вы тронетесь","Это выполняет требование повторно осмотреть и закрепить груз в течение первых 50 миль поездки","Так вы расставляете три аварийных треугольника на расстоянии 10, 100 и 200 футов перед отъездом"],"explanation":"Осмотр на уровне земли перед началом движения выявляет свежие утечки жидкости, спущенное или приспущенное колесо, а также людей и предметы под машиной или за ней."},"321":{"q":"Вы везёте гружёный прицеп и достигаете вершины длинного крутого горного спуска. Знак предупреждает о предстоящем уклоне 6%. Чтобы тормоза не перегрелись и не отказали во время спуска, когда нужно выбрать пониженную передачу для движения вниз?","options":["В тот момент, когда вы впервые почувствуете, что тормоза начинают перегреваться и слабеть","Примерно на середине спуска, когда вы сможете оценить, насколько он на самом деле крутой","До начала спуска, пока вы ещё находитесь на вершине","Только если груз сместится или ваша скорость превысит безопасный уровень"],"explanation":"Выбирайте низкую передачу перед началом спуска по длинному крутому уклону, пока вы ещё находитесь наверху."},"322":{"q":"Вы спускаетесь с груженым прицепом по длинному крутому горному склону. Примерно на середине спуска вы чувствуете запах перегретых тормозов, а педаль стала мягче, чем была наверху. Какое из перечисленных действий обеспечит самый безопасный контроль скорости на оставшейся части спуска?","options":["Нажать и удерживать ровное, сильное давление на педаль тормоза до самого низа, чтобы зафиксировать скорость","Перейти на нейтральную передачу, чтобы двигатель остыл, и слегка притормаживать до конца спуска","Быстро прокачивать педаль тормоза, чтобы восстановить давление воздуха и вернуть твёрдую педаль","Оставаться на низкой передаче, чтобы двигатель помогал сдерживать машину, и применять только лёгкое прерывистое торможение"],"explanation":"На спуске основной контроль скорости обеспечивают торможение двигателем и передачей, поэтому держите низкую передачу и применяйте только лёгкое прерывистое торможение, чтобы тормоза остывали."},"323":{"q":"Вы спускаетесь с длинного крутого горного уклона с гружёным прицепом. Чтобы держать скорость под контролем, вы всю дорогу вниз постоянно и равномерно удерживаете рабочие тормоза вместо того, чтобы использовать пониженную передачу. Когда вы приближаетесь к подножию склона, каков НАИБОЛЕЕ вероятный результат такого использования тормозов?","options":["Тормоза перегреются и потеряют эффективность (отказ от перегрева), лишившись тормозной силы в самый нужный момент","Тормоза будут схватывать тем сильнее, чем дольше их удерживать, давая дополнительный контроль","Постоянный поток воздуха через барабаны будет охлаждать тормоза, и они продолжат работать нормально","Тормоза будут изнашиваться равномерно и прослужат дольше, потому что давление плавное и постоянное"],"explanation":"Постоянное непрерывное торможение на длинном спуске нагревает тормоза быстрее, чем они остывают, поэтому они перегреваются и теряют эффективность."},"324":{"q":"Вы спускаетесь по длинному крутому горному уклону с полностью загруженным прицепом. На середине спуска вы чувствуете слабый запах гари, педаль тормоза становится мягкой, и грузовик продолжает набирать скорость, хотя вы нажимаете на тормоза. Впереди знак: \"АВАРИЙНАЯ ТОРМОЗНАЯ ПОЛОСА ДЛЯ ГРУЗОВИКОВ 1 МИЛЯ.\" Каково ОСНОВНОЕ назначение этой полосы и почему она может вам здесь понадобиться?","options":["Это специальная площадка для остановки, где вы обязаны припарковаться и дать тормозам остыть в течение 30 минут перед продолжением спуска.","Она создана для безопасной остановки потерявшего управление транспортного средства, утратившего способность тормозить, например когда тормоза перегреваются и теряют эффективность на длинном спуске.","Это полоса объезда весовой станции, где спускающиеся грузовики проверяют нагрузку на оси перед достижением подножия уклона.","Это разворотная площадка для негабаритных грузовиков, которые не могут безопасно завершить оставшийся крутой спуск."],"explanation":"Аварийная улавливающая полоса предназначена для безопасной остановки неуправляемого автомобиля, потерявшего тормоза, например из-за их перегрева на длинном спуске."},"327":{"q":"Вы остановились перед многопутным железнодорожным переездом без шлагбаумов и сигналов. Грузовой состав с грохотом проходит по ближнему пути и наконец уходит влево. Обзор вдоль обоих путей частично закрыт деревьями, и вы видите, что вам хватит места, чтобы полностью освободить все пути плюс длину вашего автопоезда и ещё около 15 футов. Прежде чем отпустить тормоз и начать движение через пути, что НАИБОЛЕЕ важно сделать?","options":["Включить самую низкую передачу, чтобы иметь максимальную тяговую мощность при проезде через пути","Убедиться, что окрашенные стрелы шлагбаума полностью подняты, прежде чем ехать","Проверить второй путь в обоих направлениях на наличие другого поезда, который мог быть скрыт первым составом","Подождать полные 15 секунд после ухода поезда, затем ехать без дальнейшей проверки"],"explanation":"Второй поезд может быть скрыт за только что проехавшим, поэтому перед переездом смотрите в обе стороны на каждом пути."},"328":{"q":"В вашем районе доставки не было дождя почти три недели, и как только вы выезжаете на оживлённую двухполосную дорогу, начинается мелкий дождь. Вы сразу чувствуете, что прицеп ведёт себя нестабильно даже при лёгком торможении, хотя покрытие выглядит едва влажным. Почему этот первый слабый дождь ОПАСНЕЕ для сцепления, чем сильный ливень позже во время той же грозы?","options":["Тонкая плёнка воды охлаждает покрытие, из-за чего резина шин твердеет и сцепление ухудшается","Слабый дождь не может промыть дорогу, поэтому при сильном ливне позже сцепление шин было бы даже лучше","Слабый дождь повышает давление в шинах, и перекачанные шины опираются на меньшее пятно контакта","Первая вода смешивается с накопившимися маслом и пылью на сухой дороге, поднимая их в скользкую плёнку прежде, чем более сильный дождь успеет её смыть"],"explanation":"Первый дождь после засухи скользкий, потому что небольшое количество воды смешивается с накопившимся маслом и пылью, образуя скользкую плёнку до того, как сильный дождь смоет её."},"329":{"q":"Вы только что проехали через затопленный низководный переезд, где вода доходила до ступиц колес. Когда вы снова разгоняетесь на сухом шоссе и приближаетесь к перекрестку в четверти мили впереди, первое торможение показывает мягкую, слабую педаль тормоза. Каковы правильные действия, чтобы восстановить торможение, прежде чем полагаться на тормоза на скорости?","options":["Двигаться на малой скорости, слегка и плавно нажимая на тормоза, чтобы проверить и просушить их теплом трения","Сильно и часто прокачивать педаль тормоза, чтобы вытолкнуть воду из барабанов перед следующей остановкой","Разогнаться до скорости шоссе, чтобы ветер и тепло двигателя быстро высушили тормоза","Заглушить двигатель и катиться накатом, чтобы тормоза высохли на воздухе естественным образом перед продолжением движения"],"explanation":"После того как глубокая вода намочит тормозные накладки, двигайтесь медленно с лёгким мягким нажатием на тормоз, чтобы тепло трения высушило их и восстановило нормальное торможение."},"330":{"q":"Вы везёте частичный груз по автомагистрали под непрерывным дождём со скоростью 50 миль/ч. Дорога впереди выглядит как сплошной слой воды, и вы чувствуете, как между шинами и покрытием образуется тонкая водяная плёнка. Внезапно рулевое колесо в ваших руках ощущается иначе. Какое изменение было бы самым явным предупреждением о том, что шины потеряли сцепление и вы, возможно, начинаете аквапланировать?","options":["Руль внезапно сопротивляется и становится тяжёлым, тугим и трудно поворачиваемым","Руль внезапно становится лёгким и легко поворачивается, как будто он ослаб","Вы слышите, как двигатель заметно громче, хотя ваша скорость постоянна","Вы замечаете сильный запах топлива, поступающий через вентиляцию кабины"],"explanation":"Когда шины теряют сцепление на мокрой поверхности и скользят по плёнке воды, руль внезапно становится лёгким и легко поворачивается."},"331":{"q":"Вы ушли с дежурства в 18:00 и взяли полный 10-часовой перерыв, затем заступили на смену в 4:00 и ехали без остановки. Диспетчер давит на вас, чтобы вы продолжали движение, ведь, по его словам, у вас ещё остаются часы в рамках 14-часового окна. Не считая 14-часового окна нахождения на службе, сколько максимум часов вам фактически разрешено провести ЗА РУЛЁМ в течение этой рабочей смены?","options":["8 часов вождения, поскольку именно тогда становится обязательным 30-минутный перерыв и ваша смена фактически заканчивается","14 часов вождения, так как именно 14-часовое окно на самом деле определяет, как долго вы можете находиться за рулём","11 часов вождения, поскольку после 10 часов непрерывного отдыха вам разрешено вести машину не более 11 часов","16 часов вождения, при условии, что вы остаётесь в пределах 14-часового окна нахождения на службе"],"explanation":"После 10 часов подряд отдыха разрешается находиться за рулем не более 11 часов, что отдельно от 14-часового лимита рабочего окна."},"332":{"q":"Вы заступили на смену в 6:00 утра. После погрузки и ожидания вы наконец начали движение в 9:00 утра. Вы проехали всего около 5 часов и сделали 30-минутный перерыв, поэтому считаете, что у вас ещё много разрешённого времени для вождения на сегодня. Когда стрелки приближаются к 20:00, какое утверждение правильно описывает, когда вы обязаны прекратить вождение в эту рабочую смену?","options":["Вы можете продолжать движение, пока не накопите 6 фактических часов за рулём, ведь именно время вождения и контролирует этот предел.","Вы можете продолжать движение, пока не превысите 10 часов нахождения на службе, потому что именно счётчик служебного времени вас останавливает.","Вы можете ехать и после 20:00, потому что ваш 30-минутный перерыв остановил отсчёт и сдвинул крайний срок на более позднее время вечера.","Вы вообще не имеете права ехать после 20:00, потому что это 14-й час после того, как вы заступили на смену, независимо от того, как мало вы фактически проехали."],"explanation":"Запрещено находиться за рулем после 14-го часа с момента выхода на дежурство, независимо от того, как мало вы фактически проехали."},"333":{"q":"Вы загружаете бортовую платформу для рейса на 300 миль. Вы сбалансировали вес над осями, накрыли груз тентом для защиты от влаги, а ваши крепления соответствуют предельной рабочей нагрузке. Делая последний обход машины, вы напоминаете себе самую главную причину, по которой груз должен быть надёжно закреплён, прежде чем вы выедете на трассу. Какое утверждение лучше всего отражает эту причину?","options":["Закреплённый груз не должен смещаться, выпадать или загораживать вам обзор дороги","Закреплённый груз должен быть полностью скрыт под тентом, чтобы его нельзя было увидеть снаружи машины","Закреплённый груз должен быть размещён так, чтобы его можно было быстро взвесить на следующем пункте контроля","Закреплённый груз должен быть уложен так, чтобы крепления были видны инспекторам со стороны пассажира"],"explanation":"Груз должен быть закреплен так, чтобы он не мог сместиться, выпасть или загораживать обзор дороги."},"334":{"q":"Вы берёте срочный груз, и грузоотправитель загружает его тяжелее, чем указано в вашем манифесте, в результате чего вы немного превышаете полную разрешённую массу (GVWR). Диспетчер говорит, что перевес \"совсем небольшой\", и велит ехать. Выезжая на трассу, какой эффект этого перегруза должен тревожить вас БОЛЬШЕ всего с точки зрения безопасности?","options":["Лишний вес сильнее прижмёт шины к дороге, дав больше сцепления и более короткий тормозной путь","Машиной будет труднее управлять, и она будет дольше останавливаться, потому что добавленный вес работает против вашего руля и тормозов","Дополнительный вес понижает центр тяжести, поэтому грузовик становится устойчивее и гораздо менее склонен к опрокидыванию","Расход топлива улучшается, потому что двигатель работает под более стабильной нагрузкой, когда грузовик полностью загружен"],"explanation":"Слишком большой вес затрудняет управление и увеличивает тормозной путь, поскольку дополнительная масса противодействует рулю и тормозам."},"335":{"q":"Во время предрейсового осмотра на погрузочной платформе в Техасе вы обнаруживаете, что две стальные трубы выступают примерно на четыре фута за задний край вашего бортового полуприцепа. Груз надёжно закреплён стяжными ремнями, документы в порядке, и вы собираетесь выехать в дневной рейс. Что федеральные правила и правила Техаса требуют сделать с той частью груза, которая выступает за задний край, перед началом движения?","options":["Ничего дополнительно не требуется, поскольку выступ меньше пяти футов, а груз уже закреплён правильным количеством стяжных ремней","Добавить один дополнительный стяжной ремень на выступающую часть и покрасить торчащие концы в тёмный цвет, чтобы они меньше отвлекали других водителей","Обозначить выступающий груз, чтобы он был хорошо виден, -- использовать флажки (и фонари при плохой видимости или ночью) на части, выступающей за задний край","Перепроверить крепление в течение первых 50 миль, но обозначать выступ не нужно, поскольку груз полностью закреплён"],"explanation":"Груз, выступающий за заднюю часть, должен быть обозначен для видимости — флажками днем и фонарями при плохой видимости или ночью."},"336":{"q":"На погрузочном доке складская бригада грузит и закрепляет цепями стальные трубы на вашем бортовом полуприцепе, начальник дока подписывает товарно-транспортную накладную, а рядом случайно стоит инспектор DOT. Вам кажется, что пара креплений ослаблена. Согласно федеральным правилам и правилам Техаса, кто в конечном счёте несёт ответственность за то, чтобы этот груз был правильно закреплён и находился в пределах допустимого веса, прежде чем вы тронетесь с места?","options":["Грузоотправитель и складская бригада, потому что они физически загрузили и закрепили цепями груз","Начальник дока, потому что его подпись на накладной удостоверяет груз","Инспектор DOT, стоящий рядом, поскольку контроль за креплением груза — это его работа","Вы, водитель, потому что вы несёте ответственность за надёжно закреплённый и законный груз, независимо от того, кто его грузил"],"explanation":"Водитель несет ответственность за надежно закрепленный и законный груз, независимо от того, кто его фактически загружал."},"337":{"q":"Вы загрузили стальные рулоны на площадке и только что выехали на автомагистраль. При закреплении груз казался надёжным, но вы знаете, что крепления и груз могут сместиться, когда машина пойдёт и цепи натянутся и осядут. Чтобы оставаться в рамках закона и безопасности, как скоро вы должны сделать ПЕРВУЮ остановку для повторной проверки крепления груза?","options":["В пределах первых 50 миль после начала поездки","В пределах первых 150 миль после начала поездки","В течение первых 3 часов движения, независимо от расстояния","Только после первого перерыва на отдых или заправки"],"explanation":"Вы обязаны проверить груз и его крепление в течение первых 50 миль после начала поездки."},"339":{"q":"Безлунная ночь, вы ведёте пустой бортовой полуприцеп по сельскому двухполосному шоссе без уличного освещения. Ваш ближний свет освещает примерно 250 футов дороги впереди, но включить дальний свет вы не можете по закону, так как постоянно появляются встречные машины. Чтобы не съехать с дороги и не наехать на невидимое препятствие, какое единственное правило должно определять вашу скорость?","options":["Вы можете держать разрешённую скорость, пока ваши фары и стоп-сигналы исправно работают","Ваша скорость должна быть достаточно низкой, чтобы вы могли остановиться в пределах расстояния, которое освещают ваши фары впереди","Вам следует держать скорость достаточно низкой, чтобы успевать прочитать каждый дорожный знак до того, как проедете мимо него","Вы можете ехать быстрее, потому что пустой полуприцеп даёт меньший тормозной путь, чем гружёный"],"explanation":"Никогда не превышайте дальность света фар — скорость должна позволять остановиться в пределах освещаемого впереди расстояния."},"340":{"q":"Вы ведёте гружёный седельный тягач с прицепом по тёмной двухполосной трассе сразу после полуночи. Встречный автомобиль едет с включённым дальним светом и не переключается на ближний, и слепящий свет ухудшает вам видимость. Вы уже мигнули фарами, чтобы напомнить водителю, но безрезультатно. Пока эта машина не проедет, как ЛУЧШЕ всего поступить со взглядом, чтобы удержать свою полосу?","options":["Смотреть прямо на встречные фары, чтобы точно определить, когда автомобиль вас минует","Перевести взгляд вверх, на небо над фарами, чтобы яркий свет оказался вне прямой линии зрения","Опустить взгляд и направить его на правый край своей полосы и вести машину по нему, пока встречный автомобиль не проедет","Опустить глаза на приборную панель и следить за приборами, пока фары не перестанут быть впереди вас"],"explanation":"Ослепленный встречным дальним светом, смотрите на правый край своей полосы и используйте его для управления, пока машина не проедет."},"341":{"q":"Вы только что выгрузили весь груз на складе и теперь гоните пустой тягач без прицепа (бобтейл) обратно на базу. Подъезжая к красному сигналу, вы тормозите так же, как при полной загрузке, и колёса внезапно блокируются и начинают скользить. Почему этот пустой грузовик тормозит ХУЖЕ, чем когда он был загружен?","options":["Чем тяжелее транспортное средство, тем дольше оно останавливается, поэтому пустой грузовик должен останавливаться легче, чем загруженный","На пустые грузовики ставят меньшие, более слабые тормоза, которые не могут создать достаточное усилие для замедления","Без груза более высокий центр тяжести заставляет грузовик наклоняться вперёд и перегружать передние тормоза","Так как малый вес слабо прижимает шины к дороге, у шин меньше сцепления, и они с большей вероятностью блокируются и идут в занос"],"explanation":"У пустого грузовика мало веса прижимает шины к дороге, поэтому у них меньше сцепления и они легче блокируются и скользят."},"342":{"q":"Идёт устойчивый дождь, и покрытие явно мокрое, но на нём пока нет ни стоячей воды, ни снежной каши. Транспорт вокруг вас по-прежнему движется почти с разрешённой скоростью 60 миль/ч. Чтобы сохранить безопасный запас управляемости на этой мокрой поверхности, примерно насколько следует снизить скорость по сравнению с той, с которой вы безопасно ехали бы по той же дороге в сухую погоду?","options":["Примерно на одну треть медленнее вашей безопасной скорости на сухой дороге","Примерно на половину медленнее вашей безопасной скорости на сухой дороге","Примерно на три четверти медленнее вашей безопасной скорости на сухой дороге","Снижать скорость не нужно, пока не образовались стоячая вода и снежная каша"],"explanation":"На мокрой дороге снижайте скорость примерно на треть по сравнению с безопасной скоростью на сухой дороге, чтобы сохранить сцепление."},"343":{"q":"Вы ведёте загруженный рефрижератор по двухполосной сельской трассе, когда температура падает и начинает идти устойчивый снег, который прилипает к покрытию и образует плотный укатанный белый слой. Поток движется нормально, дорога не обледенелая, видимость хорошая. Чтобы сохранить безопасный запас на этом укатанном снегу, примерно насколько следует снизить вашу обычную скорость для сухой дороги?","options":["Снизить скорость примерно на одну четверть","Снизить скорость примерно наполовину","Снизить скорость примерно на одну десятую","Держать обычную скорость, раз дорога не обледенелая и видимость хорошая"],"explanation":"На укатанном снегу снижайте скорость примерно вдвое, так как сцепление резко падает, а тормозной путь увеличивается."},"344":{"q":"Перед рассветом температура чуть ниже нуля, и вы ведёте гружёный автопоезд по мосту. Дорога впереди выглядит тёмной, гладкой и мокрой, но вы замечаете, что из-под колёс машины перед вами не летят брызги. Почему такая поверхность считается одной из самых опасных зимних угроз?","options":["Она яркая и хорошо заметна, поэтому водители тормозят слишком резко и теряют сцепление на явно обледенелой дороге","Она образуется только в самые жаркие часы летнего дня, когда сквозь покрытие проступает гудрон","Она выглядит как безобидная мокрая дорога, но на самом деле это тонкий прозрачный слой льда, который почти не даёт предупреждения","Она плавит дорожный гудрон под собой, оставляя скользкую маслянистую плёнку, которую легко увидеть и объехать"],"explanation":"Гололёд — это тонкий прозрачный слой льда, из-за которого дорога кажется просто мокрой и почти не даёт предупреждения."},"345":{"q":"Вы ведёте гружёный тягач с полуприцепом по сельской двухполосной дороге, когда внезапный сильный боковой порыв ветра ударяет в борт прицепа и рулевое колесо вырывается у вас из рук. Чтобы сохранить наилучший контроль и быть готовым к корректирующему повороту руля, если ветер сносит вас к обочине, как должны быть расположены ваши руки на рулевом колесе?","options":["Держите одну руку наверху руля для максимального рычага, а другую держите на коленях","Держите обе руки близко друг к другу в верхней части руля, чтобы быстро реагировать в любом направлении","Держите одну руку внизу руля, а другой только упирайтесь в дверь","Держите обе руки крепко на руле на противоположных сторонах относительно друг друга"],"explanation":"Держите руль крепко обеими руками с противоположных сторон, чтобы сохранять контроль и парировать внезапные опасности."},"346":{"q":"Вы заезжаете на переполненную стоянку для грузовиков и должны задним ходом загнать тягач с прицепом в узкое парковочное место. Помощника-сигнальщика нет, а другие фуры стоят вплотную с обеих сторон. Чтобы выполнить маневр максимально безопасно, в какую сторону вам следует сдавать назад?","options":["В сторону водителя, чтобы вы могли смотреть назад вдоль прицепа и контролировать траекторию через боковое окно со стороны водителя","В сторону пассажира, потому что прицеп с этой стороны заносит шире и это дает больше свободного пространства","В ту сторону, которая позволяет сдавать назад по прямой линии вниз по уклону площадки","В сторону вашей слепой зоны, а затем полагаться на зеркала и быстрый обход вокруг машины, чтобы покрыть то, что вы не видите"],"explanation":"Сдавайте назад в сторону водителя, чтобы смотреть прямо вдоль прицепа и видеть свой путь через боковое окно."},"348":{"q":"Вам нужно сдать назад 53-футовый прицеп в тесный погрузочный док со слепой (правой) стороны, и рядом стоит коллега, предлагающий помощь. Согласно безопасным правилам движения задним ходом, какова единственная самая важная причина использовать этого человека в качестве помощника?","options":["Он может подавать вам сигналы руками, чтобы вы вообще не пользовались зеркалами","Он может наблюдать за зонами позади и сбоку от прицепа, которые вы не видите из кабины","Он может остановить встречный поток на улице, чтобы вы сдавали назад без ожидания","Он может взять управление и сдать прицеп назад за вас, если угол окажется слишком сложным"],"explanation":"Помощник может следить за слепыми зонами позади и сбоку от прицепа, которые вы не видите из кабины."},"349":{"q":"Вы управляете автопоездом длиной 53 фута и приближаетесь к крутому правому повороту на узкую городскую улицу. Вы знаете, что прицеп пойдёт по внутренней траектории и может наехать на бордюр, если повернуть слишком резко. Сзади справа к вам только что вплотную подъехал легковой автомобиль. Что следует сделать, чтобы выполнить поворот безопасно и по правилам?","options":["Сначала сместиться широко влево перед началом поворота, чтобы у прицепа было место обойти бордюр","Немного ускориться в повороте, чтобы прицеп шёл плотнее за тягачом","Поворачивать, держась как можно правее, насколько это безопасно, удерживая заднюю часть машины близко к бордюру, чтобы никто не смог проехать справа","Сначала перестроиться в крайнюю левую полосу, а затем выполнить правый поворот оттуда, чтобы дать прицепу максимум места"],"explanation":"Поворачивайте из крайнего правого положения, насколько это безопасно, держа заднюю часть у бордюра, чтобы никто не проехал справа."},"350":{"q":"Вы управляете автопоездом длиной 53 фута (тягач с полуприцепом) и должны выполнить левый поворот на оживлённом четырёхстороннем перекрёстке. Загорается зелёный свет, встречный поток проехал. Чтобы безопасно завершить левый поворот и не дать задним колёсам полуприцепа срезать полосу, с которой вы поворачиваете, какая техника правильная?","options":["Начинайте выводить переднюю часть тягача влево сразу, как только въедете на перекрёсток, чтобы полуприцеп прошёл по более узкой траектории","Оставайтесь в крайней правой полосе на протяжении всего поворота, чтобы задние колёса полуприцепа прошли широко и не задели бордюр","Срежьте угол перекрёстка по диагонали, чтобы сократить путь, который должен пройти полуприцеп","Проедьте тягачом вперёд и достигните центра перекрёстка, прежде чем начать поворачивать руль влево"],"explanation":"Выезжайте вперёд до центра перекрёстка, прежде чем поворачивать руль влево, чтобы задние колёса прицепа не срезали угол."},"351":{"q":"Раннее утро, и вы только что забрались в кабину, чтобы начать долгий рейс. Усаживаясь, вы замечаете, что правое зеркало задрано слишком высоко и не показывает борт прицепа, и хотите его поправить. Когда правильно выполнить эту регулировку?","options":["Сейчас, до начала рейса, пока автомобиль безопасно припаркован","Когда наберёте скорость на трассе, чтобы зеркало было настроено под то, как прицеп идёт под нагрузкой","Во время первой обязательной проверки груза, в пределах первых 50 миль рейса","Только после окончания поездки, заехав на площадку в пункте назначения"],"explanation":"Регулируйте зеркала до поездки, пока машина безопасно припаркована, поскольку делать это в движении небезопасно."},"353":{"q":"Вы только что перестроились в левую полосу, чтобы обогнать более медленное транспортное средство на многополосном шоссе. Обгон завершён, и вы уже устойчиво едете в новой полосе. Взглянув на приборную панель, вы замечаете, что ваш левый указатель поворота всё ещё мигает, потому что, в отличие от легкового автомобиля, сигнал поворота вашего грузовика не отключился автоматически. Что нужно сделать В ПЕРВУЮ ОЧЕРЕДЬ?","options":["Уверенно ускориться, чтобы увеличить дистанцию между вами и обогнанным транспортным средством, а сигнал проверить позже","Вручную выключить указатель поворота, чтобы окружающие водители не были введены в заблуждение относительно ваших намерений","Притормозить, чтобы перепроверить зеркала, прежде чем решить, нужно ли отключать сигнал","Оставить сигнал включённым до следующего перестроения, так как он показывает, что вы всё ещё маневрируете"],"explanation":"У большинства крупных грузовиков нет самоотключающихся поворотников, поэтому выключайте сигнал после манёвра, чтобы не вводить других водителей в заблуждение."},"355":{"q":"Вы ведете тягач с прицепом ночью по темному двухполосному шоссе с включенным дальним светом. Вы замечаете фары встречного автомобиля в противоположной полосе, еще на некотором расстоянии впереди. На каком расстоянии вы обязаны переключить дальний свет на ближний, чтобы не ослепить водителя встречного автомобиля?","options":["В пределах 250 футов до встречного автомобиля, поскольку именно на это расстояние ваш ближний свет освещает дорогу","В пределах 200 футов до встречного автомобиля — на таком же расстоянии вы выставляете самый дальний знак аварийной остановки","В пределах 500 футов до встречного автомобиля (а также когда вы следуете за другим автомобилем в пределах 500 футов)","Только после того, как встречный автомобиль моргнет вам фарами, сигнализируя, что ваш свет слишком яркий"],"explanation":"Переключайтесь на ближний свет в пределах 500 футов от встречного автомобиля и при движении за другим автомобилем в пределах 500 футов, чтобы не ослеплять водителя."},"356":{"q":"Вы везёте гружёный прицеп по сельскому двухполосному шоссе, когда сигнал низкого уровня охлаждающей жидкости вынуждает вас заглушить двигатель. Съезда нет на несколько миль, но впереди вы видите широкую гравийную обочину. Прежде чем взяться за аварийные знаки, что нужно сделать ПЕРВЫМ, чтобы остановка была максимально безопасной?","options":["Остановиться прямо в своей полосе движения и сразу выставить три знака на расстоянии 10, 100 и 200 футов, чтобы предупредить транспорт прежде всего","Накатом остановиться на ближайшем повороте, чтобы машину было видно с обеих сторон, и включить фары","Сбросить скорость и встать на линию разметки, оставив часть грузовика на асфальте, чтобы обочина оставалась свободной для аварийных служб","Полностью съехать с асфальта на гравийную обочину и включить аварийную сигнализацию (четыре поворотника)"],"explanation":"Полностью съедьте с проезжей части на обочину и немедленно включите аварийную сигнализацию, чтобы предупредить приближающийся транспорт."},"357":{"q":"Вы заезжаете на стоянку для отдыха на небольшом уклоне вниз, чтобы быстро обойти машину и проверить крепление груза. Двигатель всё ещё работает, и вы планируете выйти из кабины всего на минуту-две. Прежде чем спуститься и выйти наружу, какое действие является единственным самым важным, чтобы автомобиль не покатился?","options":["Поставить машину на стояночный тормоз.","Включить самую низкую переднюю передачу и оставить её включённой.","Резко вывернуть передние колёса к бордюру и включить аварийную световую сигнализацию.","Крепко нажать и удерживать рабочий (ножной) тормоз, пока не будете готовы вернуться."],"explanation":"Всегда ставьте стояночный тормоз перед выходом из кабины, так как это единственное устройство, удерживающее стоящий автомобиль механически без присутствия водителя."},"358":{"q":"Вы ведёте гружёный тягач с полуприцепом по загородной трассе со скоростью 55 миль/ч. Движение слабое, дорога прямая, поэтому вы решаете сознательно зафиксировать взгляд на достаточно удалённой точке, чтобы вовремя заметить заглохшие машины, мусор на дороге или вливающийся поток и среагировать плавно, а не тормозить резко. Если измерять во ВРЕМЕНИ на этой скорости, как далеко вперёд следует смотреть?","options":["На 5-8 секунд вперёд -- тот же интервал, с которым вы должны проверять зеркала","На 12-15 секунд вперёд, что примерно равно четверти мили на трассовой скорости","Примерно на 6 секунд вперёд -- это ваш полный тормозной путь на скорости 55 миль/ч","Ровно на четверть мили, измеренную только в футах, а не в секундах движения"],"explanation":"Смотрите на 12-15 секунд вперёд, примерно на четверть мили на скоростной трассе, чтобы заранее замечать опасности и реагировать плавно, а не в панике."},"359":{"q":"Вы перевозите на бортовом полуприцепе груз стальных рулонов по загруженной автомагистрали на трассовой скорости. Движение плотное, машины постоянно перестраиваются из ряда в ряд вокруг вас. Вы хотите постоянно знать обстановку со всех сторон автопоезда, чтобы заранее среагировать на машину, подрезающую вас, или на проблему с шиной прицепа. Какой подход к использованию зеркал лучше всего соответствует безопасной практике коммерческого вождения?","options":["Взглянуть в зеркала один раз после каждого перестроения или смены полосы, поскольку именно тогда другие машины с наибольшей вероятностью окажутся рядом с вами","Подождать, пока вы не почувствуете рывок прицепа или не услышите необычный шум, и только тогда проверить, чтобы всё остальное время смотреть только вперёд на дорогу","Регулярно осматривать зеркала, примерно каждые 5–8 секунд, чтобы непрерывно отслеживать движение и состояние вашего транспортного средства со всех сторон","Проверять зеркала только в начале и в конце поездки, а в остальное время полностью сосредоточиться на участке дороги в 12–15 секундах впереди"],"explanation":"Регулярно проверяйте зеркала, примерно каждые 5-8 секунд, чтобы постоянно следить за движением, слепыми зонами и состоянием тягача и груза."},"360":{"q":"Вы ведёте гружёный седельный тягач с прицепом на постоянной скорости 55 миль/ч в правой полосе разделённого шоссе, когда легковой автомобиль начинает обгонять вас слева. На середине обгона машина задерживается в вашей левой слепой зоне и, похоже, не решается завершить манёвр. Чтобы создать для обгоняющего водителя самую безопасную и предсказуемую обстановку, какое действие вам следует предпринять?","options":["Отпустить педаль газа и слегка притормозить, чтобы автомобиль быстрее обошёл ваш передний бампер","Сместиться немного к правому краю своей полосы, чтобы освободить больше пространства со стороны водителя","Кратко ускориться, чтобы помочь автомобилю быстрее завершить обгон и вернуться в свою полосу","Удерживать своё положение по центру полосы и сохранять постоянную скорость, пока автомобиль полностью не обгонит вас и не вернётся вперёд"],"explanation":"Когда вас обгоняют, держитесь своей полосы и сохраняйте постоянную скорость, чтобы обгоняющий водитель мог предсказуемо оценить интервал и безопасно завершить обгон."},"361":{"q":"Вы приближаетесь к незнакомому путепроводу с установленным знаком ограничения высоты, а ваш прицеп загружен высоким штабелем машин в обрешётке. Какую из приведённых ниже величин вам ВСЕГО важнее точно знать, прежде чем решиться проехать под этим мостом?","options":["Полную высоту вашего гружёного транспортного средства, измеренную от земли до самой верхней точки","Точную общую массу гружёного автопоезда на весах","Количество топлива, имеющееся сейчас в баках","Марку и модель шин, установленных на ведущих осях"],"explanation":"Знайте общую высоту загруженного автомобиля от земли до самой высокой точки и сравните её с указанным габаритом, прежде чем проезжать под мостом или путепроводом."},"362":{"q":"Вы прокладываете маршрут для низкорамного трала с экскаватором через старый промышленный район. Впереди дорога ныряет под старый железнодорожный мост, и над улицей провисают несколько электрических проводов. Прежде чем проехать под ними, какой именно параметр КРИТИЧНЕЕ всего проверить относительно указанных и известных ограничений, чтобы избежать серьёзной аварии?","options":["Давление в шинах передней (рулевой) оси, ведь спущенное переднее колесо может просадить тягач и зацепить провода","Высоту вашего габарита по высоте (клиренс сверху), сравнив полную высоту гружёного автопоезда с указанной высотой моста и высотой проводов над дорогой","Полную допустимую массу автопоезда (GCWR), чтобы убедиться, что мост и дорожное полотно выдержат гружёный состав","Дистанцию до идущего впереди транспорта, чтобы не пришлось резко тормозить под сооружением"],"explanation":"Сверяйте общую высоту загруженного автомобиля с указанным габаритом моста и высотой проводов над дорогой, чтобы убедиться, что тягач безопасно пройдёт снизу."},"363":{"q":"Вы приближаетесь к перекрёстку с движением во всех четырёх направлениях на своём гружёном автопоезде, когда легковой автомобиль слева выезжает вперёд и агрессивно претендует на преимущество проезда, которое по закону принадлежит вам. Вы уже начали снижать скорость. Какое действие в этой ситуации является НАИЛУЧШИМ?","options":["Сохранять скорость и продолжать движение, так как преимущество проезда по закону ваше, и автомобиль обязан уступить","Многократно подавать звуковой сигнал и продолжать въезд на перекрёсток, отстаивая свою позицию","Уступить и пропустить другого водителя, даже если по закону преимущество проезда ваше, чтобы избежать столкновения","Ускориться, чтобы проехать перекрёсток прежде, чем автомобиль сможет выехать на вашу полосу"],"explanation":"Первая обязанность профессионального водителя - избежать столкновения, поэтому уступите и пропустите другого водителя, даже если по закону у вас есть преимущество."},"364":{"q":"Вы прокладываете маршрут для гружёного автопоезда к месту разгрузки, и навигатор направляет вас через окружной мост с указанным ограничением по весу, которое НИЖЕ вашей фактической полной массы автопоезда. Существует легальный объездной маршрут, добавляющий 12 миль. Что вы обязаны сделать?","options":["Проехать по мосту, но разогнаться, чтобы ваш полный вес давил на конструкцию как можно меньше времени","Медленно и плавно переползти, ведь указанные ограничения по весу на мостах носят рекомендательный характер и действуют только для пустого грузовика","Остановиться на мосту, чтобы проверить нагрузку на оси, прежде чем продолжить движение","Не въезжать на мост; выбрать легальный объездной маршрут, чтобы никогда не превышать указанное ограничение по весу"],"explanation":"Указанное ограничение веса на мосту - это жёсткий законный максимум, поэтому, если ваш общий вес превышает его, никогда не пересекайте мост и выберите законный объездной маршрут."},"365":{"q":"Вы везёте тяжёлый груз вниз по длинному крутому горному спуску. Хотя день холодный, через несколько миль вы нажимаете на педаль тормоза и замечаете, что грузовик почти не замедляется, а тормоза кажутся слабыми и \"ватными\". Какова НАИБОЛЕЕ вероятная причина этой потери тормозной силы?","options":["Тормоза перегрелись из-за слишком интенсивного и долгого использования на спуске, что вызвало затухание (выцветание) тормозов","Холодный наружный воздух заморозил влагу в тормозных магистралях и снизил их сцепление","Тормозные накладки слишком новые и ещё не приработались, поэтому плохо схватывают","Вы тормозили слишком слабо и осторожно, поэтому накладки не нагрелись достаточно, чтобы держать"],"explanation":"Сильное и продолжительное торможение на длинном спуске перегревает тормоза, из-за чего они теряют сцепление и тормозную силу даже при нажатой педали."},"367":{"q":"Вы ведёте гружёный полуприцеп по правой полосе разделённого шоссе с разрешённой скоростью. Водитель сзади несколько миль ехал у вас «на хвосте», затем резко обогнал вас, подрезал, нажал на тормоз и продолжает жестами требовать, чтобы вы ускорились или уступили. Впереди умеренный поток. Какое действие является самым безопасным и правильным при таком агрессивном водителе?","options":["Разогнаться до скорости этого водителя, чтобы он перестал ехать вплотную и отъехал от вас","Отпустить педаль газа, увеличить дистанцию и дать агрессивному водителю уехать далеко вперёд и подальше от вас","Сохранять точно своё положение и слегка нажать на тормоз, чтобы дать водителю сигнал отстать","Перестроиться левее и не давать агрессивному водителю снова обогнать вас, пока он не успокоится"],"explanation":"Самая безопасная реакция на агрессивного водителя — уступить ему дорогу, сбросив газ и увеличив дистанцию, чтобы он уехал далеко вперёд."},"368":{"q":"Вы только что закончили 45-минутный перерыв на обед на стоянке для грузовиков, и ваш гружёный тягач с прицепом припаркован параллельно вдоль правой обочины служебной дороги. Слева от вас по полосе движется транспорт. Вы готовы снова выехать на полосу движения. Какая последовательность действий является самым безопасным и правильным способом покинуть это место стоянки?","options":["Сразу выехать прямо, чтобы влиться в просвет в потоке, и включить левый указатель поворота только после того, как уже начнёте движение","Подать звуковой сигнал, чтобы предупредить водителей рядом, отпустить тормоза и без промедления разогнаться на полосе","Включить левый указатель поворота, проверить зеркала и пространство вокруг автомобиля на наличие транспорта и слепых зон, и выезжать только тогда, когда путь свободен","Проверить только зеркало со стороны водителя, и если выглядит свободно, плавно выехать на полосу, высматривая просвет"],"explanation":"Перед выездом со стоянки сначала включите сигнал, затем проверьте зеркала и всю зону вокруг машины на наличие транспорта и слепых зон, и выезжайте только когда путь свободен."},"370":{"q":"Вы ведёте гружёный седельный тягач с прицепом на трассовой скорости по двухполосной дороге без разделения встречных потоков. Встречный автомобиль выехал за осевую линию и теперь частично находится на вашей полосе, быстро приближаясь. Времени остановиться до столкновения нет. Справа от вас асфальтовая обочина и неглубокий травянистый кювет; слева — встречная полоса с движением. Какое действие даёт наибольший шанс избежать лобового столкновения?","options":["Свернуть влево на встречную полосу, чтобы объехать сместившийся автомобиль","Держать свою полосу и тормозить со всей силы, при необходимости блокируя колёса","Оставаться по центру полосы, мигать дальним светом и сохранять скорость","Свернуть вправо к обочине, даже если придётся съехать с покрытия"],"explanation":"Если встречная машина выезжает на вашу полосу, уходите вправо к обочине, поскольку водитель может вернуться на свою полосу, и поворот влево грозит лобовым столкновением."},"371":{"q":"Вы едете с грузом на скорости по шоссе жарким июльским днём, как вдруг слышите громкий хлопок спереди тягача. Перед этим вы не ощущали никакой вибрации или стука в сиденье. Сжимая руль, какой из следующих признаков НАИБОЛЕЕ чётко укажет, что лопнула именно ПЕРЕДНЯЯ шина, а не задняя?","options":["Руль внезапно становится очень тяжёлым, и грузовик сильно тянет в одну сторону","Вы чувствуете сильную вибрацию или стук, идущие вверх через сиденье и пол кабины","Задняя часть прицепа начинает вилять и раскачиваться из стороны в сторону","Указатель температуры двигателя растёт, и грузовик начинает терять мощность"],"explanation":"Разрыв переднего колеса делает руль внезапно очень тяжёлым и сильно уводит грузовик в сторону повреждённой шины."},"372":{"q":"Вы едете гружёным по ровному двухполосному шоссе со скоростью около 50 миль/ч, когда внезапно чувствуете, что задняя часть прицепа начинает раскачиваться и вилять из стороны в сторону, хотя руль по-прежнему ощущается нормально, а тормоза вы не трогали. Исходя из этих признаков, какой вывод НАИБОЛЕЕ точно описывает то, что вероятнее всего произошло?","options":["Спустило переднее колесо (на управляемой оси), и именно поэтому задняя часть теперь блуждает по полосе","Отказало заднее колесо, потому что разрыв заднего колеса обычно вызывает раскачивание или занос (рыскание) автомобиля","Заклинило тормоза прицепа, и это тащит заднюю часть боком","Начался занос ведущих колёс при разгоне, и нужно немедленно резко вывернуть руль в другую сторону"],"explanation":"Разрыв заднего колеса вызывает раскачивание или занос автомобиля, тогда как руль остаётся относительно нормальным."},"373":{"q":"Вы везёте пустой прицеп вниз по мокрому двухполосному шоссе, когда впереди с бокового съезда внезапно выезжает легковой автомобиль. Вы резко жмёте на педаль тормоза и чувствуете, как срабатывает ABS (антиблокировочная система). Какое утверждение ЛУЧШЕ всего описывает, что делает для вас антиблокировочная система в этот момент?","options":["Она сокращает ваш общий тормозной путь примерно вдвое по сравнению с тем, что было бы без ABS, поэтому вы остановитесь намного раньше автомобиля.","Она автоматически переключается на пониженную передачу и применяет торможение двигателем, чтобы контролируемо остановить тягач.","Она не даёт колёсам заблокироваться, поэтому вы можете продолжать рулить и сохранять управление, пока сильно тормозите.","Она дозирует тормозное давление так, что пустой прицеп останавливается на более коротком пути, чем гружёный."],"explanation":"ABS не даёт колёсам блокироваться при резком торможении, чтобы вы могли продолжать рулить и сохранять управление для объезда опасности."},"374":{"q":"Вы управляете гружёным тягачом с полуприцепом, оснащённым антиблокировочной системой тормозов (ABS), когда легковой автомобиль внезапно подрезает вас и резко останавливается. Вам нужно выполнить экстренное торможение в своёй полосе на сухом покрытии. Зная, как работает ABS, какое действие при торможении даёт лучший контроль и самый короткий безопасный остановочный путь?","options":["Быстро нажимать и отпускать педаль тормоза, чтобы колёса не блокировались, как бы вы сделали без ABS","Применить контролируемое прерывистое торможение, отпуская педаль каждый раз, когда колёса начинают блокироваться","Нажать на тормоз лишь слегка и объехать автомобиль, поскольку ABS сокращает остановочный путь","Нажать на педаль тормоза твёрдо, удерживать ровное постоянное давление и при необходимости подруливать, пока работает ABS"],"explanation":"С ABS тормозите, нажимая сильно и удерживая ровное непрерывное давление, одновременно рулите, позволяя системе предотвращать блокировку колёс."},"375":{"q":"Вы везёте частично загруженный прицеп (без ABS) по шоссе штата, когда автомобиль внезапно выезжает с второстепенной дороги прямо перед вами. Вы должны остановиться максимально быстро, не теряя возможности объехать препятствие рулём, если не успеете остановиться. Какой способ торможения следует применить?","options":["Применить контролируемое или прерывистое (рывковое) торможение, удерживая колёса на грани блокировки","Выжать педаль тормоза до упора и удерживать её, заблокировав колёса для кратчайшего пути остановки","Слегка и равномерно нажимать на тормоз, как при спуске с длинного уклона","Задействовать только ручной (прицепной) тормозной кран, чтобы колёса тягача оставались свободными для руления"],"explanation":"Без ABS контролируемое или прерывистое торможение, удерживающее колёса на грани блокировки, даёт максимальную тормозную силу при сохранении управляемости."},"376":{"q":"Вы ведёте гружёный тягач с полуприцепом с обычной (без ABS) тормозной системой, когда легковой автомобиль внезапно подрезает вас, и вам приходится резко тормозить, чтобы избежать столкновения. Вы выжимаете тормоз до отказа и чувствуете, что колёса заблокировались. Чтобы правильно применить прерывистое (рывковое) торможение и сохранить контроль над машиной, что нужно сделать в тот момент, когда колёса блокируются?","options":["Удерживать полное, ровное давление на педаль и держать колёса заблокированными до полной остановки","Отпустить тормоза, пока колёса снова не начнут вращаться, затем снова выжать тормоза до отказа","Качать педаль тормоза как можно быстрее, три-четыре раза в секунду, до полной остановки","Полностью убрать ногу с тормоза, заглушить двигатель и катиться накатом до остановки"],"explanation":"При прерывистом торможении вы отпускаете тормоза, пока заблокированные колёса снова не покатятся для восстановления управления, затем снова жмёте тормоза до упора."},"377":{"q":"Вы движетесь за гружёным автовозом по сухой четырёхполосной автомагистрали со скоростью 55 миль/ч, сохраняя несколько секунд свободной дороги между собой и грузовиком впереди. Внезапно в этот промежуток вклинивается перестраивающийся пикап, и стоп-сигналы автовоза вспыхивают. Почему сохранение этого запаса пространства было самым важным действием, которое позволило вам безопасно справиться с ситуацией?","options":["Это позволило вам держать 55 миль/ч, не отпуская педаль газа, поэтому поток позади вас двигался плавно","Это гарантировало полную остановку примерно за 60 футов — таков полный тормозной путь при 55 милях/ч","Это дало вам дополнительное пространство и время, чтобы заметить опасность и среагировать прежде, чем пришлось резко тормозить","Это удерживало вашу дистанцию следования менее одной секунды — интервал, который руководство рекомендует для скоростей на автомагистрали"],"explanation":"Запас пространства дает дополнительное место и время, чтобы заметить опасность и среагировать до резкого торможения, ведь тормозной путь на скорости намного длиннее, чем кажется."},"378":{"q":"Вы ведёте полностью гружёный тягач с прицепом со скоростью 55 миль/ч в хороших сухих условиях, и легковой автомобиль в соседней полосе резко тормозит из-за той же опасности, которую вы оба замечаете одновременно. Зная, как ведёт себя гружёный грузовик по сравнению с этим автомобилем, какое утверждение должно определять, сколько места вы себе оставляете?","options":["Гружёный грузовик и автомобиль остановятся примерно на одинаковом расстоянии, так как у обоих исправные тормоза","Гружёный грузовик остановится на гораздо меньшем расстоянии, потому что большой вес прижимает шины к дороге, обеспечивая лучшее сцепление","Это не имеет значения, потому что при 55 миль/ч любому транспортному средству нужно около 60 футов, чтобы среагировать и остановиться","Гружёному грузовику нужно гораздо большее расстояние для остановки, чем легковому автомобилю, поэтому вы должны оставлять намного больше места и начинать торможение раньше"],"explanation":"Гораздо большая масса и инерция груженого грузовика делают его полный тормозной путь намного длиннее, чем у легкового автомобиля, поэтому оставляйте больше места и тормозите раньше."},"379":{"q":"Вы движетесь с шоссейной скоростью по двухполосной дороге, и мотоциклист перестраивается в вашу полосу прямо перед вами, держась у правого края полосы. Движение умеренное, впереди начинается зона разрешённого обгона. Как безопаснее всего вести себя при следовании за этим мотоциклом?","options":["Относитесь к мотоциклу как к полноразмерному транспортному средству: оставьте ему всю полосу и держите увеличенную дистанцию, потому что он способен остановиться гораздо быстрее, чем вы","Подъедьте ближе по своей полосе и делите свободную левую часть полосы с мотоциклом, ведь байку нужна лишь часть полосы","Пристройтесь сзади на обычной для легкового авто дистанции в один корпус, ведь мотоцикл меньше и ему нужно меньше места, чем машине","Держитесь вплотную и будьте готовы сразу обогнать его в зоне обгона, ведь настоящая опасность - это плестись за медленным мотоциклом"],"explanation":"Мотоцикл имеет право на всю полосу и может остановиться на гораздо меньшем расстоянии, чем тяжелый грузовик, поэтому уступайте ему всю полосу и держите увеличенную дистанцию."},"380":{"q":"Вы приближаетесь к сельскому перекрёстку на своём гружёном составном транспортном средстве (тягач с прицепом). Светофор не работает (полностью погас), и ни в одном направлении нет знаков «Стоп» или «Уступи дорогу». Подъезжая к перекрёстку, вы видите пикап, который подъехал на мгновение раньше вас и уже остановился на пересекающей дороге справа от вас, ожидая возможности проехать. Какое действие правильное?","options":["Проехать первым, потому что гружёному составному транспортному средству нужно больше места и оно имеет преимущество перед более лёгкими автомобилями","Уступить дорогу пикапу, потому что он подъехал к перекрёстку первым и к тому же находится справа от вас","Считать погасший светофор зелёным сигналом и продолжать движение через перекрёсток не снижая скорости","Остановиться в центре перекрёстка, чтобы поперечный поток увидел вас, прежде чем вы начнёте манёвр"],"explanation":"На нерегулируемом перекрестке уступайте дорогу транспортному средству, прибывшему первым, а при одновременном прибытии — тому, что справа от вас."},"381":{"q":"Сейчас 15:15 ясного буднего дня, и вы ведёте гружёный одиночный грузовик через жилой район, когда видите мигающий жёлтый маячок и установленный знак школьной зоны. Окружающий транспорт по-прежнему движется с обычной разрешённой скоростью 30 миль/ч, и дорога впереди выглядит свободной. Какое действие является НАИЛУЧШИМ?","options":["Держать установленную скорость 30 миль/ч, ведь полоса впереди свободна, а другие машины не сбавляют ход","Перестроиться в левую полосу и быстро обогнать более медленные машины, чтобы проехать зону до появления детей","Снизить скорость ниже установленного предела и внимательно осматривать тротуары и пешеходные переходы в поисках детей, которые могут выбежать на дорогу","Сохранять скорость, но включить дальний свет, чтобы водители и пешеходы лучше видели ваш грузовик"],"explanation":"Мигающий маяк означает, что действует школьная зона с пониженной скоростью, поэтому снижайте скорость ниже лимита и следите за тротуарами и переходами на случай детей."},"382":{"q":"Вы приближаетесь к зоне дорожных работ на шоссе, где надполосный сигнал показывает зелёную стрелку для вашей полосы, но регулировщик (флагман), стоящий на проезжей части, держит знак STOP (Стоп), направленный на вас. Что вы должны сделать?","options":["Медленно проехать через зону, поскольку зелёная стрелка юридически разрешает движение по вашей полосе","Остановиться только если регулировщик также свистнет или взмахнёт обеими руками, иначе следовать зелёной стрелке","Считать это противоречие неисправностью и проехать с осторожностью со скоростью не более 15 миль/ч","Остановиться и подчиниться регулировщику, потому что указания регулировщика имеют приоритет даже над обычными сигналами"],"explanation":"Указания регулировщика имеют приоритет над всеми знаками и сигналами, поскольку он в реальном времени видит опасности зоны работ, которые стационарный сигнал не отражает."},"383":{"q":"Вы ведёте тягач с полуприцепом по правой полосе четырёхполосного шоссе без разделительной полосы, когда слышите сирену и видите, что сзади приближается машина скорой помощи с включёнными проблесковыми маячками. Впереди движение слабое, а правая обочина широкая и свободная. Какое действие правильное?","options":["Включить сигнал поворота, прижаться к правому краю дороги и остановиться, пока скорая помощь не проедет","Сохранять свою полосу и скорость, чтобы скорая помощь могла предугадать ваш путь и объехать вас","Перестроиться в левую полосу и остановиться там, чтобы полностью освободить правую сторону для скорой помощи","Ускориться, чтобы держаться впереди потока, и найти боковую улицу, чтобы свернуть"],"explanation":"При приближении машины экстренной службы с проблесковыми маячками и сиреной подайте сигнал, прижмитесь к правому краю дороги и остановитесь, пока она не проедет."},"384":{"q":"Вам поручают гружёный фургонный полуприцеп с лёгкими коробками, уложенными от пола до потолка и заполняющими прицеп до самой крыши. По сравнению с тем же прицепом, перевозящим плотный тяжёлый груз, уложенный лишь до уровня колена на полу, какое утверждение НАИБОЛЕЕ точно описывает, как высокий груз с верхней нагрузкой влияет на управление?","options":["Более высокая укладка понижает центр тяжести, поэтому вы можете безопасно проходить съезды и повороты на разрешённой для грузовиков скорости","Высокий центр тяжести повышает вероятность опрокидывания прицепа на поворотах и съездах, поэтому нужно снижать скорость заблаговременно, ещё до входа в них","Поскольку груз лёгкий, центр тяжести не влияет на риск опрокидывания и важен лишь для тормозного пути","Высокий центр тяжести в основном увеличивает ваш тормозной путь, поэтому настоящая опасность — врезаться в идущее впереди транспортное средство"],"explanation":"Высоко уложенный груз повышает центр тяжести даже при малом весе, из-за чего опрокидывание на поворотах и съездах гораздо вероятнее, поэтому снижайте скорость заранее."},"385":{"q":"Вы ведете загруженную цистерну и приближаетесь к съезду типа клеверный лист с рекомендованной скоростью 35 миль/ч. Сзади плотный поток, и вам хотелось бы не сбавлять ход. Вспоминая, что чаще всего приводит к опрокидыванию грузовиков, какой фактор является единственным главным виновником, которого вам следует больше всего опасаться на этом съезде?","options":["Груз, уложенный слишком низко, из-за чего центр тяжести прицепа оказывается опасно близко к поверхности дороги","Движение за идущим впереди автомобилем на целую секунду ближе положенного при входе в поворот","Слишком высокая скорость в повороте съезда вместо того, чтобы снизить ее до входа в поворот","Слишком слабое торможение тормозами прицепа на прямом участке перед съездом"],"explanation":"Самая частая причина опрокидывания грузовика — слишком высокая скорость на повороте или съезде, поэтому снижайте скорость до входа в поворот, а не в нем."},"386":{"q":"Вы перевозите высокий груз из штабелированных ящиков с оборудованием и съезжаете с автомагистрали на изогнутый въездной/съездной пандус с указателем 30 миль/ч. Грузовик сильно загружен и имеет высокий центр тяжести. Какое действие лучше всего защитит вас от опрокидывания на пандусе?","options":["Держать постоянные 30 миль/ч, потому что это указанная скорость пандуса, и знак уже учитывает грузовики","Сохранять скорость автомагистрали, пока не почувствуете, что прицеп начинает крениться, а затем резко тормозить в повороте","Катиться через поворот на нейтрали, чтобы двигатель не разгонял вас сильнее","Снизить скорость значительно ниже указанной скорости пандуса до въезда в поворот, поскольку указатель рассчитан на легковые автомобили, а не на высокий тяжёлый груз"],"explanation":"Знаки скорости на съездах рассчитаны на легковые машины, поэтому с высоким тяжелым грузом снижайте скорость значительно ниже указанной до входа в поворот, чтобы не опрокинуться."},"387":{"q":"Вы завершили доставку и припарковали гружёный грузовик на крутой улице, идущей под уклон, плотно прижавшись к правому бордюру. Прежде чем поставить стояночный тормоз и выйти из кабины, вы хотите так выставить передние колёса, чтобы при случайном отказе тормозов грузовик скатился В бордюр и был им остановлен, а не выкатился на полосу движущегося вниз транспорта. Как следует оставить передние колёса повёрнутыми?","options":["Повёрнутыми к бордюру (вправо), чтобы при откате бордюр заблокировал переднее колесо","Повёрнутыми от бордюра (влево), чтобы задняя часть грузовика прижалась к бордюру","Оставить прямо, так как именно поставленный стояночный тормоз удерживает грузовик на уклоне","Повёрнутыми к бордюру только при отсутствии бордюра, иначе прямо"],"explanation":"При парковке под уклон у бордюра поверните передние колеса к бордюру, чтобы при скатывании шина уперлась в него и остановила грузовик."},"388":{"q":"Вы останавливаетесь на крутой горной дороге, чтобы проверить груз, и паркуете грузовик передом ВВЕРХ по склону, с бордюром справа. Прежде чем отойти, вы хотите, чтобы при срабатывании отказа тормозов машина откатилась назад и уперлась в бордюр. Чтобы правильно выставить передние колеса в ситуации 'вверх по склону с бордюром', нужно:","options":["Повернуть передние колеса к бордюру (вправо), чтобы шина уперлась в него передней стороной","Повернуть передние колеса от бордюра (влево), чтобы при откате задняя сторона шины уперлась в бордюр","Оставить передние колеса прямо и полагаться только на стояночный тормоз","Повернуть передние колеса резко вправо, так же, как если бы бордюра не было"],"explanation":"При парковке на подъеме у бордюра поверните передние колеса от бордюра, чтобы при откате назад шина уперлась в него и остановила машину."},"389":{"q":"Вы едете за мотоциклом по сухой городской улице и выбираете дистанцию, исходя из того, как двигался мотоциклист. Какое предположение об этом мотоцикле НАИБОЛЕЕ важно учитывать, чтобы не врезаться ему в зад?","options":["Он всегда едет намного медленнее разрешённой скорости, поэтому короткая дистанция безопасна","Ему нужно место в две полные полосы, поэтому никогда не вставайте рядом с ним","Его легко не заметить в потоке, и он может остановиться гораздо быстрее вашего грузовика","Он будет держать одну ровную скорость и не станет резко тормозить"],"explanation":"Мотоциклы трудно заметить в потоке и они тормозят на гораздо меньшей дистанции, чем тяжелый грузовик, поэтому держите большую дистанцию."},"390":{"q":"Вы ведёте гружёный полуприцеп и начинаете длинный крутой спуск в сухую дневную погоду. Едущий с вами новичок спрашивает, как этот спуск влияет на расстояние, необходимое вашему автопоезду для полной остановки, по сравнению с остановкой на ровном покрытии при той же скорости. Какое утверждение верно?","options":["Это никак не влияет на тормозной путь, потому что полный тормозной путь зафиксирован примерно на 419 футах при 55 миль/ч независимо от уклона дороги.","Ваш тормозной путь становится намного короче, потому что сила тяжести, тянущая грузовик вниз, сильнее прижимает шины к дороге и улучшает сцепление при торможении.","Ваш тормозной путь на короткое время падает почти до нуля, как только на спуске торможение берут на себя двигатель и передачи.","Ваш тормозной путь увеличивается, потому что сила тяжести добавляется к вашей инерции на спуске, и тормозам приходится работать тяжелее на большем расстоянии, чтобы остановить автопоезд."],"explanation":"На спуске сила тяжести добавляется к инерции, поэтому тормозам приходится работать сильнее на большем расстоянии, и тормозной путь увеличивается."},"391":{"q":"Вы ведёте гружёный полуприцеп по сельской трассе и приближаетесь к крутому повороту с жёлтым предупреждающим знаком рекомендованной скорости 'БЕЗОПАСНАЯ СКОРОСТЬ 40 миль/ч'. Покрытие сухое, движение слабое. Какое утверждение лучше всего описывает, как вам, водителю с CDL, следует относиться к этой рекомендованной скорости?","options":["Значение 40 миль/ч рассчитано для легковых автомобилей, поэтому как гружёный грузовик с более высоким центром тяжести вы должны входить в поворот на скорости ниже указанной, чтобы избежать опрокидывания.","Поскольку знак является официальным предупреждением, 40 миль/ч — это максимально разрешённая законом скорость для всех транспортных средств, и грузовики могут проходить поворот ровно на 40 миль/ч, пока дорога сухая.","Рекомендация относится только к пустым полуприцепам; так как ваш прицеп гружёный и устойчивый, вы можете превысить 40 миль/ч в повороте.","Рекомендованные скорости устанавливаются специально для грузовиков, поэтому 40 миль/ч уже включает запас безопасности для грузовика, и вы можете ехать так же, не снижая скорость дополнительно."],"explanation":"Рекомендуемые скорости на поворотах рассчитаны для легковых машин, поэтому груженый грузовик с высоким центром тяжести должен входить ниже указанной скорости во избежание опрокидывания."},"393":{"q":"Вы завершаете длинный рейс с доставкой и заезжаете на стоянку. Сегодня утром перед предрейсовым осмотром всё было в порядке, и вы также проверили крепление груза в течение первых 50 миль и затем каждые 150 миль в пути. Теперь, когда рейс окончен и грузовик припаркован, какой осмотр следует выполнить, чтобы завершить полный цикл осмотров, которого требует DPS?","options":["Дополнительный осмотр не нужен, потому что ваши проверки в пути каждые 150 миль уже охватили транспортное средство за день","Послерейсовый осмотр, чтобы любые неисправности, возникшие во время рейса, были задокументированы до следующего водителя или вашей следующей смены","Ежегодный осмотр, поскольку это единственный формальный осмотр, требуемый после завершения дневной езды","Ежемесячный осмотр тормозов и шин, чтобы подвести итог износу за рейс"],"explanation":"Послерейсовый осмотр проводится в конце поездки, чтобы любые неисправности, возникшие во время движения, были задокументированы в отчете перед следующей сменой."},"395":{"q":"Вы только что завершили 11-часовую поездку и заехали на стоянку. Во время рейса тормоза казались немного слабыми, и вы заметили, что габаритный фонарь начал мигать и гаснуть. В рамках правильного выполнения послерейсового осмотра какой из перечисленных документов вы, как правило, обязаны заполнить и, где это требуется, сдать, чтобы следующий водитель и перевозчик были предупреждены об этих неисправностях?","options":["Журнал учёта заправок топливом и пробега, который вы ведёте для налоговой отчётности IFTA","Ваш личный дневник поездки с записями о том, как прошёл день и где вы останавливались на отдых","Отчёт водителя об осмотре транспортного средства (DVIR) с указанием всех неисправностей, таких как слабые тормоза и неработающий габаритный фонарь","Отчёт о погоде и состоянии дороги для документации диспетчера"],"explanation":"Послерейсовый осмотр требует заполнения отчета об осмотре транспортного средства водителем (DVIR), фиксирующего любые дефекты безопасности, например слабые тормоза и неработающий габаритный фонарь."},"396":{"q":"Холодное утро, вы только что завели двигатель, чтобы начать предрейсовый прогрев. Вы следите за приборами на панели, чтобы убедиться, что всё работает, прежде чем тронуться. Какое из утверждений верно описывает, как должен вести себя датчик давления масла, и указывает, что двигатель безопасно эксплуатировать?","options":["Стрелка должна подниматься медленно и достичь нормального давления через несколько минут работы на холостом ходу, когда масло прогреется","Поскольку утро холодное, нужно дать двигателю поработать на холостом ходу около часа, прежде чем давление масла станет надёжным","Давлению масла не обязательно появляться, пока вы не поедете под нагрузкой по дороге","Стрелка должна достичь нормального рабочего давления в течение нескольких секунд после запуска двигателя"],"explanation":"Давление масла должно достичь нормального рабочего уровня в течение нескольких секунд после запуска двигателя, иначе его нужно заглушить во избежание повреждения."},"397":{"q":"Вы уже 40 минут в рейсе на сельской двухполосной дороге, когда бросаете взгляд на приборы и видите, что указатель давления масла упал до нуля, хотя двигатель по-прежнему звучит и работает нормально и предупреждающий зуммер ещё не сработал. Каково правильное действие?","options":["Съехать с дороги, как только это станет безопасно, остановиться и заглушить двигатель","Продолжать ехать как обычно до ближайшей стоянки для грузовиков, раз двигатель ещё звучит нормально","Сохранять скорость, но сбросить газ и доехать до запланированной заправки","Выключить второстепенные потребители, например радио и кондиционер, чтобы снизить нагрузку на двигатель, и продолжать движение"],"explanation":"Падение давления масла означает, что двигатель больше не смазывается, поэтому при первой безопасной возможности съезжайте и немедленно глушите двигатель."},"398":{"q":"Вы поднимаетесь по длинному подъёму жарким летним днём, полностью загружены и близки к максимальной разрешённой массе (GVWR). Приближаясь к вершине, вы замечаете, что один из приборов на панели начинает заходить в красную зону. Прежде чем решить, как реагировать, какой именно прибор предназначен для предупреждения о перегреве самого двигателя?","options":["Указатель давления масла, потому что в жару масло становится более жидким и стрелка поднимается, предупреждая о высокой температуре двигателя","Указатель температуры охлаждающей жидкости, потому что он показывает температуру охлаждающей жидкости двигателя и предупреждает, что двигатель перегревается","Пирометр, потому что он измеряет температуру выхлопных газов, что в жаркий день равнозначно перегреву двигателя","Вольтметр, потому что долгий подъём в жару перегревает систему зарядки и сигнализирует о перегреве двигателя"],"explanation":"Указатель температуры охлаждающей жидкости показывает ее температуру и предупреждает о перегреве двигателя."},"399":{"q":"Во время предрейсового осмотра вы запускаете двигатель и наблюдаете за приборами на панели, пока грузовик работает на холостом ходу. Вы замечаете, что стрелка амперметра (или вольтметра) устойчиво стоит в пределах нормального диапазона, не падает и не колеблется хаотично. О чём на самом деле говорит вам этот прибор о вашем автомобиле?","options":["Давление моторного масла достаточно высокое, чтобы безопасно начать поездку","Температура охлаждающей жидкости находится в пределах безопасного рабочего диапазона","Система зарядки работает и поддерживает аккумулятор должным образом заряженным","В банках аккумулятора достаточно воды, и он надёжно закреплён болтами"],"explanation":"Стабильные показания амперметра или вольтметра в нормальном диапазоне подтверждают, что генератор вырабатывает ток и поддерживает аккумулятор в правильно заряженном состоянии."},"400":{"q":"Во время предрейсового осмотра вы беретесь за рулевое колесо тягача и покачиваете его из стороны в сторону, при этом передние колеса не двигаются. Вы чувствуете заметный люфт, прежде чем колеса начинают реагировать. Чтобы определить, находится ли этот свободный ход в безопасных пределах и можно ли законно эксплуатировать автомобиль, какой МАКСИМАЛЬНЫЙ ход рулевого колеса допустим до того, как передние колеса начнут поворачиваться?","options":["До половины оборота рулевого колеса, так как некоторый люфт нормален для тяжелых грузовиков","До полного оборота рулевого колеса, прежде чем колеса отреагируют","До 90 градусов, то есть четверти оборота колеса","Не более чем примерно 10 градусов хода до того, как колеса отреагируют"],"explanation":"Свободный ход рулевого колеса должен составлять не более примерно 10 градусов до начала поворота передних колёс; больше указывает на изношенное или ослабленное рулевое управление."},"401":{"q":"Во время предрейсового осмотра вы нажимаете на педаль сцепления и обнаруживаете, что у нее заметно больше свободного хода (свободное движение до появления сопротивления), чем обычно. Вы уже опаздываете, а грузовик все еще едет. Какое утверждение ЛУЧШЕ всего описывает то, что вы обнаружили, и что вам следует сделать?","options":["Слишком большой или слишком малый свободный ход сцепления — это механическая неисправность, которую необходимо устранить, прежде чем эксплуатация автомобиля станет безопасной","Избыточный свободный ход сцепления — это нормальный износ, который имеет значение только тогда, когда сцепление начинает пробуксовывать под нагрузкой","Это проблема, но только рулевое управление и тормоза являются пунктами осмотра, способными вывести грузовик из эксплуатации","Слабый свободный ход сцепления на самом деле хороший знак того, что привод хорошо смазан и не заедает"],"explanation":"Слишком большой или слишком малый свободный ход сцепления является механической неисправностью, которую необходимо устранить, прежде чем эксплуатировать автомобиль."},"402":{"q":"Вы спускаетесь на гружёном автопоезде по длинному горному спуску. Чтобы сэкономить топливо и снизить износ, коллега советует вам переключиться на нейтральную передачу и дать грузовику катиться вниз, используя тормоза только когда скорость становится слишком высокой. Почему следовать этому совету - неправильный выбор?","options":["Это допустимо на коротком спуске, потому что одни только тормоза могут безопасно контролировать грузовик на всём пути вниз","Вы теряете торможение двигателем и передачей, а также управление автомобилем, ваши рабочие тормоза могут перегреться и потерять эффективность, и накат на нейтрали запрещён законом","Это становится проблемой только если спуск круче, чем низшая передача, которую вы обычно выбрали бы перед спуском","Накат экономит так много топлива, что небольшая потеря контроля является приемлемым компромиссом на большинстве спусков"],"explanation":"Переключение в нейтраль на длинном спуске лишает торможения двигателем и передачей, перегревает и ослабляет рабочие тормоза, а движение накатом на нейтрали запрещено."},"403":{"q":"Вы поднимаетесь с груженым прицепом по длинному подъему на старом грузовике, у которого на панели нет индикатора передачи. Двигатель начинает работать с натугой и теряет мощность, и вы понимаете, что нужно перейти на пониженную передачу, чтобы продолжить подъем. Не имея ни таблицы переключения, ни индикатора передачи, какую информацию вам следует реально использовать, чтобы определить, какая передача правильная в данный момент?","options":["Только показания правого бокового зеркала, пока вы наблюдаете, как прицеп идет вверх по склону","Высоту вашего водительского сиденья и то, насколько крутым выглядит спуск из кабины","Вашу текущую скорость движения в сочетании с оборотами двигателя по тахометру","Положение ручки передней двери относительно вашего плеча как быстрый ориентир"],"explanation":"Правильная передача выбирается путём согласования скорости движения с оборотами двигателя, показанными на тахометре."},"404":{"q":"Вы остановились на красный свет на крутом подъёме с полностью загруженным полуприцепом. Загорается зелёный, и вам нужно плавно тронуться, не позволив машине откатиться назад к автомобилю, стоящему вплотную сзади. Когда вы готовитесь отпустить рабочий (ножной) тормоз и добавить обороты двигателю, какой приём ЛУЧШЕ всего удержит автопоезд от отката назад в момент трогания?","options":["Быстро несколько раз прокачать рабочий тормоз, чтобы поднять дополнительное давление воздуха перед стартом","Включить более высокую передачу, чтобы у двигателя было больше тяги для преодоления уклона","Поднять обороты двигателя и медленно отпускать сцепление, чтобы грузовик тронулся за счёт одного крутящего момента","Держать стояночный тормоз включённым и отпускать его лишь тогда, когда двигатель подхватит нагрузку и машина начнёт двигаться вперёд"],"explanation":"При старте на подъёме удерживайте стояночный тормоз и отпускайте его только тогда, когда двигатель подхватит нагрузку и вы начнёте движение вперёд, чтобы избежать отката назад."},"405":{"q":"Чуть ниже нуля, и двор покрыт тонкой коркой льда, когда вы трогаетесь от знака \"Стоп\" на выезде со склада с гружёным составом. Вы чувствуете, что ведущие колёса начинают терять сцепление. Какое действие даёт ЛУЧШИЙ шанс тронуться без пробуксовки ведущих колёс и заноса при разгоне?","options":["Плавно нажимайте на газ и набирайте скорость постепенно, чтобы ведущие колёса сохраняли сцепление со скользкой поверхностью","Резко выжмите педаль газа до пола, чтобы лишняя мощность протолкнула грузовик через скользкий участок","Добавьте одну дополнительную секунду дистанции на каждые 10 футов длины автомобиля перед тем, как тронуться","Держите сцепление частично выжатым и сильно раскрутите двигатель, затем резко отпустите сцепление для мощного старта"],"explanation":"На скользкой поверхности около точки замерзания плавно нажимайте на газ и набирайте скорость постепенно, чтобы ведущие колёса сохраняли сцепление и не сорвались в занос."},"406":{"q":"Только что рассвело, и вы проводите предрейсовый осмотр. Открыв капот, вы смотрите на приводные ремни генератора и водяного насоса. Какое состояние говорит о том, что ремни требуют внимания, прежде чем можно безопасно выехать на дорогу?","options":["Ремни имеют тусклый, тёмный цвет вместо яркого, блестящего вида","Ремень потрескался и обтрепался или прогибается сильнее нормы при нажатии (неправильное натяжение)","Звуковой сигнал звучит недостаточно громко при нажатии на кнопку","Указатель топлива не показывает полный бак при включённом зажигании"],"explanation":"Приводные ремни необходимо заменить, если они потрескались, обтрепались или прогибаются больше нормы, поскольку неправильное натяжение или износ могут привести к обрыву ремня."},"407":{"q":"Во время предрейсового осмотра вы открываете капот и проводите рукой вдоль шлангов радиатора и отопителя в моторном отсеке. На какое состояние вы в первую очередь проверяете эти шланги?","options":["Тёплые ли шланги на ощупь, что указывало бы на то, что двигатель достиг рабочей температуры","Громкое шипение или стук, исходящие из зоны ремня и шкива","Размягчённые участки, утечки и трещины, которые могут привести к разрыву шланга","Яркий глянцевый блеск, показывающий, что резину недавно очистили и обработали"],"explanation":"Шланги двигателя нужно проверять на мягкие участки, утечки и трещины, поскольку ослабленный шланг может лопнуть под действием тепла и давления и привести к потере охлаждающей жидкости."},"408":{"q":"Чуть ниже нуля во время утреннего предрейсового осмотра, и обходя моторный отсек, вы решаете проверить систему гидроусилителя руля перед долгим днём езды по горам. Что из перечисленного ЛУЧШЕ всего описывает, что именно нужно проверять в системе гидроусилителя руля?","options":["Свободный ход рулевого колеса не более 10 градусов (примерно 2 дюйма на 20-дюймовом руле) до того, как повернутся колёса","Громкий вой или гул насоса, поскольку звук — единственный надёжный признак неисправности гидроусилителя руля","Свежую яркую краску на бачке и магистралях, подтверждающую, что систему недавно обслуживали","Уровень жидкости гидроусилителя руля и любые признаки утечек в шлангах, бачке и соединениях"],"explanation":"Проверяйте систему гидроусилителя руля на правильный уровень жидкости и любые утечки в шлангах, бачке и соединениях, поскольку низкий уровень может вызвать внезапную потерю усилителя."},"409":{"q":"Во время предрейсового осмотра холодным ясным утром вы подходите к кабине и замечаете трещину, идущую по нижнему краю лобового стекла, а также слой дорожной грязи и засохших следов от насекомых на большей части стекла. Первый час поездки вам предстоит ехать навстречу низкому утреннему солнцу. Как правильно поступить с лобовым стеклом перед поездкой?","options":["Тщательно вымыть лобовое стекло и убедиться, что трещина не настолько велика и не расположена так, чтобы сильно ограничивать обзор, прежде чем выезжать","Оставить грязь на месте, потому что грязное, мутное стекло на самом деле уменьшает блики от низкого утреннего солнца и улучшает видимость","Нанести тёмную тонировочную плёнку на всё лобовое стекло, чтобы справиться с бликами от солнца, и ехать, не вымыв стекло","Полностью проигнорировать лобовое стекло, поскольку любая трещина, даже самая незначительная, автоматически выводит транспортное средство из эксплуатации и завершает осмотр"],"explanation":"Лобовое стекло должно быть чистым и без трещин, достаточно больших или расположенных так, что они сильно ухудшают обзор, прежде чем выезжать."},"410":{"q":"Дождливое утро, и во время предрейсового осмотра вы обнаруживаете, что щётка стеклоочистителя со стороны водителя порвана, а бачок омывателя пуст. Вы уже выбиваетесь из графика, и дождь сейчас слабый. Какая причина ЛУЧШЕ всего объясняет, почему эти неисправности нужно устранить перед поездкой, а не считать их мелким неудобством?","options":["Они нужны в основном для того, чтобы защищать краску от дорожной грязи и сохранять стоимость грузовика при перепродаже","Исправные стеклоочистители и омыватели обеспечивают чёткую видимость в дождь, а без чёткого обзора вы не можете безопасно оценивать расстояние, движение и опасности впереди","Они требуются только для того, чтобы грузовик прошёл ежегодную государственную проверку безопасности, а не для повседневной езды","Они помогают быстрее размораживать лобовое стекло, и именно поэтому они относятся к неисправностям, запрещающим эксплуатацию"],"explanation":"Дворники и омыватели обеспечивают чистый обзор в дождь, а ясное зрение необходимо для оценки дистанции, движения и опасностей впереди."},"411":{"q":"Вы сдаёте назад тягач с прицепом из тесного погрузочного дока, когда рабочий внезапно заходит в вашу слепую зону у задней части машины. Во время предрейсового осмотра вы убедились, что звуковой сигнал (клаксон) работает. В этот момент какова ГЛАВНАЯ причина, по которой исправный звуковой сигнал важен для вас как для водителя CDL?","options":["Он позволяет дать коллегам знать, что вы закончили и готовы выехать из дока","Он подтверждает, что в электросистеме достаточно заряда для работы вспомогательного оборудования","Он позволяет предупредить рабочего и других людей о непосредственной опасности, чтобы они успели отойти","Он относится к функциям комфорта и удобства, которые инспектор проверяет для оценки плавности хода"],"explanation":"Звуковой сигнал — это предупреждающее устройство, которым оповещают рабочих, пешеходов и водителей о непосредственной опасности, чтобы они отошли."},"412":{"q":"Ранним утром при температуре чуть ниже нуля во время предрейсового осмотра ветровое стекло постоянно запотевает и покрывается инеем изнутри. Вы убедились, что обогреватель и система обдува (дефростер) работают исправно. Какова главная причина безопасности, по которой эти системы обязаны работать перед выездом на дорогу?","options":["Чтобы в кабине было достаточно тепло и вы оставались бодрым и в комфорте во время долгой холодной смены","Чтобы быстро растопить лёд на наружных зеркалах и антенне перед началом движения","Чтобы тёплый воздух не давал щёткам стеклоочистителя примерзать и прилипать к стеклу","Чтобы держать ветровое стекло чистым и сохранять беспрепятственный обзор дороги в холодную или сырую погоду"],"explanation":"Обдув стекла и обогреватель сохраняют лобовое стекло чистым в холодную или сырую погоду, обеспечивая беспрепятственный обзор дороги."},"413":{"q":"Чуть ниже нуля, вам нужно проехать всего две мили до ближайшей разгрузочной площадки, и ремень безопасности кажется жёстким и неудобным поверх зимней куртки. Заканчивая предрейсовый осмотр и готовясь выехать, какое действие правильно в отношении ремня безопасности?","options":["Пристегнуть и носить ремень безопасности на протяжении всей поездки, независимо от того, насколько коротка дистанция или насколько медленно вы планируете ехать","Оставить ремень непристёгнутым, потому что поездка меньше трёх миль и вы будете ехать медленно","Заправить ремень свободно за спину, чтобы предупреждающий сигнал замолчал, но движение не было стеснено курткой","Не пристёгиваться, поскольку медленная езда по площадке и стоянке юридически не требует использования ремня"],"explanation":"Профессиональный водитель обязан пристёгиваться ремнём безопасности всегда, когда транспорт в движении, независимо от длины или скорости поездки."},"414":{"q":"Вы везёте груз по сельскому двухполосному шоссе, когда двигатель теряет мощность и вы накатом съезжаете на правую обочину. Вы включаете аварийную сигнализацию и уже чувствуете запах дыма из моторного отсека, поэтому хватаете заряженный огнетушитель. Прежде чем пойти назад выставлять предупреждающие устройства, какое ещё аварийное снаряжение вы по закону обязаны были иметь на этом грузовике, чтобы завершить установку предупреждения?","options":["Запасную CB-рацию, чтобы вызвать помощь и предупредить других водителей об опасности","Светоотражающие предупреждающие треугольники, чтобы выставить их на дороге и предупредить приближающийся транспорт","Светоотражающий жилет повышенной видимости — единственное устройство, которое правила обязывают вас возить","Только пачку дорожных фальшфейеров, ведь треугольники необязательны, если включена аварийная сигнализация"],"explanation":"Каждый коммерческий автомобиль должен иметь три светоотражающих аварийных треугольника, чтобы выставить их на дорогу и предупредить приближающийся транспорт при остановке."},"415":{"q":"Вы выходите на смену и садитесь в тягач, который другой водитель оставил два часа назад. Перед выездом с площадки вы хотите убедиться, что тормоза, фары и шины пригодны к эксплуатации. Какое одно действие даст вам самую надёжную отправную картину дефектов, уже обнаруженных на этом автомобиле?","options":["Считать машину исправной, ведь предыдущий водитель явно завершил рейс на ней без поломок","Сразу выехать на пробную поездку, ведь проехать несколько миль — самый быстрый способ почувствовать реальную проблему","Прочитать последний отчёт о техосмотре (DVIR) предыдущего водителя и проверить, что отмеченные дефекты были официально подтверждены как устранённые","Позвонить диспетчеру и спросить, жаловался ли кто-нибудь из водителей на этот тягач за прошедшую неделю"],"explanation":"Перед поездкой ознакомьтесь с последним отчётом предыдущего водителя об осмотре (DVIR) и убедитесь, что отмеченные неисправности подтверждены как устранённые."},"417":{"q":"Вы уже три часа в долгой однообразной поездке по автомагистрали после раннего выезда. Скорость незаметно для вас снизилась, вы почти не помните последние несколько миль и ловите себя на том, что трёте глаза. Согласно рекомендациям по безопасному вождению, что из перечисленного яснее всего предупреждает, что вы становитесь слишком сонным, чтобы безопасно продолжать движение?","options":["Ваши руки беспокойно двигаются на руле, и вам всё время хочется чаще проверять зеркала","Вы чувствуете себя предельно бодрым, и ваше внимание полностью сосредоточено на дороге впереди","Ваша реакция на педаль тормоза кажется быстрее и чётче, чем обычно","Ваши веки тяжелеют, а мысли постоянно уходят в сторону от дороги"],"explanation":"Тяжёлые, слипающиеся веки в сочетании с блуждающими мыслями — классические признаки опасной усталости водителя."},"418":{"q":"Сейчас 2 часа ночи, вы уже три часа в дальнем рейсе, и тут чувствуете, что веки тяжелеют, вы замечаете, что машину уводит к обочине, и не помните последние несколько миль. До терминала ещё более 100 миль. Какое действие действительно восстановит вашу способность безопасно вести машину?","options":["Съехать на безопасную зону отдыха и поспать или отдохнуть перед продолжением пути","Открыть окна и сделать радио погромче, чтобы взбодриться","Остановиться за большим кофе и ехать дальше, чтобы добраться до терминала","Увеличить дистанцию до впереди идущего транспорта и продолжать ехать осторожнее"],"explanation":"Единственное настоящее средство от сонливости — сон, поэтому остановитесь в безопасной зоне отдыха и отдохните перед продолжением пути."},"419":{"q":"Сейчас 4:30 утра, и вы собираетесь начать 9-часовой рейс после того, как плохо спали прошлой ночью. Вы чувствуете сонливость. Какой из перечисленных способов НАИМЕНЕЕ эффективен для того, чтобы усталость не привела к вождению в состоянии переутомления в этой долгой поездке?","options":["Планировать рейсы так, чтобы большую часть пути проезжать в те часы, когда вы обычно бодрствуете","Выпить большую чашку кофе и держать в кабине холод и громкое радио, чтобы взбодриться вместо того, чтобы выспаться","Хорошо выспаться перед поездкой и планировать остановки для отдыха, когда чувствуете сонливость","Избегать лекарств, вызывающих сонливость, и распознавать тревожные признаки, такие как тяжёлые веки или рассеянные мысли"],"explanation":"Кофе, холодный воздух и громкий шум лишь временно маскируют сонливость и никогда не заменят сон — единственное настоящее средство от усталости."},"421":{"q":"Стоит жара под 38 градусов (100 по Фаренгейту), и вы уже около трёх часов в пути по Западному Техасу. Вы останавливаетесь, чтобы выполнить обязательную проверку груза и шин в пути. Две шины теперь показывают заметно более высокое давление, чем во время утреннего предрейсового осмотра на холоде. Какова НАИБОЛЕЕ вероятная причина и о каком риске это говорит?","options":["Горячий асфальт охладил воздух внутри шин, снизив давление и повысив риск спустить колесо","Гудрон, выступающий от жары на дороге, впитался в шины, добавив им веса и давления","Жара повысила давление воздуха внутри шин, что увеличивает риск разрыва покрышки","Ничего страшного: на жаре давление в шинах естественно падает, поэтому повышенное показание означает, что неисправен ваш манометр"],"explanation":"В жаркую погоду воздух в шинах расширяется и давление растёт, что повышает риск разрыва шины."},"422":{"q":"Жаркий летний день в Техасе, время после полудня. Управляя гружёным составным транспортным средством, вы замечаете на асфальте впереди блестящие тёмные пятна гудрона, который 'выступает' (проступает) на поверхность дороги. Чего следует ожидать от такого проступающего гудрона и почему это важно для контроля над автомобилем?","options":["Гудрон обеспечит шинам дополнительное сцепление, потому что он липкий, поэтому через такие участки можно безопасно сохранять скорость движения по шоссе.","Главная опасность в том, что жара поднимет давление в шинах выше предела, поэтому сам гудрон никак не влияет на то, как дорога ведёт себя под шинами.","Он практически не влияет на сцепление, пока у шин управляемой (передней) оси сохраняется протектор не менее 4/32 дюйма.","Он сделает поверхность дороги скользкой и снизит сцепление шин, поэтому на таких участках следует сбросить скорость и избегать резких поворотов руля и торможения."],"explanation":"Выступающий гудрон делает дорогу скользкой и снижает сцепление, поэтому сбавьте скорость и избегайте резкого руления и торможения на таких участках."},"423":{"q":"Середина июля в Техасе, вы поднимаетесь по длинному подъему с полной загрузкой. В кабине жарко, двигатель работает на пределе, и вы хотите получить раннее предупреждение о том, что двигатель вот-вот перегреется, прежде чем застрянете или повредите его. Какой прибор даст вам это предупреждение?","options":["Указатель температуры охлаждающей жидкости","Указатель давления масла","Указатель уровня топлива","Тахометр (обороты двигателя)"],"explanation":"Указатель температуры охлаждающей жидкости — главный прямой индикатор перегрева двигателя, дающий раннее предупреждение о необходимости действовать."},"424":{"q":"Вы ведете гружёный автопоезд по двухполосному шоссе сразу после рассвета и въезжаете в полосу густого тумана, настолько плотного, что вы едва различаете разметку впереди. Вы решаете двигаться медленно, пока не доберётесь до следующего съезда. Чтобы видеть дорогу как можно лучше, НЕ ухудшая при этом собственную видимость, какой режим фар выбрать?","options":["Включить дальний свет, ведь он освещает примерно 350-500 футов и позволяет видеть сквозь туман дальше","Использовать ближний свет, потому что дальний отражается от тумана обратно в глаза и снижает видимость","Выключить весь передний свет и полагаться только на аварийную сигнализацию, чтобы встречные водители вас заметили","Ехать с дальним светом и переключаться на ближний только когда встречная машина окажется в пределах 500 футов"],"explanation":"В тумане используйте ближний свет, потому что дальний отражается от тумана и слепит глаза, ухудшая видимость."},"425":{"q":"Вы ведёте гружёный тягач с полуприцепом по двухполосному шоссе ночью и въезжаете в полосу тумана настолько густого, что больше не видите разметку полос и задние фонари идущего впереди транспорта. Какое из перечисленных действий является САМЫМ безопасным?","options":["Включить дальний свет, чтобы более яркий свет помог видеть дальше сквозь туман","Продолжать движение на сниженной скорости с ближним светом, так как останавливаться где-либо опаснее, чем ехать дальше","Полностью съехать с дороги, далеко за пределы полос движения, включить аварийную сигнализацию и подождать, пока туман рассеется","Сбросить скорость почти до нуля и остановиться прямо в своей полосе с включённой аварийной сигнализацией, пока видимость не улучшится"],"explanation":"Когда туман слишком густой, чтобы видеть, полностью съезжайте с дороги вне полос движения, включите аварийку и ждите, пока туман рассеется."},"426":{"q":"Вас отправляют в рейс в ветреный день с постоянными порывами бокового ветра на открытом участке шоссе. Четыре сцепленных автопоезда выезжают со двора одновременно с вами. Учитывая, как ветер воздействует на транспортное средство, какой водитель должен БОЛЬШЕ всего опасаться того, что его вытолкнет из полосы или даже опрокинет боковым ветром?","options":["Водитель полностью загруженной автоцистерны, потому что плещущаяся жидкость делает ветер главной угрозой","Водитель платформы с низким, тяжёлым и равномерно распределённым стальным грузом","Водитель загруженного фургонного прицепа, идущего на предельно допустимом весе, потому что более тяжёлые машины ловят больше ветра","Водитель высокого фургонного прицепа, который пуст или загружен слегка, потому что он представляет большую поверхность при малом весе, способном противостоять ветру"],"explanation":"Пустой или легко загруженный высокий фургон-прицеп наиболее уязвим к боковому ветру, так как имеет большую поверхность и малый вес для сопротивления ветру."},"427":{"q":"Вы управляете гружёным составным транспортным средством на сельской двухполосной трассе Техаса и хотите спланировать поездку так, чтобы провести как можно меньше времени в условиях, когда олени и другие крупные животные чаще всего выскакивают на дорогу. В какое время суток требуется наивысший уровень внимательности из-за выхода животных на дорогу?","options":["Периоды слабого освещения на рассвете и в сумерках","Середина дня около полудня, когда животные ищут корм","Позднее утро, после того как солнце полностью взошло","Послеобеденное время, в самую тёплую часть дня"],"explanation":"Олени и крупные животные наиболее активны на рассвете и в сумерках — в условиях слабого освещения, когда зрение водителя тоже ухудшено."},"429":{"q":"Вы ведёте гружёный составной автомобиль по оживлённой четырёхполосной автомагистрали в умеренном потоке. Яркий анимированный цифровой рекламный щит на правой обочине приковывает ваш взгляд на несколько секунд, пока вы проезжаете мимо. Какое последствие этого пристального взгляда является НАИБОЛЕЕ серьёзной угрозой безопасности, которую должен осознавать водитель CDL?","options":["Ваши глаза привыкнут к яркому свету, и вы на мгновение потеряете ночное зрение","Вы перестаёте сканировать обстановку и не замечаете возникающие опасности в других частях поля зрения","Вы подсознательно снизите скорость намного ниже потока и создадите помеху едущим сзади","Вы сосредоточитесь на щите настолько резко, что на самом деле увидите дорогу впереди чётче"],"explanation":"Фиксация взгляда на одном объекте прекращает сканирование, поэтому опасности в других частях поля зрения остаются незамеченными, пока не станет поздно."},"430":{"q":"Вы ведёте гружёный седельный тягач с прицепом по двухполосному просёлочному шоссе и догоняете медленный трактор, из-за которого едете на 15 миль/ч ниже допустимой скорости. Вы хотите его обогнать, но дорога постоянно меняется. В каком из следующих мест попытка обгона будет НАИМЕНЕЕ безопасной и с наибольшей вероятностью приведёт к лобовому столкновению?","options":["На длинном ровном прямом участке, где вы ясно видите не менее четверти мили пустой встречной полосы","На пологом спуске, где скорость нарастает естественным образом и обгон можно завершить быстро","На подъезде к вершине холма или к повороту, где дорога впереди изгибается или поднимается так, что её не видно","На прямом отрезке с прерывистой осевой линией и без встречного транспорта в поле зрения"],"explanation":"Никогда не обгоняйте на подъезде к вершине холма или повороту, где дорога уходит из вида и встречный транспорт может быть скрыт."},"431":{"q":"Вы ведёте гружёный автопоезд по двухполосному шоссе и начинаете обгон более медленного легкового автомобиля. Поравнявшись с ним, вы понимаете, что уже несколько секунд едете вровень с задней дверью автомобиля, находясь прямо в слепой зоне его водителя. Чтобы завершить этот манёвр настолько безопасно, насколько требует DPS, что вам следует сделать?","options":["Сбросить газ и удерживать положение вровень с автомобилем, чтобы у другого водителя было достаточно времени заметить вас, прежде чем вы выйдете вперёд","Оставаться рядом с автомобилем на одинаковой скорости, пока не убедитесь, что встречного транспорта нет, и только затем вернуться в свою полосу","Сохранять текущую скорость и постепенно смещаться обратно в свою полосу, всё ещё находясь рядом с автомобилем, чтобы сократить общий обгон","При необходимости ускориться, чтобы выйти из слепой зоны другого водителя и завершить обгон без промедления, а затем вернуться в свою полосу, не задерживаясь рядом с автомобилем"],"explanation":"Завершайте обгон быстро, выходя из слепой зоны другого водителя, затем возвращайтесь в свою полосу, не задерживаясь рядом."},"432":{"q":"Вы приближаетесь к перекрёстку с обозначенным пешеходным переходом. Для вас горит зелёный свет, и вы хотите повернуть направо, но пешеход уже сошёл с тротуара на переход, который вам предстоит пересечь. Что вы должны сделать?","options":["Уступить и дать пешеходу закончить переход, потому что пешеходы на обозначенном переходе имеют преимущество","Совершить поворот, поскольку зелёный свет даёт вам преимущество перед пешеходом","Подать звуковой сигнал, чтобы предупредить пешехода, и продолжить поворот, если он не остановится","Останавливаться только если пешеход находится непосредственно на вашей полосе движения, иначе продолжать движение"],"explanation":"Пешеходы, законно находящиеся на размеченном пешеходном переходе, всегда имеют преимущество, поэтому поворачивающий водитель обязан уступить им даже на зелёный сигнал."},"433":{"q":"Вы ведете тягач с прицепом по двухполосной городской улице, и впереди вас по правой части вашей полосы едет велосипедист. Движение умеренное, и вы приближаетесь к зоне с припаркованными автомобилями, где велосипедисту, возможно, придется сместиться левее. Какое действие лучше всего отражает то, как следует относиться к этому велосипедисту?","options":["Держаться вплотную сзади и дать длинный гудок, чтобы велосипедист понял, что нужно съехать на обочину","Относиться к велосипедисту так же, как к другому транспортному средству, предоставляя полное пространство и безопасный зазор перед обгоном","Протиснуться мимо в той же полосе, поскольку велосипед занимает гораздо меньше места, чем автомобиль","Перестроиться в крайнюю левую полосу и оставаться там до конца квартала"],"explanation":"Велосипедист имеет такое же право на дорогу, как и любой транспорт, поэтому дайте ему достаточно места и безопасный интервал для обгона, а не прижимайте его."},"434":{"q":"Вы приближаетесь к многополосному кольцевому перекрестку на груженом автопоезде. Транспорт уже движется внутри кольца, слева открывается просвет, но к нему все еще приближается другой автомобиль. Какое действие является правильным способом въезда?","options":["Резко ускориться и встроиться перед приближающимся автомобилем, поскольку у более крупного транспортного средства преимущество проезда","Въехать в кольцо и полностью остановиться уже внутри, затем ждать там, пока вокруг вас не освободится весь окружающий транспорт","Уступить дорогу транспорту, уже движущемуся по кольцу, и въезжать только тогда, когда есть просвет, достаточный для всей длины вашего транспортного средства","Въехать немедленно и при необходимости двигаться против потока, чтобы добраться до своего выезда кратчайшим путем"],"explanation":"Транспорт, уже движущийся по круговому перекрёстку, имеет преимущество, поэтому въезжайте только при разрыве, достаточном для всей длины вашего транспортного средства."},"435":{"q":"Уже двадцать минут идёт сильный дождь, и покрытие полностью мокрое. Вы движетесь с обычной для сухой дороги скоростью на шоссе и держите привычный 6-секундный интервал до машины впереди. По сравнению с проездом этого же участка по сухому покрытию, что является НАИБОЛЕЕ важным, что вы должны учесть в том, как вы управляете прямо сейчас?","options":["Для остановки ничего не меняется; тормоза грузовика создают то же усилие, поэтому вашего обычного интервала для сухой дороги по-прежнему достаточно","Дистанция реакции увеличивается, потому что мокрая дорога замедляет ваше восприятие, но сам тормозной путь остаётся прежним, как только тормоза схватывают","Тормозной путь становится намного короче, потому что плёнка воды позволяет шинам катиться свободнее и снижает сопротивление грузовика","Ваш общий тормозной путь увеличивается, потому что сниженное сцепление удлиняет дистанцию торможения, поэтому вы должны снизить скорость и увеличить дистанцию следования"],"explanation":"Мокрое покрытие снижает сцепление и увеличивает тормозной путь, удлиняя общую дистанцию остановки, поэтому снижайте скорость и увеличивайте дистанцию."},"437":{"q":"Вы уже 90 минут в рейсе, когда диспетчер сообщает по рации, что адрес доставки изменился и вам нужен новый маршрут в GPS-навигаторе. Движение слабое, вы едете на шоссейной скорости. Какое действие является САМЫМ безопасным способом задать новый пункт назначения?","options":["Дождаться возможности съехать с дороги и припарковаться в безопасном месте, затем ввести и задать новый маршрут до того, как снова тронуться","Ввести новый адрес на следующем красном сигнале светофора, пока вы стоите, и тронуться, как только маршрут загрузится","Закрепить навигатор пониже, рядом с рулём, и набирать адрес там, чтобы глаза оставались ближе к дороге","Продолжать движение и переводить взгляд с навигатора на дорогу и обратно, набирая новый пункт назначения"],"explanation":"GPS всегда настраивайте до начала движения, а не во время езды, поэтому съезжайте с дороги в безопасное место, задайте новый маршрут и затем продолжайте движение."},"439":{"q":"Ваш тягач с прицепом только что попал в столкновение и остановился, частично перекрыв двухполосную нераздельную сельскую трассу. Другие водители приближаются с обеих сторон. После того как вы включили аварийную сигнализацию, как ЛУЧШЕ всего предупредить приближающийся транспорт?","options":["Оставить только включенную аварийную сигнализацию, так как закон при аварии требует лишь мигающих огней","В течение 10 минут выставить светоотражающие предупреждающие треугольники -- один примерно в 30 м (100 футов) позади, один примерно в 30 м (100 футов) впереди и один примерно в 3 м (10 футов) сзади машины","Встать в полосе движения и махать руками, чтобы водители ясно вас видели и сбавляли скорость","Непрерывно сигналить, пока все приближающиеся машины не остановятся"],"explanation":"В течение 10 минут после остановки на неразделённой дороге выставьте предупреждающие треугольники: примерно в 30 м сзади, 30 м спереди и 3 м позади транспортного средства."},"441":{"q":"Вы ведёте гружёный тягач с полуприцепом со скоростью 60 миль/ч по сельскому двухполосному шоссе и замечаете в зеркалах, что пикап уже несколько миль едет вплотную за вами. Впереди движение редкое и равномерное. Какое действие ЛУЧШЕ всего снизит опасность, создаваемую этим водителем, едущим вплотную?","options":["Несколько раз слегка нажать на тормоз, чтобы подать пикапу сигнал отстать и отучить его ехать так близко","Сохранять скорость, но сместиться к левому краю своей полосы, чтобы пикап видел дорогу достаточно далеко вперёд и мог безопасно обогнать вас","Постепенно увеличить дистанцию до автомобиля впереди, чтобы у вас был запас для плавного снижения скорости вместо резкого торможения","Ускориться, чтобы создать разрыв между собой и пикапом, пока он не окажется на безопасном расстоянии и перестанет быть угрозой"],"explanation":"Когда вас преследуют вплотную, увеличьте дистанцию впереди, чтобы тормозить плавно, а не резко, давая водителю сзади больше времени на реакцию."},"442":{"q":"Вы ведёте гружёный тягач с прицепом со скоростью 55 миль/ч по сухому двухполосному шоссе, когда легковой автомобиль начинает вплотную ехать у вас на хвосте. Водитель нетерпелив и явно хочет, чтобы вы убрались с дороги. Вы хотите снизить опасность, создаваемую этим водителем сзади, не усугубляя ситуацию. Какое из следующих действий будет НАИХУДШИМ ответом с вашей стороны?","options":["Сохранять ровную, постоянную скорость, чтобы водитель сзади мог оценить безопасный промежуток и в конце концов обогнать","Плавно отпустить педаль газа, чтобы увеличить пространство впереди в качестве запаса","Держаться правее и избегать резких манёвров, чтобы у едущего сзади было место объехать вас","Увеличить скорость, чтобы оторваться от едущего сзади и создать большую дистанцию между вами"],"explanation":"Разгоняться, чтобы оторваться от преследователя, неправильно, ведь он продолжит ехать вплотную, а скорость и тормозной путь обоих транспортных средств возрастут."},"443":{"q":"Ясное утро, температура чуть ниже нуля, вы везёте груз по сельской трассе. Дорога впереди кажется просто мокрой, но вы приближаетесь к длинной эстакаде над рекой. Какое утверждение ДОЛЖНО больше всего повлиять на то, как вы проедете эстакаду?","options":["Покрытие эстакады может замёрзнуть и обледенеть раньше окружающей дороги, потому что оно теряет тепло и сверху, и снизу.","Эстакада обледенеет последней, поэтому это самое безопасное место для резкого торможения при необходимости.","Поверхность мостов и эстакад становится скользкой только летом, когда сквозь покрытие проступает гудрон.","Приподнятые пролёты никогда не замерзают, пока дорога перед ними выглядит мокрой, а не белой."],"explanation":"Мосты и эстакады обледеневают раньше дороги, теряя тепло сверху и снизу, поэтому они могут быть покрыты льдом, когда дорога ещё лишь мокрая."},"444":{"q":"Прохладным сырым осенним утром вы ведёте гружёный автопоезд по двухполосной сельской дороге. Выезжая из поворота, вы видите, что покрытие впереди застелено плотным слоем мокрых опавших листьев, который тянется через обе полосы. Какое утверждение лучше всего описывает, как вам следует вести себя на этом участке дороги?","options":["Листья улучшают сцепление так же, как мокрый песок, поэтому вы можете безопасно сохранять текущую скорость на этом участке.","Считайте покрытие, засыпанное листьями, скользкой поверхностью: плавно отпустите педаль газа и избегайте резкого торможения или поворотов руля, пока не проедете этот участок.","Поскольку листья органические и мягкие, они смягчают контакт шин и не оказывают реального влияния на сцепление или тормозной путь.","Сцепление на листьях теряют только передние (управляемые) шины, поэтому лёгкое торможение ведущими колёсами позволяет полностью сохранить контроль."],"explanation":"Мокрые листья образуют скользкий слой с низким сцеплением, как лёд, поэтому отпустите газ и избегайте резкого торможения или руления, пока не проедете их."},"445":{"q":"Температура чуть ниже нуля, светит солнце, и вы едете по сельской двухполосной дороге. Открытые, освещённые солнцем участки покрытия выглядят сухими, но дорога постоянно проходит под кронами деревьев и вдоль высоких насыпей с северной стороны, которые остаются в тени. Приближаясь к одному из таких затенённых участков, какую НАИБОЛЬШУЮ опасность вам следует ожидать скрытой в тени?","options":["Выступивший гудрон, размягчившийся на солнце и сделавший покрытие скользким","Сыпучий гравий, который движением транспорта сдвинуло в затенённые низины","Участок льда, потому что затенённое покрытие так и не прогрелось выше нуля, хотя освещённые солнцем участки сухие","Свежая дорожная разметочная краска, которая ещё не полностью высохла на холоде"],"explanation":"Затенённое покрытие не получает прямого солнечного света, поэтому влага там остаётся замёрзшей, даже когда освещённые солнцем сухие участки прогрелись выше нуля."},"446":{"q":"Вы ведете свой тягач с полуприцепом по мокрому шоссе под непрекращающимся дождем. Колонна грузовиков обгоняет вас по левой полосе, и каждый из них при обгоне выбрасывает плотную завесу дорожных брызг на ваше лобовое стекло. Размышляя о том, как эти брызги влияют на вас и на вашу способность безопасно вести машину, какое утверждение является единственным наилучшим описанием их ГЛАВНОГО эффекта?","options":["Они охлаждают тормозные барабаны, поэтому на следующем спуске можно сильнее полагаться на тормоза","Они увеличивают глубину протектора ваших шин, помогая оставаться выше минимума 4/32 дюйма для передних шин","Они смывают грязь с дороги, улучшая сцепление ваших шин с покрытием","Они на мгновение ослепляют вас, снижая видимость, поэтому следует сбросить скорость и увеличить дистанцию следования"],"explanation":"Брызги от проезжающих грузовиков на мгновение заливают лобовое стекло и резко снижают видимость, поэтому сбавьте скорость и увеличьте дистанцию."},"447":{"q":"Вы управляете автопоездом длиной 53 фута (тягач с полуприцепом) и должны выполнить крутой правый поворот с городской улицы в узкий переулок. Вы замечаете припаркованный автомобиль и бордюр с внутренней (правой) стороны поворота. Из-за смещения колёс при повороте (off-tracking) какое из утверждений ЛУЧШЕ всего описывает то, что вы должны учитывать, проводя автопоезд через этот поворот?","options":["Задние колёса полуприцепа пройдут по траектории внутри траектории передних колёс, поэтому задние шины могут заехать на бордюр или задеть припаркованный автомобиль с внутренней стороны поворота","Задние колёса полуприцепа пройдут по более широкой траектории снаружи от передних колёс, поэтому задняя часть прицепа сместится в сторону встречного движения слева","Передние и задние колёса пройдут точно по одной и той же траектории, поэтому если ваши управляемые шины минуют бордюр, то и колёса прицепа его минуют","Смещение колёс при повороте важно только на высокой скорости, поэтому на этой низкой скорости поворота все колёса идут практически по одной линии"],"explanation":"Из-за смещения траектории задние колёса длинного прицепа идут по пути внутри передних, поэтому заходите достаточно широко, чтобы задние шины не задели бордюр или машины с внутренней стороны."},"448":{"q":"Вы управляете автопоездом длиной 53 фута (тягач с прицепом) и должны выполнить крутой правый поворот с узкой двухполосной улицы на другую узкую улицу. Вы знаете, что задние колёса прицепа идут по более короткой и крутой траектории, чем передние колёса тягача (увод/смещение траектории при повороте), поэтому поворот нужно планировать тщательно. Чтобы безопасно завершить правый поворот и не дать задним колёсам прицепа наехать на бордюр, что вы должны учитывать?","options":["Из-за смещения траектории задняя часть прицепа уходит наружу, поэтому дополнительное пространство нужно только снаружи (слева) от поворота","Из-за смещения траектории задние колёса прицепа срезают путь внутрь относительно траектории тягача, поэтому нужно дополнительное пространство с внутренней стороны поворота","Смещение траектории не влияет на такой крутой поворот, поэтому дополнительное пространство не нужно ни с одной стороны","Поскольку транспортное средство длинное, с внутренней стороны нужно меньше пространства, так как прицеп идёт прямо за тягачом"],"explanation":"Из-за смещения траектории задние колёса прицепа срезают внутрь относительно пути тягача, поэтому оставляйте дополнительное место с внутренней стороны поворота."},"449":{"q":"Вы выезжаете на оживлённую автомагистраль на своём тягаче с полуприцепом, и небольшой легковой автомобиль исчезает из поля зрения прямо позади вашего правого зеркала, где вы его совсем не видите. Прежде чем перестроиться, как правильно описать и оценить эту конкретную зону вокруг вашего грузовика?","options":["Это зона с плохим сцеплением, поэтому перед перестроением мне следует мягко притормозить.","Это буферная подушка безопасности, которую другие водители обязаны держать свободной от моего прицепа.","Это одна из моих слепых зон, которую также называют «No-Zone», где других водителей мне трудно увидеть, поэтому перед перестроением я должен тщательно её проверить.","Это опасная зона, возникающая только из-за высокого центра тяжести, когда прицеп загружен."],"explanation":"Зоны вокруг грузовика, где других водителей трудно увидеть, — это слепые зоны, называемые No-Zone, которые нужно тщательно проверять перед сменой полосы."},"450":{"q":"Вы перестраиваетесь на загруженное шоссе на своём тягаче с прицепом. Легковой автомобиль, который вы только что отчётливо видели в правом боковом зеркале, теперь полностью пропал из этого зеркала, и впереди вы его тоже не видите. Прежде чем продолжить перестроение, что НАИБОЛЕЕ вероятно означает это исчезновение?","options":["Автомобиль ускорился и теперь находится далеко позади вас, поэтому полоса свободна","Автомобиль резко затормозил и съехал на правую обочину, полностью покинув проезжую часть","Ваше зеркало сбито с настройки, и его нужно отрегулировать на следующей остановке","Автомобиль ушёл в слепую зону ('No-Zone') рядом с вашим прицепом, где зеркало уже не может его показать"],"explanation":"Машина, исчезнувшая из зеркала, скорее всего вошла в слепую зону (No-Zone) сбоку от прицепа, поэтому не меняйте полосу, пока снова её не увидите."},"451":{"q":"Вы ведете груженый тягач с прицепом по четырехполосному шоссе и решаете перестроиться из правого ряда в левый, чтобы обогнать медленный автомобиль. Вы проверяете плоские и сферические (выпуклые) зеркала, видите, что они выглядят чистыми, и заранее включаете поворотник. Когда вы начинаете перестраиваться, НАИБОЛЬШУЮ опасность для вас представляет автомобиль, находящийся где?","options":["В слепой зоне вдоль вашего прицепа — в области, которую зеркала не показывают","Через две полосы в крайнем левом ряду, частично виден в сферическом зеркале","Прямо позади прицепа, где видны ваши стоп-сигналы","Впереди вас в вашем же ряду — медленный автомобиль, который вы намерены обогнать"],"explanation":"У больших грузовиков есть слепые зоны (No-Zone) по бокам и сзади, которые не видны в зеркалах, поэтому перед сменой полосы нужно повернуть голову и проверить."},"453":{"q":"Вы собираетесь выехать с терминала в рейс протяжённостью 400 миль, который проходит через горный перевал, и хотите правильно спланировать поездку до отправления. Что из перечисленного НАИБОЛЕЕ важно проверить при планировании рейса?","options":["Загружен ли ваш любимый плейлист, чтобы оставаться бодрым в долгой дороге","Запланированный маршрут и текущие погодные условия на пути следования","Что ваша дистанция следования составит 1 секунду на каждые 10 футов длины транспортного средства","Подают ли на стоянках по маршруту еду, которая вам нравится, на обед"],"explanation":"Грамотное планирование поездки означает заранее знать маршрут и погоду на нём, чтобы выбрать передачи, скорость и время в зависимости от неконтролируемых условий."},"454":{"q":"Температура чуть ниже нуля, начавшийся лёгкий дождь покрывает наледью мосты на вашем маршруте, а установленное ограничение скорости — 55 миль/ч. Движение слабое, и покрытие пока выглядит просто мокрым. Согласно правилам Техасского DPS, в какой из этих ситуаций вы ОБЯЗАНЫ двигаться со скоростью НИЖЕ установленного ограничения?","options":["Когда дорога впереди чистая и сухая, ведь свободная полоса позволяет безопасно использовать все разрешённые 55 миль/ч","Когда вокруг вас мало транспорта, ведь меньше машин — меньше причин снижать скорость","Когда условия плохие — например, мокрое, почти замёрзшее покрытие и потенциально обледеневшие мосты, с которыми вы сейчас столкнулись, — потому что безопасную скорость определяют сцепление и видимость, а не цифра на знаке","Когда вы выбиваетесь из графика, ведь спешка по плохой погоде позволяет наверстать упущенное время"],"explanation":"Безопасную скорость определяют сцепление и видимость, а не указанный лимит, поэтому снижайте скорость на мокрых, почти замёрзших дорогах и обледенелых мостах, где может скрываться чёрный лёд."},"455":{"q":"Вы ведёте гружёный полуприцеп по сельской автомагистрали с разрешённой скоростью 55 миль/ч. Начался холодный моросящий дождь, и покрытие блестит от влаги. Вы чувствуете себя комфортно, движение слабое. Какое утверждение ЛУЧШЕ всего описывает, как ограничение 55 миль/ч применяется к вам сейчас?","options":["Ограничение 55 миль/ч является не только верхним, но и нижним пределом, поэтому заметное снижение скорости в этих условиях само по себе будет нарушением","Поскольку ваш грузовик гружёный и имеет хорошее сцепление, разрешённые 55 миль/ч остаются безопасной целевой скоростью на мокром покрытии","Разрешённые ограничения уже включают встроенный запас безопасности на случай дождя, поэтому 55 миль/ч остаётся приемлемой, пока дорогу полностью не затопит","Знак 55 миль/ч задаёт максимум только для идеальных условий, поэтому на мокрой дороге безопасная скорость ниже разрешённой"],"explanation":"Указанный лимит — это законный максимум только для идеальных условий, поэтому на мокрой дороге, где падает сцепление и растёт тормозной путь, держите скорость ниже указанной."},"456":{"q":"Вы перевозите гружёный прицеп по загруженной автомагистрали в час пик. Движение плотное и идёт равномерно, машины зажимают вас с обеих сторон. Вы хотите успеть к доставке вовремя, но понимаете, что ваш тормозной путь длинный. Какое действие обеспечит ЛУЧШИЙ контроль и наименьший риск аварии в этом плотном потоке?","options":["Держать ровную скорость в соответствии с потоком и сохранять достаточную дистанцию впереди, чтобы иметь место для остановки","Часто перестраиваться, выискивая самый быстрый просвет, чтобы наверстать упущенное время","Ехать вплотную за впереди идущей машиной, чтобы другие не вклинивались в ваше пространство","Тормозить сильно и часто, удерживая скорость заметно ниже потока"],"explanation":"В плотном потоке держите ровную скорость, соответствующую потоку, и сохраняйте достаточную дистанцию впереди для длинного тормозного пути."},"458":{"q":"Вы ведете тягач с полуприцепом по холмистому двухполосному шоссе без разделительной полосы. Вы догоняете медленный сельскохозяйственный трактор и хотите его обогнать, но дорога впереди идет на подъем к вершине холма, и вы не видите, что движется по другую сторону. Что из перечисленного лучше всего описывает ситуацию, когда вам НЕ следует начинать обгон?","options":["Когда впереди длинный, чистый прямой участок и встречная полоса свободна на четверть мили","Когда дорога поднимается на вершину холма или поворот, и вы не видите достаточно далеко вперед, чтобы безопасно завершить обгон","Когда впереди много свободной дороги и хорошая видимость, но транспортное средство впереди движется медленно","Только когда встречный автомобиль уже находится в пределах 500 футов и мигает дальним светом"],"explanation":"Никогда не обгоняйте на подъёме или повороте, ограничивающем обзор, ведь вы не видите, свободна ли встречная полоса на весь манёвр."},"459":{"q":"Вы только что подогнали прицеп к погрузочной платформе клиента на тесной, незнакомой площадке. Платформа частично скрыта за прицепом, рядом сложены поддоны, а зеркала не показывают нижние несколько футов прямо позади автопоезда. Прежде чем включить заднюю передачу, что вы должны сделать В ПЕРВУЮ ОЧЕРЕДЬ, чтобы безопасно сдать назад?","options":["Начать медленно сдавать назад, полагаясь на зеркала, так как они дают самый широкий и надёжный обзор зоны позади прицепа","Подать звуковой сигнал три раза, а затем сдавать назад с ровной скоростью, надеясь, что гудки предупредят всех, кто окажется на вашем пути сзади","Выйти из кабины и подойти к задней части, чтобы осмотреть путь, зазоры и любые слепые зоны, прежде чем начать движение","Быстро сдать назад, чтобы проскочить слепую зону, пока пешеход или погрузчик не успели оказаться на вашем пути"],"explanation":"Перед движением задним ходом всегда выходите и осматривайте путь, габариты и слепые зоны, которые не видны в зеркалах (G.O.A.L.)."},"460":{"q":"Вы одни на тесной погрузочной площадке и должны задним ходом завести тягач с прицепом к доку, расположенному со стороны пассажира (справа). Чтобы увести заднюю часть прицепа к этому правому доку, вы начинаете поворачивать рулевое колесо вправо. В самый первый момент после начала движения задним ходом с рулём, повёрнутым вправо, ещё до более крупной коррекции, в какую сторону сначала сместится задняя часть прицепа?","options":["Задняя часть прицепа сразу уходит вправо, в ту же сторону, куда вы повернули руль, поэтому вы едете прямо к доку.","Прицеп идёт прямо назад в линию с тягачом и начинает складываться только после того, как вы добавите газ.","Задняя часть прицепа поднимается вверх и вправо к заезду на док, пока тягач её толкает.","Задняя часть прицепа сначала уходит влево, в сторону, противоположную повороту руля, прежде чем вы начнёте контр-руление, чтобы увести её вправо."],"explanation":"При движении задним ходом задняя часть прицепа сначала идёт в сторону, противоположную повороту руля: руль вправо — прицеп влево, затем подруливание."},"461":{"q":"Вы ведёте 53-футовый сухогрузный фургон по загруженной трёхполосной автомагистрали и начинаете смещаться в соседнюю полосу. Взглянув в зеркала, вы не видите два автомобиля, идущие рядом с вами с той же скоростью. Исходя из «слепых зон» (No-Zones) грузовика, в какой опасной зоне эти машины, скорее всего, находятся прямо сейчас?","options":["В слепых зонах, идущих вдоль правого и левого бортов прицепа","Прямо перед кабиной, где капот закрывает обзор","Вплотную позади прицепа, куда не достают ваши зеркала","Высоко наверху, в зоне над крышей прицепа"],"explanation":"Едущие рядом машины могут скрываться в боковых слепых зонах (No-Zone) вдоль правой и левой сторон прицепа, причём правая зона самая большая."},"462":{"q":"Вы ведёте гружёный полуприцеп по оживлённой четырёхполосной автомагистрали со скоростью 60 миль/ч. Сзади в правой полосе позади вас начала скапливаться вереница автомобилей, и вы чувствуете, что пара из них готовится к обгону. Чтобы правильно контролировать пространство ПОЗАДИ вашего автопоезда и следить за этими машинами, что вам следует делать?","options":["Перестать пользоваться зеркалами и сосредоточиться только на дороге далеко впереди, ведь то, что позади, не влияет на ваше вождение","Регулярно посматривать в зеркала (примерно каждые 5–8 секунд), чтобы отслеживать машины, приближающиеся сзади и сбоку от вас","Разогнаться значительно выше 60 миль/ч, чтобы машины позади отстали и пространство освободилось само собой","Часто нажимать на тормоз, чтобы заставить сидящих на хвосте отстать и создать запас пространства позади вас"],"explanation":"Пространством сзади управлять нельзя, поэтому регулярно, примерно каждые 5–8 секунд, проверяйте зеркала, отслеживая машины сзади и сбоку."},"463":{"q":"Вы ведёте гружёный тягач с полуприцепом со скоростью 55 миль/ч по ровному участку межштатной автомагистрали и видите, как в четверти мили впереди по полосам пробегают стоп-сигналы, а плотный поток машин начинает сжиматься в вашу сторону. Дистанция до впереди идущих сокращается. Какое действие ЛУЧШЕ всего управляет вашим пространством и инерцией в этой развивающейся ситуации?","options":["Сохранять скорость и направить машину к крайней полосе, чтобы объехать замедляющийся поток до того, как он полностью остановится","Немедленно применить сильное резкое торможение, чтобы быстро сбросить скорость, ведь на 55 миль/ч для остановки уже требуется около 419 футов","Отпустить педаль газа и дать дистанции до впереди идущего транспорта снова увеличиться, притормаживая мягко лишь по мере необходимости, пока зазор впереди развивается","Пока сохранять скорость и держать как минимум одну секунду дистанции на каждые 10 футов длины транспортного средства, пока обстоятельства не вынудят вас среагировать"],"explanation":"Когда машины впереди замедляются, отпустите газ, чтобы дистанция снова увеличилась, тормозя плавно лишь по мере необходимости."},"464":{"q":"Вы перевозите негабаритный по ширине груз по узкой двухполосной сельской дороге без обочины. Встречные пикапы постоянно прижимаются к осевой линии, край покрытия справа резко обрывается, а почтовые ящики и припаркованные машины стоят вплотную к полосе движения. Чтобы справиться с главной опасностью, которую создаёт ваш широкий автомобиль в этой ситуации, на чём вы должны сосредоточить основное внимание?","options":["На дорожном покрытии далеко впереди, чтобы заметить ямы до того, как до них доедут передние колёса","На пространстве над прицепом, следя за низкими ветвями и проводами над дорогой","На пространстве под прицепом, проверяя, не волочится ли что-нибудь под рамой","На пространстве по бокам, потому что из-за ширины вашего автомобиля остаётся очень мало зазора до встречного транспорта, обрыва обочины и придорожных предметов"],"explanation":"На широком транспорте по узкой дороге без обочины больше всего следите за боковыми зазорами: встречные машины, обрыв и придорожные объекты теснят с обеих сторон."},"465":{"q":"Вы завершаете длинный рейс с доставкой и останавливаетесь у придорожного пункта весового контроля. Инспектор просит вас пройти тест на алкоголь. Около часа назад за ужином вы выпили два пива, чувствуете себя совершенно трезвым и знаете, что для водителя обычного легкового автомобиля в вашем штате предел составляет 0,08. Какова САМАЯ НИЗКАЯ концентрация алкоголя в крови (BAC), при которой вы, управляя своим транспортным средством по CDL, будете дисквалифицированы?","options":["0,04 или более","0,08 или более","0,10 или более","0,02 или более"],"explanation":"Для водителя с CDL за рулём коммерческого транспорта законный предел — содержание алкоголя в крови 0,04 % или выше, вдвое меньше, чем для обычных водителей."},"466":{"q":"Вас остановили для придорожной проверки во время управления коммерческим транспортным средством (CMV), и у инспектора есть обоснованные основания потребовать, чтобы вы прошли тест на концентрацию алкоголя в крови. Вы уверены, что находитесь ниже законного предела 0,04%, и опасаетесь, что тест может быть неточным, поэтому вы заявляете инспектору, что предпочитаете просто отказаться от него. Каковы, согласно правилам CDL, последствия такого отказа?","options":["С вашими правами CDL ничего не произойдёт, если ваша фактическая концентрация алкоголя окажется ниже 0,04%","Вы лишаетесь права управлять CMV — это рассматривается так же, как если бы вы не прошли тест","Вы получаете лишь небольшой административный штраф, но сохраняете все права на управление","При первом отказе вы получаете письменное предупреждение, а наказание следует только при повторном отказе"],"explanation":"Отказ от законно требуемого теста на алкоголь влечёт дисквалификацию от управления коммерческим транспортом — то же наказание, что и провал теста."},"467":{"q":"Во время ночного рейса вы возвращаетесь к тягачу после ужина, и на придорожном посту вас останавливает дорожный инспектор. Химический анализ показывает концентрацию алкоголя в крови 0,06%, что выше предела 0,04% для водителей CDL, и вас признают виновным в управлении коммерческим транспортным средством в состоянии опьянения. Это первое подобное нарушение в вашей истории. При условии, что опасные грузы не перевозились, каков МИНИМАЛЬНЫЙ срок дисквалификации вашего CDL?","options":["60 дней — такой же срок, как при серии серьёзных нарушений ПДД","90 дней — минимальный срок вывода из эксплуатации за фальсификацию путевого журнала","Один год дисквалификации","Три года — как при первом нарушении во время перевозки опасных грузов"],"explanation":"Первое осуждение за управление коммерческим транспортом с содержанием алкоголя в крови 0,04% и выше влечёт лишение CDL минимум на один год, если не перевозились опасные материалы."},"469":{"q":"Вы остановлены на весовой станции Техасского DPS для придорожной проверки. Инспектор уже подтвердил, что ваше коммерческое водительское удостоверение (CDL) действительно, а ваш бортовой журнал в порядке. Затем он просит предъявить ещё один документ, который согласно федеральным правилам вы обязаны иметь при себе всякий раз, когда управляете транспортным средством, чтобы подтвердить, что вы физически годны к вождению. Какой документ вы должны ему предъявить?","options":["Свидетельство об окончании курсов подготовки водителей CDL, подтверждающее, что вы прошли обязательное начальное обучение водителей","Свидетельство о праве собственности на транспортное средство, подтверждающее, что грузовик законно зарегистрирован и допущен к движению по дороге","Оригинал вашего свидетельства о рождении, удостоверяющий вашу личность и законное право на получение коммерческого удостоверения","Медицинскую справку (медицинское свидетельство медэксперта), подтверждающую, что вы в настоящее время физически годны управлять коммерческим транспортным средством"],"explanation":"Вместе с CDL необходимо иметь при себе медицинскую справку (med card), которая подтверждает вашу текущую физическую пригодность к управлению коммерческим транспортом."},"470":{"q":"Вы отстаете от графика примерно на 30 минут на четырехполосном шоссе с разделительной полосой. Водитель впереди едет медленнее, чем вам хотелось бы, и вы взвешиваете варианты. Согласно правилам Техасского DPS, какое из следующих действий считается КРУПНЫМ нарушением правил дорожного движения, способным поставить под угрозу ваше удостоверение CDL?","options":["Двигаться за более медленным автомобилем на безопасной дистанции и ждать законной возможности для обгона","Кратковременно опуститься ниже установленной минимальной скорости, чтобы проверить зеркала перед сменой полосы","Агрессивно лавировать в потоке и ехать вплотную, вынуждая медленного водителя уступить дорогу","Подать сигнал о смене полосы чуть раньше, чем этого ожидает едущий прямо перед вами автомобиль"],"explanation":"Агрессивное перестроение в потоке и движение вплотную, чтобы вынудить другого водителя уступить, считается безрассудным вождением — серьезным нарушением, ведущим к лишению CDL."},"471":{"q":"Ваш тягач с прицепом заглох на правой обочине ровного, прямого двухполосного шоссе без разделительной полосы. Вы включаете аварийную сигнализацию и берёте светоотражающие треугольники, чтобы выставить их в течение 10-минутного окна. Подходя к задней части автопоезда, чтобы установить ПЕРВЫЙ (ближайший) треугольник, на каком примерно расстоянии позади машины его следует поставить?","options":["Примерно в 10 футах позади машины, со стороны движения транспорта","Примерно в 100 футах позади машины","Примерно в 200 футах позади машины","Прямо у заднего бампера, вплотную к машине"],"explanation":"Ближайший предупреждающий треугольник ставится примерно в 10 футах позади машины со стороны движения, чтобы обозначить непосредственно заднюю часть автопоезда."},"472":{"q":"Подшипник колеса вышел из строя, и вы накатом съезжаете на обочину ровного прямого двухполосного шоссе без разделения встречных потоков. Включив аварийную сигнализацию, вы берёте аварийные знаки (треугольники) и начинаете расставлять их в сторону приближающегося транспорта. Первый треугольник вы правильно ставите в 10 футах позади машины. На каком примерно расстоянии позади автомобиля на такой дороге должен стоять ВТОРОЙ треугольник, который вы ставите сзади?","options":["Примерно в 200 футах позади, а третий — ещё на 200 футов дальше","Примерно в 100 футах позади автомобиля","Примерно в 50 футах позади автомобиля","Примерно в 100 футах впереди автомобиля, на встречной полосе"],"explanation":"На двухполосной или неразделённой дороге второй треугольник ставится примерно в 100 футах позади машины, поскольку транспорт может приближаться с обеих сторон."},"473":{"q":"Ваш тягач с прицепом сломался в правой полосе прямого, ровного шоссе С РАЗДЕЛИТЕЛЬНОЙ ПОЛОСОЙ (одностороннее полотно с разделителем между встречными потоками) при хорошей видимости. Вы включаете аварийную сигнализацию и берёте комплект аварийных треугольников. Когда вы идёте назад, чтобы выставить треугольник, который должен стоять ДАЛЬШЕ всего от задней части машины, на каком примерно расстоянии его нужно поставить?","options":["Примерно в 100 футах позади, ведь именно там ставят средний треугольник","Примерно в полумиле позади, чтобы дать быстрому транспорту максимум предупреждения","Примерно в 200 футах позади машины","Примерно в 10 футах позади, сразу за задним бампером"],"explanation":"На дороге с односторонним движением или разделённой магистрали все три треугольника ставятся позади машины, а самый дальний — примерно в 200 футах в сторону приближающегося транспорта."},"474":{"q":"Вы остановились на правой обочине дороги с односторонним движением (разделённого шоссе) сразу за вершиной подъёма, где машины, идущие сзади, не видят ваш тягач до последнего момента. Вы включаете аварийную сигнализацию и начинаете выставлять три светоотражающих треугольника. Когда придёт время поставить самый дальний треугольник, который защищает вас сзади от приближающегося транспорта, что нужно сделать, чтобы учесть, что холм закрывает обзор?","options":["Держите все три треугольника в пределах 10 футов от грузовика, чтобы они стояли вместе и были видны как группа","Поставьте дальний треугольник ровно в 200 футах, как на ровном открытом участке, ведь это расстояние и есть законный стандарт","Совсем не ставьте дальний треугольник и положитесь на аварийную сигнализацию, которая на холме ярче треугольника","Отодвиньте дальний треугольник за обычное место в 200 футов (до 500 футов), чтобы водители, переваливая через вершину, успели вовремя среагировать"],"explanation":"Возле холма или поворота, перекрывающего обзор, переместите дальний треугольник за обычное место (до 500 футов), чтобы приближающиеся водители получили достаточное предупреждение."},"475":{"q":"Во время предрейсового осмотра на стоянке для отдыха вы чувствуете запах дыма и обнаруживаете небольшой огонь, который начался в куче выброшенных картонных коробок, упаковочной бумаги и стопки упаковочных одеял для переезда возле задних дверей вашего прицепа. Вы берёте огнетушитель и проверяете его класс перед тем, как действовать. Какой класс огнетушителя специально предназначен для типа горящих здесь материалов?","options":["Класс A, предназначенный для обычных горючих материалов, таких как дерево, бумага и ткань","Класс B, предназначенный для горящих жидкостей, таких как топливо, масло и смазка","Класс C, предназначенный для пожаров в проводке под напряжением и электрооборудовании под напряжением","Класс D, предназначенный для горючих металлов, таких как магний и титан"],"explanation":"Возгорания обычных горючих материалов, таких как дерево, бумага и ткань, тушатся огнетушителем класса A."},"476":{"q":"Во время предрейсового осмотра вы проверяете огнетушитель, закреплённый в кабине. Вы перевозите бочки с дизельным топливом и хотите убедиться, что огнетушитель действительно справится с наиболее вероятным для этого груза пожаром. Небольшая утечка топлива воспламеняется рядом с бочками. Какой класс огнетушителя предназначен для тушения такого пожара горящей жидкости?","options":["Огнетушитель класса A, поскольку он самый распространённый и подходит для деревянных поддонов и бумажных накладных, которые тоже находятся в прицепе","Огнетушитель класса B, поскольку он предназначен для горящих жидкостей, таких как топливо, масло и смазка","Огнетушитель класса C, поскольку пожар начался рядом с электрической и аккумуляторной системой грузовика","Огнетушитель класса D, поскольку он предназначен для пожаров с участием горючей ткани, ветоши и обтирочных тряпок"],"explanation":"Возгорания горючих жидкостей, таких как топливо, масло и смазка, тушатся огнетушителем класса B."},"477":{"q":"Во время предрейсового осмотра вы чувствуете запах перегрева у приборной панели и обнаруживаете дым, идущий из-за находящегося под напряжением распределительного щитка электросистемы вашего тягача. Вы тянетесь за огнетушителем, закреплённым в кабине. Какой класс огнетушителя необходимо использовать, чтобы безопасно потушить этот пожар?","options":["Огнетушитель класса A, поскольку он рассчитан на деревянную и бумажную отделку вокруг щитка","Огнетушитель класса B, поскольку он рассчитан на горючие жидкости, из-за которых возникает большинство пожаров в грузовиках","Огнетушитель класса C, поскольку он рассчитан на пожары в электрооборудовании под напряжением","Подойдёт любой класс, если сначала отключить аккумулятор выключателем массы"],"explanation":"Возгорания в электрооборудовании под напряжением требуют огнетушителя класса C, поскольку его непроводящее вещество не передаёт ток обратно на оператора."},"478":{"q":"Чуть ниже нуля, и вы трогаетесь с места на обледенелой подъездной рампе, покрытой коркой льда. Вы чувствуете, как грузовик вздрагивает, а тахометр подскакивает: ведущие колёса начинают буксовать, но машина не двигается вперёд. Чтобы тронуться и восстановить сцепление, какое действие НАИЛУЧШЕЕ?","options":["Сильнее нажать на педаль газа, чтобы буксующие колёса пробили лёд","Быстро прокачать педаль тормоза, чтобы ведущие колёса вгрызлись в покрытие","Резко крутить руль из стороны в сторону, чтобы кромки шин нашли сцепление","Сбросить газ, чтобы ведущие колёса замедлились и восстановили сцепление"],"explanation":"При заносе ведущих колёс отпустите педаль газа, чтобы снизить мощность, тогда буксующие колёса замедлятся до скорости машины и восстановят сцепление."},"479":{"q":"Вы спускаетесь по длинному склону и замечаете дым, а затем пламя, исходящее от одной из спаренных шин вашего прицепа. Вы безопасно останавливаетесь на обочине, выставляете аварийные треугольники и берёте необходимые средства. Когда шина активно горит, какой из следующих способов ЛУЧШЕ всего охладит и потушит огонь?","options":["Обильно залить её большим количеством воды, так как вода охлаждает горящую шину","Засыпать пламя сухим песком, чтобы перекрыть доступ кислорода","Дать потоку воздуха от медленного движения по обочине охладить шину","Покрыть поверхность шины моторным маслом, чтобы перекрыть доступ кислорода"],"explanation":"Заливайте горящую шину большим количеством воды, так как вода охлаждает резину и каркас, где накапливается тепло, и предотвращает повторное возгорание."},"480":{"q":"Холодное утро, и вы оставили грузовик работать на холостом ходу в закрытом погрузочном доке, чтобы прогреть двигатель перед предрейсовым осмотром. Через несколько минут у вас начинается головокружение и головная боль, но вы не видите и не чувствуете в воздухе ничего необычного. Исходя из свойств угарного газа, какова НАИБОЛЕЕ вероятная причина того, что вы почти не получили предупреждения до появления этих симптомов?","options":["Газ сначала издал бы резкий сладковатый запах, значит выхлопная система герметична и не является причиной","Угарный газ бесцветен и не имеет запаха, поэтому ваши органы чувств не могут обнаружить его до того, как он на вас подействует","Газ становится ярко-красным по мере накопления, но тусклое освещение дока скрыло его от вас","Угарный газ тяжелее воздуха и держится у пола, поэтому, стоя, вы получили бы предупреждение вовремя"],"explanation":"Угарный газ бесцветен и не имеет запаха, поэтому ваши органы чувств не могут обнаружить его, прежде чем он подействует на вас в замкнутых помещениях."},"481":{"q":"Вы едете на гружёном автопоезде по сельской автомагистрали Техаса и впереди видите весовую станцию с горящей табличкой \"ОТКРЫТО\", мимо которой без остановки проезжают несколько легковых машин. Вы устали и находитесь всего в паре миль от места разгрузки. Какое действие юридически правильно?","options":["Проехать мимо, как легковые машины, ведь станция сегодня явно проверяет только легковой транспорт","Считать остановку необязательной и заезжать только если инспектор подаст вам знак или если вес покажется большим","Заехать на открытую весовую станцию, потому что грузовики по закону обязаны останавливаться на любой открытой весовой станции, мимо которой проезжают","Пропустить её, поскольку до конечной разгрузки осталась пара миль, а груз уже закреплён"],"explanation":"По закону грузовики обязаны останавливаться на любой работающей весовой станции, мимо которой они проезжают, независимо от усталости, груза или действий легковых машин."},"482":{"q":"Во время предрейсового осмотра на придорожных весах инспектор Техасского DPS обнаруживает дефект тормозов на вашем тягаче, оформляет акт и налагает на транспортное средство предписание о выводе из эксплуатации (out-of-service, OOS). Ремонтная мастерская находится в 8 милях, а окно для доставки закрывается через час. Какое действие является юридически правильным?","options":["Поскольку груз срочный, вам разрешается проехать эти 8 миль напрямую до мастерской на пониженной скорости","Вы можете продолжить маршрут, если будете двигаться не быстрее 55 миль/ч и применять только лёгкое, плавное торможение","Вы можете ехать после того, как дозаправитесь и манометр пневмотормозов покажет полное давление","Вам вообще запрещается управлять транспортным средством, пока дефект не будет устранён и предписание не будет снято"],"explanation":"Предписание о выводе из эксплуатации по закону запрещает движение по дорогам общего пользования, пока неисправность не устранена и предписание не снято."},"483":{"q":"Инспектор на весовой станции просит показать ваши записи режима труда и отдыха из электронного бортового устройства (ELD). Ваш диспетчер утверждает, что это устройство нужно в основном для налоговой и бухгалтерии автопарка. Какое утверждение лучше всего описывает, что на самом деле должны фиксировать ваши записи режима труда и отдыха для этой проверки?","options":["Количество часов, которые вы провели за рулём и на службе, чтобы инспектор мог убедиться, что вы не превысили законные лимиты часов работы (hours of service)","Покупки топлива и пробег по штатам, чтобы инспектор мог проверить точность вашей налоговой отчётности IFTA","Историю технического обслуживания и ремонта транспортного средства, чтобы инспектор мог подтвердить проведение обязательных осмотров","Вес груза и проверки крепления, чтобы инспектор мог подтвердить, что вы перепроверяли груз каждые 150 миль"],"explanation":"Журнал режима труда и отдыха фиксирует часы вождения и работы, чтобы инспектор мог убедиться, что вы не превысили законные лимиты рабочего времени."},"484":{"q":"Вы выезжаете на шоссе на груженом тягаче с прицепом и хотите быстро разогнаться. Стрелка тахометра стремительно поднимается и уже касается верхней границы красной зоны, но вам нужно больше мощности, чтобы не отставать от потока. Чтобы защитить дизельный двигатель, чего из перечисленного делать НЕ следует?","options":["Дать двигателю прогреться на холостом ходу, прежде чем требовать от него большой мощности","Раскручивать двигатель выше красной линии на тахометре, чтобы выжать больше ускорения","Переключиться на повышенную передачу, чтобы обороты упали ниже красной зоны, прежде чем добавлять газ","Использовать нормальный рабочий диапазон оборотов двигателя, чтобы постепенно набирать скорость"],"explanation":"Никогда не раскручивайте двигатель выше красной зоны тахометра, так как она обозначает максимально безопасные обороты, а перекрут вызывает серьёзные повреждения двигателя."},"485":{"q":"Вы припарковали гружёный тягач с полуприцепом на небольшом уклоне вниз у погрузочной платформы клиента, поставили стояночный тормоз и вышли из кабины, чтобы начать разгрузку. Площадка неровная, и вас не будет в кабине довольно долго. В этих условиях какое действие является единственно правильной практикой перед тем, как оставить грузовик без присмотра?","options":["Ничего дополнительно не требуется, потому что пружинный стояночный тормоз бесконечно удержит гружёный полуприцеп на любом уклоне","Оставить коробку передач на низшей передаче вместо установки противооткатных упоров, поскольку включённая передача полностью заменяет упоры на уклоне","Подложить под колёса противооткатные упоры, потому что есть вероятность, что грузовик может укатиться на неровной наклонной поверхности","Не подкладывать упоры, так как уклон лишь незначительный, а упоры нужны только на крутых горных спусках"],"explanation":"Подкладывайте упоры под колёса всякий раз, когда есть вероятность отката грузовика, например на наклонной, неровной поверхности, где он стоит гружёным без присмотра."},"486":{"q":"Вы завершили доставку и должны припарковать ваш тягач с прицепом носом ВНИЗ ПО СКЛОНУ на сельской обочине. На этом участке дороги бордюра НЕТ. Готовясь покинуть машину, как нужно повернуть передние (управляемые) колёса, чтобы при возможном скатывании автомобиль ушёл ПРОЧЬ от проезжающего транспорта, а не в полосу движения?","options":["Оставить передние колёса прямо, ведь на спуске всё удержание обеспечивают стояночный тормоз и противооткатные упоры","Вывернуть передние колёса резко ВЛЕВО, так же как при парковке в гору у бордюра","Поставить колёса прямо и сделать это лишь после проверки, что глубина протектора на управляемой оси не менее 4/32 дюйма","Повернуть передние колёса к краю дороги, чтобы скатывающаяся машина съехала с покрытия в сторону от транспорта"],"explanation":"При парковке под уклон без бордюра поверните передние колёса к краю дороги, чтобы покатившаяся машина съехала с проезжей части в сторону от движения."},"487":{"q":"Во время предрейсового осмотра температура чуть ниже нуля, и вы замечаете, что ступеньки и поручни вашего тягача покрыты тонкой коркой льда и дорожной грязью. Федеральные правила и правила штата Техас требуют осматривать эти элементы. Согласно руководству, какова ГЛАВНАЯ причина, по которой вы обязаны проверить состояние ступенек и поручней перед поездкой?","options":["Чтобы вы могли безопасно входить в кабину и выходить из неё, особенно сохраняя три точки опоры, когда поверхности скользкие","Чтобы вы могли убедиться, что конструкция кабины выдержит расчётный вес груза, указанный на табличке GVWR","Чтобы вы могли проверить, что рама и крепёжные кронштейны не треснуты, иначе автомобиль выводится из эксплуатации","Чтобы вы могли держать обувь чистой и не заносить грязь на пол кабины и на педали"],"explanation":"Надёжные, целые ступени и поручни позволяют безопасно входить в кабину и выходить из неё, сохраняя три точки опоры на скользких поверхностях."},"488":{"q":"Начинается ваша смена, и вы завершаете предрейсовый осмотр. В любой точке сегодняшнего маршрута инспектор DOT может остановить вас на придорожной проверке и попросить предъявить регистрацию транспортного средства и подтверждение страховки. Чтобы соблюдать требования и быть готовым к такой проверке, где эти документы должны находиться в данный момент?","options":["Подшиты в шкафу у вас дома или в офисе автопарка, чтобы их нельзя было потерять или украсть в дороге","Внутри транспортного средства вместе с вами, чтобы вы могли предъявить их любому инспектору во время придорожной проверки","Отправлены по почте в Техасский DPS, чтобы штат хранил официальную копию в своих записях","Загружены на онлайн-портал штата, поскольку цифровая запись заменяет необходимость возить бумажные копии"],"explanation":"Держите регистрацию и страховку внутри транспортного средства, чтобы предъявить их инспектору при любой придорожной проверке или остановке."},"489":{"q":"Вы ночью приближаетесь к загородному перекрестку на гружёном автопоезде и видите, что светофор над вашей полосой мигает красным, тогда как для пересекающего потока мигает жёлтый. Учитывая, как юридически различаются эти сигналы, как вам правильно поступить?","options":["Снизить скорость и осторожно проехать без остановки, ведь мигающий сигнал лишь предупреждает быть внимательным","Сохранять скорость, но быть готовым уступить, поскольку пересекающий поток с мигающим жёлтым обязан вас пропустить","Полностью остановиться, как у знака «стоп», и продолжить движение только когда перекресток свободен","Считать это застрявшим сигналом, кратко остановиться и проехать, пока не загорелся постоянный красный"],"explanation":"Мигающий красный сигнал равнозначен знаку «Стоп»: полностью остановитесь, уступите дорогу и продолжайте движение только когда перекрёсток свободен."},"490":{"q":"Вы приближаетесь к оживлённому перекрёстку ночью, когда подвесной светофор над вашей полосой переключается на постоянно мигающий жёлтый, а для поперечной улицы горит мигающий красный. Несколько машин ожидают на поперечной улице, чтобы выехать. Как правильно проехать этот перекрёсток?","options":["Считать мигающий жёлтый точно как постоянный красный: полностью остановиться, затем проехать, когда перекрёсток освободится","Сохранять свою скорость на шоссе, потому что мигающий жёлтый даёт вам абсолютное преимущество, а поперечный поток обязан стоять","Остановиться и пропустить сначала водителей с поперечной улицы, потому что их мигающий красный работает как перекрёсток с равнозначными знаками «стоп», уступающий им","Снизить скорость и проехать перекрёсток с осторожностью, сохраняя внимание к поперечному потоку, который стоит на мигающем красном"],"explanation":"Мигающий жёлтый сигнал предупреждает об осторожности, а не требует остановки: снизьте скорость и осторожно проезжайте перекрёсток."},"491":{"q":"Вы приближаетесь к оживлённому перекрёстку на гружёном автопоезде и замечаете, что обращённый к вам светофор полностью погас, ни один сигнал не горит из-за очевидного отключения электроэнергии. Поперечный поток тоже замедляется. Как вам следует расценивать этот перекрёсток, чтобы проехать законно и безопасно?","options":["Как перекрёсток с обязательной остановкой со всех сторон (four-way stop): полностью остановитесь, затем проезжайте по очереди в порядке прибытия, уступая тем, кто подъехал раньше","Как знак 'уступи дорогу': снизьте скорость и останавливайтесь, только если другое транспортное средство уже на перекрёстке, иначе проезжайте не останавливаясь","Как зелёный свет для главной улицы, поскольку у крупного коммерческого транспорта приоритет над поперечным потоком","Как свободный проезд: сохраняйте скорость и проезжайте перекрёсток, ведь погасший светофор не является регулируемым перекрёстком"],"explanation":"Погасший или неисправный светофор следует считать перекрёстком с обязательной остановкой со всех сторон, проезжая в порядке прибытия."},"492":{"q":"Вы везёте гружёный прицеп по двухполосному шоссе позади медленного сельскохозяйственного трактора. Центр дороги размечен двойной сплошной жёлтой линией. Вы теряете время и хотели бы обогнать трактор. Исходя из этой дорожной разметки, какое из следующих действий является правильным?","options":["Вы можете пересечь линию для обгона, потому что полоса с вашей стороны является более быстрой","Вы не должны совершать обгон, потому что двойная сплошная жёлтая центральная линия запрещает обгон для обоих направлений движения","Вы можете обгонять, если встречного транспорта не видно в пределах 500 футов","Эта разметка ограничивает только стоянку, поэтому обгон разрешён, когда дорога свободна"],"explanation":"Двойная сплошная жёлтая осевая линия запрещает обгон в обоих направлениях, поэтому пересекать её для обгона нельзя."},"493":{"q":"Вы едете по многополосному шоссе в Техасе в умеренном потоке, когда разметка меняется: прерывистая белая линия между вашей полосой и полосой справа превращается в одну СПЛОШНУЮ белую линию, тянущуюся на большом протяжении. Поток в вашей полосе движется немного медленнее, чем в соседней. Что означает эта сплошная белая линия и как вам следует поступить?","options":["Она обозначает край проезжей части, поэтому вам следует прижаться к обочине, чтобы более быстрый транспорт обогнал вас слева","Она ничем не отличается от прерывистой линии, поэтому вы можете перестроиться вправо при первом же разрыве, чтобы не отставать от более быстрой полосы","Она не рекомендует пересечение, поэтому вам следует оставаться в своей полосе и перестраиваться только если это действительно необходимо и безопасно","Она означает, что обгон запрещён для всех, поэтому вы обязаны сохранять своё точное положение и не имеете права перестраиваться ни при каких обстоятельствах"],"explanation":"Одинарная сплошная белая линия разделяет полосы одного направления и не рекомендует перестроение, поэтому пересекайте её лишь при необходимости и безопасности."},"494":{"q":"Вы ведете седельный тягач с прицепом по двухполосной дороге без разделительной полосы в светлое время суток. Школьный автобус впереди вас включает попеременно мигающие КРАСНЫЕ огни и выдвигает знак 'СТОП'. Вы следуете на безопасной дистанции, и сзади мало транспорта. Что вы обязаны сделать?","options":["Снизить скорость примерно до 15 миль/ч, держать ногу над тормозом и аккуратно объехать автобус только слева, так как дорога без разделительной полосы","Продолжать движение на минимальной скорости, наблюдая за детьми, поскольку полная остановка требуется только при желтых (янтарных) предупреждающих огнях автобуса","Съехать на обочину, выставить светоотражающие треугольники и ждать, пока водитель автобуса не махнет вам рукой","Полностью остановиться и оставаться на месте, пока красные огни не перестанут мигать и знак 'СТОП' не будет убран"],"explanation":"Мигающие красные огни с выдвинутым знаком «Стоп» означают, что на дороге без разделителя транспорт в обоих направлениях должен стоять, пока огни не погаснут и знак не уберётся."},"495":{"q":"Вы приближаетесь к участку дорожного ремонта со стальными плитами и к мосту с металлическим решётчатым настилом на своём маршруте. Условия сегодня менялись несколько раз. В какой из перечисленных ситуаций следует ожидать, что эти металлические поверхности дадут НАИМЕНЬШЕЕ сцепление и будут вести себя почти как лёд?","options":["Только что начался лёгкий дождь, и стальные плиты и решётка моста стали мокрыми","Покрытие и металлические поверхности полностью сухие под ярким полуденным солнцем","Стальные плиты уложили только вчера, и они всё ещё выглядят совершенно новыми","Ремонтная бригада только что закончила сметать с плит сыпучий гравий и пыль"],"explanation":"Стальные плиты и металлическое покрытие мостов имеют слабое сцепление и становятся скользкими как лёд во влажном состоянии."},"496":{"q":"Вы съезжаете с разделённого шоссе и в полдень поворачиваете на оживлённую городскую торговую улицу. Движение плотное, у обоих тротуаров припаркованы автомобили, фургоны доставки стоят во втором ряду, вы проезжаете автобусную остановку и несколько магазинов. По сравнению с открытым шоссе, которое вы только что покинули, какой опасности теперь следует уделять НАИБОЛЬШЕ внимания?","options":["Длинным пустым прямым участкам, где можно было бы безопасно увеличить дистанцию следования","Пешеходам, которые могут внезапно выйти из-за припаркованных машин, автобусов или из магазинов","Открытым полям у дороги, дающим дополнительное пространство для выхода из заноса","Рыхлому гравию и мусору, характерным для сельских обочин вдали от этого места"],"explanation":"В городе внимательно следите за пешеходами, которые могут внезапно выйти из-за припаркованных машин, автобусов или из магазинов."},"497":{"q":"Сейчас позднее утро, и вы ведёте гружёный составной автопоезд по узкому двухполосному просёлочному шоссе через сельскохозяйственную местность. Разрешённая скорость 55 миль/ч, но, поднявшись на небольшой пригорок, вы получаете обзор примерно на четверть мили вперёд. Какую из следующих опасностей вы С НАИБОЛЬШЕЙ вероятностью встретите движущейся намного медленнее разрешённой скорости, из-за чего придётся увеличить дистанцию и, возможно, перестроиться для обгона?","options":["Городской рейсовый автобус, останавливающийся у обозначенных пассажирских павильонов","Лёгкие легковые автомобили, выезжающие с въездной рампы автомагистрали","Медленно движущаяся сельхозтехника, например трактор или комбайн","Пригородный поезд метро, идущий параллельно дороге"],"explanation":"На сельских двухполосных дорогах остерегайтесь медленной сельхозтехники, например тракторов и комбайнов, едущих намного ниже разрешённой скорости."},"498":{"q":"Вы остановились первым на перекрёстке в гружёном автопоезде, ожидая левого поворота через две полосы встречного движения. Сплошная красная стрелка, которая вас удерживала, сменяется ровно МИГАЮЩЕЙ жёлтой стрелкой левого поворота. Встречные автомобили по-прежнему приближаются к перекрёстку на скорости. Какое действие является юридически правильным и самым безопасным для водителя транспортного средства вашего размера и длины?","options":["Немедленно начать поворот, потому что мигающая жёлтая стрелка работает точно так же, как зелёная стрелка, и даёт вам защищённый поворот с преимуществом проезда","Оставаться полностью неподвижным и воспринимать мигающую жёлтую стрелку как сплошную красную стрелку, ожидая сплошной зелёной стрелки, прежде чем тронуться","Въехать в поворот, но запланировать остановку посередине перекрёстка и стоять там, пока не освободится разрыв во встречном потоке","Вы можете начать поворот, но обязаны уступить дорогу встречному транспорту и завершать поворот только тогда, когда есть разрыв, достаточный для безопасного освобождения всей длины вашего транспортного средства"],"explanation":"Мигающая жёлтая стрелка разрешает поворот, но не даёт преимущества, поэтому уступите встречному транспорту и поворачивайте лишь при достаточном для безопасного проезда промежутке."},"499":{"q":"Из-за разрушения соединения вы вынуждены остановиться на обочине, и вокруг задней части прицепа на покрытии начинает скапливаться дизельное топливо. Вам всё ещё нужно обозначить стоящий тягач для приближающегося транспорта. Учитывая разлитое топливо на земле, какое предупреждающее устройство безопаснее всего выставить?","options":["Светоотражающий треугольник, потому что он предупреждает транспорт без какого-либо пламени или тепла, способного воспламенить разлитое топливо","Зажжённый файер, потому что файеры — самое заметное стандартное предупреждающее устройство и являются обязательным оснащением вашего грузовика","Горящий сигнальный файер, установленный с наветренной стороны от разлива, чтобы пламя оставалось в стороне от паров дизеля","Маленькая зажжённая свеча, поставленная на покрытие, поскольку её пламя слишком низкое, чтобы достать до топлива"],"explanation":"Светоотражающий треугольник не дает пламени, искр или тепла, поэтому он безопасно предупреждает движение, не создавая риска воспламенения разлитого топлива."},"500":{"q":"Во время предрейсового осмотра вы видите неравномерный износ передних (рулевых) шин. В самом мелком месте протектор около 3/32 дюйма. Какое решение правильное?","options":["Не ехать — у шин рулевой оси протектор должен быть не менее 4/32 дюйма","Ехать — 3/32 дюйма выше минимума 2/32 дюйма для шин","Ехать — неравномерный износ важен только для ведущих и прицепных шин","Не ехать — любая шина ниже 6/32 дюйма запрещена на грузовике"],"explanation":"Шины управляемой оси должны иметь протектор не менее 4/32 дюйма — это более строгое требование, чем 2/32 дюйма для всех остальных шин."},"501":{"q":"Вы сделали полный предрейсовый осмотр, закрепили груз и проехали 45 миль по трассе — всё в порядке. Что требуют правила осмотра груза?","options":["Пока ничего — первая повторная проверка груза после 150 миль или 3 часов","Ничего — после закрепления и осмотра груз не проверяют до заправки","Остановиться в ближайшие мили — первая проверка груза нужна в пределах первых 50 миль","Остановиться сейчас — груз нужно проверять каждые 25 миль"],"explanation":"Первая повторная проверка груза и креплений требуется в течение первых 50 миль, так как крепления ослабевают и груз смещается сильнее всего в начале пути."},"502":{"q":"Проверяя рулевое, вы видите, что руль поворачивается больше чем на 10 градусов (около двух дюймов свободного хода на ободе 20-дюймового руля), прежде чем колёса начинают поворачивать. Что это значит?","options":["Нормальный свободный ход, он есть у любого грузовика — ничего делать не нужно","Чрезмерный люфт руля — ехать нельзя, пока не отремонтируют","Это гидроусилитель прогревается; ход уменьшится в движении","Мелочь — отметьте в послерейсовом отчёте и продолжайте ехать"],"explanation":"Свободный ход рулевого колеса более примерно 10 градусов делает управление автомобилем затруднённым и небезопасным до устранения неисправности."},"503":{"q":"В конце смены вы обнаружили проблему с регулировкой тормозов. Что верно в отношении отчёта об осмотре транспортного средства водителем (DVIR)?","options":["DVIR нужен только перед рейсом, но никогда после","Послерейсовый отчёт не обязателен, если утром был предрейсовый осмотр","Дефект можно сообщить только устно; письменная запись не нужна","Дефект нужно записать в письменный послерейсовый отчёт, чтобы устранить до следующего использования"],"explanation":"Неисправности, обнаруженные в поездке, должны быть записаны в письменном послерейсовом отчёте об осмотре, чтобы их устранили до повторного использования автомобиля."},"504":{"q":"Температура чуть ниже нуля. Дорога выглядит мокрой и блестящей, но вы замечаете, что брызги из-под колёс машин впереди исчезли. Как это вернее истолковать и что делать?","options":["Скорее всего образуется чёрный лёд — снизьте скорость, избегайте резкого руля и торможения","Дорога просто мокрая после дождя — держите ту же скорость","Это ваши шины спускают — остановитесь и проверьте давление","Это лишь иней на стекле — включите обдув и продолжайте"],"explanation":"Мокрая блестящая дорога без брызг из-под шин при температуре около нуля указывает на гололёд, поэтому снизьте скорость и избегайте резкого руления и торможения."},"505":{"q":"Ваш автомобиль начинает аквапланировать на залитом водой участке. Делать нужно всё перечисленное, КРОМЕ:","options":["Отпустить педаль газа, чтобы колёса замедлились","Выжать сцепление, чтобы колёса вращались свободно","Сильно нажать на тормоз, чтобы вернуть шины на дорогу","Держать руль прямо, пока не вернётся сцепление с дорогой"],"explanation":"При аквапланировании нельзя резко тормозить, так как это блокирует шины и усиливает занос; вместо этого отпустите газ и держите руль прямо, пока не вернётся сцепление."},"506":{"q":"Вы ведёте 60-футовую сцепку со скоростью 60 миль/ч по сухой дороге в хороших условиях. По техасскому правилу дистанции минимальный промежуток ближе всего к:","options":["Около 6 секунд","Около 7 секунд","Около 4 секунд","Около 10 секунд"],"explanation":"Отсчитывайте по одной секунде на каждые 10 футов длины при скорости до 40 миль/ч плюс ещё одну секунду свыше 40 миль/ч, поэтому 60-футовому автопоезду нужно около 7 секунд дистанции."},"507":{"q":"После нескольких сухих недель начинается сильный дождь. Почему первые минуты дождя особенно опасны и как поступить?","options":["Дождь охлаждает двигатель, поэтому можно ехать чуть быстрее","Единственная угроза — лобовое стекло; включите дворники и держите скорость","Свежий дождь сразу улучшает сцепление; опасны лишь глубокие лужи","Масло и пыль поднимаются скользкой плёнкой, пока их не смоет — снизьте скорость и увеличьте дистанцию"],"explanation":"В начале дождя масло и пыль всплывают, образуя скользкую плёнку, из-за которой дорога становится наиболее скользкой, поэтому снизьте скорость и увеличьте дистанцию."},"508":{"q":"Ночью на неосвещённой трассе с ближним светом вы понимаете, что не успеете остановиться в пределах освещённого фарами участка. Правильное действие:","options":["Снизить скорость, чтобы остановиться в пределах видимости","Включить дальний свет и держать скорость, чтобы не выбиться из графика","Подъехать ближе к другому грузовику и ехать по его свету","Скорость не менять, но внимательнее следить за правой кромкой"],"explanation":"Никогда не превышайте скорость, на которой видны фары — скорость должна позволять остановиться в пределах видимости, что означает снижение скорости на ближнем свете."},"509":{"q":"Вы вот-вот въедете в полосу густого тумана. Что из перечисленного НЕ рекомендуется?","options":["Снизить скорость ещё до того, как въедете в туман","Использовать ближний свет, а не дальний","Включить дворники и обдув, чтобы стекло оставалось чистым","Включить дальний свет, чтобы яркий луч пробивал туман"],"explanation":"В тумане используйте ближний свет, так как дальний отражается от капель воды и создаёт ослепляющий блик, ухудшающий видимость."},"510":{"q":"Температура около нуля, дороги в основном выглядят чистыми. Какую поверхность считать обледеневшей в первую очередь, даже если остальная дорога кажется нормальной?","options":["Прямые открытые участки на полном солнце","Подъёмы, потому что двигатель прогревает покрытие","Тоннели — они держат тепло и дольше остаются скользкими","Мосты и эстакады — они замерзают раньше остальной дороги"],"explanation":"Мосты и эстакады теряют тепло сверху и снизу, поэтому они обледеневают раньше дороги на твёрдом грунте, даже когда остальное покрытие ещё чистое."},"511":{"q":"В очень жаркий день вы останавливаетесь и видите, что шины заметно горячие, а давление выше обычного холодного. Какое действие правильное?","options":["Стравить воздух, пока давление не вернётся к норме холодной шины","Ехать быстрее, чтобы поток воздуха охладил шины","Полить шины водой, чтобы быстро охладить","Не трогать шины; если одна слишком горяча на ощупь — остановиться, пока не остынет"],"explanation":"Жара обычно повышает давление в шинах, поэтому шины не трогают; но слишком горячая на ощупь шина указывает на проблему, и нужно остановиться, пока она не остынет, чтобы избежать разрыва."},"512":{"q":"Вы пересекаете железнодорожный переезд на механической коробке с тяжёлым грузом. Главное правило выбора передачи на переезде:","options":["Выбрать передачу до путей и не переключаться, пока хоть часть машины на переезде","Переключиться вниз примерно на середине, чтобы хватило тяги","Включить нейтраль и катиться, чтобы уменьшить вибрацию","Включить самую высокую передачу, чтобы проскочить пути как можно быстрее"],"explanation":"Выберите передачу, которая проведёт вас через переезд, ещё до путей и никогда не переключайтесь, пока хоть часть машины на переезде, чтобы не заглохнуть на рельсах."},"513":{"q":"Вы подъезжаете к длинному крутому спуску. Когда и как выбрать передачу?","options":["Дождаться, пока тормоза начнут пропадать, и тогда понизить передачу","Включить нейтраль для экономии топлива и держать скорость только тормозами","Оставаться на высокой передаче и слегка притормаживать всю дорогу вниз","Включить пониженную передачу до начала спуска — обычно ниже, чем для подъёма на тот же холм"],"explanation":"Выберите низкую передачу до спуска, чтобы торможение двигателем сдерживало скорость; на современных грузовиках безопасная передача для спуска часто ниже, чем для подъёма."},"514":{"q":"На длинном спуске вы уже на нужной пониженной передаче, безопасная скорость 35 миль/ч. Какой приём торможения верно контролирует скорость?","options":["Постоянно держать лёгкое равномерное давление на тормоз всю дорогу вниз","Часто и постоянно прокачивать тормоз, чтобы он не грелся","Держать тормоз сильно нажатым до самого низа","При ~40 миль/ч твёрдо притормозить до ~30, отпустить и повторять"],"explanation":"Правильное прерывистое торможение — это дать скорости подняться примерно на 5 миль/ч выше безопасной, затем твёрдо затормозить примерно на 5 миль/ч ниже неё, отпустить и повторять, чтобы тормоза остывали."},"515":{"q":"На горном спуске тормоза сильно пропали, и вы набираете скорость. Делать нужно всё перечисленное, КРОМЕ:","options":["Искать и использовать аварийную улавливающую полосу, если она есть","Включить нейтраль, чтобы машина катилась плавнее","Если полосы нет — искать путь съезда: открытое поле или боковую дорогу","Оставаться на самой низкой передаче и тормозить всем, что ещё работает"],"explanation":"Никогда не переключайтесь на нейтраль на спуске, так как это отключает торможение двигателем и позволяет разгоняться; вместо этого держите низкую передачу."},"516":{"q":"Ведущие колёса начали скользить на скользкой дороге, и зад тягача поехал вправо. Чтобы вернуть управление, сначала нужно:","options":["Перестать газовать (выжать сцепление) и рулить туда, куда нужно направить перёд машины","Сильно затормозить, чтобы немедленно прекратить занос","Резко вывернуть влево, против направления заноса","Газовать, чтобы выровнять прицеп"],"explanation":"При заносе ведущих колёс сначала устраните причину — отпустите газ и выжмите сцепление, чтобы колёса вернули сцепление, затем рулите туда, куда должен идти перёд машины."},"517":{"q":"На крутом повороте передние колёса теряют сцепление, и грузовик едет прямо, хотя колёса вывернуты. Обычная причина и верное действие:","options":["Причина: слишком малая скорость — добавить газ, чтобы вернуть управление","Причина: перекачаны задние шины — остановиться и стравить воздух","Причина: слишком высокая скорость для условий — сбросить, и передние колёса снова возьмут при замедлении","Причина: прицеп толкает — сильно нажать ручной кран прицепа"],"explanation":"Занос передних колёс обычно вызван слишком высокой скоростью для условий, и поскольку руль не помогает, нужно сбросить скорость, чтобы передние шины снова обрели сцепление."},"518":{"q":"Машина впереди внезапно останавливается в вашей полосе, и места затормозить не хватает. Чаще всего безопаснее:","options":["Тормозить изо всех сил и надеяться остановиться чуть раньше","Объехать препятствие — обычно повернуть успеваешь на меньшем расстоянии, чем остановиться","Заблокировать тормоза и держать руль жёстко прямо","Сильно тормозить и одновременно поворачивать для максимального эффекта"],"explanation":"На скорости шоссе обычно можно сменить направление за меньшее расстояние, чем нужно для остановки, поэтому объезд препятствия с возвратом рулём часто позволяет избежать аварии, когда торможение не помогает."},"519":{"q":"На трассе вы слышите громкий хлопок, руль резко тянет в сторону, машину бьёт — признаки разрыва передней шины. Немедленно следует:","options":["Сразу твёрдо тормозить, чтобы замедлиться, пока не потеряли контроль","Коротко газануть для устойчивости, затем тормозить","Быстро уйти на обочину с сильным торможением","Крепко держать руль, не трогать тормоз, дать машине замедлиться, затем съехать на обочину"],"explanation":"После разрыва шины крепко держите руль и не трогайте тормоз, давая машине замедлиться самой, прежде чем мягко притормозить и съехать на обочину."},"520":{"q":"Вы везёте одну стальную трубу длиной 9 футов. По правилам крепления груза минимальное число стяжек:","options":["Две — минимум две стяжки нужны независимо от длины груза","Одна — меньше 10 футов, значит, одной хватает по правилу одна на 10 футов","Ни одной — груз короче 10 футов освобождён от правил крепления","Четыре — по одной стяжке на каждый угол груза"],"explanation":"Для любого груза, каким бы коротким он ни был, всегда требуется минимум две крепёжные стяжки, плюс одна стяжка на каждые 10 футов длины."},"521":{"q":"Ваш груз весит 40 000 фунтов. Суммарный рабочий предел нагрузки (WLL) всех стяжек должен быть не меньше:","options":["10 000 фунтов","20 000 фунтов","40 000 фунтов","80 000 фунтов"],"explanation":"Суммарный предельный рабочий нагрузочный лимит крепёжных стяжек должен составлять не менее половины веса закрепляемого груза."},"522":{"q":"Тяжёлый груз можно разместить низко и равномерно по полу прицепа или сложить высоко по центру. Что правильно и почему?","options":["Сложить высоко по центру, чтобы снять нагрузку с краёв осей","Сложить высоко, чтобы груз меньше смещался в поворотах","Разницы нет, пока общий вес в пределах закона","Уложить низко и распределить, чтобы центр тяжести был низким и снизился риск опрокидывания"],"explanation":"Размещение груза низко и равномерно понижает центр тяжести, что является главным фактором устойчивости к опрокидыванию и стабильности."},"523":{"q":"Плохое распределение веса вредит в обеих крайностях. Что верно о весе и управляемости?","options":["Перегруз ведущей оси всегда улучшает сцепление без минусов","Распределение веса влияет только на расход топлива, не на управляемость","Слишком малый вес на рулевой оси снижает сцепление передних шин и ухудшает управление","Большая нагрузка на ось всегда сокращает тормозной путь"],"explanation":"Слишком малый вес на управляемой оси снижает сцепление передних шин и ослабляет управление, поэтому правильный баланс важен не меньше общего веса."}},"tr":{"0":{"q":"Sefer öncesi kontrol sırasında diş derinliğini ölçüyorsunuz ve direksiyon (ön) aksındaki lastiklerden birinin 3/32 inçe aşındığını, çeker ve dorse lastiklerinizin de hepsinin 3/32 inç olduğunu görüyorsunuz. Aracınızın kullanılmasının yasal olup olmadığını hangi ifade doğru şekilde belirtir?","options":["Araç kullanılamaz, çünkü direksiyon aksı lastiklerinin en az 4/32 inç diş derinliği olmalıdır.","Araç kullanılabilir, çünkü tüm lastikler her lastik için geçerli olan 2/32 inç asgari değeri karşılıyor.","Araç kullanılabilir, çünkü ön lastiklerin yalnızca 2/32 inç olması yeterlidir ve diğerleri uygundur.","Araç kullanılamaz, çünkü her aksdaki tüm lastiklerin en az 4/32 inç diş derinliği olmalıdır."],"explanation":"Direksiyon dingili lastiklerinde en az 4/32 inç diş derinliği bulunmalıdır; 3/32 inçlik bir ön lastik bu sınırın altındadır ve aracı yasa dışı kılar."},"1":{"q":"Sefer öncesi kontrolünüzde tüm lastiklerin diş derinliğini ölçüm aletiyle ölçüyorsunuz. Ön direksiyon aksı lastikleri sağlıklı bir şekilde 5/32 inç gösteriyor, ancak arka çeker lastiklerinizden biri belirgin şekilde daha incelmiş durumda. Bu arka (direksiyon olmayan) lastik, muayeneden geçebilmek için yasal olarak EN AZ ne kadar diş derinliğine sahip olabilir?","options":["1/32 inç","2/32 inç","4/32 inç","6/32 inç"],"explanation":"Ön direksiyon aksı dışındaki tüm lastiklerin ana oluktan ölçülen en az 2/32 inç diş derinliğine sahip olması gerekir."},"2":{"q":"Sefer öncesi kontrolünüz sırasında, motoru çalıştırmadan önce direksiyonu tutup iki yana sallıyorsunuz. 20 inç çapındaki direksiyonunuzda, ön tekerlekler tepki vermeye başlamadan önce jantı her yöne birkaç inç çevirebiliyorsunuz. Bu boşluk hangi noktada bir direksiyon sistemi sorunundan şüphelenmenize ve aracı hizmet dışı bırakmanıza neden olmalıdır?","options":["Ön tekerlekler hareket etmeden önce direksiyon yaklaşık 10 dereceden fazla (20 inçlik direksiyonda yaklaşık 2 inç) çevrilebildiğinde","Yalnızca ön tekerlekler hareket etmeden önce direksiyon yaklaşık 20 dereceden fazla çevrilebildiğinde","Direksiyon yaklaşık 5 dereceden fazla çevrilebildiğinde, çünkü fark edilebilen her boşluk güvensizdir","Yalnızca boşluk yaklaşık 45 dereceyi aştığında, çünkü direksiyon ancak o zaman gerçekten kontrol edilmesi zorlaşır"],"explanation":"Ön tekerlekler dönmeden önce direksiyonun yaklaşık 10 dereceden fazla boşluğu (20 inçlik direksiyonda kabaca 2 inç) fazladır ve direksiyon arızasına işaret eder."},"3":{"q":"Çekici-römork aracınız bölünmemiş iki şeritli bir karayolunun banketinde stop etti ve tekrar çalışmıyor. Dörtlü flaşörleri açıyor ve aracın 100 ft arkasına, 100 ft önüne ve 10 ft gerisine reflektörlü üçgenler koymak için acil durum uyarı kitinizi alıyorsunuz. Buradaki gibi gerekli olan HER konuma uyarı cihazı yerleştirebilmek için yasal olarak donanımlı olmak adına, kamyonunuzda bulunması gereken EN AZ kaç reflektörlü üçgen olmalıdır?","options":["İki üçgen, çünkü biri aracın önüne, biri arkasına konulur","Üç üçgen","10 ft geriye konulan bir üçgen, artı dörtlü flaşörleriniz","Altı üçgen, her iki trafik yönünü de kapatabildiğinizden emin olmak için"],"explanation":"Ticari bir araç, acil uyarı cihazı olarak en az üç reflektörlü uyarı üçgeni bulundurmalıdır."},"4":{"q":"Vardiyanızın ortasındasınız ve dizel yakıt hattındaki bir rakor, motor kablolarının yakınında yakıt sızdırıyor. Aniden orada, sızan dizelle beslenen ve elektrik akımı olan kablo demetinin etrafında çıtırdayan küçük bir yangın çıkıyor. Kabininizdeki yangın söndürücüye uzanıyorsunuz. Bu söndürücünün üzerindeki hangi sınıf, onun HEM bu yanan yakıtı HEM de elektrik akımı olan elektrik yangınını söndürmek için tasarlandığını gösterir?","options":["Yanıcı sıvılar ve elektrik yangınları için derecelendirilmiş B:C sınıfı bir söndürücü","A Sınıfı bir söndürücü, çünkü ticari araçlarda taşınan standart sınıf budur","Diezeli soğutup alevi hızla bastırmak için Su tipi bir söndürücü","Alevin tabanına sıktığınız sürece hangi sınıfı kaptığınız önemli değildir"],"explanation":"Yanan yanıcı sıvı B sınıfı, elektrik akımı bulunan ekipman ise C sınıfı yangındır; bu yüzden her ikisi için B:C dereceli bir yangın söndürücü gerekir."},"5":{"q":"Saat sabahın 5:00'i ve size yeni atanan bir çekici-dorse aracının sefer öncesi kontrolünü bitiriyorsunuz. Sevkiyat sorumlunuz çıkmanız için sizi sıkıştırıyor, ancak federal kuralların her seferden önce belirli acil durum ekipmanlarını bulundurmanızı zorunlu kıldığını hatırlıyorsunuz. Kabinin hiçbir yerinde yedek elektrik sigortası takımı BULAMADINIZ. Yedek sigorta TAŞIMADAN yola çıkmanız hangi koşulda yasaldır?","options":["Yalnızca araç sigorta yerine devre kesiciler (otomatik sigorta) ile donatılmışsa","Yalnızca kabinde tam dolu bir yedek akü taşıyorsanız","Yalnızca dorseye LED gabari ve konum lambaları takılıysa","Yalnızca çekicide elektrik sistemi için yedek (ikinci) bir alternatör varsa"],"explanation":"Elektrik sistemi sigorta yerine devre kesicilerle korunduğunda yedek sigorta gerekmez, çünkü kesiciler değiştirilmek yerine sıfırlanır."},"6":{"q":"Sabahın erken saati ve sefer öncesi muayeneye başlamak için aracınıza yaklaşıyorsunuz. Eğitmeniniz yedi adımlı muayene yöntemini sırasıyla uygulamanızı hatırlatıyor. Kabine binmeden, kaputu açmadan veya tek bir düğmeye dokunmadan önce, yedi adımlı yöntemin yapmanızı istediği İLK şey nedir?","options":["Motoru çalıştırıp yağ basıncını ve hava göstergelerini izlerken ısınmasını beklemek","Aracın önüne gidip farların, sinyallerin ve dörtlü flaşörlerin çalıştığını kontrol etmek","Aracın genel bir değerlendirmesini yapmak: önceki muayene raporunu gözden geçirmek ve aracın genel durumu ile çevresine bakmak","Aracın ön altına girip direksiyon aksı lastiklerinin en az 4/32 inç diş derinliğine sahip olduğunu doğrulamak"],"explanation":"Yedi adımlı muayenenin ilk adımı genel bakıştır: son muayene raporunu inceleyip aracın genel durumunu ve çevresini kontrol etmek."},"7":{"q":"Soğuk bir sabah ve sefer öncesi muayenenize başlamak üzeresiniz. Kamyonunuzun motoru KAPALI ve kaputu kaldırılmış durumda. Aşağıdakilerden hangisi, motor çalışmıyorken ŞU ANDA kontrol edebileceğiniz ve etmeniz gereken parça grubudur?","options":["Direksiyon boşluğu ve düşük hava basıncı uyarı zilinin çalışması","Motor yağı seviyesi, soğutma suyu seviyesi ve kayışların durumu","Hava kompresörü regülatörünün devreye girme ve çıkma basınçları","Yük altında alternatör çıkışı ve şarj sistemi göstergesi"],"explanation":"Motor kapalıyken kaputu açıp motor yağ seviyesini, soğutma sıvısı seviyesini ve tahrik kayışlarının durumunu kontrol edersiniz."},"8":{"q":"Hava donma noktasının hemen altında ve yüklü çekici-dorse setinizi otoyol hızına çıkarırken otoyol giriş rampasında ince bir buz tabakası oluşmuş durumda. Çekicinin çekiş tekerleklerinin patinaj yapmaya başladığını ve kabinin arkasının yana doğru kaydığını hissediyorsunuz. Bu kaygan zeminde güvenle hızlanmak için gaz pedalını kullanmanın EN İYİ yolu nedir?","options":["Gücü yumuşak ve kademeli olarak vermek; çekiş tekerlekleri patinaj yapmaya başladığı anda gazı bırakmak","Patinaj yapan lastikler buz tabakasını delip tutunabilsin diye gaza sert şekilde basmak","Çekiş tekerleklerine giden gücü kesmek için gaz pedalına hızlıca basıp bırakmak","Sabit ve kararlı gaz vererek motorun gücünün sizi kaygan bölgeden çekmesine izin vermek"],"explanation":"Kaygan zeminde gücü yumuşak ve kademeli olarak verin; tahrik tekerlekleri dönmeye başladığı anda gazı bırakarak tutuşu geri kazanmalarını sağlayın."},"9":{"q":"Yalnızsınız ve çekici-römork aracınızı dar bir sokaktaki yükleme rampasına geri geri sokmanız gerekiyor. Rampaya, aracın sol (sürücü) tarafınıza doğru geri gideceği şekilde ya da biraz daha kısa bir manevra olan sağ tarafınıza doğru geri gideceği şekilde yaklaşabilirsiniz. Mümkün olduğunca güvende kalmak için hangi yaklaşımı seçmelisiniz ve neden?","options":["Sağ tarafa doğru geri gidin, çünkü daha kısa yol kör manevrada daha az zaman demektir","Sağ tarafa doğru geri gidin, ancak yolcu camından sarkıp kör alanı kapatmak için bir gözcü kullanın","Her iki taraf da eşit derecede güvenlidir, bu yüzden daha hızlı manevra olduğu için sağ tarafı seçin","Daha uzun olsa bile sürücü (sol) tarafına doğru geri gidin, çünkü yalnızca aynalara güvenmek yerine römorkun arkasını yan camdan izleyebilirsiniz"],"explanation":"Mümkün olduğunda sürücü (sol) tarafına doğru geri gidin, böylece römorkun arkasını yalnızca aynalara güvenmek yerine yan camdan doğrudan görebilirsiniz."},"10":{"q":"Yüklü bir römork çekiyorsunuz ve sonunda keskin bir virajla biten uzun, dik bir inişe yaklaşıyorsunuz. Şu anda vites yüksek bir kademede. Bu inişte ve virajda hızınızı kontrol etmek için kullanacağınız düşük vitesi seçmenin doğru zamanı ne zamandır?","options":["İnişe başlamadan ve viraja girmeden önce, henüz düz zemindeyken","Tam viraja girerken, böylece motor freni en çok ihtiyaç duyduğunuz yerde en yüksek gücünde olur","İnişin ortasında, kamyonun hızlandığını ve frenlerin solmaya başladığını hissettiğinizde","Yalnızca virajdan çıktıktan sonra, böylece çeker tekerlekler dönüş boyunca tam tutuş sağlar"],"explanation":"Doğru vitesi yokuş aşağı inmeden veya viraja girmeden önce, hâlâ düz zemindeyken seçin, çünkü inişe geçince vites değiştirmek mümkün olmayabilir."},"11":{"q":"Kuru bir otoyolda saatte 55 mil hızla giderken, ileride uzaktaki bir aracın lastiği patlıyor ve araç aniden sizin şeridinizde duruyor. Tehlike ortaya çıktığı andan kamyonunuz tamamen durana kadar aracınız kabaca her iki sayı bölgesi dahil bir Amerikan futbolu sahası uzunluğunda (yaklaşık 419 fit) yol kat edecektir. Hangi faktörler dizisi bu 419 fitlik toplam durma mesafesinin tamamını eksiksiz açıklar?","options":["Hava frenleri tuttuktan sonra frenlerin kamyonu fiziksel olarak yavaşlattığı mesafe, artı sistemde hava basıncı oluşurken geçen gecikme","Tehlikeyi görüp fark ederken kat ettiğiniz mesafe, artı ayağınızı pedala götürürken kat ettiğiniz mesafe, artı frenlerin sizi durdurması için gereken mesafe","Tepki verip ayağınızı pedala götürürken kat ettiğiniz mesafe, artı frenlerin sizi durdurması için gereken mesafe","Yalnızca frenler uygulandıktan sonra kamyonu durdurmaları için gereken mesafe"],"explanation":"Toplam durma mesafesi; algılama mesafesi, tepki mesafesi ve fren mesafesinin toplamıdır: tehlikeyi görmek, ayağı pedala götürmek ve frenlerin aracı durdurması."},"12":{"q":"İyi havada, kuru ve düz bir otoyolda boş olarak sabit 55 mil/saat hızla gidiyorsunuz. Önünüzdeki sürücü aniden duruyor ve tam bir acil durma yapmak zorunda kalıyorsunuz. Bir tehlikenin ilk ortaya çıktığı andan kamyonunuzun tamamen durduğu ana kadar, durmanız için yaklaşık ne kadar toplam yol mesafesi gerekir?","options":["Yaklaşık 60 fit, çünkü bu tepki vermeden önce kat ettiğiniz mesafedir","Yaklaşık 220 fit, kabaca yalnızca frenleme aşamasının uzunluğu","Yaklaşık 320 fit, tek bir Amerikan futbolu sahasından biraz daha fazla","Yaklaşık 420 fit, kabaca bir Amerikan futbolu sahası artı her iki son bölge uzunluğu"],"explanation":"İyi koşullarda saatte 55 mil hızla toplam durma mesafesi yaklaşık 420 fittir, kabaca bir futbol sahası artı iki gol bölgesi uzunluğundadır."},"13":{"q":"Normalde kuru, düz bir otoyol kesiminde 20 mil/saat hızla gidiyorsunuz ve aracınızın bu hızdan durmak için belirli bir fren mesafesine ihtiyacı olduğunu biliyorsunuz. Bu gece geç kaldığınız için aynı yolda, aynı iyi koşullarda 40 mil/saat hızla gidiyorsunuz. 20 mil/saatteki fren mesafenize kıyasla, 40 mil/saatteki fren mesafeniz yaklaşık:","options":["2 kat daha uzun olacaktır, çünkü fren mesafesi hızla doğru orantılı olarak artar","3 kat daha uzun olacaktır, çünkü tepki süresi için de ek mesafe eklemeniz gerekir","4 kat daha uzun olacaktır, çünkü fren mesafesi hızın karesiyle orantılı olarak artar","Yol kuru ve düz, frenler de iyi olduğu sürece yaklaşık olarak aynı olacaktır"],"explanation":"Fren mesafesi hızın karesiyle artar, bu yüzden hızı 20'den 40 mil/saate çıkarmak fren mesafesini yaklaşık dört kat uzatır."},"14":{"q":"Sürekli yağan yağmur otoyolu ıslatmış ve kaplamanın üzerinde ince bir su tabakası görüyorsunuz; ancak hava donma noktasının oldukça üzerinde, kar veya buz yok. Bu ıslak koşulların yarattığı daha uzun durma mesafesi için güvenli bir pay bırakmak amacıyla, aynı yolda kuru havada gideceğiniz hıza kıyasla hızınızı yaklaşık ne kadar azaltmalısınız?","options":["Yaklaşık onda bir oranında","Yaklaşık üçte bir oranında","Yaklaşık yarı yarıya","Yaklaşık dörtte üç oranında"],"explanation":"Islak yolda, kaybedilen tutuşu ve uzayan fren mesafesini telafi etmek için hızınızı kuru yoldaki güvenli hıza göre yaklaşık üçte bir azaltın."},"15":{"q":"Tüm yükünüzü yeni teslim ettiniz ve dorseniz şu anda tamamen boş. Yol kuru ve sabah boyunca tam yüklüyken sürdüğünüz aynı otoyol hızında gidiyorsunuz. Yüklü olduğunuz duruma kıyasla, bu boş aracın nasıl fren yapacağına ve nasıl tutunacağına dair beklentinizi nasıl ayarlamalısınız?","options":["Frenlerin yavaşlatması gereken ağırlık çok daha az olduğu için daha kısa mesafede durur","Hafif arka akslar daha az tutuş sağladığı ve tekerlekler kilitlenip kayabileceği için durması daha uzun mesafe gerektirir","Durma mesafesi neredeyse aynı olur, çünkü fren mesafesi yüke değil hıza bağlıdır","Boş bir dorse çekiş tekerleklerinin kilitlenmesini önlediği için artık kayamaz"],"explanation":"Boş bir kamyon daha uzun durma mesafesine ihtiyaç duyar çünkü hafif arka akslar daha az tutuşa sahiptir, bu yüzden tekerlekler kolayca kilitlenip kayar."},"16":{"q":"Otoyolda saatte yaklaşık 50 mil hızla giderken şiddetli bir sağanak başlıyor. Direksiyon aniden hafif ve boş hissettiriyor, kamyon küçük direksiyon hareketlerine yanıt vermiyor ve ön lastiklerin bir su tabakası üzerine çıkıp artık yola tutunmadığını fark ediyorsunuz. Kontrolü yeniden kazanmak için en iyi şansı hangi hareket verir?","options":["Hızı mümkün olduğunca çabuk düşürmek için fren pedalına sertçe basmak","Gaz pedalını bırakmak (ve debriyaja basmak) ve sert fren yapmadan aracın kendiliğinden yavaşlamasına izin vermek","Lastiklerin daha pürüzlü zemine tutunup yol tutuşunu geri kazanması için direksiyonu sertçe banketin yönüne kırmak","Çekiş tekerleklerinin dönmeye devam etmesi ve suyu 'aşmak' için gazı korumak veya artırmak"],"explanation":"Su kızağı yapmaya başlarsanız, sert fren yapmadan gazı bırakın ve debriyaja basın; böylece lastikler yavaşlayıp yolla teması yeniden kazanabilir."},"17":{"q":"Tamamen yüklü bir römorkla uzun ve dik bir dağ yokuşundan aşağı iniyorsunuz. Tepede düşük vites seçtiniz ve aşağı inerken yol boyunca frene hafif ama neredeyse sürekli bastınız. İnişin ortalarında fren pedalının daha yumuşak hissedildiğini ve kamyonun yokuşun başındaki gibi yavaşlamadığını fark ediyorsunuz. Bu fren kaybının EN OLASI nedeni nedir?","options":["Fren pabuçları ve kampanaları, motor ve vites freni yerine frenlerin çok fazla kullanılmasından dolayı aşırı ısındı","Kompresör yokuşta yetişemediği için fren hatlarındaki hava basıncı çok düştü","Yüksek rakımdaki soğuk dağ havası fren hidrolik yağını koyulaştırdı ve pedal tepkisini azalttı","Römork lastiklerinin havası az, bu da temas yüzeyini ve her tekerlekteki fren kuvvetini azaltıyor"],"explanation":"Uzun bir yokuşta sürekli fren basmak balata ve kampanaları aşırı ısıtarak fren etkinliğini azaltır; bunun yerine hızınızı motor ve vites freniyle tutun."},"18":{"q":"Yüklü bir çekici-römork ile kuru bir otoyolda ilerliyorsunuz ve viraj hız sınırı 35 mph olarak levhalanmış, yokuş aşağı bir çıkış rampasına yaklaşıyorsunuz. Yol yüzeyi iyi durumda ve trafik az. Levhada yazan bu 35 mph değerine nasıl davranmanız gerektiğini en iyi hangi ifade açıklar?","options":["İyi koşullarda her araç için güvenli hızdır, bu nedenle yüklü aracınızda 35 mph sorun değildir","İyi koşullardaki otomobiller için belirlenmiştir, bu nedenle viraja 35 mph'in oldukça altında bir hızla girmelisiniz","Yalnızca boş kamyonlar için geçerlidir, bu nedenle yüklü bir kamyon yasal olarak bunu aşabilir","Kamyonlar için zaten bir güvenlik payı içerir, bu nedenle tam olarak 35 mph'i korumak en güvenli seçenektir"],"explanation":"Levhadaki viraj hızları iyi koşullardaki otomobiller için belirlenmiştir, bu yüzden ağırlık merkezi daha yüksek olan kamyon virajı levhadaki hızın belirgin şekilde altında almalıdır."},"19":{"q":"Kuru bir otoyolda 60 fit uzunluğunda bir çekici-römork (TIR) kullanıyorsunuz ve hız göstergeniz seyrek trafikte sabit 55 mil/saat gösteriyor. Önünüzdeki aracın arkasında güvenli bir takip mesafesi bırakmak istiyorsunuz. Aracınızın uzunluğuna ve mevcut hızınıza göre korumanız gereken asgari takip mesafesi nedir?","options":["6 saniye, çünkü 60 fitlik bir araç her hızda her 10 fit için 1 saniyeye ihtiyaç duyar","Uzunluğundan bağımsız olarak her ağır araç gibi sabit 4 saniye","7 saniye, çünkü 60 fitlik bir araç 6 saniyeye ve 40 mil/saatin üzerinde sürdüğü için 1 saniye daha ihtiyaç duyar","Yaklaşık üç araba boyu, ki bu bir çekici-römork için kabaca yeterli bir tampondur"],"explanation":"Aracın her 3 metresi (10 feet) için 1 saniye takip mesafesi, 40 mil/saat üzerinde 1 saniye daha ekleyin; böylece 55 mil/saatteki 18 metrelik (60 feet) bir araç 7 saniyeye ihtiyaç duyar."},"20":{"q":"Hafif trafikli, geniş ve açık bir kırsal otoyolda saatte 60 mil hızla ilerliyorsunuz. İleride yol hafifçe yokuş yukarı çıkıyor ve alanınızı yönetmek, sorunları erkenden fark etmek istiyorsunuz. Doğru tarama yapmak için bu hızda sürerken gözleriniz ZAMANIN ÇOĞUNDA nereye odaklanmalı?","options":["Yoldaki engelleri anında görmek için kaputunuzun hemen önündeki asfalta","Yaklaşık 4 ila 6 saniye ileriye; güvenli takip mesafesi bırakırken kullandığınız mesafenin aynısı","Yaklaşık 12 ila 15 saniye ileriye; otoyol hızında yaklaşık çeyrek mil","Yaklaşık 30 saniye ileriye; gözünüzün yolda erişebildiği en uzak noktaya"],"explanation":"İyi sürücüler 12 ila 15 saniye ileriye bakar, bu otoyol hızında yaklaşık çeyrek mildir."},"21":{"q":"Yoğun bir şehir caddesinde dar bir ara sokağa sağa dönmek üzeresiniz. Trafik sıkışık, sağınızdaki bisiklet şeridinde bir bisikletli var ve arkanızda birkaç sürücü size yakın şekilde sıralanmış durumda. Dönüş sinyaliyle ilgili tek en doğru uygulama hangisidir?","options":["Arkadakilerin çok erken yavaşlayıp tıkanıklığa yol açmaması için, gerçekten direksiyonu kırmaya başlayana kadar bekleyip sinyali o anda vermek","Sinyali yalnızca kısa süre yakmak, çünkü yoğun trafikte çevredeki sürücüler zaten fren lambalarınızı görerek iletişimi sizin yerinize sağlıyor","Dönüşten çok önce sinyali yakmak ve tüm manevra boyunca kesintisiz olarak yanıp sönmesini sağlamak","Yanınızdaki bisikletliye daha görünür olduğu için elektrikli sinyali kullanmayıp bunun yerine el işareti vermek"],"explanation":"Dönüşten çok önce sinyali açın ve manevra boyunca yanık tutun ki diğerleri tepki vermek için en fazla zamana sahip olsun ve fikrinizi değiştirdiğinizi sanmasın."},"23":{"q":"70 fitlik bir çekici-römork kullanıyorsunuz ve dar bir yan sokağa sağa dönmeniz gerekiyor. Trafik sakin ve römorkun arka tekerleklerinin kaldırıma çıkmasından endişeleniyorsunuz. Bu dönüşü güvenli ve kurallara uygun şekilde tamamlamak için aşağıdakilerden hangisini YAPMAMALISINIZ?","options":["Römorkun dönmek için daha fazla yeri olsun diye dönüşten önce sola, yan şeride kaymak","Dönüşe yavaşça başlamak ve römorkun izlediği yolu takip etmek için aynalarınızı izlemeye devam etmek","Diğer sürücülerin sağınızdan sıkışıp geçememesi için aracın arkasını kaldırıma yakın tutmak","Geniş dönüşü yalnızca dönüşü tamamlarken, kabin köşeyi geçtikten sonra yapmak"],"explanation":"Sağa dönüşten önce sola kaymak, sağ tarafınızda araçları geçmeye davet eden bir boşluk açar ve onları dönen römorkunuzun yoluna sokar."},"24":{"q":"Boş bir kapalı kasa (kuru yük) çekiyorsunuz ve güzergahınızda 13 fit 6 inç geçiş yüksekliği belirtilen bir üst geçit var. Römorkunuzun listelenen yüksekliği 13 fit 4 inç, yani 2 inçlik bir paylar var. Bu kış başlarında yol ekibi bu kesimi yeniden asfaltladı ve dün gece yola sıkışıp kalan hafif bir kar yağdı. Üst geçidin altından geçmeye karar vermeden önce, levhada yazan geçiş yüksekliğini değerlendirmenin en savunulabilir yolu nedir?","options":["Levha resmi olarak konulduğu için 13 fit 6 inç değeri kesindir ve 2 inçlik pay geçmek için yasal olarak yeterlidir.","Yükseklik levhaları yüklü araçlar için geçerli olduğundan, boş kasa listelenen yüksekliğinden daha alçakta durur; bu yüzden fazladan boşluğunuz vardır ve geçebilirsiniz.","Levhadaki yüksekliği güvenilmez kabul edin: yeniden asfaltlama ve sıkışmış kar gerçek açıklığı azaltır, üstelik boş kasa aslında daha yüksekte gider; bu nedenle başka bir güzergah bulun veya geçmeden önce doğrulayın.","2 inçlik payınızı levhadaki 13 fit 6 inçe ekleyin; bu size yaklaşık 13 fit 8 inçlik kullanılabilir açıklık verir ve römorkunuz için fazlasıyla yeterlidir."],"explanation":"Belirtilen yükseklik işaretleri yanlış olabilir, çünkü yeniden asfaltlama ve sıkışmış kar gerçek açıklığı azaltır ve boş bir van daha yüksek durur, bu yüzden devam etmeden önce doğrulayın veya başka yol seçin."},"25":{"q":"Yoğun bir otoyola katılıyorsunuz ve sağ kapınızdaki büyük dışbükey (kavisli) aynaya bakıyorsunuz. Bu dışbükey aynada gördüğünüz bir araç küçük ve geride görünüyor, bu yüzden şerit değiştirmek için bol yeriniz olduğunu düşünüyorsunuz. Manevraya başlamadan önce, bu dışbükey aynanın size ne gösterdiği konusunda neyi anlamanız gerekir?","options":["Daha geniş bir alan gösterir, ancak nesneler gerçekte olduğundan daha küçük ve daha uzak görünür, bu yüzden o araç göründüğünden daha yakın olabilir","Dar bir yakın görüntüyü büyütür, bu yüzden araç göründüğünden aslında daha uzaktadır ve fazladan yeriniz vardır","Düz ayna ile aynı gerçek boyut ve gerçek mesafe görüntüsünü gösterir, bu yüzden gördüğünüz boşluk doğrudur","Yalnızca kendi kabininizin ve dorsenizin yanını yansıtır, bu yüzden içindeki herhangi bir araç henüz bir tehlike değildir"],"explanation":"Dışbükey aynalar daha geniş bir alan gösterir ama nesneleri daha küçük ve uzak gösterir, bu yüzden araç göründüğünden daha yakın olabilir."},"26":{"q":"Açık ve kuru bir karayolunda ilerlerken, ileride sağ banket üzerinde kaputu açık park etmiş bir araba ve arka tamponun yanında durup trafiğe doğru bakan bir kişi fark ediyorsunuz. Kaza yok, kötü hava yok ve trafik normal akıyor. Tehlikeleri görme açısından, bu park etmiş arabayı ve kişiyi nasıl sınıflandırmalısınız?","options":["Tehlikedir, çünkü acil duruma dönüşebilecek ve sizi harekete geçmeye zorlayabilecek herhangi bir yol koşulu veya yol kullanıcısıdır","Tehlike değildir, çünkü henüz bir kaza veya acil durum yaşanmıyor ve yolun kendisi açık","Tehlike değildir, çünkü tehlikeler yalnızca kötü hava, sis, buz veya diğer kötü sürüş koşullarında bulunur","Yalnızca park etmiş araba aniden şeridinize geri dönüp sizi sert fren yapmaya zorlarsa tehlikedir"],"explanation":"Tehlike, acil duruma dönüşebilecek herhangi bir yol koşulu veya yol kullanıcısıdır ve tepki vermek için zamanınız olsun diye erken fark edilir."},"27":{"q":"Dört şeritli bir karayolunda sağ şeritte seyrederken bir otomobil arkanızdan hızla yaklaşıp römorkunuza santimlerle dayanıyor, ardından yan geçip önünüze kesiyor ve sert şekilde fren yapıyor. Ticari aracınız tam yüklü ve durma mesafeniz zaten uzun. Bu agresif sürücüyle başa çıkmanın EN İYİ yolu aşağıdakilerden hangisidir?","options":["Uzun farlarınızı yakıp söndürün ve korna çalarak sürücünün geri çekilmesini işaret edin, sonra şeridinizi koruyun","Sol şeride geçip sürücüyü geçerek çatışmayı arkanızda bırakın","Hızınızı koruyun ve sürücünün sizi tekrar kesememesi için hemen arkasında yakın durun","Gaz pedalından ayağınızı çekip önünüzde mesafe açın, göz temasından kaçının ve agresif sürücünün iyice öne geçmesine izin verin"],"explanation":"Agresif bir sürücüye karşı güvenli tepki, gaz pedalını bırakıp boşluk açmak, göz teması kurmaktan kaçınmak ve onun iyice öne geçmesine izin vermektir."},"29":{"q":"Kırsal, iki şeritli bir karayolunda karanlık ve aysız bir gece; yolu yaklaşık 250 fit ileriye aydınlatan kısa hüzmeli (kısa far) ışıklarınızla gidiyorsunuz. Karşı yönden gelen trafik yok. Farlarınızın ışığını 'aşmamak' için yapmanız gereken en önemli tek şey nedir?","options":["Uzun hüzmeli farlara geçip sabit 55 mil/saat hızda gitmek, çünkü uzun farlar yaklaşık 350 fit aydınlatır ve bu tepki vermeye yeterli mesafedir","Önündeki aracın arka stop lambalarına yaklaşıp onun ışığını kullanarak yolda daha ileriyi görmek","Farlarınız şerit çizgilerini ve önünüzdeki yolu net aydınlattığı için normal gündüz hızınızı korumak","Farlarınızın gerçekte aydınlattığı mesafe içinde tamamen durabilecek kadar yavaş sürmek"],"explanation":"Asla farlarınızın aydınlattığından hızlı gitmeyin: farlarınızın gerçekten aydınlattığı mesafe içinde tamamen durabilecek kadar yavaş sürün."},"30":{"q":"Hava yeni karardı, bölünmemiş iki şeritli bir yolda ilerliyorsunuz ve farları açık bir sıra araç karşıdan yaklaşıyor. Sürücülerden biri uzun farlarını kısmıyor ve göz kamaştırıcı ışık önünüzdeki yolu görmenizi zorlaştırıyor. Gözleriniz karanlığa uyumlu kalsın ve araçlar geçene kadar şeridinizde güvenle kalabilesiniz diye bakışınızı nereye yöneltmelisiniz?","options":["Araçlar geçene kadar yol çizgilerini veya işaretlerini kılavuz alarak şeridinizin sağ kenarına","Aradaki mesafeyi ölçebilmek için doğrudan karşıdan gelen farlara","Parlak ışıktan gözlerinizi dinlendirmek için gösterge paneline aşağı","Hızınızı farlarınızın aydınlattığı mesafeyle sınırlı tutmak için karşı trafiğin çok ötesindeki yola uzağa"],"explanation":"Karşıdan gelen uzun farlar gözünüzü aldığında, sağ şerit kenarına bakın ve yol çizgisini takip edin; böylece gözleriniz karanlığa uyumlu kalır."},"31":{"q":"Şafaktan önce teslimat yaparken yoğun bir sis tabakası çöküyor ve görüş mesafesi çekici-römork uzunluğunuzdan daha azına düşüyor. Şeritte durmak yerine bir sonraki çıkışa kadar yavaşça devam etmenin en güvenli olduğuna karar veriyorsunuz. Kendinizi kör ETMEDEN yolu görmek ve görünür olmak için hangi aydınlatma ve hız seçimi tek başına en doğru uygulamadır?","options":["Maksimum menzil için uzun farları yakın ve trafiği engellememek için hızınızı koruyun","Kısa (yakın) farlarınızı (ve varsa sis farlarınızı) kullanın ve görebildiğiniz mesafe içinde durabilecek şekilde hızınızı azaltın","Farları kapatın ve konumunuzu belirtmek için yalnızca dörtlü flaşörleri çalıştırın","Uzun farları açık tutun ama yavaşlayın, çünkü siste fazladan ışık, parlamadan daha önemlidir"],"explanation":"Siste kısa farları (varsa sis farlarını) kullanın ve görebildiğiniz mesafede durabilecek kadar yavaşlayın, çünkü uzun farlar geri yansıyıp görüşü azaltır."},"32":{"q":"Açık bir sabah, hava yaklaşık 31°F (yaklaşık -1°C) ve önünüzdeki açık yol tamamen kuru görünüyor. Yüklü bir römorkla bir nehir vadisini aşan uzun bir köprüye doğru gidiyorsunuz; hemen ötesinde gölgede kalan bir üst geçit var. Oraya varmadan önce İLK NEREDE çekiş kaybı bekleyip hızınızı ayarlamalısınız?","options":["Kuru açık yolda, çünkü çekicinin ağırlığı lastikleri bastırır ve asfaltı ısıtır","Köprüde ve gölgeli üst geçitte, çünkü hava tablanın hem üstünde hem altında dolaşır, bu yüzden çevredeki yoldan önce soğur ve donar","Henüz hiçbir yerde, zemin kuru göründüğüne göre hava sıcaklığı donma noktasının altına düşmeden buzlanamaz","Yalnızca üst geçitten sonra, orada yol tuzu ve güneş yükseltilmiş yapılardaki buzu çoktan eritmiştir"],"explanation":"Köprüler ve üst geçitler tabliyenin altından ve üstünden soğuk havaya maruz kaldığından her yönden ısı kaybeder ve çevredeki yoldan önce buz tutar."},"33":{"q":"Sabahın erken saatlerinde hava donma noktasının hemen altında. İlerideki yol koyu ve ıslak görünüyor, ancak önünüzdeki kamyonun lastiklerinin hiç su sıçratmadığını ve aynalarınız ile anteninizde ince bir buz tabakası oluştuğunu fark ediyorsunuz. Yol yüzeyinde EN OLASI ne oluyor ve nasıl tepki vermelisiniz?","options":["Yüzey sadece eriyen kırağıdan ıslak; hızınızı koruyun çünkü birikintideki su normal tutuş sağlar.","Yol sadece kuruyor; frene kısa ve sert bir basış tutuşun iyi olduğunu doğrular ve takip mesafenizi korumanızı sağlar.","İnce, şeffaf bir kara buz tabakası oluştu; gazdan ayağınızı yavaşça çekin ve ani direksiyon ya da fren hareketlerinden kaçının.","Yüzeyi ıslak gösteren şey taze asfalt kaplaması; dikkatli olun ama normal hız kabul edilebilir."],"explanation":"Donma noktası civarında ıslak görünen ama lastik suyu sıçratmayan yol buzlanmayı (kara buz) gösterir; gazdan ayağınızı çekin, ani direksiyon ve frenden kaçının."},"34":{"q":"Batı Teksas'ta Temmuz ayının ortası, dış hava sıcaklığı yaklaşık 105 derece (Fahrenheit) ve asfaltta gözle görülür şekilde zift sızıyor. İki saat önce mola verdiniz ve lastikleriniz sorunsuzdu, ancak az önce otoyol hızında uzun bir eyaletler arası yola katıldınız. Bu yolculuk sırasında EN çok hangi durumu izlemeye dikkat etmelisiniz?","options":["Isı arttıkça patlamaya yol açabilecek lastik basıncının yükselmesi","Kornanın toz ve sıcaktan dolayı boğuklaşması","Valflerden soğuk hava kaçmasıyla lastik basıncının düşmesi","Cam filminin koyulaşarak ön görüşünüzü azaltması"],"explanation":"Aşırı sıcakta lastik içindeki hava genleşir ve basınç yükselir; bu da sıcaklıkla birleşince patlamaya yol açabilir."},"35":{"q":"Aracınız azami katar ağırlığına (GCWR) yakın yüklü ve uzun, dik bir dağ yokuşundan inmek üzeresiniz. Yol kuru ve hava açık. Tepeye ulaştığınızda, iniş boyunca hızınızı nasıl kontrol altında tutacağınızı düşünmeye başlıyorsunuz. Bu yokuşta hızınızı yönetmenin EN İYİ yolu hangisidir?","options":["Motor düzgün çalışsın diye yüksek viteste kalın ve hızı güvenli bir düzeyde sabit tutmak için iniş boyunca servis frenlerine sürekli basılı tutun.","Boşa alıp süzülün ve hız her arttığında frenlerin aralarda soğuması için servis frenlerine sertçe basın.","Vitesi normal yol viteslerinde tutun ve inişte hızınızı el (park) freniyle dizginlemeye güvenin.","İnişe başlamadan ÖNCE düşük bir vites seçin; böylece işin çoğunu motor ve vites frenlemesi yapsın, servis frenini ise yalnızca hafif ve düzenli bir destek olarak kullanın."],"explanation":"Uzun ve dik bir inişte, inişe başlamadan önce düşük vites seçin; böylece motor ve vites freni işin çoğunu yapar, servis frenini ise sadece hafif ve düzenli kullanın."},"36":{"q":"Yüklü bir römorkla uzun ve dik bir dağ yokuşundan iniyorsunuz. Tepede düşük vites seçtiniz ve hafif, sabit fren uyguluyorsunuz, ancak fren pedalı yavaşça yumuşuyor, hızınız sürekli artıyor ve yanık kokusu alıyorsunuz. İleride sağda çakıllı bir kaçış rampası görüyorsunuz. Aşağıdakilerden hangisi bu rampaya ne zaman girmeniz gerektiğini açıklar?","options":["Frenleriniz aşırı ısınıp etkisini yitirdiğinde veya bozulduğunda ve yokuşta artık hızınızı kontrol edemediğinizde","Yokuş için belirlenen kamyon hız sınırını yalnızca birkaç mil/saat aştığınızda","Yokuştaki trafik yoğunlaştığında ve daha fazla alan istediğinizde","Devam etmeden önce motorun ve frenlerin soğuması için kısa bir mola vermek istediğinizde"],"explanation":"Kaçış rampasını yalnızca frenleriniz aşırı ısınıp etkisini yitirdiğinde veya bozulduğunda ve inişte hızınızı kontrol edemediğinizde kullanın."},"37":{"q":"Sıcak bir yaz öğleden sonrası otoyol hızında boş giderken yüksek bir patlama sesi duyuyorsunuz ve direksiyon aniden sertçe sağa çekiyor -- bir ön lastik patladı. Boş aracınızı artık kontrol etmek daha zor. İLK doğru hareketiniz ne olmalı?","options":["Direksiyonu sıkıca tutmak, frene basmamak ve aracın kendi kendine yavaşlamasını bekledikten sonra yavaşça bankete çekmek","Kamyon yoldan çıkmadan önce hızı kesmek için sıkı ve istikrarlı şekilde fren yapmak","Kamyonu şeridin ortasında tutmak için çekiş yönünün tersine sertçe direksiyon kırmak","Debriyaja basıp daha düşük vitese geçerek motor freni ile yavaşlamak"],"explanation":"Ön lastik patlamasından sonra direksiyonu sıkıca tutun ve frene basmayın; aracın kendi kendine yavaşlamasını bekleyip yoldan öyle çıkın."},"38":{"q":"Hidrolik frenli düz bir kamyonla orta eğimli bir yokuştan inerken fren pedalına basıyorsunuz ve pedal neredeyse hiç durdurma gücü olmadan yavaşça tabana kadar iniyor. Trafik hafif ve yaklaşık bir mil ileride bir kaçış rampası var. Aracı yavaşlatmak için İLK olarak ne denemelisiniz?","options":["Aktarma organlarının kamyonu durdurmaya yardımcı olması için motoru hemen kapatın","El frenini tek bir sert hareketle kuvvetlice çekerek tekerlekleri kilitleyin","Römork frenlerini devreye sokmak için römork hava besleme (çekici koruma) düğmesini çekin","Hidrolik basıncı yeniden oluşturmak için fren pedalına hızlıca art arda basın (pompalayın)"],"explanation":"Hidrolik fren pedalı tabana kadar gidiyorsa, aracı yavaşlatacak veya durduracak basıncı yeniden oluşturmak için önce pedalı hızlıca pompalayın."},"39":{"q":"Islak, çift şeritli bir karayolunda virajdan çıkarken hızlanıyorsunuz ve çekicinin arkası aniden banket tarafına doğru kaymaya başlıyor; çeker tekerlekler tutuşunu kaybetmiş gibi hissettiriyor. Aşağıdakilerden hangisi bu çeker tekerlek kaymasında kontrolü yeniden kazanmanın EN İYİ yoludur?","options":["Aracın arkasını yavaşlatıp tekrar hizaya sokmak için fren pedalına sıkıca basıp basılı tutmak","Hızlanmayı bırakmak, debriyaja basmak ve aracı götürmek istediğiniz yöne doğru direksiyon kırmak","Gazı sabit tutup sert şekilde ters direksiyon kırarak motor gücünün çeker tekerlekleri düzeltmesini sağlamak","Kaymayı mümkün olduğunca çabuk durdurmak için frenlerle tekerlekleri kilitlemek"],"explanation":"Çekiş tekerleği hızlanma kaymasını düzeltmek için gaz vermeyi bırakın, debriyaja basarak motor gücünü kesin ve gitmek istediğiniz yöne direksiyon kırın."},"40":{"q":"Yüklü bir römorkla uzun ve virajlı bir dağ yokuşundan inerken önünüzdeki yol yüzeyi ıslak ve gölgeli görünüyor. Bir viraja girmeye başlıyorsunuz ama kamyonunuzun ön kısmı virajın dış tarafına doğru düz gitmeye devam ediyor ve direksiyonu ne kadar çevirirseniz çevirin direksiyon hafif ve tepkisiz hissettiriyor. Aşağıdakilerden hangisi bu ön tekerlek kaymasının EN olası temel nedenidir?","options":["Viraja girerken frenleri çok yumuşak bıraktınız, bu yüzden ön lastikler asfaltı hiç kavrayamadı","Yükün çok fazlası arka akslara kaydı ve direksiyon (ön) aksından ağırlık kaldırdı","Kaygan, gölgeli koşullar için çok hızlı gidiyorsunuz (ve/veya ön lastikleriniz aşınmış ya da düşük basınçlı)","Düşük viteste motor freni çekiş tekerleklerini kilitledi ve ön kısmı yoldan çıkardı"],"explanation":"Ön tekerlek kayması, koşullara göre fazla hızlı sürmekten ve aşınmış veya hava basıncı düşük ön lastiklerden kaynaklanır."},"41":{"q":"Hava donma noktasının hemen altında ve yol kaygan; bir otomobil önünüze aniden girdiğinde sert, acil bir fren yapıyorsunuz. Çekiciniz kilitlenme önleyici fren sistemi (ABS) ile donatılmış ve fren pedalına sonuna kadar sıkıca basıyorsunuz. Bu durumda ABS'nin sağladığı EN ÖNEMLİ fayda nedir?","options":["Tekerleklerin kilitlenmesini önler, böylece tehlikenin etrafından direksiyonla manevra yapmaya devam edebilirsiniz","ABS'siz aynı kamyona göre belirgin şekilde daha kısa bir durma mesafesini garanti eder","Kamyonu önünüze giren otomobilden otomatik olarak uzağa yönlendirir","Artık daha hızlı durduğunuz için öndeki aracı güvenle daha yakından takip etmenizi sağlar"],"explanation":"ABS, sert frenlemede tekerleklerin kilitlenmesini önler, böylece bir tehlikenin etrafından direksiyonla geçebilirsiniz."},"42":{"q":"İşlek, iki şeritli bir karayolunda bir kazaya ilk siz ulaştınız. Bir otomobil takla atmış ve şeridinizi kapatıyor; sürücü bilinci yerinde ama kapıya yaslanmış durumda ve kazanın arkasından trafik hâlâ otoyol hızında yaklaşıyor. Güvenli bir şekilde durdunuz ve dörtlü flaşörlerinizi yaktınız. İLK olarak ne yapmalısınız?","options":["Araç alev alır diye yaralı sürücüyü dikkatlice arabadan çıkarıp banketin üzerine yatırmak","Tek başınıza yardım edemeyeceğiniz için bir telefon bulup 911'i aramak üzere bir sonraki çıkışa kadar devam etmek","Aşağı inip hasarlı arabayı kenara itmek, böylece şerit açılsın ve trafik akmaya devam etsin","Olay yerinde başka herhangi bir şey yapmadan önce yaklaşan trafiği uyarmak için yansıtıcı uyarı üçgenlerini yerleştirmek"],"explanation":"Bir kaza yerinde ilk öncelik bölgeyi korumaktır; bu yüzden başka bir şey yapmadan önce yaklaşan trafiği uyarmak için yansıtıcı reflektör üçgenleri yerleştirin."},"43":{"q":"Motor bölmesinden duman yükseldiğini görünce bankete çekiyorsunuz. El frenini çektiniz ve B:C sınıfı yangın söndürücünüzü aldınız. Motor yangınıyla mücadeleye hazırlanırken aşağıdakilerden hangisi EN AZ uygun davranıştır?","options":["Motoru mümkün olan en kısa sürede kapatmak","Söndürücüyü alevlerin tepesine değil, yangının tabanına yöneltmek","Kaputu mümkün olduğunca kapalı tutmak ve söndürücüyü açıklıklardan veya panjurlardan sıkmak","Alevlere doğrudan nişan alabilmek için kaputu sonuna kadar açmak"],"explanation":"Kaputu sonuna kadar açmak ateşe taze oksijen verir ve şiddetle alevlenmesine yol açabilir; kaputu kapalı tutup söndürücüyü açıklıklardan sıkın."},"44":{"q":"Uzun bir sefer öncesi akşam bir düğün resepsiyonunda istikrarlı şekilde içki içiyorsunuz ama uyumadan birkaç saat önce bırakıyorsunuz. Ertesi sabah kendinizi tamamen ayık hissediyor, bol bir kahvaltı yapıyor, iki fincan kahve içiyor ve sefer öncesi kontrolünüzden önce soğuk havada tempolu bir yürüyüş yapıyorsunuz. Kabine tırmanırken, ticari aracınızı (CMV) güvenle kullanıp kullanamayacağınız konusunda yasayı ve gerçekleri en iyi hangi ifade yansıtır?","options":["Bu adımların hiçbiri kandaki alkol konsantrasyonunuzu düşürmedi; bunu yalnızca zamanın geçmesi yapar ve kandaki alkol oranı (BAC) yüzde 0,04 veya üzerindeyken CMV kullanamazsınız.","Bir CMV kullandığınız için yasal sınır yüzde 0,08'dir, bu nedenle bunun altında kaldıysanız kesinlikle sorun yoktur.","Kahve, yemek ve soğuk hava alkolün atılımını hızlandırdı, dolayısıyla BAC değeriniz artık fiilen sıfırdır ve sınırın bir önemi kalmadı.","Ayık hissetmek bir CMV sürücüsü için yasal ölçüttür; bu yüzden artık sersemlik hissetmiyorsanız sınırın altındasınız ve sürmeniz güvenlidir."],"explanation":"Kandaki alkol oranını yalnızca zamanın geçmesi düşürür ve %0,04 veya daha yüksek bir alkol oranıyla ticari araç kullanamazsınız."},"45":{"q":"Vardiyanız saatler önce bitti ve akşam yemeğinde birkaç içki içtiniz. Bir sevkiyat görevlisi arayıp boş bir çekiciyi hemen şimdi şantiyeye geri götürmenizi istiyor. Kahve içtiniz, soğuk gece havasında hızlı bir yürüyüş yaptınız ve kafanızın berrak olduğunu hissediyorsunuz. Hangi ifade, yasal olarak araç kullanmaya uygun olup olmadığınızı gerçekte neyin belirlediğini en iyi şekilde yansıtır?","options":["Kahve ve soğuk hava uyanıklığınızı yeterince artırdı, böylece kandaki alkol konsantrasyonunuz artık CDL için belirlenen %0,04 sınırının altında.","Kafanız berrak olduğu ve artık etki altında olmadığınız için çekiciyi kullanmanız güvenli ve yasaldır.","Kandaki alkol konsantrasyonunu yalnızca zamanın geçmesi düşürür; yaptığınız hiçbir şey alkolün vücuttan atılma hızını artırmaz.","Bu yüksüz bir boş sürüş olduğundan, %0,04 kan alkol sınırı bu sefer için geçerli değildir."],"explanation":"Kan alkol konsantrasyonunu yalnızca zaman düşürür, çünkü karaciğer alkolü sabit bir hızda atar ve kahve, temiz hava ya da soğuk duş bunu hızlandıramaz."},"46":{"q":"Vardiyanıza başlarken bir yol denetçisi nefes testi uyguluyor ve sonucunuz %0,02 BAC çıkıyor -- alkol tespit edilebilir düzeyde, ancak %0,04 CDL sınırının altında. Kendinizi tamamen ayık hissediyorsunuz ve herhangi bir kaza ya da başka bir ihlal söz konusu değil. Federal CDL kurallarına göre bundan sonra size ne olur?","options":["Hiçbir şey değişmez -- %0,04 sınırının altında olduğunuz için normal şekilde sürmeye devam edebilirsiniz","Ölçümünüz %0,04 diskalifiye edici seviyenin altında olsa bile 24 saat hizmet dışı bırakılırsınız","%0,04 ölçümüyle aynı şekilde işleme tabi tutulur ve DUI (alkollü araç kullanma) suçundan işlem görürsünüz","Yazılı bir uyarı alırsınız ve imzaladıktan sonra yolculuğunuza devam etmenize izin verilir"],"explanation":"%0,04'ün altındaki tespit edilebilir herhangi bir alkol miktarı, diskalifiye sınırının altında olsa bile CDL sürücüsünü 24 saat görevden uzaklaştırır."},"47":{"q":"Yükü göndericinin yerinde açık kasaya (flatbed) yükleyip sabitlediniz, sefer öncesi kontrolünüzü tamamladınız ve otoyola çıktınız. Yolculuğunuz 280 mil ve planlanmış mola yok. Yükün oturduğunu ve bağlama gereçlerinin yola çıktıktan kısa süre sonra gevşeyebileceğini bilerek, yükü kontrol edip bağlamayı yeniden sıkmak için İLK durağınızı hangi noktaya kadar yapmalısınız?","options":["İlk 50 mil içinde","İlk 150 mil içinde","İlk 3 saatlik sürüşten sonra","İlk 100 mil içinde"],"explanation":"Yükü ve bağlama düzeneklerini ilk 50 mil içinde kontrol etmelisiniz, çünkü yük oturdukça bağlar bu ilk millerde gevşer."},"48":{"q":"Sefer öncesi kontrolünüzde, açık kasaya (flatbed) 18 fit uzunluğunda ve 4.200 pound ağırlığında tek bir çelik kirişi sabitliyorsunuz. Federal yük emniyeti kurallarını yine de karşılayan en az sayıda bağlama (tie-down) kullanmak istiyorsunuz. Kullanmanız gereken EN AZ bağlama sayısını hangi ifade doğru tanımlar?","options":["En az iki bağlama, çünkü her 10 fit yük için bir bağlama gerekir ve 18 fitlik bir parça iki tane gerektirir","Tek bir bağlama yeterlidir, çünkü kiriş kasanın üzerinde düz duran tek ve dengeli bir parçadır","En az üç bağlama, çünkü 5 fitten uzun herhangi bir parça her zaman üç ayrı sabitleme noktası gerektirir","Sabit bir sayı geçerli değildir; yalnızca çalışma yük limiti yükün ağırlığının %50'sine ulaşacak kadar bağlama yeterlidir"],"explanation":"Yük her 10 fit uzunluk için en az bir bağlama gerektirir ve 5 fitten uzun her parça en az iki bağlama ister; bu nedenle 18 fitlik parça için iki bağlama gerekir."},"49":{"q":"Bir platform dorseyi yükleme rampasında yüklüyorsunuz ve birkaç ağır çelik bobin için kalan tek yer iki katlı rafın üst seviyesi; daha hafif ambalaj ise alttaki platforma konabilir. Bir iş arkadaşınız, toplam ağırlık GVWR (azami yüklü araç ağırlığı) sınırının altında kaldığı sürece ağır bobinlerin nerede taşındığının fark etmediğini söylüyor. Yola çıktığınızda güzergah, birkaç keskin virajı olan virajlı, iki şeritli bir yol içeriyor. Ağır bobinleri platforma alçak yerleştirmeye kıyasla, bu ağır yükü yükseğe istiflemenin EN önemli sonucu nedir?","options":["Aracın GVWR sınırı içinde kaldığınız için yol tutuşa gerçek bir etkisi yoktur","Daha fazla ağırlık lastikleri yere bastırdığı için kamyonu durdurmak kolaylaşır","Ağırlık merkezini yükseltir ve kamyonu virajlarda devrilmeye çok daha yatkın hale getirir","Yük şasinin üzerinde ortalandığı için virajlarda kararlılığı ve iz takibini iyileştirir"],"explanation":"Ağır yükü yükseğe yerleştirmek ağırlık merkezini yükseltir, kamyonu üst ağırlıklı yapar ve virajlarda devrilme olasılığını çok artırır."},"50":{"q":"Bir Texas DPS sahasında, sürme yetkisi almak istediğiniz bir araç katarına bakıyorsunuz: yüklü bir römork çeken bir çekici. Evraktaki kombine derecelendirme (GCWR) 33.000 lb, römorkun kendi derecelendirmesi ise 14.000 lb. Class B ehliyeti olan bir arkadaşınız, 'çünkü hepsi birden 26.001 lb'nin üzerinde' diyerek bu katarı kendi ehliyetinin kapsadığını söylüyor. Hangi ifade gerçekte ihtiyacınız olan ehliyeti ve nedenini doğru şekilde belirtir?","options":["Class B yeterli, çünkü katarın toplam derecelendirmesi 26.001 lb veya daha fazla.","Class A gerekli, ancak yalnızca katarın toplam derecelendirmesi 16.001 lb veya daha fazlaya ulaştığı için.","Class B yeterli, çünkü çekilen römork 16.000 lb'nin altında derecelendirilmiş.","Class A gerekli, çünkü katar 26.001 lb veya daha fazla derecelendirilmiş VE çekilen birim 10.000 lb'nin üzerinde derecelendirilmiş."],"explanation":"Kombinasyon GCWR'si 26.001 lb veya daha fazla ve çekilen ünite 10.000 lb üzeri olduğunda Sınıf A CDL gerekir."},"51":{"q":"Hayatınızı çekici-dorse kullanarak kazanmayı planlayarak CDL beceri sınavına geliyorsunuz; kullanacağınız her araç tam hava frenine sahip. Para biriktirmek için bir arkadaşınız size yalnızca hidrolik frenle donatılmış eski tek parçalı kamyonunu ödünç veriyor ve tüm beceri sınavını bu araçta hatasız bir şekilde geçiyorsunuz. Bu tercihin ehliyetinizi nasıl etkilediğine göre hangi ifade doğrudur?","options":["Beceri sınavını hava freni OLMAYAN bir araçta yaptığınız için, CDL ehliyetinizde hava frenli herhangi bir ticari motorlu aracı kullanmanızı yasaklayan bir hava freni kısıtlaması yer alacaktır.","Beceri sınavını hatasız bir şekilde temiz geçtiğiniz için, hava frenli araçlar için geçerli, kısıtlamasız tam bir CDL ehliyeti alacaksınız.","Sınava girdiğiniz kamyonun çalışan hidrolik frenleri olduğundan, denetçi hava freni bölümünü basitçe muaf tutup kısıtlamasız bir ehliyet düzenleyebilir.","İş için yalnızca hava frenli çekici-dorse kullanmayı düşündüğünüzden, yeniden sınava girene kadar yalnızca gece kullanımıyla kısıtlı bir ehliyet verilecektir."],"explanation":"Beceri testini havalı freni olmayan bir araçta yapmak, havalı frenli herhangi bir ticari aracı kullanmanızı yasaklayan bir havalı fren kısıtlaması doğurur."},"52":{"q":"Kırsal bir karayolunda, içinde 40 yolcu bulunan bir tur otobüsü kullanıyorsunuz ve bir demir yolu hemzemin geçidine yaklaşıyorsunuz. Geçit yalnızca çarpı (crossbuck) levhasıyla işaretli, bariyerler yukarıda, hiçbir ışık yanıp sönmüyor, her iki yöne de net görüyorsunuz ve görüş alanında hiç tren yok. Geçişten önce ne yapmanız gerekir?","options":["Bariyerler yukarıda ve sinyaller etkin olmadığı için yavaşlayın, bakın ve dinleyin, ardından durmadan geçin","Tam olarak durun, bakın ve dinleyin, ardından yalnızca rayları durmadan tamamen geçebileceğinizden eminseniz geçin","Otobüsün tüm rayları stop etmeden geçecek kadar momentumu olması için hızınızı koruyun","Yalnızca yolcuların yanı sıra plakart taşıyan tehlikeli madde de taşıyorsanız durun"],"explanation":"Otobüsler ve plakartlı tehlikeli madde araçları her demiryolu geçidinde durmalı, bakmalı ve dinlemeli; ancak rayları durmadan tamamen geçebilecekken geçmelidir."},"53":{"q":"Tam yüklü, 53 fit uzunluğunda bir çekici-römork kullanıyorsunuz ve kırsal bir iki şeritli yolda, kontrolsüz tek hatlı bir hemzemin geçide yaklaşıyorsunuz. Işık veya bariyer yok ve rayların ilerisini görüşünüz çalılıklar nedeniyle kısmen kapalı. Durmadan rayları tamamen geçemeyeceğiniz sürece geçişe asla başlamamanız gerektiğini biliyorsunuz. Geçişe başlamanın güvenli olup olmadığına karar verebilmek için, sizinki gibi bir aracın tek bir hattı tamamen boşaltması için yaklaşık ne kadar süre olması gerektiğini varsaymalısınız?","options":["Yaklaşık 3 saniye, çünkü bu kabaca otoyol hızındaki tepki sürenizdir","Şu anda görünürde tren olmadığı sürece tam süre önemli değildir","Yaklaşık 6 saniye, 55 mil/saatten toplam durma sürenizle aynı","En az 14 saniye"],"explanation":"Tipik bir çekici-römork tek bir demiryolu rayını tamamen geçmek için en az 14 saniyeye ihtiyaç duyar, bu yüzden geçişe başlamadan önce bu kadar zaman bırakın."},"54":{"q":"Öğleden sonra olmasına rağmen şiddetli bir sağanak görüşü azalttı ve gökyüzü koyu griye döndü. Yolu ve diğer araçları sürmeye yetecek kadar hâlâ görebiliyorsunuz, bu yüzden farların şu an gerçekten gerekli olup olmadığını merak ediyorsunuz. Bu durumda KISA huzme farlarınızı açmak neden EN İYİ harekettir?","options":["Farların yanması alternatörü yük altında tutar ve bu da yağmurda uzun, yavaş bir sürüş sırasında aküyü şarj etmeye yardımcı olur","Farlar yağmuru deler ve önünüzdeki yolu kişisel olarak ne kadar uzağa görebildiğinizi belirgin şekilde artırır","Siz hâlâ yeterince görebiliyor olsanız bile, farlar loş ve yağmurlu ışıkta kamyonunuzun diğer sürücüler tarafından çok daha kolay görülmesini sağlar","Yağmurda uzun huzmeye geçmek en fazla ışığı öne verir ve karşıdan gelen trafiğin sizi fark etmesinin en kesin yoludur"],"explanation":"Loş veya yağmurlu ışıkta farların asıl amacı, siz yeterince görebilseniz bile kamyonunuzu diğer sürücülere görünür kılmaktır."},"55":{"q":"Sefer öncesi kontrolünüz sırasında çelik boru yüklü bir açık platform (flatbed) etrafında dolaşırken, kabinin arkasında römorkun ön kısmına monte edilmiş yük koruma duvarını (\"headache rack\", baş ağrısı rafı) kontrol etmek için duruyorsunuz. Yeni bir sürücü, şirketin neden bu parça sağlam olmadan kamyonun yola çıkmasına izin vermediğini soruyor. Bu cihazın sağladığı GÜVENLİK amacını en iyi hangi cevap açıklar?","options":["Ön lastiklerin savurduğu çakıl ve yol molozunun yüke çarpmasını engeller","Yükü geniş/aşırı boyutlu olarak işaretler, böylece arkadan gelen trafik güvenli mesafe bırakır","Bağlama zincirlerinin yasal sabitleme için bağlanması gereken arka çapa noktası olarak hizmet eder","Sert frende veya kazada yükün öne kayıp kabine girmesini durdurarak sürücüyü korur"],"explanation":"Başlık panosu (koruma kafesi), sert frende veya kazada yükün öne kayıp kabine girerek sürücüyü yaralamasını önleyen bir bariyerdir."},"56":{"q":"Sabahın erken saatleri ve uzun bir sefere çıkmadan önce çekici-römork aracınızın çevre kontrolünü yapıyorsunuz. Arka aksları kontrol ederken çift (ikiz) lastiklere bakmak için çömeliyorsunuz. Aşağıdaki gözlemlerden hangisi, aracı yasal ve güvenli şekilde kullanabilmeniz için seferden çekmenizi gerektirir?","options":["Direksiyon (ön) aksı lastiklerinin her birinin diş derinliği 5/32 inçtir","Arka akstaki iki ikiz lastik birbirine bastırılmış ve temas halindedir","Arka akstaki dört lastiğin tamamı aynı ebat ve aynı markadır","Arka çekiş lastiklerinin diş derinliği 3/32 inçtir"],"explanation":"İkiz lastikler asla birbirine değmemelidir; temas, ısı oluşturan ve patlamaya yol açabilen uyumsuzluğa veya düşük hava basıncına işaret eder."},"58":{"q":"300 millik bir sefere çıkmadan önce çekici-römork aracınızın sefer öncesi kontrolünü tamamlıyorsunuz. Amiriniz telsizden, yol kenarındaki bir memurun kamyonunuzu federal olarak zorunlu acil durum ekipmanı açısından denetleyeceğini bildiriyor. Kabine baktığınızda, her zamanki ekipmanınızdan bir parçanın eksik olduğunu fark edip endişelenmeye başlıyorsunuz. Bu denetimi geçmek için yasal olarak araçta bulundurmak zorunda OLMADIĞINIZ parça aşağıdakilerden hangisidir?","options":["Uygun şekilde dolu ve doğru sınıfta bir yangın söndürücü","Araçta saklanan, şişirilmiş bir yedek lastik","Üç adet kırmızı reflektörlü uyarı üçgeninden oluşan bir takım","Aracın devre kesicisi yoksa, yedek elektrik sigortaları"],"explanation":"Zorunlu acil durum ekipmanı yangın söndürücü, yedek sigortalar ve uyarı üçgenleridir; yedek lastik zorunlu değildir."},"59":{"q":"Hava donma noktasının hemen altında ve yüklü bir römorku köprü tablası üzerindeki hafif bir yokuşta çekiyorsunuz. Arka çeker tekerleklerin patinaj yapmaya başladığını ve çekicinin arkasının sola savrulduğunu hissediyorsunuz. Aracı tekrar kontrol altına almak için, hangi hareket kaymayı düzeltmek yerine DAHA KÖTÜ hale getirir?","options":["Patinaj yapan çeker tekerlekleri zorla hizaya sokmak için gaza daha sert basmak","Gaz pedalını bırakıp debriyaja basarak çeker tekerleklerin yavaşlamasını sağlamak","Çekiciyi şeritte gitmesini istediğiniz yöne doğru direksiyon kırmak","Römork düzelmeye başladığında ters direksiyon kırmaya hazır olmak"],"explanation":"Çekiş tekerleği kaymasında güç vermeyi kesin: gaz pedalını bırakın ve debriyaja basın ki çekiş tekerlekleri yeniden tutuş kazansın."},"60":{"q":"Saat sabahın 5:00'i ve uzun bir sefere çıkmak üzeresiniz. Bir iş arkadaşınız, şirketin geçen hafta zaten bir muayene tamircisine para ödediğini, bu yüzden bu sabahki kendi sefer öncesi kontrolünüzün aslında sadece sizi otoyolda yolda bırakabilecek bir şeyi yakalamakla ilgili olduğunu söylüyor. Teksas'ın HER seferden önce kendi sefer öncesi muayenenizi yapmanızı neden zorunlu kıldığını EN İYİ açıklayan ifade hangisidir?","options":["Tek meşru amacı, yolda bir kazaya yol açmadan önce mekanik güvenlik kusurlarını tespit etmektir.","Esasen, eyalet ve federal kurallara uyumlu kalmak için kayda geçirmeniz gereken yasal bir formalitedir.","Asıl değeri, şirkete zaman ve para kaybettiren yol kenarı arızalarını önlemesidir.","Tüm bu amaçlara birlikte hizmet eder: güvenlik kusurlarını bulmak, yasal görevinizi yerine getirmek ve arızaları önlemek."],"explanation":"Sefer öncesi muayene üç amaca birden hizmet eder: güvenlik kusurlarını bulmak, sürücü olarak yasal görevinizi yerine getirmek ve maliyetli arızaları önlemek."},"61":{"q":"Yüklü bir çekici-dorse ile otoyol hızında giderken bir araba aniden önünüze geçip sert fren yapıyor ve şeridinizin tam ortasında bir tehlike bırakıyor; sağınızdaki banket ise açık. Zamanında durmanız mümkün değil. Bu acil durumda yalnızca sert fren yapmanın neden her zaman en güvenli tepki olmadığını EN İYİ açıklayan ifade hangisidir?","options":["Bir tehlikenin etrafından direksiyonla geçmek çoğu zaman durmak için gereken mesafeden daha kısa sürede yapılabilir; bu nedenle açık bankete doğru karşı direksiyon kırmak, durmanın yetmeyeceği durumda kazayı önleyebilir.","Acil durumda durmak asla caiz değildir, çünkü kanunun direksiyon için kullanmanızı zorunlu kıldığı tepki süresini boşa harcar.","Sert frenden esas olarak kaçınılmalıdır çünkü frenler herhangi bir panik freninin ilk birkaç saniyesinde aşırı ısınıp etkisini yitirir.","Dorseniz yüklü olduğu için 55 mil/saat hızda toplam durma mesafeniz yaklaşık 60 fite düşer, dolayısıyla bu mesafede fren yapmak anlamsızdır."],"explanation":"Bir tehlikenin etrafından direksiyonla dönmek, durmak için gereken mesafeden çok daha kısa sürer; bu yüzden boş banket yönüne kontra direksiyon kırmak, fren yetmediğinde kazayı önleyebilir."},"62":{"q":"Kuru bir otoyolda yüklü bir çekici-römork ile 55 mil/saat hızla giderken, çok ileride şeridinizde bir araba aniden durur. Tehlikenin ilk göründüğü andan kamyonunuzun tamamen durduğu ana kadar, toplam durma mesafeniz birbiri ardına gerçekleşen üç ayrı bölümden oluşur. Bu üç bölümü ilkinden sonuncusuna doğru doğru kronolojik sırayla hangi seçenek listeler?","options":["Tepki mesafesi, sonra frenleme mesafesi, sonra algılama mesafesi","Algılama mesafesi, sonra tepki mesafesi, sonra frenleme mesafesi","Frenleme mesafesi, sonra tepki mesafesi, sonra algılama mesafesi","Algılama mesafesi, sonra frenleme mesafesi, sonra tepki mesafesi"],"explanation":"Toplam durma mesafesi sırayla gerçekleşir: önce tehlikeyi algılarsınız, sonra tepki verip ayağınızı frene götürürsünüz, ardından frenler aracı yavaşlatır."},"65":{"q":"Yüklü bir römorkla uzun ve dik bir dağ yokuşundan iniyorsunuz. İnişin ortasında fren pedalına basıyorsunuz ve pedal neredeyse hiç direnç göstermeden tabana kadar gidiyor -- servis frenleriniz arıza yaptı ve kamyon hızlanıyor. Yaklaşık yarım mil ileride bir kaçış rampası (acil durdurma şeridi) işaretli. Yapılacak EN İYİ tek hareket nedir?","options":["Vites kutusunu boşa alın, böylece motor sizi tutmaz ve kamyonun kontrollü bir şekilde durana kadar serbestçe ilerlemesine izin verin","Yokuştan inmeye devam ederken basıncı yeniden oluşturmaya çalışmak için fren pedalına hızlı ve tekrar tekrar basın","İleride bulunan, frenleri arızalanmış bir aracı durdurmak için inşa edilmiş kaçış rampasına yönelin","Sürücü kapısını açın ve kamyon yokuşun dibine ulaşmadan önce dışarı atlamaya hazırlanın"],"explanation":"Kaçış rampaları, inişte frenleri arızalanan ağır bir aracı güvenle durdurmak için yapılmıştır, bu yüzden mevcut olduğunda kullanın."},"66":{"q":"Son on dakikadır aralıksız yağmur yağıyor ve yüklü bir çekici-dorse setini düzgün, iyi asfaltlanmış bir eyaletler arası otoyolda saatte 60 mil hızla sürüyorsunuz. Direksiyonun hafiflediğini ve küçük bir direksiyon düzeltmesi yaptığınızda kamyonun tepki vermediğini fark ediyorsunuz. Bu yol tutuşu kaybından EN ÇOK hangi etken sorumludur?","options":["Yol yüzeyi kuru olduğu için ön lastikler sıcak asfalt üzerindeki tutuşunu kaybetmiştir","Yolda su var ve çok hızlı sürüyorsunuz, bu yüzden lastikler bir su filmi üzerinde kayıyor","Çok yavaş sürüyorsunuz, bu da lastiklerin birikmiş suya gömülmesine yol açıyor","Lastikleriniz sıfır ve derin diş sırtı çok fazla suyu uzaklaştırıyor"],"explanation":"Su kayması, yoldaki su ile aşırı hızın birleşip lastikleri kaldırarak asfalt yerine bir su filmi üzerinde kaymalarına neden olmasıyla oluşur."},"67":{"q":"Sıcak bir yaz öğleden sonrası ve otoyolda 120 mil gittikten sonra bir dinlenme alanına yeni girdiniz. Aracı dolaşırken yola devam etmeden önce çeker aks lastiklerinizin doğru basınçta olduğundan emin olmak istiyorsunuz. Hangi yöntem size doğru ve güvenilir bir basınç okuması verir?","options":["Her lastiğe bir lastik tokmağı veya çekiçle vurup sese ve sekmeye göre basıncı tahmin edin","Lastikler otoyoldan hâlâ sıcakken hemen bir manometreyle basıncı ölçün, çünkü gerçek çalışma basıncı budur","Önce lastiklerin soğumasını bekleyin, sonra her birini doğru kalibre edilmiş bir lastik basınç manometresiyle ölçün","Her lastiğin alt kısmında ne kadar şiştiğine dikkatlice bakıp diğerleriyle karşılaştırın"],"explanation":"Lastik basıncını yalnızca lastikler soğuduktan sonra doğru kalibre edilmiş bir manometreyle ölçün, çünkü sürüş ısısı basıncı artırarak yanlış yüksek değer verir."},"68":{"q":"Yüklü çekici-dorseyle yoğun bir otoyola katılıyorsunuz. Bir binek araç sağ arkanıza iyice sokulup aynalarınızdan kayboluyor, başka bir araç da tam sol çamurluğunuzun yanında ilerliyor. Bir iş arkadaşınız size en çok 'No-Zone' (kör nokta bölgesi) konusunda dikkatli olmanızı söylemişti. Bu durumda yönetmeniz gereken No-Zone nedir?","options":["Önünüzde tutmanız gereken, 55 mil/saatte yaklaşık 419 fit olan mesafe payı","Aracınızın çevresindeki, diğer araçların görüş alanınızdan kaybolabildiği büyük kör nokta bölgeleri","Uyarı üçgenlerini koymak için duramayacağınız, sağ kaldırım boyunca uzanan park yasağı bölgesi","Kamyonların giremediği en soldaki çok yolcu taşıyan araç şeridi"],"explanation":"No-Zone, kamyonun dört bir yanını çevreleyen ve diğer araçların görüş alanından kaybolabildiği büyük kör nokta alanlarını ifade eder."},"69":{"q":"Kalabalık bir TIR park alanında yalnızsınız ve çekici-dorsenizi sağınızdaki bir duvar boyunca dar bir alana geri geri sokmanız gerekiyor. Dorseniz boş, park alanı yaya trafiğiyle yoğun ve sağ arka tarafınızın gerisindeki bölgeyi net göremiyorsunuz. Bu geri manevrayı tamamlamanın en güvenli yolu nedir?","options":["Duvar ön camdan görünür kalsın diye sağ (kör) tarafınıza doğru geri gidin ve yavaşça ilerleyin","Boşluk varken hızlıca geri gidin, çünkü şeritte oyalanmak yayalar için daha fazla risk yaratır","Yalnızca sağ yan aynanıza güvenin ve inmeyin, çünkü yoğun bir alanda durup bakmak zaman kaybıdır","Gerekirse sol (sürücü) tarafınıza doğru geri gidebilecek şekilde yeniden konumlanın ve kör alanınızı gözetlemesi için bir yardımcı veya işaretçi kullanın"],"explanation":"Mümkün olduğunda sürücü (sol) tarafına doğru geri gidin, böylece dorse boyunca doğrudan görebilirsiniz; kör alanı izlemesi için bir yardımcı veya gözcü kullanın."},"70":{"q":"İyi ve kuru koşullarda yüklü bir çekici-römork ile 55 mil/saat hızla giderken, şeridinizde sadece birkaç kamyon boyu ileride aniden arızalı bir araç beliriyor — yaklaşık 419 fitlik toplam durma mesafenizden çok daha yakın. Yan şerit boş. Hangi eylem size kazadan kaçınmak için EN İYİ şansı verir?","options":["Boş şeride geçerek engelin etrafından dolaşın, çünkü bir engelden direksiyonla kaçınmak genellikle tam durmak için gerekenden daha kısa mesafede mümkündür","Olabildiğince sert fren yapın ve tekerlekleri kilitleyin, çünkü maksimum frenleme her zaman en güvenli acil durum tepkisidir","Hızınızı koruyup düz bir şekilde içinden geçin, kamyonun kütlesinin engeli iterek yana atacağına güvenin","Şeridinizde kalıp hafifçe fren yapın, çünkü 55 mil/saatte 419 fitlik durma mesafeniz sizi zamanında durduracaktır"],"explanation":"Bir engelin etrafından dönmek genellikle tam durmak için gereken mesafeden daha kısa sürer, bu yüzden tehlikeden kaçınmak için boş şeridi kullanın."},"71":{"q":"Sağa dönmeniz gereken yoğun bir kavşağa yaklaşıyorsunuz ve arkanızda bir sıra araç var. Niyetinizi güvenli bir şekilde bildirmek ve diğer sürücülere tepki vermeleri için en fazla zamanı tanımak amacıyla sinyal lambanızı ne zaman yakmalısınız?","options":["Önce birkaç kez frene basın, ardından erken verilen bir sinyalin arkadakilerin kafasını karıştırmaması için tam dönüşe başlarken sinyal verin","Dönüşten çok önce sinyali yakın ve dönüş tamamlanana kadar sinyali açık tutun","Yalnızca yavaşladıktan ve kavşağın boş olduğunu doğruladıktan sonra, çok erken sinyal vermemek için","Manevranızı arkanızdaki sürücülere onaylamak için dönüşü tamamladıktan hemen sonra sinyal verin"],"explanation":"Dönüşten çok önce erken sinyal verin ve dönüş tamamen bitene kadar sinyali açık tutun ki diğer sürücüler tepki vermek için en fazla zamana sahip olsun."},"72":{"q":"Hava donma noktasının hemen altında ve hafif bir dondurucu çiseleme otoyolu ıslak ve parlak gösteriyor. Yüklü kamyonunuzda bir motor freni (retarder) bulunuyor. Kademeli olarak yavaşlamanız gerekebilecek bir yol kesimine yaklaşırken, bu koşullarda retarder'ı yönetmenin EN GÜVENLİ yolu nedir?","options":["Kötü havada servis frenlerinin aşınmasını azalttığı için retarder'ı tam devrede bırakın","Retarder'ı KAPATIN, çünkü kaygan zeminde çeker tekerleklerin tutuşunu kaybetmesine ve kaymaya neden olabilir","Fren pedalına basmadan yavaşlayabilmek için retarder'ı en yüksek kademede tutun","Retarder'ı yalnızca hızınız 40 mil/saatin üzerine çıktığında kullanın, altına düşünce kapatın"],"explanation":"Islak, buzlu veya kaygan yollarda retarderı kapatın çünkü yalnızca çekiş tekerleklerini frenler ve onların tutuşu kaybedip kaymasına neden olabilir."},"73":{"q":"Tam yüklü bir römork çekiyorsunuz ve dağlarda uzun, dik bir yokuşa tırmanmaya başladınız. Çekiciniz zorlanmaya başlıyor, motor devri düşüyor ve hızınız hızla azalıyor. Tırmanışta güvenli sürüşü sürdüren ve en fazla motor gücünü koruyan hangi davranıştır?","options":["Vitesi overdrive'da tutup hızı geri kazanmak için gaz pedalına sonuna kadar basmak","Motorun güç aralığında kalması ve yükü dengeli şekilde çekmesi için daha düşük bir vitese geçmek","Vitesi boşa alıp momentumun sizi yokuşun tepesinden aşırmasına izin vermek","Mevcut vitesi koruyup aracı kontrol altında tutmak için servis frenlerine hafifçe basmak"],"explanation":"Uzun ve dik bir yokuşta, motor devrini güç aralığında tutmak için alt vitese geçin ki yükü düzenli şekilde çeksin."},"74":{"q":"Kuru bir kırsal otoyolda boş olarak 30 mil/saat hızla gidiyorsunuz ve kendinize frenlemek için yeterli mesafe bırakmayı öğrendiniz. Öndeki trafik açılıyor ve 60 mil/saate hızlanıyorsunuz. 30 mil/saatte ihtiyaç duyduğunuz fren mesafesiyle karşılaştırıldığında, şimdi 60 mil/saatte yalnızca fren mesafesinin nasıl olmasını beklemelisiniz?","options":["Hızınızı iki katına çıkardığınız için yalnızca iki katına çıkar -- yani iki kat mesafe bırakmak yeterlidir","Yaklaşık dört katına çıkar, çünkü fren mesafesi hızın karesiyle orantılı olarak artar","Yaklaşık aynı kalır, çünkü boş bir kamyon yüklü olandan daha kısa mesafede durur","Yaklaşık yarısı kadar artar, çünkü toplam durma mesafesi tepki mesafesini de içerir"],"explanation":"Fren mesafesi hızın karesiyle artar, bu nedenle hızı iki katına çıkarmak fren mesafesini yaklaşık dört katına çıkarır."},"75":{"q":"Uzun bir gece yolculuğunda saat gece 02:00 ve gözlerinizin ağırlaştığını, şerit içinde savrulduğunuzu ve son birkaç kilometreyi hatırlayamadığınızı fark ediyorsunuz. Kayıt defterinizde hâlâ birkaç saat yasal sürüş süreniz var. Bu yorgunlukla başa çıkmanın TEK gerçekten etkili yolu hangisidir?","options":["Camı indirip yüzünüze soğuk hava gelmesini sağlayarak uyanık kalmak","Büyük bir kahve içip, hâlâ saatiniz varken yolculuğu bitirmek için devam etmek","Güvenli bir yerde otoyoldan çıkıp devam etmeden önce dinlenmek veya uyumak için durmak","Radyoyu açıp kabin sıcaklığını düşürerek kendinizi uyanık tutmak"],"explanation":"Uyuşukluğun tek kesin çözümü durup dinlenmek veya uyumaktır, çünkü başka hiçbir şey uyanıklığı gerçekten geri getirmez."},"77":{"q":"Yüklü bir çekici-dorse ile dört şeritli bir otoyolda ilerlerken turuncu levhalar ileride bir çalışma bölgesi olduğunu uyarıyor. Bölgeye girerken hız sınırı düşüyor ve sağ seyir şeridinin yakınında bir işaretçi ile birkaç işçi görünüyor. Trafik rahat akıyor ve hemen arkanızda kimse yok. Bölgeden geçerken EN İYİ seçim hangisidir?","options":["Trafik aktığı için otoyol hızınızı koruyun; bölgeyi hızlıca geçmek işçilerin yanında geçirdiğiniz süreyi azaltır","Hızınızı çalışma bölgesi için belirlenen sınıra düşürün, takip mesafenizi artırın ve şeride girebilecek işçilere karşı tetikte olun","Mevcut hızınızla sol şeride geçin ve koşullar değişmeden işaretçiyi geçmek için hızlanın","Diğer sürücülerin aranıza girip işçilerin yanında fren yapmanıza neden olmaması için öndeki araca yakın durun"],"explanation":"Çalışma alanında belirtilen hız sınırına yavaşlayın, takip mesafenizi artırın ve şeride giren işçilere dikkat ederek yeterli durma mesafesi bırakın."},"78":{"q":"Sefer öncesi kontrolde, hafif ama hacimli sandıkların kapalı kasa römorkunuza yüklenmesini denetliyorsunuz. Hepsinin sığması için ekip onları yüksek istifliyor ve ağırlığın çoğu, zemine alçak şekilde yayılmak yerine römorkun üst kısmında kalıyor. Toplam yük ağırlığı aks sınırlarınızın oldukça altında ve yük yanlardan dengeli. Yola çıkıp ilk otoyol giriş rampası virajına yaklaşırken, yükün bu şekilde istiflenmesinin EN önemli etkisi nedir?","options":["Ağırlık ortalandığı ve aks sınırları içinde olduğu için römork, alçak istiflenmiş bir yükten aslında daha kararlı viraj alır.","Yük ağırlığı yasal aks sınırları içinde olduğundan, yüksek istifin yol tutuşa gerçek bir etkisi yoktur.","Yüksek ağırlık merkezi, düz yolda yük güvenli hissettirse bile, virajda aracın devrilme olasılığını çok daha fazla artırır.","Asıl risk çok daha uzun bir durma mesafesidir, çünkü yüksek istiflenen ağırlık fren tutuşunu azaltır."],"explanation":"Hafif ve hacimli yükü yüksek istiflemek ağırlık merkezini yükseltir ve bu da virajda devrilme riskini büyük ölçüde artırır."},"79":{"q":"Sefer öncesi kontrolünüz sırasında, açık (flatbed) dorseniz üzerinde 8.000 lb ağırlığında tek bir çelik bobin taşıyorsunuz. Yükünüzün yasal olarak emniyete alındığını doğrulamak için bağlama zincirlerinizi ve gerdirme aparatlarınızı kontrol etmeye başlıyorsunuz. Çelik bobinin takozlanması ve desteklenmesi gerekliliğinin yanı sıra, bu 8.000 lb'lik yük için bağlama elemanlarınızın sağlaması gereken EN AZ birleşik (toplam) çalışma yük limitini hangi ifade doğru şekilde tanımlar?","options":["Bağlama elemanlarının birleşik çalışma yük limiti, yükün tam ağırlığına eşit olmalıdır, yani en az 8.000 lb.","Bağlama elemanlarının birleşik çalışma yük limiti, yük ağırlığının en az dörtte biri kadar olmalıdır, yani en az 2.000 lb.","Bağlama elemanlarının birleşik çalışma yük limiti, yük ağırlığının en az iki katı olmalıdır, yani en az 16.000 lb.","Bağlama elemanlarının birleşik çalışma yük limiti, yük ağırlığının en az yarısı kadar olmalıdır, yani en az 4.000 lb."],"explanation":"Tüm bağlama elemanlarının toplam çalışma yük limiti, yükün ağırlığının en az yarısı kadar olmalıdır."},"80":{"q":"Çekici-römork aracınızla şehir kavşağında dar bir sağ dönüşe yaklaşıyorsunuz. Römorkun, çekicinin izlediği yolun içinden geçeceğini (iz sapması) biliyorsunuz ve arka tekerleklerin kaldırıma çıkmasından endişeleniyorsunuz. Römorkun arkasının kaldırıma çarpmasını önlemek için bu sağ dönüşü yapmanın en güvenli yolu nedir?","options":["Dönüşe aracın önünü geniş şekilde SOLA çekerek başlamak, sonra keskin biçimde sağa kırarak römorkun kaldırımdan kurtulmasını sağlamak","Dönüşü TAMAMLARKEN geniş dönmek ve aracınızın arkasını kaldırıma yakın tutmak, böylece diğer sürücüler sağınızdan sıkışıp giremesin","Dönüşe sol şeritten başlamak ve kavşağı tıkadığınız süreyi kısaltmak için hızlanarak geçmek","Sağda kalmak ve yalnızca kesinlikle gerekliyse sola doğru geniş dönmek, trafiğin sağınızdan geçebileceğini kabul ederek"],"explanation":"Sağa dönüşü tamamlarken aracın arkasını kaldırıma yakın tutarak geniş dönün ki kimse sağınızdan sıkışıp giremesin."},"81":{"q":"Tam yüklü bir römork ile bir eyalet karayolunda ilerliyorsunuz ve geniş bir viraja yaklaşıyorsunuz. Yol kenarındaki bir levhada 'Viraj — 45 MPH' yazıyor. Kamyonunuz ağır ve yüksek gövdeli, ancak zemin kuru ve hava açık. Bu levhada belirtilen 45 MPH viraj hızını nasıl değerlendirmeniz gerektiğini EN İYİ hangi ifade açıklar?","options":["45 MPH'i iyi koşullardaki binek otomobiller için bir üst sınır olarak değerlendirin ve yüklü, yüksek gövdeli kamyonunuzun devrilmeyi önlemek için daha düşük bir hıza ihtiyacı olduğundan bunun altına düşün.","45 MPH'i sizinki gibi yüklü ağır kamyonlar için özel olarak hesaplanmış hız olarak değerlendirin, böylece virajı güvenle tam 45 MPH ile alabilirsiniz.","Zemin kuru ve hava açık olduğundan, bir pay ekleyip virajı 45 MPH'in biraz üzerinde alabilirsiniz.","Belirtilen hız yalnızca geceleri geçerlidir, bu yüzden açık gündüz havasında onu görmezden gelip virajda karayolu hızınızı koruyabilirsiniz."],"explanation":"Levhadaki viraj hızları iyi koşullardaki otomobiller için belirlenmiştir, bu yüzden yüklü ve yüksek bir kamyon devrilmeyi önlemek için levhadaki hızın altına inmelidir."},"82":{"q":"Tamamen yüklü bir römorku uzun ve dik bir dağ yokuşundan aşağı indiriyorsunuz. İnişin ortasında, tüm iniş boyunca frene düzenli olarak bastığınız halde fren pedalının yumuşadığını ve kamyonun yavaş yavaş hızlandığını fark ediyorsunuz. Bu fren gücü kaybının EN olası nedeni aşağıdakilerden hangisidir?","options":["İnişe yeni başladığınız için frenler hâlâ soğuk, bu yüzden henüz tam olarak tutmuyorlar","Frenler sürekli basılmaktan dolayı aşırı ısındı ve bu da frenlerin sönümlenmesine (fade) ve durdurma gücünü kaybetmesine neden oldu","Römork çok hafif yüklü, bu yüzden fren pabuçlarını kampanalara bastıracak yeterli ağırlık yok","Fren pabuçları yepyeni ve yokuşta aracı tutabilmeleri için önce alıştırılmaları (rodaj) gerekiyor"],"explanation":"Uzun bir inişte frenlere sürekli basmak onları aşırı ısıtarak fren sönmesine ve durma gücü kaybına yol açar."},"83":{"q":"Yüklü hâlde ıslak, dört şeritli bir karayolunda ilerliyorsunuz; aniden bir otomobil önünüze girip sert fren yapıyor. Gösterge panelindeki ABS lambası sönük, yani sistem çalışıyor. Fren pedalına sonuna kadar bastığınızda ABS devreye giriyor. Bu sert fren sırasında ABS'ten beklemeniz gereken ANA fayda nedir?","options":["ABS'siz bir kamyona göre belirgin biçimde daha kısa mesafede durmanızı garanti eder","Frenleri otomatik olarak pompalar, böylece kuru zeminde artık kesik kesik (stab) fren yapmanıza gerek kalmaz","Tekerleklerin kilitlenmesini önler, böylece sert fren yaparken direksiyon hâkimiyetini koruyup şeridinizde kalabilirsiniz","Bilgisayar frenleri izlediği için araç öncesi kontrolde fren ayarını denetlemeyi atlamanıza olanak tanır"],"explanation":"ABS, sert frenleme sırasında tekerleklerin kilitlenmesini önler, böylece şeridinizde kalmak veya tehlikeden kaçınmak için direksiyon kontrolünü korursunuz."},"84":{"q":"Son yükünüzü yeni boşalttınız ve şimdi boş römorku ıslak, çift şeritli bir yolda depoya geri götürüyorsunuz. Önünüzdeki bir otomobil sert fren yapıyor ve hızla durmanız gerekiyor. Bugün erken saatlerde tam yüklüyken olduğunuza kıyasla, bu durumda boş aracınızdan ne beklemelisiniz?","options":["Üzerine bastıran yük ağırlığı olmadığı için lastikler yola daha iyi tutunur, bu yüzden yüklüyken olduğunuzdan her zaman daha kısa mesafede durursunuz.","Boş bir kamyon tıpkı yüklü bir kamyon gibi davranır, bu yüzden durma mesafeniz her iki durumda da değişmez.","Çok az ağırlık olduğu için tekerlekler kilitlenemez veya kayamaz, bu yüzden sert fren yapmak artık tamamen güvenlidir.","Boş kamyonun yol tutuşu daha azdır ve zıplayabilir, bu yüzden yüklüyken olduğundan aslında daha uzun mesafede durmanız gerekebilir."],"explanation":"Boş bir kamyonun yol tutuşu daha azdır ve sıçrama eğilimindedir, bu yüzden yüklüyken olduğundan daha uzun mesafede durabilir."},"85":{"q":"Gün batımından yaklaşık bir saat önce, iki şeritli bir karayoluna çıktığınızda hafif bir yağmur başlıyor. Görüş hâlâ oldukça iyi ve farlar olmadan yolu net görebiliyorsunuz, ama karşıdan gelen araçları gri gökyüzüne karşı seçmek gittikçe zorlaşıyor. Bu durumda farlarınız için en iyi uygulama nedir?","options":["Kapalı bırakın, çünkü farları açmak yalnızca hava tamamen karardığında ve önünüzdeki yolu göremediğinizde gereklidir","Şimdi açın, çünkü alacakaranlıkta ve yağmur, sis veya diğer düşük ışık koşullarında diğer sürücülerin sizi görmesine yardımcı olurlar","Yalnızca uzun farları kullanın, çünkü yağmur ve azalan ışık mümkün olan en fazla ön aydınlatmaya ihtiyacınız olduğu anlamına gelir","Bölünmüş, yüksek hızlı bir karayoluna ulaşana kadar bekleyin, çünkü farlar esas olarak yüksek hızlarda gereklidir"],"explanation":"Alacakaranlıkta ve yağmur ya da siste farları açın, çünkü düşük ışıkta aracınızı diğer sürücülere görünür kılarlar."},"86":{"q":"Römorkunuzu dar bir yükleme rampasına geri geri sokuyorsunuz ve yolcu tarafındaki büyük dışbükey (kavisli) yardımcı aynaya bakıyorsunuz. Arka tamponunuzun yalnızca birkaç metre gerisinde park ettiğini bildiğiniz bir araba, bu aynada küçük ve uzakta görünüyor. Geri gitmeye devam etmeden önce, bu dışbükey aynanın size gösterdiği şey hakkında ne anlamanız gerekir?","options":["Size daha geniş bir görüş alanı sağlar, ancak içindeki nesneler gerçekte olduğundan daha küçük ve daha uzak görünür, bu yüzden o araba göründüğünden daha yakındır","Görüntüyü büyütür, bu yüzden nesneler gerçekte olduğundan daha büyük ve daha yakın görünür, yani o araba aslında göründüğünden daha uzaktadır","Nesnelerin gerçek boyutunu ve mesafesini gösterir, bu yüzden arabanın aynada göründüğü kadar geride olduğuna güvenebilirsiniz","Arızalıdır, çünkü düzgün ayarlanmış bir ayna yakındaki bir nesneyi asla küçük göstermez ve dışbükey aynalar zaten ticari araçlarda yasal değildir"],"explanation":"Dışbükey ayna daha geniş bir görüş alanı sağlar ama nesneleri daha küçük ve daha uzak gösterir, bu yüzden aslında göründüklerinden daha yakındırlar."},"87":{"q":"Yüklü bir çekici-dorse ile otoyol hızında giderken, yaklaşık 12-15 saniye ileride, dörtlü flaşörleri yanan ve sağ şeridi kısmen kapatan arızalı bir aracı fark ediyorsunuz. Çevrenizdeki trafik hâlâ normal akıyor ve henüz acil bir durum yok. İLK yapmanız gereken ne olmalı?","options":["Aracın, şeridinize tam olarak ne kadar girdiğini kesin biçimde değerlendirebileceğiniz kadar yaklaşmasına dek hızınızı ve konumunuzu koruyun","Şimdiden tepki vermeye hazırlanmaya başlayın -- gaz pedalından ayağınızı çekin, aynalarınızı kontrol edin ve durum acil hâle gelmeden yumuşakça ayarlama yapabilmek için bir kaçış yolu planlayın","Mümkün olan en fazla hızı hemen düşürmek için derhal sert, kontrollü kesik (stab) fren uygulayın","Diğer trafik tepki vermeden bölgeyi terk etmek için hemen sol şeride geçip hızlanın"],"explanation":"Bir tehlikeyi erken görmek tepki vermek için zaman kazandırır, bu yüzden acil duruma dönüşmeden önce gazdan ayağınızı çekin, aynaları kontrol edin ve bir kaçış yolu planlayın."},"88":{"q":"Şiddetli sağanak yağış sırasında eyaletler arası bir otoyolda boş bir römorkla saatte 55 mil hızla gidiyorsunuz. Direksiyonun hafiflediğini ve kamyonun yüzüyormuş gibi olmaya başladığını, ön lastiklerin artık yolu tam olarak izlemediğini hissediyorsunuz. Su kızağı (hidroplaning) yapmaya başladığınızı fark ediyorsunuz. Tutuşu güvenli bir şekilde yeniden kazanmak için EN İYİ şansı hangi hareket verir?","options":["Hızı çabucak düşürmek ve lastikleri zemine geri bastırmak için fren pedalına sertçe basın","Ön lastiklerin daha pürüzlü yüzeye tutunması için direksiyonu sert bir şekilde banket yönüne çevirin","Ayağınızı gaz pedalından çekin, direksiyonu düz tutun ve lastikler tekrar tutana kadar kamyonun yavaşlamasına izin verin","Sert bir şekilde vites küçültün ve hızı mümkün olduğunca çabuk atmak için motor frenini kullanın"],"explanation":"Su kızağında lastikler yolla teması kaybeder; bu yüzden gaz pedalından ayağınızı çekin ve direksiyonu düz tutun, lastikler yavaşlayıp tekrar tutana kadar."},"89":{"q":"Yüklü çekici-römork aracınızla su basmış alçak bir geçitten yavaşça geçtiniz ve su, tekerlek göbeklerini örtecek kadar yükseldi. Yol hızına çıkarken frene hafifçe dokunuyorsunuz ve frenlerin zayıf ve düzensiz tuttuğunu hissediyorsunuz. Güvenli frenlemeyi geri kazanmanın EN İYİ yolu hangisidir?","options":["Bankete çekip devam etmeden önce fren kampanalarının havayla kurumasını beklemek","Suyu balatalardan dışarı atmak için fren pedalına birkaç kez sertçe basıp pompalamak","Vites küçültüp yalnızca motor freniyle yetinmek ve sonraki birkaç mil boyunca servis frenlerine hiç dokunmamak","Yavaş sürmeye devam ederek frenlere hafif ve sürekli basınç uygulayıp sürtünme ısısıyla kurutmak"],"explanation":"Islak frenleri yavaş sürerek ve hafif, sabit basınç uygulayarak kurutun; sürtünme ısısı suyu buharlaştırırken kontrolü korursunuz."},"90":{"q":"Kırsal, iki şeritli ve hız limiti 55 mil/saat olan bir karayolunda programın gerisinde kaldınız. Önünüzdeki araç yavaş ilerliyor ve sollamak istiyorsunuz. Aşağıdaki durumlardan hangisinde sollama denemesi EN AZ güvenli olur ve bu nedenle YAPMAMANIZ gerekir?","options":["Bir tepenin zirvesine yaklaşıyorsunuz ve karşı şeritte size doğru gelen bir araç olup olmadığını göremiyorsunuz","Yolun çeyrek milden fazla ileride boş olduğunu net şekilde görebildiğiniz, uzun, düz ve dümdüz bir kesimdesiniz","Sizin tarafınızda kesik sarı orta çizgi bulunan, ileri görüşün açık olduğu işaretli bir sollama bölgesine girdiniz","Karşı şeridin boş olduğunu görebiliyorsunuz ve karşıdan gelen trafik gelmeden çok önce kendi şeridinize dönmek için yeterli alanınız var"],"explanation":"İleriyi yeterince göremediğiniz yerlerde, örneğin tepe yokuşunun zirvesine yakın, asla sollama yapmayın; çünkü karşıdan gelen araçlar son ana kadar gizli kalır."},"91":{"q":"Yüklü bir çekici-römork ile kısa bir giriş rampasında ilerliyorsunuz. Solunuzdaki otoyol yaklaşık 100 km/s (60 mil/s) hızla akıyor ve ileride sağ şeritte iki araç arasında kullanılabilir bir boşluğun açıldığını görüyorsunuz. Hızlanma şeridinin sonuna geldiğinizde trafiğe girmenin EN GÜVENLİ yolu nedir?","options":["Rampanın sonunda neredeyse durana kadar yavaşlayıp çıkmadan önce çok büyük bir boşluk beklemek","Hızlanma şeridini kullanarak hızınızı trafik akışına yakın bir seviyeye çıkarmak ve ardından açık boşluğa yumuşak bir şekilde katılmak","Hızınızı düşük tutup şeride yavaşça dalmak, arkadaki araçları fren yapıp size yer açmaya zorlamak","Birleşmeden önce trafiği değerlendirmek için daha fazla zaman kazanmak amacıyla rampada yavaş ve sabit bir tempoda ilerlemek"],"explanation":"Hızlanma şeridini kullanarak trafik akışına yakın bir hıza çıkın, ardından bir boşluğa katılın ki diğer araçlarla hız farkı en az olsun."},"92":{"q":"Yüklü bir çekici-römork ile dört şeritli bölünmüş bir karayolunun sağ şeridinde giderken bir siren duyuyor ve aynalarınızda ışıkları yanıp sönen bir ambulansın hızla yaklaştığını görüyorsunuz. Trafik orta yoğunlukta ve sağınızda asfalt bir banket var. EN İYİ hareket hangisidir?","options":["Ambulansın yolunuzu öngörebilmesi ve sizi soldan geçebilmesi için şeridinizi ve hızınızı koruyun","Bir sonraki çıkışa ulaşana kadar ambulansın önünde kalmak için hızlanın, sonra karayolundan ayrılın","Sinyal verin, aracı sağ bankete yönlendirin ve yolu açmak için güvenli olduğunda aracınızı durdurun","Sağ şeridi ve banketi acil durum aracına açmak için sola, geçiş şeridine geçin"],"explanation":"Işıklı ve sirenli acil durum aracı yaklaştığında sinyal verin, sağ banket tarafına çekin ve güvenli olduğunda durarak yol verin ve geçiş açın."},"93":{"q":"Banketin üzerine çektikten sonra çekicinizin motor bölmesinde küçük bir elektrik yangını çıkar. Yangın söndürücünüzü kapar, rüzgarı arkanıza alacak şekilde konumlanır, pimi çeker ve hortumu yangına doğrultursunuz. PASS yöntemini doğru uygulayarak, kolu sıktıktan sonra yangını etkili biçimde söndürmek için yapmanız gereken son işlem nedir?","options":["Hortumu sabit tutup görünen alevlerin üst kısmına doğru, alevler sönene kadar doğrudan nişan almak","Söndürücüyü boşa harcamamak için duman görünür görünmez püskürtmeyi hemen durdurmak","Söndürücüyü yangının üzerinde dairesel hareketlerle döndürerek söndürme maddesini geniş bir alana yaymak","Hortumu yangının tabanına doğrultarak, yangın sönene kadar bir yandan diğer yana süpürür gibi hareket ettirmek"],"explanation":"PASS yönteminin son adımı, yakıtın yandığı yangının tabanına nispetle hortumu sağa sola süpürerek ateşi boğmak ve söndürmektir."},"94":{"q":"Kırsal, iki şeritli bir karayolunda ilerlerken başka bir sürücü yanınıza yaklaşıp el işaretiyle römork lastiklerinizden birinin yandığını bağırarak söylüyor. Bankete çekip frenleri kuruyor, yangın söndürücünüzü ve yol güvenlik kitinizi alıyorsunuz. Yanan lastiğe yaklaşırken bu yangını kontrol altına almak için EN uygun davranış hangisidir?","options":["Lastiği bolca suyla soğutun, çünkü bir lastik yangını yoğun ısı üretir ve söndürülmesi için sürekli soğutmaya ihtiyaç duyar","Kuru kimyasal (B:C sınıfı) yangın söndürücünüzü doğrudan alevlerin tabanına tutun ve tüp tamamen boşalana kadar orada tutun","Güvenli bir mesafeden kendi kendine sönmesini bekleyin, çünkü kauçuk yangınını boğmaya çalışmak yalnızca yeniden alevlenmesine yol açar","Alevler sönerken kasanın çökmemesi için lastiğe dikkatlice hava basın"],"explanation":"Lastik yangını lastikte yoğun ısı tutar; bu yüzden sürekli soğutma için bol suyla söndürün, yoksa yeniden alevlenir."},"95":{"q":"Hava donma noktasının hemen altında ve hafif bir yağmur yolu buz tabakasıyla kaplamaya başlıyor. Geniş bir virajda normal otoyol hızınızla giderken, çekici-römork aracınızın arka kısmı aniden kaymaya başlıyor ve römorkun kabini yana doğru ittiğini hissediyorsunuz. Kaymanın başladığı anı dürüstçe değerlendirirseniz, tek ve EN olası neden neydi?","options":["Ön dümen aksı lastikleriniz 2/32 inç asgari sınırına yakın aşınmıştı ve ilk önce onlar tutuşunu kaybetti","Donma noktasına yakın, kaygan yol koşulları için fazla hızlı gidiyordunuz","Virajda keskin düzeltmeler yerine yumuşak ve nazik direksiyon hareketleri kullandınız","Römorkunuz boş gidiyordu ve boş römorklar yola her zaman yüklü olanlardan daha iyi tutunur"],"explanation":"Çoğu kayma, koşullara göre çok hızlı sürmekten kaynaklanır; donma noktasına yakın kaygan yollar tutuşu azaltır ve normalde güvenli bir hız aşırı olur."},"96":{"q":"Hava donma noktasının hemen altında ve hafif bir yağmur yağıyor. Üç şeritli bir otoyolun orta şeridindesiniz ve arkanızdaki dorse hafiflemeye, yan şeride doğru kaymaya başlıyor. Aşağıdaki davranışlardan hangisi aracı kontrol altında tutup tam bir savrulmayı (kaymayı) önlemek için EN İYİ şansı verir?","options":["Sert şekilde fren yapıp pedalı sıkıca basılı tutarak hızı mümkün olduğunca çabuk düşürmek","Kaymayı durdurmak için direksiyonu hızlı ve keskin bir hareketle şeridinizin ortasına geri çevirmek","Gazdan ayağınızı çekip yol tutuşunu korumak için yumuşak, nazik direksiyon ve fren hareketleri yapmak","Mevcut hızınızı koruyup sert şekilde direksiyon kırmak, çünkü orta şeritte lastiklerin hâlâ tutuşu var"],"explanation":"Kaygan, donma noktasına yakın yollarda lastiklere binen yükü azaltın: gaz pedalından ayağınızı çekin ve tutuşu korumak için yumuşak, nazik direksiyon ve fren hareketleri yapın."},"97":{"q":"Temmuz sonunda öğleden sonra ve birkaç saattir sıcak asfaltta yüklü olarak yol alıyorsunuz. Bir dinlenme molasında, bu yolculukta lastiklerinizi her zamankinden daha sık kontrol etmeye karar veriyorsunuz. Bu koşullarda bunu yapmanın EN İYİ nedeni nedir?","options":["Sıcak zemin lastiklerin içindeki havayı soğutur, böylece lastikler basınç kaybeder ve hava basıncı düşük çalışır","Sıcaklık diş kauçuğunu yumuşatır ve yazın patlamanın asıl nedeni budur","Lastikler sıcakta fiziksel olarak büzülür ve yol temas alanını küçültür","Sıcaklık lastiklerin içindeki hava basıncını artırır ve bu da patlamaya yol açabilir"],"explanation":"Sıcak havada lastiklerin içindeki hava genleşir ve basınç yükselir; bu da patlamaya yol açabilir."},"98":{"q":"Kırsal iki şeritli bir karayolunda yük taşırken, hızınızı düşürüp kısa farlara geçmenize rağmen artık şerit çizgilerini ya da öndeki herhangi bir aracı göremeyeceğiniz kadar yoğun bir sis bankasına giriyorsunuz. Hızı daha da azaltmak güvenli bir yol görme yeteneğinizi geri getirmedi. En güvenli hareket nedir?","options":["Sisin içinden daha fazla ışık geçirmek için uzun farlara geçip adım adım ilerlemeye devam etmek","Şeridinizde neredeyse duracak kadar yavaşlayıp dörtlü flaşörleri yakmak ve yavaşça ilerlemeye devam etmek","Yoldan tamamen çıkmak, trafikten iyice uzaklaşmak, farlarınızı ve flaşörlerinizi yakmak ve sisin dağılmasını beklemek","Yavaş ve sabit bir hızda kalıp şeridinizde kalmak için öndeki aracın arka stop lambalarını takip etmek"],"explanation":"Sis, düşük hızda bile güvenli yolu göremeyecek kadar yoğunsa yoldan tamamen çıkın, trafikten uzaklaşın, ışıkları ve dörtlüleri yakın ve dağılmasını bekleyin."},"99":{"q":"Bu sabah kapsamlı bir sefer öncesi kontrol yaptınız, yükünüzü sabitlediniz ve her şey yolundaydı. Yola çıktıktan üç saat sonra yemek molası için durduğunuzda, bir meslektaşınız çekicinizin etrafında dolaşıp yükünüzü yeniden kontrol etmenizin nedenini soruyor, çünkü zaten yola çıkmadan önce kontrol etmiştiniz. Gün boyu kontrol etmeye devam etmek için EN İYİ neden nedir?","options":["Doğru bir kontrol; seferden önce, sefer sırasında (yolda) ve seferden sonra yapılan sürekli bir süreçtir, çünkü aracın durumu ve yük sabitlemesi siz sürerken değişebilir.","Bir araç eksiksiz bir sefer öncesi kontrolü geçtikten sonra, yasa onu o seferin geri kalanı için yola elverişli sayar; bu yüzden etrafında dolaşmak bir zorunluluk değil, yalnızca kişisel bir alışkanlıktır.","Yolda yapılan kontroller yalnızca bir uyarı ışığı yandığında veya araç gerçekten arızalandığında gereklidir, çünkü geçilmiş bir sefer öncesi kontrolü mekanik her şeyi zaten kapsar.","Yeniden kontrol kesinlikle yükü ilk 50 mil içinde kontrol etmeniz gerektiği için zorunludur ve bu ilk kontrolden sonra gün boyunca aracın başka bir kontrolü gerekmez."],"explanation":"Muayene süreklidir — yolculuk öncesi, sırasında (yolda) ve sonrasında yapılır; çünkü lastik basıncı, yük sabitlemesi ve sıvı seviyeleri sürüş sırasında değişir."},"100":{"q":"Bu sabah bir açık dorseyi çelik rulolarla yükleyip avludan eyaletler arası otoyola çıktınız. Yaklaşık 35 mil sonra, aracınızın tamamen etrafından dolaşabileceğiniz geniş bir dinlenme alanı görüyorsunuz. Yolculuğunuz toplamda 300 milden fazla. Doğru yük prosedürüne göre, yükünüzü ve bağlamanızı kontrol etmek için ne yapmalısınız?","options":["Yola devam edin ve ilk bağlama kontrolünüzü 150 mil işaretinde yapın, çünkü standart yeniden kontrol aralığı budur","Şimdi içeri girip yükünüzü ve bağlama gerginliklerini denetleyin, çünkü ilk kontrolü ilk 50 mil içinde yapmanız ve ardından her 3 saatte veya 150 milde bir tekrar etmeniz gerekir","Sefer öncesi kontrolde yük güvenli göründüğü sürece, yakıt için durana kadar herhangi bir denetime gerek yoktur","İlk 500 mili sürene kadar bekleyin, ardından yükü periyodik olarak denetlemeye başlayın"],"explanation":"Yükü ve bağlama gergilerini ilk 50 mil içinde kontrol etmeli, sonra her 3 saatte veya 150 milde ve her moladan sonra yeniden kontrol etmelisiniz."},"101":{"q":"Sefer öncesi kontrolünüz sırasında, kabin arkasındaki yük bölmesine çelik boru yükünün nasıl bağlandığını kontrol ediyorsunuz. Bir iş arkadaşınız, yükü sıkıca bağlamanın tek gerçek nedeninin çizilmemesi veya yolculuk sırasında dağınık görünmemesi olduğunu söylüyor. Texas DPS yük emniyeti kurallarına göre, yükün doğru şekilde sabitlenmesi gerekmesinin BİRİNCİL güvenlik nedeni nedir?","options":["Teslimat noktasına vardığınızda yükün düzenli ve gösterişli kalması için","Yükün yağmurdan, yol tozundan korunması ve kötü havada kuru kalması için","Yükün kayması, araçtan düşmesi veya kayarak sürücünün kumandalarını engellemesinin önlenmesi için","Kış koşullarında sürerken yükün soğuyup donmaması için"],"explanation":"Yük, kayamayacak, araçtan düşemeyecek veya kabine kayıp sürücünün kumandalarını engelleyemeyecek şekilde sabitlenmelidir."},"102":{"q":"Öğleden sonra geç saatte yüklü bir çekici-römork ile batı yönünde ilerliyorsunuz. Güneş tam önünüzde ufka doğru alçaldı ve parlaması yolu silikleştirerek ne kadar uzağı görebildiğinizi kestirmenizi zorlaştırıyor. Öndeki araçlar bu parlak perdenin içinden aniden beliriyor. Bu durumu ele almanın en iyi yolu nedir?","options":["Güneşliği indirin, güneş gözlüğü takın ve gerçekte görebildiğiniz mesafe içinde durabilecek şekilde hızınızı azaltın","Uzun farlarınızı yakın, böylece kendi aydınlatmanız öndeki parlamayı yarıp geçsin","Hızınızı koruyun ancak telafi etmek için takip mesafenizi 6 saniyeye çıkarın","Sol şeride geçip hızlanın, böylece güneşin parladığı yol kesimini daha çabuk geçin"],"explanation":"Güneş parlamasında siperliği indirin, güneş gözlüğü takın ve gerçekten görebildiğiniz mesafede durabilecek kadar yavaşlayın."},"103":{"q":"İki şeritli kırsal bir karayolunda uzun ve dik bir yokuşu yüklü bir römorkla çıkıyorsunuz. Motorunuz zorlanıyor ve hızınız, belirlenen 55 mil/saat sınırının çok altında, yaklaşık 15 mil/saate düştü; arkanızda araçlar birikiyor. Aşağıdaki durumlardan hangisinde dörtlü acil flaşörlerinizi yakmak EN uygun davranıştır?","options":["Bir sonraki kavşakta normal bir sağa dönüş yaparken, çünkü tek başına sinyaliniz görülmeyebilir","Tepeye ulaşıp 55 mil/saat hız sınırında seyre geçtiğinizde, sürücülere yavaş bir ticari araç olduğunuzu bildirmek için","Aracı gece boyunca iyi aydınlatılmış bir mola yerine park ettikten sonra, başkaları aracın hatlarını görebilsin diye","Şimdi, trafiğin akışının çok altında bir hızla yokuşu tırmanırken, çünkü çevrenizdeki araçlardan çok daha yavaş gidiyorsunuz"],"explanation":"Çevredeki trafikten çok daha yavaş hareket ettiğinizde, örneğin dik bir yokuşu tırmanırken, arkadaki sürücüleri uyarmak için dörtlü flaşörleri yakın."},"105":{"q":"Yüklü bir kombinasyon aracıyla çok şeritli bir döner kavşağa yaklaşıyorsunuz. Girmeyi düşündüğünüz şeritte zaten dönen bir araba var ve hemen onun arkasında bir boşluk açılıyor. Aşağıdakilerden hangisi doğru ve en güvenli harekettir?","options":["Döner kavşakta zaten bulunan araca yol verin, güvenli bir boşluk oluşmasını bekleyin, ardından girip trafik akışına katılın","Hızınızı koruyun ve hemen girin, çünkü döner kavşakta zaten bulunan araçların giren kamyonlara yol vermesi gerekir","Döner kavşağın dönen şeridinde durun ve diğer tüm trafik temizlenene kadar orada bekleyin","Boşluğu yanlış değerlendirip çok erken girmeye başlarsanız, katılmadan önce güvenli takip mesafesini yeniden sağlamak için geri geri gidin"],"explanation":"Dönel kavşakta hâlihazırda bulunan trafiğin geçiş hakkı vardır; bu yüzden yol verin, güvenli bir boşluk bekleyin, sonra girip akışa katılın."},"106":{"q":"Yüklü bir römorku sağ şeritte izin verilen hızla çekerken, arkanızdaki bir sürücü hızlanmadığınız için sizi sıkıştırmaya, uzun farlarını yakıp söndürmeye ve öfkeyle el kol hareketleri yapmaya başlıyor. Öndeki trafik hemen şerit değiştirmenize engel oluyor. Bu saldırgan sürücüyle başa çıkmak ve kendi güvenliğinizi korumak için EN İYI yöntem hangisidir?","options":["Sürücüyü uzaklaşması için uyarmak amacıyla fren lambalarınızı yakıp söndürecek şekilde hafifçe frene basmak","Hızınızı koruyup şeridinizi sıkıca tutarak sürücünün büyük kamyonları sıkıştırmamayı öğrenmesini sağlamak","Güvenli olduğunda şerit değiştirip ya da hafifçe yavaşlayıp boşluk açarak, el kol hareketlerine tepki vermeden öfkeli sürücünün geçmesine izin vermek","Sürücü sizi sıkıştırmayı bırakana kadar yeterince öne geçecek şekilde izin verilen hızın üzerine çıkarak hızlanmak"],"explanation":"Arkanızda saldırgan bir sürücü varken tepki vermeyin; geçmesi için yol açın ve sakin kalarak çatışmayı yatıştırın."},"107":{"q":"Şiddetli bir sağanak, üzerinde gittiğiniz otoyolun sağ şeridinde birkaç santimetre birikmiş su bırakmış. Boş yük ile saatte 55 mil hızla gidiyorsunuz. İleride biriken derin suya yaklaşırken, aracınızı kontrol altında tutmanın EN İYİ yolu hangisidir?","options":["55 mil hızı koruyup banket tarafına yönelin, çünkü suyu direksiyon lastiklerinizden uzaklaştırmak tutuşu geri kazandırır","Suya girmeden önce hızınızı azaltın, çünkü lastikleriniz ile yol arasında sıkışan su su kızağına (hidroplanaj) ve direksiyon ile fren kontrolünün kaybına yol açabilir","Lastik dişlerinin suyu kenara atıp lastiklerin asfaltı kavramaya devam etmesi için suyun içinden kararlı şekilde gaz vererek geçin","Hızınızı sabit tutun ve suyun içindeyken ne kadar tutuş kaldığını test etmek için hafifçe fren yapın"],"explanation":"Birikintiye varmadan hız azaltın; çünkü lastiklerle yol arasına giren su, su kızağına (hidroplaning) ve direksiyon ile fren kontrolünün kaybına yol açabilir."},"108":{"q":"Kuru ve açık bir eyaletler arası otoyolda boş giderken zaman kazanmak için seyir hızınızı 30 mil/saatten 60 mil/saate çıkarmaya karar veriyorsunuz. Yanınızdaki stajyer, bu değişikliğin aracınızın tam durması için gereken fren mesafesini nasıl etkilediğini soruyor. Aslında ne olduğunu EN İYİ açıklayan yanıt hangisidir?","options":["Kamyon boş olduğu için daha hafif yük, 60'ta da 30'da olduğu gibi aşağı yukarı aynı mesafede durmasını sağlar.","Hızı ikiye katlamak durma mesafesine çok az ekler — fren mesafesi hızla orantılı artar, yani sadece ikiye katlanır.","Hızı ikiye katlamak fren mesafesini yaklaşık dörde katlar, dolayısıyla 60 mil/saat, 30 mil/saatin gerektirdiğinin yaklaşık dört katı kadar yer ister.","Islak zemin önemli olurdu, ama bu kuru yolda yüksek hız durma mesafenizi neredeyse hiç değiştirmez."],"explanation":"Fren mesafesi hızın karesiyle artar, bu yüzden hızı iki katına çıkarmak durma mesafesini yaklaşık dört katına çıkarır."},"109":{"q":"Hava donma noktasının hemen altında ve hafif yağmur yolu buz tabakasıyla kapladı. Boş yük taşıyorsunuz ve kamyonun arka tekerlekleri bir virajda kaymaya başlıyor. Bu kaymaya neyin yol açtığını gözden geçirirken, yaptığınız aşağıdaki eylemlerden hangisinin buna neden olma olasılığı EN AZdır?","options":["Virajı çekiş gücüyle aşmak için gaz pedalına sert basmak","Arka tarafın kaydığını hissedince tekerlekleri kilitleyecek kadar sert fren yapmak","Viraj boyunca direksiyon hareketlerinizi yumuşak ve kademeli tutmak","Buzlu ve ıslak koşullar için fazla hızlı gitmek"],"explanation":"Yumuşak ve kademeli direksiyon kullanımı lastik kuvvetlerini mevcut tutuş sınırında tutar, bu yüzden aşırı hız, sert frenleme veya aşırı gazın aksine kaymaya yol açmaz."},"110":{"q":"İki şeritli kırsal bir karayolunda hava iyice karardı ve yaklaşık 400 fit ileride bir tepeyi aşan karşıdan gelen bir kamyonun farlarını görüyorsunuz. Şu anda uzun farlarınız açık. Doğru hareket nedir?","options":["Diğer sürücü büyük aracınızı net görebilsin diye uzun farlarınızı açık bırakın","Araçlar birbirine 500 fit yaklaşmadan, hemen şimdi kısa farlara geçin","Diğer sürücüye işaret vermek için uzun farları kısa süre yakıp söndürün, sonra açık tutmaya devam edin","Karşıdan gelen kamyonla, göz kamaşması sorun olmadan önce karşılaşıp geçmek için hafifçe hızlanın"],"explanation":"Karşıdan gelen araca 500 fit kala kısa farlara geçin ki uzun farlarınız diğer sürücüyü kör etmesin."},"111":{"q":"Kırsal iki şeritli bir karayolunda yüklü bir açık kasa (flatbed) çekerken motorunuz güç kaybetmeye başlıyor ve sizi 55 mil/saat hız sınırı olan yolda yaklaşık 30 mil/saate düşmeye zorluyor. Arkanızda trafik birikiyor. Sorunu incelemek üzere kenara çekmek için kamyonu bir sonraki çıkışa kadar idare ederken, aşağıdakilerden hangisi dörtlü flaşörlerinizin YANLIŞ bir kullanımı olur?","options":["Daha hızlı trafiği yolun normal hızının çok altında ilerlediğiniz konusunda uyarmak için flaşörleri açık bırakmak","Çıkış rampasına gerçekten girerken flaşörleri kapatıp yalnızca sağ sinyal lambanızı kullanmak","Banketde durup motoru incelerken flaşörleri tekrar açmak","Rampaya sağa dönmek üzere olduğunuzu belirtmek için sinyal lambası yerine flaşörleri kullanmak"],"explanation":"Dörtlü flaşörler duran, arızalı veya yavaş giden bir aracı uyarmak içindir ve asla sinyal yerine kullanılmamalıdır."},"112":{"q":"Kuru ve düz bir eyalet karayolunda 40 fit uzunluğunda tek parçalı bir yük taşıyorsunuz ve gündüz iyi koşullarda hız göstergeniz sabit 45 mil/saatte duruyor. Önünüzde güvenli bir boşluk bırakmak için, öndeki araca karşı tutmanız gereken EN AZ takip mesafesi nedir?","options":["4 saniye, çünkü 40 fitlik bir araç her 10 fit uzunluk için 1 saniye gerektirir","6 saniye, çünkü 40 mil/saatin üzerindeki her hız otomatik olarak en az 6 saniye gerektirir","5 saniye, çünkü 40 fit 4 saniyeye eşittir ve 40 mil/saatin üzerinde olduğunuz için 1 saniye daha eklersiniz","3 saniye, çünkü yol kuru, düz ve görüş iyi"],"explanation":"Her 10 fitlik uzunluk için 1 saniye bırakın; 40 fitlik araç 4 saniye gerektirir, 40 mil/sa üzerinde 1 saniye daha eklenir, toplam 5 saniye olur."},"113":{"q":"50 fit uzunluğundaki bir çekici-römork ile, trafiğin azaldığı ve hız sınırının sabit 35 mil/saat hızda gitmenize izin verdiği bir yol çalışması bölgesinden geçiyorsunuz. Önünüzdeki kamyonete güvenli bir takip mesafesi bırakmak istiyorsunuz. Aracın her 10 fit uzunluğu için 1 saniye kuralını kullanarak, tam olarak bu durum için hangi takip mesafesi doğrudur?","options":["4 saniye, çünkü yavaş bir yol çalışması bölgesinde mesafeyi bir saniye kısaltabilirsiniz","7 saniye: uzunluk için 5 saniye artı yol çalışması bölgesi için 2 ekstra saniye","6 saniye, çünkü uzunluğa dayalı sayıma her zaman 1 ekstra saniye eklemeniz gerekir","5 saniye, çünkü 50 fit bölü 10 eşittir 5 ve 40 mil/saatin altında gittiğiniz için ekstra saniye eklenmez"],"explanation":"Her 10 fitlik uzunluk için 1 saniye bırakın; 50 fitlik araç 5 saniye gerektirir, 40 mil/sa altında olduğunuz için ek saniye eklenmez."},"114":{"q":"Açık bir gündüz koşulunda, kuru ve düz bir eyaletler arası otoyolda 60 fit uzunluğundaki bir çekici-römork aracını sabit 55 mil/saat hızla sürüyorsunuz. Trafik seyrek ve önünüzdeki aracın arkasında güvenli bir boşluk bırakmak istiyorsunuz. Takip mesafesi kuralına göre, bu durumda korumanız gereken EN AZ takip mesafesi ne kadardır?","options":["7 saniye","6 saniye","8 saniye","5 saniye"],"explanation":"Her 10 fitlik uzunluk için 1 saniye bırakın; 60 fitlik araç 6 saniye gerektirir, 40 mil/sa üzerinde 1 saniye daha eklenir, toplam 7 saniye olur."},"115":{"q":"Tampondan tampona 30 fit uzunluğunda tek parça düz bir kamyon kullanıyorsunuz. Şehir içi yoldaki trafik düzenli biçimde 30 mil/saat hızla akıyor; bu da sizi tam olarak 40 mil/saat sınırının hemen altında tutuyor. Bu koşullarda aracınız için güvenli bir takip mesafesi bırakmak amacıyla, önünüzdeki araçla aranızda tutmanız gereken EN AZ saniye sayısı kaçtır?","options":["2 saniye, çünkü 30 mil/saatte otoyol hızının çok altındasınız ve trafik düzgün akıyor","3 saniye; aracınızın her 10 fitlik uzunluğu için 1 saniye","4 saniye, çünkü uzunluğa göre yaptığınız sayıma her zaman 1 saniye eklemeniz gerekir","6 saniye; tam bir duruşun aldığı yaklaşık 6 saniyeye denk gelir"],"explanation":"Her 10 fitlik uzunluk için 1 saniye bırakın; 30 fitlik araç 3 saniye gerektirir, 40 mil/sa altında olduğunuz için ek saniye eklenmez."},"116":{"q":"Kuru bir otoyolda 70 fitlik bir çekici-dorse kombinasyonu kullanıyorsunuz ve hafif trafikte sabit 50 mil/saat hızda gidiyorsunuz. Önünüzdeki boşluğa bir binek araç sürekli girip çıkıyor ve şerit boşalır boşalmaz güvenli bir takip mesafesini yeniden ayarlamak istiyorsunuz. Aracınızın uzunluğu ve hızı için geçerli saniye kuralına göre, kaç saniyelik takip mesafesi oluşturmalısınız?","options":["7 saniye, çünkü 70 fitlik bir araç her 10 fit uzunluk için 1 saniyeye ihtiyaç duyar","6 saniye, çünkü otoyol hızında önerilen toplam durma mesafesi tamponu budur","8 saniye, çünkü uzunluk 7 saniye gerektirir ve 40 mil/saatin üzerinde olduğunuz için 1 saniye daha eklersiniz","9 saniye, çünkü bu kadar uzun bir araç için 40 mil/saatin üzerinde 2 saniye eklemelisiniz"],"explanation":"Takip mesafesi 40 mil/saat altında her 10 fitlik araç uzunluğu için 1 saniye, 40 mil/saat üzerinde 1 saniye eklenir; yani 50 mil/saatte 70 fitlik araç 8 saniye gerektirir."},"117":{"q":"Şehir merkezindeki bir iş bölgesinde 20 fitlik tek parça (düz) bir kamyon kullanıyorsunuz. Trafik düzenli, hız sınırı 25 mil/saat, zemin kuru ve görüş iyi. Önünüzde güvenli bir boşluk bırakmak için, öndeki araca karşı korumanız gereken EN AZ takip mesafesi nedir?","options":["1 saniye, çünkü kamyon yalnızca 20 fit uzunluğunda","4 saniye; temele 1 saniye ve şehir trafiği için 1 saniye daha eklenerek","3 saniye, çünkü temel değerin üzerine her zaman 1 saniye eklemelisiniz","2 saniye, aracın her 10 fitlik uzunluğu için bir saniye"],"explanation":"40 mil/saat altında takip mesafesi araç uzunluğunun her 10 fiti için 1 saniyedir, bu yüzden 20 fitlik araç 2 saniye gerektirir."},"118":{"q":"Kuru bir eyaletler arası otoyolda 80 fitlik bir kombinasyon aracı sürüyorsunuz ve hafif trafikte sabit 60 mil/saat hızı koruyorsunuz. Bir iş arkadaşınız size 'her 10 fit için bir saniye' bırakmanızın her hızda yeterli olduğunu söylüyor. Uzunluğunuz ve hızınız için doğru Texas DPS takip mesafesi yöntemini kullanarak, önünüzdeki aracın arkasında korunmanız gereken EN AZ takip mesafesi nedir?","options":["9 saniye — 80 fitlik uzunluk için 8 saniye, artı 40 mil/saatin üzerinde gittiğiniz için 1 ek saniye","8 saniye — 80 fitlik aracınızın her 10 fiti için 1 saniye, hız için herhangi bir düzeltme yapılmadan","10 saniye — uzunluk için 8 saniye, artı 40 mil/saat eşiğinin 20 mil/saat üzerinde olduğunuz için 2 saniye","7 saniye — her 10 fit için 1 saniye, sonra kuru zemin iyi tutuş sağladığı için 1 saniye düşülür"],"explanation":"40 mil/saat altında her 10 fitlik uzunluk için 1 saniye verin ve 40 mil/saat üzerinde 1 saniye daha ekleyin; yani 60 mil/saatte 80 fitlik araç 9 saniye gerektirir."},"119":{"q":"Kuru ve düz bir eyaletler arası otoyolda 50 fitlik bir çekici-römork sürüyorsunuz ve hız göstergeniz hafif trafikte sabit 45 mil/saat gösteriyor. Önünüzdeki binek araç sürekli frene basıyor, bu yüzden saniye kuralını kullanarak güvenli bir takip mesafesi belirlemek istiyorsunuz. O aracın arkasında kaç saniyelik mesafe bırakmalısınız?","options":["5 saniye, çünkü aracınız 50 fit uzunluğunda ve bu her 10 fit için 1 saniye verir","6 saniye, çünkü 50 fit size 5 saniye verir ve 40 mil/saatin üzerinde olduğunuz için 1 saniye daha eklersiniz","7 saniye, eyaletler arası otoyolda olduğunuz için uzunluğa dayalı değere 2 ekstra saniye ekleyerek","4 saniye, çünkü 45 mil/saat 40'ın sadece biraz üzerinde ve kuru zeminde daha kısa bir mesafe yeterli"],"explanation":"40 mil/saat altında her 10 fitlik uzunluk için 1 saniye kullanın ve 40 mil/saat üzerinde 1 saniye ekleyin; yani 45 mil/saatte 50 fitlik araç 6 saniye gerektirir."},"120":{"q":"Şehir içinde 60 fitlik (yaklaşık 18 metre) bir çekici-römork sürüyorsunuz ve daha yavaş giden bir dağıtım kamyonunun arkasına yerleşiyorsunuz. Hız göstergeniz kuru zeminde sabit 35 mil/saat gösteriyor. Bu hızda aracınız için güvenli bir takip mesafesi tutmak adına önünüzdeki araçla aranızda kaç saniyelik boşluk bırakmalısınız?","options":["5 saniye, çünkü iyi koşullarda kuru zeminde bir saniye düşülür","8 saniye: her 10 fit için bir saniye artı römork için iki ek saniye","6 saniye: araç uzunluğunun her 10 fiti için bir saniye","7 saniye: her 10 fit için bir saniye artı hareket halinde olduğunuz için bir saniye"],"explanation":"40 mil/saat altında takip mesafesi her 10 fitlik uzunluk için 1 saniyedir ve ek saniye eklenmez; yani 35 mil/saatte 60 fitlik araç 6 saniye gerektirir."},"121":{"q":"İki şeritli bir karayolunda kısmi yükle seyrederken hafif bir dondurucu çiseleme başlar ve yol yüzeyi parlamaya başlar. Sonraki bir mil boyunca üç şey yaparsınız: görüş ve tutuş azalmış olmasına rağmen seyir hızınızı sabit tutarsınız, bir geyik aniden fırlayınca fren pedalına sertçe basarsınız ve hemen ardından hafif bir yokuşta tekrar hızlanmak için gaza sertçe basıp süratlenirsiniz. Bir iş arkadaşınız daha sonra bu eylemlerden yalnızca BİRİNİN gerçekçi olarak sizi kaymaya sürükleyebileceğini iddia ediyor. Hangi ifade doğrudur?","options":["Yalnızca sert panik freni kaymaya neden olabilirdi, çünkü tekerlekleri kilitlemek tutuşu kaybetmenin tek yoludur.","Yalnızca buzlu koşullar için fazla hızlı gitmek kaymaya neden olabilirdi, çünkü kaymaların çoğu aşırı hızdan kaynaklanır.","Üç eylemin her biri — koşullara göre aşırı hız, sert panik freni ve sert hızlanma — tek başına kaymaya neden olabilirdi.","Yalnızca sert hızlanma kaymaya neden olabilirdi, çünkü kısmi (hafif) bir yük, çekiş tekerleklerine tutuş için çok az ağırlık verir."],"explanation":"Kayma, lastikler yol tutuşunu kaybettiğinde olur ve koşullara göre aşırı hız, çok sert frenleme veya çok sert hızlanmanın her biri tek başına buna yol açabilir."},"122":{"q":"Kırsal, iki şeritli bir karayolunda yüklü bir römork çekiyorsunuz. Hafif bir yağmur yeni başladı ve zemin ıslaklıktan parlıyor; ileride keskin bir viraj işareti görüyorsunuz ve virajdan sonraki çukura alçak bir sis tabakası çöküyor, bu yüzden yolu ileride pek göremiyorsunuz. Bir iş arkadaşınız size bir keresinde, aynı anda yalnızca karşılaştığınız en kötü tek tehlike için hızınızı düşürmeniz gerektiğini söylemişti. Bu durumda güvenli CDL uygulamasını en iyi yansıtan davranış hangisidir?","options":["Islak kesimde karayolu hızınızı koruyun ve yalnızca gerçekten viraja ulaştığınızda yavaşlayın, çünkü viraj en ciddi tek tehlikedir","Hızınızı sabit tutun, çünkü birden fazla küçük tehlike bir arada ortaya çıktığında sizi koruyan şey hızınız değil takip mesafenizdir","Yalnızca çukurdaki sis için yavaşlayın, çünkü düşük görüş, yasal olarak daha düşük bir hız gerektiren tek koşuldur","Üç koşulun tümü için birden hızınızı düşürün, çünkü ıslak zemin, viraj ve sınırlı görüş her biri ayrı ayrı daha düşük bir hız gerektirir"],"explanation":"Islak zemin, virajlar ve sınırlı görüş her biri tek başına güvenli hızı düşürür, bu yüzden hepsinde hızınızı azaltın ve bir arada olduklarında daha da fazla azaltın."},"123":{"q":"Saat sabah 06.00 ve uzun bir eyaletler arası sefer öncesinde çekici-römork üzerinde sefer öncesi muayene yapıyorsunuz. Daha sonra banket üzerinde arıza yaparsanız diye tam donanımlı olduğunu doğrulamak için koltuğun arkasındaki acil durum ekipmanı kutusunu açıyorsunuz. Hangi eşya grubu, taşımakla yükümlü olduğunuz TAM acil durum ekipmanını temsil eder?","options":["Üç adet yansıtıcı uyarı üçgeni, yedek elektrik sigortaları (araç devre kesicilerle donatılmamışsa) ve uygun şekilde dolu ve sınıfa uygun bir yangın söndürücü","Üç adet yansıtıcı uyarı üçgeni ve uygun şekilde dolu ve sınıfa uygun bir yangın söndürücü, ancak yedek sigortalar isteğe bağlıdır","Uygun şekilde dolu ve sınıfa uygun bir yangın söndürücü ile yedek elektrik sigortaları ve ayrıca kış güzergâhları için bir takım kar zinciri","Üç adet yansıtıcı uyarı üçgeni, bir ilk yardım çantası ve uygun şekilde dolu ve sınıfa uygun bir yangın söndürücü"],"explanation":"Zorunlu acil durum ekipmanı üç yansıtıcı uyarı üçgeni, devre kesici kullanılmadıkça yedek sigortalar ve uygun şekilde dolu ve sınıflandırılmış bir yangın söndürücüdür."},"124":{"q":"Bölünmüş bir otoyolda 65 mil/saat hız sınırının olduğu bir yolda programın 30 dakika gerisindesiniz. Tüm şeritlerdeki trafik yaklaşık 72 mil/saat akıyor, zemin kuru ve önündeki yol çeyrek mil boyunca açık ve boş. Texas DPS kurallarına göre, bu koşullardan hangisi belirtilen 65 mil/saat sınırından daha hızlı sürmenizi kabul edilebilir kılar?","options":["Çevredeki genel trafik akışı sınırın üzerinde ilerlerken, tehlike oluşturmamak için akışa ayak uydurduğunuzda","Programın gerisindeyken ve kuru, açık zemin kaybedilen zamanı güvenle telafi etmenize izin verdiğinde","Bu koşulların hiçbiri belirtilen sınırı aşmayı haklı çıkarmaz","Önündeki yol çeyrek mil boyunca boşken, bu size tam durma mesafesi verdiğinde"],"explanation":"Levhadaki hız sınırı ideal koşullar için yasal azami hızdır ve trafik, program ya da boş yol ne olursa olsun asla aşılamaz."},"125":{"q":"60 mil/saat sınırı olan bir bölgede 40 mil/saat hızla giden yavaş bir çiftlik kamyonunun arkasında, iki şeritli bir karayolunda yüklü bir çekici-römork kullanıyorsunuz. Onu geçmek için sabırsızsınız ve önünüzde dört fırsat görüyorsunuz. Geçişi tamamlamak için gerçekten GÜVENLİ olan yer hangisidir?","options":["İlerideki uzun, hafif virajda, dönemecin arkasını kısmen görebildiğiniz yerde","Tepenin doruğundan hemen önce, hâlâ biraz ileri görüşünüz varken","Bu yerlerin hiçbiri güvenli geçiş için yeterli görüş mesafesi sağlamaz","Yaklaşan kırsal kavşaktan, çünkü yan trafiğin karayoluna yol vermesi gerekir"],"explanation":"İki şeritli yolda güvenli sollama için ileride yeterli görüş mesafesi gerekir; virajlar, tepe noktaları ve kavşaklar bunu engeller."},"126":{"q":"Sıkı bir teslimat programında 40 dakika gerideniz. Aynı çekici-römork dün kullandığınızda tam bir sefer öncesi muayeneden geçti, hava açık ve kuru ve hızlı bir araç turu gözle görülür bir sorun göstermiyor. Bu durumlardan hangisinde, sürüşe başlamadan önce bugünkü sefer öncesi muayeneyi yasal ve güvenli şekilde atlamanıza izin verilir?","options":["Programın gerisinde olduğunuzda ve bir gecikme teslimatın gecikmesine yol açacağında","Araç önceki gün muayeneden geçtiğinde ve o zamandan beri işaretlenmediğinde","Bu durumların hiçbiri sefer öncesi muayeneyi atlamayı haklı çıkarmaz","Kısa bir araç turu gözle görülür bir sorun göstermediğinde ve koşullar iyi olduğunda"],"explanation":"Sefer öncesi muayene istisnasız her seferden önce zorunludur, çünkü aracın durumu her an değişebilir."},"127":{"q":"Hava yeni karardı; yüklü bir römork çekerek dar, aydınlatmasız iki şeritli bir kır yolunda ilerliyorsunuz. Karşıdan gelen bir araç yaklaşık 400 fit ileride bir tümseğe çıkıyor ve uzun farları doğrudan gözlerinize vurarak kaputunuzun önündeki her şeyi göremez hale getiriyor. Araçların karşılaşmasına yalnızca birkaç saniye var. Araç geçene kadar aracınızı kontrol altında tutmanın en güvenli yolu hangisidir?","options":["Kendi farlarınızı uzun huzmeye alın; fazladan menzilleri, karşıdaki sürücünün parlamasının ötesindeki yolu görmenizi sağlasın.","Bakışlarınızı şeridinizin sağ kenarına indirin ve karşıdan gelen araç geçene kadar hızınızı azaltın.","Uzun farlarınızı birkaç kez hızlıca yakıp söndürün; karşıdaki sürücü sorunu fark edip kısaltsın.","Gözlerinizi tam önünüzdeki orta çizgiye sabitleyin ve araç geçene kadar sürüklenmemek için hızınızı sabit tutun."],"explanation":"Karşıdan gelen uzun farlar gözünüzü kamaştırdığında, rehber olarak şeridinizin sağ kenarına bakın ve araç geçene kadar yavaşlayın."},"131":{"q":"Otoyolda yaklaşık 55 mil/saat hızla giderken ani bir sağanak yağış zeminde bir tabaka birikinti su bırakıyor. Direksiyon aniden ellerinizde hafif ve gevşek hissediliyor ve çekicinin ön lastiklerinin yolla sıkı temasını kaybedip suyun üzerinde kaydığını fark ediyorsunuz. Hangi tepki, yol tutuşunu güvenli bir şekilde yeniden kazanmanız için en iyi şansı verir?","options":["Sağlam, sabit fren basıncı uygulayın ve ön lastikleri zemine geri zorlamak için sert bir şekilde banket yönüne direksiyon kırın.","Hızınızı koruyun ancak lastiklerin kilitlenmeden su tabakasını delip geçmesi için frenlere hızlıca basıp bırakın (pompalayın).","Gaz pedalını bırakın, direksiyonu düz tutun ve lastikler yol tutuşunu yeniden kazanana kadar kamyonun kademeli olarak yavaşlamasına izin verin.","Gaz pedalına daha sert basın ve birikinti suyu lastiklerin altından itmek için çeker tekerlekleri döner halde tutun."],"explanation":"Su kızağında lastikler tutuşunu kaybeder, bu yüzden gazdan ayağınızı çekin, direksiyonu düz tutun ve tutuş geri gelene kadar kamyonun yavaşlamasını sağlayın."},"133":{"q":"Dört şeritli, refüjle ayrılmış bir otoyolun sağ şeridinde yüklü bir dorse çekiyorsunuz ve belirlenen 60 mil/saat hız sınırında ilerliyorsunuz. Bir kamyonet arkanıza iyice yaklaştı, tamponunuzun sadece birkaç adım gerisinde seyrediyor, sürekli uzun farlarını yakıp söndürüyor ve sollamak ister gibi sağa sola kırıyor. Solunuzda boş bir şerit, önünüzde ise akıcı ama yoğun trafik var. En güvenli ve hukuken en doğru tepki hangisidir?","options":["Frene birkaç kez hafifçe basarak fren lambalarınızı yakıp söndürün ve arkadan yaklaşan sürücüye geri çekilip mesafe açması gerektiğini bildirin.","Mevcut hızınızı ve şerit konumunuzu koruyun ki agresif sürücü sizi yaptığınız şeyi değiştirmeye zorlayamasın.","Yaklaşık 70 mil/saate hızlanarak arkanızdaki sürücüyle aranızı açın; çünkü agresif bir sürücünün önüne geçmek çatışmayı ortadan kaldırır.","Gazı bırakarak önünüzdeki takip mesafesini açın, ardından sinyal verip sol şerit boşsa o şeride geçin ki sürücü sizi geçebilsin."],"explanation":"Saldırgan bir takipçi varsa, gazdan ayağınızı çekerek öndeki mesafeyi açın, ardından sinyal verip şerit değiştirerek onun güvenle geçmesine izin verin."},"134":{"q":"Yüklü bir römorku otoyolda çekerken keskin bir yanık lastik kokusu alıyorsunuz ve sağ aynanızda aracınızın arkasından gri bir duman çıktığını fark ediyorsunuz. Trafik orta yoğunlukta ve birkaç yüz feet ileride geniş, asfalt bir banket var. EN İYİ hareket tarzı nedir?","options":["Erkenden sinyal verin, diğer trafikten uzakta tamamen bankete çekin, motoru kapatın ve durum kötüleşmeden önce dumanın kaynağını inceleyin.","Hızınızı koruyun ve bir sonraki çıkışa kadar devam edin; çünkü otoyol hızındaki hava akımı muhtemelen bölgeyi soğutup dumanın kendiliğinden dağılmasını sağlayacaktır.","Bankete durun ama motoru çalışır halde bırakın, sonra hapsolmuş duman ve ısının çıkması için römorkun arka kapaklarını hemen açın.","Yavaşlayın ve tamamen durmadan, bir yolcu arka lastiklere su dökerek soğutmaya çalışırken bankette düşük hızda ilerlemeye devam edin."],"explanation":"Duman veya yanık kokusu başlayan bir yangının işareti olabilir, bu yüzden trafikten uzağa tamamen yol kenarına çekin, motoru kapatın ve kötüleşmeden kaynağı kontrol edin."},"135":{"q":"Kırsal iki şeritli bir karayolunda yüklü bir römork çekerken, ileride şerit çizgilerini kısa mesafeden bile zar zor seçebildiğiniz kadar yoğun bir sis bankasına giriyorsunuz. Trafik az. Bu kesimi geçmenin en güvenli ve en doğru yolu hangisidir?","options":["Uzun farlara geçin ki daha güçlü ışık sisi delip geçsin ve şerit çizgilerini daha erken görmenizi sağlasın.","Hızınızı azaltın, kısa farlarınızı açık tutun ve yine de yeterince göremiyorsanız yoldan tamamen çekilip sisin dağılmasını bekleyin.","Normal otoyol hızınızı koruyun ama öndeki aracın arka stop lambalarına kilitlenip sisin içinde onları kılavuz olarak takip edin.","Yüklü aracınızın güvenle izin verdiği ölçüde hızlanarak sisli kesimi olabildiğince çabuk geçin, sonra seyir hızınıza geri dönün."],"explanation":"Siste yavaşlayın ve kısa farları kullanın, çünkü uzun farlar su damlacıklarından yansıyıp parlamayı artırır; hâlâ göremiyorsanız tamamen yoldan çekilin."},"136":{"q":"Vardiyanızın sonuna geliyorsunuz ve daha önce hiç gitmediğiniz bir sahada, 53 fitlik dorseyi dar bir yükleme rampasına geri geri sokmanız gerekiyor. Yardımcı bir gözcü yok, rampa şu an boş ve bir an önce bitirmek istiyorsunuz. En güvenli ve en doğru hareket hangisidir?","options":["Arkanız şu an boş olduğu için, forkliftler veya işçiler gelmeden bitirmek amacıyla sabit bir hızda hemen geri geri girin.","Yakından geçen bir işçiyi durdurup, siz geri giderken sizi izleyip yönlendirmesi için doğrudan dorsenin arkasına dikilmesini isteyin.","Araçtan inip dorsenin arkasındaki tüm güzergâhı yürüyerek engeller ve geçiş açıklığı açısından kontrol edin, ardından her iki taraftaki aynaları kullanarak yavaşça geri gidin.","Sadece aynalarınıza güvenip inmeden sabit bir hızda geri gidin, çünkü durup bakmak yalnızca sizi yavaşlatır."],"explanation":"Yardımcı yokken İn-ve-Bak yöntemini kullanın: dorsenin arkasındaki tüm güzergâhı yürüyerek engelleri ve açıklığı kontrol edin, sonra her iki aynayı kullanarak yavaşça geri gidin."},"137":{"q":"Kuru bir eyaletler arası otoyolda saatte 55 mil hızla yüklü bir römork çekerken önünüzde çok ileride şeridinizde aniden arızalı bir araba beliriyor. Eğitmeniniz daha sonra, tehlikenin görüş alanınıza girdiği andan tamamen durana kadar aracınızın gerçekte aldığı mesafenin HER bir parçasını açıklamanızı istiyor. Toplam durma mesafenizi oluşturan üç ayrı parçayı doğru şekilde tanımlayan ayırım hangisidir?","options":["3/4 saniyelik tepki süreniz boyunca alınan mesafe artı frenler tuttuktan sonraki fren mesafesi — algılama süresi zaten tepki süresine dahildir, bu nedenle ayrıca sayılmaz","Yalnızca fren mesafesi, çünkü kamyonun fiziksel olarak yavaşladığı kısım budur ve kontrol edebileceğiniz tek bölüm budur","Takip mesafesi, sinyal verme mesafesi ve kaldırım kenarında bıraktığınız park boşluğu","Algılama mesafesi, tepki mesafesi ve fren mesafesi"],"explanation":"Toplam durma mesafesi üç bölümden oluşur: algılama mesafesi, tepki mesafesi ve frenleme mesafesi."},"138":{"q":"Uzun bir sefer sırasında öğle yemeği için durdunuz ve bir arkadaşınız yemeğinizle birlikte tek bir bira ikram ediyor. Sonrasında kendinizi tamamen ayık hissediyorsunuz ve düz bir çizgide yürümekte hiç zorlanmıyorsunuz. Çekici-römork aracınıza tekrar binmeden önce, ticari aracınızı kullanmak için geçerli yasal kandaki alkol konsantrasyonu (BAC) sınırı hakkında hangi ifade doğrudur?","options":["0,04 BAC değerinde yasal sınırı aşmış olursunuz ve ticari aracı kullanamazsınız; bu değer, normal bir binek otomobil için geçerli sınırın yarısıdır.","0,08 BAC değerinde yasal sınırı aşmış olursunuz ve ticari aracı kullanamazsınız; bu, normal bir binek otomobil için geçerli olan sınırın aynısıdır.","BAC değeriniz 0,10 değerinin altında kaldığı sürece araç kullanmanızda sakınca yoktur, çünkü büyük araçlar için daha yüksek bir eşik geçerlidir.","Önemli olan ayık hissetmektir; bu nedenle belirli bir BAC sayısına bakılmaksızın, artık etki altında hissetmediğiniz anda araç kullanabilirsiniz."],"explanation":"Ticari aracı sürmek için yasal kan alkol sınırı yüzde 0,04'tür, binek araç için geçerli yüzde 0,08 sınırının tam yarısıdır, bu yüzden 0,04'te sınırı aşmış sayılırsınız."},"139":{"q":"Yatakli bolmede 10 saat kesintisiz dinlendiniz ve yeni bir vardiyaya basliyorsunuz. Sevkiyat gorevlisi seferin uzun oldugunu soyluyor ve federal calisma-saati (HOS) kurallari sizi o gun icin direksiyon basindan kaldirmadan once yasal olarak ne kadar fiili surus yapabileceginizi soruyor. Bunu saf surus olarak ele alirsak (14 saatlik pencerenizi erken kapatacak asiri gorev gecikmeleri olmadan), izin verilen azami surus suresi nedir?","options":["8 saate kadar surus, cunku once 30 dakikalik mola vermeniz gerekir","11 saate kadar surus suresi","14 saate kadar surus suresi","16 saate kadar surus suresi"],"explanation":"10 saat aralıksız görev dışı kaldıktan sonra federal çalışma saati kuralları en fazla 11 saat sürüş süresine izin verir."},"140":{"q":"Şafaktan çok önce yola çıktınız ve şimdi öğleden sonranın ortasındasınız. Kendinizi şeritte kayarken yakalıyorsunuz, göz kapaklarınız ağırlaşıyor ve son birkaç mili hatırlayamıyorsunuz. Rotanızda hâlâ saatler var ve yetişmeniz gereken bir teslimat zamanı mevcut. Aşağıdakilerden hangisi uyanıklığınızı gerçekten geri kazandıracak ve bu durumu güvenli şekilde düzeltecek TEK eylemdir?","options":["Bir sonraki dinlenme tesisinde durup iki fincan sert kahve içmek ve programa uymak için yola devam etmek","Soğuk temiz hava için camları açmak ve zihninizi uyanık tutmak için radyoyu sonuna kadar açmak","Güvenli olur olmaz yoldan çıkmak, sürmeyi bırakmak ve devam etmeden önce yeterince gerçek uyku almak","Bir enerji içeceği açmak, ağır bir yemek yemek ve telafi etmek için takip mesafenizi artırmak"],"explanation":"Uyku borcunu yalnızca gerçek ve yeterli uyku öder, bu yüzden yorgunken güvenli şekilde yoldan çekilin, sürmeyi bırakın ve devam etmeden önce uyuyun."},"141":{"q":"Açık ve kuru havada, düz ve açık bir kırsal otoyolda 55 mil/saat hızla yüklü olarak ilerliyorsunuz. Trafik az ve önünüzde yolun uzun, kesintisiz bir görüş alanı var. Görsel önden bakış sürenizi doğru yönetmek için tehlikeleri taramak amacıyla ne kadar ileriye sürekli bakmalısınız?","options":["Yalnızca hemen önünüzdeki araca, çünkü 55 mil/saat hızda daha uzaktaki her şey henüz bir tehdit değildir","Yaklaşık 30 ila 40 saniye ileriye, böylece açık otoyolda mümkün olan en fazla tepki süresine sahip olursunuz","Yaklaşık 1 ila 2 saniye ileriye, ki bu yaklaşık olarak bu hızdaki güvenli takip mesafenizdir","Yaklaşık 12 ila 15 saniye ileriye, ki bu 55 mil/saat hızda kabaca çeyrek mil veya şehir içinde yaklaşık bir blok eder"],"explanation":"Gözlerinizi hareket ettirin ve 12 ila 15 saniye ileriye bakın; bu, otoyol hızında yaklaşık çeyrek mil veya şehirde bir blok demektir ve tehlikeleri erken görmenizi sağlar."},"142":{"q":"Yüklü bir yarı römorkla yoğun, dört şeritli bir Teksas otoyolunda otoyol hızında ilerliyorsunuz. Trafik yoğun ve araçlar sürekli kör noktalarınıza girip etrafınızda şerit değiştiriyor. Aracınızın arkasında ve yanında olup biten hakkında doğru, güncel bir resmi sürekli koruyabilmek için aynalarınızı nasıl kullanmalısınız?","options":["Aynalara yalnızca şerit değiştirmeden veya birleşmeden hemen önce bakın, çünkü kör nokta trafiğinin önem kazandığı an budur","Yolda ne kadar ileriye baktığınızla eşleşecek şekilde aynalarınızı yaklaşık her 12 ila 15 saniyede bir kontrol edin","Gözleriniz asla ileri yola dönmeyecek şekilde aynalarınızı sürekli ve aralıksız izleyin","Her şerit değişikliğinden önceki kontrole ek olarak, aynalarınızı düzenli aralıklarla, yaklaşık her 5 ila 8 saniyede bir tarayın"],"explanation":"Aynalarınızı düzenli olarak, yaklaşık 5-8 saniyede bir kontrol edin; ayrıca her şerit değişikliğinden önce de bakarak trafiği ve kör noktaları takip edin."},"143":{"q":"Islak, gri bir öğleden sonra ve çekici-dorse aracınızı dar bir ara sokaktaki yükleme rampasına geri geri yanaştırmanız gerekiyor. Görüş kötü, dorsenin sağ tarafı gölgede kayboluyor ve size yardım edecek bir işaretçi yok. Manevrayı mümkün olduğunca güvenli yapmak için hangi tarafa doğru geri gitmelisiniz?","options":["Sağ (kör) tarafa doğru, çünkü dorseyi kendinizden uzağa savurmak çekiciye daha fazla dönüş açıklığı verir","En yoğun trafiğin olduğu tarafa doğru, böylece diğer sürücüler sizi görüp dorse için durur","Rampayı en yakın eden tarafa doğru, geri geri kat etmeniz gereken mesafeyi kısaltmak için","Sürücü (sol) tarafına doğru, böylece kendi yan camınızdan dorsenin tüm boyunu izleyebilirsiniz"],"explanation":"Sürücü (sol) tarafına doğru geri gitmek, römorkun tüm boyunu kendi pencerenizden izlemenizi sağlar, böylece arka kısım ve izlediği yol sürekli görüş alanınızda kalır."},"144":{"q":"Sefer öncesi kontrolünüzde, açık platformlu (flatbed) bir treylere 38 fitlik tek bir çelik kirişi bağlıyorsunuz. Uzunluğa dayalı bağlama için federal asgari şartı yine de karşılayan EN AZ sayıda bağlama (tie-down) kullanmak istiyorsunuz (çalışma yükü limiti zaten sağlanmış durumda). Kural bu yük için en az kaç bağlamaya izin verir?","options":["2 bağlama, çünkü 5 fitten uzun her parça her zaman tam olarak iki tane gerektirir","3 bağlama, çünkü bağlamayı her 3 saatte bir yeniden kontrol edersiniz","8 bağlama, çünkü yük uzunluğunun her 5 fiti için bir tane gerekir","4 bağlama, çünkü yük uzunluğunun her 10 fiti için bir tane gerekir"],"explanation":"Yük her 10 fit uzunluk için en az bir bağlama gerektirir; bu nedenle 38 fitlik kiriş yukarı yuvarlanarak dört bağlamaya çıkar."},"145":{"q":"Hava donma noktasının hemen altında ve yüklü çekici-dorseniz ile bir köprü üzerindeki viraja yaklaşıyorsunuz. Virajı takip etmek için direksiyonu çevirdiğinizde ön tekerlekler buz üzerinde tutuşunu kaybediyor. Bu ön tekerlek kaymasının EN olası sonucu nedir ve araç nasıl tepki verir?","options":["Araç düz bir şekilde ilerlemeye devam eder ve ön lastikler tutuşu geri kazanana kadar direksiyonu hangi yöne çevirirseniz çevirin aynı düz yönde gider.","Arka çeker tekerlekler bir yana savrulur ve dorse kabinin arkasında katlanmaya (jackknife) başlar.","Araç amaçladığınızdan daha keskin döner ve ön kısmı virajın iç tarafına doğru çekilir.","Direksiyon sertleşir, ön tekerlekler daha güçlü kavrar ve kamyon çevirdiğiniz yöne doğru aşırı sapar."],"explanation":"Ön tekerlek kaymasında ön lastikler tutuşu kaybeder, bu yüzden direksiyon etki etmez ve ön lastikler tutuşu yeniden kazanana kadar araç düz gitmeye devam eder."},"146":{"q":"ABS'siz, yüklü bir çekici-römork ile otoyol hızında giderken önünüze ani bir araba girip kısa mesafede duruyor. Maksimum frenlemeye ihtiyacınız var ama aracı kontrol altında tutmanız ve direksiyon kullanabilmeniz gerekiyor. Kontrollü frenleme yöntemini uygularken fren pedalı ile ne yapmalısınız?","options":["En kısa durma için pedala sonuna kadar basıp tekerlekleri kilitlemek","Tekerlekler kilitlenmeden hemen önceki noktada pedala sıkı ve sabit basınç uygulamak, ancak tekerlekler kilitlenmeye başlarsa basıncı hafifçe azaltmak","Tekerlekler dönmeye devam etsin diye pedala sert ve hızlı bir şekilde tekrar tekrar pompalamak","Ayak frenine hiç dokunmadan aracı yalnızca römork el valfi ile yavaşlatmak"],"explanation":"Kontrollü frenleme, tekerlekleri kilitleme noktasının hemen altında sağlam ve sabit basınç uygulamak, yalnızca kilitlenmeye başlarlarsa gevşetmektir, böylece hâlâ direksiyon kullanabilirsiniz."},"147":{"q":"Tam yüklü bir römorkla uzun ve dik bir dağ yokuşundan iniyorsunuz. Tepede düşük vites seçtiniz, ancak inişin ortasında yanık bir koku alıyorsunuz, fren pedalı her basışta daha yumuşak hissettiriyor ve hafif, düzenli fren yapmanıza rağmen kamyon kademeli olarak hız kazanıyor. İleride bir tabela: 'KAÇIŞ RAMPASI 1 MİL'. Bu rampanın ne için yapıldığını düşünürsek, hangi ifade doğrudur?","options":["Her yüklü kamyonun, yokuştan inmeye devam etmeden önce frenlerin soğuması için durmak zorunda olduğu zorunlu bir dinlenme alanıdır.","Aşırı ısınan frenleriniz toparlanırken yokuştan ayrılıp dibe daha hızlı ulaşmanızı sağlayan bakımlı bir kestirme yoldur.","Frenleri arızalandığında veya aşırı ısınmadan dolayı zayıfladığında bir aracı güvenli bir şekilde durdurmak için tasarlanmış acil bir kaçış rampasıdır.","Frenlerin hiç tam durmadan ısı atması için yavaşça yuvarlanmaya devam edebileceğiniz asfalt bir cep yoludur."],"explanation":"Kaçış rampası, frenleri arıza yapmış veya aşırı ısınmadan dolayı etkisini yitirmiş bir aracı güvenle durdurmak için tasarlanan acil durum rampasıdır."},"148":{"q":"Kuru bir otoyolda 55 mil/saat hızla giderken önünüze bir araba aniden girip sert fren yapıyor. Eğitmeniniz daha sonra toplam durma mesafenizin parçalarını ayırmanızı istiyor. Bu hızda TOPLAM durma mesafenizin yaklaşık 419 fit olduğunu hatırlatıyor. Bu toplamın içinde, kamyonunuz YALNIZCA tepki süreniz boyunca -- tehlikeyi gördüğünüz an ile ayağınızın fren pedalına gerçekten bastığı an arasında, frenler henüz hiç yavaşlatma yapmadan önce -- ne kadar yol kateder?","options":["Yaklaşık 419 fit, çünkü kamyon nihayet durana kadar tüm bu süre boyunca tam hızda yuvarlanmaya devam eder","Yaklaşık 250 fit, çünkü kısa hüzmeli farlarınız aşağı yukarı bu kadar uzağa ulaşır ve bu kadar ileriye tepki verebilirsiniz","Yaklaşık 6 fit, çünkü otoyol hızında eğitimli refleksleriniz ayağınızı neredeyse anında hareket ettirir","Yaklaşık 60 fit -- ortalama bir sürücünün tepki vermesi için gereken dörtte üç saniyede katedilen mesafe kadar"],"explanation":"Tepki mesafesi, tehlikeyi algıladıktan sonra fren başlamadan önce alınan yoldur; 88 km/s hızda ortalama dörtte üç saniyelik tepki süresinde yaklaşık 60 fit eder."},"149":{"q":"Yüklü çekici-römork aracınızla bir şehir kavşağına yaklaşırken trafik ışığı sabit (yanıp sönmeyen) kırmızıya dönüyor. Trafik az ve şu anda hiçbir yan trafik veya yaya görmüyorsunuz. CDL sürücüsü olarak yasal olarak hangi davranış sizden zorunludur?","options":["Yan trafik olmadığı için hızı çok düşürüp kavşaktan geçmek","Sabit kırmızıyı tıpkı yanıp sönen kırmızı gibi değerlendirmek: yol açıksa yol vermek ama mutlaka durmamak","Tam olarak durmak ve ışık yeşile dönene kadar durmaya devam etmek","Yalnızca bir araç veya yaya gerçekten yolunuzdaysa durmak, aksi halde devam etmek"],"explanation":"Sabit kırmızı ışıkta tamamen durmanız ve ışık yeşile dönene kadar durmaya devam etmeniz gerekir."},"150":{"q":"Yüklü bir çekici-römork ile kuru ve açık bir otoyolda saatte 55 mil hızla ilerliyorsunuz ve şeridinizde yaklaşık çeyrek mil (12-15 saniye) ileride kaputu açık, arızalı bir araç fark ediyorsunuz. Yan şeritteki trafik yoğun olduğundan henüz şerit değiştiremiyorsunuz. Atılacak EN İYİ ilk adım nedir?","options":["Hızınızı koruyun ve tepki vermeden önce engele yaklaşık 200 fit kalana kadar bekleyin, çünkü bu size bolca yer bırakır","Bir boşluk yaratıp arızalı araca ulaşmadan önce yan şeride zorla girmek için kısa süreliğine hızlanın","Engele ulaşmadan önce mümkün olduğunca çok hız kaybetmek için hemen sert şekilde fren yapın","Gaz pedalından ayağınızı çekin ve durum geliştikçe yumuşak bir şekilde yavaşlamaya hazır olmak için ayağınızı fren pedalının üzerine getirin"],"explanation":"Tehlike çok ileride olduğunda gaz pedalını bırakıp ayağınızı frene yaklaştırın, böylece ani durmadan yumuşakça yavaşlayabilirsiniz."},"151":{"q":"Kuru, açık, iki şeritli bir karayolunda 35 mil/saat hızla 60 fitlik bir çekici-römork kombinasyonu kullanıyorsunuz ve öndeki aracın arkasında uygun bir takip mesafesi bırakmak istiyorsunuz. Aracınızın uzunluğuna göre, bu iyi koşullarda korumanız gereken EN AZ güvenli takip mesafesi nedir?","options":["Yaklaşık 6 saniye — aracınızın uzunluğunun her 10 fiti için bir saniye","Yaklaşık 7 saniye — her 10 fit için bir saniye artı hız için bir ek saniye","Sabit 4 saniye, çünkü 4 saniye iyi havada her araç için standart aralıktır","35 mil/saatte ölçülü bir mesafeye gerek yoktur çünkü bu hız hızlıca durmaya yetecek kadar düşüktür"],"explanation":"Aracın her 10 fit uzunluğu için bir saniye takip mesafesi bırakın; bu nedenle 60 fitlik bir araç 40 mil/saat ve altında yaklaşık 6 saniyeye ihtiyaç duyar."},"152":{"q":"Sabahın erken saatlerinde sefer öncesi kontrolünüzü yapıyorsunuz. Motoru çalıştırıp gösterge panelindeki göstergeleri izliyorsunuz. Kamyonun sürmeye güvenli olduğuna karar vermeden önce, çalıştırmadan sonraki ilk anlarda motor yağ basıncı göstergesi (veya yağ basıncı uyarı ışığı) ne yapmalıdır?","options":["Motor soğukken yağ basıncı sıfırda kalmalı, basınç ancak birkaç kilometre sürdükten sonra yükselmelidir.","Yağ basıncı, çalıştırmadan kısa bir süre sonra normal değere yükselmelidir (ve yağ basıncı uyarı ışığı sönmelidir).","Yağ basıncı uyarı ışığı motor çalıştığı sürece yanık kalmalıdır; yağlama sisteminin çalıştığını böyle anlarsınız.","Yağ basıncı kısa süreliğine normalin çok üstüne fırlamalı ve orada kalmalıdır, çünkü yüksek değer güçlü yağlama anlamına gelir."],"explanation":"Motor çalıştıktan kısa süre sonra yağ basıncı normal seviyeye yükselmeli ve yağ basıncı uyarı lambası sönmelidir; bu, yağlama sisteminin çalıştığını gösterir."},"153":{"q":"Sıcak bir öğleden sonra, uzun bir yokuşu düşük viteste ağır yükle çıkıyorsunuz. Gösterge paneline baktığınızda, soğutma suyu sıcaklık göstergesinin ibresinin normal aralığının çok üzerine çıktığını görüyorsunuz. Bu özel göstergenin size bildirmek için tasarlandığı şeye dayanarak, sizi hangi durum hakkında uyarmaktadır?","options":["Yakıt deposundaki yakıt seviyesi tehlikeli derecede düşüyor ve yakında yakıt almalısınız","Alternatör artık aküyü şarj etmediği için farlarınız kararmıştır","Motor aşırı ısınıyor ve bu yük altında tırmanmaya devam ederseniz hasar görebilir","Motor yağ basıncı, hareketli parçaları düzgün yağlayamayacak kadar düşmüştür"],"explanation":"Soğutma suyu sıcaklık göstergesinin normalin üzerine çıkması, motorun aşırı ısındığını ve yük altında sürmeye devam edilirse zarar görebileceğini gösterir."},"154":{"q":"Soğuk bir sabah araç öncesi kontrolünüz sırasında motoru çalıştırıp hava basınç göstergesini izliyorsunuz. Hava depolarınızdaki basıncın çalışma aralığına doğru çok yavaş yükseldiğini ve normalden çok daha uzun sürdüğünü fark ediyorsunuz. Kompresör regülatörü henüz devreye girip kesmedi. Aşağıdakilerden hangisi bu yavaş basınç artışının EN olası açıklamasıdır?","options":["Kompresör mükemmel durumdadır ve basıncı kademeli olarak yükselterek sistemi koruyordur","Hava depolarınız zaten doludur, bu yüzden gösterge yalnızca kalıntı basıncı gösteriyordur","Servis frenleriniz çok iyi durumdadır, bu da havanın depolara girme hızını yavaşlatıyordur","Sistemde hava kaçağı vardır ya da kompresör zayıftır, bu yüzden basınç olması gerekenden daha yavaş yükseliyordur"],"explanation":"Hava basıncının çok yavaş yükselmesi, sistemde bir hava kaçağı veya talebi karşılayamayan zayıf bir kompresör olduğunu gösterir."},"155":{"q":"Donma noktasının hemen altındaki bir sıcaklıkta, sabah erken saatte sefer öncesi muayene yapıyorsunuz. Kaputu kaldırıp elinizi motorun kayışları ile radyatör ve kalorifer hortumları boyunca gezdiriyorsunuz. Aradığınız gerçek güvenlik kusuru, bu kamyonun sefere çıkmasını engellemesi gereken bulgu hangisidir?","options":["Kayış ve hortumlarda çatlaklar, lif lif ayrılma, yumuşak noktalar veya sızıntı belirtileri","Fabrika parlaklığını yitirmiş, artık mat ve tozlu görünen kayış ve hortumlar","Üzerinde artık okunabilir bir üretici marka etiketi bulunmayan hortumlar","Yeniyken sahip olduğu parlak renkten daha koyu bir tona dönüşmüş bir kayış"],"explanation":"Kayışları ve hortumları çatlak, aşınma, yumuşak noktalar veya sızıntı belirtileri için kontrol edin; bu yıpranma arızaya veya motor hasarına yol açabilir."},"156":{"q":"Soğuk bir sabah araç öncesi kontrolünüzde, arka çeker dingilindeki çelik jantlardan birinde enine giden ince bir çatlak buluyorsunuz ve başka bir tekerlekteki iki bijon somununun gözle görülür şekilde gevşek olduğunu fark ediyorsunuz. Lastiklerin kendisi havayı tutuyor ve iyi diş derinliğine sahip. Yük zaman açısından kritik olduğu için sevkiyatçı sefere çıkmanız için sizi sıkıştırıyor. Bu aracı kullanmakla ilgili doğru karar nedir?","options":["Lastikler havayı tuttuğu ve iyi dişe sahip olduğu için tekerlekler yeterince güvenlidir; dikkatlice servise gidip teslimattan sonra kontrol ettirebilirsiniz.","Çatlak jant ve gevşek bijon somunları hizmet dışı bırakma kusurlarıdır; bunlar onarılana kadar araç kullanılmamalıdır.","Gevşek bijon somunlarını elle sıkın ve çatlak jantı izleyin; çatlak ilk 50 mil içinde büyümezse sefere devam edebilirsiniz.","Bu yalnızca yön dingilinde bir sorundur; bunlar arka çeker tekerlekler olduğundan, oradaki çatlak jant ve gevşek bijonlar küçük aşınmadır ve araç çalışmaya uygundur."],"explanation":"Çatlak jantlar ve gevşek bijon somunları, aracın trafikten men edilmesini gerektiren kusurlardır; bu nedenle onarılana kadar araç sürülmemelidir."},"158":{"q":"Sahada araç öncesi muayene sırasında, çekicinin tam altında zeminde taze bir sıvı birikintisi buluyorsunuz. Hazne seviyeleri hâlâ normal aralıkta okuyor ve kamyon çalışıp sorunsuz dönüyor. Teslimat zaman pencereniz için zaten gecikmiş durumdasınız. Doğru hareket tarzı nedir?","options":["Sıvı seviyesini not edin, güvenli olmak için hazneyi tamamlayın ve göstergeler normal okuduğu için yolculuğa devam edin","Şimdilik dokunmayın ve sızıntının kötüleşip kötüleşmediğini görmek için ilk 50 mil içindeki ilk duruşunuzda birikintiyi yeniden kontrol edin","Sizi geç bıraksa bile, sızıntının kaynağını bulup tamir ettirmeden araca binmeyin","Birikintiyi silin, muayeneyi yeterli olarak kaydedin ve sürerken göstergeleri yakından izleyin"],"explanation":"Bilinen bir sıvı kaçağı, ciddi bir arızaya yol açabilen bir kusurdur; bu yüzden kaynağını bulup onartmadan, geç kalsanız bile araç sürmeyin."},"159":{"q":"Şafaktan hemen önce sefer öncesi araç çevresi kontrolünü yapıyorsunuz. Birkaç arka reflektör ve iki arka/gabari lambası kurumuş yol kiriyle kaplı ve bir arka lamba camı, ışıklar açıkken bile sönük görünüyor. Kamyon bunun dışında yüklü ve yola çıkmaya hazır. Yola çıkmadan önce lambalar ve reflektörler için muayene standardını en iyi hangi eylem karşılar?","options":["Reflektörler pasif olduğu için onlara dokunmayın, ancak yanmayan herhangi bir arka lamba ampulünü değiştirin","Reflektörlerin işlevini görmek için temiz olması gerekmediğinden yalnızca elektrikle çalışan lambaları silin","Sönük veya kirli camları yanmış bir lambayla karıştırılmamaları için bantla kapatın, sonra bir tamirhaneye gidin","Tüm lambalar ve reflektörlerdeki kiri temizleyin ve yola çıkmadan önce her birinin çalıştığını doğrulayın"],"explanation":"Yola çıkmadan önce tüm lambalar ve reflektörler hem temiz hem çalışır olmalıdır; çünkü kir, reflektörün yansıtmasını ve lambanın görülmesini engeller."},"160":{"q":"Sefer öncesi muayeneye başlamak için park yerindeki kamyonunuza geliyorsunuz. Bir an önce yola çıkmak istediğinizden, önce ne yapacağınızı zihninizde sıralıyorsunuz: motoru ısıtmak, çevreyi dolaşmak, frenleri test etmek, ışıkları kontrol etmek. Araçta herhangi bir şeye dokunmadan önce, muayene yönteminin EN İLK adımına doğru biçimde hangi işlem aittir?","options":["Araca yürüyerek yaklaşıp genel bir gözden geçirme yapmak: kabine binmeden önce genel durumunu, eğimini/duruşunu, altındaki taze sıvı birikintilerini ve etrafındaki tehlikeleri gözlemlemek","Siz çevresinde dolaşırken göstergeler doğru okusun diye motoru çalıştırıp çalışma sıcaklığına kadar ısıtmak","Yaklaşık 5 mil/saat hızla ileri giderek ve fren pedalına basarak basınçlı servis freni testini yapmak","Ön ve arkaya yürüyüp tüm dış aydınlatmaların ve reflektörlerin temiz, doğru renkte ve çalışır durumda olduğunu doğrulamak"],"explanation":"Sefer öncesi muayeneye, araca binmeden önce yürüyerek genel bir bakışla başlayın; duruşunu, altındaki sıvı birikintilerini ve çevredeki tehlikeleri kontrol edin."},"161":{"q":"Standart (senkronize olmayan) manuel şanzımanlı, yüklü bir çekici-römork sürüyorsunuz ve düz bir otoyolda hızlanırken 5. vitesten 6. vitese geçmeniz gerekiyor. Birçok kamyonda bulunan bu tür şanzımanda dişlileri öğütmeden temiz bir şekilde üst vitese geçmek için doğru teknik nedir?","options":["Debriyaja yalnızca yarım basın (\"debriyajla frenleme\") ve kolu zorla bir sonraki vitese sokun","Vites değişiminin tamamı boyunca debriyajı sonuna kadar basılı tutun ve bu sırada gaza hafifçe basın","Bir elinizi sıkıca direksiyonda tutun ve araç hareket halindeyken hiç debriyaj kullanmadan vites değiştirin","Çift debriyaj yapın: gazdan ayağınızı çekin, debriyaja basın, boşa alın, debriyajı bırakın, sonra tekrar debriyaja basıp üst vitese geçin"],"explanation":"Üst vitese geçmek için çift debriyaj yapın: gazı bırakın, debriyaja basıp boşa alın, debriyajı bırakın, sonra tekrar debriyaja basıp üst vitese geçin."},"162":{"q":"Yüklü bir römork çekiyorsunuz ve önünüzdeki yol uzun, dik bir dağ yokuşuna iniyor. İniş sırasında frenlerinizi aşırı ısıtmadan hızınızı güvenle kontrol etmek istiyorsunuz. Düşük vitese geçişi hangi noktada tamamlamalısınız?","options":["Yokuştan inmeye başlamadan önce, hâlâ tepedeki düz zemindeyken","Zaten inerken, kamyonun hız kazandığını hisseder hissetmez","Yokuşun dibinde, yol tekrar düzleştiğinde","Ancak hafif ve sabit fren basıncı sizi yavaşlatmayı bıraktıktan sonra"],"explanation":"Uzun, dik bir yokuşa inmeden önce, hâlâ düz zemindeyken düşük vitese geçin, çünkü asıl hız kontrolü motor freniyle yapılır ve servis frenleri yalnızca destektir."},"163":{"q":"Yüklü bir römorkla uzun bir dağ yokuşundan aşağı iniyorsunuz. Kamyonunuzda bir yavaşlatıcı (retarder) bulunuyor ve inişe başlarken onu devreye alıyorsunuz. Burada yavaşlatıcının sizin için ne yaptığını EN İYİ hangi ifade açıklar?","options":["Motor gücünü artırır, böylece hız kazanıp yokuşu daha çabuk geçersiniz","Aracı yavaşlatmaya yardımcı olan ek bir frenleme kuvveti uygular; bu da servis frenlerindeki aşınmayı ve ısı birikimini azaltır","Direksiyon tepkisini keskinleştirir, böylece kamyon yokuştaki virajları daha kolay alır","İniş için ana kontroldür, bu yüzden artık inişe başlamadan önce düşük vites seçmenize gerek yoktur"],"explanation":"Yavaşlatıcı, aracı yavaşlatmak için ek fren gücü uygulayarak servis frenlerindeki aşınmayı ve ısı birikimini azaltır."},"164":{"q":"Hava donma noktasının hemen altında ve güzergâhınızdaki köprülerde ince bir buz tabakası oluşmuş. Çekiciniz, gazdan ayağınızı çektiğinizde çeker akslara etki eden bir motor (hız) yavaşlatıcısı (retarder) ile donatılmış. Bu kaygan yüzeyde bir viraj için yavaşlamak amacıyla gaz pedalını bıraktığınızda, bu yavaşlatıcıyı doğru şekilde nasıl yönetirsiniz?","options":["Yavaşlatıcıyı tamamen açık bırakın; çünkü freni yalnızca çeker tekerleklere etki eder ve bu nedenle direksiyon aksını bozamaz","Buzda ayak frenine hiç dokunmamak için yavaşlatıcıyı sert ve erken devreye sokun","Çok dikkatli kullanın veya kapatın; çünkü kaygan zeminde yavaşlatıcı çeker tekerleklerin yol tutuşunu kaybetmesine ve kaymasına neden olabilir","Tahminde herhangi bir buzlanma olduğunda araç öncesi kontrolde yavaşlatıcıyı sökün veya devre dışı bırakın"],"explanation":"Kaygan zeminde yavaşlatıcıyı dikkatle kullanın veya kapatın, çünkü çekiş tekerleklerinin tutuşunu kaybedip kaymasına neden olabilir."},"165":{"q":"Gece, dar bir yükleme rampasına römorkunuzla geri geri giriyorsunuz. Sizi yönlendirecek bir yardımcı yok ve rampa alanının bir kısmı park etmiş römorklar nedeniyle görüş açınızdan kapalı. Bu manevrayı tamamlamanın en güvenli ve en doğru yolu hangisidir?","options":["Şeridi en az süre kapatmak ve manevrayı kısa tutmak için mümkün olduğunca hızlı geri gitmek","Geriye kaymadan düz girebilmek için motoru yükseltip debriyajı yarım basılı tutmak","Yalnızca sürücü tarafı aynasına bakmak, çünkü yolcu tarafı kör noktanızdır ve kontrol etmeye değmez","Yavaşça, her iki aynayı da kullanarak geri gitmek ve gideceğiniz yeri gözden kaybettiğinizde yeniden konumlanmak için ileri çekmek"],"explanation":"Her iki aynayı kullanarak yavaşça geri gidin ve gideceğiniz yeri göremediğinizde yeniden konumlanmak için öne çekin."},"167":{"q":"Yük indirme rampasına sağa dönmek istediğiniz yoğun bir kavşağa yaklaşıyorsunuz. Trafik sıkışık ve küçük bir araba çekicinizin sağ tarafından yavaşça yanaşmaya başlıyor. Niyetinizi güvenli bir şekilde bildirmek ve o arabanın kaldırıma sıkışmasını önlemek için sinyali ne zaman vermelisiniz?","options":["Erken, dönüşe başlamadan çok önce, böylece diğer sürücüler tepki verecek zamana sahip olur","Direksiyonu dönüşe kırmaya başladığınız anda, böylece zamanlama hareketinizle örtüşür","Yalnızca dönüşü tamamladıktan sonra, yakındaki sürücülerin kafasını karıştırmamak için","Yalnızca gece veya görüşün düşük olduğu koşullarda, sinyallerin en çok gerekli olduğu zaman"],"explanation":"Diğer sürücülerin tepki vermesi için sinyali erken, dönüşe başlamadan çok önce verin."},"168":{"q":"Şehir içi bir caddeden bir yükleme rampası girişine doğru yavaş ve geniş bir sola dönüş yapıyorsunuz. Dönüşün yarısında direksiyon kısmen ortalanıyor ve sinyaliniz kendi kendine kapanıyor. Yan yolda bekleyen bir araba ve arkanızdan yaklaşan bir bisikletli var. Manevranın geri kalanı için sinyalinizle ilgili doğru davranış nedir?","options":["Dönüş zaten kesinleştiği için çekicinizin ön kısmı girişe girer girmez sinyali kapatın","Sinyali tekrar açın ve dönüşü tamamen bitirip aracınız düzleşene kadar yanıp sönmeye devam etmesini sağlayın","Sinyali şimdi kapalı bırakın ve bunun yerine bisikletliye niyetinizi bildirmek için frene birkaç kez hafifçe basın","Sadece dönüşün ilk saniyesinde sinyal verin; manevraya başlamadan önce yasanın gerektirdiği tek şey budur"],"explanation":"Dönüş tamamen bitip aracınız düzelene kadar sinyali sürekli verin, çünkü dorsenin tüm yayı izlemesi gerekir."},"169":{"q":"Yoğun, dört şeritli bir otoyolda yüklü bir römork çekiyorsunuz ve yaklaşık çeyrek mil ileride yavaş trafiğin birikmeye başladığını görüyorsunuz. Yakında hızınızı düşürmeniz gerekecek ve arkanızda bir sıra araç yakın takipte. Arkanızdaki sürücülere yavaşlamak üzere olduğunuzu EN İYİ hangi hareket iletir?","options":["Dikkatlerini çekmek için farlarınızı ve arka lambalarınızı hızlıca kapatıp tekrar açın","Arkadaki sürücülerin bir değişiklik beklemesi için kornaya iki kez kısa basın","Fren ışıklarınızı önceden yakıp söndürmek için fren pedalına birkaç kez hafifçe basın","Önde boşluk açmak için kısaca hızlanın, ardından boşluk kapanınca sert şekilde frene basın"],"explanation":"Arkadakileri yavaşladığınız konusunda uyarmak için fren pedalına birkaç kez hafifçe basarak fren ışıklarınızı önceden yakıp söndürün."},"171":{"q":"Şafak yeni söktü ve güneş ufukta alçakta. Işık loş ve gri; diğer sürücüleri ve yoldaki şekilleri seçmenin gitgide zorlaştığını fark ediyorsunuz. Programınıza uygun gidiyorsunuz ve görüş henüz tamamen kaybolmuş değil. Bu alacakaranlıkta hem yolu görmek hem de aynı derecede önemli olarak diğer trafik tarafından görülmek için tek en doğru hareket hangisidir?","options":["Dışarıdaki loş koşulları içeriden daha iyi değerlendirmek için kabin içi tavan lambasını yakmak","Yolu görmek için hâlâ yeterli doğal gün ışığı olduğundan tüm dış aydınlatmaları kapalı tutmak","Görüşün kötü olduğunu diğer sürücülere bildirmek için yalnızca dörtlü flaşörleri yakmak","Hem önünüzdeki yolu görebilmeniz hem de diğer sürücülerin aracınızı net görebilmesi için farlarınızı yakmak"],"explanation":"Şafakta veya alacakaranlıkta farlarınızı açın; böylece önünüzdeki yolu görür ve diğer sürücüler aracınızı net görür."},"172":{"q":"Orta yoğunluktaki trafikte saatte 55 mil hızla yüklü bir römork çekiyorsunuz. Bir binek araç aniden önünüze girip sert fren yapıyor ve tamponunuzun önündeki güvenlik mesafesini kapattığınızı fark ediyorsunuz. Tam bu anda önünüzdeki o mesafeyi korumak neden en çok önem taşır?","options":["Tehlikeye karşı ya tam durana kadar fren yapmanız ya da direksiyonla güvenle kaçmanız için gereken alanı sağlar","Frenleri daha az kullanarak daha yüksek bir seyir hızını korumanıza imkân tanır","Düzgün akan trafikte daha az fren yapıp daha az hızlandığınız için yakıt tasarrufu sağlar","Diğer sürücülerin önünüze girip şeridinizi sıkıştırmasını caydırır"],"explanation":"Öndeki boşluk kaçış payınızdır; tam durana kadar frenlemenize ya da bir tehlikenin etrafından güvenle geçmenize yer sağlar."},"173":{"q":"Yoğun, iki şeritli bir karayolunda 50 mil/saat hızla yüklü bir çekici-dorse kombinasyonu kullanıyorsunuz ve bir otomobilin arkanıza yakın girip tamponunuza yalnızca bir-iki araç boyu mesafede yakın takip ettiğini fark ediyorsunuz. Öndeki trafik düzenli akıyor ama her an yavaşlayabilir. Bu tehlikeyi yönetmenin EN İYİ yolu aşağıdakilerden hangisidir?","options":["Fren lambalarınızı yakıp arkadan yakın takip edene geri çekilmesi için işaret vermek amacıyla frene hafifçe dokunmak","Gaz pedalını kademeli olarak bırakıp takip mesafenizi artırarak önünüzde daha fazla boşluk açmak; böylece trafik yavaşlarsa yumuşak bir şekilde fren yapabilirsiniz","Hızınızı koruyup şeridinizdeki konumunuzu sabit tutmak, çünkü aracınızın arkasındaki mesafeden yakın takip eden sorumludur","Hızlanarak yakın takip eden araçtan uzaklaşmak ve güvenli aralığı yeniden oluşturmak"],"explanation":"Sıkı takip edildiğinizde gaza yavaşça basıncı azaltıp öndeki boşluğu açın; böylece trafik yavaşlarsa ani değil, yumuşak fren yapabilirsiniz."},"174":{"q":"Üç şeritli bir otoyolun orta şeridinde otoyol hızında ilerliyorsunuz. Bir otomobil, çekicinizin sağ tarafına yerleşmiş ve bu konumu koruyarak ne geçiyor ne de geride kalıyor, kabininizle aynı hizada seyrediyor. Bu yan yana düzende kalmak, bir sürücü olarak sizin için neden EN AZ tercih edilen durumdur?","options":["Paralel ilerlemek her iki aracın da gözle görülür şekilde daha fazla yakıt tüketmesine yol açar, bu yüzden uzun bir yolculukta işletme maliyetlerinizi artırır","Teksas yasaları, erişimi kontrollü bir otoyolda iki aracın bitişik şeritlerde yan yana seyretmesini özellikle yasaklar","Otomobil büyük olasılıkla kör noktalarınızdan birinde bulunuyor, dolayısıyla şerit değiştirmeniz gerekseydi onu göremeyip üzerine doğru kayabilirdiniz","Başka bir araçla aynı hizada kalmak zamanınızı boşa harcar çünkü şerit değişimini öne ilerlemek için kullanamazsınız"],"explanation":"Yan tarafınızda seyreden bir araç çoğu zaman göremediğiniz yan kör noktada bulunur, bu yüzden şerit değiştirirken ona çarpabilirsiniz."},"175":{"q":"Yüklü bir kapalı kasa kamyonla tanımadığınız bir güzergâhta giderken, hemen ileride 13 fit 2 inç olarak işaretlenmiş bir üst geçit yükseklik sınırı görüyorsunuz. Yapıya çarpmadan altından geçip geçemeyeceğinize güvenle karar vermek için önceden bilmeniz gereken EN önemli tek şey şudur:","options":["Köprüdeki ağırlık sınırını aşmamak için kapınızda yazılı brüt araç ağırlık değeri (GVWR)","Bu hızdaki toplam durma mesafeniz; 55 mil/saatte yaklaşık 419 fittir","Durmadan önce yapıyı tamamen geçebilmeniz için aracınızın uzunluğu","Üste monte edilmiş yük veya ekipman dâhil, yüklü aracınızın yüksekliği"],"explanation":"Köprü için belirtilen yükseklik sınırıyla karşılaştırabilmek için, tavana monte yük veya ekipman dahil yüklü aracınızın gerçek yüksekliğini bilmelisiniz."},"176":{"q":"53 fitlik (16 m) bir çekici-römork kullanıyorsunuz ve bir şehir caddesinden dar bir yan yola sağa dönmeniz gerekiyor. Köşeye yaklaşırken dönüşün beklediğinizden daha keskin olduğunu fark ediyorsunuz. Bu dönüşü tamamlamak için yeterli alanı korumanın EN GÜVENLİ yolu nedir?","options":["Yaklaşırken kendi doğru şeridinizde kalın, sonra dönüşü TAMAMLARKEN geniş bir yay çizin; böylece arka tekerlekleri içeri kaçan römork köşeyi temizleyebilsin ve römorkun arkasını sürekli kaldırıma yakın tutun","Önce sol şeride geçin ve dönüşe erken başlayın, böylece römorkun arkası köşeyi sıkıca keser ve kaldırıma yakın kalır","Kavşağı daha az süre kapatmak ve hızlıca boşaltmak için dönüş boyunca hızlanın","Sağınızdaki boşluğa başka bir aracın sıkışmaması için kamyonu her zaman sağ kaldırıma yapışık tutun"],"explanation":"Dorsenin arka tekerlekleri içeriden kestiği için yaklaşırken şeridinizde kalın ve dönüşü tamamlarken geniş dönün, dorsenin arkasını bordüre yakın tutun."},"177":{"q":"Tam yüklü bir birleşik araçta dur işaretinde durmuş, her iki yönde trafiğin 55 mil/saat hızla aktığı yoğun iki şeritli bir karayolunu geçmek için bekliyorsunuz. Karşı trafikte bir boşluk açılıyor. Aracınız ağır olduğu ve yavaş hızlandığı için, çıkmaya karar vermeden önce bu boşluğun size ne yapma olanağı vermesi gerekir?","options":["Ön tamponunuzu yakın kenarın hemen ötesine sokmak, böylece karşıdan gelen sürücüler sizi görüp yavaşlasın","Bir sonraki araç size ulaşmadan önce tüm aracınızla yolu tamamen geçmek veya trafiğin hızına ulaşmak","Kavşağın ortasına ulaşıp ikinci şeridi değerlendirmek için tamamen durmak","Şeride girip yaklaşan sürücünün etrafınızdan şerit değiştirmesine yetecek kadar rölantide beklemek"],"explanation":"Yaklaşan araç size ulaşmadan önce tüm aracınızı karşıya tamamen geçirebileceğiniz veya trafik hızına ulaşabileceğiniz kadar büyük bir boşluk seçin."},"178":{"q":"Çekici-römork aracınızı öğleden sonra yoğun trafikte işlek bir eyaletler arası otoyola katıyorsunuz. Bir dizi otomobil sürekli sağ yanınız boyunca ilerliyor ve aynalarınızın size neredeyse hiçbir şey göstermediği arka tekerleklerinizin yakınında oyalanıyor. Birkaç sürücü, römorkunuzun yanındaki ve arkasındaki bu cepte rahatça yerleşmiş görünüyor. Aracınızın çevresindeki bu kör nokta bölgelerine ('No-Zone'lar) ilişkin hangi yaklaşım güvenli ticari sürüş uygulamasını en iyi yansıtır?","options":["Kör noktaları normal seyir şeritleri gibi görmek ve araçların orada durmasına izin vermek, çünkü oraya kendileri girdiler ve sorumluluk onlarındır","Otomobilleri sağ arka kör noktadan dışarı itmek için sertçe hızlanmak, çünkü cebi hızla boşaltmak her zaman en güvenli çözümdür","Kör noktalardaki araçları göremeyeceğinizi kabul etmek ve mümkün olduğunda bu bölgeleri trafikten arındırmak için sürüşünüzü buna göre yönetmek","Karşılığında otomobillerin kör noktalarına yavaşça girmek, böylece risk sizinle dört tekerlekli sürücüler arasında eşit paylaşılsın"],"explanation":"No-Zone (kör nokta) bölgelerindeki araçları göremezsiniz, bu yüzden hızınızı, şerit konumunuzu ve mesafenizi ayarlayarak bu bölgeleri trafikten uzak tutun."},"179":{"q":"Tam yüklü bir katarlı aracı sürüyorsunuz ve sağ şeritte uzun, dik bir yokuş çıkışına giriyorsunuz. Yokuşu tırmanırken motorunuz zorlanıyor ve hızınız belirlenen sınırın belirgin biçimde altına düşüyor; bu sırada arkanızda daha hızlı otomobiller ve hafif araçlar birikmeye başlıyor. Bu yokuşta aracınızı yönetmenin EN İYI yolu hangisidir?","options":["En sol şeride geçin ki arkanızdaki yavaş araçlar şerit değiştirmeden sizi sağdan geçebilsin","Vites küçültüp sertçe hızlanın ki hızınızı belirlenen sınırda tutasınız ve arkanızdaki hızlı trafiği engellemeyesiniz","Hızınızı koruyun ama sağ banket üzerine çekip kısa süre durarak araç dizisinin geçmesine izin verdikten sonra devam edin","Ağır yükün sizi yavaşlatacağını kabul edin, sağ şeritte kalın ve daha hızlı trafiğin sizi soldan geçmesine izin verin"],"explanation":"Ağır yük dik yokuşta sizi doğal olarak yavaşlatır, bu yüzden sağ şeritte kalın ve daha hızlı trafiğin soldan geçmesine izin verin."},"180":{"q":"Orta yoğunluktaki trafikte üç şeritli bir otoyolda 53 fitlik bir çekici-römork kullanıyorsunuz. Sol şeritte yanınızda bir otomobil ilerliyor ve sağınızda bir giriş rampası araçları otoyola katıyor. Aynı anda her iki taraftan da yer veremezsiniz. Bu durumda yan boşluğunuzu EN İYİ şekilde yöneten eylem hangisidir?","options":["Tüm yerinizi tek bir tarafa vermek yerine her iki tarafta da bir boşluk payı korumak için aracınızı şeridinizin ortasında tutun","Römorkunuz ile katılan rampa trafiği arasındaki mesafeyi en üst düzeye çıkarmak için sola kayıp sol şerit çizgisine yanaşın","Hiçbir aracın kör noktalarınızın yanına gelememesi için kısa süreliğine sol şeride girerek şerit çizgisine oturun","Rampa trafiği katılmayı bitirene kadar sağ banketine geçin, ardından şeridinize geri dönün"],"explanation":"Aracınızı şeridin ortasında tutmak, tehlikeler aynı anda hem soldan hem sağdan geldiğinde her iki tarafta da boşluk payı korur."},"181":{"q":"Yoğun, dur-kalk trafikte bir demir yolu geçidine yaklaşıyorsunuz. Geçitte bariyer yok, yanıp sönen sinyal yok ve önünüzdeki araçlar yavaşça ilerliyor. 73 fitlik çekici-dorse katarınız raylara ulaşacak bir sonraki araç. Raylardan geçip geçmeyeceğinize karar vermenin tek en doğru yolu nedir?","options":["Bariyer ve treni haber veren sinyal olmadığı için araçla rayların üzerine girip orada beklemek","İleride, durmadan tüm geçişi tamamlamaya yetecek kadar büyük bir boşluk oluşana dek beklemek; aracınızın tüm uzunluğu artı yaklaşık 15 fit pay bırakmak","Önünüzdeki araç hareket eder etmez geçide girmek, çünkü trafiğin akışını sürdürmek önceliklidir","Geçmeye başlamak ve trafik tıkanırsa hızla geçmek için rayların üzerinde küçük vitese geçmek"],"explanation":"Tüm aracınızın boyu artı yaklaşık 15 fitlik mesafeyi hesaba katarak, durmadan tamamen geçebileceğiniz boşluk olmadan rayların üzerinden geçmeye başlamayın."},"182":{"q":"Yüklü bir çekici-römork aracını kuru, çift şeritli bir kara yolunda sürüyorsunuz ve ileride işaretli keskin bir viraj görüyorsunuz. Şu anda yasal hıza yakın gidiyorsunuz ve mevcut hızınızın bu viraj için biraz fazla olabileceğini hissediyorsunuz. Virajı güvenle almak için hızınız ve frenlemeniz konusunda ne yapmalısınız?","options":["Viraja kadar hızınızı koruyun, sonra virajın en keskin olduğu orta noktasında sert şekilde fren yapın.","Virajdan çıkana kadar bekleyin, sonra bir sonrakine hazır olmak için yavaşlayın.","Viraja girmeden ÖNCE güvenli bir hıza düşün, ardından aracı dengede tutmak için viraj boyunca hafifçe hızlanın.","Viraja sabit bir hızla girin ve kamyonu kontrol etmek için dönüş boyunca hafif, istikrarlı fren basıncına güvenin."],"explanation":"Viraja girmeden önce güvenli bir hıza yavaşlayın, sonra içinde nazikçe hızlanın; çünkü virajda fren yapmak kaymaya veya devrilmeye yol açabilir."},"183":{"q":"Kırsal iki şeritli bir karayolunda yük taşırken sürekli bir yağmur başlıyor ve zemin parlak ve ıslak hale geliyor. Trafik 55 mil/saat olan hız sınırında ilerliyor ve uzun, geniş bir virajda direksiyonun hafifçe hafiflediğini hissediyorsunuz. Azalan yol tutuşuna karşı tek başına en güvenli tepki hangisidir?","options":["55 mil/saati koru ama takip mesafeni artır, çünkü belirtilen hız sınırı hâlâ yasaldır","Çekiş akslarına ağırlık bindirip tutuşu artırmak için virajda hafifçe hızlan","Hızını koru ve ne kadar tutuş kaldığını test etmek için frene hızlıca art arda bas","Hızını belirtilen sınırın altına düşür, çünkü ıslak zemin yol tutuşunu azaltır ve fren mesafesini uzatır"],"explanation":"Güvenli hızı belirleyen, levhadaki sınır değil yol tutuşudur; ıslak zemin tutuşu azaltıp durma mesafesini uzattığı için sınırın altına inin."},"184":{"q":"Hava donma noktasının hemen altında ve hafif kar yola yapışmaya başladı. Yüklü bir çekici-römork ile, bugün daha önce açık ve kuru havada tuttuğunuz aynı otoyol hızında gidiyorsunuz. O kuru koşullara kıyasla, aracınızın yol tutuşunda beklemeniz gereken EN önemli değişiklik nedir ve nedeni nedir?","options":["Yol tutuşu büyük ölçüde azalır, bu yüzden lastikleriniz yolu çok daha az kavrar ve durmak ile direksiyon hakimiyeti için çok daha fazla mesafeye ihtiyacınız olur","Yol tutuşu yalnızca biraz azalır, bu yüzden normal bir takip mesafesi ve sabit bir hız güvende kalmak için yeterli olacaktır","Yol tutuşu kuru zemindekiyle yaklaşık aynı kalır çünkü yüklü römorkun ağırlığı lastikleri kara sıkıca bastırır","Yol tutuşu aslında biraz artar çünkü ince kar tabakası yüzeydeki boşlukları doldurur ve lastiklere tutunacak daha fazla yer verir"],"explanation":"Kar ve buz çekişi büyük ölçüde azaltır, bu yüzden lastikler yola çok daha az tutunur ve durmak ile yön vermek için çok daha fazla mesafe gerekir."},"185":{"q":"Yükünüzü rampada boşalttınız ve şimdi tamamen boş bir dorseyle filo sahasına geri dönüyorsunuz. Islak zeminde bir SUV önünüze kırıyor ve sert fren yapmak zorunda kalıyorsunuz. Daha önce tam yüklüyken olduğunuz duruma kıyasla, kamyonunuz boşken neden gerçekte durmak için DAHA UZUN bir mesafeye ihtiyaç duyabilir?","options":["Boş çekici daha ağırdır, bu yüzden artan momentumu onu durmadan önce daha ileriye taşır","Az ağırlık lastikleri yola yeterince bastırmadığından, boş kamyonun çekiş kuvveti azdır, bu yüzden tekerlekler daha kolay kilitlenir ve fren mesafesi artar","Boş dorseler daha yüksekte durur, bu da ağırlık merkezini yükseltir ve fren mesafesini uzatır","Boş kamyonda frenler daha soğuk çalışır ve etkisini yitirir, bu da 55 mil/saatte durma mesafesine yaklaşık 60 fit ekler"],"explanation":"Boş bir kamyonda lastikleri yola bastıran ağırlık az olduğundan tutuş azalır, tekerlekler daha kolay kilitlenir ve fren mesafesi artar."},"186":{"q":"Tamamen yüklü bir römorkla uzun ve dik bir dağ yokuşundan iniyorsunuz. İnişin yarısında, sadece hızınızı sabit tutmak için fren pedalına sürekli bastığınızı fark ediyorsunuz ve kabinde sıcak bir koku oluşmaya başlıyor. Ana servis frenlerinize ne olduğunu ve nedenini EN İYİ açıklayan ifade hangisidir?","options":["Frenler ısındıkça durdurma gücü kazanıyor, bu yüzden inişin geri kalanında onlara güvenle daha sert basabilirsiniz.","Frenler sürekli hava akışıyla kendilerini soğutuyor, bu yüzden sabit pedal basıncı hızınızı kontrol etmenin doğru ana yoludur.","Frenler aşırı ısınıyor ve etkisini yitirmeye (fren sönmesi) başlıyor; bu yüzden ana kontrol düşük viteste motor freni olmalı, frenler ise yalnızca bir destek olmalıdır.","Frenler römork tekerleklerini kilitlemek üzere, bu yüzden römorkun makaslamasını önlemek için pedala hızlıca pompalamalısınız."],"explanation":"Uzun bir inişte frenler aşırı ısınıp etkisini yitirebilir, bu yüzden asıl yavaşlatmayı düşük viteste motor freni yapmalı ve frenler yalnızca destek olarak kullanılmalıdır."},"187":{"q":"Ağır, tamamen yüklü bir römork çekerek uzun ve dik bir dağ yokuşunun tepesindesiniz. Yağmur yağıyor ve yol, inişin yaklaşık ortasında keskin bir şekilde dönüyor. Frenleri bırakıp inişe başlamadan önce, aşağı inmek için güvenli bir hız belirlemeniz gerekir. Aşağıdakilerden hangisi, güvenli iniş hızınızın neye bağlı olması gerektiğini doğru şekilde açıklar?","options":["Yalnızca yokuşun dikliğine, çünkü yer çekimi bir kamyonun yokuş aşağı ne kadar hızlı yuvarlanacağını belirleyen tek faktördür","Esas olarak tepedeki motor devrine (RPM), çünkü takometre değerini tutturmak her yokuş için doğru hızı belirler","Neredeyse tamamen belirlenen hız sınırına, çünkü o değer özellikle bu yokuştaki tamamen yüklü ticari araçlar için belirlenmiştir","Aracınızın ve yükünüzün toplam ağırlığına, yokuşun uzunluğu ve dikliğine, yol koşullarına ve hava durumuna"],"explanation":"Güvenli iniş hızı; aracın ve yükün toplam ağırlığına, yokuşun uzunluğuna ve dikliğine, yol durumuna ve hava koşullarına bağlıdır."},"188":{"q":"Tam yüklü bir römork ile uzun ve dik bir dağ yokuşundan inmek üzeresiniz. İnişte frenleri aşırı ısıtıp etkisini kaybettirmeden hızınızı kontrol etmek istiyorsunuz. Hangi vitesin kullanılacağına karar vermenin en iyi yolu hangisidir?","options":["Yokuşu çıkmak için kullanacağınız aynı küçük (düşük) vitesi kullanın ve bunu inişe başlamadan ÖNCE seçin.","Motor inişte daha rahat çalışsın diye çıktığınız vitesten çok daha yüksek bir vitese geçin.","Vitesi boşa alın ve hızınızı tutmak için sürekli fren basıncına güvenin.","Normal otoyol vitesinizde kalın ve yalnızca frenler etkisini kaybetmeye başlarsa vites küçültün."],"explanation":"Yokuşu çıkmak için kullanacağınız düşük vitesin aynısını seçin ve inişe başlamadan önce vitese geçin."},"189":{"q":"Sabahın erken saatleri ve dış sıcaklık göstergesi donma noktasının hemen altını gösteriyor (yaklaşık 30 F / -1 C). Sürdüğünüz iki şeritli karayolu tamamen kuru görünüyor ve son bir saattir hiçbir tutuş (çekiş) sorunu yaşamadınız. Şimdi bir nehir vadisini aşan uzun bir üst geçide yaklaşıyorsunuz. Üst geçide ulaşırken yapabileceğiniz EN GÜVENLİ varsayım aşağıdakilerden hangisidir?","options":["Yol yüzeyi kuru kaldığı ve iyi tutuş sağladığınız için, üst geçit tablası az önce geçtiğiniz asfalttan daha kaygan olmayacaktır","Yolun geri kalanı temiz olsa bile üst geçit buzlu olabilir, çünkü köprüler ve üst geçitler yolun diğer kısımlarından önce donar","Üst geçit en son donacaktır, bu yüzden yavaşlamanız gerekirse fren yapmak veya vites küçültmek için en güvenli yerdir","Üst geçitler normal asfalttan daha erken donmaz, bu yüzden buza karşı yalnızca öğleden sonra hava ısındığında dikkat etmeniz yeterlidir"],"explanation":"Köprüler ve üst geçitler yolun diğer kısımlarından önce donar, bu yüzden yolun geri kalanı temizken bile üst geçit buzlu olabilir."},"190":{"q":"Uzun bir kuraklık döneminin ardından sürekli bir yağmur yeni başladı ve karayolunda eski yağ ve tozun üzerinde ince bir su tabakası birikiyor. Trafik az olduğu için yüksek hızda gitme isteği duyuyorsunuz. Lastiklerinizin yola tutunmasını sağlamak ve su kızağına (hidroplanaj) girmemek için, bu koşullarda hızınızı altına düşürmek üzere, su kızağının yaklaşık hangi hızda BAŞLAYABİLECEĞİNİ bilmelisiniz?","options":["Su kızağı yaklaşık 110 km/s (70 mil/s) hıza ulaşana kadar başlayamaz, bu yüzden yağmurda bunun altındaki her karayolu hızı güvenlidir.","Su kızağı yalnızca yaklaşık 8 km/s (5 mil/s) gibi çok düşük hızlarda sorun olur, bu yüzden esas olarak otopark sorunudur.","Su kızağı yaklaşık 48 km/s (30 mil/s) kadar düşük hızlarda başlayabilir, bu yüzden bu ıslak ve kaygan tabakada hızınızı bunun altına düşürmelisiniz.","Su kızağı yaklaşık 145 km/s (90 mil/s) üzerine çıkana kadar başlamaz, ki bu herhangi bir yasal kamyon hızından çok daha yüksektir."],"explanation":"Su kayması, ıslak ve kaygan bir film üzerinde yaklaşık 30 mil/saat kadar düşük hızlarda bile başlayabilir, bu yüzden hızınızı bunun altına düşürün."},"191":{"q":"Şiddetli bir yaz sağanağı sırasında Teksas eyaletler arası otoyolunda yüklü bir yarı römorku otoyol hızında kullanıyorsunuz. Şeridin tekerlek izlerinde göllenmiş su birikmiş. Aniden direksiyon hafif ve gevşek hissettiriyor, ön lastikleriniz zeminle teması kaybetmiş gibi görünüyor ve gaz pedalını değiştirmediğiniz halde hız göstergesi titriyor. Su kızağı (hidroplaning) yapmaya başladığınızı fark ediyorsunuz. Doğru ilk hareket nedir?","options":["Islak yolda en önemli şeyin durma mesafesi olduğu için, hızı mümkün olduğunca çabuk düşürmek amacıyla fren pedalına sertçe basıp basılı tutmak","Lastikleri daha iyi tutuşa sahip zemine geri döndürmek için şeridin daha yüksek ve kuru orta kısmına doğru hızlıca direksiyon kırmak","Mevcut hızı korumak ama çekiş tekerlekleri ıslak yüzeyde hâlâ tutunduğu için motor freni kullanmak amacıyla küçük vitese geçmek","Gaz pedalı üzerindeki baskıyı bırakmak, direksiyonu düz tutmak ve lastikler yolla yeniden sağlam temas kurana kadar aracın yavaşlamasına izin vermek"],"explanation":"Su kayması olduğunda gazdan ayağınızı çekin, direksiyonu düz tutun ve lastikler yolla yeniden sağlam temas kurana kadar aracın yavaşlamasına izin verin."},"192":{"q":"Batı Teksas'ta temmuz ortası ve asfalt sıcaktan titreşiyor. İki saattir otoyol hızında gidiyorsunuz ve zorunlu yük ile bağlama kontrolü için kenara çektiniz. Durduğunuz sırada, bu koşullarda izlemeniz EN önemli lastik durumu hangisidir?","options":["Arka çeker lastiklerinde 4/32 inçin altına inmiş diş derinliği","Yan duvardaki silik yazılar ve gövdedeki eksik marka işaretleri","Hemen şimdi soğuk şişirme değerine tamamlamanız gereken hafif düşük basınç","Lastiklerin aşırı ısınması ve basıncın soğuk ayarın üzerine çıkması, patlama riskine işaret ediyor"],"explanation":"Sıcak havada, soğuk ayarın üstüne çıkan basınçla ısınan lastiklere dikkat edin, çünkü aşırı ısınmış ve fazla basınçlı lastikler patlamaya yatkındır."},"193":{"q":"Vardiyanızın başında hava sıcaklığı -2 derece (28 F) ve gece yağan ıslak kar çekiciinize donmuş durumda. Sefer öncesi kontrolünüzde ön camın alt yarısında ince bir buz tabakası ve her iki yan aynada donmuş kar kabuğu buluyorsunuz. Zaten programın gerisindesiniz. Otoyola çıkmadan önce Texas DPS sizden ne yapmanızı ister?","options":["Sürmeden önce ön cam ve her iki ayna tamamen temiz olacak şekilde tüm buzu ve donmuş karı tamamen temizlemek","Sadece baktığınız sürücü tarafındaki alanı temizleyip aynaları bırakmak, çünkü hareket ettiğinizde defroster onları eritecektir","Ön camda küçük bir görüş alanı kazıyıp, buzlu aynalar yerine geri görüş kamerasına ve omuz kontrollerine güvenmek","Buz tabakasını yerinde bırakmak, çünkü -2 derecede sıcaklık buzun yol tutuşunu etkilediği noktanın üzerindedir ve düşük hızda sürmek"],"explanation":"Sürüşe başlamadan önce ön cam ve her iki ayna tamamen temiz olacak şekilde tüm buz ve donmuş karı eksiksiz temizleyin."},"194":{"q":"Nemli bir sabahta hava sıfırın hemen altında ve sefer öncesi kontrolünüzde çekicinizin altındaki asfalt buzlu değil, sadece ıslak ve parlak görünüyor. Otoyola çıkarken direksiyonun hafiflediğini ve aracın hafifçe kaydığını hissediyorsunuz. Büyük olasılıkla üzerine girdiğiniz 'kara buz' tam da bu tür bir durumda neden bu kadar tehlikelidir?","options":["Görünür şekilde pürüzlü, kabuklu bir yüzey oluşturur, böylece onu erkenden fark edip ona varmadan sert fren yapabilirsiniz","İnce, saydam bir tabakadır ve yolu yalnızca ıslakmış gibi gösterir; bu yüzden onu göremezsiniz ve tutuşu kaybedene kadar yüzeyin donmuş olduğunu fark etmeyebilirsiniz","Yalnızca tepe sırtlarında birikir, bu yüzden tehlike rotanın kısa ve önceden tahmin edilebilir bölümleriyle sınırlıdır","Her zaman kalın beyaz bir tabaka olarak görünür ve önceden yavaşlamanız için size bolca uyarı verir"],"explanation":"Kara buz, yolu yalnızca ıslak gösteren ince ve saydam bir tabakadır; bu yüzden görülemez ve çekişi kaybedene kadar yüzeyin donmuş olduğu anlaşılmayabilir."},"195":{"q":"Şafaktan hemen sonra, yoğun ve parça parça sisin görüş mesafesini yaklaşık aracınızın boyu kadar düşürdüğü alçak bir nehir vadisinden yüklü bir römork çekiyorsunuz. Şeritte durmak yerine yavaşça ilerlemeye karar veriyorsunuz. Hangi aydınlatma seçimi size en iyi görüşü sağlar ve sizi başkalarına en görünür kılar?","options":["Uzun farlara geç, çünkü daha parlak ışık öndeki sisi daha derine keser","Parlamayı önlemek için farları kapat ve sadece dörtlü ikaz flaşörlerini çalıştır","Kısa farlarını kullan (varsa sis farlarıyla birlikte), çünkü uzun farlar sisten yansıyıp ışığı sana geri gönderir","Uzun farları açık bırak ama sadece karşıdan gelen bir araca 500 fit yaklaştığında kıs"],"explanation":"Siste kısa farları kullanın, çünkü uzun farlar havadaki su damlacıklarından yansıyıp parlamayı size geri yansıtır ve görüşünüzü azaltır."},"196":{"q":"Sokak lambası olmayan, kırsal iki şeritli bir karayolunda karanlık, aysız bir gece. Kısa huzmeli farlarınız önünüzdeki yaklaşık 250 fitlik yolu aydınlatıyor. Güvenli sürmek için hızınızı nasıl seçmelisiniz?","options":["Gündüz hız sınırına uyun, çünkü sınır yol için belirlenmiştir ve karanlık bastıktan sonra değişmez","Toplam durma mesafenizin, farlarınızın gösterdiği mesafenin iki katına eşit olduğu bir hız seçin; bu size güvenlik payı sağlar","Sabit 88 km/sa (55 mil/sa) hızda gidin ve önünüzdeki herhangi bir şeye zamanında tepki vermek için uzun huzmeli farlarınıza güvenin","Farlarınızın aydınlattığı mesafe içinde tamamen durabilecek kadar yavaş sürün"],"explanation":"Farlarınızın aydınlattığından daha hızlı sürmeyin; hızınızı, farlarınızın önünüzde aydınlattığı mesafe içinde durabilecek kadar düşük tutun."},"197":{"q":"Öğleden sonranın sonlarında, yüklü bir çekici-yarı römork aracını kırsal iki şeritli bir karayolunda sürerken aniden bastıran şiddetli sağanak görüşünüzü birkaç yüz fitle sınırlandırıyor. Trafik seyrek ama karşıdan zaman zaman araçlar çıkıyor; hem yolu görmek hem de görülmek istiyorsunuz. Bu şiddetli yağmur koşullarında en doğru far ayarı hangisidir?","options":["Kısa huzmeli farlar, çünkü şiddetli yağmurdan geri yansıyan parlama yaratmadan başkalarının sizi görmesini sağlar","Uzun huzmeli farlar, çünkü şiddetli yağmurun içini görebilmek için aydınlattıkları ek mesafe gereklidir","Farlar kapalı, yalnızca park lambaları açık, böylece ıslak yol yüzeyi dikkat dağıtan yansımalar oluşturmaz","Karşıdan gelen trafiğe görüşün kötü olduğunu bildirmek için uzun huzmeli farları yakıp söndürmek"],"explanation":"Şiddetli yağmurda kısa farları kullanın; böylece diğer sürücüler sizi görür ve uzun farların yağmurdan yansıyıp oluşturduğu parlamadan kaçınırsınız."},"198":{"q":"Teksas'ta bir sıcak hava dalgasında öğleden sonranın ortasıdır ve yol yüzeyi sıcaklığı gün boyunca yükselmektedir. Gölgeli bir kavşak için yavaşlarken, ileride şeritteki asfalt eklerinden sızan koyu, parlak katran çizgileri fark edersiniz. Çok sıcak havanın yol yüzeyini nasıl etkilediğini göz önünde bulundurarak, bu lekelerin üzerinden geçerken EN ÇOK hangi tehlikeye karşı hazırlıklı olmalısınız?","options":["Katran sertleşip pürüzlü, yüksek tutuşlu bir yüzeye dönüşeceğinden normalden daha sert fren yapabilirsiniz","Sızan katran yol yüzeyini kayganlaştırabilir, bu yüzden hızınızı azaltın ve üzerinden geçerken sert fren veya keskin direksiyon hareketinden kaçının","Lekeler kara buz oluşturuyordur, dolayısıyla ıslak görünen yüzey aslında donmuştur","Sıcaklık lastik basıncını yeterince yükselteceğinden katran üzerindeki tutuş iyileşir, bu nedenle hız değişikliğine gerek yoktur"],"explanation":"Çok sıcak havalarda zift yüzeye çıkarak kayganlaşır, bu yüzden hızınızı azaltın ve üzerinden geçerken sert frenden veya keskin direksiyondan kaçının."},"199":{"q":"Rüzgarlı, esintili bir öğleden sonrasında, açık bir otoyol kesiminde yüksek ve hafif yüklü bir kapalı kasa römorkla yola çıkmak üzeresiniz. Bir iş arkadaşınız endişelenmemenizi, çünkü boş ve yüksek bir römorkun rüzgarda 'kendi kendini daha iyi idare ettiğini' söylüyor. Kuvvetli yan rüzgarın yüksek profilli bir römork üzerindeki etkisini düşününce, aracınızı kontrol etme konusunda gerçekte ne beklemelisiniz?","options":["Yüksek römorku kontrol etmek daha kolay olur, çünkü yüksekliği onu rüzgara karşı yere sabitler","Yüksek römork daha hızlı durur, çünkü rüzgar ileri hareketinize karşı iterek yardımcı olur","Yüksek römorku kontrol etmek daha zor olur, çünkü kuvvetli rüzgar onun büyük ve yüksek yan yüzeyine baskı yapar","Yüksek römork daha az yakıt tüketir, çünkü rüzgar çeker dingilinizdeki yükü azaltır"],"explanation":"Kuvvetli rüzgâr, yüksek bir dorsenin büyük ve yüksek yan yüzeyine yüklenerek aracın kontrolünü zorlaştırır, özellikle boş veya hafif yüklüyken."},"200":{"q":"Hava donma noktasının hemen altında ve hafif bir yağmur yağıyor. Gölgede kalan bir köprüye yaklaşırken, aynalarınız ve anteniniz buzlanmaya başlamış olsa bile önünüzdeki yol yüzeyi aniden ıslak ve parlak görünüyor. Yüklü aracınızı bu kesimden geçirmenin en güvenli yolu hangisidir?","options":["Mevcut hızınızı koruyun ama yüzeyde ne kadar tutuş kaldığını test etmek için şimdi frene birkaç kez basıp bırakın","Hızınızı koruyun ve sadece takip mesafesini artırın, çünkü köprüler açık yoldan daha hızlı çözülür","Yüzey daha fazla donmadan köprüyü hızlıca geçmek için yumuşakça hızlanın","Köprüden çok önce hızınızı azaltın ve direksiyon, fren ve gazı yumuşak, nazik bir şekilde kullanın"],"explanation":"Aynalarda ve antende buzla birlikte ıslak, parlak bir görünüm buzlanmayı gösterir ve köprüler önce donar, bu yüzden erkenden yavaşlayın ve yumuşak, nazik hareketler yapın."},"201":{"q":"Ay olmayan bir gece ve kötü aydınlatılmış bir tır durağından kırsal iki şeritli bir karayolunda 4 saatlik bir yolculuğa çıkmak üzeresiniz. Araç çevresi kontrolü sırasında her iki far camının da yol kiri ve kurumuş böcek kalıntısı tabakasıyla kaplı olduğunu ve parlaklıklarını gözle görülür şekilde azalttığını fark ediyorsunuz. Yola çıkmadan önce yapılacak EN İYİ hareket nedir?","options":["Far camlarını temizleyin ki tam ışık versinler ve zamanında durabilecek kadar ileriyi görebilesiniz","Şimdilik yola çıkın ve sadece hızınızı düşürün ki kısa hüzmeleriniz sürerken yine de yolu aydınlatsın","Kirli camların kısık ışığını telafi etmek için tüm yolculuk boyunca uzun hüzmeleri kullanın","Temizlemeyi atlayın ve yolunuzu işaretlemek için park ve gabari lambalarına güvenin"],"explanation":"Kirli far camları kısa farlarınızın menzilini azaltır, bu yüzden onları temizleyerek tam ışığı geri kazanın ve zamanında durabilecek kadar ileriyi görün."},"202":{"q":"Yüklü bir römorkla uzun ve dik bir dağ yokuşundan iniyorsunuz. İnişin ortasında fren pedalına bastığınızda pedal neredeyse tabana kadar gidiyor ve aracı yavaşlatmıyor, ayrıca yanık kokusu alıyorsunuz. Hızınız artmaya başlıyor. Yapılacak EN İYİ hareket nedir?","options":["Basıncı geri kazanmak için fren pedalını sert ve hızlı bir şekilde pompalayın, sonra mevcut viteste yuvarlanmaya devam edin","Motor freninin sizi yavaşlatması için daha düşük bir vitese geçin ve bir sonraki kaçış rampasına doğru yönelin","Şanzımanı korumak için boşa alın ve yokuş düzleşene kadar kamyonun yuvarlanmasına izin verin","Sert bir şekilde sol banket üzerine çekin ve 10, 100 ve 200 fitlik mesafelere üç yansıtıcı üçgen yerleştirin"],"explanation":"İniş yokuşunda servis frenleri sönükleşince, motor freninden yararlanmak için düşük vitese geçin ve güvenle yavaşlamak için bir kaçış rampasına yönelin."},"203":{"q":"Yüklü bir çekici-dorse ile uzun ve dik bir dağ yokuşundan aşağı iniyorsunuz. İnişten önce düşük vitese geçmenize ve hafif, sabit fren kullanmanıza rağmen hafif bir yanık kokusu alıyorsunuz ve fren pedalınız yumuşak ve süngerimsi hissedilmeye başlıyor. İleride sağ banket üzerinde bir kaçış rampası tabelası görüyorsunuz. Bu koşullarda, o rampayı ne zaman ve neden kullanmanız gerektiğine dair doğru anlayış nedir?","options":["Aşırı ısınan frenlerin inişe devam etmeden önce soğuması için geceleyin park edebileceğiniz, belirlenmiş bir durma cebidir","Yorgun sürücülerin uzun bir inişi tamamlamadan önce bir süre durup dinlenebilmeleri için dik yokuşlara yerleştirilmiş bir dinlenme alanıdır","Kontrolden çıkan bir aracı durdurmak için yapılmıştır; bu yüzden frenleriniz tutmaz hale geldiyse ve artık hızınızı kontrol edemiyorsanız, kamyonu güvenli bir şekilde durdurmak için onu kullanmalısınız","Araç hâlâ yokuş aşağı hareket halindeyken güvenle daha düşük vitese geçebileceğiniz belirlenmiş bir şerittir"],"explanation":"Kaçış rampası, frenleri sönükleşmiş kontrolden çıkan bir aracı durdurmak için yapılmıştır, bu yüzden hızınızı kontrol edemediğinizde aracı güvenle durdurmak için onu kullanın."},"204":{"q":"Kuru, iki şeritli bir yolda otoyol hızında yüklü bir katar sürerken direksiyon aniden boşa çıkıyor ve kamyon direksiyon hareketlerinize normal şekilde yanıt vermeyi bırakıyor. Trafik az ve ileride banket boş. EN İYİ ilk tepki hangisidir?","options":["Mevcut hızınızı koruyup direksiyon yeniden tepki verene kadar direksiyonu zorlayarak sağa sola çevirmek","Direksiyonu tamamen bırakıp aracın kendi yolunu bulmasına izin verirken telsize uzanmak","Aracı kontrollü ve güvenli bir şekilde durdurmak için frenlere yumuşak ve düzgün şekilde basmak","Mümkün olan en kısa mesafede durmak için frenlere sert basıp tekerlekleri hemen kilitlemek"],"explanation":"Direksiyon aniden arızalanırsa hâlâ kontrol edebileceğiniz tek şey hızdır, bu yüzden aracı güvenli ve kontrollü şekilde durdurmak için yavaş ve düzgün fren yapın."},"205":{"q":"İki şeritli kırsal bir karayolunda iki aracın çarpıştığı kazaya ilk ulaşan araç sizsiniz. Sürücülerden biri direksiyona yığılmış ve yaralı görünüyor; her iki şeride de kırık cam ve sıvı yayılmış durumda. Her iki yönden de başka araçlar yaklaşmaya devam ediyor. Kamyonunuzu güvenli bir şekilde durdurduktan sonra YAPMANIZ GEREKEN İLK şey nedir?","options":["Kaza alanını koruma altına alıp yaklaşan trafiği uyararak yeni çarpışmaların önüne geçmek","Yaralı sürücüyü araçtan çıkarıp banketin kenarına taşımak","Hasarı rapor için belgelemek amacıyla olay yerinin fotoğraflarını çekmek","Her bir yaralıyı kontrol etmeye ve ilk yardım uygulamaya başlamak"],"explanation":"Herhangi bir kaza yerinde ilk öncelik ikinci bir çarpışmayı önlemektir, bu yüzden başka bir şey yapmadan önce alanı koruyun ve yaklaşan trafiği uyarın."},"206":{"q":"Kırsal iki şeritli bir karayolunda kuru bir kasa taşırken duman kokusu alıyor ve arka aks tekerlek bölgesinde alevler görüyorsunuz. Hızla durmanız gerekiyor, ama önünüzde birkaç durma noktası var. Yangınla başa çıkmak için aracı kenara çekip park etmek için EN İYİ yer neresidir?","options":["Yaklaşan karayolu tünelinin girişinin hemen ötesinde, yapı kamyonu rüzgardan koruyacak şekilde","Kamyon durağındaki çakıl cebe, yangın söndürücü elinizin altında olsun diye dizel pompalarının yanına park ederek","Açık bir kesimin geniş banketinde, binalardan ve diğer araçlardan iyice uzakta, acil çağrı kutusunun yakınında","Bir sonraki beton üst geçidin altında, gölge yükün daha fazla ısınmasını önlesin diye"],"explanation":"Araç yangınında binalardan, trafikten ve yanıcı maddelerden uzak açık bir banket üzerinde ama bir acil telefon kutusu yakınında durun, böylece yangın izole edilir ve yardım ulaşılabilir kalır."},"207":{"q":"Yüklü bir çekici-dorse ile ıslak bir otoyolda giderken bir otomobil aniden önünüze girip kısa mesafede duruyor. Sert fren yapıyorsunuz, ABS uyarı ışığı kapalı (sistem çalışıyor) ve çarpışmayı önlemek için boş emniyet şeridine kırmanız gerekiyor. Bu acil durumda ABS'ye güvenirken, gerçekte sizin için yapacağı EN doğru şey nedir?","options":["Toplam durma mesafenizi, bir tırın 55 mil/saatte ihtiyaç duyduğu yaklaşık 419 fitin çok altına indirir, böylece manevra yapmadan zamanında durabilirsiniz","Önündeki engeli algılar algılamaz aracı otomatik olarak frenler ve sizin yerinize emniyet şeridine yönlendirir","Tekerleklerin kilitli kalmasını garanti eder, böylece lastikler ıslak zemine daha güçlü tutunarak maksimum kavrama sağlar","Tekerleklerinizin kilitlenmesini önler, böylece sert fren yaparken bile direksiyon hakimiyetini koruyup aracı emniyet şeridine yönlendirebilirsiniz"],"explanation":"ABS, sert frende tekerleklerin kilitlenmesini önler, böylece direksiyon kontrolünü korur ve fren yaparken banket tarafına manevra yapabilirsiniz."},"208":{"q":"Yüklü bir römorku ıslak, dört şeritli bir karayolunda aşağı doğru sürerken bir otomobil önünüze aniden giriyor. Sert fren yapıyorsunuz, ABS (kilitlenmeyi önleyici fren sistemi) devreye giriyor, aracı kontrol altında tutuyor ve tehlikenin etrafından direksiyonla geçiyorsunuz. Sonrasında daha acemi bir sürücü, kamyonunuzda ABS olduğu için artık öndeki araçları daha yakından takip edebileceğinizi, çünkü ABS'nin çok daha kısa mesafede durmanızı sağladığını söylüyor. Bu mantık neden YANLIŞTIR?","options":["ABS fren mesafenizi mutlaka kısaltmaz; asıl yararı, tekerleklerin kilitlenmesini önleyerek fren yaparken direksiyon kullanabilmenizi sağlamaktır.","ABS yalnızca yol kuruyken çalışır, bu yüzden bu ıslak karayolunda frenlemeye hiçbir katkısı olmamıştır.","ABS fren mesafesini yalnızca direksiyon (ön) dingilinde kısaltır, bu yüzden takip mesafesi yarıya indirilebilir ama tamamen değil.","ABS frenleri sizin yerinize otomatik olarak uygular, bu yüzden karayolu hızında artık hiç takip mesafesi bırakmanıza gerek yoktur."],"explanation":"ABS fren mesafesini mutlaka kısaltmaz; asıl görevi tekerleklerin kilitlenmesini önleyerek sert frenlemede direksiyon hakimiyetini korumanızı sağlamaktır."},"209":{"q":"Çekici-römork aracınızda kilitlenmeyi önleyici fren sistemi (ABS) YOKTUR. Kırsal iki şeritli bir yolda, bir araba yan sokaktan aniden tam önünüze çıkar ve aracı kontrol altında, kendi şeridinizde tutarak mümkün olduğunca çabuk durmanız gerekir. Hangi frenleme yöntemi, direksiyon kontrolünü kaybetmeden en kısa güvenli duruşu sağlar?","options":["Fren pedalına sonuna kadar basıp tutarak tekerleklerin kilitlenmesini sağlamak, böylece maksimum fren gücü elde etmek","Kontrollü frenleme (kilitlenme eşiğinin hemen altında sabit ve kararlı basınç uygulamak) veya kesintili (stab) frenleme yapmak, tekerlekler kilitlenirse pedalı bırakmak","Tam durana kadar frene hızlı ve rastgele şekilde pompalamak","Yalnızca römork el valfini kullanarak römorkun aracı sürükleyip durdurmasını sağlamak"],"explanation":"ABS yoksa kontrollü frenleme (kilitlenmenin hemen altında sabit ve kararlı basınç) veya darbeli frenleme kullanarak, tekerlekler kilitlendiğinde bırakarak kilitlenmeyi önleyin."},"210":{"q":"Sıcak bir yaz öğleden sonrasında, bölünmüş bir karayolunda yaklaşık 60 mil/saat hızla yüklü olarak gidiyorsunuz. Aniden yüksek bir patlama sesi duyuyorsunuz ve çekicinizin ön kısmı sarsılıp sertçe bir tarafa çekiyor -- direksiyon (ön) aksındaki bir lastik patladı. Bu ilk anda, başka bir şey yapmadan önce, aracın kontrolünü korumanız için EN İYİ şansı hangi tepki verir?","options":["Araç daha fazla yoldan çıkmadan güvenli bir hıza inmek için hemen sert ve kararlı şekilde fren yapmak","Çeki dingiline güç eklemek ve çekiciyi düz çekmek için gaza basın, ardından düzgün gittiğinde gazı bırakın","Çekiciyi şeridinizin ortasına doğru düzeltmek için aracın çektiği tarafın tersine direksiyonu sertçe kırın","Direksiyonu iki elinizle sıkıca kavrayın, önce frene basmayın, şeridinizde kalın ve hafifçe fren yapmadan önce aracın kendiliğinden yavaşlamasını bekleyin"],"explanation":"Lastik patladığında direksiyonu iki elinizle sıkıca tutun, başlangıçta frene basmayın, şeridinizi koruyun ve hafifçe fren yapmadan önce aracın yavaşlamasına izin verin."},"212":{"q":"Sefer öncesi kontrolünüzde, sevk belgeleri römorkunuzun azami yüklü ağırlığının (GVWR) birkaç bin libre üzerinde yüklendiğini gösteriyor. Geç kaldınız ve önünüzdeki güzergâhta uzun bir iniş ve birkaç keskin viraj var. Bir iş arkadaşınız fazladan ağırlığın aslında 'yola tutunmanıza yardımcı olacağını', yani sorun olmadığını söylüyor. Aşırı yükün araç kontrolünü nasıl etkilediğine göre hangi ifade doğrudur?","options":["Eklenen ağırlık lastikleri yere daha sert bastırır, bu yüzden fren mesafeniz yasal yüklü haldekinden daha kısa olur.","Yük akslar üzerinde olduğu için fazladan ağırlık ağırlık merkezinizi düşürür ve virajlarda devrilme riskini azaltır.","Fazla ağırlık kamyonu durdurmayı ve yönlendirmeyi zorlaştırır, fren mesafenizi ve inişte ve virajlarda kontrolü kaybetme riskinizi artırır.","Aşırı yük yalnızca yakıt ekonomisi ve lastik aşınması için önemlidir; kamyonun nasıl durduğu veya yönlendirildiği üzerinde gerçek bir etkisi yoktur."],"explanation":"Fazla ağırlık kamyonu durdurmayı ve yönlendirmeyi zorlaştırır, fren mesafesini ve eğimlerde ve virajlarda kontrolü kaybetme riskini artırır."},"213":{"q":"Sefer öncesi kontrolünüzde bir açık kasayı yüklüyorsunuz ve ağır makinelerin neredeyse tamamının arka aks üzerinde üst üste yığıldığını ve palet istifinin üzerinde yüksekçe durduğunu fark ediyorsunuz. Yola çıkmadan önce, aracınızın güvenli gitmesi için bu yükü ele almanın EN İYİ yolu nedir?","options":["Yükü arka çekiş aksı üzerinde toplu bırakın; çünkü oradaki ek ağırlık çekiş lastiklerine daha fazla tutuş kazandırır","Tüm yükü öne itin, böylece bütün ağırlık daha iyi direksiyon kontrolü için ön yönlendirme aksı üzerine binsin","Yüksek ve ortalanmış istifli halde bırakın; çünkü sağdan sola ortalanmış yüksek bir yük zaten yeterince dengelidir","Yükü yeniden dağıtarak ağırlığın önden arkaya ve yandan yana dağıtılıp dengelenmesini sağlayın ve ağırlık merkezini mümkün olduğunca alçak tutun"],"explanation":"Yükü öne-arkaya ve yana doğru dağıtıp dengeleyin, ağırlık merkezini mümkün olduğunca alçak tutarak bir aksın aşırı yüklenmesini veya devrilmeyi önleyin."},"214":{"q":"Sefer öncesi kontrolde bir tankeri kısmen doldurup yüklü platformun üzerine birkaç palet istifliyorsunuz; böylece en ağır yük yüksekte kalıyor. Güzergâhınızı planlarken, bu kamyonun artık nasıl davranacağı konusunda sizi EN çok endişelendirmesi gereken risk hangisidir?","options":["Yüksek ağırlık merkezi, kamyonun bir virajda veya ani direksiyon hareketinde devrilme olasılığını çok daha fazla artırır.","Yüksekteki yük, fazladan aşağı yönlü kuvvet sayesinde kamyonun çok daha kısa mesafede durmasını sağlar.","Yükseltilmiş ağırlık, yük daha düzgün gittiği için düz otoyolda yakıt ekonominizi iyileştirir.","Üstten ağır yük, otoyol hızında direksiyonu belirgin şekilde daha hafif ve kolay hale getirir."],"explanation":"Yüksek bir ağırlık merkezi ağırlığın daha fazlasını yukarıda toplar ve kamyonun bir virajda veya ani direksiyon hareketinde devrilme olasılığını büyük ölçüde artırır."},"215":{"q":"Araç öncesi kontrolünüz sırasında römorksuz tek bir düz kamyonunuzu kontrol ederken, sürücü kapısı çerçevesinde 'GVWR' harflerinin yanına 33.000 lb değeri damgalanmış metal bir sertifika plakası buluyorsunuz. Sevkiyat sorumlunuz bu rakamın bu araç hakkında gerçekte ne ifade ettiğini soruyor. Hangi ifade doğrudur?","options":["Bu kamyonun, çektiği herhangi bir römorkla birlikte tek bir birim olarak izin verilen birleşik azami yüklü ağırlığıdır","Bu tek aracın taşıyabileceği, üretici tarafından belirlenen azami yüklü ağırlıktır","Yük bölmesine yasal olarak koyabileceğiniz tüm yükün ve bağlama ekipmanlarının toplam ağırlığıdır","Kamyonun herhangi bir tekil dingiline binebilecek azami ağırlıktır"],"explanation":"GVWR, üretici tarafından belirlenen, tek bir aracın taşıyabileceği azami yüklü ağırlıktır."},"216":{"q":"Sefer öncesi kontrolünüzde, açık platform üzerinde duran 12 fitlik bir çelik kirişin, ön panele dayanmış herhangi bir takoz olmadan, iki adet aşırı yıpranmış ve eskimiş halatla tutturulduğunu fark ediyorsunuz. Önünüzde uzun bir karayolu güzergâhı var. Yola yasal ve güvenli bir şekilde çıkmadan önce bu yük için ne gerekir?","options":["Başka bir şeye gerek yok -- iki ayrı halat, 5 fitten uzun bir parça için gereken en az iki bağlama elemanı şartını zaten karşılıyor, dolayısıyla kiriş emniyete alınmıştır","Sadece mevcut halatları daha sıkı bağlamak yeterli, çünkü römorkun önündeki panel kirişin kendiliğinden öne kaymasını engelleyecektir","Yeterli sayıda sağlam bağlama elemanı ve takoz -- uygun çalışma yük limitine sahip sağlam bağlama elemanları artı kama/takoz -- kirişi her yöne kaymaya karşı gerçekten tutacak şekilde","Ortadan geçen tek bir zincir yeterli, çünkü açık platformdaki herhangi bir yük için tek bir bağlama elemanı zorunludur"],"explanation":"Yük, herhangi bir yöne kaymasını önleyecek kadar sağlam ve yeterli çalışma yükü limitine sahip bağlama elemanı ile takoz ve destekle sabitlenmelidir."},"217":{"q":"Kabin arkasına bir koruma panosu (header board, headache rack) takılı düz platformlu bir dorseye çelik bobinler ve ağır sandıklar yüklüyorsunuz. Bir iş arkadaşınız, zaten doğru bağlama kayışları kullanılırken şirketin neden bu panolara para harcadığını soruyor. Bu koruma panosunun BİRİNCİL amacını doğru şekilde belirten cevap hangisidir?","options":["Sağlam bir bağlama noktası sağladığı için bağlama elemanlarınızın toplam çalışma yük sınırı, yük ağırlığının yarısından daha azına düşürülebilir","Yükün ön tarafından gelen rüzgâr türbülansını ve yol suyunu engelleyerek yakıt verimini ve ayna görüşünü iyileştirir","Yükledikten sonra ilk 150 mili sürene kadar kabin içinden yük kontrolünü yasal olarak atlamanıza izin verir","Sert bir frende yükün öne kayıp sürücü bölmesine doğru ezerek girmesini durdurarak sizi kabinde korur"],"explanation":"Ön pano (başlık rafı), sert bir duruşta yükün öne doğru kabine kaymasını engelleyerek sürücünün çarpılmasını veya ezilmesini önler."},"219":{"q":"Yüklü çekicinizi yol kenarındaki kantarda tartırdınız ve memur size birkaç farklı sayı içeren bir çıktı uzatıyor: yere temas eden her tekerlek grubu için bir değer ve tek bir birleşik toplam. Memur \"aks ağırlığı\" yazan satırı işaret ediyor ve bu belirli sayının neyi ifade ettiğini anladığınızı doğrulamanızı istiyor. Doğru yanıt vermek için, aks ağırlığı değerinin ne anlama geldiğini memura nasıl söylemelisiniz?","options":["Her bir aksın yola aktardığı ağırlık miktarı","Tüm yüklü aracın ve içindeki tüm yükün birleşik toplam ağırlığı","Yalnızca römork üzerindeki yükün ve bağlama ekipmanının ağırlığı","Üreticinin aracın güvenle taşıyabileceğini belirttiği azami ağırlık"],"explanation":"Aks ağırlığı, tek bir aksın taşıdığı ve yere ilettiği ağırlık miktarıdır, aracın tamamının ağırlığı değildir."},"220":{"q":"Uzun bir gece sürüşünde saat gece 3 ve kendinizi şeritten kayarken ve sürekli esnerken yakalıyorsunuz. Sefer planınıza göre hâlâ birkaç saatlik sürüşünüz var. Yorgunluğunuzu gerçekten gidererek güvenle devam etmenizi sağlayacak eylem hangisidir?","options":["Büyük bir sade kahve içip kalan saatleri atlatmak için radyonun sesini sonuna kadar açmak","Güvenli bir dinlenme alanına çıkıp sürüşü bırakmak ve devam etmeden önce gerçekten uyumak","Soğuk temiz hava için yan camı indirmek ve şeker patlaması için biraz şekerleme yemek","Sürmeye devam etmek ama tepki için daha fazla zaman kazanmak amacıyla takip mesafesini her 3 metre araç uzunluğu için bir saniyeye çıkarmak"],"explanation":"Yorgunluğu yalnızca gerçek uyku giderir, bu yüzden güvenli bir dinlenme alanına çekip devam etmeden önce uyumak için durun."},"221":{"q":"Alerji mevsimi ve sefer öncesi araç kontrolü sırasında soğuk algınlığı belirtileri hissediyorsunuz. Uzun bir gündüz seferi için kabine binmeden önce çantanızdan reçetesiz bir soğuk algınlığı ve alerji hapı alıyorsunuz. Bu ilacın hangi etkisi, şu anda araç kullanmayı yeniden düşünmek için EN ÖNEMLİ nedendir?","options":["Uyanıklığınızı artırır, böylece sürüş saatlerinizi güvenle uzatabilirsiniz","Vücudunuzda kalan tüm alkolü atarak yolculuktan önce BAC değerinizi düşürür","Uyku hâli yapabilir ve sürüşünüzü bozabilir, bu yüzden araç kullanmadan önce etiketi kontrol etmelisiniz","Tepki sürenizi iyileştirir ve yoldaki odaklanmanızı keskinleştirir"],"explanation":"Birçok reçetesiz soğuk algınlığı ve alerji ilacı uyku hali yapar ve sürüşü bozar, bu yüzden her zaman etiketi okuyun ve makine kullanmaya karşı uyarı varsa araç sürmeyin."},"222":{"q":"İki saat önce akşam yemeğinde iki bira içtiniz ve gece sürüşü için çekici-römork aracınıza binmeden önce kendinizi tamamen ayık hissediyorsunuz. Sert bir kahvenin ve soğuk gece havasının sizi zinde tutacağını düşünüyorsunuz. Bu durumda araç kullanarak aldığınız gerçek riski en iyi hangi ifade açıklar?","options":["Önemli bir risk yok -- iki saat ve bir kahveden sonra alkolün sizin kilonuzdaki bir sürücü üzerinde ölçülebilir bir etkisi kalmaz","Asıl önemli olan, aracı kullanırken CDL'iniz için geçerli olan %0,08'lik kandaki alkol (BAC) sınırının altında kalmaktır","Kahve ve soğuk hava, vücudunuzun alkolü ne kadar hızlı attığını hızlandırır, böylece otoyola çıkmadan önce becerileriniz eski haline döner","Alkol, kendinizi iyi hissetseniz bile muhakeme yeteneğinizi ve tepki sürenizi bozar ve onu vücudunuzdan yalnızca zaman çıkarır -- kahve veya temiz hava değil"],"explanation":"Alkol, kendinizi iyi hissetseniz bile muhakemeyi ve tepki süresini bozar ve onu vücudunuzdan yalnızca zamanın geçmesi atar -- kahve veya temiz hava değil."},"224":{"q":"Uzun bir vardiyayı sabah saat 2'de bitirdiniz ve bir sonraki sevkiyattan önce yalnızca yaklaşık dört saat uyudunuz. Sevkiyat sorumlusu yola çıkmanız için sizi sıkıştırıyor ve kendinize kahve ve açık bir pencereyle 'açığı kapatabileceğinizi' söylüyorsunuz. El kitabının yorgunluğu önleme konusunda söylediklerine göre, gerçekten dinlenmiş ve güvenle araç kullanabilir olmanız için aslında neye ihtiyacınız olduğunu hangi ifade yansıtır?","options":["Çoğu yetişkinin gerçekten dinlenmiş olması için yaklaşık 7–8 saat uykuya ihtiyacı vardır ve uyanıklığı yalnızca gerçek uyku geri kazandırır — kahve veya temiz hava değil.","Deneyimli bir sürücü için yaklaşık 4–5 saat uyku yeterlidir, çünkü kahve ve temiz hava gerisini telafi edebilir.","Uyanıklığınızı yeniden kontrol etmek için her 150 milde bir mola verdiğiniz sürece yaklaşık 2–3 saat uyku kabul edilebilir.","Herhangi bir ticari yolculuktan önce tam 12–14 saat uykuya ihtiyacınız vardır, yoksa yasal olarak araç kullanmaya uygun değilsiniz."],"explanation":"Çoğu yetişkinin gerçekten dinlenmiş olması için yaklaşık 7 ila 8 saat uykuya ihtiyacı vardır ve dikkatliliği yalnızca gerçek uyku geri getirir -- kahve veya temiz hava değil."},"225":{"q":"Uzun ve monoton bir otoyolda saatlerdir araç kullanıyorsunuz ve göz kapaklarınız ağırlaşıyor. Uyanık kalmak için camı açıp temiz hava alıyor ve büyük bir kahve içiyorsunuz. Bu yöntemlerle ilgili hangi ifade doğrudur?","options":["Kafein ile serin temiz hava, vardiyanın geri kalanı boyunca dikkatinizi kalıcı olarak geri kazandırır","Kısa bir süre yardımcı olabilirler, ancak uyku haline karşı tek gerçek çare durup uyumaktır","Temiz hava ve kahve tehlikelidir ve uyku halinizi daha da kötüleştirir","Sürüş saatlerinizi tamamen sıfırlarlar, böylece durmadan güvenle devam edebilirsiniz"],"explanation":"Kafein ve temiz hava uyku halini yalnızca kısa süreliğine gizler; tek gerçek çare durup uyumaktır."},"226":{"q":"Bölünmüş bir otoyolun sağ şeridinde seyrederken, bir sürücü arkanızdan hızla yaklaşıp aracınıza yakın takip ediyor, uzun farlarını yakıp söndürüyor, ardından sol şeride geçip öfkeyle el kol hareketleri yaparak sizi geçmeye çalışıyor. İlerideki trafik orta yoğunlukta. EN iyi ve en güvenli tepki hangisidir?","options":["Geçişini hızlıca tamamlayıp tamponunuzu sıkıştırmayı bıraksın diye hızınızı onunkine eşitlemek","Şerit konumunuzu korumak ve sadece hafifçe yavaşlayıp, yakın takip etmemeyi öğrensin diye onu bekletmek","Gazdan ayağınızı çekerek yer açmak, göz teması kurmaktan kaçınmak ve onun çok ileri gitmesine izin vermek","Sola, onun şeridine geçip sakinleşip geri çekilene kadar geçişini engellemek"],"explanation":"Saldırgan bir sürücüye bol yer verin ve tahrik etmeyin -- gazdan ayağınızı çekin, göz temasından kaçının ve onun iyice öne geçmesine izin verin."},"227":{"q":"Yüklü çekici-römorkunuzla yoğun bir eyaletler arası otoyola katılırken bir otomobil önünüze aniçe girip sizi sert fren yapmaya zorluyor. Sinirlenen diğer sürücü ardından size yakın takip yapıyor, etrafınızdan sıyrılıyor, önünüzde sert fren yapıyor ve müstehçen el işaretleri yapıyor. El kitabına göre, diğer sürücünün davranışını EN iyi hangi terim tanımlar ve aynı şeyden suçlu duruma düşmemek için kendi davranışınızı nasıl düşünmeniz en güvenlidir?","options":["Agresif şerit değiştirme — yoğun trafiğin normal bir parçasıdır; buna hızlanarak karşılık vermeli, konumunuzu korumalı ve otomobillerin yavaş bir kamyondan faydalanmasına izin vermemelisiniz","Savunmacı sürüş — diğer sürücü sadece alanını koruyor, bu yüzden fren yapıp yolu kapatarak onun davranışını taklit etmeli ve otomobillere büyük bir aracı saygı duymayı öğretmelisiniz","Dikkati dağılmış sürüş — sürücü açıkça yola dikkat etmiyor, bu yüzden doğru tepki hızlanıp onu hızlıca geçerek kendinizi tehlikeden uzaklaştırmaktır","Yol öfkesi (road rage) — öfkeli, saldırgan sürüş; sakin kalarak, karşılık vermeyerek ve öfkeli sürücüye uzaklaşması için yer vererek kendiniz buna düşmekten kaçınırsınız"],"explanation":"Yol öfkesi öfkeli, şiddetli sürüştür ve bunu sakin kalarak, karşılık vermeyerek ve öfkeli sürücüye uzaklaşması için yer vererek önlersiniz."},"228":{"q":"Bir Teksas eyaletler arası otoyolunda yoğun öğleden sonra trafiğinde yüklü bir çekici-römork kombinasyonu kullanıyorsunuz. Bir iş arkadaşınız, gelişen tehlikeleri erken yakalamanın en iyi yolunun, fren ışıklarını asla kaçırmamak için tam önündeki kamyonun tamponuna gözünü dikmek olduğunu söylüyor. Tehlikeleri güvenli tepki verecek kadar erken fark etme şansını gerçekte hangi yaklaşım verir?","options":["Gözlerinizi sürekli hareket ettirin ve tarayın — önce ileriye (12–15 saniye) bakın, sonra yakına dönün ve aynalarınızı her 5–8 saniyede bir kontrol edin","Dümdüz ileriye bakın ve fren ışıkları daima net görünür olsun diye gözünüzü tam önünüzdeki araça sabitleyin","Ağırlıklı olarak aynalarınıza güvenin, çünkü yoğun trafikte sürprizlerin çoğu sizi arkadan geçen araçlardan gelir","Gelişen bir mekanik arıza uyarısını kaçırmamak için ileriye bakışlar arasında radyo kadranını ve gösterge panelini izleyin"],"explanation":"Gözlerinizi sürekli hareket ettirip tarayın -- 12 ila 15 saniye ileriye, sonra yakın alana bakın ve aynalarınızı her 5 ila 8 saniyede bir kontrol edin."},"229":{"q":"Şehir merkezindeki bir iş bölgesinden 25 mil/saat hızla geçiyorsunuz. Sağ kaldırım boyunca paralel park etmiş bir araç dizisi görüyorsunuz. İleriyi tararken, bu park etmiş araçlardan birinin fren lambalarının yandığını, egzozdan duman çıktığını ve koltukta bir sürücünün silüetini görüyorsunuz. Neden TAM OLARAK bu park etmiş aracı aktif bir tehlike olarak görüp yavaşlamaya veya şerit konumunuzu değiştirmeye hazırlanmalısınız?","options":["Yanan fren lambaları aracın yerinde tutulduğu anlamına gelir, bu yüzden hareket edemez ve yalnızca onun önündeki lambasız araçlar bir tehdit oluşturur","İçinde biri olan ve motoru çalışan bir araç aniden şeridinize çıkabilir veya bir kapı yolunuza doğru açılabilir, bu yüzden frene hazır olun ve fazladan mesafe bırakın","Çalışan motor lastikleri ısıtır, bu da kendi durma mesafenizi yaklaşık 419 fite uzatır ve yavaşlamanızı zorunlu kılar","Egzoz ve yanan fren lambaları park etmiş bir araç için normaldir ve hiçbir şey ifade etmez, bu yüzden hızda veya şerit konumunda değişiklik gerekmez"],"explanation":"İçinde biri olan ve çalışır durumdaki park halindeki bir araç aniden şeridinize girebilir veya yolunuza kapı açabilir, bu yüzden frene hazır olun ve ona fazladan yer verin."},"230":{"q":"Sıcak bir öğleden sonra kamyonunuzu yerleşim bölgesinde saatte 30 mil hızla sürüyorsunuz. İleride sağda, kaldırım kenarında topla oynayan birkaç çocuk görüyorsunuz ve içlerinden biri kamyonunuza değil, topa bakıyor. El kitabı bu durumu neden, hemen yavaşlamaya veya durmaya hazır olmanızı gerektiren özel bir tehlike olarak görür?","options":["Çünkü saatte 30 milde toplam durma mesafeniz zaten yaklaşık 419 fittir, bu yüzden hiçbir şey için zamanında duramazsınız","Çünkü çocuklar her zaman kaldırımda kalır ve ancak bir yetişkin karşıya geçmelerini söylerse tehlike oluştururlar","Çünkü çocuklar aniden ve öngörülemez şekilde davranabilir, örneğin trafiğe bakmadan topun peşinden yola fırlayabilirler","Çünkü çocuklar o kadar yavaş hareket eder ki, yoldan çekilmelerini beklediğinizden çok sonra hâlâ yolda olurlar"],"explanation":"Çocuklar özel bir tehlikedir çünkü trafiği kontrol etmeden topun peşinden yola fırlamak gibi aniden ve öngörülemez şekilde davranabilirler."},"231":{"q":"Dört şeritli bölünmüş bir otoyolda yüklü bir römork ile saatte yaklaşık 55 mil hızla gidiyorsunuz. Küçük bir araba aniden sağdan önünüze giriyor, ardından az kalsın kaçıracağı bir çıkışa girmek için sert şekilde fren yapıyor. Takip mesafeniz daraldı ve içinizde bir öfke dalgası hissediyorsunuz. En güvenli ve en savunmacı tepki hangisidir?","options":["Arabanın hemen arkasında yakın durup, sürücünün yarattığı tehlikeyi anlaması için uzun farlarınızı yakıp söndürün","Öngörülemeyen bir sürücünün arkasında sıkışıp kalmamak için hızlanıp arabanın yanına gelin","Hızlı bir uyarı için frene hafifçe basın, ardından tekrar orijinal 4 saniyelik takip mesafenize kadar yaklaşın","Güvenli takip mesafesini yeniden oluşturmak için gazdan ayağınızı çekin, sakin kalın ve diğer sürücüye ihtiyacı olan alanı bırakın"],"explanation":"Başka bir sürücü hata yaptığında, güvenli takip mesafesini yeniden oluşturmak için gazdan ayağınızı çekin, sakin kalın ve ona ihtiyaç duyduğu yeri verin."},"233":{"q":"Gece tanımadığınız bir kavşağa yaklaşırken üstteki trafik sinyalinin her yönde kırmızı yanıp söndüğünü fark ediyorsunuz. Ortalıkta polis yok ve yan yoldan gelen trafik az. Bu kavşaktan doğru ve yasal şekilde geçmek için ne yapmalısınız?","options":["Tam olarak durun, ardından tıpkı bir DUR (STOP) levhasında olduğu gibi yalnızca güvenli olduğunda kavşaktan geçin","Yavaşlayın, her iki yöne bakın ve tam durmadan dikkatlice yuvarlanarak geçin","Çalışmayan sinyali bir 'yol ver' gibi kabul edip hızınızı koruyarak ilk boşlukta geçin","Yanıp sönen sinyal ışığın arızalı olduğu ve kuralların geçerli olmadığı anlamına geldiği için hızınızı koruyarak kavşaktan geçin"],"explanation":"Yanıp sönen kırmızı sinyal, DUR levhasıyla aynı anlama gelir: tamamen durun ve yalnızca güvenli olduğunda devam edin."},"234":{"q":"Yüklü çekici-römork aracınızla gece geç saatte bir kavşağa yaklaşıyorsunuz. Gündüz boyunca sabit yeşil yanan sinyal, şimdi YANIP SÖNEN SARI gösteriyor. Kesişen yolda görünür başka trafik yok. Bu sinyali ele almanın doğru yolu hangisidir?","options":["Tam olarak yanıp sönen kırmızı gibi davranın: tamamen durun, sonra yol açıkken geçin","Yavaşlayın, tetikte kalın ve kesişen trafiği kontrol ettikten sonra kavşaktan dikkatle geçin","Sarı sinyal size kesişen yola göre geçiş üstünlüğü verdiği için otoyol hızınızı koruyun","Çizgide tamamen durun ve hareket etmeden önce sinyalin sabit yeşile dönmesini bekleyin"],"explanation":"Yanıp sönen sarı sinyal bir uyarıdır; bu yüzden yavaşlayın, dikkatli olun ve kavşaktan geçerken yandan gelen trafiği kontrol ederek temkinli ilerleyin."},"235":{"q":"Yüklü çekici-dorse aracınızla kırsal bir kavşağa yaklaşıyorsunuz. Hiçbir yönde dur işareti, yol ver işareti veya trafik ışığı yok ve çalılar sağa görüşünüzü kısmen kapatıyor. Sağınızdan bir kamyonet kavşağa yaklaşık aynı anda yaklaşıyor. Yapmanız gereken en güvenli ve doğru hareket nedir?","options":["Hızınızı koruyun ve önce siz geçin, çünkü yüklü bir ticari araç daha küçük araçlara göre yasal geçiş üstünlüğüne sahiptir","Kavşağın ortasında tam olarak durun ve hareket etmeden önce kamyonetin geçmesini bekleyin","Yaklaşırken hızınızı azaltın, ayağınızı frene hazır tutun ve devam etmeden önce gerektiğinde kamyonete yol vermeye hazır olun","Korna çalın ve aynı hızla geçmeye devam edin, böylece diğer sürücü önce sizin geçmek istediğinizi anlasın"],"explanation":"Kontrolsüz bir kavşakta hiçbir aracın otomatik geçiş üstünlüğü yoktur; bu yüzden yavaşlayın, ayağınızı frene yaklaştırın ve devam etmeden önce yol vermeye hazır olun."},"237":{"q":"Ağır bir yük taşıyorsunuz ve uzun, dik bir dağ yokuşunun tepesine yaklaşıyorsunuz. Yokuş birkaç kilometre uzunluğunda, zemin kuru ve inişte servis frenlerinizin ısınıp (fren kaybı) verimini yitirmesini önlemek istiyorsunuz. Güvenli dağ sürüş kurallarına göre, iniş sırasında hızınız üzerinde en güvenilir kontrolü hangi davranış sağlar?","options":["Normal otoyol vitesinizde kalıp, hızı sabit tutmak için inişin tamamı boyunca servis frenlerine hafifçe basmaya devam etmek","Kamyonun iniş ortasında hızlanmaya başlamasını bekleyip ardından aracı tekrar yavaşlatmak için düşük vitese geçmek","Motorun dinlenmesi için şanzımanı yüksek viteste tutmak ve hızı kontrol etmek için esas olarak sert, tekrarlı fren uygulamalarına güvenmek","İnişe başlamadan ÖNCE düşük vitesi seçmek; böylece motor ve vites freni işin çoğunu yapsın, servis frenlerini ise yalnızca hafif ve düzenli bir destek olarak kullanmak"],"explanation":"Uzun bir yokuştan inmeye başlamadan önce düşük vites seçin ki frenlemenin çoğunu motor ve vites yapsın; servis frenlerini yalnızca hafif ve düzenli bir destek olarak kullanın."},"238":{"q":"Tamamen yüklü bir römorkla dağlık arazide ilerlerken navigasyonunuz ileride bir acil kaçış rampası olduğu uyarısını veriyor. Yanınızdaki acemi bir sürücü, karayolları idaresinin neden bu çakıl dolu uzun rampayı güzergâhın başka bir yerine değil de tam bu noktaya yaptığını soruyor. Bu rampaların kullanım amacına göre, idare böyle bir rampayı EN OLASI nereye yapar?","options":["Ağır araçların fren aşırı ısınmasından dolayı fren kaybı (fren sönmesi) riskinin en yüksek olduğu uzun ve dik bir inişin ortasında","Kamyonların genellikle en yüksek seyir hızlarına ulaştığı düz, açık bir otoyol bölümünde","Şehir trafiğinin sık sık sert frenlemeyi zorunlu kıldığı, şehir merkezindeki yoğun bir kavşaktan hemen önce","Birçok kamyonun geceyi geçirdiği büyük bir dinlenme tesisi otoparkının girişinde"],"explanation":"Kaçak kamyon rampaları, ağır araçların aşırı ısınmaya bağlı fren kaybına en çok uğradığı uzun ve dik inişlerin orta kesimlerine yerleştirilir."},"239":{"q":"Hava iyice karardı ve kırsal, iki şeritli bir karayolunda kısa farlarla ilerliyorsunuz; bu farlar yolu yaklaşık 250 fit ileriye kadar aydınlatıyor. Önünüzde keskin bir viraj var ve virajın ötesinde yolda ne olduğunu göremiyorsunuz. Farlarınızın aydınlattığından daha hızlı gitmemelisiniz kuralına en uygun davranış hangisidir?","options":["Virajda uzun farlara geçip dönemecin ötesini daha uzaktan görmek, düzlüğe çıkınca tekrar kısa farlara dönmek","Viraja girmeden önce hızınızı azaltarak, farlarınızın gerçekten aydınlattığı mesafe içinde durabilecek şekilde sürmek","Mevcut hızınızı koruyup öndeki aracı daha yakından takip ederek onun arka stop lambalarının sizi virajda yönlendirmesini sağlamak","Karayolu hızını korumak, çünkü 55 mil/saatte farlarınız ihtiyaç duyduğunuz 419 fitlik durma mesafesinin tamamını zaten aydınlatır"],"explanation":"Asla farlarınızın aydınlattığından hızlı gitmeyin: virajdan önce yavaşlayın ki farlarınızın gerçekten aydınlattığı mesafe içinde durabilesiniz."},"240":{"q":"Sefer öncesi muayene sırasında çekici-dorse aracınızın etrafını dolaşmayı bitirdiniz ve görünüşte her şey yolunda. Yola çıkıp trafiğe katılmadan önce, servis frenlerinizin gerçekten çalıştığını doğrulamanın doğru yolu nedir?","options":["Çevre kontrolü fren parçalarının iyi göründüğünü zaten doğruladığı için çalışma testini atlamak ve yalnızca ilk 50 milden sonra yeniden kontrol etmek","Otoyol hızına ulaşana kadar bekleyip ardından frenlere sertçe basarak kamyonun bir tarafa çekip çekmediğini hissetmek","Düşük hızda harekete geçip frenlere yumuşakça basarak aracın durduğundan ve bir tarafa çekmediğinden emin olmak","Park halindeyken fren pedalına birkaç kez basıp hava basıncı göstergesinin düşmesini izlemek; bu, frenlerin sizi durduracağını kanıtlar"],"explanation":"Çevre kontrolünden sonra, yavaşça hareket edip nazikçe fren yaparak servis frenlerini test edin; aracın durduğundan ve bir tarafa çekmediğinden emin olun."},"241":{"q":"İki şeritli kırsal bir karayolunda yüklü bir römork çekerken, güçlü bir yan rüzgâr esintisi çekicinizin ön kısmını aniden banket tarafına itiyor. Direksiyonu düzeltirken araç üzerinde en iyi kontrolü sağlamak için direksiyon simidindeki en güvenli el konumu hangisidir?","options":["Rüzgâra karşı hızlı ve geniş bir dönüş yapabilmek için bir elinizi direksiyonun en altında tutun","Tek elle direksiyon kullanın, diğer elinizi römorku yavaşlatmak için römork fren el valfine hazır tutun","Esinti geçtikten sonra kendi kendine merkezlenmesi için direksiyonun kısa bir süre ellerinizin arasından serbestçe kaymasına izin verin","Düzgün tepki verebilmek ve istikrarlı kontrolü koruyabilmek için her iki elinizi de direksiyonun karşılıklı taraflarında sıkıca tutun"],"explanation":"Direksiyonu karşılıklı taraflardan iki elinizle sıkıca tutun ki ani bir yan rüzgâr esintisinde yumuşak tepki verip kontrolü sabit tutabilesiniz."},"242":{"q":"Kalabalık bir TIR durağında yalnızsınız ve yerinizden çıkmanın tek yolu geri gitmek. Bir seçeneğiniz var: yaklaşımınızı sol (sürücü) tarafınıza doğru geri gidecek şekilde ayarlayabilir veya biraz daha kısa olan sağ (kör) tarafınıza doğru geri gidebilirsiniz. Hangi yaklaşım en güvenlidir ve neden?","options":["Sürücü (sol) tarafına doğru geri gidin, çünkü pencereden dışarı bakıp römorkunuzun arkasını tüm süre boyunca doğrudan izleyebilirsiniz.","Kör (sağ) tarafa doğru geri gidin, çünkü yol daha kısadır ve aynalarınız o tarafı tam olarak gösterir.","Hareket etmeden önce kornaya iki kez basıp dörtlü flaşörleri açtığınız sürece her iki taraf da eşit derecede güvenlidir.","Sadece düz geri gidin ve römorku asla açıyla döndürmeyin, çünkü TIR durağında her türlü yanal geri gitme yasaktır."],"explanation":"Her zaman sürücü (sol) tarafına doğru geri gidin; çünkü camdan dışarı bakıp römorkun arkasını yalnızca aynalara güvenmeden doğrudan görebilirsiniz."},"243":{"q":"Yüklü bir çekici-römork ile kuru ve düz bir otoyolda 55 mil/saat hızla giderken başka bir kamyonu geçmeye karar veriyorsunuz. Bunu güvenle yapmak için 65 mil/saat hıza çıkıyorsunuz. 55 mil/saatteki durmanıza kıyasla, bu hız değişikliğinin acil bir durumda durabilme yeteneğiniz üzerindeki EN önemli etkisi nedir?","options":["Yol kuru ve frenleriniz iyi olduğu için durma mesafesi yaklaşık aynı kalır","Durma mesafesi keskin biçimde artar, çünkü frenleme mesafesi yaklaşık olarak hızın karesiyle büyür","Daha hızlı dönen tekerlekler yola daha iyi tutunduğu için durma mesafesi biraz azalır","Durma mesafesi hızdan etkilenmez ve yalnızca yükünüzün ağırlığına bağlıdır"],"explanation":"Hız arttıkça durma mesafesi keskin biçimde artar; çünkü fren mesafesi yaklaşık olarak hızın karesiyle büyür."},"244":{"q":"Yüklü bir çekici-römork ile yoğun bir otoyola giriş rampasında ilerliyorsunuz. Hızlanma şeridi oldukça kısa, sağ şeritteki trafik yaklaşık 100 km/s (60 mil/s) hızla düzenli akıyor ve hemen önünüzde dar bir boşluk açılıyor. Birleşmeyi mümkün olduğunca güvenli tamamlamak için ne yapmalısınız?","options":["Rampanın sonunda tamamen durup, çıkmadan önce tüm trafiğin geçmesini beklemek","Yavaş ve temkinli bir hızla şeride girip, daha hızlı trafiğin aracınızın etrafında kendini ayarlamasına izin vermek","Hızlanma şeridini kullanarak trafik akışının hızına ulaşmak ve ardından açılan boşluğa girmek","Şerit konumunuzu koruyarak geçiş hakkınızı kullanmak, böylece ana şeritteki araçların size yol vermesini sağlamak"],"explanation":"Hızlanma şeridi, otoyol trafiğinin hızına ulaşıp başkalarını frenlemeye veya yön değiştirmeye zorlamadan boş aralığa düzgünce girmenizi sağlar."},"245":{"q":"Yoğun, dur-kalk şehir trafiğinde yüklü bir çekici-römork kullanıyorsunuz. Telefonuyla dikkati dağılmış bir yaya kaldırımdan iniyor ve önünüzdeki kısa bir mesafede şeridinize doğru yürümeye başlıyor. Gaz pedalını çoktan bıraktınız ve ayağınızı frenin üzerinde tutuyorsunuz. Bu anda kornanın hangi şekilde kullanılması DPS'ye göre uygundur?","options":["Yakındaki sürücüleri tetikte tutmak için kornaya hafifçe ve sürekli basın, çünkü trafik sıkışıklığında sürekli sinyal vermek çarpışmaları önler","Kornayı tamamen kullanmaktan kaçının ve yalnızca frene güvenin, çünkü şehir trafiğinde bir yayanın yakınında korna çalmaya asla izin verilmez","Yayanın ve çevredeki sürücülerin kavşağa büyük bir kamyonun yaklaştığını bilmesi için uzun, dostça bir korna çalın","Yayayı ani tehlikeye karşı uyarmak için kornayı çalın; bunu yalnızca başkalarını tehlikeye karşı uyarmak için kullanın"],"explanation":"Korna, yalnızca yolunuza giren dikkatsiz bir yaya gibi gerçek ve ani bir tehlikeye karşı başkalarını uyarmak için kullanılan bir uyarı aracıdır."},"246":{"q":"Hava donma noktasının hemen altında ve çekici-dorseyi dik bir iniş eğimine sahip yolun sağ banketine park etmeniz gerekiyor. El frenini çekiyorsunuz, ancak bu buzlu eğimde araç kaymaya başlarsa frenlerin tek başına aracı tutamayabileceğini biliyorsunuz. Araç kayarsa kaldırımı son bir engel olarak kullanmak için ön tekerlekleri hangi yöne çevirmelisiniz?","options":["Ön tekerlekleri kaldırıma doğru (sağa) çevirin; böylece öne doğru herhangi bir kayma ön lastiği kaldırıma sıkıştırır","Ön tekerlekleri kaldırımdan uzağa (sola, yola doğru) çevirin; böylece araç kayarsa kaldırımdan uzaklaşır","Ön tekerlekleri düz bırakın; çünkü el freni ve takozlar tutmayı tek başına yapar","El freni çekiliyse iniş eğiminde yön fark etmez"],"explanation":"Yokuş aşağı park ederken ön tekerlekleri kaldırıma doğru çevirin; böylece ileri kayış olursa bir lastik kaldırıma dayanıp aracı durdurur."},"247":{"q":"Kırsal iki şeritli bir karayolunda yüklü bir çekici-römork ile 50 mil/saat hızla giderken aynayı kontrol etmek için bir an aşağıya bakıyorsunuz. Başınızı kaldırdığınızda, sağ taraftaki tekerlekleriniz asfalttan kayıp yumuşak çakıllı banket üzerine kaymış ve çekiciniz hafifçe sağa çekiyor. Hemen önünüzde bir engel yok. Yola geri dönmenin EN İYI yolu nedir?","options":["Daha fazla yoldan çıkmadan hattınızı düzeltmek için direksiyonu hızlı ve sert bir hareketle çevirerek hemen asfalta geri dönün","Ayağınızı gaz pedalından çekin, direksiyonu sıkıca tutun ve kamyon yavaşlayıp kontrol altına girdikten sonra kademeli olarak asfalta geri yönlendirin","Aracın herhangi bir kısmı banketten çıkmadan önce hızı düşürmek için derhal sert bir şekilde fren yapın","Yumuşak çakılın içinden güç alarak geçmek ve aracı daha sağlam asfalta geri çekmek için gaza basın"],"explanation":"Tekerlekler banket toprağına kayarsa sert fren yapmadan gazdan ayağınızı çekin ve kamyon yavaşladıktan sonra kademeli olarak yola geri dönün."},"248":{"q":"İki şeritli bir kara yolunun sağ şeridinde, izin verilen 55 mil/saat hızla yüklü bir çekici-römork kullanıyorsunuz. Son birkaç dakikadır bir kamyonet sizi o kadar yakından takip ediyor ki artık aynalarınızda farlarını göremiyorsunuz ve önünüzde araç yok. Sol şeritteki trafik hafif. Bu sıkı takip eden (arkanıza yapışan) sürücüye karşı EN GÜVENLİ davranış nedir?","options":["Fren lambalarınızı yakıp sürücüyü geri çekilmesi için uyarmak amacıyla frene birkaç kez hafifçe basın","Hızınızı koruyun ama öndeki araçlarla takip mesafenizi azaltın ki arkanıza yapışan sürücüye yer açılsın","Önünüzdeki takip mesafesini artırın, ardından güvenli olduğunda şerit değiştirip arkanıza yapışan sürücünün geçmesine izin verin","Arkanıza yapışan sürücü tamponunuzdan ayrılana kadar yavaş yavaş 55 mil/saatin epey üzerine çıkın"],"explanation":"Arkanızda sıkı takip eden biri varsa öndeki mesafeyi artırın ve ardından kenara çekilerek güvenle geçmesine izin verin."},"249":{"q":"Yüklü bir çekici-römork ile çok şeritli bir otoyolda gidiyorsunuz ve yaklaşık bir mil sonra gelecek olan çıkıştan önce sağ şeride geçmeniz gerekiyor. Trafik orta yoğunlukta ve sağ kör noktanızda gerideki bir yerde bir otomobil bulunuyor. DPS'in diğer sürücülerle iletişim kurma rehberine göre, çevrenizdeki sürücülere ne yapmak istediğinizi bildirmenin TEK EN İYİ yolu nedir?","options":["Arkadaki aracın fren lambalarınızı görüp yavaşlayıp şerit değiştireceğinizi anlaması için birkaç kez frene hafifçe basın","Sağ şeritteki trafiğe geçiş yaptığınızı haber vermek için uzun farlarınızı yakıp söndürün","Hızlanın ve şerit değişimini hızlıca yapın, böylece kör noktanızdaki aracın yanında mümkün olan en az süre geçirirsiniz","Sağ sinyalinizi erkenden açın ve açık bırakın, şerit değiştirme niyetinizi açıkça ve çok önceden bildirin"],"explanation":"Niyetinizi açıkça bildirmek için sinyali erken ve manevradan çok önce açın, böylece diğer sürücüler tepki verecek zamana sahip olur."},"250":{"q":"Kuru bir otoyolda 30 fitlik tek parça bir kamyonu hafif trafikte sabit 50 mil/saat hızla sürüyorsunuz. Önünüzdeki bir otomobil sürekli şerit değiştiriyor, bu yüzden güvenli bir takip mesafesi belirlemeye karar veriyorsunuz. Standart takip mesafesi kuralına göre, o aracın arkasında bırakmanız gereken EN AZ takip mesafesi ne kadardır?","options":["4 saniye","3 saniye","5 saniye","6 saniye"],"explanation":"Her 10 fitlik uzunluk için 1 saniye takip mesafesi bırakın ve 40 mph üzerinde 1 saniye ekleyin: 50 mph'deki 30 fitlik kamyon 3 + 1 = 4 saniye gerektirir."},"251":{"q":"Şehir içinde 40 fit uzunluğunda tek parça (düz) bir kamyon kullanıyorsunuz ve hız göstergesi kuru zeminde sabit 35 mil/saat gösteriyor. Trafik az, ancak öndeki araç aniden frene basarsa tepki verebilmek için güvenli bir takip mesafesi bırakmak istiyorsunuz. Aracınızın uzunluğu ve mevcut hızınız için önerilen takip mesafesi kuralını kullanarak, koruyabileceğiniz EN AZ takip mesafesi nedir?","options":["5 saniye, çünkü 40 fitlik bir araç temel değerin üzerine otomatik olarak bir saniye daha gerektirir","4 saniye, çünkü her 10 fit uzunluk için 1 saniye ayırırsınız ve 40 mil/saatin altında fazladan hiçbir şey eklemezsiniz","3 saniye, çünkü üç saniye herhangi bir ticari araç için standart asgari mesafedir","6 saniye, çünkü bu uzunlukta güvenlik için her 10 fitlik sayımı her zaman iki katına çıkarmalısınız"],"explanation":"Her 10 fitlik uzunluk için 1 saniye takip mesafesi bırakın ve 40 mph altında ekleme yapmayın; 35 mph'deki 40 fitlik kamyon 4 saniye gerektirir."},"252":{"q":"Tamponundan tamponuna kadar 50 fit uzunluğunda bir düz platformlu çekici-römork kombinasyonu taşıyorsunuz. Eyaletler arası otoyolda trafik yoğunlaştı ve hız göstergeniz kuru, açık hava koşullarında istikrarlı bir şekilde 55 mil/saatte duruyor. Önünüzdeki aracın arkasına yerleşirken, el kitabının önerdiği güvenli mesafe içinde kalmak için saniye cinsinden korumanız gereken minimum takip mesafesi nedir?","options":["5 saniye, çünkü aracın her 10 fit uzunluğu için 1 saniye ayırırsınız","7 saniye, hızınız 40 mil/saatin çok üzerinde olduğu için 2 ekstra saniye ekleyerek","6 saniye, çünkü 50 fit size 5 saniye verir ve 40 mil/saatin üzerinde olduğunuz için 1 saniye daha eklersiniz","4 saniye, çünkü kuru havada istikrarlı bir otoyol hızı mesafeyi kısaltmanıza izin verir"],"explanation":"Her 10 fit uzunluk için 1 saniye bırakın ve 40 mph üzerinde 1 saniye ekleyin: 55 mph'deki 50 fitlik araç 5 + 1 = 6 saniye gerektirir."},"253":{"q":"İyi gündüz koşullarında, kuru ve düz bir eyaletler arası otoyolda 60 fit uzunluğundaki bir çekici-römork aracını sabit 45 mil/saat hızla sürüyorsunuz. Trafik az, ancak öndeki aracın arkasında güvenli bir takip mesafesi bırakmak istiyorsunuz. Aşağıdakilerden hangisi korumanız gereken minimum takip mesafesini saniye cinsinden doğru şekilde belirtir?","options":["6 saniye, çünkü aracın her 10 fit uzunluğu için 1 saniye bırakırsınız","5 saniye, çünkü uzun bir kombine araç her 10 fit için yalnızca yaklaşık yarım saniyeye ihtiyaç duyar","8 saniye, 40 mil/saatin üzerinde olduğunuz için 2 ek saniye ekleyerek","7 saniye, çünkü uzunluk için 6 saniye artı 40 mil/saatin üzerinde olduğunuz için 1 saniye daha bırakırsınız"],"explanation":"Her 10 fit uzunluk için 1 saniye bırakın ve 40 mph üzerinde 1 saniye ekleyin: 45 mph'deki 60 fitlik araç 6 + 1 = 7 saniye gerektirir."},"254":{"q":"Açık ve kuru hava koşullarında, düz bir şehir ana yolunda sabit 35 mil/saat hızla 70 fit uzunluğunda bir çekici-römork sürüyorsunuz. Önünüzdeki trafik düzgün ilerliyor ve güvenli bir takip mesafesi belirlemek istiyorsunuz. Takip mesafesini hesaplama formülünü kullanarak, önünüzdeki araçla aranızda bırakmanız gereken EN AZ mesafe şudur:","options":["7 saniye","8 saniye","6 saniye","9 saniye"],"explanation":"Aracın her 10 feet uzunluğu için 1 saniye takip mesafesi bırakın; 40 mph altında ek saniye eklenmez, bu yüzden 70 feet'lik bir kamyon 7 saniye gerektirir."},"255":{"q":"Kuru bir eyaletler arası otoyolda yük taşıyorsunuz ve hız göstergeniz sabit 45 mil/saat gösteriyor. Aynalarınıza bir göz attığınızda, çekici-römork kombinasyonunuzun ön tamponundan römorkun arkasına kadar tam 80 fit uzunlukta olduğunu tahmin ediyorsunuz. Trafik düzgün akıyor ve önünüzdeki araçla güvenli bir mesafe bırakmak istiyorsunuz. Önerilen takip mesafesi kuralına göre kaç saniyelik boşluk bırakmalısınız?","options":["8 saniye, çünkü kural sadece aracın her 10 fitlik uzunluğu için 1 saniyedir","9 saniye, çünkü 80 fit size 8 saniye verir ve 40 mil/saatin üzerinde gittiğiniz için 1 saniye eklersiniz","7 saniye, çünkü bu hızda uzunluğa dayalı sayımdan bir saniye çıkarabilirsiniz","10 saniye, çünkü uzunluğu yukarı yuvarlamalı ve otoyol hızında tam 2 saniyelik bir tampon eklemelisiniz"],"explanation":"Her 10 feet uzunluk için 1 saniye ile temel 8 saniye elde edilir, ardından 40 mph üzeri hız için 1 saniye eklenerek toplam 9 saniye olur."},"256":{"q":"Kuru bir otoyolda hafif trafikte sabit 50 mph hızla 90 fit uzunluğunda bir kombinasyon aracı sürüyorsunuz. Bir otomobil önünüze geçiyor ve güvenli bir mesafeyi yeniden oluşturmanız gerekiyor. Takip mesafesi kuralına göre, o aracın arkasında bırakmanız gereken EN AZ mesafe nedir?","options":["9 saniye, çünkü kural sadece aracın her 10 fitlik uzunluğu için 1 saniyedir","8 saniye, çünkü kuru zeminde istikrarlı şekilde ilerlerken biraz zaman kısabilirsiniz","10 saniye takip mesafesi","11 saniye, 40 mph'nin oldukça üzerinde olduğunuz için 2 ekstra saniye ekleyerek"],"explanation":"Her 10 feet uzunluk için 1 saniye ile temel 9 saniye elde edilir, ardından 40 mph üzeri hız için 1 saniye eklenerek toplam 10 saniye olur."},"257":{"q":"Ön tamponundan römork sonuna kadar 100 fit uzunluğunda bir açık kasa (flatbed) kombinasyon aracı kullanıyorsunuz. Trafik açılıyor ve kuru bir otoyolda 60 mil/saate hızlanıyorsunuz. Aynanıza bakarak, takip ettiğiniz aracın arkasında güvenli bir takip mesafesi bırakmak istiyorsunuz. Takip mesafesi kuralına göre, korumanız gereken EN AZ kaç saniyelik boşluktur?","options":["10 saniye, çünkü aracın her 10 fitlik uzunluğu için 1 saniye ayırırsınız ve 100 bölü 10 eşittir 10","12 saniye: her 10 fit için 1 saniye artı yüksek hız için 2 ek saniye","9 saniye, çünkü 60 mil/saat, uzunluğa dayalı sayımdan bir saniye çıkaracak kadar hızlıdır","11 saniye, çünkü 100 fit 10 saniye verir ve 40 mil/saatin üzerinde seyahat ettiğiniz için 1 saniye daha eklersiniz"],"explanation":"Her 10 feet uzunluk için 1 saniye ile temel 10 saniye elde edilir, ardından 40 mph üzeri hız için 1 saniye eklenerek toplam 11 saniye olur."},"258":{"q":"Kuru bir eyaletler arası otoyolda 40 fitlik tek parça bir kamyon kullanıyorsunuz ve iyi gündüz koşullarında sabit 55 mil/saat hızla gidiyorsunuz. Önünüzdeki trafik akıcı. El kitabındaki güvenli takip mesafesi kuralını uygulayarak, önünüzdeki araçla aranızda korumanız gereken EN AZ boşluk nedir?","options":["5 saniye","4 saniye","6 saniye","3 saniye"],"explanation":"Her 10 feet uzunluk için 1 saniye ile temel 4 saniye elde edilir, ardından 40 mph üzeri hız için 1 saniye eklenerek toplam 5 saniye olur."},"259":{"q":"Bir açık kasa (flatbed) yük taşıyorsunuz ve sefer öncesi kontrol sırasında çekici-römork aracınızı tamponundan tamponuna 50 fit ölçüyorsunuz. Kuru bir kırsal otoyolda hafif trafikte hız göstergeniz sabit 50 mil/saatte duruyor. Öndeki araçla güvenli takip mesafesini belirleme kuralını kullanarak, bu hız ve uzunlukta kaç saniyelik mesafe bırakmalısınız?","options":["5 saniye, çünkü aracın her 10 fitlik uzunluğu için 1 saniye ayrılır","6 saniye, çünkü her 10 fit uzunluk için 1 saniye ayrılır ve 40 mil/saatin üzerinde olduğu için 1 saniye daha eklenir","7 saniye, çünkü her 10 fit uzunluk için 1 saniye ayrılır ve otoyol hızı için 2 saniye daha eklenir","4 saniye, çünkü takip mesafesi yalnızca hıza bağlıdır, aracın uzunluğuna değil"],"explanation":"Her 10 feet uzunluk için 1 saniye ile temel 5 saniye elde edilir, ardından 40 mph üzeri hız için 1 saniye eklenerek toplam 6 saniye olur."},"260":{"q":"Kuru ve düz bir eyaletler arası otoyolda 70 fitlik (yaklaşık 21 m) bir çekici-römork sürüyorsunuz ve hafif trafikte sabit 45 mil/saat hızı koruyorsunuz. Aynalarınıza bakarak, öndeki araç sabit bir nesneyi geçtikten sonra o noktaya ulaşmanızın kaç saniye sürdüğünü sayarak takip mesafenizi belirlemeye karar veriyorsunuz. Aracınızın uzunluğuna ve mevcut hızınıza göre korumanız gereken EN AZ takip mesafesi nedir?","options":["7 saniye, çünkü kural sadece aracın her 10 fitlik uzunluğu için 1 saniyedir","6 saniye, çünkü otoyol hızında yaklaşık 6 saniyelik toplam durma mesafesi yeterlidir","8 saniye, çünkü her 10 fit uzunluk için 1 saniye ve 40 mil/saatin üzerinde olduğunuz için 1 ek saniye gereklidir","9 saniye, uzunluk ve hız saniyelerine ek olarak kuru zemin için bir saniye ekleyerek"],"explanation":"Her 10 feet uzunluk için 1 saniye ile temel 7 saniye elde edilir, ardından 40 mph üzeri hız için 1 saniye eklenerek toplam 8 saniye olur."},"261":{"q":"Ön tamponundan römork arkasına kadar 80 fit uzunluğunda bir açık kasa kombinasyon aracı kullanıyorsunuz. Düz, iki şeritli bir karayolunda trafik akıcı ve hız göstergeniz sabit 35 mil/saatte. Önünüzdeki kamyonun arkasında güvenli bir takip mesafesi tutmak için hangi boşluğu korumalısınız?","options":["9 saniye, çünkü uzunluk için 8 saniye alıp karayolu hızı için 1 saniye daha eklersiniz","7 saniye, çünkü düşük hızlarda tampon mesafesi bir saniye kısaltılabilir","10 saniye, herhangi bir büyük kombinasyon aracının ihtiyaç duyabileceği azami tampon","8 saniye, çünkü her 10 fit uzunluk 1 saniye gerektirir ve 40 mil/saatin altında ek saniye eklenmez"],"explanation":"Her 10 feet uzunluk için 1 saniye ile 8 saniye olur ve 35 mph'de (40 mph altı) ek saniye eklenmez, bu yüzden mesafe 8 saniyedir."},"262":{"q":"Sefer öncesi kontrolünüzde, düz platformlu bir treylere tek bir 15 fitlik çelik boruyu sabitliyorsunuz. Boru, kayışlarınızın çalışma yük sınırının rahatça içinde. Federal yük emniyeti asgari koşulunu karşılamak için bu tek parça üzerinde yasal olarak kullanabileceğiniz EN AZ kaç bağlama (tie-down) gerekir?","options":["2 bağlama","1 bağlama","3 bağlama","4 bağlama"],"explanation":"Yük her 10 feet uzunluk için en az 1 bağlama ve 5 feet'ten uzun her parça için en az 2 bağlama gerektirir, bu yüzden 15 feet'lik bir boru 2 bağlama gerektirir."},"263":{"q":"Sefer öncesi kontrolünüzde, römorkunuza düz yerleştirilmiş 25 fitlik tek bir çelik I-kirişi buluyorsunuz ve onu yalnızca 2 zincir bağlama tutuyor. Kiriş ağırlık sınırlarınızın oldukça altında ve platform iyi durumda. Yasal olarak yola çıkabilmeniz için bu parçanın sahip olması gereken EN AZ kaç bağlama olmalıdır?","options":["2 bağlama, çünkü 5 fitten uzun herhangi bir parça yasal olarak en az 2 sabitleme cihazı gerektirir","3 bağlama, çünkü her 10 fit yük için en az bir bağlama gerekir ve 25 fit yukarı yuvarlanarak 3'e çıkar","4 bağlama, çünkü uzun ve ağır çelik, uzunluğunun her 5 fitinde sabitlenmelidir","1 bağlama, çünkü kiriş platformun üzerinde sağlam duran tek ve rijit bir parçadır"],"explanation":"Yük her 10 feet uzunluk için en az 1 bağlama gerektirir ve yukarı yuvarlanır, bu yüzden 25 feet'lik bir kiriş 3 bağlama gerektirir."},"264":{"q":"Sefer öncesi kontrolünüzde, açık kasa platformda duran 35 fit uzunluğundaki tek bir çelik kirişi sabitliyorsunuz. Bu uzunluktaki yükün kaç bağlama gerektirdiği kuralını bilerek, bu kirişi yasal olarak sabitlemek için kullanabileceğiniz EN AZ bağlama sayısı kaçtır?","options":["3 bağlama, çünkü 35 fit 10'a bölününce üç tam 10 fitlik bölüm verir","2 bağlama, çünkü tek bir parçaya sadece her iki ucundan birer tane gerekir","4 bağlama, çünkü her 10 fit için en az bir tane gerekir ve 35 fit yukarı yuvarlanır","5 bağlama, çünkü bu uzunlukta bir kiriş güvenlik payı için fazladan bir tane gerektirir"],"explanation":"Yük emniyeti her 10 fitlik uzunluk için en az bir bağlama gerektirir ve kısmi bölüm yukarı yuvarlanır, bu yüzden 35 fit 4 gerektirir."},"265":{"q":"Sefer öncesi kontrolde, açık kasalı (flatbed) bir araca 45 fitlik tek bir çelik kirişi bağlıyorsunuz. Kiriş 9.000 lb ağırlığında ve her zincirinizin çalışma yük limiti yükün gerektirdiğinin çok üzerinde, bu yüzden ağırlık derecelendirmesi burada sizin sorununuz değil. SADECE asgari bağlama sayısı kuralına dayanarak, bu kirişi yasal olarak taşımak için kullanmanız gereken EN AZ kaç bağlama gereklidir?","options":["4 bağlama, çünkü her tam 10 fit uzunluk için bir tane sayıp artan 5 fiti dikkate almazsınız","3 bağlama, çünkü çalışma yük limiti yükü tutmaya zaten yeterince yüksek","6 bağlama, uzunluk kuralının ötesine güvenlik payı olarak bir fazladan ekleyerek","5 bağlama, çünkü her 10 fit için en az bir tane gerekir ve 45 fit yukarı yuvarlanarak 5 eder"],"explanation":"Her 10 fitlik yük için en az bir bağlama gerekir ve kalan kısım yukarı yuvarlanır, bu yüzden 45 fitlik yük 5 gerektirir."},"266":{"q":"Yola çıkış öncesi kontrolünüz sırasında düz platformlu (flatbed) bir araca tek bir 55 fitlik çelik kirişi sabitliyorsunuz. Yük uzunluğuna göre bağlama sayısı için asgari federal/Teksas sabitleme kuralını karşılamak istiyorsunuz. Yalnızca uzunluğa dayalı gereksinimi dikkate alarak, bu kiriş için yasal olarak kullanabileceğiniz EN AZ kaç bağlama gereklidir?","options":["6 bağlama, çünkü her 10 fit yük için en az bir tane gerekir ve 55 fit yukarı yuvarlanarak 6 olur","5 bağlama, çünkü 55 bölü 10 eşittir 5 ve kalanı atarsınız","7 bağlama, çünkü her 10 fit için bir tane artı 5 fitten uzun her parça için fazladan bir tane gerekir","4 bağlama, çünkü her iki uçta ikişer bağlama herhangi bir tek kirişi sabitlemek için yeterlidir"],"explanation":"Her 10 fitlik yük için bir bağlama gerekir ve kısmi bölüm yukarı yuvarlanır, bu yüzden 55 fitlik yük 6 gerektirir."},"267":{"q":"Sefer öncesi kontrolünüz sırasında düz platform üzerinde tek bir çelik kirişi sabitliyorsunuz. Kiriş yaklaşık 8 fit uzunluğunda ve kabaca 3.000 libre ağırlığında. 10 fitten epey kısa olduğu için 'her 10 fite bir bağlama' kuralının tek bir bağlamayı yeterli kıldığını düşünüyorsunuz. Kullanmanız gereken EN AZ bağlama sayısını hangi ifade doğru tanımlar?","options":["1 bağlama, çünkü kiriş 10 fitten kısa ve her-10-fit kuralı geçerlidir","2 bağlama, çünkü 5 fitten uzun herhangi bir parça, her-10-fit sayımından bağımsız olarak en az 2 bağlama gerektirir","1 bağlama, çünkü kiriş tek bağlama için belirlenen 1.100 libre eşiğinden daha hafiftir","Bu kadar kısa tek bir parça için hiç bağlama gerekmez"],"explanation":"5 fitten uzun herhangi bir tekil yük parçası, her 10 fit hesabından bağımsız olarak en az 2 bağlamaya sahip olmalıdır."},"268":{"q":"Bir kırsal otoyol kesimini normalde saatte 25 mil hızla geçersiniz ve deneyiminizden, frenler tuttuktan sonra yüklü aracınızın orada yaklaşık 30 fit fren mesafesine ihtiyaç duyduğunu bilirsiniz. Bu gece aynı yolda, aynı yükle, aynı kuru zeminde, ancak saatte 50 mil hızla gidiyorsunuz. Saatte 25 mildeki normal fren mesafenize kıyasla, saatte 50 mildeki fren mesafeniz yaklaşık olarak ne kadar olur:","options":["Yaklaşık aynı, çünkü yük ve zemin değişmedi","Yaklaşık iki katı, çünkü hızınızı ikiye katladınız","Yaklaşık dört katı, çünkü fren mesafesi hızın karesiyle orantılı olarak artar","Yaklaşık yarısı kadar, çünkü tekerlekler daha hızlı döner ve enerjiyi daha çabuk dağıtır"],"explanation":"Fren mesafesi hızın karesiyle artar, bu yüzden hızı iki katına çıkarmak fren mesafesini yaklaşık dört kat uzatır."},"269":{"q":"İyi havada, kuru ve düz bir otoyolda saatte 55 mil hızla giderken, önünüzdeki şeritte uzakta aniden arızalı bir araba beliriyor. Bir yolcunuz, tehlikeyi ilk fark ettiğiniz andan itibaren tamamen durmak için gerçekte ne kadar yol gerektiğini soruyor. Algılama, tepki VE frenleme mesafesini birlikte saydığınızda, toplam durma mesafenizin hangi tahmini gerçeğe en yakındır?","options":["Yaklaşık 60 fit — kamyonunuzun yalnızca tepki süresi boyunca katettiği mesafe kadar","Yaklaşık 100 fit — bir kamyon boyundan biraz fazlası","Yaklaşık 250 fit — gece kısa hüzme farlarınızın aydınlattığı mesafe","Yaklaşık 419 fit — bir Amerikan futbolu sahası artı her iki sayı bölgesi uzunluğuna yakın (yaklaşık 6 saniyelik yol)"],"explanation":"Toplam durma mesafesi algılama, tepki ve fren mesafelerinin toplamıdır ve 55 mil/saatte yaklaşık 419 fit eder (yaklaşık 6 saniye)."},"270":{"q":"Şehir içi teslimat rotanızda normalde 30 mil/saat hızla seyrediyorsunuz, ancak bugün bir sapma sizi aynı kuru zeminde ve aynı yüklü dorseyle 60 mil/saatlik bir otoyola çıkarıyor. Yanınızda giden yeni bir sürücü, sadece hızınızı iki katına çıkardığınız için durmanın yaklaşık iki kat mesafe alacağını sanıyor. Hızınızı kabaca İKİYE KATLAMAK fren mesafenizi gerçekte nasıl değiştirir?","options":["Fren mesafesi yaklaşık dört kat artar, çünkü hızın karesiyle orantılı olarak büyür","Fren mesafesi yalnızca yaklaşık iki katına çıkar, hızla doğru orantılı olarak artar","Fren mesafesi neredeyse aynı kalır, çünkü yüklü dorse yol tutuşu ekler","Fren mesafesi yalnızca biraz artar, çünkü hızla asıl büyüyen şey tepki mesafesidir"],"explanation":"Fren mesafesi hızın karesiyle artar, bu yüzden hızı iki katına çıkarmak onu iki değil yaklaşık dört kat uzatır."},"271":{"q":"Otoyol hızında giderken, önünüzde yola aniden bir geyik çıkar. Durmanın ilk aşaması ALGILAMADIR: geyiğin görüş alanınıza ilk girdiği andan, beyninizin onu gerçekten bir tehlike olarak tanıdığı ana kadar geçen süre. Bu aşama, siz daha ayağınızı frene doğru hareket ettirmeden önce gerçekleşir. Yaklaşık 55 mil/saat hızdaki dikkatli bir sürücü için bu algılama aşaması tek başına yaklaşık ne kadar ZAMAN alır?","options":["Yaklaşık 3/4 saniye, ama bu aslında tehlike tanındıktan sonra ayağınızı pedala götürmek için gereken tepki süresidir","Yaklaşık 1,75 saniye; el kitabının, herhangi bir tepki başlamadan önce otoyol hızında bir tehlikeyi algılamak ve tanımak için verdiği süre","Yaklaşık 6 saniye, ama bu gerçekte 55 mil/saat hızdan tamamen durmak için gereken toplam süredir, yalnızca algılama aşaması değil","Yaklaşık onda bir saniye, çünkü dikkatli bir profesyonel sürücü tehlikeleri neredeyse anında algılar"],"explanation":"Algılama, beynin bir tehlikeyi görüp tanıması için gereken süredir; otoyol hızında herhangi bir tepki başlamadan önce yaklaşık 1,75 saniyedir."},"272":{"q":"Kuru bir otoyolda 55 mil/saat hızla ilerlerken, ileride şeridinizde aniden arızalı bir araç beliriyor. Tamamen durana kadar aracınız yaklaşık bir futbol sahası artı her iki kaçış bölgesi uzunluğunda (yaklaşık 419 fit) yol alır. Eğitmenler bu toplam durma mesafesini üç parçaya ayırır: tehlikeyi GÖRDÜĞÜNÜZ sırada aracın aldığı mesafe (algılama mesafesi), ayağınızı pedala götürdüğünüz sırada aldığı mesafe (tepki mesafesi) ve bir parça daha. Hangi parça toplam durma mesafesini tamamlar?","options":["Direksiyon mesafesi — engelin etrafından dolaşmak için direksiyonu çevirirken alınan mesafe","Sinyal mesafesi — trafiği uyarmak için dörtlülerinizi yakarken alınan mesafe","Frenleme mesafesi — frenler tuttuktan sonra araç tamamen durana kadar aldığı mesafe","Park mesafesi — güvenle kenara çektiğinizde bordur kenarında bıraktığınız fazladan boşluk"],"explanation":"Toplam durma mesafesinin üçüncü bileşeni fren mesafesidir; kamyonun frenlere basıldıktan sonra tamamen durana kadar kat ettiği mesafedir."},"273":{"q":"İyi havada düz bir otoyolda 20 fit uzunluğundaki düz kasa kamyonunuzu hafif trafikte sabit 35 mil/saat hızla sürüyorsunuz. Önünüzdeki aracın arkasında doğru asgari takip mesafesini bırakmak istiyorsunuz. Aracın her 10 fit uzunluğu için 1 saniye kuralını kullanarak, bu hızda kaç saniyelik takip mesafesi bırakmalısınız?","options":["4 saniye, çünkü kamyonun her 10 fitlik uzunluğu için her zaman tam bir ekstra saniye eklemelisiniz","3 saniye, uzunluğa dayalı değere 1 saniye ekleyerek, çünkü otoyol trafiği öngörülemez","1 saniye, çünkü 35 mil/saatte 40 mil/saatin altındasınız ve ekstra saniye kuralı geçerli değildir","2 saniye, çünkü 20 fit uzunluk 2 saniye verir ve 40 mil/saatin altında saniye eklenmez"],"explanation":"40 mil/saatin altında her 10 fitlik araç uzunluğu için 1 saniye takip mesafesi gerekir, bu yüzden 20 fitlik bir araç 2 saniye gerektirir."},"274":{"q":"Açık havada kuru bir eyaletler arası otoyolda sabit 55 mil/saat hızla 20 fitlik (yaklaşık 6 metre) düz bir kamyon kullanıyorsunuz. Trafik az ve öndeki aracın arkasında güvenli bir takip mesafesi bırakmak istiyorsunuz. Takip mesafesini araç uzunluğuna ve hıza göre belirleme kuralını kullanarak kaç saniyelik mesafe bırakmalısınız?","options":["3 saniye","2 saniye","4 saniye","6 saniye"],"explanation":"Aracın her 10 fitlik uzunluğu için 1 saniye takip mesafesi bırakın, 40 mil/saatin üzerindeki hızlarda 1 saniye daha ekleyin."},"275":{"q":"Tamponundan tamponuna 30 fit uzunluğunda tek parçalı bir kamyon kullanıyorsunuz. Şehir içinde trafik düzenli akıyor ve hız göstergeniz 35 mil/saat gösteriyor. Önünüzde güvenli bir mesafe bırakmak için, öndeki araçla aranızda tutmanız gereken en az takip mesafesi nedir?","options":["2 saniye, çünkü yol düz ve otoyol hızının çok altındasınız","3 saniye, çünkü bu hızda aracınızın her 10 fit uzunluğu için 1 saniye ayırırsınız","4 saniye, trafikte olduğunuz için uzunluğa dayalı mesafeye 1 saniye daha ekleyerek","5 saniye, bu uzunlukta bir araç için daha yüksek otoyol hızlarında kullanılan mesafeye uygun olarak"],"explanation":"Aracın her 10 fitlik uzunluğu için 1 saniye takip mesafesi bırakın; 40 mil/saatin altındaki hızlarda fazladan saniye eklenmez."},"276":{"q":"Kuru bir otoyolda 30 fit uzunluğunda tek parça düz bir kamyon kullanıyorsunuz ve hafif trafikte sabit 55 mil/saat hızla gidiyorsunuz. Öndeki araçla güvenli bir mesafe bırakmak için yol kenarında sabit bir nesne seçip ön tamponunuz oraya ulaşana kadar saniyeleri sayıyorsunuz. Bu durumda kaç saniye takip mesafesi bırakmalısınız?","options":["3 saniye, çünkü kural aracın her 10 fit uzunluğu için 1 saniyedir","5 saniye, uzunluk ve hız kuralının gerektirdiğinden 1 saniye fazla bırakarak","4 saniye, çünkü 30 fit 3 saniye verir ve 40 mil/saatin üzerinde olduğunuz için 1 saniye daha eklersiniz","2 saniye, bir binek otomobilin otoyol hızında bıraktığı aynı asgari mesafe"],"explanation":"Aracın her 10 fitlik uzunluğu için 1 saniye takip mesafesi bırakın, 40 mil/saatin üzerindeki hızlarda 1 saniye daha ekleyin."},"277":{"q":"Kuru ve düz bir otoyolda 40 fit uzunluğunda dümdüz bir yük taşıyorsunuz ve hafif trafikte hız göstergeniz 50 mph'de sabitleniyor. Önünüzdeki araçla güvenli bir mesafe bırakmak için bu durumda kaç saniyelik takip mesafesi korumalısınız?","options":["4 saniye, çünkü aracınızın her 10 fit uzunluğu için 1 saniye ayrılır","6 saniye, çünkü bu otoyol hızında bir kamyonun ihtiyaç duyduğu toplam durma mesafesine denk gelir","3 saniye, tüm araçlara uygulanan standart 3 saniye kuralına göre","5 saniye, çünkü 40 mph'den hızlı giderken uzunluğa dayalı sayıya 1 ekstra saniye eklersiniz"],"explanation":"Aracın her 10 fitlik uzunluğu için 1 saniye takip mesafesi bırakın, 40 mil/saatin üzerindeki hızlarda 1 saniye daha ekleyin."},"278":{"q":"Kuru bir eyaletler arası otoyolda 60 fit uzunluğunda bir çekici-dorse takımı kullanıyorsunuz ve hafif trafikte sabit 50 mil/saat hızı koruyorsunuz. Önünüzdeki bir otomobil hızınızı belirliyor ve güvenli bir boşluk bırakmak istiyorsunuz. El kitabındaki temel takip mesafesi kuralını kullanarak, o aracın arkasında kaç saniyelik mesafe bırakmalısınız?","options":["7 saniye, çünkü 60 fit uzunluk 6 saniye verir, artı 40 mil/saatin üzerinde gitmek için 1 ek saniye","6 saniye, çünkü aracın her 10 fit uzunluğu için 1 saniye ayırırsınız","8 saniye, çünkü uzunluk için 6 saniyenin üstüne otoyol hızı için 2 saniye eklersiniz","5 saniye, çünkü 60 fitlik bir araç orta hızda her 5 fit için yaklaşık yarım saniyeye ihtiyaç duyar"],"explanation":"Aracın her 10 fitlik uzunluğu için 1 saniye takip mesafesi bırakın, 40 mil/saatin üzerindeki hızlarda 1 saniye daha ekleyin."},"279":{"q":"Açık bir gündüz havasında, kuru bir eyaletler arası otoyolda 70 fit uzunluğunda bir çekici-römork ile sabit 55 mph hızla seyrediyorsunuz. Önünüzdeki sürücü hafifçe fren yapıyor ve olmanız gerekenden daha yakına kaydığınızı fark ediyorsunuz. Takip mesafesi için temel kuralı kullanarak, o aracın arkasında tutmanız gereken EN AZ boşluk nedir?","options":["7 saniye, çünkü aracınızın uzunluğunun her 10 fiti için 1 saniye ayırırsınız","8 saniye, çünkü her 10 fit uzunluk için 1 saniye ayırır ve 40 mph üzerinde gitmek için 1 saniye daha eklersiniz","6 saniye, çünkü 55 mph hızda toplam durma mesafesi yaklaşık 6 saniyedir","9 saniye, her 10 fit için 1 saniye artı otoyol hızı için 2 ek saniye ayırarak"],"explanation":"Aracın her 10 fitlik uzunluğu için 1 saniye takip mesafesi bırakın, 40 mil/saatin üzerindeki hızlarda 1 saniye daha ekleyin."},"280":{"q":"Tampondan tampona 90 fit uzunluğundaki bir çekici-römork aracıyla 35 mil/saat hız sınırlı bir yol çalışması bölgesinden yük taşıyorsunuz. Trafik düzenli, zemin kuru ve aracın uzunluğuna göre saniye kuralını kullanarak güvenli bir takip mesafesi belirlemek istiyorsunuz. Bu durumda önünüzdeki aracın arkasında kaç saniyelik takip mesafesi bırakmalısınız?","options":["10 saniye, çünkü bu uzunluktaki herhangi bir kombinasyon araç hızdan bağımsız olarak bir ekstra saniye eklenmesini gerektirir","8 saniye, çünkü 90 fitlik uzunluğu en yakın tam kural aralığına aşağı yuvarlarsınız","9 saniye, çünkü aracın her 10 fit uzunluğu için 1 saniye ayırırsınız ve hızınız 40 mil/saatin altındadır","11 saniye, çünkü her 10 fit için 1 saniye ayırır ve yol çalışması bölgesi için tam bir ekstra saniye eklersiniz"],"explanation":"Aracın her 10 fitlik uzunluğu için 1 saniye takip mesafesi bırakın; 40 mil/saatin altındaki hızlarda fazladan saniye eklenmez."},"281":{"q":"Düz bir eyaletler arası otoyolda 90 fit uzunluğunda bir çekici-römork kombinasyonu çekiyorsunuz ve hız göstergeniz açık, kuru havada sabit 60 mil/saat gösteriyor. Öndeki trafik serbestçe akıyor. El kitabındaki güvenli takip mesafesini değerlendirme kuralını kullanarak, aracınızın önü ile öndeki araç arasında kaç saniyelik boşluk bırakmalısınız?","options":["8 saniye, çünkü 60 mil/saatte daha yüksek otoyol hızını hesaba katmak için temel değeri azaltırsınız","11 saniye, 40 mil/saatin oldukça üzerinde olduğunuz için 2 ekstra saniye ekleyerek","9 saniye, çünkü aracın her 10 fitlik uzunluğu için yalnızca 1 saniye sayarsınız","10 saniye, her 10 fit uzunluk için 1 saniye sayıp 40 mil/saatin üzerindeki hız için 1 saniye daha ekleyerek"],"explanation":"Aracın her 10 fitlik uzunluğu için 1 saniye takip mesafesi bırakın, 40 mil/saatin üzerindeki hızlarda 1 saniye daha ekleyin."},"282":{"q":"Düz, kuru bir kırsal otoyolda 100 fit uzunluğunda bir çekici-römork kombinasyonu sürüyorsunuz ve hız göstergeniz sabit şekilde 35 mil/saati gösteriyor. Önünüzdeki bir otomobil aynı hızla ilerliyor ve güvenli bir takip mesafesi belirlemek istiyorsunuz. Öndeki aracın az önce geçtiği sabit bir işarete ön tamponunuzun ulaşması için geçen saniyeleri sayarak, korumanız gereken EN AZ takip mesafesi nedir?","options":["10 saniye","11 saniye","9 saniye","7 saniye"],"explanation":"Aracın her 10 fitlik uzunluğu için 1 saniye takip mesafesi bırakın; 40 mil/saatin altındaki hızlarda fazladan saniye eklenmez."},"283":{"q":"Açık kasalı bir yarı römork çekiyorsunuz ve tamponundan tamponuna çekiciniz tam 100 fit (yaklaşık 30 metre) uzunluğunda. Kırsal otoyolda trafik oturmuş durumda ve hız göstergeniz kuru, açık koşullarda sabit şekilde 45 mil/saatte duruyor. Önünüzdeki aracın sabit bir işareti geçişini sayarak, o aracın arkasında kaç saniyelik takip mesafesi bırakmalısınız?","options":["10 saniye, çünkü aracınızın her 10 fitlik uzunluğu için 1 saniye ayırırsınız","11 saniye, çünkü 100 fit 10 saniye gerektirir ve 40 mil/saatin üzerinde olduğunuz için 1 saniye daha eklersiniz","12 saniye, her 10 fit için 1 saniye artı otoyol hızı için 2 ekstra saniye ayırarak","9 saniye, kuru zemin nedeniyle 100 fitlik aracı aşağı yuvarlayarak"],"explanation":"Aracın her 10 fitlik uzunluğu için 1 saniye takip mesafesi bırakın, 40 mil/saatin üzerindeki hızlarda 1 saniye daha ekleyin."},"284":{"q":"Kuru bir otoyolda 60 fit uzunluğunda bir çekici-römork kombinasyonu sürüyorsunuz ve seyrek trafikte sabit 60 mil/saat hızı koruyorsunuz. El kitabındaki takip mesafesi kuralını hatırlayarak, önünüzdeki araçla aranızda bırakmanız gereken EN AZ mesafe ne olmalıdır?","options":["6 saniye, çünkü 60 fitlik bir araç her 10 fit uzunluk için 1 saniyeye ihtiyaç duyar","5 saniye, çünkü trafik seyrek ve yol kuru","7 saniye: her 10 fit uzunluk için 1 saniye, artı 40 mil/saatin üzerinde olduğu için 1 saniye daha","8 saniye, otoyol hızı söz konusu olduğu için temel değere 2 saniye ekleyerek"],"explanation":"Aracın her 10 fitlik uzunluğu için 1 saniye takip mesafesi bırakın, 40 mil/saat üzerindeki hızlarda ise 1 saniye daha ekleyin."},"285":{"q":"Alacakaranlıkta kuru, iki şeritli bir kır yolunda yüklü bir çekici-römork ile otoyol hızında ilerlerken, büyük bir geyik ağaç sırasından fırlayıp yaklaşık 150 fit ileride sizin şeridinizde donup kalıyor. Sol şerit boş görünüyor ve sağınızda asfalt bir banket var. Genellikle EN güvenli tepki hangisidir?","options":["Boş göründüğü için hayvanın etrafından dolaşmak üzere hızlıca sol şeride yönelmek","Sağ bankete kırıp geyik hareket etmeden önce hızlanarak yanından geçmek","Ellerinizi direksiyondan çekip kamyonun kendi kendine düz gitmesine izin vermek","Sağlam, kontrollü fren uygulamak ve kendi şeridinizde kalmak"],"explanation":"Sert ve kontrollü fren yapın ve şeridinizde kalın, çünkü ani keskin manevra yüksek ağırlık merkezli aracı devirebilir veya katlayabilir."},"286":{"q":"Bölünmüş bir otoyolda yüklü bir çekici-römork kombinasyonu kullanırken şerit daralarak bir çalışma alanına giriyor. Turuncu işaretler hız sınırını otoyol hızının çok altına düşürüyor, ileride bir işaretçi (bayrakçı) duruyor ve işçiler açık şeridin yakınında hareket ediyor. Çevrenizdeki trafik hâlâ otoyol hızına yakın ilerliyor. En güvenli ve yasal olarak doğru tepki hangisidir?","options":["Hızınızı çalışma alanı için belirtilen sınıra düşürün ve işçilere, ekipmana ve işaretçinin işaretlerine karşı tetikte olun","Önünüzde zaten 7 saniyelik boşluk bıraktığınız için takip mesafenizi ve otoyol hızınızı koruyun","Araçlar arasında tehlikeli bir hız farkı oluşturmamak için çevredeki trafiğin temposuna ayak uydurun","Daha hızlı şeride geçip yavaşlayan araçları geçerek çalışma alanını mümkün olduğunca çabuk geride bırakın"],"explanation":"Çalışma bölgesinde belirlenen hız sınırına yavaşlayın ve işçilere, ekipmanlara ve trafiği yöneten işaretçiye karşı tetikte olun."},"287":{"q":"Nemli iki şeritli bir karayolunda virajdan çıkarken hızınızı yeniden kazanmak için gaza basıyorsunuz. Devir göstergesi aniden yükseliyor ve çekiş tekerlekleri yol tutuşunu kaybedip patinaj yaparken çekicinin arkasının savrulmaya başladığını hissediyorsunuz. Kontrolü yeniden kazanmak için EN İYİ şansı hangi hareket verir?","options":["Patinaj yapan çekiş tekerleklerini yavaşlatmak ve virajdaki çizginizi daraltmak için frene sert basın","Çekiş tekerleklerinin yavaşlamasına izin vermek için gazdan ayağınızı çekin ve aracı gitmesini istediğiniz yöne doğru yönlendirin","Savrulmayı en hızlı şekilde dengelemek için direksiyonu virajın tersi yönüne keskince kırın","Çekişli tekerleklerin sizi savrulmadan düz şekilde çekip çıkarması için gaza sabit basınç uygulamaya devam edin"],"explanation":"Çekiş tekerleği kaymasından kurtulmak için gaza basmayı bırakın ki tekerlekler tutuş kazansın ve kamyonu gitmesini istediğiniz yöne doğru direksiyonla yönlendirin."},"288":{"q":"Kırsal iki şeritli bir karayolunda, ağırlık merkezi yüksek olan kısmi bir yük taşıyorsunuz. Bir tepeden çıkarken, önünüzdeki virajın işaretin uyardığından daha keskin olduğunu fark ediyorsunuz ve viraja rahat olduğundan daha fazla hızla girdiniz. Hangi eylem, kayma veya devrilme olmadan şeridinizde kalmanız için EN İYİ şansı verir?","options":["Fazla hızı çabucak atmak için virajın tepe noktasında sert ve güçlü fren yapın","Daha yüksek bir vitese geçin ve kamyon devrilmeden önce onu dönüşten geçirmek için hızlanın","Virajdan ÖNCE yavaşlamanız gerektiğini kabul edin, bu yüzden gazdan ayağınızı çekin ve dönüş boyunca kamyonu sabit tutarak yalnızca hafif, kademeli fren uygulayın","Debriyaja basın ve çekiş tekerlekleri tutuş kaybetmesin diye virajı boşta savrularak geçin"],"explanation":"Virajın içindeyken gazı bırakın ve yalnızca hafif, kademeli fren kullanın, çünkü sert fren ağırlığı kaydırır ve tutuşu kaybettirebilir."},"290":{"q":"Kuru bir eyaletler arası otoyolda 60 mil/saat hızla yüklü bir çekici-römork sürüyorsunuz ve önünüze araç giremesin diye bir kapalı kasa kamyonun hemen arkasında yakın takip ediyorsunuz. Kamyonun fren lambaları yanıyor ve tıkanan trafik nedeniyle sert şekilde duruyor; siz ani fren yapıp yalnızca birkaç santim payla duruyorsunuz. Bu kıl payı atlatmayı sonradan değerlendirirken, güvenle durmak için gerçekten ihtiyaç duyduğunuz zamanı ve mesafeyi hangi davranış size sağlardı?","options":["4 saniye takip mesafesi bırakmak, çünkü bu 55 mil/saatte toplam durma mesafesidir (yaklaşık 419 fit)","Tam olarak aynı yerde kalıp, fren lambaları yandığı anda yarım saniye daha erken fren yapmak","Hiçbir aracın araya girip sizi fren yapmaya zorlamaması için araları büsbütün daha da kapatmak","Güvenli bir takip mesafesi koruyacak kadar geride kalmak, böylece tehlikeyi fark etme, tepki verme ve kamyona yetişmeden fren yapma zamanına sahip olmak"],"explanation":"Güvenli takip mesafesi koruyun, çünkü toplam durma mesafesi algılama, tepki ve frenleme mesafesinin toplamıdır ve yüzlerce fit eder."},"291":{"q":"Hava kararalı çok oldu ve daha önce hiç sürmediğiniz, dar ve iki şeritli bir kırsal yola döndünüz. Sokak lambası yok, banketler işaretsiz ve farlarınızın ötesini pek göremiyorsunuz. Bu kesimi en güvenli şekilde geçmek için ne yapmalısınız?","options":["Her zaman farlarınızın aydınlattığı mesafe içinde durabileceğiniz şekilde hızınızı azaltın ve karşıdan trafik olmayan yerlerde uzun farları kullanın","Trafik akışından daha yavaş gitmemek için önünüzdeki birkaç aracın hızına ayak uydurun","Uzun farları açın ve yolu olabildiğince uzağa görebilmek için sürekli açık tutun","Geceleri hız düşürmek sizi daha hızlı trafiğe karşı tehlikeli kıldığından, normal gündüz seyir hızınızı koruyun"],"explanation":"Asla farlarınızın görüş mesafesinden hızlı gitmeyin; aydınlanan mesafe içinde durabilecek kadar yavaş gidin ve karşıdan trafik yokken uzun far kullanın."},"293":{"q":"Çekici-römork aracınızı, hafif trafikte yaklaşık 25 mil/saat hızla şehir merkezindeki iş bölgesinden geçiriyorsunuz. İşaretsiz bir ada ortası bölgeye yaklaşırken, kaldırımda duran bir yaya aniden önünüzde birkaç araç boyu mesafede yola adım atıyor; telefona bakıyor ve size doğru bakmıyor. Sağ şeridiniz park etmiş araçlarla kapalı ve solunuzda karşıdan gelen trafik var. En güvenli ve hukuken doğru tepki hangisidir?","options":["Kornaya sert basın ve hızınızı koruyun, çünkü kendi şeridinizde geçiş üstünlüğü sizdedir ve yaya büyük olasılıkla geri çekilecektir","Gazdan ayağınızı çekin, ayağınızı frene yaklaştırın, yavaşlayın ve yaya için durmaya hazır olun","Yayanın etrafından dolaşmak için hafifçe karşı şeride yönelin, sonra geçince kendi şeridinize dönün","Yaya tamamen yolunuza girmeden önce bölgeyi geçmek için kısa süreliğine hızlanın"],"explanation":"Yola adım atmış bir yaya için gazı bırakın, ayağınızı frene yakın tutun, yavaşlayın ve durmaya hazır olun."},"294":{"q":"Yüklü bir kombinasyon aracı dört şeritli bir otoyolda kullanıyorsunuz ve yaklaşık iki mil ileride bir çıkışa hazırlanmak için bir şerit sola geçmeniz gerekiyor. Sinyal veriyor, sol aynalarınızı kontrol ediyor ve kaymaya başlıyorsunuz, ancak bunu yaparken bir binek otomobilin aynalarınızın tam olarak göremediği bölgede çekicinizin yanında ilerlediğini fark ediyorsunuz. En iyi ve en güvenli tepki hangisidir?","options":["Frene basarak şeride kaymaya devam edin, çünkü fren lambalarınız otomobili uyarıp geride kalmasını ve size boşluk açmasını sağlayacaktır","Çekicinizi otomobilin önüne geçirmek için kararlı bir şekilde hızlanın, böylece otomobil römorkunuzun arkasında kalsın, ve bir sonraki ayna kontrolünden önce şerit değiştirmeyi tamamlayın","Şerit değiştirmeyi iptal edin, konumunuzu koruyun, boş bir aralık bekleyin ve tekrar geçmeyi denemeden önce aynayı ve o kör noktayı yeniden kontrol edin","Şerit değiştirmeye devam edin, çünkü zaten erkenden sinyal verdiniz ve ayna kontrolünüzü tamamladınız; yanınızda ilerleyen bir sürücü, sinyal veren bir kamyona yol vermekle yükümlüdür"],"explanation":"Kör noktanızdaki bir araç şeridin boş olmadığı anlamına gelir; bu yüzden şerit değiştirmeyi iptal edin ve geçmeden önce aynayı ve kör noktayı yeniden kontrol edin."},"296":{"q":"Yoğun trafikli dört şeritli bir otoyolun sağ şeridinde, saatte 55 mil hızla yüklü bir çekici-römork kullanıyorsunuz. Önünüzde, kendi şeridinizde yavaş ilerleyen bir bakım kamyonu beliriyor ve hızınızı korumak için sol şeride geçmeniz gerektiğine karar veriyorsunuz. Her iki tarafta da trafik yoğun. Bu şerit değişimini tamamlamanın en güvenli ve doğru yolu hangi sıralamadır?","options":["Hızlanarak bir boşluk yaratıp, kimse doldurmadan önce sol şeride dalmak","Önce sert fren yaparak arkanızda yer açmak, ardından yavaşladıktan sonra sol şeride geçmek","Sol aynanıza bir kez bakıp yumuşakça kaymak, çünkü yoğun yolda sinyal vermek diğer sürücüleri yalnızca şaşırtır","Sol sinyalinizi erkenden yakmak, aynalarınızı ve sol kör noktanızı ('No-Zone') kontrol etmek ve yalnızca şeridin boş olduğunu doğruladıktan sonra geçmek"],"explanation":"Erken sinyal verin, aynalarınızı ve sol kör noktayı (No-Zone) kontrol edin ve ancak şeridin boş olduğunu doğruladıktan sonra geçin."},"297":{"q":"Sefer öncesi kontrolünüz sırasında, önceki sürücünün hasarlı tek bir lastiği değiştirdiğini fark ediyorsunuz. Yeni lastik radyal, ancak aynı aksta yanındaki diğer lastik çapraz katlı (bias-ply). Aksların diğer iki konumu birbiriyle uyumlu. Bu kamyonun yasal ve güvenli şekilde sürülebilmesi için düzeltmeniz gereken durum hangisidir?","options":["Aynı aksta radyal bir lastiğin çapraz katlı (bias-ply) bir lastiğin yanına takılı olması","Direksiyon aksındaki bir lastiğin 4/32 inç diş derinliği göstermesi","Arka (direksiyon dışı) bir lastiğin 2/32 inç diş derinliği göstermesi","Aynı markadan ancak farklı satın alma tarihlerine sahip iki lastiğin tek bir aksta bulunması"],"explanation":"Radyal ve çapraz katlı lastikler aynı aksta asla birlikte kullanılmamalıdır, çünkü farklı yapıları düzensiz ve öngörülemez tutuş ve yol tutuşuna neden olur."},"298":{"q":"Sefer öncesi muayenede, çeker aks lastiklerinizden birinde sırtın lastik gövdesinden ayrıldığı bir bölge ve altındaki kordu açığa çıkaracak kadar derin uzun bir yarık fark ediyorsunuz. Lastik hâlâ havayı tutuyor ve diğer yerlerdeki diş derinliği 2/32 inçin epey üzerinde ölçülüyor. Bu lastik için doğru karar nedir?","options":["Sürmek yasaldır çünkü kalan diş derinliği, direksiyon dışı bir lastik için 2/32 inç asgari sınırının hâlâ üzerindedir","Lastik hizmet dışıdır ve diş derinliği veya hava basıncı ne olursa olsun, araç sürülmeden önce değiştirilmelidir","Hızınızı düşük tutup ilk durakta tekrar kontrol etmeniz koşuluyla kısa bir yerel sefer için kabul edilebilir","Lastik direksiyon aksında değil çeker aksta olduğu için bu yalnızca küçük bir kusurdur"],"explanation":"Sırt ayrılması veya katları açığa çıkaran derin bir kesik, lastiği servis dışı bırakır; bu yüzden diş derinliği veya hava basıncı ne olursa olsun lastik sürüşten önce değiştirilmelidir."},"299":{"q":"Sefer öncesi kontrolünüzde, kaplama (sırt geçirilmiş) yüzeyli bir lastik ve yan duvarında yeniden oluk açılmış işaretleri olan başka bir lastik buluyorsunuz. Teslimat süreniz dar ve bu lastikleri değiştirmek yerine aracınızın bir yerinde kullanımda tutmak istiyorsunuz. Yeniden oluk açılmış veya kaplama bir lastik takmanın YASAK olacağı ve bunun yerine düzgün yeni bir lastik takmaya zorlanacağınız tek tekerlek konumu hangisidir?","options":["Arka römork dingilinde, çünkü römork lastikleri en ağır yükü taşır ve en hızlı aşınır","İç ikiz konumunda, çünkü oradaki gizli bir kaplama kontrol edilmesi en zor olanıdır","Ön (direksiyon) dingili konumunda, burada yeniden oluk açılmış veya kaplama lastiğe izin verilmez","Yedek tekerlekte, çünkü kaplama bir lastik asla yedek olarak taşınamaz"],"explanation":"Yeniden oluklanmış veya kaplama lastikler ön direksiyon aksında yasaktır, çünkü buradaki bir direksiyon lastiği arızası anında direksiyon kontrolünün kaybına yol açar."},"300":{"q":"Sefer öncesi kontrolünüz sırasında, römorkunuzun arka aksındaki çift lastikleri incelemek için çömeliyorsunuz. Her iki lastik de aynı ebatta ve markada görünüyor, diş derinlikleri de iyi. Aralarındaki boşluğa yakından bakarken, bu çift lastik takımını yasa dışı ve sürüş için güvensiz hale getirecek durumun hangisi olduğuna karar vermelisiniz. Aşağıdakilerden hangisi izin vermemeniz gereken kusurdur?","options":["İki lastik tam olarak aynı ebatta ve eşleşen diş desenlerine sahip","Her iki lastik de sıkıca şişirilmiş ve yaklaşık olarak aynı hava basıncını tutuyor","Her lastik arka aksta 2/32 inç minimum dişin epey üzerinde diş gösteriyor","İki lastik içe doğru şişerek birbirine temas ediyor"],"explanation":"İkiz lastikler birbirine veya aracın herhangi bir parçasına asla değmemelidir, çünkü temas düşük basınç veya hatalı montaj demektir ve sürtünme ısısı patlamaya yol açabilir."},"301":{"q":"Soğuk bir sabah araç öncesi kontrolünüz sırasında, çeker dingilindeki tekerlek jantlarından birinde görünür bir çatlak buluyorsunuz. Lastik havasını tutuyor, diş derinliği iyi ve teslimat için zaten geç kaldınız. Hangi eylem doğrudur?","options":["Aracı hizmet dışı bırakın ve çatlak jant onarılana veya değiştirilene kadar sürmeyin","Lastik hâlâ havasını tuttuğu ve diş derinliği iyi olduğu için teslimata dikkatlice sürün","Jant üzerindeki gerilimi azaltmak için lastiğin havasını birkaç psi indirin, sonra düşük hızda devam edin","Bu sadece küçük bir kozmetik çatlak, bu yüzden normal aşınma olarak kaydedin ve ilk 50 millik yük durağınızda tekrar kontrol edin"],"explanation":"Çatlak veya kırık bir jant otomatik olarak servis dışı bırakan bir durumdur, çünkü yük altında kırılıp lastiği yüksek hızda janttan ayırabilir."},"302":{"q":"Sefer öncesi kontrolünüz sırasında römorkun altına giriyorsunuz ve arka süspansiyonun yaprak yayında bir yaprağın çatlayıp kırıldığını, ikinci bir yaprağın ise montaj yuvasından kaydığını görüyorsunuz. Kamyon sahada hâlâ düz duruyor ve kısa test turunda sorunsuz gidiyor. Sefere çıkmadan önce bu bulguyu doğru şekilde nasıl sınıflandırıp ele almalısınız?","options":["Kamyon düz durduğu ve sorunsuz gittiği için çatlak yaprak kozmetiktir; yola çıkıp sefer boyunca takip edebilirsiniz","Bu, araç hizmete alınmadan önce onarılması gereken bir süspansiyon arızasıdır","İlk 50 mil içinde yük bağlantısını tekrar kontrol etmeniz koşuluyla kabul edilebilir","Bu, aslında sürüş konforunu artıran ve hiçbir işlem gerektirmeyen normal bir durumdur"],"explanation":"Çatlak, kırık, gevşek, eksik veya kaymış yaprak yaylar, araç servise girmeden önce onarılması gereken servis dışı bir süspansiyon kusurudur."},"303":{"q":"Sabahın erken saatlerinde, sefer öncesi muayene sırasında çekici-römork aracınızın etrafında dolaşıyorsunuz. Arka süspansiyonda, amortisörlerden birini kaplayan ıslak, yağlı bir tabaka ve toz koruyucuya doğru akan ince bir sıvı izi fark ediyorsunuz. O aks üzerindeki diğer her şey normal görünüyor. Bu parça hakkında doğru sonuç nedir ve ne yapmalısınız?","options":["Yağlı tabaka sadece lastiklerin savurduğu yol kiridir, bu yüzden amortisör olduğu gibi bırakılabilir ve sefere devam edebilirsiniz.","Amortisörler kendi kendini yağlamak için az miktarda yağ sızdıracak şekilde tasarlanmıştır, bu yüzden hafif bir tabaka kabul edilebilir ve yalnızca yoğun, damlayan bir sızıntı kusur sayılır.","Sızdıran bir amortisör bir kusurdur; amortisörler güvenli şekilde sabitlenmiş ve sızıntısız olmalıdır, bu yüzden araç güvenle sürülebilir hale gelmeden önce bu onarılmalıdır.","Amortisörler yük taşımaz ve yalnızca sürüş konforunu etkiler, bu yüzden sızıntı küçük kozmetik bir sorundur ve bir sonraki 150 millik yük kontrolünde not edip giderebilirsiniz."],"explanation":"Amortisörler sağlam şekilde monte edilmiş ve sızdırmaz olmalıdır; bu yüzden sızdıran bir amortisör, araç güvenle sürülmeden önce onarılması gereken bildirilmesi gereken bir kusurdur."},"304":{"q":"Sefer öncesi kontrol sırasında çekicinin altına giriyorsunuz ve yaprak yay askısının yakınında şasi kirişinde uzanan taze bir çatlak ile gevşemiş olduğu açıkça görülen bir motor takozu buluyorsunuz. Düz şehir caddelerinde kısa, 40 millik yerel bir teslimat için zaten geç kalmış durumdasınız. Hangi davranış doğrudur?","options":["Sadece düz caddelerde kısa ve düşük hızlı bir yolculuk olduğu için aracı teslimata kadar sürebilir ve çatlağı sonradan bildirebilirsiniz","Çatlak bölgeyi ağır hizmet bandıyla sıkıca sarın ve elinizle sıkabildiğinizi sıkın ki gün sonuna kadar dayansın","Düşük hızda sürün ve şasiyi ile takozları ilk 50 mil içinde yeniden kontrol edin, çünkü yük emniyeti o zaman kontrol edilmelidir","Aracı hizmet dışı bırakın ve sürmeden önce çatlak şasiyi ve gevşek takozları tamir ettirin"],"explanation":"Çatlak bir şasi veya gevşek bir bağlantı yapısal, servis dışı bir kusurdur, çünkü şasi tüm yük yollarını taşır ve bir çatlak ilerleyip feci şekilde kırılabilir."},"305":{"q":"Sabahın erken saatlerinde, sıcaklık donma noktasının hemen altındayken sefere çıktınız, bu yüzden kabin camlarını kapalı ve kaloriferi açık tutuyorsunuz. Sefer öncesi kontrolünüzde egzoz borusunun susturucuyla birleştiği yerde küçük bir kaçak fark ettiniz, ancak motor sorunsuz çalıştığı için yola çıkmaya karar verdiniz. Bir saat sonra kendinizi uykulu ve hafif baş ağrılı hissediyorsunuz. Bu egzoz kaçağının hangi sonucu, yola çıkmadan önce onarmanız için EN ciddi nedendir?","options":["Karbonmonoksit dahil egzoz gazları kapalı kabine sızarak sizi zehirleyebilir","Kaçak kabine soğuk dış hava sokar ve kaloriferi aşırı çalıştırır","Kaçan egzoz motor gücünü düşürür ve yokuşta yakıt israf eder","Kaçak motorun daha gürültülü çalışmasına neden olur ve diğer uyarı seslerini örtebilir"],"explanation":"Sızdıran bir egzoz sistemi tehlikelidir, çünkü karbonmonoksit dahil egzoz gazları kapalı kabine sızıp sürücüyü zehirleyebilir."},"306":{"q":"Sefer öncesi muayene sırasında akü kutusunu açtığınızda akünün hafifçe oynadığını ve altındaki tepside küçük bir sıvı birikintisi olduğunu görüyorsunuz. Kablolar bağlı ve kamyon sorunsuz çalışıyor. Texas DPS muayene standartlarına göre, bu aracı yasal olarak yola çıkarmadan önce akü hangi koşulu sağlamalıdır?","options":["Motoru çalıştıracak kadar şarjlı olması yeterlidir, çünkü marş gücü akünün yola elverişli olduğunu kanıtlar","Hareket edemeyecek şekilde bir sabitleme kelepçesiyle sıkıca yerine tutturulmuş olmalı ve sızıntı yapmamalıdır","Sıvı seviyesi plakaların üzerinde kaldığı sürece hafif elektrolit sızıntısı kabul edilebilir","Gevşek bir akü kısa yolculuklarda sorun değildir, çünkü kablolar tek başına onun oynamasını önler"],"explanation":"Akü, hareket edemeyecek şekilde bir tutucuyla sıkıca sabitlenmeli ve sızıntı olmamalıdır, çünkü kayan veya sızdıran bir akü kısa devre yapabilir, çatlayabilir veya aşındırıcı asit dökebilir."},"307":{"q":"Uzun bir seferin sonunda bir yakıt adasına giriyorsunuz. Römorkun soğutucu (reefer) ünitesi hâlâ çalışıyor, telefonunuzun şarjı %8 olduğu için hızlıca bir arama yapmak istiyorsunuz ve yakınlarda bekleyen yardımcı sürücü pompalardan yaklaşık 6 metre uzakta bir sigara yaktı. Depoya dizel doldurmaya başlamadan önce, aşağıdakilerden hangisi yapılacak doğru harekettir?","options":["Hava sistemi ve soğutucu ünite basınç ve soğuk kalsın diye motoru rölantide çalışır bırakmak, ama yakıt tabancasını sabit tutup yavaş doldurmak","Kamyonu çalışır durumda bırakıp depo dolarken telefon görüşmesi için uzaklaşmak, çünkü otomatik kapatma tabancası akışı durduracaktır","Motoru kapatmak, sigara içmemek ve yakıt noktasının yakınında sigara içilmesine izin vermemek, ve yakıt doldururken tabancanın başında kalmak","Sigara 4,5 metreden uzakta olduğu için kalmasına izin vermek ve doldurmadan önce hatları temizlemek için motoru kısaca gazlamak"],"explanation":"Dizel buharları kolayca tutuşur; bu yüzden motor kapatılmalı, yakıt noktasında sigara içilmemeli ve doldurma boyunca biri tabancanın başında durmalıdır."},"309":{"q":"Kış sabahı hava donma noktasının hemen altında ve uzun bir sefer öncesi araç öncesi kontrolünüzü yapıyorsunuz. Motor bölmesini kontrol ederken, soğukta yola çıktığınızda aracınızın aşırı ısınmamasını veya donmamasını sağlamak istiyorsunuz. Hangi kontrol, karşılaştığınız kış koşullarına karşı soğutma sistemini doğrudan korur?","options":["Camdaki yol çamurunu temizleyebilmek için cam yıkama deposunun dolu olduğunu doğrulayın","Soğutma sıvısı seviyesi gözetleme camında dolu görünsün diye radyatöre düz su ekleyin","Soğuk havada yağ koyulaşıp daha hızlı yanacağı için fazladan motor yağı ekleyin","Soğutma sıvısında düşük sıcaklıklarda donmasını önleyecek kadar antifriz olduğunu doğrulayın"],"explanation":"Antifriz, soğutma sıvısının donma noktasını düşürür; bu yüzden soğuk havada sıvının donup motoru çatlatmasını önleyecek kadar antifriz olduğundan emin olmalısınız."},"310":{"q":"Bir dağ geçidinde sıcaklık donma noktasının hemen altında, kar yağıyor ve bir levha bu noktadan sonra zincir takılmasının zorunlu olduğunu bildiriyor. Durup çekiş lastiklerinize zincir takıyorsunuz. Zincirlerin yokuş yukarı güvenle ilerlemenize yardımcı olmasının BAŞLICA nedeni nedir?","options":["Kar ve buza tutunarak çekiş lastiklerinize kaygan yüzeyi kavramak için gereken tutuşu sağlarlar","Yuvarlanma direncini azaltarak uzun tırmanışta yakıt tüketiminizi düşürürler","Karla kaplı yolda çekiş aksı üzerinde yasal olarak daha fazla yük taşımanıza izin verirler","Sürüşü yumuşatır ve sıkışmış kar üzerinde kamyonun daha sessiz çalışmasını sağlarlar"],"explanation":"Lastik zincirleri kar ve buza saplanarak çeker lastiklerin kaygan yüzeyde tutunmasını ve patinaj yapmadan güç aktarmasını sağlar."},"311":{"q":"Gece bölünmüş bir otoyolda yüklü bir çekici-dorse aracı sürüyorsunuz ve önünüzdeki otomobilin garip davrandığını fark ediyorsunuz. Hangi gözlem, önünüzdeki sürücünün sarhoş veya etki altında olabileceğine dair EN GÜÇLÜ işarettir ve takip mesafenizi artırıp onun iyice öne geçmesine izin vermeniz gerektiğini gösterir?","options":["Otomobil sabit bir hız tutuyor ve hafif bir virajda şeridinin ortasında kalıyor","Otomobil şerit çizgileri arasında bir o yana bir bu yana savruluyor ve belirgin bir neden olmadan sürekli hızlanıp yavaşlıyor","Otomobil şerit değiştirmeden önce erkenden sinyal veriyor ve uygun bir boşluk oluşmasını bekliyor","Otomobil yavaşça yavaşlayıp dörtlü flaşörlerini yakarak sağ banket şeridine geçiyor"],"explanation":"Şerit çizgileri arasında savrulmayla birlikte düzensiz, açıklanamayan hızlanıp yavaşlama, sürücünün uyuşmuş olduğunun klasik belirtileridir; bu yüzden ona geniş alan bırakın."},"313":{"q":"Yüklü bir çekici-römork ile kırsal bir karayolunda ilerlerken gaz pedalınız aniden yere yapışıyor ve ayağınızı çekmenize rağmen motor devir yapmaya devam ediyor. Trafik az ve ileride asfalt bir banket var. Aracın kontrolünü yeniden sağlamak için İLK öncelikli eyleminiz hangisidir?","options":["Motor freninizi kaybetmemek için viteste kalarak, pedalı kurtarmaya çalışmak amacıyla ayağınızla gaz pedalına hızla basıp çekmek","Tahrik tekerleklerinin kamyonu öne çekmeyi durdurması için hâlâ vitesteyken kontak anahtarıyla motoru derhal kapatmak","Motoru tahrik tekerleklerinden ayırmak için vitesi boşa almak, ardından aracı güvenle yavaşlatıp durdurmak için frenlere basmak","Viteste kalmak ve bankete ulaşana kadar motoru bastırmak için yalnızca düzenli, hafif fren basıncına güvenmek"],"explanation":"Vites boşa alındığında motor çeker tekerleklerden ayrılır; böylece gaz pedalı takıldığında frenler aracı yavaşlatıp durdurabilir."},"314":{"q":"Bir yanık kokusu alıyorsunuz ve güvenli bir şekilde kenara çekiyorsunuz. Kabini açtığınızda, gösterge panelinin arkasından kablo tesisatının yakınından alevler çıktığını görüyorsunuz ve akü ile alternatör devreleri etkilenmiş gibi görünüyor. Kabinde monteli bir yangın söndürücünüz var. Bu yangını kontrol altına almak için EN İYİ ve en güvenli şansı hangi eylem verir?","options":["Kabloları görebilmek için gücü açık bırakın, ardından alevleri soğutmak için tabanına düzenli bir su akıntısı tutun","Bir şey yapmadan önce ısının ve dumanın çıkması için motor kaputunu ve arka kapıları sonuna kadar açın","Alternatör şarj etmeye devam etsin diye motoru çalışır halde tutun ve alevleri kabindeki nemli bir bezle bastırın","Mümkünse elektrik gücünü kapatın (aküyü ayırın / kontağı kapatın), ardından B:C sınıfı yangın söndürücü ile söndürün"],"explanation":"Elektrik yangınında, güvenliyse önce gücü keserek tutuşma kaynağını ortadan kaldırın, ardından suyla değil B:C sınıfı söndürücüyle söndürün."},"315":{"q":"Bir tepenin zirvesini geçtikten hemen sonra motorunuz güç kaybeder ve iki şeritli kırsal bir karayolunun sağ şeridinde rölantiyle durursunuz. Dörtlü flaşörleri açıp acil durum üçgenlerinizi alırsınız. Yardımcı sürücünüz, trafik az olduğu için acele etmeye gerek olmadığını söyler. Yolda durma kurallarına göre, uyarı cihazlarınızı yerleştirmeden önce bekleyebileceğiniz EN UZUN süre nedir?","options":["Durduktan sonra 10 dakika içinde","Flaşörler açık kaldığı sürece durduktan sonra 1 saat içinde","Durduktan sonra 1 dakika içinde","Sürüş gününüzün sonuna kadar, çünkü flaşörler zaten trafiği uyarıyor"],"explanation":"Yolda veya banketta durduktan sonra dörtlü flaşörleri hemen yakın ve üç adet yansıtıcı uyarı üçgenini 10 dakika içinde yerleştirin."},"316":{"q":"Aracınız kırsal iki şeritli bir yolda makaslama yaptı ve sıyırdığınız arabanın sürücüsü direksiyona yığılmış durumda - bilinci yerinde ama boyun ağrısından şikayet ediyor. Trafik az, hava açık ve soğutucu sıvısı kokusu alıyorsunuz ama duman ya da alev görünmüyor. Teksas DPS yönergelerine göre bu yaralı kişiyi araçtan ne zaman çıkarmalısınız?","options":["Hemen, çünkü boyun ağrısı omurga yaralanması demektir ve onu yere düz yatırmanız gerekir","Yalnızca yangın gibi gerçek bir tehlike ortaya çıkarsa; aksi halde onu olduğu yerde bırakın ve eğitimli yardımı bekleyin","Üç reflektörlü üçgeni 10, 100 ve 200 fitlik mesafelere yerleştirir yerleştirmez","Trafik birikmeye başladığında, şeridi açıp diğer sürücülerin güvenliğini sağlamak için"],"explanation":"Yangın gibi gerçek bir tehlike olmadıkça yaralı kişiyi hareket ettirmeyin; çünkü boyun veya omurga yaralanması olan birini taşımak kalıcı felce yol açabilir."},"317":{"q":"Saat sabahın 5:30'u ve bir teslimat son tarihiniz var. Dün gece birkaç bira içtiniz ve yaklaşık dört saat önce içmeyi bıraktınız. Sürüşe hazır hissetmek için iki büyük sade kahve içiyor, soğuk sabah havasında tempolu bir yürüyüş yapıyor ve kabin termometresini kontrol ediyorsunuz. Bunlardan hangisi kanınızda hâlâ bulunan alkolü gerçekten azaltarak ticari aracınızı (CMV) güvenli ve yasal şekilde kullanmanızı sağlar?","options":["Soğuk sabah havası, çünkü temiz havayı derin solumak vücudun alkolü daha hızlı atmasına yardımcı olur","İki büyük sade kahve, çünkü kafein metabolizmanızı hızlandırır ve kalan alkolü yakar","Bunların hiçbiri; yalnızca yeterince zaman geçmesi alkolü kanınızdan uzaklaştırır ve BAC değerinizi yüzde 0,04 sınırının altına indirir","Üçü birlikte, çünkü kahve, soğuk hava ve uyanık olmak bir araya gelerek vardiyanızdan önce sizi ayıltır"],"explanation":"Yalnızca zaman, karaciğerin alkolü metabolize edip kandaki alkol oranını düşürmesini sağlar; kahve, temiz hava veya kendini zinde hissetmek bu süreci hızlandıramaz."},"318":{"q":"Uzun bir seferin 9. saatindesiniz ve uyku basmaya başladı. Mola yerinde başka bir sürücü size kafein hapları ve uyarıcılar (\"uppers\") teklif ediyor ve bunların sizi seferi güvenle bitirecek kadar zinde tutacağını söylüyor. Reddedip bunun yerine dinlenmek için durmanın EN İYİ nedeni aşağıdakilerden hangisidir?","options":["Etkilerini dengelemek için yanında kahve içip temiz hava aldığınız sürece uyarıcılar sakıncasızdır","Uyarıcılar tepki sürenizi keskinleştirir ve gece görüşünüzü iyileştirir, ancak kabinde taşınması yasaktır","Uyarıcılar yalnızca ekstra dikkat gereken 419 fitten uzun inişlerde kabul edilebilir","Uyarıcılar sizi güvenli bir sürücü yapmaz; etkileri geçtiğinde öncesinden daha yorgun ve tehlikeli hale gelebilirsiniz"],"explanation":"Uyarıcılar yorgunluğu yalnızca geçici olarak gizler ve sizi güvenli yapmaz; etkileri geçtiğinde öncekinden daha yorgun ve tehlikeli hale gelebilirsiniz."},"319":{"q":"Dört şeritli bir otoyolun sağ şeridinde 55 mil/saat hızla gidiyorsunuz. Yaklaşık çeyrek mil ileride, sağ banket üzerine çekilmiş, dörtlü flaşörleri yanan arızalı bir araba ve bagajın yanında duran bir kişi görüyorsunuz. Bunu neden bir tehlike olarak değerlendirip daha yakına gelmeyi beklemeden şimdiden ayarlama yapmaya başlamalısınız?","options":["Duran araba ya da yanındaki kişi aniden şeridinize girebilir, bu yüzden yavaşlamalı, takip mesafenizi artırmalı ve güvenliyse sola geçmelisiniz.","Banket, yavaş trafik için yasal seyir alanıdır, bu yüzden arızalı arabaya tüm şeridi bırakmak için banket üzerine geçmeniz gerekir.","Bu, yalnızca sürücü üç yansıtıcı üçgeni 10, 100 ve 200 fitte yerleştirmediyse bir tehlikedir; aksi takdirde hızınızı koruyabilirsiniz.","Banketteki arızalı bir araba, flaşörleri yandığı sürece gerçek bir risk oluşturmaz, bu yüzden hız veya konum değişikliği gerekmez."],"explanation":"Duran bir araç ya da yanındaki kişi aniden şeridinize girebilir; bu yüzden yavaşlayın, takip mesafenizi artırın ve güvenliyse sola geçin."},"320":{"q":"Güzergâhın ortasında bir dinlenme alanına giriyorsunuz ve kabine geri tırmanmadan önce çömelip çekici-römork takımınızın altına hızlı bir göz atıyorsunuz. Hiçbir şeyin sürüklenmediğini doğrulamanın yanı sıra, el kitabının durakta araç altına yapılan bu kısa zemin seviyesi bakışını önermesinin ANA güvenlik nedeni nedir?","options":["Direksiyon lastiklerinde en az 4/32 inç diş kaldığını doğrulamak için lastik diş derinliği ölçerini okumanızı sağlar","Hareket etmeden önce taze sıvı sızıntısını, sönük ya da patlak bir lastiği ve aracın altında veya arkasında olabilecek insanları ya da nesneleri ortaya çıkarabilir","Yükünüzü yolculuğun ilk 50 mili içinde yeniden denetleme ve yeniden sabitleme gereğini karşılar","Hareket etmeden önce üç uyarı üçgeninizi 10, 100 ve 200 fit mesafeye böyle yerleştirirsiniz"],"explanation":"Hareket etmeden önce yerden yapılan kontrol, taze sıvı sızıntılarını, inmiş veya az şişirilmiş lastiği ve aracın altındaki ya da arkasındaki kişi veya nesneleri ortaya çıkarır."},"321":{"q":"Yüklü bir römork çekiyorsunuz ve uzun, dik bir dağ inişinin tepesine ulaşıyorsunuz. Bir levha ileride %6'lık bir eğim olduğu konusunda uyarıyor. İniş sırasında frenlerinizin aşırı ısınıp güç kaybetmesini önlemek için, iniş için kullanacağınız düşük vitesi ne zaman seçmelisiniz?","options":["Frenlerin ısınmaya ve güç kaybetmeye başladığını ilk hissettiğiniz anda","İnişin ne kadar dik olduğunu değerlendirebileceğiniz, yaklaşık yarısına geldiğinizde","Hâlâ tepedeyken, inişe başlamadan önce","Yalnızca yük kayarsa veya hızınız güvenli seviyenin üzerine çıkarsa"],"explanation":"Uzun ve dik bir yokuşu inmeye başlamadan önce, henüz tepedeyken düşük vitese geçin."},"322":{"q":"Yüklü bir römorkla uzun ve dik bir dağ yokuşundan iniyorsunuz. İnişin yaklaşık yarısında fren kokusu hissediyorsunuz ve pedal tepedekine göre daha yumuşak gelmeye başlıyor. Aşağıdakilerden hangisi inişin geri kalanında hızınızı en güvenli şekilde kontrol etmenizi sağlar?","options":["Hızı sabit tutmak için iniş boyunca fren pedalına sürekli, sert ve sabit basınç uygulamak","Motorun soğuması için boşa almak ve sonra dibe kadar frenleri hafifçe kullanmak","Hava basıncını geri kazanıp sert bir pedal hissi elde etmek için fren pedalına hızlıca pompalamak","Motorun sizi tutmasına yardımcı olması için düşük viteste kalmak ve yalnızca hafif, aralıklı fren uygulamaları yapmak"],"explanation":"Yokuş aşağı asıl hız kontrolü motor ve vites frenidir; bu yüzden düşük viteste kalın ve frenlerin soğuması için yalnızca hafif, aralıklı fren uygulayın."},"323":{"q":"Yüklü bir römorkla uzun ve dik bir dağ yokuşundan aşağı iniyorsunuz. Hızınızı kontrol altında tutmak için, düşük vitese geçmek yerine iniş boyunca servis frenlerine sürekli ve sabit basınç uyguluyorsunuz. Yokuşun dibine yaklaşırken, frenleri bu şekilde kullanmanın EN olası sonucu nedir?","options":["Frenler aşırı ısınıp etkisini yitirir (fren sönmesi) ve tam ihtiyacınız olduğu anda durdurma gücünü kaybedersiniz","Frenler ne kadar uzun basılı tutulursa o kadar sıkı tutar ve size ek kontrol sağlar","Kampanaların üzerinden geçen sürekli hava akımı frenleri serin tutar ve normal çalışmaya devam ederler","Basınç yumuşak ve sabit olduğu için frenler eşit aşınır ve daha uzun ömürlü olur"],"explanation":"Uzun bir yokuş aşağıda sürekli ve sabit frenleme, ısıyı dağıtabileceğinden daha hızlı biriktirir; böylece frenler aşırı ısınıp solar ve durdurma gücünü kaybeder."},"324":{"q":"Tam yüklü bir dorseyle uzun ve dik bir dağ yokuşunu iniyorsunuz. İnişin ortasında hafif bir yanık kokusu alıyorsunuz, fren pedalınız yumuşuyor ve frene basmanıza rağmen kamyon hızlanmaya devam ediyor. İlerideki tabelada \"KAÇIŞ RAMPASI 1 MİL\" yazıyor. Bu rampanın BİRİNCİL amacı nedir ve burada neden ihtiyaç duyabilirsiniz?","options":["İnişe devam etmeden önce 30 dakika boyunca park edip frenlerin soğumasını beklemeniz gereken belirlenmiş bir durak alanıdır.","Fren yeteneğini kaybetmiş, kontrolden çıkmış bir aracı güvenle durdurmak için yapılmıştır; örneğin uzun bir inişte frenlerin aşırı ısınıp etkisini yitirmesi durumunda.","İnen kamyonların yokuşun dibine varmadan önce aks ağırlıklarını doğruladığı bir tartı istasyonu atlama şerididir.","Dik yokuşun geri kalanını güvenle tamamlayamayan büyük boy kamyonlar için bir geri dönüş alanıdır."],"explanation":"Kaçış rampası, uzun bir yokuş aşağıda frenlerin aşırı ısınıp solması gibi nedenlerle fren gücünü kaybetmiş kontrolsüz bir aracı güvenle durdurmak için yapılmıştır."},"327":{"q":"Bariyeri ve sinyali olmayan çok hatlı bir hemzemin geçitte durmuş bekliyorsunuz. Bir yük treni yakın hattan gürültüyle geçiyor ve sonunda solunuza doğru geçidi terk ediyor. Her iki hat boyunca görüş ağaçlarla kısmen kapalı ve tüm hatları, aracınızın tam boyunu ve yaklaşık 15 fit fazlasını tamamen geçecek kadar yerinizin olduğunu görüyorsunuz. Freni bırakıp hatları geçmeye başlamadan önce yapılması EN önemli şey nedir?","options":["Hatları geçerken maksimum çekiş gücüne sahip olmak için en düşük vitese geçmek","İlerlemeden önce geçidin boyalı bariyer kollarının tamamen kalkık olduğunu doğrulamak","İlk trenin gizlemiş olabileceği başka bir tren için ikinci hattı her iki yönde de kontrol etmek","Tren geçtikten sonra tam 15 saniye beklemek, ardından başka kontrol yapmadan ilerlemek"],"explanation":"İkinci bir tren az önce geçen trenin arkasında gizlenmiş olabilir; bu yüzden geçmeden önce her rayda iki yöne de bakın."},"328":{"q":"Teslimat bölgenizde yaklaşık üç haftadır yağmur yağmadı ve yoğun iki şeritli bir yola çıkarken hafif bir yağmur başladı. Zemin zar zor ıslak görünmesine rağmen, hafif fren yaptığınızda römorkun hemen kayganlaştığını hissediyorsunuz. Bu erken hafif yağmur, aynı fırtınada daha sonra gelen şiddetli sağanaktan neden yol tutuşunuz için DAHA tehlikelidir?","options":["İnce su tabakası zemini soğutur, bu da lastiklerin kauçuğunu sertleştirir ve tutuşu azaltır","Hafif yağmur yolu yıkayamaz, bu yüzden daha sonra gelen şiddetli sağanak aslında size daha iyi lastik tutuşu sağlar","Hafif yağmur lastik basıncını artırır ve aşırı şişmiş lastikler daha küçük bir temas yüzeyinde gider","İlk su, kuru yolda birikmiş yağ ve tozla karışır ve daha şiddetli yağmur onu yıkayamadan önce kaygan bir tabaka halinde yüzeye çıkarır"],"explanation":"Kurak bir dönemden sonraki ilk yağmur kaygandır, çünkü az miktardaki su birikmiş yağ ve tozla karışarak, daha şiddetli yağmur yıkayıp temizleyemeden kaygan bir tabaka oluşturur."},"329":{"q":"Suyun tekerlek göbeklerine kadar ulaştığı sular altında kalmış alçak su geçidini yeni geçtiniz. Kuru otoyola tekrar hızlanarak çıkıp çeyrek mil ileride bir kavşağa yaklaşırken, ilk durmanızda yumuşak ve zayıf bir fren pedalı hissediyorsunuz. Hızdayken frenlere güvenmeden önce fren gücünü geri kazanmak için doğru hareket nedir?","options":["Düşük bir hızda giderken frenlere hafif ve nazik basınç uygulayarak sürtünme ısısıyla test edip kurutmak","Bir sonraki durmadan önce suyu kampanalardan çıkarmak için fren pedalına sert ve hızlı şekilde pompalamak","Rüzgarın ve motor ısısının frenleri çabucak kurutması için otoyol hızına çıkmak","Devam etmeden önce frenlerin doğal olarak havayla kurumasını sağlamak için motoru kapatıp rölantide kaymak"],"explanation":"Derin su fren balatalarını ıslattıktan sonra yavaş sürün ve hafif, nazik fren uygulayın; böylece sürtünme ısısı balataları kurutup normal frenlemeyi geri getirir."},"330":{"q":"Sürekli yağmur altında bir eyaletler arası otoyolda saatte 50 milde kısmi yük taşıyorsunuz. Önünüzdeki yol kesintisiz bir su tabakası gibi görünüyor ve lastiklerinizle zemin arasında ince bir su filmi oluştuğunu hissediyorsunuz. Aniden direksiyon ellerinizde farklı hissettiriyor. Lastiklerinizin tutuşunu kaybettiğinin ve su kızağı yapmaya başlıyor olabileceğinizin en açık uyarısı hangi değişiklik olurdu?","options":["Direksiyon aniden size direnir ve ağır, sert ve çevrilmesi zor hissettirir","Direksiyon aniden hafif ve kolay çevrilir hissettirir, sanki gevşemiş gibi","Hızınız sabit olmasına rağmen motorun gözle görülür şekilde sesini yükselttiğini duyarsınız","Kabin havalandırmasından gelen güçlü bir yakıt kokusu fark edersiniz"],"explanation":"Lastikler ıslak yüzeyde tutuşunu kaybedip bir su tabakası üzerinde kayınca, direksiyon aniden hafifler ve kolayca dönmeye başlar."},"331":{"q":"Saat 18:00'de görevden ayrıldınız ve tam 10 saatlik bir mola verdiniz, ardından saat 04:00'te göreve başlayıp aralıksız sürüş yaptınız. Bir sevkiyat görevlisi, 14 saatlik pencerenizde hâlâ saatiniz kaldığını söyleyerek devam etmeniz için sizi sıkıştırıyor. 14 saatlik görev penceresini bir kenara bırakırsak, bu çalışma vardiyasında fiilen ARAÇ KULLANMANIZA izin verilen azami saat sayısı kaçtır?","options":["8 saat sürüş, çünkü 30 dakikalık molanın zorunlu hâle geldiği an budur ve vardiyanız fiilen biter","14 saat sürüş, çünkü direksiyon başında ne kadar kalabileceğinizi gerçekte belirleyen şey 14 saatlik penceredir","11 saat sürüş, çünkü 10 saat kesintisiz görev dışı kaldıktan sonra en fazla 11 saat araç kullanabilirsiniz","16 saat sürüş, yeter ki 14 saatlik görev penceresi içinde kalın"],"explanation":"10 saat aralıksız dinlenmeden sonra en fazla 11 saat araç kullanabilirsiniz; bu, 14 saatlik görev penceresi sınırından ayrıdır."},"332":{"q":"Sabah 06.00'da göreve başladınız. Yükleme ve bekleme sonrası nihayet 09.00'da sürüşe başladınız. Toplamda yalnızca yaklaşık 5 saat sürüş yaptınız ve 30 dakikalık bir mola verdiniz, bu yüzden bugün hâlâ bol yasal sürüş süreniz olduğunu düşünüyorsunuz. Saat 20.00'ye yaklaşırken, bu çalışma vardiyasında sürmeyi ne zaman bırakmanız gerektiğini hangi ifade doğru biçimde açıklar?","options":["Direksiyon başında 6 fiili saat tamamlayana kadar sürmeye devam edebilirsiniz, çünkü sınırı asıl belirleyen şey sürüş süresidir.","10 saatlik görev süresini aşmadığınız sürece sürmeye devam edebilirsiniz, çünkü sizi durduran şey görev süresi sayacıdır.","Saat 20.00'den sonra da sürebilirsiniz, çünkü 30 dakikalık molanız sayacı durdurdu ve son saatinizi akşamın daha geç bir vaktine itti.","Saat 20.00'den sonra hiç süremezsiniz, çünkü bu, göreve başladıktan sonraki 14. saattir; gerçekte ne kadar az sürmüş olduğunuzun hiçbir önemi yoktur."],"explanation":"Göreve başladığınız andan itibaren 14. saatten sonra, gerçekte ne kadar az sürdüğünüz fark etmeksizin araç kullanamazsınız."},"333":{"q":"300 millik bir sefer için açık kasalı (flatbed) bir araç yüklüyorsunuz. Ağırlığı dingiller üzerine dengelediniz, yükü kuru tutmak için brandayla örttünüz ve bağlama elemanlarınız çalışma yük sınırını karşılıyor. Son bir araç turu atarken, otoyola çıkmadan önce yükün neden düzgün şekilde sabitlenmesi gerektiğine dair en önemli tek nedeni kendinize hatırlatıyorsunuz. Bu nedeni en iyi hangi ifade açıklar?","options":["Sabitlenmiş yük; kayması, düşmesi veya yol görüşünüzü engellemesi önlenecek şekilde tutulmalıdır","Sabitlenmiş yük, aracın dışından görülemeyecek şekilde tamamen brandanın altında gizli tutulmalıdır","Sabitlenmiş yük, bir sonraki denetim istasyonunda hızlıca tartılabilecek şekilde düzenlenmelidir","Sabitlenmiş yük, bağlama elemanları yolcu tarafından memurlara görünür olacak şekilde yüklenmelidir"],"explanation":"Yük; kayamayacak, düşemeyecek veya yol görüşünüzü engellemeyecek şekilde sabitlenmelidir."},"334":{"q":"Son dakika bir yük alıyorsunuz ve gönderici, yükü irsaliyenizde gösterilenden daha ağır yüklüyor; bu da sizi azıcık GVWR (azami yüklü araç ağırlığı) sınırınızın üzerine çıkarıyor. Sevkiyatçı \"sadece birazcık fazla\" diyor ve yola çıkmanızı söylüyor. Otoyola çıkarken, bu aşırı yüklemenin hangi etkisi güvenlik açısından sizi EN ÇOK endişelendirmelidir?","options":["Fazladan ağırlık lastikleri yola daha sert bastırarak daha fazla tutuş sağlar ve durma mesafesini kısaltır","Eklenen ağırlık direksiyonunuza ve frenlerinize karşı çalıştığı için aracı yönlendirmek zorlaşır ve durması daha uzun sürer","Eklenen ağırlık ağırlık merkezini düşürür, böylece kamyon daha kararlı hale gelir ve devrilme olasılığı çok daha azalır","Kamyon tam yüklüyken motor daha istikrarlı bir yük altında çalıştığı için yakıt ekonomisi iyileşir"],"explanation":"Aşırı ağırlık aracın direksiyonunu zorlaştırır ve durma mesafesini artırır, çünkü eklenen kütle direksiyona ve frenlere karşı çalışır."},"335":{"q":"Teksas'ta bir yükleme rampasında araç öncesi kontrolünüzü yaparken, iki adet çelik borunun düz platformlu dorsenizin arka kenarından yaklaşık dört fit dışarı taştığını fark ediyorsunuz. Yük bağlama kayışlarıyla düzgün şekilde sabitlenmiş, evraklarınız tamam ve gündüz bir sefere çıkmak üzeresiniz. Yükün arkadan dışarı taşan kısmıyla ilgili olarak, federal ve Teksas mevzuatı hareket etmeden önce ne yapmanızı gerektirir?","options":["Ek bir şey gerekmez, çünkü taşma beş fitten az ve yük zaten doğru sayıda bağlama kayışıyla sabitlenmiş durumda","Taşan kısma bir ek bağlama kayışı ekleyin ve dışarı çıkan uçları, trafiğin dikkatini daha az dağıtması için koyu renge boyayın","Taşan yükü görünür hale getirin -- arkadan dışarı taşan kısma bayrak (ve görüş kötüyse veya geceyse ışık) takın","İlk 50 mil içinde bağlamayı yeniden kontrol edin, ancak yük tamamen bağlı olduğundan taşan kısmı işaretlemeye gerek yoktur"],"explanation":"Aracın arkasından taşan yük görünür olacak şekilde işaretlenmelidir — gündüz bayraklarla, görüş kötüyse veya geceleyin ışıklarla."},"336":{"q":"Bir sevkiyat rampasında, depo ekibi açık kasalı dorseye çelik boruları yükleyip zincirlerle bağlıyor, rampa amiri taşıma irsaliyesini imzalıyor ve yakınlarda bir DOT memuru duruyor. Bağlama gerginlerinden birkaçının gevşek göründüğünü düşünüyorsunuz. Federal ve Teksas kurallarına göre, yola çıkmadan önce bu yükün düzgün sabitlendiğinden ve yasal ağırlık sınırları içinde olduğundan emin olmaktan nihai olarak kim sorumludur?","options":["Yükü fiziksel olarak yükleyip zincirledikleri için nakliyeci ve depo ekibi","İmzası irsaliyede yükü onayladığı için rampa amiri","Bağlama denetimi onun görevi olduğu için yakında duran DOT memuru","Siz, sürücü, çünkü yükü kim yüklerse yüklesin güvenli ve yasal bir yükten siz sorumlusunuz"],"explanation":"Yükü kimin yüklediğine bakılmaksızın, güvenli ve yasal bir yükten sürücü sorumludur."},"337":{"q":"Sahada çelik bobinleri yüklediniz ve az önce otoyola çıktınız. Bağladığınızda yük sağlam görünüyordu, ancak araç hareket edip zincirler oturduğunda bağlama ekipmanlarının ve yükün kayabileceğini biliyorsunuz. Yasalara ve güvenliğe uygun kalmak için yük bağlamasını yeniden kontrol etmek üzere İLK durağınızı ne kadar erken yapmalısınız?","options":["Yolculuğa başladıktan sonraki ilk 50 mil içinde","Yolculuğa başladıktan sonraki ilk 150 mil içinde","Mesafeden bağımsız olarak, sürüşün ilk 3 saati içinde","Yalnızca ilk dinlenme molanızdan veya yakıt durağınızdan sonra"],"explanation":"Yükü ve sabitlemesini, yolculuğa başladıktan sonraki ilk 50 mil içinde kontrol etmelisiniz."},"339":{"q":"Aysız bir gecede, sokak lambası olmayan kırsal iki şeritli bir karayolunda boş bir açık kasa (flatbed) sürüyorsunuz. Kısa farlarınız önünüzdeki yaklaşık 250 fitlik yolu aydınlatıyor, ancak sürekli karşıdan araç geldiği için yasal olarak uzun far kullanamıyorsunuz. Yoldan çıkmamak veya görünmeyen bir tehlikeye çarpmamak için hızınız hangi tek kurala göre belirlenmelidir?","options":["Farlarınız ve fren lambalarınız düzgün çalıştığı sürece belirlenen hız sınırını koruyabilirsiniz","Hızınız, farlarınızın önünüzde aydınlattığı mesafe içinde durabileceğiniz kadar yavaş olmalıdır","Geçmeden önce her trafik işaretini okuyabilecek kadar hızınızı düşük tutmalısınız","Daha hızlı gidebilirsiniz çünkü boş bir römork yüklü olana göre daha kısa durma mesafesi sağlar"],"explanation":"Asla farlarınızın ötesinde hız yapmayın — hızınız, farlarınızın önde aydınlattığı mesafe içinde durabilmenize izin vermelidir."},"340":{"q":"Gece yarısından hemen sonra karanlık, çift şeritli bir karayolunda yüklü bir çekici-dorse kullanıyorsunuz. Karşıdan gelen bir araç uzun farlarını açık tutuyor ve kısmaya yanaşmıyor; göz alıcı ışık görüşünüzü bozuyor. Sürücüyü uyarmak için farlarınızı çoktan yaktınız ama sonuç alamadınız. O araç geçene kadar, şeridinizde kontrolü korumak için gözlerinizle yapılacak EN İYİ şey nedir?","options":["Aracın sizi tam olarak ne zaman geçeceğini kestirebilmek için doğrudan karşıdan gelen farlara bakmak","Parlak ışık doğrudan görüş hattınızdan çıksın diye farların üstündeki gökyüzüne doğru bakmak","Bakışınızı aşağıya ve kendi şeridinizin sağ kenarına kaydırıp araç geçene kadar bu kenarı referans alarak direksiyon kullanmak","Farlar artık önünüzde olmayana kadar gözlerinizi gösterge paneline indirip göstergelere odaklanmak"],"explanation":"Karşıdan gelen uzun farlarla gözünüz kamaştığında, şeridinizin sağ kenarına bakın ve araç geçene kadar yönlendirmek için onu kullanın."},"341":{"q":"Yükünüzün tamamını bir depoya boşalttınız ve şimdi boş çekiciyi (bobtail) tek başına garaja geri sürüyorsunuz. Kırmızı ışığa yaklaşırken, tam yüklüyken yaptığınız gibi fren yapıyorsunuz ve tekerlekler aniden kilitlenip kaymaya başlıyor. Bu boş kamyon neden yüklüyken olduğundan DAHA KÖTÜ fren yapıyor?","options":["Araç ne kadar ağırsa durması o kadar uzun sürer, bu yüzden boş bir kamyon aslında yüklü bir kamyondan daha kolay durmalıdır","Boş kamyonlara, aracı yavaşlatmaya yetecek kuvveti üretemeyen daha küçük ve zayıf frenler takılır","Yük olmadığında, daha yüksek ağırlık merkezi kamyonun öne doğru eğilmesine ve ön frenlerin aşırı yüklenmesine neden olur","Az ağırlık lastikleri yola çok az bastırdığı için lastiklerin yol tutuşu azalır ve kilitlenip kayma olasılıkları artar"],"explanation":"Boş bir kamyonda lastikleri yola bastıran ağırlık az olduğundan, lastikler daha az tutuş sağlar ve daha kolay kilitlenip kayar."},"342":{"q":"Sürekli bir yağmur yağıyor ve zemin açıkça ıslak, ancak henüz birikmiş su veya sulu karla kaplı değil. Çevrenizdeki trafik hâlâ izin verilen 60 mil/saat sınırına yakın bir hızda akıyor. Bu ıslak yüzeyde güvenli bir kontrol payı korumak için, aynı yol kuruyken güvenle gideceğiniz hıza kıyasla hızınızı yaklaşık ne kadar düşürmelisiniz?","options":["Kuru yoldaki güvenli hızınızdan yaklaşık üçte bir daha yavaş","Kuru yoldaki güvenli hızınızdan yaklaşık yarı yarıya daha yavaş","Kuru yoldaki güvenli hızınızdan yaklaşık dörtte üç daha yavaş","Birikmiş su ve sulu kar oluşmadığı sürece hızı düşürmeye gerek yoktur"],"explanation":"Islak yollarda yeterli tutuşu korumak için hızınızı kuru yoldaki güvenli hızınıza göre yaklaşık üçte bir oranında azaltın."},"343":{"q":"Yüklü bir frigorifik aracı kırsal iki şeritli bir karayolunda sürerken sıcaklık düşüyor ve sürekli yağan kar yola yapışarak sert sıkışmış beyaz bir tabaka oluşturuyor. Trafik düzgün akıyor, yol buzlu değil ve görüş hâlâ açık. Bu sıkışmış kar zemininde güvenli bir pay bırakmak için, normal kuru yol hızınızı yaklaşık ne kadar azaltmalısınız?","options":["Hızınızı yaklaşık dörtte bir oranında azaltın","Hızınızı yaklaşık yarı yarıya azaltın","Hızınızı yaklaşık onda bir oranında azaltın","Yol buzlu olmadığı ve görüş iyi olduğu için normal hızınızı koruyun"],"explanation":"Sıkışmış karda tutuş ciddi şekilde azaldığı ve durma mesafesi uzadığı için hızınızı yaklaşık yarıya düşürün."},"344":{"q":"Şafak vakti hava donma noktasının hemen altında ve yüklü bir çekici-dorse aracıyla bir köprüden geçiyorsunuz. Önünüzdeki yol koyu, pürüzsüz ve ıslak görünüyor, ancak önünüzdeki aracın lastiklerinden hiç su sıçramadığını fark ediyorsunuz. Bu tür bir yüzey neden en tehlikeli kış tehlikelerinden biri sayılır?","options":["Parlak ve belirgindir, bu yüzden sürücüler çok sert fren yapar ve açıkça buzlu yolda yol tutuşunu kaybeder","Yalnızca yaz öğleden sonralarının en sıcak saatlerinde, asfaltın altından zift sızdığında oluşur","Zararsız ıslak bir yol gibi görünür ama aslında neredeyse hiç uyarı vermeyen ince, saydam bir buz tabakasıdır","Altındaki yol ziftini eritir ve görmesi ve etrafından dolaşması kolay olan kaygan, yağlı bir tabaka bırakır"],"explanation":"Buz tabakası, yolu yalnızca ıslakmış gibi gösteren ve neredeyse hiç uyarı vermeyen ince, saydam bir buz katmanıdır."},"345":{"q":"Yüklü bir çekici-römork ile kırsal iki şeritli bir karayolunda giderken, ani ve kuvvetli bir yan rüzgâr römorkun yan tarafına çarpıyor ve direksiyon elinizde sarsılıyor. En iyi kontrolü sağlamak ve rüzgâr sizi banketin yönüne iterse karşı yöne direksiyon kırmaya hazır olmak için ellerinizin direksiyon üzerindeki konumu nasıl olmalıdır?","options":["En fazla kaldıraç gücü için bir elinizi direksiyonun en üstünde tutun, diğer elinizi kucağınızda dinlendirin","Her iki yöne de hızlıca tepki verebilmek için iki elinizi direksiyonun üst kısmında birbirine yakın tutun","Bir elinizi direksiyonun alt kısmında tutun, diğer elinizi yalnızca kapıya yaslamak için kullanın","Her iki elinizi de direksiyon üzerinde, birbirinin karşı taraflarında sıkıca tutun"],"explanation":"Direksiyonu her iki elinizle karşılıklı taraflardan sıkıca tutun ki kontrolü koruyup ani tehlikelere karşı yön düzeltmesi yapabilesiniz."},"346":{"q":"Kalabalık bir TIR durağına giriyorsunuz ve çekici-dorsenizi dar bir park yerine geri geri sokmanız gerekiyor. Size yardım edecek bir gözcü yok ve her iki tarafta da diğer araçlar yakın park etmiş durumda. Manevrayı mümkün olduğunca güvenli yapmak için hangi tarafa doğru geri gitmelisiniz?","options":["Sürücü tarafına doğru, böylece dorse boyunca geriye bakabilir ve yolunuzu sürücü camından izleyebilirsiniz","Yolcu tarafına doğru, çünkü dorse o tarafta daha geniş savrulur ve size daha fazla açıklık sağlar","Park alanının eğimi boyunca düz bir çizgide geri gitmenize izin veren hangi tarafsa o tarafa doğru","Kör tarafınıza doğru, sonra göremediğinizi kapatmak için aynalara ve hızlı bir araç çevresi kontrolüne güvenerek"],"explanation":"Sürücü tarafına doğru geri gidin ki römork boyunca doğrudan arkaya bakıp yolunuzu yan camdan görebilesiniz."},"348":{"q":"53 fitlik dorsenizi kör (sağ) taraftan dar bir yükleme rampasına geri geri sokmanız gerekiyor ve yakında bir iş arkadaşınız yardım teklif ederek duruyor. Güvenli geri gitme prosedürlerine göre, bu kişiyi yardımcı olarak kullanmanın tek en önemli nedeni nedir?","options":["Aynaları hiç kullanmak zorunda kalmamanız için size el işaretleri verebilir","Kabinden göremediğiniz, dorsenin arkasındaki ve yanındaki alanları izleyebilir","Beklemeden geri gidebilmeniz için caddedeki karşı yönden gelen trafiği durdurabilir","Açı çok zorlaşırsa kontrolü devralıp dorseyi sizin yerinize geri geri sokabilir"],"explanation":"Bir yardımcı, kabinden göremediğiniz römorkun arkasındaki ve yanındaki kör nokta alanlarını izleyebilir."},"349":{"q":"53 fitlik bir çekici-römork sürüyorsunuz ve dar bir şehir sokağına keskin bir sağ dönüş yapmak üzeresiniz. Çok keskin dönerseniz römorkun içeriden döneceğini ve kaldırıma çıkabileceğini biliyorsunuz. Sağ tarafınızda hemen arkanıza bir otomobil yanaştı. Bu dönüşü güvenli ve kurallara uygun şekilde tamamlamak için ne yapmalısınız?","options":["Römorkun kaldırımı kurtarması için dönüşe başlamadan önce geniş bir şekilde sola kayın","Römorkun çekiciyi daha sıkı takip etmesi için dönüş sırasında biraz hızlanın","Güvenli olduğu ölçüde mümkün olduğunca sağdan dönün, aracınızın arkasını kaldırıma yakın tutarak kimsenin sağınızdan geçmesine izin vermeyin","Önce en sol şeride geçin, ardından römorka maksimum yer vermek için sağ dönüşü oradan yapın"],"explanation":"Güvenli olduğu kadar sağdan dönün ve aracın arkasını bordüre yakın tutun ki kimse sağınızdan geçemesin."},"350":{"q":"53 fitlik bir çekici-römork (tır) kullanıyorsunuz ve yoğun bir dört yönlü kavşakta sola dönüş yapmanız gerekiyor. Işık yeşile döndü ve karşıdan gelen trafik açıldı. Bu sola dönüşü güvenli şekilde tamamlamak ve römorkun arka tekerleklerinin döndüğünüz şeridi kesmesini önlemek için doğru teknik nedir?","options":["Römorkun daha dar bir yol izlemesi için kavşağa girer girmez çekicinin önünü hemen sola kırmaya başlayın","Römorkun arka tekerlekleri geniş dönsün ve kaldırımdan uzak kalsın diye dönüş boyunca en sağdaki şeritte kalın","Römorkun kat etmesi gereken mesafeyi kısaltmak için kavşağın köşesini çaprazlama kesin","Direksiyonu sola çevirmeye başlamadan önce çekicinizi ileri sürün ve kavşağın ortasına ulaşın"],"explanation":"Direksiyonu sola çevirmeden önce kavşağın ortasına kadar ileri gidin ki römorkun arka tekerlekleri köşeyi kesmesin."},"351":{"q":"Sabahın erken saati ve uzun bir sefere başlamak için kabine yeni bindiniz. Yerleşirken sağ aynanın çok yukarı açılı olduğunu ve römorkun yan tarafını göstermediğini fark ediyorsunuz ve düzeltmek istiyorsunuz. Bu ayarı yapmak için doğru zaman ne zamandır?","options":["Şimdi, sefere başlamadan önce, araç güvenli şekilde park halindeyken","Otoyol hızına ulaşınca, ayna römorkun yük altında nasıl gittiğine göre ayarlansın diye","Seferin ilk 50 mili içinde, ilk zorunlu yük kontrolünde","Yalnızca sürüş bittikten ve varış sahasına girdikten sonra"],"explanation":"Aynaları hareket hâlindeyken güvenli ayarlayamayacağınız için, yolculuktan önce araç güvenli şekilde parkhâldeyken ayarlayın."},"353":{"q":"Çok şeritli bir otoyolda daha yavaş bir aracı geçmek için sol şeride geçtiniz. Geçiş tamamlandı ve artık yeni şeritte düzgün şekilde ilerliyorsunuz. Gösterge paneline baktığınızda, sol sinyalinizin hâlâ yanıp söndüğünü fark ediyorsunuz; çünkü bir otomobilin aksine kamyonunuzun sinyali kendiliğinden kapanmadı. İLK olarak ne yapmalısınız?","options":["Geçtiğiniz araçla aranızdaki mesafeyi artırmak için kararlı şekilde hızlanın, sinyali sonra kontrol edin","Çevredeki sürücüler niyetiniz konusunda yanılmasın diye sinyali elle kapatın","Sinyalin kapatılması gerekip gerekmediğine karar vermeden önce aynaları yeniden kontrol etmek için yavaşlayın","Hâlâ manevra yaptığınızı gösterdiği için bir sonraki şerit değişikliğine kadar sinyali açık bırakın"],"explanation":"Çoğu büyük kamyonda sinyal kendiliğinden kapanmaz, bu yüzden diğer sürücüleri yanıltmamak için manevradan sonra sinyali kapatın."},"355":{"q":"Gece, karanlık iki şeritli bir karayolunda uzun farlarınız açıkken çekici-römork aracınızı kullanıyorsunuz. Karşı şeritte size doğru gelen bir aracın farlarını henüz biraz ileride fark ediyorsunuz. Karşıdan gelen sürücüyü kör etmemek için uzun farlarınızı kısa farlara hangi mesafede indirmeniz gerekir?","options":["Karşıdan gelen araca 250 fit kala, çünkü kısa farlarınızın yolu aydınlattığı mesafe budur","Karşıdan gelen araca 200 fit kala, en uzaktaki uyarı üçgeninizi yerleştirdiğiniz mesafeyle aynı","Karşıdan gelen araca 500 fit kala (ayrıca başka bir aracı 500 fit içinde takip ederken de)","Yalnızca karşıdan gelen araç, farlarınızın çok parlak olduğunu belirtmek için kendi farlarını yaktığında"],"explanation":"Karşıdan gelen bir araca 500 fit yaklaşınca ve başka bir aracı 500 fit içinde takip ederken, körleştirici parlamayı önlemek için uzun farları kısa fara çevirin."},"356":{"q":"Kırsal iki şeritli bir karayolunda yüklü bir römork çekerken düşük soğutucu uyarısı sizi motoru durdurmaya zorluyor. Kilometrelerce çıkış yok, ama ileride geniş bir çakıl banket görüyorsunuz. Daha uyarı üçgenlerinize uzanmadan, durağı mümkün olduğunca güvenli hale getirmek için yapmanız gereken İLK şey nedir?","options":["Kendi şeridinizde durup hemen üç üçgeni 10, 100 ve 200 fit mesafelere yerleştirerek trafiği her şeyden önce uyarmak","Bir sonraki virajda yuvarlanarak durup aracınızın her iki yönden görünmesini sağlamak ve farları açmak","Yavaşlayıp şerit çizgisine oturarak kamyonun bir kısmını asfaltta tutmak ve banketi acil araçlar için açık bırakmak","Asfaltı tamamen terk edip çakıl bankete inmek ve dörtlü flaşörlerinizi açmak"],"explanation":"Aracı yoldan tamamen banketin üzerine çekin ve yaklaşan trafiği uyarmak için derhal dörtlü flaşörleri açın."},"357":{"q":"Hafif yokuş aşağı bir eğimde bulunan bir dinlenme alanına girip aracın etrafını hızlıca dolaşmak ve yük bağlamasını kontrol etmek istiyorsunuz. Motor hâlâ çalışıyor ve kabinden yalnızca bir-iki dakika dışarıda kalmayı düşünüyorsunuz. Aşağı inip dışarı çıkmadan önce, aracın kaymasını önlemek için yapılacak en önemli tek işlem hangisidir?","options":["El frenini (park frenini) çekmek.","Vitesi en düşük ileri kademeye takıp öyle bırakmak.","Ön tekerlekleri kaldırıma doğru sertçe kırıp dörtlü flaşörleri yakmak.","Geri dönmeye hazır olana kadar servis (ayak) frenine sıkıca basıp tutmak."],"explanation":"Kabinden ayrılmadan önce her zaman park frenini çekin, çünkü sürücü olmadan park halindeki aracı mekanik olarak tutmak için tasarlanmış tek cihaz odur."},"358":{"q":"Yüklü bir çekici-dorseyi kırsal bir karayolunda 55 mil/saat hızla sürüyorsunuz. Trafik az ve yol düz, bu yüzden gözlerinizi yeterince ileri bir noktaya bilinçli olarak sabitlemeye karar veriyorsunuz; böylece arızalı araçları, yoldaki enkazı veya katılan trafiği zamanında fark edip sert fren yerine yumuşak tepki verebilirsiniz. Bu hızda ZAMAN cinsinden ne kadar ileriye bakmalısınız?","options":["5-8 saniye ileriye; bu, aynalarınızı kontrol etmeniz gereken aralıkla aynıdır","12-15 saniye ileriye; bu, karayolu hızında yaklaşık çeyrek mile denk gelir","Yaklaşık 6 saniye ileriye; bu, 55 mil/saatte toplam durma mesafenizdir","Yalnızca fit cinsinden ölçülen tam bir çeyrek mil, hareket saniyesi cinsinden değil"],"explanation":"Tehlikeleri erken fark edip panik yerine yumuşak tepki verebilmek için 12 ila 15 saniye ileriye, otoyol hızında yaklaşık çeyrek mil mesafeye bakın."},"359":{"q":"Yoğun bir eyaletler arası otoyolda, açık platform (flatbed) dorseyle çelik rulo yükü taşıyorsunuz ve otoyol hızındasınız. Trafik yoğun ve araçlar sürekli çevrenizdeki şeritlere girip çıkıyor. Önünüze kıvrılan bir otomobile ya da dorsenizdeki bir lastik sorununa erkenden tepki verebilmek için aracınızın her yönündeki durumdan haberdar olmak istiyorsunuz. Aynalarınızı kullanmaya yönelik hangi yaklaşım güvenli ticari sürüş uygulamasına en uygundur?","options":["Diğer araçların yanınızda olma olasılığının en yüksek olduğu an olduğu için, her birleşme veya şerit değişiminden sonra aynalarınıza bir kez bakın","Geri kalan zamanda gözlerinizi yoldan ayırmamak için, dorsenin çekmesini hissedene ya da olağandışı bir ses duyana kadar bekleyip öyle kontrol edin","Trafiği ve aracınızın her yöndeki durumunu sürekli izlemek için aynalarınızı düzenli olarak, yaklaşık her 5 ila 8 saniyede bir tarayın","Aynalarınızı yalnızca yolculuğun başında ve sonunda kontrol edin, geri kalan zamanda tamamen 12 ila 15 saniye ileride bulunan yola odaklanın"],"explanation":"Trafiğin, kör noktaların ve aracınız ile yükünüzün durumunun farkında kalmak için aynalarınızı düzenli olarak, yaklaşık her 5 ila 8 saniyede bir kontrol edin."},"360":{"q":"Bölünmüş bir otoyolun sağ şeridinde yüklü bir çekici-römork ile sabit 55 mil/saat hızla giderken, bir otomobil solunuzdan sizi geçmeye başlıyor. Geçişin yarısında araç sol kör noktanızda oyalanıyor ve manevrayı tamamlamakta tereddüt ediyor gibi görünüyor. Geçiş yapan sürücüye en güvenli ve en öngörülebilir durumu sağlamak için hangi eylemi yapmalısınız?","options":["Gaz pedalından ayağınızı çekip hafifçe fren yapın, böylece araç ön tamponunuzu daha çabuk geçsin","Sürücü tarafında daha fazla boşluk açmak için şeridinizin sağ kenarına doğru biraz kayın","Aracın geçişi daha hızlı bitirip kendi şeridine dönmesine yardımcı olmak için kısa süre hızlanın","Şeridinizin ortasındaki konumunuzu koruyun ve araç sizi tamamen geçip önünüze dönene kadar sabit bir hız tutun"],"explanation":"Başka bir araç sizi geçerken şeridinizde kalın ve sabit bir hız tutun ki geçen sürücü mesafeyi öngörülebilir şekilde değerlendirip geçişi güvenle tamamlayabilsin."},"361":{"q":"Asılı bir yükseklik sınırı levhası bulunan, tanımadığınız bir alt geçide doğru ilerliyorsunuz ve römorkunuz sandıklanmış makinelerin yüksek bir istifiyle yüklü. Bu köprünün altından geçmeye karar vermeden önce aşağıdaki değerlerden hangisini kesin olarak bilmeniz EN ÇOK gereklidir?","options":["Yüklü aracınızın yerden en yüksek noktasına kadar ölçülen toplam yüksekliği","Kantarda yüklü çekici-römork takımının tam toplam ağırlığı","Depolarınızda şu anda bulunan yakıt miktarı","Çeker akslara takılı lastiklerin markası ve modeli"],"explanation":"Bir köprü veya alt geçitten geçmeden önce, yüklü aracınızın zeminden en yüksek noktasına kadar olan toplam yüksekliğini bilin ve bunu işaretli açıklıkla karşılaştırın."},"362":{"q":"Bir ekskavatör yüklü alçak platformlu (low-boy) römorku eski bir sanayi bölgesinden geçecek şekilde yönlendiriyorsunuz. İleride yol eski bir demiryolu köprüsünün altından geçiyor ve cadde üzerinden sarkmış birkaç havai elektrik hattı uzanıyor. Bunların altından geçmeye karar vermeden önce, ciddi bir kazadan kaçınmak için belirtilen ve bilinen sınırlara göre doğrulamanız EN kritik ölçü hangisidir?","options":["Ön (direksiyon) aks lastik basıncınız, çünkü inik bir ön lastik aracı alçaltıp tellere takılmasına yol açabilir","Üstten geçiş yükseklik gabariniz; yüklü aracınızın toplam yüksekliğini belirtilen köprü yüksekliği ve üstteki tellerin yüksekliğiyle karşılaştırarak","Brüt kombinasyon ağırlık değeriniz (GCWR), köprünün ve yolun yüklü aracı güvenle taşıyabildiğini doğrulamak için","Öndeki araçla takip mesafeniz, böylece yapının altında sert fren yapmak zorunda kalmazsınız"],"explanation":"Aracın altından güvenle geçebileceğinden emin olmak için toplam yüklü açıklık yüksekliğinizi işaretli köprü açıklığı ve havai tellerin yüksekliği ile karşılaştırın."},"363":{"q":"Yüklü çekici-dorse aracınızla dört yönlü bir kavşağa yaklaşırken, solunuzdaki bir binek otomobil öne doğru çıkıp yasal olarak size ait olan geçiş hakkını agresif bir şekilde almaya çalışıyor. Hızınızı azaltmaya başladınız bile. Bu durumda EN İYİ hareket hangisidir?","options":["Geçiş hakkı yasal olarak sizin olduğu ve otomobilin yol vermesi gerektiği için hızınızı koruyup devam edin","Tekrar tekrar korna çalıp konumunuzu savunarak kavşağa girmeye devam edin","Geçiş hakkı yasal olarak sizin olsa bile, çarpışmayı önlemek için yol verip diğer sürücünün geçmesine izin verin","Otomobil yolunuza giremeden kavşağı geçmek için hızlanın"],"explanation":"Profesyonel bir sürücünün ilk görevi kazayı önlemektir; bu yüzden yasal olarak geçiş hakkı sizde olsa bile yol verin ve diğer sürücünün geçmesine izin verin."},"364":{"q":"Yüklü çekici-dorse aracınızla teslimat için rota çiziyorsunuz ve navigasyon sizi, gerçek toplam kombinasyon ağırlığınızdan DÜŞÜK bir ağırlık sınırı levhası bulunan bir ilçe köprüsüne yönlendiriyor. 12 mil ekleyen yasal bir alternatif güzergâh var. Ne yapmalısınız?","options":["Köprüden geçin ancak hızlanın, böylece tüm ağırlığınız yapının üzerinde mümkün olan en kısa süre kalsın","Yavaş ve sabit bir şekilde sürünerek geçin, çünkü köprülerdeki ağırlık sınırı levhaları tavsiye niteliğindedir ve yalnızca kamyon boşken uygulanır","Devam etmeden önce dingil ağırlıklarınızı doğrulamak için köprünün üzerinde durun","Köprüden geçmeyin; yasal alternatif güzergâhı kullanın, böylece levhada belirtilen ağırlık sınırını asla aşmazsınız"],"explanation":"İşaretli köprü ağırlık sınırı kesin bir yasal üst limittir; bu yüzden toplam ağırlığınız bunu aşıyorsa asla geçmeyin ve bunun yerine yasal alternatif yolu kullanın."},"365":{"q":"Uzun ve dik bir dağ yokuşundan ağır bir yükle iniyorsunuz. Hava soğuk olmasına rağmen, birkaç kilometre sonra fren pedalına bastığınızda kamyonun neredeyse hiç yavaşlamadığını ve frenlerin zayıf ve süngerimsi hissettirdiğini fark ediyorsunuz. Bu fren gücü kaybının EN olası nedeni nedir?","options":["Frenler inişte çok ağır ve uzun süre kullanılmaktan dolayı aşırı ısındı ve fren sönmesi (fade) meydana geldi","Soğuk dış hava, fren hatlarındaki nemi dondurdu ve tutuş güçlerini azalttı","Fren balataları çok yeni ve henüz alıştırılmadığı için düzgün kavramıyor","Çok hafif ve dikkatli fren yaptınız, bu yüzden balatalar tutacak kadar ısınmadı"],"explanation":"Uzun bir inişte ağır ve sürekli fren yapmak frenleri aşırı ısıtır ve pedala basılsa bile sürtünmeyi ve durma gücünü kaybetmelerine yol açar."},"367":{"q":"Bölünmüş bir otoyolun sağ şeridinde, izin verilen hızla yüklü bir römork çekiyorsunuz. Arkanızdaki bir sürücü kilometrelerce sizi çok yakından takip etti, ardından sizi sert şekilde geçti, önünüze keskin biçimde girdi, fren yaptı ve hızlanmanız ya da yol vermeniz için işaretler yapmaya devam ediyor. İleride trafik orta yoğunlukta. Bu agresif sürücüyle başa çıkmanın en güvenli ve en doğru yolu hangisidir?","options":["Diğer sürücünün hızına yetişmek için hızlanın, böylece sizi yakın takip etmeyi bırakıp uzaklaşsın","Gaz pedalını bırakın, takip mesafenizi artırın ve agresif sürücünün iyice öne geçip sizden uzaklaşmasına izin verin","Konumunuzu tam olarak koruyun ve sürücüye geri durması için işaret vermek üzere frene hafifçe dokunun","Sola geçerek, sakinleşene kadar agresif sürücünün sizi tekrar geçmesini engelleyin"],"explanation":"Saldırgan bir sürücüye en güvenli tepki, gazdan ayağınızı çekip takip mesafenizi artırarak yolunu açmak ve onun iyice öne geçmesini sağlamaktır."},"368":{"q":"Bir kamyon durağında 45 dakikalık yemek molanızı yeni bitirdiniz ve yüklü çekici-römork aracınız servis yolunun sağ banketi boyunca paralel olarak park edilmiş durumda. Solunuzdan trafik akıp geçiyor. Tekrar seyir şeridine girmeye hazırsınız. Bu park pozisyonundan ayrılmanın en güvenli ve doğru yolu hangi eylem sırasıdır?","options":["Trafikteki boşluğa katılmak için hemen düz bir şekilde çıkın, sol sinyali ancak hareket ettikten sonra açın","Yakındaki sürücüleri uyarmak için kornaya basın, frenleri bırakın ve gecikmeden şeride hızlanarak girin","Sol sinyalinizi açın, trafik ve kör noktalar için aynalarınızı ve aracın etrafındaki alanı kontrol edin ve yalnızca yol açık olduğunda çıkın","Yalnızca sürücü tarafı aynanızı kontrol edin ve açık görünüyorsa, boşluğu gözleyerek yavaşça şeride çıkın"],"explanation":"Park yerinden çıkmadan önce önce sinyal verin, sonra aynaları ve aracın çevresindeki tüm alanları trafik ve kör noktalar için kontrol edin, ancak yol açıkken çıkın."},"370":{"q":"Yüklü bir çekici-römork ile bölünmemiş iki şeritli bir yolda otoyol hızında ilerliyorsunuz. Karşıdan gelen bir otomobil orta çizgiyi geçti ve şimdi kısmen sizin şeridinizde, hızla yaklaşıyor. Çarpışmadan önce durmaya zaman yok. Sağınızda asfalt bir banket ve sığ çimenli bir hendek var; solunuzda ise trafiğin aktığı karşı şerit. Kafa kafaya çarpışmadan kaçınmak için size en iyi şansı hangi hareket verir?","options":["Kayan otomobilin etrafından dolaşmak için sola, karşı şeride yönelmek","Şeridinizi koruyup gerekirse tekerlekleri kilitleyecek kadar sert fren yapmak","Şerit ortasında kalıp uzun farları çakarak hızınızı korumak","Kaplamadan çıkmak anlamına gelse bile sağa, bankete doğru yönelmek"],"explanation":"Karşıdan gelen bir araç şeridinize kaydığında sağa, banket yönüne kırın; çünkü sürücü kendi şeridine dönebilir ve sola kırmak kafa kafaya çarpışma riski taşır."},"371":{"q":"Sıcak bir Temmuz öğleden sonrasında yüklü hâlde otoyol hızında giderken çekicinizin ön tarafından aniden yüksek bir patlama sesi duyuyorsunuz. Öncesinde koltukta hiçbir titreşim ya da tıkırtı hissetmediniz. Direksiyonu kavradığınızda, aşağıdakilerden hangisi patlayan lastiğin arka değil de ÖN lastik olduğunu EN net şekilde gösterir?","options":["Direksiyon aniden çok ağırlaşır ve kamyon güçlü bir şekilde bir tarafa çeker","Koltuktan ve kabin tabanından yukarı doğru gelen ağır bir titreşim ya da tıkırtı hissedersiniz","Römorkun arkası savrulmaya ve bir yandan bir yana sallanmaya başlar","Motor sıcaklık göstergesi yükselir ve kamyon güç kaybetmeye başlar"],"explanation":"Ön lastik patlaması direksiyonu aniden çok ağırlaştırır ve kamyonu patlayan lastik yönüne doğru güçlü şekilde çeker."},"372":{"q":"Düz, iki şeritli bir karayolunda yaklaşık 50 mil/saat hızla yüklü olarak giderken, direksiyon hâlâ normal hissedilmesine ve frene hiç dokunmamış olmanıza rağmen, römorkun arka kısmının aniden bir yandan diğer yana savrulup yalpalamaya başladığını hissediyorsunuz. Bu belirtilere göre, büyük olasılıkla ne olduğu konusunda EN doğru sonuç hangisidir?","options":["Ön (direksiyon dingili) lastiği havasını kaybetti ve bu yüzden arka kısım şimdi şeritte savruluyor","Arka lastik patladı, çünkü arka lastik patlaması tipik olarak aracın yalpalamasına veya kuyruk savurmasına (fishtail) neden olur","Römork frenleri kilitlendi ve arka kısmı yana doğru sürüklüyor","Çekiş tekerleği ile bir hızlanma kayması başladınız ve hemen sert biçimde diğer yöne direksiyon kırmalısınız"],"explanation":"Arka lastik arızası, direksiyon hâlâ nispeten normal hissettirirken aracın sallanmasına veya kuyruk savurmasına neden olur."},"373":{"q":"Islak iki şeritli bir karayolunda boş bir römork çekerken, ileride bir yan yoldan aniden bir otomobil çıkıyor. Fren pedalına sertçe basıyorsunuz ve ABS'nin (kilitlenme önleyici fren sistemi) devreye girdiğini hissediyorsunuz. Bu anda kilitlenme önleyici fren sisteminizin sizin için ne yaptığını EN İYİ hangi ifade açıklar?","options":["Toplam durma mesafenizi ABS olmadan olacağının yaklaşık yarısına indiriyor, böylece otomobilden çok önce durabiliyorsunuz.","Aracı kontrollü bir şekilde durdurmak için otomatik olarak düşük vitese geçiyor ve motor freni uyguluyor.","Tekerleklerinizin kilitlenmesini önlüyor, böylece sert fren yaparken direksiyon kullanmaya ve kontrolü korumaya devam edebiliyorsunuz.","Fren basıncını ayarlayarak boş römorkun yüklü bir römorktan daha kısa mesafede durmasını sağlıyor."],"explanation":"ABS, sert frenlemede tekerleklerin kilitlenmesini önler, böylece direksiyon hâkimiyetini koruyup tehlikeden kaçınmak için yön verebilirsiniz."},"374":{"q":"Kilitlenmeyi önleyen fren sistemiyle (ABS) donatılmış yüklü bir çekici-römork kullanırken, bir otomobil aniden önünüze geçip birden duruyor. Kuru zeminde, kendi şeridinizde sert bir acil duruş yapmanız gerekiyor. ABS'nin nasıl çalışmak üzere tasarlandığını bilerek, hangi frenleme yöntemi size en iyi kontrolü ve en kısa güvenli duruşu sağlar?","options":["ABS olmadan yapacağınız gibi, tekerleklerin kilitlenmesini önlemek için fren pedalına hızla basıp bırakın","Tekerlekler kilitlenmeye başladıkça pedalı her seferinde bırakarak kontrollü kesik (stab) frenleme uygulayın","ABS duruş mesafenizi kısalttığı için frene yalnızca hafifçe basıp arabayı manevrayla atlatın","Fren pedalına sertçe basın, sabit ve sürekli basınç uygulayın ve ABS çalışırken gerektiğinde direksiyonla yön verin"],"explanation":"ABS varken sıkıca basıp sabit, sürekli basınç uygulayarak fren yapın ve direksiyonu çevirin; tekerlek kilitlenmesini sistemin önlemesine izin verin."},"375":{"q":"ABS'siz, kısmen yüklü bir römork ile eyalet karayolunda giderken, bir araba aniden yan yoldan tam önünüze çıkıyor. Zamanında duramazsanız tehlikenin etrafından direksiyonla geçme yeteneğinizi kaybetmeden, fiziksel olarak mümkün olan en hızlı şekilde durmanız gerekir. Hangi frenleme yöntemini kullanmalısınız?","options":["Tekerlekleri kilitlenmenin tam eşiğinde tutarak kontrollü veya kesik kesik (stab) frenleme uygulayın","Frene sonuna kadar basıp en kısa mesafe için tekerlekleri kilitleyecek şekilde sıkıca basılı tutun","Uzun bir inişte yapacağınız gibi frene hafif ve düzenli şekilde dokunarak basın","Çekicinin tekerlekleri direksiyon için serbest kalsın diye yalnızca römork (el) freni valfini uygulayın"],"explanation":"ABS olmadan, tekerlekleri kilitlenmenin hemen eşiğinde tutan kontrollü veya kesik kesik frenleme, direksiyon hâkimiyetini korurken en yüksek durma gücünü sağlar."},"376":{"q":"ABS'siz (standart) frenli, yüklü bir çekici-römork sürüyorsunuz ve bir otomobil aniden önünüze kırınca çarpışmayı önlemek için sert fren yapmanız gerekiyor. Frene tam basıyorsunuz ve tekerleklerin kilitlendiğini hissediyorsunuz. Kademeli (stab) frenlemeyi doğru uygulamak ve aracı kontrol altında tutmak için, tekerlekler kilitlendiği anda ne yapmalısınız?","options":["Pedala tam ve sabit basınç uygulamaya devam edip tam durana kadar tekerlekleri kilitli tutmak","Tekerlekler tekrar dönmeye başlayana kadar frenleri bırakmak, sonra frenlere yeniden tam basmak","Durana kadar fren pedalını saniyede üç-dört kez, mümkün olduğunca hızlı pompalamak","Ayağınızı frenden tamamen çekip motoru durdurmak ve durana kadar serbest bırakarak kaymak"],"explanation":"Kesik kesik frenlemede, kilitlenen tekerlekler tekrar dönmeye başlayana kadar freni bırakıp direksiyon hâkimiyetini geri kazanırsınız, sonra freni tam olarak yeniden uygularsınız."},"377":{"q":"Kuru, dört şeritli bir otoyolda 55 mil/saat hızla yüklü bir araç taşıyıcısını takip ediyorsunuz ve önünüzdeki kamyonla aranızda birkaç saniyelik boş yol bırakıyorsunuz. Aniden bir kamyonet bu boşluğa giriyor ve araç taşıyıcısının fren lambaları yanıyor. Bu durumu güvenli bir şekilde yönetmek için o güvenlik mesafesini korumanız neden yaptığınız en önemli şeydi?","options":["Gaz pedalından ayağınızı çekmeden 55 mil/saat hızı korumanızı sağladı, böylece arkanızdaki trafik düzgün aktı","Yaklaşık 60 fit içinde tam duruşu garanti etti; bu 55 mil/saatteki toplam durma mesafesidir","Tehlikeyi fark etmeniz ve sert fren yapmak zorunda kalmadan önce tepki vermeniz için size ekstra alan ve zaman tanıdı","Takip mesafenizi bir saniyenin altında tuttu; bu, el kitabının otoyol hızları için önerdiği aralıktır"],"explanation":"Güvenlik mesafesi, sert fren yapmadan önce tehlikeyi fark edip tepki vermeniz için fazladan yer ve zaman kazandırır; çünkü yüksek hızda durma mesafesi göründüğünden çok daha uzundur."},"378":{"q":"İyi ve kuru koşullarda 55 mil/saat hızla tam yüklü bir çekici-römork sürüyorsunuz ve yan şeritteki bir otomobil, ikinizin de aynı anda gördüğü aynı tehlike için sert fren yapıyor. Yüklü bir kamyonun o otomobile kıyasla nasıl davrandığını bilerek, kendinize ne kadar boşluk bırakacağınızı hangi ifade belirlemelidir?","options":["Yüklü kamyon ve otomobil yaklaşık aynı mesafede durur, çünkü ikisinin de frenleri iyidir","Yüklü kamyon çok daha kısa mesafede durur, çünkü ağır yükü lastikleri yere bastırarak daha iyi tutuş sağlar","Hiç fark etmez, çünkü 55 mil/saatte herhangi bir araç tepki verip durmak için yaklaşık 60 fit mesafeye ihtiyaç duyar","Yüklü kamyonun durması otomobile göre çok daha fazla mesafe gerektirir, bu yüzden çok daha fazla boşluk bırakmalı ve frene daha erken basmalısınız"],"explanation":"Yüklü bir kamyonun çok daha fazla kütlesi ve momentumu, toplam durma mesafesini bir otomobilinkinden çok daha uzun yapar; bu yüzden daha fazla mesafe bırakıp daha erken fren yapmalısınız."},"379":{"q":"İki şeritli bir yolda otoyol hızıyla ilerlerken, bir motosikletli tam önünüzde aynı şeride geçiyor ve şeridin sağ kenarına yakın gidiyor. Trafik orta yoğunlukta ve önünüzde bir geçiş bölgesi var. Bu motosikletin arkasında takip mesafenizi yönetmenin en güvenli yolu nedir?","options":["Motosikleti tam boyutlu bir araç gibi düşünün: tüm şeridi ona bırakın ve fazladan mesafeyle takip edin, çünkü o sizden çok daha kısa mesafede durabilir","Şeridinizde öne yaklaşın ve şeridin boş olan sol kısmını motosikletle paylaşın, çünkü bir motosiklet şeridin yalnızca bir kısmına ihtiyaç duyar","Normal bir otomobil takip mesafesiyle arkasına geçin, çünkü motosiklet daha küçüktür ve bir otomobilden daha az yere ihtiyaç duyar","Yakın durun ve geçiş bölgesinde hemen geçmeye hazırlanın, çünkü asıl tehlike yavaş bir motosikletin arkasında oyalanmaktır"],"explanation":"Bir motosiklet tüm şeride hak sahibidir ve ağır bir kamyondan çok daha kısa mesafede durabilir; bu yüzden ona tüm şeridi bırakın ve fazladan mesafe ile takip edin."},"380":{"q":"Yüklü çekici-römork (kombinasyon) aracınızla kırsal bir kavşağa yaklaşıyorsunuz. Trafik ışığı sönmüş durumda (tamamen çalışmıyor) ve hiçbir yönde dur ya da yol ver levhası yok. Kavşağa yaklaşırken, sizden bir an önce gelmiş ve sağınızdaki yan yolda çoktan durmuş, geçmeyi bekleyen bir kamyonet görüyorsunuz. Doğru davranış nedir?","options":["İlk siz geçin, çünkü yüklü kombinasyon araç daha fazla yere ihtiyaç duyar ve daha hafif araçlara göre geçiş üstünlüğüne sahiptir","Kamyonete yol verin, çünkü kavşağa önce o gelmiştir ve ayrıca sağınızdadır","Sönmüş ışığı yeşil ışığınız gibi kabul edip hız kesmeden geçmeye devam edin","Yan trafiğin sizi görebilmesi için, dönüşe başlamadan önce kavşağın ortasında durun"],"explanation":"Kontrolsüz bir kavşakta önce gelen araca yol verirsiniz; aynı anda geldiyseniz sağınızdaki araca yol verirsiniz."},"381":{"q":"Açık bir hafta içi günü saat 15:15 ve yüklü bir tek parça kamyonu yerleşim bölgesinden geçirirken yanıp sönen sarı bir ikaz lambası ve bir okul bölgesi levhası görüyorsunuz. Çevrenizdeki trafik hâlâ normal 30 mil/saat hız sınırında ilerliyor ve ileride yol açık görünüyor. Yapılacak EN İYİ hareket nedir?","options":["İleride şerit boş olduğundan ve diğer araçlar yavaşlamadığından, belirlenen 30 mil/saat sınırını koruyun","Sol şeride geçip yavaş araçları hızla geçerek, çocuklar ortaya çıkmadan bölgeyi terk edin","Hızınızı belirlenen sınırın altına düşürün ve aniden yola fırlayabilecek çocuklar için kaldırımları ve yaya geçitlerini dikkatle tarayın","Hızınızı koruyun ancak sürücülerin ve yayaların kamyonunuzu daha net görebilmesi için uzun farlarınızı yakın"],"explanation":"Yanıp sönen ışık, hız sınırının düşürüldüğü okul bölgesinin aktif olduğunu gösterir; bu yüzden sınırın altına inin ve aniden çıkabilecek çocuklar için kaldırımları ve yaya geçitlerini tarayın."},"382":{"q":"Üst şerit sinyalinin şeridiniz için yeşil ok gösterdiği, ancak yolda duran bir işaretçinin (flagger) size doğru tutulmuş bir DUR levhası taşıdığı bir karayolu yol çalışması bölgesine yaklaşıyorsunuz. Ne yapmalısınız?","options":["Yeşil ok sinyali şeridinizin devam etmesine yasal olarak izin verdiği için bölgeden yavaşça geçin","Yalnızca işaretçi düdük de çalarsa veya iki koluyla işaret ederse durun, aksi takdirde yeşil oku izleyin","Bu çelişkiyi bir arıza olarak değerlendirin ve saatte en fazla 15 mil hızla dikkatli şekilde ilerleyin","Durun ve işaretçiye uyun, çünkü işaretçinin talimatları normal sinyallerin bile üzerinde önceliğe sahiptir"],"explanation":"İşaretçinin talimatları tüm işaret ve sinyallere göre önceliklidir; çünkü işaretçi, sabit bir sinyalin yansıtamayacağı çalışma bölgesi tehlikelerini anlık olarak bilir."},"383":{"q":"Bölünmemiş dört şeritli bir karayolunun sağ şeridinde çekici-römork aracınızı kullanırken bir siren sesi duyuyorsunuz ve arkanızdan acil durum lambaları yanan bir ambulansın yaklaştığını görüyorsunuz. İleride trafik az ve sağdaki banket geniş ve boş. Hangi davranış doğrudur?","options":["Sinyal verin, yolun sağ kenarına yanaşın ve ambulans geçene kadar aracı durdurun","Ambulansın yolunuzu tahmin edip etrafınızdan dolaşabilmesi için şeridinizi ve hızınızı koruyun","Sol şeride geçip orada durarak sağ tarafı ambulans için tamamen açık bırakın","Trafiğin önünde kalmak için hızlanın ve sapacak bir yan sokak bulun"],"explanation":"Işıkları ve sireniyle bir acil durum aracı yaklaştığında sinyal verin, yolun sağ kenarına çekin ve geçene kadar durun."},"384":{"q":"Size, tabandan tavana kadar istiflenmiş ve römorku çatıya kadar dolduran hafif kutular taşıyan yüklü bir van römork veriliyor. Aynı römorkun, tabanda yalnızca diz hizasına kadar istiflenmiş yoğun ve ağır yük taşıdığı duruma kıyasla, yüksek ve tepesi ağır yükün sürüşünüzü nasıl etkilediğine dair EN doğru ifade hangisidir?","options":["Daha yüksek istifleme ağırlık merkezini düşürür, böylece rampaları ve virajları kamyonlar için belirlenen hızlarda güvenle alabilirsiniz","Yüksek ağırlık merkezi, römorkun virajlarda ve rampalarda devrilme olasılığını artırır; bu nedenle bunlara girmeden çok önce yavaşlamanız gerekir","Yük hafif olduğu için ağırlık merkezinin devrilme riski üzerinde etkisi yoktur ve yalnızca fren mesafesi için önemlidir","Yüksek ağırlık merkezi esas olarak fren mesafenizi artırır, bu yüzden asıl tehlike öndeki araca arkadan çarpmaktır"],"explanation":"Yükü yüksek istiflemek, hafif olsa bile ağırlık merkezini yükseltir ve aracın virajlarda ve rampalarda devrilme olasılığını çok artırır; bu yüzden onlardan çok önce yavaşlayın."},"385":{"q":"Yüklü bir tanker çekiyorsunuz ve tavsiye edilen hızı 35 mil/saat olan bir yonca yaprağı çıkış rampasına yaklaşıyorsunuz. Arkanızdaki trafik yoğun ve hareket halinde kalmak istiyorsunuz. Kamyonların en sık neden devrildiğini gözden geçirdiğinizde, bu rampada en çok endişelenmeniz gereken tek en büyük etken hangisidir?","options":["Çok alçak dengelenmiş, römorkun ağırlık merkezini yol yüzeyine tehlikeli derecede yakın bırakan bir yük","Viraja girerken öndeki aracı tam bir saniye fazla yakın takip etmek","Rampanın virajına girmeden önce yavaşlamak yerine virajda hızınızı çok yüksek tutmak","Rampadan önceki düz yaklaşma bölümünde römork frenleriyle çok hafif fren yapmak"],"explanation":"Kamyon devrilmesinin en yaygın nedeni dönüşe veya rampaya çok hızlı girmektir; bu yüzden viraja girmeden önce güvenli hıza inin, viraj içindeyken değil."},"386":{"q":"İstiflenmiş makine sandıklarından oluşan yüksek bir yük taşıyorsunuz ve otoyoldan 30 mil/saat işaretli, virajlı bir giriş/çıkış rampasına çıkıyorsunuz. Kamyonunuz ağır yüklü ve ağırlık merkezi yüksek. Rampada devrilmeye karşı sizi en iyi koruyan davranış hangisidir?","options":["Sabit 30 mil/saat'te kalmak, çünkü bu işaretli rampa hızıdır ve tabela zaten kamyonları hesaba katar","Römork yana yatmaya başladığını hissedene kadar otoyol hızınızı korumak, sonra virajda sert fren yapmak","Motorun sizi daha hızlı itmemesi için virajı boşta (vites boşta) almak","Viraja girmeden önce işaretli rampa hızının çok altına yavaşlamak, çünkü tabela yüksek ağır bir yük için değil, otomobiller için ayarlanmıştır"],"explanation":"Rampa hız tabelaları otomobiller için belirlenmiştir; bu yüzden yüksek, ağır bir yükle devrilmemek için viraja girmeden önce belirtilen rampa hızının çok altına inin."},"387":{"q":"Bir teslimatı tamamlayıp yüklü düz kamyonunuzu yokuş aşağı inen dik bir sokakta sağdaki bordüre sıkıca yanaştırarak park ediyorsunuz. El frenini çekip kabinden ayrılmadan önce, frenler boşalırsa kamyonun aşağı yöndeki trafik şeridine kaymak yerine bordürE doğru yuvarlanıp onun tarafından durdurulması için ön tekerlekleri nasıl bırakmalısınız?","options":["Bordüre doğru (sağa) çevrilmiş, böylece kayma olursa bordür ön lastiği engeller","Bordürden uzağa (sola) çevrilmiş, böylece kamyonun arkası bordüre doğru savrulur","Düz bırakılmış, çünkü kamyonu eğimde asıl tutan çekili el frenidir","Yalnızca bordür yoksa bordüre doğru çevrilmiş, aksi halde düz"],"explanation":"Bordürlü yokuş aşağı park ederken ön tekerlekleri bordüre doğru çevirin ki kayma olursa lastik bordüre dayanıp kamyonu durdursun."},"388":{"q":"Yükünüzü kontrol etmek için dik bir dağ yolunda durup kamyonu YOKUŞ YUKARI bakacak şekilde, sağ tarafta bordür olacak biçimde park ediyorsunuz. Aracın yanından ayrılmadan önce, frenler boşalırsa aracın geri kayıp bordüre dayanarak durmasını istiyorsunuz. Bu 'yokuş yukarı ve bordürlü' durumda ön tekerlekleri doğru ayarlamak için:","options":["Ön tekerlekleri bordüre doğru (sağa) çevirin, böylece lastik ön yüzüyle bordüre dayansın","Ön tekerlekleri bordürden uzağa (sola) çevirin, böylece araç geri kaydığında lastiğin arka yüzü bordüre dayansın","Ön tekerlekleri düz bırakın ve yalnızca el frenine güvenin","Bordür yokmuş gibi ön tekerlekleri keskin biçimde sağa çevirin"],"explanation":"Bordürlü yokuş yukarı park ederken ön tekerlekleri bordürden uzağa çevirin ki geri kayma olursa lastik bordüre takılıp aracı durdursun."},"389":{"q":"Kuru bir şehir yolunda bir motosikletin arkasından gidiyorsunuz ve takip mesafenizi sürücünün o ana kadarki hareketine göre ayarlıyorsunuz. Ona arkadan çarpmamak için o motosiklet hakkında plan yapmanız gereken EN önemli varsayım hangisidir?","options":["Her zaman hız sınırının çok altında gider, bu yüzden kısa bir mesafe güvenlidir","İki tam şerit kadar yer gerektirir, bu yüzden asla yanına geçmemelisiniz","Trafikte fark edilmesi kolayca gözden kaçabilir ve kamyonunuzdan çok daha hızlı durabilir","Tek ve sabit bir hızda gider, aniden yavaşlamaz"],"explanation":"Motosikletleri trafikte görmek zordur ve ağır bir kamyondan çok daha kısa mesafede durabilirler, bu yüzden fazladan takip mesafesi bırakın."},"390":{"q":"Yüklü bir römork çekiyorsunuz ve kuru, gündüz koşullarında uzun, dik bir inişe başlıyorsunuz. Yanınızdaki acemi sürücü, bu inişin aracınızın tam olarak durması için gereken mesafeyi, aynı hızda düz zeminde durmaya kıyasla nasıl etkilediğini soruyor. Hangi ifade doğrudur?","options":["Durma mesafenizi hiç etkilemez, çünkü toplam durma mesafesi yolun eğiminden bağımsız olarak 55 mil/saatte yaklaşık 419 fitte sabittir.","Durma mesafeniz çok daha kısalır, çünkü kamyonu aşağı çeken yer çekimi lastikleri yola daha sert bastırır ve fren tutuşunu iyileştirir.","Motor ve vites inişte frenlemeyi devraldığında durma mesafeniz kısa süreliğine neredeyse sıfıra düşer.","Durma mesafeniz artar, çünkü yer çekimi inişte momentumunuza eklenir ve aracı durdurmak için frenler daha uzun bir mesafede daha fazla çalışmak zorunda kalır."],"explanation":"İnişli yokuşta yerçekimi momentuma eklenir, bu yüzden frenler daha uzun mesafede daha fazla çalışmak zorunda kalır ve durma mesafeniz artar."},"391":{"q":"Yüklü bir römork çekerek kırsal bir karayolunda ilerliyorsunuz ve 'GÜVENLİ HIZ 40 MPH' yazan sarı bir tavsiye levhasının bulunduğu keskin bir viraja yaklaşıyorsunuz. Zemin kuru ve trafik az. Bir CDL sürücüsü olarak bu tavsiye edilen hızı nasıl değerlendirmeniz gerektiğini en iyi hangi ifade açıklar?","options":["40 mph değeri binek otomobiller için hesaplanmıştır; bu nedenle ağırlık merkezi daha yüksek olan yüklü bir kamyon olarak devrilmeyi önlemek için viraja bu hızın altında girmelisiniz.","Levha yasal bir tavsiye olduğundan, 40 mph tüm araçlar için izin verilen azami hızdır ve yol kuru olduğu sürece kamyonlar virajı tam 40 mph ile alabilir.","Tavsiye yalnızca boş römorklar için geçerlidir; römorkunuz yüklü ve dengeli olduğundan virajda 40 mph'yi aşabilirsiniz.","Tavsiye hızları özellikle kamyonlar için belirlenmiştir, bu yüzden 40 mph zaten bir kamyon güvenlik payını içerir ve daha fazla yavaşlamadan bu hızı tutturabilirsiniz."],"explanation":"Viraj tavsiye hızları binek araçlar için belirlenir, bu yüzden ağırlık merkezi yüksek yüklü kamyon devrilmeyi önlemek için yazılı hızın altında girmelidir."},"393":{"q":"Uzun bir teslimat seferini bitirip sahaya giriyorsunuz. Bu sabah sefer öncesi muayeneden önce her şey yolundaydı ve yük bağlamanızı da ilk 50 milde, ardından yol boyunca her 150 milde bir yeniden kontrol ettiniz. Sefer bittiğine ve kamyon park edildiğine göre, DPS'in sizden beklediği tam muayene döngüsünü tamamlamak için hangi muayeneyi yapmalısınız?","options":["Her 150 milde bir yaptığınız yol içi kontroller aracı zaten gün boyunca kapsadığı için başka muayeneye gerek yoktur","Sefer sonrası muayene, böylece sefer sırasında oluşan herhangi bir arıza, bir sonraki sürücüden veya bir sonraki vardiyanızdan önce belgelenir","Yıllık muayene, çünkü günlük sürüş bittikten sonra gereken tek resmi muayene budur","Seferin aşınmasını kapatmak için frenlerin ve lastiklerin aylık muayenesi"],"explanation":"Sefer sonrası muayene, sürüş sırasında oluşan arızaların bir sonraki vardiyadan önce raporda belgelenmesi için yolculuğun sonunda yapılır."},"395":{"q":"11 saatlik bir seferi yeni bitirdiniz ve sahaya girdiniz. Yolculuk sırasında frenler biraz boşta hissettirdi ve bir konum lambasının yanıp sönerek söndüğünü fark ettiniz. Sefer sonrası muayenenizi doğru şekilde tamamlamanın bir parçası olarak, bir sonraki sürücünün ve taşıyıcının bu durumlardan haberdar olması için aşağıdakilerden hangisini doldurmanız ve gerektiğinde teslim etmeniz beklenir?","options":["IFTA vergi raporlaması için tuttuğunuz yakıt alımı ve kilometre makbuz kaydı","Günün nasıl geçtiğini ve dinlenmek için nerede durduğunuzu not ettiğiniz kişisel sefer günlüğünüz","Boştaki frenler ve arızalı konum lambası gibi tüm kusurları belgeleyen bir sürücü araç muayene raporu (DVIR)","Sevkiyat görevlisinin kayıtları için bir yol kenarı hava durumu ve yol koşulu raporu"],"explanation":"Sefer sonrası muayene, yumuşak frenler ve arızalı işaret lambası gibi güvenlik kusurlarını belgeleyen bir sürücü araç muayene raporu (DVIR) doldurmayı gerektirir."},"396":{"q":"Soğuk bir sabah ve yola çıkış öncesi ısınma için motoru yeni çalıştırdınız. Yola çıkmadan önce her şeyin düzgün çalıştığından emin olmak için gösterge panelini izliyorsunuz. Yağ basıncı göstergesiyle ilgili doğru beklenti hangisidir ve motorun çalıştırılmasının güvenli olduğunu gösterir?","options":["İbre yavaşça yükselmeli ve yağ ısındıktan sonra birkaç dakikalık rölantinin ardından normal basınca ulaşmalıdır","Sabah soğuk olduğu için, yağ basıncı güvenilir hale gelmeden önce motoru yaklaşık bir saat rölantide bekletmelisiniz","Yolda yük altında hareket edene kadar yağ basıncının görünmesi gerekmez","İbre, motor çalıştıktan sonra birkaç saniye içinde normal çalışma basıncına ulaşmalıdır"],"explanation":"Yağ basıncı, motor çalıştırıldıktan birkaç saniye içinde normal çalışma basıncına ulaşmalıdır, aksi halde hasarı önlemek için motoru durdurmalısınız."},"397":{"q":"Kırsal bir iki şeritli karayolunda yolculuğunuzun 40. dakikasındasınız ve göstergelere baktığınızda yağ basıncı göstergesinin sıfıra düştüğünü görüyorsunuz; oysa motor hâlâ normal ses çıkarıyor, normal çalışıyor ve henüz uyarı zili çalmadı. Doğru hareket nedir?","options":["Güvenli olur olmaz yolun kenarına çekin, durun ve motoru kapatın","Motor hâlâ normal ses çıkardığı için bir sonraki tır durağına kadar normal şekilde sürmeye devam edin","Hızı koruyun ama gaza basmayı azaltın ve planlanan yakıt durağınıza kadar devam edin","Motor yükünü azaltmak için radyo ve klima gibi gereksiz aksesuarları kapatın ve yola devam edin"],"explanation":"Yağ basıncı kaybı motorun artık yağlanmadığı anlamına gelir, bu yüzden güvenli olur olmaz kenara çekin ve motoru hemen durdurun."},"398":{"q":"Sıcak bir yaz öğleden sonrası, GVWR sınırınıza yakın tam yüklü halde uzun bir yokuşu tırmanıyorsunuz. Tepeye yaklaşırken gösterge panelindeki göstergelerden biri kırmızı bölgeye doğru yükselmeye başlıyor. Nasıl tepki vereceğinize karar vermeden önce, motorun kendisinin aşırı ısındığını size uyarmak için özel olarak tasarlanmış gösterge hangisidir?","options":["Yağ basıncı göstergesi, çünkü sıcak havada yağ incelir ve ibre yükselerek yüksek motor sıcaklığını uyarır","Soğutma suyu sıcaklık göstergesi, çünkü motor soğutma suyunun sıcaklığını okur ve motorun aşırı ısındığını uyarır","Pirometre, çünkü egzoz gazı ısısını okur ve sıcak bir günde bu motorun aşırı ısınmasıyla aynıdır","Voltmetre, çünkü sıcak bir günde uzun bir tırmanış şarj sistemini aşırı ısıtır ve motorun aşırı ısındığını gösterir"],"explanation":"Soğutma suyu sıcaklık göstergesi motor soğutma sıvısının sıcaklığını okur ve motor aşırı ısındığında sizi uyarır."},"399":{"q":"Sefer öncesi kontrol sırasında motoru çalıştırıyorsunuz ve kamyon rölantide çalışırken gösterge panelindeki göstergeleri izliyorsunuz. Ampermetre (veya voltmetre) ibresinin normal aralıkta sabit durduğunu, düşmediğini veya düzensizce sallanmadığını fark ediyorsunuz. Bu gösterge aracınız hakkında size gerçekte ne söylüyor?","options":["Motor yağ basıncı, seferinize güvenle başlamak için yeterince yüksektir","Soğutma sıvısı sıcaklığı güvenli çalışma aralığı içindedir","Şarj sistemi çalışıyor ve aküyü düzgün şekilde şarjlı tutuyor","Akünün gözlerinde yeterli su var ve akü cıvatalarla sağlam şekilde sabitlenmiş"],"explanation":"Ampermetre veya voltmetrenin normal aralıkta sabit göstermesi, alternatörün akım ürettiğini ve aküyü düzgün şarjlı tuttuğunu doğrular."},"400":{"q":"Sefer öncesi kontrolünüz sırasında çekicinizin direksiyonunu tutup ön tekerlekler hareket etmeden sağa sola oynatıyorsunuz. Tekerlekler tepki vermeye başlamadan önce belirgin bir boşluk hissediyorsunuz. Bu serbest hareketin güvenli sınırlar içinde olup olmadığına ve aracın yasal olarak kullanılabilir olduğuna karar vermek için, ön tekerlekler dönmeye başlamadan önce direksiyonda en FAZLA ne kadar hareket olmalıdır?","options":["Direksiyonun yarım turuna kadar, çünkü ağır kamyonlarda biraz boşluk normaldir","Tekerlekler tepki vermeden önce direksiyonun tam bir turuna kadar","Direksiyonun çeyrek turu olan 90 dereceye kadar","Tekerlekler tepki vermeden önce yaklaşık 10 dereceden fazla olmamalı"],"explanation":"Direksiyonun boşluğu, ön tekerlekler tepki vermeden önce yaklaşık 10 dereceyi geçmemelidir; fazlası aşınmış veya gevşek direksiyon anlamına gelir."},"401":{"q":"Sefer öncesi kontrolünüz sırasında debriyaj pedalına bastığınızda, normalden belirgin şekilde daha fazla boşluk (dirençle karşılaşmadan önceki gevşek hareket) olduğunu fark ediyorsunuz. Zaten geç kaldınız ve kamyon hâlâ çalışıyor. Hangi ifade bulduğunuz durumu ve ne yapmanız gerektiğini EN İYİ şekilde açıklar?","options":["Çok fazla veya çok az debriyaj boşluğu, aracın güvenli şekilde kullanılabilmesi için önce onarılması gereken mekanik bir arızadır","Aşırı debriyaj boşluğu, yalnızca debriyaj yük altında kaymaya başladığında önem kazanan normal bir aşınmadır","Bir sorundur, ancak yalnızca direksiyon ve frenler kamyonu hizmet dışı bırakabilecek kontrol maddeleridir","Gevşek debriyaj boşluğu aslında bağlantının iyi yağlandığının ve sıkışmadığının iyi bir işaretidir"],"explanation":"Debriyaj boşluğunun fazla veya az olması, araç güvenle kullanılmadan önce onarılması gereken mekanik bir arızadır."},"402":{"q":"Yüklü bir römorkla uzun bir dağ yokuşundan aşağı iniyorsunuz. Yakıt tasarrufu sağlamak ve aşınmayı azaltmak için bir meslektaşınız, vitesi boşa alıp kamyonun yokuştan aşağı kaymasına izin vermenizi, frenleri yalnızca hızınız çok yükseldiğinde kullanmanızı öneriyor. Bu tavsiyeye uymak neden yanlış bir seçimdir?","options":["Kısa bir yokuşta kabul edilebilir çünkü frenler tek başına kamyonu aşağıya kadar güvenle kontrol edebilir","Motor ve vites frenlemesini ve araç kontrolünü kaybedersiniz, servis frenleriniz aşırı ısınıp etkisini yitirebilir (fren sönmesi) ve viteste boşta kaymak yasa dışıdır","Bu yalnızca yokuş, inmeden önce normalde seçeceğiniz düşük vitesten daha dikse sorun olur","Boşta kayma o kadar çok yakıt tasarrufu sağlar ki, küçük bir kontrol kaybı çoğu inişte kabul edilebilir bir ödünleşmedir"],"explanation":"Uzun bir inişte boşa almak motor ve vites frenlemesini ortadan kaldırır, servis frenlerini aşırı ısıtıp güçten düşürür ve boşta kaymak yasaktır."},"403":{"q":"Vites göstergesi paneli üzerinde bulunmayan eski bir kamyonla, yüklü bir römorku uzun bir yokuştan yukarı çekiyorsunuz. Motor zorlanmaya ve güç kaybetmeye başlıyor ve tırmanışı sürdürmek için daha düşük bir vitese geçmeniz gerektiğini biliyorsunuz. Güvenebileceğiniz bir vites tablosu ya da vites göstergesi olmadan, bu an için hangi vitesin doğru olduğuna karar vermek için gerçekte hangi bilgiyi kullanmalısınız?","options":["Römorkun yokuş yukarı izlediği yolu izlerken yalnızca sağ yan aynanızın gösterdiği görüntüyü","Sürücü koltuğunuzun yüksekliğini ve yokuşun kabinden ne kadar dik göründüğünü","Mevcut yol hızınızı, takometrede gösterilen motor devriyle (rpm) birlikte","Hızlı bir referans olarak ön kapı kolunun omzunuza göre konumunu"],"explanation":"Doğru vites, yol hızınızı takometrede gösterilen motor devriyle eşleştirerek seçilir."},"404":{"q":"Tam yüklü bir yarı römorkla dik bir yokuş yukarı eğimde kırmızı ışıkta durdunuz. Işık yeşile döner ve aracı, hemen arkanızda duran otomobile doğru geri kaymadan yumuşak bir şekilde hareket ettirmeniz gerekir. Servis (ayak) frenini bırakıp motora gaz vermeye hazırlanırken, kalkış sırasında aracın geriye kaymasını EN İYİ hangi teknik önler?","options":["Kalkıştan önce ekstra hava basıncı oluşturmak için servis frenine birkaç kez hızlıca basıp bırakmak","Motorun eğimi yenmek için daha fazla çekiş gücüne sahip olması için daha yüksek bir vitese geçmek","Motoru yükseltip debriyajı yavaşça kaydırarak kamyonu yalnızca tork ile öne doğru hareket ettirmek","El frenini çekili tutmak ve yalnızca motor yükü kavrayıp araç öne hareket etmeye başladığında bırakmak"],"explanation":"Yokuşta hareket ederken el frenini basılı tutun ve ancak motor yükü çekip ileri gitmeye başladığınızda bırakın, böylece geri kaymayı önlersiniz."},"405":{"q":"Hava donma noktasının hemen altında ve depo çıkışındaki avlu ince bir buz tabakasıyla kaplıyken yüklü çekici-dorse setinizle dur işaretinden hareket ediyorsunuz. Çeker tekerleklerin yol tutuşunu kaybetmeye başladığını hissediyorsunuz. Çeker tekerlekleri patinaj yaptırmadan ve hızlanma kaymasına yol açmadan hareket etmeniz için EN İYİ şansı hangi eylem verir?","options":["Gaza yavaşça basın ve hızı kademeli olarak artırın ki çeker lastikler kaygan zeminde tutuşlarını korusun","Fazla güç kamyonu kaygan bölgeden geçirsin diye gaz pedalına sonuna kadar sertçe basın","Hareket etmeden önce aracın her 10 fitlik uzunluğu için bir saniye ekstra takip mesafesi ekleyin","Debriyajı yarı basılı tutup motoru yüksek devirde döndürün, sonra güçlü bir kalkış için hızla bırakın"],"explanation":"Kaygan, donma noktasındaki bir yüzeyde gaza yumuşak basın ve hızı kademeli artırın ki çekiş lastikleri tutuşunu korusun ve patinaja girmesin."},"406":{"q":"Şafak yeni sökmüş ve sefer öncesi muayenenizi yapıyorsunuz. Kaputu açıp alternatör ile su pompası tahrik kayışlarına baktığınızda, kamyonu güvenle yola çıkarmadan önce kayışların dikkat gerektirdiğini hangi durum gösterir?","options":["Kayışlar parlak, pırıltılı bir görünüm yerine mat, koyu bir renkte","Bir kayış çatlamış ve liflenmiş ya da bastırdığınızda olması gerekenden fazla esniyor (uygun olmayan gerginlik)","Korna düğmesine bastığınızda yeterince yüksek sesle çalmıyor","Kontak açıkken yakıt göstergesi dolu okumuyor"],"explanation":"Tahrik kayışları çatlamış, liflenmiş ya da olması gerekenden fazla esniyorsa değiştirilmelidir, çünkü yanlış gerginlik veya aşınma kayışın kopmasına yol açabilir."},"407":{"q":"Sefer öncesi kontrolünüz sırasında kaputu açıp motor bölmesindeki radyatör ve kalorifer hortumları boyunca elinizi gezdiriyorsunuz. Bu hortumları öncelikle hangi durum için kontrol edersiniz?","options":["Hortumların sıcak olup olmadığı, motorun çalışma sıcaklığına ulaştığını gösterip göstermediği","Kayış ve kasnak bölgesinden gelen yüksek bir tıslama veya vurma sesi","Hortumun patlamasına yol açabilecek yumuşamış noktalar, sızıntılar ve çatlaklar","Lastiğin yakın zamanda temizlenip bakımdan geçtiğini gösteren parlak ve cilalı bir görünüm"],"explanation":"Motor hortumları yumuşamış noktalar, sızıntılar ve çatlaklar için kontrol edilmelidir, çünkü zayıflamış bir hortum ısı ve basınç altında patlayıp soğutucu kaybına yol açabilir."},"408":{"q":"Sabah araç öncesi kontrolünüz sırasında hava donma noktasının hemen altında ve motor bölmesinin etrafında dolaşırken, uzun bir dağ sürüşü gününden önce direksiyon hidrolik (güç direksiyon) sistemini kontrol etmeye karar veriyorsunuz. Aşağıdakilerden hangisi güç direksiyon sisteminde neyi incelemeniz gerektiğini EN İYİ şekilde açıklar?","options":["Tekerlekler dönmeden önce direksiyon simidinde en fazla 10 derece (20 inçlik bir simitte yaklaşık 2 inç) boşluk olması","Pompadan gelen yüksek uğultu veya inilti sesleri, çünkü ses güç direksiyon arızasının tek güvenilir belirtisidir","Sistemin yakın zamanda bakımdan geçtiğini doğrulayan, depo ve hatlar üzerindeki taze, parlak boya","Güç direksiyon sıvısı seviyesi ve hortumlarda, depoda ve bağlantılarda herhangi bir sızıntı belirtisi"],"explanation":"Hidrolik direksiyon sistemini doğru sıvı seviyesi ve hortumlar, depo ile bağlantılardaki sızıntılar açısından kontrol edin, çünkü düşük seviye ani güç desteği kaybına yol açabilir."},"409":{"q":"Soğuk, parlak bir sabah araç öncesi kontrolünüzü yaparken kabine yaklaşıyorsunuz ve ön camın alt kenarı boyunca uzanan bir çatlak ile camın büyük bölümünü kaplayan bir yol kiri ve kurumuş böcek lekesi tabakası fark ediyorsunuz. Yolculuğunuzun ilk saatinde alçak sabah güneşine doğru süreceksiniz. Sürmeden önce ön camla ilgili yapılacak doğru işlem nedir?","options":["Sürmeden önce ön camı iyice temizleyin ve çatlağın görüşünüzü ciddi şekilde engelleyecek kadar büyük ya da öyle bir konumda olmadığından emin olun","Kiri olduğu gibi bırakın çünkü kirli, puslu bir ön cam aslında alçak sabah güneşinin parlamasını azaltır ve görüşü iyileştirir","Güneş parlamasıyla başa çıkmak için ön camın tamamına koyu renk film kaplayın, sonra camı temizlemeden sürün","Ön camı tamamen görmezden gelin çünkü ne kadar küçük olursa olsun herhangi bir çatlak aracı otomatik olarak hizmet dışı bırakır ve kontrolü sonlandırır"],"explanation":"Sürmeden önce ön cam temiz olmalı ve görüşü ciddi şekilde engelleyecek kadar büyük ya da kötü konumlu bir çatlak bulunmamalıdır."},"410":{"q":"Yağmurlu bir sabah ve araç öncesi kontrolünüz sırasında sürücü tarafındaki silecek lastiğinin yırtık ve cam yıkama deposunun boş olduğunu fark ediyorsunuz. Zaten programın gerisindesiniz ve şu an yağmur hafif. Bu sorunları küçük bir kolaylık meselesi gibi görmek yerine sürmeden önce gidermeniz gerektiğini EN İYİ açıklayan neden hangisidir?","options":["Esas olarak boyayı yol kirinden korumak ve kamyonun ikinci el değerini muhafaza etmek için gereklidirler","Çalışan silecekler ve cam yıkayıcılar yağmurda görüşünüzü net tutar; net görüş olmadan öndeki mesafeyi, trafiği ve tehlikeleri güvenle değerlendiremezsiniz","Yalnızca kamyonun yıllık devlet güvenlik muayenesinden geçmesi için gereklidirler, günlük sürüş için değil","Ön camı daha hızlı buz çözmeye yardımcı olurlar; bunları hizmet dışı bırakan asıl neden de budur"],"explanation":"Silecekler ve cam yıkayıcılar yağmurda görüşü açık tutar; mesafeyi, trafiği ve önündeki tehlikeleri değerlendirmek için net görüş şarttır."},"411":{"q":"Çekici-römork aracınızı dar bir yükleme rampasından geri geri çıkarırken, yaya bir işçi aniden aracın arkasındaki kör noktanıza giriyor. Sefer öncesi kontrolünüzde kornanızın çalıştığını doğrulamıştınız. Bu anda, çalışan bir kornanın bir CDL sürücüsü olarak sizin için önemli olmasının BİRİNCİL nedeni nedir?","options":["İş arkadaşlarınıza işinizin bittiğini ve rampadan ayrılmaya hazır olduğunuzu bildirmenizi sağlar","Elektrik sisteminizin aksesuarları çalıştıracak kadar şarjı olduğunu doğrular","İşçiyi ve diğer insanları ani tehlikeye karşı uyarmanızı sağlar, böylece güvenli bir yere çekilebilirler","Müfettişin sürüş konforu için kontrol ettiği bir konfor ve kolaylık özelliğini karşılar"],"explanation":"Korna, işçileri, yayaları ve sürücüleri ani tehlikeye karşı uyarıp uzaklaşmalarını sağlamak için kullanılan bir güvenlik uyarı aygıtıdır."},"412":{"q":"Sabahın erken saatinde hava donma noktasının hemen altındayken yaptığınız sefer öncesi kontrolde ön cam içeriden sürekli buğulanıp buz tutuyor. Defrosterin (cam buz çözücü) ve kaloriferin düzgün çalıştığını doğruluyorsunuz. Yola çıkmadan önce bu sistemlerin çalışıyor olması gereken temel güvenlik nedeni nedir?","options":["Uzun ve soğuk bir vardiyada uyanık ve rahat kalabilmeniz için kabinin yeterince sıcak kalması","Sürüşe başlamadan önce dış aynalardaki ve antendeki buzu hızlıca çözebilmeniz","Sıcak havanın silecek lastiklerinin cama yapışıp donmasını önlemesi","Soğuk veya yağışlı havada ön camı temiz tutarak yolu engelsiz bir şekilde görmeye devam edebilmeniz"],"explanation":"Buz çözücü ve ısıtıcı, soğuk veya yağışlı havada ön camı temiz tutarak yolun engelsiz görüşünü korur."},"413":{"q":"Hava donma noktasının hemen altında, sadece yakındaki bir boşaltma sahasına iki mil gideceksiniz ve emniyet kemeri kışlık montunuzun üzerinde sert ve rahatsız edici hissettiriyor. Sefer öncesi kontrolünüzü bitirip yola çıkmaya hazırlanırken, emniyet kemeriyle ilgili hangi davranış doğrudur?","options":["Mesafe ne kadar kısa olursa olsun veya ne kadar yavaş süreceğinizi planlarsanız planlayın, tüm yolculuk boyunca emniyet kemerini takın ve kullanın","Yolculuk üç milin altında olduğu ve yavaş süreceğiniz için kemeri takmadan bırakın","Uyarı sesi sussun ama montunuz hareketinizi kısıtlamasın diye kemeri arkanıza gevşekçe sıkıştırın","Düşük hızlı saha ve park alanı sürüşü yasal olarak emniyet kemeri gerektirmediği için kemeri takmayın"],"explanation":"Ticari sürücü, yolculuk ne kadar kısa veya yavaş olursa olsun, araç hareket halindeyken her zaman emniyet kemerini takmalıdır."},"414":{"q":"Kırsal iki şeritli bir karayolunda yük taşırken motorunuz gücünü kaybediyor ve araç sağ banket üzerine süzülerek duruyor. Dörtlü flaşörlerinizi yakıyorsunuz ve motor bölmesinden duman kokusu almaya başlıyorsunuz, bu yüzden dolu yangın söndürücünüzü kapıyorsunuz. Uyarı cihazlarını yerleştirmek için geriye yürümeye başlamadan önce, uyarı düzenini tamamlayabilmeniz için bu kamyonda yasal olarak bulundurmanız gereken diğer acil durum ekipmanı hangisidir?","options":["Yardım çağırmak ve diğer sürücüleri tehlikeye karşı uyarmak için yedek bir CB telsizi","Yola koyup yaklaşan trafiği uyarmak için yansıtıcı uyarı üçgenleri","Yüksek görünürlüklü güvenlik yeleği; kuralların bulundurmanızı zorunlu kıldığı tek cihaz budur","Sadece bir torba yol fişeği, çünkü flaşörleriniz yanınca üçgenler isteğe bağlı hale gelir"],"explanation":"Her ticari araç, durduğunda yola yerleştirip yaklaşan trafiği uyarmak için üç adet reflektörlü uyarı üçgeni taşımalıdır."},"415":{"q":"Vardiyanıza geldiniz ve başka bir sürücünün iki saat önce bıraktığı bir çekiciye biniyorsunuz. Sahadan çıkmadan önce frenlerin, farların ve lastiklerin yola elverişli olduğunu doğrulamak istiyorsunuz. Bu araçta daha önce tespit edilmiş arızalar hakkında size en güvenilir başlangıç tablosunu hangi tek eylem verir?","options":["Önceki sürücü açıkça arıza yapmadan seferini tamamladığı için aracı yola elverişli kabul etmek","Doğrudan bir yol testine geçmek, çünkü kamyonu birkaç mil sürmek gerçek bir sorunu hissetmenin en hızlı yoludur","Önceki sürücünün son araç muayene raporunu (DVIR) okumak ve belirtilen arızaların onarıldığının belgelendiğini doğrulamak","Sevkiyatı arayıp geçen hafta başka bir sürücünün bu araçtan şikayet edip etmediğini sormak"],"explanation":"Sürmeden önce önceki sürücünün son araç muayene raporunu (DVIR) inceleyin ve belirtilen arızaların onarıldığının onaylandığını doğrulayın."},"417":{"q":"Erken bir başlangıçtan sonra uzun ve tekdüze bir eyaletler arası yolculuğun üçüncü saatindesiniz. Hızınız siz fark etmeden düşmüş, son birkaç mili tam olarak hatırlamıyorsunuz ve kendinizi gözlerinizi ovuştururken yakalıyorsunuz. Güvenli sürüş kılavuzuna göre, güvenli sürmeye devam edemeyecek kadar uykulu hâle geldiğinizi en açık şekilde gösteren uyarı hangisidir?","options":["Elleriniz direksiyonda huzursuzca hareket ediyor ve aynalarınızı daha sık kontrol etme isteği duyuyorsunuz","Kendinizi son derece uyanık hissediyorsunuz ve dikkatiniz tamamen önünüzdeki yola kilitlenmiş durumda","Fren pedalındaki tepki süreniz her zamankinden daha hızlı ve daha keskin hissettiriyor","Göz kapaklarınız ağırlaşıyor ve düşünceleriniz sürekli yoldan uzaklaşıp dağılıyor"],"explanation":"Ağırlaşan, düşen göz kapakları ile dağılan düşünceler, tehlikeli sürücü yorgunluğunun klasik uyarı işaretleridir."},"418":{"q":"Saat gece 2 ve uzun bir seferin üçüncü saatindesiniz; göz kapaklarınız ağırlaşıyor, kendinizi banketin kenarına doğru kayarken yakalıyorsunuz ve son birkaç mili hatırlamıyorsunuz. Terminale hâlâ 100 milden fazla yolunuz var. Güvenli sürüş yeteneğinizi gerçekten hangi davranış geri kazandırır?","options":["Güvenli bir dinlenme alanına çekip devam etmeden önce uyumak veya dinlenmek","Camları açıp radyoyu sonuna kadar açarak uyanık kalmaya çalışmak","Büyük bir kahve almak için durup terminale ulaşmak için yola devam etmek","Takip mesafenizi artırıp daha dikkatli bir şekilde sürüşe devam etmek"],"explanation":"Uykululuğun tek gerçek çözümü uykudur; bu yüzden güvenli bir dinlenme alanına geçip devam etmeden önce dinlenin."},"419":{"q":"Saat sabahın 4:30'u ve önceki gece kötü uyuduktan sonra 9 saatlik bir sefere başlamak üzeresiniz. Kendinizi uykulu hissediyorsunuz. Bu uzun yolculukta yorgunluğun sizi bitkin halde araç kullanmaya itmesini önlemek için aşağıdakilerden hangisi EN AZ etkili yöntemdir?","options":["Seferlerinizi, sürüşün çoğunu normalde uyanık olduğunuz saatlerde yapacak şekilde planlamak","Uyumak yerine uyanık kalmak için büyük bir kahve içmek ve kabini soğuk, radyoyu yüksek sesli tutmak","Yolculuktan önce bir gece tam uyumak ve uykunuz geldiğinde durup dinlenmeyi planlamak","Uyku yapan ilaçlardan kaçınmak ve ağırlaşan göz kapakları ya da dağılan düşünceler gibi uyarı işaretlerini fark etmek"],"explanation":"Kahve, soğuk hava ve yüksek ses uykululuğu yalnızca geçici olarak maskeler ve yorgunluğun tek gerçek çözümü olan uykunun yerini asla tutmaz."},"421":{"q":"Hava 38 dereceyi (100 Fahrenheit) buluyor ve Batı Teksas boyunca uzun bir yolculuğun yaklaşık üçüncü saatindesiniz. Yükünüzü ve lastiklerinizi yol üzerinde zorunlu olarak kontrol etmek için kenara çekiyorsunuz. İki lastik şimdi, serin sabah yola çıkış öncesi kontrolünüzdekine göre belirgin şekilde daha yüksek basınç gösteriyor. EN olası neden nedir ve bu, karşılaştığınız risk hakkında ne söyler?","options":["Sıcak asfalt lastiklerin içindeki havayı soğutarak basıncı düşürdü ve patlak lastik riskini artırdı","Sıcak yoldan sızan zift lastiklere emildi, onlara ağırlık ve basınç kattı","Sıcaklık lastiklerin içindeki hava basıncını artırdı; bu da lastik patlaması (blow-out) riskini yükseltir","Bir sorun yok; lastik basıncı sıcakta doğal olarak düşer, bu yüzden yüksek okuma manometrenizin arızalı olduğu anlamına gelir"],"explanation":"Sıcak havada lastik içindeki hava genleşir ve basınç artar, bu da patlama riskini yükseltir."},"422":{"q":"Teksas'ta çok sıcak bir yaz gününün öğleden sonrası ve yüklü bir çekici-römork aracını sürerken önünüzdeki asfaltın yüzeyine parlak, koyu renkli zift lekelerinin 'sızdığını' fark ediyorsunuz. Bu sızan ziftin yola ne yapmasını beklemelisiniz ve bu, aracın kontrolü açısından neden önemlidir?","options":["Zift yapışkan olduğu için lastiklere ekstra tutuş sağlar, bu yüzden bu lekelerin üzerinden otoyol hızınızı güvenle koruyabilirsiniz.","Asıl tehlike sıcağın lastik basıncınızı sınırın üzerine çıkarmasıdır; bu nedenle ziftin kendisi yolun lastiklerin altında nasıl hissettirdiğini etkilemez.","Direksiyon (ön) aksı lastiklerinizde en az 4/32 inç diş derinliği kaldığı sürece tutuş üzerinde gerçek bir etkisi yoktur.","Yol yüzeyini kaygan hale getirir ve lastik tutuşunu azaltır; bu yüzden yavaşlamalı ve bu lekelerin üzerinde sert direksiyon ya da fren hareketinden kaçınmalısınız."],"explanation":"Yüzeye çıkan zift yolu kaygan yapar ve tutuşu azaltır, bu yüzden yavaşlayın ve o bölgelerde sert direksiyon veya frenden kaçının."},"423":{"q":"Teksas'ta temmuz ortasındasınız ve tam yüklü halde uzun bir yokuşu tırmanıyorsunuz. Kabin sıcak, motor zorlanıyor ve mahsur kalmadan ya da hasar vermeden önce motorun aşırı ısınmak üzere olduğuna dair erken bir uyarı almak istiyorsunuz. Bu uyarıyı hangi gösterge verir?","options":["Soğutma sıvısı sıcaklık göstergesi","Yağ basıncı göstergesi","Yakıt göstergesi","Devir göstergesi (motor devri/RPM)"],"explanation":"Soğutma suyu sıcaklık göstergesi, motor aşırı ısınmasının başlıca ve doğrudan göstergesidir ve harekete geçmek için en erken uyarıyı verir."},"424":{"q":"Şafaktan hemen sonra yüklü bir çekici-römork aracını iki şeritli bir karayolunda sürerken, önünüzdeki şerit çizgilerini zar zor seçebileceğiniz kadar yoğun bir sis bandına giriyorsunuz. Bir sonraki çıkışa ulaşana kadar yavaşça ilerlemeye devam etmeniz gerektiğine karar veriyorsunuz. Kendi görüşünüzü kötüleştirMEDEN yolu mümkün olduğunca iyi görmek için hangi far ayarı en iyi seçimdir?","options":["Uzun farları açın, çünkü yaklaşık 350-500 feet aydınlatır ve sisin içinden daha uzağı görmenizi sağlar","Kısa farları kullanın, çünkü uzun farlar sisten gözünüze geri yansır ve görüşünüzü azaltır","Tüm ön farları kapatın ve karşıdan gelen sürücülerin sizi fark etmesi için yalnızca dörtlü flaşörlere güvenin","Şimdi uzun far kullanın ve yalnızca karşıdan gelen bir araç 500 feet içine girdiğinde kısaltın"],"explanation":"Siste kısa farları kullanın, çünkü uzun farlar sisten yansıyıp parlamayı gözlerinize geri yansıtarak görüşü azaltır."},"425":{"q":"Gece, iki şeritli bir karayolunda yüklü bir çekici-römork kullanıyorsunuz ve o kadar yoğun bir sis bankasına giriyorsunuz ki artık şerit çizgilerini veya önünüzdeki aracın arka stop lambalarını göremiyorsunuz. Aşağıdakilerden hangisi alınacak EN GÜVENLİ önlemdir?","options":["Daha parlak ışık sisin içinde daha uzağı görmenize yardımcı olsun diye uzun farlara geçmek","Herhangi bir yerde durmak devam etmekten daha tehlikeli olduğu için kısa farlarla düşük hızda yola devam etmek","Yolu tamamen terk edip seyir şeritlerinden iyice uzaklaşmak, dörtlü flaşörlerinizi yakmak ve sisin dağılmasını beklemek","Hızı iyice düşürüp dörtlüleriniz yanık halde görüş düzelene kadar kendi şeridinizde durmak"],"explanation":"Sis görüşü engelleyecek kadar yoğunsa, tamamen yoldan çıkıp şeritlerden uzaklaşın, dörtlüleri yakın ve sisin dağılmasını bekleyin."},"426":{"q":"Rüzgârlı bir günde, otoyolun açık bir kesiminde sürekli yan rüzgâr esintileri varken sefere çıkarılıyorsunuz. Sizinle aynı anda dört çekici-römork aracı tesisten ayrılıyor. Rüzgârın bir aracı nasıl etkilediğini göz önünde bulundurursak, hangi sürücü yan rüzgâr nedeniyle şeritten dışarı itilmek ya da hatta devrilmek konusunda EN ÇOK endişelenmelidir?","options":["Tamamen yüklü bir tankerin sürücüsü, çünkü çalkalanan sıvı rüzgârı en büyük tehdit hâline getirir","Alçak, ağır ve dengeli dağıtılmış çelik yüklü bir açık kasa (flatbed) sürücüsü","Yasal ağırlık sınırında giden yüklü bir kapalı kasa römork sürücüsü, çünkü daha ağır araçlar daha fazla rüzgâr yakalar","Boş veya hafif yüklü, yüksek bir kapalı kasa römork sürücüsü, çünkü rüzgâra karşı koyacak az ağırlıkla birlikte geniş bir yüzey sunar"],"explanation":"Boş ya da hafif yüklü yüksek kapalı dorse, yan rüzgârda en riskli olandır çünkü rüzgâra direnecek ağırlığı az olan geniş bir yüzey sunar."},"427":{"q":"Teksas'ta kırsal, iki şeritli bir karayolunda yüklü bir katar aracı kullanıyorsunuz ve geyiklerin ve diğer büyük hayvanların yola fırlama olasılığının en yüksek olduğu koşullarda en az zamanı geçirecek şekilde yolculuğunuzu planlamak istiyorsunuz. Hayvan geçişleri açısından en yüksek dikkat seviyesini günün hangi bölümü gerektirir?","options":["Şafak ve alacakaranlıktaki az ışıklı dönemler","Hayvanların yiyecek aradığı, öğlen vakti civarındaki günün ortası","Güneş tamamen yükseldikten sonraki sabahın geç saatleri","Günün en sıcak bölümü olan öğleden sonranın ortası"],"explanation":"Geyikler ve büyük hayvanlar en çok şafak ve alacakaranlıkta hareketlidir; bu loş ışıklı saatlerde sürücünün görüşü de en zayıftır."},"429":{"q":"Yüklü bir çekici-römork aracını orta yoğunluktaki trafikte, işlek dört şeritli bir otoyolda kullanıyorsunuz. Sağ banketteki parlak ve hareketli dijital reklam panosu, yanından geçerken gözlerinizi birkaç saniye boyunca kendisine kilitliyor. Bu sabit bakışın hangi sonucu, bir CDL sürücüsünün fark etmesi gereken EN ciddi güvenlik tehlikesidir?","options":["Gözleriniz parlamaya alışır ve bir an için gece görüşünüzü kaybedersiniz","Etrafı taramayı bırakır ve görüş alanınızın diğer bölgelerinde gelişen tehlikeleri fark edemezsiniz","Bilinçsizce hızınızı trafik akışının çok altına düşürür ve arkanızdaki araçları engellersiniz","Panoya o kadar keskin odaklanırsınız ki aslında önünüzdeki yolu daha net görürsünüz"],"explanation":"Tek bir nesneye takılıp kalmak gözlerinizin tarama yapmasını durdurur, böylece görüş alanınızın başka yerlerinde gelişen tehlikeler iş işten geçene kadar fark edilmez."},"430":{"q":"İki şeritli kırsal bir karayolunda yüklü bir çekici-römork aracı kullanıyorsunuz ve sizi hız sınırının 15 mil/sa altında tutan yavaş bir traktöre yetiştiniz. Sollamak istiyorsunuz, ama yol sürekli değişiyor. Aşağıdaki yerlerden hangisinde sollamaya kalkışmak EN AZ güvenli olur ve sizi büyük olasılıkla kafa kafaya çarpışma durumuna sokar?","options":["En az çeyrek mil boyunca karşı şeridin boş olduğunu net biçimde görebildiğiniz uzun, düz bir yolda","Hızınızın doğal olarak arttığı ve sollamayı hızla tamamlayabileceğiniz hafif bir inişte","İleride yolun büküldüğü veya yükselerek görüş alanından çıktığı bir tepe doruğuna ya da viraja yaklaşırken","Kesik orta çizgili ve görüş alanında karşıdan gelen araç bulunmayan düz bir kesimde"],"explanation":"Tepe noktasına ya da viraja yaklaşırken asla sollama yapmayın; yol görüş dışına yükseldiği veya kıvrıldığı için karşıdan gelen trafik gizli olabilir."},"431":{"q":"Yüklü çekici-dorseniz ile iki şeritli bir karayolunda gidiyorsunuz ve daha yavaş bir otomobili geçmeye başlıyorsunuz. Otomobilin yanına geldiğinizde, birkaç saniyedir otomobilin arka kapısıyla aynı hizada, tam sürücünün kör noktasında ilerlediğinizi fark ediyorsunuz. Bu manevrayı DPS'nin gerektirdiği kadar güvenli şekilde tamamlamak için ne yapmalısınız?","options":["Gazdan ayağınızı çekip otomobille aynı hizada kalın ki diğer sürücü siz öne geçmeden önce sizi fark etmek için bolca zaman bulsun","Karşıdan gelen trafik olmadığından emin olana kadar otomobilin yanında eşit hızda kalın, sonra kendi şeridinize geri dönün","Mevcut hızınızı koruyun ve hâlâ otomobilin yanındayken yavaşça kendi şeridinize doğru kayarak genel geçişi kısaltın","Gerekirse hızlanarak diğer sürücünün kör noktasından çıkın ve geçişi gecikmeden tamamlayın, ardından aracın yanında oyalanmadan kendi şeridinize geri dönün"],"explanation":"Sollamayı hızlıca tamamlayın ve diğer sürücünün kör noktasından çıkın, ardından yanında oyalanmadan şeridinize dönün."},"432":{"q":"İşaretli yaya geçidi bulunan bir kavşağa yaklaşıyorsunuz. Işık sizin için yeşil ve sağa dönmek istiyorsunuz, ancak bir yaya geçmek üzere olduğunuz yaya geçidine kaldırımdan inmiş durumda. Ne yapmalısınız?","options":["Yol verin ve yayanın geçişini tamamlamasına izin verin, çünkü işaretli yaya geçidindeki yayaların geçiş üstünlüğü vardır","Yeşil ışık size yaya karşısında geçiş üstünlüğü verdiği için dönüşünüzü yapın","Yayayı uyarmak için kornaya basın ve durmazsa dönmeye devam edin","Yalnızca yaya doğrudan sizin şeridinizdeyse durun, aksi halde hareketinize devam edin"],"explanation":"İşaretli yaya geçidinde yasal olarak bulunan yayalar her zaman geçiş üstünlüğüne sahiptir, bu yüzden dönüş yapan sürücü yeşil ışıkta bile yol vermelidir."},"433":{"q":"Çekici-römork aracınızı iki şeritli bir şehir caddesinde sürüyorsunuz ve önünüzde bir bisikletli, şeridinizin sağ kısmında ilerliyor. Trafik orta yoğunlukta ve bisikletlinin sola kaymak zorunda kalabileceği park halindeki araçların bulunduğu bir bölgeye yaklaşıyorsunuz. Bu bisikletliye nasıl davranmanız gerektiğini en iyi hangi davranış yansıtır?","options":["Hemen arkasında yakın durup uzun bir korna çalarak bisikletlinin banket tarafına çekilmesi gerektiğini bilmesini sağlamak","Bisikletliye başka bir araca davranır gibi davranmak, geçmeden önce tam alan ve güvenli bir mesafe bırakmak","Bisiklet bir arabadan çok daha az yer kapladığı için aynı şeritte sıkışarak geçmek","En sol şeride geçmek ve sokağın sonuna kadar orada kalmak"],"explanation":"Bisikletli, herhangi bir araç kadar yolu kullanma hakkına sahiptir, bu yüzden onu sıkıştırmak yerine tam yer ve güvenli bir geçiş mesafesi bırakın."},"434":{"q":"Yüklü bir çekici-dorse ile çok şeritli bir döner kavşağa yaklaşıyorsunuz. Trafik döner kavşağın içinde zaten dönüyor, solunuzda bir boşluk açılıyor ama o boşluğa hâlâ yaklaşan bir araç var. Kavşağa girmenin doğru yolu hangisidir?","options":["Sert şekilde hızlanıp yaklaşan araç giriş noktanıza ulaşmadan önce katılın, çünkü daha büyük araç geçiş üstünlüğüne sahiptir","Kavşağa girip içeri girdikten sonra tamamen durun, sonra çevrenizdeki tüm trafik dağılana kadar orada bekleyin","Döner kavşakta zaten dönmekte olan trafiğe yol verin ve yalnızca aracınızın tüm uzunluğu için yeterince büyük bir boşluk olduğunda girin","Hemen girin ve gerekirse en kısa yoldan çıkışınıza ulaşmak için akışa ters yönde ilerleyin"],"explanation":"Dönel kavşakta zaten dönmekte olan trafik geçiş üstünlüğüne sahiptir, bu yüzden ancak aracınızın tüm uzunluğuna yetecek kadar boşluk olduğunda girin."},"435":{"q":"Yirmi dakikadır aralıksız yağmur yağıyor ve zemin tamamen ıslak. Kuru yoldaki normal otoyol hızınızla gidiyor ve önünüzdeki araca her zamanki 6 saniyelik takip mesafenizi koruyorsunuz. Aynı yolu kuru zeminde sürmeye kıyasla, şu anda aracı kullanma şeklinizde dikkate almanız gereken EN önemli şey nedir?","options":["Durma açısından hiçbir şey değişmez; kamyonun frenleri aynı kuvveti uygular, bu yüzden normal kuru yol takip mesafeniz hâlâ yeterlidir","Islak yol algınızı yavaşlattığı için tepki mesafeniz artar, ancak frenler tuttuktan sonra gerçek fren mesafesi aynı kalır","Su filmi lastiklerin daha serbest dönmesini sağlayıp kamyonun sürtünmesini azalttığı için durma mesafesi çok daha kısalır","Azalan yol tutuşu fren mesafesini uzattığı için toplam durma mesafeniz uzar, bu yüzden yavaşlamalı ve takip mesafenizi artırmalısınız"],"explanation":"Islak zemin yol tutuşunu azaltıp fren mesafesini uzatarak toplam durma mesafesini artırır, bu yüzden hızınızı düşürün ve takip mesafenizi artırın."},"437":{"q":"Sefere çıkalı 90 dakika olmuşken sevkiyat görevlisi telsizle teslimat adresinizin değiştiğini ve GPS'inizde yeni bir rota gerektiğini bildiriyor. Trafik sakin ve otoyol hızında ilerliyorsunuz. Yeni varış noktasını girmenin EN güvenli yolu hangisidir?","options":["Yoldan çıkıp güvenli bir yerde park edebilecek duruma gelene kadar bekleyin, sonra tekrar harekete geçmeden önce yeni rotayı girip ayarlayın","Bir sonraki kırmızı ışıkta durduğunuzda yeni adresi girin, rota yüklenir yüklenmez hemen hareket edin","Cihazı direksiyona yakın alçak bir yere monte edip adresi orada yazın, böylece gözleriniz yola yakın kalsın","Sürüşe devam edip yeni varış noktasını yazarken bakışlarınızı GPS ile yol arasında gidip getirin"],"explanation":"GPS'i her zaman sürüşten önce ayarlayın, asla hareket hâlindeyken değil, bu yüzden yolun güvenli bir yerine çekilin, yeni rotayı girin ve sonra sürüşe devam edin."},"439":{"q":"Çekiciniz ve römorkunuz az önce bir çarpışmaya karıştı ve iki şeritli, bölünmemiş kırsal bir karayolunun bir kısmını kapatarak durdu. Diğer sürücüler her iki yönden de yaklaşıyor. Dörtlü flaşörlerinizi yaktıktan sonra, yaklaşan trafiği uyarmanın EN İYİ yolu nedir?","options":["Yalnızca dörtlü flaşörleri açık bırakmak, çünkü yasa kaza durumunda sadece flaşör ister","10 dakika içinde yansıtıcı uyarı üçgenlerinizi yerleştirin -- biri aracın yaklaşık 30 m (100 ft) arkasına, biri yaklaşık 30 m (100 ft) önüne ve biri aracın yaklaşık 3 m (10 ft) gerisine","Trafik şeridinde durup kollarınızı sallayarak sürücülerin sizi net görüp yavaşlamasını sağlamak","Yaklaşan tüm araçlar durana kadar kornaya aralıksız basmak"],"explanation":"Bölünmemiş bir yolda durduktan sonra 10 dakika içinde uyarı üçgenlerini aracın yaklaşık 30 m arkasına, 30 m önüne ve 3 m arkasına yerleştirin."},"441":{"q":"Kırsal iki şeritli bir karayolunda yüklü bir çekici-dorse ile saatte 60 mil hızla giderken, aynalarınızda bir kamyonetin birkaç mildir size çok yakın takip ettiğini fark ediyorsunuz. İleride trafik seyrek ve düzenli. Bu yakın takip eden sürücünün yarattığı tehlikeyi azaltmanın EN İYİ yolu hangisidir?","options":["Kamyonete geri çekilmesi için sinyal vermek ve bu kadar yakın takip etmesini caydırmak için frene birkaç kez hafifçe basmak","Hızınızı korumak ama şeridinizin sol kenarına yaklaşmak, böylece kamyonet sizi güvenle geçebilecek kadar ileriyi görebilsin","Önünüzdeki araçla aranızdaki takip mesafesini kademeli olarak artırmak, böylece sert fren yerine yumuşak bir şekilde yavaşlamak için fazladan yeriniz olsun","Hızlanarak kendinizle kamyonet arasında bir boşluk açmak, ta ki kamyonet tehlike oluşturacak kadar yakın olmayana dek"],"explanation":"Yakın takip edildiğinizde önünüzdeki mesafeyi artırın ki sert frenleme yerine yavaşça yavaşlayabilesiniz, böylece arkadaki sürücüye tepki için daha çok zaman tanırsınız."},"442":{"q":"Kuru, iki şeritli bir kara yolunda yüklü bir çekici-römork ile 55 mil/saat hızla giderken bir binek otomobil sizi çok yakından takip etmeye (sıkıştırmaya) başlıyor. Sürücü sabırsız ve açıkça yolundan çekilmenizi istiyor. Durumu daha da kötüleştirmeden, arkadan sıkıştıran bu sürücünün yarattığı tehlikeyi azaltmak istiyorsunuz. Aşağıdakilerden hangisi vereceğiniz EN KÖTÜ tepki olur?","options":["Arkadaki aracın güvenli bir boşluğu değerlendirip sonunda sollayabilmesi için sabit, düzenli bir hızda kalmak","Önünüzde tampon görevi görecek daha fazla boşluk açmak için gaz pedalını kademeli olarak bırakmak","Sağa yaklaşmak ve ani hareketlerden kaçınmak, böylece arkadan sıkıştıran sürücüye sizi geçmesi için yer açmak","Arkadan sıkıştıran aracdan uzaklaşmak ve aranızdaki mesafeyi artırmak için hızınızı artırmak"],"explanation":"Yakın takip edeni atlatmak için hızlanmak yanlıştır, çünkü o yine yakından takip ederken her iki aracın hızını ve durma mesafesini artırır."},"443":{"q":"Açık bir sabah, hava donma noktasının hemen altında ve kırsal bir karayolunda yük taşıyorsunuz. İleride yol sadece ıslak görünüyor, ancak bir nehri aşan uzun bir üst geçide yaklaşıyorsunuz. Üst geçidi nasıl geçeceğinizi EN ÇOK hangi ifade etkilemelidir?","options":["Üst geçit tablası, hem üstten hem alttan ısı kaybettiği için çevredeki yoldan daha önce donup buzlanabilir.","Üst geçit en son buzlanan yüzey olacağından, gerekirse sert fren yapmak için en güvenli yerdir.","Köprü ve üst geçit yüzeyleri yalnızca yazın, asfalttan zift sızdığında kayganlaşır.","Yaklaşım yolu beyaz değil de ıslak göründüğü sürece yükseltilmiş tablalar asla donmaz."],"explanation":"Köprüler ve üst geçitler hem üstten hem alttan ısı kaybettiği için yoldan önce donar, bu yüzden yol sadece ıslakken bunlar buzlu olabilir."},"444":{"q":"Serin ve nemli bir sonbahar sabahında, yüklü bir çekici-dorse aracını iki şeritli kırsal bir yolda kullanıyorsunuz. Bir virajdan çıkarken, önünüzdeki yol yüzeyinin her iki şeridi de kaplayan kalın bir ıslak ve dökülmüş yaprak tabakasıyla örtülü olduğunu görüyorsunuz. Bu yol kesimine nasıl yaklaşmanız gerektiğini en iyi hangi ifade açıklar?","options":["Yapraklar ıslak kum gibi tutuş sağlar, bu yüzden bu kesimde mevcut hızınızı güvenle koruyabilirsiniz.","Yaprakla kaplı yolu kaygan bir yüzey olarak kabul edin; gaz pedalından yavaşça ayağınızı çekin ve bu kesimi geçene kadar sert frenleme veya direksiyon hareketinden kaçının.","Yapraklar organik ve yumuşak olduğu için lastikleri yastıklar ve tutuş ya da durma mesafesi üzerinde gerçek bir etkisi yoktur.","Yapraklarda yalnızca ön (direksiyon aksı) lastikleri tutuşunu kaybeder, bu yüzden çeker tekerleklerle hafif frenleme sizi tamamen kontrolde tutar."],"explanation":"Islak yapraklar buz gibi kaygan, düşük tutuşlu bir tabaka oluşturur, bu yüzden gazdan ayağınızı çekin ve geçene kadar sert frenleme veya direksiyon hareketinden kaçının."},"445":{"q":"Hava sıfırın hemen altında ve güneş açıkken kırsal bir iki şeritli yolda araç kullanıyorsunuz. Açık, güneş alan asfalt kesimleri kuru görünüyor, ancak yol sürekli olarak ağaç gölgeliklerinin altından ve gölgede kalan yüksek kuzeye bakan şevlerin yanından geçiyor. Bu gölgeli kesimlerden birine yaklaşırken, gölgenin sakladığını beklemeniz gereken EN BÜYÜK tehlike nedir?","options":["Güneşte yumuşayıp yüzeyi kayganlaştıran, sızan zift","Trafiğin gölgeli çukurlara ittiği gevşek çakıl","Bir buz tabakası, çünkü güneşli kesimler kuru olsa da gölgeli asfalt hiç donma noktasının üzerine ısınmadı","Soğukta henüz tam kurumamış taze yol çizgi boyası"],"explanation":"Gölgeli yol yüzeyi doğrudan güneş ışığı almaz, bu yüzden güneşli kuru kesimler donma noktasının üzerine ısınsa bile oradaki nem donmuş kalır."},"446":{"q":"Sürekli yağan yağmurda, çekici-römork aracınızı ıslak otoyolda sürüyorsunuz. Bir dizi kamyon sol şeritten sizi geçiyor ve her biri geçerken ön camınıza yoğun bir yol suyu perdesi savuruyor. Bu su sıçramasının sizi ve güvenli sürüş yeteneğinizi nasıl etkilediğini düşündüğünüzde, ANA etkisini en iyi açıklayan tek ifade hangisidir?","options":["Fren kampanalarını soğutur, böylece bir sonraki yokuş aşağıda frenlere daha fazla güvenebilirsiniz","Lastik diş derinliğinizi artırır, ön lastiklerde 4/32 inç asgari sınırının üzerinde kalmanıza yardımcı olur","Yoldaki kiri yıkar, lastikleriniz ile asfalt arasındaki tutuşu iyileştirir","Görüşünüzü keserek sizi kısa süreliğine kör eder, bu yüzden yavaşlamalı ve takip mesafenizi artırmalısınız"],"explanation":"Yandan geçen kamyonların sıçrattığı su anlık olarak ön camınızı kaplar ve görüşü ciddi şekilde azaltır, bu yüzden yavaşlayın ve takip mesafenizi artırın."},"447":{"q":"53 feet uzunluğunda bir çekici-römork (TIR) kullanıyorsunuz ve şehir caddesinden dar bir ara sokağa keskin bir sağ dönüş yapmanız gerekiyor. Dönüşün iç (sağ) tarafında park etmiş bir araç ve bir bordür fark ediyorsunuz. Aks kayması (off-tracking) nedeniyle, aracı bu dönüşten geçirirken neyi planlamanız gerektiğini EN İYİ şekilde aşağıdakilerden hangisi açıklar?","options":["Römorkun arka tekerlekleri, ön tekerleklerin izlediği yolun içinden geçen bir yol izler; bu yüzden arka lastikler dönüşün iç tarafındaki bordüre çıkabilir veya park etmiş araca çarpabilir","Römorkun arka tekerlekleri ön tekerleklerin dışından daha geniş bir yol izler; bu yüzden römorkun arkası soldaki karşı yönden gelen trafiğe doğru savrulur","Ön ve arka tekerlekler tam olarak aynı yolu izler; bu yüzden direksiyon lastikleriniz bordürü geçerse römork tekerlekleri de geçer","Aks kayması yalnızca otoyol hızında önemlidir; bu yüzden bu düşük dönüş hızında dört tekerlek grubu da neredeyse aynı çizgiyi izler"],"explanation":"İç çekme nedeniyle uzun bir dorsenin arka tekerlekleri ön tekerleklerin iç tarafından geçer, bu yüzden arka lastiklerin iç kaldırıma veya araçlara çarpmaması için yeterince geniş dönün."},"448":{"q":"53 fitlik bir çekici-römork (tır) kullanıyorsunuz ve dar, iki şeritli bir sokaktan başka dar bir sokağa keskin bir sağa dönüş yapmanız gerekiyor. Römorkun arka tekerleklerinin, çekicinin ön tekerleklerinden daha kısa ve daha dar bir yol izlediğini (iz sapması / off-tracking) bildiğiniz için dönüşü dikkatlice planlamanız gerekir. Römorkun arka tekerlekleri kaldırıma çıkmadan bu sağa dönüşü güvenle tamamlamak için neyi hesaba katmalısınız?","options":["İz sapması nedeniyle römorkun arkası dışa savrulur, bu yüzden yalnızca dönüşün dış tarafında (solda) ek boşluk gerekir","İz sapması nedeniyle römorkun arka tekerlekleri çekicinin izlediği yolun iç tarafından keser, bu yüzden dönüşün iç tarafında ek alana ihtiyacınız vardır","İz sapması bu kadar keskin bir dönüşü etkilemez, bu yüzden hiçbir yönde ek alana gerek yoktur","Araç uzun olduğu için iç tarafta daha az alan gerekir, çünkü römork çekicinin tam arkasından düz gider"],"explanation":"İç çekme, dorsenin arka tekerleklerinin çekicinin izinden içeriye doğru kesmesine neden olur, bu yüzden dönüşün iç tarafında fazladan yer bırakın."},"449":{"q":"Çekici-dorse aracınızla yoğun bir otoyola giriş yapıyorsunuz ve küçük bir otomobil tam sağ aynanızın arkasında, artık onu hiç göremediğiniz bir yere girerek görüş alanınızdan kayboluyor. Şerit değiştirmeden önce, kamyonunuzun çevresindeki bu belirli bölgeyi nasıl doğru şekilde tanımlamalı ve değerlendirmelisiniz?","options":["Burası düşük tutuş bölgesidir, bu yüzden şeride geçmeden önce hafifçe fren yapmalıyım.","Burası bir tampon boşluktur ve diğer sürücülerin dorsemden uzak tutmakla yükümlü olduğu bir alandır.","Burası kör noktalarımdan biridir, ayrıca 'No-Zone' olarak da adlandırılır; diğer sürücüleri burada görmem zordur, bu yüzden şerit değiştirmeden önce dikkatlice kontrol etmeliyim.","Burası yalnızca dorse yüklüyken yüksek ağırlık merkezimin oluşturduğu tehlike bölgesidir."],"explanation":"Kamyonun çevresinde diğer sürücülerin görülmesinin zor olduğu alanlar, No-Zone denilen kör noktalardır ve şerit değiştirmeden önce dikkatle kontrol edilmelidir."},"450":{"q":"Çekici-römork aracınızla yoğun bir otoyola katılıyorsunuz. Az önce sağ yan aynanızda net şekilde gördüğünüz bir binek otomobil şimdi o aynadan tamamen kayboldu ve önünüzde de görünmüyor. Şerit değiştirmeye devam etmeden önce, bu kaybolma EN OLASI olarak ne anlama gelir?","options":["Otomobil hızlandı ve şimdi çok gerinizde, uzakta; bu yüzden şerit boştur","Otomobil sert fren yapıp sağ banket üzerine çekti ve tamamen yoldan çıktı","Aynanız ayardan kaçmıştır ve bir sonraki durağınızda yeniden ayarlanması gerekir","Otomobil, aynanızın artık gösteremediği, römorkunuzun yanındaki bir kör noktaya ('No-Zone') girmiştir"],"explanation":"Aynanızdan kaybolan bir araç büyük olasılıkla dorsenizin yanındaki kör noktaya (No-Zone) girmiştir, bu yüzden onu tekrar görene kadar asla şerit değiştirmeyin."},"451":{"q":"Dört şeritli bir otoyolda yüklü bir çekici-römork kullanıyorsunuz ve yavaş bir aracı geçmek için sağ şeritten sol şeride geçmeye karar veriyorsunuz. Hem düz hem de dışbükey (geniş açılı) aynalarınızı kontrol ediyor, temiz göründüklerini görüyor ve erkenden sinyal veriyorsunuz. Şeridi değiştirmeye başladığınızda sizin için EN BÜYÜK tehlike nerede bulunan bir araçtır?","options":["Aynalarınızın göstermediği bir bölge olan, römorkunuzun yanındaki kör noktada","En sol şeritte iki şerit ötede, dışbükey aynanızda kısmen görünen","Fren lambalarınızın görüldüğü, römorkunuzun tam arkasında","Kendi şeridinizde önünüzde, geçmek istediğiniz yavaş araç"],"explanation":"Büyük kamyonların yanlarında ve arkasında aynaların gösteremediği kör noktalar (No-Zone) vardır, bu yüzden şerit değiştirmeden önce başınızı çevirip kontrol etmelisiniz."},"453":{"q":"Bir dağ geçidinden geçen 400 millik bir sefer için terminalden ayrılmak üzeresiniz ve yola çıkmadan önce yolculuğu doğru şekilde planlamak istiyorsunuz. Sefer planlaması sırasında kontrol edilmesi EN önemli şey aşağıdakilerden hangisidir?","options":["Uzun yolculukta uyanık kalmak için en sevdiğiniz müzik listesinin indirilmiş olup olmadığı","Planladığınız güzergâh ve yol boyunca mevcut hava koşulları","Takip mesafenizin aracın her 10 fitlik uzunluğu için 1 saniye olacağı","Güzergâhınızdaki mola yerlerinin öğle yemeği için sevdiğiniz türde yemek sunup sunmadığı"],"explanation":"İyi seyahat planlaması, güzergâhınızı ve yol boyunca havayı önceden bilmek demektir; böylece kontrol edemeyeceğiniz koşullara göre vites, hız ve zamanlamayı seçebilirsiniz."},"454":{"q":"Hava sıfırın hemen altında, başlayan hafif yağmur güzergâhınızdaki köprüleri buzla kaplamaya başladı ve belirlenen hız sınırı saatte 55 mil. Trafik az ve zemin hâlâ yalnızca ıslak görünüyor. Texas DPS kurallarına göre, bu durumlardan hangisinde belirlenen sınırın ALTINDA bir hızla sürmeniz ZORUNLUDUR?","options":["İleride yol açık ve kuru olduğunda, çünkü açık bir şerit belirlenen 55 mili güvenle kullanmanıza izin verir","Etrafınızdaki trafik az olduğunda, çünkü daha az araç hızınızı düşürmek için daha az sebep demektir","Koşullar kötü olduğunda — şu an karşılaştığınız ıslak, donma noktasına yakın zemin ve buzlanma ihtimali olan köprüler gibi — çünkü güvenli hızı tabeladaki sayı değil, yol tutuşu ve görüş belirler","Programın gerisinde kaldığınızda, çünkü kötü havada acele etmek kaybedilen zamanı telafi etmenizi sağlar"],"explanation":"Güvenli hız, yazılı limit değil, yol tutuşu ve görüş tarafından belirlenir; bu yüzden buz ihtimali olan ıslak, donma noktasına yakın yollarda ve buzlu köprülerde hızınızı azaltın."},"455":{"q":"Kırsal bir otoyolda 55 mph hız sınırı olan bir yolda yüklü bir römork çekiyorsunuz. Soğuk bir çiseleme başladı ve zemin ıslaklıktan parlıyor. Kendinizi rahat hissediyorsunuz ve trafik az. Şu anda 55 mph hız sınırının size nasıl uygulandığını EN İYİ hangi ifade açıklar?","options":["55 mph sınırı hem üst hem de alt sınırdır, bu nedenle bu koşullarda çok daha düşük bir hıza inmek başlı başına bir ihlal olur","Kamyonunuz yüklü olduğu ve iyi yol tutuşu sağladığı için, ıslak zeminde 55 mph hız sınırı güvenli bir hedef hız olmaya devam eder","Belirlenen sınırlar yağmur için zaten yerleşik bir güvenlik payı içerir, bu yüzden yol tamamen su altında kalana kadar 55 mph uygun kalır","55 mph levhası yalnızca ideal koşullar için belirlenen azami hızdır, bu nedenle ıslak yolda güvenli hız belirlenen sınırın altındadır"],"explanation":"Yazılı hız limiti yalnızca ideal koşullar için yasal üst sınırdır, bu yüzden yol tutuşunun düştüğü ve durma mesafesinin arttığı ıslak yolda yazılı hızın altında sürün."},"456":{"q":"Yoğun saatlerde işlek bir eyaletler arası otoyolda yüklü bir römork çekiyorsunuz. Trafik sıkışık ama düzenli akıyor; araçlar sizi iki taraftan da sıkıştırıyor. Teslimata zamanında yetişmek istiyorsunuz ama durma mesafenizin uzun olduğunu da biliyorsunuz. Bu yoğun trafikte EN İYİ kontrolü ve en düşük kaza riskini hangi davranış sağlar?","options":["Akışa uyan sabit bir hız tutun ve durabilmek için önünüzde yeterli takip mesafesini koruyun","Kaybedilen zamanı telafi etmek için en hızlı ilerleyen boşluğu bulmak amacıyla sık sık şerit değiştirin","Başka araçlar boşluğunuza girmesin diye öndeki aracı çok yakından takip edin","Hızınızı trafik akışının belirgin biçimde altında tutmak için sert ve sık fren yapın"],"explanation":"Yoğun trafikte akışa uygun sabit bir hız tutun ve uzun durma mesafeniz için önünüzde yeterli boşluk bırakın."},"458":{"q":"Engebeli, iki şeritli ve refüjsüz bir karayolunda çekici-römork sürüyorsunuz. Yavaş giden bir tarım traktörüne yetişiyorsunuz ve onu geçmek istiyorsunuz, ancak ileride yol bir tepenin zirvesine çıkıyor ve karşıdan ne geldiğini göremiyorsunuz. Aşağıdakilerden hangisi geçişe BAŞLAMAMANIZ gereken durumu en iyi şekilde tanımlar?","options":["İleride uzun, açık ve düz bir yol olduğunda ve karşı şerit çeyrek mil boyunca boş olduğunda","Yol bir tepenin zirvesine ya da viraja çıktığında ve geçişi güvenli bir şekilde tamamlayacak kadar ileriyi göremediğinizde","İleride bol açık yol ve iyi görüş olduğunda ancak öndeki araç yavaş gittiğinde","Yalnızca karşıdan gelen bir araç zaten 500 fit içinde olduğunda ve uzun farlarını yakıp söndürdüğünde"],"explanation":"Tepe veya viraj görüşünüzü engellediğinde asla sollama yapmayın, çünkü karşı şeridin tüm manevra boyunca boş olup olmadığını göremezsiniz."},"459":{"q":"Dar ve tanımadığınız bir sahada römorkunuzu bir müşterinin yükleme rampasına yeni yanaştırdınız. Rampa kısmen römorkunuzun arkasında gizli, yakınında istiflenmiş paletler var ve aynalarınız aracın hemen arkasındaki alt birkaç metreyi göstermiyor. Geri vitese takmadan önce güvenli geri gitmek için İLK olarak ne yapmalısınız?","options":["Aynalara güvenerek yavaşça geri gitmeye başlayın, çünkü aynalar römorkun arkasındaki alanın en geniş ve en güvenilir görüşünü sağlar","Kornaya üç kez basın ve ardından sabit bir hızda geri gidin, korna seslerinin arkanızdaki yolda bulunan herkesi uyaracağına güvenin","Kabinden inip aracın arkasına yürüyerek hareket etmeden önce yolu, mesafeleri ve tüm kör noktaları inceleyin","Bir yaya veya forklift yolunuza girmeye fırsat bulamadan kör noktadan geçmek için hızlıca geri gidin"],"explanation":"Geri gitmeden önce daima inip bakın (G.O.A.L.); yolu, açıklıkları ve aynaların gösteremediği kör noktaları kontrol edin."},"460":{"q":"Dar bir yükleme sahasında yalnızsınız ve çekici-römorkunuzu yolcu (sağ) tarafına denk gelen bir rampaya geri geri sokmanız gerekiyor. Römorkun arkasını o sağ taraftaki rampaya doğru salınmak için direksiyonu sağa çevirmeye başlıyorsunuz. Direksiyon sağa kırılmış halde geri gitmeye başladığınız ilk anda, daha büyük bir düzeltme yapmadan önce, römorkun arkası ilk olarak hangi yöne hareket eder?","options":["Römorkun arkası direksiyonu çevirdiğiniz yönle aynı şekilde hemen sağa savrulur, böylece doğrudan rampaya doğru sürersiniz.","Römork çekiciyle aynı hizada düz geri gider ve ancak gaz verdiğinizde açılanmaya başlar.","Çekici iterken römorkun arkası rampa yaklaşımına doğru yukarı ve sağa tırmanır.","Römorkun arkası önce sola, yani direksiyonu çevirdiğiniz yönün tersine hareket eder; siz onu sağa almak için ters direksiyon kırana kadar."],"explanation":"Geri giderken römorkun arkası önce direksiyonun tersine gider; direksiyonu sağa çevirince arka önce sola kayar, sonra karşı yönde düzeltirsiniz."},"461":{"q":"Yoğun, üç şeritli bir otoyolda 53 ayaklık kapalı kasa bir dorse çekiyorsunuz ve yan şeride doğru kaymaya başlıyorsunuz. Aynalarınıza baktığınızda, sizinle aynı hızda yan yana giden iki aracı göremiyorsunuz. Kamyonun No-Zone (kör nokta) bölgelerine göre, bu araçlar şu anda büyük olasılıkla hangi tehlike bölgesinde gizleniyor?","options":["Dorsenin sağ ve sol yanları boyunca uzanan kör noktalarda","Kaputun görüşünüzü engellediği, kabinin tam önünde","Aynalarınızın ulaşamadığı, dorsenin tam arkasında","Dorsenin tavanının üstündeki bölgede, yukarıda"],"explanation":"Yanınızda giden araçlar, römorkun sağ ve sol kenarındaki yan kör nokta (No-Zone) bölgelerinde gizlenebilir; sağ taraf en büyüğüdür."},"462":{"q":"Yoğun, dört şeritli bir eyaletler arası otoyolda yüklü bir römork ile 60 mil/saat hızla gidiyorsunuz. Sağ şeritte arkanızda bir sıra araç birikmeye başladı ve birkaçının sollamaya hazırlandığını hissediyorsunuz. Aracınızın ARKASINDAKİ boşluğu doğru yönetmek ve bu araçlardan haberdar kalmak için ne yapmalısınız?","options":["Aynalarınızı kullanmayı bırakıp yalnızca çok ileriye odaklanın, çünkü arkanızdaki şey sürüşünüzü etkileyemez","Arkanızdan ve yanınızdan yaklaşan araçları takip etmek için düzenli olarak (yaklaşık her 5–8 saniyede bir) aynalarınıza bakın","Arkadaki araçlar geride kalsın ve boşluk kendiliğinden açılsın diye 60 mil/saatin epey üzerine hızlanın","Sıkı takip edenleri geri çekilmeye zorlamak ve arkanızda bir tampon oluşturmak için sık sık frene basın"],"explanation":"Arkanızdaki boşluğu kontrol edemezsiniz, bu yüzden aynalarınıza düzenli olarak, yaklaşık her 5–8 saniyede bir bakarak arkadan ve yandan yaklaşan araçları izleyin."},"463":{"q":"Yüklü bir çekici-dorse ile düz bir eyaletler arası otoyolda saatte 55 mil hızla giderken, çeyrek mil ileride şeritler boyunca fren ışıklarının dalga dalga yandığını ve trafik kümesinin size doğru sıkışmaya başladığını görüyorsunuz. Takip mesafesi kapanıyor. Bu gelişen durumda alanınızı ve aracın enerjisini EN İYİ yöneten tepki hangisidir?","options":["Hızınızı koruyup, yavaşlayan küme tamamen durmadan etrafından dolaşmak için aracı yan şeride doğru yöneltmek","Hemen sert ve kuvvetli fren yaparak hızı hızla düşürmek, çünkü saatte 55 milde durmak zaten yaklaşık 419 fit gerektirir","Gaz pedalından ayağınızı çekip takip mesafenizin yeniden açılmasına izin vermek, öndeki boşluk geliştikçe yalnızca gerektiğinde hafifçe fren yapmak","Şimdilik hızınızı korumak ve sizi tepki vermeye zorlayana kadar araç uzunluğunun her 10 fiti için en az bir saniyelik takip mesafesi bırakmak"],"explanation":"Önünüzdeki trafik yavaşladığında gazdan ayağınızı çekerek takip mesafenizin yeniden açılmasını sağlayın, yalnızca gerektiğinde yumuşakça frene basın."},"464":{"q":"Banketsiz, dar ve iki şeritli bir kırsal yolda fazla geniş bir yük taşıyorsunuz. Karşıdan gelen kamyonetler sürekli orta çizgiye yanaşıyor, sağdaki yol kenarı keskin biçimde aşağı düşüyor ve posta kutuları ile park etmiş araçlar şeride çok yakın duruyor. Geniş aracınızın burada yarattığı en büyük tehlikeyi yönetmek için dikkatinizi en çok nereye vermelisiniz?","options":["Ön tekerlekleriniz çukurlara ulaşmadan onları görebilmek için çok ileride yol yüzeyine","Alçak dallar ve havai hatları gözlemek için römorkun üst boşluğuna","Şasinin altında bir şeyin sürtünüp sürtünmediğini kontrol etmek için römorkun alt boşluğuna","Yanlardaki boşluğa, çünkü aracınızın genişliği karşıdan gelen trafikle, kenar düşüşüyle ve yol kenarındaki nesnelerle aranızda çok az açıklık bırakır"],"explanation":"Banketsiz dar yolda geniş bir araçla yan açıklığınıza en çok dikkat edin; karşıdan gelen trafik, yol kenarı düşüşü ve nesneler iki yandan da sıkıştırır."},"465":{"q":"Uzun bir teslimat seferini bitirip yol kenarındaki tartı istasyonunda duruyorsunuz. Bir memur sizden nefes testi yapmanızı istiyor. Yaklaşık bir saat önce akşam yemeğinde iki bira içtiniz, kendinizi tamamen ayık hissediyorsunuz ve eyaletinizde sıradan bir binek otomobil sürücüsü için sınırın 0,08 olduğunu biliyorsunuz. CDL aracınızı kullanırken diskalifiye edileceğiniz EN DÜŞÜK kandaki alkol konsantrasyonu (BAC) nedir?","options":["0,04 veya daha fazla","0,08 veya daha fazla","0,10 veya daha fazla","0,02 veya daha fazla"],"explanation":"Ticari araç kullanan bir CDL sürücüsü için yasal sınır, kandaki alkol oranının yüzde 0,04 veya üzeri olmasıdır; normal sürücülerin sınırının yarısıdır."},"466":{"q":"Ticari motorlu taşıtınızı (CMV) kullanırken bir yol kenarı denetiminde durduruldunuz ve memurun, kandaki alkol konsantrasyonunuzu ölçen bir teste tabi olmanızı isteyecek makul bir gerekçesi var. Yasal sınır olan %0,04'ün altında olduğunuzdan eminsiniz ve testin yanlış sonuç verebileceğinden endişelendiğiniz için memura testi reddetmeyi tercih ettiğinizi söylüyorsunuz. CDL kurallarına göre bu reddin sonucu nedir?","options":["Gerçek kan alkol seviyeniz %0,04'ün altında çıktığı sürece CDL belgenize hiçbir şey olmaz","CMV kullanmaktan men edilirsiniz; bu, testi geçemediğiniz durumla aynı şekilde işlem görür","Yalnızca küçük bir idari para cezası alırsınız ancak tüm sürüş ayrıcalıklarınızı korursunuz","İlk reddinizde yazılı bir uyarı alırsınız ve yalnızca tekrar reddederseniz cezalandırılırsınız"],"explanation":"Yasal olarak istenen alkol testini reddetmek, sizi ticari araç kullanmaktan men eder; bu, testi geçememekle aynı cezadır."},"467":{"q":"Gece boyu süren bir sefer sırasında yemekten sonra çekicinize dönerken yol kenarındaki bir kontrol noktasında bir trafik polisi sizi durdurur. Kimyasal test, kandaki alkol konsantrasyonunuzun, CDL sınırı olan %0,04'ün üzerinde, %0,06 olduğunu gösterir ve ticari aracı alkollü olarak kullanmaktan suçlu bulunursunuz. Bu, sicilinizdeki ilk böyle mahkumiyettir. Tehlikeli madde taşınmadığı varsayıldığında, CDL belgenizin geçersiz sayılacağı ASGARİ süre nedir?","options":["60 gün, ciddi trafik ihlali örüntüsü için kullanılan süreyle aynı","90 gün, seyir defteri sahteciliği için asgari hizmet dışı bırakma süresi","Bir yıllık ehliyet geçersizliği","Üç yıl, tehlikeli madde taşırken işlenen ilk ihlalle aynı"],"explanation":"Tehlikeli madde taşınmadığında, kanda 0,04% veya daha yüksek alkol oranıyla ticari araç kullanmaktan ilk mahkumiyet, CDL'nin en az bir yıl iptaliyle sonuçlanır."},"469":{"q":"Teksas DPS tartı istasyonunda yol kenarı denetimi için durduruldunuz. Görevli, ticari sürücü belgenizin (CDL) geçerli olduğunu ve seyir defterinizin düzgün olduğunu zaten doğruladı. Ardından, aracı her kullandığınızda yanınızda bulundurmanızı federal kuralların zorunlu kıldığı ve sürmeye fiziksel olarak uygun olduğunuzu kanıtlayan bir belge daha göstermenizi istiyor. Hangi belgeyi ona vermelisiniz?","options":["Zorunlu başlangıç düzeyi sürücü eğitimini tamamladığınızı kanıtlayan CDL eğitim okulu mezuniyet sertifikanız","Kamyonun yasal olarak tescilli ve yolda bulunmaya yetkili olduğunu kanıtlayan aracın ruhsat (tescil) belgesi","Kimliğinizi ve ticari belgeye sahip olma yasal hakkınızı kanıtlayan asıl doğum belgeniz","Şu anda ticari araç kullanmaya fiziksel olarak uygun olduğunuzu kanıtlayan tıbbi muayene sertifikanız (sağlık kartı)"],"explanation":"CDL'nizle birlikte tıbbi muayene sertifikanızı (med kartı) taşımanız gerekir, çünkü bu belge ticari araç kullanmaya şu anda fiziksel olarak uygun olduğunuzu kanıtlar."},"470":{"q":"Dört şeritli, refüjle ayrılmış bir otoyolda programınızın yaklaşık 30 dakika gerisindesiniz. Önünüzdeki sürücü istediğinizden daha yavaş gidiyor ve seçeneklerinizi tartıyorsunuz. Texas DPS kurallarına göre, aşağıdaki davranışlardan hangisi CDL belgenizi tehlikeye atabilecek BÜYÜK bir trafik ihlali sayılır?","options":["Yavaş aracı güvenli bir mesafeden takip etmek ve yasal bir geçiş fırsatı beklemek","Şerit değiştirmeden önce aynalarınızı kontrol etmek için kısa süreliğine asgari hız sınırının altına düşmek","Trafikte agresif biçimde slalom yaparak ve sıkı takip ederek yavaş sürücüyü kenara çekmeye zorlamak","Şerit değişikliğinizi, hemen önünüzdeki aracın beklediğinden biraz daha erken sinyalle bildirmek"],"explanation":"Trafikte agresif şerit değiştirip başka bir sürücüyü zorlamak için yakın takip yapmak pervasız sürüştür; bu, CDL diskalifiyesine yol açabilen büyük bir ihlaldir."},"471":{"q":"Çekiciniz ve dorseniz, düz, dümdüz, bölünmemiş iki şeritli bir karayolunun sağ banketinde stop etti. Dörtlü flaşörleri açıp, 10 dakikalık süre dolmadan yansıtıcı üçgenleri yerleştirmek için alıyorsunuz. İLK (en yakın) üçgeni koymak için aracın arkasına doğru yürürken, üçgeni araçtan yaklaşık ne kadar geriye koymalısınız?","options":["Aracın yaklaşık 10 fit gerisine, trafik tarafına","Aracın yaklaşık 100 fit gerisine","Aracın yaklaşık 200 fit gerisine","Doğrudan arka tamponun dibine, araca değecek şekilde"],"explanation":"En yakın uyarı üçgeni, aracın hemen arkasını işaretlemek için trafik tarafında aracın yaklaşık 3 metre arkasına yerleştirilir."},"472":{"q":"Bir teker rulmanı arıza yapar ve çekici-dorsenizi düz, dümdüz, bölünmemiş iki şeritli bir karayolunun banketine doğru kaydırarak durdurursunuz. Dörtlü flaşörü açtıktan sonra acil durum üçgenlerinizi alıp yaklaşan trafiğe doğru yerleştirmeye başlarsınız. İlk üçgeni doğru şekilde aracın 10 fit arkasına koyarsınız. Bu tür bir yolda aracınızın arkasına koyduğunuz İKİNCİ üçgen, araçtan yaklaşık ne kadar geriye yerleştirilmelidir?","options":["Yaklaşık 200 fit geriye, üçüncüsü de ondan 200 fit daha ileriye","Aracın yaklaşık 100 fit arkasına","Aracın yaklaşık 50 fit arkasına","Aracın yaklaşık 100 fit önüne, karşı yönden gelen şeride"],"explanation":"İki şeritli veya bölünmemiş bir yolda, trafik her iki yönden de yaklaşabileceği için ikinci üçgen aracın yaklaşık 30 metre arkasına yerleştirilir."},"473":{"q":"Çekici-römork katarınız, görüşün iyi olduğu düz, düz zeminli, BÖLÜNMÜŞ bir karayolunun (karşı yönü bir refüjle ayrılan tek yönlü bir taşıt yolu) sağ şeridinde arıza yaptı. Dörtlü flaşörleri açıp acil durum üçgeni setinizi alıyorsunuz. Aracın arkasından EN UZAĞA yerleştirilmesi gereken üçgeni koymak için geri yürürken, onu yaklaşık ne kadar geriye koymalısınız?","options":["Yaklaşık 100 fit geriye, çünkü orta üçgen oraya konur","Yaklaşık yarım mil geriye, hızlı trafiğe mümkün olan en fazla uyarıyı vermek için","Aracın yaklaşık 200 fit gerisine","Yaklaşık 10 fit geriye, tam arka tamponun hemen ardına"],"explanation":"Tek yönlü veya bölünmüş bir karayolunda üç üçgenin tümü aracın arkasına yerleştirilir; en uzaktaki, yaklaşan trafiğe doğru yaklaşık 60 metre geriye konur."},"474":{"q":"Tek yönlü (bölünmüş) bir karayolunun sağ banketinde, bir tepenin doruğunu hemen geçtikten sonra durdunuz; arkanızdan gelen araçlar aracınızı son ana kadar göremiyor. Dörtlü flaşörlerinizi yakıp üç yansıtıcı üçgeni yerleştirmeye başlıyorsunuz. Yaklaşan trafiğe karşı arkanızı koruyan en uzaktaki üçgeni koyma sırası geldiğinde, tepenin görüşü engellemesini hesaba katmak için ne yapmalısınız?","options":["Üç üçgeni de kamyonun 10 fit yakınında tutun ki bir arada ve birlikte görünür kalsınlar","Uzak üçgeni, düz ve açık bir kesimdeki gibi tam 200 fit geriye koyun, çünkü bu mesafe yasal standarttır","Uzak üçgeni hiç koymayın ve tepede üçgenden daha parlak olan dörtlü flaşörlerinize güvenin","Uzak üçgeni normal yeri olan 200 fitin ötesine (500 fite kadar) taşıyın ki tepeyi aşan sürücüler tepki vermek için yeterince uyarı alsın"],"explanation":"Görüşü engelleyen bir tepe veya virajın yakınında, yaklaşan sürücülerin yeterli uyarı alması için en uzaktaki üçgeni normal yerinin ötesine (150 metreye kadar) geriye taşıyın."},"475":{"q":"Bir dinlenme tesisinde araç öncesi muayeneniz sırasında duman kokusu alıyorsunuz ve römorkunuzun arka kapılarının yakınında, atılmış karton kutular, ambalaj kâğıdı ve bir yığın nakliye battaniyesinde başlamış küçük bir yangın buluyorsunuz. Harekete geçmeden önce yangın söndürücünüzü alıp sınıfını kontrol ediyorsunuz. Burada yanan malzeme türü için özel olarak hangi sınıf söndürücü tasarlanmıştır?","options":["A Sınıfı, ahşap, kâğıt ve kumaş gibi sıradan yanıcı maddeler için derecelendirilmiştir","B Sınıfı, yakıt, yağ ve gres gibi yanan sıvılar için derecelendirilmiştir","C Sınıfı, elektrik akımı olan kablolar ve enerjili ekipmandaki yangınlar için derecelendirilmiştir","D Sınıfı, magnezyum ve titanyum gibi yanıcı metaller için derecelendirilmiştir"],"explanation":"Ahşap, kâğıt ve kumaş gibi sıradan yanıcı maddelerdeki yangınlar A sınıfı yangın söndürücü ile söndürülür."},"476":{"q":"Sefer öncesi kontrolünüzde kabininize monte edilmiş yangın söndürücüyü kontrol ediyorsunuz. Dizel yakıt varilleri taşıyorsunuz ve söndürücünün bu yük için en olası yangınla gerçekten başa çıkabileceğinden emin olmak istiyorsunuz. Küçük bir yakıt sızıntısı varillerin yanında tutuşuyor. Bu yanan sıvı yangınıyla mücadele etmek için hangi sınıf yangın söndürücü uygundur?","options":["A sınıfı söndürücü, çünkü en yaygın türdür ve römorktaki ahşap paletlerde ve kâğıt irsaliyelerde de işe yarar","B sınıfı söndürücü, çünkü yakıt, yağ ve gres gibi yanan sıvılar için uygundur","C sınıfı söndürücü, çünkü yangın kamyonun elektrik ve akü sisteminin yakınında başladı","D sınıfı söndürücü, çünkü yanıcı kumaş, bez ve atölye paçavralarını içeren yangınlar içindir"],"explanation":"Yakıt, yağ ve gres gibi yanıcı sıvılardaki yangınlar B sınıfı yangın söndürücü ile söndürülür."},"477":{"q":"Sefer öncesi kontrolünüz sırasında gösterge panelinin yakınında sıcak bir koku alıyorsunuz ve çekicinizin elektrik sisteminin gerilim altındaki kablo panosunun arkasından duman geldiğini fark ediyorsunuz. Kabinde takılı yangın söndürücüye uzanıyorsunuz. Bu yangınla güvenli bir şekilde mücadele etmek için hangi sınıf söndürücüyü kullanmalısınız?","options":["A sınıfı söndürücü, çünkü pano çevresindeki ahşap ve kağıt kaplama için tasarlanmıştır","B sınıfı söndürücü, çünkü çoğu kamyon yangınına neden olan yanıcı sıvılar için tasarlanmıştır","C sınıfı söndürücü, çünkü gerilim altındaki elektrik ekipmanındaki yangınlar için tasarlanmıştır","Önce akü şalterini kapatırsanız her sınıf işe yarar"],"explanation":"Elektrik akımı olan ekipmandaki yangınlar C sınıfı söndürücü gerektirir, çünkü iletken olmayan maddesi akımı kullanıcıya geri iletmez."},"478":{"q":"Hava donma noktasının hemen altında ve buz tutmuş, camlaşmış bir rampada duruştan kalkış yapıyorsunuz. Kamyonun sarsıldığını ve devir göstergesinin fırladığını hissediyorsunuz; çekiş tekerlekleri araç ileri gitmeden boşa dönmeye başlıyor. Harekete geçmek ve çekişi yeniden kazanmak için EN İYİ hareket nedir?","options":["Boşa dönen tekerlekleri buzdan geçirmek için gaz pedalına daha sert basın","Çekiş tekerleklerinin zemine tutunmasını sağlamak için fren pedalını hızla pompalayın","Lastik kenarlarının tutunma bulması için direksiyonu hızla saǧa sola çevirin","Gazdan ayağınızı çekin ki çekiş tekerlekleri yavaşlayıp yeniden çekiş kazansın"],"explanation":"Çekiş tekerleği kaymasında, gazdan ayağınızı çekerek gücü azaltın, böylece dönen tekerlekler araç hızına yavaşlar ve yol tutuşunu yeniden kazanır."},"479":{"q":"Uzun bir yokuştan inerken römorkunuzun ikiz lastiklerinden birinden önce duman, ardından alev çıktığını fark ediyorsunuz. Banketta güvenli bir şekilde durup uyarı üçgenlerinizi yerleştiriyor ve malzemelerinizi alıyorsunuz. Lastik aktif olarak yanarken, ateşi soğutmanın ve söndürmenin EN İYİ yolu aşağıdakilerden hangisidir?","options":["Üzerine bol su dökün, çünkü su yanan lastiği soğutur","Alevlerin üzerine doğrudan kuru kum atarak boğun","Banket boyunca yavaşça ilerleyerek hava akımının lastiği soğutmasını bekleyin","Lastik yüzeyini oksijenden yalıtmak için motor yağı sıkın"],"explanation":"Yanan bir lastiği bol suyla söndürün, çünkü su ısının biriktiği lastik ve karkası soğutarak yeniden alevlenmeyi önler."},"480":{"q":"Soğuk bir sabah ve sürüş öncesi kontrolden önce motoru ısıtmak için kamyonunuzu kapalı bir yükleme rampasında rölantide bırakıyorsunuz. Birkaç dakika sonra başınız dönmeye ve ağrımaya başlıyor, ancak havada görsel veya kokusal olarak olağandışı hiçbir şey fark etmiyorsunuz. Karbon monoksitin nasıl davrandığına göre, bu belirtiler başlamadan önce neredeyse hiç uyarı almamanızın EN olası nedeni nedir?","options":["Gaz önce keskin, tatlı bir koku verirdi, bu yüzden egzoz sistemi sızdırmaz olmalı ve sebep bu değildir","Karbon monoksit renksiz ve kokusuzdur, bu yüzden duyularınız sizi etkilemeden önce onu algılayamaz","Gaz biriktikçe görünür parlak kırmızıya döner, ancak loş rampa aydınlatması onu sizden gizledi","Karbon monoksit havadan ağırdır ve zemine yakın kalır, bu yüzden ayağa kalkmak sizi zamanında uyarırdı"],"explanation":"Karbon monoksit renksiz ve kokusuzdur, bu yüzden kapalı alanlarda sizi etkilemeden önce duyularınızla onu fark edemezsiniz."},"481":{"q":"Yüklü bir çekici-dorse kombinasyonuyla kırsal bir Teksas otoyolunda ilerlerken, ileride \"AÇIK\" tabelası yanan bir kantar istasyonu görüyorsunuz ve birkaç binek araç yavaşlamadan oradan geçiyor. Yorgunsunuz ve teslimat noktanıza sadece birkaç mil uzaktasınız. Hangi davranış yasal olarak doğrudur?","options":["Binek araçların yaptığı gibi geçip gitmek, çünkü istasyon bugün belli ki yalnızca binek araçları denetliyor","İstasyonu isteğe bağlı saymak ve yalnızca bir memur sizi kenara çağırırsa veya brüt ağırlığınız size yüksek gelirse girmek","Açık kantar istasyonuna girmek, çünkü kamyonların geçtikleri her açık kantar istasyonunda yasal olarak durması zorunludur","Son teslimat noktanıza birkaç mil kala olduğunuz ve yükünüz zaten sabitlenmiş olduğu için istasyonu atlamak"],"explanation":"Kamyonlar, yorgunluk, yük veya otomobillerin davranışından bağımsız olarak, geçtikleri açık her tartı istasyonunda kanunen durmak zorundadır."},"482":{"q":"Yol kenarındaki kantarda araç öncesi muayene sırasında bir Texas DPS müfettişi çekicinizde bir fren arızası tespit eder, tutanak tutar ve araca hizmet dışı (out-of-service, OOS) emri koyar. Tamirhane 8 mil uzaklıkta ve teslimat zaman aralığınız bir saat sonra kapanıyor. Hangi davranış yasal olarak doğrudur?","options":["Yük zaman hassas olduğu için, düşük hızda doğrudan tamirhaneye olan 8 mili sürebilirsiniz","55 mil/saatin altında kalıp yalnızca hafif ve dengeli fren kullandığınız sürece rotanıza devam edebilirsiniz","Yakıt deposunu doldurup hava freni göstergesi tam basıncı gösterdiğinde sürebilirsiniz","Arıza giderilip emir kaldırılana kadar aracı hiç süremezsiniz"],"explanation":"Hizmet dışı bırakma emri, arıza onarılıp emir kaldırılana kadar aracı umumi yolda kullanmanızı yasal olarak yasaklar."},"483":{"q":"Bir kantar istasyonundaki yol kenarı denetçisi, ELD cihazınızdaki çalışma durumu kayıtlarınızı (records of duty status) incelemek istiyor. Sevkiyat görevliniz, bu cihazın esasen vergi dairesini ve filonuzun muhasebe departmanını tatmin etmek için var olduğunu iddia ediyor. Bu denetim için çalışma durumu kayıtlarınızın gerçekte neyi belgelemek üzere tasarlandığını en iyi hangi ifade açıklar?","options":["Memurun yasal çalışma saati (hours of service) sınırları içinde olduğunuzu doğrulayabilmesi için sürdüğünüz ve görevde olduğunuz saat sayısı","Memurun IFTA vergi beyanınızın doğru olduğunu doğrulayabilmesi için eyalet bazında yakıt alımlarınız ve kat ettiğiniz mesafe","Memurun zorunlu muayenelerin yapıldığını doğrulayabilmesi için aracın bakım ve onarım geçmişi","Memurun yükünüzü her 150 milde bir yeniden kontrol ettiğinizi doğrulayabilmesi için yük ağırlığı ve emniyet kontrolleri"],"explanation":"Görev durumu kayıtları, sürüş ve görev saatlerinizi belgeleyerek bir denetçinin yasal hizmet saati sınırları içinde olduğunuzu doğrulamasını sağlar."},"484":{"q":"Yüklü çekici-römork aracınızla otoyola katılıyorsunuz ve hızlı bir şekilde hızlanmak istiyorsunuz. Takometre ibresi hızla yükseliyor ve şimdi kırmızı bölgenin tepesine değiyor, ancak trafiğe ayak uydurmak için daha fazla güç istiyorsunuz. Dizel motoru korumak için aşağıdakilerden hangisini YAPMAMALISINIZ?","options":["Motordan yüksek güç talep etmeden önce rölantide ısınmasına izin vermek","Daha fazla hızlanma elde etmek için motoru takometredeki kırmızı çizginin ötesine zorlamak","Gaz vermeden önce motor devri kırmızı bölgenin altına düşsün diye üst vitese geçmek","Hızı kademeli olarak artırmak için motorun normal çalışma devir aralığını kullanmak"],"explanation":"Motoru asla takometredeki kırmızı çizginin ötesine zorlamayın, çünkü kırmızı çizgi güvenli azami devri gösterir ve aşırı devir ciddi motor hasarına yol açar."},"485":{"q":"Yüklü çekici-dorsenizi bir müşterinin yükleme rampasında hafif bir iniş eğiminde park ediyor, el frenini çekiyor ve boşaltmaya başlamak için kabinden iniyorsunuz. Zemin tam düz değil ve bir süre kabinin dışında olacaksınız. Bu koşullarda, kamyonu gözetimsiz bırakmadan önceki tek en doğru uygulama hangisidir?","options":["Ek bir şey gerekmez çünkü yaylı el freni yüklü dorseyi her eğimde süresiz olarak tutar","Takoz koymak yerine vitesi düşük bir vitese almak, çünkü vitesin takılı olması eğimde takozların yerini tamamen alır","Tekerlekleri takozlayın, çünkü kamyonun engebeli ve eğimli zeminde kayıp yuvarlanma ihtimali vardır","Eğim yalnızca hafif olduğundan takozları atlayın; takozlar yalnızca dik dağ inişlerinde gereklidir"],"explanation":"Kamyonun yuvarlanma ihtimali olduğu her durumda, örneğin yüklü ve gözetimsiz bırakıldığı eğimli, engebeli zeminde, tekerlekleri takozlayın."},"486":{"q":"Bir teslimatı bitirdiniz ve çekici-dorseyi kırsal bir banket üzerinde burnu YOKUŞ AŞAĞI bakacak şekilde park etmeniz gerekiyor. Yolun bu kesiminde bordür (kaldırım kenarı) YOK. Aracı terk etmeye hazırlanırken, aracın yuvarlanması durumunda trafik şeridine değil, geçen trafikten UZAĞA gitmesi için ön (direksiyon dingili) tekerlekleri nasıl konumlandırmalısınız?","options":["Ön tekerlekleri düz bırakın, çünkü inişte tutma işini el freni ve takozlar yapar","Ön tekerlekleri sert şekilde SOLA çevirin, tıpkı bordüre dayalı yokuş yukarı park ederken yaptığınız gibi","Tekerlekleri düz tutun ve bunu ancak direksiyon dingili lastik diş derinliğinin en az 4/32 inç olduğunu kontrol ettikten sonra yapın","Ön tekerlekleri yolun kenarına doğru çevirin, böylece yuvarlanan araç asfaltı terk edip trafikten uzaklaşsın"],"explanation":"Bordür olmayan bir yokuş aşağı park ederken ön tekerlekleri yolun kenarına doğru çevirin ki yuvarlanan araç trafikten uzağa, yol dışına kaysın."},"487":{"q":"Araç öncesi kontrolünüz sırasında hava donma noktasının hemen altında ve çekicinizin basamaklarıyla tutamaklarının ince bir buz tabakası ve yol kiriyle kaplandığını fark ediyorsunuz. Federal ve Teksas yönetmelikleri bu parçaları kontrol etmenizi zorunlu kılar. El kitabına göre, sürüşten önce basamakların ve tutamakların durumunu kontrol etmenizin BİRİNCİL nedeni nedir?","options":["Kabine güvenli bir şekilde inip binebilmeniz için, özellikle yüzeyler kaygan olduğunda üç temas noktasını koruyarak","Kabin yapısının GVWR plakasında belirtilen kabul edilen kargo ağırlığını taşıyabileceğini doğrulayabilmeniz için","Şasi ve montaj braketlerinin çatlamadığını doğrulayabilmeniz için, aksi halde araç hizmet dışı bırakılır","Botlarınızı temiz tutup kabin tabanına ve pedallara çamur taşımamanız için"],"explanation":"Sağlam ve bütün basamaklar ile tutamaçlar, yüzeyler kaygan olduğunda üç temas noktasını koruyarak kabine güvenle inip binmenizi sağlar."},"488":{"q":"Vardiyanızın başındasınız ve sefer öncesi kontrolünüzü tamamlıyorsunuz. Bir DOT memuru bugünkü güzergahınızın herhangi bir noktasında sizi yol kenarı denetiminde durdurup araç tescil belgenizi ve sigorta kanıtınızı görmek isteyebilir. Kurallara uygun ve bu denetime hazır olmak için bu belgeler şu anda nerede bulunmalıdır?","options":["Yolda kaybolmamaları veya çalınmamaları için evinizdeki ya da terminal ofisindeki bir dolapta dosyalanmış halde","Yol kenarı denetimi sırasında herhangi bir memura gösterebilmeniz için sizinle birlikte aracın içinde","Eyaletin resmi kopyayı kayıtlarında tutması için posta yoluyla Texas DPS'e gönderilmiş halde","Çevrimiçi bir eyalet portalına yüklenmiş halde, çünkü dijital kayıt kağıt kopya taşıma ihtiyacının yerini alır"],"explanation":"Ruhsatınızı ve sigorta belgenizi araç içinde tutun ki herhangi bir yol kenarı denetiminde veya durdurmada bir memura gösterebilesiniz."},"489":{"q":"Yüklü çekici-dorse aracınızla gece kırsal bir kavşağa yaklaşırken, sizin yönünüzdeki trafik sinyalinin kırmızı yanıp söndüğünü, kesişen trafiğin ise sarı yanıp söndüğünü görüyorsunuz. Bu sinyallerin yasal olarak nasıl farklılaştığını göz önünde bulundurarak, doğru hareket nedir?","options":["Yavaşlayıp durmadan dikkatlice geçmek, çünkü yanıp sönen sinyal sadece dikkatli olmanız için uyarır","Hızınızı korumak ama yol vermeye hazır olmak, çünkü sarı yanıp sönen kesişen trafik size yol vermek zorundadır","Dur işaretinde olduğu gibi tamamen durmak, ardından yalnızca kavşak boş olduğunda ilerlemek","Bunu arızalı bir sinyal sayıp kısaca durmak ve sabit kırmızıya dönmeden geçmek"],"explanation":"Yanıp sönen kırmızı ışık dur işaretiyle aynı anlama gelir: tamamen durun, yol verin ve ancak kavşak boşaldığında ilerleyin."},"490":{"q":"Gece yoğun bir kavşağa yaklaşırken, şeridinizin üzerindeki trafik sinyali sürekli yanıp sönen sarıya geçerken, yan sokak yanıp sönen kırmızıya geçiyor. Yan sokakta girmek için bekleyen birkaç araç var. Bu kavşaktan geçmenin doğru yolu nedir?","options":["Yanıp sönen sarıyı tam olarak sabit kırmızı gibi değerlendirin: tamamen durun, ardından kavşak boşaldığında geçin","Otoyol hızınızı koruyun çünkü yanıp sönen sarı size mutlak geçiş üstünlüğü verir ve yan trafik durmaya devam etmek zorundadır","Durun ve önce yan sokaktaki sürücülerin geçmesini bekleyin çünkü onların yanıp sönen kırmızısı, onlara yol veren dört yönlü dur gibi işler","Hızınızı azaltın ve kavşaktan dikkatle geçin, yanıp sönen kırmızıda duran yan trafiğe karşı tetikte kalın"],"explanation":"Yanıp sönen sarı ışık durma değil dikkat işaretidir: yavaşlayın ve kavşaktan dikkatlice geçin."},"491":{"q":"Yüklü çekici-yarı römork aracınızla yoğun bir kavşağa yaklaşırken, karşınızdaki trafik ışığının belli bir elektrik kesintisi nedeniyle tamamen karanlık olduğunu, hiçbir ışığın yanmadığını fark ediyorsunuz. Çapraz trafik de yavaşlıyor. Bu kavşaktan hem yasal hem de güvenli geçmek için onu nasıl değerlendirmelisiniz?","options":["Dört yönlü dur (four-way stop) olarak: tamamen durun, ardından araçların geliş sırasına göre sıranızla ilerleyin, önce gelenlere yol verin","Yol ver olarak: yavaşlayın ve yalnızca başka bir araç zaten kavşaktaysa durun, aksi takdirde durmadan geçin","Ana cadde için yeşil ışık olarak, çünkü büyük ticari aracın çapraz trafiğe göre geçiş üstünlüğü vardır","Serbest geçiş olarak: hızınızı koruyup kavşaktan geçin, çünkü karanlık bir sinyal kontrollü bir kavşak değildir"],"explanation":"Sönük veya arızalı bir trafik ışığı dört yönlü dur olarak kabul edilmeli ve araçlar geliş sırasına göre ilerlemelidir."},"492":{"q":"İki şeritli bir karayolunda yavaş giden bir tarım traktörünün arkasında yüklü bir römork çekiyorsunuz. Yolun ortası çift düz sarı çizgiyle işaretlenmiştir. Zaman kaybediyorsunuz ve traktörü geçmek istiyorsunuz. Bu yol işaretlemesine göre aşağıdakilerden hangisi doğru harekettir?","options":["Sizin tarafınızdaki şerit daha hızlı şerit olduğu için geçmek üzere çizgiyi aşabilirsiniz","Geçiş yapmamalısınız, çünkü çift düz sarı orta çizgi her iki yöndeki trafik için de geçişi yasaklar","500 fit içinde karşıdan gelen trafik görünmediği sürece geçiş yapabilirsiniz","İşaretleme yalnızca park etmeyi kısıtlar, bu nedenle yol boşken geçiş yapmaya izin verilir"],"explanation":"Çift düz sarı orta çizgi her iki yöndeki trafik için sollamayı yasaklar, bu yüzden geçmek için çizgiyi aşamazsınız."},"493":{"q":"Teksas'ta çok şeritli bir otoyolda orta yoğunlukta trafikte ilerlerken şerit çizgileri değişiyor: sizin şeridiniz ile sağınızdaki şerit arasındaki kesik beyaz çizgi, uzun bir mesafe boyunca devam eden tek bir KESİNTİSİZ (düz) beyaz çizgiye dönüşüyor. Sizin şeridinizdeki trafik, yanınızdaki şeritten biraz daha yavaş ilerliyor. Bu kesintisiz beyaz çizgi neyi ifade eder ve nasıl davranmalısınız?","options":["Yolun kenarını işaret eder, bu yüzden daha hızlı trafiğin solunuzdan geçmesi için banket tarafına yaklaşmalısınız","Kesik çizgiyle aynıdır, bu yüzden daha hızlı şeride ayak uydurmak için boşluk bulduğunuzda sağa geçebilirsiniz","Çizgiyi geçmenizi caydırır, bu yüzden kendi şeridinizde kalmalı ve yalnızca gerçekten gerekli ve güvenli olduğunda şerit değiştirmelisiniz","Herkes için geçişin yasak olduğu anlamına gelir, bu yüzden tam konumunuzu korumalı ve hiçbir koşulda şerit değiştirmemelisiniz"],"explanation":"Tek düz beyaz çizgi aynı yöndeki şeritleri ayırır ve şerit değiştirmeyi caydırır; bu yüzden yalnızca gerekli ve güvenli olduğunda geçin."},"494":{"q":"Gündüz vakti, bölünmemiş iki şeritli bir yolda çekici-römork aracınızı kullanıyorsunuz. Önünüzdeki okul otobüsü dönüşümlü yanıp sönen KIRMIZI ışıklarını yakıyor ve dur kolunu açıyor. Yasal takip mesafesinde gidiyorsunuz ve arkanızdaki trafik az. Ne yapmak zorundasınız?","options":["Hızınızı yaklaşık 15 mil/saate düşürün, frene basmaya hazır olun ve yol bölünmemiş olduğu için otobüsü yalnızca sol tarafından dikkatlice geçin","Çocuklara dikkat ederek çok düşük bir hızda ilerlemeye devam edin, çünkü tam durmak yalnızca otobüs sarı (amber) uyarı ışıklarını gösterdiğinde gereklidir","Bankete çekin, yansıtıcı üçgenlerinizi yerleştirin ve otobüs şoförünün size geçmeniz için işaret etmesini bekleyin","Tamamen durun ve kırmızı ışıklar yanıp sönmeyi kesip dur kolu geri çekilene kadar durmaya devam edin"],"explanation":"Dur kolu açıkken yanıp sönen kırmızı ışıklar, bölünmemiş yolda her iki yöndeki trafiğin ışıklar sönüp kol geri çekilene dek durması gerektiği anlamına gelir."},"495":{"q":"Güzergâhınızda çelik plaka kaplı bir yol onarım bölgesine ve metal ızgaralı bir köprü tabanına yaklaşıyorsunuz. Koşullar bugün birkaç kez değişti. Aşağıdaki durumlardan hangisinde bu metal yüzeylerin size EN AZ tutuş sağlamasını ve neredeyse buz gibi davranmasını beklemelisiniz?","options":["Hafif bir yağmur henüz başladı ve çelik plakalar ile köprü ızgarası ıslak","Parlak öğleden sonra güneşi altında zemin ve metal yüzeyler tamamen kuru","Çelik plakalar daha dün döşendi ve hâlâ yepyeni görünüyor","Bir bakım ekibi plakaların üzerindeki gevşek çakıl ve tozu az önce süpürüp temizledi"],"explanation":"Çelik plakalar ve metal köprü zeminleri az tutuş sağlar ve ıslandığında buz kadar kaygan olur."},"496":{"q":"Bölünmüş bir otoyoldan çıkıp öğle vakti şehir merkezindeki yoğun bir ticari caddeye dönüyorsunuz. Trafik sıkışık, her iki kaldırım boyunca park etmiş araçlar var, teslimat minibüsleri çift sıra park etmiş, bir otobüs durağının ve birkaç dükkanın önünden geçiyorsunuz. Az önce ayrıldığınız açık otoyola kıyasla, şimdi EN BÜYÜK dikkati hangi tehlikeye vermelisiniz?","options":["Takip mesafenizi güvenle artırabileceğiniz uzun, boş düz yollara","Park etmiş araçların, otobüslerin ya da dükkanların arasından aniden çıkabilecek yayalara","Kaymadan çıkmak için size fazladan alan veren yol kenarındaki geniş açık tarlalara","Buradan uzaktaki kırsal banketlere özgü gevşek çakıl ve molozlara"],"explanation":"Şehirde, park etmiş araçların, otobüslerin ya da mağaza önlerinin arasından aniden çıkabilecek yayalara dikkatle bakın."},"497":{"q":"Sabahın geç saatleri ve tarım arazileri arasından geçen dar, çift şeritli bir kırsal karayolunda yüklü bir çekici-römork aracını kullanıyorsunuz. Belirtilen hız 55 mil/saat, ancak küçük bir tümseği aştığınızda görüş alanınız yaklaşık çeyrek mil ileriye açılıyor. Aşağıdaki tehlikelerden hangisiyle, belirtilen hızın çok altında hareket ederek takip mesafenizi ayarlamanıza ve geçmek için belki de şerit değiştirmenize neden olacak şekilde karşılaşmanız EN olasıdır?","options":["İşaretli yolcu duraklarında duran bir şehir içi toplu taşıma otobüsü","Otoyol giriş rampasından katılan hafif binek otomobiller","Traktör veya biçerdöver gibi yavaş hareket eden tarım makineleri","Yola paralel ilerleyen bir banliyö metro treni"],"explanation":"Kırsal iki şeritli yollarda, hız sınırının çok altında giden traktör ve biçerdöver gibi yavaş tarım araçlarına dikkat edin."},"498":{"q":"Yüklü bir çekici-römork aracında kavşağın en önünde durmuş, iki şeritlik karşıdan gelen trafiği keserek sola dönmeyi bekliyorsunuz. Sizi tutan sabit kırmızı ok, düzenli olarak YANIP SÖNEN sarı sola dönüş okuna dönüşüyor. Karşıdan gelen araçlar hâlâ kavşağa hızla yaklaşıyor. Sizin boyutunuzda ve uzunluğunuzdaki bir araç sürücüsü için yasal olarak doğru ve en güvenli tepki hangisidir?","options":["Hemen dönüşe başlayın, çünkü yanıp sönen sarı ok tam olarak yeşil ok gibi işlev görür ve size korumalı, geçiş üstünlüğü olan bir dönüş hakkı verir","Tamamen durmaya devam edin ve yanıp sönen sarı oku sabit kırmızı ok gibi kabul edip hareket etmeden önce sabit yeşil oku bekleyin","Dönüşe girin ama kavşağın ortasında durup karşıdan gelen trafikte boşluk açılana kadar orada beklemeyi planlayın","Dönüşe başlayabilirsiniz, ancak karşıdan gelen trafiğe yol vermek zorundasınız ve dönüşü yalnızca aracınızın tüm uzunluğunun güvenle geçebileceği kadar büyük bir boşluk olduğunda tamamlayın"],"explanation":"Yanıp sönen sarı ok dönüşe izin verir ama geçiş üstünlüğü vermez; bu yüzden karşıdan gelen trafiğe yol verin ve ancak güvenli geçişe yetecek boşluk olduğunda dönün."},"499":{"q":"Bir bağlantı parçası arızalandıktan sonra banketde durmak zorunda kalıyorsunuz ve römorkunuzun arka tarafında zemine motorin birikmeye başlıyor. Yine de duran aracınızı yaklaşan trafiğe karşı işaretlemeniz gerekiyor. Yerdeki yakıtı göz önünde bulundurarak, koymak için en güvenli uyarı cihazı hangisidir?","options":["Yansıtıcı üçgen, çünkü dökülen yakıtı tutuşturabilecek herhangi bir alev veya ısı olmadan trafiği uyarır","Yanan bir işaret fişeği, çünkü fişekler en görünür standart uyarı cihazıdır ve kamyonunuzda bulunması zorunlu ekipmandır","Alevin motorin buharlarından uzak kalması için dökülen yakıtın rüzgar üstü tarafına yerleştirilen yanan bir işaret fişeği","Zemine konulan küçük yanan bir mum, çünkü alevi yakıta ulaşamayacak kadar alçaktır"],"explanation":"Yansıtıcı üçgen alev, kıvılcım veya ısı üretmez, bu yüzden dökülen yakıtı tutuşturma riski olmadan trafiği güvenle uyarır."},"500":{"q":"Yola çıkış öncesi muayenede ön (direksiyon) lastiklerinin düzensiz aşındığını görüyorsun. En sığ noktada diş derinliği yaklaşık 3/32 inç. Doğru karar nedir?","options":["Sürme — direksiyon aksı lastiklerinde en az 4/32 inç diş olmalı","Sür — 3/32 inç, lastikler için 2/32 inç asgari sınırın üstünde","Sür — düzensiz aşınma sadece çeker ve dorse lastiklerinde önemlidir","Sürme — 6/32 inç altındaki her lastik ticari araçta yasaktır"],"explanation":"Direksiyon (ön) aks lastiklerinin en az 4/32 inç diş derinliği olmalıdır — diğer tüm lastiklerdeki 2/32 inç şartından daha yüksek bir standart."},"501":{"q":"Tam bir yola çıkış muayenesi yaptın, yükü sabitledin ve otoyolda 45 mil sürdün, her şey yolunda. Yük muayene kuralları ne gerektirir?","options":["Henüz bir şey yok — ilk yük kontrolü 150 mil veya 3 saatte gerekir","Hiçbir şey — sabitleyip muayene ettikten sonra yakıt alana dek kontrol gerekmez","Birkaç mil içinde dur — ilk yük kontrolü ilk 50 mil içinde gerekir","Şimdi dur — yük her 25 milde bir kontrol edilmeli"],"explanation":"Yükün ve bağlama düzeneklerinin ilk kontrolü ilk 50 mil içinde yapılmalıdır, çünkü bağlar gevşer ve yük en çok ilk millerde kayar."},"502":{"q":"Direksiyonu kontrol ederken, ön lastikler dönmeye başlamadan önce direksiyonun 10 dereceden fazla (20 inçlik jantın kenarında yaklaşık iki inç boşluk) döndüğünü görüyorsun. Bu ne anlama gelir?","options":["Her ağır kamyonda olan normal boşluk — bir şey yapmaya gerek yok","Aşırı direksiyon boşluğu — onarılana dek araç sürülemez","Hidrolik direksiyon ısınıyor; sürünce sıkılaşır","Küçük bir madde — sefer sonu raporuna yaz ve sürmeye devam et"],"explanation":"Direksiyonda yaklaşık 10 dereceden fazla boşluk aracı kontrol etmeyi zorlaştırır ve onarılana kadar sürmek güvensizdir."},"503":{"q":"Vardiya sonunda bir fren ayarı sorunu buluyorsun. Sürücü Araç Muayene Raporu (DVIR) hakkında hangisi doğrudur?","options":["DVIR sadece sefer öncesi gerekir, sefer sonrası asla","Aynı sabah sefer öncesi muayene yaptıysan sefer sonu raporu isteğe bağlıdır","Kusuru yalnızca sözlü bildirebilirsin; yazılı kayda gerek yok","Kusuru yazılı sefer sonu raporuna geçirmelisin ki araç tekrar kullanılmadan onarılsın"],"explanation":"Sefer sırasında bulunan arızalar, araç tekrar kullanılmadan önce onarılmaları için yazılı sefer sonu muayene raporuna kaydedilmelidir."},"504":{"q":"Hava donma noktasının hemen altında. Yol ıslak ve parlak görünüyor, ama öndeki araçlardan normalde gördüğün lastik sıçramasının kesildiğini fark ediyorsun. En güvenli yorum ve hareket nedir?","options":["Büyük olasılıkla buz tutuyor (kara buz) — yavaşla, ani direksiyon ve frenden kaçın","Yol önceki yağmurdan sadece ıslak — mevcut hızını koru","Kendi lastiklerin hava kaybediyor — kenara çekip basıncı kontrol et","Sadece cam buzu — defrostu aç ve devam et"],"explanation":"Donma sıcaklığına yakın, ıslak ve parlak görünen ama lastiklerden su sıçramayan yol buz çağlasının (siyah buz) işaretidir; bu yüzden hızı azaltın ve ani direksiyon ya da frenden kaçının."},"505":{"q":"Aracın su basmış bir kesimde su üstünde kaymaya (hydroplaning) başlıyor. Aşağıdakilerin hepsini yapmalısın, ŞU HARİÇ:","options":["Tekerleklerin yavaşlaması için gazdan ayağını çek","Tekerlekler serbest dönsün diye debriyaja bas","Lastikleri yola geri zorlamak için sert fren yap","Tutuş dönene dek direksiyonu düz tut"],"explanation":"Su kızağı (hidroplanaj) sırasında asla sert fren yapmayın, çünkü lastikleri kilitler ve kaymayı kötüleştirir; bunun yerine gazdan ayağınızı çekin ve tutuş geri gelene kadar direksiyonu düz tutun."},"506":{"q":"Kuru yolda iyi koşullarda 60 fitlik bir kombinasyonu 60 mil/saat ile sürüyorsun. Texas takip mesafesi kuralına göre tutman gereken asgari boşluk en yakın olarak:","options":["Yaklaşık 6 saniye","Yaklaşık 7 saniye","Yaklaşık 4 saniye","Yaklaşık 10 saniye"],"explanation":"40 mil/saatin altında her 10 fitlik uzunluk için bir saniye, 40 mil/saatin üzerinde ise bir saniye daha ekleyin; böylece 60 fitlik bir araç yaklaşık 7 saniyelik takip mesafesi gerektirir."},"507":{"q":"Birkaç kurak haftadan sonra şiddetli yağmur başlıyor. Yağmurun ilk anları neden özellikle tehlikelidir ve ne yapmalısın?","options":["Yağmur motoru soğutur, bu yüzden biraz daha hızlı gidebilirsin","Tek gerçek tehlike ön cam — silecekleri çalıştır ve hızını koru","Taze yağmur tutuşu hemen artırır; sadece derin su birikintisi sorun olur","Yoldaki yağ ve toz, yıkanıp gitmeden önce kaygan bir tabaka olur — yavaşla ve takip mesafesini artır"],"explanation":"Yağmur ilk başladığında yağ ve toz yüzeye çıkıp kaygan bir film oluşturarak yolu en kaygan hale getirir; bu yüzden yavaşlayın ve takip mesafesini artırın."},"508":{"q":"Geceleyin aydınlatmasız bir otoyolda kısa farlarla giderken, farların aydınlattığı mesafe içinde duramayacağını fark ediyorsun. Doğru hareket:","options":["Görebildiğin mesafe içinde durabilecek kadar yavaşla","Uzun farı yak ve programdan geri kalmamak için hızını koru","Başka bir kamyonun arkasına yaklaşıp onun ışığıyla sür","Hızını koru ama sağ kenar çizgisini daha dikkatli izle"],"explanation":"Farlarınızın menzilini asla aşmayın — hızınız, gerçekten görebildiğiniz mesafe içinde durmanıza izin vermeli, bu da kısa farlarla yavaşlamak demektir."},"509":{"q":"Yoğun bir sis bankına girmek üzeresin. Aşağıdakilerden hangisi önerilmez?","options":["Sise varmadan önce yavaşlamak","Uzun yerine kısa farları kullanmak","Cam temiz kalsın diye sileceği ve defrostu kullanmak","Parlak ışık sisi delsin diye uzun farları yakmak"],"explanation":"Sisli havada kısa farları kullanın, çünkü uzun farlar su damlacıklarından yansıyıp parlamayı size geri vurarak görüşünüzü azaltır."},"510":{"q":"Hava donma noktasında ve yollar çoğunlukla temiz görünüyor. Yolun geri kalanı iyi görünse bile hangi yüzeyi ilk buzlanmış say?","options":["Tam güneş alan düz, açık kesimler","Yokuş yukarı kesimler, çünkü motor yüzeyi ısıtır","Sıcak havayı tutan ve en uzun kaygan kalan tüneller","Çevredeki yoldan önce donan köprü ve üst geçitler"],"explanation":"Köprüler ve üst geçitler hem üstten hem alttan ısı kaybeder, bu yüzden yolun geri kalanı temizken bile sağlam zemindeki yoldan önce buz tutarlar."},"511":{"q":"Çok sıcak bir günde durup lastiklerin belirgin sıcak ve basıncın normal soğuk değerin üstünde olduğunu görüyorsun. Doğru hareket nedir?","options":["Basınç normal soğuk değere inene dek hava boşalt","Hava akımı lastikleri soğutsun diye daha hızlı sür","Hızlı soğutmak için lastiklere su dök","Lastiklere dokunma; biri elle tutulamayacak kadar sıcaksa soğuyana dek sürmeyi bırak"],"explanation":"Isı normalde lastik basıncını artırır, bu yüzden lastiklere dokunmayın; ancak dokunulamayacak kadar sıcak bir lastik sorun işaretidir, patlamayı önlemek için soğuyana kadar durun."},"512":{"q":"Manuel vitesle ve ağır yükle bir demiryolu geçidini geçiyorsun. Geçitte vites seçimiyle ilgili en önemli kural:","options":["Raylardan önce bir vites seç ve aracın herhangi bir kısmı geçitteyken vites değiştirme","Yeterli güç için yaklaşık ortada vites küçült","Titreşimi azaltmak için boşa alıp süzülerek geç","Rayları olabildiğince hızlı geçmek için en yüksek vitesi kullan"],"explanation":"Raylara ulaşmadan önce sizi karşıya tam geçirecek bir vites seçin ve aracın herhangi bir kısmı geçitteyken asla vites değiştirmeyin, böylece raylarda stop etmezsiniz."},"513":{"q":"Uzun ve dik bir inişe yaklaşıyorsun. Vitesini ne zaman ve nasıl seçmelisin?","options":["Frenler kaybetmeye başlayana dek bekle, sonra küçük vitese geç","Yakıt için boşa al ve hızı yalnızca frenle kontrol et","Yüksek viteste kal ve tüm iniş boyunca frene hafifçe bas","İnişe başlamadan önce küçük vites seç — genelde aynı tepeyi çıkarken kullandığından daha küçük"],"explanation":"İniş öncesinde alçak vitesi seçin ki motor ve kompresyon freni hızınızı tutsun; modern kamyonlarda güvenli iniş vitesi genellikle tırmanış vitesinden daha düşüktür."},"514":{"q":"Uzun bir inişte zaten doğru küçük vittesin ve güvenli hızın 35 mil/saat. Hızını doğru kontrol eden fren tekniği hangisi?","options":["Tüm iniş boyunca sürekli hafif ve sabit fren basıncı uygula","Soğuk kalsın diye freni sürekli ve hızlı pompala","En alta kadar freni sert basılı tut","Yaklaşık 40 mil/saate gelince sert frenle ~30'a in, bırak ve tekrarla"],"explanation":"Doğru aralıklı (snub) frenleme, hızın güvenli hızınızın yaklaşık 5 mil/saat üzerine çıkmasına izin verip sonra sıkıca yaklaşık 5 mil/saat altına frenlemek, bırakmak ve tekrarlamaktır; böylece frenler soğur."},"515":{"q":"Dağ inişinde frenlerin ciddi şekilde kaybetti ve hız kazanıyorsun. Aşağıdakilerin hepsini yapmalısın, ŞU HARİÇ:","options":["Varsa bir kaçış rampası ara ve kullan","Kamyon daha yumuşak süzülsün diye boşa al","Rampa yoksa açık tarla ya da yan yol gibi bir kaçış yolu ara","En küçük viteste kal ve elinde kalan her frenle olabildiğince yavaşla"],"explanation":"İnişte asla boşa (neutral) almayın, çünkü bu motor frenini ortadan kaldırır ve hızlanmanıza neden olur; bunun yerine aracı alçak viteste tutun."},"516":{"q":"Çeker tekerlekler kaygan yolda kaymaya başlıyor ve çekicinin arkası sağa kaymaya başlıyor. Kontrolü geri almak için önce:","options":["Gazı bırak (debriyaja bas), sonra aracın önünü gitmesini istediğin yöne doğru çevir","Kaymayı hemen durdurmak için sert fren yap","Kaymanın tersine, sert biçimde sola kır","Dorseyi hizaya çekmek için gaz ver"],"explanation":"Çeker teker kaymasında önce nedeni ortadan kaldırın: gazdan ayağınızı çekip debriyaja basın ki tekerlekler tutuşu geri kazansın, sonra aracın önünün gitmesini istediğiniz yöne direksiyonu kırın."},"517":{"q":"Keskin bir virajda ön tekerlekler tutuşu kaybediyor ve tekerlekler kırık olmasına rağmen kamyon düz gidiyor. Olağan neden ve doğru tepki:","options":["Neden: çok düşük hız — direksiyonu geri kazanmak için gaz ver","Neden: aşırı şişmiş arka lastikler — kenara çekip hava boşalt","Neden: koşullara göre çok hızlı — gazı bırak, yavaşladıkça ön tekerlekler yeniden tutar","Neden: dorse itiyor — dorse el valfini sertçe çek"],"explanation":"Ön teker kayması genellikle koşullara göre çok hızlı sürmekten kaynaklanır ve direksiyon işe yaramadığı için, yavaşlarken ön lastiklerin tekrar tutması için gazı bırakmalısınız."},"518":{"q":"Önündeki araç şeritte aniden duruyor ve durmaya yerin yok. Çoğu durumda daha güvenli acil hareket:","options":["Var gücünle frenle ve hemen önünde durmayı um","Engelin etrafından dön — genelde durmaktan daha kısa mesafede dönüp kaçabilirsin","Frenleri kilitle ve direksiyonu katı biçimde düz tut","Aynı anda sert frenle ve direksiyon kır, en yüksek etki için"],"explanation":"Otoyol hızında genellikle yönü, durmak için gereken mesafeden daha kısa mesafede değiştirebilirsiniz, bu yüzden engelin etrafından dönüp sonra geri direksiyon kırmak, durmanın yetmediği yerde kazayı çoğunlukla önler."},"519":{"q":"Otoyol hızında yüksek bir patlama duyuyorsun, direksiyon aniden bir yana sert çekiyor ve araç zıplıyor — ön lastik patlaması belirtileri. Anında tepkin:","options":["Kontrolü kaybetmeden yavaşlamak için hemen sert fren yap","Dengeyi geri kazanmak için kısaca gaz ver, sonra frenle","Sert frenle hızlıca banket üzerine kır","Direksiyonu sıkıca tut, frene basma, araç yavaşlasın, sonra yavaşça kenara çek"],"explanation":"Lastik patlamasından sonra direksiyonu sıkıca tutun ve frene basmayın, aracın kendiliğinden yavaşlamasına izin verin, sonra yavaşça frenleyip banketе çekin."},"520":{"q":"Tek bir 9 fitlik çelik boru taşıyorsun. Yük sabitleme kurallarına göre gereken asgari bağ (tie-down) sayısı:","options":["İki — yük ne kadar kısa olursa olsun en az iki bağ gerekir","Bir — 10 fitten kısa, yani 10 fitte bir bağ kuralına bir bağ yeter","Hiç — 10 fitten kısa yük bağ kurallarından muaftır","Dört — yükün her köşesi için bir bağ"],"explanation":"Yük ne kadar kısa olursa olsun her parça için her zaman en az iki bağlama gereklidir, ayrıca her 10 fitlik uzunluk için bir bağlama daha eklenir."},"521":{"q":"Yükün 40.000 pound ağırlığında. Kullandığın tüm bağların toplam çalışma yükü limiti (WLL) en az ne olmalı?","options":["10.000 pound","20.000 pound","40.000 pound","80.000 pound"],"explanation":"Bağlamalarınızın toplam çalışma yükü sınırı, sabitlenen yükün ağırlığının en az yarısına eşit olmalıdır."},"522":{"q":"Ağır bir yükü ya alçak ve dorse tabanına yayarak ya da yüksek ve ortaya istifleyerek koyabilirsin. Hangisi doğru ve neden?","options":["Ağırlığı aks kenarlarından uzak tutmak için yüksek ve ortaya istifle","Yük dönüşlerde daha az kaysın diye yüksek istifle","Toplam ağırlık yasal sınırda oldukça fark etmez","Ağırlık merkezini alçak tutup devrilme riskini azaltmak için alçak ve yayarak yükle"],"explanation":"Yükü alçak ve eşit şekilde dağıtmak ağırlık merkezini düşürür; bu da devrilmeye direnmede ve dengeli kalmada en büyük etkendir."},"523":{"q":"Kötü ağırlık dağılımı her iki uçta da sorun yaratır. Ağırlık ve araç kontrolü hakkında hangisi doğrudur?","options":["Çeker aksı aşırı yüklemek hep tutuşu artırır, hiç dezavantajı yoktur","Ağırlık dağılımı sadece yakıtı etkiler, yol tutuşunu değil","Direksiyon aksında çok az ağırlık, ön lastiklerin tutuşunu ve direksiyon kontrolünü zayıflatabilir","Daha ağır aks yükü hep durma mesafeni kısaltır"],"explanation":"Direksiyon aksında çok az ağırlık ön lastik tutuşunu azaltır ve direksiyon kontrolünü zayıflatır, bu yüzden doğru denge toplam ağırlık kadar önemlidir."}},"es":{"0":{"q":"Durante su inspección previaje, mide la profundidad de la banda de rodadura y descubre que uno de los neumáticos del eje de dirección (delantero) se ha desgastado hasta 3/32 de pulgada, mientras que los neumáticos de tracción y del remolque están todos también en 3/32 de pulgada. ¿Qué afirmación identifica correctamente si su vehículo es legal para conducir?","options":["El vehículo NO es legal para conducir, porque los neumáticos del eje de dirección deben tener al menos 4/32 de pulgada de banda de rodadura.","El vehículo es legal para conducir, porque todos los neumáticos cumplen el mínimo de 2/32 de pulgada para cada neumático.","El vehículo es legal para conducir, porque los neumáticos delanteros solo necesitan 2/32 de pulgada y los demás están bien.","El vehículo NO es legal para conducir, porque todos los neumáticos de cada eje deben tener al menos 4/32 de pulgada de banda de rodadura."],"explanation":"Los neumáticos del eje de dirección deben tener al menos 4/32 de pulgada de banda de rodadura, por lo que uno delantero a 3/32 está por debajo del mínimo y hace ilegal conducir el vehículo."},"1":{"q":"Durante su inspección previaje, mide la profundidad de la banda de rodadura de todas las llantas con un calibrador. Las llantas del eje delantero (de dirección) marcan unos saludables 5/32 de pulgada, pero una de las llantas traseras de tracción está desgastada a un valor notablemente más delgado. ¿Cuál es la MENOR profundidad de banda que esa llanta trasera (no de dirección) puede tener legalmente y aún así pasar la inspección?","options":["1/32 de pulgada","2/32 de pulgada","4/32 de pulgada","6/32 de pulgada"],"explanation":"Todas las llantas excepto las del eje de dirección delantero deben tener al menos 2/32 de pulgada de profundidad de banda medida en una ranura principal."},"2":{"q":"Durante la inspección previaje, agarra el volante y lo mueve de lado a lado antes de arrancar el motor. En su volante de 20 pulgadas de diámetro, puede girar el aro un par de pulgadas en cada dirección antes de que las ruedas delanteras empiecen a responder. ¿A partir de qué punto este juego libre debería hacerle sospechar un problema en el sistema de dirección y retirar el vehículo del servicio?","options":["Cuando el volante se puede girar más de unos 10 grados (aproximadamente 2 pulgadas en un volante de 20 pulgadas) antes de que las ruedas delanteras se muevan","Solo cuando el volante se puede girar más de unos 20 grados antes de que las ruedas delanteras se muevan","Cuando el volante se puede girar más de unos 5 grados, ya que cualquier juego perceptible es inseguro","Solo cuando el juego libre supera unos 45 grados, ya que es entonces cuando la dirección se vuelve realmente difícil de controlar"],"explanation":"Más de unos 10 grados de juego libre en el volante (cerca de 2 pulgadas en un volante de 20 pulgadas) antes de que giren las ruedas delanteras es excesivo e indica un problema de dirección."},"3":{"q":"Su tractocamión se ha quedado parado en el acotamiento de una carretera de dos carriles sin división y no vuelve a arrancar. Enciende las luces intermitentes de emergencia y toma su kit de advertencia para colocar triángulos reflectantes a 100 pies por detrás, 100 pies por delante y 10 pies por la parte trasera del vehículo. Para estar legalmente equipado y poder colocar dispositivos de advertencia en CADA posición requerida como esta, ¿cuál es el número MÍNIMO de triángulos reflectantes que debe llevar su camión?","options":["Dos triángulos, ya que uno se coloca por delante y otro por detrás del vehículo","Tres triángulos","Un triángulo colocado a 10 pies por la parte trasera, más sus luces intermitentes de emergencia","Seis triángulos, para asegurarse de cubrir ambos sentidos del tránsito"],"explanation":"Un vehículo comercial debe llevar al menos tres triángulos reflectantes de advertencia como dispositivos de emergencia."},"4":{"q":"Está a la mitad de su turno y un acople de la línea de diésel ha estado goteando combustible cerca del cableado del motor. De repente surge un pequeño incendio allí, alimentado por el diésel que gotea y crepitando alrededor del arnés eléctrico con corriente. Usted toma el extintor montado en su cabina. ¿Qué clasificación en ese extintor le indica que está diseñado para combatir TANTO este combustible en llamas COMO el incendio eléctrico energizado?","options":["Un extintor B:C, clasificado para líquidos en llamas e incendios eléctricos","Un extintor Clase A, ya que es la clasificación estándar que se lleva en vehículos comerciales","Un extintor tipo Agua, para enfriar el diésel y sofocar el fuego rápidamente","No importa qué clasificación tome, mientras descargue en la base de las llamas"],"explanation":"Un líquido inflamable en llamas es fuego Clase B y el equipo eléctrico con corriente es Clase C, por lo que se necesita un extintor con clasificación B:C para ambos."},"5":{"q":"Son las 5:00 a. m. y está terminando la inspección previaje de un tractocamión que le acaban de asignar. Su despachador lo apura para que salga, pero recuerda que las normas federales exigen llevar cierto equipo de emergencia antes de cualquier viaje. NO encontró un juego de fusibles eléctricos de repuesto en ninguna parte de la cabina. ¿Bajo qué condición es legal que conduzca SIN llevar fusibles de repuesto?","options":["Solo si el camión está equipado con disyuntores (interruptores automáticos) en lugar de fusibles","Solo si lleva una batería de repuesto totalmente cargada en la cabina","Solo si el remolque tiene luces de gálibo y de posición tipo LED","Solo si el tractor tiene un alternador de respaldo (segundo) para el sistema eléctrico"],"explanation":"No se requieren fusibles de repuesto cuando el sistema eléctrico está protegido por disyuntores, ya que estos se restablecen en vez de necesitar reemplazo."},"6":{"q":"Es temprano por la mañana y se acerca a su camión para comenzar la inspección previaje. Su instructor le recuerda seguir en orden el método de inspección de siete pasos. Antes de subir a la cabina, abrir el capó o tocar un solo interruptor, ¿qué es lo PRIMERO que exige el método de siete pasos?","options":["Arrancar el motor y dejar que se caliente mientras observa la presión de aceite y los manómetros de aire","Ir al frente y verificar que los faros, las direccionales y las luces intermitentes de emergencia funcionen","Hacer una revisión general del vehículo: revisar el informe de la inspección anterior y observar su estado general y el entorno que lo rodea","Meterse bajo la parte delantera del vehículo y confirmar que las llantas del eje de dirección tengan al menos 4/32 de pulgada de banda de rodadura"],"explanation":"El primer paso de la inspección de siete pasos es la revisión general: revisar el último informe de inspección y verificar la condición general del camión y su entorno."},"7":{"q":"Es una mañana fría y está por comenzar su inspección previaje. El motor de su camión está APAGADO y el capó está levantado. ¿Cuál de los siguientes es el grupo de elementos que puede y debe inspeccionar AHORA MISMO, mientras el motor no está en marcha?","options":["El juego libre del volante y el funcionamiento de la alarma de baja presión de aire","El nivel de aceite del motor, el nivel del refrigerante y el estado de las correas","Las presiones de conexión y desconexión del gobernador del compresor de aire","La salida del alternador y el medidor del sistema de carga bajo carga"],"explanation":"Con el motor apagado se abre el capó para revisar el nivel de aceite, el nivel de refrigerante y el estado de las correas de transmisión."},"8":{"q":"Está apenas bajo cero y se ha formado una fina capa de hielo en la rampa de acceso mientras lleva su combinación cargada a velocidad de autopista. Siente que las ruedas motrices del tractor empiezan a patinar y la parte trasera de la cabina se desvía hacia un lado. Para alcanzar la velocidad con seguridad en esta superficie resbaladiza, ¿cuál es la MEJOR manera de manejar el acelerador?","options":["Aplicar potencia de forma suave y gradual, soltando el acelerador en cuanto las ruedas motrices empiecen a patinar","Pisar el acelerador a fondo para que las ruedas que patinan agarren y rompan la capa de hielo","Bombear el acelerador rápidamente para cortar la potencia que llega a las ruedas motrices","Mantener el acelerador firme y constante y dejar que la potencia del motor lo saque del tramo resbaladizo"],"explanation":"En superficies resbaladizas acelere de forma suave y gradual, soltando el acelerador apenas las ruedas motrices empiecen a patinar para que recuperen la tracción."},"9":{"q":"Está solo y debe meter en reversa su tractocamión con remolque hacia un muelle de carga en un callejón estrecho. Podría acercarse al muelle de modo que el conjunto retroceda hacia su lado izquierdo (del conductor), o hacia su lado derecho, lo que sería una maniobra algo más corta. Para mantenerse lo más seguro posible, ¿qué enfoque debería elegir y por qué?","options":["Retroceder hacia el lado derecho, porque el camino más corto significa menos tiempo maniobrando a ciegas","Retroceder hacia el lado derecho, pero asomarse por la ventanilla del pasajero y usar a un señalero para cubrir el ángulo muerto","Ambos lados son igual de seguros, así que elija el lado derecho ya que es la maniobra más rápida","Retroceder hacia el lado del conductor (izquierdo), aunque sea más largo, porque puede vigilar la parte trasera del remolque por la ventanilla lateral en lugar de depender solo de los espejos"],"explanation":"Retroceda hacia el lado del conductor (izquierdo) cuando sea posible para ver la parte trasera del remolque directamente por la ventanilla en vez de depender solo de los espejos."},"10":{"q":"Conduce un remolque cargado y se acerca a una bajada larga y empinada que termina en una curva cerrada al final. Su transmisión está actualmente en una marcha alta. ¿Cuál es el momento correcto para seleccionar la marcha baja que usará para controlar su velocidad en esta pendiente y a lo largo de la curva?","options":["Antes de comenzar a bajar la pendiente y antes de la curva, mientras todavía está en terreno llano","Justo al entrar en la curva, para que el motor dé su máxima fuerza de frenado exactamente donde más la necesita","A mitad de la bajada, una vez que sienta que el camión empieza a tomar velocidad y los frenos comienzan a perder eficacia","Solo después de salir de la curva, para que las ruedas motrices mantengan toda la tracción durante el giro"],"explanation":"Seleccione la marcha adecuada antes de comenzar a bajar una pendiente o entrar a una curva, aún en terreno plano, porque al descender puede no ser posible cambiar."},"11":{"q":"Conduce por una autopista seca a 55 mph cuando a un automóvil muy por delante se le revienta un neumático y se detiene de repente en su carril. Desde el instante en que aparece el peligro hasta que su camión se detiene por completo, su unidad habrá recorrido aproximadamente la longitud de un campo de fútbol americano incluyendo ambas zonas de anotación (unos 419 pies). ¿Qué conjunto de factores explica por completo esa distancia total de frenado de 419 pies?","options":["La distancia en que sus frenos frenan físicamente el camión después de que los frenos de aire actúan, más el retraso mientras se acumula la presión de aire en el sistema","La distancia que recorre mientras ve y reconoce el peligro, más la distancia mientras mueve el pie al pedal, más la distancia que tardan los frenos en detenerlo","La distancia mientras reacciona y mueve el pie al pedal, más la distancia que tardan los frenos en detenerlo","Solamente la distancia que necesitan los frenos para detener el camión una vez que se aplican"],"explanation":"La distancia total de frenado es la distancia de percepción más la de reacción más la de frenado: ver el peligro, llevar el pie al pedal y que los frenos detengan el camión."},"12":{"q":"Va circulando vacío por una autopista seca y nivelada a una velocidad constante de 55 mph con buen tiempo. El conductor que va delante se detiene de repente y usted tiene que hacer una parada de emergencia total. Desde el momento en que aparece por primera vez un peligro hasta el momento en que su camión queda completamente detenido, ¿qué distancia total de carretera le tomará aproximadamente detenerse?","options":["Alrededor de 60 pies, ya que es la distancia que recorre antes de poder reaccionar","Alrededor de 220 pies, aproximadamente la longitud de la fase de frenado por sí sola","Alrededor de 320 pies, un poco más que un solo campo de fútbol americano","Alrededor de 420 pies, aproximadamente la longitud de un campo de fútbol americano más ambas zonas de anotación"],"explanation":"A 55 mph en buenas condiciones, la distancia total de frenado es de unos 420 pies, aproximadamente el largo de un campo de fútbol americano más ambas zonas de anotación."},"13":{"q":"Normalmente conduce un tramo de autopista seco y plano a 20 mph y sabe que su camión necesita cierta distancia de frenado para detenerse desde esa velocidad. Esta noche, con retraso, recorre ese mismo camino a 40 mph en las mismas buenas condiciones. En comparación con su distancia de frenado a 20 mph, su distancia de frenado a 40 mph será aproximadamente:","options":["2 veces más larga, porque la distancia de frenado aumenta en proporción directa a la velocidad","3 veces más larga, ya que también debe añadir distancia adicional por el tiempo de reacción","4 veces más larga, porque la distancia de frenado crece con el cuadrado de la velocidad","Aproximadamente igual, siempre que el camino esté seco y plano y los frenos estén en buen estado"],"explanation":"La distancia de frenado aumenta con el cuadrado de la velocidad, por lo que duplicarla de 20 a 40 mph hace que la distancia de frenado sea unas cuatro veces mayor."},"14":{"q":"Una lluvia constante ha empapado la autopista y ve una fina capa de agua sobre el pavimento, aunque la temperatura está muy por encima del punto de congelación y no hay nieve ni hielo. Para mantener un margen seguro ante la mayor distancia de frenado que crean estas condiciones de mojado, ¿en qué proporción debería reducir su velocidad respecto a la que llevaría en la misma vía cuando está seca?","options":["Alrededor de una décima parte","Alrededor de un tercio","Alrededor de la mitad","Alrededor de tres cuartas partes"],"explanation":"En pavimento mojado, reduzca su velocidad aproximadamente un tercio respecto a su velocidad segura en seco para compensar la menor tracción y la mayor distancia de frenado."},"15":{"q":"Acaba de entregar toda su carga y su remolque ahora está completamente vacío. El camino está seco y circula a la misma velocidad de autopista que condujo toda la mañana cuando iba cargado por completo. En comparación con cuando iba cargado, ¿cómo debe ajustar su expectativa sobre cómo frenará y se manejará este equipo vacío?","options":["Se detendrá en una distancia más corta porque hay mucho menos peso que los frenos deben desacelerar","Necesitará una distancia más larga para detenerse porque los ejes traseros ligeros tienen menos tracción y las ruedas pueden bloquearse y derrapar","Su distancia de frenado será esencialmente la misma, ya que depende de la velocidad y no de la carga","Ahora no puede derrapar porque un remolque vacío impide que las ruedas motrices se bloqueen"],"explanation":"Un camión vacío necesita mayor distancia de frenado porque los ejes traseros ligeros tienen menos tracción, por lo que las ruedas se bloquean y patinan con más facilidad."},"16":{"q":"Circula a unas 50 mph por una interestatal cuando comienza un aguacero intenso. La dirección de repente se siente liviana y suelta, el camión deja de responder a los pequeños giros del volante y se da cuenta de que las llantas delanteras se han subido sobre una capa de agua y ya no agarran el pavimento. ¿Qué acción le da la mejor oportunidad de recuperar el control?","options":["Pisar el freno con firmeza para reducir la velocidad lo más rápido posible","Soltar el acelerador (y pisar el embrague) y dejar que el vehículo desacelere por sí solo sin frenar bruscamente","Girar bruscamente el volante hacia el arcén para que las llantas muerdan el pavimento más áspero y recuperen la tracción","Mantener o aumentar el acelerador para que las ruedas motrices sigan girando y 'atravesar' el agua a fuerza"],"explanation":"Si empiezas a hidroplanear, suelta el acelerador y pisa el embrague sin frenar fuerte para que los neumáticos reduzcan velocidad y recuperen contacto con la carretera."},"17":{"q":"Usted desciende por una pendiente de montaña larga y empinada con un remolque completamente cargado. Seleccionó una marcha baja en la cima y ha venido frenando ligeramente pero de forma casi continua durante todo el descenso. A mitad de la bajada, nota que el pedal del freno se siente más blando y que el camión ya no frena como lo hacía al inicio de la pendiente. ¿Cuál es la causa MÁS probable de esta pérdida de frenado?","options":["Las zapatas y los tambores del freno se sobrecalentaron por usar demasiado los frenos en lugar de frenar con el motor y la marcha baja","La presión de aire en las líneas de freno bajó demasiado porque el compresor no da abasto en una pendiente","El aire frío de la montaña a mayor altitud espesó el líquido de frenos y redujo la respuesta del pedal","Los neumáticos del remolque están con baja presión, lo que reduce el área de contacto y la fuerza de frenado en cada rueda"],"explanation":"Frenar de forma continua en una bajada larga sobrecalienta las zapatas y los tambores, causando pérdida de frenado; controla la velocidad con el motor y la marcha baja."},"18":{"q":"Usted conduce un tractocamión cargado por una autopista seca y se acerca a una rampa de salida en bajada con un límite de velocidad de curva señalizado de 35 mph. El pavimento está en buen estado y hay poco tráfico. ¿Qué afirmación describe mejor cómo debe tratar esa cifra señalizada de 35 mph?","options":["Es la velocidad segura para cualquier vehículo en buenas condiciones, así que 35 mph está bien en su equipo cargado","Está fijada para automóviles en buenas condiciones, por lo que debe entrar a la curva a una velocidad muy por debajo de 35 mph","Solo aplica a camiones vacíos, por lo que un camión cargado puede superarla legalmente","Ya incluye un margen de seguridad para camiones, por lo que mantener exactamente 35 mph es la opción más segura"],"explanation":"Las velocidades señaladas en las curvas se fijan para autos en buenas condiciones, por lo que un camión, con su centro de gravedad más alto, debe entrar muy por debajo de esa velocidad."},"19":{"q":"Conduce un tractocamión con remolque de 60 pies de largo por una carretera seca, y su velocímetro marca constantemente 55 mph con tráfico ligero. Quiere mantener una distancia de seguimiento segura detrás del auto que va delante de usted. Según la longitud de su vehículo y su velocidad actual, ¿cuál es la distancia de seguimiento mínima que debe mantener?","options":["6 segundos, porque un vehículo de 60 pies necesita 1 segundo por cada 10 pies a cualquier velocidad","Un valor fijo de 4 segundos, igual que cualquier vehículo pesado sin importar su longitud","7 segundos, porque un vehículo de 60 pies necesita 6 segundos más 1 segundo adicional por conducir a más de 40 mph","Aproximadamente tres largos de auto, que es más o menos suficiente margen para un tractocamión"],"explanation":"Deja 1 segundo de distancia de seguimiento por cada 10 pies de longitud del vehículo, más 1 segundo extra a más de 40 mph, así un vehículo de 60 pies a 55 mph necesita 7 segundos."},"20":{"q":"Circula a 60 mph por una carretera rural amplia y despejada, con poco tráfico. El camino por delante sube en una pendiente suave y usted quiere gestionar su espacio y detectar problemas con anticipación. Para explorar correctamente, ¿dónde deben estar enfocados sus ojos la MAYOR parte del tiempo mientras conduce a esta velocidad?","options":["En el pavimento justo más allá del frente del capó, para detectar de inmediato los obstáculos en la vía","Aproximadamente de 4 a 6 segundos por delante, la misma distancia que usaría para dejar un espacio de seguimiento seguro","Aproximadamente de 12 a 15 segundos por delante, alrededor de un cuarto de milla a velocidad de carretera","Aproximadamente 30 segundos por delante, tan lejos en la vía como su vista pueda alcanzar"],"explanation":"Los buenos conductores miran de 12 a 15 segundos adelante, lo que equivale a un cuarto de milla a velocidad de autopista."},"21":{"q":"Se aproxima a un giro a la derecha hacia un callejón estrecho en una calle urbana congestionada. El tráfico es denso, hay un ciclista en el carril bici a su derecha y varios conductores están amontonados muy cerca detrás de usted. Respecto a su señal de giro, ¿cuál es la única mejor práctica?","options":["Esperar hasta que realmente empiece a girar el volante para señalizar, así los conductores de atrás no frenan demasiado pronto ni provocan un atasco","Señalizar solo brevemente, porque en tráfico denso los conductores a su alrededor ya ven sus luces de freno comunicando por usted","Encender la señal mucho antes del giro y mantenerla parpadeando de forma continua durante toda la maniobra","Omitir la señal eléctrica y usar una señal con la mano en su lugar, ya que es más visible para el ciclista junto a usted"],"explanation":"Señalice mucho antes de girar y mantenga la luz intermitente durante toda la maniobra para que los demás tengan el máximo tiempo de reaccionar y no crean que cambió de idea."},"23":{"q":"Conduce un tractocamión con remolque de 70 pies y debe girar a la derecha hacia una calle lateral estrecha. Hay poco tráfico y le preocupa que las ruedas traseras del remolque se suban al bordillo. Para completar este giro de forma segura y conforme a la ley, ¿cuál de las siguientes acciones NO debe realizar?","options":["Desplazarse hacia la izquierda al carril contiguo antes de girar para que el remolque tenga más espacio para maniobrar","Iniciar el giro lentamente y seguir vigilando los espejos para controlar la trayectoria del remolque","Mantener la parte trasera del vehículo cerca del bordillo para que otros conductores no puedan colarse por su derecha","Abrirse hacia la derecha solo al completar el giro, después de que la cabina haya pasado la esquina"],"explanation":"Desviarse a la izquierda antes de un giro a la derecha abre un hueco que invita a los vehículos a pasar por tu derecha, poniéndolos en la trayectoria del remolque al girar."},"24":{"q":"Conduce un remolque de caja seca vacío y su ruta muestra un paso elevado con una altura libre indicada de 13 pies 6 pulgadas. La altura registrada de su remolque es de 13 pies 4 pulgadas, lo que le deja un margen de 2 pulgadas. A principios de este invierno la cuadrilla reasfaltó este tramo, y anoche cayó una nevada ligera que ha quedado compactada sobre la calzada. ¿Cuál es la forma más defendible de interpretar ese letrero de altura libre antes de decidirse a pasar por debajo del paso elevado?","options":["El letrero está colocado oficialmente, así que la cifra de 13 pies 6 pulgadas es exacta y un margen de 2 pulgadas es legalmente suficiente para continuar.","Como los letreros de altura libre aplican a vehículos cargados, un remolque vacío queda más bajo que su altura registrada, así que tiene espacio de sobra y puede continuar.","Trate la altura indicada como poco fiable: el reasfaltado y la nieve compactada reducen la altura libre real, y su remolque vacío en realidad va más alto, así que busque otra ruta o verifique antes de continuar.","Sume su margen de 2 pulgadas a los 13 pies 6 pulgadas indicados, obteniendo unos 13 pies 8 pulgadas de altura útil, más que suficiente para su remolque."],"explanation":"Los letreros de altura libre pueden estar errados porque el reasfaltado y la nieve compactada reducen el espacio real y una caja vacía va más alta, así que verifica o busca otra ruta."},"25":{"q":"Está incorporándose a una autopista con mucho tráfico y mira el gran espejo convexo (curvo) montado en su puerta derecha. Un automóvil que ve en ese espejo convexo parece pequeño y muy atrás, así que siente que tiene mucho espacio para cambiar de carril. Antes de hacerlo, ¿qué debe entender sobre lo que le indica este espejo convexo?","options":["Muestra un área más amplia, pero los objetos se ven más pequeños y más lejos de lo que realmente están, por lo que ese auto puede estar más cerca de lo que parece","Amplía un primer plano estrecho, por lo que el auto en realidad está más lejos de lo que parece y usted tiene espacio de sobra","Muestra la misma imagen de tamaño y distancia reales que un espejo plano, por lo que la separación que ve es exacta","Solo refleja el costado de su propia cabina y remolque, por lo que cualquier vehículo en él aún no es un peligro"],"explanation":"Los espejos convexos muestran un área más amplia pero hacen que los objetos se vean más pequeños y lejanos, así que un vehículo puede estar más cerca de lo que parece."},"26":{"q":"Conduce por una autopista despejada y seca cuando observa más adelante un automóvil estacionado en el acotamiento derecho con el cofre levantado y una persona de pie cerca del parachoques trasero mirando hacia el tránsito. No hay choque, no hay mal tiempo y el tránsito fluye con normalidad. Para efectos de detectar peligros, ¿cómo debe clasificar este automóvil estacionado y a la persona?","options":["Es un peligro, porque es cualquier condición de la vía o usuario de la vía que podría convertirse en una emergencia y obligarlo a actuar","No es un peligro, porque todavía no ocurre ningún choque ni emergencia y la calzada en sí está despejada","No es un peligro, porque los peligros solo existen con mal tiempo, niebla, hielo u otras malas condiciones de manejo","Es un peligro solo si el automóvil estacionado se reincorpora de pronto a su carril y lo obliga a frenar bruscamente"],"explanation":"Un peligro es cualquier condición de la vía o usuario que podría convertirse en una emergencia, reconocido a tiempo para que tengas oportunidad de reaccionar."},"27":{"q":"Circula por el carril derecho de una autopista de cuatro carriles cuando un automóvil se le acerca a gran velocidad por detrás, se le pega a pocos centímetros del remolque, luego lo rebasa bruscamente, se le cruza por delante y frena en seco. Su vehículo comercial va completamente cargado y su distancia de frenado ya es larga. ¿Cuál es la MEJOR manera de manejar a este conductor agresivo?","options":["Hacer destellos con las luces altas y tocar la bocina para indicarle al conductor que se aleje, y luego mantener su posición en el carril","Pasarse al carril izquierdo y rebasar al conductor para dejar el conflicto atrás","Mantener su velocidad y seguir de cerca para que el conductor no pueda volver a cruzársele","Soltar el acelerador para abrir espacio adelante, evitar el contacto visual y dejar que el conductor agresivo se adelante bastante"],"explanation":"La respuesta segura ante un conductor agresivo es soltar el acelerador para abrir espacio, evitar el contacto visual y dejar que se adelante bastante."},"29":{"q":"Es una noche oscura y sin luna en una carretera rural de dos carriles y conduce con las luces bajas, que iluminan el camino unos 250 pies por delante. No hay tráfico en sentido contrario. Para no 'sobrepasar el alcance de sus faros', ¿cuál es la única cosa más importante que debe hacer?","options":["Cambiar a luces altas y mantener una velocidad constante de 55 mph, ya que las luces altas alcanzan unos 350 pies y ese espacio basta para reaccionar","Acercarse a las luces traseras del vehículo de adelante y usar su luz para ver más lejos en la carretera","Mantener su velocidad normal de día porque sus faros iluminan claramente las líneas del carril y el camino de adelante","Conducir lo bastante despacio para poder detenerse por completo dentro de la distancia que realmente iluminan sus faros"],"explanation":"Nunca conduzcas más rápido de lo que alcanzan tus faros: ve lo bastante despacio para detenerte por completo dentro de la distancia que estos iluminan."},"30":{"q":"Acaba de oscurecer en una carretera de dos carriles sin división central y se aproxima una fila de vehículos con los faros encendidos. Un conductor no baja sus luces altas y el deslumbramiento le dificulta ver el camino. Para mantener los ojos adaptados y permanecer con seguridad en su carril hasta que pasen los vehículos, ¿hacia dónde debe dirigir la mirada?","options":["Hacia el borde derecho de su carril, usando la línea pintada o las marcas del pavimento como guía hasta que pasen los vehículos","Directamente a los faros que se aproximan para calcular la distancia entre usted y los otros vehículos","Hacia abajo a los instrumentos del tablero para descansar los ojos del deslumbramiento","Muy adelante en el camino, más allá del tránsito que se aproxima, para mantener su velocidad dentro del alcance de sus faros"],"explanation":"Cuando lo deslumbren las luces altas que vienen de frente, mire hacia el borde derecho de su carril y siga la línea pintada para mantener los ojos adaptados a la oscuridad."},"31":{"q":"Está realizando una entrega antes del amanecer cuando un banco espeso de niebla aparece y la visibilidad cae a menos que el largo de su tractocamión con remolque. Decide que lo más seguro es seguir avanzando despacio hasta la próxima salida en lugar de detenerse en el carril de circulación. Para ver la carretera y ser visto SIN cegarse a sí mismo, ¿cuál elección de luces y velocidad es la única mejor práctica?","options":["Encender las luces altas para máximo alcance y mantener la velocidad para no bloquear el tránsito","Usar las luces bajas (y las antiniebla si las tiene) y reducir la velocidad para poder detenerse dentro de la distancia que alcanza a ver","Apagar los faros y circular solo con las luces intermitentes de emergencia para marcar su posición","Mantener las luces altas encendidas pero reducir la velocidad, ya que en la niebla la luz extra importa más que el resplandor"],"explanation":"Con niebla, use luces bajas (y antiniebla si las tiene) y reduzca la velocidad para poder detenerse dentro de la distancia que ve, ya que las luces altas se reflejan y reducen la visibilidad."},"32":{"q":"Es una mañana despejada a unos 31°F (cerca de -1°C) y la calzada abierta que tiene delante se ve completamente seca. Conduce un remolque cargado hacia un puente largo que cruza el valle de un río, con un paso elevado en sombra justo después. ¿Dónde debe esperar perder tracción PRIMERO y ajustar su velocidad antes de llegar?","options":["En la carretera abierta y seca, porque el peso del tractor presiona los neumáticos y calienta el pavimento","En el puente y el paso elevado en sombra, porque el aire circula por encima y por debajo del tablero, así que se enfría y se congela antes que la carretera de alrededor","Todavía en ningún sitio, porque si el pavimento se ve seco no puede estar helado hasta que la temperatura del aire baje de cero","Solo después del paso elevado, donde la sal de carretera y el sol ya han derretido el hielo de las estructuras elevadas"],"explanation":"Los puentes y pasos elevados están expuestos al aire frío por arriba y por abajo, así que pierden calor por todos lados y se congelan antes que el resto de la carretera."},"33":{"q":"Es temprano en la mañana y la temperatura está justo bajo cero. El pavimento adelante se ve oscuro y mojado, pero nota que los neumáticos del camión que va delante de usted no levantan nada de rocío de agua, y sus espejos y la antena tienen una fina capa de hielo. ¿Qué es lo MÁS probable que esté ocurriendo con la superficie de la carretera y cómo debe reaccionar?","options":["El pavimento solo está mojado por la escarcha derretida; mantenga su velocidad ya que el agua estancada brinda tracción normal.","La carretera simplemente se está secando; un golpe rápido al freno confirmará que el agarre es bueno y le permitirá mantener su distancia de seguimiento.","Se ha formado una capa fina y transparente de hielo negro; suelte suavemente el acelerador y evite cualquier giro o frenado brusco.","Es sellador de asfalto fresco lo que hace que la superficie parezca mojada; conduzca con cuidado pero la velocidad normal es aceptable."],"explanation":"Una carretera que parece mojada pero sin rociado de las llantas cerca del punto de congelación indica hielo negro, así que suelte el acelerador y evite frenar o girar de golpe."},"34":{"q":"Es mediados de julio en el oeste de Texas, con una temperatura exterior cercana a los 105 grados Fahrenheit y el asfalto exudando alquitrán de forma visible. Se detuvo hace dos horas y sus neumáticos funcionaban bien, pero acaba de incorporarse a un tramo largo de carretera interestatal a velocidad de autopista. ¿Qué condición debería vigilar con MÁS atención durante este trayecto?","options":["El aumento de la presión de los neumáticos que puede provocar un reventón a medida que sube el calor","El claxon volviéndose apagado por el polvo y el calor","La caída de la presión de los neumáticos por la fuga de aire frío en las válvulas","El polarizado de las ventanas oscureciéndose y reduciendo su visibilidad hacia adelante"],"explanation":"Con calor extremo el aire dentro del neumático se expande y la presión sube, lo que junto con el calor puede causar un reventón."},"35":{"q":"Va cargado casi al peso bruto combinado máximo (GCWR) y está a punto de descender una pendiente de montaña larga y empinada. El pavimento está seco y despejado. Al llegar a la cima, empieza a pensar cómo mantendrá la velocidad bajo control durante todo el descenso. ¿Cuál es la MEJOR manera de controlar su velocidad en esta bajada?","options":["Mantenerse en una marcha alta para que el motor funcione suave y oprimir los frenos de servicio de forma constante durante toda la bajada para fijar la velocidad en un nivel seguro.","Poner en neutral y dejarse rodar, aplicando los frenos de servicio con fuerza cada vez que la velocidad sube, para que los frenos se enfríen entre aplicaciones.","Dejar la transmisión en una marcha normal de carretera y confiar en el freno de estacionamiento (de mano) para retener la velocidad durante el descenso.","Seleccionar una marcha baja ANTES de empezar a bajar, de modo que el freno de motor y de transmisión hagan la mayor parte del trabajo, usando solo un frenado de servicio ligero y constante como complemento."],"explanation":"En una bajada larga y empinada elija una marcha baja antes de empezar a descender para que el freno de motor haga la mayor parte, usando solo un frenado de servicio ligero y constante."},"36":{"q":"Está bajando una pendiente larga y empinada de montaña con un remolque cargado. Seleccionó una marcha baja en la cima y ha estado aplicando frenadas ligeras y constantes, pero el pedal del freno se está ablandando poco a poco, su velocidad sigue aumentando y huele a quemado. Más adelante, a la derecha, ve una rampa de escape de grava. ¿Cuál de las siguientes opciones describe cuándo debe dirigirse hacia esa rampa?","options":["Cuando sus frenos se han recalentado o fallado y ya no puede controlar su velocidad en la pendiente","Cuando solo va unas pocas millas por hora por encima del límite de velocidad para camiones en la pendiente","Cuando el tráfico en la bajada se ha vuelto intenso y quiere más espacio","Cuando quiere una breve pausa para dejar enfriar el motor y los frenos antes de continuar"],"explanation":"Use una rampa de escape solo cuando los frenos hayan fallado o perdido eficacia y ya no pueda controlar la velocidad en la pendiente."},"37":{"q":"Circula vacío una calurosa tarde de verano a velocidad de carretera cuando oye un fuerte estallido y el volante tira bruscamente hacia la derecha: ha reventado un neumático delantero. Ahora su unidad vacía es más difícil de controlar. ¿Cuál es su PRIMERA acción correcta?","options":["Sujetar el volante con firmeza, no tocar el freno y dejar que el vehículo reduzca la velocidad por sí solo antes de salir poco a poco al arcén","Frenar de forma firme y constante para reducir la velocidad antes de que el camión se salga de la vía","Girar bruscamente el volante en sentido contrario al tirón para mantener el camión centrado en el carril","Pisar el embrague y reducir de marcha para frenar con el motor"],"explanation":"Tras el reventón de un neumático delantero, sujete firme el volante y no frene, dejando que el vehículo reduzca solo la velocidad antes de salir de la vía."},"38":{"q":"Va bajando una pendiente moderada en un camión rígido con frenos hidráulicos cuando pisa el pedal del freno y este se hunde lentamente hacia el piso casi sin poder de frenado. Hay poco tráfico y aproximadamente a una milla adelante hay una rampa de escape para camiones. ¿Qué debe intentar PRIMERO para reducir la velocidad?","options":["Apagar el motor de inmediato para que la transmisión ayude a detener el camión","Aplicar el freno de estacionamiento con fuerza en un solo movimiento firme para bloquear las ruedas","Jalar la perilla de suministro de aire al remolque (protección del tractor) para aplicar los frenos del remolque","Bombear rápidamente el pedal del freno para tratar de recuperar la presión hidráulica"],"explanation":"Cuando el pedal de freno hidráulico se hunde hasta el fondo, bombéelo rápido primero para recuperar presión suficiente y reducir la velocidad o detenerse."},"39":{"q":"Está acelerando al salir de una curva en una carretera mojada de dos carriles cuando la parte trasera del tractocamión comienza a deslizarse de repente hacia el acotamiento y las ruedas motrices parecen haber perdido la tracción. De las siguientes, ¿cuál es la MEJOR manera de recuperar el control de este derrape de las ruedas motrices?","options":["Pisar el freno con firmeza y mantenerlo para frenar la parte trasera del vehículo y volver a alinearla","Dejar de acelerar, pisar el embrague y dirigir el volante hacia donde quiere que vaya el vehículo","Mantener el acelerador constante y contravolantear con fuerza para que la potencia del motor enderece las ruedas motrices","Bloquear las ruedas con los frenos para detener el derrape lo más rápido posible"],"explanation":"Para corregir un derrape de las ruedas motrices por aceleración, deje de acelerar, pise el embrague para cortar la potencia del motor y dirija hacia donde quiere ir."},"40":{"q":"Está descendiendo una pendiente larga y curva de montaña con un remolque cargado cuando la superficie de la carretera más adelante se ve mojada y en sombra. Comienza a girar, pero la parte delantera de su camión sigue empujando recto hacia el exterior de la curva y la dirección se siente ligera y sin respuesta por mucho que gire el volante. De las siguientes, ¿cuál es la causa raíz MÁS probable de este derrape de las ruedas delanteras?","options":["Soltó los frenos con demasiada suavidad al entrar en la curva, por lo que las llantas delanteras nunca agarraron el pavimento","Demasiada carga se desplazó hacia los ejes traseros, quitando peso del eje de dirección","Conduce demasiado rápido para las condiciones resbaladizas y en sombra (y/o sus llantas delanteras están gastadas o con baja presión)","El freno de motor en marcha baja bloqueó las ruedas motrices y desvió la parte delantera de su trayectoria"],"explanation":"Un derrape de las ruedas delanteras se debe a conducir demasiado rápido para las condiciones, junto con llantas delanteras gastadas o con poca presión."},"41":{"q":"Está apenas bajo cero y usted hace una frenada fuerte de emergencia en una carretera resbaladiza cuando un auto se le cruza por delante. Su tractocamión está equipado con frenos antibloqueo (ABS) y pisa el pedal del freno con fuerza hasta el fondo. En esta situación, ¿cuál es el beneficio PRINCIPAL que ofrece el ABS?","options":["Evita que las ruedas se bloqueen para que usted pueda seguir dirigiendo y esquivar el peligro","Garantiza una distancia de frenado notablemente más corta que el mismo camión sin ABS","Dirige automáticamente el camión lejos del auto que se le cruzó por delante","Le permite seguir con seguridad a menor distancia porque ahora frena más rápido"],"explanation":"El ABS evita que las ruedas se bloqueen durante un frenado fuerte para que puedas seguir dirigiendo el vehículo y esquivar un peligro."},"42":{"q":"Usted es el primero en llegar al lugar de un choque en una carretera de dos carriles con mucho tráfico. Un automóvil volcó y bloquea su carril; el conductor está consciente pero recostado contra la puerta, y el tráfico sigue acercándose por detrás de los restos a velocidad de autopista. Usted se detuvo de forma segura y encendió las luces intermitentes de emergencia. ¿Qué debe hacer PRIMERO?","options":["Sacar con cuidado al conductor herido del automóvil y recostarlo en el acotamiento, por si el vehículo se incendia","Continuar hasta la próxima salida para buscar un teléfono y llamar al 911, ya que usted solo no puede ayudar","Bajar y empujar el automóvil accidentado hacia un lado para despejar el carril y que el tráfico siga circulando","Colocar triángulos reflectantes de advertencia para alertar al tráfico que se acerca antes de hacer cualquier otra cosa en el lugar"],"explanation":"En el lugar de un choque la primera prioridad es protegerlo, así que coloque triángulos reflectantes de advertencia para avisar al tránsito que se acerca antes de hacer cualquier otra cosa."},"43":{"q":"Se detiene en el acotamiento al ver humo saliendo del compartimento del motor. Ha puesto el freno de estacionamiento y tomado su extintor clase B:C. ¿Cuál de las siguientes acciones es la MENOS apropiada al prepararse para combatir este incendio del motor?","options":["Apagar el motor tan pronto como pueda","Apuntar el extintor a la base del fuego, no a la parte alta de las llamas","Mantener el capó bajado lo más posible y descargar el extintor por las rendijas o rejillas","Abrir el capó por completo para apuntar el extintor directamente a las llamas"],"explanation":"Abrir el capó de par en par aporta oxígeno al fuego y puede avivarlo con violencia; mantenga el capó bajado y dirija el extintor por las aberturas."},"44":{"q":"En una recepción de boda la noche antes de un viaje largo, bebe de forma constante pero deja de hacerlo varias horas antes de acostarse. A la mañana siguiente se siente completamente sobrio, desayuna abundantemente, toma dos tazas de café y da una caminata enérgica al aire frío antes de su inspección previa al viaje. Al subir a la cabina, ¿qué afirmación refleja mejor la ley y los hechos sobre si está en condiciones seguras de conducir su vehículo comercial (CMV)?","options":["Ninguno de esos pasos redujo su concentración de alcohol en sangre; solo el paso del tiempo lo hace, y no puede operar el CMV con una concentración de alcohol en sangre (BAC) de 0,04 % o más.","Como está operando un CMV, el límite legal es del 0,08 %, así que claramente está bien siempre que se haya mantenido por debajo de eso.","El café, la comida y el aire frío han acelerado la eliminación del alcohol, así que su BAC ahora es prácticamente cero y el límite ya no importa.","Sentirse sobrio es el criterio legal para un conductor de CMV, así que si ya no se siente afectado, está por debajo del límite y es seguro conducir."],"explanation":"Solo el paso del tiempo reduce la concentración de alcohol en sangre, y no puede manejar un vehículo comercial con un BAC de 0.04% o más."},"45":{"q":"Su turno terminó hace horas y tomó varias bebidas alcohólicas en la cena. Un despachador le llama y le pide que lleve ahora mismo un tractor vacío de regreso al patio. Tomó café, dio una caminata rápida en el aire frío de la noche y se siente lúcido. ¿Qué afirmación refleja mejor lo que en realidad determina si usted está legalmente apto para conducir?","options":["El café y el aire frío han aumentado su estado de alerta lo suficiente como para que su concentración de alcohol en sangre esté ahora por debajo del límite del 0,04% para CDL.","Como se siente lúcido y ya no está afectado, es seguro y legal que opere el tractor.","Solo el paso del tiempo reduce su concentración de alcohol en sangre; nada de lo que ha hecho acelera la velocidad con que el alcohol sale de su cuerpo.","Dado que se trata de un traslado vacío sin carga, el límite del 0,04% de alcohol en sangre no se aplica a este viaje."],"explanation":"Solo el tiempo reduce tu concentración de alcohol en sangre, porque el hígado elimina el alcohol a un ritmo fijo que el café, el aire fresco o una ducha fría no aceleran."},"46":{"q":"Está comenzando su turno cuando un inspector de carretera le hace una prueba de aliento y su resultado marca 0,02% de concentración de alcohol en sangre (BAC): alcohol detectable, pero por debajo del límite de 0,04% para CDL. Se siente completamente sobrio y no hay choque ni ninguna otra infracción de por medio. Según las normas federales de CDL, ¿qué le sucede a continuación?","options":["No cambia nada: como está por debajo del límite de 0,04%, queda autorizado a seguir conduciendo con normalidad","Lo ponen fuera de servicio durante 24 horas, aunque su lectura esté por debajo del nivel descalificante de 0,04%","Se le trata igual que con una lectura de 0,04% y se le imputa un delito de conducir bajo los efectos del alcohol (DUI)","Recibe una advertencia por escrito y se le permite continuar su viaje una vez que la firme"],"explanation":"Cualquier cantidad detectable de alcohol por debajo de 0.04% deja al conductor con CDL fuera de servicio por 24 horas, aunque esté por debajo del nivel descalificante."},"47":{"q":"Cargó y aseguró una plataforma plana (flatbed) en el cargador, completó su inspección previaje y salió a la carretera. Su viaje es de 280 millas sin paradas programadas. Sabiendo que la carga se asienta y las amarras pueden aflojarse poco después de empezar a rodar, ¿para qué punto debe hacer su PRIMERA parada para inspeccionar la carga y volver a apretar el aseguramiento?","options":["Dentro de las primeras 50 millas","Dentro de las primeras 150 millas","Después de las primeras 3 horas de conducción","Dentro de las primeras 100 millas"],"explanation":"Debes inspeccionar la carga y sus amarres dentro de las primeras 50 millas, porque las sujeciones se aflojan a medida que la carga se asienta en esos primeros kilómetros."},"48":{"q":"Durante su inspección previa al viaje está asegurando una sola viga de acero de 18 pies de largo y 4,200 libras de peso sobre una plataforma plana. Quiere usar la menor cantidad de amarres (tie-downs) que aún cumpla las normas federales de sujeción de carga. ¿Qué afirmación describe correctamente el número MÍNIMO de amarres que debe usar?","options":["Al menos dos amarres, porque se necesita uno por cada 10 pies de carga y una pieza de 18 pies requiere dos","Un solo amarre basta porque la viga es una pieza única y equilibrada que descansa plana sobre la plataforma","Al menos tres amarres, porque cualquier pieza de más de 5 pies siempre requiere tres puntos de anclaje separados","No aplica un número fijo; solo necesita los amarres suficientes para alcanzar el 50% del peso de la carga como límite de carga de trabajo"],"explanation":"La carga necesita al menos una amarra por cada 10 pies de largo, y todo artículo de más de 5 pies requiere dos, así que una pieza de 18 pies exige dos amarras."},"49":{"q":"Está cargando una plataforma plana en el muelle y el único espacio que queda para varias bobinas de acero pesadas es el nivel superior de un estante de dos niveles, mientras que el embalaje más ligero podría ir en la plataforma de abajo. Un compañero dice que no importa dónde viajen las bobinas pesadas mientras el peso total se mantenga por debajo del GVWR (peso bruto vehicular permitido). Al salir, la ruta incluye una carretera sinuosa de dos carriles con varias curvas cerradas. En comparación con colocar las bobinas pesadas abajo en la plataforma, ¿cuál es la consecuencia MÁS importante de apilar ese peso pesado en lo alto?","options":["No tiene un efecto real sobre el manejo porque sigue estando legalmente dentro del GVWR del vehículo","Hace que el camión sea más fácil de detener porque más peso presiona los neumáticos contra el suelo","Eleva el centro de gravedad, haciendo que el camión sea mucho más propenso a volcar en las curvas","Mejora la estabilidad y el seguimiento en las curvas porque la carga queda centrada sobre el chasis"],"explanation":"Cargar la carga pesada en alto eleva el centro de gravedad, haciendo el camión inestable y mucho más propenso a volcar en las curvas."},"50":{"q":"Está parado en un patio del DPS de Texas observando un equipo para el que quiere licencia: un tractocamión que arrastra un remolque cargado. La clasificación combinada en los papeles (GCWR) indica 33,000 lb, y el remolque por sí solo está clasificado en 14,000 lb. Un compañero con Class B le dice que su licencia cubre esto 'porque todo el conjunto pasa de 26,001 lb.' ¿Cuál afirmación identifica correctamente la licencia que realmente necesita y por qué?","options":["Una Class B basta, ya que la clasificación total de la combinación es de 26,001 lb o más.","Una Class A, pero solo porque la clasificación total de la combinación alcanza 16,001 lb o más.","Una Class B basta, porque el remolque arrastrado está clasificado en menos de 16,000 lb.","Una Class A, porque la combinación está clasificada en 26,001 lb o más Y la unidad arrastrada está clasificada en más de 10,000 lb."],"explanation":"Se requiere una CDL Clase A cuando el GCWR de la combinación es de 26,001 lb o más y la unidad remolcada está clasificada en más de 10,000 lb."},"51":{"q":"Se presenta a su examen de habilidades de la CDL con la intención de ganarse la vida conduciendo un tractocamión con remolque, donde cada vehículo que llegará a manejar tiene frenos de aire completos. Para ahorrar dinero, un amigo le presta su camión rígido más viejo, equipado únicamente con frenos hidráulicos, y aprueba todo el examen de habilidades en él sin cometer ningún error. Según cómo afecta esa decisión a su licencia, ¿cuál afirmación es correcta?","options":["Como realizó el examen de habilidades en un vehículo que NO tiene frenos de aire, su CDL llevará una restricción de frenos de aire que le prohíbe conducir cualquier vehículo comercial equipado con frenos de aire.","Como aprobó el examen de habilidades de forma impecable sin ningún error, recibirá una CDL completa y sin restricciones, válida para vehículos con frenos de aire.","Como el camión en el que se examinó tenía frenos hidráulicos en buen estado, el examinador puede simplemente eximir la parte de frenos de aire y emitir una licencia sin restricciones.","Como solo piensa conducir tractocamiones con frenos de aire para trabajar, le emitirán una licencia restringida a la conducción nocturna hasta que vuelva a examinarse."],"explanation":"Tomar el examen de destrezas en un vehículo sin frenos de aire genera una restricción que le prohíbe conducir cualquier CMV equipado con frenos de aire."},"52":{"q":"Conduce un autobús chárter con 40 pasajeros a bordo y se aproxima a un cruce ferroviario en una carretera rural. El cruce está señalizado solo con una señal de aspa (crossbuck), las barreras están levantadas, ninguna luz parpadea, ve con claridad en ambas direcciones y no hay ningún tren a la vista. ¿Qué está obligado a hacer antes de cruzar?","options":["Reducir la velocidad, mirar y escuchar, y continuar sin detenerse porque las barreras están levantadas y no hay señales activas","Detenerse por completo, mirar y escuchar, y luego cruzar solo cuando pueda despejar totalmente las vías sin detenerse","Mantener la velocidad para que el autobús tenga suficiente impulso para despejar todas las vías sin calarse","Detenerse solo si además de los pasajeros transporta materiales peligrosos con placas (placards)"],"explanation":"Los autobuses y vehículos con placas de materiales peligrosos deben parar, mirar y escuchar en cada cruce ferroviario y cruzar solo cuando puedan despejar las vías sin detenerse."},"53":{"q":"Conduce un tractocamión con remolque de 53 pies completamente cargado y se aproxima a un cruce ferroviario de vía única sin control en una carretera rural de dos carriles. No hay luces ni barreras, y su visión a lo largo de las vías está parcialmente bloqueada por la maleza. Sabe que nunca debe comenzar a cruzar a menos que pueda despejar por completo las vías sin detenerse. ¿Cuánto tiempo debe suponer que necesita un equipo como el suyo para despejar completamente una vía única, de modo que pueda juzgar si es seguro comenzar a cruzar?","options":["Unos 3 segundos, ya que ese es aproximadamente su tiempo de reacción a velocidad de autopista","El tiempo exacto no importa mientras no haya ningún tren a la vista en este momento","Unos 6 segundos, lo mismo que su tiempo total de frenado desde 55 mph","Al menos 14 segundos"],"explanation":"Un tractocamión típico necesita al menos 14 segundos para despejar por completo una sola vía férrea, así que deja ese tiempo antes de decidir cruzar."},"54":{"q":"Es media tarde, pero un aguacero fuerte ha reducido la visibilidad y el cielo se ha puesto gris oscuro. Todavía ve la carretera y los demás vehículos lo suficientemente bien como para conducir, así que se pregunta si las luces son siquiera necesarias ahora. ¿Por qué encender los faros de luz BAJA es la MEJOR acción en esta situación?","options":["Mantener los faros encendidos somete al alternador a carga, lo que ayuda a cargar la batería durante un viaje largo y lento bajo la lluvia","Los faros atraviesan la lluvia y mejoran notablemente la distancia a la que usted mismo puede ver la carretera por delante","Los faros hacen que su camión sea mucho más fácil de ver para los demás conductores con la luz tenue y lluviosa, aunque usted todavía vea bastante bien","Cambiar a luces altas bajo la lluvia proyecta la mayor cantidad de luz hacia adelante y es la forma más segura de que lo note el tráfico que viene de frente"],"explanation":"Con poca luz o lluvia, el propósito principal de los faros es hacer que su camión sea visible para otros conductores, aunque usted aún vea bien."},"55":{"q":"Durante su inspección previaje, camina alrededor de una plataforma plana (flatbed) cargada con tubería de acero y se detiene a revisar la pared protectora de carga (\"headache rack\", bastidor antichoque) montada en la parte delantera del remolque detrás de la cabina. Un conductor nuevo le pregunta por qué la empresa no deja salir el camión sin una en buen estado. ¿Qué respuesta describe mejor el propósito de SEGURIDAD que cumple este dispositivo?","options":["Bloquea la grava y los escombros del camino lanzados por las llantas delanteras para que no golpeen la carga","Señala que la carga es de gran tamaño para que el tránsito que sigue mantenga una distancia segura","Sirve como el punto de anclaje trasero al que las cadenas de amarre deben conectarse para una sujeción legal","Protege al conductor al impedir que la carga se deslice hacia adelante dentro de la cabina en una frenada brusca o un choque"],"explanation":"El cabezal o mampara protectora es una barrera que impide que la carga se deslice hacia adelante hacia la cabina y lesione al conductor en una frenada brusca o choque."},"56":{"q":"Es temprano por la mañana y está realizando una inspección de recorrido alrededor de su tractocamión antes de un viaje largo. Al revisar los ejes traseros, se agacha para observar los neumáticos duales. ¿Cuál de las siguientes observaciones le obligaría a poner el vehículo fuera de servicio antes de poder conducir de forma legal y segura?","options":["Los neumáticos del eje de dirección (delantero) miden cada uno 5/32 de pulgada de profundidad de banda","Los dos neumáticos duales del eje trasero están presionados uno contra el otro y haciendo contacto","Los cuatro neumáticos del eje trasero son del mismo tamaño y la misma marca","Los neumáticos de tracción traseros miden 3/32 de pulgada de profundidad de banda"],"explanation":"Las llantas dobles nunca deben tocarse, ya que el contacto indica un desajuste o baja presión que genera calor y puede provocar un reventón."},"58":{"q":"Está terminando la inspección previa al viaje de su tractocamión antes de un recorrido de 300 millas. Su supervisor le avisa por radio que un oficial en la carretera revisará su camión para verificar el equipo de emergencia exigido por las normas federales. Al mirar dentro de la cabina, se da cuenta de que falta un artículo de su equipo habitual y empieza a preocuparse. ¿Cuál de los siguientes es el artículo que NO está legalmente obligado a llevar a bordo para aprobar esa revisión?","options":["Un extintor de incendios debidamente cargado y de la clasificación correcta","Una llanta de repuesto inflada guardada en el vehículo","Un juego de tres triángulos reflectantes rojos de advertencia","Fusibles eléctricos de repuesto, a menos que el camión use disyuntores (interruptores automáticos)"],"explanation":"El equipo de emergencia obligatorio es un extintor, fusibles de repuesto y triángulos de advertencia; una llanta de repuesto no es obligatoria."},"59":{"q":"Está apenas bajo cero y sube por una leve pendiente sobre el tablero de un puente con un remolque cargado. Siente que las ruedas motrices traseras empiezan a patinar y la parte trasera del tractor se va hacia la izquierda. Para recuperar el control del conjunto, ¿qué acción EMPEORARÍA el derrape en lugar de ayudarle a recuperarse?","options":["Pisar más fuerte el acelerador para forzar a las ruedas motrices que patinan a volver a su línea","Soltar el acelerador y pisar el embrague para que las ruedas motrices reduzcan velocidad","Dirigir hacia donde quiere que vaya el tractor por el carril","Estar listo para contradirigir cuando el remolque empiece a enderezarse"],"explanation":"En un patinazo de ruedas motrices, deje de dar potencia: suelte el acelerador y pise el embrague para que las ruedas motrices recuperen tracción."},"60":{"q":"Son las 5:00 a.m. y está a punto de iniciar un viaje largo. Un compañero le dice que la empresa ya pagó la semana pasada a un mecánico de inspección, así que su propia revisión previa al viaje de esta mañana en realidad solo sirve para detectar algo que podría dejarlo varado en la carretera. ¿Qué afirmación describe MEJOR por qué Texas le exige realizar su propia inspección previa antes de CADA viaje?","options":["Su único propósito legítimo es detectar defectos mecánicos de seguridad antes de que causen un choque en la carretera.","Es fundamentalmente una formalidad legal que debe registrar para cumplir con las normas estatales y federales.","Su valor principal es prevenir averías en la carretera que le cuestan tiempo y dinero a la empresa.","Cumple todos estos propósitos a la vez: encontrar defectos de seguridad, cumplir con su deber legal y prevenir averías."],"explanation":"La inspección previaje cumple tres fines a la vez: detectar defectos de seguridad, cumplir su deber legal como conductor y prevenir averías costosas."},"61":{"q":"Conduce un tractocamión cargado a velocidad de autopista cuando un automóvil se le cruza de repente y frena con fuerza, dejando un peligro justo en su carril mientras el acotamiento a su derecha queda libre. Detenerse a tiempo no es posible. ¿Qué afirmación explica MEJOR por qué frenar fuerte por sí solo no siempre es la respuesta de emergencia más segura aquí?","options":["A menudo se puede esquivar un peligro con el volante en menos distancia de la que se necesita para detenerse, así que contradireccionar hacia el acotamiento libre puede evitar el choque cuando frenar no alcanza.","Detenerse nunca está permitido en una emergencia porque desperdicia el tiempo de reacción que la ley exige usar para girar el volante.","Hay que evitar frenar fuerte principalmente porque los frenos se sobrecalientan y pierden eficacia en los primeros segundos de cualquier frenada de pánico.","Como su remolque va cargado, su distancia total de frenado a 55 mph baja a unos 60 pies, así que frenar a esa distancia no sirve de nada."],"explanation":"Normalmente puede esquivar un peligro con la dirección en mucha menos distancia de la que toma frenar, por lo que virar hacia un arcén libre puede evitar el choque cuando frenar no alcanza."},"62":{"q":"Conduce un tractocamión cargado a 55 mph por una carretera seca cuando un automóvil se detiene de repente en su carril muy adelante. Desde el instante en que aparece el peligro hasta el instante en que su camión se detiene por completo, su distancia total de frenado se compone de tres partes separadas que ocurren una tras otra. ¿Qué secuencia enumera esas tres partes en el orden cronológico correcto, de la primera a la última?","options":["Distancia de reacción, luego distancia de frenado, luego distancia de percepción","Distancia de percepción, luego distancia de reacción, luego distancia de frenado","Distancia de frenado, luego distancia de reacción, luego distancia de percepción","Distancia de percepción, luego distancia de frenado, luego distancia de reacción"],"explanation":"La distancia total de frenado ocurre en secuencia: primero percibes el peligro, luego reaccionas y mueves el pie al freno, y después los frenos detienen el vehículo."},"65":{"q":"Va descendiendo una pendiente de montaña larga y empinada con un remolque cargado. A mitad de la bajada, pisa el pedal del freno y este se hunde hasta el fondo casi sin resistencia: los frenos de servicio han fallado y el camión está ganando velocidad. Hay una rampa de escape para vehículos sin frenos señalizada aproximadamente media milla más adelante. ¿Cuál es la ÚNICA mejor acción a tomar?","options":["Poner la transmisión en neutro para que el motor ya no lo frene y dejar que el camión ruede hasta detenerse de forma controlada","Bombear el pedal del freno rápida y repetidamente para intentar recuperar presión mientras continúa bajando la pendiente","Dirigirse a la rampa de escape que hay más adelante, construida para detener un vehículo cuyos frenos han fallado","Abrir de golpe la puerta del conductor y prepararse para saltar antes de que el camión llegue al final de la bajada"],"explanation":"Las rampas de escape están construidas para detener con seguridad un vehículo pesado cuyos frenos fallaron en una bajada, así que úsala siempre que haya una disponible."},"66":{"q":"Ha estado lloviendo de forma constante durante los últimos diez minutos y conduce un conjunto combinado cargado a 60 mph por una interestatal lisa y bien pavimentada. Nota que la dirección se siente ligera y el camión no responde cuando hace una pequeña corrección del volante. ¿Qué factor es el MÁS responsable de esta pérdida de contacto con la carretera?","options":["La superficie de la carretera está seca, por lo que los neumáticos delanteros han perdido agarre sobre el pavimento caliente","Hay agua en la carretera y conduce demasiado rápido, por lo que los neumáticos van sobre una película de agua","Conduce muy despacio, lo que permite que los neumáticos se hundan en el agua estancada","Sus neumáticos son nuevos y la banda de rodadura profunda canaliza demasiada agua"],"explanation":"El hidroplaneo ocurre cuando el agua en la carretera junto con exceso de velocidad levanta las llantas, haciéndolas rodar sobre una película de agua en vez del pavimento."},"67":{"q":"Es una calurosa tarde de verano y acaba de entrar a un área de descanso tras conducir 120 millas por la autopista. Durante la inspección a pie quiere confirmar que las llantas del eje motriz tienen la presión correcta antes de continuar. ¿Qué método le da una lectura de inflado precisa y confiable?","options":["Golpear cada llanta con un mazo o martillo de llantas y juzgar el inflado por el sonido y el rebote","Medir la presión ahora mismo con un manómetro mientras las llantas siguen calientes por la autopista, ya que esa es su verdadera presión de trabajo","Dejar que las llantas se enfríen primero y luego revisar cada una con un manómetro de presión debidamente calibrado","Observar de cerca cuánto se abulta cada llanta en la parte inferior y compararla con las demás"],"explanation":"Revise la presión de las llantas solo con un manómetro bien calibrado después de que se enfríen, ya que el calor de la conducción sube la presión y da una lectura falsamente alta."},"68":{"q":"Está incorporándose a una autopista interestatal con mucho tráfico en su tractocamión cargado. Un automóvil se pega justo detrás de su lado trasero derecho y desaparece de sus espejos, mientras otro coche circula al lado de su guardabarros izquierdo. Un compañero le dijo una vez que se preocupara sobre todo por la 'No-Zone'. En esta situación, ¿cuál es la No-Zone que debe controlar?","options":["El margen de espacio que debe mantener por delante, equivalente a unos 419 pies a 55 mph","Las grandes zonas de puntos ciegos alrededor de su camión donde otros vehículos pueden desaparecer de su vista","La zona de prohibido estacionar junto al bordillo derecho donde no puede detenerse para colocar los triángulos de advertencia","El carril de la izquierda de alta ocupación al que los camiones tienen prohibido entrar"],"explanation":"La No-Zone son las grandes áreas de punto ciego que rodean al camión por los cuatro lados, donde otros vehículos pueden desaparecer de la vista."},"69":{"q":"Está solo en un estacionamiento de camiones muy concurrido y necesita retroceder su tractocamión hacia un espacio estrecho junto a una pared a su derecha. Su remolque está vacío, el estacionamiento tiene mucho tránsito peatonal y no puede ver con claridad la zona detrás de su parte trasera derecha. ¿Cuál es la forma más segura de completar este retroceso?","options":["Retroceder hacia su lado derecho (ciego) para que la pared permanezca a la vista a través del parabrisas, y avanzar despacio","Retroceder rápido mientras todavía tiene un espacio, ya que demorarse en el carril crea más riesgo para los peatones","Confiar solo en su espejo del lado derecho y no bajarse, porque detenerse a mirar pierde tiempo en un estacionamiento concurrido","Reposicionarse si es necesario para poder retroceder hacia su lado izquierdo (del conductor), y usar un ayudante o guía que vigile su zona ciega"],"explanation":"Siempre que sea posible retroceda hacia el lado del conductor (izquierdo) para ver directamente a lo largo del remolque, y use un ayudante o guía para vigilar su punto ciego."},"70":{"q":"Conduce un tractocamión cargado a 55 mph en buenas condiciones, con pavimento seco, cuando de repente aparece un auto averiado en su carril a solo unas pocas longitudes de camión por delante — mucho más cerca que su distancia total de frenado de aproximadamente 419 pies. El carril contiguo está despejado. ¿Qué acción le da la MEJOR oportunidad de evitar una colisión?","options":["Esquivar el obstáculo girando hacia el carril despejado, ya que normalmente puede girar para evitar un obstáculo en menos distancia de la que se necesita para detenerse","Frenar tan fuerte como pueda y bloquear las ruedas, porque el frenado máximo siempre es la respuesta de emergencia más segura","Mantener la velocidad y pasar directamente a través, confiando en que la masa del camión apartará el obstáculo","Permanecer en su carril y frenar suavemente, ya que a 55 mph su distancia de frenado de 419 pies lo detendrá a tiempo"],"explanation":"Por lo general, puede esquivar un obstáculo en menos distancia de la que necesita para frenar por completo, así que use el carril libre para evitar el peligro."},"71":{"q":"Se aproxima a un cruce concurrido donde debe girar a la derecha, y hay una fila de vehículos detrás de usted. Para comunicar sus intenciones de forma segura y dar a los demás conductores el mayor tiempo posible para reaccionar, ¿cuándo debe activar la señal de giro?","options":["Toque el freno varias veces primero y luego señalice justo al iniciar el giro, para que los conductores que le siguen no se confundan con una señal demasiado anticipada","Señalice con bastante antelación antes del giro y mantenga la señal encendida hasta completar el giro","Solo después de haber reducido la velocidad y confirmado que el cruce está despejado, para evitar señalizar demasiado pronto","Señalice justo después de haber completado el giro para confirmar la maniobra a los conductores que van detrás"],"explanation":"Señalice con anticipación, mucho antes de girar, y mantenga la señal encendida hasta completar el giro para que otros conductores tengan el máximo tiempo de reacción."},"72":{"q":"La temperatura está justo bajo cero y una ligera llovizna helada ha dejado la carretera con aspecto mojado y brillante. Su camión cargado está equipado con un freno de motor (retardador). Al acercarse a un tramo de carretera donde podría necesitar reducir la velocidad de forma gradual, ¿cuál es la manera MÁS SEGURA de manejar el retardador en estas condiciones?","options":["Dejar el retardador totalmente activado, ya que reduce el desgaste de los frenos de servicio en mal tiempo","APAGAR el retardador, porque puede hacer que las ruedas motrices pierdan tracción y patinen sobre la superficie resbaladiza","Mantener el retardador en su nivel más alto para poder reducir la velocidad sin tocar el pedal del freno","Usar el retardador solo cuando su velocidad supere las 40 mph y apagarlo por debajo de esa velocidad"],"explanation":"Apague el ralentizador en caminos mojados, helados o resbaladizos, ya que frena solo las ruedas motrices y puede hacer que pierdan tracción y patinen."},"73":{"q":"Lleva un remolque completamente cargado y ha comenzado a subir una pendiente larga y empinada en la montaña. El tractor empieza a esforzarse, las revoluciones del motor (RPM) caen y su velocidad disminuye rápidamente. ¿Qué acción le permite seguir conduciendo con seguridad y mantener la mayor potencia del motor en la subida?","options":["Mantener la transmisión en sobremarcha (overdrive) y pisar el acelerador a fondo para recuperar velocidad","Cambiar a una marcha más baja para que el motor se mantenga en su rango de potencia y tire de la carga de forma constante","Poner la transmisión en neutro y dejar que el impulso lo lleve hasta la cima de la pendiente","Mantener la marcha actual y bombear suavemente los frenos de servicio para mantener el vehículo bajo control"],"explanation":"En una subida larga y empinada, reduzca a una marcha más baja para mantener las RPM del motor en su rango de potencia y que tire de la carga de manera constante."},"74":{"q":"Circula vacío a 30 mph por una carretera rural seca y ha aprendido a dejarse suficiente espacio para frenar. El tráfico de adelante se despeja y acelera a 60 mph. En comparación con la distancia de frenado que necesitaba a 30 mph, ¿qué debe esperar ahora de la distancia de frenado por sí sola a 60 mph?","options":["Solo se duplica, ya que duplicó la velocidad -- así que dejar el doble de espacio es suficiente","Aumenta aproximadamente cuatro veces, porque la distancia de frenado crece con el cuadrado de la velocidad","Se mantiene casi igual, porque un camión vacío se detiene en una distancia más corta que uno cargado","Aumenta cerca de la mitad, ya que la distancia total de detención también incluye la distancia de reacción"],"explanation":"La distancia de frenado aumenta con el cuadrado de la velocidad, por lo que duplicar la velocidad la hace aproximadamente cuatro veces mayor."},"75":{"q":"Son las 2 de la madrugada en un viaje nocturno largo y nota que los párpados le pesan, se ha desviado dentro de su carril y no recuerda las últimas millas. Todavía le quedan varias horas de conducción legal en su registro. ¿Cuál es la ÚNICA forma realmente eficaz de afrontar esta fatiga?","options":["Bajar la ventanilla y dejar que el aire frío le dé en la cara para mantenerse alerta","Tomar un café grande y seguir adelante para terminar el viaje mientras aún tiene horas disponibles","Salir de la autopista en un lugar seguro y detenerse a descansar o dormir antes de continuar","Subir el volumen de la radio y bajar la temperatura de la cabina para mantenerse despierto"],"explanation":"La única cura segura para la somnolencia es detenerse y descansar o dormir, ya que nada más restablece realmente el estado de alerta."},"77":{"q":"Conduce un tractocamión cargado por una autopista de cuatro carriles cuando unas señales naranjas advierten de una zona de obras más adelante. Al entrar, el límite señalizado baja y se ven un señalero y varios trabajadores cerca del carril derecho de circulación. El tráfico fluye con normalidad y nadie va justo detrás de usted. ¿Cuál es la MEJOR acción al atravesar la zona?","options":["Mantener su velocidad de autopista, ya que el tráfico fluye y despejar la zona rápidamente reduce su tiempo cerca de los trabajadores","Reducir la velocidad al límite señalizado de la zona de obras, aumentar la distancia de seguimiento y estar atento a los trabajadores que entren al carril","Cambiarse al carril izquierdo a su velocidad actual y acelerar para pasar al señalero antes de que cambien las condiciones","Mantenerse pegado al vehículo de adelante para que otros conductores no se metan entre ustedes y lo obliguen a frenar cerca de los trabajadores"],"explanation":"En una zona de trabajo, reduzca a la velocidad indicada, aumente la distancia de seguimiento y vigile a los trabajadores que entren al carril para tener espacio suficiente para frenar."},"78":{"q":"Durante su inspección previaje supervisa la carga de cajas ligeras pero voluminosas en su furgón cerrado. Para que quepan todas, la cuadrilla las apila en alto, dejando la mayor parte del peso en lo alto del remolque en lugar de repartido bajo sobre el piso. El peso total de la carga está muy por debajo de los límites de sus ejes y la carga está centrada de lado a lado. Al salir y acercarse a la primera curva de la rampa de acceso a la autopista, cual es el efecto MAS importante de cómo se apiló esta carga?","options":["Como el peso está centrado y dentro de los límites de los ejes, el remolque en realidad tomará la curva con más estabilidad que una carga apilada baja.","El apilado alto no tiene efecto real en el manejo, ya que el peso de la carga está dentro de los límites legales de los ejes.","El centro de gravedad alto hace que el vehículo tenga muchas más probabilidades de volcarse en la curva, aunque la carga se sienta segura en la recta.","El riesgo principal es una distancia de frenado mucho mayor, porque el peso apilado en alto reduce la tracción de frenado."],"explanation":"Apilar carga ligera y voluminosa en alto eleva el centro de gravedad, lo que aumenta considerablemente el riesgo de volcar en una curva."},"79":{"q":"Durante su inspección previaje, transporta una sola bobina de acero que pesa 8,000 lb sobre su plataforma plana. Comienza a revisar sus cadenas de amarre y tensores para confirmar que su carga está asegurada legalmente. Además del requisito de que la bobina de acero esté calzada y arriostrada, ¿qué afirmación describe correctamente el límite de carga de trabajo combinado (agregado) MÍNIMO que deben proporcionar sus amarres para esta carga de 8,000 lb?","options":["El límite de carga de trabajo combinado de los amarres debe ser igual al peso total de la carga, es decir, al menos 8,000 lb.","El límite de carga de trabajo combinado de los amarres debe ser al menos un cuarto del peso de la carga, es decir, al menos 2,000 lb.","El límite de carga de trabajo combinado de los amarres debe ser al menos el doble del peso de la carga, es decir, al menos 16,000 lb.","El límite de carga de trabajo combinado de los amarres debe ser al menos la mitad del peso de la carga, es decir, al menos 4,000 lb."],"explanation":"El límite de carga de trabajo combinado de todas las amarras debe ser al menos la mitad del peso de la carga."},"80":{"q":"Se aproxima a un giro a la derecha cerrado en una intersección urbana con su tractocamión. Sabe que el remolque seguirá una trayectoria más corta que la del tractor (desplazamiento de la trayectoria de los ejes traseros) y le preocupa que las ruedas traseras suban al bordillo. Para evitar que la parte trasera del remolque golpee el bordillo, ¿cuál es la forma más segura de hacer este giro a la derecha?","options":["Iniciar el giro desviando el frente del vehículo ampliamente hacia la IZQUIERDA y luego girar bruscamente a la derecha para que el remolque libre el bordillo","Girar de forma amplia al COMPLETAR el giro manteniendo la parte trasera del vehículo cerca del bordillo, para que otros conductores no puedan meterse por su derecha","Comenzar el giro desde el carril izquierdo y acelerar para reducir el tiempo que bloquea la intersección","Mantenerse a la derecha y girar ampliamente hacia la izquierda solo si es absolutamente necesario, aceptando que el tránsito pueda pasarle por la derecha"],"explanation":"Gire abierto solo al completar un giro a la derecha, manteniendo la parte trasera pegada al bordillo, para que nadie pueda meterse por su derecha."},"81":{"q":"Está transportando un remolque completamente cargado por una carretera estatal y se acerca a una curva amplia. Una señal al borde del camino dice 'Curva — 45 MPH'. Su camión es pesado y de carrocería alta, pero el pavimento está seco y el clima despejado. ¿Qué afirmación describe MEJOR cómo debe interpretar esa velocidad de curva señalizada de 45 MPH?","options":["Considere las 45 MPH como un máximo para automóviles en buenas condiciones, y reduzca por debajo de esa cifra porque su camión cargado y de carrocería alta necesita una velocidad menor para evitar el vuelco.","Considere las 45 MPH como la velocidad calculada específicamente para camiones pesados cargados como el suyo, de modo que puede tomar la curva con seguridad exactamente a 45 MPH.","Como el pavimento está seco y el clima despejado, puede añadir un margen y tomar la curva ligeramente por encima de 45 MPH.","La velocidad señalizada solo aplica de noche, así que en pleno día despejado puede ignorarla y mantener su velocidad de carretera en la curva."],"explanation":"Las velocidades indicadas en las curvas se fijan para automóviles en buenas condiciones, por lo que un camión cargado y de centro alto debe bajar de esa velocidad para evitar volcar."},"82":{"q":"Usted desciende un descenso de montaña largo y empinado con un remolque completamente cargado. A mitad del descenso, nota que el pedal del freno se está volviendo más blando y el camión va ganando velocidad poco a poco, aunque ha estado presionando los frenos de forma constante durante todo el descenso. ¿Cuál de las siguientes es la causa MÁS probable de esta pérdida de potencia de frenado?","options":["Los frenos todavía están fríos porque apenas comenzó el descenso, por lo que aún no agarran por completo","Los frenos se han sobrecalentado por presionarlos continuamente, lo que provoca que se desvanezcan (fade) y pierdan capacidad de frenado","El remolque está demasiado ligero de carga, por lo que no hay suficiente peso presionando las zapatas contra los tambores","Las zapatas de freno son nuevas y necesitan asentarse antes de poder sostener el vehículo en una pendiente"],"explanation":"Mantener los frenos aplicados en una bajada larga los sobrecalienta, lo que provoca pérdida de eficacia y de capacidad de frenado."},"83":{"q":"Va cargado circulando por una autopista mojada de cuatro carriles cuando un automóvil se le cruza de repente y frena con fuerza. La luz de ABS del tablero está apagada, así que el sistema funciona. Al pisar el freno a fondo y activarse el ABS, ¿cuál es el beneficio PRINCIPAL que debe esperar del ABS en esta frenada brusca?","options":["Le garantiza que se detendrá en una distancia notablemente más corta que un camión sin ABS","Bombea los frenos automáticamente, así que ya no necesita usar el frenado por golpes (stab) en pavimento seco","Evita que las ruedas se bloqueen, de modo que puede seguir dirigiendo y mantenerse en su carril mientras frena con fuerza","Le permite omitir la revisión del ajuste de frenos en la inspección previa al viaje porque la computadora vigila los frenos"],"explanation":"El ABS evita que las ruedas se bloqueen al frenar fuerte, de modo que conserva el control de la dirección para mantenerse en el carril o esquivar un peligro."},"84":{"q":"Acaba de descargar su última carga y ahora regresa al patio con el remolque vacío por una carretera mojada de dos carriles. Un automóvil delante frena bruscamente y usted debe detenerse rápidamente. En comparación con cuando iba completamente cargado más temprano hoy, ¿qué debe esperar de su unidad vacía en esta situación?","options":["Sin el peso de la carga presionando hacia abajo, las llantas se agarran mejor al camino, así que siempre se detendrá en una distancia más corta que cuando iba cargado.","Un camión vacío se comporta exactamente igual que uno cargado, por lo que su distancia de frenado no cambia en ninguno de los dos casos.","Como hay tan poco peso, las ruedas no pueden bloquearse ni patinar, así que frenar fuerte ahora es completamente seguro.","El camión vacío tiene menos tracción y puede rebotar, por lo que en realidad podría tomarle más distancia detenerse que cuando iba cargado."],"explanation":"Un camión vacío tiene menos tracción y tiende a rebotar, por lo que puede tardar más en detenerse que cuando va cargado."},"85":{"q":"Falta aproximadamente una hora para el atardecer y comienza una lluvia ligera cuando entra a una carretera de dos carriles. La visibilidad aún es bastante buena y puede ver la carretera con claridad sin ellos, pero cada vez cuesta más distinguir los autos que vienen de frente contra el cielo gris. ¿Cuál es la mejor práctica para sus faros en esta situación?","options":["Déjelos apagados, porque solo es necesario encenderlos cuando ya está completamente oscuro y no puede ver la carretera por delante","Enciéndalos ahora, porque ayudan a que otros conductores lo vean al atardecer y bajo lluvia, niebla u otras condiciones de poca luz","Use solo las luces altas, ya que la lluvia y la luz que se desvanece significan que necesita la máxima iluminación frontal disponible","Espere hasta llegar a una autopista dividida de mayor velocidad, ya que los faros se necesitan principalmente a velocidades de autopista"],"explanation":"Encienda los faros al anochecer y con lluvia o niebla porque hacen visible su vehículo para otros conductores en condiciones de poca luz."},"86":{"q":"Está retrocediendo con su remolque hacia un muelle de carga estrecho y mira el espejo auxiliar convexo (curvo) grande del lado del pasajero. Un automóvil que usted sabe que está estacionado a solo unos pocos pies detrás de su parachoques trasero se ve pequeño y lejano en ese espejo. Antes de continuar retrocediendo, ¿qué debe entender sobre lo que le muestra este espejo convexo?","options":["Le ofrece un campo de visión más amplio, pero los objetos en él se ven más pequeños y más lejanos de lo que realmente están, así que ese automóvil está más cerca de lo que parece","Amplía la imagen, por lo que los objetos se ven más grandes y más cercanos de lo que realmente están, lo que significa que ese automóvil en realidad está más lejos de lo que parece","Muestra el tamaño y la distancia reales de los objetos, así que puede confiar en que el automóvil está tan atrás como aparece en el espejo","Está fallando, porque un espejo bien ajustado nunca haría que un objeto cercano se viera pequeño, y de todos modos los espejos convexos no son legales en vehículos comerciales"],"explanation":"Un espejo convexo ofrece un campo de visión más amplio, pero hace que los objetos parezcan más pequeños y lejanos, por lo que en realidad están más cerca de lo que aparentan."},"87":{"q":"Conduce un tractocamión cargado a velocidad de autopista cuando, a unos 12 a 15 segundos por delante, divisa un auto averiado que bloquea parcialmente el carril derecho con sus luces de emergencia encendidas. El tránsito a su alrededor aún circula con normalidad y todavía no hay una emergencia inmediata. ¿Cuál debe ser su PRIMERA acción?","options":["Mantener su velocidad y posición hasta que el auto esté lo bastante cerca para juzgar con exactitud cuánto invade su carril","Empezar a prepararse para reaccionar ya -- soltar el acelerador, revisar los espejos y planificar una vía de escape para poder ajustar con suavidad antes de que se convierta en una emergencia","Aplicar de inmediato un frenado intermitente (controlado) fuerte para reducir cuanta velocidad sea posible de una vez","Cambiarse al carril izquierdo de inmediato y acelerar para despejar la zona antes de que el resto del tránsito reaccione"],"explanation":"Detectar un peligro a tiempo da margen para reaccionar, así que suelte el acelerador, revise los espejos y planifique una vía de escape antes de que se vuelva una emergencia."},"88":{"q":"Conduce con un remolque vacío a 55 mph en una autopista interestatal durante un aguacero intenso. Siente que la dirección se vuelve ligera y el camión empieza a sentirse como si flotara, con las llantas delanteras que ya no siguen del todo la carretera. Se da cuenta de que está empezando a hidroplanear. ¿Qué acción le da la MEJOR posibilidad de recuperar la tracción de forma segura?","options":["Pisar el freno con firmeza para reducir la velocidad rápidamente y forzar las llantas de vuelta al pavimento","Girar bruscamente hacia el arcén para que las llantas delanteras se agarren a la superficie más rugosa","Quitar el pie del acelerador, mantener el volante recto y dejar que el camión reduzca la velocidad hasta que las llantas vuelvan a agarrar","Reducir la marcha de forma agresiva y usar el freno motor para quitar velocidad lo más rápido posible"],"explanation":"En el hidroplaneo los neumáticos pierden contacto con el camino, así que suelte el acelerador y mantenga el volante recto hasta que reduzcan velocidad y recuperen tracción."},"89":{"q":"Acaba de cruzar lentamente con su vehículo combinado cargado un vado inundado, y el agua subió lo suficiente como para cubrir los cubos de las ruedas. Al acelerar de nuevo a velocidad de carretera, toca los frenos y siente que agarran débil y desigualmente. ¿Cuál es la MEJOR manera de recuperar un frenado seguro?","options":["Detenerse en el acotamiento y esperar a que los tambores de freno se sequen al aire antes de continuar","Bombear el pedal del freno con fuerza varias veces para expulsar el agua de las balatas","Reducir la marcha y depender solo del freno motor, sin tocar los frenos de servicio durante las próximas millas","Seguir conduciendo despacio y aplicar presión ligera y constante sobre los frenos para secarlos con el calor de la fricción"],"explanation":"Seque los frenos mojados conduciendo despacio y aplicando presión ligera y constante para que el calor por fricción evapore el agua y usted mantenga el control."},"90":{"q":"Va con retraso en una carretera rural de dos carriles con un límite de 55 mph. El vehículo delante avanza despacio y usted está ansioso por rebasar. ¿En cuál de las siguientes situaciones intentar rebasar sería MENOS seguro y, por lo tanto, algo que NO debería hacer?","options":["Se aproxima a la cima de una colina y no puede ver si viene algún vehículo hacia usted en el carril contrario","Está en un tramo largo, plano y recto donde ve claramente que la vía está despejada por más de un cuarto de milla por delante","Ha entrado en una zona de rebase señalizada con línea central amarilla discontinua de su lado y buena visibilidad por delante","Puede ver que el carril contrario está despejado y tiene espacio suficiente para volver a su carril mucho antes de que llegue tráfico en sentido contrario"],"explanation":"Nunca rebase donde no pueda ver suficientemente lejos, como cerca de la cima de una colina, porque los vehículos que vienen permanecen ocultos hasta que es demasiado tarde."},"91":{"q":"Conduce un tractocamión cargado por una rampa de entrada corta. La autopista a su izquierda circula a unas 60 mph, y ve un espacio aprovechable que se abre entre dos autos en el carril derecho más adelante. Al llegar al final del carril de aceleración, ¿cuál es la forma MÁS SEGURA de incorporarse al tráfico?","options":["Reducir casi hasta detenerse al final de la rampa y esperar un espacio muy grande antes de salir","Usar el carril de aceleración para llevar su velocidad cerca del flujo del tráfico y luego incorporarse suavemente en el espacio abierto","Mantener la velocidad baja e introducirse poco a poco en el carril, obligando a los autos de atrás a frenar y hacerle lugar","Mantener un avance lento y constante por la rampa para tener más tiempo de evaluar el tráfico antes de incorporarse"],"explanation":"Use el carril de aceleración para alcanzar una velocidad cercana al flujo del tráfico y luego incorpórese en un espacio para que la diferencia de velocidad sea mínima."},"92":{"q":"Conduce un tractocamión cargado por el carril derecho de una autopista dividida de cuatro carriles cuando escucha una sirena y ve por los espejos una ambulancia que se aproxima rápidamente con las luces encendidas. El tráfico es moderado y hay un acotamiento pavimentado a su derecha. ¿Cuál es la MEJOR acción?","options":["Mantener su carril y velocidad para que la ambulancia pueda prever su trayectoria y rebasarlo por la izquierda","Acelerar para mantenerse delante de la ambulancia hasta la próxima salida y luego abandonar la autopista","Señalizar, dirigir el vehículo hacia el acotamiento derecho y detenerse cuando sea seguro para despejar el paso","Cambiarse a la izquierda al carril de rebase para dejar libre el carril derecho y el acotamiento al vehículo de emergencia"],"explanation":"Ante un vehículo de emergencia con luces y sirena, señale, oríllese al acotamiento derecho y deténgase cuando sea seguro para ceder el paso y despejar el camino."},"93":{"q":"Se inicia un pequeño incendio eléctrico en el compartimiento del motor de su tractocamión después de que se orilla en el acotamiento. Toma el extintor, se coloca de espaldas al viento, jala el pasador y apunta la boquilla. Siguiendo correctamente el método PASS, después de apretar la palanca, ¿cuál es la acción final que debe realizar para apagar el fuego de manera eficaz?","options":["Mantener la boquilla fija y apuntar directamente a la parte superior de las llamas visibles hasta que disminuyan","Dejar de descargar de inmediato en cuanto aparezca humo para no desperdiciar el extintor","Girar el extintor en movimiento circular por encima del fuego para esparcir el agente sobre una zona amplia","Barrer la boquilla de lado a lado, apuntando a la base del fuego, hasta que quede extinguido"],"explanation":"El último paso del método PASS es barrer la boquilla de lado a lado en la base del fuego, donde arde el combustible, para sofocarlo y extinguirlo."},"94":{"q":"Conduce por una carretera rural de dos carriles cuando otro conductor se pone a su lado, señalando y gritando que uno de los neumáticos de su remolque está en llamas. Se detiene en el arcén, aplica los frenos y toma el extintor y el kit de seguridad vial. Al acercarse al neumático en llamas, ¿cuál es la acción MÁS apropiada para controlar este incendio?","options":["Rocíe el neumático con abundante agua para enfriarlo, porque un incendio de neumático genera un calor intenso y necesita enfriamiento continuo para apagarse","Apunte su extintor de polvo químico seco (clase B:C) directamente a la base de las llamas y manténgalo ahí hasta vaciar el cilindro","Déjelo y permita que se consuma solo a una distancia segura, ya que sofocar un incendio de caucho solo hace que vuelva a avivarse","Con cuidado, añada aire al neumático para evitar que la carcasa se colapse mientras las llamas se apagan"],"explanation":"Un incendio de neumático retiene calor intenso en el caucho, así que rocíelo con abundante agua para enfriarlo continuamente o se reavivará."},"95":{"q":"La temperatura está justo bajo cero y una lluvia ligera empieza a cubrir la carretera con una capa de hielo. Mientras mantiene su velocidad normal de autopista en una curva amplia, la parte trasera de su tractocamión de repente comienza a deslizarse hacia un lado y siente que el remolque empuja la cabina lateralmente. Si analiza con honestidad el momento en que empezó el derrape, ¿cuál fue la causa individual MÁS probable?","options":["Las llantas del eje delantero de dirección estaban gastadas casi al mínimo de 2/32 de pulgada y perdieron el agarre primero","Conducía demasiado rápido para las condiciones resbaladizas de la carretera cerca del punto de congelación","Usó movimientos del volante suaves y delicados en la curva en lugar de correcciones bruscas","Su remolque iba vacío, y los remolques vacíos siempre se agarran mejor a la carretera que los cargados"],"explanation":"La mayoría de los derrapes se deben a conducir demasiado rápido para las condiciones, y un camino resbaloso casi helado reduce la tracción, volviendo excesiva una velocidad normal."},"96":{"q":"La temperatura está justo bajo cero y ha estado cayendo una lluvia ligera. Usted circula en el carril central de una autopista de tres carriles cuando el remolque detrás empieza a sentirse liviano y a desviarse hacia el carril contiguo. De las siguientes acciones, ¿cuál le da la MEJOR posibilidad de mantener el vehículo bajo control y evitar un derrape total?","options":["Frenar con fuerza y mantener el pedal presionado firmemente para reducir la velocidad lo más rápido posible","Hacer una corrección de dirección rápida y brusca de vuelta hacia el centro de su carril para detener el desvío","Soltar el acelerador y realizar movimientos suaves y delicados de dirección y freno para conservar la tracción","Mantener su velocidad actual y girar con fuerza, ya que las llantas todavía tienen agarre en el carril central"],"explanation":"En caminos resbalosos y casi helados, reduzca la exigencia sobre los neumáticos soltando el acelerador y haciendo movimientos suaves y gentiles de dirección y frenado para conservar tracción."},"97":{"q":"Es media tarde a finales de julio y lleva varias horas conduciendo cargado sobre asfalto caliente. Durante una parada de descanso decide revisar las llantas con más frecuencia de lo habitual en este viaje. ¿Cuál es la MEJOR razón para hacerlo en estas condiciones?","options":["El pavimento caliente enfría el aire dentro de las llantas, por lo que pierden presión y ruedan con baja presión","El calor ablanda el caucho de la banda de rodadura, que es la causa principal de un reventón en verano","Las llantas se contraen físicamente con el calor, reduciendo el tamaño de la huella de contacto","El calor aumenta la presión del aire dentro de las llantas, lo que puede provocar un reventón"],"explanation":"Con clima caluroso el aire dentro de los neumáticos se expande y la presión aumenta, lo que puede provocar un reventón."},"98":{"q":"Está transportando carga en una carretera rural de dos carriles cuando entra en un banco de niebla tan densa que ya no puede ver las líneas del carril ni ningún vehículo por delante, incluso después de reducir la velocidad y cambiar a las luces bajas. Reducir aún más la velocidad no le ha devuelto la capacidad de ver un camino seguro. ¿Cuál es la acción más segura?","options":["Cambiar a las luces altas para proyectar más luz a través de la niebla y seguir avanzando muy despacio","Reducir casi hasta detenerse en su carril, encender las luces intermitentes de emergencia y seguir avanzando poco a poco","Salirse completamente de la calzada, alejarse bien del tráfico, encender las luces y las intermitentes y esperar a que la niebla se disipe","Mantener una velocidad lenta y constante y seguir las luces traseras del vehículo de adelante para mantenerse en su carril"],"explanation":"Cuando la niebla sea tan densa que no vea un camino seguro ni a baja velocidad, salga completamente de la vía, aléjese del tráfico, encienda luces e intermitentes y espere a que se disipe."},"99":{"q":"Esta mañana completó una inspección previa al viaje minuciosa, aseguró su carga y todo estaba en orden. Tres horas después de iniciar su recorrido, se detiene para almorzar y un colega le pregunta por qué está rodeando su camión y revisando su carga otra vez si ya la inspeccionó antes de salir. ¿Cuál es la MEJOR razón para seguir inspeccionando a lo largo del día?","options":["Una inspección adecuada es un proceso continuo que se realiza antes del viaje, durante el viaje (en ruta) y después del viaje, porque el estado del vehículo y la sujeción de la carga pueden cambiar mientras conduce.","Una vez que un vehículo aprueba una inspección previa al viaje completa, la ley lo considera apto para circular durante el resto de ese viaje, por lo que rodear el vehículo es solo un hábito personal, no un requisito.","Las inspecciones en ruta solo son necesarias si se enciende una luz de advertencia o si el vehículo realmente se avería, ya que una inspección previa aprobada ya cubre todo lo mecánico.","Una nueva revisión se requiere estrictamente porque debe inspeccionar la carga dentro de las primeras 50 millas, y después de esa primera revisión no es necesaria ninguna otra inspección del vehículo durante el día."],"explanation":"La inspección es continua — antes, durante (en ruta) y después del viaje — porque la presión de los neumáticos, la sujeción de la carga y los niveles de líquidos cambian al conducir."},"100":{"q":"Esta mañana cargó una plataforma plana con bobinas de acero y salió del patio hacia la autopista interestatal. A unas 35 millas de camino ve una amplia área de descanso con espacio para caminar alrededor de todo su equipo. Su viaje supera las 300 millas en total. Según el procedimiento correcto de carga, ¿qué debe hacer respecto a revisar su carga y su sujeción?","options":["Seguir conduciendo y hacer su primera revisión de sujeción en la marca de las 150 millas, ya que ese es el intervalo estándar de reinspección","Detenerse e inspeccionar su carga y las amarras ahora, porque debe hacer su primera revisión dentro de las primeras 50 millas y luego reinspeccionar cada 3 horas o 150 millas","No se necesita ninguna inspección hasta que pare a cargar combustible, siempre que la carga se viera segura durante su inspección previa al viaje","Esperar a haber conducido las primeras 500 millas y luego comenzar a inspeccionar la carga periódicamente"],"explanation":"Debe revisar la carga y las amarras dentro de las primeras 50 millas, y luego cada 3 horas o 150 millas y después de cada descanso."},"101":{"q":"Durante su inspección previa al viaje, está revisando cómo se aseguró una carga de tubería de acero en el área de carga detrás de la cabina. Un compañero le dice que la única razón real para amarrar la carga con fuerza es para que no se raye ni se vea desordenada durante el viaje. Según las normas de carga del DPS de Texas, ¿cuál es la razón PRINCIPAL de seguridad por la que la carga debe asegurarse correctamente?","options":["Para que la carga se mantenga ordenada y presentable al llegar al punto de entrega","Para que la carga esté protegida de la lluvia, el polvo del camino y se mantenga seca en mal tiempo","Para que la carga no pueda desplazarse, caerse del vehículo ni moverse y bloquear los controles del conductor","Para que la carga no se enfríe ni se congele al conducir en condiciones invernales"],"explanation":"La carga debe asegurarse para que no pueda desplazarse, caerse del vehículo ni deslizarse a la cabina y bloquear los controles del conductor."},"102":{"q":"Conduce un tractocamión cargado en dirección oeste a última hora de la tarde. El sol ha descendido bajo en el horizonte justo enfrente, y su resplandor desdibuja la carretera y dificulta calcular hasta dónde puede ver. Los vehículos que van delante aparecen de repente desde ese velo brillante. ¿Cuál es la mejor forma de manejar esta situación?","options":["Bajar la visera, ponerse gafas de sol y reducir la velocidad para poder detenerse dentro de la distancia que realmente puede ver","Encender las luces altas para que su propia iluminación atraviese el resplandor de adelante","Mantener la velocidad pero aumentar la distancia de seguimiento a 6 segundos para compensar","Cambiarse al carril izquierdo y acelerar para pasar más rápido el tramo afectado por el resplandor"],"explanation":"Con deslumbramiento solar, baje la visera, póngase gafas de sol y reduzca la velocidad para poder detenerse dentro de la distancia que realmente ve."},"103":{"q":"Está subiendo una pendiente larga y empinada con un remolque cargado por una carretera rural de dos carriles. El motor se esfuerza y su velocidad ha bajado a unas 15 mph, muy por debajo del límite señalizado de 55 mph, mientras los autos se acumulan detrás de usted. ¿En cuál de estas situaciones encender las luces intermitentes de emergencia (cuatro direccionales) es la acción MÁS apropiada?","options":["Cuando hace un giro normal a la derecha en la próxima intersección, ya que su intermitente sola podría no verse","Una vez que llega a la cima y retoma la marcha al límite de 55 mph, para avisar a los conductores que es un vehículo comercial lento","Después de estacionar el camión durante la noche en una parada de camiones bien iluminada, para que otros vean su silueta","Ahora, mientras avanza muy lento subiendo la pendiente, muy por debajo del flujo del tránsito, porque se mueve mucho más despacio que los vehículos a su alrededor"],"explanation":"Encienda las luces intermitentes de emergencia cuando circule mucho más despacio que el tráfico, como al subir lentamente una pendiente, para advertir a los conductores de atrás."},"105":{"q":"Se acerca a una rotonda de varios carriles en su vehículo combinado cargado. Un automóvil ya está circulando en el carril en el que pretende entrar, y se está abriendo un espacio justo detrás de él. ¿Cuál de las siguientes es la acción correcta y más segura?","options":["Ceda el paso al vehículo que ya está en la rotonda, espere un espacio seguro, luego entre e incorpórese al flujo del tráfico","Mantenga su velocidad y entre de inmediato, ya que los vehículos que ya están en la rotonda deben ceder el paso a los camiones que entran","Deténgase dentro del carril de circulación de la rotonda y espere allí hasta que todo el demás tráfico se haya despejado","Si calcula mal el espacio y comienza a entrar demasiado pronto, dé marcha atrás para restablecer una distancia de seguimiento segura antes de incorporarse"],"explanation":"El tráfico que ya circula en una glorieta tiene la preferencia, así que ceda el paso, espere un espacio seguro y luego entre e incorpórese al flujo."},"106":{"q":"Conduce un remolque cargado por el carril derecho al límite señalizado cuando un conductor detrás de usted empieza a pegarse demasiado, le hace ráfagas con las luces altas y le gesticula con enojo porque usted no acelera. El tráfico de adelante le impide cambiar de carril de inmediato. ¿Cuál es la MEJOR manera de manejar a este conductor agresivo y proteger su propia seguridad?","options":["Tocar ligeramente el freno para encender las luces de freno y advertir al conductor que se aleje","Mantener su velocidad y conservar firmemente su carril para que el conductor aprenda a no acosar a los camiones grandes","Cuando sea seguro, cambiarse de carril o reducir un poco para abrir espacio y dejar pasar al conductor enojado sin reaccionar a sus gestos","Acelerar por encima del límite señalizado hasta adelantarse lo suficiente para que el conductor deje de pegarse"],"explanation":"Con un conductor agresivo detrás, no reaccione; déle espacio para que pase y mantenga la calma para evitar el conflicto."},"107":{"q":"Una fuerte tormenta ha dejado varias pulgadas de agua estancada acumulada en el carril derecho de la autopista por la que conduce. Va vacío y circula a 55 mph. Al acercarse a la zona de agua profunda que tiene delante, ¿cuál es la MEJOR manera de mantener el control de su vehículo?","options":["Mantener 55 mph pero dirigirse hacia el arcén, ya que alejar el agua de las llantas de dirección recupera el agarre","Reducir la velocidad antes de llegar al agua, porque el agua atrapada entre las llantas y la carretera puede causar hidroplaneo y la pérdida del control de la dirección y de los frenos","Acelerar con firmeza al cruzar el agua para que la banda de rodadura de las llantas la desvíe y las llantas sigan agarrando el pavimento","Mantener la velocidad constante y frenar levemente mientras está en el agua para comprobar cuánta tracción le queda"],"explanation":"Reduzca la velocidad antes de llegar al agua estancada, porque el agua entre los neumáticos y la carretera puede causar hidroplaneo y pérdida de control de dirección y frenado."},"108":{"q":"Va conduciendo vacío por una autopista interestatal seca y despejada y decide subir su velocidad de crucero de 30 mph a 60 mph para recuperar tiempo. Un aprendiz que va con usted le pregunta cómo afecta este cambio a la distancia que su vehículo necesitará para frenar hasta detenerse por completo. ¿Cuál respuesta describe MEJOR lo que realmente ocurre?","options":["Como el camión va vacío, la carga más ligera le permite detenerse a 60 en aproximadamente la misma distancia que a 30.","Duplicar la velocidad solo añade un poco a la frenada — la distancia de frenado crece en proporción a la velocidad, así que solo se duplica.","Duplicar la velocidad cuadruplica aproximadamente la distancia de frenado, por lo que a 60 mph se necesita unas cuatro veces el espacio que a 30 mph.","El pavimento mojado sí importaría, pero en esta carretera seca la mayor velocidad apenas cambia la distancia que necesita para detenerse."],"explanation":"La distancia de frenado aumenta con el cuadrado de la velocidad, por lo que duplicar la velocidad cuadruplica aproximadamente la distancia para detenerse."},"109":{"q":"La temperatura está justo bajo cero y una lluvia ligera ha cubierto la carretera con una capa de hielo. Va conduciendo vacío y las ruedas traseras del camión empiezan a deslizarse en una curva. Al analizar qué provocó este patinazo, ¿cuál de las siguientes acciones que usted realizó es la MENOS probable de haberlo causado?","options":["Pisar el acelerador con fuerza para atravesar la curva con tracción","Frenar bruscamente hasta bloquear las ruedas en cuanto sintió que la parte trasera se movía","Mantener el giro del volante suave y gradual durante toda la curva","Llevar demasiada velocidad para las condiciones heladas y mojadas"],"explanation":"Una dirección suave y gradual mantiene las fuerzas del neumático dentro de la tracción disponible, por lo que no causa derrapes, a diferencia del exceso de velocidad, el frenado brusco o la aceleración excesiva."},"110":{"q":"Es bien entrada la noche en una carretera rural de dos carriles y ve los faros de un camión que viene en sentido contrario asomar sobre una loma a unos 400 pies por delante. En este momento tiene las luces altas encendidas. ¿Cuál es la acción correcta?","options":["Dejar las luces altas encendidas para que el otro conductor pueda ver claramente su vehículo grande","Cambiar a las luces bajas ahora mismo, antes de que los vehículos estén a menos de 500 pies uno del otro","Hacer un breve destello con las luces altas para avisar al otro conductor y luego dejarlas encendidas","Acelerar un poco para cruzarse con el camión que viene antes de que el deslumbramiento sea un problema"],"explanation":"Cambie a luces bajas a menos de 500 pies de un vehículo que se aproxima para que sus luces altas no encandilen al otro conductor."},"111":{"q":"Va conduciendo una plataforma plana cargada por una carretera rural de dos carriles cuando su motor empieza a perder potencia y lo obliga a bajar a unas 30 mph en una vía de 55 mph. El tráfico se acumula detrás de usted. Mientras lleva el camión con cuidado hasta la próxima salida para orillarse e inspeccionar el problema, ¿cuál de las siguientes sería una utilización INCORRECTA de sus luces intermitentes de emergencia (cuatro direccionales)?","options":["Dejarlas encendidas para advertir al tráfico más rápido que usted circula muy por debajo de la velocidad normal de la vía","Apagarlas y usar solo la direccional derecha en el momento en que realmente entra a la rampa de salida","Volver a encenderlas una vez que está detenido en el acotamiento mientras inspecciona el motor","Usarlas en lugar de la direccional para indicar que está a punto de girar a la derecha hacia la rampa"],"explanation":"Las luces intermitentes de emergencia advierten de un vehículo detenido, averiado o lento y nunca deben usarse en lugar de la direccional."},"112":{"q":"Conduce una carga rígida de 40 pies por una autopista estatal seca y nivelada, y su velocímetro se mantiene estable a 45 mph en buenas condiciones diurnas. Para mantener un margen seguro por delante, ¿cuál es la MENOR distancia de seguimiento que debe conservar detrás del vehículo que va adelante?","options":["4 segundos, porque un vehículo de 40 pies necesita 1 segundo por cada 10 pies de longitud","6 segundos, porque cualquier velocidad superior a 40 mph exige automáticamente al menos 6 segundos","5 segundos, porque 40 pies equivalen a 4 segundos y se suma 1 segundo más por ir a más de 40 mph","3 segundos, ya que la carretera está seca, nivelada y la visibilidad es buena"],"explanation":"Deje 1 segundo por cada 10 pies de longitud, así que un vehículo de 40 pies necesita 4 segundos, más 1 segundo adicional por encima de 40 mph, en total 5 segundos."},"113":{"q":"Conduce un tractocamión de 50 pies a través de una zona de obras donde el tráfico ha disminuido y el límite señalizado le permite mantener una velocidad constante de 35 mph. Quiere establecer una distancia de seguimiento segura detrás de la camioneta que va delante. Usando la regla de 1 segundo por cada 10 pies de longitud del vehículo, ¿cuál es la distancia de seguimiento correcta para esta situación exacta?","options":["4 segundos, porque en una zona de obras lenta puede acortar el margen en un segundo","7 segundos: 5 segundos por la longitud más 2 segundos adicionales por la zona de obras","6 segundos, porque siempre debe añadir 1 segundo adicional al conteo basado en la longitud","5 segundos, porque 50 pies divididos entre 10 es 5, y no se añade ningún segundo ya que va a menos de 40 mph"],"explanation":"Deje 1 segundo por cada 10 pies de longitud, así que un vehículo de 50 pies necesita 5 segundos, sin segundo adicional por ir a menos de 40 mph."},"114":{"q":"Conduce un tractocamión con remolque de 60 pies por una autopista interestatal seca y nivelada a una velocidad constante de 55 mph en condiciones diurnas despejadas. El tráfico es ligero y desea mantener un espacio seguro detrás del vehículo que va adelante. Según la regla de la distancia de seguimiento, ¿cuál es la MENOR distancia de seguimiento que debe mantener en esta situación?","options":["7 segundos","6 segundos","8 segundos","5 segundos"],"explanation":"Deje 1 segundo por cada 10 pies de longitud, así que un vehículo de 60 pies necesita 6 segundos, más 1 segundo adicional por encima de 40 mph, en total 7 segundos."},"115":{"q":"Conduce un camión recto de una sola unidad que mide 30 pies de defensa a defensa. El tránsito en la calle urbana avanza de forma constante a 30 mph, lo que lo mantiene justo por debajo del umbral de 40 mph. Para dejar una distancia de seguimiento segura para su vehículo en estas condiciones, el MENOR número de segundos que debe mantener respecto al vehículo de adelante es:","options":["2 segundos, porque a 30 mph va muy por debajo de la velocidad de carretera y el tránsito fluye sin problemas","3 segundos, asignando 1 segundo por cada 10 pies de longitud de su vehículo","4 segundos, porque siempre debe sumar 1 segundo adicional a su cuenta basada en la longitud","6 segundos, igualando los aproximadamente 6 segundos que toma detenerse por completo"],"explanation":"Deje 1 segundo por cada 10 pies de longitud, así que un vehículo de 30 pies necesita 3 segundos, sin segundo adicional por ir a menos de 40 mph."},"116":{"q":"Conduce una combinación de 70 pies en una autopista seca, manteniendo unas 50 mph constantes con tráfico ligero. Un automóvil pequeño no deja de meterse y salir del espacio que tiene delante, y usted quiere restablecer una distancia de seguimiento segura en cuanto el carril quede libre. Según la regla de los segundos para la longitud y la velocidad de su vehículo, ¿cuántos segundos de distancia de seguimiento debe restablecer?","options":["7 segundos, porque un vehículo de 70 pies necesita 1 segundo por cada 10 pies de longitud","6 segundos, porque ese es el margen de distancia total de frenado recomendado a velocidad de autopista","8 segundos, porque la longitud exige 7 segundos y usted añade 1 segundo más por ir a más de 40 mph","9 segundos, porque debe añadir 2 segundos por encima de 40 mph para un vehículo tan largo"],"explanation":"La distancia de seguimiento es 1 segundo por cada 10 pies de longitud a menos de 40 mph, más 1 segundo por encima de 40 mph, así que un camión de 70 pies a 50 mph necesita 8 segundos."},"117":{"q":"Conduce un camión rígido de 20 pies por un distrito comercial del centro de la ciudad. El tráfico es constante a un límite señalizado de 25 mph, el pavimento está seco y la visibilidad es buena. Para mantener un colchón seguro por delante, ¿cuál es la MENOR distancia de seguimiento que debe mantener detrás del vehículo que va adelante?","options":["1 segundo, porque el camión solo mide 20 pies de largo","4 segundos, sumando 1 segundo a la base y 1 más por el tráfico urbano","3 segundos, ya que siempre debe sumar 1 segundo sobre la cifra base","2 segundos, un segundo por cada 10 pies de longitud del vehículo"],"explanation":"A menos de 40 mph, la distancia de seguimiento es 1 segundo por cada 10 pies de longitud del vehículo, así que un vehículo de 20 pies necesita 2 segundos."},"118":{"q":"Conduce una combinación de 80 pies por una autopista interestatal seca, manteniendo una velocidad constante de 60 mph con tráfico ligero. Un compañero le dice que con dejar 'un segundo por cada diez pies' basta a cualquier velocidad. Usando el método correcto de distancia de seguimiento del Texas DPS según su longitud y velocidad, ¿cuál es la MENOR distancia de seguimiento que debe mantener detrás del vehículo de adelante?","options":["9 segundos — 8 segundos por los 80 pies de longitud, más 1 segundo adicional porque circula a más de 40 mph","8 segundos — 1 segundo por cada 10 pies de su vehículo de 80 pies, sin ajuste por velocidad","10 segundos — 8 segundos por la longitud, más 2 segundos porque va 20 mph por encima del umbral de 40 mph","7 segundos — 1 segundo por cada 10 pies, y luego se resta 1 segundo porque el pavimento seco le da buena tracción"],"explanation":"A menos de 40 mph deje 1 segundo por cada 10 pies de longitud y agregue 1 segundo más por encima de 40 mph, así que un vehículo de 80 pies a 60 mph necesita 9 segundos."},"119":{"q":"Conduce un tractocamión de 50 pies por una autopista interestatal seca y nivelada, y su velocímetro marca de forma constante 45 mph con poco tráfico. Un automóvil delante de usted toca el freno repetidamente, así que quiere mantener una distancia de seguimiento segura usando la regla de los segundos. ¿Cuántos segundos de espacio debe dejar detrás de ese vehículo?","options":["5 segundos, porque su vehículo mide 50 pies y eso da 1 segundo por cada 10 pies","6 segundos, porque 50 pies le dan 5 segundos y suma 1 segundo más por ir a más de 40 mph","7 segundos, sumando 2 segundos extra a la cifra basada en la longitud por estar en una autopista interestatal","4 segundos, ya que 45 mph apenas supera las 40 mph y en pavimento seco basta con un margen menor"],"explanation":"Use 1 segundo por cada 10 pies de longitud a menos de 40 mph y agregue 1 segundo por encima de 40 mph, así que un vehículo de 50 pies a 45 mph necesita 6 segundos."},"120":{"q":"Conduce un tractocamión con remolque de 60 pies (unos 18 metros) por la ciudad y se coloca detrás de un camión de reparto más lento. Su velocímetro marca de forma constante 35 mph sobre pavimento seco. Para mantener una distancia de seguimiento segura para su unidad a esta velocidad, ¿cuántos segundos de espacio debe dejar entre usted y el vehículo que va adelante?","options":["5 segundos, porque sobre pavimento seco y en buenas condiciones se resta un segundo","8 segundos: un segundo por cada 10 pies más dos segundos adicionales por el remolque","6 segundos: un segundo por cada 10 pies de longitud del vehículo","7 segundos: un segundo por cada 10 pies más un segundo porque está en movimiento"],"explanation":"A menos de 40 mph la distancia de seguimiento es 1 segundo por cada 10 pies de longitud sin agregar segundo extra, así que un vehículo de 60 pies a 35 mph necesita 6 segundos."},"121":{"q":"Conduce con una carga parcial por una carretera de dos carriles cuando comienza una llovizna helada ligera y el pavimento empieza a verse brilloso. Durante la siguiente milla hace tres cosas: mantiene su velocidad de crucero constante aunque la visibilidad y el agarre han disminuido, pisa el freno con fuerza cuando un venado se cruza de repente, y momentos después pisa el acelerador con firmeza para recuperar velocidad en una ligera subida. Un compañero luego argumenta que solo UNA de estas acciones pudo realmente haberlo hecho derrapar. ¿Cuál afirmación es correcta?","options":["Solo el frenazo de pánico fuerte pudo causar un derrape, porque bloquear las ruedas es la única forma de perder tracción.","Solo conducir demasiado rápido para las condiciones heladas pudo causar un derrape, ya que la mayoría de los derrapes se deben al exceso de velocidad.","Cada una de las tres acciones — exceso de velocidad para las condiciones, frenazo de pánico fuerte y aceleración firme — pudo causar un derrape por sí sola.","Solo la aceleración firme pudo causar un derrape, porque una carga parcial (más liviana) deja muy poco peso sobre las ruedas motrices para tener tracción."],"explanation":"Un derrape ocurre cuando los neumáticos pierden tracción, y exceder la velocidad para las condiciones, frenar demasiado fuerte o acelerar demasiado pueden causarlo cada uno por separado."},"122":{"q":"Está conduciendo un remolque cargado por una carretera rural de dos carriles. Acaba de empezar a llover ligeramente y el pavimento brilla de mojado; ve señalizada una curva cerrada más adelante, y un banco bajo de niebla se asienta en la hondonada después de la curva, por lo que no puede ver muy lejos en la carretera. Un compañero le dijo una vez que solo necesita reducir la velocidad por el único peligro más grave que enfrente a la vez. ¿Qué acción refleja mejor la práctica segura de CDL en esta situación?","options":["Mantener su velocidad de carretera en el tramo mojado y reducir la velocidad solo cuando llegue realmente a la curva, ya que la curva es el peligro individual más grave","Mantener su velocidad constante porque lo que lo protege cuando aparecen varios peligros menores juntos es la distancia de seguimiento, no la velocidad","Reducir la velocidad solo por la niebla en la hondonada, porque la visibilidad reducida es la única condición que legalmente exige una velocidad menor","Reducir la velocidad por las tres condiciones a la vez, porque el pavimento mojado, la curva y la visibilidad limitada exigen cada uno por separado una velocidad menor"],"explanation":"El pavimento mojado, las curvas y la visibilidad limitada reducen por sí solos la velocidad segura, así que reduzca la velocidad por todas ellas y aún más cuando se combinan."},"123":{"q":"Son las 6:00 a.m. y está realizando la inspección previaje de un tractocamión con remolque antes de un viaje largo por una autopista interestatal. Abre la caja de equipo de emergencia detrás del asiento para confirmar que está completamente equipada por si se avería en el acotamiento más tarde. ¿Qué conjunto de artículos representa el equipo de emergencia COMPLETO que está obligado a llevar?","options":["Tres triángulos reflectantes de advertencia, fusibles eléctricos de repuesto (a menos que el vehículo tenga interruptores automáticos) y un extintor de incendios debidamente cargado y del tipo adecuado","Tres triángulos reflectantes de advertencia y un extintor de incendios debidamente cargado y del tipo adecuado, pero los fusibles de repuesto son opcionales","Un extintor de incendios debidamente cargado y del tipo adecuado y fusibles eléctricos de repuesto, además de un juego de cadenas para neumáticos para rutas invernales","Tres triángulos reflectantes de advertencia, un botiquín de primeros auxilios y un extintor de incendios debidamente cargado y del tipo adecuado"],"explanation":"El equipo de emergencia obligatorio son tres triángulos reflectantes de advertencia, fusibles de repuesto salvo que use disyuntores, y un extintor debidamente cargado y clasificado."},"124":{"q":"Va con 30 minutos de retraso en una autopista dividida con un límite señalizado de 65 mph. El tráfico en todos los carriles circula a unas 72 mph, el pavimento está seco y la vía por delante está despejada y vacía durante un cuarto de milla. Según las normas del DPS de Texas, ¿cuál de estas condiciones haría aceptable conducir más rápido que el límite señalizado de 65 mph?","options":["Cuando el flujo general del tráfico circundante circula por encima del límite, y usted mantiene el ritmo para no ser un peligro","Cuando va con retraso y el pavimento seco y despejado le permite recuperar con seguridad el tiempo perdido","Ninguna de estas condiciones justifica superar el límite señalizado","Cuando la vía por delante está vacía durante un cuarto de milla, lo que le da una distancia de frenado completa"],"explanation":"El límite de velocidad indicado es la máxima velocidad legal para condiciones ideales y nunca debe excederse, sin importar el tráfico, el horario o la vía despejada."},"125":{"q":"Conduce un tractocamión cargado por una carretera de dos carriles detrás de un camión agrícola lento que va a 40 mph en una zona de 60 mph. Está ansioso por rebasarlo y ve cuatro oportunidades por delante. ¿Cuál de estos lugares es realmente SEGURO para completar el rebase?","options":["En la curva larga y suave de adelante, donde puede ver parcialmente al otro lado de la curva","Justo antes de la cima de la colina, mientras todavía tiene algo de visibilidad hacia adelante","Ninguno de estos lugares le da suficiente distancia de visibilidad para rebasar con seguridad","A través del cruce rural que se aproxima, ya que el tráfico transversal debe ceder el paso a la carretera"],"explanation":"Rebasar con seguridad en una carretera de dos carriles requiere suficiente distancia de visión adelante, que las curvas, cimas y cruces bloquean."},"126":{"q":"Va con 40 minutos de retraso en una entrega ajustada. El mismo tractocamión pasó una inspección previa al viaje completa cuando lo condujo ayer, el clima está despejado y seco, y un recorrido rápido no muestra nada evidentemente mal. ¿En cuál de estas circunstancias se le permite legal y seguramente omitir la inspección previa al viaje de hoy antes de conducir?","options":["Cuando va con retraso y una demora pondría en riesgo una entrega tardía","Cuando el vehículo pasó la inspección el día anterior y no ha tenido novedades desde entonces","Ninguna de estas circunstancias justifica omitir la inspección previa al viaje","Cuando un breve recorrido no muestra nada visiblemente mal y las condiciones son buenas"],"explanation":"La inspección previa al viaje es obligatoria antes de cada viaje sin excepción, ya que el estado del vehículo puede cambiar en cualquier momento."},"127":{"q":"Acaba de oscurecer en un camino rural angosto, sin alumbrado y de dos carriles, y usted lleva un remolque cargado. Un auto que viene en sentido contrario corona una loma a unos 400 pies de distancia con las luces altas encendidas directamente hacia sus ojos, borrando todo lo que hay frente a su cofre. Solo tiene un par de segundos antes de que los vehículos se crucen. ¿Cuál es la forma más segura de mantener el control de su equipo hasta que el vehículo pase?","options":["Ponga sus propios faros en luces altas para que su mayor alcance le permita ver el camino más allá del resplandor del otro conductor.","Baje la mirada hacia el borde derecho de su carril y reduzca la velocidad hasta que el auto que viene en sentido contrario haya pasado.","Destelle rápidamente sus luces altas varias veces para que el otro conductor note el problema y baje las suyas.","Fije la mirada en la línea central justo al frente y mantenga la velocidad constante para no desviarse antes de que el auto pase."],"explanation":"Si las luces altas de un vehículo que viene de frente lo encandilan, mire hacia el borde derecho de su carril como guía y reduzca la velocidad hasta que pase."},"131":{"q":"Circula a unas 55 mph por una autopista interestatal cuando un aguacero repentino deja una película de agua estancada sobre el pavimento. El volante se siente de pronto ligero y suelto en sus manos, y se da cuenta de que las llantas delanteras del tractor han perdido el contacto firme con la carretera y están flotando sobre el agua (hidroplaneo). ¿Qué respuesta le da la mejor oportunidad de recuperar la tracción con seguridad?","options":["Aplique presión de freno firme y constante y gire con fuerza hacia el acotamiento para obligar a las llantas delanteras a bajar de nuevo al pavimento.","Mantenga su velocidad pero bombee los frenos rápidamente para que las llantas atraviesen la película de agua sin bloquearse.","Suelte el acelerador, mantenga el volante recto y deje que el camión reduzca la velocidad gradualmente hasta que las llantas recuperen el agarre.","Pise el acelerador con más fuerza y mantenga girando las ruedas motrices para empujar el agua estancada fuera de debajo de las llantas."],"explanation":"En un hidroplaneo las llantas pierden el agarre, así que suelte el acelerador, mantenga el volante recto y deje que el camión frene hasta recuperar la tracción."},"133":{"q":"Conduce un remolque cargado por el carril derecho de una autopista dividida de cuatro carriles, a la velocidad máxima permitida de 60 mph. Una camioneta se le ha pegado por detrás, circulando a solo unos pies de su parachoques, encendiendo repetidamente las luces altas y haciendo zigzag como si buscara rebasar. Hay un carril libre a su izquierda y tráfico fluido pero denso adelante. ¿Cuál es la respuesta más segura y legalmente correcta?","options":["Toque ligeramente el freno varias veces para que se enciendan las luces de freno y avisar al conductor de atrás que debe retroceder y dejar espacio.","Mantenga su velocidad y posición en el carril para que el conductor agresivo no pueda obligarlo a cambiar lo que está haciendo.","Acelere a unas 70 mph para alejarse del que lo sigue de cerca, ya que adelantarse a un conductor agresivo elimina el conflicto.","Levante el pie del acelerador para abrir más distancia de seguimiento por delante, luego señalice y muévase al carril izquierdo si está despejado para que el conductor pueda rebasar."],"explanation":"Ante un conductor agresivo que lo sigue de cerca, suelte el acelerador para abrir espacio adelante, luego señalice y cámbiese de carril para dejarlo pasar con seguridad."},"134":{"q":"Está remolcando un tráiler cargado por la interestatal cuando percibe un fuerte olor a goma quemada y nota humo gris saliendo de la parte trasera de su unidad en el espejo derecho. El tráfico es moderado y hay un arcén pavimentado ancho a unos cientos de pies más adelante. ¿Cuál es la MEJOR forma de actuar?","options":["Señalice con antelación, salga por completo al arcén lejos del resto del tráfico, apague el motor e inspeccione la fuente del humo antes de que empeore.","Mantenga la velocidad y continúe hasta la próxima salida, ya que el flujo de aire a velocidad de autopista probablemente enfriará la zona y disipará el humo por sí solo.","Deténgase en el arcén pero deje el motor encendido, y luego abra de inmediato las puertas traseras del tráiler para dejar salir el humo y el calor atrapados.","Reduzca la velocidad y siga avanzando lentamente por el arcén mientras un pasajero echa agua sobre los neumáticos traseros para enfriarlos sin detenerse del todo."],"explanation":"El humo o un olor a quemado puede indicar un incendio en desarrollo, así que salga completamente de la vía lejos del tráfico, apague el motor e inspeccione antes de que empeore."},"135":{"q":"Conduce un remolque cargado por una carretera rural de dos carriles cuando entra en un banco de niebla tan densa que apenas distingue las líneas del carril a corta distancia. El tráfico es ligero. ¿Cuál es la forma más segura y correcta de manejar este tramo?","options":["Cambiar a las luces altas para que la luz más intensa atraviese la niebla y le permita ver las líneas del carril antes.","Reducir la velocidad, mantener las luces bajas encendidas y, si aún así no ve lo suficientemente bien, salirse por completo de la carretera y esperar a que se disipe la niebla.","Mantener su velocidad normal de carretera pero fijarse en las luces traseras del vehículo de adelante y seguirlas como guía a través de la niebla.","Acelerar para salir del tramo con niebla lo más rápido que su unidad cargada permita de forma segura, y luego retomar la velocidad de crucero."],"explanation":"Con niebla, reduzca la velocidad y use las luces bajas porque las altas se reflejan en las gotas de agua y aumentan el deslumbramiento, y salga completamente de la vía si aún no puede ver."},"136":{"q":"Está al final de su turno y debe meter en reversa su remolque de 53 pies en un muelle de carga estrecho, en un patio que nunca ha visitado. No hay nadie que lo guíe, el muelle está vacío en este momento y usted tiene prisa por terminar. ¿Cuál es la acción más segura y correcta?","options":["Como la zona detrás de usted está despejada ahora mismo, retroceda de inmediato a velocidad constante para terminar antes de que lleguen montacargas o trabajadores.","Llame a un trabajador que pasa cerca y pídale que se pare justo detrás del remolque para observarlo y guiarlo mientras retrocede.","Bájese y camine todo el recorrido detrás del remolque para revisar obstáculos y espacio libre, luego retroceda lentamente usando los espejos de ambos lados.","Confíe solo en sus espejos y retroceda a velocidad constante sin bajarse, ya que detenerse a mirar solo lo haría más lento."],"explanation":"Sin señalero, use el método de bajarse y mirar: recorra a pie toda la trayectoria detrás del remolque para revisar obstáculos y espacio, luego retroceda despacio usando ambos espejos."},"137":{"q":"Conduce un remolque cargado a 55 mph en una autopista interestatal seca cuando un auto averiado aparece de repente en su carril muy adelante. Su instructor luego le pide que dé cuenta de CADA parte de la distancia que su vehículo realmente recorrió desde el instante en que vio el peligro hasta que se detuvo por completo. ¿Qué desglose identifica correctamente las tres partes separadas que juntas conforman su distancia total de frenado?","options":["La distancia recorrida durante su reacción de 3/4 de segundo más la distancia de frenado una vez que los frenos agarran — el tiempo de percepción ya está incluido en el tiempo de reacción, por lo que no se cuenta por separado","Solo la distancia de frenado, porque esa es la parte en que el camión está físicamente desacelerando y es la única porción que usted puede controlar","Distancia de seguimiento, distancia de señalización y el espacio de estacionamiento que deja junto al bordillo","Distancia de percepción, distancia de reacción y distancia de frenado"],"explanation":"La distancia total de frenado es la suma de tres partes: distancia de percepción, distancia de reacción y distancia de frenado."},"138":{"q":"Se detuvo a almorzar durante un viaje largo y un amigo le ofrece una sola cerveza con la comida. Después se siente completamente sobrio y camina en línea recta sin ningún problema. Antes de volver a subir a su tractocamión, ¿cuál afirmación sobre el límite legal de concentración de alcohol en la sangre (BAC) para operar su vehículo comercial es correcta?","options":["Usted está legalmente por encima del límite y no puede conducir el vehículo comercial con un BAC del 0.04 por ciento, que es la mitad del límite que aplica a un automóvil de pasajeros normal.","Usted está legalmente por encima del límite y no puede conducir el vehículo comercial con un BAC del 0.08 por ciento, el mismo límite que aplica a un automóvil de pasajeros normal.","Puede conducir siempre que su BAC se mantenga por debajo del 0.10 por ciento, porque los vehículos más grandes se rigen por un umbral más alto.","Lo que importa es sentirse sobrio, así que puede conducir en cuanto deje de sentirse afectado, sin importar ningún número específico de BAC."],"explanation":"El límite legal de alcoholemia para conducir un CMV es 0.04 por ciento, exactamente la mitad del límite de 0.08 por ciento para un automóvil, así que con 0.04 ya supera el límite."},"139":{"q":"Acaba de completar 10 horas consecutivas fuera de servicio en la litera y comienza un nuevo turno. Su despachador dice que el viaje es largo y le pregunta cuánto tiempo de conducción real puede hacer legalmente antes de que las reglas federales de horas de servicio (HOS) le exijan dejar de conducir por ese día. Considerándolo como conducción pura (sin demoras excesivas en servicio que cierren antes su ventana de 14 horas), ¿cuál es el tiempo máximo de conducción permitido?","options":["Hasta 8 horas de conducción, porque primero debe tomar un descanso de 30 minutos","Hasta 11 horas de tiempo de conducción","Hasta 14 horas de tiempo de conducción","Hasta 16 horas de tiempo de conducción"],"explanation":"Tras 10 horas consecutivas fuera de servicio, las normas federales de horas de servicio permiten un máximo de 11 horas de conducción."},"140":{"q":"Ha estado conduciendo desde mucho antes del amanecer y ahora es media tarde. Se sorprende a sí mismo desviándose dentro del carril, los párpados le pesan y no recuerda las últimas millas. Todavía le quedan horas de ruta y una ventana de entrega que cumplir. ¿Cuál de las siguientes es la ÚNICA acción que realmente le devolverá el estado de alerta y corregirá esta condición de forma segura?","options":["Detenerse en la próxima área de servicios, tomar dos tazas de café cargado y seguir adelante para no atrasarse","Bajar las ventanillas para que entre aire frío y fresco y subir el volumen de la radio para mantener la mente activa","Salir de la carretera en cuanto sea seguro, dejar de conducir y dormir lo suficiente de verdad antes de continuar","Abrir una bebida energética, comer una comida pesada y aumentar la distancia de seguimiento para compensar"],"explanation":"Solo el sueño real y suficiente paga la deuda de sueño, así que al estar fatigado salga de la vía con seguridad, deje de conducir y duerma antes de continuar."},"141":{"q":"Conduce cargado por una autopista rural llana y despejada a 55 mph con clima claro y seco. El tráfico es ligero y tiene una visión larga e ininterrumpida del camino por delante. Para gestionar correctamente su tiempo de anticipación visual, ¿qué tan lejos hacia adelante debe mirar y escanear constantemente en busca de peligros?","options":["Solo el vehículo directamente delante de usted, ya que a 55 mph cualquier cosa más lejana aún no es una amenaza","Aproximadamente de 30 a 40 segundos por delante, para tener el máximo tiempo de reacción posible en la autopista abierta","Aproximadamente de 1 a 2 segundos por delante, que es más o menos su distancia de seguimiento segura a esta velocidad","Aproximadamente de 12 a 15 segundos por delante, que a 55 mph equivale a un cuarto de milla o cerca de una cuadra de ciudad en la ciudad"],"explanation":"Mantenga la vista en movimiento y mire de 12 a 15 segundos adelante, lo que equivale a un cuarto de milla a velocidad de carretera o una cuadra en ciudad, para detectar peligros temprano."},"142":{"q":"Está transportando un remolque cargado por una concurrida autopista interestatal de cuatro carriles en Texas a velocidad de autopista. El tráfico es intenso y los vehículos no dejan de meterse en sus puntos ciegos e incorporarse a su alrededor. Para mantener una imagen precisa y actualizada de lo que ocurre detrás y al lado de su camión, ¿cómo debe usar los espejos?","options":["Mirar los espejos solo justo antes de cambiar de carril o incorporarse, ya que es entonces cuando más importa el tráfico en los puntos ciegos","Revisar los espejos aproximadamente cada 12 a 15 segundos, igual que la distancia que mira hacia adelante en la carretera","Observar los espejos de forma continua y fija para que sus ojos nunca vuelvan a la carretera de adelante","Revisar los espejos con regularidad, aproximadamente cada 5 a 8 segundos, además de revisarlos antes de cualquier cambio de carril"],"explanation":"Revise los espejos con regularidad, cada 5 a 8 segundos, además de mirar antes de cada cambio de carril, para vigilar el tráfico y los puntos ciegos."},"143":{"q":"Es una tarde húmeda y gris y debe retroceder su tractocamión con remolque hacia un muelle de carga en un callejón estrecho. La visibilidad es mala, el lado derecho del remolque desaparece en la sombra y no cuenta con un señalero que lo ayude. Para que la maniobra sea lo más segura posible, ¿hacia qué lado debe retroceder?","options":["Hacia el lado derecho (ciego), porque alejar el remolque de usted le da al tractor más espacio para girar","Hacia el lado con más tráfico, para que los demás conductores lo vean y se detengan ante el remolque","Hacia el lado que deje el muelle más cerca, para acortar la distancia que debe recorrer en reversa","Hacia el lado del conductor (izquierdo), para poder vigilar todo el largo del remolque por su propia ventanilla"],"explanation":"Retroceder hacia su lado izquierdo (del conductor) le permite vigilar todo el largo del remolque por su ventanilla, manteniendo siempre a la vista la parte trasera y su trayectoria."},"144":{"q":"Durante su inspección previaje está asegurando una sola viga de acero de 38 pies en una plataforma plana (flatbed). Quiere usar la MENOR cantidad de amarres (tie-downs) que aún cumpla con el mínimo federal de sujeción según la longitud (el límite de carga de trabajo ya está cubierto). ¿Cuál es la menor cantidad de amarres que permite la regla para esta carga?","options":["2 amarres, porque toda pieza de más de 5 pies siempre necesita exactamente dos","3 amarres, porque usted revisa la sujeción cada 3 horas","8 amarres, porque se necesita uno por cada 5 pies de longitud de la carga","4 amarres, porque se necesita uno por cada 10 pies de longitud de la carga"],"explanation":"La carga necesita al menos una amarra por cada 10 pies de largo, así que una viga de 38 pies se redondea a cuatro amarras."},"145":{"q":"Está apenas bajo cero y se acerca a una curva sobre un puente con su tractocamión cargado. Al girar el volante para seguir la curva, las ruedas delanteras pierden tracción sobre el hielo. ¿Cuál es el resultado MÁS probable de este patinazo de ruedas delanteras y cómo responde el vehículo?","options":["El vehículo sigue avanzando en línea recta y continúa así sin importar hacia dónde gire el volante, hasta que las ruedas delanteras recuperen la tracción.","Las ruedas motrices traseras se desvían hacia un lado y el remolque empieza a plegarse (jackknife) detrás de la cabina.","El vehículo gira más cerrado de lo que pretendía, jalando el frente hacia el interior de la curva.","La dirección se endurece, las ruedas delanteras agarran con más fuerza y el camión se sobrecorrige hacia el lado al que giró."],"explanation":"En un derrape de ruedas delanteras estas pierden tracción, por lo que girar el volante no surte efecto y el vehículo sigue recto hasta que las ruedas delanteras recuperan agarre."},"146":{"q":"Conduce un tractocamión con remolque cargado y sin ABS a velocidad de autopista cuando un automóvil se le cruza de repente y frena bruscamente delante de usted. Necesita el máximo frenado, pero debe mantener el control del conjunto y poder dirigir. Aplicando el método de frenado controlado, ¿qué debe hacer con el pedal del freno?","options":["Pisar el pedal hasta el fondo para bloquear las ruedas y lograr la parada más corta posible","Aplicar presión firme y constante sobre el pedal justo antes del punto de bloqueo de las ruedas, aliviando solo si las ruedas empiezan a bloquearse","Bombear el pedal con fuerza y rapidez una y otra vez para que las ruedas sigan girando","No tocar el freno de pie y frenar el conjunto usando solo la válvula de mano del remolque"],"explanation":"El frenado controlado consiste en aplicar presión firme y constante justo antes de bloquear las ruedas, aflojando solo si empiezan a bloquearse para poder seguir dirigiendo."},"147":{"q":"Está descendiendo una pendiente de montaña larga y empinada con un remolque completamente cargado. Seleccionó una marcha baja en la cima, pero a mitad de la bajada huele algo caliente, el pedal del freno se siente más blando con cada pisada y el camión gana velocidad poco a poco a pesar de un frenado ligero y constante. Un letrero adelante dice: 'RAMPA DE ESCAPE PARA CAMIONES 1 MILLA'. Considerando para qué está construida esa rampa, ¿cuál afirmación es correcta?","options":["Es un área de descanso obligatoria donde todo camión cargado debe detenerse para dejar enfriar los frenos antes de continuar la bajada.","Es un atajo mantenido que le permite salir de la pendiente y llegar más rápido al fondo mientras sus frenos sobrecalentados se recuperan.","Es una rampa de escape de emergencia diseñada para detener de forma segura un vehículo cuyos frenos han fallado o se han debilitado por sobrecalentamiento.","Es un apartadero pavimentado donde puede seguir rodando despacio para que los frenos disipen el calor sin llegar nunca a detenerse por completo."],"explanation":"Una rampa de escape para camiones es una vía de emergencia diseñada para detener con seguridad un vehículo cuyos frenos han fallado o se han desvanecido por sobrecalentamiento."},"148":{"q":"Circula a 55 mph por una autopista seca cuando un auto se le cruza de repente y frena bruscamente delante de usted. Más tarde su instructor le pide separar las partes de su distancia total de frenado. Le recuerda que su distancia TOTAL de frenado a esta velocidad es de aproximadamente 419 pies. De ese total, ¿qué distancia recorre su camión durante ÚNICAMENTE su tiempo de reacción -- el intervalo entre ver el peligro y el momento en que su pie realmente pisa el pedal del freno, antes de que los frenos hayan reducido la velocidad en lo más mínimo?","options":["Unos 419 pies, porque el camión sigue rodando a toda velocidad todo ese tiempo hasta que por fin se detiene","Unos 250 pies, ya que esa es aproximadamente la distancia que alcanzan sus luces bajas y hasta donde puede reaccionar adelante","Unos 6 pies, porque a velocidad de autopista sus reflejos entrenados mueven el pie casi al instante","Unos 60 pies, aproximadamente la distancia recorrida en los tres cuartos de segundo que tarda un conductor promedio en reaccionar"],"explanation":"La distancia de reacción es el recorrido tras percibir un peligro antes de frenar, unos 60 pies a 55 mph durante el tiempo medio de reacción de tres cuartos de segundo."},"149":{"q":"Usted se aproxima a una intersección urbana en su vehículo combinado cargado cuando el semáforo cambia a luz roja fija (no intermitente). El tránsito es escaso y en ese momento no ve tráfico transversal ni peatones. ¿Qué acción le exige legalmente la ley como conductor con CDL?","options":["Reducir hasta casi detenerse y cruzar la intersección porque no hay tráfico transversal","Tratar la roja fija igual que una roja intermitente: ceder el paso pero no necesariamente detenerse si la vía está despejada","Detenerse por completo y permanecer detenido hasta que la señal cambie a verde","Detenerse solo si hay un vehículo o peatón realmente en su trayectoria, de lo contrario continuar"],"explanation":"Una luz roja fija exige que se detenga por completo y permanezca detenido hasta que la señal cambie a verde."},"150":{"q":"Conduce un tractocamión cargado por una autopista seca y despejada a 55 mph cuando ve un automóvil averiado con el capó levantado a aproximadamente un cuarto de milla (12-15 segundos) por delante en su carril. El tráfico en el carril contiguo es denso, por lo que todavía no puede cambiarse de carril. ¿Cuál es la MEJOR primera acción que debe tomar?","options":["Mantener la velocidad y esperar hasta estar a unos 200 pies de distancia antes de reaccionar, ya que eso le da mucho espacio","Acelerar brevemente para crear un hueco y meterse a la fuerza en el carril contiguo antes de llegar al automóvil averiado","Frenar fuerte de inmediato para perder toda la velocidad posible antes de llegar al peligro","Soltar el acelerador y cubrir el freno para estar listo para reducir la velocidad de forma suave a medida que se desarrolla la situación"],"explanation":"Cuando un peligro está lejos adelante, suelte el acelerador y cubra el freno para reducir la velocidad suavemente sin una frenada brusca."},"151":{"q":"Conduce una combinación de 60 pies por una carretera de dos carriles seca y despejada a 35 mph y quiere mantener una distancia de seguimiento adecuada detrás del auto que va adelante. Según la longitud de su vehículo, ¿cuál es la distancia de seguimiento segura MÍNIMA que debe mantener en estas buenas condiciones?","options":["Unos 6 segundos: un segundo por cada 10 pies de longitud de su vehículo","Unos 7 segundos: un segundo por cada 10 pies más un segundo adicional por la velocidad","Un valor fijo de 4 segundos, ya que 4 segundos es el intervalo estándar para cualquier vehículo con buen clima","No se necesita ninguna distancia medida a 35 mph porque esa velocidad es lo bastante baja para detenerse rápido"],"explanation":"Deja un segundo de distancia de seguimiento por cada 10 pies de longitud del vehículo, así un conjunto de 60 pies necesita unos 6 segundos a 40 mph o menos."},"152":{"q":"Es temprano por la mañana durante su inspección previaje. Arranca el motor y observa los indicadores del tablero. En los primeros momentos después del arranque, ¿qué debe hacer el indicador de presión de aceite del motor (o la luz de advertencia de presión de aceite) antes de que usted decida que el camión es seguro para conducir?","options":["La presión de aceite debe permanecer en cero mientras el motor está frío y subir solo después de haber conducido varias millas.","La presión de aceite debe subir a un valor normal poco después del arranque (y cualquier luz de advertencia de presión de aceite debe apagarse).","La luz de advertencia de presión de aceite debe permanecer encendida todo el tiempo que el motor funcione; así sabe que el sistema de lubricación está activo.","La presión de aceite debe dispararse brevemente muy por encima del rango normal y quedarse allí, ya que un valor más alto significa una lubricación fuerte."],"explanation":"La presión de aceite debe subir al rango normal poco después del arranque y apagarse cualquier luz de advertencia, confirmando que el sistema de lubricación funciona."},"153":{"q":"Es una tarde calurosa y está subiendo una pendiente larga con una carga pesada en marcha baja. Al mirar el tablero de instrumentos, ve que la aguja del indicador de temperatura del refrigerante sube muy por encima de su rango normal. Según lo que este indicador específico está diseñado para informarle, ¿de qué condición le está advirtiendo?","options":["El nivel de combustible en el tanque está peligrosamente bajo y debería repostar pronto","Los faros se han atenuado porque el alternador ya no carga la batería","El motor se está sobrecalentando y podría dañarse si continúa subiendo con esta carga","La presión del aceite del motor ha bajado demasiado para lubricar correctamente las piezas móviles"],"explanation":"Si la aguja de temperatura del refrigerante sube por encima del rango normal, el motor se está sobrecalentando y podría dañarse si sigues conduciendo con carga."},"154":{"q":"Durante su inspección previaje en una mañana fría, arranca el motor y observa el manómetro de presión de aire. Nota que la presión de aire en sus tanques sube muy lentamente hacia el rango de operación, tardando mucho más de lo habitual en acumularse. El gobernador del compresor aún no se ha desconectado. De las siguientes, ¿cuál es la explicación MÁS probable de esta acumulación lenta?","options":["El compresor está en excelente estado y simplemente protege el sistema acumulando la presión de forma gradual","Sus tanques de aire ya están llenos, por lo que el manómetro solo muestra presión residual","Sus frenos de servicio están en muy buen estado, lo que reduce la velocidad con que entra el aire a los tanques","Hay una fuga de aire en el sistema o el compresor está débil, por lo que la presión sube más lento de lo que debería"],"explanation":"Una presión de aire que sube demasiado lento advierte de una fuga en el sistema o de un compresor débil que no puede mantener el ritmo de la demanda."},"155":{"q":"Es una inspección previaje a primera hora de la mañana, con la temperatura apenas bajo cero. Levanta el capó y pasa la mano por las correas del motor y por las mangueras del radiador y de la calefacción. ¿Cuál de estos hallazgos es el verdadero defecto de seguridad que está buscando, el que debería impedir que este camión entre en servicio?","options":["Grietas, deshilachado, zonas blandas o señales de fugas en las correas y mangueras","Correas y mangueras que han perdido el brillo de fábrica y ahora se ven opacas y polvorientas","Mangueras que ya no muestran una etiqueta legible con la marca del fabricante","Una correa que tiene un tono más oscuro que el color vivo que tenía cuando era nueva"],"explanation":"Inspecciona las correas y mangueras en busca de grietas, deshilachado, puntos blandos o señales de fugas, pues ese deterioro puede causar una avería o fallo del motor."},"156":{"q":"Durante su inspección previa al viaje en una mañana fría, encuentra una grieta fina que atraviesa uno de los rines de acero de un eje motriz trasero, y en otra rueda dos de las tuercas de los pernos están notablemente flojas. Los neumáticos en sí mantienen el aire y tienen buena banda de rodadura. Su despachador lo presiona para hacer el viaje porque la carga es urgente. ¿Cuál es la decisión correcta sobre conducir este vehículo?","options":["Como los neumáticos mantienen el aire y tienen buena banda de rodadura, las ruedas son lo bastante seguras; puede conducir con cuidado hasta el taller y revisarlo después de la entrega.","El rin agrietado y las tuercas flojas son defectos que obligan a poner el vehículo fuera de servicio; no debe conducirse hasta que se reparen.","Apriete a mano las tuercas flojas y vigile el rin agrietado; si la grieta no crece durante las primeras 50 millas, puede continuar el viaje.","Solo es un problema en el eje de dirección; como estas son ruedas motrices traseras, un rin agrietado y tuercas flojas ahí son desgaste menor y el vehículo está bien para operar."],"explanation":"Las llantas agrietadas y las tuercas flojas son defectos que ponen el vehículo fuera de servicio, por lo que no debe conducirse hasta repararlos."},"158":{"q":"Durante su inspección previa al viaje en el patio, encuentra un charco fresco de líquido en el pavimento justo debajo del tractocamión. Los depósitos aún marcan dentro de su rango normal y el camión arranca y funciona bien. Ya va retrasado para su ventana de entrega. ¿Cuál es la acción correcta?","options":["Anotar el nivel del líquido, rellenar el depósito por precaución y continuar el viaje ya que los indicadores marcan normal","Dejarlo por ahora y volver a revisar el charco en su primera parada dentro de las primeras 50 millas para ver si empeora","No conducir hasta localizar el origen de la fuga y repararla, aunque eso lo haga llegar tarde","Limpiar el charco, registrar la inspección como satisfactoria y vigilar de cerca los indicadores mientras conduce"],"explanation":"Una fuga de líquido conocida es un defecto que puede fallar de forma catastrófica, así que no conduzcas hasta localizar el origen y repararlo, aunque llegues tarde."},"159":{"q":"Es justo antes del amanecer y está haciendo la inspección de recorrido previo al viaje alrededor del vehículo. Varios reflectores traseros y dos de sus luces traseras/de gálibo están cubiertos de mugre seca del camino, y la lente de una luz trasera se ve tenue incluso con las luces encendidas. Por lo demás, el camión está cargado y listo para salir. ¿Qué acción cumple mejor con la norma de inspección de luces y reflectores antes de partir?","options":["Dejar los reflectores en paz porque son dispositivos pasivos, pero reemplazar cualquier bombilla de luz trasera que no encienda","Limpiar solo las luces que reciben energía eléctrica, porque los reflectores no necesitan estar limpios para cumplir su función","Cubrir con cinta las lentes tenues o sucias para que no se confundan con una luz quemada, y luego conducir a un taller","Limpiar la mugre de todas las luces y reflectores y confirmar que cada uno funciona antes del viaje"],"explanation":"Todas las luces y reflectores deben estar limpios y funcionando antes del viaje, ya que la suciedad impide que un reflector refleje y que una luz se vea."},"160":{"q":"Llega a su camión en el patio para comenzar la inspección previa al viaje. Como tiene ganas de salir pronto, empieza a enumerar mentalmente qué hacer primero: calentar el motor, recorrer el área a pie, probar los frenos, revisar las luces. Antes de tocar nada del vehículo, ¿qué acción corresponde correctamente al PRIMER paso del método de inspección?","options":["Hacer una revisión general acercándose al vehículo a pie, observando su estado general, su inclinación/postura, los charcos frescos de líquido debajo y cualquier peligro a su alrededor antes de subir","Arrancar el motor y dejarlo calentar hasta la temperatura de funcionamiento para que los indicadores marquen con precisión mientras usted da la vuelta","Realizar la prueba de frenos de servicio con presión aplicada avanzando a unas 5 mph y pisando el pedal del freno","Caminar al frente y a la parte trasera y confirmar que todas las luces exteriores y reflectores estén limpios, del color correcto y funcionando"],"explanation":"Comience la inspección previaje con un recorrido a pie, revisando la postura del vehículo, los charcos de fluido y los peligros alrededor antes de subir."},"161":{"q":"Conduce un tractocamión con remolque cargado, equipado con una transmisión manual estándar (no sincronizada), y al acelerar en una carretera plana necesita subir de la 5.ª a la 6.ª marcha. Para hacer este cambio ascendente de forma limpia y sin que rechinen los engranajes, ¿cuál es la técnica correcta para el tipo de transmisión que llevan muchos camiones?","options":["Pisar el embrague solo hasta la mitad (\"frenado con embrague\") y forzar la palanca a la siguiente marcha","Mantener el embrague pisado a fondo durante todo el cambio mientras se modula el acelerador","Mantener una mano firme en el volante y cambiar sin usar el embrague en absoluto una vez que el vehículo está en marcha","Hacer doble embrague: soltar el acelerador, pisar el embrague, poner en punto muerto, soltar el embrague, luego volver a pisar el embrague y meter la marcha más alta"],"explanation":"Para subir de marcha use doble embrague: suelte el acelerador, pise el embrague y ponga punto muerto, suelte el embrague, vuelva a pisarlo y cambie a la marcha superior."},"162":{"q":"Conduce un remolque cargado y el camino más adelante desciende por una pendiente de montaña larga y empinada. Quiere controlar su velocidad de forma segura al bajar sin sobrecalentar los frenos. ¿En qué momento debe completar el cambio a una marcha baja?","options":["Antes de empezar a bajar la pendiente, mientras todavía está en terreno plano en la cima","Mientras ya está descendiendo, en cuanto sienta que el camión gana velocidad","Al pie de la pendiente, una vez que el camino vuelve a nivelarse","Solo después de que el frenado ligero y constante deje de reducir su velocidad"],"explanation":"Cambie a una marcha baja antes de comenzar a bajar una pendiente larga y empinada, aún en terreno plano, pues el freno motor controla la velocidad y los frenos de servicio solo complementan."},"163":{"q":"Está bajando una larga pendiente de montaña con un remolque cargado. Su camión está equipado con un ralentizador (retardador) y lo activa al comenzar el descenso. ¿Qué afirmación describe MEJOR lo que el ralentizador hace por usted en esta situación?","options":["Aumenta la potencia del motor para que gane velocidad y supere la pendiente más rápido","Aplica una fuerza de frenado adicional que ayuda a reducir la velocidad del vehículo, lo que disminuye el desgaste y el sobrecalentamiento de los frenos de servicio","Endurece la respuesta de la dirección para que el camión tome las curvas de la pendiente con más facilidad","Es el control principal del descenso, por lo que ya no necesita seleccionar una marcha baja antes de empezar a bajar"],"explanation":"El retardador aplica fuerza de frenado adicional para reducir el desgaste y el sobrecalentamiento de los frenos de servicio."},"164":{"q":"La temperatura está apenas bajo cero y se ha formado una fina capa de hielo en los puentes de su ruta. Su tractor está equipado con un retardador de motor (de velocidad) que actúa sobre los ejes de tracción cuando suelta el acelerador. Al levantar el pie del acelerador para reducir la velocidad antes de una curva en esta superficie resbaladiza, ¿cuál es la forma correcta de manejar ese retardador?","options":["Dejar el retardador totalmente activado, ya que su frenado actúa solo sobre las ruedas de tracción y, por lo tanto, no puede desestabilizar el eje de dirección","Aplicar el retardador con fuerza y de forma anticipada para no tener que tocar el freno de pie sobre el hielo","Usarlo con mucho cuidado o apagarlo, porque en una superficie resbaladiza el retardador puede hacer que las ruedas de tracción pierdan adherencia y patinen","Quitar o desactivar el retardador durante la inspección previaje siempre que haya hielo en el pronóstico"],"explanation":"En superficie resbaladiza, use el retardador con cuidado o apáguelo, porque puede hacer que las ruedas motrices pierdan tracción y derrapen."},"165":{"q":"Está dando marcha atrás para meter su remolque en un muelle de carga estrecho de noche. No hay nadie que le ayude a guiarse, y parte de la zona del muelle queda oculta a la vista por remolques estacionados. ¿Cuál es la forma más segura y correcta de completar la maniobra?","options":["Retroceder lo más rápido posible para obstruir el carril el menor tiempo posible y acortar la maniobra","Acelerar el motor y pisar a medias el embrague para entrar recto sin rodar hacia atrás","Fijar la vista solo en el espejo del lado del conductor, ya que el lado del pasajero es su punto ciego y no vale la pena revisarlo","Retroceder despacio, usando ambos espejos, y avanzar para reposicionarse cada vez que pierda de vista hacia dónde va"],"explanation":"Retroceda despacio usando ambos espejos, y avance para reposicionarse cada vez que pierda de vista hacia dónde va."},"167":{"q":"Se acerca a un cruce concurrido donde tiene la intención de girar a la derecha hacia un muelle de carga. El tráfico es denso y un automóvil pequeño comienza a acercarse poco a poco junto a su tractocamión por la derecha. Para comunicar sus intenciones de forma segura y evitar que ese automóvil quede aprisionado contra el bordillo, ¿cuándo debe activar la señal de giro?","options":["Con anticipación, mucho antes de comenzar el giro, para que los demás conductores tengan tiempo de reaccionar","En el momento en que empieza a girar el volante, para que el momento coincida con su movimiento","Solo después de haber completado el giro, para no confundir a los conductores cercanos","Solo de noche o en condiciones de baja visibilidad, cuando las señales son más necesarias"],"explanation":"Señale con anticipación, mucho antes de iniciar el giro, para que los demás conductores tengan tiempo de reaccionar."},"168":{"q":"Está haciendo un giro a la izquierda lento y amplio desde una calle de la ciudad hacia la entrada de un muelle de carga. A mitad del giro, el volante se recentra parcialmente y la luz direccional se apaga sola. Hay un auto esperando en la calle transversal y un ciclista que se acerca por detrás. ¿Cuál es la forma correcta de manejar su señal durante el resto de esta maniobra?","options":["Apagar la señal en cuanto el frente de su tractor haya entrado a la entrada, ya que el giro está prácticamente comprometido","Volver a activar la señal y mantenerla parpadeando hasta haber completado por completo el giro y que su vehículo esté recto","Dejar la señal apagada ahora y en su lugar tocar el freno un par de veces para comunicar su intención al ciclista","Señalizar solo durante el primer segundo del giro, que es todo lo que exige la ley antes de comprometerse con la maniobra"],"explanation":"Mantenga la señal encendida de forma continua hasta completar el giro y enderezar el vehículo, ya que el remolque necesita todo el arco para seguir la trayectoria."},"169":{"q":"Conduce un remolque cargado en una autopista concurrida de cuatro carriles y ve que el tráfico lento se está acumulando aproximadamente a un cuarto de milla por delante. Pronto deberá reducir la velocidad, y una fila de autos lo sigue de cerca. ¿Qué acción comunica MEJOR a los conductores que vienen detrás que está a punto de reducir la velocidad?","options":["Apagar y volver a encender rápidamente los faros y las luces traseras para llamar su atención","Tocar la bocina dos veces brevemente para que los conductores de atrás esperen un cambio","Pisar ligeramente el pedal del freno varias veces para hacer destellar las luces de freno con anticipación","Acelerar brevemente para abrir espacio adelante y luego frenar con fuerza cuando se cierre el hueco"],"explanation":"Para advertir a los conductores de atrás que va a frenar, pise el pedal del freno suavemente varias veces para destellar las luces de freno con anticipación."},"171":{"q":"Acaba de amanecer y el sol está bajo en el horizonte. La luz es tenue y grisácea, y nota que cada vez le cuesta más distinguir a otros conductores y las siluetas contra la carretera. Va a tiempo y la visibilidad aún no se ha perdido por completo. Para ver la carretera y, igual de importante, ser visto por el resto del tráfico en esta penumbra, ¿cuál es la única mejor decisión?","options":["Encender la luz interior de la cabina (plafón) para juzgar mejor desde dentro las condiciones tenues del exterior","Dejar todas las luces exteriores apagadas, ya que todavía hay suficiente luz natural para ver la carretera","Encender solo las luces intermitentes de emergencia para avisar a otros conductores de que la visibilidad es mala","Encender los faros para poder ver la carretera y para que los demás conductores vean claramente su vehículo"],"explanation":"Al amanecer o al anochecer, encienda los faros para ver el camino y para que los demás conductores vean claramente su vehículo."},"172":{"q":"Está transportando un remolque cargado en tráfico moderado a 55 mph. Un automóvil pequeño se le mete de golpe por delante y frena con fuerza, y se da cuenta de que ha reducido el colchón de espacio delante de su parachoques. ¿Por qué es más importante mantener ese espacio por delante justo en este momento?","options":["Le da el espacio que necesita para frenar hasta detenerse por completo o esquivar el peligro con el volante de forma segura","Le permite mantener una velocidad de crucero más alta usando menos los frenos","Ahorra combustible porque frena y acelera menos en un tráfico constante","Disuade a otros conductores de meterse y apretarle el carril"],"explanation":"El espacio adelante es su margen de escape, que le da lugar para frenar hasta detenerse o esquivar un peligro con seguridad."},"173":{"q":"Conduce una combinación cargada por una concurrida carretera de dos carriles a 50 mph cuando nota que un automóvil se ha colocado muy cerca detrás de usted y le va pegado, manteniéndose a solo uno o dos largos de su parachoques. El tráfico de adelante avanza de forma constante, pero podría reducir la velocidad en cualquier momento. ¿Cuál de las siguientes es la MEJOR manera de manejar este peligro?","options":["Tocar levemente los frenos para destellar las luces de freno y hacerle señas al que va pegado para que se aleje","Abrir más espacio delante de usted soltando gradualmente el acelerador y aumentando su distancia de seguimiento, para poder frenar suavemente si el tráfico se reduce","Mantener su velocidad y conservar la posición en su carril, ya que el que va pegado es responsable del espacio detrás de su vehículo","Acelerar para alejarse del que va pegado y restablecer una distancia segura"],"explanation":"Cuando lo siguen muy de cerca, suelte el acelerador gradualmente para abrir más espacio adelante y poder frenar suavemente, no de golpe, si el tráfico se detiene."},"174":{"q":"Circula a velocidad de autopista por el carril central de una interestatal de tres carriles. Un automóvil se ha colocado junto a su tractor por la derecha y mantiene esa posición, sin adelantar ni quedarse atrás, viajando a la par de su cabina. ¿Por qué permanecer en esta disposición lado a lado es la situación MENOS deseable para usted como conductor?","options":["Circular en paralelo obliga a ambos vehículos a consumir notablemente más combustible, por lo que aumenta sus costos de operación en un viaje largo","La ley de Texas prohíbe específicamente que dos vehículos circulen a la par en carriles contiguos de una autopista de acceso controlado","Lo más probable es que el automóvil esté situado en uno de sus puntos ciegos, así que si necesitara cambiar de carril podría no verlo e invadir su espacio al incorporarse","Mantenerse a la par de otro vehículo le hace perder tiempo porque no puede aprovechar el cambio de carril para avanzar"],"explanation":"Un vehículo que va a tu costado suele quedar en un punto ciego lateral donde no lo ves, por lo que podrías chocarlo al cambiar de carril."},"175":{"q":"Conduce un camión de caja cerrada cargado por una ruta desconocida cuando ve más adelante un paso elevado con un gálibo (altura libre) indicado de 13 pies 2 pulgadas. Para decidir con seguridad si puede pasar por debajo sin golpear la estructura, lo MÁS importante que ya debe saber es:","options":["El peso bruto vehicular (GVWR) indicado en la puerta, para no exceder un límite de peso señalizado del puente","Su distancia total de frenado a esta velocidad, que es de unos 419 pies a 55 mph","La longitud de su vehículo, para librar por completo la estructura antes de detenerse","La altura de su vehículo cargado, incluida cualquier carga o equipo montado en la parte superior"],"explanation":"Debes conocer la altura real de tu vehículo cargado, incluida la carga o equipo en el techo, para compararla con la altura libre señalizada del paso."},"176":{"q":"Conduce un tractocamión con remolque de 53 pies (16 m) y necesita girar a la derecha desde una calle urbana hacia una vía lateral estrecha. Al acercarse a la esquina, se da cuenta de que el giro es más cerrado de lo que esperaba. ¿Cuál es la forma MÁS SEGURA de mantener suficiente espacio para completar este giro?","options":["Mantenga su carril correcto en la aproximación y luego ábrase hacia afuera al COMPLETAR el giro, para que el remolque (cuyas ruedas traseras se desplazan hacia adentro) libre la esquina, manteniendo la parte trasera del remolque pegada al bordillo en todo momento","Meterse primero en el carril izquierdo y empezar el giro temprano para que la parte trasera del remolque recorte la esquina de cerca y se pegue al bordillo","Acelerar durante el giro para pasar menos tiempo bloqueando el cruce y despejarlo rápidamente","Mantener el camión pegado al bordillo derecho todo el tiempo para que ningún otro vehículo pueda colarse en el hueco a su derecha"],"explanation":"Como las ruedas traseras del remolque se desplazan hacia adentro, mantén tu carril al acercarte y gira amplio al completar el giro, dejando la cola del remolque cerca del bordillo."},"177":{"q":"Está detenido en una señal de alto en un vehículo combinado totalmente cargado, esperando para cruzar una concurrida carretera de dos carriles donde el tráfico circula a 55 mph en ambos sentidos. Se abre un hueco en el tráfico transversal. Como su equipo es pesado y acelera lentamente, ¿qué debe permitirle hacer ese hueco antes de decidirse a salir?","options":["Adelantar el parachoques delantero justo más allá del borde cercano para que los conductores que vienen lo vean y reduzcan la velocidad","Cruzar la carretera por completo con todo el vehículo, o alcanzar la velocidad del tráfico, antes de que el siguiente vehículo llegue hasta usted","Llegar al centro de la intersección y detenerse por completo para evaluar el segundo carril","Entrar y quedarse al ralentí en el carril solo el tiempo justo para que el conductor que se acerca cambie de carril y lo rodee"],"explanation":"Elige un espacio lo bastante grande para cruzar por completo o alcanzar la velocidad del tránsito antes de que un vehículo que se aproxima llegue hasta ti."},"178":{"q":"Está incorporándose con su tractocamión a una autopista interestatal congestionada durante el tráfico pesado de la tarde. Una fila de automóviles sigue desplazándose por su costado derecho, demorándose cerca de sus ruedas traseras, donde los espejos casi no le muestran nada. Varios conductores parecen acomodarse cómodamente en ese hueco al lado y detrás de su remolque. Respecto a estas áreas de punto ciego (las 'No-Zones') alrededor de su unidad, ¿qué enfoque refleja mejor una práctica segura de conducción comercial?","options":["Tratar las No-Zones como carriles normales de circulación y dejar que los autos permanezcan allí, ya que ellos eligieron estar ahí y la responsabilidad es suya","Acelerar bruscamente para sacar a los autos del punto ciego trasero derecho, porque despejar el hueco rápidamente siempre es la solución más segura","Reconocer que no puede ver los vehículos en las No-Zones y gestionar su conducción para mantener esas áreas libres de tráfico siempre que sea posible","Meterse usted lentamente en los puntos ciegos de los autos a cambio, para que el riesgo se reparta por igual entre usted y los conductores de turismos"],"explanation":"No puedes ver los vehículos en las No-Zones, así que gestiona tu velocidad, posición en el carril y distancia para mantener esos puntos ciegos libres de tránsito."},"179":{"q":"Usted conduce un vehículo combinado totalmente cargado e ingresa a una pendiente larga y empinada de subida por el carril derecho. A medida que sube, el motor se esfuerza y su velocidad baja de forma constante muy por debajo del límite indicado, mientras que automóviles más rápidos y vehículos livianos comienzan a acumularse detrás de usted. ¿Cuál es la MEJOR manera de manejar su camión en esta subida?","options":["Cambiarse al carril del extremo izquierdo para que los vehículos más lentos detrás de usted puedan pasar por la derecha sin cambiar de carril","Reducir la marcha y acelerar con fuerza para mantener la velocidad en el límite indicado y no obstruir al tránsito más rápido que viene detrás","Mantener la velocidad pero orillarse al acotamiento derecho y detenerse brevemente para dejar pasar la fila de vehículos antes de continuar","Aceptar que la carga pesada lo hará ir más despacio, permanecer en el carril derecho y dejar que el tránsito más rápido lo rebase por la izquierda"],"explanation":"Una carga pesada te frena de forma natural en una cuesta empinada, así que quédate en el carril derecho y deja que el tránsito más rápido pase por la izquierda."},"180":{"q":"Está conduciendo un tractocamión con remolque de 53 pies en una autopista de tres carriles con tráfico moderado. Un automóvil circula a su lado en el carril izquierdo y, a su derecha, una rampa de acceso incorpora vehículos a la autopista. No puede ceder espacio en ambos lados a la vez. ¿Qué acción gestiona MEJOR su espacio lateral en esta situación?","options":["Mantenga su vehículo centrado en su carril para conservar un margen de espacio a ambos lados en lugar de entregar todo su espacio a un solo lado","Desplácese y péguese a la línea del carril izquierdo para maximizar la distancia entre su remolque y el tráfico que se incorpora por la rampa","Pise brevemente la línea del carril metiéndose al carril izquierdo para que ningún vehículo pueda colocarse junto a sus puntos ciegos","Métase al acotamiento derecho hasta que termine de incorporarse el tráfico de la rampa, y luego regrese a su carril"],"explanation":"Mantener tu vehículo centrado en el carril conserva un colchón de espacio a ambos lados cuando hay amenazas por la izquierda y la derecha a la vez."},"181":{"q":"Usted se acerca a un cruce ferroviario con tráfico pesado de pare y siga. El cruce no tiene barrera ni señales intermitentes, y los vehículos de adelante avanzan lentamente. Su combinación de 73 pies es el siguiente vehículo en llegar a las vías. ¿Cuál es la mejor manera de decidir si cruzar las vías?","options":["Avanzar sobre las vías y esperar allí, ya que no hay barrera ni señal que advierta de un tren","Esperar hasta que haya un espacio lo bastante grande para cruzar por completo sin detenerse, dejando margen para toda la longitud de su vehículo más unos 15 pies","Entrar al cruce en cuanto avance el vehículo de adelante, porque mantener el flujo del tráfico es la prioridad","Empezar a cruzar y, si el tráfico se detiene, cambiar a una marcha más baja sobre las vías para pasar rápido"],"explanation":"Nunca empieces a cruzar las vías a menos que el espacio te permita despejarlas por completo sin detenerte, contando tu largo total más unos 15 pies."},"182":{"q":"Conduce un vehículo combinado cargado por una carretera seca de dos carriles y ve adelante una curva cerrada señalizada. Va casi a la velocidad permitida y siente que su velocidad actual podría ser un poco alta para el giro. Para tomar la curva con seguridad, ¿qué debe hacer con su velocidad y su frenado?","options":["Mantener la velocidad hasta la curva y luego frenar con fuerza una vez que esté en la mitad de la curva, donde el giro es más cerrado.","Esperar a haber salido de la curva y entonces reducir la velocidad para estar listo para la siguiente.","Reducir a una velocidad segura ANTES de entrar en la curva y luego acelerar suavemente a lo largo de ella para mantener el vehículo estable.","Entrar a la curva a velocidad constante y confiar en una presión de freno ligera y constante durante todo el giro para controlar el camión."],"explanation":"Reduce a una velocidad segura antes de entrar en la curva y luego acelera suavemente a través de ella, ya que frenar dentro de la curva puede causar un derrape o vuelco."},"183":{"q":"Está transportando una carga por una carretera rural de dos carriles cuando comienza una lluvia constante y el pavimento se vuelve brillante y mojado. El tráfico circula al límite señalizado de 55 mph, y siente que la dirección se vuelve ligeramente liviana en una curva larga y amplia. ¿Cuál es la única respuesta más segura ante la reducción de tracción?","options":["Mantener las 55 mph pero aumentar la distancia de seguimiento para compensar, ya que el límite señalizado sigue siendo legal","Acelerar ligeramente en la curva para mantener el peso sobre los ejes de tracción y mejorar el agarre","Mantener la velocidad y bombear el freno rápidamente para comprobar cuánta tracción queda","Reducir la velocidad por debajo del límite señalizado porque el pavimento mojado reduce la tracción y alarga la distancia de frenado"],"explanation":"La tracción, no el límite señalizado, fija la velocidad segura, y el pavimento mojado reduce la tracción y alarga la distancia de frenado, así que baja del límite."},"184":{"q":"La temperatura está justo bajo cero y una nevada ligera ha comenzado a adherirse a la calzada. Conduce un tractocamión cargado a la misma velocidad de carretera que mantenía esta mañana con clima despejado y seco. En comparación con aquellas condiciones secas, ¿cuál es el cambio MÁS importante que debe esperar en el manejo de su vehículo, y por qué?","options":["La tracción se reduce enormemente, por lo que los neumáticos se agarran mucho menos al pavimento y necesita mucha más distancia para detenerse y maniobrar","La tracción se reduce solo ligeramente, así que mantener una distancia de seguimiento normal y una velocidad constante será suficiente para ir seguro","La tracción se mantiene casi igual que en pavimento seco porque el peso del remolque cargado presiona los neumáticos firmemente contra la nieve","La tracción en realidad mejora un poco porque la fina capa de nieve rellena las irregularidades de la superficie y da a los neumáticos más agarre"],"explanation":"La nieve y el hielo reducen mucho la tracción, por lo que los neumáticos se agarran mucho menos y se necesita mucha más distancia para frenar y dirigir."},"185":{"q":"Acaba de descargar toda su carga en el muelle y ahora regresa al patio con un remolque completamente vacío. Sobre el pavimento mojado, una camioneta se le cruza y tiene que frenar con fuerza. En comparación con cuando iba totalmente cargado antes, ¿por qué podría su camión necesitar en realidad una distancia MÁS LARGA para detenerse ahora que está vacío?","options":["Un camión vacío es más pesado, así que su mayor inercia lo lleva más lejos antes de poder detenerse","Como hay poco peso presionando los neumáticos contra el camino, el camión vacío tiene menos tracción, por lo que las ruedas se bloquean con más facilidad y la distancia de frenado aumenta","Los remolques vacíos van más altos, lo que eleva el centro de gravedad y alarga la distancia de frenado","En un camión vacío los frenos funcionan más fríos y pierden eficacia, lo que añade unos 60 pies a la distancia de frenado a 55 mph"],"explanation":"Un camión vacío tiene poco peso presionando los neumáticos, por lo que se agarran menos, se bloquean más fácilmente y aumenta la distancia de frenado."},"186":{"q":"Está descendiendo una pendiente de montaña larga y empinada con un remolque completamente cargado. A mitad del descenso, nota que mantiene el pie sobre el pedal del freno de forma continua solo para sostener su velocidad, y la cabina empieza a oler a recalentado. ¿Qué afirmación describe MEJOR lo que les está pasando a sus frenos de servicio principales y por qué?","options":["Los frenos ganan potencia de frenado a medida que se calientan, así que puede aplicarlos con más fuerza con seguridad durante el resto del descenso.","Los frenos se enfrían solos mediante el flujo de aire continuo, así que mantener una presión constante en el pedal es la forma principal y correcta de controlar su velocidad.","Los frenos se están recalentando y empezando a perder eficacia (desvanecimiento de frenos), por lo que el freno de motor en marcha baja debe ser el control principal y los frenos solo un complemento.","Los frenos están a punto de bloquear las ruedas del remolque, así que debe bombear el pedal rápidamente para evitar que el remolque se pliegue (efecto tijera)."],"explanation":"En una bajada larga los frenos pueden sobrecalentarse y perder eficacia, por lo que el frenado con motor en marcha baja debe ser el control principal y los frenos solo un complemento."},"187":{"q":"Está en la cima de una pendiente de montaña larga y empinada transportando un remolque pesado y completamente cargado. Está lloviendo y la carretera tiene una curva cerrada aproximadamente a la mitad del descenso. Antes de soltar los frenos y comenzar a bajar, debe decidir una velocidad segura para el descenso. ¿Cuál de las siguientes describe correctamente de qué debe depender su velocidad segura de descenso?","options":["Solo de lo empinada que es la pendiente, ya que la gravedad es el único factor que controla qué tan rápido rodará un camión cuesta abajo","Principalmente de las revoluciones del motor (RPM) en la cima, porque igualar la lectura del tacómetro establece la velocidad correcta para cualquier pendiente","Casi por completo del límite de velocidad señalizado, ya que ese número se fija específicamente para vehículos comerciales completamente cargados en esa pendiente","Del peso total de su vehículo y su carga, la longitud y lo empinada de la pendiente, las condiciones de la carretera y el clima"],"explanation":"La velocidad segura para descender depende del peso total del vehículo y la carga, la longitud y la pendiente de la bajada, el estado de la carretera y el clima."},"188":{"q":"Está a punto de comenzar a bajar una pendiente de montaña larga y empinada con un remolque completamente cargado. Quiere controlar la velocidad sin sobrecalentar los frenos ni perder su eficacia en la bajada. ¿Cuál es la mejor forma de decidir qué marcha usar?","options":["Use la misma marcha baja que necesitaría para subir la pendiente, y selecciónela ANTES de empezar a bajar.","Cambie a una marcha mucho más alta que la que usó para subir, para que el motor trabaje más cómodo en la bajada.","Ponga la transmisión en neutral y confíe en una presión constante del freno para mantener la velocidad.","Permanezca en su marcha normal de carretera y reduzca solo si los frenos empiezan a perder eficacia."],"explanation":"Use la misma marcha baja que necesitaría para subir la pendiente, y selecciónela antes de empezar a bajar."},"189":{"q":"Es temprano por la mañana y el indicador de temperatura exterior marca justo por debajo del punto de congelación (unos 30 F / -1 C). La carretera de dos carriles por la que conduce se ve completamente seca y no ha tenido problemas de tracción durante la última hora. Ahora se aproxima a un paso elevado largo que cruza el valle de un río. ¿Cuál de las siguientes es la suposición MÁS SEGURA al llegar al paso elevado?","options":["Como la superficie del camino se ha mantenido seca y ha tenido buena tracción, la plataforma del paso elevado no será más resbaladiza que el pavimento que acaba de dejar","El paso elevado puede estar helado aunque el resto del camino esté despejado, porque los puentes y pasos elevados se congelan antes que otras partes del camino","El paso elevado se congelará al final de todo, así que es el lugar más seguro para frenar o reducir de marcha si necesita disminuir la velocidad","Los pasos elevados no se congelan antes que el pavimento normal, así que solo debe vigilar el hielo cuando el aire se caliente por la tarde"],"explanation":"Los puentes y pasos elevados se congelan antes que el resto de la carretera, por lo que un paso elevado puede estar helado aunque el resto del pavimento esté despejado."},"190":{"q":"Después de una larga sequía acaba de comenzar una lluvia constante, y una fina película de agua se acumula sobre la autopista encima del aceite y el polvo viejos. Hay poco tráfico, así que se siente tentado a mantener una velocidad alta. Para que sus neumáticos sigan agarrando la carretera y evitar el hidroplaneo, ¿a qué velocidad aproximada debe entender que el hidroplaneo puede COMENZAR, de modo que reduzca por debajo de ella en estas condiciones?","options":["El hidroplaneo no puede comenzar hasta que alcance unas 70 mph, así que cualquier velocidad de autopista por debajo de eso es segura bajo la lluvia.","El hidroplaneo solo es preocupante a velocidades muy bajas, alrededor de 5 mph, por lo que es principalmente un problema de estacionamiento.","El hidroplaneo puede comenzar a velocidades tan bajas como unas 30 mph, por lo que debe reducir su velocidad por debajo de eso sobre esta película mojada y resbaladiza.","El hidroplaneo no comenzará hasta que supere las 90 mph, mucho más alto que cualquier velocidad legal de un camión."],"explanation":"El hidroplaneo puede comenzar a velocidades tan bajas como unas 30 mph sobre una película mojada y resbaladiza, así que reduzca su velocidad por debajo de ese punto."},"191":{"q":"Conduce un remolque cargado a velocidad de autopista en una interestatal de Texas durante un fuerte aguacero de verano. Se ha acumulado agua estancada en las roderas del carril. De repente la dirección se siente liviana y floja, los neumáticos delanteros parecen perder contacto con el pavimento y la aguja del velocímetro parpadea aunque usted no ha cambiado el acelerador. Se da cuenta de que está empezando a hidroplanear. ¿Cuál es la primera acción correcta?","options":["Pisar el freno con firmeza y mantenerlo para reducir la velocidad lo más rápido posible, ya que en una carretera mojada lo que más importa es la distancia de frenado","Girar bruscamente hacia la parte más alta y seca del centro del carril para devolver los neumáticos al pavimento con mejor agarre","Mantener la velocidad actual pero reducir de marcha para usar el freno de motor, ya que las ruedas motrices aún tienen agarre en la superficie mojada","Soltar la presión sobre el acelerador, mantener el volante recto y dejar que el vehículo reduzca la velocidad hasta que los neumáticos recuperen un contacto firme con la carretera"],"explanation":"Al hidroplanear, suelte el acelerador, mantenga el volante recto y deje que el vehículo desacelere hasta que los neumáticos recuperen el contacto firme con la carretera."},"192":{"q":"Es mediados de julio en el oeste de Texas y el pavimento reluce por el calor. Ha conducido a velocidad de autopista durante dos horas y se detiene para la inspección obligatoria de la carga y su sujeción. Mientras está detenido, ¿qué condición de los neumáticos es la MÁS importante de vigilar en estas condiciones?","options":["Banda de rodadura desgastada por debajo de 4/32 de pulgada en los neumáticos de tracción traseros","Letras descoloridas en el flanco y marcas de marca faltantes en la carcasa","Presión algo baja que debería completar ahora mismo hasta el valor de inflado en frío","Neumáticos recalentados con una presión que ha subido por encima del valor en frío, lo que indica riesgo de reventón"],"explanation":"Con calor, vigile los neumáticos que se calientan y cuya presión sube por encima del ajuste en frío, ya que un neumático sobrecalentado y con exceso de presión tiende a reventar."},"193":{"q":"Al comenzar su turno hay 28 F (menos 2 grados Celsius) y la nieve húmeda de la noche se ha congelado sobre su tractor. Durante su inspección previa al viaje encuentra una fina capa de hielo en la mitad inferior del parabrisas y una costra de nieve congelada en ambos espejos laterales. Ya va atrasado en su horario. Antes de salir a la carretera, ¿qué exige el DPS de Texas que haga?","options":["Eliminar por completo todo el hielo y la nieve congelada para que el parabrisas y ambos espejos queden totalmente despejados antes de conducir","Despejar solo la zona del lado del conductor por donde mira y dejar los espejos, ya que el desempañador los derretirá una vez en marcha","Raspar una pequeña zona de visión en el parabrisas y confiar en la cámara de reversa y en mirar por encima del hombro en lugar de los espejos helados","Dejar la capa de hielo porque a 28 F la temperatura está por encima del punto en que el hielo afecta la tracción, y conducir a velocidad reducida"],"explanation":"Quite por completo todo el hielo y la nieve congelada para que el parabrisas y ambos espejos estén totalmente despejados antes de conducir."},"194":{"q":"Es una mañana húmeda con la temperatura apenas bajo cero, y durante su inspección previa al viaje el pavimento debajo de su tractor se ve solo mojado y brillante, no helado. Al incorporarse a la autopista nota que la dirección se vuelve ligera y el camión se desliza levemente. ¿Por qué el 'hielo negro' sobre el que probablemente ha entrado es tan peligroso precisamente en este tipo de situación?","options":["Forma una superficie visiblemente áspera y costrosa, por lo que puede detectarlo a tiempo y frenar con fuerza antes de llegar a él","Es una capa fina y transparente que hace que la carretera parezca solo mojada, así que no puede verlo y quizá no se dé cuenta de que la superficie está congelada hasta que pierda la tracción","Solo se acumula en las cimas de las colinas, por lo que el peligro se limita a tramos cortos y predecibles de la ruta","Siempre aparece como una capa blanca y gruesa, dándole tiempo de sobra para reducir la velocidad con antelación"],"explanation":"El hielo negro es una capa fina y transparente que hace que la carretera parezca solo mojada, por lo que no se ve y puede que no se note que está congelada hasta perder la tracción."},"195":{"q":"Justo después del amanecer está remolcando un tráiler cargado a través de un valle fluvial bajo, donde una niebla densa e irregular ha reducido la visibilidad a aproximadamente el largo de su equipo. Decide seguir avanzando lentamente en lugar de detenerse en el carril de circulación. ¿Qué elección de iluminación le da la mejor visión y lo hace más visible para los demás?","options":["Cambiar a las luces altas, ya que la luz más brillante penetrará más profundo en la niebla que tiene adelante","Apagar los faros y usar solo las luces intermitentes de emergencia para evitar el deslumbramiento","Usar las luces bajas (junto con las luces antiniebla si las tiene), porque las luces altas se reflejan en la niebla y le devuelven la luz a usted","Dejar las luces altas encendidas pero bajarlas solo cuando esté dentro de los 500 pies de un vehículo que viene en sentido contrario"],"explanation":"Use las luces bajas en la niebla porque las luces altas se reflejan en las gotas de agua suspendidas y le devuelven el resplandor, reduciendo su visibilidad."},"196":{"q":"Es una noche oscura y sin luna en una carretera rural de dos carriles sin alumbrado público. Sus luces bajas iluminan aproximadamente 250 pies de camino por delante. Para conducir con seguridad, ¿cómo debe elegir su velocidad?","options":["Igualar el límite de velocidad diurno publicado, ya que el límite se fija para la vía y no cambia después del anochecer","Elegir una velocidad a la que su distancia total de frenado equivalga al doble de la distancia que iluminan sus faros, dándole un margen de seguridad","Mantener constantes 55 mph y confiar en sus luces altas para reaccionar a tiempo ante cualquier cosa adelante","Conducir lo suficientemente despacio para poder detenerse por completo dentro de la distancia iluminada por sus faros"],"explanation":"Nunca conduzca más rápido de lo que alcanzan sus faros; mantenga una velocidad que le permita detenerse dentro de la distancia que iluminan adelante."},"197":{"q":"Conduce un vehículo combinado cargado por una carretera rural de dos carriles a última hora de la tarde cuando un aguacero repentino y fuerte reduce su visibilidad a unos pocos cientos de pies. Hay poco tráfico, pero de vez en cuando aparecen vehículos en sentido contrario, y usted quiere tanto ver la carretera como ser visto. ¿Qué posición de los faros es la mejor opción para estas condiciones de lluvia intensa?","options":["Luces bajas, porque ayudan a que otros lo vean sin reflejar el resplandor de vuelta por la lluvia intensa","Luces altas, porque la distancia extra que iluminan es necesaria para ver a través de la lluvia intensa","Faros apagados con solo las luces de estacionamiento, para que el pavimento mojado no genere reflejos que distraigan","Luces altas encendidas y apagadas de forma intermitente para advertir al tráfico que viene en sentido contrario que la visibilidad es mala"],"explanation":"Use las luces bajas en lluvia fuerte para que otros conductores lo vean, evitando el resplandor que producen las luces altas al reflejarse en la lluvia."},"198":{"q":"Es media tarde durante una ola de calor en Texas y la temperatura del pavimento ha estado subiendo todo el día. Al reducir la velocidad para un cruce con sombra, nota franjas oscuras y brillantes de alquitrán que rezuman a través de las juntas del asfalto en el carril de circulación más adelante. Según cómo el clima muy caluroso afecta la superficie de la carretera, ¿para qué peligro debe estar MÁS preparado al pasar sobre estas manchas?","options":["El alquitrán se habrá endurecido en una superficie rugosa de alto agarre, por lo que puede frenar más fuerte de lo normal","El alquitrán que rezuma puede volver resbaladiza la superficie, así que reduzca la velocidad y evite frenar bruscamente o girar de forma brusca al pasar sobre ella","Las manchas están formando hielo negro, por lo que la superficie que parece mojada en realidad está congelada","El calor habrá elevado la presión de los neumáticos lo suficiente como para mejorar el agarre sobre el alquitrán, así que no se necesita cambiar la velocidad"],"explanation":"Con mucho calor el alquitrán aflora a la superficie y se vuelve resbaladizo, así que reduzca la velocidad y evite frenar fuerte o girar bruscamente al cruzarlo."},"199":{"q":"Es una tarde ventosa con ráfagas y está a punto de salir con un remolque de caja alto y ligeramente cargado por un tramo expuesto de la interestatal. Un compañero le dice que no se preocupe porque un remolque alto y vacío 'se maneja solo' mejor con viento. Considerando cómo actúan los vientos cruzados fuertes sobre un remolque de perfil alto, ¿qué debe esperar realmente respecto al control de su equipo?","options":["El remolque alto será más fácil de controlar, porque su altura lo mantiene firme contra el viento","El remolque alto se detendrá más rápido, ya que el viento ayuda empujando contra su movimiento hacia adelante","El remolque alto será más difícil de controlar, porque los vientos fuertes empujan contra su gran superficie lateral alta","El remolque alto usará menos combustible, porque el viento reduce la carga sobre su eje motriz"],"explanation":"El viento fuerte empuja la gran superficie lateral alta de un remolque alto, dificultando el control del vehículo, sobre todo cuando va vacío o con poca carga."},"200":{"q":"La temperatura está apenas por debajo del punto de congelación y ha estado cayendo una lluvia ligera. Al acercarse a un puente en sombra, el pavimento más adelante de repente se ve mojado y brillante, aunque sus espejos y la antena ya empezaron a cubrirse de hielo. ¿Cuál es la forma más segura de pasar su camión cargado por este tramo?","options":["Mantener su velocidad actual pero bombear los frenos unas cuantas veces ahora para probar cuánta tracción le queda a la superficie","Mantener la velocidad y simplemente aumentar la distancia de seguimiento, ya que los puentes se descongelan más rápido que la carretera abierta","Acelerar suavemente para cruzar el puente rápido antes de que la superficie se congele aún más","Reducir la velocidad bastante antes del puente y usar de forma suave y delicada la dirección, el freno y el acelerador"],"explanation":"Un aspecto húmedo y brillante con hielo en espejos y antena indica hielo negro, y los puentes se congelan primero, así que reduzca la velocidad con tiempo y maneje con suavidad."},"201":{"q":"Es una noche sin luna y está a punto de salir de una parada de camiones mal iluminada para un recorrido de 4 horas por una carretera rural de dos carriles. Durante la inspección a pie nota que ambos cristales de los faros están cubiertos por una capa de mugre del camino e insectos secos, reduciendo notablemente su brillo. ¿Cuál es la MEJOR acción antes de salir?","options":["Limpiar los cristales de los faros para que proyecten toda su luz y usted pueda ver lo suficientemente lejos como para detenerse a tiempo","Salir ahora y simplemente reducir la velocidad para que las luces bajas aún cubran el camino mientras conduce","Usar las luces altas durante todo el viaje para compensar los cristales sucios y atenuados","Omitir la limpieza y confiar en las luces de posición y de gálibo para marcar su trayectoria"],"explanation":"Los cristales sucios de los faros reducen el alcance de las luces bajas, así que límpielos para recuperar toda la luz y ver lo suficiente adelante para detenerse a tiempo."},"202":{"q":"Va descendiendo por una pendiente larga y empinada de montaña con un remolque cargado. A mitad del descenso, pisa el pedal del freno y este se hunde hacia el piso casi sin efecto de frenado, y huele algo quemado. Su velocidad empieza a aumentar. ¿Cuál es la MEJOR acción a tomar?","options":["Bombear el pedal del freno fuerte y rápido para recuperar la presión, y luego seguir rodando en la marcha actual","Reducir a una marcha más baja para que el freno de motor lo desacelere, y dirigirse hacia la próxima rampa de escape","Poner el cambio en neutro para proteger la transmisión y dejar que el camión ruede hasta que la pendiente se nivele","Salir bruscamente al acotamiento izquierdo y colocar tres triángulos reflectantes a 10, 100 y 200 pies"],"explanation":"Cuando los frenos de servicio fallan en una bajada, reduzca a una marcha más baja para usar el freno del motor y dirija hacia una rampa de escape para detenerse con seguridad."},"203":{"q":"Usted conduce un tractocamión cargado descendiendo por una pendiente de montaña larga y empinada. A pesar de haber seleccionado una marcha baja antes del descenso y de usar un frenado ligero y constante, percibe un leve olor a quemado y el pedal del freno empieza a sentirse blando y esponjoso. Más adelante, en el arcén derecho, ve una señal de rampa de escape. Bajo estas condiciones, ¿cuál es la comprensión correcta de cuándo y por qué debe usar esa rampa?","options":["Es un área de estacionamiento designada donde puede aparcar durante la noche y dejar que los frenos sobrecalentados se enfríen antes de continuar el descenso","Es un área de descanso colocada en pendientes empinadas para que los conductores cansados puedan detenerse un rato y recuperarse antes de terminar una bajada larga","Está construida para detener un vehículo fuera de control, así que si sus frenos han fallado y ya no puede controlar la velocidad, debe usarla para detener el camión de forma segura","Es un carril designado donde puede cambiar con seguridad a una marcha más baja mientras el vehículo todavía baja por la pendiente"],"explanation":"Una rampa de escape está hecha para detener un vehículo desbocado cuyos frenos fallaron, así que úsela para detener el camión con seguridad cuando ya no pueda controlar la velocidad."},"204":{"q":"Conduce un vehículo combinado cargado a velocidad de carretera en un camino seco de dos carriles cuando el volante de repente se afloja y el camión deja de responder normalmente a sus movimientos de dirección. Hay poco tránsito y el acotamiento adelante está despejado. ¿Cuál es la MEJOR primera reacción?","options":["Mantener la velocidad actual y forzar el volante de un lado a otro hasta que la dirección vuelva a responder","Soltar el volante por completo y dejar que el vehículo siga su propia trayectoria mientras alcanza la radio","Aplicar los frenos de forma suave y gradual para detener el vehículo de manera controlada y segura","Pisar fuerte y bloquear los frenos de inmediato para detener el vehículo en la menor distancia posible"],"explanation":"Si la dirección falla de repente, lo único que aún controlas es la velocidad, así que frena suave y gradualmente hasta detener el vehículo de forma segura y controlada."},"205":{"q":"Usted es el primer vehículo en llegar a un choque entre dos autos en una carretera rural de dos carriles. Un conductor está desplomado sobre el volante y parece herido, y hay vidrios rotos y líquido derramado en ambos carriles. Siguen acercándose otros vehículos desde ambas direcciones. ¿Qué es lo PRIMERO que debe hacer después de detener su camión de forma segura?","options":["Proteger la zona del accidente y advertir al tránsito que se aproxima para evitar más choques","Sacar al conductor herido del auto y llevarlo al acotamiento","Tomar fotos de la escena para documentar los daños para el informe","Empezar a revisar a cada víctima en busca de lesiones y brindar primeros auxilios"],"explanation":"En cualquier accidente la primera prioridad es evitar un segundo choque, así que protege la zona y advierte al tránsito que se acerca antes de hacer cualquier otra cosa."},"206":{"q":"Está transportando un remolque seco por una carretera rural de dos carriles cuando huele humo y ve llamas parpadeando cerca de la zona de las ruedas del eje trasero. Necesita detenerse rápido, pero hay varios lugares para parar más adelante. ¿Cuál es el MEJOR lugar para orillarse y estacionar para enfrentar el incendio?","options":["Justo pasando la entrada del túnel que se aproxima, para que la estructura proteja al camión del viento","En el área de grava de la parada de camiones, estacionando cerca de los surtidores de diésel para tener un extintor a la mano","En el amplio acotamiento de un tramo abierto, bien lejos de edificios y otros vehículos, cerca de una caseta de emergencia","Debajo del siguiente paso a desnivel de concreto, donde la sombra evita que la carga se sobrecaliente aún más"],"explanation":"En un incendio del vehículo, detente en un acotamiento abierto lejos de edificios, tránsito e inflamables pero cerca de un teléfono de emergencia para aislar el fuego y poder pedir ayuda."},"207":{"q":"Conduce un tractocamión cargado por una autopista mojada cuando un automóvil se le cruza de repente y frena en seco. Usted frena con fuerza, la luz de advertencia del ABS está apagada (el sistema funciona) y debe desviarse hacia el acotamiento vacío para evitar la colisión. Contando con su ABS en esta emergencia, ¿qué es lo MÁS exacto que realmente hará por usted?","options":["Reducirá su distancia total de frenado muy por debajo de los aproximadamente 419 pies que necesita un camión a 55 mph, así que podrá detenerse a tiempo sin desviarse","Frenará y dirigirá automáticamente el camión hacia el acotamiento por usted en cuanto detecte el obstáculo adelante","Garantiza que las ruedas permanezcan bloqueadas para que las llantas se aferren con más fuerza al pavimento mojado y logren el máximo agarre","Evitará que sus ruedas se bloqueen para que pueda mantener el control de la dirección y desviarse hacia el acotamiento mientras frena con fuerza"],"explanation":"El ABS evita que las ruedas se bloqueen al frenar fuerte, de modo que conserva el control de la dirección y puede desviarse hacia el arcén mientras frena."},"208":{"q":"Va conduciendo un remolque cargado cuesta abajo por una autopista mojada de cuatro carriles cuando un automóvil se le cruza de repente. Frena con fuerza, se activa el ABS (sistema antibloqueo de frenos), mantiene el control del camión y esquiva el peligro con la dirección. Después, un conductor con menos experiencia le dice que, como su camión tiene ABS, ahora puede seguir a otros vehículos más de cerca porque el ABS le permite detenerse en una distancia mucho más corta. ¿Por qué es INCORRECTO ese razonamiento?","options":["El ABS no necesariamente acorta su distancia de frenado; su principal beneficio es evitar que las ruedas se bloqueen para que pueda dirigir mientras frena.","El ABS solo funciona cuando el pavimento está seco, así que en esta autopista mojada no ayudó en nada al frenar.","El ABS acorta la distancia de frenado solo en el eje de dirección (delantero), así que la distancia de seguimiento puede reducirse a la mitad pero no del todo.","El ABS aplica los frenos automáticamente por usted, así que ya no necesita dejar ninguna distancia de seguimiento a velocidad de autopista."],"explanation":"El ABS no necesariamente acorta la distancia de frenado; su función principal es evitar que las ruedas se bloqueen para que pueda dirigir mientras frena fuerte."},"209":{"q":"Su tractocamión NO está equipado con frenos antibloqueo (ABS). En una carretera rural de dos carriles, un automóvil sale de repente de una calle lateral directamente hacia su trayectoria y usted debe detenerse lo más rápido posible manteniendo el control del conjunto y dentro de su carril. ¿Qué método de frenado le da la parada segura más corta sin perder el control de la dirección?","options":["Pisar el pedal del freno hasta el fondo y mantenerlo para que las ruedas se bloqueen y obtener la máxima fuerza de frenado","Usar el frenado controlado (aplicar presión firme y constante justo antes del bloqueo) o el frenado intermitente (stab), soltando si las ruedas se bloquean","Bombear los frenos de forma rápida y aleatoria durante todo el trayecto hasta detenerse","Aplicar solo la válvula manual del remolque para que el remolque arrastre el conjunto hasta detenerlo"],"explanation":"Sin ABS, evite el bloqueo de las ruedas usando frenado controlado (presión firme y constante justo antes del bloqueo) o frenado intermitente, soltando cuando las ruedas se bloqueen."},"210":{"q":"Conduce cargado en una calurosa tarde de verano a unas 60 mph por una carretera dividida. De repente escucha un fuerte estallido y la parte delantera de su tractocamión se sacude y tira con fuerza hacia un lado -- una llanta del eje delantero (de dirección) ha reventado. En ese primer instante, antes de hacer cualquier otra cosa, ¿qué respuesta le da la MEJOR probabilidad de mantener el control del vehículo?","options":["Frenar fuerte y con firmeza de inmediato para bajar a una velocidad segura antes de que el camión se desvíe aún más","Pisar el acelerador para dar potencia a las ruedas motrices y enderezar el tractocamión, y luego soltarlo cuando vaya recto","Girar bruscamente hacia el lado contrario al que tira para enderezar el tractocamión de vuelta al centro de su carril","Sujetar el volante con firmeza con ambas manos, no tocar el freno al principio, mantener su carril y dejar que el vehículo reduzca la velocidad por sí solo antes de frenar suavemente"],"explanation":"En un reventón, sujeta firme el volante con ambas manos, no frenes al principio, mantén tu carril y deja que el vehículo desacelere antes de frenar suavemente."},"212":{"q":"Durante su inspección previaje, los documentos de embarque muestran que su remolque está cargado varios miles de libras por encima de su peso bruto vehicular (GVWR). Va con retraso y la ruta por delante tiene una bajada larga y un par de curvas cerradas. Un compañero le dice que el peso extra en realidad le 'ayudará a agarrarse al camino', así que no es para tanto. Según cómo afecta la sobrecarga al control del vehículo, ¿qué afirmación es correcta?","options":["El peso añadido presiona las llantas con más fuerza contra el suelo, así que su distancia de frenado será más corta que si fuera cargado dentro del límite legal.","Como la carga está sobre los ejes, el peso extra baja su centro de gravedad y reduce el riesgo de volcadura en las curvas.","El exceso de peso hace que el camión sea más difícil de detener y de dirigir, aumentando su distancia de frenado y el riesgo de perder el control en la bajada y las curvas.","La sobrecarga solo importa para el consumo de combustible y el desgaste de las llantas; no tiene efecto real en cómo se detiene o se dirige el camión."],"explanation":"El exceso de peso hace que el camión sea más difícil de detener y de dirigir, aumentando la distancia de frenado y el riesgo de perder el control en pendientes y curvas."},"213":{"q":"Durante su inspección previaje carga una plataforma y nota que casi toda la maquinaria pesada quedó amontonada sobre el eje trasero, apilada en alto sobre una pila de tarimas. Antes de salir, ¿cuál es la MEJOR manera de manejar esta carga para que su camión circule con seguridad?","options":["Dejar el peso amontonado atrás sobre el eje motriz, ya que el peso adicional allí da más tracción a las llantas motrices","Empujar toda la carga hacia adelante para que todo el peso quede sobre el eje delantero de dirección y así controlar mejor el volante","Dejarla apilada en alto y centrada, porque una carga alta centrada de lado a lado ya está suficientemente equilibrada","Redistribuir la carga para que el peso quede repartido y equilibrado de adelante hacia atrás y de lado a lado, manteniendo el centro de gravedad lo más bajo posible"],"explanation":"Distribuya y equilibre el peso de la carga de adelante hacia atrás y de lado a lado, manteniendo el centro de gravedad lo más bajo posible para evitar sobrecargar un eje o un vuelco."},"214":{"q":"Durante su inspección previa al viaje, carga un tanque parcialmente lleno y apila varias tarimas sobre la plataforma ya cargada, dejando el peso más pesado en lo alto. Al planificar su ruta, ¿qué riesgo debería preocuparle MÁS sobre cómo se comportará ahora este camión?","options":["El centro de gravedad alto hace que el camión sea mucho más propenso a volcarse en una curva o ante un movimiento brusco del volante.","La carga elevada hará que el camión se detenga en una distancia mucho más corta debido a la fuerza adicional hacia abajo.","El peso elevado mejorará su economía de combustible en autopista plana porque la carga viaja más suave.","La carga pesada en lo alto hará que la dirección sea notablemente más ligera y fácil a velocidad de autopista."],"explanation":"Un centro de gravedad alto coloca más peso en lo alto, lo que hace que el camión sea mucho más propenso a volcar en una curva o durante un movimiento brusco del volante."},"215":{"q":"Durante su inspección previaje, está revisando su camión rígido sencillo (sin remolque) y encuentra una placa metálica de certificación en el marco de la puerta del conductor estampada con el número 33,000 lb junto a las letras 'GVWR'. Su despachador le pregunta qué le indica realmente esa cifra sobre este vehículo. ¿Cuál afirmación es correcta?","options":["Es el peso máximo cargado combinado permitido para este camión más cualquier remolque que arrastre como una sola unidad","Es el peso máximo cargado, fijado por el fabricante, para el cual está clasificado este vehículo individual","Es el peso total de toda la carga y los amarres que puede colocar legalmente en la caja de carga","Es el peso máximo que puede descansar sobre cualquier eje individual del camión"],"explanation":"El GVWR es el peso máximo cargado, establecido por el fabricante, para el cual está clasificado un solo vehículo."},"216":{"q":"Durante su inspección previaje encuentra una viga de acero de 12 pies sobre la plataforma plana, sujeta con dos cuerdas muy deshilachadas y desgastadas, sin ningún calzo contra el cabezal delantero. Aún le queda un largo recorrido por carretera. Antes de poder salir de forma legal y segura, ¿qué requiere esta carga?","options":["No hace falta nada más: dos cuerdas separadas ya cumplen el mínimo de dos amarres para una pieza de más de 5 pies, así que la viga está asegurada","Solo volver a atar más tensas las cuerdas existentes, ya que el cabezal delantero del remolque impedirá por sí solo que la viga se deslice hacia adelante","Suficientes amarres en buen estado y arriostramiento -- amarres sólidos con un límite de carga de trabajo adecuado más calzos/arriostramiento -- para sujetar de verdad la viga contra cualquier desplazamiento en cualquier dirección","Una sola cadena cruzada en el centro basta, porque un solo amarre es todo lo que se exige para cualquier carga en una plataforma plana"],"explanation":"La carga necesita suficientes amarres en buen estado con un límite de carga de trabajo adecuado, más calzado y refuerzo, para sujetarla contra desplazamientos en cualquier dirección."},"217":{"q":"Está cargando bobinas de acero y cajas pesadas en un remolque de plataforma equipado con un tablero protector (header board, headache rack) justo detrás de la cabina. Un compañero le pregunta por qué la empresa gasta dinero en estos tableros si ya se usan amarres adecuados. ¿Qué respuesta indica correctamente el propósito PRINCIPAL que cumple este tablero protector?","options":["Ofrece un punto de anclaje firme para que el límite de carga de trabajo total de sus amarres pueda reducirse a menos de la mitad del peso de la carga","Bloquea la turbulencia del viento y el rocío de la carretera en la parte delantera de la carga, mejorando el consumo de combustible y la visibilidad de los espejos","Le permite legalmente omitir la reinspección de la carga desde la cabina hasta que haya conducido las primeras 150 millas tras cargar","Lo protege en la cabina al impedir que la carga se desplace hacia adelante y se estrelle dentro del compartimento del conductor durante una frenada brusca"],"explanation":"Una mampara delantera (header board) evita que la carga se desplace hacia adelante hacia la cabina durante una frenada brusca, protegiendo al conductor de ser golpeado o aplastado."},"219":{"q":"Acaba de pesar su camión cargado en una báscula de carretera, y el oficial le entrega una impresión con varios números diferentes: una cifra para cada conjunto de ruedas sobre el suelo, más un único total combinado. El oficial señala la línea rotulada \"peso por eje\" y le pide que confirme que entiende qué representa ese número específico. Para responder correctamente, ¿qué debe decirle al oficial que significa la cifra del peso por eje?","options":["La cantidad de peso que cada eje individual transmite al suelo","El peso total combinado de todo el vehículo cargado y toda su carga","El peso únicamente de la carga y del equipo de sujeción que va sobre el remolque","El peso máximo que el fabricante clasifica que el vehículo puede transportar con seguridad"],"explanation":"El peso por eje es la cantidad de peso que soporta y transmite al suelo un eje individual, no el peso de todo el vehículo."},"220":{"q":"Son las 3 de la madrugada en un viaje nocturno largo y se da cuenta de que se está saliendo del carril y bosteza repetidamente. Según su plan de viaje, todavía le quedan varias horas de conducción. ¿Qué acción corregirá realmente su fatiga para que pueda continuar con seguridad?","options":["Tomar un café negro grande y subir el volumen de la radio para aguantar las horas que faltan","Salir a un área de descanso segura y dejar de conducir para dormir de verdad antes de continuar","Bajar la ventanilla lateral para que entre aire frío y comer un dulce para un golpe de azúcar","Seguir conduciendo pero aumentar la distancia de seguimiento a un segundo por cada 3 metros de longitud del vehículo para darse más tiempo de reacción"],"explanation":"Solo el sueño real cura la fatiga, así que deténgase en un área de descanso segura y duerma antes de continuar."},"221":{"q":"Es temporada de alergias y durante la inspección previa al viaje siente que le está empezando un resfriado. Antes de subir a la cabina para un viaje largo de día, toma de su bolso una pastilla sin receta para el resfriado y la alergia. ¿Cuál efecto de este medicamento es la razón MÁS importante para reconsiderar conducir en este momento?","options":["Aumentará su estado de alerta, por lo que podrá extender sus horas de conducción de forma segura","Elimina cualquier alcohol que quede en su organismo, reduciendo su BAC antes del viaje","Puede causarle somnolencia y afectar su conducción, por lo que debe revisar la etiqueta antes de conducir","Mejora su tiempo de reacción y agudiza su concentración en la carretera"],"explanation":"Muchos medicamentos de venta libre para resfriados y alergias causan somnolencia y afectan la conducción, así que lea siempre la etiqueta y no conduzca si advierte contra el uso de maquinaria."},"222":{"q":"Hace dos horas se tomó dos cervezas con la cena y se siente completamente sobrio antes de subir a su tractocamión para un viaje nocturno. Se dice a sí mismo que un café cargado y el aire frío de la noche lo mantendrán alerta. ¿Qué afirmación explica mejor el riesgo real que asume al conducir en estas condiciones?","options":["Ninguno significativo: después de dos horas y un café, el alcohol ya no tiene ningún efecto medible en un conductor de su complexión","La única preocupación real es mantenerse por debajo del límite de 0.08% de alcohol en sangre (BAC) que aplica a su CDL mientras opera el camión","El café y el aire frío acelerarán la rapidez con que su cuerpo elimina el alcohol, así que sus habilidades se restaurarán antes de llegar a la carretera","El alcohol afecta su juicio y su tiempo de reacción incluso cuando se siente bien, y solo el tiempo -- no el café ni el aire fresco -- lo elimina de su cuerpo"],"explanation":"El alcohol afecta el juicio y el tiempo de reacción aunque se sienta bien, y solo el paso del tiempo -- no el café ni el aire fresco -- lo elimina del cuerpo."},"224":{"q":"Terminó un turno largo a las 2 de la madrugada y solo durmió unas cuatro horas antes de su siguiente despacho. Su despachador lo presiona para que salga, y usted se dice a sí mismo que puede 'recuperarse' con café y una ventanilla abierta. Según lo que dice el manual sobre la prevención de la fatiga, ¿qué afirmación refleja lo que realmente necesita para estar genuinamente descansado y conducir con seguridad?","options":["La mayoría de los adultos necesitan alrededor de 7 a 8 horas de sueño para estar verdaderamente descansados, y solo el sueño real — no el café ni el aire fresco — restaura el estado de alerta.","Unas 4 a 5 horas de sueño son suficientes para un conductor experimentado, ya que el café y el aire fresco pueden compensar el resto.","Alrededor de 2 a 3 horas de sueño es aceptable siempre que tome un descanso cada 150 millas para volver a verificar su estado de alerta.","Necesita unas 12 a 14 horas completas de sueño antes de cualquier viaje comercial o legalmente no está apto para conducir."],"explanation":"La mayoría de los adultos necesitan unas 7 a 8 horas de sueño para estar realmente descansados, y solo el sueño real -- no el café ni el aire fresco -- restaura el estado de alerta."},"225":{"q":"Lleva varias horas conduciendo por un tramo largo y monótono de la autopista y se le empiezan a cerrar los párpados. Baja la ventanilla para tomar aire fresco y se bebe un café grande para mantenerse alerta. ¿Qué afirmación sobre estos métodos es correcta?","options":["La cafeína junto con el aire fresco y frío restauran permanentemente su estado de alerta durante el resto del turno","Pueden ayudar por un corto tiempo, pero la única cura real contra la somnolencia es detenerse y dormir","El aire fresco y el café son peligrosos y empeorarán su somnolencia","Reinician por completo sus horas de conducción, así que puede continuar con seguridad sin detenerse"],"explanation":"La cafeína y el aire fresco solo enmascaran la somnolencia por poco tiempo; la única cura real es detenerse y dormir."},"226":{"q":"Circula por el carril derecho de una autopista dividida cuando un conductor se acerca a gran velocidad por detrás, le sigue muy de cerca, le hace ráfagas con las luces altas y luego se cambia al carril izquierdo gesticulando con enojo mientras intenta adelantarlo. El tráfico por delante es moderado. ¿Cuál es la respuesta MEJOR y más segura?","options":["Acelerar para igualar su ritmo de modo que complete el adelantamiento rápido y deje de pisarle el parachoques","Mantener su posición en el carril y reducir solo un poco la velocidad, haciéndolo esperar para que aprenda a no seguir tan de cerca","Levantar el pie del acelerador para darle espacio, evitar el contacto visual y dejar que se adelante bastante","Cambiarse al carril izquierdo, hacia el de él, para bloquear el adelantamiento hasta que se calme y se retire"],"explanation":"Déle al conductor agresivo mucho espacio y no se enfrente -- suelte el acelerador, evite el contacto visual y déjelo adelantarse bien."},"227":{"q":"Está incorporándose a una autopista interestatal con mucho tráfico con su tractocamión cargado cuando un automóvil se le cruza y lo obliga a frenar bruscamente. Molesto, el otro conductor luego lo sigue muy de cerca, lo rebasa, frena de golpe delante de usted y hace gestos obscenos. Según el manual, ¿qué término describe MEJOR la conducta del otro conductor y cuál es la forma más segura de pensar sobre su propio comportamiento para no caer usted mismo en lo mismo?","options":["Incorporación agresiva — una parte normal del tráfico pesado a la que debe responder acelerando para mantener su posición y no dejar que los autos se aprovechen de un camión lento","Conducción defensiva — el otro conductor solo protege su espacio, así que debe imitar su conducta frenando y bloqueando para enseñar a los automóviles a respetar un vehículo grande","Conducción distraída — el conductor claramente no presta atención, así que la respuesta correcta es acelerar y rebasarlo rápido para alejarse del peligro","Furia al volante (road rage) — conducción airada y violenta; usted evita cometerla manteniéndose tranquilo, sin tomar represalias y dándole espacio al conductor enojado para que se aleje"],"explanation":"La furia al volante es conducir con ira y violencia, y la evita manteniendo la calma, no respondiendo y dándole al conductor enojado espacio para irse."},"228":{"q":"Conduce un vehículo combinado cargado en tráfico denso de la tarde por una autopista interestatal de Texas. Un compañero le dice que la mejor forma de detectar peligros a tiempo es fijar la vista en el parachoques del camión que va justo delante para no perderse nunca sus luces de freno. ¿Qué método le da realmente la mejor oportunidad de detectar peligros a tiempo para reaccionar con seguridad?","options":["Mantenga los ojos en movimiento y explore continuamente: mire lejos hacia adelante (de 12 a 15 segundos), luego cerca, y revise los espejos cada 5 a 8 segundos","Mire fijamente hacia adelante y clave la vista en el vehículo de delante para que sus luces de freno siempre estén a la vista","Confíe principalmente en los espejos, ya que en tráfico pesado la mayoría de las sorpresas vienen de vehículos que lo rebasan por detrás","Vigile el dial de la radio y los indicadores del tablero entre miradas al frente para no perder una falla mecánica que se esté desarrollando"],"explanation":"Mantenga los ojos en movimiento y explore continuamente -- mire lejos hacia adelante de 12 a 15 segundos, luego la escena cercana, y revise los espejos cada 5 a 8 segundos."},"229":{"q":"Está conduciendo por un distrito comercial del centro a 25 mph. A lo largo del bordillo derecho ve una fila de autos estacionados en paralelo. Al observar el camino adelante, nota que uno de esos autos estacionados tiene las luces de freno encendidas y sale humo del tubo de escape, y puede ver la silueta de un conductor en el asiento. ¿Por qué debería tratar ESTE auto estacionado en particular como un peligro activo y prepararse para reducir la velocidad o cambiar su posición en el carril?","options":["Las luces de freno encendidas significan que el auto está sujeto en su lugar, así que no puede moverse y solo los autos sin luces delante de él representan alguna amenaza","Un auto ocupado y en marcha puede salir de repente a su carril o una puerta puede abrirse hacia su trayectoria, por lo que debe cubrir el freno y darle espacio adicional","Un motor en marcha calienta las llantas, lo que alarga su propia distancia de frenado a unos 419 pies y lo obliga a reducir la velocidad","El humo del escape y las luces de freno encendidas son normales en un auto estacionado y no indican nada, así que no se necesita ningún cambio de velocidad ni de posición en el carril"],"explanation":"Un auto estacionado ocupado y encendido puede salir de pronto a su carril o abrir una puerta en su trayectoria, así que cubra el freno y déle espacio adicional."},"230":{"q":"Conduce su camión a 30 mph por un vecindario residencial en una tarde calurosa. Más adelante, a la derecha, ve a varios niños jugando con una pelota cerca del bordillo, y uno de ellos mira hacia la pelota, no hacia su camión. ¿Por qué el manual considera esta situación un peligro especial que exige que esté listo para reducir la velocidad o detenerse de inmediato?","options":["Porque a 30 mph su distancia total de frenado ya es de unos 419 pies, así que es imposible que pueda detenerse a tiempo ante cualquier cosa","Porque los niños siempre se quedan en la acera y solo se convierten en un peligro si un adulto les dice que crucen","Porque los niños pueden actuar de forma repentina e impredecible, como lanzarse a la calle tras la pelota sin mirar el tráfico","Porque los niños se mueven tan despacio que seguirán en la calzada mucho después de que usted espere que la despejen"],"explanation":"Los niños son un peligro especial porque pueden actuar de forma repentina e impredecible, como lanzarse a la calle tras una pelota sin fijarse en el tráfico."},"231":{"q":"Conduce un remolque cargado por una autopista dividida de cuatro carriles a unas 55 mph. Un auto pequeño se le mete de repente por la derecha y luego frena con fuerza para tomar una salida que casi se le pasa. Su distancia de seguimiento se ha reducido y siente una oleada de ira. ¿Cuál es la respuesta más segura y defensiva?","options":["Mantenerse pegado detrás del auto y hacer destellos con las luces altas para que el conductor entienda el peligro que creó","Acelerar para ponerse al lado del auto y así no quedar atrapado detrás de un conductor impredecible","Tocar los frenos ligeramente para dar un aviso rápido y luego volver a acercarse a su intervalo original de 4 segundos","Soltar el acelerador para reconstruir una distancia de seguimiento segura, mantener la calma y darle al otro conductor el espacio que necesita"],"explanation":"Cuando otro conductor comete un error, suelte el acelerador para recuperar una distancia de seguimiento segura, mantenga la calma y déle el espacio que necesita."},"233":{"q":"De noche se acerca a un cruce desconocido y nota que el semáforo de arriba parpadea en rojo en todas las direcciones. No hay ningún policía presente y el tránsito de la calle transversal es escaso. Para pasar este cruce de forma correcta y legal, ¿qué debe hacer?","options":["Detenerse por completo y luego cruzar la intersección solo cuando sea seguro, igual que lo haría ante una señal de ALTO (PARE)","Reducir la velocidad, mirar hacia ambos lados y pasar con cautela sin detenerse por completo","Tratar el semáforo apagado como un 'ceda el paso' y pasar en cuanto aparezca un hueco, manteniendo su impulso","Mantener la velocidad al cruzar, ya que un semáforo intermitente significa que está averiado y las reglas no aplican"],"explanation":"Una señal roja intermitente significa lo mismo que un letrero de ALTO: deténgase por completo y avance solo cuando sea seguro."},"234":{"q":"Se aproxima a una intersección de noche en su vehículo combinado cargado. El semáforo que estuvo en verde fijo durante el día ahora muestra un AMARILLO INTERMITENTE. No hay otro tráfico visible en la vía transversal. ¿Cuál es la forma correcta de manejar esta señal?","options":["Tratarlo exactamente como un rojo intermitente: detenerse por completo y luego avanzar cuando esté despejado","Reducir la velocidad, mantenerse alerta y cruzar la intersección con precaución tras verificar el tráfico transversal","Mantener su velocidad de carretera porque una señal amarilla le otorga la preferencia de paso sobre la vía transversal","Detenerse por completo en la línea y esperar a que la señal cambie a verde fijo antes de avanzar"],"explanation":"Una señal amarilla intermitente es una advertencia, así que reduzca la velocidad, manténgase alerta y cruce la intersección con precaución tras verificar el tráfico transversal."},"235":{"q":"Usted se aproxima a una intersección rural con su vehículo combinado cargado. No hay señales de alto, de ceda el paso ni semáforos en ninguna dirección, y la maleza le bloquea parcialmente la vista hacia la derecha. Una camioneta se acerca al cruce por su derecha aproximadamente al mismo tiempo. ¿Cuál es la acción más segura y correcta que debe tomar?","options":["Mantener su velocidad y pasar primero, ya que un vehículo comercial cargado tiene el derecho de paso legal sobre los vehículos más pequeños","Detenerse por completo en el centro de la intersección y esperar a que la camioneta pase antes de avanzar","Reducir la velocidad al aproximarse, mantener el pie listo sobre el freno y estar preparado para ceder el paso a la camioneta según sea necesario antes de continuar","Tocar la bocina y continuar a la misma velocidad para que el otro conductor sepa que usted tiene la intención de cruzar primero"],"explanation":"En una intersección sin control ningún vehículo tiene derecho de paso automático, así que reduzca la velocidad, cubra el freno y prepárese para ceder antes de avanzar."},"237":{"q":"Lleva una carga pesada y se aproxima a la cima de una pendiente de montaña larga y empinada. La bajada tiene varias millas, el pavimento está seco y usted quiere evitar que los frenos de servicio se sobrecalienten (pierdan eficacia) durante el descenso. Según el procedimiento seguro de conducción en montaña, ¿qué acción le da el control más confiable de su velocidad durante la bajada?","options":["Mantener la marcha normal de carretera y pisar levemente los frenos de servicio durante toda la bajada para conservar una velocidad constante","Esperar a que el camión empiece a acelerar a mitad de la bajada y entonces cambiar a una marcha más baja para volver a frenar el equipo","Mantener la transmisión en una marcha alta para que el motor descanse y depender principalmente de frenadas fuertes y repetidas para controlar la velocidad","Seleccionar una marcha baja ANTES de iniciar el descenso para que el freno de motor y de transmisión hagan la mayor parte del trabajo, usando los frenos de servicio solo como un complemento ligero y constante"],"explanation":"Seleccione una marcha baja antes de comenzar a bajar una pendiente larga para que el freno del motor y la marcha hagan la mayor parte del trabajo, usando los frenos de servicio solo como un complemento ligero y constante."},"238":{"q":"Usted conduce un remolque totalmente cargado por terreno montañoso cuando su GPS le advierte de una rampa de escape de emergencia más adelante. Un conductor novato que va con usted le pregunta por qué el departamento de carreteras construyó una rampa larga llena de grava en este punto exacto y no en otro lugar de la ruta. Según el uso para el que están destinadas estas rampas, ¿en qué lugar es MÁS probable que el departamento coloque una?","options":["A media bajada de una pendiente larga y empinada, donde los vehículos pesados corren mayor riesgo de perder los frenos por sobrecalentamiento (desvanecimiento de frenos)","En un tramo de carretera plano y abierto, donde los camiones suelen alcanzar sus velocidades de crucero más altas","Justo antes de un cruce concurrido del centro de la ciudad, donde el tráfico urbano obliga a frenazos frecuentes","A la entrada de un gran estacionamiento de área de descanso, donde muchos camiones pernoctan"],"explanation":"Las rampas de escape se ubican a media bajada en pendientes largas y empinadas, donde los vehículos pesados tienen mayor probabilidad de perder los frenos por sobrecalentamiento."},"239":{"q":"Es bien entrada la noche en una carretera rural de dos carriles y circula con luces bajas, que iluminan el camino unos 250 pies por delante. Se aproxima una curva cerrada y no puede ver qué hay en la carretera más allá de ella. ¿Qué acción se ajusta mejor a la regla de que nunca debe conducir más rápido de lo que alcanzan sus faros?","options":["Cambiar a luces altas durante la curva para ver más lejos al doblar, y volver a las luces bajas una vez en el tramo recto","Reducir la velocidad antes de entrar en la curva para poder detenerse dentro de la distancia que sus faros realmente iluminan","Mantener la velocidad actual pero seguir más de cerca al vehículo de adelante para que sus luces traseras lo guíen en la curva","Mantener la velocidad de carretera porque a 55 mph sus faros aún cubren los 419 pies completos de distancia de frenado que necesita"],"explanation":"Nunca conduzca más allá del alcance de sus faros: reduzca la velocidad antes de una curva para poder detenerse dentro de la distancia que realmente iluminan."},"240":{"q":"Ha terminado de caminar alrededor de su tractocamión durante la inspección previaje y todo se ve bien visualmente. Antes de salir a la carretera e incorporarse al tráfico, ¿cuál es la forma correcta de confirmar que sus frenos de servicio realmente funcionan?","options":["Omitir la prueba de funcionamiento porque la inspección a pie ya confirmó que los componentes del freno se veían bien, y volver a revisar solo después de las primeras 50 millas","Esperar a alcanzar la velocidad de la autopista y luego presionar los frenos con fuerza para sentir si el camión se jala hacia un lado","Comenzar a avanzar a baja velocidad y aplicar suavemente los frenos para asegurarse de que el vehículo se detiene y no se jala hacia un lado","Bombear el pedal del freno varias veces estando estacionado y observar que la presión de aire baje, lo cual prueba que los frenos lo detendrán"],"explanation":"Tras la inspección a pie, pruebe los frenos de servicio avanzando despacio y frenando suavemente para confirmar que el vehículo se detiene y no se desvía hacia un lado."},"241":{"q":"Usted lleva un remolque cargado por una carretera rural de dos carriles cuando una fuerte ráfaga de viento cruzado empuja de repente la parte delantera de su tractor hacia el arcén. Para mantener el mejor control del vehículo mientras corrige la dirección, ¿cuál es la posición más segura de las manos en el volante?","options":["Mantenga una mano abajo en la parte inferior del volante para hacer un giro rápido y amplio contra el viento","Conduzca con una mano y mantenga la otra lista sobre la válvula manual del freno del remolque para frenar el remolque","Deje brevemente que el volante deslice libremente entre sus manos para que se autocentre después de la ráfaga","Mantenga ambas manos firmes en el volante, en lados opuestos, para poder reaccionar con suavidad y mantener un control estable"],"explanation":"Mantenga ambas manos firmes en el volante en lados opuestos para reaccionar con suavidad y conservar el control estable ante una ráfaga repentina de viento lateral."},"242":{"q":"Está solo en una parada de camiones llena y la única forma de salir de su espacio es retroceder. Tiene una opción: puede preparar su aproximación para retroceder hacia su lado izquierdo (del conductor), o retroceder hacia su lado derecho (ciego), lo que sería una maniobra un poco más corta. ¿Cuál enfoque es el más seguro y por qué?","options":["Retroceder hacia el lado del conductor (izquierdo), porque puede asomarse por la ventanilla y ver directamente la parte trasera de su remolque todo el tiempo.","Retroceder hacia el lado ciego (derecho), porque es el camino más corto y sus espejos cubren por completo ese lado.","Cualquier lado es igual de seguro siempre que toque el claxon dos veces y encienda las luces intermitentes de emergencia antes de moverse.","Retroceder solo en línea recta y nunca angular el remolque, porque cualquier retroceso lateral está prohibido en una parada de camiones."],"explanation":"Retroceda siempre hacia el lado del conductor (izquierdo), porque puede mirar por la ventana y ver directamente la parte trasera del remolque en lugar de depender solo de los espejos."},"243":{"q":"Conduce un tractocamión cargado por una autopista seca y nivelada a 55 mph cuando decide adelantar a otro camión. Para hacerlo con seguridad, acelera hasta 65 mph. En comparación con su frenada a 55 mph, ¿cuál es el efecto MÁS importante que este cambio de velocidad tiene sobre su capacidad de detenerse en una emergencia?","options":["La distancia de frenado permanece más o menos igual porque la vía está seca y sus frenos están en buen estado","La distancia de frenado aumenta de forma pronunciada, porque la distancia de frenado crece aproximadamente con el cuadrado de su velocidad","La distancia de frenado disminuye un poco porque las ruedas que giran más rápido se agarran mejor a la vía","La distancia de frenado no se ve afectada por la velocidad y depende solo del peso de su carga"],"explanation":"La distancia de frenado total aumenta bruscamente a mayor velocidad, porque la distancia de frenado crece aproximadamente con el cuadrado de la velocidad."},"244":{"q":"Conduce un tractocamión con remolque cargado subiendo por una rampa de acceso a una autopista muy transitada. El carril de aceleración es bastante corto, el tránsito en el carril derecho circula de forma constante a unas 60 mph y se está abriendo un hueco estrecho justo delante de usted. Para completar la incorporación de la manera más segura posible, ¿qué debería hacer?","options":["Detenerse al final de la rampa y esperar a que todo el tránsito pase por completo antes de incorporarse","Meterse en el carril a una velocidad lenta y prudente y dejar que el tránsito más rápido se ajuste alrededor de su unidad","Usar el carril de aceleración para alcanzar la velocidad del flujo del tránsito y luego incorporarse en el hueco abierto","Mantener su posición en el carril y hacer valer su derecho de paso para que los vehículos del carril principal le cedan el paso"],"explanation":"El carril de aceleración sirve para igualar la velocidad del tráfico y entrar suavemente en un espacio abierto sin obligar a otros a frenar o desviarse."},"245":{"q":"Conduce un tractocamión con remolque cargado en un tráfico urbano denso con frecuentes paradas y arranques. Un peatón distraído con su teléfono baja de la acera y empieza a caminar hacia su carril a poca distancia por delante. Usted ya soltó el acelerador y mantiene el pie sobre el freno. ¿Qué uso del claxon en este momento considera apropiado el DPS?","options":["Tocar el claxon de forma leve y repetida para mantener alerta a los conductores cercanos, ya que señalizar constantemente en la congestión previene colisiones","Evitar el claxon por completo y confiar solo en el frenado, porque tocar el claxon cerca de un peatón nunca está permitido en el tráfico urbano","Dar un bocinazo largo y amistoso para que el peatón y los conductores cercanos sepan que un camión grande se acerca al cruce","Tocar el claxon para advertir al peatón del peligro inmediato, usándolo solo para alertar a los demás del riesgo"],"explanation":"La bocina es un dispositivo de advertencia que solo debe usarse para alertar de un peligro real e inmediato, como un peatón distraído que entra en su camino."},"246":{"q":"Está justo por debajo del punto de congelación y debe estacionar su tractocamión en el arcén derecho de una carretera con una pendiente pronunciada cuesta abajo. Aplica el freno de estacionamiento, pero sabe que en esta pendiente helada los frenos solos podrían no retener el vehículo si empieza a desplazarse. Para usar el bordillo como tope final en caso de que el vehículo ruede, ¿hacia qué lado debe girar las ruedas delanteras?","options":["Girar las ruedas delanteras hacia el bordillo (a la derecha), para que cualquier desplazamiento hacia adelante apoye un neumático delantero contra el bordillo","Girar las ruedas delanteras alejándolas del bordillo (a la izquierda, hacia la calzada), para que el vehículo se aparte del bordillo si rueda","Dejar las ruedas delanteras rectas, ya que el freno de estacionamiento y los calzos hacen toda la retención","La dirección no importa en una pendiente cuesta abajo mientras el freno de estacionamiento esté aplicado"],"explanation":"Al estacionar de frente cuesta abajo, gire las ruedas delanteras hacia el bordillo para que, si el vehículo rueda, una llanta lo trabe y lo detenga."},"247":{"q":"Conduce un tractocamión cargado por una carretera rural de dos carriles a 50 mph cuando baja la vista para revisar un espejo. Al volver a mirar, las ruedas del lado derecho se han salido del pavimento hacia un acotamiento de grava suelta, y el tractor jala ligeramente hacia la derecha. No hay ningún obstáculo justo adelante. ¿Cuál es la MEJOR manera de regresar a la calzada?","options":["Regrese al pavimento de inmediato con un giro rápido y firme del volante para corregir su trayectoria antes de perder más terreno","Quite el pie del acelerador, mantenga un agarre firme y regrese al pavimento de forma gradual una vez que el camión haya reducido la velocidad y esté bajo control","Aplique los frenos con fuerza de inmediato para reducir la velocidad antes de que alguna parte del equipo salga del acotamiento","Pise el acelerador para atravesar la grava suelta con potencia y subir el equipo de vuelta al pavimento más firme"],"explanation":"Si las ruedas se salen al acotamiento, suelte el acelerador sin frenar bruscamente y regrese gradualmente al pavimento después de que el camión disminuya la velocidad."},"248":{"q":"Conduce un tractocamión cargado por el carril derecho de una carretera de dos carriles a las 55 mph permitidas. Durante los últimos minutos una camioneta lo viene siguiendo tan de cerca que ya no puede ver sus faros en los espejos, y no hay ningún vehículo delante de usted. El tránsito en el carril izquierdo es ligero. ¿Cuál es la forma MÁS SEGURA de manejar a este conductor que lo sigue demasiado cerca?","options":["Toque levemente los frenos varias veces para encender las luces de freno y advertir al conductor que se aleje","Mantenga su velocidad pero reduzca la distancia de seguimiento con los vehículos de adelante para darle espacio al que lo sigue de cerca","Aumente el espacio de seguimiento hacia adelante y luego cámbiese de carril para dejar pasar al conductor que lo sigue de cerca cuando sea seguro","Acelere gradualmente bastante por encima de las 55 mph hasta que el que lo sigue de cerca deje de pegarse a su parachoques"],"explanation":"Si lo siguen muy de cerca, aumente el espacio por delante y luego hágase a un lado para dejarlo pasar con seguridad."},"249":{"q":"Conduce un tractocamión cargado por una autopista de varios carriles y necesita cambiarse al carril derecho antes de su salida, que llegará en aproximadamente una milla. El tráfico es moderado y hay un automóvil en algún punto detrás, en su punto ciego del lado derecho. Según las pautas del DPS sobre cómo comunicarse con otros conductores, ¿cuál es la ÚNICA MEJOR manera de avisar a los conductores que lo rodean lo que usted pretende hacer?","options":["Tocar el freno varias veces para que el auto de atrás vea sus luces de freno y entienda que va a frenar y a cambiarse de carril","Destellar las luces altas al tráfico del carril derecho para alertarlos de que se va a mover","Acelerar y hacer el cambio de carril rápidamente para pasar el menor tiempo posible junto al auto en su punto ciego","Encender la direccional derecha con anticipación y dejarla puesta, señalando con claridad y mucha antelación su intención de cambiar de carril"],"explanation":"Comunique sus intenciones con claridad encendiendo la señal temprano y con suficiente anticipación para que los demás conductores tengan tiempo de reaccionar."},"250":{"q":"Conduce un camión rígido de 30 pies por una autopista seca, manteniendo de forma constante 50 mph con poco tráfico. Un auto pequeño adelante cambia de carril repetidamente, así que decide establecer un espacio de seguimiento seguro. Según la regla estándar de distancia de seguimiento, ¿cuál es la MENOR distancia de seguimiento que debe mantener detrás de ese vehículo?","options":["4 segundos","3 segundos","5 segundos","6 segundos"],"explanation":"Deje 1 segundo de distancia por cada 10 pies de longitud y sume 1 segundo a más de 40 mph: un camión de 30 pies a 50 mph necesita 3 + 1 = 4 segundos."},"251":{"q":"Conduce un camión rígido de 40 pies por la ciudad y el velocímetro marca un constante 35 mph sobre pavimento seco. Hay poco tráfico, pero quiere mantener un espacio seguro detrás del auto que va adelante para poder reaccionar si frena de repente. Aplicando la regla recomendada de distancia de seguimiento según la longitud de su vehículo y su velocidad actual, ¿cuál es la MENOR distancia de seguimiento que debería mantener?","options":["5 segundos, porque un vehículo de 40 pies necesita automáticamente un segundo extra sobre la cifra base","4 segundos, porque se asigna 1 segundo por cada 10 pies de longitud y no se añade nada extra por debajo de 40 mph","3 segundos, porque tres segundos es el intervalo mínimo estándar para cualquier vehículo comercial","6 segundos, porque con esta longitud siempre debe duplicar el conteo por cada 10 pies por seguridad"],"explanation":"Deje 1 segundo de distancia por cada 10 pies de longitud y no sume nada por debajo de 40 mph, así que un camión de 40 pies a 35 mph necesita 4 segundos."},"252":{"q":"Está transportando una combinación de plataforma plana que mide 50 pies de parachoques a parachoques. El tránsito en la interestatal ha aumentado y su velocímetro se mantiene estable en 55 mph en condiciones secas y despejadas. Al colocarse detrás del vehículo que va adelante, ¿cuál es la distancia mínima de seguimiento que debe mantener, contada en segundos, para permanecer dentro del espacio seguro que recomienda el manual?","options":["5 segundos, porque se asigna 1 segundo por cada 10 pies de longitud del vehículo","7 segundos, sumando 2 segundos adicionales porque su velocidad supera ampliamente las 40 mph","6 segundos, porque 50 pies le dan 5 segundos y suma 1 más por ir a más de 40 mph","4 segundos, ya que una velocidad estable en carretera y con clima seco le permite acortar el espacio"],"explanation":"Deje 1 segundo por cada 10 pies de longitud y sume 1 segundo a más de 40 mph: un vehículo de 50 pies a 55 mph necesita 5 + 1 = 6 segundos."},"253":{"q":"Está conduciendo un tractocamión con remolque de 60 pies de largo por una autopista interestatal seca y plana en buenas condiciones de luz diurna, manteniendo una velocidad constante de 45 mph. El tráfico es ligero, pero usted quiere establecer una distancia de seguimiento segura detrás del automóvil que va adelante. ¿Cuál de las siguientes opciones indica correctamente la distancia de seguimiento mínima que debe mantener, en segundos?","options":["6 segundos, porque se deja 1 segundo por cada 10 pies de longitud del vehículo","5 segundos, ya que un vehículo combinado largo solo necesita aproximadamente medio segundo por cada 10 pies","8 segundos, agregando 2 segundos adicionales porque va a más de 40 mph","7 segundos, porque se dejan 6 segundos por la longitud más 1 segundo adicional por ir a más de 40 mph"],"explanation":"Deje 1 segundo por cada 10 pies de longitud y sume 1 segundo a más de 40 mph: un vehículo de 60 pies a 45 mph necesita 6 + 1 = 7 segundos."},"254":{"q":"Está conduciendo una combinación de 70 pies de largo por una arteria urbana plana, manteniendo una velocidad constante de 35 mph en condiciones despejadas y secas. El tráfico delante avanza con fluidez y usted quiere establecer una distancia de seguimiento segura. Usando la fórmula para calcular la distancia de seguimiento, el colchón MÍNIMO que debe mantener detrás del vehículo que va adelante es:","options":["7 segundos","8 segundos","6 segundos","9 segundos"],"explanation":"Deje 1 segundo de distancia de seguimiento por cada 10 pies de longitud del vehículo, y por debajo de 40 mph no se suma un segundo extra, así que un camión de 70 pies necesita 7 segundos."},"255":{"q":"Está transportando una carga por una autopista interestatal seca y su velocímetro marca unos 45 mph constantes. Al mirar los espejos, estima que su conjunto tractor-remolque mide unos 80 pies completos desde el parachoques delantero hasta la parte trasera del remolque. El tráfico fluye sin problemas y desea mantener una separación segura detrás del auto que va adelante. Según la regla recomendada de distancia de seguimiento, ¿cuántos segundos de espacio debe mantener?","options":["8 segundos, porque la regla es simplemente 1 segundo por cada 10 pies de longitud del vehículo","9 segundos, porque 80 pies dan 8 segundos y se añade 1 segundo por circular a más de 40 mph","7 segundos, ya que a esta velocidad puede restar un segundo al conteo basado en la longitud","10 segundos, porque debe redondear la longitud hacia arriba y añadir 2 segundos completos de margen a velocidad de autopista"],"explanation":"Deje 1 segundo por cada 10 pies de longitud para una base de 8 segundos, luego sume 1 segundo por velocidades superiores a 40 mph, dando un total de 9 segundos."},"256":{"q":"Conduce una combinación de 90 pies de largo por una autopista seca, a una velocidad constante de 50 mph con poco tráfico. Un automóvil se incorpora delante de usted y necesita restablecer un espacio seguro. Según la regla de la distancia de seguimiento, ¿cuál es la MENOR cantidad de espacio que debe mantener detrás de ese vehículo?","options":["9 segundos, porque la regla es simplemente 1 segundo por cada 10 pies de longitud del vehículo","8 segundos, ya que puede reducir tiempo una vez que avanza de forma constante sobre pavimento seco","10 segundos de distancia de seguimiento","11 segundos, sumando 2 segundos extra porque va muy por encima de las 40 mph"],"explanation":"Deje 1 segundo por cada 10 pies de longitud para una base de 9 segundos, luego sume 1 segundo por velocidades superiores a 40 mph, dando un total de 10 segundos."},"257":{"q":"Conduce una combinación de plataforma plana que mide 100 pies desde el parachoques delantero hasta el final del remolque. El tráfico se despeja y acelera a 60 mph en una autopista seca. Al mirar por el espejo, desea establecer una distancia de seguimiento segura detrás del auto que va siguiendo. Según la regla de distancia de seguimiento, ¿cuál es el número MÍNIMO de segundos de espacio que debe mantener?","options":["10 segundos, porque asigna 1 segundo por cada 10 pies de longitud del vehículo y 100 dividido entre 10 es igual a 10","12 segundos, asignando 1 segundo por cada 10 pies más 2 segundos adicionales por la mayor velocidad","9 segundos, ya que 60 mph es lo suficientemente rápido como para restar un segundo al conteo basado en la longitud","11 segundos, porque 100 pies dan 10 segundos y se agrega 1 segundo más por circular a más de 40 mph"],"explanation":"Deje 1 segundo por cada 10 pies de longitud para una base de 10 segundos, luego sume 1 segundo por velocidades superiores a 40 mph, dando un total de 11 segundos."},"258":{"q":"Conduce un camión rígido de 40 pies por una autopista interestatal seca, manteniendo una velocidad constante de 55 mph en buenas condiciones diurnas. El tráfico por delante circula con fluidez. Aplicando la regla del manual sobre la distancia de seguimiento segura, ¿cuál es el espacio MÍNIMO que debe mantener detrás del vehículo que va delante de usted?","options":["5 segundos","4 segundos","6 segundos","3 segundos"],"explanation":"Deje 1 segundo por cada 10 pies de longitud para una base de 4 segundos, luego sume 1 segundo por velocidades superiores a 40 mph, dando un total de 5 segundos."},"259":{"q":"Está transportando una carga en una plataforma plana (flatbed) y, durante la inspección previa al viaje, mide su tractocamión de 50 pies de parachoques a parachoques. En una carretera rural seca, con tráfico ligero, su velocímetro se mantiene constante a 50 mph. Aplicando la regla para calcular una distancia de seguimiento segura detrás del vehículo de adelante, ¿cuántos segundos de espacio debe mantener a esta velocidad y longitud?","options":["5 segundos, porque se cuenta 1 segundo por cada 10 pies de longitud del vehículo","6 segundos, porque se cuenta 1 segundo por cada 10 pies de longitud y se añade 1 segundo más por ir a más de 40 mph","7 segundos, porque se cuenta 1 segundo por cada 10 pies de longitud y se añaden 2 segundos más por la velocidad de autopista","4 segundos, porque la distancia de seguimiento se basa solo en la velocidad, no en la longitud del vehículo"],"explanation":"Deje 1 segundo por cada 10 pies de longitud para una base de 5 segundos, luego sume 1 segundo por velocidades superiores a 40 mph, dando un total de 6 segundos."},"260":{"q":"Conduce un tractocamión de 70 pies (unos 21 m) por una autopista interestatal seca y nivelada, manteniendo una velocidad constante de 45 mph con tráfico ligero. Al mirar los espejos, decide fijar su distancia de seguimiento contando los segundos que tarda en llegar a un objeto fijo después de que el vehículo de adelante lo pasa. Según la longitud de su vehículo y su velocidad actual, ¿cuál es la distancia de seguimiento MÍNIMA que debe mantener?","options":["7 segundos, porque la regla es simplemente 1 segundo por cada 10 pies de longitud del vehículo","6 segundos, ya que unos 6 segundos de distancia total de frenado bastan a velocidad de autopista","8 segundos, porque necesita 1 segundo por cada 10 pies de longitud y 1 segundo adicional por ir a más de 40 mph","9 segundos, sumando un segundo por el pavimento seco a los segundos por longitud y velocidad"],"explanation":"Deje 1 segundo por cada 10 pies de longitud para una base de 7 segundos, luego sume 1 segundo por velocidades superiores a 40 mph, dando un total de 8 segundos."},"261":{"q":"Conduce una combinación de plataforma plana que mide 80 pies desde el parachoques delantero hasta la parte trasera del remolque. El tránsito fluye sin problemas en una carretera plana de dos carriles y su velocímetro se mantiene fijo en 35 mph. Para conservar una distancia de seguimiento segura detrás del camión que va adelante, ¿qué espacio debe mantener?","options":["9 segundos, porque toma 8 segundos por la longitud y suma 1 segundo más por la velocidad de carretera","7 segundos, ya que a velocidades más bajas el margen puede reducirse en un segundo","10 segundos, el margen máximo que cualquier combinación grande llegaría a necesitar","8 segundos, porque cada 10 pies de longitud necesitan 1 segundo y no se añade un segundo extra por debajo de 40 mph"],"explanation":"Deje 1 segundo por cada 10 pies de longitud para 8 segundos, y a 35 mph (por debajo de 40 mph) no se suma un segundo extra, así que el margen es de 8 segundos."},"262":{"q":"Durante su inspección previaje, está asegurando un solo tubo de acero de 15 pies de largo en una plataforma plana. El tubo está holgadamente dentro del límite de carga de trabajo de sus correas. Para cumplir con el mínimo federal de sujeción de carga, ¿cuál es la MENOR cantidad de amarres que puede usar legalmente en esta sola pieza?","options":["2 amarres","1 amarre","3 amarres","4 amarres"],"explanation":"La carga necesita al menos 1 amarre por cada 10 pies de longitud y al menos 2 para cualquier artículo de más de 5 pies, así que una tubería de 15 pies requiere 2 amarres."},"263":{"q":"Durante su inspección previa al viaje encuentra una sola viga de acero en I de 25 pies cargada plana sobre su remolque y sujeta con solo 2 amarres de cadena. La viga está muy por debajo de sus límites de peso y la plataforma está en buen estado. Antes de poder circular legalmente, ¿cuál es el número MÍNIMO de amarres que debe tener esta pieza?","options":["2 amarres, porque cualquier pieza de más de 5 pies requiere legalmente al menos 2 dispositivos de sujeción","3 amarres, porque se necesita al menos un amarre por cada 10 pies de carga y 25 pies se redondea hacia arriba a 3","4 amarres, porque el acero largo y pesado debe asegurarse cada 5 pies de su longitud","1 amarre, porque la viga es una sola pieza rígida que descansa firmemente sobre la plataforma"],"explanation":"La carga necesita al menos 1 amarre por cada 10 pies de longitud, redondeando hacia arriba, así que una viga de 25 pies requiere 3 amarres."},"264":{"q":"Durante su inspección previaje, está asegurando una sola viga de acero que mide 35 pies de largo apoyada sobre la plataforma plana. Sabiendo la regla sobre cuántas amarras requiere la carga de esta longitud, ¿cuál es el número MÍNIMO de amarras que puede usar legalmente para asegurar esta viga?","options":["3 amarras, ya que 35 pies divididos entre 10 dan tres secciones completas de 10 pies","2 amarras, porque cualquier pieza individual solo necesita una en cada extremo","4 amarras, porque se necesita al menos una por cada 10 pies y 35 pies se redondea hacia arriba","5 amarras, ya que una viga de esta longitud requiere una adicional por margen de seguridad"],"explanation":"La sujeción de carga exige al menos un amarre por cada 10 pies de longitud, redondeando hacia arriba cualquier tramo parcial, así que 35 pies requieren 4."},"265":{"q":"Durante su inspección previaje, está asegurando una sola viga de acero de 45 pies en una plataforma plana (flatbed). La viga pesa 9,000 lb y cada una de sus cadenas tiene un límite de carga de trabajo muy superior a lo que requiere la carga, así que la capacidad de peso no es su preocupación aquí. Basándose ÚNICAMENTE en la regla del número mínimo de amarres, ¿cuál es la MENOR cantidad de amarres que debe usar para transportar legalmente esta viga?","options":["4 amarres, porque cuenta uno por cada 10 pies completos de longitud e ignora los 5 pies sobrantes","3 amarres, ya que el límite de carga de trabajo es de por sí lo bastante alto para sujetar la carga","6 amarres, agregando uno extra más allá de la regla de longitud como margen de seguridad","5 amarres, porque necesita al menos uno por cada 10 pies y 45 pies se redondean hacia arriba a 5"],"explanation":"Se requiere al menos un amarre por cada 10 pies de carga, redondeando hacia arriba cualquier resto, así que una carga de 45 pies necesita 5."},"266":{"q":"Durante su inspección previa al viaje, está asegurando una sola viga de acero de 55 pies sobre una plataforma plana (flatbed). Desea cumplir la regla mínima federal/de Texas de sujeción según el número de amarres basado en la longitud de la carga. Considerando solo el requisito por longitud, ¿cuál es el MENOR número de amarres que puede usar legalmente para esta viga?","options":["6 amarres, porque necesita al menos uno por cada 10 pies de carga y 55 pies se redondea hacia arriba a 6","5 amarres, porque 55 dividido entre 10 es igual a 5 y se descarta el resto","7 amarres, porque necesita uno por cada 10 pies más uno adicional para cualquier pieza de más de 5 pies","4 amarres, porque dos amarres en cada extremo bastan para inmovilizar cualquier viga individual"],"explanation":"Se requiere un amarre por cada 10 pies de carga, redondeando hacia arriba cualquier tramo parcial, así que una carga de 55 pies necesita 6."},"267":{"q":"Durante su inspección previaje, usted está asegurando una sola viga de acero sobre su plataforma plana. Mide unos 8 pies de largo y pesa aproximadamente 3,000 libras. Usted razona que, como mide bastante menos de 10 pies, la regla de \"una amarra por cada 10 pies\" significa que basta con una sola amarra. ¿Qué afirmación describe correctamente el número MÍNIMO de amarras que debe usar?","options":["1 amarra, porque la viga mide menos de 10 pies y rige la regla de una por cada 10 pies","2 amarras, porque cualquier pieza de más de 5 pies requiere al menos 2, sin importar el conteo por cada 10 pies","1 amarra, porque la viga pesa menos del umbral de 1,100 libras para una sola amarra","No se requiere ninguna amarra para una sola pieza tan corta"],"explanation":"Cualquier artículo de carga de más de 5 pies debe tener al menos 2 amarres, sin importar el conteo por cada 10 pies."},"268":{"q":"Normalmente recorre un tramo de carretera rural a 25 mph y, por experiencia, sabe que su equipo cargado necesita allí unos 30 pies de distancia de frenado una vez que los frenos hacen efecto. Esta noche recorre la misma carretera, con la misma carga y el mismo pavimento seco, pero a 50 mph. En comparación con su distancia de frenado habitual a 25 mph, su distancia de frenado a 50 mph será aproximadamente:","options":["Aproximadamente igual, porque la carga y el pavimento no han cambiado","Aproximadamente el doble de larga, porque ha duplicado la velocidad","Aproximadamente cuatro veces más larga, porque la distancia de frenado crece con el cuadrado de la velocidad","Aproximadamente la mitad de larga, porque las ruedas giran más rápido y disipan la energía antes"],"explanation":"La distancia de frenado crece con el cuadrado de la velocidad, así que duplicar la velocidad hace que la distancia de frenado sea unas cuatro veces mayor."},"269":{"q":"Circula por una autopista seca y nivelada a 55 mph con buen tiempo cuando, muy adelante en su carril, aparece de repente un auto averiado. Un pasajero le pregunta cuánta carretera necesitará realmente para detenerse por completo desde el instante en que avista el peligro. Contando la distancia de percepción, la de reacción Y la de frenado, ¿qué estimación de su distancia total de frenado es la más cercana a la correcta?","options":["Unos 60 pies — aproximadamente lo que su camión recorre solo durante el tiempo de reacción","Unos 100 pies — un poco más que el largo de un camión","Unos 250 pies — la distancia que iluminan sus luces bajas de noche","Unos 419 pies — casi el largo de un campo de fútbol americano más ambas zonas de anotación (unos 6 segundos de recorrido)"],"explanation":"La distancia total de frenado es la de percepción más la de reacción más la de frenado, que a 55 mph suma unos 419 pies (aproximadamente 6 segundos)."},"270":{"q":"Normalmente circula a 30 mph en su ruta de reparto urbano, pero hoy un desvío lo lleva a una autopista de 60 mph con el mismo pavimento seco y el mismo remolque cargado. Un conductor novato que va con usted supone que, como solo duplicó la velocidad, necesitará aproximadamente el doble de distancia para detenerse. ¿Cómo cambia en realidad su distancia de frenado al DUPLICAR aproximadamente su velocidad?","options":["La distancia de frenado aumenta aproximadamente cuatro veces, porque crece con el cuadrado de la velocidad","La distancia de frenado solo se duplica aproximadamente, aumentando en proporción directa a la velocidad","La distancia de frenado se mantiene casi igual porque el remolque cargado añade tracción","La distancia de frenado aumenta solo un poco, ya que lo que realmente crece con la velocidad es la distancia de reacción"],"explanation":"La distancia de frenado aumenta con el cuadrado de la velocidad, así que duplicar la velocidad la hace unas cuatro veces mayor, no solo el doble."},"271":{"q":"Conduce a velocidad de autopista cuando un venado se cruza de repente en la carretera bastante adelante. La primera fase de la detención es la PERCEPCIÓN: el tiempo desde el instante en que el venado entra en su campo de visión hasta que su cerebro realmente lo reconoce como un peligro. Esta fase ocurre antes incluso de que empiece a mover el pie hacia el freno. Para un conductor atento a unas 55 mph, ¿cuánto TIEMPO toma por sí sola esta fase de percepción?","options":["Unos 3/4 de segundo, que en realidad es el tiempo de reacción para llevar el pie al pedal después de que el peligro ya ha sido reconocido","Unos 1.75 segundos, el tiempo que el manual asigna para percibir y reconocer un peligro a velocidad de autopista antes de que comience cualquier reacción","Unos 6 segundos, que en realidad es el tiempo total para detenerse por completo a 55 mph, no solo la fase de percepción","Una décima de segundo, ya que un conductor profesional atento percibe los peligros casi de inmediato"],"explanation":"La percepción es el tiempo que tu cerebro necesita para ver y reconocer un peligro, unos 1,75 segundos a velocidad de autopista antes de cualquier reacción."},"272":{"q":"Circula a 55 mph por una autopista seca cuando, muy adelante, aparece de repente un auto averiado en su carril. Para cuando se detiene por completo, su tracto-camión ha recorrido aproximadamente el largo de un campo de fútbol americano más ambas zonas de anotación (unos 419 pies). Los instructores dividen esta distancia total de frenado en tres partes: la distancia recorrida mientras usted VE el peligro (distancia de percepción), la distancia recorrida mientras mueve el pie hacia el pedal (distancia de reacción) y una parte más. ¿Qué parte completa la distancia total de frenado?","options":["Distancia de dirección — la distancia recorrida mientras gira el volante para esquivar el obstáculo","Distancia de señalización — la distancia recorrida mientras activa las luces de emergencia para advertir al tráfico","Distancia de frenado — la distancia que recorre el camión después de que los frenos actúan hasta detenerse por completo","Distancia de estacionamiento — el espacio adicional que deja junto al borde una vez que se ha orillado con seguridad"],"explanation":"El tercer componente de la distancia total de frenado es la distancia de frenado, lo que recorre el camión tras aplicar los frenos hasta detenerse por completo."},"273":{"q":"Conduce su camión rígido de 20 pies de largo por una autopista plana con buen tiempo, manteniendo una velocidad constante de 35 mph en tráfico ligero. Quiere dejar la distancia de seguimiento mínima correcta detrás del auto que va adelante. Usando la regla de 1 segundo por cada 10 pies de longitud del vehículo, ¿cuántos segundos de distancia de seguimiento debe mantener a esta velocidad?","options":["4 segundos, porque siempre debe añadir un segundo entero adicional por cada 10 pies de longitud del camión","3 segundos, añadiendo 1 segundo a la cifra basada en la longitud porque el tráfico de la autopista es impredecible","1 segundo, ya que a 35 mph va por debajo de 40 mph y la regla del segundo adicional no aplica","2 segundos, porque 20 pies de longitud dan 2 segundos y no se añade ningún segundo por debajo de 40 mph"],"explanation":"Por debajo de 40 mph se necesita 1 segundo de distancia de seguimiento por cada 10 pies de longitud del vehículo, así que uno de 20 pies necesita 2 segundos."},"274":{"q":"Usted conduce un camión recto de 20 pies (unos 6 metros) por una autopista interestatal seca a una velocidad constante de 55 mph con clima despejado. Hay poco tráfico y desea mantener una distancia de seguimiento segura detrás del automóvil que va adelante. Usando la regla para calcular la distancia de seguimiento según el largo del vehículo y la velocidad, ¿cuántos segundos de espacio debe mantener?","options":["3 segundos","2 segundos","4 segundos","6 segundos"],"explanation":"Deje 1 segundo de distancia de seguimiento por cada 10 pies de longitud del vehículo y sume 1 segundo más a más de 40 mph."},"275":{"q":"Conduce un camión rígido que mide 30 pies de parachoques a parachoques. El tránsito avanza de forma constante por la ciudad y su velocímetro marca 35 mph. Para mantener un margen seguro al frente, ¿cuál es la distancia de seguimiento mínima que debe mantener detrás del vehículo que va adelante?","options":["2 segundos, porque el camino es plano y va muy por debajo de la velocidad de carretera","3 segundos, porque a esta velocidad cuenta 1 segundo por cada 10 pies de longitud de su vehículo","4 segundos, sumando 1 segundo adicional a la distancia basada en la longitud por ir en el tránsito","5 segundos, igualando el margen que se usa a velocidades de carretera más altas para un vehículo de este tamaño"],"explanation":"Deje 1 segundo de distancia de seguimiento por cada 10 pies de longitud del vehículo, sin sumar segundo extra a menos de 40 mph."},"276":{"q":"Conduce un camión recto de una sola unidad de 30 pies por una autopista seca, manteniendo una velocidad constante de 55 mph con tráfico ligero. Para mantener un margen seguro detrás del auto que va adelante, elige un objeto fijo al borde de la carretera y cuenta los segundos hasta que su parachoques delantero lo alcanza. ¿Cuántos segundos de distancia de seguimiento debe mantener en esta situación?","options":["3 segundos, porque la regla es 1 segundo por cada 10 pies de longitud del vehículo","5 segundos, agregando 1 segundo extra más allá de lo que exige la regla de longitud y velocidad","4 segundos, porque 30 pies dan 3 segundos y usted suma 1 segundo más por ir a más de 40 mph","2 segundos, el mismo intervalo mínimo que mantiene un automóvil de pasajeros a velocidad de autopista"],"explanation":"Deje 1 segundo de distancia de seguimiento por cada 10 pies de longitud del vehículo y sume 1 segundo más a más de 40 mph."},"277":{"q":"Usted transporta una carga recta de 40 pies por una autopista seca y plana, y con tráfico ligero su velocímetro se estabiliza en 50 mph. Para dejarse un margen seguro detrás del vehículo de adelante, ¿cuántos segundos de distancia de seguimiento debe mantener en esta situación?","options":["4 segundos, porque se deja 1 segundo por cada 10 pies de longitud de su vehículo","6 segundos, ya que eso coincide con la distancia total de frenado que un camión necesita a velocidad de autopista","3 segundos, siguiendo la regla estándar de los 3 segundos que aplica a todos los vehículos","5 segundos, porque se añade 1 segundo adicional al conteo basado en la longitud cuando va a más de 40 mph"],"explanation":"Deje 1 segundo de distancia de seguimiento por cada 10 pies de longitud del vehículo y sume 1 segundo más a más de 40 mph."},"278":{"q":"Conduce una combinación de 60 pies de largo por una autopista interestatal seca, manteniendo una velocidad constante de 50 mph con tráfico ligero. Un automóvil delante marca su ritmo y usted quiere dejar un espacio seguro. Usando la regla básica de distancia de seguimiento del manual, ¿cuántos segundos de espacio debe mantener detrás de ese vehículo?","options":["7 segundos, porque 60 pies de longitud dan 6 segundos, más 1 segundo adicional por circular a más de 40 mph","6 segundos, porque se permite 1 segundo por cada 10 pies de longitud del vehículo","8 segundos, porque se suman 2 segundos por la velocidad de autopista además de los 6 segundos por la longitud","5 segundos, porque un vehículo de 60 pies a velocidad moderada necesita aproximadamente medio segundo por cada 5 pies"],"explanation":"Deje 1 segundo de distancia de seguimiento por cada 10 pies de longitud del vehículo y sume 1 segundo más a más de 40 mph."},"279":{"q":"Conduce un tractocamión de 70 pies por una autopista interestatal seca, a una velocidad constante de 55 mph en condiciones diurnas despejadas. El conductor que va delante frena levemente y se da cuenta de que se ha acercado más de lo debido. Aplicando la regla práctica de la distancia de seguimiento, ¿cuál es el intervalo MÍNIMO que debe mantener detrás de ese vehículo?","options":["7 segundos, porque se asigna 1 segundo por cada 10 pies de longitud de su vehículo","8 segundos, porque se asigna 1 segundo por cada 10 pies de longitud y se añade 1 segundo más por circular a más de 40 mph","6 segundos, porque la distancia total de frenado a 55 mph es de unos 6 segundos","9 segundos, asignando 1 segundo por cada 10 pies más 2 segundos adicionales por la velocidad en autopista"],"explanation":"Deje 1 segundo de distancia de seguimiento por cada 10 pies de longitud del vehículo y sume 1 segundo más a más de 40 mph."},"280":{"q":"Está transportando una carga por un corredor de obras con límite de 35 mph en un vehículo combinado que mide 90 pies de parachoques a parachoques. El tránsito es constante, el pavimento está seco y desea fijar una distancia de seguimiento segura usando la regla de los segundos según la longitud del vehículo. ¿Cuántos segundos de distancia de seguimiento debe mantener detrás del vehículo que va adelante en esta situación?","options":["10 segundos, porque cualquier vehículo combinado de esta longitud necesita un segundo adicional sin importar la velocidad","8 segundos, porque se redondea hacia abajo la longitud de 90 pies al intervalo entero más cercano de la regla","9 segundos, porque se asigna 1 segundo por cada 10 pies de longitud del vehículo y su velocidad es menor a 40 mph","11 segundos, porque se asigna 1 segundo por cada 10 pies y se añade un segundo adicional completo por la zona de obras"],"explanation":"Deje 1 segundo de distancia de seguimiento por cada 10 pies de longitud del vehículo, sin sumar segundo extra a menos de 40 mph."},"281":{"q":"Está transportando una combinación de 90 pies de longitud en una autopista interestatal plana y su velocímetro marca de forma constante 60 mph con tiempo despejado y seco. El tránsito por delante circula sin obstáculos. Usando la regla del manual para juzgar una distancia de seguimiento segura, ¿cuántos segundos de espacio debe mantener entre el frente de su unidad y el vehículo de adelante?","options":["8 segundos, porque a 60 mph se reduce la cifra base para tener en cuenta la mayor velocidad en autopista","11 segundos, sumando 2 segundos adicionales porque va muy por encima de las 40 mph","9 segundos, ya que simplemente se cuenta 1 segundo por cada 10 pies de longitud del vehículo","10 segundos, contando 1 segundo por cada 10 pies de longitud y sumando 1 segundo más por la velocidad superior a 40 mph"],"explanation":"Deje 1 segundo de distancia de seguimiento por cada 10 pies de longitud del vehículo y sume 1 segundo más a más de 40 mph."},"282":{"q":"Está conduciendo una combinación de 100 pies de largo por una carretera rural plana y seca, y su velocímetro se mantiene firme en 35 mph. Un automóvil delante de usted circula a la misma velocidad y quiere establecer una distancia de seguimiento segura. Contando los segundos que tarda su parachoques delantero en alcanzar un punto fijo que el vehículo de adelante acaba de pasar, ¿cuál es la distancia de seguimiento MÍNIMA que debe mantener?","options":["10 segundos","11 segundos","9 segundos","7 segundos"],"explanation":"Deje 1 segundo de distancia de seguimiento por cada 10 pies de longitud del vehículo, sin sumar segundo extra a menos de 40 mph."},"283":{"q":"Conduce un tractocamión con una plataforma plana y, de un parachoques a otro, mide justo 100 pies (unos 30 metros). El tráfico en la carretera rural ya se estabilizó y su velocímetro se mantiene firme en 45 mph sobre pavimento seco y despejado. Contando los segundos mientras el vehículo de adelante pasa un punto fijo, ¿cuántos segundos de distancia de seguimiento debería mantener detrás de ese vehículo?","options":["10 segundos, ya que asigna 1 segundo por cada 10 pies de longitud de su vehículo","11 segundos, porque 100 pies exigen 10 segundos y usted suma 1 segundo más por ir a más de 40 mph","12 segundos, asignando 1 segundo por cada 10 pies más 2 segundos extra por la velocidad en carretera","9 segundos, redondeando hacia abajo el equipo de 100 pies por el pavimento seco"],"explanation":"Deje 1 segundo de distancia de seguimiento por cada 10 pies de longitud del vehículo y sume 1 segundo más a más de 40 mph."},"284":{"q":"Conduce una combinación de 60 pies de longitud por una autopista seca, manteniendo una velocidad constante de 60 mph con tráfico ligero. Recordando la regla de distancia de seguimiento del manual, ¿cuál es el espacio MÍNIMO que debe mantener respecto al vehículo que va delante?","options":["6 segundos, porque un vehículo de 60 pies necesita 1 segundo por cada 10 pies de longitud","5 segundos, ya que el tráfico es ligero y la carretera está seca","7 segundos: 1 segundo por cada 10 pies de longitud más 1 segundo adicional por ir a más de 40 mph","8 segundos, sumando 2 segundos a la cifra base porque se trata de velocidad de autopista"],"explanation":"Deje 1 segundo de distancia de seguimiento por cada 10 pies de longitud del vehículo y sume 1 segundo más cuando circule a más de 40 mph."},"285":{"q":"Conduce un tractocamión con remolque cargado a velocidad de autopista en una carretera rural seca de dos carriles al anochecer cuando un venado grande sale de la arboleda y se queda paralizado en su carril a unos 150 pies por delante. El carril izquierdo parece despejado y hay un acotamiento pavimentado a su derecha. ¿Cuál acción suele ser la MÁS segura?","options":["Cambiarse rápidamente al carril izquierdo para rodear al animal, ya que parece despejado","Virar hacia el acotamiento derecho y acelerar para pasar al venado antes de que se mueva","Soltar las manos del volante y dejar que el camión siga recto por sí solo","Aplicar un frenado firme y controlado y permanecer en su carril"],"explanation":"Frene con firmeza y manténgase en su carril, ya que un viraje brusco puede volcar o doblar en navaja un vehículo con centro de gravedad alto."},"286":{"q":"Conduce una combinación cargada por una autopista dividida cuando el carril se estrecha y entra en una zona de obras. Las señales naranjas reducen el límite indicado muy por debajo de la velocidad de la autopista, hay un señalero (abanderado) más adelante y los trabajadores se mueven cerca del carril abierto. El tráfico a su alrededor sigue circulando casi a velocidad de autopista. ¿Cuál es la respuesta más segura y legalmente correcta?","options":["Reduzca su velocidad al límite indicado de la zona de obras y manténgase atento a los trabajadores, los equipos y las señales del señalero","Mantenga su intervalo de distancia de seguimiento y la velocidad de autopista, ya que usted ya deja 7 segundos de espacio por delante","Siga el ritmo del tráfico que lo rodea para no crear una peligrosa diferencia de velocidad entre los vehículos","Cámbiese al carril más rápido y rebase a los vehículos que frenan para salir de la zona de obras lo antes posible"],"explanation":"Reduzca a la velocidad indicada en la zona de obras y manténgase atento a los trabajadores, el equipo y el señalero que controla el tránsito."},"287":{"q":"Está saliendo de una curva en una carretera húmeda de dos carriles y pisa el acelerador para recuperar la velocidad de marcha. El tacómetro sube de golpe y siente que la parte trasera del tractor empieza a salirse porque las ruedas motrices pierden tracción y patinan. ¿Qué acción le da la MEJOR oportunidad de recuperar el control?","options":["Frenar con firmeza para reducir la velocidad de las ruedas motrices que patinan y cerrar su trazada en la curva","Soltar el acelerador para que las ruedas motrices reduzcan su velocidad y dirigir el camión hacia donde quiere ir","Girar bruscamente el volante hacia el lado contrario de la curva para contrarrestar el coletazo lo más rápido posible","Mantener una presión constante en el acelerador para que las ruedas motrices lo saquen recto del derrape"],"explanation":"Para recuperarse de un derrape de las ruedas motrices, suelte el acelerador para que recuperen tracción y dirija hacia donde quiere ir."},"288":{"q":"Está transportando una carga parcial con un centro de gravedad alto en una carretera rural de dos carriles. Al salir de una colina, se da cuenta de que la curva que se aproxima es más cerrada de lo que advertía la señal, y ha entrado en ella con más velocidad de la que es cómoda. ¿Qué acción le da la MEJOR oportunidad de permanecer en su carril sin un derrape o un vuelco?","options":["Frenar fuerte y con firmeza a través del vértice de la curva para reducir el exceso de velocidad rápidamente","Poner una marcha más alta y acelerar para empujar el camión a través del giro antes de que pueda volcar","Reconocer que debió reducir la velocidad ANTES de la curva, así que soltar el acelerador y usar solo un frenado ligero y gradual manteniendo el camión estable durante el giro","Pisar el embrague y avanzar por inercia en punto muerto a través de la curva para que las ruedas motrices no pierdan tracción"],"explanation":"Dentro de una curva, suelte el acelerador y frene solo de forma ligera y gradual, ya que frenar fuerte desplaza el peso y puede perder la tracción."},"290":{"q":"Conduce un tractocamión cargado a 60 mph por una autopista interestatal seca, pegado detrás de un camión de caja para que los autos no se metan delante de usted. Las luces de freno del camión se encienden y frena en seco por un atasco; usted frena de golpe y se detiene con apenas unos centímetros de margen. Al analizar después el casi accidente, ¿qué acción le habría dado el tiempo y el espacio que realmente necesitaba para detenerse con seguridad?","options":["Seguir a 4 segundos, porque esa es la distancia total de frenado a 55 mph (unos 419 pies)","Quedarse exactamente donde estaba pero frenar medio segundo antes en el instante en que se encendieron las luces de freno","Cerrar aún más el espacio para que ningún auto se interpusiera y lo obligara a frenar","Seguir lo bastante atrás para mantener una distancia de seguimiento segura, dándole tiempo para percibir, reaccionar y frenar antes de alcanzar al camión"],"explanation":"Mantenga una distancia de seguimiento segura, pues la distancia total de frenado es percepción más reacción más frenado, sumando cientos de pies."},"291":{"q":"Ya hace rato que anocheció y ha doblado hacia un camino rural angosto de dos carriles por el que nunca ha conducido antes. No hay alumbrado, los acotamientos no están marcados y apenas puede ver más allá de sus faros. Para recorrer este tramo con la mayor seguridad, ¿qué debe hacer?","options":["Reduzca la velocidad para poder detenerse siempre dentro de la distancia iluminada por sus faros, y use las luces altas donde no haya tránsito en sentido contrario","Mantenga la velocidad de los pocos autos que van adelante para no circular más lento que el flujo del tránsito","Encienda las luces altas y déjelas encendidas de forma continua para ver lo más lejos posible en el camino","Mantenga su velocidad de crucero diurna habitual, ya que reducir la velocidad de noche lo convierte en un peligro para el tránsito más rápido"],"explanation":"Nunca conduzca más rápido de lo que alcanzan sus faros: mantenga una velocidad que le permita detenerse dentro de la zona iluminada y use luces altas cuando no haya tránsito en sentido contrario."},"293":{"q":"Conduce su tractocamión con remolque por un distrito comercial del centro a unas 25 mph con tráfico ligero. Al aproximarse a una zona no señalizada a mitad de cuadra, un peatón que estaba parado en la acera baja repentinamente a la calle a varios largos de auto por delante de usted, mirando su teléfono y no hacia usted. Su carril derecho está bloqueado por autos estacionados y a su izquierda hay tráfico en sentido contrario. ¿Cuál es la respuesta más segura y legalmente correcta?","options":["Toque la bocina con firmeza y mantenga su velocidad, ya que tiene el derecho de paso en su carril y el peatón probablemente retrocederá","Suelte el acelerador, mantenga el pie sobre el freno, reduzca la velocidad y esté listo para detenerse ante el peatón","Gire ligeramente hacia el carril contrario para rodear al peatón y luego regrese a su carril una vez libre","Acelere brevemente para despejar la zona antes de que el peatón entre por completo en su trayectoria"],"explanation":"Ante un peatón que ha bajado a la calzada, suelte el acelerador, cubra el freno, reduzca la velocidad y prepárese para detenerse."},"294":{"q":"Conduce un vehículo combinado cargado por una autopista interestatal de cuatro carriles y necesita cambiarse un carril a la izquierda para prepararse para una salida que está a unas dos millas. Pone la señal, revisa los espejos del lado izquierdo y comienza a desplazarse, pero al hacerlo se da cuenta de que un automóvil circula junto a su tractor en la zona que sus espejos no cubren por completo. ¿Cuál es la respuesta mejor y más segura?","options":["Mantenga su desplazamiento hacia el carril mientras toca los frenos, ya que sus luces de freno alertarán al automóvil para que se quede atrás y le abra el hueco","Acelere con firmeza para adelantar su tractor al automóvil de modo que quede detrás de su remolque, y complete el cambio de carril antes de la siguiente revisión de espejos","Cancele el cambio de carril, mantenga su posición, espere un hueco despejado y vuelva a revisar el espejo y esa zona del punto ciego antes de intentar cambiarse de nuevo","Continúe el cambio de carril porque ya señaló con anticipación y completó su revisión de espejos, y un conductor que circula a su lado tiene la obligación de ceder el paso a un camión que señaliza"],"explanation":"Un vehículo en su punto ciego significa que el carril no está libre, así que cancele el cambio de carril y vuelva a revisar el espejo y el punto ciego antes de moverse."},"296":{"q":"Conduce un tractocamión cargado por el carril derecho de una autopista concurrida de cuatro carriles a 55 mph. Aparece adelante en su carril un camión de mantenimiento que avanza lento, y decide que necesita pasarse al carril izquierdo para mantener su velocidad. El tráfico es denso por ambos lados. ¿Cuál es la secuencia más segura y correcta para completar este cambio de carril?","options":["Acelerar rápido para crear un hueco y meterse al carril izquierdo antes de que alguien lo ocupe","Frenar fuerte primero para abrir espacio atrás y luego pasarse al carril izquierdo una vez que haya reducido la velocidad","Mirar una sola vez el espejo izquierdo y desplazarse con suavidad, ya que señalizar en una vía concurrida solo confunde a los demás conductores","Encender la direccional izquierda con anticipación, revisar los espejos y su punto ciego izquierdo (la 'No-Zone') y cambiarse solo después de confirmar que el carril está despejado"],"explanation":"Señalice con antelación, revise los espejos y el punto ciego izquierdo (la No-Zone) y cámbiese de carril solo tras confirmar que está libre."},"297":{"q":"Durante su inspección previaje descubre que el conductor anterior reemplazó un solo neumático dañado. El neumático nuevo es radial, pero el otro neumático junto a él en el mismo eje es de capas diagonales (bias-ply). Las otras dos posiciones de los ejes están emparejadas. ¿Cuál condición debe corregir antes de que este camión sea legal y seguro para conducir?","options":["Tener un neumático radial montado junto a un neumático de capas diagonales (bias-ply) en el mismo eje","Un neumático del eje de dirección que muestra 4/32 de pulgada de profundidad de banda de rodadura","Un neumático trasero (no de dirección) que muestra 2/32 de pulgada de profundidad de banda de rodadura","Tener dos neumáticos de la misma marca pero con distintas fechas de compra en un mismo eje"],"explanation":"Los neumáticos radiales y diagonales nunca deben mezclarse en el mismo eje porque su distinta construcción provoca tracción y manejo desiguales e impredecibles."},"298":{"q":"Durante la inspección previa al viaje, descubre que en uno de los neumáticos del eje motriz la banda de rodadura se está desprendiendo del cuerpo del neumático, además de un corte largo y profundo que deja expuesta la cuerda interior. El neumático todavía mantiene el aire y la profundidad de la banda en otras zonas mide muy por encima de 2/32 de pulgada. ¿Cuál es la decisión correcta sobre este neumático?","options":["Es legal conducir porque la profundidad de banda restante sigue por encima del mínimo de 2/32 de pulgada para un neumático que no es de dirección","El neumático queda fuera de servicio y debe reemplazarse antes de conducir el vehículo, sin importar la profundidad de banda ni la presión de aire","Es aceptable para un viaje local corto siempre que mantenga la velocidad baja y lo vuelva a revisar en la primera parada","Es solo un defecto menor porque el neumático está en el eje motriz y no en el eje de dirección"],"explanation":"La separación de la banda de rodadura o un corte profundo que expone la lona deja el neumático fuera de servicio, por lo que debe reemplazarse antes de conducir sin importar la profundidad de dibujo ni la presión."},"299":{"q":"Durante su inspección previaje encuentra un neumático con superficie recauchutada (reencauchada) y otro con marcas de costado reranurado. Tiene un plazo de entrega ajustado y quiere mantener estos neumáticos en servicio en algún lugar de su camión en vez de reemplazarlos. ¿En cuál única posición de rueda estaría PROHIBIDO montar un neumático reranurado o recauchutado, obligándolo a colocar allí un neumático nuevo y adecuado?","options":["En un eje trasero del remolque, porque los neumáticos del remolque cargan el mayor peso y se desgastan más rápido","En una posición dual interior, porque un recauchutado oculto allí es el más difícil de inspeccionar","En una posición del eje delantero (de dirección), donde no se permite un neumático reranurado o recauchutado","En la rueda de repuesto, porque un recauchutado nunca puede llevarse como respaldo"],"explanation":"Los neumáticos reranurados o recauchutados están prohibidos en el eje delantero de dirección, porque una falla del neumático de dirección causa la pérdida inmediata del control de la dirección."},"300":{"q":"Durante su inspección previaje, se agacha para examinar los neumáticos dobles del eje trasero de su remolque. Ambos neumáticos parecen ser del mismo tamaño y marca, con buena profundidad de banda de rodadura. Al observar de cerca el espacio entre ellos, debe decidir qué condición haría que este conjunto doble fuera ilegal e inseguro para conducir. ¿Cuál de los siguientes es el defecto que NO debe permitir?","options":["Los dos neumáticos son exactamente del mismo tamaño y tienen patrones de banda de rodadura iguales","Ambos neumáticos están inflados firmes y mantienen aproximadamente la misma presión de aire","Cada neumático muestra bastante por encima del mínimo de 2/32 de pulgada de banda de rodadura en el eje trasero","Los dos neumáticos se abultan hacia adentro y hacen contacto entre sí"],"explanation":"Los neumáticos duales nunca deben tocarse entre sí ni ninguna parte del vehículo, pues el contacto indica baja presión o mal montaje y el roce y calor pueden causar un reventón."},"301":{"q":"Durante su inspección previaje en una mañana fría, encuentra una grieta visible que atraviesa uno de los rines de las ruedas en su eje motriz. La llanta retiene el aire, la banda de rodadura está bien y ya va atrasado para una entrega. ¿Cuál acción es correcta?","options":["Poner el vehículo fuera de servicio y no conducir hasta que el rin agrietado sea reparado o reemplazado","Conducir con cuidado a la entrega ya que la llanta aún retiene el aire y la profundidad de la banda está bien","Desinflar la llanta unas libras para aliviar la tensión en el rin, y luego continuar a velocidad reducida","Es solo una grieta cosmética menor, así que regístrela como desgaste normal y revísela en su primera parada de carga a las 50 millas"],"explanation":"Una llanta agrietada o rota es una condición automática de fuera de servicio porque puede fallar bajo carga y separar el neumático de la rueda a velocidad."},"302":{"q":"Durante su inspección previaje se mete debajo del remolque y descubre que una hoja del muelle de ballesta de la suspensión trasera está agrietada por completo y que una segunda hoja se ha salido de su montaje. El camión todavía se mantiene nivelado en el patio y rueda bien en la vuelta corta de prueba. ¿Cuál es la forma correcta de clasificar y manejar este hallazgo antes de su recorrido?","options":["Como el camión se mantiene nivelado y rueda bien, la hoja agrietada es cosmética y puede conducir vigilándola durante el viaje","Es un defecto de la suspensión que debe repararse antes de poner el vehículo en servicio","Es aceptable siempre que vuelva a revisar la sujeción de la carga dentro de las primeras 50 millas","Es una condición normal que en realidad mejora la suavidad de marcha y no requiere ninguna acción"],"explanation":"Las ballestas agrietadas, rotas, sueltas, faltantes o desplazadas son un defecto de suspensión fuera de servicio que debe repararse antes de poner el vehículo en servicio."},"303":{"q":"Es temprano por la mañana y usted camina alrededor de su tractocamión durante la inspección previaje. En la suspensión trasera observa una película húmeda y aceitosa que recubre uno de los amortiguadores, y un fino reguero de líquido que baja hasta el guardapolvo. Todo lo demás en ese eje se ve normal. ¿Cuál es la conclusión correcta sobre este componente y qué debe hacer?","options":["La película aceitosa es solo mugre de la carretera lanzada por las llantas, así que el amortiguador está bien tal como está y puede continuar con el viaje.","Los amortiguadores están diseñados para rezumar un poco de aceite para mantenerse lubricados, así que una película ligera es aceptable y solo una fuga abundante que gotea sería un defecto.","Un amortiguador con fuga es un defecto; los amortiguadores deben estar bien sujetos y sin fugas, así que esto debe repararse antes de que el vehículo sea seguro para conducir.","Los amortiguadores no soportan carga y solo afectan la comodidad de marcha, así que una fuga es un problema cosmético menor que puede simplemente anotar y atender en la próxima revisión de carga a las 150 millas."],"explanation":"Los amortiguadores deben estar bien sujetos y sin fugas, por lo que un amortiguador con fuga es un defecto que debe repararse antes de que el vehículo sea seguro para conducir."},"304":{"q":"Durante la inspección previaje se mete debajo del tractocamión y encuentra una grieta nueva que atraviesa un larguero del chasis cerca de un soporte de ballesta, y uno de los soportes del motor está visiblemente flojo. Ya va con retraso para una entrega local corta de 40 millas por calles urbanas planas. ¿Cuál es la acción correcta?","options":["Como solo es un viaje corto a baja velocidad por calles planas, puede conducir hasta la entrega y reportar la grieta después","Envuelva la zona agrietada con cinta resistente y apriete a mano lo que pueda para que aguante hasta el final del día","Conduzca a velocidad reducida y vuelva a inspeccionar el chasis y los soportes dentro de las primeras 50 millas, ya que es cuando debe revisarse la sujeción de la carga","Ponga el vehículo fuera de servicio y haga reparar el chasis agrietado y los soportes flojos antes de conducirlo siquiera"],"explanation":"Un chasis agrietado o un soporte suelto es un defecto estructural fuera de servicio, ya que el chasis soporta toda la carga y una grieta puede propagarse y fallar catastróficamente."},"305":{"q":"Es un viaje de madrugada con la temperatura justo bajo cero, así que mantiene las ventanas de la cabina cerradas y la calefacción encendida. Durante la inspección previa al viaje notó una pequeña fuga donde el tubo de escape se une al silenciador, pero el motor funcionaba bien, así que decidió conducir. Una hora después se siente somnoliento y con un ligero dolor de cabeza. ¿Cuál consecuencia de esa fuga de escape es la razón MÁS grave por la que debió repararla antes de conducir?","options":["Los gases de escape, incluido el monóxido de carbono, pueden filtrarse a la cabina cerrada y envenenarlo","La fuga deja entrar aire frío del exterior a la cabina y sobrecarga la calefacción","El escape que se fuga reduce la potencia del motor y desperdicia combustible en la pendiente","La fuga hace que el motor suene más fuerte y puede ocultar otros sonidos de advertencia"],"explanation":"Un sistema de escape con fugas es peligroso porque los gases de escape, incluido el monóxido de carbono, pueden filtrarse a una cabina cerrada y envenenar al conductor."},"306":{"q":"Durante su inspección previaje, abre la caja de la batería y encuentra que la batería se mueve ligeramente con un pequeño charco de líquido en la bandeja debajo de ella. Los cables están conectados y el camión arranca bien. Según las normas de inspección del DPS de Texas, ¿qué condición debe cumplir la batería antes de poder llevar legalmente este vehículo a la carretera?","options":["Solo necesita estar lo suficientemente cargada para arrancar el motor, ya que la potencia de arranque prueba que la batería está apta para circular","Debe estar firmemente sujeta por una abrazadera de sujeción para que no pueda moverse, y no debe tener fugas","Una fuga menor de electrolito es aceptable mientras el nivel del líquido se mantenga por encima de las placas","Una batería suelta está bien en viajes cortos porque los cables por sí solos evitan que se mueva"],"explanation":"La batería debe estar firmemente sujeta por un sujetador para que no se mueva y no debe tener fugas, ya que una batería que se desplaza o gotea puede hacer cortocircuito, agrietarse o derramar ácido corrosivo."},"307":{"q":"Usted entra a una isla de combustible al final de un viaje largo. La unidad refrigerada (reefer) del remolque sigue encendida, su teléfono está al 8% y quiere hacer una llamada rápida, y un co-conductor que espera cerca acaba de encender un cigarrillo a unos 6 metros de los surtidores. Antes de comenzar a echar diésel al tanque, ¿cuál de las siguientes es la acción correcta?","options":["Dejar el motor al ralentí para que el sistema de aire y el refrigerador sigan con presión y en frío, pero mantener la boquilla firme y cargar despacio","Mantener el camión encendido pero alejarse para atender la llamada telefónica mientras se llena el tanque, ya que la boquilla con corte automático detendrá el flujo","Apagar el motor, no fumar ni permitir que se fume cerca del punto de carga, y permanecer junto a la boquilla mientras carga combustible","Dejar el cigarrillo porque está a más de 4,5 metros, y acelerar el motor brevemente primero para limpiar las líneas antes de cargar"],"explanation":"Los vapores del diésel se inflaman con facilidad, por lo que el motor debe estar apagado, sin fumar cerca del punto de carga y alguien debe permanecer junto a la boquilla todo el tiempo."},"309":{"q":"Es una mañana de invierno con la temperatura justo bajo cero y está realizando la inspección previaje antes de un viaje largo. Mientras revisa el compartimiento del motor, quiere asegurarse de que su vehículo no se sobrecaliente ni se congele una vez que esté en marcha con el frío. ¿Qué revisión protege directamente el sistema de enfriamiento contra las condiciones invernales que enfrenta?","options":["Confirmar que el depósito del lavaparabrisas esté lleno para poder limpiar la aguanieve del cristal","Llenar el radiador con agua común para que el nivel de refrigerante marque lleno en la mirilla","Agregar aceite de motor adicional porque el frío espesa el aceite y lo quema más rápido","Verificar que el refrigerante tenga suficiente anticongelante para que no se congele a bajas temperaturas"],"explanation":"El anticongelante baja el punto de congelación del refrigerante, así que en clima frío debe confirmar que haya suficiente para evitar que se congele y dañe el motor."},"310":{"q":"Está justo bajo el punto de congelación en un puerto de montaña, está nevando y un letrero indica que se requieren cadenas más allá de este punto. Usted se detiene y coloca cadenas en las llantas de tracción. ¿Cuál es la razón PRINCIPAL por la que las cadenas le ayudan a seguir subiendo con seguridad la pendiente?","options":["Se clavan en la nieve y el hielo, dando a las llantas de tracción el agarre necesario para sujetarse a una superficie resbaladiza","Reducen la resistencia a la rodadura, lo que disminuye su consumo de combustible en la larga subida","Le permiten transportar legalmente más peso sobre el eje de tracción en una carretera cubierta de nieve","Amortiguan la marcha y hacen que el camión funcione más silencioso sobre nieve compactada"],"explanation":"Las cadenas para neumáticos muerden la nieve y el hielo para que las llantas de tracción agarren una superficie resbaladiza y transmitan fuerza sin patinar."},"311":{"q":"Conduce un vehículo combinado cargado por una autopista dividida de noche y nota que el automóvil que va delante de usted se comporta de forma extraña. ¿Cuál observación es la señal MÁS FUERTE de que el conductor de adelante puede estar ebrio o con sus facultades alteradas, indicándole que aumente su distancia de seguimiento y se prepare para dejar que se adelante bastante?","options":["El automóvil mantiene una velocidad constante y permanece centrado en su carril al tomar una curva suave","El automóvil se desvía de un lado a otro cruzando las líneas del carril y acelera y frena repetidamente sin motivo aparente","El automóvil señaliza el cambio de carril con anticipación y espera un espacio libre antes de moverse","El automóvil reduce la velocidad gradualmente y se desplaza al acotamiento derecho con las luces intermitentes de emergencia encendidas"],"explanation":"Cruzar las líneas del carril junto con acelerones y frenazos erráticos y sin motivo son señales clásicas de un conductor incapacitado, así que déle mucho espacio."},"313":{"q":"Conduce un tractocamión con remolque cargado por una carretera rural cuando el pedal del acelerador se queda pegado al piso de repente y el motor sigue acelerando aunque levante el pie. Hay poco tráfico y un acotamiento pavimentado más adelante. ¿Cuál es su PRIMERA acción prioritaria para recuperar el control del vehículo?","options":["Bombear el pedal del acelerador rápidamente con el pie para tratar de liberarlo, manteniendo la marcha puesta para no perder el frenado del motor","Apagar el motor de inmediato con la llave de encendido con la marcha aún puesta, para que las ruedas motrices dejen de empujar el camión hacia adelante","Poner la transmisión en neutral para desconectar el motor de las ruedas motrices y luego aplicar los frenos para reducir la velocidad y detenerse con seguridad","Quedarse con la marcha puesta y confiar solo en una presión de freno suave y constante para vencer al motor hasta llegar al acotamiento"],"explanation":"Poner en neutral desconecta el motor de las ruedas de tracción para que los frenos puedan reducir la velocidad y detener el vehículo cuando el acelerador se atasca."},"314":{"q":"Huele algo quemándose y se detiene de forma segura en el arcén. Al abrir la cabina, ve llamas que salen de detrás del tablero, cerca del cableado, y parece que están afectados los circuitos de la batería y del alternador. Tiene un extintor montado en la cabina. ¿Qué acción le da la MEJOR y más segura posibilidad de controlar este incendio?","options":["Dejar la energía conectada para poder ver el cableado y luego dirigir un chorro constante de agua a la base de las llamas para enfriarlas","Abrir de par en par el capó del motor y las puertas traseras para dejar salir el calor y el humo antes de hacer cualquier otra cosa","Mantener el motor en marcha para que el alternador siga cargando y sofocar las llamas con un trapo húmedo de la cabina","Si puede, corte la energía eléctrica (desconecte la batería / apague el encendido) y luego apáguelo con un extintor de clase B:C"],"explanation":"En un incendio eléctrico, primero corte la energía si es seguro para eliminar la fuente de ignición, y luego apáguelo con un extintor de clase B:C en vez de agua."},"315":{"q":"Justo después de coronar una colina, su motor pierde potencia y usted se detiene por inercia en el carril derecho de una carretera rural de dos carriles. Enciende las luces intermitentes de emergencia y toma sus triángulos de emergencia. Su co-conductor dice que no hay prisa porque hay poco tráfico. Según las reglas para detenerse en la vía, ¿cuál es el TIEMPO MÁXIMO que debe esperar antes de colocar sus dispositivos de advertencia?","options":["Dentro de los 10 minutos de haberse detenido","Dentro de 1 hora de haberse detenido, mientras las intermitentes sigan encendidas","Dentro de 1 minuto de haberse detenido","Antes del final de su jornada de conducción, ya que las intermitentes ya advierten al tráfico"],"explanation":"Tras detenerse en la vía o el acotamiento, encienda de inmediato las luces de emergencia y coloque sus tres triángulos reflectantes en un plazo de 10 minutos."},"316":{"q":"Su camión se ha plegado en tijera en una carretera rural de dos carriles y el conductor del auto que rozó está desplomado, consciente pero quejándose de dolor en el cuello. Hay poco tráfico, el clima está despejado y huele a refrigerante, pero no ve humo ni llamas. Según las indicaciones del DPS de Texas, ¿cuándo debe sacar a esta persona lesionada del vehículo?","options":["De inmediato, ya que un dolor de cuello significa una lesión de columna y hay que tenderla plana en el suelo","Solo si surge un peligro real como un incendio; de lo contrario, déjela donde está y espere ayuda capacitada","En cuanto haya colocado sus tres triángulos reflectantes a 10, 100 y 200 pies","Cuando el tráfico empiece a acumularse, para reabrir el carril y mantener seguros a los demás conductores"],"explanation":"No mueva a una persona herida a menos que la amenace un peligro real como un incendio, ya que mover a alguien con trauma de cuello o columna puede causar parálisis permanente."},"317":{"q":"Son las 5:30 a. m. y tiene un plazo de entrega. Anoche se tomó varias cervezas y dejó de beber hace unas cuatro horas. Para sentirse listo para conducir, se toma dos cafés negros grandes, da una caminata enérgica en el aire frío de la mañana y revisa el termómetro de la cabina. ¿Cuál de estas acciones realmente reducirá el alcohol que aún queda en su sangre para que pueda operar su vehículo comercial (CMV) de forma segura y legal?","options":["El aire frío de la mañana, porque respirar profundamente aire fresco ayuda al cuerpo a eliminar el alcohol más rápido","Los dos cafés negros grandes, porque la cafeína acelera el metabolismo y quema el alcohol restante","Ninguna de esas acciones; solo el paso de suficiente tiempo eliminará el alcohol de su sangre y bajará su BAC por debajo del límite de 0.04%","Las tres juntas, ya que el café, el aire frío y estar alerta se combinan para despejarlo antes de su turno"],"explanation":"Solo el tiempo permite que el hígado metabolice el alcohol y baje su BAC; el café, el aire fresco o sentirse despierto no aceleran ese proceso."},"318":{"q":"Lleva 9 horas en un viaje largo y empieza a sentir somnolencia. Otro conductor en la parada le ofrece pastillas de cafeína y estimulantes (\"uppers\"), asegurando que lo mantendrán lo bastante alerta para terminar su recorrido con seguridad. ¿Cuál es la MEJOR razón para rechazarlos y, en cambio, detenerse a descansar?","options":["Los estimulantes están bien siempre que además tome café y respire aire fresco para equilibrar sus efectos","Los estimulantes agudizan su tiempo de reacción y mejoran su visión nocturna, pero es ilegal llevarlos en la cabina","Los estimulantes solo son aceptables en pendientes de más de 419 pies, donde necesita mayor alerta","Los estimulantes no lo convierten en un conductor seguro; cuando su efecto desaparece puede quedar más cansado y peligroso que antes"],"explanation":"Los estimulantes solo enmascaran la fatiga temporalmente y no lo hacen seguro; cuando su efecto pasa, puede quedar más cansado y peligroso que antes."},"319":{"q":"Usted conduce por el carril derecho de una autopista de cuatro carriles a 55 mph. A aproximadamente un cuarto de milla por delante, ve un automóvil averiado detenido en el acotamiento derecho con las luces intermitentes encendidas y a una persona parada junto a él, cerca de la cajuela. ¿Por qué debe tratar esto como un peligro y comenzar a ajustar ahora, en lugar de esperar a estar más cerca?","options":["El auto detenido o la persona junto a él podrían entrar de repente en su carril, así que debe reducir la velocidad, aumentar su distancia de seguimiento y cambiarse a la izquierda si es seguro.","El acotamiento es el área de circulación legal para el tránsito lento, así que debe pasar a él para cederle el carril completo al auto averiado.","Solo es un peligro si el conductor no ha colocado los tres triángulos de advertencia a 10, 100 y 200 pies; de lo contrario, puede mantener la velocidad.","Un auto averiado en el acotamiento no representa ningún riesgo real mientras tenga las intermitentes encendidas, así que no es necesario cambiar la velocidad ni la posición."],"explanation":"Un auto detenido o una persona a su lado puede entrar de repente a su carril, así que reduzca la velocidad, aumente su distancia de seguimiento y muévase a la izquierda cuando sea seguro."},"320":{"q":"Entra a un área de descanso a mitad de la ruta y, antes de volver a subir a la cabina, se agacha y echa un vistazo rápido por debajo de su tractocamión con remolque. Además de confirmar que nada se arrastra, ¿cuál es la PRINCIPAL razón de seguridad por la que el manual recomienda esta breve mirada a ras de suelo bajo el vehículo en una parada?","options":["Le permite leer el calibrador de profundidad de la banda de rodadura para confirmar que los neumáticos de dirección aún tienen al menos 4/32 de pulgada","Puede revelar una fuga reciente de líquido, un neumático desinflado o pinchado, y personas u objetos que puedan estar debajo o detrás del vehículo antes de que arranque","Cumple con el requisito de reinspeccionar y reasegurar la carga dentro de las primeras 50 millas del viaje","Es la forma de colocar sus tres triángulos de advertencia a 10, 100 y 200 pies antes de partir"],"explanation":"Una revisión a nivel del suelo antes de avanzar revela fugas de líquido recientes, una llanta desinflada o con baja presión, y personas u objetos bajo o detrás del vehículo."},"321":{"q":"Está transportando un remolque cargado y llega a la cima de una bajada de montaña larga y empinada. Un letrero advierte de una pendiente del 6% más adelante. Para evitar que sus frenos se desvanezcan durante el descenso, ¿cuándo debe elegir la marcha baja que usará para bajar?","options":["En el punto en que sienta por primera vez que los frenos comienzan a sobrecalentarse y a desvanecerse","Aproximadamente a la mitad de la bajada, una vez que pueda juzgar lo empinada que es en realidad","Antes de comenzar a bajar la pendiente, mientras todavía está en la cima","Solo si la carga se desplaza o su velocidad supera un nivel seguro"],"explanation":"Seleccione una marcha baja antes de comenzar a bajar una pendiente larga y empinada, mientras aún está en la cima."},"322":{"q":"Está bajando una pendiente de montaña larga y empinada con un remolque cargado. A la mitad del descenso nota olor a frenos recalentados y el pedal empieza a sentirse más blando que en la cima. De las siguientes, ¿qué acción le da el control más seguro de su velocidad durante el resto del descenso?","options":["Mantener presión firme y constante en el pedal del freno durante todo el descenso para fijar la velocidad","Poner el cambio en neutral para que el motor se enfríe y luego frenar suavemente hasta abajo","Bombear rápidamente el pedal del freno para recuperar la presión de aire y restaurar un pedal firme","Permanecer en una marcha baja para que el motor ayude a frenar y usar solo aplicaciones de freno ligeras e intermitentes"],"explanation":"El freno de motor y de marcha son el control principal de velocidad en una bajada, así que mantenga una marcha baja y aplique solo frenadas ligeras e intermitentes para que los frenos se enfríen."},"323":{"q":"Está bajando una pendiente de montaña larga y empinada con un remolque cargado. Para mantener la velocidad bajo control, mantiene presión continua y constante sobre los frenos de servicio durante todo el descenso en lugar de usar una marcha baja. Al acercarse al final de la bajada, ¿cuál es el resultado MÁS probable de usar los frenos de esta manera?","options":["Los frenos se sobrecalentarán y perderán eficacia (se desvanecerán), quedándose sin capacidad de frenado justo cuando más la necesita","Los frenos agarrarán con más fuerza cuanto más tiempo se apliquen, dándole control adicional","El flujo continuo de aire sobre los tambores mantendrá los frenos fríos y funcionando con normalidad","Los frenos se desgastarán de forma pareja y durarán más porque la presión es suave y constante"],"explanation":"El frenado continuo y constante en una bajada larga genera calor más rápido de lo que puede disiparse, por lo que los frenos se sobrecalientan, se desvanecen y pierden poder de frenado."},"324":{"q":"Está descendiendo una pendiente de montaña larga y empinada con un remolque totalmente cargado. A mitad de la bajada percibe un leve olor a quemado, el pedal del freno se va aflojando y el camión sigue ganando velocidad aunque está pisando los frenos. Adelante un letrero dice \"RAMPA DE ESCAPE PARA CAMIONES 1 MILLA.\" ¿Cuál es el propósito PRINCIPAL de esa rampa y por qué podría necesitarla aquí?","options":["Es una zona de descanso designada donde debe estacionar y dejar enfriar los frenos durante 30 minutos antes de continuar el descenso.","Está construida para detener de forma segura un vehículo fuera de control que ha perdido la capacidad de frenar, como cuando los frenos se sobrecalientan y pierden eficacia en una bajada larga.","Es un carril de paso de la estación de pesaje donde los camiones que descienden verifican el peso de sus ejes antes de llegar al final de la pendiente.","Es un punto de giro para camiones de gran tamaño que no pueden completar con seguridad el resto de la pendiente empinada."],"explanation":"Una rampa de escape está construida para detener de forma segura un vehículo descontrolado que ha perdido la capacidad de frenar, como cuando los frenos se sobrecalientan y se desvanecen en una bajada larga."},"327":{"q":"Está detenido en un cruce ferroviario de varias vías sin barreras ni señales. Un tren de carga pasa con estruendo por la vía más cercana y por fin despeja hacia su izquierda. La vista a lo largo de ambas vías está parcialmente bloqueada por árboles, y ve que tiene espacio para librar por completo todas las vías más el largo total de su vehículo y unos 15 pies adicionales. Antes de soltar el freno y empezar a cruzar, ¿qué es lo MÁS importante que debe hacer?","options":["Poner la marcha más baja para tener la máxima fuerza de tracción al cruzar las vías","Confirmar que los brazos pintados de la barrera del cruce estén totalmente levantados antes de avanzar","Revisar la segunda vía en ambas direcciones por si viene otro tren que el primero pudo haber ocultado","Esperar 15 segundos completos después de que pase el tren y luego avanzar sin volver a revisar"],"explanation":"Un segundo tren puede estar oculto detrás del que acaba de pasar, así que mire en ambas direcciones en cada vía antes de cruzar."},"328":{"q":"No ha llovido en su zona de reparto durante casi tres semanas, y una lluvia ligera acaba de empezar a caer cuando entra en una concurrida carretera de dos carriles. Inmediatamente siente que el remolque se vuelve inestable con un frenado leve, aunque el pavimento apenas parece mojado. ¿Por qué esta lluvia ligera inicial es MÁS peligrosa para su tracción que un aguacero fuerte más tarde durante la misma tormenta?","options":["La fina película de agua enfría el pavimento, lo que endurece el caucho de los neumáticos y reduce el agarre","La lluvia ligera no puede limpiar la carretera, así que un aguacero fuerte más tarde le daría en realidad mejor agarre de los neumáticos","La lluvia ligera aumenta la presión de los neumáticos, y los neumáticos sobreinflados ruedan sobre una huella de contacto más pequeña","La primera agua se mezcla con el aceite y el polvo acumulados en la carretera seca, levantándolos en una película resbaladiza antes de que una lluvia más fuerte pueda lavarla"],"explanation":"La primera lluvia tras un período seco es resbaladiza porque el agua ligera se mezcla con el aceite y el polvo acumulados, formando una película resbalosa antes de que una lluvia más fuerte la arrastre."},"329":{"q":"Acaba de cruzar un vado inundado de bajo nivel donde el agua era lo bastante profunda para llegar a los cubos de las ruedas. Mientras acelera de vuelta a la carretera seca y se acerca a una intersección a un cuarto de milla por delante, su primera frenada revela un pedal de freno blando y débil. ¿Cuál es la acción correcta para restaurar el frenado antes de depender de los frenos a velocidad?","options":["Conducir a baja velocidad aplicando presión ligera y suave a los frenos para probarlos y secarlos con el calor de la fricción","Bombear el pedal del freno fuerte y rápido para forzar la salida del agua de los tambores antes de la próxima parada","Acelerar a velocidad de carretera para que el viento y el calor del motor sequen los frenos rápidamente","Apagar el motor y rodar por inercia para que los frenos se sequen al aire de forma natural antes de continuar"],"explanation":"Después de que el agua profunda moje las balatas, conduzca despacio aplicando presión ligera y suave para que el calor de la fricción las seque y restablezca el frenado normal."},"330":{"q":"Usted transporta una carga parcial en una autopista interestatal bajo lluvia continua a 50 mph. La carretera por delante parece una lámina continua de agua y siente que se forma una fina película entre sus neumáticos y el pavimento. De repente el volante se siente diferente en sus manos. ¿Cuál cambio sería la advertencia más clara de que sus neumáticos han perdido el agarre y que podría estar empezando a hidroplanear?","options":["El volante de repente se resiste y se siente pesado, rígido y difícil de girar","El volante de repente se siente liviano y fácil de girar, como si se hubiera aflojado","Oye que el motor se vuelve notablemente más ruidoso aunque su velocidad sea constante","Nota un fuerte olor a combustible que entra por las rejillas de ventilación de la cabina"],"explanation":"Cuando las llantas pierden agarre en una superficie mojada y ruedan sobre una capa de agua, la dirección se siente de repente liviana y fácil de girar."},"331":{"q":"Salió de servicio a las 6:00 p. m. y tomó un descanso completo de 10 horas; luego entró en servicio a las 4:00 a. m. y condujo sin parar. Un despachador lo presiona para que siga conduciendo porque, según él, aún le quedan horas dentro de su ventana de 14 horas. Dejando a un lado la ventana de servicio de 14 horas, ¿cuál es el número máximo de horas que en realidad se le permite pasar CONDUCIENDO durante este turno de trabajo?","options":["8 horas de conducción, porque es cuando se vuelve obligatorio un descanso de 30 minutos y su turno termina en la práctica","14 horas de conducción, ya que la ventana de 14 horas es lo que realmente controla cuánto tiempo puede permanecer al volante","11 horas de conducción, porque después de 10 horas consecutivas fuera de servicio puede conducir un máximo de 11 horas","16 horas de conducción, siempre que permanezca dentro de la ventana de servicio de 14 horas"],"explanation":"Tras 10 horas consecutivas fuera de servicio, puede conducir un máximo de 11 horas, aparte del límite de la ventana de 14 horas de servicio."},"332":{"q":"Entró de servicio a las 6:00 a.m. Tras cargar y esperar, finalmente comenzó a conducir a las 9:00 a.m. Solo ha conducido unas 5 horas en total y ha tomado un descanso de 30 minutos, por lo que cree que todavía le queda bastante tiempo legal de conducción en el día. Cuando el reloj se acerca a las 8:00 p.m., ¿qué afirmación describe correctamente cuándo debe dejar de conducir en este turno de trabajo?","options":["Puede seguir conduciendo hasta acumular 6 horas reales al volante, ya que el tiempo de conducción es lo que en verdad controla el límite.","Puede seguir conduciendo mientras no supere las 10 horas de servicio, porque es el reloj de servicio el que lo detiene.","Puede seguir conduciendo después de las 8:00 p.m. porque su descanso de 30 minutos detuvo el reloj y desplazó su hora límite a más tarde por la noche.","No puede conducir en absoluto después de las 8:00 p.m., porque esa es la hora 14 después de haber entrado de servicio, sin importar lo poco que haya conducido en realidad."],"explanation":"No puede conducir después de la hora 14 desde que entró en servicio, sin importar cuán poco haya conducido en realidad."},"333":{"q":"Está cargando una plataforma plana (flatbed) para un recorrido de 300 millas. Ha equilibrado el peso sobre los ejes, ha cubierto la carga con una lona para mantenerla seca y sus amarres cumplen con el límite de carga de trabajo. Mientras hace una última inspección caminando alrededor del vehículo, se recuerda a sí mismo la razón más importante por la cual la carga debe asegurarse correctamente antes de salir a la carretera. ¿Qué afirmación expresa mejor esa razón?","options":["La carga asegurada debe evitar desplazarse, caerse o bloquearle la visión de la carretera","La carga asegurada debe mantenerse totalmente oculta bajo una lona para que no pueda verse desde fuera del vehículo","La carga asegurada debe colocarse de modo que pueda pesarse rápidamente en la próxima estación de inspección","La carga asegurada debe cargarse de modo que los amarres sean visibles para los oficiales desde el lado del pasajero"],"explanation":"La carga debe asegurarse para que no pueda desplazarse, caerse ni bloquear su visión de la carretera."},"334":{"q":"Recoge una carga de último momento y el cargador la empaca más pesada de lo que indica su manifiesto, dejándolo ligeramente por encima de su GVWR (peso bruto vehicular permitido). El despachador dice que es \"solo un poco de más\" y le ordena llevarla. Al incorporarse a la autopista, ¿qué efecto de esta sobrecarga debería preocuparle MÁS desde el punto de vista de la seguridad?","options":["El peso adicional presionará las llantas con más fuerza contra el suelo, dándole más tracción y una distancia de frenado más corta","El vehículo será más difícil de dirigir y tardará más en detenerse porque el peso añadido trabaja en contra de su dirección y sus frenos","El peso adicional baja el centro de gravedad, así que el camión se vuelve más estable y mucho menos propenso a volcarse","El consumo de combustible mejora porque el motor trabaja con una carga más estable cuando el camión está completamente cargado"],"explanation":"El exceso de peso dificulta el manejo del volante y aumenta la distancia de frenado, porque la masa adicional actúa contra la dirección y los frenos."},"335":{"q":"Durante la inspección previaje en un muelle de carga de Texas, descubre que dos tramos de tubería de acero sobresalen unos cuatro pies por la parte trasera de su remolque de plataforma. La carga está debidamente asegurada con amarres, sus documentos están en orden y está a punto de salir en un viaje diurno. Respecto a la parte de la carga que sobresale por la parte trasera, ¿qué exige la normativa federal y de Texas que haga antes de conducir?","options":["No se requiere nada adicional, porque el saliente mide menos de cinco pies y la carga ya está asegurada con la cantidad correcta de amarres","Añadir un amarre adicional a la sección que sobresale y pintar los extremos salientes de un color oscuro para que distraigan menos al tráfico","Marcar la carga que sobresale para que sea visible -- usar banderas (y luces si la visibilidad es mala o de noche) en la parte que sobresale por la parte trasera","Volver a revisar la sujeción dentro de las primeras 50 millas, pero no es necesario marcar el saliente porque la carga está totalmente amarrada"],"explanation":"La carga que sobresale por la parte trasera debe marcarse para que sea visible: con banderas de día y luces cuando hay poca visibilidad o de noche."},"336":{"q":"En un muelle de carga, la cuadrilla del almacén carga y amarra con cadenas una plataforma de tubería de acero para usted, el supervisor del muelle firma el conocimiento de embarque y un oficial del DOT está parado por casualidad cerca. Usted cree que un par de amarres se ven sueltos. Según las normas federales y de Texas, ¿quién es en última instancia responsable de asegurarse de que esta carga esté bien asegurada y dentro de los límites legales de peso antes de que usted arranque?","options":["El expedidor y la cuadrilla del almacén, porque ellos cargaron y encadenaron físicamente la carga","El supervisor del muelle, porque su firma en el conocimiento de embarque certifica la carga","El oficial del DOT que está parado cerca, ya que hacer cumplir el aseguramiento es su trabajo","Usted, el conductor, porque usted es responsable de una carga segura y legal sin importar quién la cargó"],"explanation":"El conductor es responsable de una carga segura y legal, sin importar quién la haya cargado."},"337":{"q":"Cargó bobinas de acero en el patio y acaba de salir a la autopista interestatal. La carga parecía firme cuando la aseguró, pero usted sabe que las amarras y la carga pueden moverse una vez que el camión rueda y las cadenas se asientan. Para mantenerse dentro de la ley y la seguridad, ¿qué tan pronto debe hacer su PRIMERA parada para volver a revisar el aseguramiento de la carga?","options":["Dentro de las primeras 50 millas después de comenzar el viaje","Dentro de las primeras 150 millas después de comenzar el viaje","Dentro de las primeras 3 horas de conducción, sin importar la distancia","Solo después de su primer descanso o parada para combustible"],"explanation":"Debe inspeccionar la carga y su sujeción dentro de las primeras 50 millas después de comenzar el viaje."},"339":{"q":"Es una noche sin luna y conduce un remolque plano vacío por una carretera rural de dos carriles sin alumbrado público. Sus luces bajas iluminan unos 250 pies de carretera por delante, pero no puede usar legalmente las luces altas porque aparecen vehículos en sentido contrario constantemente. Para no salirse de la carretera ni golpear un peligro no visto, ¿qué regla única debe gobernar su velocidad?","options":["Puede mantener el límite de velocidad señalizado siempre que sus faros y luces de freno funcionen correctamente","Su velocidad debe ser lo suficientemente lenta para poder detenerse dentro de la distancia que sus faros iluminan por delante","Debe mantener la velocidad lo bastante baja para leer cada señal de tránsito antes de pasarla","Puede conducir más rápido porque un remolque vacío da una distancia de frenado más corta que uno cargado"],"explanation":"Nunca conduzca más allá del alcance de sus faros: su velocidad debe permitirle detenerse dentro de la distancia que iluminan adelante."},"340":{"q":"Conduce un tractocamión cargado por una carretera oscura de dos carriles justo pasada la medianoche. Un auto que viene de frente mantiene las luces altas encendidas y se niega a bajarlas, y el resplandor le está nublando la vista. Ya le hizo señas con sus luces para recordarle al conductor, sin resultado. Hasta que ese auto pase, ¿qué es lo MEJOR que puede hacer con la mirada para mantener el control de su carril?","options":["Mirar fijamente las luces que vienen de frente para calcular con exactitud cuándo lo pasará el auto","Levantar la vista hacia el cielo por encima de los faros para sacar la luz intensa de su línea directa de visión","Bajar la mirada y dirigirla hacia el borde derecho de su propio carril y guiarse por él para conducir hasta que el auto haya pasado","Bajar los ojos al tablero y fijarse en los instrumentos hasta que los faros ya no estén frente a usted"],"explanation":"Cuando le encandilen las luces altas que se aproximan, mire hacia el borde derecho de su carril y úselo para guiarse hasta que el vehículo pase."},"341":{"q":"Acaba de descargar toda su carga en un almacén y ahora conduce el tractocamión vacío sin remolque (bobtail) de regreso al patio. Al acercarse a un semáforo en rojo, frena de la misma manera que lo hacía cuando iba cargado, y las ruedas de repente se bloquean y empiezan a derrapar. ¿Por qué este camión vacío frena PEOR que cuando iba cargado?","options":["Cuanto más pesado es el vehículo, más tarda en detenerse, así que un camión vacío debería detenerse más fácilmente que uno cargado","A los camiones vacíos se les instalan frenos más pequeños y débiles que no pueden generar suficiente fuerza para frenar el vehículo","Sin carga, el centro de gravedad más alto hace que el camión se incline hacia adelante y sobrecargue los frenos delanteros","Con poco peso presionando los neumáticos contra el pavimento, los neumáticos tienen menos tracción y es más probable que se bloqueen y derrapen"],"explanation":"Un camión vacío tiene poco peso presionando los neumáticos contra el camino, por lo que tienen menos tracción y se bloquean y patinan con más facilidad."},"342":{"q":"Ha estado cayendo una lluvia constante y el pavimento está claramente mojado, pero aún no cubierto de agua estancada ni de aguanieve. El tránsito a su alrededor todavía circula cerca del límite señalizado de 60 mph. Para mantener un margen seguro de control sobre esta superficie mojada, ¿en aproximadamente cuánto debería reducir su velocidad respecto a la que conduciría con seguridad en la misma carretera cuando está seca?","options":["Aproximadamente un tercio más lento que su velocidad segura en carretera seca","Aproximadamente la mitad más lento que su velocidad segura en carretera seca","Aproximadamente tres cuartos más lento que su velocidad segura en carretera seca","No es necesario reducir mientras no se hayan formado agua estancada ni aguanieve"],"explanation":"En carreteras mojadas, reduzca su velocidad aproximadamente un tercio respecto a su velocidad segura en seco para conservar la tracción."},"343":{"q":"Conduce un refrigerado cargado por una carretera rural de dos carriles cuando la temperatura baja y empieza a caer una nieve constante que se adhiere y deja una capa blanca dura y compactada sobre el pavimento. El tránsito fluye bien, la carretera no está helada y aún ve con claridad. Para mantener un margen seguro en esta superficie de nieve compactada, ¿en qué proporción aproximada debe reducir su velocidad normal de carretera seca?","options":["Reduzca su velocidad aproximadamente una cuarta parte","Reduzca su velocidad aproximadamente a la mitad","Reduzca su velocidad aproximadamente una décima parte","Mantenga su velocidad normal ya que la carretera no está helada y la visibilidad es buena"],"explanation":"En nieve compactada, reduzca su velocidad aproximadamente a la mitad porque la tracción disminuye mucho y aumenta la distancia de frenado."},"344":{"q":"Es justo antes del amanecer, la temperatura está apenas bajo cero y conduce un vehículo combinado cargado sobre un puente. El pavimento por delante se ve oscuro, liso y mojado, pero nota que no salpica nada de agua de las llantas del auto que va adelante. ¿Por qué se considera este tipo de superficie uno de los peligros invernales más graves?","options":["Es brillante y evidente, por lo que los conductores frenan demasiado fuerte y pierden tracción en una vía claramente helada","Solo se forma en la parte más calurosa de una tarde de verano, cuando el alquitrán brota a través del pavimento","Parece una inofensiva vía mojada, pero en realidad es una capa fina y transparente de hielo que casi no da aviso alguno","Derrite el alquitrán del pavimento por debajo, dejando una película aceitosa resbaladiza fácil de ver y esquivar"],"explanation":"El hielo negro es una capa fina y transparente de hielo que hace que la carretera parezca solo mojada y casi no da aviso."},"345":{"q":"Conduce un tractocamión cargado por una carretera rural de dos carriles cuando una ráfaga de viento lateral fuerte y repentina golpea el costado del remolque y el volante se sacude en sus manos. Para mantener el mejor control y estar listo para contravolantear si el viento lo empuja hacia el acotamiento, ¿cómo deben estar colocadas sus manos en el volante?","options":["Mantenga una mano en la parte superior del volante para tener la mayor palanca y descanse la otra mano sobre su regazo","Mantenga ambas manos juntas cerca de la parte superior del volante para poder reaccionar rápido en cualquier dirección","Mantenga una mano cerca de la parte inferior del volante y use la otra solo para apoyarse contra la puerta","Mantenga ambas manos firmes sobre el volante, en lados opuestos una de la otra"],"explanation":"Sujete el volante con firmeza con ambas manos en lados opuestos para mantener el control y poder contradirigir ante peligros repentinos."},"346":{"q":"Entra a una parada de camiones abarrotada y debe retroceder su tractocamión hacia un espacio de estacionamiento estrecho. No hay quien le sirva de guía y otros camiones están estacionados muy cerca a ambos lados. Para que la maniobra sea lo más segura posible, ¿hacia qué lado debe retroceder?","options":["Hacia el lado del conductor, para poder mirar hacia atrás a lo largo del remolque y vigilar su trayectoria por la ventanilla del conductor","Hacia el lado del pasajero, porque el remolque se abre más por ese lado y le da más espacio libre","Hacia el lado que le permita retroceder en línea recta cuesta abajo por la pendiente del estacionamiento","Hacia su lado ciego, y luego confiar en los espejos y en un rápido recorrido a pie para cubrir lo que no puede ver"],"explanation":"Retroceda hacia el lado del conductor para mirar directamente a lo largo del remolque y ver su trayectoria por la ventanilla lateral."},"348":{"q":"Necesita retroceder su remolque de 53 pies hacia un muelle de carga estrecho por el lado ciego (derecho), y un compañero de trabajo está cerca ofreciéndose a ayudar. Según los procedimientos seguros de retroceso, ¿cuál es la única razón más importante para usar a esta persona como ayudante?","options":["Puede hacerle señas con las manos para que usted no tenga que usar los espejos en absoluto","Puede vigilar las zonas detrás y al lado de su remolque que usted no puede ver desde la cabina","Puede detener el tráfico que viene por la calle para que usted retroceda sin esperar","Puede tomar el control y retroceder el remolque por usted si el ángulo se vuelve demasiado difícil"],"explanation":"Un ayudante puede vigilar las zonas ciegas detrás y al lado del remolque que usted no puede ver desde la cabina."},"349":{"q":"Conduce un tractocamión con remolque de 53 pies y se aproxima a una curva cerrada a la derecha hacia una calle urbana estrecha. Sabe que el remolque seguirá una trayectoria interior y podría subirse al bordillo si gira demasiado cerrado. Un automóvil acaba de acercarse justo detrás de usted por su lado derecho. Para completar esta vuelta de forma segura y legal, ¿qué debe hacer?","options":["Desviarse ampliamente hacia la izquierda antes de iniciar la vuelta para que el remolque tenga espacio para librar el bordillo","Acelerar un poco durante la vuelta para que el remolque siga al tractor de forma más ajustada","Girar desde lo más a la derecha que sea seguro, manteniendo la parte trasera del vehículo cerca del bordillo para que nadie pueda pasar por su derecha","Cambiarse primero al carril más a la izquierda y luego hacer la vuelta a la derecha desde allí para dar al remolque el máximo espacio"],"explanation":"Gire desde lo más a la derecha que sea seguro y mantenga la parte trasera cerca del bordillo para que nadie pase por su derecha."},"350":{"q":"Conduce un tractocamión con remolque de 53 pies y necesita girar a la izquierda en una intersección concurrida de cuatro vías. El semáforo se pone en verde y el tráfico en sentido contrario ya pasó. Para completar este giro a la izquierda con seguridad y evitar que las ruedas traseras del remolque corten el carril del que sale, ¿cuál es la técnica correcta?","options":["Comience a mover el frente del tractor hacia la izquierda en cuanto entre a la intersección para que el remolque siga una trayectoria más cerrada","Permanezca en el carril más a la derecha durante todo el giro para que las ruedas traseras del remolque tracen amplio y libren la acera","Corte en diagonal por la esquina de la intersección para acortar la distancia que debe recorrer el remolque","Avance con el tractor y alcance el centro de la intersección antes de comenzar a girar el volante hacia la izquierda"],"explanation":"Avance hasta el centro del cruce antes de girar el volante a la izquierda para que las ruedas traseras del remolque no corten la esquina."},"351":{"q":"Es temprano por la mañana y acaba de subir a la cabina para comenzar un viaje largo. Al acomodarse, nota que el espejo del lado derecho está inclinado demasiado alto y no muestra el costado del remolque, y quiere corregirlo. ¿Cuándo es el momento correcto para hacer este ajuste?","options":["Ahora, antes de iniciar el viaje, con el vehículo estacionado de forma segura","Una vez que alcance la velocidad de la autopista, para que el espejo quede ajustado según cómo va el remolque bajo carga","En su primera revisión obligatoria de la carga, dentro de las primeras 50 millas del viaje","Solo después de terminar de conducir y haber entrado al patio de destino"],"explanation":"Ajuste los espejos antes del viaje mientras el vehículo está estacionado de forma segura, ya que no puede hacerlo con seguridad en movimiento."},"353":{"q":"Acaba de cambiarse al carril izquierdo para adelantar a un vehículo más lento en una autopista de varios carriles. El adelantamiento ha terminado y ya circula estable en el nuevo carril. Al mirar el tablero, se da cuenta de que su intermitente izquierda sigue parpadeando porque, a diferencia de un automóvil, la señal de su camión no se canceló sola. ¿Qué debe hacer PRIMERO?","options":["Acelerar con firmeza para aumentar la distancia con el vehículo que acaba de adelantar y revisar la señal más tarde","Apagar manualmente la señal de giro para que los conductores a su alrededor no se confundan sobre sus intenciones","Frenar para revisar nuevamente los espejos antes de decidir si hay que cancelar la señal","Dejar la señal encendida hasta el próximo cambio de carril, ya que muestra que todavía está maniobrando"],"explanation":"La mayoría de los camiones grandes no cancelan solos las señales, así que apague la luz tras la maniobra para no confundir a otros conductores."},"355":{"q":"Conduce su tractocamión de noche por una carretera oscura de dos carriles con las luces altas encendidas. Divisa los faros de un vehículo que se aproxima en el carril opuesto, todavía a cierta distancia por delante. ¿A qué distancia está obligado a bajar las luces altas a luces bajas para no encandilar al conductor que se aproxima?","options":["A menos de 250 pies del vehículo que se aproxima, ya que esa es la distancia que sus luces bajas iluminan la carretera","A menos de 200 pies del vehículo que se aproxima, la misma distancia a la que coloca su triángulo de advertencia más lejano","A menos de 500 pies del vehículo que se aproxima (y también cuando sigue a otro vehículo a menos de 500 pies)","Solo cuando el vehículo que se aproxima le hace señales con sus propias luces para indicar que las suyas son demasiado brillantes"],"explanation":"Baje las luces altas dentro de los 500 pies de un vehículo que se aproxima y al seguir a otro vehículo dentro de los 500 pies para evitar deslumbrarlo."},"356":{"q":"Va conduciendo un remolque cargado por una carretera rural de dos carriles cuando una alerta de bajo nivel de refrigerante lo obliga a apagar el motor. No hay salida durante varias millas, pero ve un arcén de grava ancho más adelante. Antes incluso de tomar sus triángulos de advertencia, ¿qué es lo PRIMERO que debe hacer para que la parada sea lo más segura posible?","options":["Detenerse en su carril de circulación y colocar de inmediato los tres triángulos a 10, 100 y 200 pies para advertir al tráfico antes que nada","Dejarse rodar hasta detenerse en la siguiente curva para que su vehículo se vea desde ambos lados, y encender los faros","Reducir la velocidad y quedarse sobre la línea divisoria dejando parte del camión sobre el pavimento, manteniendo el arcén libre para vehículos de emergencia","Salirse por completo del pavimento hacia el arcén de grava y encender las luces intermitentes de emergencia (las cuatro direccionales)"],"explanation":"Salga completamente de la calzada hacia el acotamiento y encienda de inmediato las luces intermitentes de emergencia para advertir al tráfico que se aproxima."},"357":{"q":"Entra a un área de descanso en una leve pendiente cuesta abajo para dar una vuelta rápida e inspeccionar el aseguramiento de la carga. El motor sigue encendido y planea estar fuera de la cabina solo un minuto o dos. Antes de bajar para salir, ¿cuál es la única acción más importante para evitar que el vehículo ruede?","options":["Poner el freno de estacionamiento.","Poner la transmisión en la marcha de avance más baja y dejarla ahí.","Girar bruscamente las ruedas delanteras hacia el bordillo y encender las luces intermitentes de emergencia.","Presionar y mantener firmemente el freno de servicio (de pie) hasta que esté listo para regresar."],"explanation":"Ponga siempre el freno de estacionamiento antes de salir de la cabina, ya que es el único dispositivo diseñado para sujetar mecánicamente un vehículo estacionado sin el conductor."},"358":{"q":"Conduce un tractocamión cargado por una carretera rural a 55 mph. Hay poco tráfico y la vía es recta, así que decide fijar conscientemente la vista en un punto lo bastante lejano para detectar vehículos averiados, escombros o tráfico que se incorpora a tiempo de reaccionar con suavidad en lugar de frenar bruscamente. Medido en TIEMPO a esta velocidad, ¿qué tan adelante debería estar mirando?","options":["De 5 a 8 segundos adelante, el mismo intervalo que debe usar para revisar los espejos","De 12 a 15 segundos adelante, lo que equivale aproximadamente a un cuarto de milla a velocidad de carretera","Unos 6 segundos adelante, que es su distancia total de frenado a 55 mph","Un cuarto de milla exacto medido solo en pies, no en segundos de recorrido"],"explanation":"Mire de 12 a 15 segundos por delante, aproximadamente un cuarto de milla a velocidad de autopista, para detectar peligros temprano y reaccionar con suavidad y no con pánico."},"359":{"q":"Transporta una carga de bobinas de acero en un remolque de plataforma (flatbed) por una autopista interestatal con mucho tráfico a velocidad de carretera. El tráfico es denso y los vehículos entran y salen constantemente de los carriles a su alrededor. Quiere mantenerse consciente de lo que ocurre en todos los lados de su equipo para reaccionar a tiempo ante un automóvil que se le cruza o ante un problema de neumático en su remolque. ¿Qué enfoque para usar los espejos se ajusta mejor a la práctica de conducción comercial segura?","options":["Mirar los espejos una vez después de cada incorporación o cambio de carril, ya que es cuando es más probable que otros vehículos estén a su lado","Esperar hasta sentir que el remolque tira o escuchar un ruido inusual antes de revisar, para mantener la vista en la carretera por delante el resto del tiempo","Revisar los espejos con regularidad, aproximadamente cada 5 a 8 segundos, para seguir continuamente el tráfico y el estado de su vehículo por todos los lados","Revisar los espejos solo al inicio y al final del viaje, y el resto del tiempo concentrarse por completo en el camino 12 a 15 segundos por delante"],"explanation":"Revise los espejos con regularidad, cada 5 a 8 segundos aproximadamente, para mantenerse atento al tráfico, los puntos ciegos y el estado de su equipo y carga."},"360":{"q":"Conduce un tractocamión cargado a una velocidad constante de 55 mph en el carril derecho de una autopista dividida cuando un automóvil comienza a rebasarlo por su izquierda. A mitad del rebase, el auto se demora en su punto ciego del lado izquierdo y parece dudar en completar la maniobra. Para brindarle al conductor que rebasa la situación más segura y predecible, ¿qué acción debe tomar?","options":["Soltar el acelerador y frenar suavemente para que el auto despeje su parachoques delantero más pronto","Desplazarse un poco hacia el borde derecho de su carril para abrir más espacio del lado del conductor","Acelerar brevemente para ayudar al auto a terminar el rebase y volver a su carril más rápido","Mantener su posición en el centro de su carril y conservar una velocidad constante hasta que el auto lo haya rebasado por completo y regresado adelante"],"explanation":"Cuando otro vehículo lo está rebasando, mantenga su carril y una velocidad constante para que el conductor que rebasa pueda calcular el espacio y completar el rebase con seguridad."},"361":{"q":"Se aproxima a un paso inferior desconocido que tiene un letrero de altura libre permitida, y su remolque va cargado con una pila alta de maquinaria embalada en cajones. De las siguientes cifras, ¿cuál necesita conocer con certeza con MAYOR razón antes de decidirse a pasar por debajo de ese puente?","options":["La altura total de su vehículo cargado, medida desde el suelo hasta su punto más alto","El peso total exacto del conjunto cargado en la báscula","La cantidad de combustible que hay actualmente en sus tanques","La marca y el modelo de las llantas montadas en los ejes de tracción"],"explanation":"Conozca la altura total de su vehículo cargado desde el suelo hasta su punto más alto y compárela con la altura libre indicada antes de pasar bajo un puente o paso a desnivel."},"362":{"q":"Está planificando la ruta de un remolque de cama baja (low-boy) cargado con una excavadora a través de un antiguo distrito industrial. Más adelante, la carretera baja por debajo de un viejo puente ferroviario y varios cables eléctricos aéreos cuelgan cruzando la calle. Antes de decidir pasar por debajo de ellos, ¿cuál medida es la MÁS crítica que debe verificar frente a los límites señalizados y conocidos para evitar un accidente grave?","options":["La presión de los neumáticos del eje delantero (de dirección), ya que un neumático delantero bajo podría hacer que el camión se hunda y enganche los cables","Su altura de gálibo superior (despeje vertical), comparando la altura total del camión cargado con el gálibo señalizado del puente y la altura de los cables","Su peso bruto combinado nominal (GCWR), para confirmar que el puente y la carretera puedan soportar con seguridad el camión cargado","Su distancia de seguimiento con el vehículo de adelante, para no verse obligado a frenar bruscamente bajo la estructura"],"explanation":"Compare la altura libre total de su rig cargado con la altura indicada del puente y la altura de los cables aéreos para asegurarse de que pueda pasar con seguridad por debajo."},"363":{"q":"Se aproxima a una intersección de cuatro vías en su vehículo combinado cargado cuando un automóvil a su izquierda avanza y reclama agresivamente el derecho de paso que legalmente le corresponde a usted. Ya ha comenzado a reducir la velocidad. ¿Cuál es la MEJOR acción en esta situación?","options":["Mantener su velocidad y continuar, ya que el derecho de paso legalmente es suyo y el automóvil debe ceder","Tocar la bocina repetidamente y continuar hacia la intersección para imponer su posición","Ceder y dejar pasar al otro conductor, aunque legalmente usted tenga el derecho de paso, para evitar una colisión","Acelerar para despejar la intersección antes de que el automóvil pueda entrar en su trayectoria"],"explanation":"El primer deber de un conductor profesional es evitar una colisión, así que ceda el paso y deje pasar al otro conductor aunque usted tenga legalmente el derecho de paso."},"364":{"q":"Está trazando la ruta de su vehículo combinado cargado hacia una entrega y el GPS lo envía sobre un puente del condado con un límite de peso señalizado que es MENOR que su peso bruto combinado real. Existe una ruta alterna legal que añade 12 millas. ¿Qué debe hacer?","options":["Cruzar el puente pero acelerar para que su peso total descanse sobre la estructura el menor tiempo posible","Cruzar despacio y a paso constante, ya que los límites de peso señalizados en puentes son orientativos y solo se aplican cuando el camión va vacío","Detenerse sobre el puente para verificar el peso de sus ejes antes de continuar","No cruzar el puente; tomar la ruta alterna legal para nunca exceder el límite de peso señalizado"],"explanation":"El límite de peso indicado en un puente es un máximo legal estricto, así que si su peso bruto lo excede, nunca cruce y tome la ruta alterna legal en su lugar."},"365":{"q":"Está bajando con una carga pesada por una pendiente de montaña larga y empinada. Aunque es un día frío, después de varias millas pisa el pedal del freno y nota que el camión apenas reduce la velocidad y los frenos se sienten débiles y esponjosos. ¿Cuál es la causa MÁS probable de esta pérdida de potencia de frenado?","options":["Los frenos se sobrecalentaron por usarse de forma demasiado intensa y prolongada en el descenso, provocando el desvanecimiento del freno (brake fade)","El aire frío del exterior congeló la humedad en las líneas de freno y redujo su agarre","Las balatas (forros) de freno son demasiado nuevas y aún no se han asentado para agarrar bien","Frenó de manera demasiado suave y cuidadosa, por lo que las balatas nunca se calentaron lo suficiente para sujetar"],"explanation":"El frenado fuerte y prolongado en una bajada larga sobrecalienta los frenos, haciéndoles perder fricción y capacidad de frenado aunque se pise el pedal."},"367":{"q":"Conduce un remolque cargado por el carril derecho de una autopista dividida al límite de velocidad permitido. Un conductor detrás de usted lo ha venido siguiendo demasiado cerca durante varias millas, luego lo rebasa bruscamente, se mete de golpe delante de usted, frena y sigue haciéndole gestos para que acelere o se aparte. El tráfico adelante es moderado. ¿Cuál es la forma más segura y correcta de lidiar con este conductor agresivo?","options":["Acelerar para igualar la velocidad del otro conductor, de modo que deje de seguirlo de cerca y se aleje de usted","Soltar el acelerador, aumentar su distancia de seguimiento y dejar que el conductor agresivo se adelante bastante y se aleje de usted","Mantener su posición exacta y tocar levemente los frenos para indicarle al conductor que se retire","Moverse a la izquierda para impedir que el conductor agresivo lo vuelva a rebasar hasta que se calme"],"explanation":"La respuesta más segura ante un conductor agresivo es apartarse de su camino soltando el acelerador y aumentando la distancia de seguimiento para que se adelante."},"368":{"q":"Acaba de terminar un descanso de 45 minutos para comer en una parada de camiones y su tractocamión cargado está estacionado en paralelo a lo largo del arcén derecho de una vía de servicio. El tráfico circula a su izquierda. Está listo para reincorporarse al carril de circulación. ¿Cuál secuencia de acciones es la forma más segura y correcta de salir de esta posición de estacionamiento?","options":["Salir derecho de inmediato para incorporarse al hueco en el tráfico y encender la señal izquierda solo cuando ya esté en movimiento","Tocar la bocina para alertar a los conductores cercanos, soltar los frenos y acelerar hacia el carril sin demora","Encender la señal izquierda, revisar los espejos y el área alrededor del vehículo en busca de tráfico y puntos ciegos, y salir solo cuando esté despejado","Revisar solo el espejo del lado del conductor y, si parece despejado, salir con cuidado al carril mientras vigila el hueco"],"explanation":"Antes de salir de un estacionamiento, primero señalice, luego revise los espejos y toda el área alrededor del vehículo por tráfico y puntos ciegos, y salga solo cuando esté despejado."},"370":{"q":"Conduce un tractocamión cargado a velocidad de carretera por una vía de dos carriles sin separación central. Un auto que viene de frente se ha cruzado la línea central y ahora está parcialmente en su carril, acercándose rápido. No hay tiempo de detenerse antes del impacto. A su derecha hay un acotamiento pavimentado y una zanja poco profunda con pasto; a su izquierda está el carril contrario con tráfico. ¿Qué acción le da la mejor probabilidad de evitar un choque de frente?","options":["Girar a la izquierda hacia el carril contrario para rodear al auto que se desvió","Mantener su carril y frenar lo más fuerte posible, bloqueando las ruedas si hace falta","Quedarse centrado, hacer cambio de luces altas y mantener la velocidad","Girar a la derecha hacia el acotamiento, aunque implique salirse del pavimento"],"explanation":"Cuando un vehículo en sentido contrario invade su carril, gire a la derecha hacia el arcén, ya que el conductor puede corregir y girar a la izquierda arriesga un choque frontal."},"371":{"q":"Conduce cargado a velocidad de autopista en una calurosa tarde de julio cuando de repente oye un fuerte \"estallido\" en la parte delantera del tractor. No sintió ninguna vibración ni golpeteo en el asiento antes. Al sujetar el volante, ¿cuál de los siguientes le indicaría MÁS claramente que fue una llanta DELANTERA la que reventó, y no una trasera?","options":["La dirección se vuelve de repente muy dura y el camión tira con fuerza hacia un lado","Siente una fuerte vibración o golpeteo que sube por el asiento y el piso de la cabina","La parte trasera del remolque empieza a colear y a balancearse de lado a lado","El indicador de temperatura del motor sube y el camión empieza a perder potencia"],"explanation":"El reventón de una llanta delantera hace que la dirección se vuelva muy dura de repente y jala el camión con fuerza hacia la llanta dañada."},"372":{"q":"Va circulando cargado por una carretera plana de dos carriles a unas 50 mph cuando de repente siente que la parte trasera de su remolque empieza a balancearse y a serpentear de un lado a otro, aunque el volante todavía se siente normal y usted no ha tocado los frenos. Según estos síntomas, ¿cuál conclusión es la MÁS acertada sobre lo que probablemente ha ocurrido?","options":["Una llanta delantera (del eje de dirección) ha perdido aire, y por eso la parte trasera ahora se desvía por el carril","Una llanta trasera ha fallado, porque el reventón de una llanta trasera suele hacer que el vehículo se balancee o colee (fishtail)","Los frenos del remolque se han bloqueado, lo que arrastra la parte trasera de costado","Ha iniciado un derrape de las ruedas motrices por aceleración y debe girar de inmediato con fuerza hacia el otro lado"],"explanation":"La falla de una llanta trasera hace que el vehículo se balancee o coletee mientras la dirección sigue sintiéndose relativamente normal."},"373":{"q":"Va remolcando un tráiler vacío por una carretera mojada de dos carriles cuando un automóvil sale de repente de un camino lateral más adelante. Pisa con fuerza el pedal del freno y siente que el ABS (sistema de frenos antibloqueo) se activa. ¿Qué afirmación describe MEJOR lo que su sistema de frenos antibloqueo está haciendo por usted en este momento?","options":["Está reduciendo su distancia total de frenado aproximadamente a la mitad de lo que sería sin ABS, de modo que se detiene mucho antes que el automóvil.","Está reduciendo la marcha automáticamente y aplicando el freno de motor para detener el conjunto de forma controlada.","Está evitando que sus ruedas se bloqueen para que pueda seguir dirigiendo y mantener el control mientras frena con fuerza.","Está dosificando la presión de frenado para que el remolque vacío se detenga en una distancia más corta que uno cargado."],"explanation":"El ABS evita que las ruedas se bloqueen durante un frenado fuerte para que pueda seguir dirigiendo y mantener el control para esquivar el peligro."},"374":{"q":"Conduce un tractocamión cargado equipado con frenos antibloqueo (ABS) cuando un automóvil se le cruza de repente y frena en seco. Necesita hacer una parada de emergencia fuerte en su carril sobre pavimento seco. Sabiendo cómo está diseñado para funcionar el ABS, ¿qué acción de frenado le da el mejor control y la parada segura más corta?","options":["Bombear el pedal del freno rápidamente para evitar que las ruedas se bloqueen, como lo haría sin ABS","Aplicar frenado intermitente controlado (stab), soltando el pedal cada vez que las ruedas empiecen a bloquearse","Pisar el freno solo suavemente y esquivar el auto, ya que el ABS acorta su distancia de frenado","Pisar el pedal del freno con firmeza, mantener una presión constante y dirigir según sea necesario mientras el ABS actúa"],"explanation":"Con ABS, frene presionando firme y manteniendo una presión constante y continua mientras dirige, dejando que el sistema evite el bloqueo de las ruedas."},"375":{"q":"Conduce un remolque parcialmente cargado (sin ABS) por una carretera estatal cuando un automóvil sale de repente de una vía lateral justo frente a usted. Debe detenerse lo más rápido físicamente posible sin perder la capacidad de girar para esquivar el peligro si no logra detenerse a tiempo. ¿Qué método de frenado debe usar?","options":["Aplicar frenado controlado o intermitente (stab), manteniendo las ruedas justo al borde del bloqueo","Pisar el freno hasta el fondo y mantenerlo firme para bloquear las ruedas y lograr la distancia más corta","Frenar de forma ligera y constante, como lo haría en una bajada larga","Aplicar solo la válvula manual del remolque para que las ruedas del tractor queden libres para girar"],"explanation":"Sin ABS, el frenado controlado o intermitente que mantiene las ruedas justo antes del bloqueo da la máxima fuerza de frenado conservando la dirección."},"376":{"q":"Conduce un tractocamión con remolque cargado y frenos estándar (sin ABS) cuando un automóvil se le atraviesa de repente y debe frenar con fuerza para evitar un choque. Aplica los frenos a fondo y siente que las ruedas se bloquean. Para usar correctamente el frenado intermitente (stab) y mantener el control del vehículo, ¿qué debe hacer en el instante en que las ruedas se bloquean?","options":["Mantener presión total y constante en el pedal y conservar las ruedas bloqueadas hasta detenerse por completo","Soltar los frenos hasta que las ruedas vuelvan a girar, y luego volver a aplicar los frenos a fondo","Bombear el pedal del freno lo más rápido posible, tres o cuatro veces por segundo, hasta detenerse","Quitar el pie del freno por completo, apagar el motor y dejar que el vehículo ruede libre hasta parar"],"explanation":"En el frenado intermitente, suelte los frenos hasta que las ruedas bloqueadas vuelvan a girar para recuperar la dirección, y luego vuelva a frenar a fondo."},"377":{"q":"Circula detrás de un transportador de autos cargado en una autopista seca de cuatro carriles a 55 mph, manteniendo varios segundos de carretera libre entre usted y el camión de adelante. De repente, una camioneta que se incorpora se mete en ese espacio y se encienden las luces de freno del transportador. ¿Por qué mantener ese colchón de espacio fue lo más importante que hizo para manejar esta situación con seguridad?","options":["Le permitió mantener las 55 mph sin soltar el acelerador, de modo que el tráfico detrás de usted siguió fluyendo sin problemas","Garantizó una parada completa en unos 60 pies, que es la distancia total de frenado a 55 mph","Le dio espacio y tiempo adicionales para percibir el peligro y reaccionar antes de tener que frenar con fuerza","Mantuvo su distancia de seguimiento por debajo de un segundo, el espacio que el manual recomienda para velocidades de autopista"],"explanation":"Un colchón de espacio le da margen y tiempo extra para detectar un peligro y reaccionar antes de frenar bruscamente, ya que la distancia de frenado a alta velocidad es mucho mayor de lo que parece."},"378":{"q":"Conduce un tractocamión completamente cargado a 55 mph en buenas condiciones secas cuando un automóvil en el carril contiguo frena bruscamente ante el mismo peligro que ambos ven en el mismo instante. Sabiendo cómo se comporta un camión cargado en comparación con ese automóvil, ¿qué afirmación debe guiar cuánto espacio se deja a sí mismo?","options":["El camión cargado y el automóvil se detendrán en aproximadamente la misma distancia, ya que ambos tienen buenos frenos","El camión cargado se detendrá en mucha menos distancia porque su gran peso presiona los neumáticos contra el suelo y mejora el agarre","No hay diferencia, porque a 55 mph cualquier vehículo necesita unos 60 pies para reaccionar y detenerse","El camión cargado necesita mucha más distancia para detenerse que el automóvil, por lo que debe dejar mucho más espacio y empezar a frenar antes"],"explanation":"La mucho mayor masa e inercia de un camión cargado hacen que su distancia total de frenado sea mucho mayor que la de un auto, por lo que debe dejar más espacio y empezar a frenar antes."},"379":{"q":"Circula a velocidad de carretera por una vía de dos carriles y un motociclista se incorpora a su mismo carril justo delante de usted, conduciendo cerca del borde derecho del carril. El tráfico es moderado y se aproxima una zona de adelantamiento. ¿Cuál es la forma más segura de gestionar su distancia de seguimiento detrás de esta motocicleta?","options":["Trate la motocicleta como un vehículo de tamaño completo: déjele todo el carril y sígala con distancia adicional, porque puede detenerse en mucho menos espacio que usted","Acérquese en su carril y comparta con la motocicleta la parte izquierda libre del carril, ya que una moto solo necesita parte de un carril","Colóquese detrás a su distancia normal de un largo de coche, porque una motocicleta es más pequeña y necesita menos espacio que un automóvil","Manténgase pegado y prepárese para adelantar de inmediato en la zona de adelantamiento, ya que el verdadero peligro es quedarse detrás de una moto lenta"],"explanation":"Una motocicleta tiene derecho a todo el carril y puede detenerse en mucha menos distancia que un camión pesado, así que cédale el carril completo y siga con espacio extra."},"380":{"q":"Usted se acerca a una intersección rural con su vehículo combinado cargado (tractocamión con remolque). El semáforo está apagado (completamente fuera de servicio) y no hay señales de alto ni de ceda el paso en ninguna dirección. Al acercarse a la intersección, ve una camioneta que llegó un instante antes que usted y que ya está detenida en la calle transversal a su derecha, esperando para avanzar. ¿Cuál es la acción correcta?","options":["Avanzar primero, porque un vehículo combinado cargado necesita más espacio y tiene la preferencia de paso sobre vehículos más livianos","Cederle el paso a la camioneta, porque llegó primero a la intersección y además está a su derecha","Tratar el semáforo apagado como su luz verde y continuar sin reducir la velocidad","Detenerse en el centro de la intersección para que el tránsito transversal lo vea antes de iniciar la maniobra"],"explanation":"En una intersección sin control debe ceder el paso al vehículo que llegó primero y, si llegan casi al mismo tiempo, al que está a su derecha."},"381":{"q":"Son las 3:15 p. m. de un día laborable despejado y conduce un camión rígido cargado por una zona residencial cuando ve una baliza amarilla intermitente y una señal de zona escolar. El tráfico a su alrededor sigue circulando al límite normal de 30 mph y la vía por delante parece despejada. ¿Cuál es la MEJOR acción a tomar?","options":["Mantener el límite señalizado de 30 mph, ya que el carril por delante está despejado y los demás vehículos no reducen la velocidad","Cambiarse al carril izquierdo y adelantar rápidamente a los autos más lentos para salir de la zona antes de que aparezcan los niños","Reducir la velocidad por debajo del límite señalizado y explorar con atención las aceras y los cruces peatonales en busca de niños que puedan salir corriendo a la vía","Mantener la velocidad pero encender las luces altas para que conductores y peatones vean su camión con mayor claridad"],"explanation":"Una luz intermitente indica que la zona escolar de velocidad reducida está activa, así que baje de la velocidad límite y vigile aceras y cruces por niños que puedan salir de repente."},"382":{"q":"Usted se acerca a una zona de construcción en la carretera donde la señal elevada de carril muestra una flecha verde para su carril, pero un señalero (flagger) parado en la vía sostiene una paleta de PARE (STOP) dirigida hacia usted. ¿Qué debe hacer?","options":["Avanzar lentamente por la zona, ya que la flecha verde autoriza legalmente que su carril continúe","Detenerse solo si el señalero también toca un silbato o agita ambos brazos; de lo contrario, seguir la flecha verde","Tratar el conflicto como una falla y avanzar con precaución a no más de 15 mph","Detenerse y obedecer al señalero, porque las indicaciones de un señalero tienen prioridad incluso sobre las señales normales"],"explanation":"Las indicaciones de un señalero tienen prioridad sobre todas las señales y semáforos, porque conoce en tiempo real los peligros de la zona de obras que una señal fija no refleja."},"383":{"q":"Conduce su tractocamión por el carril derecho de una autopista de cuatro carriles sin división central cuando oye una sirena y ve que una ambulancia se acerca por detrás con sus luces de emergencia encendidas. El tráfico adelante es ligero y el acotamiento derecho es amplio y está despejado. ¿Cuál es la acción correcta?","options":["Señalice, muévase hacia el borde derecho de la carretera y detenga el vehículo hasta que la ambulancia haya pasado","Mantenga su carril y velocidad para que la ambulancia pueda predecir su trayectoria y rodearlo","Cámbiese al carril izquierdo y deténgase allí para dejar todo el lado derecho libre para la ambulancia","Acelere para mantenerse adelante del tráfico y busque una calle lateral para desviarse"],"explanation":"Cuando un vehículo de emergencia se acerca con luces y sirena, señalice, oríllese al borde derecho de la vía y deténgase hasta que haya pasado."},"384":{"q":"Le asignan un remolque tipo furgón cargado que transporta cajas ligeras apiladas del piso al techo, llenando el remolque hasta arriba. En comparación con el mismo remolque transportando carga densa y pesada apilada solo hasta la altura de la rodilla sobre el piso, ¿qué afirmación es la MÁS precisa sobre cómo la carga alta y de peso superior afecta su conducción?","options":["El apilamiento más alto baja el centro de gravedad, por lo que puede tomar rampas y curvas con seguridad a las velocidades señaladas para camiones","El centro de gravedad alto hace que el remolque tenga más probabilidad de volcar en curvas y rampas, por lo que debe reducir la velocidad mucho antes de entrar en ellas","Como la carga es ligera, el centro de gravedad no influye en el riesgo de vuelco y solo importa para la distancia de frenado","El centro de gravedad alto aumenta principalmente su distancia de frenado, así que el verdadero peligro es chocar por detrás al vehículo de adelante"],"explanation":"Apilar la carga muy alto eleva el centro de gravedad aunque sea liviana, haciendo mucho más probable un vuelco en curvas y rampas, así que reduzca la velocidad bastante antes."},"385":{"q":"Conduce una cisterna cargada y se acerca a una rampa de salida tipo trébol con una velocidad recomendada de 35 mph. El tráfico detrás de usted es intenso y le gustaría seguir avanzando. Repasando qué causa con mayor frecuencia que los camiones vuelquen, ¿cuál es el único factor que más contribuye y que más debería preocuparle en esta rampa?","options":["Una carga equilibrada demasiado baja, que deja el centro de gravedad del remolque peligrosamente cerca de la superficie de la carretera","Seguir al vehículo de adelante un segundo entero demasiado cerca al entrar en la curva","Llevar una velocidad demasiado alta a través de la curva de la rampa en lugar de reducirla antes de entrar en ella","Frenar con demasiada suavidad con los frenos del remolque mientras aún está en la aproximación recta antes de la rampa"],"explanation":"La causa más común de vuelco de un camión es tomar una curva o rampa demasiado rápido, así que reduzca a una velocidad segura antes de entrar a la curva, no dentro de ella."},"386":{"q":"Transporta una carga alta de cajas de maquinaria apiladas y sale de la autopista hacia una rampa de entrada/salida con curva señalizada a 30 mph. Su camión va muy cargado y tiene un centro de gravedad alto. ¿Qué acción le ofrece la mejor protección contra una volcadura en la rampa?","options":["Mantener constantes 30 mph porque es la velocidad señalizada de la rampa y el letrero ya tiene en cuenta los camiones","Mantener la velocidad de autopista hasta sentir que el remolque empieza a inclinarse, y entonces frenar fuerte en la curva","Pasar la curva en punto muerto para que el motor no lo empuje más rápido","Reducir a una velocidad muy por debajo de la velocidad señalizada de la rampa antes de entrar en la curva, ya que la señal está fijada para automóviles, no para una carga alta y pesada"],"explanation":"Las señales de velocidad de rampa se fijan para autos, así que con una carga alta y pesada reduzca muy por debajo de la velocidad indicada antes de entrar a la curva para no volcar."},"387":{"q":"Termina una entrega y estaciona su camión rígido cargado en una calle empinada con pendiente descendente, pegándose bien contra el bordillo del lado derecho. Antes de poner el freno de estacionamiento y bajar de la cabina, quiere dejar las ruedas delanteras de modo que, si los frenos llegaran a soltarse, el camión ruede HACIA el bordillo y este lo detenga, en lugar de irse hacia el carril de tráfico que baja. ¿Cómo debe dejar giradas las ruedas delanteras?","options":["Giradas hacia el bordillo (a la derecha), para que al rodar el bordillo bloquee el neumático delantero","Giradas en sentido contrario al bordillo (a la izquierda), para que la parte trasera del camión se apoye en el bordillo","Dejadas rectas, ya que es el freno de estacionamiento puesto lo que en realidad sostiene el camión en la pendiente","Giradas hacia el bordillo solo si no hay bordillo, de lo contrario rectas"],"explanation":"Al estacionar cuesta abajo con bordillo, gira las ruedas delanteras hacia el bordillo para que, si rueda, la llanta lo tope y detenga el camión."},"388":{"q":"Se detiene en una carretera de montaña empinada para revisar la carga y estaciona el camión orientado CUESTA ARRIBA, con el bordillo (cordón) a la derecha. Antes de alejarse, quiere que, si los frenos se sueltan, el camión ruede hacia atrás y quede detenido contra el bordillo. Para colocar correctamente las ruedas delanteras en esta situación de cuesta arriba con bordillo, debe:","options":["Girar las ruedas delanteras hacia el bordillo (a la derecha) para que la llanta lo toque de frente","Girar las ruedas delanteras en sentido contrario al bordillo (a la izquierda) para que, al rodar hacia atrás, la parte trasera de la llanta quede contra el bordillo","Dejar las ruedas delanteras rectas y confiar solo en el freno de estacionamiento","Girar las ruedas delanteras bruscamente a la derecha, igual que haría si no hubiera bordillo"],"explanation":"Al estacionar cuesta arriba con bordillo, gira las ruedas delanteras hacia afuera para que, si rueda hacia atrás, la llanta lo tope y detenga el camión."},"389":{"q":"Va siguiendo a una motocicleta por una calle urbana seca y ajusta su distancia de seguimiento según cómo se ha estado moviendo el motociclista. ¿Cuál es la suposición MÁS importante que debe prever sobre esa motocicleta para no chocarla por detrás?","options":["Siempre irá muy por debajo del límite de velocidad, así que un espacio corto es seguro","Necesita el espacio de dos carriles completos, así que nunca debe ponerse a su lado","Puede pasar desapercibida fácilmente en el tráfico y puede frenar mucho más rápido que su camión","Mantendrá una velocidad constante y no reducirá la velocidad de forma repentina"],"explanation":"Las motocicletas son difíciles de ver en el tráfico y pueden frenar en mucha menos distancia que un camión pesado, así que deja más espacio detrás."},"390":{"q":"Conduce un remolque cargado y comienza una bajada larga y empinada en condiciones secas y de día. Un novato que va con usted pregunta cómo afecta esta bajada a la distancia que necesitará su unidad para detenerse por completo, en comparación con frenar en pavimento llano a la misma velocidad. ¿Cuál afirmación es correcta?","options":["No influye en su distancia de frenado, porque la distancia total de frenado es fija en unos 419 pies a 55 mph, sin importar la pendiente de la carretera.","Su distancia de frenado se acorta mucho, porque la gravedad que tira del camión cuesta abajo presiona más las llantas contra el pavimento y mejora la tracción al frenar.","Su distancia de frenado cae brevemente casi a cero una vez que el motor y las marchas asumen el frenado en la pendiente.","Su distancia de frenado aumenta, porque la gravedad se suma a su impulso cuesta abajo y los frenos deben trabajar más a lo largo de una distancia mayor para detener la unidad."],"explanation":"En una bajada la gravedad se suma al impulso, así que los frenos deben trabajar más sobre una distancia mayor y aumenta la distancia de frenado."},"391":{"q":"Conduce con un remolque cargado por una carretera rural y se aproxima a una curva cerrada con una señal amarilla de advertencia que indica 'VELOCIDAD SEGURA 40 MPH'. El pavimento está seco y el tráfico es ligero. ¿Qué afirmación describe mejor cómo usted, como conductor con CDL, debe interpretar esa velocidad recomendada?","options":["La cifra de 40 mph se calcula para automóviles de pasajeros, por lo que como camión cargado con un centro de gravedad más alto debe entrar en la curva por debajo de ella para evitar un vuelco.","Como la señal es una advertencia oficial, 40 mph es la velocidad máxima legal para todos los vehículos, y los camiones pueden tomar la curva a exactamente 40 mph mientras la vía esté seca.","La advertencia se aplica solo a remolques vacíos; como su remolque está cargado y estable, puede superar las 40 mph en la curva.","Las velocidades recomendadas se publican específicamente para camiones, así que 40 mph ya incluye un margen de seguridad para camiones y puede igualarla sin reducir más la velocidad."],"explanation":"Las velocidades recomendadas en curvas se calculan para autos, así que un camión cargado con centro de gravedad alto debe entrar por debajo de la velocidad indicada para evitar volcar."},"393":{"q":"Termina un largo viaje de entrega y entra al patio. Esta mañana, antes de la inspección previaje, todo estaba en orden, y también volvió a revisar la sujeción de la carga dentro de las primeras 50 millas y de nuevo cada 150 millas en ruta. Ahora que el viaje terminó y el camión está estacionado, ¿qué inspección debe realizar para completar el ciclo completo de inspección que el DPS espera de usted?","options":["No se necesita ninguna inspección adicional porque sus revisiones en ruta cada 150 millas ya cubrieron el vehículo durante el día","Una inspección posviaje, para que cualquier defecto surgido durante el viaje quede documentado antes del próximo conductor o de su próximo turno","Una inspección anual, ya que es la única inspección formal requerida una vez terminada la conducción diaria","Una inspección mensual de los frenos y las llantas para cerrar el desgaste del viaje"],"explanation":"La inspección posterior al viaje se hace al final del recorrido para documentar en un informe cualquier defecto surgido al conducir antes del próximo turno."},"395":{"q":"Acaba de terminar un recorrido de 11 horas y entró al patio. Durante el viaje los frenos se sentían algo blandos y notó que una luz de posición parpadeaba y se apagaba. Como parte de completar correctamente su inspección posterior al viaje, ¿cuál de los siguientes documentos se espera generalmente que llene y, donde se requiera, entregue para que el siguiente conductor y el transportista sean advertidos de estas condiciones?","options":["El registro de recibos de compra de combustible y kilometraje que lleva para la declaración de impuestos IFTA","Su diario personal del viaje anotando cómo fue el día y dónde paró a descansar","Un informe de inspección del vehículo por el conductor (DVIR) que documenta cualquier defecto, como los frenos blandos y la luz de posición que falla","Un informe del clima y del estado de la carretera para los registros del despachador"],"explanation":"La inspección posterior al viaje exige completar un informe de inspección del conductor (DVIR) que documente todo defecto de seguridad, como frenos blandos y una luz de gálibo averiada."},"396":{"q":"Es una mañana fría y acaba de arrancar el motor para comenzar el calentamiento previo al viaje. Está observando los indicadores del tablero para asegurarse de que todo funcione antes de salir. ¿Cuál de las siguientes es la expectativa correcta para el indicador de presión de aceite e indica que el motor es seguro para operar?","options":["La aguja debe subir lentamente y alcanzar la presión normal después de varios minutos al ralentí, una vez que el aceite se haya calentado","Como la mañana es fría, debe dejarlo al ralentí cerca de una hora antes de que la presión de aceite sea confiable","La presión de aceite no necesita registrarse hasta que esté en movimiento bajo carga en la carretera","La aguja debe alcanzar la presión de operación normal en cuestión de pocos segundos después de arrancar el motor"],"explanation":"La presión de aceite debe alcanzar la presión normal de operación pocos segundos después de arrancar el motor, o debes apagarlo para evitar daños."},"397":{"q":"Lleva 40 minutos de viaje en una carretera rural de dos carriles cuando mira los indicadores y ve que el manómetro de presión de aceite ha caído a cero, aunque el motor todavía suena y funciona con normalidad y aún no ha sonado ninguna alarma. ¿Cuál es la acción correcta?","options":["Salirse de la carretera en cuanto sea seguro, detenerse y apagar el motor","Seguir conduciendo normalmente hasta la próxima parada de camiones, ya que el motor todavía suena bien","Mantener la velocidad pero aliviar el acelerador y continuar hasta su parada de combustible programada","Apagar accesorios no esenciales como la radio y el aire acondicionado para reducir la carga del motor y seguir conduciendo"],"explanation":"La pérdida de presión de aceite significa que el motor ya no se lubrica, así que sal de la vía en cuanto sea seguro y apaga el motor de inmediato."},"398":{"q":"Está subiendo una pendiente larga en una tarde calurosa de verano, completamente cargado y cerca de su GVWR. Al acercarse a la cima, una de las agujas del tablero empieza a subir hacia la zona roja. Antes de decidir cómo reaccionar, ¿cuál es el medidor diseñado específicamente para advertirle que el motor mismo se está sobrecalentando?","options":["El medidor de presión de aceite, porque el calor adelgaza el aceite y la aguja sube para advertir de la alta temperatura del motor","El medidor de temperatura del refrigerante, porque mide la temperatura del refrigerante del motor y le advierte que el motor se está sobrecalentando","El pirómetro, porque mide el calor de los gases de escape, que en un día caluroso equivale al sobrecalentamiento del motor","El voltímetro, porque una subida larga en un día caluroso sobrecalienta el sistema de carga e indica el sobrecalentamiento del motor"],"explanation":"El indicador de temperatura del refrigerante mide la temperatura del refrigerante del motor y te avisa cuando el motor se está sobrecalentando."},"399":{"q":"Durante su inspección previaje, arranca el motor y observa los indicadores del tablero mientras el camión está en ralentí. Nota que la aguja del amperímetro (o voltímetro) se mantiene estable dentro del rango normal y no baja ni oscila de forma errática. ¿Qué le está indicando realmente este medidor sobre su vehículo?","options":["La presión del aceite del motor es lo suficientemente alta para comenzar el viaje con seguridad","La temperatura del refrigerante está dentro del rango de funcionamiento seguro","El sistema de carga está funcionando y mantiene la batería correctamente cargada","La batería tiene suficiente agua en sus celdas y está sujeta firmemente con pernos"],"explanation":"Una lectura estable del amperímetro o voltímetro en el rango normal confirma que el alternador genera corriente y mantiene la batería bien cargada."},"400":{"q":"Durante su inspección previaje, agarra el volante de su tractocamión y lo mueve de un lado a otro sin que las ruedas delanteras se muevan. Siente una holgura notable antes de que las ruedas empiecen a responder. Para decidir si este juego libre está dentro de los límites seguros y el vehículo es legal para conducir, ¿cuánto movimiento del volante es el MÁXIMO que debería tener antes de que las ruedas delanteras empiecen a girar?","options":["Hasta media vuelta del volante, ya que algo de holgura es normal en camiones pesados","Hasta una vuelta completa del volante antes de que las ruedas reaccionen","Hasta 90 grados, que es un cuarto de vuelta del volante","No más de unos 10 grados de movimiento antes de que las ruedas respondan"],"explanation":"El juego libre del volante no debe superar unos 10 grados antes de que las ruedas delanteras respondan; más indica dirección desgastada o floja."},"401":{"q":"Durante su inspección previaje, presiona el pedal del embrague y nota que tiene notablemente más juego libre (recorrido suelto antes de la resistencia) de lo normal. Ya va con retraso y el camión todavía circula. ¿Cuál enunciado describe MEJOR lo que ha encontrado y lo que debe hacer?","options":["Un juego libre del embrague que sea excesivo o insuficiente es un defecto mecánico que debe repararse antes de que sea seguro operar el vehículo","El juego libre excesivo del embrague es desgaste normal que solo importa una vez que el embrague empieza a patinar bajo carga","Es un problema, pero solo la dirección y los frenos son elementos de inspección que pueden dejar un camión fuera de servicio","Un juego libre suelto del embrague es en realidad una buena señal de que el varillaje está bien lubricado y no se traba"],"explanation":"Un juego libre del embrague excesivo o insuficiente es un defecto mecánico que debe repararse antes de que el vehículo sea seguro para operar."},"402":{"q":"Está conduciendo un remolque cargado por una larga pendiente de montaña. Para ahorrar combustible y reducir el desgaste, un compañero le sugiere que ponga el cambio en punto muerto y deje que el camión ruede cuesta abajo, usando los frenos solo cuando la velocidad sea demasiado alta. ¿Por qué seguir este consejo es la opción equivocada?","options":["Es aceptable en una pendiente corta porque solo los frenos pueden controlar el camión de forma segura durante todo el descenso","Pierde el frenado del motor y de la transmisión y el control del vehículo, sus frenos de servicio pueden sobrecalentarse y perder eficacia, y rodar en punto muerto es ilegal","Solo se convierte en un problema si la pendiente es más empinada que la marcha baja que normalmente seleccionaría antes de descender","Rodar en punto muerto ahorra tanto combustible que la pequeña pérdida de control es un compromiso aceptable en la mayoría de las pendientes"],"explanation":"Poner el cambio en neutral en una bajada larga elimina el freno motor y de marchas, recalienta y desvanece los frenos de servicio, y rodar en neutral es ilegal."},"403":{"q":"Va subiendo una pendiente larga con un remolque cargado en un camión antiguo cuya transmisión no tiene indicador de marcha en el tablero. El motor empieza a forzarse y a perder potencia, y usted sabe que necesita bajar a una marcha más baja para seguir subiendo. Sin una tabla de cambios ni una pantalla de marcha en que apoyarse, ¿qué información debe usar realmente para decidir cuál es la marcha correcta en este momento?","options":["Únicamente lo que ve en el espejo del lado derecho mientras observa el remolque subir la cuesta","La altura de su asiento de conductor y lo empinada que se ve la pendiente desde la cabina","Su velocidad de marcha actual combinada con las revoluciones del motor (rpm) que indica el tacómetro","La posición de la manija de la puerta delantera respecto a su hombro como referencia rápida"],"explanation":"La marcha correcta se elige haciendo coincidir tu velocidad en carretera con las rpm del motor que muestra el tacómetro."},"404":{"q":"Está detenido en un semáforo en rojo en una pendiente empinada cuesta arriba con un remolque completamente cargado. El semáforo se pone verde y necesita poner el conjunto en marcha suavemente sin dejar que se deslice hacia el auto detenido muy cerca detrás de usted. Al prepararse para soltar el freno de servicio (de pie) y acelerar el motor, ¿qué técnica evita MEJOR que el vehículo retroceda durante el arranque?","options":["Bombear rápidamente el freno de servicio varias veces para generar presión de aire adicional antes de arrancar","Poner una marcha más alta para que el motor tenga más fuerza de tracción para vencer la pendiente","Acelerar el motor y soltar lentamente el embrague para que el camión avance solo con el par motor","Mantener el freno de estacionamiento aplicado y soltarlo solo cuando el motor tome la carga y comience a avanzar"],"explanation":"Al arrancar en una subida, mantén el freno de mano y suéltalo solo cuando el motor tome la carga y comiences a avanzar, evitando el retroceso."},"405":{"q":"Está justo bajo cero y una fina capa de hielo cubre el patio mientras saca su combinación cargada desde una señal de alto en la salida del almacén. Siente que las ruedas motrices empiezan a perder agarre. ¿Qué acción le da la MEJOR posibilidad de arrancar sin patinar las ruedas motrices y provocar un derrape por aceleración?","options":["Pise el acelerador suavemente y aumente la velocidad de forma gradual para que las llantas motrices mantengan el agarre en la superficie resbaladiza","Pise el acelerador con firmeza hasta el fondo para que la potencia adicional empuje el camión a través del tramo resbaladizo","Agregue un segundo extra de distancia de seguimiento por cada 10 pies de longitud del vehículo antes de arrancar","Mantenga el embrague parcialmente engranado y acelere el motor muy alto, luego suéltelo rápido para lograr un arranque fuerte"],"explanation":"En una superficie resbaladiza y casi helada, acelera suavemente y aumenta la velocidad de forma gradual para que las ruedas motrices mantengan el agarre y no patinen."},"406":{"q":"Acaba de amanecer y está haciendo su inspección previaje. Al abrir el capó y mirar las correas de transmisión del alternador y de la bomba de agua, ¿qué condición le indica que las correas necesitan atención antes de poder sacar el camión a la carretera con seguridad?","options":["Las correas tienen un color apagado y oscuro en lugar de un acabado brillante y reluciente","Una correa está agrietada y deshilachada, o se flexiona más de lo debido al presionarla (tensión incorrecta)","La bocina no suena lo bastante fuerte al presionarla","El indicador de combustible no marca lleno cuando la llave está puesta"],"explanation":"Las correas de transmisión deben reemplazarse si están agrietadas, deshilachadas o se flexionan más de lo debido, pues la tensión incorrecta o el desgaste pueden hacerlas fallar."},"407":{"q":"Durante su inspección previaje, abre el capó y pasa la mano a lo largo de las mangueras del radiador y de la calefacción en el compartimento del motor. ¿Qué condición revisa principalmente en estas mangueras?","options":["Si las mangueras se sienten calientes, lo que indicaría que el motor alcanzó la temperatura de funcionamiento","Un silbido fuerte o un golpeteo que proviene de la zona de la correa y la polea","Puntos blandos, fugas y grietas que podrían provocar la falla de una manguera","Un acabado brillante y lustroso que muestra que el caucho fue limpiado y tratado recientemente"],"explanation":"Las mangueras del motor deben inspeccionarse en busca de puntos blandos, fugas y grietas, porque una manguera debilitada puede reventar por calor y presión y causar pérdida de refrigerante."},"408":{"q":"Está justo bajo cero durante su inspección matutina previaje y, mientras camina alrededor del compartimiento del motor, decide revisar el sistema de dirección asistida (servodirección) antes de un largo día de conducción en montaña. ¿Cuál de las siguientes opciones describe MEJOR lo que debería inspeccionar en el sistema de dirección asistida?","options":["El volante con no más de 10 grados (unas 2 pulgadas en un volante de 20 pulgadas) de juego libre antes de que giren las ruedas","Ruidos fuertes de zumbido o gemido de la bomba, ya que el sonido es el único indicio fiable de un problema de dirección asistida","Pintura fresca y brillante en el depósito y las líneas para confirmar que el sistema fue reparado recientemente","El nivel del líquido de la dirección asistida y cualquier señal de fugas en las mangueras, el depósito y las conexiones"],"explanation":"Revisa el sistema de dirección asistida para verificar el nivel correcto de líquido y cualquier fuga en mangueras, depósito y conexiones, pues un nivel bajo puede causar pérdida repentina de asistencia."},"409":{"q":"Durante su inspección previaje en una mañana fría y luminosa, se acerca a la cabina y nota una grieta que recorre el borde inferior del parabrisas, además de una capa de mugre del camino y restos secos de insectos sobre gran parte del vidrio. Conducirá hacia el sol bajo de la mañana durante la primera hora de su viaje. ¿Cuál es la forma correcta de manejar el parabrisas antes de conducir?","options":["Limpiar bien el parabrisas y asegurarse de que la grieta no sea lo bastante grande ni esté ubicada de modo que obstruya gravemente su visión antes de conducir","Dejar la mugre en su lugar porque un parabrisas sucio y empañado en realidad reduce el deslumbramiento del sol bajo de la mañana y mejora su visión","Aplicar una película de tinte oscuro sobre todo el parabrisas para manejar el deslumbramiento del sol y luego conducir sin limpiar el vidrio","Ignorar por completo el parabrisas, ya que cualquier grieta, por mínima que sea, deja automáticamente el vehículo fuera de servicio y termina la inspección"],"explanation":"Antes de conducir, el parabrisas debe estar limpio y sin grietas lo bastante grandes o ubicadas como para obstruir gravemente la visión."},"410":{"q":"Es una mañana lluviosa y durante la inspección previaje descubre que la escobilla del limpiaparabrisas del lado del conductor está rasgada y el depósito del lavaparabrisas está vacío. Ya va atrasado y ahora mismo la lluvia es ligera. ¿Cuál razón explica MEJOR por qué debe reparar estos elementos antes de conducir, en lugar de tratarlos como una molestia menor?","options":["Sirven principalmente para mantener la suciedad del camino lejos de la pintura y conservar el valor de reventa del camión","Los limpiaparabrisas y lavaparabrisas en buen estado mantienen su visión clara bajo la lluvia, y sin visión clara no puede juzgar con seguridad la distancia, el tránsito y los peligros adelante","Solo se exigen para que el camión pase la inspección anual estatal de seguridad, no para la conducción diaria","Ayudan a descongelar el parabrisas más rápido, que es la verdadera razón por la que son un elemento de fuera de servicio"],"explanation":"Los limpiaparabrisas y lavadores mantienen la visión clara bajo la lluvia, y ver con claridad es esencial para calcular distancia, tráfico y peligros."},"411":{"q":"Está retrocediendo su tractocamión con remolque para salir de un muelle de carga estrecho cuando un trabajador a pie de repente entra en su punto ciego cerca de la parte trasera. Durante su inspección previaje confirmó que la bocina funciona. En este momento, ¿cuál es la razón PRINCIPAL por la que una bocina que funcione le importa a usted como conductor CDL?","options":["Le permite avisar a sus compañeros de que ya terminó y está listo para salir del muelle","Confirma que su sistema eléctrico tiene carga suficiente para alimentar los accesorios","Le permite advertir al trabajador y a otras personas de un peligro inminente para que puedan apartarse","Cumple con una función de comodidad y conveniencia que el inspector revisa para la calidad de marcha"],"explanation":"La bocina es un dispositivo de advertencia que alerta a trabajadores, peatones y conductores de un peligro inmediato para que se aparten."},"412":{"q":"Es temprano por la mañana, con la temperatura apenas bajo cero, y durante su inspección previaje el parabrisas se empaña y escarcha por dentro de forma constante. Confirma que el desempañador (defroster) y la calefacción funcionan correctamente. ¿Cuál es la principal razón de seguridad por la que estos sistemas deben funcionar antes de salir a la carretera?","options":["Para que la cabina se mantenga lo bastante caliente y usted siga alerta y cómodo durante un turno largo y frío","Para poder descongelar rápidamente el hielo de los espejos exteriores y la antena antes de conducir","Para que el aire caliente evite que las escobillas del limpiaparabrisas se peguen y se congelen al cristal","Para mantener el parabrisas despejado y conservar una visión sin obstrucciones de la carretera en clima frío o húmedo"],"explanation":"El desempañador y la calefacción mantienen el parabrisas despejado en clima frío o húmedo, conservando una visión sin obstrucciones de la carretera."},"413":{"q":"Está justo bajo el punto de congelación, solo conducirá dos millas hasta un patio de descarga cercano, y el cinturón de seguridad se siente rígido e incómodo sobre su abrigo de invierno. Al terminar su inspección previaje y prepararse para salir, ¿qué acción es correcta respecto a su cinturón de seguridad?","options":["Abrocharse y usar el cinturón de seguridad durante todo el viaje, sin importar lo corta que sea la distancia o lo lento que planee conducir","Dejar el cinturón sin abrochar porque el viaje es de menos de tres millas y conducirá lentamente","Meter el cinturón holgadamente detrás de usted para que el aviso sonoro se detenga pero su movimiento no quede restringido por el abrigo","Omitir el cinturón ya que conducir lento en el patio y el estacionamiento no exige legalmente el uso de sujeción"],"explanation":"Un conductor comercial debe usar el cinturón de seguridad siempre que el vehículo esté en movimiento, sin importar lo corto o lento del viaje."},"414":{"q":"Usted transporta una carga por una carretera rural de dos carriles cuando el motor pierde potencia y usted se deja rodar hasta el acotamiento derecho. Enciende las luces intermitentes de emergencia y ya percibe olor a humo del compartimiento del motor, así que toma su extintor cargado. Antes de empezar a caminar hacia atrás para colocar los dispositivos de advertencia, ¿qué otro equipo de emergencia está usted legalmente obligado a llevar en este camión para poder completar la señalización de advertencia?","options":["Un radio CB de respaldo para pedir ayuda y advertir a otros camioneros del peligro","Triángulos reflectantes de advertencia para colocarlos en la vía y alertar al tránsito que se aproxima","Un chaleco de seguridad de alta visibilidad, que es el único dispositivo que las reglas le exigen llevar","Solo una bolsa de bengalas de carretera, ya que los triángulos son opcionales una vez encendidas las intermitentes"],"explanation":"Todo vehículo comercial debe llevar tres triángulos reflectantes de advertencia para colocarlos en la vía y alertar al tráfico que se aproxima al detenerse."},"415":{"q":"Llega a su turno y se sube a un tractocamión que otro conductor dejó hace dos horas. Antes de salir del patio, quiere confirmar que los frenos, las luces y los neumáticos están en condiciones para circular. ¿Qué única acción le da el panorama inicial más fiable de los defectos que ya se habían detectado en este vehículo?","options":["Dar por bueno el vehículo porque el conductor anterior claramente terminó un viaje sin averiarse","Pasar directamente a una prueba de manejo, ya que conducir el camión unas millas es la forma más rápida de notar un problema real","Leer el último informe de inspección del vehículo (DVIR) del conductor anterior y verificar que los defectos anotados fueron certificados como reparados","Llamar al despachador y preguntar si algún otro conductor se ha quejado de esta unidad en la última semana"],"explanation":"Antes de conducir, revise el último informe de inspección del conductor anterior (DVIR) y confirme que los defectos anotados fueron certificados como reparados."},"417":{"q":"Lleva tres horas en un largo y monótono trayecto por la autopista interestatal tras una salida temprana. Su velocidad ha bajado sin que usted lo notara, apenas recuerda las últimas millas y se sorprende frotándose los ojos. Según las pautas de conducción segura, ¿cuál de estas es la señal más clara de que se está volviendo demasiado somnoliento para seguir conduciendo de forma segura?","options":["Sus manos se sienten inquietas en el volante y le dan ganas de revisar los espejos con más frecuencia","Se siente muy alerta y su atención está totalmente fija en la carretera que tiene delante","Su tiempo de reacción en el pedal del freno se siente más rápido y nítido de lo habitual","Le pesan los párpados y sus pensamientos se desvían constantemente de la carretera"],"explanation":"Los párpados pesados y caídos junto con pensamientos que divagan son señales clásicas de fatiga peligrosa del conductor."},"418":{"q":"Son las 2 de la madrugada y lleva tres horas en un viaje largo cuando siente los párpados pesados, se sorprende desviándose hacia el acotamiento y no recuerda las últimas millas. Aún le quedan más de 100 millas hasta la terminal. ¿Qué acción realmente restaurará su capacidad de conducir con seguridad?","options":["Salir a un área de descanso segura y dormir o descansar antes de continuar","Bajar las ventanillas y subir el volumen de la radio para mantenerse alerta","Parar por un café grande y seguir adelante para llegar a la terminal","Aumentar la distancia de seguimiento y seguir conduciendo con más precaución"],"explanation":"La única cura real para la somnolencia es dormir, así que deténgase en un área de descanso segura y descanse antes de continuar."},"419":{"q":"Son las 4:30 a.m. y está a punto de comenzar un viaje de 9 horas después de haber dormido mal la noche anterior. Se siente somnoliento. ¿Cuál de las siguientes es la forma MENOS eficaz de asegurarse de que la fatiga no lo haga conducir en estado de agotamiento en este viaje largo?","options":["Programar sus viajes para conducir la mayor parte durante las horas en que normalmente está despierto","Tomar un café grande y mantener la cabina fría y la radio a todo volumen para mantenerse alerta en lugar de dormir","Dormir una noche completa antes del viaje y planear detenerse a descansar cuando sienta somnolencia","Evitar medicamentos que causen somnolencia y reconocer señales de advertencia como párpados pesados o pensamientos dispersos"],"explanation":"El café, el aire frío y el ruido fuerte solo enmascaran la somnolencia de forma temporal y nunca sustituyen al sueño, la única cura real de la fatiga."},"421":{"q":"Es una tarde de 38 grados (100 Fahrenheit) y lleva unas tres horas de un viaje largo cruzando el oeste de Texas. Se detiene para hacer una revisión obligatoria de la carga y las llantas durante la marcha. Dos llantas marcan ahora una presión notablemente más alta que durante su inspección previa al viaje en la fresca mañana. ¿Cuál es la razón MÁS probable y qué le indica sobre el riesgo que enfrenta ahora?","options":["El pavimento caliente ha enfriado el aire dentro de las llantas, bajando la presión y aumentando el riesgo de un pinchazo","El alquitrán que rezuma del camino caliente se ha absorbido en las llantas, añadiendo peso y presión","El calor ha aumentado la presión del aire dentro de las llantas, lo que eleva el riesgo de un reventón","No pasa nada; la presión de las llantas baja de forma natural con el calor, así que la lectura más alta significa que su manómetro está defectuoso"],"explanation":"El calor hace que el aire dentro de los neumáticos se expanda y suba la presión, aumentando el riesgo de reventón."},"422":{"q":"Es media tarde de un día de verano muy caluroso en Texas y, mientras conduce un vehículo combinado cargado, nota parches oscuros y brillantes de alquitrán que 'rezuma' hacia la superficie del asfalto más adelante. ¿Qué debería esperar que este alquitrán que rezuma le haga a la carretera y por qué es importante para el control del vehículo?","options":["El alquitrán dará más agarre a los neumáticos porque es pegajoso, así que puede mantener con seguridad su velocidad de autopista al pasar por esos parches.","El peligro principal es que el calor elevará la presión de sus neumáticos por encima del límite, por lo que el alquitrán en sí no afecta cómo se siente la carretera bajo los neumáticos.","No tiene un efecto real sobre la tracción mientras los neumáticos del eje de dirección (delantero) aún tengan al menos 4/32 de pulgada de banda de rodadura.","Hará que la superficie de la carretera quede resbaladiza y reducirá la tracción de los neumáticos, por lo que debe reducir la velocidad y evitar girar o frenar bruscamente sobre esos parches."],"explanation":"El alquitrán que aflora vuelve la carretera resbaladiza y reduce la tracción, así que reduzca la velocidad y evite girar o frenar bruscamente en esos tramos."},"423":{"q":"Es mediados de julio en Texas y usted sube una pendiente larga completamente cargado. La cabina está caliente, el motor trabaja con esfuerzo y usted quiere una advertencia temprana de que el motor está a punto de sobrecalentarse antes de quedar varado o causar daños. ¿Qué indicador le da esa advertencia?","options":["El indicador de temperatura del refrigerante","El indicador de presión de aceite","El indicador de combustible","El tacómetro (revoluciones del motor/RPM)"],"explanation":"El indicador de temperatura del refrigerante es el indicador principal y directo del sobrecalentamiento del motor, dando el aviso más temprano para actuar."},"424":{"q":"Conduce un vehículo combinado cargado por una carretera de dos carriles justo después del amanecer cuando entra en un tramo de niebla tan densa que apenas distingue las líneas del carril por delante. Decide que debe seguir avanzando despacio hasta llegar a la próxima salida. Para ver la carretera lo mejor posible SIN empeorar su propia visibilidad, ¿qué configuración de luces es la mejor opción?","options":["Encender las luces altas, ya que alumbran unos 350 a 500 pies y le permiten ver más lejos a través de la niebla","Usar las luces bajas, porque las luces altas se reflejan en la niebla hacia sus ojos y reducen lo que puede ver","Apagar todas las luces delanteras y depender solo de las intermitentes de emergencia para que los conductores que vienen lo vean","Usar luces altas ahora y bajarlas solo cuando un vehículo que viene de frente esté a 500 pies"],"explanation":"Con niebla use las luces bajas, porque las luces altas se reflejan en la niebla y devuelven el resplandor a sus ojos, reduciendo la visibilidad."},"425":{"q":"Conduce un tractocamión cargado por una carretera de dos carriles de noche cuando entra en un banco de niebla tan densa que ya no puede ver las líneas del carril ni las luces traseras del vehículo que va adelante. ¿Cuál de las siguientes es la acción MÁS SEGURA?","options":["Cambiar a las luces altas para que la luz más brillante le ayude a ver más lejos a través de la niebla","Seguir avanzando a velocidad reducida con las luces bajas, ya que detenerse en cualquier lugar es más peligroso que continuar","Salirse completamente de la carretera, bien apartado de los carriles de circulación, encender las luces intermitentes de emergencia y esperar a que se disipe la niebla","Reducir casi hasta detenerse y parar en su propio carril con las cuatro intermitentes encendidas hasta que mejore la visibilidad"],"explanation":"Cuando la niebla sea demasiado densa para ver, salga completamente de la carretera lejos de los carriles, encienda las luces de emergencia y espere a que se disipe."},"426":{"q":"Lo despachan en un día ventoso con ráfagas constantes de viento cruzado en un tramo abierto de la autopista. Cuatro vehículos combinados salen del patio al mismo tiempo que usted. Según cómo afecta el viento a un vehículo, ¿qué conductor debería estar MÁS preocupado por ser empujado fuera del carril o incluso volcado por el viento cruzado?","options":["El conductor de un tanque totalmente cargado, porque el líquido que se mueve hace del viento la mayor amenaza","El conductor de una plataforma plana con una carga de acero baja, pesada y distribuida uniformemente","El conductor de un remolque cerrado cargado que viaja en el límite legal de peso, porque los vehículos más pesados atrapan más viento","El conductor de un remolque tipo caja alto que está vacío o ligeramente cargado, porque presenta una gran superficie con poco peso para resistir el viento"],"explanation":"Un remolque tipo caja alto, vacío o ligeramente cargado, corre más riesgo con viento cruzado porque ofrece una gran superficie con poco peso para resistir el viento."},"427":{"q":"Conduce un vehículo combinado cargado por una carretera rural de dos carriles de Texas y quiere planificar su viaje para pasar el menor tiempo posible en las condiciones en que los venados y otros animales grandes tienen más probabilidad de cruzar la vía de repente. ¿Qué parte del día exige el mayor nivel de atención por cruces de animales?","options":["Los períodos de poca luz alrededor del amanecer y el atardecer","La mitad del día, cerca del mediodía, cuando los animales buscan alimento","Al final de la mañana, después de que el sol ha salido por completo","A media tarde, durante la parte más calurosa del día"],"explanation":"Los venados y animales grandes son más activos al amanecer y al anochecer, las horas de poca luz cuando la visión del conductor también está más limitada."},"429":{"q":"Conduce un vehículo combinado cargado por una concurrida autopista de cuatro carriles con tráfico moderado. Una valla publicitaria digital, brillante y animada, en el arcén derecho atrae su mirada durante varios segundos mientras pasa junto a ella. ¿Cuál consecuencia de esta mirada fija es la preocupación de seguridad MÁS grave que un conductor de CDL debe reconocer?","options":["Sus ojos se adaptarán al resplandor y perderá momentáneamente la visión nocturna","Deja de explorar el entorno y no detecta peligros que se desarrollan en otras partes de su campo visual","Reducirá la velocidad de forma inconsciente muy por debajo del flujo del tráfico y obstaculizará a los vehículos de atrás","Se fijará tan intensamente en el cartel que en realidad verá el camino más adelante con mayor claridad"],"explanation":"Fijar la vista en un solo objeto detiene el barrido visual, por lo que los peligros que surgen en otras partes de su campo visual pasan inadvertidos hasta que es demasiado tarde."},"430":{"q":"Conduce un vehículo combinado cargado por una carretera rural de dos carriles y alcanza a un tractor lento que lo obliga a circular 15 mph por debajo del límite. Quiere rebasar, pero la carretera no deja de cambiar. ¿En cuál de los siguientes lugares intentar rebasar sería MENOS seguro y más probable que lo coloque en una situación de choque frontal?","options":["En una recta larga y plana donde ve claramente al menos un cuarto de milla de carril contrario vacío","En una bajada suave donde la velocidad aumenta de forma natural y puede completar el rebase rápidamente","En la aproximación a la cima de una colina o a una curva, donde la vía adelante se dobla o sube y queda fuera de la vista","En un tramo recto con línea central discontinua y sin tráfico en sentido contrario a la vista"],"explanation":"Nunca adelante al acercarse a la cima de una colina o una curva, donde el camino sube o se desvía fuera de la vista y el tráfico en sentido contrario puede estar oculto."},"431":{"q":"Conduce su tractocamión cargado por una carretera de dos carriles y comienza a rebasar a un automóvil más lento. Al colocarse a su lado, se da cuenta de que lleva varios segundos circulando a la par de la puerta trasera del automóvil, justo en el punto ciego del conductor. Para completar esta maniobra con la seguridad que exige el DPS, ¿qué debe hacer?","options":["Levantar el pie del acelerador y mantenerse a la par del automóvil para que el otro conductor tenga tiempo de sobra para notarlo antes de adelantarse","Permanecer junto al automóvil a la misma velocidad hasta estar seguro de que no se aproxima tráfico en sentido contrario, y luego regresar a su carril","Mantener su velocidad actual y desplazarse de forma gradual hacia su carril mientras aún está al lado del automóvil para acortar el rebase total","Acelerar lo necesario para salir del punto ciego del otro conductor y completar el rebase con prontitud, y luego regresar a su carril sin demorarse junto al vehículo"],"explanation":"Complete el adelantamiento con prontitud y salga del punto ciego del otro conductor, luego regrese a su carril sin quedarse a su lado."},"432":{"q":"Usted se aproxima a una intersección con un cruce peatonal marcado. El semáforo está en verde para usted y desea girar a la derecha, pero un peatón ya bajó de la acera al cruce que está a punto de atravesar. ¿Qué debe hacer?","options":["Ceder el paso y dejar que el peatón termine de cruzar, porque los peatones en un cruce peatonal marcado tienen el derecho de paso","Realizar el giro ya que su luz verde le da el derecho de paso por encima del peatón","Tocar la bocina para alertar al peatón y continuar el giro si no se detiene","Detenerse solo si el peatón está directamente en su carril de circulación, de lo contrario seguir avanzando"],"explanation":"Los peatones que cruzan legalmente por un paso de peatones marcado siempre tienen el derecho de paso, por lo que el conductor que gira debe cederles incluso con luz verde."},"433":{"q":"Conduce su tractocamión con remolque por una calle urbana de dos carriles y un ciclista circula delante de usted en la parte derecha de su carril. El tránsito es moderado y se aproxima a una zona de autos estacionados donde el ciclista quizá deba desplazarse hacia la izquierda. ¿Qué acción refleja mejor cómo debe tratar a este ciclista?","options":["Mantenerse muy cerca detrás y dar un bocinazo largo para que el ciclista sepa que debe orillarse al acotamiento","Tratar al ciclista como trataría a otro vehículo, dándole espacio completo y una distancia segura antes de rebasarlo","Pasar apretado en el mismo carril, ya que una bicicleta ocupa mucho menos espacio que un auto","Cambiarse al carril del extremo izquierdo y permanecer allí el resto de la cuadra"],"explanation":"Un ciclista tiene el mismo derecho a la vía que cualquier vehículo, así que dele espacio suficiente y un margen seguro al rebasar en lugar de acorralarlo."},"434":{"q":"Usted se aproxima a una rotonda de varios carriles en su vehículo combinado cargado. El tránsito ya circula dentro de la rotonda y se abre un espacio a su izquierda, pero un vehículo todavía se acerca a ese espacio. ¿Cuál es la forma correcta de entrar?","options":["Acelerar con fuerza e incorporarse antes de que el vehículo que se acerca llegue a su punto de entrada, ya que el vehículo más grande tiene la preferencia de paso","Entrar al círculo y detenerse por completo una vez dentro, y luego esperar allí hasta que todo el tránsito a su alrededor se despeje","Ceder el paso al tránsito que ya circula en la rotonda y entrar solo cuando haya un espacio lo suficientemente grande para toda la longitud de su vehículo","Entrar de inmediato y, si es necesario, circular en sentido contrario para llegar a su salida por el camino más corto"],"explanation":"El tránsito que ya circula en la rotonda tiene el derecho de paso, así que ingrese solo cuando haya un espacio suficiente para todo el largo de su vehículo."},"435":{"q":"Ha estado lloviendo sin parar durante los últimos veinte minutos y el pavimento está completamente mojado. Circula a su velocidad habitual de carretera para pavimento seco y mantiene su intervalo de seguimiento usual de 6 segundos detrás del auto de adelante. En comparación con conducir este mismo tramo en pavimento seco, ¿cuál es lo MÁS importante que debe tener en cuenta en cómo conduce en este momento?","options":["Nada cambia para detenerse; los frenos del camión aplican la misma fuerza, así que su intervalo de seguimiento habitual para pavimento seco sigue siendo suficiente","Su distancia de reacción aumenta porque el pavimento mojado retrasa su percepción, pero la distancia de frenado real permanece igual una vez que los frenos agarran","La distancia de frenado se acorta mucho porque una película de agua deja que las llantas rueden más libremente y reduce el arrastre del camión","Su distancia total de frenado aumenta porque la menor tracción alarga la distancia de frenado, así que debe reducir la velocidad y aumentar su distancia de seguimiento"],"explanation":"El pavimento mojado reduce la tracción y alarga la distancia de frenado, aumentando la distancia total de detención, así que reduzca la velocidad y aumente la distancia de seguimiento."},"437":{"q":"Lleva 90 minutos en ruta cuando el despachador le avisa por radio que la dirección de entrega ha cambiado y necesita una nueva ruta en su GPS. Hay poco tráfico y circula a velocidad de autopista. ¿Cuál es la forma MÁS segura de manejar el nuevo destino?","options":["Esperar hasta poder salir de la vía y estacionar en un lugar seguro, luego introducir y fijar la nueva ruta antes de volver a conducir","Introducir la nueva dirección en el próximo semáforo en rojo mientras está detenido, y arrancar en cuanto cargue la ruta","Montar el dispositivo abajo, cerca del volante, y escribir la dirección ahí para mantener la vista cerca del camino","Seguir conduciendo y alternar la mirada entre el GPS y el camino mientras escribe el nuevo destino"],"explanation":"Configure siempre el GPS antes de conducir, nunca en movimiento, así que detengase en un lugar seguro fuera de la vía, ingrese la nueva ruta y luego reanude la marcha."},"439":{"q":"Su tractocamión acaba de verse involucrado en una colisión y está detenido, bloqueando parte de una carretera rural de dos carriles sin división central. Otros conductores se acercan desde ambas direcciones. Después de encender las luces intermitentes de emergencia, ¿cuál es la MEJOR forma de advertir al tránsito que se aproxima?","options":["Dejar solo las luces intermitentes de emergencia encendidas, ya que la ley en un choque solo exige las intermitentes","Dentro de los 10 minutos, colocar los triángulos reflectantes de advertencia: uno a unos 30 m (100 pies) detrás, uno a unos 30 m (100 pies) adelante y uno a unos 3 m (10 pies) detrás del vehículo","Pararse en el carril de circulación y agitar los brazos para que los conductores lo vean claramente y reduzcan la velocidad","Tocar la bocina de forma continua hasta que todos los vehículos que se aproximan se detengan"],"explanation":"Dentro de los 10 minutos de detenerse en una vía no dividida, coloque los triángulos de advertencia a unos 30 m detrás, 30 m delante y 3 m detrás del vehículo."},"441":{"q":"Conduce un tractocamión con remolque cargado a 60 mph por una carretera rural de dos carriles cuando nota por los espejos que una camioneta lo ha venido siguiendo muy de cerca durante varias millas. El tráfico adelante es ligero y constante. ¿Cuál es la MEJOR manera de reducir el peligro que crea quien lo sigue de cerca?","options":["Tocar el freno ligeramente varias veces para indicarle a la camioneta que se aleje y disuadirla de seguir tan de cerca","Mantener su velocidad pero moverse hacia el borde izquierdo de su carril para que la camioneta pueda ver lo suficientemente lejos y rebasarlo con seguridad","Aumentar gradualmente su distancia de seguimiento con el vehículo de adelante para tener espacio extra y frenar de forma suave en lugar de frenar bruscamente","Acelerar para abrir una brecha entre usted y la camioneta hasta que ya no esté lo bastante cerca como para ser un peligro"],"explanation":"Cuando lo siguen muy de cerca, deje más espacio adelante para frenar de forma gradual en lugar de bruscamente, dando al conductor de atras más tiempo para reaccionar."},"442":{"q":"Conduce un tractocamión cargado a 55 mph en una carretera seca de dos carriles cuando un automóvil comienza a seguirlo muy de cerca (pegado a su parachoques). El conductor está impaciente y claramente quiere que se aparte. Usted desea reducir el peligro que crea este conductor que lo sigue de cerca sin empeorar la situación. ¿Cuál de las siguientes sería la PEOR reacción de su parte?","options":["Mantener una velocidad constante y uniforme para que el auto de atrás pueda calcular un hueco seguro y finalmente rebasar","Soltar gradualmente el acelerador para abrir más espacio delante de usted como margen de seguridad","Mantenerse a la derecha y evitar maniobras bruscas para que quien lo sigue tenga espacio para adelantarlo","Aumentar su velocidad para alejarse del que lo sigue y poner más distancia entre ambos"],"explanation":"Acelerar para perder a quien lo sigue de cerca es un error, porque seguirá pegado mientras aumentan la velocidad y la distancia de frenado de ambos vehículos."},"443":{"q":"Es una mañana despejada con temperatura apenas bajo cero y usted transporta una carga por una carretera rural. El pavimento más adelante solo parece mojado, pero se aproxima a un paso elevado largo que cruza un río. ¿Qué afirmación debería influir MÁS en cómo maneja el paso elevado?","options":["La superficie del paso elevado puede estar congelada y con hielo antes que la carretera circundante, porque pierde calor tanto por arriba como por debajo.","El paso elevado será la última superficie en helarse, así que es el lugar más seguro para frenar bruscamente si hace falta.","Las superficies de puentes y pasos elevados solo se vuelven resbaladizas en verano, cuando el alquitrán aflora a través del pavimento.","Las plataformas elevadas nunca se congelan mientras la carretera de acceso siga pareciendo mojada y no blanca."],"explanation":"Los puentes y pasos elevados se congelan antes que la carretera porque pierden calor por arriba y por abajo, por lo que pueden estar helados mientras la vía solo está mojada."},"444":{"q":"Es una mañana fresca y húmeda de otoño y conduce un vehículo combinado cargado por una carretera rural de dos carriles. Al salir de una curva, ve que el pavimento más adelante está cubierto por una espesa capa de hojas mojadas y caídas que se extiende por ambos carriles. ¿Qué afirmación describe mejor cómo debe tratar ese tramo de la carretera?","options":["Las hojas añaden agarre igual que la arena mojada, así que puede mantener su velocidad actual con seguridad al pasar por el tramo.","Trate el pavimento cubierto de hojas como una superficie resbaladiza, soltando suavemente el acelerador y evitando frenar o girar bruscamente hasta haberlo pasado.","Como las hojas son orgánicas y blandas, amortiguan los neumáticos y no tienen ningún efecto real sobre la tracción ni sobre la distancia de frenado.","Solo los neumáticos delanteros (del eje de dirección) pierden tracción sobre las hojas, así que frenar levemente con las ruedas motrices lo mantiene plenamente en control."],"explanation":"Las hojas mojadas forman una capa resbaladiza de baja tracción como el hielo, así que suelte el acelerador y evite frenar o girar bruscamente hasta superarlas."},"445":{"q":"La temperatura está justo bajo cero y hace sol mientras conduce por una carretera rural de dos carriles. Los tramos abiertos y soleados del pavimento parecen secos, pero la vía pasa repetidamente bajo el dosel de los árboles y junto a altos terraplenes orientados al norte que permanecen en sombra. Al acercarse a una de estas secciones sombreadas, ¿cuál es el MAYOR peligro que debería esperar que la sombra esté ocultando?","options":["Alquitrán supurante que se ha ablandado al sol y ha vuelto resbaladiza la superficie","Grava suelta que el tráfico ha empujado hacia las zonas bajas en sombra","Una placa de hielo, porque el pavimento en sombra nunca se calentó por encima del punto de congelación aunque los tramos soleados estén secos","Pintura fresca de señalización vial que aún no se ha curado del todo con el frío"],"explanation":"El pavimento en sombra no recibe luz solar directa, por lo que la humedad allí permanece congelada aunque los tramos soleados y secos hayan superado el punto de congelación."},"446":{"q":"Usted conduce su tractocamión con remolque por una autopista mojada bajo una lluvia constante. Una fila de camiones lo adelanta por el carril izquierdo, y cada uno arroja una densa cortina de salpicaduras de la carretera sobre su parabrisas al pasar. Al pensar en cómo estas salpicaduras lo afectan a usted y a su capacidad de conducir con seguridad, ¿cuál afirmación es la única que mejor describe su efecto PRINCIPAL?","options":["Enfrían los tambores de freno, por lo que puede confiar más en ellos en la próxima bajada pronunciada","Aumentan la profundidad de la banda de rodadura de sus llantas, ayudándolo a mantenerse por encima del mínimo de 4/32 de pulgada de las llantas delanteras","Lavan la suciedad de la carretera, mejorando la tracción entre sus llantas y el pavimento","Lo ciegan brevemente al reducir su visibilidad, por lo que debe reducir la velocidad y aumentar su distancia de seguimiento"],"explanation":"El rocío de los camiones que pasan cubre momentáneamente el parabrisas y reduce bruscamente la visibilidad, así que reduzca la velocidad y aumente la distancia de seguimiento."},"447":{"q":"Usted conduce un tractocamión con remolque de 53 pies y necesita hacer un giro cerrado a la derecha desde una calle de la ciudad hacia un callejón estrecho. Nota un auto estacionado y un bordillo en el lado interior (derecho) del giro. Debido al desfase de las ruedas en la curva (off-tracking), ¿cuál de las siguientes opciones describe MEJOR lo que debe prever al pasar la unidad por este giro?","options":["Las ruedas traseras del remolque seguirán una trayectoria por dentro de la trayectoria de las ruedas delanteras, por lo que las llantas traseras podrían subirse al bordillo o golpear el auto estacionado en el lado interior del giro","Las ruedas traseras del remolque seguirán una trayectoria más amplia por fuera de las ruedas delanteras, por lo que la parte trasera del remolque se desviará hacia el tráfico que viene de frente por la izquierda","Las ruedas delanteras y traseras seguirán exactamente la misma trayectoria, por lo que si sus llantas direccionales libran el bordillo, las ruedas del remolque también lo librarán","El desfase de las ruedas solo importa a velocidad de autopista, así que a esta baja velocidad de giro los cuatro juegos de ruedas siguen prácticamente la misma línea"],"explanation":"Por el desplazamiento de las ruedas traseras, las ruedas traseras de un remolque largo siguen una trayectoria por dentro de las delanteras, así que abra lo suficiente para que no toquen el bordillo ni los vehículos del lado interior."},"448":{"q":"Usted conduce un tractocamión con remolque de 53 pies y debe hacer un giro cerrado a la derecha desde una calle angosta de dos carriles hacia otra calle angosta. Sabe que, debido a que las ruedas traseras del remolque siguen una trayectoria más corta y cerrada que las ruedas delanteras del tractor (off-tracking o desplazamiento de trayectoria), debe planear el giro con cuidado. Para completar este giro a la derecha de forma segura sin que las ruedas traseras del remolque se suban a la acera, ¿qué debe tener en cuenta?","options":["Debido al off-tracking, la parte trasera del remolque se abre hacia afuera, así que solo necesita espacio adicional en el exterior (izquierda) del giro","Debido al off-tracking, las ruedas traseras del remolque cortan por dentro de la trayectoria del tractor, así que necesita espacio adicional en el interior del giro","El off-tracking no afecta un giro tan cerrado, así que no se necesita espacio adicional en ninguna dirección","Como el vehículo es largo, necesita menos espacio en el interior porque el remolque sigue en línea recta detrás del tractor"],"explanation":"El desplazamiento de las ruedas traseras hace que las ruedas traseras del remolque corten por dentro de la trayectoria del tractor, así que deje espacio adicional en el interior del giro."},"449":{"q":"Está incorporándose a una autopista con mucho tráfico en su tractocamión y un automóvil pequeño desaparece de su vista justo detrás de su espejo del lado derecho, donde ya no puede verlo en absoluto. Antes de cambiar de carril, ¿cómo debe describir y tratar correctamente esta área específica alrededor de su camión?","options":["Es una zona de baja tracción, por lo que debo frenar suavemente antes de meterme en el carril.","Es un colchón de protección que los demás conductores son responsables de mantener libre de mi remolque.","Es uno de mis puntos ciegos, también llamado No-Zone, donde me resulta difícil ver a otros conductores, así que debo revisarlo con cuidado antes de cambiarme.","Es la zona de peligro creada únicamente por mi alto centro de gravedad cuando el remolque va cargado."],"explanation":"Las áreas alrededor de un camión donde es difícil ver a otros conductores son los puntos ciegos, llamados No-Zones, que deben revisarse con cuidado antes de cambiar de carril."},"450":{"q":"Está incorporándose con su tractocamión a una autopista concurrida. Un automóvil que vio claramente hace un instante en su espejo lateral derecho ahora ha desaparecido por completo de ese espejo, y tampoco lo ve adelante. Antes de continuar el cambio de carril, ¿qué significa MÁS probablemente esta desaparición?","options":["El automóvil aceleró y ahora está muy lejos detrás de usted, así que el carril está libre","El automóvil frenó fuerte y se orilló al acotamiento derecho, totalmente fuera de la calzada","Su espejo está mal ajustado y debe reposicionarlo en su próxima parada","El automóvil se metió en un punto ciego (una 'No-Zone') junto a su remolque, donde el espejo ya no puede mostrarlo"],"explanation":"Un vehículo que desaparece de su espejo probablemente entró en un punto ciego (No-Zone) junto a su remolque, así que nunca cambie de carril hasta poder ubicarlo de nuevo."},"451":{"q":"Conduce un tractocamión cargado por una autopista de cuatro carriles y decide pasar del carril derecho al carril izquierdo para rebasar a un vehículo lento. Revisa sus espejos planos y convexos (gran angular), ve que parecen despejados y señala con anticipación. Cuando empieza a desplazarse, el MAYOR peligro para usted es un vehículo ubicado dónde?","options":["En el punto ciego a lo largo de su remolque, una zona que sus espejos no muestran","Dos carriles más allá en el carril izquierdo extremo, parcialmente visible en su espejo convexo","Directamente detrás de su remolque, donde se ven sus luces de freno","Adelante de usted en su propio carril, el vehículo lento que pretende rebasar"],"explanation":"Los camiones grandes tienen puntos ciegos (No-Zones) a los lados y atrás que los espejos no muestran, por lo que hay que girar la cabeza y verificar antes de cambiar de carril."},"453":{"q":"Está a punto de salir de la terminal para un recorrido de 400 millas que cruza un paso de montaña, y quiere planificar el viaje de la manera correcta antes de arrancar. ¿Cuál de las siguientes es la cosa MÁS importante que debe verificar durante la planificación del viaje?","options":["Si su lista de música favorita está descargada para mantenerse alerta en el largo trayecto","Su ruta planificada y las condiciones meteorológicas actuales a lo largo del camino","Que su distancia de seguimiento sea de 1 segundo por cada 10 pies de longitud del vehículo","Si las paradas de camiones de su ruta sirven el tipo de comida que le gusta para el almuerzo"],"explanation":"Una buena planificación del viaje significa conocer de antemano su ruta y el clima en ella, para elegir las marchas, la velocidad y el momento según condiciones que no puede controlar."},"454":{"q":"La temperatura está justo bajo cero, una lluvia ligera ha comenzado a cubrir de hielo los puentes de su ruta y el límite de velocidad indicado es de 55 mph. El tráfico es escaso y el pavimento aún solo parece mojado. Según las normas del DPS de Texas, ¿en cuál de estas situaciones está OBLIGADO a circular a una velocidad POR DEBAJO del límite indicado?","options":["Cuando el camino por delante está despejado y seco, porque un carril libre le permite usar con seguridad las 55 mph indicadas","Cuando el tráfico a su alrededor es escaso, porque menos vehículos significa menos motivos para reducir la velocidad","Cuando las condiciones son malas —como la superficie mojada y casi congelada y los puentes potencialmente helados que ahora enfrenta—, porque la velocidad segura la determinan la tracción y la visibilidad, no el número indicado","Cuando va atrasado respecto al horario, porque apurarse en mal tiempo le permite recuperar el tiempo perdido"],"explanation":"La velocidad segura la determinan la tracción y la visibilidad, no el límite señalado, así que reduzca la velocidad en carreteras mojadas y casi heladas y en puentes con hielo donde puede ocultarse el hielo negro."},"455":{"q":"Conduce un remolque cargado por una carretera rural con un límite señalizado de 55 mph. Ha comenzado una llovizna fría y el pavimento brilla por la humedad. Se siente cómodo y hay poco tráfico. ¿Qué afirmación describe MEJOR cómo se le aplica el límite de 55 mph en este momento?","options":["El límite de 55 mph es tanto un mínimo como un máximo legal, así que bajar mucho de esa velocidad en estas condiciones sería en sí una infracción","Como su camión va cargado y tiene buena tracción, las 55 mph señalizadas siguen siendo una velocidad objetivo segura sobre el pavimento mojado","Los límites señalizados ya incluyen un margen de seguridad para la lluvia, así que 55 mph sigue siendo apropiado hasta que la vía quede totalmente inundada","La señal de 55 mph es el máximo solo para condiciones ideales, así que en el pavimento mojado una velocidad segura está por debajo del límite señalizado"],"explanation":"El límite señalado es el máximo legal solo para condiciones ideales, así que en una carretera mojada, donde baja la tracción y aumenta la distancia de frenado, conduzca por debajo de la velocidad indicada."},"456":{"q":"Conduce un remolque cargado por una autopista interestatal congestionada en hora pico. El tráfico es denso pero avanza de manera constante, y hay vehículos encajonándolo por ambos lados. Quiere llegar a tiempo a su entrega, pero también sabe que su distancia de frenado es larga. ¿Qué acción le da el MEJOR control y el menor riesgo de choque en este tráfico pesado?","options":["Mantener una velocidad constante acorde con el flujo y conservar buen espacio delante para tener lugar donde detenerse","Cambiar de carril con frecuencia para encontrar el hueco que avance más rápido y recuperar el tiempo perdido","Seguir muy de cerca al vehículo de adelante para que otros autos no se metan en su espacio","Frenar fuerte y con frecuencia para mantener su velocidad bastante por debajo del flujo del tráfico"],"explanation":"En tráfico denso, mantenga una velocidad constante acorde al flujo y conserve amplio espacio adelante para su larga distancia de frenado."},"458":{"q":"Usted conduce su tractocamión por una carretera de dos carriles sin división, en terreno montañoso. Alcanza a un tractor agrícola lento y quiere rebasarlo, pero el camino más adelante sube hacia la cima de una colina y no puede ver lo que viene del otro lado. ¿Cuál de las siguientes opciones describe mejor cuándo NO debe iniciar el rebase?","options":["Cuando tiene una recta larga y despejada y el carril contrario está vacío por un cuarto de milla","Cuando el camino sube hacia la cima de una colina o curva y no puede ver lo suficientemente lejos para completar el rebase con seguridad","Cuando hay mucho camino abierto y buena visibilidad pero el vehículo de adelante avanza lentamente","Solo cuando un vehículo que viene en sentido contrario ya está dentro de 500 pies y le destella las luces altas"],"explanation":"Nunca rebase cuando una cima o curva bloquee su vista, pues no puede ver si el carril contrario está libre durante toda la maniobra."},"459":{"q":"Acaba de acoplar su remolque al muelle de carga de un cliente en un patio estrecho y desconocido. El muelle está parcialmente oculto detrás de su remolque, hay tarimas apiladas cerca y sus espejos no muestran los primeros metros directamente detrás del equipo. Antes de poner el camión en reversa, ¿qué debe hacer PRIMERO para retroceder con seguridad?","options":["Comenzar a retroceder lentamente confiando en sus espejos, ya que ofrecen la vista más amplia y confiable de la zona detrás del remolque","Tocar la bocina tres veces y luego retroceder a velocidad constante, confiando en que los bocinazos advertirán a quien esté en su camino por detrás","Bajarse de la cabina y caminar hasta la parte trasera para inspeccionar el camino, los espacios libres y cualquier punto ciego antes de empezar a moverse","Retroceder rápidamente para cruzar el punto ciego antes de que un peatón o un montacargas tenga oportunidad de meterse en su camino"],"explanation":"Antes de retroceder, siempre baje y mire (G.O.A.L.) para revisar el camino, los espacios libres y los puntos ciegos que los espejos no muestran."},"460":{"q":"Está solo en un patio de carga estrecho y debe meter en reversa su tractocamión hasta un andén ubicado del lado del pasajero (derecho). Para llevar la parte trasera del remolque hacia ese andén del lado derecho, comienza a girar el volante hacia la derecha. En el primer instante después de empezar a retroceder con el volante girado a la derecha, antes de cualquier corrección mayor, ¿hacia qué lado se mueve primero la parte trasera del remolque?","options":["La parte trasera del remolque se desvía de inmediato hacia la derecha, la misma dirección en que giró el volante, así que conduce recto hacia el andén.","El remolque retrocede recto en línea con el tractor y solo empieza a inclinarse cuando acelera.","La parte trasera del remolque sube y se va hacia la derecha, hacia la aproximación del andén, mientras el tractor la empuja.","La parte trasera del remolque se mueve primero hacia la izquierda, lo opuesto a como giró el volante, antes de que contradireccione para llevarla a la derecha."],"explanation":"Al retroceder, la parte trasera del remolque se mueve primero al lado opuesto al volante: girar a la derecha la manda a la izquierda antes de contradirigir."},"461":{"q":"Conduce un remolque cerrado de 53 pies en una concurrida autopista de tres carriles y comienza a desviarse hacia el carril contiguo. Al mirar los espejos, no ve dos autos que circulan a su lado a su misma velocidad. Según las zonas ciegas (No-Zones) del camión, ¿en qué área de peligro es más probable que estén ocultos esos vehículos en este momento?","options":["En los puntos ciegos que se extienden a lo largo de los lados derecho e izquierdo del remolque","Justo delante de la cabina, donde el capó bloquea su visión","Muy cerca detrás del remolque, donde sus espejos no alcanzan","Muy por encima, en el área sobre el techo del remolque"],"explanation":"Los vehículos que circulan a su lado pueden ocultarse en los puntos ciegos laterales (No-Zone) a la derecha e izquierda del remolque, siendo el derecho el mayor."},"462":{"q":"Conduce un remolque cargado por una concurrida autopista interestatal de cuatro carriles a 60 mph. Una fila de autos ha comenzado a acumularse muy cerca detrás de usted en el carril derecho, y percibe que un par de ellos se preparan para adelantar. Para gestionar correctamente el espacio DETRÁS de su unidad y mantenerse atento a estos vehículos, ¿qué debe hacer?","options":["Dejar de usar los espejos y concentrarse solo en la carretera muy por delante, ya que lo que está detrás no puede afectar su conducción","Mirar los espejos con regularidad (aproximadamente cada 5 a 8 segundos) para vigilar los vehículos que se acercan por detrás y por los lados","Acelerar muy por encima de 60 mph para que los autos de atrás se queden rezagados y el espacio se abra por sí solo","Frenar con frecuencia para obligar a los que lo siguen de cerca a retroceder y crear un colchón detrás de usted"],"explanation":"No puede controlar el espacio detrás de usted, así que revise los espejos con regularidad, cada 5 a 8 segundos, para vigilar los vehículos que se acercan atrás y al lado."},"463":{"q":"Conduce un tractocamión cargado a 55 mph por una autopista interestatal llana cuando ve que las luces de freno se propagan por los carriles a un cuarto de milla por delante y el grupo de tráfico empieza a comprimirse hacia usted. La distancia de seguimiento se está cerrando. ¿Qué respuesta gestiona MEJOR su espacio y su energía en esta situación que se desarrolla?","options":["Mantener la velocidad y dirigirse hacia el carril del arcén para esquivar el grupo que frena antes de que se detenga por completo","Aplicar un frenado firme y fuerte ahora para reducir la velocidad rápidamente, ya que a 55 mph ya se necesitan unos 419 pies para detenerse","Soltar el acelerador y dejar que su distancia de seguimiento vuelva a abrirse, frenando suavemente solo cuando sea necesario a medida que se desarrolla el hueco por delante","Mantener la velocidad por ahora y conservar al menos un segundo de distancia de seguimiento por cada 10 pies de longitud del vehículo hasta que se vea obligado a reaccionar"],"explanation":"Cuando el tráfico de adelante reduce la velocidad, suelte el acelerador para que la distancia de seguimiento vuelva a abrirse, frenando suavemente solo si es necesario."},"464":{"q":"Transporta una carga sobreancho por una carretera rural angosta de dos carriles sin arcén. Las camionetas que vienen de frente se acercan constantemente a la línea central, el borde del pavimento cae bruscamente a su derecha, y hay buzones y autos estacionados muy cerca del carril de circulación. Para controlar el mayor peligro que crea aquí su vehículo ancho, ¿dónde debe concentrar la mayor parte de su atención?","options":["En la superficie de la vía muy adelante, para detectar baches antes de que las ruedas delanteras los alcancen","En el espacio sobre el remolque, vigilando ramas bajas y cables aéreos","En el espacio debajo del remolque, comprobando que nada se arrastre bajo el chasis","En el espacio a los lados, porque el ancho de su vehículo deja muy poca holgura respecto al tránsito que viene de frente, el desnivel del borde y los objetos al costado del camino"],"explanation":"En un vehículo ancho por una carretera angosta sin acotamiento, vigile más el espacio lateral, pues el tráfico contrario, el desnivel y los objetos lo estrechan a ambos lados."},"465":{"q":"Termina un largo recorrido de entrega y se detiene en una báscula al borde de la carretera. Un oficial le pide que se someta a una prueba de aliento. Hace aproximadamente una hora bebió dos cervezas durante la cena, se siente completamente sobrio y sabe que el límite para un conductor común de automóvil de pasajeros en su estado es 0.08. ¿Cuál es la concentración de alcohol en sangre (BAC) MÁS BAJA con la cual usted, operando su vehículo con CDL, quedaría descalificado?","options":["0.04 o más","0.08 o más","0.10 o más","0.02 o más"],"explanation":"Para un conductor con CDL que opera un vehículo comercial, el límite legal es una concentración de alcohol en sangre de 0.04 por ciento o más, la mitad del límite normal."},"466":{"q":"Lo detienen en una inspección al borde de la carretera mientras opera su vehículo comercial (CMV), y el oficial tiene causa razonable para pedirle que se someta a una prueba que mide su concentración de alcohol en la sangre. Usted está seguro de que está por debajo del límite legal de 0.04% y le preocupa que la prueba pueda ser inexacta, así que le dice al oficial que prefiere simplemente negarse. Según las reglas de la CDL, ¿cuál es la consecuencia de esa negativa?","options":["No le pasa nada a su CDL siempre que su concentración real de alcohol resulte ser inferior a 0.04%","Queda descalificado para operar un CMV, tratado igual que si hubiera reprobado la prueba","Recibe solo una pequeña multa administrativa pero conserva todos sus privilegios de conducción","Recibe una advertencia por escrito en la primera negativa y solo es sancionado si se niega de nuevo"],"explanation":"Negarse a una prueba de alcohol exigida legalmente lo descalifica para operar un vehículo comercial, la misma sanción que reprobar la prueba."},"467":{"q":"Durante un viaje nocturno, regresa a su tractocamión después de cenar cuando un agente estatal lo detiene en un punto de control en la carretera. Una prueba química muestra que su concentración de alcohol en sangre es del 0,06%, por encima del límite del 0,04% para CDL, y lo declaran culpable de operar el vehículo comercial bajo los efectos del alcohol. Es la primera condena de este tipo en su historial. Suponiendo que no se transportaban materiales peligrosos, ¿cuál es el período MÍNIMO de descalificación de su CDL?","options":["60 días, el mismo período que para un patrón de infracciones de tránsito graves","90 días, el período mínimo fuera de servicio por falsificar el registro de horas","Un año de descalificación","Tres años, igual que una primera infracción transportando materiales peligrosos"],"explanation":"Una primera condena por conducir un vehículo comercial con un nivel de alcohol en sangre de 0.04% o más conlleva la descalificación de la CDL por al menos un año cuando no hay materiales peligrosos."},"469":{"q":"Está detenido en una estación de pesaje del DPS de Texas durante una inspección en carretera. El oficial ya confirmó que su licencia de conducir comercial (CDL) es válida y que su bitácora está en orden. Luego le pide que presente un documento más que las normas federales exigen llevar consigo siempre que opera el vehículo, para demostrar que está físicamente apto para conducir. ¿Qué documento debe entregarle?","options":["Su certificado de graduación de la escuela de capacitación para CDL, que demuestra que completó la instrucción obligatoria para conductores principiantes","El certificado de título del vehículo, que demuestra que el camión está legalmente registrado y autorizado para circular","Su certificado de nacimiento original, que acredita su identidad y su derecho legal a poseer la licencia comercial","Su certificado del examinador médico (tarjeta médica), que demuestra que está actualmente apto físicamente para operar un vehículo comercial"],"explanation":"Debe llevar su certificado del examinador médico (tarjeta médica) junto con su CDL, ya que comprueba que está actualmente apto físicamente para conducir un vehículo comercial."},"470":{"q":"Va aproximadamente 30 minutos retrasado respecto a su horario en una autopista dividida de cuatro carriles. El conductor que va delante avanza más despacio de lo que usted quisiera, así que está sopesando sus opciones. Según las normas del DPS de Texas, ¿cuál de las siguientes acciones se consideraría una infracción de tránsito GRAVE que podría poner en riesgo su CDL?","options":["Seguir al vehículo más lento a una distancia segura y esperar una oportunidad legal para rebasar","Bajar brevemente por debajo de la velocidad mínima señalizada para revisar los espejos antes de cambiar de carril","Zigzaguear agresivamente entre el tráfico y pegarse al vehículo de adelante para obligar al conductor lento a hacerse a un lado","Señalizar su cambio de carril un poco antes de lo que espera el vehículo que va justo delante"],"explanation":"Zigzaguear agresivamente entre el tráfico y pegarse al vehículo de adelante para presionar a otro conductor es conducción imprudente, una infracción grave que puede causar la descalificación de la CDL."},"471":{"q":"Su tractocamión con remolque se queda parado en el acotamiento derecho de una carretera plana, recta, de dos carriles y sin división central. Enciende las luces intermitentes de emergencia y toma sus triángulos reflectantes para colocarlos antes de que se cierre la ventana de 10 minutos. Mientras camina hacia la parte trasera de su unidad para colocar el PRIMER triángulo (el más cercano), ¿aproximadamente a qué distancia detrás del vehículo debe ponerlo?","options":["A unos 10 pies detrás del vehículo, del lado del tránsito","A unos 100 pies detrás del vehículo","A unos 200 pies detrás del vehículo","Justo en la defensa trasera, pegado al vehículo"],"explanation":"El triángulo de advertencia más cercano se coloca aproximadamente a 10 pies detrás del vehículo, del lado del tráfico, para marcar la parte trasera inmediata del camión."},"472":{"q":"Se daña un rodamiento de rueda y deja rodar su tractocamión hasta el acotamiento de una carretera plana, recta, de dos carriles y sin división central. Tras encender las luces intermitentes de emergencia, toma sus triángulos de advertencia y empieza a colocarlos hacia el tráfico que se aproxima. Coloca correctamente el primer triángulo a 10 pies por detrás. En este tipo de carretera, ¿aproximadamente a qué distancia por detrás del vehículo debe ir el SEGUNDO triángulo que coloca atrás?","options":["A unos 200 pies por detrás, y un tercero otros 200 pies más allá","A unos 100 pies por detrás del vehículo","A unos 50 pies por detrás del vehículo","A unos 100 pies por delante del vehículo, en el carril contrario"],"explanation":"En una carretera de dos carriles o sin división, el segundo triángulo se coloca aproximadamente a 100 pies detrás del vehículo porque el tráfico puede acercarse desde ambas direcciones."},"473":{"q":"Su tractocamión se avería en el carril derecho de una carretera recta, plana y DIVIDIDA (una calzada de un solo sentido con una mediana que separa el tráfico opuesto) con buena visibilidad. Enciende las luces intermitentes de emergencia y toma su kit de triángulos de advertencia. Mientras camina hacia atrás para colocar el triángulo que debe quedar MÁS LEJOS de la parte trasera de su vehículo, ¿a qué distancia aproximada debe ponerlo?","options":["A unos 100 pies por detrás, ya que ahí va el triángulo del medio","A media milla por detrás, para dar al tráfico rápido la mayor advertencia posible","A unos 200 pies por detrás del vehículo","A unos 10 pies por detrás, justo pasando el parachoques trasero"],"explanation":"En una autopista de un solo sentido o dividida, los tres triángulos van detrás del vehículo, y el más lejano se coloca aproximadamente a 200 pies hacia el tráfico que se acerca."},"474":{"q":"Se ha detenido en el acotamiento derecho de una autopista de un solo sentido (dividida), justo pasada la cima de una colina, donde los vehículos que vienen detrás no pueden ver su camión hasta el último momento. Enciende las luces intermitentes de emergencia y comienza a colocar sus tres triángulos reflectantes. Cuando llegue el momento de colocar el triángulo más lejano que protege su parte trasera del tráfico que se aproxima, ¿qué debe hacer para compensar que la colina bloquea la visibilidad?","options":["Mantener los tres triángulos a menos de 10 pies del camión para que queden agrupados y visibles juntos","Colocar el triángulo lejano exactamente a 200 pies, igual que en un tramo plano y despejado, ya que esa distancia es el estándar legal","Omitir por completo el triángulo lejano y confiar en las luces intermitentes, que en una colina son más brillantes que un triángulo","Mover el triángulo lejano más allá de su posición normal de 200 pies (hasta 500 pies), para que los conductores coronen la colina con suficiente aviso para reaccionar"],"explanation":"Cerca de una colina o curva que bloquea la línea de visión, mueva el triángulo lejano más allá de su posición normal (hasta 500 pies) para que los conductores que se acercan reciban suficiente advertencia."},"475":{"q":"Durante la inspección previaje en un área de descanso, huele humo y encuentra un pequeño incendio que comenzó en un montón de cajas de cartón desechadas, papel de embalaje y una pila de mantas de mudanza cerca de las puertas traseras de su remolque. Toma su extintor y verifica su clasificación antes de actuar. ¿Qué clase de extintor está diseñada específicamente para el tipo de materiales que se están quemando aquí?","options":["Clase A, clasificada para combustibles ordinarios como madera, papel y tela","Clase B, clasificada para líquidos en llamas como combustible, aceite y grasa","Clase C, clasificada para incendios en cableado eléctrico con corriente y equipos energizados","Clase D, clasificada para metales combustibles como magnesio y titanio"],"explanation":"Los incendios en combustibles ordinarios como madera, papel y tela corresponden a un extintor Clase A."},"476":{"q":"Durante su inspección previaje revisa el extintor montado en la cabina. Transporta tambores de combustible diésel y quiere asegurarse de que el extintor pueda realmente enfrentar el incendio más probable para esta carga. Una pequeña fuga de combustible se enciende cerca de los tambores. ¿Qué clase de extintor está clasificada para combatir este incendio de líquidos inflamables?","options":["Un extintor Clase A, ya que es el tipo más común y sirve para los palés de madera y los albaranes de papel que también van en el remolque","Un extintor Clase B, ya que está clasificado para líquidos inflamables como combustible, aceite y grasa","Un extintor Clase C, ya que el incendio comenzó cerca del sistema eléctrico y de la batería del camión","Un extintor Clase D, ya que está destinado a incendios de tela combustible, trapos y paños de taller"],"explanation":"Los incendios de líquidos inflamables como combustible, aceite y grasa corresponden a un extintor Clase B."},"477":{"q":"Durante la inspección previaje huele algo caliente cerca del tablero y descubre humo que sale de detrás del panel de cableado energizado del sistema eléctrico de su tractor. Alcanza el extintor montado en la cabina. Para combatir este incendio de forma segura, ¿qué clase de extintor debe usar?","options":["Un extintor Clase A, porque está clasificado para la madera y el papel del acabado alrededor del panel","Un extintor Clase B, porque está clasificado para los líquidos inflamables que originan la mayoría de los incendios en camiones","Un extintor Clase C, porque está clasificado para incendios en equipos eléctricos energizados","Cualquier clase sirve siempre que primero desconecte la batería con el corte de corriente"],"explanation":"Los incendios en equipo eléctrico energizado requieren un extintor Clase C porque su agente no conductor no transmite corriente de vuelta al operador."},"478":{"q":"La temperatura está justo bajo cero y usted arranca desde una parada en una rampa cubierta de hielo cristalizado. Siente que el camión se sacude y el tacómetro sube de golpe mientras las ruedas motrices empiezan a patinar sin que el vehículo avance. Para arrancar y recuperar la tracción, ¿cuál es la MEJOR acción?","options":["Pisar más fuerte el acelerador para que las ruedas que patinan atraviesen el hielo","Bombear rápidamente el pedal del freno para que las ruedas motrices se aferren a la superficie","Girar el volante rápidamente de lado a lado para que los bordes de las llantas encuentren agarre","Soltar el acelerador para que las ruedas motrices reduzcan velocidad y recuperen la tracción"],"explanation":"En un derrape de las ruedas motrices, suelte el acelerador para reducir la potencia, de modo que las ruedas que giran bajen a la velocidad del vehículo y recuperen la tracción."},"479":{"q":"Está descendiendo una pendiente larga y nota humo y luego llamas que salen de uno de los neumáticos duales de su remolque. Se detiene de forma segura en el arcén, coloca sus triángulos de advertencia y toma sus suministros. Con un neumático ardiendo activamente, ¿cuál de las siguientes es la MEJOR manera de enfriar y apagar el fuego?","options":["Rociarlo con abundante agua, ya que el agua enfría el neumático en llamas","Sofocarlo echando arena seca directamente sobre las llamas","Dejar que la corriente de aire al avanzar lentamente por el arcén enfríe el neumático","Rociar aceite de motor para cubrir y aislar la superficie del neumático del oxígeno"],"explanation":"Apaga un neumático en llamas con abundante agua, ya que el agua enfría el caucho y la carcasa donde se acumula el calor y evita que se reavive."},"480":{"q":"Es una mañana fría y deja su camión en marcha mínima dentro de un muelle de carga cerrado para calentarlo antes de su inspección previa al viaje. Después de unos minutos comienza a sentir mareos y le da dolor de cabeza, pero no ve ni huele nada inusual en el aire. Según cómo se comporta el monóxido de carbono, ¿cuál es la razón MÁS probable de que recibiera poca o ninguna advertencia antes de que comenzaran estos síntomas?","options":["El gas habría despedido primero un olor dulce y penetrante, así que el sistema de escape debe estar sellado y no es la causa","El monóxido de carbono es incoloro e inodoro, por lo que sus sentidos no pueden detectarlo antes de que le afecte","El gas se vuelve de un rojo brillante visible a medida que se acumula, pero la tenue iluminación del muelle se lo ocultó","El monóxido de carbono es más pesado que el aire y se queda cerca del suelo, así que ponerse de pie le habría advertido a tiempo"],"explanation":"El monóxido de carbono es incoloro e inodoro, por lo que tus sentidos no pueden detectarlo antes de que te afecte en espacios cerrados."},"481":{"q":"Conduce un vehículo combinado cargado por una carretera rural de Texas cuando ve más adelante una estación de pesaje con el letrero de \"ABIERTO\" encendido y varios automóviles pasando de largo sin reducir la velocidad. Está cansado y a solo un par de millas de su entrega. ¿Qué acción es legalmente correcta?","options":["Pasar de largo como hicieron los automóviles, ya que hoy la estación claramente solo inspecciona vehículos de pasajeros","Considerar la estación como opcional y entrar solo si un oficial le hace señas o si su peso bruto le parece elevado","Entrar en la estación de pesaje abierta, porque los camiones están obligados por ley a detenerse en cualquier estación de pesaje abierta por la que pasen","Omitirla porque está a un par de millas de su entrega final y su carga ya está asegurada"],"explanation":"La ley exige que los camiones se detengan en cualquier estación de pesaje abierta que pasen, sin importar la fatiga, la carga o lo que hagan los autos."},"482":{"q":"Durante su inspección previaje en una báscula de carretera, un inspector del DPS de Texas detecta un defecto de frenos en su tractocamión, levanta el acta y coloca una orden de fuera de servicio (out-of-service, OOS) sobre el vehículo. El taller está a 8 millas y su ventana de entrega cierra en una hora. ¿Qué acción es legalmente correcta?","options":["Como la carga es urgente, puede conducir las 8 millas directamente hasta el taller a velocidad reducida","Puede continuar su ruta siempre que se mantenga por debajo de 55 mph y use solo un frenado ligero y constante","Puede conducir una vez que llene el tanque de combustible y el manómetro de frenos de aire marque presión total","No puede conducir el vehículo en absoluto hasta que el defecto sea reparado y la orden sea levantada"],"explanation":"Una orden de fuera de servicio te prohíbe legalmente conducir en la vía pública hasta que se repare el defecto y se levante la orden."},"483":{"q":"Un inspector de carretera en una báscula le pide revisar sus registros del estado de servicio (records of duty status) de su ELD. Su despachador afirma que el dispositivo existe principalmente para satisfacer al fisco y al departamento de contabilidad de su flota. ¿Qué afirmación describe mejor lo que sus registros del estado de servicio están realmente diseñados para documentar en esta inspección?","options":["La cantidad de horas que ha conducido y ha estado de servicio, para que el oficial pueda confirmar que está dentro de sus límites legales de horas de servicio (hours of service)","Las compras de combustible y el kilometraje por estado, para que el oficial pueda verificar que su declaración de impuestos IFTA es correcta","El historial de mantenimiento y reparación del vehículo, para que el oficial pueda confirmar que se realizaron las inspecciones requeridas","El peso de la carga y las revisiones de sujeción, para que el oficial pueda confirmar que volvió a revisar su carga cada 150 millas"],"explanation":"Los registros del estado de servicio documentan tus horas de conducción y de servicio para que un inspector confirme que cumples los límites legales de horas de servicio."},"484":{"q":"Está incorporándose a una autopista con su tractocamión cargado y desea acelerar rápidamente. La aguja del tacómetro sube rápido y ahora toca la parte superior de la zona roja, pero usted quiere más potencia para seguir el ritmo del tráfico. Para proteger el motor diésel, ¿cuál de las siguientes acciones NO debería hacer?","options":["Dejar que el motor se caliente en ralentí antes de exigirle mucha potencia","Forzar el motor más allá de la línea roja del tacómetro para obtener más aceleración","Subir de marcha para que las revoluciones bajen por debajo de la zona roja antes de acelerar","Usar el rango normal de revoluciones del motor para ganar velocidad de forma gradual"],"explanation":"Nunca lleves el motor más allá de la línea roja del tacómetro, ya que esta marca el RPM máximo seguro y sobrerrevolucionar causa daños graves al motor."},"485":{"q":"Estaciona su tractocamión cargado en una pendiente ligera de bajada en el muelle de un cliente, aplica el freno de estacionamiento y baja de la cabina para empezar a descargar. El terreno no está perfectamente nivelado y estará lejos de la cabina por un buen rato. En estas condiciones, ¿cuál es la única mejor práctica antes de dejar el camión desatendido?","options":["No se necesita nada adicional porque el freno de estacionamiento de resorte sostendrá un remolque cargado indefinidamente en cualquier pendiente","Dejar la transmisión en una marcha baja en lugar de calzar, ya que tener una marcha puesta reemplaza por completo las calzas en una pendiente","Calzar las ruedas, porque existe la posibilidad de que el camión ruede en la superficie inclinada y desnivelada","Omitir las calzas porque la pendiente es solo ligera, y las calzas solo se requieren en bajadas empinadas de montaña"],"explanation":"Calza las ruedas siempre que exista la posibilidad de que el camión ruede, como en una superficie inclinada y desigual donde queda cargado y sin vigilancia."},"486":{"q":"Termina una entrega y debe estacionar su tractocamión apuntando CUESTA ABAJO en un acotamiento rural. En este tramo de la carretera NO hay borde de banqueta (cordón). Al prepararse para dejar el vehículo, ¿cómo debe colocar las ruedas delanteras (del eje de dirección) para que, si el camión llegara a rodar, se desplace LEJOS del tránsito que pasa y no hacia el carril de circulación?","options":["Dejar las ruedas delanteras rectas, ya que en una bajada el freno de estacionamiento y las cuñas hacen toda la retención","Girar las ruedas delanteras fuerte hacia la IZQUIERDA, igual que al estacionar cuesta arriba contra un cordón","Dejar las ruedas rectas y hacerlo solo tras verificar que la banda de rodamiento del eje de dirección tiene al menos 4/32 de pulgada","Girar las ruedas delanteras hacia el borde de la carretera, para que un vehículo que ruede se salga del pavimento lejos del tránsito"],"explanation":"Al estacionar cuesta abajo sin bordillo, gira las ruedas delanteras hacia el borde de la vía para que un vehículo que ruede se desvíe fuera del pavimento, lejos del tráfico."},"487":{"q":"Durante su inspección previaje la temperatura está justo bajo cero y nota que los escalones y las agarraderas de su tractocamión están cubiertos por una fina capa de hielo y mugre del camino. Las normas federales y de Texas exigen inspeccionar estos elementos. Según el manual, ¿cuál es la razón PRINCIPAL por la que debe revisar el estado de los escalones y las agarraderas antes de conducir?","options":["Para poder subir y bajar de la cabina con seguridad, especialmente manteniendo tres puntos de contacto cuando las superficies están resbaladizas","Para poder confirmar que la estructura de la cabina soporta el peso de carga nominal indicado en la placa del GVWR","Para poder verificar que el bastidor y los soportes de montaje no estén agrietados, lo que pondría el vehículo fuera de servicio","Para mantener limpias las botas y evitar arrastrar lodo al piso de la cabina y a los pedales"],"explanation":"Los escalones y agarraderas firmes e intactos te permiten subir y bajar de la cabina con seguridad, manteniendo tres puntos de contacto cuando las superficies están resbaladizas."},"488":{"q":"Es el inicio de su turno y está completando la inspección previa al viaje. Un oficial del DOT podría detenerlo en un control en carretera en cualquier punto de la ruta de hoy y pedirle que muestre el registro del vehículo y el comprobante de seguro. Para mantenerse en cumplimiento y estar listo para esa inspección, ¿dónde deben estar estos documentos en este momento?","options":["Archivados en un gabinete en su casa u oficina de la terminal para que no se puedan perder ni robar en la carretera","Dentro del vehículo con usted, para poder presentarlos a cualquier oficial durante una inspección en carretera","Enviados por correo al DPS de Texas para que el estado conserve la copia oficial en su registro","Subidos a un portal estatal en línea, ya que un registro digital reemplaza la necesidad de llevar copias en papel"],"explanation":"Lleva el registro y el comprobante de seguro dentro del vehículo para poder presentarlos a un agente durante cualquier inspección o parada en carretera."},"489":{"q":"Se aproxima de noche a una intersección rural con su vehículo combinado cargado y ve que el semáforo sobre su carril destella en rojo en su dirección, mientras que el tráfico transversal tiene un destello amarillo. Dado cómo difieren legalmente estas señales, ¿cuál es la acción correcta que debe tomar?","options":["Reducir la velocidad y pasar con precaución sin detenerse, ya que una señal intermitente solo advierte que esté alerta","Mantener la velocidad pero estar listo para ceder, porque el tráfico transversal con destello amarillo debe cederle el paso a usted","Detenerse por completo como en una señal de alto y avanzar solo cuando la intersección esté despejada","Tratarla como una señal averiada, detenerse brevemente y pasar antes de que cambie a rojo fijo"],"explanation":"Una señal roja intermitente equivale a una señal de alto: deténgase por completo, ceda el paso y avance solo cuando la intersección esté despejada."},"490":{"q":"Se acerca a una intersección concurrida de noche cuando el semáforo elevado sobre su carril cambia a amarillo intermitente constante, mientras la calle transversal tiene un rojo intermitente. Varios autos esperan en la calle transversal para incorporarse. ¿Cuál es la forma correcta de cruzar esta intersección?","options":["Tratar el amarillo intermitente exactamente como un rojo fijo: detenerse por completo y luego avanzar cuando la intersección esté despejada","Mantener su velocidad de carretera porque el amarillo intermitente le otorga el derecho de paso absoluto y el tráfico transversal debe permanecer detenido","Detenerse y esperar a que los conductores de la calle transversal pasen primero, porque su rojo intermitente funciona como una parada de cuatro vías que les cede el paso","Reducir la velocidad y cruzar la intersección con precaución, manteniéndose alerta ante el tráfico transversal que está detenido en el rojo intermitente"],"explanation":"Una señal amarilla intermitente es de precaución, no de alto: reduzca la velocidad y cruce la intersección con cuidado."},"491":{"q":"Se acerca a una intersección concurrida con su vehículo combinado cargado cuando nota que el semáforo que lo enfrenta está completamente apagado, sin ninguna luz encendida, debido a un aparente corte de energía. El tráfico transversal también está reduciendo la velocidad. Para proceder de manera legal y segura, ¿cómo debe tratar esta intersección?","options":["Como un alto de cuatro vías (four-way stop): deténgase por completo y luego avance por turnos según el orden de llegada de los vehículos, cediendo el paso a quienes llegaron primero","Como un ceda el paso: reduzca la velocidad y deténgase solo si otro vehículo ya está en la intersección; de lo contrario, pase sin detenerse","Como una luz verde para la calle principal, ya que el vehículo comercial más grande tiene la preferencia de paso sobre el tráfico transversal","Como un paso libre: mantenga su velocidad a través de la intersección porque un semáforo apagado no es una intersección controlada"],"explanation":"Un semáforo apagado o averiado debe tratarse como un alto de cuatro vías, avanzando los vehículos en el orden en que llegaron."},"492":{"q":"Está transportando un remolque cargado por una carretera de dos carriles detrás de un tractor agrícola lento. El centro de la carretera está marcado con una doble línea amarilla continua. Está perdiendo tiempo y quiere rebasar al tractor. Según esta marca del pavimento, ¿cuál de las siguientes es la acción correcta?","options":["Puede cruzar la línea para rebasar porque el carril de su lado es el carril más rápido","No debe rebasar, porque una doble línea amarilla continua en el centro prohíbe rebasar en ambos sentidos de circulación","Puede rebasar siempre que no se vea tráfico en sentido contrario dentro de 500 pies","La marca solo restringe el estacionamiento, así que se permite rebasar cuando la vía está despejada"],"explanation":"Una doble línea amarilla continua en el centro prohíbe rebasar en ambos sentidos, por lo que no debe cruzarla para adelantar."},"493":{"q":"Usted conduce por una autopista de varios carriles en Texas con tráfico moderado cuando las marcas del pavimento cambian: la línea blanca discontinua entre su carril y el carril a su derecha se convierte en una sola línea blanca CONTINUA (sólida) que sigue por un largo tramo. El tráfico en su carril avanza un poco más lento que el del carril contiguo. ¿Qué comunica esta línea blanca continua y cómo debería responder?","options":["Marca el borde de la calzada, así que debería arrimarse hacia el acotamiento para que el tráfico más rápido lo rebase por la izquierda","Es igual que una línea discontinua, así que puede pasarse a la derecha cuando aparezca un hueco para mantener el ritmo del carril más rápido","Desaconseja cruzarla, así que debe permanecer en su carril y cambiar de carril solo si es verdaderamente necesario y seguro hacerlo","Significa que rebasar está prohibido para todos, así que debe mantener su posición exacta y no puede cambiar de carril bajo ninguna circunstancia"],"explanation":"Una línea blanca continua sencilla separa carriles del mismo sentido y desaconseja el cambio de carril, así que cámbielo solo si es necesario y seguro."},"494":{"q":"Conduce su tractocamión con remolque por una carretera de dos carriles sin división, a plena luz del día, cuando el autobús escolar que va delante de usted activa sus luces ROJAS intermitentes alternas y extiende su brazo de pare. Usted circula a una distancia legal y hay poco tráfico detrás. ¿Qué está obligado a hacer?","options":["Reducir a unas 15 mph, cubrir el freno y rebasar el autobús solo por su lado izquierdo, ya que está en una carretera sin división","Seguir avanzando a una velocidad muy lenta mientras vigila a los niños, porque solo se exige una parada total cuando el autobús muestra luces amarillas (ámbar) de advertencia","Salir al acotamiento, colocar sus triángulos reflectantes y esperar a que el conductor del autobús le haga señas para avanzar","Detenerse por completo y permanecer detenido hasta que las luces rojas dejen de parpadear y el brazo de pare se retraiga"],"explanation":"Las luces rojas intermitentes con el brazo de alto extendido obligan a detenerse al tránsito en ambos sentidos de una vía sin división hasta que las luces se apaguen y el brazo se retraiga."},"495":{"q":"En su ruta se aproxima a un tramo de reparación con placas de acero y a un puente con tablero de rejilla metálica. Las condiciones han cambiado varias veces hoy. ¿En cuál de las siguientes situaciones debería esperar que estas superficies metálicas le den MENOS tracción y se comporten casi como hielo?","options":["Acaba de empezar una lluvia ligera y las placas de acero y la rejilla del puente están mojadas","El pavimento y las superficies metálicas están completamente secos bajo un sol brillante de la tarde","Las placas de acero se instalaron apenas ayer y todavía se ven completamente nuevas","Una cuadrilla de mantenimiento acaba de terminar de barrer la grava suelta y el polvo de las placas"],"explanation":"Las placas de acero y los tableros metálicos de puentes ofrecen poca tracción y se vuelven tan resbaladizos como el hielo cuando están mojados."},"496":{"q":"Sale de una autopista dividida y a mediodía gira hacia una concurrida calle comercial del centro. El tráfico es denso, hay autos estacionados a ambos lados, furgonetas de reparto en doble fila, y pasa una parada de autobús y varios comercios. En comparación con la autopista abierta que acaba de dejar, ¿a qué peligro debe prestar AHORA la MAYOR atención?","options":["Tramos rectos largos y vacíos donde podría aumentar con seguridad su distancia de seguimiento","Peatones que pueden salir de repente entre autos estacionados, autobuses o comercios","Campos abiertos junto a la vía que le dan espacio adicional para recuperarse de un derrape","Grava suelta y escombros típicos de los arcenes rurales, lejos de esta zona"],"explanation":"En la ciudad, vigile de cerca a los peatones que pueden salir de repente entre autos estacionados, autobuses o tiendas."},"497":{"q":"Es media mañana y conduce un vehículo combinado cargado por una estrecha carretera rural de dos carriles a través de zona agrícola. La velocidad indicada es de 55 mph, pero al coronar una pequeña loma su visión se despeja hasta aproximadamente un cuarto de milla por delante. De los siguientes peligros, ¿con cuál es MÁS probable que se encuentre circulando muy por debajo de la velocidad indicada, obligándole a ajustar su distancia de seguimiento y posiblemente cambiar de carril para adelantar?","options":["Un autobús urbano de transporte público deteniéndose en marquesinas de pasajeros señalizadas","Automóviles ligeros de pasajeros incorporándose desde una rampa de acceso a una autopista","Maquinaria agrícola de movimiento lento, como un tractor o una cosechadora","Un tren de metro de cercanías circulando paralelo a la carretera"],"explanation":"En carreteras rurales de dos carriles, esté atento a maquinaria agrícola lenta como tractores y cosechadoras que circulan muy por debajo del límite."},"498":{"q":"Está detenido al frente de una intersección en su vehículo combinado cargado, esperando para girar a la izquierda cruzando dos carriles de tráfico que viene en sentido contrario. La flecha roja fija que lo retenía cambia a una flecha amarilla de giro a la izquierda que PARPADEA de forma constante. Los vehículos que vienen de frente siguen acercándose a la intersección a velocidad. ¿Cuál respuesta es legalmente correcta y la más segura para un conductor de su tamaño y longitud?","options":["Inicie el giro de inmediato, porque una flecha amarilla intermitente funciona exactamente igual que una flecha verde y le da un giro protegido con derecho de paso","Permanezca completamente detenido y trate la flecha amarilla intermitente como una flecha roja fija, esperando una flecha verde fija antes de moverse","Avance al giro pero planee detenerse y quedarse en medio de la intersección hasta que se libere un espacio en el tráfico que viene de frente","Puede iniciar el giro, pero debe ceder el paso al tráfico que viene de frente y completar el giro solo cuando exista un espacio lo bastante grande para que toda la longitud de su vehículo libere la intersección con seguridad"],"explanation":"Una flecha amarilla intermitente permite el giro pero no otorga prioridad, así que ceda el paso al tránsito que viene y gire solo cuando el espacio sea suficiente para librarlo con seguridad."},"499":{"q":"Se ve obligado a detenerse en el acotamiento después de que falla un acoplamiento y el diésel comienza a acumularse sobre el pavimento alrededor de la parte trasera de su remolque. Aún debe señalizar su unidad detenida para el tránsito que se aproxima. Considerando el combustible en el suelo, ¿qué dispositivo de advertencia es la opción más segura para colocar?","options":["Un triángulo reflectante, porque advierte al tránsito sin ninguna llama ni calor que pudiera encender el combustible derramado","Una bengala encendida, porque las bengalas son el dispositivo de advertencia estándar más visible y son equipo obligatorio en su camión","Una bengala de señalización encendida colocada contra el viento respecto al derrame para que la llama quede lejos de los vapores del diésel","Una pequeña vela encendida colocada en el pavimento, ya que su llama es demasiado baja para alcanzar el combustible"],"explanation":"Un triángulo reflectante no produce llama, chispa ni calor, por lo que advierte al tráfico de forma segura sin riesgo de inflamar el combustible derramado."},"500":{"q":"En la inspección previa al viaje nota un desgaste disparejo en las llantas delanteras (de dirección). En el punto más bajo la banda mide unos 3/32 de pulgada. ¿Cuál es la decisión correcta?","options":["No conducir — las llantas del eje de dirección requieren al menos 4/32 de pulgada","Conducir — 3/32 supera el mínimo de 2/32 de pulgada que rige las llantas","Conducir — el desgaste disparejo solo importa en las llantas de tracción y remolque","No conducir — toda llanta bajo 6/32 de pulgada es ilegal en un vehículo comercial"],"explanation":"Los neumáticos del eje de dirección deben tener al menos 4/32 de pulgada de banda de rodadura, un estándar más alto que los 2/32 exigidos a los demás neumáticos."},"501":{"q":"Hizo una inspección previa completa, aseguró la carga y ya recorrió 45 millas en la autopista sin novedad. Según las reglas de inspección de carga, ¿qué debe hacer?","options":["Nada aún — la primera reinspección de carga es a las 150 millas o 3 horas","Nada — una vez asegurada e inspeccionada, no se revisa hasta cargar combustible","Detenerse en las próximas millas — la primera revisión se exige dentro de las primeras 50 millas","Detenerse ya — la carga debe reinspeccionarse cada 25 millas"],"explanation":"La primera revisión de la carga y los dispositivos de sujeción debe hacerse dentro de las primeras 50 millas, porque las amarras se asientan y la carga se desplaza más al principio."},"502":{"q":"Al revisar la dirección, el volante gira más de 10 grados (unas dos pulgadas de juego en el borde de un volante de 20 pulgadas) antes de que las ruedas delanteras se muevan. ¿Qué significa?","options":["Juego libre normal que todo camión pesado tiene — no hay que hacer nada","Juego excesivo en la dirección — el vehículo es inseguro hasta que se repare","La dirección hidráulica apenas se calienta; se ajustará al conducir","Un detalle menor que puede anotar en el reporte posterior y seguir conduciendo"],"explanation":"Más de unos 10 grados de juego libre en la dirección hace que el vehículo sea difícil de controlar e inseguro de conducir hasta que se repare."},"503":{"q":"Al final de su turno descubre un problema de ajuste de frenos. Respecto al Reporte de Inspección del Vehículo por el Conductor (DVIR), ¿qué afirmación es correcta?","options":["El DVIR solo se exige antes del viaje, nunca después","El reporte posterior es opcional si hizo la inspección previa esa misma mañana","Puede reportar el defecto solo de forma verbal; no hace falta registro escrito","Debe anotar el defecto en un reporte posterior escrito para que se repare antes de volver a usar el vehículo"],"explanation":"Los defectos hallados durante el viaje deben anotarse en un informe escrito de inspección posterior al viaje para que se reparen antes de volver a usar el vehículo."},"504":{"q":"La temperatura está apenas bajo cero. El pavimento se ve mojado y brillante, pero nota que el rocío de las llantas que normalmente vería de los vehículos de adelante ha cesado. ¿Cuál es la interpretación y acción más segura?","options":["Probablemente se forma hielo negro — reduzca la velocidad y evite giros o frenadas bruscas","El camino solo está mojado por la lluvia anterior — mantenga su velocidad","Sus propias llantas pierden aire — orille y revise la presión","Es solo escarcha en el parabrisas — encienda el desempañador y siga"],"explanation":"Una carretera mojada y brillante sin salpicaduras de los neumáticos a temperaturas cercanas a la congelación indica hielo negro, así que reduzca la velocidad y evite frenar o girar bruscamente."},"505":{"q":"Su vehículo comienza a hidroplanear en un tramo inundado de la autopista. Debe hacer todo lo siguiente, EXCEPTO:","options":["Soltar el acelerador para que las ruedas reduzcan velocidad","Pisar el embrague para que las ruedas giren libremente","Frenar con firmeza para forzar las llantas de vuelta al pavimento","Mantener el volante recto hasta sentir que regresa la tracción"],"explanation":"Durante un hidroplaneo nunca frene con fuerza, pues bloquea los neumáticos y empeora el deslizamiento; en su lugar suelte el acelerador y mantenga el volante recto hasta recuperar la tracción."},"506":{"q":"Conduce una combinación de 60 pies a 60 mph en camino seco y buenas condiciones. Según la regla de distancia de seguimiento de Texas, el intervalo mínimo que debe mantener es de aproximadamente:","options":["Unos 6 segundos","Unos 7 segundos","Unos 4 segundos","Unos 10 segundos"],"explanation":"Cuente un segundo por cada 10 pies de longitud por debajo de 40 mph más un segundo adicional por encima de 40 mph, así que un vehículo de 60 pies necesita unos 7 segundos de distancia de seguimiento."},"507":{"q":"Empieza a llover fuerte tras varias semanas secas. ¿Por qué la primera parte de la lluvia es especialmente peligrosa y cómo debe responder?","options":["La lluvia enfría el motor, así que puede ir un poco más rápido con seguridad","El único peligro real es el parabrisas — use los limpiadores y mantenga la velocidad","La lluvia nueva mejora la tracción de inmediato; solo el agua profunda preocupa","El aceite y el polvo forman una capa resbalosa antes de lavarse — reduzca la velocidad y aumente la distancia"],"explanation":"Cuando comienza a llover, el aceite y el polvo flotan formando una película resbaladiza que hace la carretera más deslizante, así que reduzca la velocidad y aumente la distancia de seguimiento."},"508":{"q":"Conduciendo de noche en una autopista sin alumbrado con luces bajas, nota que no puede detenerse dentro de la distancia que iluminan sus faros. La respuesta correcta es:","options":["Reducir la velocidad para poder detenerse dentro de la distancia que ve","Cambiar a luces altas y mantener la velocidad para no atrasarse","Acercarse detrás de otro camión y guiarse por sus luces","Mantener la velocidad pero vigilar más la línea del borde derecho"],"explanation":"Nunca sobrepase el alcance de sus faros: su velocidad debe permitirle detenerse dentro de la distancia que realmente puede ver, lo que significa reducir la velocidad con las luces bajas."},"509":{"q":"Está a punto de entrar en un banco de niebla densa. ¿Cuál de las siguientes NO es una práctica recomendada?","options":["Reducir la velocidad antes de llegar a la niebla","Usar las luces bajas en lugar de las altas","Usar los limpiadores y el desempañador para mantener limpio el parabrisas","Encender las luces altas para que la luz más brillante atraviese la niebla"],"explanation":"Use las luces bajas en la niebla, porque las luces altas se reflejan en las gotas de agua y le devuelven el deslumbramiento, reduciendo lo que puede ver."},"510":{"q":"La temperatura está justo en el punto de congelación y los caminos se ven mayormente despejados. ¿Qué superficie debe tratar como helada primero, aunque el resto del camino parezca bien?","options":["Tramos rectos y abiertos que reciben pleno sol","Las subidas, porque el motor calienta la superficie","Los túneles, que atrapan aire caliente y siguen resbalosos más tiempo","Puentes y pasos elevados, que se congelan antes que el camino que los rodea"],"explanation":"Los puentes y pasos elevados pierden calor por arriba y por abajo, por lo que se congelan antes que la carretera sobre suelo firme aunque el resto del pavimento siga limpio."},"511":{"q":"En un día muy caluroso se detiene y encuentra las llantas notablemente calientes, con una presión mayor que la normal en frío. ¿Cuál es la acción correcta?","options":["Sacar aire hasta que la presión vuelva al valor normal en frío","Conducir más rápido para que el aire enfríe las llantas","Echar agua sobre las llantas para enfriarlas rápido","Dejar las llantas en paz; si una está demasiado caliente al tacto, deje de conducir hasta que se enfríe"],"explanation":"El calor normalmente eleva la presión de los neumáticos, así que no los toque; pero un neumático demasiado caliente para tocarlo indica un problema, así que deténgase hasta que se enfríe para evitar un reventón."},"512":{"q":"Cruza una vía férrea con transmisión manual y carga pesada. La regla más importante sobre la selección de marcha en el cruce es:","options":["Elegir la marcha antes de las vías y no cambiar mientras cualquier parte del vehículo esté sobre el cruce","Reducir de marcha más o menos a mitad del cruce para mantener fuerza","Poner neutro y cruzar en inercia para reducir la vibración","Usar la marcha más alta para librar las vías lo más rápido posible"],"explanation":"Elija una marcha que lo lleve hasta el otro lado antes de llegar a las vías y nunca cambie de marcha mientras alguna parte del vehículo esté en el cruce, para no quedarse parado sobre los rieles."},"513":{"q":"Se acerca a una bajada larga y empinada. ¿Cuándo y cómo debe elegir la marcha?","options":["Esperar a que los frenos empiecen a fallar y entonces reducir de marcha","Poner neutro para ahorrar combustible y controlar la velocidad solo con los frenos","Quedarse en marcha alta y frenar suavemente toda la bajada","Elegir una marcha baja antes de empezar a bajar — normalmente más baja que la que usaría para subir la misma cuesta"],"explanation":"Seleccione la marcha baja antes de bajar para que el freno motor y de compresión controlen su velocidad; en los camiones modernos la marcha segura de bajada suele ser más baja que la de subida."},"514":{"q":"En una bajada larga ya va en la marcha baja correcta y su velocidad segura es 35 mph. ¿Qué técnica de frenado controla bien su velocidad?","options":["Aplicar presión de freno ligera y constante durante toda la bajada","Bombear los frenos rápida y constantemente para mantenerlos fríos","Mantener los frenos pisados con fuerza hasta el final de la bajada","Al llegar a unas 40 mph, frenar con firmeza hasta unas 30, soltar y repetir"],"explanation":"El frenado intermitente correcto consiste en dejar que la velocidad suba unas 5 mph por encima de su velocidad segura, frenar firmemente hasta unas 5 mph por debajo, soltar y repetir para que los frenos se enfríen."},"515":{"q":"Sus frenos han fallado seriamente en una bajada de montaña y va ganando velocidad. Debe hacer todo lo siguiente, EXCEPTO:","options":["Buscar y usar una rampa de escape si hay una disponible","Poner neutro para que el camión baje en inercia de forma más suave","Si no hay rampa, buscar una ruta de escape como un campo abierto o un camino lateral","Mantener la marcha más baja y usar el frenado que le quede para reducir lo más posible"],"explanation":"Nunca ponga el cambio en punto muerto en una bajada porque elimina el freno motor y deja que acelere; mantenga el vehículo en una marcha baja."},"516":{"q":"Las ruedas de tracción empiezan a patinar en un camino resbaloso y la parte trasera del tractor comienza a irse a la derecha. Para recuperar el control, primero debe:","options":["Dejar de acelerar (y pisar el embrague), luego dirigir hacia donde quiere que vaya el frente del vehículo","Frenar fuerte para detener el patinazo de inmediato","Girar bruscamente a la izquierda, en sentido contrario al patinazo","Acelerar para volver a alinear el remolque"],"explanation":"En un derrape de las ruedas motrices, primero elimine la causa soltando el acelerador y pisando el embrague para que las ruedas recuperen el agarre, luego dirija hacia donde quiere que vaya el frente."},"517":{"q":"En una curva cerrada sus ruedas delanteras pierden tracción y el camión sigue derecho aunque las ruedas están giradas. La causa habitual y la respuesta correcta son:","options":["Causa: poca velocidad — acelerar para recuperar la dirección","Causa: llantas traseras sobreinfladas — orillarse y sacar algo de aire","Causa: ir demasiado rápido para las condiciones — soltar el acelerador, y al bajar la velocidad las ruedas delanteras volverán a agarrar","Causa: el remolque empuja — aplicar fuerte la válvula de mano del remolque"],"explanation":"Un derrape de las ruedas delanteras suele deberse a conducir demasiado rápido para las condiciones, y como girar el volante no sirve, debe levantar el pie para que los neumáticos delanteros vuelvan a agarrar al frenar."},"518":{"q":"Un auto se detiene de repente en su carril y no tiene espacio para frenar a tiempo. En la mayoría de los casos la acción de emergencia más segura es:","options":["Frenar lo más fuerte posible y esperar detenerse justo antes","Esquivar el obstáculo — suele poder girar para librarlo en menos distancia de la que toma frenar","Bloquear los frenos y sujetar el volante rígidamente recto","Frenar fuerte y girar al mismo tiempo para máximo efecto"],"explanation":"A velocidad de autopista normalmente puede cambiar de dirección en menos distancia de la que necesita para detenerse, por lo que esquivar el peligro y luego contravirar suele evitar el choque cuando frenar no puede."},"519":{"q":"A velocidad de autopista escucha un fuerte estallido, la dirección jala con fuerza hacia un lado y el vehículo da tumbos — señales de un reventón de llanta delantera. Su respuesta inmediata debe ser:","options":["Frenar con firmeza de inmediato para reducir antes de perder el control","Acelerar un instante para recuperar estabilidad y luego frenar","Dirigirse rápido al acotamiento mientras frena fuerte","Sujetar el volante con firmeza, no tocar el freno y dejar que el vehículo reduzca antes de orillarse"],"explanation":"Tras un reventón, sujete el volante con firmeza y no toque el freno, dejando que el vehículo se detenga por sí solo antes de frenar suavemente y orillarse en el acotamiento."},"520":{"q":"Transporta un solo tubo de acero de 9 pies. Según las reglas de sujeción de carga, el número mínimo de amarres requerido es:","options":["Dos — se requieren al menos dos amarres sin importar lo corta que sea la carga","Uno — mide menos de 10 pies, así que un amarre cumple la regla de uno por cada 10 pies","Ninguno — la carga de menos de 10 pies está exenta de las reglas de amarre","Cuatro — un amarre por cada esquina de la carga"],"explanation":"Siempre se requieren al menos dos amarres para cualquier carga, por corta que sea, más un amarre por cada 10 pies de longitud."},"521":{"q":"Su carga pesa 40,000 libras. El límite de carga de trabajo (WLL) combinado de todos los amarres que use debe ser de al menos:","options":["10,000 libras","20,000 libras","40,000 libras","80,000 libras"],"explanation":"El límite de carga de trabajo combinado de los amarres debe ser al menos la mitad del peso de la carga que se asegura."},"522":{"q":"Puede colocar una carga pesada baja y repartida por el piso del remolque, o apilada alta y centrada. ¿Cuál es lo correcto y por qué?","options":["Apilarla alta y centrada para quitar peso de los bordes de los ejes","Apilarla alta para que la carga se mueva menos en las curvas","No hay diferencia mientras el peso total esté dentro de lo legal","Cargarla baja y repartida para mantener bajo el centro de gravedad y reducir el riesgo de volcadura"],"explanation":"Cargar bajo y distribuir el peso de forma uniforme baja el centro de gravedad, el factor más importante para resistir el vuelco y mantener la estabilidad."},"523":{"q":"Una mala distribución del peso causa problemas en ambos extremos. ¿Qué afirmación sobre el peso y el control del vehículo es correcta?","options":["Sobrecargar el eje de tracción siempre mejora la tracción sin desventajas","La distribución del peso solo afecta el consumo de combustible, no el manejo","Muy poco peso en el eje de dirección puede hacer que las llantas delanteras pierdan agarre y debilite el control de la dirección","Una mayor carga por eje siempre acorta la distancia de frenado"],"explanation":"Muy poco peso sobre el eje de dirección reduce el agarre de las ruedas delanteras y debilita el control, por lo que el equilibrio importa tanto como el peso total."}},"hi":{"0":{"q":"अपनी यात्रा-पूर्व जांच के दौरान, आप ट्रेड की गहराई मापते हैं और पाते हैं कि स्टीयरिंग (अगले) एक्सल का एक टायर घिसकर 3/32 इंच रह गया है, जबकि आपके ड्राइव और ट्रेलर के सभी टायर भी 3/32 इंच पर हैं। कौन सा कथन सही ढंग से बताता है कि आपका वाहन चलाना कानूनी है या नहीं?","options":["वाहन चलाना कानूनी नहीं है, क्योंकि स्टीयरिंग एक्सल के टायरों में कम से कम 4/32 इंच ट्रेड होना चाहिए।","वाहन चलाना कानूनी है, क्योंकि सभी टायर हर टायर के लिए निर्धारित 2/32 इंच की न्यूनतम सीमा को पूरा करते हैं।","वाहन चलाना कानूनी है, क्योंकि अगले टायरों को केवल 2/32 इंच की जरूरत है और बाकी ठीक हैं।","वाहन चलाना कानूनी नहीं है, क्योंकि हर एक्सल के सभी टायरों में कम से कम 4/32 इंच ट्रेड होना चाहिए।"],"explanation":"स्टीयरिंग-एक्सल टायरों में कम से कम 4/32 इंच ट्रेड होना चाहिए, इसलिए 3/32 इंच वाला अगला टायर न्यूनतम से कम है और वाहन को चलाना अवैध बना देता है।"},"1":{"q":"अपनी यात्रा-पूर्व जांच के दौरान आप सभी टायरों पर ट्रेड-डेप्थ गेज से माप लेते हैं। स्टीयरिंग-एक्सल (अगले) टायर अच्छे 5/32 इंच दिखाते हैं, लेकिन आपके पिछले ड्राइव टायरों में से एक स्पष्ट रूप से अधिक घिसा हुआ है। यह पिछला (गैर-स्टीयरिंग) टायर कानूनी रूप से कम-से-कम कितनी ट्रेड गहराई के साथ जांच में पास हो सकता है?","options":["1/32 इंच","2/32 इंच","4/32 इंच","6/32 इंच"],"explanation":"अगले स्टीयरिंग एक्सल को छोड़कर सभी टायरों में मुख्य ग्रूव में मापी गई कम से कम 2/32 इंच ट्रेड गहराई होनी चाहिए।"},"2":{"q":"अपने प्री-ट्रिप निरीक्षण के दौरान, इंजन चालू करने से पहले आप स्टीयरिंग व्हील को पकड़कर आगे-पीछे हिलाते हैं। आपके 20 इंच व्यास वाले व्हील पर, अगले पहिए प्रतिक्रिया देना शुरू करने से पहले आप रिम को हर दिशा में कुछ इंच घुमा सकते हैं। किस बिंदु पर यह फ्री प्ले आपको स्टीयरिंग-सिस्टम की खराबी का संदेह कराकर वाहन को सेवा से हटाने पर मजबूर करना चाहिए?","options":["जब अगले पहिए हिलने से पहले व्हील को लगभग 10 डिग्री से अधिक (20 इंच के व्हील पर लगभग 2 इंच) घुमाया जा सके","केवल तब जब अगले पहिए हिलने से पहले व्हील को लगभग 20 डिग्री से अधिक घुमाया जा सके","जब व्हील को लगभग 5 डिग्री से अधिक घुमाया जा सके, क्योंकि कोई भी ध्यान देने योग्य प्ले असुरक्षित है","केवल तब जब फ्री प्ले लगभग 45 डिग्री से अधिक हो, क्योंकि तभी स्टीयरिंग वास्तव में नियंत्रित करना कठिन हो जाता है"],"explanation":"अगले पहिए घूमने से पहले स्टीयरिंग व्हील में लगभग 10 डिग्री (20 इंच के व्हील पर करीब 2 इंच) से अधिक खाली घुमाव अत्यधिक है और स्टीयरिंग में खराबी दर्शाता है।"},"3":{"q":"आपका ट्रैक्टर-ट्रेलर बिना विभाजन वाले दो-लेन राजमार्ग के किनारे पर बंद हो गया है और दोबारा चालू नहीं हो रहा। आप अपनी खतरे की चेतावनी वाली लाइटें (हैज़र्ड फ्लैशर) चालू करते हैं और आपातकालीन चेतावनी किट उठाते हैं ताकि वाहन के 100 फीट पीछे, 100 फीट आगे और 10 फीट पिछली ओर परावर्तक त्रिकोण रख सकें। इस तरह हर आवश्यक स्थान पर चेतावनी उपकरण रखने के लिए कानूनी रूप से सुसज्जित होने हेतु, आपके ट्रक में कम से कम कितने परावर्तक त्रिकोण होने चाहिए?","options":["दो त्रिकोण, क्योंकि एक वाहन के आगे और एक पीछे रखा जाता है","तीन त्रिकोण","10 फीट पिछली ओर रखा एक त्रिकोण, और आपकी हैज़र्ड फ्लैशर लाइटें","छह त्रिकोण, ताकि यातायात की दोनों दिशाओं को निश्चित रूप से कवर किया जा सके"],"explanation":"एक वाणिज्यिक वाहन को आपातकालीन चेतावनी उपकरण के रूप में कम से कम तीन रिफ्लेक्टिव चेतावनी त्रिकोण रखने चाहिए।"},"4":{"q":"आपकी शिफ्ट के बीच में, डीज़ल लाइन का एक फिटिंग इंजन की वायरिंग के पास से ईंधन रिस रहा है। अचानक वहाँ एक छोटी आग भड़क उठती है, जो रिसते डीज़ल से भड़कती है और करंट वाले बिजली के हार्नेस के चारों ओर चटकती है। आप अपने केबिन में लगे अग्निशामक यंत्र की ओर बढ़ते हैं। उस यंत्र पर कौन-सी रेटिंग बताती है कि यह इस जलते ईंधन और करंट वाली बिजली की आग, दोनों से लड़ने के लिए बनाया गया है?","options":["B:C अग्निशामक, जो जलते तरल पदार्थों और बिजली की आग के लिए रेटेड है","क्लास A अग्निशामक, क्योंकि यही मानक रेटिंग है जो वाणिज्यिक वाहनों में रखी जाती है","वॉटर-टाइप अग्निशामक, ताकि डीज़ल को ठंडा कर आग को तेज़ी से दबाया जा सके","आप कौन-सी रेटिंग उठाते हैं इससे फर्क नहीं पड़ता, बशर्ते आप उसे लपटों के आधार पर छोड़ें"],"explanation":"जलता हुआ ज्वलनशील तरल Class B आग है और बिजली वाला उपकरण Class C, इसलिए दोनों के लिए B:C रेटिंग वाला अग्निशामक चाहिए।"},"5":{"q":"सुबह के 5:00 बज रहे हैं और आप अभी-अभी आपको सौंपे गए ट्रैक्टर-ट्रेलर की प्री-ट्रिप जाँच पूरी कर रहे हैं। आपका डिस्पैचर आपको जल्दी निकलने के लिए दबाव डाल रहा है, लेकिन आपको याद है कि संघीय नियमों के अनुसार किसी भी यात्रा से पहले कुछ आपातकालीन उपकरण साथ रखना अनिवार्य है। आपको केबिन में कहीं भी अतिरिक्त बिजली के फ़्यूज़ का सेट नहीं मिला। किस स्थिति में अतिरिक्त फ़्यूज़ साथ रखे बिना गाड़ी चलाना कानूनी है?","options":["केवल तभी जब ट्रक में फ़्यूज़ के बजाय सर्किट ब्रेकर (स्वचालित कटऑफ़) लगे हों","केवल तभी जब आप केबिन में पूरी तरह चार्ज एक अतिरिक्त बैटरी रखते हों","केवल तभी जब ट्रेलर में LED क्लीयरेंस और मार्कर लाइटें लगी हों","केवल तभी जब ट्रैक्टर में बिजली प्रणाली के लिए एक बैकअप (दूसरा) अल्टरनेटर हो"],"explanation":"जब विद्युत प्रणाली सर्किट ब्रेकर से सुरक्षित हो तो अतिरिक्त फ़्यूज़ की आवश्यकता नहीं होती, क्योंकि ब्रेकर बदलने के बजाय रीसेट हो जाते हैं।"},"6":{"q":"सुबह जल्दी का समय है और आप अपनी प्री-ट्रिप जांच शुरू करने के लिए अपने ट्रक के पास पहुंचते हैं। आपका प्रशिक्षक आपको सात-चरण जांच विधि को क्रम से अपनाने की याद दिलाता है। केबिन में चढ़ने, बोनट खोलने या किसी एक स्विच को छूने से पहले, सात-चरण विधि के अनुसार सबसे पहला काम क्या है?","options":["इंजन चालू करें और तेल के दबाव तथा हवा के गेज देखते हुए उसे गर्म होने दें","आगे जाकर जांचें कि हेडलाइट, टर्न सिग्नल और चारों ओर की आपातकालीन फ्लैशर सभी काम कर रही हैं","वाहन का सामान्य अवलोकन करें: पिछली जांच रिपोर्ट देखें और वाहन की समग्र स्थिति तथा उसके आसपास के वातावरण का निरीक्षण करें","वाहन के अगले हिस्से के नीचे जाकर पुष्टि करें कि स्टीयरिंग-एक्सल के टायरों में कम से कम 4/32 इंच ट्रेड है"],"explanation":"सात-चरणीय निरीक्षण का पहला चरण वाहन का समग्र अवलोकन है: पिछली निरीक्षण रिपोर्ट देखना और ट्रक की समग्र स्थिति व आसपास की जाँच करना।"},"7":{"q":"एक ठंडी सुबह है और आप अपना यात्रा-पूर्व निरीक्षण शुरू करने वाले हैं। आपके ट्रक का इंजन बंद है और हुड उठा हुआ है। निम्नलिखित में से कौन-सा वस्तुओं का समूह है जिसे आप अभी, इंजन बंद रहते हुए, जाँच सकते हैं और जाँचना चाहिए?","options":["स्टीयरिंग व्हील का खाली घुमाव और कम वायु दबाव चेतावनी बजर का संचालन","इंजन ऑयल का स्तर, कूलेंट का स्तर, और ड्राइव बेल्ट की स्थिति","एयर कंप्रेसर गवर्नर के कट-इन और कट-आउट दबाव","लोड के तहत अल्टरनेटर आउटपुट और चार्जिंग-सिस्टम गेज"],"explanation":"इंजन बंद होने पर हुड खोलकर इंजन ऑयल स्तर, शीतलक स्तर और ड्राइव बेल्टों की स्थिति की जाँच की जाती है।"},"8":{"q":"तापमान जमाव बिंदु से थोड़ा नीचे है और जब आप अपने लदे हुए संयोजन वाहन को हाईवे की गति तक ले जा रहे हैं तो ऑन-रैंप पर बर्फ की एक पतली परत जम गई है। आप महसूस करते हैं कि ट्रैक्टर के ड्राइव पहिये फिसलना (स्पिन) शुरू कर रहे हैं और केबिन का पिछला हिस्सा बगल की ओर खिसक रहा है। इस फिसलन भरी सतह पर सुरक्षित रूप से गति पकड़ने के लिए, एक्सेलरेटर को संभालने का सबसे अच्छा तरीका क्या है?","options":["धीरे-धीरे और सहजता से शक्ति बढ़ाएँ, और जैसे ही ड्राइव पहिये फिसलना शुरू करें, तुरंत एक्सेलरेटर छोड़ दें","एक्सेलरेटर को जोर से दबाएँ ताकि घूमते पहिये पकड़ बना सकें और बर्फ की परत को तोड़ सकें","ड्राइव पहियों तक जाने वाली शक्ति को काटने के लिए एक्सेलरेटर को तेजी से बार-बार दबाएँ और छोड़ें","स्थिर और मजबूत एक्सेलरेटर बनाए रखें और इंजन की शक्ति को आपको फिसलन वाले हिस्से से खींचकर निकालने दें"],"explanation":"फिसलन भरी सतह पर धीरे-धीरे और सहजता से पावर दें, और ड्राइव पहिए घूमते (स्पिन) ही एक्सेलेरेटर छोड़ें ताकि वे फिर से पकड़ बना लें।"},"9":{"q":"आप अकेले हैं और आपको अपने ट्रैक्टर-ट्रेलर को एक संकरी गली के लोडिंग डॉक में पीछे की ओर लगाना है। आप डॉक तक इस तरह पहुँच सकते हैं कि वाहन आपके बाएँ (चालक) तरफ की ओर पीछे जाए, या आपके दाएँ तरफ की ओर पीछे जाए, जो थोड़ी छोटी क्रिया होगी। यथासंभव सुरक्षित रहने के लिए, आपको कौन-सा तरीका चुनना चाहिए और क्यों?","options":["दाएँ तरफ की ओर पीछे जाएँ, क्योंकि छोटा रास्ता मतलब बिना देखे कम समय तक चलाना","दाएँ तरफ की ओर पीछे जाएँ, लेकिन यात्री खिड़की से झुककर एक सहायक का उपयोग करके अंधे क्षेत्र को कवर करें","दोनों तरफ समान रूप से सुरक्षित हैं, इसलिए दाएँ तरफ चुनें क्योंकि यह तेज़ क्रिया है","चालक (बाएँ) तरफ की ओर पीछे जाएँ, भले ही वह लंबा हो, क्योंकि आप केवल शीशों पर निर्भर रहने के बजाय साइड खिड़की से ट्रेलर के पिछले हिस्से को देख सकते हैं"],"explanation":"जब भी संभव हो चालक (बाईं) ओर बैक करें ताकि केवल शीशों पर निर्भर रहने के बजाय साइड खिड़की से ट्रेलर का पिछला हिस्सा सीधे देख सकें।"},"10":{"q":"आप एक भरा हुआ ट्रेलर खींच रहे हैं और एक लंबी, तीव्र ढलान के पास पहुँच रहे हैं जो नीचे एक तीखे मोड़ पर समाप्त होती है। आपका गियरबॉक्स इस समय ऊँचे गियर में है। इस ढलान पर और मोड़ में अपनी गति को नियंत्रित करने के लिए जिस निचले गियर का उपयोग करेंगे, उसे चुनने का सही समय कब है?","options":["ढलान उतरना शुरू करने से पहले और मोड़ से पहले, जब आप अभी भी समतल ज़मीन पर हों","ठीक मोड़ में प्रवेश करते समय, ताकि इंजन की ब्रेकिंग शक्ति वहीं अपने चरम पर हो जहाँ आपको सबसे अधिक ज़रूरत है","ढलान के बीच में, जब आपको लगे कि ट्रक गति पकड़ने लगा है और ब्रेक कमज़ोर पड़ने लगे हैं","केवल मोड़ से बाहर निकलने के बाद, ताकि ड्राइव पहिये मोड़ के दौरान पूरी पकड़ बनाए रखें"],"explanation":"ढलान शुरू करने या मोड़ में घुसने से पहले, समतल जमीन पर रहते हुए ही सही गियर चुनें, क्योंकि उतरते समय गियर बदलना संभव नहीं हो सकता।"},"11":{"q":"आप 55 मील प्रति घंटे की रफ़्तार से एक सूखे राजमार्ग पर चल रहे हैं, तभी बहुत आगे एक कार का टायर फट जाता है और वह अचानक आपकी लेन में रुक जाती है। जिस क्षण ख़तरा सामने आता है उससे लेकर आपके ट्रक के पूरी तरह रुकने तक, आपका रिग लगभग एक फुटबॉल मैदान की लंबाई जितना (दोनों एंड ज़ोन सहित, करीब 419 फुट) चल चुका होगा। कौन-सा कारकों का समूह उस पूरी 419 फुट की कुल रुकने की दूरी को पूरी तरह दर्शाता है?","options":["एयर ब्रेक पकड़ने के बाद ब्रेक जिस दूरी में ट्रक को शारीरिक रूप से धीमा करते हैं, साथ ही सिस्टम में हवा का दबाव बनने तक की देरी की दूरी","वह दूरी जो आप ख़तरे को देखते और पहचानते हुए तय करते हैं, साथ ही पैर को पेडल तक ले जाते हुए तय की गई दूरी, साथ ही ब्रेक द्वारा आपको रोकने में लगने वाली दूरी","वह दूरी जब आप प्रतिक्रिया करते और पैर पेडल तक ले जाते हैं, साथ ही ब्रेक द्वारा आपको रोकने में लगने वाली दूरी","केवल वह दूरी जो ब्रेक लगाने के बाद ट्रक को रोकने के लिए ब्रेक को चाहिए होती है"],"explanation":"कुल रुकने की दूरी प्रत्यक्षण दूरी, प्रतिक्रिया दूरी और ब्रेकिंग दूरी का योग है: खतरे को देखना, पैर पेडल पर ले जाना, और ब्रेक से ट्रक रुकना।"},"12":{"q":"अच्छे मौसम में आप एक सूखे, समतल अंतरराज्यीय राजमार्ग पर खाली ट्रक के साथ लगातार 55 मील प्रति घंटे की गति से चल रहे हैं। आगे चल रहा चालक अचानक रुक जाता है और आपको पूरी आपातकालीन रोक लगानी पड़ती है। जिस क्षण कोई खतरा पहली बार सामने आता है, उस क्षण से लेकर आपके ट्रक के पूरी तरह रुकने तक, रुकने में आपको लगभग कुल कितनी सड़क दूरी लगेगी?","options":["लगभग 60 फीट, क्योंकि प्रतिक्रिया देने से पहले आप इतनी दूरी तय कर लेते हैं","लगभग 220 फीट, मोटे तौर पर केवल ब्रेकिंग चरण की लंबाई","लगभग 320 फीट, एक अमेरिकी फुटबॉल मैदान से थोड़ा अधिक","लगभग 420 फीट, मोटे तौर पर एक अमेरिकी फुटबॉल मैदान और उसके दोनों एंड ज़ोन की लंबाई"],"explanation":"अच्छी परिस्थितियों में 55 मील प्रति घंटे पर कुल रुकने की दूरी लगभग 420 फीट होती है, करीब एक फुटबॉल मैदान और दोनों एंड ज़ोन की लंबाई जितनी।"},"13":{"q":"आप आम तौर पर सूखे, समतल राजमार्ग के एक हिस्से पर 20 मील प्रति घंटे की रफ्तार से चलते हैं और जानते हैं कि उस गति से रुकने के लिए आपके ट्रक को एक निश्चित ब्रेकिंग दूरी चाहिए। आज रात, देर होने पर, आप उसी सड़क पर उन्हीं अच्छी परिस्थितियों में 40 मील प्रति घंटे की रफ्तार से चलते हैं। 20 मील प्रति घंटे पर अपनी ब्रेकिंग दूरी की तुलना में, 40 मील प्रति घंटे पर आपकी ब्रेकिंग दूरी लगभग होगी:","options":["2 गुना अधिक, क्योंकि ब्रेकिंग दूरी गति के सीधे अनुपात में बढ़ती है","3 गुना अधिक, क्योंकि आपको प्रतिक्रिया समय के लिए भी अतिरिक्त दूरी जोड़नी होगी","4 गुना अधिक, क्योंकि ब्रेकिंग दूरी गति के वर्ग के अनुपात में बढ़ती है","लगभग समान, जब तक सड़क सूखी और समतल है और ब्रेक अच्छे हैं"],"explanation":"ब्रेकिंग दूरी गति के वर्ग के अनुपात में बढ़ती है, इसलिए गति 20 से 40 मील प्रति घंटे करने पर ब्रेकिंग दूरी लगभग चार गुना हो जाती है।"},"14":{"q":"लगातार बारिश से राजमार्ग भीग गया है और आपको सड़क की सतह पर पानी की एक पतली परत दिखाई दे रही है, हालाँकि तापमान हिमांक से काफी ऊपर है और कहीं बर्फ या पाला नहीं है। इन गीली परिस्थितियों के कारण बढ़ी हुई रुकने की दूरी के लिए सुरक्षित अंतर बनाए रखने हेतु, उसी सड़क पर सूखे मौसम में जिस गति से आप चलते, उसकी तुलना में आपको अपनी गति लगभग कितनी कम करनी चाहिए?","options":["लगभग दसवें हिस्से जितनी","लगभग एक-तिहाई जितनी","लगभग आधी जितनी","लगभग तीन-चौथाई जितनी"],"explanation":"गीली सड़क पर, घटी हुई पकड़ और लंबी ब्रेकिंग दूरी की भरपाई के लिए सूखी सड़क की सुरक्षित गति की तुलना में अपनी गति लगभग एक-तिहाई कम करें।"},"15":{"q":"आपने अभी-अभी अपना पूरा माल पहुंचाया है और आपका ट्रेलर अब पूरी तरह खाली है। सड़क सूखी है और आप उसी हाईवे गति पर चल रहे हैं जिस पर आप पूरी सुबह पूरी तरह लदे हुए चले थे। लदे होने की तुलना में, आपको इस खाली रिग के ब्रेक लगाने और संभलने के बारे में अपनी अपेक्षा को कैसे समायोजित करना चाहिए?","options":["यह कम दूरी में रुक जाएगा क्योंकि ब्रेक को धीमा करने के लिए बहुत कम वजन है","इसे रुकने के लिए अधिक दूरी चाहिए क्योंकि हल्के पिछले एक्सल में कम ट्रैक्शन होता है और पहिए लॉक होकर स्किड कर सकते हैं","इसकी रुकने की दूरी मूलतः वही रहेगी, क्योंकि यह गति पर निर्भर करती है, लदान पर नहीं","अब यह स्किड नहीं कर सकता क्योंकि खाली ट्रेलर ड्राइव पहियों को कभी लॉक होने से रोकता है"],"explanation":"खाली ट्रक को रुकने के लिए अधिक दूरी चाहिए क्योंकि हल्के पिछले एक्सल की पकड़ कम होती है, जिससे पहिए आसानी से लॉक होकर फिसल जाते हैं।"},"16":{"q":"आप एक इंटरस्टेट पर लगभग 50 मील प्रति घंटे की गति से चल रहे हैं, तभी मूसलाधार बारिश शुरू हो जाती है। स्टीयरिंग अचानक हल्की और ढीली महसूस होती है, ट्रक स्टीयरिंग के छोटे मोड़ों पर प्रतिक्रिया देना बंद कर देता है, और आपको एहसास होता है कि अगले टायर पानी की एक परत पर तैरने लगे हैं और अब सड़क पर पकड़ नहीं बना रहे हैं। नियंत्रण फिर से पाने का सबसे अच्छा मौका कौन सी क्रिया देती है?","options":["गति को जितनी जल्दी हो सके कम करने के लिए ब्रेक पेडल को मजबूती से दबाएं","एक्सेलरेटर छोड़ दें (और क्लच दबाएं) और बिना जोर से ब्रेक लगाए वाहन को अपने आप धीमा होने दें","टायरों को खुरदरे फुटपाथ पर पकड़ बनाने के लिए स्टीयरिंग को तेजी से किनारे (शोल्डर) की ओर मोड़ें","ड्राइव पहियों को घूमता रखने और पानी को 'पार करने' के लिए एक्सेलरेटर बनाए रखें या बढ़ाएं"],"explanation":"यदि हाइड्रोप्लेनिंग शुरू हो जाए, तो एक्सेलरेटर से पैर हटाएं और बिना तेज़ ब्रेक लगाए क्लच दबाएं, ताकि टायर धीमे होकर सड़क से फिर संपर्क बना सकें।"},"17":{"q":"आप पूरी तरह लदे ट्रेलर के साथ एक लंबी, खड़ी पहाड़ी ढलान से नीचे उतर रहे हैं। आपने ऊपर शिखर पर कम गियर चुना और पूरे रास्ते नीचे उतरते हुए हल्के पर लगभग लगातार ब्रेक लगाते रहे। आधी ढलान उतरने के बाद, आप देखते हैं कि ब्रेक पैडल पहले से नरम महसूस हो रहा है और ट्रक उस तरह नहीं रुक रहा जैसे ढलान की शुरुआत में रुक रहा था। इस ब्रेकिंग की हानि का सबसे संभावित कारण क्या है?","options":["इंजन और गियर ब्रेकिंग पर निर्भर रहने के बजाय ब्रेक का बहुत अधिक उपयोग करने से ब्रेक शू और ड्रम अधिक गर्म हो गए हैं","ब्रेक लाइनों में हवा का दबाव बहुत कम हो गया है क्योंकि ढलान पर कंप्रेसर उसकी भरपाई नहीं कर पा रहा","अधिक ऊँचाई पर ठंडी पहाड़ी हवा ने ब्रेक फ्लूइड को गाढ़ा कर दिया और पैडल की प्रतिक्रिया कम कर दी","ट्रेलर के टायरों में हवा कम है, जिससे संपर्क क्षेत्र और हर पहिये पर ब्रेकिंग बल घट जाता है"],"explanation":"लंबी ढलान पर लगातार ब्रेक लगाने से ब्रेक शू और ड्रम ज़्यादा गरम होकर ब्रेक फेड हो जाते हैं; इसके बजाय गति को इंजन और गियर ब्रेकिंग से नियंत्रित करें।"},"18":{"q":"आप एक सूखे राजमार्ग पर लदा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं और एक ढलान वाले निकास रैंप के पास पहुँच रहे हैं जहाँ मोड़ की गति सीमा 35 मील प्रति घंटा अंकित है। सड़क की सतह अच्छी हालत में है और यातायात कम है। उस अंकित 35 मील प्रति घंटा के आँकड़े को आपको कैसे लेना चाहिए, यह कौन-सा कथन सबसे अच्छी तरह बताता है?","options":["यह अच्छी परिस्थितियों में किसी भी वाहन के लिए सुरक्षित गति है, इसलिए आपके लदे हुए रिग में 35 मील प्रति घंटा ठीक है","यह अच्छी परिस्थितियों में कारों के लिए निर्धारित की गई है, इसलिए आपको मोड़ में 35 मील प्रति घंटा से काफी कम गति पर प्रवेश करना चाहिए","यह केवल खाली ट्रकों पर लागू होती है, इसलिए एक लदा हुआ ट्रक कानूनी रूप से इससे अधिक चल सकता है","इसमें ट्रकों के लिए सुरक्षा मार्जिन पहले से शामिल है, इसलिए ठीक 35 मील प्रति घंटा बनाए रखना सबसे सुरक्षित विकल्प है"],"explanation":"मोड़ पर लिखी गति अच्छी परिस्थितियों में कारों के लिए होती है, इसलिए ऊँचे गुरुत्व केंद्र वाले ट्रक को उस गति से काफी कम पर मोड़ में प्रवेश करना चाहिए।"},"19":{"q":"आप एक सूखे राजमार्ग पर 60 फुट लंबा ट्रैक्टर-ट्रेलर चला रहे हैं, और हल्के यातायात में आपका स्पीडोमीटर स्थिर रूप से 55 मील प्रति घंटा दिखा रहा है। आप अपने आगे चल रहे वाहन के पीछे एक सुरक्षित अनुसरण दूरी बनाए रखना चाहते हैं। अपने वाहन की लंबाई और अपनी वर्तमान गति के आधार पर, आपको कम से कम कितनी अनुसरण दूरी रखनी चाहिए?","options":["6 सेकंड, क्योंकि 60 फुट लंबे वाहन को किसी भी गति पर प्रत्येक 10 फुट के लिए 1 सेकंड चाहिए","एक निश्चित 4 सेकंड, लंबाई की परवाह किए बिना किसी भी भारी वाहन के समान","7 सेकंड, क्योंकि 60 फुट लंबे वाहन को 6 सेकंड और 40 मील प्रति घंटा से अधिक गति से चलने के लिए 1 अतिरिक्त सेकंड चाहिए","लगभग तीन कार लंबाई, जो एक ट्रैक्टर-ट्रेलर के लिए मोटे तौर पर पर्याप्त गुंजाइश है"],"explanation":"वाहन की प्रत्येक 10 फुट लंबाई के लिए 1 सेकंड का अनुसरण अंतराल रखें, और 40 मील/घंटा से ऊपर 1 अतिरिक्त सेकंड जोड़ें, इसलिए 55 मील/घंटा पर 60-फुट वाहन को 7 सेकंड चाहिए।"},"20":{"q":"आप हल्के यातायात वाले एक खुले ग्रामीण राजमार्ग पर 60 मील प्रति घंटे की गति से चल रहे हैं। आगे सड़क हल्की चढ़ाई पर जा रही है और आप अपनी जगह संभालना तथा समस्याओं को पहले ही पहचानना चाहते हैं। सही ढंग से नज़र दौड़ाने के लिए, इस गति पर गाड़ी चलाते समय आपकी आँखें अधिकांश समय कहाँ केंद्रित होनी चाहिए?","options":["अपने हुड के अगले हिस्से के ठीक आगे की सड़क पर, ताकि सड़क की रुकावटें तुरंत दिख जाएँ","लगभग 4 से 6 सेकंड आगे, वही दूरी जो आप सुरक्षित फॉलोइंग गैप रखने के लिए उपयोग करते हैं","लगभग 12 से 15 सेकंड आगे, जो राजमार्ग की गति पर लगभग एक चौथाई मील होता है","लगभग 30 सेकंड आगे, सड़क पर जहाँ तक आपकी नज़र पहुँच सके उतनी दूर"],"explanation":"अच्छे ड्राइवर 12 से 15 सेकंड आगे देखते हैं, जो हाईवे गति पर लगभग एक चौथाई मील होता है।"},"21":{"q":"आप एक भीड़भाड़ वाली शहरी सड़क पर एक संकरी गली में दाहिनी ओर मुड़ने के पास पहुँच रहे हैं। यातायात घना है, आपकी दाहिनी ओर साइकिल लेन में एक साइकिल चालक है, और कई वाहन आपके ठीक पीछे सटकर खड़े हैं। अपने टर्न सिग्नल के संबंध में, सबसे अच्छा तरीका कौन सा है?","options":["तब तक रुकें जब तक आप वास्तव में पहिया घुमाना शुरू न कर दें, ताकि पीछे वाले चालक बहुत जल्दी धीमे न हों और जाम न लगे","सिग्नल केवल थोड़ी देर के लिए दें, क्योंकि घने यातायात में आसपास के चालक आपके ब्रेक लाइट को पहले ही देख लेते हैं जो आपकी ओर से संवाद कर देती हैं","मोड़ से काफी पहले सिग्नल चालू करें और पूरे युद्धाभ्यास के दौरान उसे लगातार चमकता रहने दें","बिजली के सिग्नल को छोड़ दें और इसके बजाय हाथ के संकेत का उपयोग करें, क्योंकि यह आपके बगल वाले साइकिल चालक को अधिक दिखाई देता है"],"explanation":"मुड़ने से काफी पहले सिग्नल चालू करें और पूरे मोड़ के दौरान उसे जलता रखें ताकि दूसरों को प्रतिक्रिया का पूरा समय मिले और वे यह न समझें कि आपने इरादा बदल दिया।"},"23":{"q":"आप 70 फुट लंबा ट्रैक्टर-ट्रेलर चला रहे हैं और एक संकरी गली में दाईं ओर मुड़ना है। यातायात हल्का है, और आपको चिंता है कि ट्रेलर के पिछले पहिये कर्ब (किनारे) पर चढ़ जाएंगे। इस मोड़ को सुरक्षित और नियमानुसार पूरा करने के लिए, निम्नलिखित में से आपको क्या नहीं करना चाहिए?","options":["मुड़ने से पहले बाईं ओर बगल वाली लेन में खिसक जाएं ताकि ट्रेलर को मुड़ने के लिए अधिक जगह मिले","मोड़ धीरे-धीरे शुरू करें और ट्रेलर के मार्ग पर नज़र रखने के लिए अपने शीशों को लगातार देखते रहें","वाहन के पिछले हिस्से को कर्ब के पास रखें ताकि अन्य चालक आपके दाईं ओर से निकल न सकें","केवल मोड़ पूरा करते समय चौड़ा मुड़ें, जब केबिन कोना पार कर चुका हो"],"explanation":"दाएं मुड़ने से पहले बाएं खिसकने से एक जगह खुल जाती है जो वाहनों को आपके दाईं ओर से निकलने का न्योता देती है, जिससे वे घूमते ट्रेलर के रास्ते में आ जाते हैं।"},"24":{"q":"आप एक खाली ड्राई वैन (बंद बॉक्स ट्रेलर) खींच रहे हैं और आपके मार्ग पर एक ओवरपास है जिस पर 13 फुट 6 इंच की क्लीयरेंस ऊँचाई लिखी है। आपके ट्रेलर की दर्ज ऊँचाई 13 फुट 4 इंच है, यानी आपके पास 2 इंच का अंतर है। इस सर्दी की शुरुआत में सड़क दल ने इस हिस्से को फिर से डामर से ढका था, और कल रात हल्की बर्फ गिरी जो सड़क पर दबकर जम गई है। ओवरपास के नीचे से गुज़रने का फैसला करने से पहले, उस लिखी हुई क्लीयरेंस ऊँचाई को मानने का सबसे उचित तरीका क्या है?","options":["साइन आधिकारिक रूप से लगाया गया है, इसलिए 13 फुट 6 इंच का आंकड़ा सटीक है और 2 इंच का अंतर आगे बढ़ने के लिए कानूनी रूप से पर्याप्त है।","चूँकि क्लीयरेंस साइन लदे हुए वाहनों के लिए होते हैं, खाली वैन अपनी दर्ज ऊँचाई से नीची रहती है, इसलिए आपके पास अतिरिक्त जगह है और आप आगे बढ़ सकते हैं।","लिखी हुई ऊँचाई को अविश्वसनीय मानें: फिर से डामर बिछाना और दबी हुई बर्फ असली क्लीयरेंस को घटा देते हैं, और आपकी खाली वैन वास्तव में ऊँची चलती है, इसलिए दूसरा मार्ग खोजें या आगे बढ़ने से पहले जाँच लें।","अपने 2 इंच के अंतर को लिखे हुए 13 फुट 6 इंच में जोड़ें, जिससे लगभग 13 फुट 8 इंच की उपयोगी क्लीयरेंस मिलती है, जो आपके ट्रेलर के लिए पर्याप्त से अधिक है।"],"explanation":"दर्ज की गई ऊंचाई सूचना गलत हो सकती है क्योंकि नई सड़क परत और जमी बर्फ असली जगह घटाती हैं और खाली वैन ऊंची चलती है, इसलिए आगे बढ़ने से पहले जांचें या रास्ता बदलें।"},"25":{"q":"आप एक व्यस्त फ्रीवे पर मर्ज कर रहे हैं और अपने दाहिने दरवाज़े पर लगे बड़े उत्तल (घुमावदार) दर्पण में देखते हैं। उस उत्तल दर्पण में आपको दिखने वाली एक कार छोटी और बहुत पीछे दिखाई देती है, इसलिए आपको लगता है कि लेन बदलने के लिए आपके पास काफी जगह है। ऐसा करने से पहले, इस उत्तल दर्पण के बारे में आपको क्या समझना ज़रूरी है?","options":["यह एक अधिक चौड़ा क्षेत्र दिखाता है, लेकिन वस्तुएँ वास्तविकता से छोटी और दूर दिखती हैं, इसलिए वह कार दिखने से अधिक नज़दीक हो सकती है","यह एक संकरे नज़दीकी दृश्य को बड़ा करके दिखाता है, इसलिए कार वास्तव में दिखने से अधिक दूर है और आपके पास अतिरिक्त जगह है","यह समतल दर्पण जैसी ही सही आकार और सही दूरी वाली छवि दिखाता है, इसलिए आपको दिखने वाला अंतर सटीक है","यह केवल आपके अपने केबिन और ट्रेलर का किनारा दिखाता है, इसलिए उसमें दिखने वाला कोई भी वाहन अभी ख़तरा नहीं है"],"explanation":"उत्तल दर्पण व्यापक क्षेत्र दिखाते हैं पर वस्तुओं को छोटा और दूर दिखाते हैं, इसलिए वाहन दिखने से अधिक करीब हो सकता है।"},"26":{"q":"आप एक साफ, सूखे राजमार्ग पर गाड़ी चला रहे हैं तभी आपको आगे दाहिनी ओर के किनारे (शोल्डर) पर एक कार खड़ी दिखती है जिसका बोनट खुला है और पिछले बंपर के पास एक व्यक्ति खड़ा होकर यातायात की ओर देख रहा है। कोई दुर्घटना नहीं है, मौसम खराब नहीं है और यातायात सामान्य रूप से चल रहा है। खतरों को पहचानने के उद्देश्य से, आपको इस खड़ी कार और व्यक्ति को कैसे वर्गीकृत करना चाहिए?","options":["यह खतरा है, क्योंकि यह कोई भी ऐसी सड़क स्थिति या सड़क उपयोगकर्ता है जो आपात स्थिति में बदल सकता है और आपको कार्रवाई करने पर मजबूर कर सकता है","यह खतरा नहीं है, क्योंकि अभी तक कोई दुर्घटना या आपात स्थिति नहीं हुई है और सड़क स्वयं साफ है","यह खतरा नहीं है, क्योंकि खतरे केवल खराब मौसम, कोहरे, बर्फ या अन्य खराब ड्राइविंग परिस्थितियों में ही होते हैं","यह खतरा केवल तभी है जब खड़ी कार अचानक आपकी लेन में वापस आ जाए और आपको जोर से ब्रेक लगाने पर मजबूर कर दे"],"explanation":"खतरा कोई भी सड़क स्थिति या सड़क उपयोगकर्ता है जो आपातकाल बन सकता है, जिसे जल्दी पहचाना जाता है ताकि आपके पास प्रतिक्रिया करने का समय हो।"},"27":{"q":"आप चार-लेन के राजमार्ग पर दाहिनी लेन में चल रहे हैं, तभी एक कार तेज़ी से आपके पीछे आती है, आपके ट्रेलर से कुछ इंच की दूरी पर सटकर चलती है, फिर तेज़ी से बगल से निकलकर आपके आगे कट मारती है और ज़ोर से ब्रेक लगाती है। आपका वाणिज्यिक वाहन पूरी तरह लदा हुआ है और आपकी रुकने की दूरी पहले से ही लंबी है। इस आक्रामक चालक से निपटने का सबसे अच्छा तरीका इनमें से कौन-सा है?","options":["अपनी हाई बीम चमकाएँ और हॉर्न बजाकर चालक को पीछे हटने का संकेत दें, फिर अपनी लेन में बने रहें","बाईं लेन में जाकर चालक को ओवरटेक करें ताकि टकराव पीछे छूट जाए","अपनी गति बनाए रखें और एकदम पीछे सटकर चलें ताकि चालक दोबारा आपके आगे कट न मार सके","एक्सेलरेटर से पैर हटाकर आगे जगह बढ़ाएँ, आँख मिलाने से बचें, और आक्रामक चालक को काफ़ी आगे निकल जाने दें"],"explanation":"आक्रामक चालक के प्रति सुरक्षित प्रतिक्रिया है कि एक्सेलरेटर से पैर हटाकर जगह बनाएं, आँख न मिलाएं और उसे अपने से काफी आगे निकल जाने दें।"},"29":{"q":"ग्रामीण दो-लेन वाले राजमार्ग पर एक अंधेरी, चांद रहित रात है और आप अपनी लो बीम (नीची रोशनी) पर चल रहे हैं, जो सड़क को लगभग 250 फीट आगे तक रोशन करती है। सामने से कोई यातायात नहीं आ रहा। अपनी हेडलाइट की रोशनी से 'आगे न निकलने' (overdriving) के लिए, सबसे महत्वपूर्ण एकमात्र काम क्या है?","options":["हाई बीम पर स्विच करें और स्थिर 55 मील प्रति घंटा बनाए रखें, क्योंकि हाई बीम लगभग 350 फीट तक पहुंचती है और प्रतिक्रिया के लिए यह दूरी पर्याप्त है","आगे चल रहे वाहन की पिछली बत्तियों के करीब पहुंचें और उसकी रोशनी का उपयोग करके सड़क पर आगे तक देखें","अपनी सामान्य दिन वाली गति बनाए रखें क्योंकि आपकी हेडलाइट लेन की लाइनों और सामने की सड़क को साफ रोशन करती हैं","इतनी धीमी गति से चलें कि आप उतनी दूरी के भीतर पूरी तरह रुक सकें जितनी आपकी हेडलाइट वास्तव में रोशन करती हैं"],"explanation":"अपनी हेडलाइट से तेज़ कभी न चलें: इतनी धीमी गति से चलें कि आप उस दूरी के भीतर पूरी तरह रुक सकें जितनी आपकी हेडलाइट वास्तव में रोशन करती है।"},"30":{"q":"अभी-अभी अंधेरा हुआ है और आप एक बिना विभाजन वाली दो-लेन वाली सड़क पर हैं, जहाँ सामने से वाहनों की एक कतार हेडलाइट जलाए हुए आ रही है। एक चालक अपनी हाई बीम कम नहीं करता और तेज़ चकाचौंध से आपको आगे की सड़क देखने में कठिनाई हो रही है। जब तक वाहन गुज़र न जाएँ, अपनी आँखों को अंधेरे के अनुकूल बनाए रखने और सुरक्षित रूप से अपनी लेन में रहने के लिए आपको अपनी नज़र कहाँ रखनी चाहिए?","options":["अपनी लेन के दाहिने किनारे की ओर, सड़क की रेखा या निशानों को मार्गदर्शक बनाकर, जब तक वाहन गुज़र न जाएँ","सीधे सामने आ रही हेडलाइट्स पर, ताकि आप अपने और दूसरे वाहनों के बीच की दूरी आँक सकें","नीचे डैशबोर्ड के यंत्रों पर, ताकि तेज़ चकाचौंध से आपकी आँखों को आराम मिले","सामने के यातायात से बहुत आगे सड़क पर दूर तक, ताकि आपकी गति आपकी हेडलाइट की पहुँच के भीतर रहे"],"explanation":"सामने से आती तेज़ हेडलाइट से चौंधियाने पर अपनी लेन के दाहिने किनारे की ओर देखें और पेंट की गई रेखा का अनुसरण करें ताकि आँखें अँधेरे में अनुकूलित रहें।"},"31":{"q":"आप भोर से पहले एक डिलीवरी कर रहे हैं तभी घना कोहरा छा जाता है और दृश्यता आपके ट्रैक्टर-ट्रेलर की लंबाई से भी कम रह जाती है। आप तय करते हैं कि चलती लेन में रुकने के बजाय धीरे-धीरे अगले निकास तक चलते रहना सबसे सुरक्षित है। खुद को चौंधियाए बिना सड़क देखने और दिखाई देने के लिए, कौन-सा रोशनी और गति का चयन एकमात्र सर्वोत्तम तरीका है?","options":["अधिकतम पहुँच के लिए अपनी हाई बीम जलाएँ और गति बनाए रखें ताकि यातायात बाधित न हो","अपनी लो बीम (और फॉग लाइट यदि लगी हो) का उपयोग करें और गति इतनी कम करें कि जितनी दूरी तक देख सकते हैं उसी में रुक सकें","हेडलाइट बंद कर दें और केवल चारों हैज़र्ड फ्लैशर जलाकर अपनी स्थिति दर्शाएँ","हाई बीम जलाए रखें पर गति कम करें, क्योंकि कोहरे में अतिरिक्त रोशनी चकाचौंध से ज़्यादा मायने रखती है"],"explanation":"कोहरे में लो बीम (और हो तो फॉग लाइट) का उपयोग करें और इतना धीमा करें कि दिखने वाली दूरी में रुक सकें, क्योंकि हाई बीम वापस परावर्तित होकर दृश्यता घटाती है।"},"32":{"q":"एक साफ़ सुबह है, तापमान लगभग 31°F (करीब -1°C) है, और आगे की खुली सड़क पूरी तरह सूखी दिख रही है। आप एक लदे हुए ट्रेलर के साथ नदी की घाटी को पार करने वाले एक लंबे पुल की ओर जा रहे हैं, और उसके ठीक आगे छाया में एक ओवरपास है। वहाँ पहुँचने से पहले आपको सबसे पहले कहाँ पकड़ (traction) खोने की उम्मीद करनी चाहिए और अपनी गति समायोजित करनी चाहिए?","options":["सूखी खुली सड़क पर, क्योंकि ट्रैक्टर का वज़न टायरों को नीचे दबाता है और सड़क की सतह को गर्म कर देता है","पुल और छाया वाले ओवरपास पर, क्योंकि हवा डेक के ऊपर और नीचे दोनों ओर बहती है, इसलिए यह आसपास की सड़क से पहले ठंडा होकर जम जाता है","अभी कहीं नहीं, क्योंकि जब सतह सूखी दिख रही है तो जब तक हवा का तापमान जमाव बिंदु से नीचे न गिरे, बर्फ़ नहीं बन सकती","केवल ओवरपास के बाद, जहाँ सड़क के नमक और धूप ने ऊँची संरचनाओं पर की बर्फ़ पहले ही पिघला दी है"],"explanation":"पुल और ओवरपास के डेक के ऊपर-नीचे ठंडी हवा लगती है, इसलिए वे हर तरफ से गर्मी खोकर आसपास की सड़क से पहले जम जाते हैं।"},"33":{"q":"सुबह-सुबह तापमान हिमांक से ठीक नीचे है। आगे की सड़क गहरी और गीली दिखती है, लेकिन आप देखते हैं कि आपके आगे चल रहे ट्रक के टायर बिल्कुल भी छींटे नहीं उड़ा रहे, और आपके शीशों तथा एंटीना पर बर्फ की एक पतली परत जम गई है। सड़क की सतह पर सबसे अधिक संभावना क्या हो रही है, और आपको कैसे प्रतिक्रिया देनी चाहिए?","options":["सतह केवल पिघले पाले से गीली है; अपनी गति बनाए रखें क्योंकि जमा पानी सामान्य पकड़ देता है।","सड़क बस सूख रही है; ब्रेक पर एक तेज़ झटका यह पुष्टि कर देगा कि पकड़ ठीक है और आपको अपनी अनुगमन दूरी बनाए रखने देगा।","ब्लैक आइस की एक पतली, पारदर्शी परत बन गई है; एक्सेलरेटर से धीरे-धीरे पैर हटाएं और किसी भी अचानक स्टीयरिंग या ब्रेकिंग से बचें।","यह ताज़ा डामर सीलेंट है जो सतह को गीला दिखा रहा है; सावधानी से चलें पर सामान्य गति स्वीकार्य है।"],"explanation":"जमाव बिंदु के पास गीली दिखने वाली सड़क पर टायरों से छींटे न उठें तो यह ब्लैक आइस का संकेत है, इसलिए एक्सेलरेटर छोड़ें और अचानक स्टीयरिंग या ब्रेक न लगाएं।"},"34":{"q":"पश्चिमी टेक्सास में जुलाई के मध्य का समय है, बाहर का तापमान लगभग 105 डिग्री फ़ारेनहाइट है और डामर से साफ़ तौर पर तारकोल रिस रहा है। आपने दो घंटे पहले रुककर देखा था और आपके टायर ठीक चल रहे थे, लेकिन अभी-अभी आप हाईवे की गति से एक लंबे इंटरस्टेट मार्ग पर आए हैं। इस यात्रा के दौरान आपको किस स्थिति पर निगरानी रखने के लिए सबसे अधिक सतर्क रहना चाहिए?","options":["गर्मी बढ़ने के साथ टायर का दबाव बढ़ना, जिससे टायर फट सकता है","धूल और गर्मी के कारण हॉर्न की आवाज़ का दबा-दबा होना","वाल्व से ठंडी हवा निकलने के कारण टायर का दबाव गिरना","खिड़की की रंगीन परत का गहरा होकर आपकी आगे की दृश्यता कम करना"],"explanation":"अत्यधिक गर्मी में टायर के अंदर की हवा फैलती है और दबाव बढ़ता है, जो गर्मी के साथ मिलकर टायर फटने (ब्लो-आउट) का कारण बन सकता है।"},"35":{"q":"आपका वाहन अपने अधिकतम संयुक्त सकल भार (GCWR) के लगभग बराबर लदा हुआ है और आप एक लंबी, खड़ी पहाड़ी ढलान उतरने वाले हैं। सड़क सूखी और मौसम साफ है। चोटी पर पहुँचते ही आप सोचने लगते हैं कि पूरे उतार में अपनी गति को कैसे नियंत्रित रखेंगे। इस ढलान पर अपनी गति संभालने का सबसे अच्छा तरीका कौन-सा है?","options":["ऊँचे गियर में रहें ताकि इंजन सुचारू चले, और गति को सुरक्षित स्तर पर बनाए रखने के लिए पूरे उतार में लगातार सर्विस ब्रेक दबाए रखें।","न्यूट्रल में डालकर लुढ़कते जाएँ, और जब-जब गति बढ़े तब-तब सर्विस ब्रेक जोर से लगाएँ ताकि ब्रेक बीच-बीच में ठंडे हो सकें।","ट्रांसमिशन को सामान्य रोड गियर में रखें और उतरते समय गति रोकने के लिए पार्किंग (हैंड) ब्रेक पर भरोसा करें।","उतराई शुरू करने से पहले निचला गियर चुनें ताकि अधिकांश काम इंजन और गियर ब्रेकिंग करे, और सर्विस ब्रेक का उपयोग केवल हल्के, स्थिर सहारे के रूप में करें।"],"explanation":"लंबी, तीखी ढलान पर उतरने से पहले लो गियर चुनें ताकि इंजन और गियर ब्रेकिंग अधिकांश काम करे, और केवल हल्का, स्थिर सर्विस ब्रेक लगाएं।"},"36":{"q":"आप एक लदे हुए ट्रेलर के साथ एक लंबी, खड़ी पहाड़ी ढलान से नीचे उतर रहे हैं। आपने ऊपर पर कम गियर चुना था और हल्की, स्थिर ब्रेकिंग कर रहे हैं, लेकिन ब्रेक पेडल धीरे-धीरे ढीला होता जा रहा है, आपकी गति लगातार बढ़ रही है, और आपको जलने की गंध आ रही है। आगे दाईं ओर आपको एक बजरी वाला एस्केप रैंप दिखता है। निम्नलिखित में से कौन सा वर्णन करता है कि आपको उस रैंप पर कब मुड़ना चाहिए?","options":["जब आपके ब्रेक अधिक गर्म होकर फेल हो गए हों या काम करना बंद कर दें और आप ढलान पर अपनी गति को नियंत्रित नहीं कर पा रहे हों","जब आप ढलान के लिए निर्धारित ट्रक गति सीमा से केवल कुछ मील प्रति घंटा ऊपर हों","जब ढलान पर यातायात भारी हो गया हो और आप अधिक जगह चाहते हों","जब आप आगे बढ़ने से पहले इंजन और ब्रेक को ठंडा होने देने के लिए एक छोटा विराम लेना चाहते हों"],"explanation":"एस्केप रैंप का उपयोग केवल तब करें जब आपके ब्रेक फीके पड़ जाएं या फेल हो जाएं और आप ढलान पर अपनी गति नियंत्रित न कर सकें।"},"37":{"q":"गर्म गर्मी की दोपहर में आप खाली ट्रक हाईवे की गति पर चला रहे हैं, तभी एक तेज़ धमाका सुनाई देता है और स्टीयरिंग अचानक तेज़ी से दाईं ओर खिंच जाता है -- आगे का एक टायर फट गया है। अब आपके खाली ट्रक को नियंत्रित करना और कठिन है। आपकी पहली सही कार्रवाई क्या होनी चाहिए?","options":["स्टीयरिंग व्हील को मज़बूती से पकड़ना, ब्रेक से दूर रहना, और वाहन को अपने आप धीमा होने देना, फिर धीरे-धीरे किनारे पर ले जाना","ट्रक के सड़क से उतरने से पहले गति कम करने के लिए मज़बूती और स्थिरता से ब्रेक लगाना","ट्रक को लेन के बीच में रखने के लिए खिंचाव की विपरीत दिशा में तेज़ी से स्टीयरिंग घुमाना","क्लच दबाकर निचले गियर में बदलना ताकि इंजन ब्रेकिंग से गति कम हो"],"explanation":"आगे का टायर फटने पर स्टीयरिंग को मजबूती से पकड़ें और ब्रेक न लगाएं, वाहन को खुद धीमा होने दें और फिर सड़क से हटें।"},"38":{"q":"आप हाइड्रॉलिक ब्रेक वाले एक सीधे (सिंगल) ट्रक में एक मध्यम ढलान से उतर रहे हैं, तभी आप ब्रेक पैडल दबाते हैं और वह लगभग बिना किसी रोकने की शक्ति के धीरे-धीरे फर्श की ओर धँस जाता है। यातायात हल्का है और लगभग एक मील आगे ट्रकों के लिए एक एस्केप रैंप है। वाहन की गति कम करने के लिए आपको सबसे पहले क्या आज़माना चाहिए?","options":["इंजन को तुरंत बंद कर दें ताकि ड्राइवट्रेन ट्रक को रोकने में मदद करे","पहियों को लॉक करने के लिए पार्किंग ब्रेक को एक ज़ोरदार झटके में कस कर लगाएँ","ट्रेलर के ब्रेक लगाने के लिए ट्रेलर एयर-सप्लाई (ट्रैक्टर प्रोटेक्शन) नॉब को खींचें","हाइड्रॉलिक दबाव फिर से बनाने के लिए ब्रेक पैडल को तेज़ी से बार-बार पंप करें"],"explanation":"जब हाइड्रोलिक ब्रेक पेडल दबकर फर्श तक चला जाए, तो पहले उसे तेजी से पंप करें ताकि वाहन को धीमा या रोकने लायक दबाव फिर से बन सके।"},"39":{"q":"आप गीले दो-लेन वाले राजमार्ग पर एक मोड़ से निकलते समय गति बढ़ा रहे हैं, तभी ट्रैक्टर का पिछला हिस्सा अचानक किनारे (शोल्डर) की ओर फिसलने लगता है और ड्राइव पहिये ऐसा महसूस कराते हैं मानो उनकी पकड़ छूट गई हो। निम्नलिखित में से, इस ड्राइव-व्हील स्किड पर दोबारा नियंत्रण पाने का सबसे अच्छा तरीका कौन-सा है?","options":["ब्रेक पैडल को मज़बूती से दबाकर रखें ताकि वाहन का पिछला हिस्सा धीमा होकर फिर से सीध में आ जाए","गति बढ़ाना बंद करें, क्लच दबाएँ, और वाहन को जिस दिशा में ले जाना चाहते हैं उसी दिशा में स्टीयर करें","एक समान थ्रॉटल बनाए रखें और ज़ोर से काउंटर-स्टीयर करें ताकि इंजन की शक्ति ड्राइव पहियों को सीधा खींच ले","फिसलन को जितनी जल्दी हो सके रोकने के लिए ब्रेक से पहियों को लॉक कर दें"],"explanation":"ड्राइव-व्हील एक्सेलरेशन स्किड ठीक करने के लिए गति बढ़ाना बंद करें, इंजन की शक्ति काटने हेतु क्लच दबाएं, और जिस दिशा में जाना है उधर स्टीयर करें।"},"40":{"q":"आप एक लदे हुए ट्रेलर के साथ एक लंबी, घुमावदार पहाड़ी ढलान से नीचे उतर रहे हैं, तभी आगे की सड़क की सतह गीली और छायादार दिखती है। आप मुड़ना शुरू करते हैं, लेकिन आपके ट्रक का अगला हिस्सा मोड़ के बाहरी किनारे की ओर सीधा बढ़ता रहता है और स्टीयरिंग हल्की तथा निष्क्रिय महसूस होती है, चाहे आप पहिया कितना भी घुमाएँ। निम्नलिखित में से, इस अगले-पहिये की फिसलन का सबसे संभावित मूल कारण क्या है?","options":["आपने मोड़ में प्रवेश करते समय ब्रेक बहुत धीरे से छोड़े, इसलिए अगले टायरों ने सड़क को कभी पकड़ा ही नहीं","बहुत अधिक भार पिछले एक्सल पर खिसक गया, जिससे स्टीयरिंग (अगले) एक्सल से वजन उठ गया","आप फिसलन भरी, छायादार परिस्थितियों के लिए बहुत तेज़ चला रहे हैं (और/या आपके अगले टायर घिसे हुए या कम हवा वाले हैं)","निचले गियर में इंजन ब्रेकिंग ने ड्राइव पहियों को लॉक कर दिया और अगले हिस्से को रास्ते से भटका दिया"],"explanation":"अगले पहियों की स्किड परिस्थितियों के हिसाब से तेज़ चलने और घिसे या कम हवा वाले अगले टायरों के कारण होती है।"},"41":{"q":"तापमान जमाव बिंदु से थोड़ा नीचे है और एक फिसलन भरी हाईवे पर आप तेज़, आपातकालीन ब्रेक लगा रहे हैं, तभी एक कार अचानक आपके सामने आ जाती है। आपके ट्रैक्टर-ट्रेलर में एंटी-लॉक ब्रेक (ABS) लगे हैं, और आप ब्रेक पैडल को पूरी ताकत से नीचे तक दबाते हैं। इस स्थिति में, ABS का मुख्य लाभ क्या है?","options":["यह पहियों को लॉक होने से रोकता है ताकि आप स्टीयरिंग करते हुए खतरे से बचकर निकल सकें","यह बिना ABS वाले उसी ट्रक की तुलना में निश्चित रूप से काफ़ी कम रुकने की दूरी की गारंटी देता है","यह ट्रक को आपके सामने आई कार से अपने आप दूर मोड़ देता है","यह आपको सुरक्षित रूप से और नज़दीक से पीछा करने देता है क्योंकि अब रुकना तेज़ हो गया है"],"explanation":"ABS तेज़ ब्रेकिंग के दौरान पहियों को जाम होने से रोकता है, ताकि आप किसी खतरे के चारों ओर वाहन को मोड़ सकें।"},"42":{"q":"एक व्यस्त दो-लेन वाले राजमार्ग पर हुई दुर्घटना के स्थल पर सबसे पहले आप पहुँचते हैं। एक कार पलट गई है और आपकी लेन को रोके हुए है; चालक होश में है लेकिन दरवाज़े से टिका हुआ है, और दुर्घटनाग्रस्त वाहन के पीछे से यातायात अभी भी राजमार्ग की गति से पास आ रहा है। आपने सुरक्षित रूप से वाहन रोक दिया है और अपनी हैज़र्ड फ्लैशर लाइट चालू कर दी हैं। आपको सबसे पहले क्या करना चाहिए?","options":["वाहन में आग लगने की स्थिति को ध्यान में रखते हुए, घायल चालक को सावधानी से कार से बाहर निकालकर किनारे पर लिटा देना","अगले निकास तक चलते रहना ताकि फ़ोन ढूँढकर 911 पर कॉल कर सकें, क्योंकि अकेले आप मदद नहीं कर सकते","बाहर निकलकर दुर्घटनाग्रस्त कार को एक ओर धकेल देना ताकि लेन खाली हो जाए और यातायात चलता रहे","स्थल पर कुछ और करने से पहले पास आ रहे यातायात को आगाह करने के लिए परावर्तक चेतावनी त्रिकोण लगाना"],"explanation":"दुर्घटना स्थल पर पहली प्राथमिकता उसे सुरक्षित करना है, इसलिए कुछ और करने से पहले आती हुई ट्रैफ़िक को चेतावनी देने के लिए परावर्तक चेतावनी त्रिकोण लगाएं।"},"43":{"q":"इंजन वाले हिस्से से धुआं उठता देखकर आप गाड़ी को किनारे रोक देते हैं। आपने पार्किंग ब्रेक लगा लिया है और अपना B:C श्रेणी का अग्निशामक यंत्र उठा लिया है। इंजन की आग बुझाने की तैयारी करते समय निम्नलिखित में से कौन-सा कदम सबसे कम उपयुक्त है?","options":["जितनी जल्दी हो सके इंजन बंद कर देना","अग्निशामक को लपटों के ऊपरी हिस्से पर नहीं, बल्कि आग के आधार पर निशाना लगाना","हुड को यथासंभव बंद रखना और अग्निशामक को दरारों या झरोखों से छोड़ना","हुड को पूरा खोल देना ताकि अग्निशामक को सीधे आग की लपटों पर निशाना लगाया जा सके"],"explanation":"बोनट को पूरा खोलने से आग को ताजा ऑक्सीजन मिलती है और वह भड़क सकती है; बोनट नीचे रखें और दरारों से अग्निशामक छोड़ें।"},"44":{"q":"एक लंबी यात्रा से एक रात पहले शादी के स्वागत समारोह में आप लगातार शराब पीते हैं लेकिन सोने से कई घंटे पहले रुक जाते हैं। अगली सुबह आप खुद को पूरी तरह होश में महसूस करते हैं, भरपूर नाश्ता करते हैं, दो कप कॉफ़ी पीते हैं, और अपनी यात्रा-पूर्व जाँच से पहले ठंडी हवा में तेज़ टहलते हैं। केबिन में चढ़ते समय, कौन सा कथन इस बारे में कानून और तथ्यों को सबसे सही ढंग से दर्शाता है कि आप अपना वाणिज्यिक वाहन (CMV) सुरक्षित रूप से चला सकते हैं या नहीं?","options":["इनमें से किसी भी कदम ने आपके रक्त में अल्कोहल की मात्रा कम नहीं की; ऐसा केवल समय बीतने से होता है, और 0.04% या उससे अधिक रक्त अल्कोहल सांद्रता (BAC) पर आप CMV नहीं चला सकते।","चूँकि आप CMV चला रहे हैं, कानूनी सीमा 0.08% है, इसलिए जब तक आप उससे नीचे रहे हैं तब तक आप निश्चित रूप से ठीक हैं।","कॉफ़ी, भोजन और ठंडी हवा ने अल्कोहल के निष्कासन को तेज़ कर दिया है, इसलिए आपका BAC अब व्यावहारिक रूप से शून्य है और सीमा अब मायने नहीं रखती।","होश में महसूस करना ही CMV चालक के लिए कानूनी मानदंड है, इसलिए यदि आप अब प्रभावित महसूस नहीं करते तो आप सीमा से नीचे हैं और चलाना सुरक्षित है।"],"explanation":"रक्त में अल्कोहल की मात्रा केवल समय बीतने से ही कम होती है, और आप 0.04% या उससे अधिक BAC के साथ वाणिज्यिक वाहन नहीं चला सकते।"},"45":{"q":"आपकी शिफ्ट कई घंटे पहले खत्म हो गई थी और आपने रात के खाने के साथ कई पेय (शराब) पिए। एक डिस्पैचर फोन करके आपसे अभी एक खाली ट्रैक्टर को यार्ड वापस पहुंचाने के लिए कहता है। आपने कॉफी पी, ठंडी रात की हवा में तेज़ टहल लिया, और आप खुद को साफ़ दिमाग वाला महसूस कर रहे हैं। कौन सा कथन सबसे अच्छी तरह दर्शाता है कि असल में क्या तय करता है कि आप कानूनी रूप से गाड़ी चलाने योग्य हैं या नहीं?","options":["कॉफी और ठंडी हवा ने आपकी सतर्कता इतनी बढ़ा दी है कि अब आपके रक्त में अल्कोहल की मात्रा CDL की 0.04% सीमा से नीचे आ गई है।","चूंकि आप साफ़ दिमाग महसूस कर रहे हैं और अब नशे में नहीं हैं, इसलिए ट्रैक्टर चलाना आपके लिए सुरक्षित और कानूनी है।","केवल समय बीतने से ही आपके रक्त में अल्कोहल की मात्रा कम होती है; आपने जो कुछ भी किया है उससे शरीर से अल्कोहल निकलने की गति तेज़ नहीं होती।","चूंकि यह बिना माल के खाली ट्रैक्टर ले जाने का काम है, इसलिए 0.04% रक्त-अल्कोहल सीमा इस यात्रा पर लागू नहीं होती।"],"explanation":"रक्त में अल्कोहल की मात्रा केवल समय बीतने से कम होती है, क्योंकि लीवर अल्कोहल को एक निश्चित दर से निकालता है जिसे कॉफी, ताज़ी हवा या ठंडा स्नान तेज़ नहीं कर सकता।"},"46":{"q":"आप अपनी पाली शुरू कर रहे हैं, तभी एक सड़क निरीक्षक सांस की जांच करता है और आपका परिणाम 0.02% BAC दिखाता है -- शराब पता लगने योग्य है, लेकिन CDL की 0.04% सीमा से कम। आप पूरी तरह से होश में महसूस करते हैं और कोई दुर्घटना या अन्य उल्लंघन नहीं है। संघीय CDL नियमों के अनुसार, अब आपके साथ क्या होगा?","options":["कुछ नहीं बदलता -- चूंकि आप 0.04% सीमा से नीचे हैं, इसलिए आपको सामान्य रूप से गाड़ी चलाते रहने की अनुमति है","आपको 24 घंटे के लिए सेवा से बाहर कर दिया जाता है, भले ही आपका माप 0.04% की अयोग्यता-स्तर से नीचे हो","आपके साथ 0.04% माप जैसा ही व्यवहार किया जाता है और DUI (नशे में गाड़ी चलाने) के अपराध का आरोप लगाया जाता है","आपको एक लिखित चेतावनी मिलती है और उस पर हस्ताक्षर करने के बाद आपको अपनी यात्रा जारी रखने दिया जाता है"],"explanation":"0.04% से कम कोई भी पहचान-योग्य अल्कोहल मात्रा CDL चालक को 24 घंटे के लिए सेवा से बाहर कर देती है, भले ही वह अयोग्यता स्तर से नीचे हो।"},"47":{"q":"आपने शिपर के यहां फ्लैटबेड पर माल लादकर बांधा, अपनी प्री-ट्रिप जांच पूरी की और राजमार्ग पर आ गए। आपकी यात्रा 280 मील की है जिसमें कोई निर्धारित विराम नहीं है। यह जानते हुए कि चलना शुरू करने के तुरंत बाद माल बैठ जाता है और बंधन (टाई-डाउन) ढीले हो सकते हैं, माल का निरीक्षण करने और बंधन को फिर से कसने के लिए आपको किस बिंदु तक अपना पहला (FIRST) ठहराव करना चाहिए?","options":["पहले 50 मील के भीतर","पहले 150 मील के भीतर","पहले 3 घंटे की ड्राइविंग के बाद","पहले 100 मील के भीतर"],"explanation":"माल और उसके बांधने वाले उपकरणों की जाँच पहले 50 मील के भीतर करनी चाहिए, क्योंकि शुरुआती मीलों में माल जमने से बंधन ढीले हो जाते हैं।"},"48":{"q":"अपनी प्री-ट्रिप जाँच के दौरान आप एक फ्लैटबेड पर 18 फुट लंबी और 4,200 पाउंड वजनी एक अकेली स्टील बीम को बाँध रहे हैं। आप उतने ही कम टाई-डाउन उपयोग करना चाहते हैं जो फिर भी संघीय कार्गो सुरक्षा नियमों को पूरा करते हों। कौन-सा कथन उस न्यूनतम टाई-डाउन संख्या का सही वर्णन करता है जो आपको उपयोग करनी चाहिए?","options":["कम से कम दो टाई-डाउन, क्योंकि हर 10 फुट कार्गो के लिए एक चाहिए और 18 फुट के टुकड़े के लिए दो चाहिए","एक टाई-डाउन पर्याप्त है क्योंकि बीम एक अकेला, संतुलित टुकड़ा है जो डेक पर सपाट रखा है","कम से कम तीन टाई-डाउन, क्योंकि 5 फुट से लंबे किसी भी टुकड़े के लिए हमेशा तीन अलग एंकर बिंदु चाहिए","कोई निश्चित संख्या लागू नहीं होती; आपको केवल इतने टाई-डाउन चाहिए कि वर्किंग लोड लिमिट कार्गो के वजन के 50% तक पहुँच जाए"],"explanation":"माल को हर 10 फुट लंबाई पर कम से कम एक टाई-डाउन चाहिए, और 5 फुट से लंबी किसी भी वस्तु को कम से कम दो, इसलिए 18 फुट के टुकड़े को दो टाई-डाउन चाहिए।"},"49":{"q":"आप डॉक पर एक फ्लैटबेड लोड कर रहे हैं और कई भारी स्टील कॉइल के लिए बची हुई एकमात्र जगह दो-स्तरीय रैक का ऊपरी स्तर है, जबकि हल्की पैकेजिंग नीचे के डेक पर रखी जा सकती है। एक सहकर्मी कहता है कि जब तक कुल वजन आपके GVWR (सकल वाहन भार रेटिंग) से नीचे रहता है, तब तक भारी कॉइल कहाँ रखी जाती हैं इससे कोई फर्क नहीं पड़ता। निकलते समय, मार्ग में कई तीखे मोड़ों वाली एक घुमावदार दो-लेन सड़क शामिल है। भारी कॉइल को डेक पर नीचे रखने की तुलना में, उस भारी वजन को ऊपर रखने का सबसे महत्वपूर्ण परिणाम क्या है?","options":["इसका हैंडलिंग पर कोई वास्तविक प्रभाव नहीं पड़ता क्योंकि आप अभी भी वाहन के GVWR के भीतर कानूनी रूप से हैं","इससे ट्रक को रोकना आसान हो जाता है क्योंकि अधिक वजन टायरों को नीचे दबाता है","यह गुरुत्वाकर्षण केंद्र को ऊपर उठा देता है, जिससे ट्रक मोड़ों पर पलटने की बहुत अधिक संभावना वाला हो जाता है","यह मोड़ों पर स्थिरता और ट्रैकिंग में सुधार करता है क्योंकि भार फ्रेम के ऊपर केंद्रित होता है"],"explanation":"भारी माल ऊपर रखने से गुरुत्व केंद्र ऊँचा हो जाता है, जिससे ट्रक ऊपर से भारी होकर मोड़ों पर पलटने की संभावना कहीं अधिक हो जाती है।"},"50":{"q":"आप टेक्सास DPS के एक यार्ड में खड़े होकर एक ऐसे वाहन-संयोजन को देख रहे हैं जिसे चलाने का लाइसेंस आप चाहते हैं: एक ट्रैक्टर जो एक लदे हुए ट्रेलर को खींच रहा है। कागजात पर संयुक्त रेटिंग (GCWR) 33,000 lb दर्शाती है, और अकेले ट्रेलर की रेटिंग 14,000 lb है। Class B लाइसेंस वाला आपका एक साथी कहता है कि उसका लाइसेंस इसे कवर करता है 'क्योंकि पूरा संयोजन 26,001 lb से अधिक है।' कौन सा कथन सही ढंग से बताता है कि आपको वास्तव में किस लाइसेंस की आवश्यकता है और क्यों?","options":["Class B पर्याप्त है, क्योंकि संयोजन की कुल रेटिंग 26,001 lb या अधिक है।","Class A चाहिए, लेकिन केवल इसलिए कि संयोजन की कुल रेटिंग 16,001 lb या अधिक तक पहुँचती है।","Class B पर्याप्त है, क्योंकि खींचे जा रहे ट्रेलर की रेटिंग 16,000 lb से कम है।","Class A चाहिए, क्योंकि संयोजन की रेटिंग 26,001 lb या अधिक है तथा खींची जा रही इकाई की रेटिंग 10,000 lb से अधिक है।"],"explanation":"क्लास A CDL तब आवश्यक है जब संयोजन का GCWR 26,001 पाउंड या अधिक हो और खींची जाने वाली इकाई 10,000 पाउंड से अधिक की हो।"},"51":{"q":"आप अपनी CDL कौशल परीक्षा के लिए यह योजना बनाकर आते हैं कि आप जीविका के लिए ट्रैक्टर-ट्रेलर चलाएँगे, जहाँ आप जो भी वाहन कभी चलाएँगे उसमें पूर्ण एयर ब्रेक होते हैं। पैसे बचाने के लिए, एक दोस्त आपको अपना पुराना सीधा ट्रक उधार देता है जिसमें केवल हाइड्रॉलिक ब्रेक लगे हैं, और आप उसी में पूरी कौशल परीक्षा बिना किसी गलती के पास कर लेते हैं। यह चुनाव आपके लाइसेंस को कैसे प्रभावित करता है, उसके आधार पर कौन-सा कथन सही है?","options":["क्योंकि आपने कौशल परीक्षा ऐसे वाहन में दी जिसमें एयर ब्रेक नहीं थे, इसलिए आपके CDL पर एयर-ब्रेक प्रतिबंध लगेगा जो आपको एयर ब्रेक से लैस किसी भी वाणिज्यिक मोटर वाहन को चलाने से रोकता है।","क्योंकि आपने कौशल परीक्षा बिना किसी गलती के साफ-सुथरे ढंग से पास की, इसलिए आपको एयर-ब्रेक वाहनों के लिए मान्य पूर्ण, बिना प्रतिबंध वाला CDL मिलेगा।","क्योंकि जिस ट्रक में आपने परीक्षा दी उसमें काम करने वाले हाइड्रॉलिक ब्रेक थे, इसलिए परीक्षक एयर-ब्रेक वाला हिस्सा माफ कर सकता है और बिना प्रतिबंध वाला लाइसेंस जारी कर सकता है।","क्योंकि आप काम के लिए केवल एयर-ब्रेक वाले ट्रैक्टर-ट्रेलर ही चलाने का इरादा रखते हैं, इसलिए दोबारा परीक्षा देने तक आपको केवल रात में चलाने तक सीमित लाइसेंस जारी किया जाएगा।"],"explanation":"एयर ब्रेक रहित वाहन में स्किल्स टेस्ट देने पर एयर-ब्रेक प्रतिबंध लगता है, जो आपको एयर ब्रेक वाले किसी भी CMV को चलाने से रोकता है।"},"52":{"q":"आप एक ग्रामीण राजमार्ग पर 40 यात्रियों के साथ एक चार्टर बस चला रहे हैं और एक रेलवे क्रॉसिंग के पास पहुँचते हैं। क्रॉसिंग पर केवल क्रॉसबक (आड़ा-तिरछा) चिह्न लगा है, गेट ऊपर उठे हैं, कोई बत्ती नहीं चमक रही, आप दोनों दिशाओं में साफ़ देख सकते हैं, और कहीं भी कोई ट्रेन नज़र नहीं आ रही। पटरियाँ पार करने से पहले आपको क्या करना आवश्यक है?","options":["गति धीमी करें, देखें और सुनें, और बिना रुके आगे बढ़ें क्योंकि गेट ऊपर हैं और कोई सिग्नल सक्रिय नहीं है","पूरी तरह रुकें, देखें और सुनें, और फिर पटरियाँ तभी पार करें जब आप बिना रुके उन्हें पूरी तरह पार कर सकें","गति बनाए रखें ताकि बस के पास सभी पटरियाँ बिना रुके पार करने के लिए पर्याप्त गति (momentum) हो","केवल तभी रुकें जब आप यात्रियों के साथ-साथ प्लेकार्ड वाली खतरनाक सामग्री भी ले जा रहे हों"],"explanation":"बसों और प्लेकार्ड वाले हैजमैट वाहनों को हर रेलवे क्रॉसिंग पर रुककर देखना और सुनना चाहिए, और तभी पार करना चाहिए जब बिना रुके पूरी पटरी साफ़ कर सकें।"},"53":{"q":"आप पूरी तरह लदे हुए 53-फुट लंबे ट्रैक्टर-ट्रेलर को चला रहे हैं और एक ग्रामीण दो-लेन सड़क पर एक अनियंत्रित सिंगल-ट्रैक रेलवे क्रॉसिंग के पास पहुँच रहे हैं। यहाँ न तो बत्तियाँ हैं और न ही गेट, और पटरियों के आगे का आपका दृश्य झाड़ियों से आंशिक रूप से ढका हुआ है। आप जानते हैं कि जब तक आप बिना रुके पटरियों को पूरी तरह पार न कर सकें, तब तक कभी भी पार करना शुरू नहीं करना चाहिए। यह तय करने के लिए कि पार करना शुरू करना सुरक्षित है या नहीं, आपको लगभग कितना समय मानना चाहिए कि आपके जैसे रिग को एक सिंगल ट्रैक को पूरी तरह खाली करने में लगेगा?","options":["लगभग 3 सेकंड, क्योंकि हाईवे की गति पर यही मोटे तौर पर आपका प्रतिक्रिया समय है","जब तक इस समय कोई ट्रेन दिखाई नहीं दे रही, तब तक सटीक समय मायने नहीं रखता","लगभग 6 सेकंड, जो 55 मील प्रति घंटा से आपके कुल रुकने के समय के बराबर है","कम से कम 14 सेकंड"],"explanation":"एक सामान्य ट्रैक्टर-ट्रेलर को एक रेलवे पटरी पूरी तरह पार करने के लिए कम से कम 14 सेकंड चाहिए, इसलिए पार करने से पहले इतना समय रखें।"},"54":{"q":"दोपहर बाद का समय है, लेकिन तेज़ बारिश की बौछार ने दृश्यता घटा दी है और आसमान गहरा धूसर हो गया है। आप सड़क और दूसरे वाहनों को गाड़ी चलाने लायक अब भी काफी साफ़ देख पा रहे हैं, इसलिए आप सोचते हैं कि क्या इस समय हेडलाइट की ज़रूरत भी है। इस स्थिति में अपनी LOW-बीम हेडलाइट चालू करना सबसे अच्छा कदम क्यों है?","options":["हेडलाइट चलाने से अल्टरनेटर पर भार बना रहता है, जो बारिश में लंबी, धीमी यात्रा के दौरान बैटरी चार्ज करने में मदद करता है","हेडलाइट बारिश को चीरकर आगे की सड़क को आप व्यक्तिगत रूप से कितनी दूर तक देख सकते हैं, उसे काफ़ी बढ़ा देती है","मंद, बारिश वाली रोशनी में हेडलाइट आपके ट्रक को दूसरे चालकों के लिए देखना बहुत आसान बना देती है, भले ही आप खुद अब भी ठीक से देख पा रहे हों","बारिश में हाई बीम पर जाना सबसे ज़्यादा रोशनी आगे फेंकता है और सामने से आते यातायात द्वारा आपको देखे जाने का सबसे पक्का तरीका है"],"explanation":"धुंधली या बरसाती रोशनी में हेडलाइट का मुख्य उद्देश्य आपके ट्रक को अन्य चालकों को दिखाई देना है, भले ही आप खुद ठीक से देख पा रहे हों।"},"55":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान आप स्टील पाइप से लदे एक फ्लैटबेड के चारों ओर घूम रहे हैं और कैब के पीछे ट्रेलर के अगले हिस्से पर लगे माल-सुरक्षा बोर्ड (\"headache rack\", हेडर बोर्ड) को जाँचने के लिए रुकते हैं। एक नया चालक पूछता है कि कंपनी इसके ठीक हालत में हुए बिना ट्रक को क्यों नहीं चलने देती। कौन-सा उत्तर इस उपकरण के सुरक्षा उद्देश्य को सबसे अच्छी तरह बताता है?","options":["यह अगले टायरों से उछलकर आने वाली बजरी और सड़क के मलबे को माल से टकराने से रोकता है","यह माल को अति-चौड़ा दर्शाता है ताकि पीछे आने वाला यातायात सुरक्षित दूरी बनाए रखे","यह वह पिछला एंकर बिंदु है जिससे कानूनी बँधाई के लिए टाई-डाउन ज़ंजीरों को जोड़ना ज़रूरी होता है","यह तेज़ ब्रेक या टक्कर के समय माल को आगे खिसककर कैब में घुसने से रोककर चालक की रक्षा करता है"],"explanation":"हेडर बोर्ड, या हेडेक रैक, एक अवरोध है जो तेज ब्रेक या टक्कर में माल को आगे केबिन में फिसलने और चालक को चोट पहुंचाने से रोकता है।"},"56":{"q":"सुबह का समय है और एक लंबी यात्रा से पहले आप अपने ट्रैक्टर-ट्रेलर का चारों ओर घूमकर निरीक्षण कर रहे हैं। पिछले एक्सल जांचते समय, आप झुककर डुअल (जुड़वां) टायरों को देखते हैं। निम्नलिखित में से कौन-सा अवलोकन आपको वाहन को कानूनी और सुरक्षित रूप से चलाने से पहले सेवा से बाहर करने के लिए बाध्य करेगा?","options":["स्टीयरिंग (अगले) एक्सल के प्रत्येक टायर की ट्रेड गहराई 5/32 इंच है","पिछले एक्सल के दो डुअल टायर एक-दूसरे से दबकर संपर्क में आ रहे हैं","पिछले एक्सल के चारों टायर एक ही आकार और एक ही ब्रांड के हैं","पिछले ड्राइव टायरों की ट्रेड गहराई 3/32 इंच है"],"explanation":"जुड़वां टायर कभी एक-दूसरे को नहीं छूने चाहिए, क्योंकि संपर्क बेमेल या कम हवा का संकेत है जो गर्मी पैदा करता है और टायर फटने का कारण बन सकता है।"},"58":{"q":"300 मील की यात्रा से पहले आप अपने ट्रैक्टर-ट्रेलर की प्री-ट्रिप जाँच पूरी कर रहे हैं। आपका सुपरवाइज़र रेडियो पर बताता है कि सड़क किनारे एक अधिकारी आपके ट्रक की जाँच करेगा कि उसमें संघीय नियमों के अनुसार आवश्यक आपातकालीन उपकरण मौजूद हैं या नहीं। केबिन में नज़र डालने पर आपको एहसास होता है कि आपके सामान्य सेट से एक वस्तु गायब है और आप चिंतित होने लगते हैं। उस जाँच को पास करने के लिए निम्नलिखित में से कौन-सी वस्तु आपको कानूनी रूप से साथ रखना ज़रूरी नहीं है?","options":["उचित रूप से चार्ज और सही रेटिंग वाला अग्निशामक यंत्र","वाहन पर रखा हुआ एक हवा भरा अतिरिक्त (स्पेयर) टायर","तीन लाल परावर्तक (रिफ्लेक्टिव) चेतावनी त्रिकोणों का एक सेट","अतिरिक्त बिजली के फ़्यूज़, जब तक कि ट्रक में सर्किट ब्रेकर न हों"],"explanation":"अनिवार्य आपातकालीन उपकरण अग्निशामक यंत्र, अतिरिक्त फ्यूज़ और चेतावनी त्रिकोण हैं; अतिरिक्त टायर आवश्यक नहीं है।"},"59":{"q":"तापमान जमाव बिंदु से थोड़ा नीचे है और आप एक पुल के डेक पर हल्की चढ़ाई पर एक भरा हुआ ट्रेलर खींच रहे हैं। आप महसूस करते हैं कि पीछे के ड्राइव पहिए घूमने (फिसलने) लगते हैं और ट्रैक्टर का पिछला हिस्सा बाईं ओर झूलने लगता है। वाहन को फिर से नियंत्रण में लाने के लिए, कौन-सा कदम स्किड से उबरने में मदद करने के बजाय उसे और बिगाड़ देगा?","options":["घूम रहे ड्राइव पहियों को जबरन लाइन में लाने के लिए थ्रॉटल को और जोर से दबाएं","एक्सेलरेटर से पैर हटाएं और क्लच दबाएं ताकि ड्राइव पहिए धीमे हो जाएं","ट्रैक्टर को लेन में जिस दिशा में ले जाना चाहते हैं उसी दिशा में स्टीयर करें","जैसे ही ट्रेलर सीधा होने लगे, काउंटर-स्टीयर करने के लिए तैयार रहें"],"explanation":"ड्राइव-व्हील स्किड में पावर देना बंद करें: एक्सेलेरेटर छोड़ें और क्लच दबाएं ताकि ड्राइव पहिये फिर से पकड़ बना सकें।"},"60":{"q":"सुबह के 5:00 बजे हैं और आप एक लंबी यात्रा शुरू करने वाले हैं। एक सहकर्मी आपको बताता है कि कंपनी ने पिछले सप्ताह पहले ही एक निरीक्षण मैकेनिक को भुगतान कर दिया था, इसलिए आज सुबह आपका अपना यात्रा-पूर्व निरीक्षण असल में सिर्फ ऐसी किसी चीज़ को पकड़ने के लिए है जो आपको राजमार्ग पर बीच में फँसा सकती है। टेक्सास आपसे हर यात्रा से पहले अपना खुद का यात्रा-पूर्व निरीक्षण करने की माँग क्यों करता है, इसका सबसे अच्छा वर्णन कौन-सा कथन करता है?","options":["इसका एकमात्र वैध उद्देश्य यांत्रिक सुरक्षा दोषों को सड़क पर दुर्घटना का कारण बनने से पहले पकड़ना है।","यह मूल रूप से एक कानूनी औपचारिकता है जिसे राज्य और संघीय नियमों का पालन करने के लिए आपको लॉग में दर्ज करना होता है।","इसका मुख्य मूल्य सड़क किनारे होने वाली खराबियों को रोकना है, जो कंपनी का समय और पैसा खर्च कराती हैं।","यह इन सभी उद्देश्यों को एक साथ पूरा करता है: सुरक्षा दोष ढूँढना, अपना कानूनी कर्तव्य निभाना और खराबियों को रोकना।"],"explanation":"ट्रिप-पूर्व निरीक्षण एक साथ तीन उद्देश्य पूरा करता है: सुरक्षा दोष ढूँढना, चालक के रूप में अपना कानूनी कर्तव्य निभाना, और महँगी खराबी रोकना।"},"61":{"q":"आप राजमार्ग की गति पर एक लदे हुए ट्रैक्टर-ट्रेलर को चला रहे हैं, तभी एक कार अचानक आपके आगे आकर ज़ोर से ब्रेक लगा देती है और आपकी ही लेन में सीधे एक खतरा छोड़ देती है, जबकि आपकी दाईं ओर का किनारा (शोल्डर) खुला है। समय रहते रुकना संभव नहीं है। इस आपात स्थिति में केवल ज़ोर से ब्रेक लगाना हमेशा सबसे सुरक्षित प्रतिक्रिया क्यों नहीं है, यह कौन-सा कथन सबसे अच्छी तरह समझाता है?","options":["अक्सर किसी खतरे को स्टीयरिंग से बचाकर निकलने में रुकने की तुलना में कम दूरी लगती है, इसलिए खुले किनारे की ओर काउंटर-स्टीयर करना उस स्थिति में टक्कर टाल सकता है जब ब्रेक लगाना पर्याप्त नहीं हो।","आपात स्थिति में रुकना कभी अनुमत नहीं है क्योंकि यह उस प्रतिक्रिया समय को बर्बाद करता है जिसे कानून स्टीयरिंग के लिए उपयोग करना अनिवार्य करता है।","ज़ोर से ब्रेक लगाने से मुख्यतः इसलिए बचना चाहिए क्योंकि किसी भी आकस्मिक ब्रेकिंग के पहले कुछ सेकंडों में ही ब्रेक ज़्यादा गर्म होकर फेड हो जाएंगे।","चूँकि आपका ट्रेलर लदा हुआ है, 55 मील प्रति घंटा पर आपकी कुल रुकने की दूरी घटकर लगभग 60 फुट रह जाती है, इसलिए उस दूरी पर ब्रेक लगाना व्यर्थ है।"],"explanation":"किसी खतरे से बचने के लिए स्टीयरिंग से मुड़ना आमतौर पर रुकने की दूरी से बहुत कम जगह लेता है, इसलिए खुले किनारे की ओर मोड़ना ब्रेक से न रुक पाने पर टक्कर टाल सकता है।"},"62":{"q":"आप एक सूखे राजमार्ग पर 55 मील प्रति घंटे की गति से एक भरा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं, तभी बहुत आगे आपकी लेन में एक कार अचानक रुक जाती है। जिस क्षण खतरा पहली बार दिखाई देता है, उससे लेकर जिस क्षण आपका ट्रक पूरी तरह रुक जाता है, तक आपकी कुल रुकने की दूरी तीन अलग-अलग भागों से बनती है जो एक के बाद एक होते हैं। कौन सा क्रम इन तीन भागों को सही कालानुक्रमिक क्रम में, पहले से अंतिम तक, सूचीबद्ध करता है?","options":["प्रतिक्रिया दूरी, फिर ब्रेकिंग दूरी, फिर अनुभूति (परसेप्शन) दूरी","अनुभूति (परसेप्शन) दूरी, फिर प्रतिक्रिया दूरी, फिर ब्रेकिंग दूरी","ब्रेकिंग दूरी, फिर प्रतिक्रिया दूरी, फिर अनुभूति (परसेप्शन) दूरी","अनुभूति (परसेप्शन) दूरी, फिर ब्रेकिंग दूरी, फिर प्रतिक्रिया दूरी"],"explanation":"कुल रुकने की दूरी क्रम में होती है: पहले आप खतरे को भांपते हैं, फिर प्रतिक्रिया देकर पैर ब्रेक पर ले जाते हैं, और फिर ब्रेक वाहन को धीमा करते हैं।"},"65":{"q":"आप एक लदे हुए ट्रेलर के साथ एक लंबी, तीव्र पहाड़ी ढलान से नीचे उतर रहे हैं। ढलान के बीच में, आप ब्रेक पेडल दबाते हैं और वह लगभग बिना किसी प्रतिरोध के फर्श तक धंस जाता है -- आपके सर्विस ब्रेक फेल हो गए हैं और ट्रक की गति बढ़ रही है। लगभग आधा मील आगे एक रनअवे एस्केप रैंप (आपातकालीन रोकथाम ढलान) का संकेत है। उठाने के लिए एकमात्र सबसे अच्छा कदम क्या है?","options":["ट्रांसमिशन को न्यूट्रल में डाल दें ताकि इंजन अब आपको रोके नहीं, और ट्रक को नियंत्रित तरीके से रुकने तक लुढ़कने दें","ढलान से नीचे उतरते हुए दबाव फिर से बनाने की कोशिश में ब्रेक पेडल को तेजी से और बार-बार पंप करें","आगे मौजूद रनअवे एस्केप रैंप की ओर मुड़ें, जो फेल हुए ब्रेक वाले वाहन को रोकने के लिए बनाया गया है","ड्राइवर का दरवाजा खोलकर ट्रक के ढलान के निचले सिरे तक पहुँचने से पहले बाहर कूदने के लिए तैयार हो जाएं"],"explanation":"रनअवे एस्केप रैंप उतार पर ब्रेक फेल हो चुके भारी वाहन को सुरक्षित रूप से रोकने के लिए बनाए जाते हैं, इसलिए जब भी उपलब्ध हो इसका उपयोग करें।"},"66":{"q":"पिछले दस मिनट से लगातार बारिश हो रही है और आप एक लदे हुए संयोजन (combination) वाहन को एक चिकने, अच्छी तरह से पक्के इंटरस्टेट पर 60 मील प्रति घंटे की रफ्तार से चला रहे हैं। आप देखते हैं कि स्टीयरिंग हल्का महसूस हो रहा है और जब आप पहिये में छोटा सुधार करते हैं तो ट्रक प्रतिक्रिया नहीं देता। सड़क से इस संपर्क-हानि के लिए सबसे अधिक जिम्मेदार कारक कौन-सा है?","options":["सड़क की सतह सूखी है, इसलिए आगे के टायरों ने गर्म पक्की सड़क पर अपनी पकड़ खो दी है","सड़क पर पानी है और आप बहुत तेज़ चला रहे हैं, इसलिए टायर पानी की एक परत पर फिसल रहे हैं","आप बहुत धीरे चला रहे हैं, जिससे टायर रुके हुए पानी में धंस जाते हैं","आपके टायर बिल्कुल नए हैं और गहरी ट्रेड बहुत ज्यादा पानी को बहा ले जा रही है"],"explanation":"हाइड्रोप्लेनिंग तब होती है जब सड़क पर पानी और अधिक गति मिलकर टायरों को उठा देते हैं, जिससे वे सड़क के बजाय पानी की परत पर फिसलने लगते हैं।"},"67":{"q":"गर्मी की एक तपती दोपहर है और हाईवे पर 120 मील चलने के बाद आप अभी-अभी एक विश्राम स्थल पर रुके हैं। वाहन के चारों ओर निरीक्षण करते समय आगे बढ़ने से पहले आप यह पक्का करना चाहते हैं कि आपके ड्राइव-एक्सल टायरों में हवा का दबाव सही है। कौन-सा तरीका आपको सटीक और भरोसेमंद दबाव माप देता है?","options":["हर टायर पर टायर थम्पर या हथौड़े से मारें और आवाज़ तथा उछाल से हवा के दबाव का अंदाज़ा लगाएं","अभी, जब टायर हाईवे से अब भी गर्म हैं, तभी गेज से दबाव जांचें, क्योंकि यही उनका असली कार्यशील दबाव है","पहले टायरों को ठंडा होने दें, फिर हर एक को सही ढंग से कैलिब्रेट किए गए टायर प्रेशर गेज से जांचें","ध्यान से देखें कि हर टायर नीचे से कितना फूला हुआ है और उसकी तुलना बाकी टायरों से करें"],"explanation":"टायर का दबाव हमेशा टायर ठंडे होने के बाद सही ढंग से कैलिब्रेटेड गेज से ही जाँचें, क्योंकि चलने की गर्मी दबाव बढ़ाकर गलत रूप से ऊँचा पाठ दिखाती है।"},"68":{"q":"आप अपने लदे हुए ट्रैक्टर-ट्रेलर में एक व्यस्त इंटरस्टेट हाईवे पर मर्ज कर रहे हैं। एक छोटी कार आपके दाहिने पिछले हिस्से के बिल्कुल पीछे आ जाती है और आपके शीशों से गायब हो जाती है, जबकि दूसरी कार आपके बाएं फेंडर के ठीक बगल में चल रही है। एक सहकर्मी ने आपसे एक बार कहा था कि सबसे ज़्यादा 'No-Zone' को लेकर चिंतित रहना। इस स्थिति में, वह No-Zone क्या है जिसे आपको संभालना चाहिए?","options":["वह दूरी का अंतर जो आपको अपने आगे रखना चाहिए, जो 55 मील प्रति घंटे पर लगभग 419 फुट होता है","आपके ट्रक के चारों ओर के बड़े ब्लाइंड-स्पॉट क्षेत्र जहाँ अन्य वाहन आपकी नज़रों से गायब हो सकते हैं","दाहिने किनारे के साथ नो-पार्किंग क्षेत्र जहाँ आप चेतावनी त्रिकोण रखने के लिए नहीं रुक सकते","सबसे बाईं ओर की उच्च-अधिभोग लेन जहाँ ट्रकों का प्रवेश प्रतिबंधित है"],"explanation":"No-Zone ट्रक के चारों ओर के बड़े ब्लाइंड-स्पॉट क्षेत्र हैं जहाँ अन्य वाहन नज़र से ओझल हो सकते हैं।"},"69":{"q":"आप एक भीड़भाड़ वाले ट्रक-स्टॉप पार्किंग में अकेले हैं और आपको अपने ट्रैक्टर-ट्रेलर को अपनी दाईं ओर एक दीवार के साथ एक तंग जगह में पीछे करना है। आपका ट्रेलर खाली है, पार्किंग में पैदल चलने वालों की भीड़ है, और आप अपने दाएं पिछले हिस्से के पीछे के क्षेत्र को साफ़ नहीं देख सकते। इस बैकिंग को पूरा करने का सबसे सुरक्षित तरीका क्या है?","options":["अपनी दाईं (अंधी) ओर पीछे करें ताकि दीवार विंडशील्ड से दिखती रहे, और धीरे-धीरे आगे बढ़ें","जब तक जगह है तब तक तेज़ी से पीछे करें, क्योंकि लेन में रुके रहना पैदल चलने वालों के लिए अधिक जोखिम पैदा करता है","केवल अपने दाएं साइड मिरर पर भरोसा करें और नीचे न उतरें, क्योंकि व्यस्त पार्किंग में रुककर देखना समय की बर्बादी है","ज़रूरत हो तो अपनी स्थिति बदलें ताकि आप अपनी बाईं (चालक) ओर पीछे कर सकें, और अपने अंधे क्षेत्र पर नज़र रखने के लिए किसी सहायक या स्पॉटर का उपयोग करें"],"explanation":"जब भी संभव हो चालक (बाएँ) की ओर बैक करें ताकि आप ट्रेलर के साथ सीधे देख सकें, और अपने ब्लाइंड एरिया पर नज़र रखने के लिए सहायक या स्पॉटर का उपयोग करें।"},"70":{"q":"आप अच्छी, सूखी परिस्थितियों में 55 मील प्रति घंटे की रफ़्तार से एक भरा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं, तभी आपकी लेन में केवल कुछ ट्रक-लंबाई आगे अचानक एक बंद पड़ी कार दिखाई देती है — जो आपकी लगभग 419 फीट की कुल रुकने की दूरी से बहुत अधिक नज़दीक है। बगल वाली लेन खाली है। कौन-सा कार्य आपको दुर्घटना से बचने का सर्वोत्तम मौका देता है?","options":["खाली लेन में मुड़कर बाधा के चारों ओर से निकल जाएं, क्योंकि आमतौर पर किसी बाधा से बचने के लिए स्टीयरिंग से मुड़ना, पूरी तरह रुकने में लगने वाली दूरी से कम दूरी में संभव होता है","जितना हो सके उतना ज़ोर से ब्रेक लगाएं और पहियों को लॉक कर दें, क्योंकि अधिकतम ब्रेकिंग हमेशा सबसे सुरक्षित आपातकालीन प्रतिक्रिया होती है","अपनी गति बनाए रखें और सीधे उसमें से होकर निकल जाएं, इस भरोसे पर कि ट्रक का भार बाधा को धकेलकर एक तरफ कर देगा","अपनी लेन में रहें और हल्का ब्रेक लगाएं, क्योंकि 55 मील प्रति घंटे पर आपकी 419 फीट की रुकने की दूरी आपको समय रहते रोक देगी"],"explanation":"किसी बाधा को मोड़कर बचना आमतौर पर पूरी तरह रुकने के लिए जरूरी दूरी से कम में हो जाता है, इसलिए खतरे से बचने के लिए खाली लेन का उपयोग करें।"},"71":{"q":"आप एक व्यस्त चौराहे के पास पहुँच रहे हैं जहाँ आपको दाहिनी ओर मुड़ना है, और आपके पीछे वाहनों की कतार लगी है। अपने इरादों को सुरक्षित रूप से बताने और अन्य चालकों को प्रतिक्रिया करने के लिए अधिकतम समय देने हेतु, आपको अपना टर्न सिग्नल कब चालू करना चाहिए?","options":["पहले कुछ बार ब्रेक दबाएँ, फिर ठीक मोड़ शुरू करते समय सिग्नल दें ताकि जल्दी दिया गया सिग्नल पीछे वालों को भ्रमित न करे","मोड़ से काफी पहले सिग्नल दें और मोड़ पूरा होने तक सिग्नल चालू रखें","केवल गति धीमी करने और यह पुष्टि करने के बाद कि चौराहा खाली है, ताकि बहुत जल्दी सिग्नल न दिया जाए","मोड़ पूरा करने के तुरंत बाद सिग्नल दें ताकि पीछे के चालकों को आपके युद्धाभ्यास की पुष्टि हो सके"],"explanation":"मुड़ने से काफी पहले जल्दी सिग्नल दें और मोड़ पूरा होने तक सिग्नल चालू रखें ताकि अन्य चालकों को प्रतिक्रिया देने का अधिकतम समय मिले।"},"72":{"q":"तापमान हिमांक से थोड़ा नीचे है और हल्की जमने वाली बूंदाबांदी ने राजमार्ग को गीला और चमकदार बना दिया है। आपके लदे हुए ट्रक में इंजन ब्रेक (रिटार्डर) लगा है। ऐसे रास्ते के पास पहुँचते समय जहाँ आपको धीरे-धीरे गति कम करनी पड़ सकती है, इन परिस्थितियों में रिटार्डर को संभालने का सबसे सुरक्षित तरीका क्या है?","options":["रिटार्डर को पूरी तरह चालू रखें, क्योंकि यह खराब मौसम में सर्विस ब्रेक की घिसाई कम करता है","रिटार्डर को बंद कर दें, क्योंकि यह फिसलन भरी सतह पर ड्राइव पहियों की पकड़ खो सकता है और स्किड करा सकता है","रिटार्डर को उसकी सबसे ऊँची सेटिंग पर रखें ताकि आप ब्रेक पेडल छुए बिना गति कम कर सकें","रिटार्डर का उपयोग केवल तब करें जब आपकी गति 40 मील प्रति घंटे से ऊपर हो, उसके नीचे इसे बंद कर दें"],"explanation":"गीली, बर्फीली या फिसलन भरी सड़कों पर रिटार्डर बंद कर दें क्योंकि यह केवल ड्राइव पहियों को ब्रेक करता है और उनकी पकड़ छुड़ाकर फिसला सकता है।"},"73":{"q":"आप पूरी तरह लदे हुए ट्रेलर को खींच रहे हैं और पहाड़ों में एक लंबी, खड़ी चढ़ाई पर चढ़ना शुरू कर चुके हैं। आपका ट्रैक्टर जोर लगाने लगता है, इंजन की RPM गिर रही है और आपकी गति तेजी से कम हो रही है। चढ़ाई पर सुरक्षित रूप से चलते रहने और इंजन की अधिकतम शक्ति बनाए रखने के लिए कौन सा कार्य सही है?","options":["ट्रांसमिशन को ओवरड्राइव में रखें और गति वापस पाने के लिए एक्सीलेटर को पूरी तरह दबाएं","नीचे के गियर में शिफ्ट करें ताकि इंजन अपनी शक्ति सीमा में बना रहे और भार को स्थिर रूप से खींचे","ट्रांसमिशन को न्यूट्रल में डालें और गति (मोमेंटम) को आपको चढ़ाई के शीर्ष तक ले जाने दें","अपने वर्तमान गियर को बनाए रखें और वाहन को नियंत्रण में रखने के लिए सर्विस ब्रेक को हल्के से दबाते रहें"],"explanation":"लंबी, खड़ी चढ़ाई पर निचले गियर में शिफ्ट करें ताकि इंजन RPM अपने पावर रेंज में रहे और भार को स्थिर रूप से खींचे।"},"74":{"q":"आप सूखे ग्रामीण राजमार्ग पर खाली ट्रक में 30 मील प्रति घंटे की गति से चल रहे हैं और आपने ब्रेक लगाने के लिए पर्याप्त जगह छोड़ना सीख लिया है। आगे का यातायात साफ़ हो जाता है और आप 60 मील प्रति घंटे तक गति बढ़ाते हैं। 30 मील प्रति घंटे पर जिस ब्रेकिंग दूरी की ज़रूरत थी, उसकी तुलना में अब 60 मील प्रति घंटे पर केवल ब्रेकिंग दूरी से आपको क्या अपेक्षा करनी चाहिए?","options":["यह केवल दोगुनी होती है, क्योंकि आपने गति दोगुनी की -- इसलिए दोगुनी जगह छोड़ना पर्याप्त है","यह लगभग चार गुना बढ़ जाती है, क्योंकि ब्रेकिंग दूरी गति के वर्ग के अनुपात में बढ़ती है","यह लगभग वही रहती है, क्योंकि खाली ट्रक भरे हुए ट्रक की तुलना में कम दूरी में रुकता है","यह लगभग आधी बढ़ जाती है, क्योंकि कुल रुकने की दूरी में प्रतिक्रिया दूरी भी शामिल होती है"],"explanation":"ब्रेकिंग दूरी गति के वर्ग के अनुपात में बढ़ती है, इसलिए गति दोगुनी करने पर यह लगभग चार गुना हो जाती है।"},"75":{"q":"एक लंबी रात की यात्रा में रात के 2 बजे हैं और आप महसूस करते हैं कि आपकी पलकें भारी हो रही हैं, आप अपनी लेन के भीतर बहक गए हैं, और आपको पिछले कुछ मील याद नहीं हैं। आपके लॉग में अभी भी कई घंटे की कानूनी ड्राइविंग का समय बचा है। इस थकान से निपटने का एकमात्र वास्तव में प्रभावी तरीका कौन सा है?","options":["खिड़की नीचे करके ठंडी हवा अपने चेहरे पर आने दें ताकि सतर्क रहें","एक बड़ी कॉफी पिएं और जब तक घंटे बचे हैं, यात्रा पूरी करने के लिए आगे बढ़ते रहें","सुरक्षित जगह पर हाईवे से बाहर निकलें और आगे बढ़ने से पहले आराम करने या सोने के लिए रुकें","रेडियो की आवाज़ तेज़ करें और केबिन का तापमान कम करें ताकि जागते रहें"],"explanation":"उनींदेपन का एकमात्र पक्का उपाय गाड़ी रोककर आराम करना या सोना है, क्योंकि और कुछ भी सतर्कता को सही मायने में वापस नहीं लाता।"},"77":{"q":"आप चार-लेन के राजमार्ग पर एक लदे हुए ट्रैक्टर-ट्रेलर को चला रहे हैं, तभी नारंगी संकेत आगे एक कार्य क्षेत्र (work zone) की चेतावनी देते हैं। प्रवेश करते ही निर्धारित गति सीमा घट जाती है और दाहिनी चलती लेन के पास एक फ्लैगर तथा कई मजदूर दिखाई देते हैं। यातायात सुचारू रूप से चल रहा है और आपके ठीक पीछे कोई नहीं है। इस क्षेत्र से गुजरते समय सबसे अच्छा (BEST) कदम कौन-सा है?","options":["अपनी राजमार्ग गति बनाए रखें क्योंकि यातायात चल रहा है और क्षेत्र को जल्दी पार करने से मजदूरों के पास बिताया गया समय कम हो जाता है","अपनी गति को कार्य क्षेत्र की निर्धारित सीमा तक घटाएं, अनुसरण दूरी बढ़ाएं, और लेन में आने वाले मजदूरों के प्रति सतर्क रहें","अपनी वर्तमान गति पर बाईं लेन में जाएं और परिस्थितियां बदलने से पहले फ्लैगर को पार करने के लिए गति बढ़ाएं","आगे वाले वाहन के करीब बने रहें ताकि अन्य चालक आपके बीच में न आ सकें और मजदूरों के पास आपको ब्रेक लगाने पर मजबूर न करें"],"explanation":"कार्य क्षेत्र में निर्धारित गति सीमा तक धीमा करें, अपनी अनुसरण दूरी बढ़ाएं और लेन में आने वाले श्रमिकों पर नज़र रखें ताकि रुकने के लिए पर्याप्त जगह रहे।"},"78":{"q":"अपनी प्री-ट्रिप जाँच के दौरान आप अपने बंद वैन में हल्के लेकिन भारी-भरकम (बड़े आकार के) बक्सों की लोडिंग की निगरानी कर रहे हैं। सब कुछ समा जाए, इसके लिए चालक दल उन्हें ऊँचा ढेर बनाकर रखता है, जिससे अधिकांश वज़न फर्श पर नीचे फैलने के बजाय ट्रेलर में ऊपर की ओर रह जाता है। कुल कार्गो वज़न आपकी एक्सल सीमा के भीतर ही है और लोड दोनों किनारों से केंद्रित है। जब आप निकलते हैं और हाईवे के पहले ऑन-रैंप मोड़ के पास पहुँचते हैं, तो इस तरह लोड लगाने का सबसे महत्वपूर्ण प्रभाव क्या है?","options":["चूँकि वज़न केंद्रित है और एक्सल सीमा के भीतर है, इसलिए ट्रेलर वास्तव में नीचे रखे गए लोड की तुलना में मोड़ को अधिक स्थिरता से पार करेगा।","ऊँचा ढेर लगाने से चालन (हैंडलिंग) पर कोई वास्तविक प्रभाव नहीं पड़ता, क्योंकि कार्गो का वज़न कानूनी एक्सल सीमा के भीतर है।","ऊँचा गुरुत्व केंद्र वाहन के मोड़ में पलटने या लुढ़कने की संभावना को बहुत अधिक बढ़ा देता है, भले ही सीधी सड़क पर लोड सुरक्षित महसूस हो।","मुख्य जोखिम बहुत लंबी रुकने की दूरी है, क्योंकि ऊँचा रखा गया वज़न ब्रेकिंग ट्रैक्शन को कम कर देता है।"],"explanation":"हल्के, भारी-भरकम माल को ऊँचा रखने से गुरुत्व केंद्र ऊपर उठ जाता है, जिससे मोड़ पर पलटने का खतरा काफी बढ़ जाता है।"},"79":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान, आप अपने फ्लैटबेड पर 8,000 पाउंड वजन की एक स्टील कॉइल ढो रहे हैं। यह पुष्टि करने के लिए कि आपका भार कानूनी रूप से सुरक्षित है, आप अपनी बंधन (टाई-डाउन) चेन और बाइंडर जाँचना शुरू करते हैं। स्टील कॉइल को ठोक कर रोकने (ब्लॉक) और सहारा देने (ब्रेस) की आवश्यकता के अलावा, कौन सा कथन सही ढंग से उस न्यूनतम संयुक्त (कुल) कार्य भार सीमा का वर्णन करता है जो इस 8,000 पाउंड भार के लिए आपके बंधनों को प्रदान करनी चाहिए?","options":["बंधनों की संयुक्त कार्य भार सीमा भार के पूरे वजन के बराबर होनी चाहिए, यानी कम से कम 8,000 पाउंड।","बंधनों की संयुक्त कार्य भार सीमा भार के वजन का कम से कम एक-चौथाई होनी चाहिए, यानी कम से कम 2,000 पाउंड।","बंधनों की संयुक्त कार्य भार सीमा भार के वजन की कम से कम दोगुनी होनी चाहिए, यानी कम से कम 16,000 पाउंड।","बंधनों की संयुक्त कार्य भार सीमा भार के वजन की कम से कम आधी होनी चाहिए, यानी कम से कम 4,000 पाउंड।"],"explanation":"सभी टाई-डाउन की संयुक्त वर्किंग लोड लिमिट माल के वजन के कम से कम आधे के बराबर होनी चाहिए।"},"80":{"q":"आप अपने ट्रैक्टर-ट्रेलर के साथ एक शहरी चौराहे पर तीखे दाएं मोड़ के पास पहुंच रहे हैं। आप जानते हैं कि ट्रेलर ट्रैक्टर के मुकाबले अंदर की ओर चलेगा (ऑफ-ट्रैकिंग), और आपको चिंता है कि पिछले पहिये कर्ब (फुटपाथ के किनारे) पर चढ़ सकते हैं। ट्रेलर का पिछला हिस्सा कर्ब से टकराने से बचाने के लिए, यह दायां मोड़ लेने का सबसे सुरक्षित तरीका क्या है?","options":["मोड़ की शुरुआत वाहन के अगले हिस्से को चौड़ा करके बाईं ओर ले जाकर करें, फिर तेजी से दाएं काटें ताकि ट्रेलर कर्ब से बच जाए","मोड़ पूरा करते समय चौड़ा मुड़ें और वाहन के पिछले हिस्से को कर्ब के पास रखें, ताकि अन्य चालक आपके दाईं ओर से न घुस सकें","मोड़ बाईं लेन से शुरू करें और गति बढ़ाकर निकलें ताकि आप चौराहे को कम समय तक रोकें","दाईं ओर रहें और केवल नितांत आवश्यक होने पर ही बाईं ओर चौड़ा मुड़ें, यह स्वीकार करते हुए कि यातायात आपके दाईं ओर से निकल सकता है"],"explanation":"दाईं ओर मुड़ते समय केवल मोड़ पूरा करते वक्त चौड़ा मुड़ें और वाहन का पिछला हिस्सा फुटपाथ के पास रखें ताकि कोई आपकी दाईं ओर से न घुस सके।"},"81":{"q":"आप एक पूरी तरह लदे ट्रेलर के साथ एक राज्य राजमार्ग पर चल रहे हैं और एक चौड़े मोड़ के पास पहुँच रहे हैं। सड़क किनारे एक संकेत पर लिखा है 'मोड़ — 45 MPH'। आपका ट्रक भारी है और ऊँचा है, लेकिन सड़क सूखी है और मौसम साफ है। कौन सा कथन सबसे अच्छा बताता है कि आपको उस लिखी हुई 45 MPH मोड़ गति को कैसे लेना चाहिए?","options":["45 MPH को अच्छी परिस्थितियों में कारों के लिए अधिकतम मानें, और इससे कम गति पर चलें क्योंकि आपके लदे, ऊँचे ट्रक को पलटने से बचने के लिए कम गति की आवश्यकता है।","45 MPH को विशेष रूप से आपके जैसे लदे भारी ट्रकों के लिए गणना की गई गति मानें, ताकि आप मोड़ को सुरक्षित रूप से ठीक 45 MPH पर ले सकें।","चूँकि सड़क सूखी है और मौसम साफ है, आप एक छूट जोड़ सकते हैं और मोड़ को 45 MPH से थोड़ा ऊपर ले सकते हैं।","लिखी हुई गति केवल रात में लागू होती है, इसलिए साफ दिन में आप इसे अनदेखा कर सकते हैं और मोड़ पर अपनी राजमार्ग गति बनाए रख सकते हैं।"],"explanation":"मोड़ पर लगी गति सीमा अच्छी परिस्थितियों में कारों के लिए तय होती है, इसलिए लदे, ऊँचे ट्रक को पलटने से बचने के लिए संकेत से कम गति रखनी चाहिए।"},"82":{"q":"आप एक पूरी तरह से लदे हुए ट्रेलर को एक लंबी, खड़ी पहाड़ी ढलान से नीचे ले जा रहे हैं। ढलान के बीच में, आप देखते हैं कि ब्रेक पेडल नरम होता जा रहा है और ट्रक धीरे-धीरे गति पकड़ रहा है, जबकि आप पूरी ढलान के दौरान लगातार ब्रेक दबाते रहे हैं। इस ब्रेकिंग शक्ति के नुकसान का सबसे संभावित कारण निम्नलिखित में से कौन सा है?","options":["ब्रेक अभी भी ठंडे हैं क्योंकि आपने अभी-अभी ढलान शुरू की है, इसलिए वे अभी पूरी तरह पकड़ नहीं रहे","लगातार दबाए रखने से ब्रेक अधिक गरम हो गए हैं, जिससे वे फीके (fade) पड़ गए और रोकने की शक्ति खो बैठे","ट्रेलर बहुत हल्का लदा है, इसलिए ब्रेक शूज़ को ड्रम पर दबाने के लिए पर्याप्त वजन नहीं है","ब्रेक शूज़ बिल्कुल नए हैं और ढलान पर वाहन को रोक पाने से पहले उन्हें घिसकर बैठने की जरूरत है"],"explanation":"लंबी ढलान पर लगातार ब्रेक दबाए रखने से वे ज्यादा गरम हो जाते हैं, जिससे ब्रेक फेड होकर रुकने की क्षमता खो देते हैं।"},"83":{"q":"आप लदे हुए ट्रक से गीले चार-लेन हाईवे पर चल रहे हैं, तभी एक कार अचानक आपके आगे आकर जोर से ब्रेक लगाती है। आपके डैश पर ABS लैंप बुझा है, यानी सिस्टम काम कर रहा है। जब आप ब्रेक पेडल को पूरी तरह दबाते हैं और ABS सक्रिय होता है, तो इस आपात ब्रेकिंग में ABS से आपको कौन-सा मुख्य लाभ अपेक्षित होना चाहिए?","options":["यह गारंटी देता है कि आप ABS रहित ट्रक की तुलना में काफी कम दूरी में रुक जाएँगे","यह अपने आप ब्रेक पंप करता है, इसलिए सूखी सड़क पर अब आपको स्टैब ब्रेकिंग करने की जरूरत नहीं रहती","यह पहियों को लॉक होने से रोकता है, ताकि जोर से ब्रेक लगाते समय भी आप स्टीयरिंग नियंत्रित रख सकें और अपनी लेन में बने रहें","यह आपको प्री-ट्रिप जाँच में ब्रेक एडजस्टमेंट देखना छोड़ने देता है क्योंकि कंप्यूटर ब्रेक की निगरानी करता है"],"explanation":"ABS तेज ब्रेकिंग के दौरान पहियों को लॉक होने से रोकता है, जिससे आप स्टीयरिंग नियंत्रण बनाए रखकर अपनी लेन में रहते हैं या खतरे से बच सकते हैं।"},"84":{"q":"आपने अभी-अभी अपना आखिरी माल उतारा है और अब खाली ट्रेलर को गीली दो-लेन वाली सड़क पर वापस यार्ड ले जा रहे हैं। आगे एक कार जोर से ब्रेक लगाती है और आपको जल्दी रुकना पड़ता है। आज सुबह जब आप पूरी तरह लदे हुए थे, उसकी तुलना में इस स्थिति में अपने खाली रिग से आपको क्या उम्मीद करनी चाहिए?","options":["माल का वजन नीचे न दबने के कारण टायर सड़क को बेहतर पकड़ते हैं, इसलिए आप लदे होने की तुलना में हमेशा कम दूरी में रुकेंगे।","खाली ट्रक बिल्कुल लदे हुए ट्रक की तरह व्यवहार करता है, इसलिए दोनों ही स्थिति में आपकी रुकने की दूरी अपरिवर्तित रहती है।","क्योंकि वजन बहुत कम है, पहिए लॉक या स्किड नहीं हो सकते, इसलिए अब जोर से ब्रेक लगाना पूरी तरह सुरक्षित है।","खाली ट्रक की पकड़ (ट्रैक्शन) कम होती है और वह उछल सकता है, इसलिए लदे होने की तुलना में इसे रुकने में वास्तव में अधिक दूरी लग सकती है।"],"explanation":"खाली ट्रक की पकड़ कम होती है और वह उछलता है, इसलिए लदे हुए की तुलना में उसे रुकने में ज्यादा समय लग सकता है।"},"85":{"q":"सूर्यास्त से लगभग एक घंटा पहले हल्की बारिश शुरू हो जाती है जब आप दो-लेन वाले राजमार्ग पर मुड़ते हैं। दृश्यता अभी भी काफी अच्छी है और आप इनके बिना सड़क साफ देख सकते हैं, लेकिन भूरे आसमान के सामने सामने से आने वाली गाड़ियों को पहचानना मुश्किल होता जा रहा है। इस स्थिति में आपकी हेडलाइट के लिए सबसे अच्छा तरीका क्या है?","options":["उन्हें बंद रहने दें, क्योंकि हेडलाइट चालू करना केवल तभी ज़रूरी है जब पूरी तरह अंधेरा हो जाए और आप आगे की सड़क न देख सकें","उन्हें अभी चालू करें, क्योंकि वे शाम के धुंधलके में और बारिश, कोहरे या अन्य कम रोशनी की स्थितियों में दूसरे चालकों को आपको देखने में मदद करती हैं","केवल हाई बीम का उपयोग करें, क्योंकि बारिश और घटती रोशनी का मतलब है कि आपको अधिकतम आगे की रोशनी चाहिए","तब तक प्रतीक्षा करें जब तक आप अधिक गति वाले विभाजित राजमार्ग पर न पहुँचें, क्योंकि हेडलाइट मुख्य रूप से राजमार्ग की गति पर ज़रूरी होती हैं"],"explanation":"शाम के धुंधलके और बारिश या कोहरे में हेडलाइट चालू करें क्योंकि कम रोशनी में ये आपके वाहन को अन्य चालकों को दिखाई देने लायक बनाती हैं।"},"86":{"q":"आप अपने ट्रेलर को एक तंग लोडिंग डॉक में पीछे ले जा रहे हैं और यात्री की ओर लगे बड़े उत्तल (घुमावदार) सहायक दर्पण में देखते हैं। एक कार, जिसके बारे में आप जानते हैं कि वह आपके पिछले बंपर से केवल कुछ ही फुट पीछे खड़ी है, उस दर्पण में छोटी और दूर दिखाई देती है। पीछे जाना जारी रखने से पहले, इस उत्तल दर्पण के द्वारा दिखाई जा रही चीज़ के बारे में आपको क्या समझना चाहिए?","options":["यह आपको अधिक चौड़ा दृश्य क्षेत्र देता है, लेकिन इसमें वस्तुएँ अपने वास्तविक स्थान से छोटी और दूर दिखाई देती हैं, इसलिए वह कार दिखने से अधिक पास है","यह दृश्य को बड़ा करता है, इसलिए वस्तुएँ अपने वास्तविक रूप से बड़ी और पास दिखाई देती हैं, यानी वह कार वास्तव में दिखने से अधिक दूर है","यह वस्तुओं का वास्तविक आकार और दूरी दिखाता है, इसलिए आप भरोसा कर सकते हैं कि कार उतनी ही पीछे है जितनी दर्पण में दिखती है","यह खराब है, क्योंकि सही ढंग से समायोजित दर्पण किसी पास की वस्तु को कभी छोटा नहीं दिखाएगा, और वैसे भी उत्तल दर्पण व्यावसायिक वाहनों पर कानूनी नहीं हैं"],"explanation":"उत्तल दर्पण व्यापक दृश्य देता है पर वस्तुएँ छोटी और दूर दिखाती हैं, इसलिए वे दिखने से असल में नजदीक होती हैं।"},"87":{"q":"आप राजमार्ग की गति पर एक लदा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं, तभी लगभग 12 से 15 सेकंड आगे आपको एक खराब खड़ी कार दिखती है जो अपनी खतरे की बत्तियाँ (हैज़र्ड लाइट) जलाए हुए दाहिनी लेन को आंशिक रूप से रोके हुए है। आपके आस-पास का यातायात अभी भी सामान्य रूप से चल रहा है और अभी कोई तात्कालिक आपात स्थिति नहीं है। आपकी पहली कार्रवाई क्या होनी चाहिए?","options":["अपनी गति और स्थिति बनाए रखें जब तक कार इतनी पास न आ जाए कि आप ठीक-ठीक आँक सकें कि वह आपकी लेन में कितनी घुसी हुई है","अभी से प्रतिक्रिया देने की तैयारी शुरू करें -- एक्सेलरेटर से पैर हटाएँ, अपने शीशे जाँचें और बचाव का रास्ता तय करें ताकि आपात स्थिति बनने से पहले आप सहजता से समायोजन कर सकें","तुरंत ज़ोरदार, नियंत्रित रुक-रुक कर (स्टैब) ब्रेक लगाएँ ताकि अभी से अधिक से अधिक गति कम कर सकें","तुरंत बायीं लेन में चले जाएँ और तेज़ी बढ़ाएँ ताकि बाकी यातायात के प्रतिक्रिया देने से पहले उस क्षेत्र को पार कर लें"],"explanation":"खतरे को जल्दी भांपने से प्रतिक्रिया का समय मिलता है, इसलिए आपातकाल बनने से पहले एक्सेलेरेटर छोड़ें, शीशे देखें और बचने का रास्ता तय करें।"},"88":{"q":"तेज़ मूसलाधार बारिश के दौरान आप एक अंतरराज्यीय राजमार्ग पर खाली ट्रेलर के साथ 55 मील प्रति घंटे की रफ़्तार से चल रहे हैं। आपको महसूस होता है कि स्टीयरिंग हल्की हो गई है और ट्रक तैरता हुआ-सा लगने लगा है, और आगे के टायर अब सड़क को पूरी तरह नहीं पकड़ रहे। आप समझ जाते हैं कि हाइड्रोप्लेनिंग शुरू हो रही है। सुरक्षित रूप से पकड़ वापस पाने का सबसे अच्छा मौका कौन-सी क्रिया देती है?","options":["जल्दी से रफ़्तार कम करने और टायरों को वापस सड़क पर दबाने के लिए ब्रेक पेडल को मज़बूती से दबाएं","स्टीयरिंग को ज़ोर से किनारे (शोल्डर) की ओर मोड़ें ताकि आगे के टायर खुरदरी सतह पर पकड़ बना लें","एक्सेलेरेटर से पैर हटा लें, स्टीयरिंग सीधी रखें और ट्रक को तब तक धीमा होने दें जब तक टायर दोबारा पकड़ न बना लें","आक्रामक तरीके से गियर कम करें और रफ़्तार जल्द से जल्द घटाने के लिए इंजन ब्रेकिंग का इस्तेमाल करें"],"explanation":"हाइड्रोप्लेनिंग में टायर सड़क से संपर्क खो देते हैं, इसलिए एक्सेलेरेटर से पैर हटाएँ और स्टीयरिंग सीधा रखें जब तक गति घटकर पकड़ वापस न आ जाए।"},"89":{"q":"आपने अभी-अभी अपने लदे हुए संयोजन वाहन को धीरे-धीरे एक जलमग्न निचले जल-क्रॉसिंग से पार किया है, और पानी इतना ऊपर चढ़ गया कि पहियों के हब डूब गए। जब आप वापस सड़क की गति पर तेज़ होते हैं, तो आप ब्रेक हल्के से दबाते हैं और महसूस करते हैं कि वे कमज़ोर और असमान रूप से पकड़ रहे हैं। सुरक्षित ब्रेकिंग बहाल करने का सबसे अच्छा तरीका कौन सा है?","options":["किनारे पर रुककर आगे बढ़ने से पहले ब्रेक ड्रम के हवा में सूखने का इंतज़ार करना","लाइनिंग से पानी निकालने के लिए ब्रेक पैडल को कई बार ज़ोर से पंप करना","गियर कम करके केवल इंजन ब्रेकिंग पर निर्भर रहना और अगले कुछ मील तक सर्विस ब्रेक को बिल्कुल न छूना","धीरे-धीरे चलते रहना और ब्रेक पर हल्का, स्थिर दबाव डालकर घर्षण की गर्मी से उन्हें सुखाना"],"explanation":"गीले ब्रेक को धीरे चलाते हुए हल्का, स्थिर दबाव देकर सुखाएँ ताकि घर्षण की गर्मी पानी को भाप बना दे और नियंत्रण बना रहे।"},"90":{"q":"आप 55 मील प्रति घंटे की गति सीमा वाले एक ग्रामीण दो-लेन राजमार्ग पर समय से पीछे चल रहे हैं। आगे का वाहन धीरे चल रहा है और आप उसे ओवरटेक करना चाहते हैं। निम्नलिखित में से किस स्थिति में ओवरटेक करने का प्रयास सबसे कम सुरक्षित होगा और इसलिए आपको ऐसा नहीं करना चाहिए?","options":["आप एक पहाड़ी की चोटी के पास पहुँच रहे हैं और देख नहीं सकते कि सामने वाली लेन में कोई वाहन आपकी ओर आ रहा है या नहीं","आप एक लंबे, समतल और सीधे हिस्से पर हैं जहाँ आप साफ़ देख सकते हैं कि आगे एक-चौथाई मील से अधिक तक सड़क खाली है","आप एक चिह्नित ओवरटेकिंग ज़ोन में प्रवेश कर चुके हैं जहाँ आपकी ओर टूटी हुई पीली केंद्र रेखा है और आगे की दृश्यता साफ़ है","आप देख सकते हैं कि सामने वाली लेन खाली है और आपके पास सामने से आने वाले यातायात से बहुत पहले अपनी लेन में लौटने के लिए पर्याप्त जगह है"],"explanation":"जहाँ आप पर्याप्त दूर तक न देख सकें, जैसे पहाड़ी की चोटी के पास, वहाँ कभी ओवरटेक न करें क्योंकि सामने से आते वाहन देर होने तक छिपे रहते हैं।"},"91":{"q":"आप एक छोटे प्रवेश रैंप पर एक लदे हुए ट्रैक्टर-ट्रेलर को चला रहे हैं। आपकी बाईं ओर फ्रीवे पर ट्रैफ़िक लगभग 60 मील प्रति घंटा की गति से चल रहा है, और आगे दाईं लेन में दो कारों के बीच एक उपयोगी खाली जगह खुलती दिख रही है। जैसे ही आप त्वरण लेन (एक्सेलरेशन लेन) के अंत तक पहुँचते हैं, ट्रैफ़िक में प्रवेश करने का सबसे सुरक्षित तरीका क्या है?","options":["रैंप के अंत में लगभग रुकने तक धीमा हो जाएँ और निकलने से पहले बहुत बड़ी खाली जगह का इंतज़ार करें","त्वरण लेन का उपयोग करके अपनी गति को ट्रैफ़िक के प्रवाह के करीब लाएँ, फिर सहजता से खुली जगह में विलय करें","अपनी गति कम रखें और धीरे-धीरे लेन में घुसें, पीछे की कारों को ब्रेक लगाकर आपके लिए जगह बनाने पर मजबूर करें","विलय से पहले ट्रैफ़िक को आंकने के लिए अधिक समय पाने हेतु रैंप पर धीमी, स्थिर गति से रेंगते रहें"],"explanation":"त्वरण लेन का उपयोग कर यातायात प्रवाह के करीब गति प्राप्त करें, फिर खाली जगह में मिलें ताकि अन्य वाहनों से गति का अंतर कम से कम हो।"},"92":{"q":"आप चार-लेन वाले विभाजित राजमार्ग की दाहिनी लेन में एक लदे हुए ट्रैक्टर-ट्रेलर को चला रहे हैं, तभी आपको सायरन सुनाई देता है और आईने में जलती हुई बत्तियों के साथ तेज़ी से पास आती एक एम्बुलेंस दिखती है। यातायात मध्यम है और आपकी दाहिनी ओर पक्का किनारा (शोल्डर) है। सबसे अच्छी कार्रवाई कौन-सी है?","options":["अपनी लेन और गति बनाए रखें ताकि एम्बुलेंस आपके रास्ते का अनुमान लगा सके और आपको बायीं ओर से पार कर सके","अगले निकास तक एम्बुलेंस से आगे रहने के लिए गति बढ़ाएँ, फिर राजमार्ग छोड़ दें","संकेत दें, वाहन को दाहिने किनारे की ओर ले जाएँ, और रास्ता खाली करने के लिए सुरक्षित होने पर अपने वाहन को रोक दें","दाहिनी लेन और किनारा आपातकालीन वाहन के लिए खाली करने हेतु बायीं ओर ओवरटेकिंग लेन में चले जाएँ"],"explanation":"बत्ती और सायरन वाले आपातकालीन वाहन के आने पर संकेत दें, दाहिने किनारे की ओर जाएँ और सुरक्षित होने पर रुककर रास्ता दें।"},"93":{"q":"शोल्डर पर रुकने के बाद आपके ट्रैक्टर के इंजन डिब्बे में एक छोटी विद्युत आग लग जाती है। आप अपना अग्निशामक यंत्र उठाते हैं, हवा की दिशा में अपनी पीठ करके खड़े होते हैं, पिन खींचते हैं और नोज़ल को आग की ओर ताकते हैं। PASS विधि का सही पालन करते हुए, हैंडल दबाने के बाद आग को प्रभावी ढंग से बुझाने के लिए आपको कौन सी अंतिम क्रिया करनी चाहिए?","options":["नोज़ल को स्थिर रखें और दिखाई देने वाली लपटों के ऊपरी हिस्से पर सीधे निशाना लगाएं जब तक वे कम न हो जाएं","धुआं दिखते ही तुरंत छिड़काव बंद कर दें ताकि अग्निशामक यंत्र बर्बाद न हो","अग्निशामक यंत्र को आग के ऊपर गोलाकार घुमाएं ताकि बुझाने वाला पदार्थ एक बड़े क्षेत्र में फैल जाए","नोज़ल को आग के आधार की ओर ताकते हुए, आग बुझने तक इसे एक ओर से दूसरी ओर झाड़ू की तरह घुमाएं"],"explanation":"PASS विधि का अंतिम चरण है नोज़ल को आग के आधार पर, जहाँ ईंधन जलता है, अगल-बगल घुमाना ताकि आग दबकर बुझ जाए।"},"94":{"q":"आप एक ग्रामीण दो-लेन वाले राजमार्ग पर गाड़ी चला रहे हैं, तभी एक अन्य चालक आपके बगल में आकर इशारा करते हुए चिल्लाता है कि आपके ट्रेलर का एक टायर जल रहा है। आप किनारे पर गाड़ी रोकते हैं, ब्रेक लगाते हैं, और अपना अग्निशामक यंत्र तथा सड़क सुरक्षा किट उठाते हैं। जलते हुए टायर के पास जाते समय, इस आग पर काबू पाने के लिए सबसे उपयुक्त कार्य क्या है?","options":["टायर को ठंडा करने के लिए उस पर भरपूर पानी डालें, क्योंकि टायर की आग तीव्र गर्मी पैदा करती है और इसे बुझाने के लिए लगातार ठंडा करने की आवश्यकता होती है","अपने सूखे रासायनिक (B:C श्रेणी) अग्निशामक यंत्र को सीधे लपटों के आधार पर ताकें और सिलेंडर खाली होने तक वहीं रखें","इसे छोड़ दें और सुरक्षित दूरी से इसे अपने आप जलकर बुझने दें, क्योंकि रबर की आग को दबाने से वह फिर से भड़क उठती है","लपटें शांत होने तक टायर के ढाँचे को ढहने से बचाने के लिए सावधानी से उसमें हवा भरें"],"explanation":"टायर की आग रबर में तीव्र गर्मी रोके रखती है, इसलिए लगातार ठंडा करने के लिए खूब पानी डालें वरना वह फिर भड़क उठेगी।"},"95":{"q":"तापमान हिमांक से थोड़ा नीचे है और हल्की बारिश सड़क पर बर्फ की परत जमाना शुरू कर रही है। एक चौड़े मोड़ पर अपनी सामान्य हाईवे गति बनाए रखते हुए, आपके ट्रैक्टर-ट्रेलर का पिछला हिस्सा अचानक बगल की ओर फिसलने लगता है और आप महसूस करते हैं कि ट्रेलर केबिन को बगल में धकेल रहा है। जिस क्षण फिसलन शुरू हुई, उसका ईमानदारी से आकलन करें तो सबसे अधिक संभावित एकमात्र कारण क्या था?","options":["आपके आगे के स्टीयरिंग-एक्सल टायर 2/32 इंच की न्यूनतम सीमा के करीब घिस चुके थे और सबसे पहले उनकी पकड़ खो गई","हिमांक के निकट फिसलन भरी सड़क की स्थितियों के लिए आप बहुत तेज़ चल रहे थे","आपने मोड़ पर तेज़ सुधारों के बजाय सहज, हल्के स्टीयरिंग का उपयोग किया","आपका ट्रेलर खाली चल रहा था, और खाली ट्रेलर हमेशा भरे हुए ट्रेलरों की तुलना में सड़क पर बेहतर पकड़ बनाते हैं"],"explanation":"अधिकांश स्किड परिस्थितियों के लिए तेज़ चलाने से होती हैं, और जमाव-बिंदु के पास फिसलन भरी सड़क पकड़ घटा देती है जिससे सामान्य गति भी अत्यधिक हो जाती है।"},"96":{"q":"तापमान जमाव बिंदु से थोड़ा नीचे है और हल्की बारिश हो रही है। आप तीन-लेन वाले राजमार्ग की बीच वाली लेन में हैं, तभी पीछे का ट्रेलर हल्का महसूस होने लगता है और बगल वाली लेन की ओर खिसकने लगता है। नीचे दिए गए कार्यों में से कौन-सा आपको वाहन पर नियंत्रण बनाए रखने और पूरी तरह फिसलन (स्किड) से बचने का सबसे अच्छा मौका देता है?","options":["जोर से ब्रेक लगाएं और पेडल को मजबूती से दबाए रखें ताकि गति जितनी जल्दी हो सके कम हो जाए","खिसकाव रोकने के लिए स्टीयरिंग को तेज, झटकेदार तरीके से अपनी लेन के बीच की ओर वापस मोड़ें","एक्सेलरेटर से पैर हटाएं और पकड़ (ट्रैक्शन) बनाए रखने के लिए स्टीयरिंग व ब्रेक के सहज, नरम इनपुट दें","अपनी मौजूदा गति बनाए रखें और जोर से स्टीयरिंग घुमाएं, क्योंकि बीच वाली लेन में टायरों की पकड़ अभी भी है"],"explanation":"फिसलन भरी, जमाव-बिंदु के पास सड़कों पर टायरों पर भार घटाएँ: एक्सेलेरेटर छोड़ें और पकड़ बनाए रखने के लिए सहज, हल्के स्टीयरिंग व ब्रेकिंग करें।"},"97":{"q":"जुलाई के अंत में दोपहर बाद का समय है और आप कई घंटों से गर्म डामर पर भरे हुए ट्रक के साथ चल रहे हैं। आराम के लिए रुकने पर आप इस यात्रा में अपने टायरों को सामान्य से अधिक बार जाँचने का फैसला करते हैं। इन परिस्थितियों में ऐसा करने का सबसे अच्छा कारण क्या है?","options":["गर्म सड़क टायरों के अंदर की हवा को ठंडा कर देती है, जिससे उनका दबाव घट जाता है और वे कम हवा भरे चलते हैं","गर्मी ट्रेड की रबर को नरम कर देती है, जो गर्मियों में टायर फटने का मुख्य कारण है","टायर गर्मी में भौतिक रूप से सिकुड़ जाते हैं, जिससे सड़क से संपर्क क्षेत्र छोटा हो जाता है","गर्मी टायरों के अंदर हवा का दबाव बढ़ा देती है, जिससे टायर फट सकता है"],"explanation":"गर्म मौसम में टायरों के अंदर बंद हवा फैलती है और दबाव बढ़ता है, जिससे टायर फट सकता है।"},"98":{"q":"आप एक ग्रामीण दो-लेन राजमार्ग पर माल ढो रहे हैं तभी आप इतने घने कोहरे के बैंक में प्रवेश करते हैं कि गति कम करने और लो बीम पर स्विच करने के बाद भी आप लेन की लाइनें या आगे कोई वाहन नहीं देख पाते। गति को और कम करने से भी सुरक्षित रास्ता देखने की आपकी क्षमता वापस नहीं आई। सबसे सुरक्षित कार्रवाई क्या है?","options":["कोहरे के पार अधिक रोशनी फेंकने के लिए हाई बीम पर स्विच करना और बहुत धीमी गति से रेंगते हुए आगे बढ़ते रहना","अपनी लेन में लगभग रुकने तक धीमा होना, अपनी हैज़र्ड फ्लैशर चालू करना और धीरे-धीरे आगे बढ़ते रहना","सड़क से पूरी तरह बाहर निकल जाना, यातायात से अच्छी तरह दूर हो जाना, अपनी लाइटें और फ्लैशर चालू करना और कोहरा छंटने का इंतज़ार करना","एक धीमी स्थिर गति बनाए रखना और अपनी लेन में बने रहने के लिए आगे के वाहन की पिछली लाइटों का पीछा करना"],"explanation":"जब कोहरा इतना घना हो कि धीमी गति पर भी सुरक्षित रास्ता न दिखे, तो सड़क से पूरी तरह बाहर निकलें, यातायात से दूर हटें, लाइट और फ्लैशर चालू करें और इसके छंटने तक रुकें।"},"99":{"q":"आज सुबह आपने एक पूरी प्री-ट्रिप जांच पूरी की, अपना माल सुरक्षित किया, और सब कुछ ठीक पाया गया। यात्रा के तीन घंटे बाद आप भोजन के विराम के लिए रुकते हैं, और एक साथी चालक पूछता है कि जब आप निकलने से पहले ही जांच कर चुके थे, तो अब आप अपने ट्रक के चारों ओर घूमकर अपने माल की दोबारा जांच क्यों कर रहे हैं। पूरे दिन जांच जारी रखने का सबसे अच्छा कारण क्या है?","options":["एक उचित जांच एक निरंतर प्रक्रिया है जो यात्रा से पहले, यात्रा के दौरान (रास्ते में) और यात्रा के बाद की जाती है, क्योंकि वाहन की स्थिति और माल की बंधाई गाड़ी चलाते समय बदल सकती है।","एक बार जब कोई वाहन पूरी प्री-ट्रिप जांच पास कर लेता है, तो कानून उसे उस यात्रा के शेष भाग के लिए सड़क-योग्य मान लेता है, इसलिए चारों ओर घूमना केवल एक व्यक्तिगत आदत है, कोई आवश्यकता नहीं।","रास्ते में जांच केवल तभी जरूरी है जब कोई चेतावनी बत्ती जले या वाहन वास्तव में खराब हो जाए, क्योंकि एक पास की गई प्री-ट्रिप जांच पहले ही सभी यांत्रिक चीजों को कवर कर लेती है।","दोबारा जांच केवल इसलिए जरूरी है क्योंकि आपको पहले 50 मील के भीतर माल की जांच करनी होती है, और उस पहली जांच के बाद पूरे दिन वाहन की कोई और जांच जरूरी नहीं है।"],"explanation":"निरीक्षण एक सतत प्रक्रिया है — यात्रा से पहले, दौरान (मार्ग में) और बाद में — क्योंकि टायर दबाव, कार्गो की सुरक्षा और तरल स्तर चलते समय बदलते हैं।"},"100":{"q":"आज सुबह आपने एक फ्लैटबेड पर स्टील के कॉइल लादे और यार्ड से निकलकर इंटरस्टेट हाईवे पर आ गए। लगभग 35 मील आगे आपको एक चौड़ा विश्राम क्षेत्र दिखता है जहाँ आप अपने पूरे ट्रक के चारों ओर चल सकते हैं। आपकी यात्रा कुल मिलाकर 300 मील से अधिक की है। सही माल प्रक्रिया के अनुसार, अपने माल और उसकी बंधाई की जाँच के बारे में आपको क्या करना चाहिए?","options":["गाड़ी चलाते रहें और अपनी पहली बंधाई जाँच 150 मील के निशान पर करें, क्योंकि यही मानक पुनः-जाँच अंतराल है","अभी अंदर रुककर अपने माल और टाई-डाउन की जाँच करें, क्योंकि आपको पहली जाँच पहले 50 मील के भीतर करनी होती है और फिर हर 3 घंटे या 150 मील पर दोबारा जाँचनी होती है","जब तक आप ईंधन के लिए न रुकें तब तक किसी जाँच की आवश्यकता नहीं, बशर्ते प्री-ट्रिप के दौरान माल सुरक्षित दिखा हो","पहले 500 मील चलाने तक प्रतीक्षा करें, फिर माल का समय-समय पर निरीक्षण शुरू करें"],"explanation":"आपको पहले 50 मील के भीतर कार्गो और टाई-डाउन की जाँच करनी चाहिए, फिर हर 3 घंटे या 150 मील पर और हर ब्रेक के बाद दोबारा जाँचें।"},"101":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान आप देख रहे हैं कि केबिन के पीछे कार्गो क्षेत्र में स्टील पाइप का माल कैसे बाँधा गया है। एक सहकर्मी आपको बताता है कि कार्गो को कसकर बाँधने का एकमात्र असली कारण यह है कि यात्रा के दौरान वह खरोंचे नहीं या बिखरा हुआ न दिखे। टेक्सास DPS के कार्गो नियमों के अनुसार, कार्गो को ठीक से सुरक्षित करना आवश्यक होने का प्रमुख सुरक्षा कारण क्या है?","options":["ताकि डिलीवरी स्थल पर पहुँचने पर माल साफ-सुथरा और प्रस्तुत करने योग्य दिखे","ताकि माल बारिश, सड़क की धूल से सुरक्षित रहे और खराब मौसम में सूखा रहे","ताकि माल खिसक न सके, वाहन से गिर न सके, या हिलकर चालक के नियंत्रणों को बाधित न कर सके","ताकि सर्दियों की परिस्थितियों में गाड़ी चलाते समय माल ठंडा होकर जम न जाए"],"explanation":"कार्गो को इस तरह सुरक्षित करना चाहिए कि वह न हिले, वाहन से न गिरे, या केबिन में फिसलकर चालक के नियंत्रणों को न रोके।"},"102":{"q":"आप दोपहर बाद देर से एक लदे हुए ट्रैक्टर-ट्रेलर को पश्चिम दिशा में चला रहे हैं। सूरज ठीक सामने क्षितिज पर नीचे आ गया है, और उसकी चकाचौंध सड़क को धुंधला कर रही है जिससे यह आंकना मुश्किल हो रहा है कि आप कितनी दूर तक देख सकते हैं। आगे के वाहन उस चमकीले परदे में से अचानक सामने आ जाते हैं। इस स्थिति से निपटने का सबसे अच्छा तरीका क्या है?","options":["सन वाइज़र नीचे करें, धूप का चश्मा लगाएं, और अपनी गति इतनी कम करें कि आप वास्तव में जितनी दूर देख सकते हैं उतनी दूरी के भीतर रुक सकें","अपनी हाई बीम चालू कर दें ताकि आपकी अपनी रोशनी आगे की चकाचौंध को चीरकर निकल सके","अपनी गति बनाए रखें लेकिन भरपाई के लिए अपनी अनुसरण दूरी 6 सेकंड तक बढ़ा दें","बाईं लेन में जाकर गति बढ़ा दें ताकि चकाचौंध से प्रभावित सड़क के हिस्से को जल्दी पार कर सकें"],"explanation":"सूरज की चकाचौंध में सन वाइज़र नीचे करें, धूप का चश्मा पहनें और इतना धीमा करें कि वास्तव में दिखने वाली दूरी में रुक सकें।"},"103":{"q":"आप दो-लेन वाले ग्रामीण राजमार्ग पर एक लंबी, खड़ी चढ़ाई पर लदे हुए ट्रेलर को ऊपर ले जा रहे हैं। आपका इंजन जोर लगा रहा है और आपकी गति निर्धारित 55 मील प्रति घंटे की सीमा से काफी कम, लगभग 15 मील प्रति घंटे तक गिर गई है, जबकि आपके पीछे कारें जमा हो रही हैं। इनमें से किस स्थिति में अपनी चार-तरफा आपातकालीन फ्लैशर लाइटें चालू करना सबसे उपयुक्त कार्य है?","options":["जब आप अगले चौराहे पर सामान्य दाहिना मोड़ लेते हैं, क्योंकि अकेला आपका सिग्नल शायद न दिखे","जैसे ही आप चोटी पर पहुँचते हैं और 55 मील प्रति घंटे की सीमा पर सामान्य गति से चलने लगते हैं, ताकि चालकों को सूचित किया जा सके कि आप एक धीमा वाणिज्यिक वाहन हैं","रात भर के लिए वाहन को एक अच्छी तरह रोशन ट्रक स्टॉप पर पार्क करने के बाद, ताकि दूसरे उसकी रूपरेखा देख सकें","अभी, जब आप यातायात के प्रवाह से बहुत धीमी गति से चढ़ाई पर रेंग रहे हैं, क्योंकि आप अपने आसपास के वाहनों की तुलना में बहुत धीमे चल रहे हैं"],"explanation":"जब आप आसपास के यातायात से बहुत धीमे चल रहे हों, जैसे तीव्र चढ़ाई पर रेंगते हुए, तब पीछे वाले चालकों को चेतावनी देने के लिए चारों ओर के फ्लैशर चालू करें।"},"105":{"q":"आप अपने लदे हुए संयोजन वाहन में एक बहु-लेन गोलचक्कर (राउंडअबाउट) के पास पहुँच रहे हैं। जिस लेन में आप प्रवेश करना चाहते हैं, उसमें एक कार पहले से ही घूम रही है, और उसके ठीक पीछे एक जगह खुल रही है। निम्नलिखित में से कौन-सा सही और सबसे सुरक्षित कार्य है?","options":["गोलचक्कर में पहले से मौजूद वाहन को रास्ता दें, एक सुरक्षित जगह की प्रतीक्षा करें, फिर प्रवेश करें और यातायात के प्रवाह में मिल जाएँ","अपनी गति बनाए रखें और तुरंत प्रवेश करें, क्योंकि गोलचक्कर में पहले से मौजूद वाहनों को प्रवेश करने वाले ट्रकों को रास्ता देना आवश्यक है","गोलचक्कर की घूमती हुई लेन के अंदर रुक जाएँ और तब तक वहीं प्रतीक्षा करें जब तक बाकी सारा यातायात साफ़ न हो जाए","यदि आप जगह का गलत अनुमान लगाते हैं और बहुत जल्दी प्रवेश करना शुरू कर देते हैं, तो मिलने से पहले एक सुरक्षित अनुसरण दूरी फिर से बनाने के लिए पीछे की ओर वाहन ले जाएँ"],"explanation":"राउंडअबाउट में पहले से मौजूद यातायात को प्राथमिकता होती है, इसलिए रास्ता दें, सुरक्षित अंतराल का इंतजार करें, फिर प्रवेश करें और प्रवाह में मिल जाएँ।"},"106":{"q":"आप दाहिनी लेन में निर्धारित गति-सीमा पर एक लदा हुआ ट्रेलर चला रहे हैं, तभी पीछे का एक चालक बहुत पास आकर चलने लगता है, हाई बीम जलाता-बुझाता है और गुस्से में इशारे करता है क्योंकि आप गति नहीं बढ़ा रहे। आगे का यातायात आपको तुरंत लेन बदलने नहीं देता। इस आक्रामक चालक को संभालने और अपनी सुरक्षा की रक्षा करने का सबसे अच्छा तरीका कौन-सा है?","options":["ब्रेक हल्के से दबाकर ब्रेक-लाइट चमकाएँ ताकि चालक को पीछे हटने की चेतावनी मिले","अपनी गति बनाए रखें और दृढ़ता से अपनी लेन में बने रहें ताकि चालक सीख ले कि बड़े ट्रकों के पास नहीं आना चाहिए","जब सुरक्षित हो, तब लेन बदलकर या थोड़ा धीमा होकर जगह बनाएँ और इशारों पर प्रतिक्रिया दिए बिना गुस्साए चालक को आगे निकलने दें","निर्धारित गति-सीमा से अधिक तेज़ चलाएँ जब तक आप इतना आगे न निकल जाएँ कि चालक पास आकर चलना बंद कर दे"],"explanation":"पीछे आक्रामक चालक हो तो उलझें नहीं; उसे आगे निकलने की जगह दें और शांत रहकर टकराव टालें।"},"107":{"q":"एक भारी आंधी-तूफान ने जिस हाईवे पर आप चला रहे हैं उसकी दाहिनी लेन में कई इंच जमा हुआ खड़ा पानी छोड़ दिया है। आप खाली (बिना लदान) 55 मील प्रति घंटा की गति से चल रहे हैं। आगे जमा गहरे पानी के पास पहुँचते समय, अपने वाहन को नियंत्रण में रखने का सबसे अच्छा तरीका कौन सा है?","options":["55 मील प्रति घंटा बनाए रखें लेकिन कंधे (शोल्डर) की ओर मुड़ें, क्योंकि स्टीयरिंग टायरों से पानी हटाने से पकड़ वापस आ जाती है","पानी में घुसने से पहले अपनी गति कम कर लें, क्योंकि आपके टायरों और सड़क के बीच फँसा पानी हाइड्रोप्लेनिंग और स्टीयरिंग व ब्रेक नियंत्रण के नुकसान का कारण बन सकता है","पानी के बीच से मज़बूती से गति बढ़ाकर निकलें ताकि टायर का ट्रेड पानी को किनारे कर दे और टायर सड़क को पकड़े रहें","अपनी गति स्थिर रखें और पानी में रहते हुए हल्के से ब्रेक लगाएँ ताकि जाँच सकें कि आपके पास कितनी पकड़ बची है"],"explanation":"रुके हुए पानी तक पहुँचने से पहले गति कम करें, क्योंकि टायरों और सड़क के बीच फँसा पानी हाइड्रोप्लेनिंग और स्टीयरिंग व ब्रेकिंग नियंत्रण के नुकसान का कारण बन सकता है।"},"108":{"q":"आप एक सूखे, साफ़ अंतरराज्यीय राजमार्ग पर खाली ट्रक चला रहे हैं और समय बचाने के लिए अपनी गति 30 मील प्रति घंटा से बढ़ाकर 60 मील प्रति घंटा करने का फैसला करते हैं। आपके साथ बैठा एक प्रशिक्षु पूछता है कि यह बदलाव आपके ट्रक को पूरी तरह रोकने के लिए ज़रूरी ब्रेकिंग दूरी को कैसे प्रभावित करता है। कौन सा उत्तर सबसे अच्छी तरह बताता है कि वास्तव में क्या होता है?","options":["चूंकि ट्रक खाली है, हल्का भार इसे 60 पर लगभग उतनी ही दूरी में रोकने देता है जितनी 30 पर थी।","गति दोगुनी करने से रुकने की दूरी में केवल थोड़ी वृद्धि होती है — ब्रेकिंग दूरी गति के अनुपात में बढ़ती है, इसलिए यह बस दोगुनी हो जाती है।","गति दोगुनी करने से ब्रेकिंग दूरी लगभग चार गुना हो जाती है, इसलिए 60 मील प्रति घंटा पर 30 मील प्रति घंटा की तुलना में लगभग चार गुना जगह चाहिए।","गीली सड़क पर यह मायने रखता, पर इस सूखी सड़क पर अधिक गति आपकी रुकने की दूरी को शायद ही बदलती है।"],"explanation":"ब्रेकिंग दूरी गति के वर्ग के अनुपात में बढ़ती है, इसलिए गति दोगुनी करने पर रुकने की दूरी लगभग चार गुना हो जाती है।"},"109":{"q":"तापमान हिमांक से ठीक नीचे है और हल्की बारिश ने सड़क पर बर्फ की परत जमा दी है। आप खाली ट्रक चला रहे हैं और एक मोड़ पर ट्रक के पिछले पहिये फिसलने लगते हैं। यह स्किड किस कारण से हुई, इसकी समीक्षा करते हुए, आपके द्वारा की गई निम्नलिखित में से कौन सी क्रिया इसका कारण होने की सबसे कम संभावना रखती है?","options":["मोड़ को ट्रैक्शन की ताकत से पार करने के लिए एक्सेलेरेटर को जोर से दबाना","जब आपने महसूस किया कि पिछला हिस्सा हिल रहा है तो पहियों को लॉक करने जितनी जोर से ब्रेक लगाना","पूरे मोड़ के दौरान स्टीयरिंग को सहज और क्रमिक रखना","बर्फीली और गीली परिस्थितियों के लिए बहुत अधिक गति बनाए रखना"],"explanation":"सहज और क्रमिक स्टीयरिंग टायर के बलों को उपलब्ध पकड़ की सीमा में रखती है, इसलिए अत्यधिक गति, तेज़ ब्रेकिंग या अधिक त्वरण के विपरीत यह स्किड नहीं कराती।"},"110":{"q":"दो-लेन वाले ग्रामीण राजमार्ग पर अच्छी तरह अंधेरा हो चुका है और आप लगभग 400 फुट आगे एक ढलान के ऊपर से आ रहे सामने वाले ट्रक की हेडलाइटें देखते हैं। इस समय आपकी हाई बीम चालू है। सही कार्रवाई क्या है?","options":["अपनी हाई बीम चालू रहने दें ताकि दूसरा चालक आपके बड़े वाहन को साफ़ देख सके","अभी, वाहनों के एक-दूसरे से 500 फुट के भीतर आने से पहले ही लो बीम पर स्विच करें","दूसरे चालक को संकेत देने के लिए हाई बीम को थोड़ी देर बंद-चालू करें, फिर उसे चालू रखें","थोड़ा तेज़ चलें ताकि चकाचौंध समस्या बनने से पहले आप सामने वाले ट्रक से पार हो जाएं"],"explanation":"सामने से आते वाहन के 500 फुट के भीतर लो बीम पर आ जाएं ताकि आपकी हाई बीम दूसरे चालक की आँखें न चौंधिया दे।"},"111":{"q":"आप एक ग्रामीण दो-लेन राजमार्ग पर एक लदी हुई फ्लैटबेड चला रहे हैं, तभी आपका इंजन शक्ति खोने लगता है और 55 मील प्रति घंटे वाली सड़क पर आपको लगभग 30 मील प्रति घंटे तक धीमा होना पड़ता है। आपके पीछे ट्रैफ़िक जमा हो रहा है। जब आप समस्या जाँचने के लिए किनारे रुकने हेतु ट्रक को अगले निकास (एग्ज़िट) तक संभालकर ले जा रहे हैं, तो निम्नलिखित में से कौन-सा आपके चार-तरफ़ा हैज़र्ड फ़्लैशर का अनुचित उपयोग होगा?","options":["तेज़ ट्रैफ़िक को यह चेतावनी देने के लिए उन्हें चालू रखना कि आप सड़क की सामान्य गति से बहुत धीमे चल रहे हैं","जब आप वास्तव में निकास रैंप में मुड़ रहे हों, तब उन्हें बंद करके केवल अपना दायाँ टर्न सिग्नल उपयोग करना","जब आप किनारे (शोल्डर) पर रुककर इंजन की जाँच कर रहे हों, तब उन्हें फिर से चालू करना","रैंप की ओर दाएँ मुड़ने वाले हैं यह दर्शाने के लिए टर्न सिग्नल के बजाय उनका उपयोग करना"],"explanation":"हज़ार्ड फ्लैशर रुके, खराब या धीमे चल रहे वाहन की चेतावनी देते हैं और इन्हें कभी टर्न सिग्नल के बदले इस्तेमाल नहीं करना चाहिए।"},"112":{"q":"आप एक सूखे, समतल राज्य राजमार्ग पर 40 फुट लंबा ठोस भार ले जा रहे हैं और दिन के अच्छे हालात में आपका स्पीडोमीटर स्थिर रूप से 45 मील प्रति घंटा दिखा रहा है। आगे सुरक्षित दूरी बनाए रखने के लिए, आगे चल रहे वाहन के पीछे आपको कम से कम कितनी अनुसरण दूरी (फॉलोइंग डिस्टेंस) रखनी चाहिए?","options":["4 सेकंड, क्योंकि 40 फुट के वाहन को हर 10 फुट लंबाई के लिए 1 सेकंड चाहिए","6 सेकंड, क्योंकि 40 मील प्रति घंटा से ऊपर की कोई भी गति अपने आप कम से कम 6 सेकंड मांगती है","5 सेकंड, क्योंकि 40 फुट के बराबर 4 सेकंड होते हैं और 40 मील प्रति घंटा से ऊपर होने पर आप 1 सेकंड और जोड़ते हैं","3 सेकंड, क्योंकि सड़क सूखी, समतल है और दृश्यता अच्छी है"],"explanation":"प्रत्येक 10 फुट लंबाई के लिए 1 सेकंड रखें, इसलिए 40-फुट वाहन को 4 सेकंड चाहिए, और 40 मील/घंटा से ऊपर होने पर 1 सेकंड और जोड़ें, कुल 5 सेकंड।"},"113":{"q":"आप 50 फुट लंबे ट्रैक्टर-ट्रेलर को एक निर्माण कार्य क्षेत्र से निकाल रहे हैं जहाँ यातायात कम हो गया है और निर्धारित गति सीमा आपको स्थिर 35 मील प्रति घंटे की गति से चलने देती है। आप आगे चल रहे पिकअप के पीछे एक सुरक्षित अनुसरण दूरी रखना चाहते हैं। वाहन की हर 10 फुट लंबाई के लिए 1 सेकंड के नियम का उपयोग करते हुए, इस विशेष स्थिति के लिए कौन सी अनुसरण दूरी सही है?","options":["4 सेकंड, क्योंकि धीमे निर्माण क्षेत्र में आप अंतर को एक सेकंड कम कर सकते हैं","7 सेकंड: लंबाई के लिए 5 सेकंड और निर्माण क्षेत्र के लिए 2 अतिरिक्त सेकंड","6 सेकंड, क्योंकि लंबाई-आधारित गणना में आपको हमेशा 1 अतिरिक्त सेकंड जोड़ना चाहिए","5 सेकंड, क्योंकि 50 फुट को 10 से भाग देने पर 5 आता है, और चूंकि आप 40 मील प्रति घंटे से कम पर हैं इसलिए कोई अतिरिक्त सेकंड नहीं जोड़ा जाता"],"explanation":"प्रत्येक 10 फुट लंबाई के लिए 1 सेकंड रखें, इसलिए 50-फुट वाहन को 5 सेकंड चाहिए, और 40 मील/घंटा से कम होने के कारण कोई अतिरिक्त सेकंड नहीं जोड़ा जाता।"},"114":{"q":"आप एक 60-फुट लंबे ट्रैक्टर-ट्रेलर को साफ दिन के मौसम में सूखे, समतल अंतरराज्यीय राजमार्ग पर लगातार 55 मील प्रति घंटे की गति से चला रहे हैं। यातायात हल्का है और आप आगे चल रहे वाहन के पीछे एक सुरक्षित दूरी रखना चाहते हैं। अनुसरण दूरी के नियम के अनुसार, इस स्थिति में आपको कम से कम कितनी अनुसरण दूरी रखनी चाहिए?","options":["7 सेकंड","6 सेकंड","8 सेकंड","5 सेकंड"],"explanation":"प्रत्येक 10 फुट लंबाई के लिए 1 सेकंड रखें, इसलिए 60-फुट वाहन को 6 सेकंड चाहिए, और 40 मील/घंटा से ऊपर होने पर 1 सेकंड और जोड़ें, कुल 7 सेकंड।"},"115":{"q":"आप एक सीधा सिंगल-यूनिट ट्रक चला रहे हैं जो बंपर से बंपर तक 30 फीट लंबा है। शहरी सड़क पर यातायात लगातार 30 मील प्रति घंटा की गति से चल रहा है, जो आपको ठीक 40 मील प्रति घंटा की सीमा से नीचे रखता है। इन परिस्थितियों में अपने वाहन के लिए सुरक्षित अनुसरण दूरी छोड़ने हेतु, आगे चल रहे वाहन से आपको कम से कम जितने सेकंड रखने चाहिए, वह है:","options":["2 सेकंड, क्योंकि 30 मील प्रति घंटा पर आप हाईवे गति से काफी नीचे हैं और यातायात सुचारू रूप से बह रहा है","3 सेकंड, अपने वाहन की लंबाई के प्रत्येक 10 फीट के लिए 1 सेकंड देते हुए","4 सेकंड, क्योंकि लंबाई-आधारित गणना में आपको हमेशा 1 अतिरिक्त सेकंड जोड़ना चाहिए","6 सेकंड, पूरी तरह रुकने में लगने वाले लगभग 6 सेकंड के बराबर"],"explanation":"प्रत्येक 10 फुट लंबाई के लिए 1 सेकंड रखें, इसलिए 30-फुट वाहन को 3 सेकंड चाहिए, और 40 मील/घंटा से कम होने के कारण कोई अतिरिक्त सेकंड नहीं जोड़ा जाता।"},"116":{"q":"आप एक सूखे इंटरस्टेट हाईवे पर 70 फुट लंबा संयोजन वाहन चला रहे हैं और हल्के ट्रैफिक में स्थिर 50 मील प्रति घंटे की गति बनाए हुए हैं। आपके आगे के अंतराल में एक छोटी कार बार-बार घुसती और निकलती रहती है, और जैसे ही लेन खाली हो, आप एक सुरक्षित अनुसरण दूरी फिर से स्थापित करना चाहते हैं। अपने वाहन की लंबाई और गति के लिए सेकंड के नियम के आधार पर, आपको कितने सेकंड की अनुसरण दूरी फिर से स्थापित करनी चाहिए?","options":["7 सेकंड, क्योंकि 70 फुट के वाहन को हर 10 फुट लंबाई के लिए 1 सेकंड चाहिए","6 सेकंड, क्योंकि हाईवे गति पर यही अनुशंसित कुल रुकने की दूरी का अंतराल है","8 सेकंड, क्योंकि लंबाई के लिए 7 सेकंड चाहिए और 40 मील प्रति घंटे से ऊपर होने के कारण आप 1 सेकंड और जोड़ते हैं","9 सेकंड, क्योंकि इतने लंबे वाहन के लिए 40 मील प्रति घंटे से ऊपर आपको 2 सेकंड जोड़ने चाहिए"],"explanation":"40 मील/घंटा से कम पर वाहन की लंबाई के हर 10 फुट के लिए 1 सेकंड और 40 मील/घंटा से ऊपर 1 सेकंड जोड़ें, इसलिए 50 मील/घंटा पर 70 फुट के ट्रक को 8 सेकंड चाहिए।"},"117":{"q":"आप शहर के बीचोंबीच एक व्यावसायिक क्षेत्र से होकर 20 फुट लंबा सीधा (सिंगल) ट्रक चला रहे हैं। यातायात एकसमान है, निर्धारित गति 25 मील प्रति घंटा है, सड़क सूखी है और दृश्यता अच्छी है। आगे सुरक्षित दूरी बनाए रखने के लिए, आगे चल रहे वाहन के पीछे आपको कम से कम कितनी अनुसरण दूरी (फॉलोइंग डिस्टेंस) रखनी चाहिए?","options":["1 सेकंड, क्योंकि ट्रक केवल 20 फुट लंबा है","4 सेकंड, आधार में 1 सेकंड और शहरी यातायात के लिए 1 सेकंड और जोड़कर","3 सेकंड, क्योंकि आधार मान के ऊपर आपको हमेशा 1 सेकंड जोड़ना चाहिए","2 सेकंड, वाहन की लंबाई के प्रत्येक 10 फुट के लिए एक सेकंड"],"explanation":"40 मील/घंटा से कम पर अनुसरण दूरी वाहन की लंबाई के हर 10 फुट के लिए 1 सेकंड है, इसलिए 20 फुट के वाहन को 2 सेकंड चाहिए।"},"118":{"q":"आप एक सूखे इंटरस्टेट हाइवे पर 80 फुट लंबा संयोजन वाहन चला रहे हैं, हल्के यातायात में लगातार 60 मील प्रति घंटा की गति बनाए हुए हैं। एक सहकर्मी कहता है कि बस 'हर दस फुट के लिए एक सेकंड' छोड़दें और किसी भी गति पर आप ठीक रहेंगे। अपनी लंबाई और गति के लिए सही Texas DPS पालन दूरी विधि का उपयोग करते हुए, आगे चल रहे वाहन के पीछे आपको कम से कम कितनी पालन दूरी रखनी चाहिए?","options":["9 सेकंड — 80 फुट लंबाई के लिए 8 सेकंड, और 40 मील प्रति घंटा से अधिक गति पर चलने के कारण 1 अतिरिक्त सेकंड","8 सेकंड — आपके 80 फुट वाहन के हर 10 फुट के लिए 1 सेकंड, गति के लिए कोई समायोजन नहीं","10 सेकंड — लंबाई के लिए 8 सेकंड, और 40 मील प्रति घंटा की सीमा से 20 मील प्रति घंटा अधिक होने के कारण 2 सेकंड","7 सेकंड — हर 10 फुट के लिए 1 सेकंड, फिर 1 सेकंड घटाएं क्योंकि सूखी सड़क अच्छी पकड़ देती है"],"explanation":"40 मील/घंटा से कम पर लंबाई के हर 10 फुट के लिए 1 सेकंड दें और 40 मील/घंटा से ऊपर 1 सेकंड और जोड़ें, इसलिए 60 मील/घंटा पर 80 फुट के वाहन को 9 सेकंड चाहिए।"},"119":{"q":"आप एक सूखे, समतल अंतरराज्यीय राजमार्ग पर 50 फुट लंबा ट्रैक्टर-ट्रेलर चला रहे हैं और हल्के ट्रैफ़िक में आपका स्पीडोमीटर लगातार 45 मील प्रति घंटा दिखा रहा है। आपके आगे एक छोटी कार बार-बार ब्रेक दबा रही है, इसलिए आप सेकंड के नियम का उपयोग करके सुरक्षित अनुसरण दूरी रखना चाहते हैं। उस वाहन के पीछे आपको कितने सेकंड का अंतराल रखना चाहिए?","options":["5 सेकंड, क्योंकि आपका वाहन 50 फुट लंबा है और इससे हर 10 फुट के लिए 1 सेकंड मिलता है","6 सेकंड, क्योंकि 50 फुट से आपको 5 सेकंड मिलते हैं और 40 मील प्रति घंटा से अधिक होने पर आप 1 सेकंड और जोड़ते हैं","7 सेकंड, अंतरराज्यीय राजमार्ग पर होने के कारण लंबाई-आधारित आंकड़े में 2 अतिरिक्त सेकंड जोड़ते हुए","4 सेकंड, क्योंकि 45 मील प्रति घंटा 40 से थोड़ा ही अधिक है और सूखी सड़क पर कम अंतराल भी ठीक है"],"explanation":"40 मील/घंटा से कम पर लंबाई के हर 10 फुट के लिए 1 सेकंड लें और 40 मील/घंटा से ऊपर 1 सेकंड जोड़ें, इसलिए 45 मील/घंटा पर 50 फुट के वाहन को 6 सेकंड चाहिए।"},"120":{"q":"आप शहर से होकर 60 फुट लंबा ट्रैक्टर-ट्रेलर चला रहे हैं और एक धीमी डिलीवरी ट्रक के पीछे आ जाते हैं। सूखी सड़क पर आपका स्पीडोमीटर लगातार 35 मील प्रति घंटा दिखा रहा है। इस गति पर अपने वाहन के लिए सुरक्षित अनुसरण दूरी बनाए रखने हेतु आपको अपने और आगे चल रहे वाहन के बीच कितने सेकंड का अंतर रखना चाहिए?","options":["5 सेकंड, क्योंकि अच्छी परिस्थितियों में सूखी सड़क पर एक सेकंड घटा दिया जाता है","8 सेकंड: प्रत्येक 10 फुट के लिए एक सेकंड और ट्रेलर के लिए दो अतिरिक्त सेकंड","6 सेकंड: वाहन की लंबाई के प्रत्येक 10 फुट के लिए एक सेकंड","7 सेकंड: प्रत्येक 10 फुट के लिए एक सेकंड और चलने के कारण एक अतिरिक्त सेकंड"],"explanation":"40 मील/घंटा से कम पर अनुसरण दूरी लंबाई के हर 10 फुट के लिए 1 सेकंड है, बिना अतिरिक्त सेकंड जोड़े, इसलिए 35 मील/घंटा पर 60 फुट के वाहन को 6 सेकंड चाहिए।"},"121":{"q":"आप दो-लेन राजमार्ग पर आंशिक भार ढोकर चला रहे हैं, तभी हल्की जमादेने वाली बूंदाबांदी शुरू होती है और सड़क की सतह चमकीली दिखने लगती है। अगले एक मील में आप तीन काम करते हैं: दृश्यता और पकड़ कम होने के बावजूद आप अपनी रफ़्तार स्थिर रखते हैं, एक हिरन अचानक सामने आ जाने पर आप ज़ोर से ब्रेक दबाते हैं, और कुछ ही पल बाद एक हल्की चढ़ाई पर रफ़्तार पाने के लिए आप ज़ोर से एक्सेलेटर दबाते हैं। एक सहकर्मी बाद में तर्क देता है कि इनमें से केवल एक काम ही वास्तव में आपको स्किड (फिसलन) में डाल सकता था। कौन-सा कथन सही है?","options":["केवल ज़ोर से घबराहट में लगाया गया ब्रेक ही स्किड का कारण बन सकता था, क्योंकि पहियों को लॉक करना ही पकड़ खोने का एकमात्र तरीका है।","केवल बर्फीली परिस्थितियों के लिए बहुत तेज़ चलाना ही स्किड का कारण बन सकता था, क्योंकि अधिकांश स्किड अत्यधिक गति से होते हैं।","तीनों काम — परिस्थितियों के लिए अत्यधिक गति, ज़ोर से घबराहट में ब्रेक और ज़ोर से एक्सेलेशन — अलग-अलग रूप से स्किड का कारण बन सकते थे।","केवल ज़ोर से एक्सेलेशन ही स्किड का कारण बन सकता था, क्योंकि आंशिक (हल्का) भार ड्राइव पहियों पर पकड़ के लिए बहुत कम वज़न डालता है।"],"explanation":"स्किड तब होती है जब टायर पकड़ खो देते हैं, और परिस्थितियों के लिए अधिक गति, बहुत जोर से ब्रेक लगाना या बहुत तेज त्वरण इनमें से प्रत्येक अकेले इसका कारण बन सकता है।"},"122":{"q":"आप एक ग्रामीण दो-लेन राजमार्ग पर एक लदा हुआ ट्रेलर खींच रहे हैं। अभी हल्की बारिश शुरू हुई है और सड़क की सतह गीली होकर चमक रही है; आगे एक तीखे मोड़ का संकेत दिख रहा है, और मोड़ के आगे गड्ढे में नीचे कोहरे की एक परत जम रही है, जिससे आप सड़क पर दूर तक नहीं देख सकते। एक सहकर्मी ने आपको एक बार बताया था कि आपको एक समय में केवल सबसे गंभीर एकल खतरे के लिए ही गति कम करनी चाहिए। इस स्थिति में सुरक्षित CDL अभ्यास को सबसे अच्छी तरह कौन सा कार्य दर्शाता है?","options":["गीले हिस्से में अपनी राजमार्ग गति बनाए रखें और केवल तभी धीमे हों जब आप वास्तव में मोड़ तक पहुँच जाएँ, क्योंकि मोड़ सबसे गंभीर एकल खतरा है","अपनी गति स्थिर रखें क्योंकि जब कई छोटे खतरे एक साथ आते हैं तो आपकी रक्षा आपकी गति नहीं बल्कि पीछा करने की दूरी करती है","केवल गड्ढे के कोहरे के लिए धीमे हों, क्योंकि कम दृश्यता ही एकमात्र ऐसी स्थिति है जो कानूनी रूप से कम गति की माँग करती है","तीनों स्थितियों के लिए एक साथ अपनी गति कम करें, क्योंकि गीली सतह, मोड़ और सीमित दृश्यता प्रत्येक स्वतंत्र रूप से कम गति की माँग करते हैं"],"explanation":"गीली सड़क, मोड़ और सीमित दृश्यता प्रत्येक अपने आप सुरक्षित गति को कम करते हैं, इसलिए इन सभी के लिए गति कम करें और जब ये एक साथ हों तो और भी अधिक।"},"123":{"q":"सुबह के 6:00 बजे हैं और आप एक लंबी अंतरराज्यीय यात्रा से पहले ट्रैक्टर-ट्रेलर की प्री-ट्रिप जांच कर रहे हैं। बाद में यदि आप शोल्डर (किनारे) पर खराब हो जाएं, इसके लिए यह पुष्टि करने हेतु कि आपातकालीन उपकरण पूरी तरह से भरा हुआ है, आप सीट के पीछे रखे आपातकालीन उपकरण बॉक्स को खोलते हैं। वस्तुओं का कौन सा समूह उस संपूर्ण आपातकालीन उपकरण को दर्शाता है जिसे ले जाना आपके लिए अनिवार्य है?","options":["तीन परावर्तक चेतावनी त्रिकोण, अतिरिक्त विद्युत फ्यूज़ (जब तक कि वाहन में सर्किट ब्रेकर न लगे हों), और एक उचित रूप से चार्ज किया हुआ और सही श्रेणी का अग्निशामक यंत्र","तीन परावर्तक चेतावनी त्रिकोण और एक उचित रूप से चार्ज किया हुआ और सही श्रेणी का अग्निशामक यंत्र, लेकिन अतिरिक्त फ्यूज़ वैकल्पिक हैं","एक उचित रूप से चार्ज किया हुआ और सही श्रेणी का अग्निशामक यंत्र और अतिरिक्त विद्युत फ्यूज़, साथ ही सर्दियों के मार्गों के लिए टायर चेन का एक सेट","तीन परावर्तक चेतावनी त्रिकोण, एक प्राथमिक चिकित्सा किट, और एक उचित रूप से चार्ज किया हुआ और सही श्रेणी का अग्निशामक यंत्र"],"explanation":"आवश्यक आपातकालीन उपकरण हैं तीन परावर्तक चेतावनी त्रिकोण, सर्किट ब्रेकर न होने पर अतिरिक्त फ्यूज, और उचित रूप से चार्ज व रेटेड अग्निशामक यंत्र।"},"124":{"q":"एक विभाजित राजमार्ग पर जहाँ 65 mph की गति सीमा अंकित है, आप अपने समय-कार्यक्रम से 30 मिनट पीछे चल रहे हैं। सभी लेन में यातायात लगभग 72 mph की गति से बह रहा है, सड़क सूखी है, और आगे की सड़क एक चौथाई मील तक साफ और खाली है। टेक्सास DPS नियमों के अनुसार, इनमें से कौन-सी स्थिति आपके लिए अंकित 65 mph सीमा से तेज़ चलाना स्वीकार्य बनाएगी?","options":["जब आसपास के यातायात का सामान्य प्रवाह सीमा से ऊपर चल रहा हो, और आप खतरा न बनने के लिए उसी रफ़्तार में बने रहें","जब आप समय से पीछे हों और सूखी, साफ सड़क आपको खोया हुआ समय सुरक्षित रूप से पूरा करने दे","इनमें से कोई भी स्थिति अंकित सीमा से अधिक चलाने को उचित नहीं ठहराती","जब आगे की सड़क एक चौथाई मील तक खाली हो, जिससे आपको पूरी रुकने की दूरी मिल जाती है"],"explanation":"लगाई गई गति सीमा आदर्श परिस्थितियों के लिए अधिकतम कानूनी गति है और यातायात, समय या खुली सड़क चाहे जो भी हो, इसे कभी पार नहीं किया जा सकता।"},"125":{"q":"आप 60 मील प्रति घंटे वाले क्षेत्र में 40 मील प्रति घंटे की रफ्तार से चल रहे एक धीमे खेती के ट्रक के पीछे दो-लेन वाले राजमार्ग पर एक लदा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं। आप इससे आगे निकलने के लिए बेचैन हैं और आगे चार अवसर देखते हैं। ओवरटेक पूरा करने के लिए वास्तव में कौन-सी जगह सुरक्षित है?","options":["आगे आने वाले लंबे, हल्के मोड़ पर, जहाँ आप मोड़ के पार आंशिक रूप से देख सकते हैं","पहाड़ी की चोटी से ठीक पहले, जब आपके पास अभी भी आगे का कुछ दृश्य है","इनमें से कोई भी जगह सुरक्षित रूप से ओवरटेक करने के लिए पर्याप्त दृश्यता दूरी नहीं देती","आने वाले ग्रामीण चौराहे से होकर, क्योंकि आड़ी-तिरछी यातायात को राजमार्ग को रास्ता देना ही पड़ता है"],"explanation":"दो-लेन सड़क पर सुरक्षित ओवरटेक के लिए आगे पर्याप्त दृश्यता दूरी चाहिए, जिसे मोड़, पहाड़ी की चोटी और चौराहे रोक देते हैं।"},"126":{"q":"एक सख्त डिलीवरी में आप समय-सारणी से 40 मिनट पीछे चल रहे हैं। जब आपने कल इसी ट्रैक्टर-ट्रेलर को चलाया था तब यह पूरी प्री-ट्रिप जाँच में पास हुआ था, मौसम साफ और सूखा है, और एक त्वरित निरीक्षण में कोई स्पष्ट खराबी नहीं दिखती। इनमें से किस परिस्थिति में आपको चलाने से पहले आज की प्री-ट्रिप जाँच को छोड़ने की कानूनी और सुरक्षित अनुमति है?","options":["जब आप समय-सारणी से पीछे हों और देरी से डिलीवरी लेट होने का खतरा हो","जब वाहन पिछले दिन जाँच में पास हुआ हो और तब से कोई समस्या दर्ज न हुई हो","इनमें से कोई भी परिस्थिति प्री-ट्रिप जाँच छोड़ने को उचित नहीं ठहराती","जब एक संक्षिप्त निरीक्षण में कोई दृश्य खराबी न दिखे और स्थितियाँ अच्छी हों"],"explanation":"हर यात्रा से पहले बिना किसी अपवाद के प्री-ट्रिप निरीक्षण आवश्यक है, क्योंकि वाहन की स्थिति किसी भी समय बदल सकती है।"},"127":{"q":"अभी-अभी अंधेरा हुआ है और आप एक सँकरी, बिना रोशनी वाली दो-लेन की ग्रामीण सड़क पर लदा हुआ ट्रेलर खींचते हुए चल रहे हैं। सामने से आती एक कार लगभग 400 फुट आगे एक चढ़ाई पर आती है और उसकी हाई बीम सीधे आपकी आँखों में पड़ती है, जिससे आपके बोनट के सामने सब कुछ धुँधला हो जाता है। दोनों गाड़ियों के मिलने में बस कुछ ही सेकंड बचे हैं। जब तक वह वाहन गुज़र न जाए, अपने रिग को नियंत्रण में रखने का सबसे सुरक्षित तरीका कौन-सा है?","options":["अपनी हेडलाइट्स को हाई बीम पर कर दें ताकि उनकी अधिक पहुँच से आप दूसरे चालक की चकाचौंध के पार सड़क देख सकें।","अपनी नज़र अपनी लेन के दाहिने किनारे की ओर नीचे कर लें और सामने से आती कार के गुज़र जाने तक गति धीमी कर दें।","अपनी हाई बीम को कुछ बार तेज़ी से चमकाएँ ताकि दूसरा चालक समस्या समझकर अपनी लाइट कम कर ले।","अपनी नज़र ठीक सामने की केंद्र रेखा पर टिकाएँ और गति स्थिर रखें ताकि कार के गुज़रने से पहले आप न भटकें।"],"explanation":"सामने से आती तेज़ हेडलाइट से चकाचौंध होने पर, मार्गदर्शक के रूप में अपनी लेन के दाएं किनारे की ओर देखें और वाहन गुजरने तक गति धीमी करें।"},"131":{"q":"आप एक इंटरस्टेट हाईवे पर लगभग 55 मील प्रति घंटे की रफ्तार से चल रहे हैं, तभी अचानक तेज़ बारिश सड़क की सतह पर खड़े पानी की एक परत छोड़ देती है। स्टीयरिंग व्हील अचानक आपके हाथों में हल्का और ढीला महसूस होता है, और आपको एहसास होता है कि ट्रैक्टर के अगले टायरों का सड़क से मज़बूत संपर्क टूट गया है और वे पानी के ऊपर तैर रहे हैं (हाइड्रोप्लेनिंग)। कौन सी प्रतिक्रिया आपको सुरक्षित रूप से पकड़ (ट्रैक्शन) वापस पाने का सबसे अच्छा मौका देती है?","options":["मज़बूत, स्थिर ब्रेक दबाव लगाएँ और अगले टायरों को वापस सड़क पर ज़बरदस्ती लाने के लिए तेज़ी से किनारे (शोल्डर) की ओर स्टीयरिंग घुमाएँ।","अपनी गति बनाए रखें लेकिन ब्रेक को तेज़ी से पंप करें ताकि टायर बिना लॉक हुए पानी की परत को भेद सकें।","एक्सेलेरेटर छोड़ दें, स्टीयरिंग व्हील को सीधा रखें, और ट्रक को धीरे-धीरे गति कम करने दें जब तक टायर फिर से पकड़ न पा लें।","एक्सेलेरेटर को और ज़ोर से दबाएँ और ड्राइव पहियों को घूमता रखें ताकि टायरों के नीचे से खड़ा पानी बाहर निकल जाए।"],"explanation":"हाइड्रोप्लेन में टायर पकड़ खो देते हैं, इसलिए एक्सेलेरेटर छोड़ें, स्टीयरिंग सीधा रखें, और पकड़ वापस आने तक ट्रक को धीमा होने दें।"},"133":{"q":"आप चार-लेन वाले विभाजित राजमार्ग की दाहिनी लेन में एक लदा हुआ ट्रेलर चला रहे हैं और निर्धारित 60 मील प्रति घंटे की सीमा पर जा रहे हैं। एक पिकअप ट्रक आपके पीछे बिल्कुल सट गया है, आपके बंपर से केवल कुछ फीट की दूरी पर चल रहा है, बार-बार अपनी हाई बीम जला-बुझा रहा है और ओवरटेक करने की ताक में इधर-उधर घूम रहा है। आपकी बाईं ओर एक खाली लेन है और आगे लगातार यातायात है। सबसे सुरक्षित और कानूनी रूप से सही प्रतिक्रिया कौन सी है?","options":["ब्रेक को कुछ बार हल्के से दबाएं ताकि ब्रेक लाइटें जलें और पीछे वाले चालक को संकेत मिले कि उसे पीछे हटकर जगह देनी चाहिए।","अपनी मौजूदा गति और लेन की स्थिति बनाए रखें ताकि आक्रामक चालक आपको अपना काम बदलने के लिए मजबूर न कर सके।","लगभग 70 मील प्रति घंटे तक गति बढ़ाकर पीछे सटे चालक से दूरी बना लें, क्योंकि आक्रामक चालक से आगे निकल जाना टकराव को खत्म कर देता है।","एक्सेलेरेटर से पैर हटाकर अपने आगे की दूरी बढ़ाएं, फिर सिग्नल देकर बाईं लेन खाली हो तो उसमें चले जाएं ताकि वह चालक आगे निकल सके।"],"explanation":"पीछे से बहुत पास चल रहे आक्रामक चालक के साथ, आगे जगह बनाने के लिए एक्सेलेरेटर छोड़ें, फिर संकेत देकर लेन बदलें ताकि वह सुरक्षित रूप से आगे निकल सके।"},"134":{"q":"आप एक भरे हुए ट्रेलर को इंटरस्टेट पर खींच रहे हैं, तभी आपको जलते रबर की तीखी गंध आती है और दाहिने शीशे में अपने यूनिट के पिछले हिस्से से धुंआ निकलता दिखता है। यातायात मध्यम है और कुछ सौ फीट आगे एक चौड़ा पक्का किनारा (शोल्डर) है। सबसे अच्छा कदम क्या है?","options":["पहले से संकेत (सिग्नल) दें, बाकी यातायात से दूर पूरी तरह शोल्डर पर रोकें, इंजन बंद करें, और स्थिति बिगड़ने से पहले धुएं के स्रोत की जांच करें।","गति बनाए रखें और अगले निकास (एग्ज़िट) तक चलते रहें, क्योंकि हाईवे गति पर हवा का बहाव शायद उस हिस्से को ठंडा कर देगा और धुंआ अपने आप साफ हो जाएगा।","शोल्डर पर रुकें लेकिन इंजन चालू रखें, फिर फंसे हुए धुएं और गर्मी को बाहर निकालने के लिए तुरंत ट्रेलर के पिछले दरवाजे खोल दें।","गति धीमी करें और शोल्डर पर कम गति से चलते रहें जबकि एक सवारी बिना पूरी तरह रुके पिछले टायरों पर पानी डालकर उन्हें ठंडा करे।"],"explanation":"धुआं या जलने की गंध शुरू होती आग का संकेत हो सकती है, इसलिए यातायात से दूर पूरी तरह सड़क के किनारे रुकें, इंजन बंद करें और बिगड़ने से पहले स्रोत की जांच करें।"},"135":{"q":"आप एक ग्रामीण दो-लेन राजमार्ग पर लदा हुआ ट्रेलर चला रहे हैं, तभी आप इतने घने कोहरे के झुंड में प्रवेश करते हैं कि थोड़ी ही दूरी पर लेन की रेखाएँ भी मुश्किल से दिखाई देती हैं। यातायात कम है। इस हिस्से को संभालने का सबसे सुरक्षित और सही तरीका कौन सा है?","options":["हाई बीम पर स्विच करें ताकि तेज़ रोशनी कोहरे को चीरकर निकले और आप लेन की रेखाएँ जल्दी देख सकें।","अपनी गति कम करें, लो बीम चालू रखें, और यदि फिर भी पर्याप्त रूप से नहीं देख पाते, तो पूरी तरह सड़क से हटकर रुकें और कोहरा छँटने तक प्रतीक्षा करें।","अपनी सामान्य राजमार्ग गति बनाए रखें, परंतु आगे वाले वाहन की पिछली बत्तियों पर ध्यान केंद्रित करें और कोहरे में उन्हीं को मार्गदर्शक मानकर उनका अनुसरण करें।","अपने लदे हुए वाहन की सुरक्षित अनुमति के अनुसार जितनी तेज़ी से हो सके, कोहरे वाले हिस्से को पार करने के लिए गति बढ़ाएँ, फिर अपनी सामान्य गति पर लौट आएँ।"],"explanation":"कोहरे में गति कम करें और लो बीम का उपयोग करें क्योंकि हाई बीम पानी की बूंदों से परावर्तित होकर चकाचौंध बढ़ाती है, और यदि फिर भी न दिखे तो पूरी तरह सड़क से हट जाएं।"},"136":{"q":"आपकी शिफ्ट का अंत है और आपको एक ऐसे यार्ड में, जहाँ आप पहले कभी नहीं गए, अपने 53 फुट के ट्रेलर को एक तंग लोडिंग डॉक में पीछे की ओर ले जाना है। कोई गाइड करने वाला मौजूद नहीं है, डॉक इस समय खाली है, और आप जल्दी काम खत्म करना चाहते हैं। सबसे सुरक्षित और सही कदम कौन सा है?","options":["चूँकि आपके पीछे का क्षेत्र अभी खाली है, फोर्कलिफ्ट या कर्मचारी आने से पहले काम खत्म करने के लिए एक समान गति से तुरंत पीछे ले जाएँ।","पास से गुजरते किसी कर्मचारी को रोककर उसे ट्रेलर के ठीक पीछे खड़ा करें ताकि वह आपको देखता रहे और पीछे करते समय इशारे से मार्गदर्शन करे।","केबिन से उतरकर ट्रेलर के पीछे के पूरे रास्ते पर चलकर बाधाओं और जगह की जाँच करें, फिर दोनों तरफ के शीशों का उपयोग करते हुए धीरे-धीरे पीछे ले जाएँ।","केवल अपने शीशों पर भरोसा करें और बिना उतरे एक समान गति से पीछे ले जाएँ, क्योंकि रुककर देखने से केवल देर होगी।"],"explanation":"बिना सहायक के, उतरकर-देखो विधि अपनाएं: ट्रेलर के पीछे के पूरे रास्ते पर चलकर बाधाएं और जगह जांचें, फिर दोनों दर्पणों का उपयोग करते हुए धीरे-धीरे पीछे करें।"},"137":{"q":"आप 55 मील प्रति घंटा की रफ्तार से एक सूखे अंतरराज्यीय राजमार्ग पर एक लदी हुई ट्रेलर खींच रहे हैं, तभी दूर सामने आपकी लेन में अचानक एक खराब कार दिखाई देती है। आपका प्रशिक्षक बाद में आपसे उस पूरी दूरी के हर एक भाग का हिसाब मांगता है जो आपके ट्रक ने उस क्षण से तय की जब खतरा नज़र में आया, जब तक कि आप पूरी तरह रुक नहीं गए। कौन सा विभाजन उन तीन अलग-अलग भागों को सही ढंग से पहचानता है जो मिलकर आपकी कुल रुकने की दूरी बनाते हैं?","options":["आपकी 3/4 सेकंड की प्रतिक्रिया के दौरान तय की गई दूरी प्लस ब्रेक पकड़ने के बाद की ब्रेकिंग दूरी — प्रत्यक्षण (देखने) का समय पहले से ही प्रतिक्रिया समय में शामिल है, इसलिए इसे अलग से नहीं गिना जाता","केवल ब्रेकिंग दूरी, क्योंकि यही वह भाग है जहां ट्रक भौतिक रूप से धीमा हो रहा होता है और यही एकमात्र हिस्सा है जिसे आप नियंत्रित कर सकते हैं","पीछा करने की दूरी, संकेत देने की दूरी और फुटपाथ के किनारे छोड़ी गई पार्किंग की जगह","प्रत्यक्षण दूरी (देखने की), प्रतिक्रिया दूरी और ब्रेकिंग दूरी"],"explanation":"कुल रुकने की दूरी तीन भागों का योग है: अनुभव दूरी, प्रतिक्रिया दूरी और ब्रेकिंग दूरी।"},"138":{"q":"लंबी यात्रा के दौरान आप दोपहर के भोजन के लिए रुके और एक मित्र आपको भोजन के साथ एक बीयर देता है। इसके बाद आप पूरी तरह से होश में महसूस करते हैं और सीधी रेखा में चलने में आपको कोई परेशानी नहीं होती। अपने ट्रैक्टर-ट्रेलर में दोबारा बैठने से पहले, अपने वाणिज्यिक वाहन को चलाने के लिए रक्त में अल्कोहल सांद्रता (BAC) की कानूनी सीमा के बारे में कौन सा कथन सही है?","options":["0.04 प्रतिशत BAC पर आप कानूनी रूप से सीमा से अधिक हैं और वाणिज्यिक वाहन नहीं चला सकते; यह एक सामान्य यात्री कार पर लागू होने वाली सीमा का आधा है।","0.08 प्रतिशत BAC पर आप कानूनी रूप से सीमा से अधिक हैं और वाणिज्यिक वाहन नहीं चला सकते; यह वही सीमा है जो एक सामान्य यात्री कार पर लागू होती है।","जब तक आपका BAC 0.10 प्रतिशत से नीचे रहता है तब तक आप चला सकते हैं, क्योंकि बड़े वाहनों के लिए एक उच्च सीमा लागू होती है।","मायने यह रखता है कि आप होश में महसूस करें, इसलिए जैसे ही आपको नशा महसूस होना बंद हो जाए आप चला सकते हैं, चाहे कोई भी विशिष्ट BAC संख्या हो।"],"explanation":"वाणिज्यिक वाहन चलाने के लिए कानूनी रक्त-अल्कोहल सीमा 0.04 प्रतिशत है, जो यात्री कार की 0.08 प्रतिशत सीमा से ठीक आधी है, इसलिए 0.04 पर आप सीमा से अधिक हैं।"},"139":{"q":"आपने स्लीपर बर्थ में लगातार 10 घंटे ड्यूटी से बाहर पूरे किए हैं और एक नई शिफ्ट शुरू कर रहे हैं। आपका डिस्पैचर कहता है कि यात्रा लंबी है और पूछता है कि संघीय सेवा-घंटे (HOS) नियम आपको उस दिन के लिए गाड़ी चलाना बंद करने के लिए बाध्य करने से पहले आप कानूनी रूप से कितने वास्तविक घंटे गाड़ी चला सकते हैं। इसे शुद्ध ड्राइविंग मानते हुए (ऐसी कोई अत्यधिक ऑन-ड्यूटी देरी नहीं जो आपकी 14-घंटे की खिड़की जल्दी बंद कर दे), अनुमत अधिकतम ड्राइविंग समय क्या है?","options":["8 घंटे तक की ड्राइविंग, क्योंकि आपको पहले 30 मिनट का ब्रेक लेना होगा","11 घंटे तक का ड्राइविंग समय","14 घंटे तक का ड्राइविंग समय","16 घंटे तक का ड्राइविंग समय"],"explanation":"लगातार 10 घंटे ड्यूटी से बाहर रहने के बाद, संघीय सेवा-घंटे नियम अधिकतम 11 घंटे ड्राइविंग समय की अनुमति देते हैं।"},"140":{"q":"आप भोर से बहुत पहले से गाड़ी चला रहे हैं और अब दोपहर बीत चुकी है। आप खुद को लेन में बहकते हुए पाते हैं, आपकी पलकें भारी हो रही हैं, और आपको पिछले कुछ मील याद नहीं हैं। आपके मार्ग में अभी कई घंटे बाकी हैं और एक डिलीवरी का समय भी पूरा करना है। निम्नलिखित में से कौन सा एकमात्र ऐसा कदम है जो वास्तव में आपकी सतर्कता वापस लाएगा और इस स्थिति को सुरक्षित रूप से ठीक करेगा?","options":["अगले सर्विस स्टेशन पर रुकें, दो कप कड़क कॉफ़ी पिएं, और समय पर पहुंचने के लिए आगे बढ़ते रहें","ठंडी ताज़ी हवा के लिए खिड़कियां खोल लें और दिमाग को सक्रिय रखने के लिए रेडियो की आवाज़ तेज़ कर दें","जैसे ही सुरक्षित हो, सड़क से हट जाएं, गाड़ी चलाना बंद करें, और आगे बढ़ने से पहले पर्याप्त असली नींद लें","एक एनर्जी ड्रिंक खोलें, भारी भोजन करें, और भरपाई के लिए अपनी पीछा करने की दूरी बढ़ा दें"],"explanation":"नींद के कर्ज को केवल वास्तविक, पर्याप्त नींद ही चुकाती है, इसलिए थकान होने पर सुरक्षित रूप से सड़क से हटें, गाड़ी चलाना बंद करें और जारी रखने से पहले सोएं।"},"141":{"q":"आप साफ, सूखे मौसम में एक समतल, खुले ग्रामीण राजमार्ग पर 55 मील प्रति घंटे की गति से लदे हुए चल रहे हैं। यातायात हल्का है और आगे की सड़क का आपको लंबा, निर्बाध दृश्य दिखाई दे रहा है। अपने दृश्य अग्रिम समय को सही ढंग से प्रबंधित करने के लिए, खतरों को भांपने के लिए आपको कितनी दूर आगे लगातार देखते और स्कैन करते रहना चाहिए?","options":["केवल अपने ठीक आगे वाले वाहन पर, क्योंकि 55 मील प्रति घंटे पर उससे दूर की कोई भी चीज़ अभी खतरा नहीं है","लगभग 30 से 40 सेकंड आगे, ताकि खुले राजमार्ग पर आपको अधिकतम संभव प्रतिक्रिया समय मिले","लगभग 1 से 2 सेकंड आगे, जो इस गति पर मोटे तौर पर आपकी सुरक्षित अनुसरण दूरी है","लगभग 12 से 15 सेकंड आगे, जो 55 मील प्रति घंटे पर लगभग एक-चौथाई मील या शहर में लगभग एक सिटी ब्लॉक के बराबर है"],"explanation":"अपनी नजरें घुमाते रहें और 12 से 15 सेकंड आगे देखें, जो हाईवे गति पर लगभग एक चौथाई मील या शहर में एक ब्लॉक होता है, ताकि खतरों को जल्दी पहचान सकें।"},"142":{"q":"आप एक लदे हुए ट्रेलर को टेक्सास के व्यस्त चार-लेन इंटरस्टेट हाईवे पर हाईवे की गति से चला रहे हैं। यातायात घना है और वाहन लगातार आपके ब्लाइंड स्पॉट में आ रहे हैं और आपके आसपास लेन बदल रहे हैं। अपने ट्रक के पीछे और बगल में क्या हो रहा है, इसकी सटीक और ताज़ा तस्वीर बनाए रखने के लिए आपको अपने शीशों (मिरर) का उपयोग कैसे करना चाहिए?","options":["शीशों में केवल लेन बदलने या मर्ज करने से ठीक पहले देखें, क्योंकि तभी ब्लाइंड स्पॉट का यातायात सबसे अधिक मायने रखता है","अपने शीशों को लगभग हर 12 से 15 सेकंड में जाँचें, जितनी दूर आप सड़क पर आगे देखते हैं उसी के अनुसार","अपने शीशों को लगातार और स्थिर रूप से देखते रहें ताकि आपकी नज़र कभी आगे की सड़क पर वापस न जाए","किसी भी लेन बदलने से पहले की जाँच के अलावा, अपने शीशों को नियमित रूप से, लगभग हर 5 से 8 सेकंड में देखते रहें"],"explanation":"हर लेन बदलने से पहले देखने के अलावा, हर 5 से 8 सेकंड में नियमित रूप से शीशे देखें ताकि यातायात और ब्लाइंड स्पॉट पर नजर बनी रहे।"},"143":{"q":"एक नम, धुंधली दोपहर है और आपको अपने ट्रैक्टर-ट्रेलर को एक तंग गली के लोडिंग डॉक में पीछे की ओर ले जाना है। दृश्यता खराब है, ट्रेलर का दायाँ हिस्सा छाया में गायब हो रहा है, और आपकी मदद के लिए कोई संकेतक (स्पॉटर) मौजूद नहीं है। इस युद्धाभ्यास को यथासंभव सुरक्षित बनाने के लिए, आपको किस ओर की तरफ पीछे ले जाना चाहिए?","options":["दाहिनी (अंधी) ओर, क्योंकि ट्रेलर को अपने से दूर घुमाने से ट्रैक्टर को मुड़ने के लिए अधिक जगह मिलती है","सबसे अधिक यातायात वाली ओर, ताकि अन्य चालक आपको देखें और ट्रेलर के लिए रुक जाएँ","जिस ओर डॉक सबसे नज़दीक हो, ताकि पीछे की ओर तय की जाने वाली दूरी कम हो जाए","चालक की (बाईं) ओर, ताकि आप अपनी खिड़की से ट्रेलर की पूरी लंबाई पर नज़र रख सकें"],"explanation":"चालक (बाएं) ओर पीछे लेने से आप अपनी खिड़की से ट्रेलर की पूरी लंबाई देख सकते हैं, जिससे उसका पिछला भाग और रास्ता हर समय नजर में रहता है।"},"144":{"q":"अपनी प्री-ट्रिप जाँच के दौरान आप एक फ्लैटबेड पर 38 फुट लंबे एक स्टील बीम को बाँध रहे हैं। आप उतने ही न्यूनतम टाई-डाउन (बंधन) इस्तेमाल करना चाहते हैं जो लंबाई-आधारित सुरक्षा के संघीय न्यूनतम मानक को पूरा करें (कार्यभार सीमा यानी WLL पहले से पूरी है)। इस भार के लिए नियम कम से कम कितने टाई-डाउन की अनुमति देता है?","options":["2 टाई-डाउन, क्योंकि 5 फुट से लंबे किसी भी टुकड़े को हमेशा ठीक दो की ज़रूरत होती है","3 टाई-डाउन, क्योंकि आप हर 3 घंटे में बंधन दोबारा जाँचते हैं","8 टाई-डाउन, क्योंकि भार की हर 5 फुट लंबाई के लिए एक चाहिए","4 टाई-डाउन, क्योंकि भार की हर 10 फुट लंबाई के लिए एक चाहिए"],"explanation":"माल को हर 10 फुट लंबाई पर कम से कम एक टाई-डाउन चाहिए, इसलिए 38 फुट के बीम के लिए ऊपर की ओर पूर्णांकित कर चार टाई-डाउन चाहिए।"},"145":{"q":"तापमान हिमांक से थोड़ा नीचे है और आप अपने लदे हुए ट्रैक्टर-ट्रेलर में एक पुल पर बने मोड़ के पास पहुँच रहे हैं। मोड़ का अनुसरण करने के लिए जब आप स्टीयरिंग व्हील घुमाते हैं, तो आगे के पहिये बर्फ पर पकड़ खो देते हैं। इस फ्रंट-व्हील स्किड का सबसे संभावित परिणाम क्या है और वाहन कैसी प्रतिक्रिया देता है?","options":["वाहन सीधा आगे बढ़ता रहता है और आप स्टीयरिंग को किसी भी दिशा में घुमाएँ, यह तब तक उसी सीधी दिशा में चलता रहता है जब तक आगे के टायर फिर से पकड़ नहीं बना लेते।","पीछे के ड्राइव पहिये एक ओर फिसल जाते हैं और ट्रेलर कैब के पीछे मुड़कर जैकनाइफ होने लगता है।","वाहन आपके इरादे से अधिक तीखा मुड़ जाता है और उसका अगला हिस्सा मोड़ के भीतरी किनारे की ओर खिंच जाता है।","स्टीयरिंग सख्त हो जाती है, आगे के पहिये और मजबूती से पकड़ लेते हैं और ट्रक जिस ओर आपने घुमाया उसी ओर अधिक झुक जाता है।"],"explanation":"फ्रंट-व्हील स्किड में आगे के टायर पकड़ खो देते हैं इसलिए स्टीयरिंग का कोई असर नहीं होता, और वाहन तब तक सीधा चलता रहता है जब तक आगे के टायर फिर से पकड़ न बना लें।"},"146":{"q":"आप एक भरे हुए, बिना ABS वाले ट्रैक्टर-ट्रेलर को हाईवे की गति पर चला रहे हैं, तभी एक कार अचानक आपके सामने आ जाती है और थोड़ी ही दूरी पर रुक जाती है। आपको अधिकतम ब्रेकिंग चाहिए, लेकिन वाहन को नियंत्रण में रखना और स्टीयरिंग करना भी ज़रूरी है। नियंत्रित ब्रेकिंग (controlled braking) विधि का उपयोग करते हुए, आपको ब्रेक पेडल के साथ क्या करना चाहिए?","options":["सबसे छोटी रुकावट के लिए पेडल को पूरी तरह दबाकर पहियों को लॉक कर दें","पहियों के लॉक होने से ठीक पहले के बिंदु पर पेडल पर मज़बूत, स्थिर दबाव डालें, और केवल तभी दबाव कम करें जब पहिए लॉक होने लगें","पहिए घूमते रहें इसके लिए पेडल को बार-बार ज़ोर से और तेज़ी से पंप करें","फुट ब्रेक को बिल्कुल न छुएं और वाहन को केवल ट्रेलर हैंड वाल्व से धीमा करें"],"explanation":"नियंत्रित ब्रेकिंग का अर्थ है पहियों को लॉक होने से ठीक पहले तक दृढ़, स्थिर दबाव लगाना, और केवल तब ढील देना जब वे लॉक होने लगें ताकि आप स्टीयर कर सकें।"},"147":{"q":"आप पूरी तरह लदे ट्रेलर के साथ एक लंबी, खड़ी पहाड़ी ढलान से नीचे उतर रहे हैं। आपने ऊपर ही कम गियर चुना था, लेकिन उतराई के बीच में आपको कुछ गरम जलने जैसी गंध आती है, हर बार दबाने पर ब्रेक पेडल और नरम महसूस होता है, और हल्के, स्थिर ब्रेक लगाने के बावजूद ट्रक धीरे-धीरे रफ्तार पकड़ रहा है। आगे एक चिह्न है: 'रनअवे ट्रक रैंप 1 मील'। यह रैंप जिस काम के लिए बनाया गया है उसे ध्यान में रखते हुए, कौन-सा कथन सही है?","options":["यह एक अनिवार्य विश्राम क्षेत्र है जहाँ हर लदे ट्रक को ढलान पर आगे बढ़ने से पहले ब्रेक ठंडे करने के लिए रुकना ही पड़ता है।","यह एक रखरखाव वाला शॉर्टकट है जो आपके अधिक गरम हुए ब्रेकों के ठीक होने के दौरान ढलान छोड़कर नीचे तक जल्दी पहुँचने देता है।","यह एक आपातकालीन एस्केप रैंप है, जिसे उस वाहन को सुरक्षित रूप से रोकने के लिए बनाया गया है जिसके ब्रेक फेल हो गए हों या अधिक गरम होने से कमजोर पड़ गए हों।","यह एक पक्की पुलआउट जगह है जहाँ आप धीरे-धीरे चलते रह सकते हैं ताकि ब्रेक पूरी तरह रुके बिना ही गर्मी छोड़ दें।"],"explanation":"रनअवे ट्रक रैंप एक आपातकालीन एस्केप रैंप है जो ब्रेक फेल होने या ज़्यादा गरम होकर फीके पड़ने पर वाहन को सुरक्षित रूप से रोकने के लिए बनाई जाती है।"},"148":{"q":"आप सूखे इंटरस्टेट हाईवे पर 55 मील प्रति घंटे की रफ्तार से चल रहे हैं, तभी एक कार अचानक आपके आगे आकर जोर से ब्रेक लगा देती है। बाद में आपका प्रशिक्षक आपसे आपकी कुल रुकने की दूरी के हिस्सों को अलग करने को कहता है। वह याद दिलाता है कि इस गति पर आपकी कुल रुकने की दूरी लगभग 419 फीट है। इस कुल में से, आपका ट्रक केवल आपके प्रतिक्रिया समय के दौरान -- खतरे को देखने और आपके पैर के वास्तव में ब्रेक पेडल दबाने के बीच के अंतराल में, इससे पहले कि ब्रेक ने जरा भी गति कम की हो -- कितनी दूरी तय करता है?","options":["लगभग 419 फीट, क्योंकि ट्रक इस पूरे समय तक पूरी गति से लुढ़कता रहता है जब तक कि अंततः रुक न जाए","लगभग 250 फीट, क्योंकि आपकी लो-बीम हेडलाइट्स लगभग इतनी ही दूर तक पहुँचती हैं और आप आगे इतनी ही दूर तक प्रतिक्रिया कर सकते हैं","लगभग 6 फीट, क्योंकि हाईवे की गति पर आपके प्रशिक्षित प्रतिवर्त आपके पैर को लगभग तुरंत हिला देते हैं","लगभग 60 फीट, यानी लगभग वह दूरी जो एक औसत चालक को प्रतिक्रिया करने में लगने वाले तीन-चौथाई सेकंड में तय होती है"],"explanation":"प्रतिक्रिया दूरी वह दूरी है जो खतरा भांपने के बाद ब्रेक लगने से पहले तय होती है; 55 मील/घंटा पर औसत तीन-चौथाई सेकंड में लगभग 60 फीट होती है।"},"149":{"q":"आप अपने भरे हुए संयुक्त (कॉम्बिनेशन) वाहन में एक शहरी चौराहे के पास पहुँच रहे हैं, तभी ट्रैफ़िक सिग्नल स्थिर (बिना झपकने वाली) लाल बत्ती पर बदल जाता है। यातायात कम है और इस समय आपको कोई आड़ा (क्रॉस) यातायात या पैदल यात्री नहीं दिखता। CDL चालक के रूप में कानूनी रूप से आपके लिए कौन-सी कार्रवाई अनिवार्य है?","options":["चूँकि कोई आड़ा यातायात नहीं है, इसलिए गति बहुत धीमी करके चौराहा पार कर लें","स्थिर लाल को बिल्कुल झपकती लाल की तरह मानें: रास्ता साफ़ हो तो रास्ता दें पर रुकना ज़रूरी नहीं","पूरी तरह रुक जाएँ और सिग्नल के हरा होने तक रुके रहें","केवल तभी रुकें जब कोई वाहन या पैदल यात्री वास्तव में आपके रास्ते में हो, अन्यथा आगे बढ़ते रहें"],"explanation":"स्थिर लाल बत्ती पर आपको पूरी तरह रुकना होगा और सिग्नल हरा होने तक रुके रहना होगा।"},"150":{"q":"आप एक लदे हुए ट्रैक्टर-ट्रेलर को सूखे, खुले राजमार्ग पर 55 मील प्रति घंटे की गति से चला रहे हैं, तभी आपको अपनी लेन में लगभग एक चौथाई मील (12-15 सेकंड) आगे एक खराब कार दिखाई देती है जिसका बोनट खुला हुआ है। बगल वाली लेन में यातायात घना है, इसलिए आप अभी लेन नहीं बदल सकते। उठाया जाने वाला सबसे अच्छा पहला कदम क्या है?","options":["अपनी गति बनाए रखें और प्रतिक्रिया देने से पहले तब तक प्रतीक्षा करें जब तक आप बाधा से लगभग 200 फीट दूर न हों, क्योंकि इससे आपको पर्याप्त जगह मिलती है","एक जगह बनाने के लिए थोड़ी देर के लिए गति बढ़ाएं और खराब कार तक पहुंचने से पहले बगल वाली लेन में जबरदस्ती घुस जाएं","बाधा तक पहुंचने से पहले जितनी हो सके उतनी गति कम करने के लिए तुरंत जोर से ब्रेक लगाएं","एक्सेलेरेटर से पैर हटाएं और ब्रेक पर पैर रखें ताकि स्थिति बदलने पर आप सुचारू रूप से गति कम करने के लिए तैयार रहें"],"explanation":"खतरा दूर आगे हो तो एक्सेलेरेटर छोड़ें और ब्रेक पर पैर तैयार रखें ताकि अचानक रुके बिना सहजता से धीमा हो सकें।"},"151":{"q":"आप सूखे, साफ़ दो-लेन वाले राजमार्ग पर 35 मील प्रति घंटे की रफ़्तार से 60 फुट लंबा संयोजन वाहन (कॉम्बिनेशन) चला रहे हैं और आगे वाली कार के पीछे उचित अनुसरण दूरी रखना चाहते हैं। अपने वाहन की लंबाई के आधार पर, इन अच्छी परिस्थितियों में आपको कम से कम कितनी सुरक्षित अनुसरण दूरी रखनी चाहिए?","options":["लगभग 6 सेकंड — आपके वाहन की लंबाई के हर 10 फुट के लिए एक सेकंड","लगभग 7 सेकंड — हर 10 फुट के लिए एक सेकंड और रफ़्तार के लिए एक अतिरिक्त सेकंड","तय 4 सेकंड, क्योंकि अच्छे मौसम में किसी भी वाहन के लिए 4 सेकंड मानक अंतराल है","35 मील प्रति घंटे पर कोई मापी हुई दूरी की ज़रूरत नहीं है क्योंकि यह रफ़्तार इतनी कम है कि जल्दी रुका जा सकता है"],"explanation":"वाहन की लंबाई के हर 10 फीट के लिए एक सेकंड की दूरी रखें, इसलिए 60 फीट के संयोजन को 40 मील/घंटा या उससे कम पर लगभग 6 सेकंड चाहिए।"},"152":{"q":"सुबह जल्दी का समय है और आप अपनी प्री-ट्रिप जांच कर रहे हैं। आप इंजन चालू करते हैं और डैशबोर्ड के गेज देखते हैं। ट्रक को चलाने के लिए सुरक्षित मानने से पहले, इंजन चालू होने के पहले कुछ क्षणों में इंजन ऑयल प्रेशर गेज (या ऑयल प्रेशर चेतावनी लाइट) को क्या करना चाहिए?","options":["जब तक इंजन ठंडा है तब तक ऑयल प्रेशर शून्य पर रहना चाहिए, और कई मील चलने के बाद ही बढ़ना चाहिए।","इंजन चालू होने के थोड़े ही समय में ऑयल प्रेशर सामान्य स्तर तक पहुंच जाना चाहिए (और ऑयल प्रेशर चेतावनी लाइट बुझ जानी चाहिए)।","जब तक इंजन चलता है तब तक ऑयल प्रेशर चेतावनी लाइट जलती रहनी चाहिए; इसी से आप जानते हैं कि स्नेहन प्रणाली सक्रिय है।","ऑयल प्रेशर को थोड़ी देर के लिए सामान्य सीमा से बहुत ऊपर उछलकर वहीं रुक जाना चाहिए, क्योंकि अधिक मान का अर्थ है मजबूत स्नेहन।"],"explanation":"इंजन चालू होने के तुरंत बाद तेल का दबाव सामान्य स्तर तक पहुँच जाना चाहिए और तेल दबाव चेतावनी लाइट बुझ जानी चाहिए, जिससे स्नेहन प्रणाली काम कर रही पुष्टि होती है।"},"153":{"q":"एक गर्म दोपहर है और आप कम गियर में एक लंबी चढ़ाई पर भारी भार खींच रहे हैं। अपने इंस्ट्रूमेंट पैनल पर नज़र डालते हुए, आप देखते हैं कि शीतलक तापमान गेज की सुई अपनी सामान्य सीमा से काफी ऊपर चढ़ रही है। यह विशेष गेज आपको जो बताने के लिए डिज़ाइन किया गया है, उसके आधार पर यह आपको किस स्थिति के बारे में चेतावनी दे रहा है?","options":["आपके टैंक में ईंधन का स्तर खतरनाक रूप से कम हो रहा है और आपको जल्द ही ईंधन भरना चाहिए","आपकी हेडलाइट्स मंद हो गई हैं क्योंकि अल्टरनेटर अब बैटरी चार्ज नहीं कर रहा है","इंजन अधिक गरम हो रहा है और इस भार के साथ चढ़ाई जारी रखने पर क्षतिग्रस्त हो सकता है","इंजन ऑयल का दबाव चलने वाले पुर्जों को ठीक से चिकनाई देने के लिए बहुत कम हो गया है"],"explanation":"शीतलक तापमान सुई का सामान्य सीमा से ऊपर चढ़ना दर्शाता है कि इंजन ज़्यादा गरम हो रहा है और भार के साथ चलाते रहने पर खराब हो सकता है।"},"154":{"q":"एक ठंडी सुबह अपने प्री-ट्रिप निरीक्षण के दौरान, आप इंजन चालू करते हैं और एयर प्रेशर गेज देखते हैं। आप देखते हैं कि आपके टैंकों में हवा का दबाव ऑपरेटिंग रेंज की ओर बहुत धीरे-धीरे बढ़ रहा है और सामान्य से कहीं अधिक समय ले रहा है। कंप्रेसर गवर्नर अभी तक कट-आउट नहीं हुआ है। निम्नलिखित में से इस धीमी वृद्धि का सबसे अधिक संभावित कारण क्या है?","options":["कंप्रेसर उत्कृष्ट स्थिति में है और बस धीरे-धीरे दबाव बनाकर सिस्टम की रक्षा कर रहा है","आपके एयर टैंक पहले से ही भरे हुए हैं, इसलिए गेज केवल शेष दबाव दिखा रहा है","आपके सर्विस ब्रेक बहुत अच्छी स्थिति में हैं, जिससे टैंकों में हवा भरने की गति धीमी हो जाती है","सिस्टम में हवा का रिसाव है या कंप्रेसर कमजोर है, इसलिए दबाव जितना बनना चाहिए उससे धीमे बनता है"],"explanation":"हवा का दबाव बहुत धीरे बढ़ना यह चेतावनी देता है कि सिस्टम में हवा का रिसाव है या कमज़ोर कंप्रेसर माँग के अनुरूप काम नहीं कर पा रहा।"},"155":{"q":"सुबह-सुबह की प्री-ट्रिप जांच के दौरान तापमान ठंड के बिंदु से थोड़ा नीचे है। आप हुड उठाते हैं और इंजन की ड्राइव बेल्ट तथा रेडिएटर और हीटर की नलियों (होज़) पर हाथ फेरते हैं। आप जिस वास्तविक सुरक्षा दोष की जांच कर रहे हैं, वह कौन सा है, जिसके कारण इस ट्रक को सेवा में नहीं जाने देना चाहिए?","options":["बेल्ट और नलियों पर दरारें, घिसाव से उधड़ना, मुलायम स्थान, या रिसाव के संकेत","बेल्ट और नलियां जिनकी फैक्ट्री चमक चली गई है और अब वे फीकी तथा धूल भरी दिखती हैं","ऐसी नलियां जिन पर अब निर्माता के ब्रांड-नाम का पढ़ने योग्य टैग नहीं दिखता","एक बेल्ट जो नई होने पर अपने चमकीले रंग की तुलना में अब गहरे रंग की हो गई है"],"explanation":"बेल्ट और होज़ में दरारें, घिसाव, नरम स्थान या रिसाव के संकेत जाँचें, क्योंकि यह क्षति खराबी या इंजन फेल का कारण बन सकती है।"},"156":{"q":"एक ठंडी सुबह अपनी प्री-ट्रिप जाँच के दौरान आपको पिछले ड्राइव एक्सल के एक स्टील व्हील रिम पर आर-पार जाती हुई एक बारीक दरार मिलती है, और एक दूसरे पहिये पर दो लग नट साफ़ तौर पर ढीले हैं। टायर खुद हवा रोके हुए हैं और उनका ट्रेड अच्छा है। आपका डिस्पैचर आप पर यह चक्कर लगाने का दबाव डाल रहा है क्योंकि लदान समय-संवेदनशील है। इस वाहन को चलाने के बारे में सही निर्णय क्या है?","options":["चूँकि टायर हवा रोके हुए हैं और उनका ट्रेड अच्छा है, पहिये काफ़ी सुरक्षित हैं; आप सावधानी से शॉप तक चला सकते हैं और डिलीवरी के बाद इसे दिखवा सकते हैं।","दरकी हुई रिम और ढीले लग नट आउट-ऑफ-सर्विस दोष हैं; जब तक इनकी मरम्मत न हो जाए, वाहन को नहीं चलाया जाना चाहिए।","ढीले लग नट को हाथ से कस लें और दरकी रिम पर नज़र रखें; अगर पहले 50 मील में दरार न बढ़े, तो आप यात्रा जारी रख सकते हैं।","यह केवल स्टीयरिंग एक्सल पर समस्या है; चूँकि ये पिछले ड्राइव पहिये हैं, वहाँ दरकी रिम और ढीले लग नट मामूली घिसाव हैं और वाहन चलाने के लिए ठीक है।"],"explanation":"टूटे हुए रिम और ढीले लग नट सेवा-से-बाहर दोष हैं, इसलिए मरम्मत होने तक वाहन नहीं चलाना चाहिए।"},"158":{"q":"यार्ड में अपनी प्री-ट्रिप जांच के दौरान, आप ट्रैक्टर के ठीक नीचे फुटपाथ पर तरल पदार्थ का एक ताज़ा गड्ढा पाते हैं। टंकियों का स्तर अभी भी सामान्य सीमा में है और ट्रक स्टार्ट होकर ठीक चलता है। आप अपनी डिलीवरी विंडो के लिए पहले से ही देरी से चल रहे हैं। सही कार्रवाई क्या है?","options":["तरल का स्तर नोट करें, सुरक्षा के लिए टंकी भर दें और गेज सामान्य दिखाने के कारण यात्रा जारी रखें","अभी इसे छोड़ दें और यह देखने के लिए कि रिसाव बढ़ रहा है या नहीं, पहले 50 मील के भीतर अपने पहले पड़ाव पर गड्ढे की फिर से जांच करें","जब तक आप रिसाव का स्रोत न ढूंढ लें और उसकी मरम्मत न करा लें तब तक गाड़ी न चलाएं, भले ही इससे आपको देर हो जाए","गड्ढे को पोंछ दें, जांच को संतोषजनक के रूप में दर्ज करें और गाड़ी चलाते समय गेजों पर बारीकी से नज़र रखें"],"explanation":"ज्ञात तरल रिसाव एक ऐसा दोष है जो भयानक रूप से फेल हो सकता है, इसलिए स्रोत खोजकर मरम्मत कराए बिना न चलाएँ, भले ही देर हो जाए।"},"159":{"q":"भोर से ठीक पहले आप यात्रा-पूर्व निरीक्षण के लिए वाहन के चारों ओर घूम रहे हैं। कई पिछले रिफ्लेक्टर और आपके दो टेल/क्लीयरेंस लैंप सूखी सड़क की गंदगी से ढके हैं, और एक टेल लैंप का लेंस लाइट चालू होने पर भी मंद दिखता है। बाकी मामलों में ट्रक लदा हुआ और चलने के लिए तैयार है। रवाना होने से पहले लाइटों और रिफ्लेक्टरों के निरीक्षण मानक को कौन-सी कार्रवाई सबसे अच्छी तरह पूरा करती है?","options":["रिफ्लेक्टरों को छोड़ दें क्योंकि वे निष्क्रिय उपकरण हैं, लेकिन जो भी टेल लैंप बल्ब नहीं जलता उसे बदल दें","केवल उन लैंपों को पोंछें जो बिजली से चलते हैं, क्योंकि रिफ्लेक्टरों को अपना काम करने के लिए साफ होने की जरूरत नहीं है","मंद या गंदे लेंसों को टेप से ढक दें ताकि उन्हें जला हुआ लैंप न समझा जाए, फिर वर्कशॉप तक चलाएं","सभी लैंपों और रिफ्लेक्टरों से गंदगी साफ करें और यात्रा से पहले पुष्टि करें कि हर एक काम कर रहा है"],"explanation":"यात्रा से पहले सभी लैंप और रिफ्लेक्टर साफ और चालू होने चाहिए, क्योंकि गंदगी रिफ्लेक्टर को परावर्तित करने और लैंप को दिखने से रोकती है।"},"160":{"q":"आप सफर-पूर्व निरीक्षण शुरू करने के लिए यार्ड में अपने ट्रक के पास पहुँचते हैं। जल्दी निकलने की चाह में आप मन ही मन सोचने लगते हैं कि पहले क्या करना है: इंजन गरम करना, चारों ओर पैदल घूमना, ब्रेक जाँचना, लाइटें जाँचना। वाहन पर कुछ भी छूने से पहले, निरीक्षण विधि के सबसे पहले चरण में कौन-सा काम सही ढंग से आता है?","options":["वाहन के पास पैदल जाकर एक सामान्य अवलोकन करना: कैब में बैठने से पहले उसकी समग्र स्थिति, झुकाव/मुद्रा, नीचे ताज़ा तरल पदार्थ के जमाव और आसपास के किसी भी खतरे को देखना","इंजन चालू करके उसे कार्य-तापमान तक गरम होने देना ताकि चारों ओर घूमते समय गेज सही रीडिंग दें","लगभग 5 मील प्रति घंटे की गति से आगे बढ़ाकर और ब्रेक पेडल दबाकर दबाव-लागू सर्विस ब्रेक परीक्षण करना","आगे और पीछे जाकर पुष्टि करना कि सभी बाहरी लाइटें और परावर्तक साफ़, सही रंग के और काम करने योग्य हैं"],"explanation":"प्री-ट्रिप निरीक्षण की शुरुआत पैदल चलकर वाहन के आसपास घूमने से करें, अंदर बैठने से पहले उसकी मुद्रा, नीचे तरल पदार्थ के रिसाव और आसपास के खतरों की जाँच करें।"},"161":{"q":"आप एक मानक (बिना सिंक्रोनाइज़्ड) मैनुअल ट्रांसमिशन वाला लदा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं और समतल हाईवे पर गति बढ़ाते समय आपको 5वें गियर से 6वें गियर में जाना है। कई ट्रकों में पाए जाने वाले इस प्रकार के ट्रांसमिशन में गियर घिसे बिना साफ-सुथरे ढंग से ऊपर के गियर में बदलने के लिए सही तकनीक क्या है?","options":["क्लच को केवल आधा दबाएं (\"क्लच ब्रेकिंग\") और लीवर को जबरदस्ती अगले गियर में डाल दें","पूरे गियर बदलाव के दौरान क्लच को पूरी तरह दबाए रखें और साथ ही एक्सेलरेटर को हल्का-हल्का दबाते रहें","एक हाथ स्टीयरिंग व्हील पर मजबूती से रखें और वाहन के चलते रहने पर बिना क्लच का इस्तेमाल किए ही गियर बदलें","डबल-क्लच करें: एक्सेलरेटर छोड़ें, क्लच दबाएं, न्यूट्रल में लाएं, क्लच छोड़ें, फिर दोबारा क्लच दबाकर ऊंचे गियर में डालें"],"explanation":"ऊँचे गियर में जाने के लिए डबल-क्लच करें: एक्सेलेरेटर छोड़ें, क्लच दबाकर न्यूट्रल करें, क्लच छोड़ें, फिर दोबारा क्लच दबाकर ऊँचे गियर में डालें।"},"162":{"q":"आप एक भरा हुआ ट्रेलर खींच रहे हैं और आगे की सड़क एक लंबी, खड़ी पहाड़ी ढलान में उतरती है। आप नीचे उतरते समय अपने ब्रेक को ज़्यादा गरम किए बिना सुरक्षित रूप से अपनी गति नियंत्रित करना चाहते हैं। आपको किस बिंदु पर लो गियर में अपना शिफ्ट पूरा करना चाहिए?","options":["ढलान से नीचे उतरना शुरू करने से पहले, जब आप अभी भी ऊपर समतल ज़मीन पर हों","जब आप पहले से ही उतर रहे हों, जैसे ही आपको लगे कि ट्रक गति पकड़ रहा है","ढलान के नीचे, जब सड़क फिर से समतल हो जाए","केवल तभी जब हल्का, स्थिर ब्रेक दबाव आपको धीमा करना बंद कर दे"],"explanation":"लंबी, खड़ी ढलान उतरने से पहले समतल जमीन पर रहते हुए ही नीचे का गियर लगाएं, क्योंकि गति नियंत्रण मुख्यतः इंजन ब्रेकिंग से होता है और सर्विस ब्रेक केवल सहायक हैं।"},"163":{"q":"आप एक लदे हुए ट्रेलर के साथ एक लंबी पहाड़ी ढलान से नीचे उतर रहे हैं। आपके ट्रक में एक रिटार्डर लगा है, और उतराई शुरू करते समय आप उसे चालू कर देते हैं। यहाँ रिटार्डर आपके लिए क्या कर रहा है, इसका सबसे अच्छा वर्णन कौन-सा कथन करता है?","options":["यह इंजन की शक्ति बढ़ाता है ताकि आप गति पकड़ सकें और ढलान को अधिक तेज़ी से पार कर सकें","यह वाहन को धीमा करने में मदद करने के लिए अतिरिक्त ब्रेकिंग बल लगाता है, जिससे सर्विस ब्रेक पर घिसाव और गर्मी का जमाव कम होता है","यह स्टीयरिंग प्रतिक्रिया को कसता है ताकि ट्रक ढलान के मोड़ों पर अधिक आसानी से मुड़ सके","यह उतराई का मुख्य नियंत्रण है, इसलिए अब आपको उतरना शुरू करने से पहले कम गियर चुनने की आवश्यकता नहीं है"],"explanation":"रिटार्डर अतिरिक्त ब्रेकिंग बल लगाकर वाहन को धीमा करता है, जिससे सर्विस ब्रेक पर घिसाव और गर्मी कम होती है।"},"164":{"q":"तापमान जमाव बिंदु से थोड़ा नीचे है और आपके मार्ग के पुलों पर बर्फ की एक पतली परत जम गई है। आपके ट्रैक्टर में एक इंजन (स्पीड) रिटार्डर लगा है जो एक्सेलरेटर छोड़ने पर ड्राइव एक्सल पर असर डालता है। इस फिसलन भरी सतह पर एक मोड़ के लिए गति कम करने हेतु जब आप एक्सेलरेटर से पैर हटाते हैं, तो उस रिटार्डर को संभालने का सही तरीका क्या है?","options":["रिटार्डर को पूरी तरह चालू रहने दें, क्योंकि इसका ब्रेक केवल ड्राइव पहियों पर असर करता है और इसलिए स्टीयरिंग एक्सल को अस्थिर नहीं कर सकता","रिटार्डर को जोर से और पहले ही लगा दें ताकि बर्फ पर आपको फुट ब्रेक को बिल्कुल न छूना पड़े","इसे बहुत सावधानी से उपयोग करें या बंद कर दें, क्योंकि फिसलन भरी सतह पर रिटार्डर ड्राइव पहियों की पकड़ खत्म कर सकता है और स्किड करा सकता है","जब भी पूर्वानुमान में बर्फ हो, प्री-ट्रिप जाँच के दौरान रिटार्डर को हटा दें या निष्क्रिय कर दें"],"explanation":"फिसलन भरी सतह पर रिटार्डर का प्रयोग सावधानी से करें या बंद कर दें, क्योंकि यह ड्राइव पहियों की पकड़ छीनकर स्किड करा सकता है।"},"165":{"q":"रात में आप अपने ट्रेलर को एक तंग लोडिंग डॉक में पीछे की ओर ले जा रहे हैं। आपको दिशा बताने के लिए कोई सहायक नहीं है, और खड़े ट्रेलरों के कारण डॉक क्षेत्र का कुछ हिस्सा आपकी नज़र से छिपा हुआ है। इस पैंतरे को पूरा करने का सबसे सुरक्षित और सही तरीका कौन-सा है?","options":["जितनी जल्दी हो सके पीछे जाएँ ताकि लेन कम से कम समय के लिए बाधित हो और पैंतरा छोटा रहे","इंजन को तेज़ करें और क्लच को आधा दबाए रखें ताकि बिना पीछे लुढ़के सीधे अंदर जा सकें","केवल चालक की ओर वाले शीशे पर नज़र रखें, क्योंकि यात्री की ओर आपका अंधा क्षेत्र है और उसे जाँचने लायक नहीं","धीरे-धीरे पीछे जाएँ, दोनों शीशों का उपयोग करें, और जब भी आप अपने रास्ते को देखना खो दें तो दोबारा स्थिति ठीक करने के लिए आगे बढ़ें"],"explanation":"दोनों शीशों का उपयोग करते हुए धीरे-धीरे पीछे जाएँ, और जब भी रास्ता दिखना बंद हो जाए तो आगे बढ़कर दोबारा सही स्थिति में आएँ।"},"167":{"q":"आप एक व्यस्त चौराहे के पास पहुँच रहे हैं जहाँ आप लोडिंग डॉक की ओर दाएँ मुड़ने का इरादा रखते हैं। यातायात घना है और एक छोटी कार आपके ट्रैक्टर के दाईं ओर धीरे-धीरे बराबर में आने लगती है। अपने इरादे को सुरक्षित रूप से बताने और उस कार को किनारे (कर्ब) से दबने से बचाने के लिए, आपको अपना टर्न सिग्नल कब चालू करना चाहिए?","options":["जल्दी, मोड़ शुरू करने से काफी पहले, ताकि अन्य चालकों को प्रतिक्रिया करने का समय मिले","जैसे ही आप पहिया मोड़ना शुरू करते हैं, ताकि समय आपकी गतिविधि से मेल खाए","केवल मोड़ पूरा करने के बाद, ताकि आस-पास के चालकों को भ्रमित न करें","केवल रात में या कम दृश्यता की स्थिति में, जब सिग्नल की सबसे अधिक आवश्यकता होती है"],"explanation":"मुड़ने से काफी पहले ही जल्दी संकेत दें, ताकि अन्य चालकों को प्रतिक्रिया करने का समय मिल सके।"},"168":{"q":"आप शहर की एक सड़क से लोडिंग डॉक के प्रवेश मार्ग की ओर धीमा, चौड़ा बायाँ मोड़ ले रहे हैं। मोड़ के बीच में, स्टीयरिंग व्हील आंशिक रूप से सीधा हो जाता है और आपका टर्न सिग्नल अपने आप बंद हो जाता है। क्रॉस स्ट्रीट पर एक कार रुकी है और पीछे से एक साइकिल चालक आ रहा है। इस पूरी क्रिया के बाकी हिस्से के लिए अपने सिग्नल को संभालने का सही तरीका क्या है?","options":["जैसे ही आपके ट्रैक्टर का अगला हिस्सा प्रवेश मार्ग में घुस जाए, सिग्नल बंद कर दें, क्योंकि मोड़ अब लगभग तय हो चुका है","सिग्नल फिर से चालू करें और जब तक आप मोड़ पूरी तरह से पूरा न कर लें और आपका वाहन सीधा न हो जाए, तब तक उसे जलता हुआ रखें","सिग्नल अभी बंद रहने दें और इसके बजाय साइकिल चालक को अपना इरादा बताने के लिए ब्रेक को दो बार हल्के से दबाएँ","मोड़ के केवल पहले सेकंड के लिए सिग्नल दें, क्योंकि माहौल में उतरने से पहले कानून बस इतना ही माँगता है"],"explanation":"मोड़ पूरी तरह पूरा होने और वाहन सीधा होने तक लगातार संकेत देते रहें, क्योंकि ट्रेलर को पूरे चाप से गुजरना होता है।"},"169":{"q":"आप एक व्यस्त चार-लेन हाईवे पर लदा हुआ ट्रेलर चला रहे हैं और आप देखते हैं कि लगभग एक-चौथाई मील आगे धीमा ट्रैफ़िक जमा हो रहा है। आपको जल्द ही गति कम करनी होगी, और आपके ठीक पीछे कारों की एक कतार चल रही है। पीछे चल रहे चालकों को यह बताने के लिए सबसे अच्छा कौन सा कदम है कि आप गति कम करने वाले हैं?","options":["उनका ध्यान खींचने के लिए अपनी हेडलाइट और पिछली लाइटें तेज़ी से बंद करके फिर चालू करें","हॉर्न को दो बार छोटी आवाज़ में बजाएँ ताकि पीछे के चालक किसी बदलाव की उम्मीद करें","ब्रेक पेडल को हल्के से कई बार दबाएँ ताकि आपकी ब्रेक लाइटें पहले से चमक उठें","आगे जगह बनाने के लिए थोड़ा तेज़ करें, फिर जब दूरी घट जाए तो ज़ोर से ब्रेक लगाएँ"],"explanation":"पीछे के चालकों को धीमा होने की चेतावनी देने के लिए ब्रेक पेडल को कुछ बार हल्के से दबाकर अपनी ब्रेक लाइटें पहले ही चमकाएँ।"},"171":{"q":"अभी-अभी भोर हुई है और सूरज क्षितिज पर नीचे है। रोशनी धुंधली और भूरी है, और आप देखते हैं कि सड़क की पृष्ठभूमि में दूसरे चालकों और आकृतियों को पहचानना कठिन होता जा रहा है। आप समय पर चल रहे हैं और दृश्यता अभी पूरी तरह खत्म नहीं हुई है। इस धुंधलके में सड़क देखने के लिए और, उतना ही महत्वपूर्ण, दूसरे यातायात द्वारा देखे जाने के लिए, एकमात्र सबसे अच्छा कदम कौन-सा है?","options":["केबिन की भीतरी छत वाली लाइट जलाना ताकि बाहर की धुंधली परिस्थितियों का अंदर से बेहतर अंदाज़ा लगाया जा सके","सभी बाहरी लाइटें बंद रखना, क्योंकि सड़क देखने के लिए अभी भी पर्याप्त प्राकृतिक दिन का उजाला है","केवल चारों ओर की खतरा (हैज़र्ड) लाइटें जलाना ताकि दूसरे चालकों को कम दृश्यता की चेतावनी मिले","अपनी हेडलाइटें जलाना ताकि आप आगे की सड़क देख सकें और दूसरे चालक आपके वाहन को साफ़ देख सकें"],"explanation":"भोर या सांझ के समय अपनी हेडलाइटें चालू करें ताकि आप आगे का रास्ता देख सकें और अन्य चालक आपके वाहन को साफ़ देख सकें।"},"172":{"q":"आप मध्यम यातायात में 55 मील प्रति घंटा की गति से एक भरा हुआ ट्रेलर चला रहे हैं। एक छोटी कार अचानक आपके आगे घुस जाती है और जोर से ब्रेक लगाती है, और आपको एहसास होता है कि आपने अपने बंपर के आगे की जगह का अंतर घटा दिया है। ठीक इसी क्षण आगे की वह जगह बनाए रखना सबसे अधिक क्यों मायने रखता है?","options":["यह आपको वह जगह देती है जिसकी जरूरत आपको या तो पूरी तरह रुकने तक ब्रेक लगाने या किसी खतरे से सुरक्षित रूप से मुड़कर बचने के लिए होती है","यह आपको ब्रेक का कम उपयोग करते हुए अधिक ऊँची क्रूज़िंग गति बनाए रखने देती है","यह ईंधन बचाती है क्योंकि स्थिर यातायात में आप कम ब्रेक और कम तेज करते हैं","यह दूसरे चालकों को आपके आगे घुसने और आपकी लेन में दबाव डालने से हतोत्साहित करती है"],"explanation":"आगे की जगह आपका बचाव मार्जिन है, जो आपको या तो पूरी तरह रुकने के लिए ब्रेक लगाने या किसी खतरे के चारों ओर सुरक्षित रूप से मुड़ने की जगह देती है।"},"173":{"q":"आप एक व्यस्त दो-लेन वाले राजमार्ग पर 50 मील प्रति घंटे की गति से एक भरा हुआ संयोजन वाहन चला रहे हैं, तभी आप देखते हैं कि एक छोटी कार आपके पीछे बहुत करीब आ गई है और आपके बंपर से केवल एक-दो वाहन की लंबाई की दूरी पर बहुत पास से चल रही है। आगे का यातायात स्थिर रूप से चल रहा है, लेकिन किसी भी समय धीमा हो सकता है। इस खतरे को संभालने का सबसे अच्छा तरीका निम्नलिखित में से कौन सा है?","options":["अपने ब्रेक लाइट चमकाने के लिए ब्रेक को हल्के से दबाएं और पीछे से बहुत पास चल रहे चालक को पीछे हटने का संकेत दें","धीरे-धीरे एक्सेलरेटर छोड़कर और अपनी अनुसरण दूरी बढ़ाकर अपने आगे अधिक जगह बनाएं, ताकि यातायात धीमा होने पर आप धीरे से ब्रेक लगा सकें","अपनी गति बनाए रखें और अपनी लेन की स्थिति बनाए रखें, क्योंकि आपके वाहन के पीछे की जगह के लिए पीछे से पास चलने वाला चालक जिम्मेदार है","पीछे से पास चल रहे वाहन से दूर निकलने और सुरक्षित अंतराल फिर से बनाने के लिए गति बढ़ाएं"],"explanation":"जब कोई बहुत पास से पीछे चल रहा हो, तो धीरे-धीरे एक्सेलेरेटर छोड़कर आगे अधिक जगह बनाएँ ताकि यातायात धीमा होने पर आप अचानक के बजाय धीरे से ब्रेक लगा सकें।"},"174":{"q":"आप तीन-लेन वाले इंटरस्टेट के बीच वाले लेन में हाईवे की गति से चल रहे हैं। एक कार आपके ट्रैक्टर के दाईं ओर बराबर में आकर टिक गई है और वही स्थिति बनाए हुए है, न आगे निकल रही है न पीछे हट रही है, आपकी कैब के ठीक बराबर चल रही है। एक चालक के रूप में आपके लिए इस तरह अगल-बगल चलते रहना सबसे कम वांछनीय स्थिति क्यों है?","options":["समानांतर चलने से दोनों वाहनों को काफी अधिक ईंधन खर्च करना पड़ता है, इसलिए यह एक लंबी यात्रा में आपकी परिचालन लागत बढ़ा देता है","टेक्सास का कानून विशेष रूप से दो वाहनों को नियंत्रित-पहुंच वाले हाईवे पर आसन्न लेनों में बराबर-बराबर चलने से रोकता है","वह कार संभवतः आपके किसी एक ब्लाइंड स्पॉट में बैठी है, इसलिए यदि आपको लेन बदलनी पड़े तो आप उसे देख नहीं पाएंगे और लेन बदलते समय उससे टकरा सकते हैं","किसी अन्य वाहन के बराबर बने रहना आपका समय बर्बाद करता है क्योंकि आप लेन-परिवर्तन का उपयोग आगे बढ़ने के लिए नहीं कर सकते"],"explanation":"बगल में चल रहा वाहन अक्सर साइड के ब्लाइंड स्पॉट में होता है जहाँ वह दिखाई नहीं देता, इसलिए लेन बदलते समय आप उससे टकरा सकते हैं।"},"175":{"q":"आप एक भरे हुए बॉक्स ट्रक को एक अनजान रास्ते पर चला रहे हैं, तभी आगे एक ओवरपास पर 13 फुट 2 इंच की निकासी (clearance) ऊँचाई लिखी दिखती है। संरचना से टकराए बिना उसके नीचे से सुरक्षित रूप से निकलने का निर्णय लेने के लिए, सबसे महत्वपूर्ण बात जो आपको पहले से पता होनी चाहिए, वह है:","options":["आपके दरवाज़े पर अंकित सकल वाहन भार रेटिंग (GVWR), ताकि आप पुल की निर्धारित भार सीमा से अधिक न हों","इस गति पर आपकी कुल रुकने की दूरी, जो 55 मील प्रति घंटे पर लगभग 419 फुट है","आपके वाहन की लंबाई, ताकि रुकने से पहले आप संरचना को पूरी तरह पार कर सकें","आपके भरे हुए वाहन की ऊँचाई, जिसमें ऊपर लगा कोई भी माल या उपकरण शामिल है"],"explanation":"पुल पर दर्शाई गई ऊँचाई सीमा से तुलना करने के लिए आपको छत पर रखे माल या उपकरण सहित अपने लदे वाहन की वास्तविक ऊँचाई पता होनी चाहिए।"},"176":{"q":"आप 53 फुट (16 मीटर) लंबा ट्रैक्टर-ट्रेलर चला रहे हैं और आपको एक शहरी सड़क से एक संकरी बगल वाली सड़क पर दाएं मुड़ना है। मोड़ के पास पहुंचते समय आपको एहसास होता है कि मोड़ आपकी अपेक्षा से अधिक तीखा है। इस मोड़ को पूरा करने के लिए पर्याप्त जगह बनाए रखने का सबसे सुरक्षित तरीका क्या है?","options":["पहुंचते समय अपनी सही लेन में रहें, फिर मोड़ को पूरा करते समय चौड़ा मुड़ें ताकि ट्रेलर (जिसके पिछले पहिए अंदर की ओर खिंचते हैं) कोने को साफ निकाल सके, और ट्रेलर के पिछले हिस्से को हर समय कर्ब के पास बनाए रखें","पहले बाईं लेन में जाएं और मोड़ जल्दी शुरू करें ताकि ट्रेलर का पिछला हिस्सा कोने को कसकर काटे और कर्ब के पास बना रहे","मोड़ के दौरान गति बढ़ाएं ताकि आप चौराहे को कम समय तक रोकें और उसे जल्दी खाली कर दें","ट्रक को हर समय दाएं कर्ब से सटाकर रखें ताकि कोई अन्य वाहन आपके दाईं ओर की जगह में घुस न सके"],"explanation":"चूँकि ट्रेलर के पिछले पहिये अंदर की ओर कटते हैं, मोड़ के पास अपनी लेन में रहें और मोड़ पूरा करते समय चौड़ा मुड़ें, ट्रेलर का पिछला हिस्सा कर्ब के पास रखें।"},"177":{"q":"आप पूरी तरह लदे हुए संयुक्त वाहन में एक स्टॉप साइन पर रुके हैं, एक व्यस्त दो-लेन वाले राजमार्ग को पार करने की प्रतीक्षा कर रहे हैं जहाँ दोनों दिशाओं में यातायात 55 मील प्रति घंटे की गति से चल रहा है। आड़े यातायात में एक खाली जगह (गैप) खुल रही है। चूँकि आपका रिग भारी है और धीरे-धीरे गति पकड़ता है, बाहर निकलने का निर्णय लेने से पहले उस गैप को आपको क्या करने देना चाहिए?","options":["अपने अगले बंपर को नज़दीकी किनारे से थोड़ा आगे ले जाना ताकि सामने से आने वाले चालक आपको देखकर धीमे हो जाएँ","अगला वाहन आप तक पहुँचने से पहले अपने पूरे वाहन के साथ सड़क को पूरी तरह पार कर लेना, या यातायात की गति तक पहुँच जाना","चौराहे के बीच तक पहुँचकर दूसरी लेन का आकलन करने के लिए पूरी तरह रुक जाना","लेन में घुसकर इंजन चालू रखते हुए बस इतनी देर रुकना कि आने वाला चालक लेन बदलकर आपके चारों ओर से निकल जाए"],"explanation":"ऐसा अंतराल चुनें जो आ रहे वाहन के पहुँचने से पहले आपके पूरे वाहन को पार कराने या ट्रैफ़िक की गति तक पहुँचने के लिए पर्याप्त बड़ा हो।"},"178":{"q":"दोपहर के भारी यातायात के दौरान आप अपने ट्रैक्टर-ट्रेलर को एक व्यस्त अंतरराज्यीय राजमार्ग पर मिला रहे हैं। यात्री कारों की एक कतार लगातार आपके दाहिने ओर के साथ बहती रहती है, आपके पिछले पहियों के पास टिकी रहती है जहाँ आपके दर्पण आपको लगभग कुछ नहीं दिखाते। कई चालक आपके ट्रेलर के बगल और पीछे के इस खाली कोने में आराम से जमे हुए लगते हैं। अपने वाहन के चारों ओर इन अंध-क्षेत्रों ('No-Zones') के संबंध में, कौन सा तरीका सुरक्षित वाणिज्यिक ड्राइविंग अभ्यास को सबसे अच्छी तरह दर्शाता है?","options":["अंध-क्षेत्रों को सामान्य यात्रा लेन मानें और कारों को वहाँ रहने दें, क्योंकि उन्होंने स्वयं वहाँ रहना चुना और जिम्मेदारी उनकी है","कारों को दाहिने-पिछले अंध-क्षेत्र से बाहर धकेलने के लिए तेज़ी से गति बढ़ाएँ, क्योंकि उस कोने को जल्दी खाली करना हमेशा सबसे सुरक्षित उपाय होता है","यह पहचानें कि आप अंध-क्षेत्रों में वाहनों को नहीं देख सकते और अपनी ड्राइविंग को इस तरह प्रबंधित करें कि जब भी संभव हो उन क्षेत्रों को यातायात से मुक्त रखें","बदले में स्वयं धीरे-धीरे कारों के अंध-क्षेत्रों में चले जाएँ ताकि जोखिम आपके और चार-पहिया चालकों के बीच बराबर बँट जाए"],"explanation":"नो-ज़ोन (ब्लाइंड स्पॉट) में वाहन दिखाई नहीं देते, इसलिए अपनी गति, लेन स्थिति और दूरी संभालें ताकि वे क्षेत्र ट्रैफ़िक से खाली रहें।"},"179":{"q":"आप पूरी तरह लदे एक संयोजन वाहन (कॉम्बिनेशन) को दाहिनी लेन में चलाते हुए एक लंबी, तीव्र चढ़ाई वाली ढलान पर पहुँचते हैं। चढ़ाई के दौरान आपका इंजन जोर लगा रहा है और आपकी गति लगातार निर्धारित सीमा से काफी नीचे गिरती जा रही है, जबकि आपके पीछे तेज़ कारें और हल्के वाहन इकट्ठा होने लगते हैं। इस चढ़ाई पर अपने ट्रक को संभालने का सबसे अच्छा तरीका कौन-सा है?","options":["सबसे बायीं लेन में चले जाएँ ताकि आपके पीछे के धीमे वाहन बिना लेन बदले आपको दाहिनी ओर से पार कर सकें","गियर कम करके तेज़ी से गति बढ़ाएँ ताकि आप निर्धारित सीमा पर गति बनाए रखें और पीछे के तेज़ यातायात में बाधा न डालें","गति बनाए रखें लेकिन दाहिनी पटरी (शोल्डर) पर ले जाकर थोड़ी देर रुक जाएँ ताकि वाहनों की कतार निकल जाए, फिर आगे बढ़ें","यह स्वीकार करें कि भारी भार आपको धीमा कर देगा, दाहिनी लेन में बने रहें, और तेज़ यातायात को अपनी बायीं ओर से आगे निकलने दें"],"explanation":"भारी भार खड़ी चढ़ाई पर आपको स्वाभाविक रूप से धीमा कर देता है, इसलिए दाहिनी लेन में रहें और तेज़ ट्रैफ़िक को बाईं ओर से निकलने दें।"},"180":{"q":"आप मध्यम यातायात में तीन लेन वाले राजमार्ग पर 53 फुट लंबा ट्रैक्टर-ट्रेलर चला रहे हैं। आपके बाईं ओर वाली लेन में एक कार साथ-साथ चल रही है, और आपके दाईं ओर एक ऑन-रैंप वाहनों को फ्रीवे पर ला रहा है। आप एक साथ दोनों ओर जगह नहीं छोड़ सकते। इस स्थिति में आपके बगल की जगह को सबसे अच्छी तरह कौन सी क्रिया प्रबंधित करती है?","options":["अपने वाहन को अपनी लेन के बीच में रखें ताकि अपनी सारी जगह एक ओर देने के बजाय दोनों ओर जगह का एक कुशन बना रहे","अपने ट्रेलर और रैंप से आने वाले यातायात के बीच अधिकतम दूरी बनाने के लिए बाईं लेन की रेखा से सटकर चलें","थोड़ी देर के लिए बाईं लेन में जाकर लेन रेखा पर चलें ताकि कोई वाहन आपके ब्लाइंड स्पॉट के बगल में न आ सके","जब तक रैंप का यातायात मिल न जाए तब तक दाएं किनारे (शोल्डर) पर चलें, फिर अपनी लेन में लौट आएं"],"explanation":"अपने वाहन को लेन के बीच में रखने से जब खतरे एक साथ बाएँ और दाएँ से आएँ, तब दोनों ओर जगह का बफर बना रहता है।"},"181":{"q":"आप भारी रुक-रुक कर चलने वाले यातायात में एक रेलवे क्रॉसिंग के पास पहुँच रहे हैं। क्रॉसिंग पर न कोई गेट है और न ही चमकती चेतावनी बत्तियाँ, और आगे के वाहन धीरे-धीरे रेंगते हुए आगे बढ़ रहे हैं। आपका 73 फुट लंबा कॉम्बिनेशन वाहन पटरियों तक पहुँचने वाला अगला वाहन है। पटरियों को पार करना है या नहीं, यह तय करने का सबसे सही तरीका क्या है?","options":["पटरियों पर आगे बढ़कर वहीं रुककर इंतज़ार करें, क्योंकि न तो कोई गेट है और न ही ट्रेन की चेतावनी देने वाला कोई सिग्नल","तब तक प्रतीक्षा करें जब तक आगे इतना बड़ा अंतराल न हो कि आप बिना रुके पूरी क्रॉसिंग पार कर सकें, अपने वाहन की पूरी लंबाई और लगभग 15 फुट की अतिरिक्त जगह छोड़ते हुए","आगे का वाहन हटते ही क्रॉसिंग पर बढ़ जाएँ, क्योंकि यातायात का प्रवाह बनाए रखना प्राथमिकता है","पार करना शुरू करें और यदि यातायात रुक जाए तो जल्दी निकलने के लिए पटरियों पर ही नीचे के गियर में बदल लें"],"explanation":"पटरियों को तभी पार करना शुरू करें जब अंतराल बिना रुके उन्हें पूरी तरह पार करने दे, अपने पूरे वाहन की लंबाई और लगभग 15 फीट जगह को ध्यान में रखते हुए।"},"182":{"q":"आप एक सूखे दो-लेन वाले राजमार्ग पर भरा हुआ संयोजन वाहन (कॉम्बिनेशन व्हीकल) चला रहे हैं और आगे एक तीखा मोड़ (कर्व) चिह्नित देखते हैं। आप इस समय लगभग कानूनी गति से चल रहे हैं और महसूस करते हैं कि इस मोड़ के लिए आपकी मौजूदा गति शायद थोड़ी ज़्यादा है। मोड़ को सुरक्षित रूप से पार करने के लिए आपको अपनी गति और ब्रेकिंग के बारे में क्या करना चाहिए?","options":["मोड़ तक अपनी गति बनाए रखें, फिर मोड़ के बीच में, जहाँ वह सबसे तीखा है, ज़ोर से ब्रेक लगाएँ।","मोड़ से बाहर निकलने तक प्रतीक्षा करें, फिर अगले मोड़ के लिए तैयार रहने हेतु गति कम करें।","मोड़ में प्रवेश करने से पहले सुरक्षित गति तक धीमे हो जाएँ, फिर वाहन को स्थिर रखने के लिए मोड़ के दौरान धीरे-धीरे गति बढ़ाएँ।","मोड़ में स्थिर गति से प्रवेश करें और ट्रक को नियंत्रित करने के लिए पूरे मोड़ के दौरान हल्के, स्थिर ब्रेक दबाव पर निर्भर रहें।"],"explanation":"मोड़ में घुसने से पहले सुरक्षित गति तक धीमा करें, फिर उसमें हल्के से गति बढ़ाएँ, क्योंकि मोड़ के अंदर ब्रेक लगाने से फिसलन या पलटना हो सकता है।"},"183":{"q":"आप ग्रामीण दो-लेन राजमार्ग पर एक भार ढो रहे हैं, तभी लगातार बारिश शुरू हो जाती है और सड़क चमकदार और गीली हो जाती है। यातायात 55 मील प्रति घंटे की निर्धारित सीमा पर चल रहा है, और एक लंबे चौड़े मोड़ पर आपको स्टीयरिंग थोड़ा हल्का महसूस होता है। घटी हुई पकड़ (ट्रैक्शन) के लिए अकेला सबसे सुरक्षित कदम कौन सा है?","options":["55 मील प्रति घंटे बनाए रखें लेकिन भरपाई के लिए अपनी अनुसरण दूरी बढ़ाएँ, क्योंकि निर्धारित सीमा अभी भी कानूनी है","ड्राइव एक्सल पर वज़न बनाए रखने और पकड़ बेहतर करने के लिए मोड़ में हल्का त्वरण करें","अपनी गति बनाए रखें और यह जाँचने के लिए कि कितनी पकड़ बची है, ब्रेक को तेज़ी से बार-बार दबाएँ","अपनी गति निर्धारित सीमा से नीचे कम करें क्योंकि गीली सड़क पकड़ घटाती है और रुकने की दूरी बढ़ाती है"],"explanation":"सुरक्षित गति पकड़ (ट्रैक्शन) तय करती है, चिह्नित सीमा नहीं; गीली सड़क पकड़ घटाती और रुकने की दूरी बढ़ाती है, इसलिए सीमा से नीचे गति रखें।"},"184":{"q":"तापमान हिमांक से ठीक नीचे है और हल्की बर्फ सड़क पर जमने लगी है। आप एक लदे हुए ट्रैक्टर-ट्रेलर को उसी हाईवे गति पर चला रहे हैं जो आपने आज पहले साफ, सूखे मौसम में रखी थी। उन सूखी परिस्थितियों की तुलना में, आपके वाहन के संचालन में सबसे महत्वपूर्ण बदलाव क्या होने की उम्मीद आपको करनी चाहिए, और क्यों?","options":["पकड़ (ट्रैक्शन) बहुत अधिक कम हो जाती है, इसलिए आपके टायर सड़क को कहीं कम पकड़ते हैं और आपको रुकने तथा मोड़ने के लिए कहीं अधिक दूरी की आवश्यकता होती है","पकड़ केवल थोड़ी सी कम होती है, इसलिए सामान्य अनुसरण दूरी और स्थिर गति बनाए रखना सुरक्षित रहने के लिए पर्याप्त होगा","पकड़ सूखी सड़क जितनी ही लगभग बनी रहती है क्योंकि लदे ट्रेलर का वजन टायरों को बर्फ पर मजबूती से दबाता है","पकड़ वास्तव में थोड़ी बेहतर हो जाती है क्योंकि बर्फ की पतली परत सतह के गड्ढों को भर देती है और टायरों को पकड़ने के लिए अधिक जगह देती है"],"explanation":"बर्फ और पाला कर्षण को बहुत घटा देते हैं, इसलिए टायरों की पकड़ कम हो जाती है और रुकने व मोड़ने के लिए कहीं अधिक दूरी चाहिए होती है।"},"185":{"q":"आपने अभी-अभी डॉक पर अपना पूरा भार उतार दिया है और अब पूरी तरह खाली ट्रेलर के साथ यार्ड की ओर लौट रहे हैं। गीली सड़क पर एक एसयूवी आपके सामने आ जाती है और आपको ज़ोर से ब्रेक लगाना पड़ता है। पहले जब आप पूरी तरह लदे हुए थे उसकी तुलना में, अब जब ट्रक खाली है तो रुकने के लिए वास्तव में अधिक दूरी की ज़रूरत क्यों पड़ सकती है?","options":["खाली ट्रक भारी होता है, इसलिए उसकी बढ़ी हुई गति-शक्ति (मोमेंटम) उसे रुकने से पहले और आगे ले जाती है","चूँकि कम वज़न टायरों को सड़क पर हल्के से दबाता है, खाली ट्रक की पकड़ (ट्रैक्शन) कम होती है, इसलिए पहिये अधिक आसानी से लॉक हो जाते हैं और ब्रेकिंग दूरी बढ़ जाती है","खाली ट्रेलर ऊँचे चलते हैं, जिससे गुरुत्व केंद्र ऊपर उठता है और ब्रेकिंग दूरी बढ़ जाती है","खाली ट्रक में ब्रेक अधिक ठंडे चलते हैं और फीके पड़ जाते हैं, जिससे 55 मील प्रति घंटे पर रुकने की दूरी में लगभग 60 फीट जुड़ जाते हैं"],"explanation":"खाली ट्रक में टायरों पर बहुत कम भार पड़ता है, इसलिए पकड़ कम होती है, पहिए जल्दी जाम हो जाते हैं और ब्रेकिंग दूरी बढ़ जाती है।"},"186":{"q":"आप पूरी तरह लदे हुए ट्रेलर के साथ एक लंबी, खड़ी पहाड़ी ढलान पर नीचे उतर रहे हैं। आधी ढलान पर आप देखते हैं कि अपनी गति बनाए रखने के लिए ही आप लगातार ब्रेक पेडल दबाए हुए हैं, और केबिन में गर्म होने जैसी गंध आने लगी है। आपके मुख्य सर्विस ब्रेकों के साथ क्या हो रहा है और क्यों, इसका सबसे अच्छा वर्णन कौन-सा कथन करता है?","options":["गर्म होने के साथ ब्रेक अधिक रोकने की शक्ति पा रहे हैं, इसलिए बाकी की ढलान में आप उन्हें सुरक्षित रूप से और जोर से दबा सकते हैं।","ब्रेक लगातार हवा के प्रवाह से खुद को ठंडा कर रहे हैं, इसलिए पेडल पर स्थिर दबाव बनाए रखना ही गति नियंत्रित करने का सही मुख्य तरीका है।","ब्रेक अधिक गर्म होकर अपनी क्षमता खोने (ब्रेक फेड) लगे हैं, इसीलिए कम गियर में इंजन ब्रेकिंग मुख्य नियंत्रण होना चाहिए और ब्रेक केवल एक सहायक।","ब्रेक ट्रेलर के पहियों को लॉक करने वाले हैं, इसलिए ट्रेलर को जैकनाइफ होने से रोकने के लिए आपको पेडल को तेजी से पंप करना चाहिए।"],"explanation":"लंबी ढलान पर ब्रेक गरम होकर असर खो सकते हैं, इसलिए मुख्य नियंत्रण कम गियर में इंजन ब्रेकिंग से करें और ब्रेक का उपयोग केवल सहायक के रूप में करें।"},"187":{"q":"आप एक भारी, पूरी तरह लदे हुए ट्रेलर को खींचते हुए एक लंबी, तीव्र पहाड़ी ढलान की चोटी पर हैं। बारिश हो रही है और ढलान के लगभग बीच में सड़क तीखा मोड़ लेती है। ब्रेक छोड़कर नीचे उतरना शुरू करने से पहले, आपको नीचे जाने के लिए एक सुरक्षित गति तय करनी होगी। निम्नलिखित में से कौन सा सही ढंग से बताता है कि आपकी सुरक्षित उतराई गति किस पर निर्भर होनी चाहिए?","options":["केवल ढलान की तीव्रता पर, क्योंकि गुरुत्वाकर्षण ही एकमात्र कारक है जो यह नियंत्रित करता है कि ट्रक नीचे की ओर कितनी तेज़ी से लुढ़केगा","मुख्य रूप से चोटी पर इंजन की RPM पर, क्योंकि टैकोमीटर की रीडिंग का मिलान किसी भी ढलान के लिए सही गति निर्धारित करता है","लगभग पूरी तरह से निर्धारित गति सीमा पर, क्योंकि वह संख्या विशेष रूप से उस ढलान पर पूरी तरह लदे वाणिज्यिक वाहनों के लिए तय की गई है","आपके वाहन और माल के कुल वजन, ढलान की लंबाई और तीव्रता, सड़क की स्थिति, और मौसम पर"],"explanation":"उतराई की सुरक्षित गति वाहन व माल के कुल वजन, ढलान की लंबाई और तीव्रता, सड़क की स्थिति और मौसम पर निर्भर करती है।"},"188":{"q":"आप पूरी तरह लदे ट्रेलर के साथ एक लंबी, खड़ी पहाड़ी ढलान से नीचे उतरने वाले हैं। आप उतरते समय ब्रेक को ज़्यादा गरम किए और उनकी पकड़ खोए बिना अपनी गति नियंत्रित करना चाहते हैं। कौन-सा गियर चुनना है, यह तय करने का सबसे अच्छा तरीका कौन-सा है?","options":["वही कम (लो) गियर इस्तेमाल करें जो आपको इस ढलान पर चढ़ने के लिए चाहिए होता, और उसे नीचे उतरना शुरू करने से पहले ही लगा लें।","चढ़ाई वाले गियर से बहुत ऊँचे गियर में डालें ताकि उतराई पर इंजन पर ज़ोर कम पड़े।","ट्रांसमिशन को न्यूट्रल में डालें और गति बनाए रखने के लिए लगातार ब्रेक दबाव पर निर्भर रहें।","अपने सामान्य हाईवे गियर में ही रहें और गियर तभी घटाएँ जब ब्रेक की पकड़ कमज़ोर पड़ने लगे।"],"explanation":"उसी कम गियर का चयन करें जो ढलान चढ़ने के लिए चाहिए होता, और उतरना शुरू करने से पहले ही उसे लगा लें।"},"189":{"q":"सुबह का समय है और बाहरी तापमान मीटर हिमांक से ठीक नीचे (लगभग 30 F / -1 C) दिखा रहा है। जिस दो-लेन राजमार्ग पर आप गाड़ी चला रहे हैं वह पूरी तरह सूखा दिख रहा है, और पिछले एक घंटे से आपको पकड़ (ट्रैक्शन) की कोई समस्या नहीं हुई है। अब आप एक नदी घाटी के ऊपर बने एक लंबे ओवरपास के पास पहुँच रहे हैं। ओवरपास तक पहुँचते समय निम्नलिखित में से कौन-सी सबसे सुरक्षित धारणा है?","options":["चूँकि सड़क की सतह सूखी रही है और आपको अच्छी पकड़ मिली है, इसलिए ओवरपास का डेक उस सड़क से ज़्यादा फिसलन भरा नहीं होगा जिसे आपने अभी छोड़ा है","भले ही बाकी सड़क साफ हो, ओवरपास बर्फीला हो सकता है, क्योंकि पुल और ओवरपास सड़क के अन्य हिस्सों से पहले जम जाते हैं","ओवरपास सबसे आखिर में जमेगा, इसलिए यदि आपको गति कम करनी हो तो ब्रेक लगाने या निचले गियर में बदलने के लिए यह सबसे सुरक्षित जगह है","ओवरपास सामान्य सड़क से पहले नहीं जमते, इसलिए आपको बर्फ पर ध्यान केवल तब देना है जब दोपहर में हवा गर्म हो जाए"],"explanation":"पुल और ओवरपास सड़क के बाकी हिस्सों से पहले जम जाते हैं, इसलिए बाकी सड़क साफ होने पर भी ओवरपास पर बर्फ हो सकती है।"},"190":{"q":"लंबे सूखे के बाद अभी-अभी लगातार बारिश शुरू हुई है, और राजमार्ग पर पुराने तेल और धूल के ऊपर पानी की एक पतली परत जमा हो रही है। यातायात कम है, इसलिए आपको तेज़ गति बनाए रखने का लालच होता है। अपने टायरों की सड़क पर पकड़ बनाए रखने और हाइड्रोप्लेनिंग से बचने के लिए, इन परिस्थितियों में गति को उससे नीचे लाने हेतु, आपको समझना चाहिए कि हाइड्रोप्लेनिंग लगभग किस गति पर शुरू हो सकती है?","options":["हाइड्रोप्लेनिंग लगभग 70 मील प्रति घंटे तक पहुँचने से पहले शुरू नहीं हो सकती, इसलिए बारिश में उससे कम कोई भी राजमार्ग गति सुरक्षित है।","हाइड्रोप्लेनिंग केवल बहुत कम गति पर, लगभग 5 मील प्रति घंटे पर ही चिंता का विषय बनती है, इसलिए यह मुख्यतः पार्किंग स्थल की समस्या है।","हाइड्रोप्लेनिंग लगभग 30 मील प्रति घंटे जितनी कम गति पर भी शुरू हो सकती है, इसलिए इस गीली, फिसलन भरी परत पर आपको अपनी गति उससे नीचे कर देनी चाहिए।","हाइड्रोप्लेनिंग तब तक शुरू नहीं होगी जब तक आप लगभग 90 मील प्रति घंटे से ऊपर न हों, जो किसी भी कानूनी ट्रक गति से कहीं अधिक है।"],"explanation":"गीली, फिसलन भरी परत पर हाइड्रोप्लेनिंग लगभग 30 मील/घंटा जैसी कम गति पर ही शुरू हो सकती है, इसलिए अपनी गति उससे नीचे रखें।"},"191":{"q":"तेज़ गर्मी की मूसलाधार बारिश के दौरान आप टेक्सास के एक इंटरस्टेट हाईवे पर हाईवे की गति से एक लदा हुआ ट्रेलर चला रहे हैं। चलने वाली लेन के पहिया-निशानों में पानी जमा हो गया है। अचानक स्टीयरिंग हल्का और ढीला महसूस होता है, आपके अगले टायर सड़क से संपर्क खोते हुए लगते हैं, और एक्सेलरेटर न बदलने के बावजूद आपका स्पीडोमीटर कांपता है। आपको एहसास होता है कि आप हाइड्रोप्लेन करने लगे हैं। सही पहला कदम क्या है?","options":["गति को जितनी जल्दी हो सके कम करने के लिए ब्रेक पेडल को मज़बूती से दबाकर रखें, क्योंकि गीली सड़क पर सबसे ज़्यादा मायने रुकने की दूरी रखती है","टायरों को बेहतर पकड़ वाली सड़क पर वापस लाने के लिए लेन के ऊँचे, सूखे बीच की ओर तेज़ी से स्टीयरिंग घुमाएँ","अपनी मौजूदा गति बनाए रखें लेकिन इंजन ब्रेकिंग के लिए नीचे गियर डालें, क्योंकि गीली सतह पर ड्राइव पहियों की पकड़ अब भी बनी हुई है","एक्सेलरेटर से दबाव हटा दें, स्टीयरिंग व्हील को सीधा रखें, और वाहन को तब तक धीमा होने दें जब तक टायर सड़क से मज़बूत संपर्क दोबारा न पा लें"],"explanation":"हाइड्रोप्लेनिंग के समय एक्सेलेरेटर छोड़ें, स्टीयरिंग सीधा रखें और वाहन को धीमा होने दें जब तक टायर फिर से सड़क पर मजबूत पकड़ न बना लें।"},"192":{"q":"पश्चिमी टेक्सास में जुलाई का मध्य है और गर्मी से सड़क झिलमिला रही है। आप दो घंटे से हाईवे गति पर चल रहे हैं और अनिवार्य माल एवं बंधन जाँच के लिए किनारे रुकते हैं। रुकने के दौरान, इन परिस्थितियों में टायर की कौन-सी स्थिति देखना सबसे महत्वपूर्ण है?","options":["पिछले ड्राइव टायरों पर 4/32 इंच से कम घिसा हुआ ट्रेड","साइडवॉल पर फीके पड़े अक्षर और केसिंग पर गायब ब्रांड के निशान","थोड़ा कम दबाव जिसे आपको अभी ठंडे-इन्फ्लेशन मान तक भर देना चाहिए","गर्म होते टायर और ठंडी सेटिंग से ऊपर बढ़ा दबाव, जो फटने के जोखिम का संकेत देता है"],"explanation":"गर्म मौसम में उन टायरों पर नज़र रखें जो गर्म हो रहे हों और जिनका दबाव ठंडी सेटिंग से ऊपर चढ़ गया हो, क्योंकि अधिक गर्म और अधिक दबाव वाले टायर फटने की आशंका रखते हैं।"},"193":{"q":"आपकी पाली की शुरुआत में तापमान 28 F (शून्य से 2 डिग्री सेल्सियस नीचे) है और रात की गीली बर्फ आपके ट्रैक्टर पर जम गई है। यात्रा-पूर्व जाँच के दौरान आपको विंडशील्ड के निचले आधे हिस्से पर बर्फ की पतली परत और दोनों साइड मिरर पर जमी बर्फ की पपड़ी मिलती है। आप पहले से ही समय से पीछे चल रहे हैं। राजमार्ग पर निकलने से पहले टेक्सास DPS आपसे क्या करने की अपेक्षा करता है?","options":["गाड़ी चलाने से पहले सारी बर्फ और जमी हुई बर्फ को पूरी तरह हटा दें ताकि विंडशील्ड और दोनों मिरर पूरी तरह साफ हो जाएँ","केवल चालक की ओर का वह हिस्सा साफ करें जिससे आप देखते हैं और मिरर छोड़ दें, क्योंकि चलने पर डीफ्रॉस्टर उन्हें पिघला देगा","विंडशील्ड पर देखने के लिए एक छोटा हिस्सा खुरच लें और बर्फीले मिरर के बजाय बैकिंग कैमरे और कंधे के ऊपर देखने पर भरोसा करें","बर्फ की परत को वैसे ही रहने दें क्योंकि 28 F पर तापमान उस बिंदु से ऊपर है जहाँ बर्फ ट्रैक्शन को प्रभावित करती है, और कम गति पर चलाएँ"],"explanation":"गाड़ी चलाने से पहले सारी बर्फ और जमी हुई बर्फ पूरी तरह हटा दें ताकि विंडशील्ड और दोनों शीशे पूरी तरह साफ हों।"},"194":{"q":"एक नम सुबह में तापमान ठीक हिमांक से थोड़ा नीचे है, और अपने पूर्व-यात्रा निरीक्षण के दौरान आपके ट्रैक्टर के नीचे की सड़क बर्फीली नहीं, बल्कि सिर्फ गीली और चमकदार दिखती है। राजमार्ग पर चढ़ते समय आप महसूस करते हैं कि स्टीयरिंग हल्का हो गया है और ट्रक थोड़ा फिसल रहा है। जिस 'काली बर्फ' पर आप संभवतः चढ़ गए हैं, वह ठीक इसी तरह की स्थिति में इतनी खतरनाक क्यों है?","options":["यह एक स्पष्ट रूप से खुरदरी, पपड़ीदार सतह बनाती है, इसलिए आप इसे समय रहते देख सकते हैं और उस तक पहुँचने से पहले ज़ोर से ब्रेक लगा सकते हैं","यह एक पतली, पारदर्शी परत है जो सड़क को सिर्फ गीली दिखाती है, इसलिए आप इसे देख नहीं पाते और जब तक पकड़ खो नहीं देते तब तक आपको पता ही नहीं चलता कि सतह जमी हुई है","यह केवल पहाड़ियों की चोटियों पर जमती है, इसलिए खतरा मार्ग के छोटे, अनुमान-योग्य हिस्सों तक ही सीमित है","यह हमेशा एक मोटी सफेद परत के रूप में दिखती है, जिससे आपको पहले से गति कम करने के लिए भरपूर चेतावनी मिल जाती है"],"explanation":"ब्लैक आइस एक पतली, पारदर्शी परत है जो सड़क को केवल गीली दिखाती है, इसलिए वह दिखती नहीं और कर्षण खोने तक सतह के जमे होने का पता नहीं चलता।"},"195":{"q":"भोर के तुरंत बाद आप एक लदे हुए ट्रेलर को एक नीची नदी घाटी से खींच रहे हैं, जहां घने, छितरे हुए कोहरे ने दृश्यता को लगभग आपके वाहन की लंबाई तक घटा दिया है। आप चलती लेन में रुकने के बजाय धीरे-धीरे आगे बढ़ते रहने का निर्णय लेते हैं। कौन सा प्रकाश विकल्प आपको सबसे अच्छी दृश्यता देता है और आपको दूसरों के लिए सबसे अधिक दृश्यमान बनाता है?","options":["हाई बीम पर स्विच करें, क्योंकि तेज़ रोशनी आगे के कोहरे में अधिक गहराई तक कटेगी","अपनी हेडलाइट बंद कर दें और चकाचौंध से बचने के लिए केवल चार-तरफा हैज़र्ड फ्लैशर चलाएं","अपनी लो बीम का उपयोग करें (यदि उपलब्ध हो तो फॉग लाइट के साथ), क्योंकि हाई बीम कोहरे से परावर्तित होकर रोशनी को आपकी ओर वापस लौटाती है","हाई बीम चालू रखें लेकिन उन्हें केवल तभी मद्धम करें जब आप सामने से आ रहे वाहन के 500 फ़ीट के भीतर हों"],"explanation":"कोहरे में लो बीम का उपयोग करें क्योंकि हाई बीम हवा में मौजूद पानी की बूंदों से परावर्तित होकर चकाचौंध वापस आपकी ओर भेजती है और दृश्यता घटाती है।"},"196":{"q":"ग्रामीण दो-लेन राजमार्ग पर बिना किसी स्ट्रीटलाइट के एक अंधेरी, चांद रहित रात है। आपकी लो बीम आगे लगभग 250 फीट सड़क को रोशन करती हैं। सुरक्षित रूप से चलाने के लिए, आपको अपनी गति कैसे चुननी चाहिए?","options":["दिन के निर्धारित गति सीमा का पालन करें, क्योंकि सीमा सड़क के लिए तय की गई है और अंधेरा होने के बाद नहीं बदलती","ऐसी गति चुनें जिस पर आपकी कुल रुकने की दूरी आपकी हेडलाइट द्वारा दिखाई गई दूरी से दोगुनी हो, जिससे आपको सुरक्षा का अंतर मिले","स्थिर 55 mph बनाए रखें और आगे किसी भी चीज़ पर समय रहते प्रतिक्रिया देने के लिए अपनी हाई बीम पर भरोसा करें","इतनी धीमी गति से चलाएं कि आप अपनी हेडलाइट से रोशन दूरी के भीतर पूरी तरह रुक सकें"],"explanation":"अपनी हेडलाइट की रोशनी से तेज़ कभी न चलाएं; गति इतनी कम रखें कि हेडलाइट जितनी दूरी रोशन करती है उसी के भीतर पूरी तरह रुक सकें।"},"197":{"q":"देर दोपहर में आप एक ग्रामीण दो-लेन राजमार्ग पर एक लदा हुआ संयोजन वाहन चला रहे हैं, तभी अचानक भारी मूसलाधार बारिश आपकी दृश्यता को कुछ सौ फ़ीट तक घटा देती है। यातायात कम है, फिर भी सामने से कभी-कभी वाहन आते रहते हैं, और आप सड़क देखना भी चाहते हैं और दिखना भी चाहते हैं। भारी बारिश की इन परिस्थितियों के लिए हेडलाइट की कौन-सी सेटिंग सबसे अच्छी है?","options":["लो बीम, क्योंकि वे दूसरों को आपको देखने में मदद करती हैं और भारी बारिश से चकाचौंध को वापस परावर्तित नहीं करतीं","हाई बीम, क्योंकि भारी बारिश के आर-पार देखने के लिए उनकी अधिक दूरी तक रोशनी ज़रूरी है","हेडलाइट बंद और केवल पार्किंग लाइट चालू, ताकि गीली सड़क की सतह ध्यान भटकाने वाले परावर्तन न बनाए","सामने से आते यातायात को खराब दृश्यता की चेतावनी देने के लिए हाई बीम को बार-बार जलाना-बुझाना"],"explanation":"भारी बारिश में लो बीम का उपयोग करें ताकि अन्य चालक आपको देख सकें और हाई बीम से बारिश पर परावर्तित होकर बनने वाली चकाचौंध से बचा जा सके।"},"198":{"q":"टेक्सास में गर्मी की लहर के दौरान दोपहर का समय है और सड़क की सतह का तापमान पूरे दिन बढ़ता रहा है। एक छायादार चौराहे के लिए गति धीमी करते समय, आप आगे चलने वाली लेन में डामर की दरारों से रिसते हुए तारकोल की गहरी, चमकदार धारियाँ देखते हैं। बहुत गर्म मौसम सड़क की सतह को कैसे प्रभावित करता है, इसके आधार पर, इन हिस्सों से गुजरते समय आपको किस खतरे के लिए सबसे अधिक तैयार रहना चाहिए?","options":["तारकोल सख्त होकर खुरदरी, अधिक पकड़ वाली सतह बन जाएगा, इसलिए आप सामान्य से अधिक जोर से ब्रेक लगा सकते हैं","रिसता हुआ तारकोल सड़क की सतह को फिसलन भरा बना सकता है, इसलिए गति कम करें और उस पर से गुजरते समय जोर से ब्रेक लगाने या तीखे मोड़ से बचें","ये हिस्से ब्लैक आइस बना रहे हैं, इसलिए जो सतह गीली दिखती है वह वास्तव में जमी हुई है","गर्मी से टायर का दबाव इतना बढ़ जाएगा कि तारकोल पर पकड़ बेहतर हो जाती है, इसलिए गति बदलने की जरूरत नहीं है"],"explanation":"बहुत गर्म मौसम में तारकोल सतह पर आकर फिसलन भरा हो जाता है, इसलिए गति कम करें और उस पर तेज़ ब्रेक या तीखा स्टीयरिंग न करें।"},"199":{"q":"एक तेज हवा वाली, झोंकेदार दोपहर है और आप एक खुले इंटरस्टेट खंड पर एक ऊंचे, हल्के लदे बॉक्स ट्रेलर के साथ निकलने वाले हैं। एक सहकर्मी कहता है कि चिंता मत करो क्योंकि एक खाली, ऊंचा ट्रेलर हवा में खुद को बेहतर 'संभाल लेता' है। यह देखते हुए कि तेज बगल की हवाएं एक ऊंचे ट्रेलर पर कैसे असर डालती हैं, अपने वाहन को नियंत्रित करने के बारे में आपको वास्तव में क्या अपेक्षा करनी चाहिए?","options":["ऊंचे ट्रेलर को नियंत्रित करना आसान होगा, क्योंकि इसकी ऊंचाई इसे हवा के खिलाफ जमाए रखती है","ऊंचा ट्रेलर तेजी से रुकेगा, क्योंकि हवा आपकी आगे की गति के खिलाफ धक्का देकर मदद करती है","ऊंचे ट्रेलर को नियंत्रित करना कठिन होगा, क्योंकि तेज हवाएं इसकी बड़ी, ऊंची सतह पर धक्का देती हैं","ऊंचा ट्रेलर कम ईंधन खर्च करेगा, क्योंकि हवा आपके ड्राइव एक्सल पर भार कम कर देती है"],"explanation":"तेज़ हवा ऊँचे ट्रेलर की बड़ी, ऊँची साइड सतह पर दबाव डालती है, जिससे वाहन नियंत्रित करना कठिन हो जाता है, खासकर जब वह खाली या हल्के भार में हो।"},"200":{"q":"तापमान हिमांक से थोड़ा नीचे है और हल्की बारिश हो रही है। एक छायादार पुल के पास पहुँचते समय आगे की सड़क अचानक गीली और चमकदार दिखती है, जबकि आपके शीशे और एंटीना पर बर्फ जमने लगी है। अपने भरे हुए ट्रक को इस हिस्से से निकालने का सबसे सुरक्षित तरीका कौन सा है?","options":["अपनी मौजूदा गति बनाए रखें लेकिन यह जाँचने के लिए कि सतह पर कितनी पकड़ बची है, अभी ब्रेक को कुछ बार दबाएँ-छोड़ें","गति बनाए रखें और बस अनुसरण दूरी बढ़ा दें, क्योंकि पुल खुली सड़क की तुलना में जल्दी पिघलते हैं","सतह के और सख्त जमने से पहले पुल को जल्दी पार करने के लिए धीरे-धीरे गति बढ़ाएँ","पुल से काफी पहले अपनी गति कम करें और स्टीयरिंग, ब्रेक तथा एक्सेलरेटर का सुचारू, कोमल उपयोग करें"],"explanation":"शीशों और एंटीना पर बर्फ के साथ गीली, चमकदार सतह ब्लैक आइस का संकेत है और पुल पहले जमते हैं, इसलिए पहले से गति कम करें और सहज, कोमल नियंत्रण रखें।"},"201":{"q":"एक चांद रहित रात है और आप एक खराब रोशनी वाले ट्रक स्टॉप से ग्रामीण दो-लेन राजमार्ग पर 4 घंटे की यात्रा के लिए निकलने वाले हैं। पैदल निरीक्षण के दौरान आप देखते हैं कि दोनों हेडलाइट के शीशों पर सड़क की गंदगी और सूखे कीड़ों की परत जमी है, जिससे उनकी चमक स्पष्ट रूप से कम हो गई है। निकलने से पहले सबसे अच्छा कदम क्या है?","options":["हेडलाइट के शीशों को साफ करें ताकि वे पूरी रोशनी फेंकें और आप समय पर रुकने के लिए पर्याप्त दूर तक देख सकें","अभी निकल जाएं और बस अपनी गति कम कर दें ताकि चलते समय आपकी लो बीम अभी भी सड़क को रोशन करे","गंदे मंद शीशों की भरपाई के लिए पूरी यात्रा में हाई बीम चलाएं","सफाई छोड़ दें और अपना रास्ता दिखाने के लिए मार्कर और क्लीयरेंस लाइटों पर भरोसा करें"],"explanation":"गंदे हेडलाइट लेंस लो बीम की पहुँच घटा देते हैं, इसलिए उन्हें साफ करें ताकि पूरी रोशनी लौटे और आप समय पर रुकने के लिए पर्याप्त दूर तक देख सकें।"},"202":{"q":"आप एक लदे हुए ट्रेलर के साथ एक लंबी, खड़ी पहाड़ी ढलान से नीचे उतर रहे हैं। आधे रास्ते में, आप ब्रेक पेडल दबाते हैं और वह लगभग फर्श तक धँस जाता है और गाड़ी को धीमा नहीं करता, और आपको कुछ जलने की गंध आती है। आपकी गति बढ़ने लगती है। सबसे अच्छा कदम क्या है?","options":["दबाव वापस बनाने के लिए ब्रेक पेडल को ज़ोर से और तेज़ी से पंप करें, फिर मौजूदा गियर में ही लुढ़कते रहें","इंजन ब्रेकिंग से गति धीमी करने के लिए नीचे के गियर में बदलें, और अगली एस्केप रैंप (बचाव ढलान) की ओर मोड़ें","ट्रांसमिशन को बचाने के लिए न्यूट्रल में डालें और ढलान समतल होने तक ट्रक को लुढ़कने दें","तेज़ी से बाईं ओर के किनारे पर रोकें और 10, 100 और 200 फीट पर तीन परावर्तक त्रिकोण रखें"],"explanation":"ढलान पर सर्विस ब्रेक कमजोर पड़ने पर, इंजन ब्रेकिंग के लिए निचले गियर में डाउनशिफ्ट करें और सुरक्षित रूप से धीमा होने के लिए एस्केप रैंप की ओर बढ़ें।"},"203":{"q":"आप एक भरे हुए ट्रैक्टर-ट्रेलर को एक लंबी, खड़ी पहाड़ी ढलान से नीचे चला रहे हैं। ढलान शुरू करने से पहले कम गियर चुनने और हल्का, स्थिर ब्रेक लगाने के बावजूद, आपको जलने की हल्की गंध आती है और आपका ब्रेक पेडल नरम और स्पंजी महसूस होने लगता है। आगे दाईं ओर के किनारे पर आपको एक एस्केप रैंप (बचाव रैंप) का चिह्न दिखता है। इन परिस्थितियों में, उस रैंप का उपयोग कब और क्यों करना चाहिए, इसकी सही समझ क्या है?","options":["यह एक निर्धारित पुल-ऑफ है जहाँ आप रात भर पार्क कर सकते हैं और ढलान जारी रखने से पहले अधिक गर्म ब्रेक को ठंडा होने दे सकते हैं","यह खड़ी ढलानों पर रखा गया एक विश्राम क्षेत्र है ताकि थके हुए चालक लंबी उतराई पूरी करने से पहले कुछ देर रुककर आराम कर सकें","यह बेकाबू हो चुके वाहन को रोकने के लिए बनाया गया है, इसलिए यदि आपके ब्रेक फेल/फेड हो गए हैं और आप अब अपनी गति को नियंत्रित नहीं कर सकते, तो आपको ट्रक को सुरक्षित रूप से रोकने के लिए इसका उपयोग करना चाहिए","यह एक निर्धारित लेन है जहाँ वाहन के ढलान से नीचे चलते रहने के दौरान आप सुरक्षित रूप से कम गियर में बदल सकते हैं"],"explanation":"एस्केप रैंप उस बेकाबू वाहन को रोकने के लिए बनाया गया है जिसके ब्रेक फेल हो गए हों, इसलिए जब आप गति नियंत्रित न कर सकें तो ट्रक को सुरक्षित रोकने के लिए इसका उपयोग करें।"},"204":{"q":"आप एक सूखी, दो-लेन वाली सड़क पर हाईवे की गति से एक लदे हुए संयोजन वाहन को चला रहे हैं, तभी स्टीयरिंग व्हील अचानक ढीला हो जाता है और ट्रक आपके स्टीयरिंग पर सामान्य रूप से प्रतिक्रिया देना बंद कर देता है। यातायात कम है और आगे का किनारा साफ है। सबसे अच्छी पहली प्रतिक्रिया कौन-सी है?","options":["अपनी मौजूदा गति बनाए रखें और स्टीयरिंग के दोबारा काम करने तक पहिये को जोर लगाकर इधर-उधर घुमाते रहें","पहिया पूरी तरह छोड़ दें और वाहन को अपने रास्ते पर चलने दें जबकि आप रेडियो की ओर हाथ बढ़ाएं","वाहन को नियंत्रित और सुरक्षित रूप से रोकने के लिए ब्रेक को धीरे और सहजता से लगाएं","सबसे कम दूरी में रोकने के लिए तुरंत जोर से ब्रेक दबाकर पहियों को लॉक कर दें"],"explanation":"अगर स्टीयरिंग अचानक फेल हो जाए तो आप केवल गति को नियंत्रित कर सकते हैं, इसलिए धीरे और सहजता से ब्रेक लगाकर वाहन को सुरक्षित, नियंत्रित रूप से रोकें।"},"205":{"q":"दो-लेन वाले ग्रामीण राजमार्ग पर दो कारों की टक्कर वाली जगह पर पहुँचने वाला पहला वाहन आपका है। एक चालक स्टीयरिंग पर झुका हुआ है और घायल लगता है, और दोनों लेन में टूटा हुआ काँच तथा तरल पदार्थ फैला हुआ है। दोनों दिशाओं से अभी भी अन्य वाहन आ रहे हैं। अपने ट्रक को सुरक्षित रूप से रोकने के बाद आपको सबसे पहले क्या करना चाहिए?","options":["दुर्घटना स्थल की सुरक्षा करना और आ रहे यातायात को चेतावनी देना ताकि और टक्करें न हों","घायल चालक को कार से बाहर खींचकर सड़क के किनारे ले जाना","रिपोर्ट के लिए नुकसान का दस्तावेज़ बनाने हेतु घटनास्थल की तस्वीरें लेना","हर घायल की चोटों की जाँच करना और प्राथमिक उपचार देना शुरू करना"],"explanation":"किसी भी दुर्घटना स्थल पर पहली प्राथमिकता दूसरी टक्कर रोकना है, इसलिए कुछ और करने से पहले क्षेत्र की सुरक्षा करें और आ रहे यातायात को चेतावनी दें।"},"206":{"q":"आप एक ग्रामीण दो-लेन राजमार्ग पर एक ड्राई वैन ले जा रहे हैं, तभी आपको धुएं की गंध आती है और पिछले एक्सल के पहिए के पास लपटें दिखाई देती हैं। आपको तेज़ी से रुकना है, लेकिन आगे रुकने के कई स्थान हैं। आग से निपटने के लिए गाड़ी रोककर पार्क करने के लिए सबसे अच्छी जगह कौन सी है?","options":["आने वाली राजमार्ग सुरंग के प्रवेश द्वार के ठीक आगे, ताकि संरचना ट्रक को हवा से बचाए","ट्रक स्टॉप के बजरी वाले हिस्से में, डीज़ल पंपों के पास पार्क करके, ताकि अग्निशामक यंत्र पहुंच में रहे","एक खुले हिस्से के चौड़े किनारे पर, इमारतों और अन्य वाहनों से अच्छी तरह दूर, एक आपातकालीन कॉल बॉक्स के पास","अगले कंक्रीट ओवरपास के नीचे, जहां छाया माल को और अधिक गर्म होने से बचाएगी"],"explanation":"वाहन में आग लगने पर इमारतों, यातायात और ज्वलनशील चीजों से दूर खुले किनारे पर रुकें पर कॉल बॉक्स के पास, ताकि आग अलग रहे और मदद पहुंच में बनी रहे।"},"207":{"q":"आप एक गीले हाईवे पर लदा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं, तभी एक कार अचानक आपके सामने आ जाती है और झटके से रुक जाती है। आप ज़ोर से ब्रेक लगाते हैं, ABS की चेतावनी लाइट बंद है (सिस्टम सही चल रहा है), और टक्कर से बचने के लिए आपको गाड़ी को खाली किनारे (शोल्डर) की ओर मोड़ना होगा। इस आपात स्थिति में ABS पर भरोसा करते हुए, वह वास्तव में आपके लिए जो करेगा, उसका सबसे सटीक विवरण क्या है?","options":["यह आपकी कुल रुकने की दूरी को उन लगभग 419 फीट से बहुत कम कर देगा जो 55 मील प्रति घंटा पर एक ट्रक को चाहिए, ताकि आप बिना मोड़े समय पर रुक सकें","जैसे ही यह आगे की रुकावट को भांप लेगा, यह अपने आप ब्रेक लगाकर ट्रक को आपके बजाय शोल्डर की ओर मोड़ देगा","यह सुनिश्चित करता है कि पहिए लॉक रहें ताकि टायर गीली सड़क पर ज़्यादा मज़बूती से पकड़ बनाएँ और अधिकतम ग्रिप मिले","यह आपके पहियों को लॉक होने से रोकेगा ताकि ज़ोर से ब्रेक लगाते हुए भी आप स्टीयरिंग नियंत्रण बनाए रखें और गाड़ी को शोल्डर की ओर मोड़ सकें"],"explanation":"ABS तेज़ ब्रेकिंग के दौरान पहियों को लॉक होने से रोकता है, जिससे आप स्टीयरिंग नियंत्रण बनाए रखते हैं और ब्रेक लगाते हुए किनारे की ओर मुड़ सकते हैं।"},"208":{"q":"आप एक लदे हुए ट्रेलर को गीले चार-लेन हाईवे पर ढलान से नीचे ले जा रहे हैं, तभी एक कार अचानक आपके आगे आ जाती है। आप जोर से ब्रेक लगाते हैं, आपका ABS (एंटी-लॉक ब्रेक सिस्टम) सक्रिय हो जाता है, और आप ट्रक को नियंत्रण में रखते हुए खतरे के चारों ओर स्टीयर कर लेते हैं। बाद में एक नया चालक आपसे कहता है कि चूंकि आपके ट्रक में ABS है, अब आप दूसरे वाहनों के और करीब चल सकते हैं क्योंकि ABS आपको बहुत कम दूरी में रोक देता है। यह तर्क गलत क्यों है?","options":["ABS जरूरी नहीं कि आपकी रुकने की दूरी को कम करे; इसका मुख्य लाभ पहियों को लॉक होने से रोकना है ताकि आप ब्रेक लगाते समय स्टीयर कर सकें।","ABS केवल तभी काम करता है जब सड़क सूखी हो, इसलिए इस गीले हाईवे पर इसने ब्रेक लगाने में कोई मदद नहीं की।","ABS रुकने की दूरी को केवल स्टीयरिंग (आगे वाले) एक्सल पर कम करता है, इसलिए फॉलोइंग दूरी आधी की जा सकती है लेकिन पूरी तरह नहीं।","ABS आपके लिए अपने आप ब्रेक लगा देता है, इसलिए हाईवे की गति पर आपको कोई फॉलोइंग दूरी रखने की जरूरत नहीं है।"],"explanation":"ABS जरूरी नहीं कि रुकने की दूरी कम करे; इसका मुख्य काम पहियों को लॉक होने से रोकना है ताकि तेज ब्रेक लगाते समय आप स्टीयरिंग कर सकें।"},"209":{"q":"आपके ट्रैक्टर-ट्रेलर में एंटी-लॉक ब्रेक (ABS) नहीं लगे हैं। एक ग्रामीण दो-लेन वाली सड़क पर, एक कार अचानक एक बगल की गली से सीधे आपके रास्ते में आ जाती है और आपको अपने वाहन को नियंत्रण में और अपनी लेन में रखते हुए जितनी जल्दी हो सके रुकना होगा। कौन सी ब्रेकिंग विधि स्टीयरिंग नियंत्रण खोए बिना सबसे छोटी सुरक्षित रुकावट देती है?","options":["ब्रेक पेडल को पूरी तरह से दबाकर रखें ताकि पहिये लॉक हो जाएं और अधिकतम ब्रेकिंग बल मिले","नियंत्रित ब्रेकिंग का उपयोग करें (लॉक होने से ठीक पहले तक दृढ़ और स्थिर दबाव लगाएं) या स्टैब ब्रेकिंग करें, और पहिये लॉक होने पर पेडल छोड़ दें","पूरी तरह रुकने तक ब्रेक को तेज़ी से और बेतरतीब ढंग से पंप करते रहें","केवल ट्रेलर हैंड वाल्व लगाएं ताकि ट्रेलर वाहन को घसीटकर रोक दे"],"explanation":"ABS के बिना, नियंत्रित ब्रेकिंग (लॉक होने से ठीक पहले स्थिर मजबूत दबाव) या स्टैब ब्रेकिंग का उपयोग करें और पहिये लॉक होने पर ब्रेक छोड़ दें ताकि पहिये न लॉक हों।"},"210":{"q":"एक गर्म गर्मी की दोपहर में आप विभाजित राजमार्ग पर लगभग 60 मील प्रति घंटे की रफ्तार से लदे हुए ट्रक में चल रहे हैं। अचानक आपको एक ज़ोरदार धमाका सुनाई देता है और आपके ट्रैक्टर का अगला हिस्सा झटका खाकर ज़ोर से एक ओर खिंचने लगता है -- स्टीयरिंग (अगले) एक्सल का एक टायर फट गया है। उस पहले क्षण में, कुछ और करने से पहले, कौन सी प्रतिक्रिया आपको वाहन पर नियंत्रण बनाए रखने का सबसे अच्छा मौका देती है?","options":["तुरंत ज़ोर से और मजबूती से ब्रेक लगाएं ताकि ट्रक के और अधिक रास्ते से भटकने से पहले उसे सुरक्षित गति पर ले आएं","ड्राइव पहियों को शक्ति देने और ट्रैक्टर को सीधा खींचने के लिए एक्सेलरेटर दबाएं, फिर जब वह सीधा चलने लगे तो उसे छोड़ दें","जिस ओर खिंचाव हो रहा है उसके विपरीत दिशा में तेज़ी से स्टीयरिंग मोड़ें ताकि ट्रैक्टर वापस आपकी लेन के केंद्र की ओर सीधा हो जाए","स्टीयरिंग व्हील को दोनों हाथों से मजबूती से पकड़ें, पहले ब्रेक पर पैर न रखें, अपनी लेन में बने रहें, और हल्के से ब्रेक लगाने से पहले वाहन को अपने आप धीमा होने दें"],"explanation":"टायर फटने पर स्टीयरिंग को दोनों हाथों से मजबूती से पकड़ें, पहले ब्रेक न लगाएं, अपनी लेन बनाए रखें और धीरे ब्रेक लगाने से पहले वाहन को खुद धीमा होने दें।"},"212":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान, शिपिंग कागजात दिखाते हैं कि आपका ट्रेलर उसके सकल वाहन भार रेटिंग (GVWR) से कई हज़ार पाउंड अधिक लदा हुआ है। आपको देर हो रही है और आगे के मार्ग में एक लंबी ढलान और कुछ तीखे मोड़ हैं। एक सहकर्मी आपसे कहता है कि अतिरिक्त भार असल में 'सड़क पर पकड़ बनाने में मदद करेगा', इसलिए कोई बड़ी बात नहीं है। ओवरलोडिंग वाहन नियंत्रण को कैसे प्रभावित करती है, इसके आधार पर कौन-सा कथन सही है?","options":["अतिरिक्त भार टायरों को ज़मीन पर अधिक ज़ोर से दबाता है, इसलिए आपकी ब्रेकिंग दूरी कानूनी रूप से लदे होने की तुलना में वास्तव में कम होगी।","चूँकि भार धुरों के ऊपर है, अतिरिक्त वज़न आपके गुरुत्व केंद्र को नीचे कर देता है और मोड़ों पर पलटने का जोखिम कम कर देता है।","अतिरिक्त भार ट्रक को रोकना और मोड़ना कठिन बना देता है, जिससे आपकी रुकने की दूरी और ढलान व मोड़ों पर नियंत्रण खोने का जोखिम बढ़ जाता है।","ओवरलोडिंग केवल ईंधन की बचत और टायर घिसाव के लिए मायने रखती है; ट्रक कैसे रुकता या मुड़ता है, इस पर इसका कोई वास्तविक प्रभाव नहीं पड़ता।"],"explanation":"अधिक वजन ट्रक को रोकना और स्टीयर करना कठिन बना देता है, जिससे रुकने की दूरी और ढलानों व मोड़ों पर नियंत्रण खोने का जोखिम बढ़ता है।"},"213":{"q":"अपनी प्री-ट्रिप जाँच के दौरान आप एक फ्लैटबेड लोड करते हैं और देखते हैं कि लगभग सारी भारी मशीनरी पिछले एक्सल के ऊपर एक साथ ढेर हो गई है और पैलेट के ढेर पर ऊँचाई पर रखी है। चलने से पहले, अपने ट्रक को सुरक्षित रूप से चलाने के लिए इस लोड को संभालने का सबसे अच्छा तरीका क्या है?","options":["वजन को पिछले ड्राइव एक्सल के ऊपर एक साथ जमा रहने दें, क्योंकि वहाँ अतिरिक्त वजन ड्राइव टायरों को अधिक पकड़ देता है","पूरे लोड को आगे की ओर धकेल दें ताकि सारा वजन आगे के स्टीयरिंग एक्सल पर आ जाए और स्टीयरिंग नियंत्रण बेहतर हो","इसे ऊँचा और बीच में रखा रहने दें, क्योंकि बाएँ-दाएँ केंद्रित एक ऊँचा लोड पहले से ही पर्याप्त रूप से संतुलित है","लोड को फिर से वितरित करें ताकि वजन आगे-पीछे और दाएँ-बाएँ फैला और संतुलित हो, और गुरुत्व केंद्र को यथासंभव नीचा रखें"],"explanation":"माल का वजन आगे-पीछे और दाएं-बाएं फैलाकर संतुलित करें, गुरुत्व केंद्र को जितना संभव हो उतना नीचा रखें ताकि किसी एक्सल पर अधिक भार या पलटी न हो।"},"214":{"q":"अपनी प्री-ट्रिप जाँच के दौरान आप एक टैंकर को आंशिक रूप से भरते हैं और लदे हुए डेक के ऊपर कई पैलेट चढ़ा देते हैं, जिससे सबसे भारी वज़न ऊपर की ओर रहता है। अपने मार्ग की योजना बनाते समय, यह ट्रक अब कैसे चलेगा, इस बारे में किस जोखिम की आपको सबसे ज़्यादा चिंता होनी चाहिए?","options":["ऊँचा गुरुत्व केंद्र ट्रक को मोड़ पर या अचानक स्टीयरिंग करने पर पलटने की संभावना बहुत अधिक बढ़ा देता है।","ऊँचा लदा हुआ माल अतिरिक्त नीचे की ओर बल के कारण ट्रक को बहुत कम दूरी में रोक देगा।","ऊपर उठा हुआ वज़न समतल हाईवे पर आपकी ईंधन बचत को बेहतर करेगा क्योंकि माल अधिक सहजता से चलता है।","ऊपर से भारी माल हाईवे की गति पर स्टीयरिंग को काफ़ी हल्का और आसान बना देगा।"],"explanation":"ऊंचा गुरुत्व केंद्र अधिक वजन ऊपर रखता है, जिससे मोड़ पर या अचानक स्टीयरिंग करते समय ट्रक के पलटने की संभावना बहुत बढ़ जाती है।"},"215":{"q":"अपने प्री-ट्रिप निरीक्षण के दौरान आप अपने एकल सीधे ट्रक (बिना ट्रेलर) की जाँच कर रहे हैं और चालक के दरवाज़े के फ्रेम पर एक धातु की प्रमाणन प्लेट पाते हैं जिस पर 'GVWR' अक्षरों के बगल में 33,000 पाउंड का अंक अंकित है। आपका डिस्पैचर पूछता है कि यह आँकड़ा वास्तव में इस वाहन के बारे में आपको क्या बताता है। कौन-सा कथन सही है?","options":["यह इस ट्रक और इसके द्वारा एक इकाई के रूप में खींचे जाने वाले किसी भी ट्रेलर के लिए संयुक्त रूप से अनुमत अधिकतम लदा हुआ वज़न है","यह निर्माता द्वारा निर्धारित अधिकतम लदा हुआ वज़न है, जिसके लिए यह एकल वाहन रेट किया गया है","यह सभी माल और बंधनों का कुल वज़न है जिसे आप क़ानूनी रूप से कार्गो बॉक्स में रख सकते हैं","यह अधिकतम वज़न है जो ट्रक के किसी एक अलग धुरी पर टिक सकता है"],"explanation":"GVWR वह अधिकतम लदा हुआ वजन है, जो निर्माता द्वारा तय किया जाता है, जिसके लिए एक अकेला वाहन रेटेड होता है।"},"216":{"q":"अपने यात्रा-पूर्व निरीक्षण के दौरान आप पाते हैं कि फ्लैटबेड पर रखी 12-फुट की एक स्टील बीम दो बुरी तरह घिसी-फटी, जर्जर रस्सियों से बंधी है, और सामने के हेडबोर्ड के विरुद्ध कोई ब्लॉकिंग नहीं है। अभी आपके आगे एक लंबा हाईवे सफर है। कानूनी और सुरक्षित रूप से निकलने से पहले इस माल के लिए क्या आवश्यक है?","options":["और कुछ की जरूरत नहीं -- दो अलग रस्सियाँ पहले से ही 5 फुट से लंबे टुकड़े के लिए दो टाई-डाउन के न्यूनतम नियम को पूरा करती हैं, इसलिए बीम सुरक्षित है","बस मौजूदा रस्सियों को और कसकर बाँध देना काफी है, क्योंकि ट्रेलर के आगे का हेडबोर्ड अपने आप बीम को आगे खिसकने से रोक देगा","पर्याप्त संख्या में दुरुस्त टाई-डाउन और ब्रेसिंग -- उपयुक्त वर्किंग लोड लिमिट वाले मजबूत टाई-डाउन के साथ ब्लॉकिंग/ब्रेसिंग -- ताकि बीम को हर दिशा में खिसकने से सचमुच रोका जा सके","बीच में एक ही जंजीर काफी है, क्योंकि फ्लैटबेड पर किसी भी माल के लिए बस एक ही टाई-डाउन जरूरी होता है"],"explanation":"माल को किसी भी दिशा में खिसकने से रोकने के लिए पर्याप्त मजबूत टाई-डाउन (उपयुक्त वर्किंग लोड लिमिट सहित) तथा ब्लॉकिंग और ब्रेसिंग से बांधना जरूरी है।"},"217":{"q":"आप केबिन के ठीक पीछे लगे एक हेडर बोर्ड (हेडेक रैक) वाले फ्लैटबेड ट्रेलर पर स्टील के कॉइल और भारी क्रेट लाद रहे हैं। आपका सहकर्मी पूछता है कि जब पहले से ही सही टाई-डाउन का उपयोग हो रहा है, तो कंपनी इन रैक पर पैसा क्यों खर्च करती है। कौन-सा उत्तर इस हेडर बोर्ड के मुख्य उद्देश्य को सही ढंग से बताता है?","options":["यह एक मजबूत बंधन-बिंदु देता है ताकि आपके टाई-डाउन की कुल कार्य भार सीमा को माल के वजन के आधे से भी कम तक घटाया जा सके","यह माल के अगले हिस्से से हवा की अशांति और सड़क के छींटों को रोकता है, जिससे ईंधन खपत और दर्पण की दृश्यता बेहतर होती है","यह आपको कानूनी रूप से तब तक केबिन से माल की दोबारा जांच छोड़ने देता है जब तक आप लादने के बाद पहले 150 मील नहीं चला लेते","यह केबिन में आपकी रक्षा करता है, तेज ब्रेक के दौरान माल को आगे खिसककर चालक के कक्ष में घुसने से रोककर"],"explanation":"हेडर बोर्ड (हेडेक रैक) तेज ब्रेक के दौरान माल को आगे केबिन में खिसकने से रोकता है, जिससे चालक चोट या कुचले जाने से बच जाता है।"},"219":{"q":"आपने अभी-अभी अपने लदे हुए ट्रक का वजन सड़क किनारे लगे कांटे (स्केल) पर कराया, और अधिकारी आपको एक प्रिंटआउट देता है जिसमें कई अलग-अलग संख्याएँ हैं: ज़मीन पर टिके पहियों के हर समूह के लिए एक आँकड़ा, और एक एकल संयुक्त कुल योग। अधिकारी \"एक्सल वजन\" लिखी पंक्ति की ओर इशारा करता है और पुष्टि करने को कहता है कि आप समझते हैं कि वह विशिष्ट संख्या क्या दर्शाती है। सही उत्तर देने के लिए, आपको अधिकारी को क्या बताना चाहिए कि एक्सल वजन का आँकड़ा क्या मतलब रखता है?","options":["वह वजन जो प्रत्येक अलग एक्सल ज़मीन पर पहुँचाता है","पूरे लदे हुए वाहन और उसके सारे माल का संयुक्त कुल वजन","केवल ट्रेलर पर रखे माल और बाँधने वाले उपकरण का वजन","वह अधिकतम वजन जिसे निर्माता वाहन के सुरक्षित ढोने के लिए निर्धारित करता है"],"explanation":"एक्सल वेट वह वजन है जो कोई एक अलग एक्सल उठाता है और जमीन तक पहुंचाता है, न कि पूरे वाहन का वजन।"},"220":{"q":"एक लंबी रात की यात्रा के दौरान रात के 3 बजे हैं और आप पाते हैं कि आप अपनी लेन से भटक रहे हैं और बार-बार जम्हाई ले रहे हैं। आपकी यात्रा योजना के अनुसार अभी कई घंटे की गाड़ी चलानी बाकी है। कौन-सा कार्य वास्तव में आपकी थकान को दूर करेगा ताकि आप सुरक्षित रूप से आगे बढ़ सकें?","options":["एक बड़ा काला कॉफ़ी पिएं और बचे हुए घंटों को पार करने के लिए रेडियो की आवाज़ तेज़ कर दें","एक सुरक्षित विश्राम स्थल पर रुकें और गाड़ी चलाना बंद कर दें ताकि आगे बढ़ने से पहले सचमुच नींद ले सकें","ठंडी ताज़ी हवा के लिए साइड की खिड़की नीचे करें और शुगर के झटके के लिए कुछ कैंडी खाएं","गाड़ी चलाते रहें लेकिन अपनी प्रतिक्रिया के लिए अधिक समय देने हेतु वाहन की लंबाई के हर 10 फीट के लिए एक सेकंड तक फ़ॉलोइंग दूरी बढ़ा दें"],"explanation":"थकान केवल असली नींद से दूर होती है, इसलिए सुरक्षित विश्राम स्थल पर रुकें और आगे बढ़ने से पहले सोएं।"},"221":{"q":"एलर्जी का मौसम है और ट्रिप-पूर्व जांच के दौरान आपको सर्दी-जुकाम शुरू होने का एहसास होता है। एक लंबी दिन की यात्रा के लिए केबिन में चढ़ने से पहले आप अपने बैग से बिना पर्ची वाली सर्दी और एलर्जी की गोली लेते हैं। इस दवा का कौन सा प्रभाव अभी गाड़ी चलाने पर पुनर्विचार करने का सबसे महत्वपूर्ण कारण है?","options":["यह आपकी सतर्कता बढ़ा देगी, जिससे आप सुरक्षित रूप से अपने ड्राइविंग घंटे बढ़ा सकते हैं","यह आपके शरीर में बचे किसी भी अल्कोहल को निकाल देती है, जिससे यात्रा से पहले आपका BAC कम हो जाता है","यह आपको नींद ला सकती है और आपकी ड्राइविंग को बिगाड़ सकती है, इसलिए गाड़ी चलाने से पहले आपको लेबल जांचना चाहिए","यह आपके प्रतिक्रिया समय को बेहतर बनाती है और सड़क पर आपका ध्यान तेज करती है"],"explanation":"बिना पर्ची वाली कई सर्दी और एलर्जी की दवाएं तंद्रा लाती हैं और ड्राइविंग को बिगाड़ती हैं, इसलिए हमेशा लेबल पढ़ें और यदि मशीनरी चलाने के विरुद्ध चेतावनी हो तो गाड़ी न चलाएं।"},"222":{"q":"दो घंटे पहले आपने रात के खाने के साथ दो बीयर पी थीं और रात भर की यात्रा के लिए अपने ट्रैक्टर-ट्रेलर में चढ़ने से पहले आप खुद को पूरी तरह होश में महसूस करते हैं। आप खुद को समझाते हैं कि एक कड़क कॉफी और ठंडी रात की हवा आपको चौकस रखेगी। इस स्थिति में गाड़ी चलाकर आप जो असली जोखिम ले रहे हैं, उसे कौन सा कथन सबसे अच्छी तरह समझाता है?","options":["कोई खास जोखिम नहीं -- दो घंटे और एक कॉफी के बाद, आपके आकार के चालक पर शराब का कोई मापने योग्य असर नहीं रहता","असली चिंता केवल इतनी है कि ट्रक चलाते समय आपके CDL पर लागू 0.08% रक्त अल्कोहल (BAC) सीमा से नीचे रहा जाए","कॉफी और ठंडी हवा आपके शरीर से शराब निकलने की गति बढ़ा देंगी, इसलिए हाईवे पर पहुँचने से पहले ही आपकी क्षमताएँ बहाल हो जाएँगी","शराब आपके निर्णय और प्रतिक्रिया समय को तब भी बिगाड़ देती है जब आप ठीक महसूस करते हैं, और इसे आपके शरीर से केवल समय निकालता है -- कॉफी या ताज़ी हवा नहीं"],"explanation":"शराब आपके अच्छा महसूस करने पर भी निर्णय क्षमता और प्रतिक्रिया समय को बिगाड़ती है, और केवल समय बीतना -- कॉफी या ताजी हवा नहीं -- इसे शरीर से निकालता है।"},"224":{"q":"आपने रात 2 बजे एक लंबी शिफ्ट खत्म की और अगले डिस्पैच से पहले केवल लगभग चार घंटे की नींद ली। आपका डिस्पैचर आप पर निकलने का दबाव डालता है, और आप खुद से कहते हैं कि आप कॉफी और खुली खिड़की के साथ इसकी 'भरपाई' कर सकते हैं। थकान रोकने के बारे में हैंडबुक जो कहती है, उसके आधार पर कौन सा कथन यह दर्शाता है कि वास्तव में आराम पाने और सुरक्षित रूप से गाड़ी चलाने के लिए आपको वास्तव में क्या चाहिए?","options":["अधिकांश वयस्कों को वास्तव में आराम पाने के लिए लगभग 7 से 8 घंटे की नींद चाहिए, और केवल असली नींद — कॉफी या ताज़ी हवा नहीं — सतर्कता को बहाल करती है।","एक अनुभवी ड्राइवर के लिए लगभग 4 से 5 घंटे की नींद पर्याप्त है, क्योंकि कॉफी और ताज़ी हवा बाकी की भरपाई कर सकती है।","लगभग 2 से 3 घंटे की नींद स्वीकार्य है जब तक आप अपनी सतर्कता को फिर से जांचने के लिए हर 150 मील पर ब्रेक लेते हैं।","किसी भी वाणिज्यिक यात्रा से पहले आपको पूरे 12 से 14 घंटे की नींद चाहिए वरना आप कानूनी रूप से गाड़ी चलाने के अयोग्य हैं।"],"explanation":"अधिकांश वयस्कों को वास्तव में आराम पाने के लिए लगभग 7 से 8 घंटे की नींद चाहिए, और केवल असली नींद -- कॉफी या ताजी हवा नहीं -- सतर्कता बहाल करती है।"},"225":{"q":"आप कई घंटों से एक लंबे, नीरस राजमार्ग पर गाड़ी चला रहे हैं और आपकी पलकें भारी होती जा रही हैं. सतर्क रहने के लिए आप खिड़की खोलकर ताज़ी हवा लेते हैं और एक बड़ा कॉफ़ी पीते हैं. इन तरीकों के बारे में कौन-सा कथन सही है?","options":["कैफ़ीन और ठंडी ताज़ी हवा मिलकर बाकी पूरी शिफ़्ट के लिए आपकी सतर्कता को स्थायी रूप से बहाल कर देते हैं","ये थोड़ी देर के लिए मदद कर सकते हैं, लेकिन नींद/उनींदेपन का एकमात्र असली इलाज रुककर सोना है","ताज़ी हवा और कॉफ़ी ख़तरनाक हैं और आपके उनींदेपन को और बढ़ा देंगी","ये आपके ड्राइविंग घंटों को पूरी तरह रीसेट कर देते हैं, इसलिए आप बिना रुके सुरक्षित रूप से चलते रह सकते हैं"],"explanation":"कैफीन और ताजी हवा तंद्रा को थोड़े समय के लिए ही छिपाते हैं; एकमात्र असली उपाय है गाड़ी रोककर सोना।"},"226":{"q":"आप एक विभाजित राजमार्ग की दाहिनी लेन में चल रहे हैं, तभी एक चालक तेज़ी से आपके पीछे आता है, बहुत करीब से पीछा करता है, हाई बीम चमकाता है, फिर बाईं लेन में मुड़कर गुस्से में इशारे करते हुए आपसे आगे निकलने की कोशिश करता है। आगे यातायात मध्यम है। सबसे अच्छी और सुरक्षित प्रतिक्रिया कौन-सी है?","options":["उसकी रफ़्तार के बराबर गति बढ़ा लें ताकि वह जल्दी से आगे निकल जाए और आपके बंपर पर दबाव डालना बंद कर दे","अपनी लेन में बने रहें और बस थोड़ा धीमा करें, उसे रुकवाकर सबक सिखाएँ कि इतना करीब से पीछा न करे","एक्सेलरेटर से पैर हटाकर जगह दें, आँख मिलाने से बचें, और उसे काफ़ी आगे निकल जाने दें","बाईं ओर उसकी लेन में आकर उसके आगे निकलने को तब तक रोकें जब तक वह शांत होकर पीछे न हट जाए"],"explanation":"आक्रामक चालक को पर्याप्त जगह दें और उलझें नहीं -- एक्सेलरेटर से पैर हटाएं, आंख मिलाने से बचें और उसे काफी आगे निकलने दें।"},"227":{"q":"आप अपने लदे हुए ट्रैक्टर-ट्रेलर के साथ एक व्यस्त अंतरराज्यीय राजमार्ग पर मर्ज कर रहे हैं, तभी एक छोटी कार आपके सामने कट जाती है, जिससे आपको जोर से ब्रेक लगाना पड़ता है। गुस्से में वह दूसरा चालक फिर आपके बहुत करीब चलता है, आपके चारों ओर से निकलता है, आपके सामने अचानक ब्रेक लगाता है और अश्लील इशारे करता है। हैंडबुक के अनुसार, कौन सा शब्द दूसरे चालक के व्यवहार का सबसे अच्छा वर्णन करता है, और अपने आपको उसी दोष का दोषी बनने से बचाने के लिए अपने व्यवहार के बारे में सोचने का सबसे सुरक्षित तरीका क्या है?","options":["आक्रामक मर्जिंग — भारी यातायात का एक सामान्य हिस्सा, जिसका जवाब आपको गति बढ़ाकर अपनी जगह बनाए रखने से देना चाहिए ताकि कारें एक धीमे ट्रक का फायदा न उठा सकें","रक्षात्मक ड्राइविंग — दूसरा चालक केवल अपनी जगह की रक्षा कर रहा है, इसलिए आपको ब्रेक लगाकर और रास्ता रोककर उसके व्यवहार की नकल करनी चाहिए ताकि कारों को बड़े वाहन का सम्मान करना सिखाया जा सके","ध्यानभंग ड्राइविंग — चालक स्पष्ट रूप से ध्यान नहीं दे रहा, इसलिए सही प्रतिक्रिया यह है कि गति बढ़ाकर उसे तेजी से ओवरटेक करें और खुद को खतरे से दूर कर लें","रोड रेज (road rage) — क्रोधित, हिंसक ड्राइविंग; आप शांत रहकर, जवाबी कार्रवाई न करके और गुस्सैल चालक को दूर जाने के लिए जगह देकर खुद इससे बचते हैं"],"explanation":"रोड रेज गुस्से भरी, हिंसक ड्राइविंग है, और आप शांत रहकर, जवाबी कार्रवाई न करके और गुस्साए चालक को जाने की जगह देकर इससे बचते हैं।"},"228":{"q":"आप टेक्सास के एक अंतरराज्यीय राजमार्ग पर दोपहर के घने यातायात में एक लदा हुआ संयुक्त वाहन चला रहे हैं। एक सहकर्मी आपसे कहता है कि खतरों को जल्दी पकड़ने का सबसे अच्छा तरीका यह है कि आप ठीक आगे चल रहे ट्रक के बंपर पर अपनी नज़र टिकाए रखें ताकि उसकी ब्रेक लाइटें कभी न चूकें। वास्तव में कौन सा तरीका आपको समय रहते खतरों को पहचानकर सुरक्षित प्रतिक्रिया देने का सबसे अच्छा मौका देता है?","options":["अपनी नज़र लगातार घुमाते रहें और पूरे दृश्य को स्कैन करें — पहले दूर आगे (12 से 15 सेकंड) देखें, फिर पास, और हर 5 से 8 सेकंड में अपने शीशे देखें","सीधे आगे देखें और ठीक आगे चल रहे वाहन पर नज़र जमाए रखें ताकि उसकी ब्रेक लाइटें हमेशा साफ दिखती रहें","मुख्य रूप से अपने शीशों पर भरोसा करें, क्योंकि घने यातायात में ज्यादातर अचानक खतरे पीछे से ओवरटेक करने वाले वाहनों से आते हैं","आगे देखने के बीच-बीच में रेडियो डायल और डैशबोर्ड गेज देखते रहें ताकि किसी बढ़ती यांत्रिक चेतावनी को न चूकें"],"explanation":"अपनी आंखें लगातार घुमाते रहें और स्कैन करें -- 12 से 15 सेकंड आगे तक देखें, फिर पास के दृश्य पर, और हर 5 से 8 सेकंड में अपने शीशे जांचें।"},"229":{"q":"आप शहर के बीचों-बीच एक व्यावसायिक क्षेत्र से 25 मील प्रति घंटे की रफ्तार से गुजर रहे हैं। दाहिने किनारे के साथ आपको समानांतर खड़ी कारों की एक कतार दिखती है। आगे देखते समय आप ध्यान देते हैं कि उनमें से एक खड़ी कार की ब्रेक लाइटें जल रही हैं, एग्जॉस्ट पाइप से धुआँ निकल रहा है, और सीट पर एक चालक की आकृति दिख रही है। आपको इसी खड़ी कार को एक सक्रिय खतरा क्यों मानना चाहिए और धीमा होने या लेन में अपनी स्थिति बदलने के लिए तैयार रहना चाहिए?","options":["जलती ब्रेक लाइटों का मतलब है कि कार अपनी जगह पर रोकी हुई है, इसलिए वह हिल नहीं सकती और केवल उसके आगे बिना लाइट वाली कारें ही कोई खतरा हैं","जिसमें कोई बैठा हो और इंजन चालू हो ऐसी कार अचानक आपकी लेन में निकल सकती है या दरवाज़ा आपके रास्ते में खुल सकता है, इसलिए ब्रेक पर पैर रखें और अतिरिक्त जगह छोड़ें","चालू इंजन टायरों को गर्म करता है, जिससे आपकी अपनी रुकने की दूरी लगभग 419 फीट तक बढ़ जाती है और आपको गति कम करनी पड़ती है","एग्जॉस्ट और जलती ब्रेक लाइटें खड़ी कार के लिए सामान्य हैं और कुछ नहीं दर्शातीं, इसलिए गति या लेन की स्थिति में कोई बदलाव ज़रूरी नहीं है"],"explanation":"किसी के बैठे और चालू इंजन वाली खड़ी कार अचानक आपकी लेन में आ सकती है या आपके रास्ते में दरवाजा खोल सकती है, इसलिए ब्रेक पर पैर रखें और अतिरिक्त जगह दें।"},"230":{"q":"एक गर्म दोपहर में आप अपना ट्रक एक रिहायशी इलाके में 30 मील प्रति घंटे की रफ्तार से चला रहे हैं। आगे दाईं ओर आप कुछ बच्चों को किनारे के पास गेंद से खेलते हुए देखते हैं, और उनमें से एक बच्चा आपके ट्रक की बजाय गेंद की ओर देख रहा है। नियमावली इस स्थिति को एक विशेष खतरा क्यों मानती है, जिसमें आपको तुरंत गति धीमी करने या रुकने के लिए तैयार रहना चाहिए?","options":["क्योंकि 30 मील प्रति घंटे पर आपकी कुल रुकने की दूरी पहले से ही लगभग 419 फीट है, इसलिए आप किसी भी चीज़ के लिए समय पर रुक ही नहीं सकते","क्योंकि बच्चे हमेशा फुटपाथ पर ही रहते हैं और तभी खतरा बनते हैं जब कोई बड़ा उन्हें सड़क पार करने को कहे","क्योंकि बच्चे अचानक और अप्रत्याशित तरीके से व्यवहार कर सकते हैं, जैसे यातायात देखे बिना गेंद के पीछे सड़क पर दौड़ पड़ना","क्योंकि बच्चे इतने धीरे चलते हैं कि जब तक आप उनके हटने की उम्मीद करते हैं, उसके बहुत बाद तक भी वे सड़क पर ही रहेंगे"],"explanation":"बच्चे एक विशेष खतरा हैं क्योंकि वे अचानक और अप्रत्याशित रूप से व्यवहार कर सकते हैं, जैसे ट्रैफिक देखे बिना गेंद के पीछे सड़क पर दौड़ पड़ना।"},"231":{"q":"आप एक चार-लेन विभाजित राजमार्ग पर लगभग 55 मील प्रति घंटे की गति से एक लदा हुआ ट्रेलर चला रहे हैं। एक छोटी कार अचानक दाईं ओर से आपके आगे घुस जाती है, फिर एक निकास लेने के लिए जोर से ब्रेक लगाती है जिसे वह लगभग चूक गई थी। आपकी अनुसरण दूरी सिकुड़ गई है और आपको गुस्से की लहर महसूस होती है। सबसे सुरक्षित और रक्षात्मक प्रतिक्रिया कौन सी है?","options":["कार के ठीक पीछे नजदीक बने रहें और अपनी हाई बीम चमकाएं ताकि चालक उस खतरे को समझे जो उसने पैदा किया","तेजी बढ़ाकर कार के बराबर आ जाएं ताकि आप एक अप्रत्याशित चालक के पीछे फंसे न रहें","त्वरित चेतावनी देने के लिए हल्के से ब्रेक दबाएं, फिर अपने मूल 4-सेकंड के अनुसरण अंतराल तक वापस नजदीक आ जाएं","सुरक्षित अनुसरण दूरी फिर से बनाने के लिए एक्सेलेरेटर से पैर हटाएं, शांत रहें, और दूसरे चालक को वह जगह दें जिसकी उसे जरूरत है"],"explanation":"जब कोई अन्य चालक गलती करे, तो सुरक्षित अनुगमन दूरी फिर से बनाने के लिए एक्सेलरेटर से पैर हटाएं, शांत रहें और उसे आवश्यक जगह दें।"},"233":{"q":"रात में आप एक अनजान चौराहे के पास पहुंच रहे हैं, तभी आप देखते हैं कि ऊपर लगा ट्रैफिक सिग्नल हर दिशा में लाल रंग में चमक (फ्लैश) रहा है। वहां कोई पुलिसकर्मी मौजूद नहीं है और क्रॉस सड़क से आने वाला यातायात कम है। इस चौराहे को सही और कानूनी तरीके से पार करने के लिए आपको क्या करना चाहिए?","options":["पूरी तरह रुकें, फिर ठीक वैसे ही जैसे STOP (रुको) के संकेत पर करते हैं, सुरक्षित होने पर ही चौराहे को पार करें","गति धीमी करें, दोनों दिशाओं में देखें और पूरी तरह रुके बिना सावधानी से धीरे-धीरे आगे बढ़ जाएं","बंद पड़े सिग्नल को 'रास्ता दो' (यील्ड) मानकर, अपनी गति बनाए रखते हुए जैसे ही जगह मिले पार कर जाएं","चौराहे को पार करते समय अपनी गति बनाए रखें, क्योंकि चमकता सिग्नल यह दर्शाता है कि लाइट खराब है और नियम लागू नहीं होते"],"explanation":"चमकती लाल सिग्नल का अर्थ STOP चिह्न के समान है: पूरी तरह रुकें और तभी आगे बढ़ें जब सुरक्षित हो।"},"234":{"q":"देर रात आप अपने लदे हुए संयुक्त वाहन में एक चौराहे के पास पहुँच रहे हैं। जो सिग्नल दिन में लगातार हरा था, वह अब टिमटिमाता पीला (फ्लैशिंग येलो) दिखा रहा है। पार करने वाली सड़क पर कोई अन्य यातायात दिखाई नहीं दे रहा। इस सिग्नल को संभालने का सही तरीका कौन-सा है?","options":["इसे बिल्कुल टिमटिमाते लाल की तरह मानें: पूरी तरह रुकें, फिर रास्ता साफ होने पर आगे बढ़ें","गति धीमी करें, सतर्क रहें और क्रॉस ट्रैफ़िक जाँचने के बाद सावधानी से चौराहा पार करें","अपनी हाईवे गति बनाए रखें क्योंकि पीला सिग्नल आपको पार करने वाली सड़क पर रास्ते का अधिकार देता है","लाइन पर पूरी तरह रुकें और चलने से पहले सिग्नल के लगातार हरे होने का इंतज़ार करें"],"explanation":"चमकती पीली सिग्नल एक चेतावनी है, इसलिए गति धीमी करें, सतर्क रहें और क्रॉस ट्रैफ़िक जाँचने के बाद सावधानी से चौराहा पार करें।"},"235":{"q":"आप अपने लदे हुए संयोजन वाहन (कॉम्बिनेशन वाहन) के साथ एक ग्रामीण चौराहे के पास पहुँच रहे हैं। किसी भी दिशा में कोई स्टॉप साइन, यील्ड साइन या ट्रैफ़िक सिग्नल नहीं है, और झाड़ियाँ आपकी दाहिनी ओर का दृश्य आंशिक रूप से रोक रही हैं। एक पिकअप लगभग उसी समय आपकी दाहिनी ओर से चौराहे की ओर आ रहा है। आपके लिए सबसे सुरक्षित और सबसे सही कार्रवाई क्या है?","options":["अपनी गति बनाए रखें और पहले निकल जाएँ, क्योंकि एक लदे हुए वाणिज्यिक वाहन को छोटे वाहनों पर कानूनी रास्ते का अधिकार होता है","चौराहे के बीच में पूरी तरह रुक जाएँ और आगे बढ़ने से पहले पिकअप के निकलने का इंतज़ार करें","पास आते समय गति कम करें, अपना पैर ब्रेक पर तैयार रखें, और आगे बढ़ने से पहले आवश्यकतानुसार पिकअप को रास्ता देने के लिए तैयार रहें","हॉर्न बजाएँ और उसी गति से आगे बढ़ते रहें ताकि दूसरे चालक को पता चले कि आप पहले पार करना चाहते हैं"],"explanation":"अनियंत्रित चौराहे पर किसी भी वाहन को स्वतः अग्रता नहीं मिलती, इसलिए गति धीमी करें, ब्रेक पर पैर तैयार रखें और आगे बढ़ने से पहले रास्ता देने को तैयार रहें।"},"237":{"q":"आप एक भारी भार ढो रहे हैं और एक लंबी, खड़ी पहाड़ी ढलान की चोटी के पास पहुँच रहे हैं। ढलान कई मील लंबी है, सड़क सूखी है, और आप नीचे उतरते समय अपने सर्विस ब्रेक को गर्म होकर फेल (ब्रेक फेड) होने से बचाना चाहते हैं। सुरक्षित पहाड़ी ड्राइविंग प्रक्रिया के अनुसार, उतराई के दौरान आपकी गति पर सबसे भरोसेमंद नियंत्रण कौन-सा कार्य देता है?","options":["अपने सामान्य हाईवे गियर में ही रहें और गति स्थिर रखने के लिए पूरी उतराई में सर्विस ब्रेक को हल्के-हल्के दबाते रहें","ढलान के बीच में जब ट्रक की गति बढ़ने लगे तब तक प्रतीक्षा करें, फिर वाहन को दोबारा धीमा करने के लिए नीचे के गियर में बदलें","इंजन को आराम देने के लिए ट्रांसमिशन को ऊँचे गियर में रखें और गति नियंत्रित करने के लिए मुख्य रूप से जोरदार, बार-बार ब्रेक लगाने पर निर्भर रहें","उतराई शुरू करने से पहले निचला गियर चुनें ताकि इंजन और गियर ब्रेकिंग अधिकांश काम करें, और सर्विस ब्रेक को केवल हल्के, स्थिर सहायक के रूप में इस्तेमाल करें"],"explanation":"लंबी ढलान उतरना शुरू करने से पहले निचला गियर चुनें ताकि अधिकांश ब्रेकिंग इंजन और गियर से हो, और सर्विस ब्रेक का उपयोग केवल हल्के, स्थिर सहारे के रूप में करें।"},"238":{"q":"आप पूरी तरह लदे ट्रेलर के साथ पहाड़ी इलाके से गुजर रहे हैं, तभी आपका GPS आगे एक आपातकालीन एस्केप रैंप (बचाव ढलान) की चेतावनी देता है। आपके साथ बैठा एक नया चालक पूछता है कि राजमार्ग विभाग ने यह लंबा, बजरी से भरा रैंप रास्ते में कहीं और के बजाय ठीक इसी जगह क्यों बनाया। इन रैंपों के इच्छित उपयोग के आधार पर, विभाग इसे सबसे संभावित रूप से कहाँ बनाएगा?","options":["किसी लंबी, तीव्र ढलान के बीच में, जहाँ भारी वाहनों के ब्रेक ज़्यादा गरम होकर फेल होने (ब्रेक फेड) का जोखिम सबसे अधिक होता है","किसी समतल, खुले राजमार्ग खंड पर, जहाँ ट्रक आमतौर पर अपनी सबसे तेज़ क्रूज़िंग गति तक पहुँचते हैं","शहर के व्यस्त चौराहे से ठीक पहले, जहाँ शहरी यातायात बार-बार ज़ोर से ब्रेक लगाने को मजबूर करता है","किसी बड़े विश्राम-क्षेत्र पार्किंग स्थल के प्रवेश द्वार पर, जहाँ कई ट्रक रात भर खड़े रहते हैं"],"explanation":"रनअवे ट्रक रैंप लंबी, खड़ी ढलानों के बीच में बनाए जाते हैं, जहाँ भारी वाहनों के ब्रेक ज़्यादा गरम होकर फेड होने की सबसे अधिक संभावना होती है।"},"239":{"q":"रात काफी गहरा चुकी है और आप एक ग्रामीण दो-लेन राजमार्ग पर लो बीम पर चल रहे हैं, जो सड़क को लगभग 250 फीट आगे तक रोशन करती है। आगे एक तीखा मोड़ आ रहा है और आप उसके पार सड़क पर क्या है यह नहीं देख सकते। इस नियम के अनुसार कि आपको कभी भी अपनी हेडलाइट्स की पहुँच से तेज़ नहीं चलना चाहिए, कौन सा कदम सबसे उपयुक्त है?","options":["मोड़ पर हाई बीम चालू करें ताकि मोड़ के पार दूर तक देख सकें, और सीधा रास्ता आने पर फिर से लो बीम पर लौट आएं","मोड़ में प्रवेश करने से पहले अपनी गति कम करें ताकि आप उतनी दूरी के भीतर रुक सकें जितनी आपकी हेडलाइट्स वास्तव में रोशन करती हैं","अपनी मौजूदा गति बनाए रखें लेकिन आगे वाले वाहन के और करीब चलें ताकि उसकी पिछली लाइटें मोड़ पर आपका मार्गदर्शन करें","राजमार्ग गति बनाए रखें क्योंकि 55 मील/घंटा पर आपकी हेडलाइट्स अभी भी आवश्यक पूरे 419 फीट रुकने की दूरी को कवर करती हैं"],"explanation":"अपनी हेडलाइट से तेज़ कभी न चलें: मोड़ से पहले गति धीमी करें ताकि आप उतनी दूरी में रुक सकें जितनी आपकी हेडलाइट वास्तव में रोशन करती है।"},"240":{"q":"ट्रिप-पूर्व निरीक्षण के दौरान आपने अपने ट्रैक्टर-ट्रेलर के चारों ओर घूमकर जाँच पूरी कर ली है और देखने में सब ठीक लग रहा है। सड़क पर निकलकर यातायात में शामिल होने से पहले, यह पुष्टि करने का सही तरीका क्या है कि आपके सर्विस ब्रेक वास्तव में काम कर रहे हैं?","options":["कार्य-परीक्षण को छोड़ देना क्योंकि चारों ओर के निरीक्षण ने पहले ही पुष्टि कर दी कि ब्रेक के पुर्ज़े ठीक दिख रहे थे, और केवल पहले 50 मील के बाद फिर से जाँचना","हाईवे की गति तक पहुँचने तक रुकना, फिर ब्रेक को ज़ोर से दबाकर महसूस करना कि ट्रक एक तरफ खिंचता है या नहीं","कम गति पर चलना शुरू करना और ब्रेक को धीरे से दबाना ताकि यह सुनिश्चित हो कि वाहन रुकता है और एक तरफ नहीं खिंचता","खड़े रहते हुए ब्रेक पेडल को कई बार दबाना और वायु-दाब गेज को गिरते हुए देखना, जो साबित करता है कि ब्रेक आपको रोक देंगे"],"explanation":"वॉक-अराउंड निरीक्षण के बाद, धीरे चलकर और हल्के से ब्रेक लगाकर सर्विस ब्रेक की जाँच करें ताकि पुष्टि हो कि वाहन रुकता है और एक ओर नहीं खिंचता।"},"241":{"q":"आप दो-लेन वाले ग्रामीण राजमार्ग पर लदा हुआ ट्रेलर खींच रहे हैं, तभी तेज़ बगल की हवा का झोंका अचानक आपके ट्रैक्टर के अगले हिस्से को किनारे की ओर धकेल देता है। स्टीयरिंग को सही करते समय वाहन पर सबसे अच्छा नियंत्रण बनाए रखने के लिए, स्टीयरिंग व्हील पर हाथों की सबसे सुरक्षित स्थिति क्या है?","options":["एक हाथ व्हील के सबसे नीचे रखें ताकि आप हवा के विरुद्ध तेज़, चौड़ा मोड़ ले सकें","एक हाथ से स्टीयर करें और दूसरा हाथ ट्रेलर को धीमा करने के लिए ट्रेलर ब्रेक हैंड वाल्व पर तैयार रखें","झोंका गुज़र जाने के बाद व्हील को खुद-ब-खुद केंद्रित होने देने के लिए उसे थोड़ी देर हाथों में स्वतंत्र रूप से फिसलने दें","दोनों हाथ व्हील पर विपरीत दिशाओं में मज़बूती से रखें, ताकि आप सहजता से प्रतिक्रिया दे सकें और स्थिर नियंत्रण बनाए रख सकें"],"explanation":"स्टीयरिंग व्हील पर दोनों हाथ विपरीत दिशाओं में मज़बूती से रखें ताकि अचानक तेज़ बगल हवा के झोंके में आप सहजता से प्रतिक्रिया दें और स्थिर नियंत्रण बनाए रखें।"},"242":{"q":"आप एक भीड़भाड़ वाले ट्रक स्टॉप पर अकेले हैं और अपनी जगह से निकलने का एकमात्र तरीका पीछे की ओर चलना है। आपके पास एक विकल्प है: आप अपनी पहुँच इस तरह तैयार कर सकते हैं कि अपनी बाईं (चालक) ओर पीछे जाएँ, या अपनी दाईं (अंधी) ओर पीछे जाएँ, जो थोड़ी छोटी पैंतरेबाज़ी होगी। कौन सा तरीका सबसे सुरक्षित है और क्यों?","options":["चालक (बाईं) ओर पीछे जाएँ, क्योंकि आप खिड़की से बाहर झाँककर पूरे समय अपने ट्रेलर के पिछले हिस्से को सीधे देख सकते हैं।","अंधी (दाईं) ओर पीछे जाएँ, क्योंकि रास्ता छोटा है और आपके दर्पण उस तरफ का पूरा दृश्य देते हैं।","कोई भी तरफ समान रूप से सुरक्षित है बशर्ते आप चलने से पहले दो बार हॉर्न बजाएँ और अपनी चार-तरफा फ्लैशर चालू करें।","केवल सीधे पीछे जाएँ और ट्रेलर को कभी कोण पर न मोड़ें, क्योंकि ट्रक स्टॉप पर किसी भी प्रकार की बगल की ओर पीछे जाना प्रतिबंधित है।"],"explanation":"हमेशा चालक की (बाईं) ओर बैक करें, क्योंकि आप खिड़की से बाहर देखकर ट्रेलर के पिछले हिस्से को सीधे देख सकते हैं, केवल शीशों पर निर्भर नहीं रहना पड़ता।"},"243":{"q":"आप एक भरे हुए ट्रैक्टर-ट्रेलर को सूखे, समतल इंटरस्टेट हाईवे पर 55 मील प्रति घंटे की रफ्तार से चला रहे हैं, तभी आप दूसरे ट्रक से आगे निकलने का फैसला करते हैं। इसे सुरक्षित रूप से करने के लिए आप रफ्तार बढ़ाकर 65 मील प्रति घंटा कर लेते हैं। 55 मील प्रति घंटे पर रुकने की तुलना में, इस रफ्तार परिवर्तन का आपातकाल में रुकने की आपकी क्षमता पर सबसे महत्वपूर्ण प्रभाव क्या है?","options":["रुकने की दूरी लगभग वही रहती है क्योंकि सड़क सूखी है और आपके ब्रेक अच्छे हैं","रुकने की दूरी तेजी से बढ़ जाती है, क्योंकि ब्रेकिंग दूरी लगभग रफ्तार के वर्ग के अनुपात में बढ़ती है","रुकने की दूरी थोड़ी कम हो जाती है क्योंकि तेजी से घूमते पहिये सड़क को बेहतर पकड़ते हैं","रुकने की दूरी रफ्तार से प्रभावित नहीं होती और केवल आपके भार के वजन पर निर्भर करती है"],"explanation":"अधिक गति पर रुकने की दूरी तेज़ी से बढ़ती है, क्योंकि ब्रेकिंग दूरी लगभग गति के वर्ग के अनुपात में बढ़ती है।"},"244":{"q":"आप एक भरे हुए ट्रैक्टर-ट्रेलर को व्यस्त इंटरस्टेट हाईवे की प्रवेश रैंप पर ऊपर की ओर चला रहे हैं। एक्सेलरेशन लेन काफी छोटी है, दाईं लेन का यातायात लगभग 60 मील प्रति घंटे की रफ्तार से लगातार चल रहा है, और आपके ठीक आगे एक छोटा-सा अंतराल खुल रहा है। विलय (मर्ज) को यथासंभव सुरक्षित तरीके से पूरा करने के लिए आपको क्या करना चाहिए?","options":["रैंप के अंत में पूरी तरह रुक जाएं और बाहर निकलने से पहले सारा यातायात गुजर जाने का इंतजार करें","धीमी, सावधान गति से लेन में घुस जाएं और तेज यातायात को अपने वाहन के इर्द-गिर्द खुद को समायोजित करने दें","एक्सेलरेशन लेन का उपयोग करके यातायात के प्रवाह की गति तक पहुंचें, फिर खुले अंतराल में चले जाएं","अपनी लेन की स्थिति बनाए रखें और अपने रास्ते के अधिकार पर जोर दें ताकि मुख्य लेन के वाहन आपको रास्ता दें"],"explanation":"त्वरण लेन का उद्देश्य हाईवे यातायात की गति से मेल खाना है ताकि आप दूसरों को ब्रेक या मुड़ने पर मजबूर किए बिना खुले अंतराल में सहजता से शामिल हो सकें।"},"245":{"q":"आप घनी, रुक-रुक कर चलने वाली शहरी ट्रैफ़िक में एक लदा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं। फ़ोन में व्यस्त एक पैदल यात्री फ़ुटपाथ से उतरकर थोड़ी दूरी आगे आपकी लेन में चलने लगता है। आप पहले ही एक्सेलेरेटर से पैर हटा चुके हैं और ब्रेक पर पैर रखे हुए हैं। इस क्षण में हॉर्न का कौन सा उपयोग DPS उचित मानता है?","options":["पास के चालकों को सतर्क रखने के लिए हॉर्न को हल्के से बार-बार बजाएँ, क्योंकि भीड़भाड़ में लगातार संकेत देना टक्करों को रोकता है","हॉर्न का बिल्कुल उपयोग न करें और केवल ब्रेकिंग पर भरोसा करें, क्योंकि शहरी ट्रैफ़िक में पैदल यात्री के पास हॉर्न बजाना कभी अनुमत नहीं है","एक लंबा, मित्रवत हॉर्न बजाएँ ताकि पैदल यात्री और आसपास के चालक जान लें कि एक बड़ा ट्रक चौराहे की ओर आ रहा है","पैदल यात्री को तत्काल खतरे से सचेत करने के लिए हॉर्न बजाएँ, इसका उपयोग केवल दूसरों को खतरे की चेतावनी देने के लिए करें"],"explanation":"हॉर्न एक चेतावनी उपकरण है जिसका उपयोग केवल वास्तविक, तत्काल खतरे के बारे में दूसरों को सचेत करने के लिए किया जाता है, जैसे आपके रास्ते में आने वाला असावधान पैदल यात्री।"},"246":{"q":"तापमान हिमांक से ठीक नीचे है और आपको अपने ट्रैक्टर-ट्रेलर को एक तीव्र ढलान वाली सड़क के दाहिने किनारे पर पार्क करना है। आप पार्किंग ब्रेक लगाते हैं, लेकिन आप जानते हैं कि इस बर्फीली ढलान पर यदि वाहन खिसकने लगे तो अकेले ब्रेक उसे रोक नहीं पाएंगे। यदि वाहन लुढ़के तो कर्ब (किनारे की दीवार) को अंतिम रोक के रूप में उपयोग करने के लिए, आपको अगले पहियों को किस ओर मोड़ना चाहिए?","options":["अगले पहियों को कर्ब की ओर (दाईं ओर) मोड़ें, ताकि आगे की ओर कोई भी खिसकाव अगले टायर को कर्ब से टिका दे","अगले पहियों को कर्ब से दूर (बाईं ओर, सड़क की ओर) मोड़ें, ताकि लुढ़कने पर वाहन कर्ब से हट जाए","अगले पहियों को सीधा रखें, क्योंकि पार्किंग ब्रेक और चॉक ही पूरी रोक का काम करते हैं","ढलान पर दिशा से कोई फर्क नहीं पड़ता, बशर्ते पार्किंग ब्रेक लगा हो"],"explanation":"ढलान पर नीचे की ओर मुख करके पार्क करते समय अगले पहियों को कर्ब की ओर मोड़ें ताकि आगे लुढ़कने पर टायर कर्ब से टकराकर वाहन को रोक दे।"},"247":{"q":"आप एक ग्रामीण दो-लेन राजमार्ग पर 50 मील प्रति घंटे की गति से एक लदे हुए ट्रैक्टर-ट्रेलर को चला रहे हैं, तभी आप एक दर्पण देखने के लिए नीचे नज़र डालते हैं। जब आप ऊपर देखते हैं, तो आपके दाहिनी ओर के पहिये पक्की सड़क से हटकर मुलायम बजरी वाले किनारे (शोल्डर) पर चले गए हैं, और आपका ट्रैक्टर हल्का-सा दाईं ओर खिंच रहा है। ठीक आगे कोई बाधा नहीं है। सड़क पर वापस आने का सबसे अच्छा तरीका क्या है?","options":["और अधिक ज़मीन खोने से पहले अपनी दिशा सुधारने के लिए स्टीयरिंग को तेज़ी से और मज़बूती से घुमाकर तुरंत पक्की सड़क पर वापस आ जाएं","अपना पैर एक्सेलरेटर से हटा लें, स्टीयरिंग को मज़बूती से पकड़ें, और ट्रक के धीमा होकर नियंत्रण में आ जाने के बाद धीरे-धीरे पक्की सड़क पर वापस आ जाएं","वाहन का कोई भी हिस्सा किनारे से बाहर निकलने से पहले गति कम करने के लिए तुरंत ज़ोर से ब्रेक लगाएं","मुलायम बजरी में से ताकत के साथ निकलने और वाहन को अधिक मज़बूत पक्की सड़क पर वापस खींचने के लिए एक्सेलरेटर दबाएं"],"explanation":"यदि पहिए किनारे पर उतर जाएं, तो जोर से ब्रेक लगाए बिना एक्सेलेरेटर से पैर हटाएं और ट्रक की गति कम होने के बाद धीरे-धीरे वापस सड़क पर लौटें।"},"248":{"q":"आप दो-लेन वाले राजमार्ग की दाईं लेन में, निर्धारित 55 मील प्रति घंटे की गति से एक भरे हुए ट्रैक्टर-ट्रेलर को चला रहे हैं। पिछले कुछ मिनटों से एक पिकअप आपके इतने करीब चिपककर चल रहा है कि अब आप अपने शीशों में उसकी हेडलाइट नहीं देख सकते, और आपके आगे कोई वाहन नहीं है। बाईं लेन में यातायात हल्का है। पीछे से बहुत करीब चिपककर चलने वाले (टेलगेटर) इस चालक से निपटने का सबसे सुरक्षित तरीका क्या है?","options":["अपनी ब्रेक लाइटें चमकाने और चालक को पीछे हटने की चेतावनी देने के लिए कई बार हल्के से ब्रेक दबाएँ","अपनी गति बनाए रखें लेकिन आगे के वाहनों से अपनी पीछा-दूरी कम कर दें ताकि पीछे चिपककर चलने वाले को जगह मिल जाए","आगे की ओर अपनी पीछा-दूरी बढ़ाएँ, फिर जब सुरक्षित हो तब लेन बदलकर पीछे चिपककर चलने वाले चालक को आगे निकल जाने दें","धीरे-धीरे गति बढ़ाकर 55 मील प्रति घंटे से काफी ऊपर ले जाएँ जब तक कि पीछे चिपककर चलने वाला आपके बंपर से न हट जाए"],"explanation":"पीछे कोई बहुत करीब चल रहा हो तो आगे अतिरिक्त जगह बढ़ाएं और फिर किनारे होकर उसे सुरक्षित रूप से आगे निकलने दें।"},"249":{"q":"आप एक बहु-लेन राजमार्ग पर लदा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं और आपको अपने एग्ज़िट से पहले दाईं लेन में जाना है, जो लगभग एक मील में आने वाला है। यातायात मध्यम है और आपके दाईं ओर के ब्लाइंड स्पॉट में पीछे कहीं एक कार है। अन्य चालकों से संवाद करने पर DPS के मार्गदर्शन के अनुसार, अपने आस-पास के चालकों को यह बताने का एकमात्र सबसे अच्छा तरीका क्या है कि आप क्या करने का इरादा रखते हैं?","options":["ब्रेक को कुछ बार हल्के से दबाएँ ताकि पीछे की कार आपकी ब्रेक लाइटें देखे और समझ जाए कि आप धीमे होकर लेन बदलने वाले हैं","दाईं लेन के यातायात पर अपनी हाई बीम चमकाएँ ताकि उन्हें सचेत किया जा सके कि आप लेन बदल रहे हैं","गति बढ़ाएँ और लेन परिवर्तन जल्दी करें ताकि आप ब्लाइंड स्पॉट में मौजूद कार के बगल में कम से कम समय बिताएँ","अपना दायाँ टर्न सिग्नल जल्दी चालू करें और उसे चालू रखें, लेन बदलने के अपने इरादे को स्पष्ट रूप से और काफी पहले से संकेत दें"],"explanation":"अपने इरादे स्पष्ट रूप से बताने के लिए सिग्नल जल्दी और काफी पहले से चालू करें ताकि अन्य चालकों को प्रतिक्रिया करने का समय मिले।"},"250":{"q":"आप एक सूखे इंटरस्टेट हाईवे पर 30 फुट लंबा सीधा ट्रक चला रहे हैं, हल्के यातायात में लगातार 50 मील प्रति घंटे की गति से चल रहे हैं। आपके आगे एक छोटी कार बार-बार लेन बदल रही है, इसलिए आप एक सुरक्षित फॉलोइंग दूरी तय करने का निर्णय लेते हैं। मानक फॉलोइंग-दूरी नियम के अनुसार, उस वाहन के पीछे आपको कम से कम कितनी फॉलोइंग दूरी रखनी चाहिए?","options":["4 सेकंड","3 सेकंड","5 सेकंड","6 सेकंड"],"explanation":"हर 10 फुट लंबाई के लिए 1 सेकंड की दूरी रखें और 40 मील/घंटा से ऊपर 1 सेकंड जोड़ें: 50 मील/घंटा पर 30 फुट का ट्रक 3 + 1 = 4 सेकंड चाहता है।"},"251":{"q":"आप शहर में 40 फुट लंबा सीधा (सिंगल) ट्रक चला रहे हैं और सूखी सड़क पर स्पीडोमीटर लगातार 35 मील प्रति घंटा दिखा रहा है। यातायात कम है, लेकिन आप आगे वाली गाड़ी के पीछे सुरक्षित दूरी रखना चाहते हैं ताकि वह अचानक ब्रेक लगाए तो आप प्रतिक्रिया कर सकें। अपने वाहन की लंबाई और वर्तमान गति के लिए अनुशंसित अनुसरण-दूरी नियम का उपयोग करते हुए, आपको कम से कम कितनी अनुसरण-दूरी रखनी चाहिए?","options":["5 सेकंड, क्योंकि 40 फुट का वाहन आधार आंकड़े से स्वतः एक अतिरिक्त सेकंड मांगता है","4 सेकंड, क्योंकि आप हर 10 फुट लंबाई के लिए 1 सेकंड रखते हैं और 40 मील प्रति घंटा से कम पर कुछ भी अतिरिक्त नहीं जोड़ते","3 सेकंड, क्योंकि तीन सेकंड किसी भी वाणिज्यिक वाहन के लिए मानक न्यूनतम अंतराल है","6 सेकंड, क्योंकि इस लंबाई पर सुरक्षा के लिए आपको हमेशा प्रति 10 फुट की गिनती दोगुनी करनी चाहिए"],"explanation":"हर 10 फुट लंबाई के लिए 1 सेकंड की दूरी रखें और 40 मील/घंटा से कम पर कुछ न जोड़ें, इसलिए 35 मील/घंटा पर 40 फुट के ट्रक को 4 सेकंड चाहिए।"},"252":{"q":"आप एक फ्लैटबेड संयोजन वाहन चला रहे हैं जो बम्पर से बम्पर तक 50 फीट लंबा है। इंटरस्टेट पर यातायात बढ़ गया है और सूखी, साफ परिस्थितियों में आपका स्पीडोमीटर स्थिर रूप से 55 मील प्रति घंटा पर बना हुआ है। आगे चल रहे वाहन के पीछे व्यवस्थित होते समय, हैंडबुक द्वारा अनुशंसित सुरक्षित अंतराल के भीतर रहने के लिए, सेकंड में गिनी गई न्यूनतम अनुसरण दूरी कितनी होनी चाहिए?","options":["5 सेकंड, क्योंकि आप वाहन की लंबाई के प्रत्येक 10 फीट के लिए 1 सेकंड देते हैं","7 सेकंड, 2 अतिरिक्त सेकंड जोड़ते हुए क्योंकि आपकी गति 40 मील प्रति घंटा से काफी अधिक है","6 सेकंड, क्योंकि 50 फीट आपको 5 सेकंड देते हैं और 40 मील प्रति घंटा से ऊपर होने के लिए आप 1 और जोड़ते हैं","4 सेकंड, क्योंकि सूखे मौसम में राजमार्ग पर स्थिर गति आपको अंतराल कम करने की अनुमति देती है"],"explanation":"हर 10 फुट लंबाई के लिए 1 सेकंड रखें और 40 मील/घंटा से ऊपर 1 सेकंड जोड़ें: 55 मील/घंटा पर 50 फुट का वाहन 5 + 1 = 6 सेकंड चाहता है।"},"253":{"q":"आप अच्छी दिन की रोशनी की परिस्थितियों में एक सूखे, समतल अंतरराज्यीय राजमार्ग पर 60 फुट लंबे ट्रैक्टर-ट्रेलर को 45 मील प्रति घंटे की स्थिर गति से चला रहे हैं। यातायात हल्का है, लेकिन आप आगे चल रही कार के पीछे एक सुरक्षित अनुसरण दूरी बनाए रखना चाहते हैं। निम्नलिखित में से कौन सा विकल्प सेकंड में उस न्यूनतम अनुसरण दूरी को सही ढंग से बताता है जो आपको बनाए रखनी चाहिए?","options":["6 सेकंड, क्योंकि आप वाहन की लंबाई के प्रत्येक 10 फुट के लिए 1 सेकंड रखते हैं","5 सेकंड, क्योंकि एक लंबे संयुक्त वाहन को प्रत्येक 10 फुट के लिए केवल लगभग आधे सेकंड की आवश्यकता होती है","8 सेकंड, 2 अतिरिक्त सेकंड जोड़ते हुए क्योंकि आप 40 मील प्रति घंटे से अधिक की गति पर हैं","7 सेकंड, क्योंकि आप लंबाई के लिए 6 सेकंड रखते हैं और 40 मील प्रति घंटे से अधिक होने के लिए 1 और सेकंड जोड़ते हैं"],"explanation":"हर 10 फुट लंबाई के लिए 1 सेकंड रखें और 40 मील/घंटा से ऊपर 1 सेकंड जोड़ें: 45 मील/घंटा पर 60 फुट का वाहन 6 + 1 = 7 सेकंड चाहता है।"},"254":{"q":"आप साफ, सूखी परिस्थितियों में एक समतल शहरी मुख्य सड़क पर 70 फुट लंबे संयोजन वाहन को 35 मील प्रति घंटे की स्थिर गति से चला रहे हैं। आगे का यातायात सुचारू रूप से चल रहा है और आप एक सुरक्षित अनुगमन दूरी रखना चाहते हैं। अनुगमन दूरी आंकने के सूत्र का उपयोग करते हुए, आपके आगे चल रहे वाहन के पीछे आपको जो न्यूनतम अंतराल रखना चाहिए, वह है:","options":["7 सेकंड","8 सेकंड","6 सेकंड","9 सेकंड"],"explanation":"वाहन की हर 10 फीट लंबाई के लिए 1 सेकंड की अनुसरण दूरी रखें, और 40 mph से कम गति पर कोई अतिरिक्त सेकंड नहीं जोड़ा जाता, इसलिए 70 फीट के ट्रक को 7 सेकंड चाहिए।"},"255":{"q":"आप एक सूखे इंटरस्टेट हाईवे पर माल ढो रहे हैं और आपका स्पीडोमीटर स्थिर रूप से 45 मील प्रति घंटा दिखा रहा है। अपने शीशों पर नज़र डालकर आप अनुमान लगाते हैं कि आपका ट्रैक्टर-ट्रेलर संयोजन सामने के बंपर से लेकर ट्रेलर के पिछले हिस्से तक पूरे 80 फीट लंबा है। यातायात सुचारू रूप से चल रहा है और आप आगे वाली कार के पीछे एक सुरक्षित अंतर रखना चाहते हैं। अनुशंसित अनुसरण-दूरी नियम के अनुसार, आपको कितने सेकंड का स्थान रखना चाहिए?","options":["8 सेकंड, क्योंकि नियम बस वाहन की लंबाई के हर 10 फीट के लिए 1 सेकंड है","9 सेकंड, क्योंकि 80 फीट से 8 सेकंड मिलते हैं और 40 मील प्रति घंटा से ऊपर चलने के लिए आप 1 सेकंड जोड़ते हैं","7 सेकंड, क्योंकि इस गति पर आप लंबाई-आधारित गिनती में से एक सेकंड कम कर सकते हैं","10 सेकंड, क्योंकि आपको लंबाई को ऊपर की ओर पूर्णांकित करना चाहिए और हाईवे की गति पर पूरे 2 सेकंड का अतिरिक्त मार्जिन जोड़ना चाहिए"],"explanation":"हर 10 फीट लंबाई के लिए 1 सेकंड से 8 सेकंड का आधार बनता है, फिर 40 mph से अधिक गति के लिए 1 सेकंड जोड़ें, जिससे कुल 9 सेकंड होते हैं।"},"256":{"q":"आप सूखे इंटरस्टेट हाईवे पर हल्के ट्रैफ़िक में 50 मील प्रति घंटे की स्थिर गति से 90 फुट लंबा कॉम्बिनेशन वाहन चला रहे हैं। एक छोटी कार आपके आगे आ जाती है और आपको सुरक्षित दूरी फिर से बनानी है। फॉलोइंग-डिस्टेंस नियम के अनुसार, उस वाहन के पीछे आपको कम से कम कितनी दूरी रखनी चाहिए?","options":["9 सेकंड, क्योंकि नियम बस वाहन की हर 10 फुट लंबाई के लिए 1 सेकंड है","8 सेकंड, क्योंकि सूखी सड़क पर स्थिर चलते समय आप थोड़ा समय कम कर सकते हैं","10 सेकंड की फॉलोइंग दूरी","11 सेकंड, क्योंकि आप 40 मील प्रति घंटे से काफी ऊपर हैं, इसलिए 2 अतिरिक्त सेकंड जोड़ते हुए"],"explanation":"हर 10 फीट लंबाई के लिए 1 सेकंड से 9 सेकंड का आधार बनता है, फिर 40 mph से अधिक गति के लिए 1 सेकंड जोड़ें, जिससे कुल 10 सेकंड होते हैं।"},"257":{"q":"आप एक फ्लैटबेड कॉम्बिनेशन वाहन चला रहे हैं जिसकी लंबाई आगे के बंपर से ट्रेलर के अंत तक 100 फीट है। ट्रैफ़िक खुल जाता है और आप सूखे इंटरस्टेट हाईवे पर 60 मील प्रति घंटे की रफ़्तार पकड़ लेते हैं। अपने शीशे में देखते हुए, आप जिस कार के पीछे चल रहे हैं उससे सुरक्षित अनुसरण दूरी रखना चाहते हैं। अनुसरण दूरी के नियम के अनुसार, आपको कम से कम (न्यूनतम) कितने सेकंड का अंतराल रखना चाहिए?","options":["10 सेकंड, क्योंकि आप वाहन की प्रत्येक 10 फीट लंबाई के लिए 1 सेकंड देते हैं और 100 को 10 से भाग देने पर 10 आता है","12 सेकंड, प्रत्येक 10 फीट के लिए 1 सेकंड और अधिक गति के लिए 2 अतिरिक्त सेकंड जोड़ते हुए","9 सेकंड, क्योंकि 60 मील प्रति घंटा इतनी तेज़ है कि लंबाई-आधारित गणना में से एक सेकंड घटाया जा सके","11 सेकंड, क्योंकि 100 फीट से 10 सेकंड मिलते हैं और 40 मील प्रति घंटे से अधिक गति पर चलने के लिए आप 1 सेकंड और जोड़ते हैं"],"explanation":"हर 10 फीट लंबाई के लिए 1 सेकंड से 10 सेकंड का आधार बनता है, फिर 40 mph से अधिक गति के लिए 1 सेकंड जोड़ें, जिससे कुल 11 सेकंड होते हैं।"},"258":{"q":"आप एक सूखे अंतरराज्यीय राजमार्ग पर 40-फुट लंबा एकल ट्रक चला रहे हैं और अच्छी दिन की परिस्थितियों में लगातार 55 मील प्रति घंटे की गति बनाए हुए हैं। आगे का यातायात स्वतंत्र रूप से चल रहा है। सुरक्षित अनुसरण दूरी के लिए हैंडबुक के नियम को लागू करते हुए, आपको अपने आगे वाले वाहन के पीछे कम से कम कितना अंतराल रखना चाहिए?","options":["5 सेकंड","4 सेकंड","6 सेकंड","3 सेकंड"],"explanation":"हर 10 फीट लंबाई के लिए 1 सेकंड से 4 सेकंड का आधार बनता है, फिर 40 mph से अधिक गति के लिए 1 सेकंड जोड़ें, जिससे कुल 5 सेकंड होते हैं।"},"259":{"q":"आप एक फ्लैटबेड पर माल ढो रहे हैं और यात्रा-पूर्व जांच के दौरान आप अपने ट्रैक्टर-ट्रेलर को बंपर से बंपर तक 50 फीट मापते हैं। एक सूखे ग्रामीण राजमार्ग पर हल्के यातायात में आपका स्पीडोमीटर स्थिर रूप से 50 मील प्रति घंटा पर टिक जाता है। आगे चल रहे वाहन से सुरक्षित अनुसरण दूरी आंकने के नियम का उपयोग करते हुए, इस गति और लंबाई पर आपको कितने सेकंड की दूरी बनाए रखनी चाहिए?","options":["5 सेकंड, क्योंकि वाहन की हर 10 फीट लंबाई के लिए 1 सेकंड रखा जाता है","6 सेकंड, क्योंकि हर 10 फीट लंबाई के लिए 1 सेकंड रखा जाता है और 40 मील प्रति घंटा से अधिक होने पर 1 सेकंड और जोड़ा जाता है","7 सेकंड, क्योंकि हर 10 फीट लंबाई के लिए 1 सेकंड रखा जाता है और राजमार्ग गति के लिए 2 सेकंड और जोड़े जाते हैं","4 सेकंड, क्योंकि अनुसरण दूरी केवल गति पर आधारित होती है, वाहन की लंबाई पर नहीं"],"explanation":"हर 10 फीट लंबाई के लिए 1 सेकंड से 5 सेकंड का आधार बनता है, फिर 40 mph से अधिक गति के लिए 1 सेकंड जोड़ें, जिससे कुल 6 सेकंड होते हैं।"},"260":{"q":"आप एक सूखे, समतल अंतरराज्यीय राजमार्ग पर 70 फुट (लगभग 21 मीटर) लंबा ट्रैक्टर-ट्रेलर चला रहे हैं और हल्के यातायात में स्थिर 45 मील प्रति घंटा की गति बनाए हुए हैं। अपने शीशों में देखते हुए, आप यह तय करते हैं कि आगे का वाहन किसी स्थिर वस्तु को पार करने के बाद उस तक पहुँचने में आपको कितने सेकंड लगते हैं, यह गिनकर अपनी अनुसरण दूरी निर्धारित करें। अपने वाहन की लंबाई और वर्तमान गति के आधार पर, आपको कम से कम कितनी अनुसरण दूरी (न्यूनतम) रखनी चाहिए?","options":["7 सेकंड, क्योंकि नियम बस इतना है कि वाहन की प्रत्येक 10 फुट लंबाई के लिए 1 सेकंड","6 सेकंड, क्योंकि राजमार्ग की गति पर लगभग 6 सेकंड की कुल रुकने की दूरी पर्याप्त है","8 सेकंड, क्योंकि प्रत्येक 10 फुट लंबाई के लिए 1 सेकंड और 40 मील प्रति घंटा से अधिक होने के लिए 1 अतिरिक्त सेकंड चाहिए","9 सेकंड, लंबाई और गति के सेकंडों के ऊपर सूखे फुटपाथ के लिए एक सेकंड जोड़ते हुए"],"explanation":"हर 10 फीट लंबाई के लिए 1 सेकंड से 7 सेकंड का आधार बनता है, फिर 40 mph से अधिक गति के लिए 1 सेकंड जोड़ें, जिससे कुल 8 सेकंड होते हैं।"},"261":{"q":"आप एक फ्लैटबेड संयोजन वाहन चला रहे हैं जो अगले बंपर से ट्रेलर के पिछले हिस्से तक 80 फ़ीट लंबा है। समतल दो-लेन राजमार्ग पर यातायात सुचारू रूप से चल रहा है और आपका स्पीडोमीटर स्थिर रूप से 35 मील प्रति घंटा दिखा रहा है। आगे चल रहे ट्रक के पीछे सुरक्षित अनुसरण दूरी बनाए रखने के लिए आपको कितना अंतराल रखना चाहिए?","options":["9 सेकंड, क्योंकि लंबाई के लिए 8 सेकंड लेते हैं और राजमार्ग गति के लिए 1 सेकंड और जोड़ते हैं","7 सेकंड, क्योंकि धीमी गति पर अंतराल को एक सेकंड कम किया जा सकता है","10 सेकंड, किसी भी बड़े संयोजन वाहन को कभी भी ज़रूरत पड़ने वाला अधिकतम अंतराल","8 सेकंड, क्योंकि हर 10 फ़ीट लंबाई के लिए 1 सेकंड चाहिए और 40 मील प्रति घंटा से कम पर कोई अतिरिक्त सेकंड नहीं जोड़ा जाता"],"explanation":"हर 10 फीट लंबाई के लिए 1 सेकंड से 8 सेकंड बनते हैं, और 35 mph (40 mph से कम) पर कोई अतिरिक्त सेकंड नहीं जोड़ा जाता, इसलिए दूरी 8 सेकंड है।"},"262":{"q":"अपनी प्री-ट्रिप जांच के दौरान आप एक फ्लैटबेड पर 15 फुट लंबी एक स्टील पाइप बांध रहे हैं। पाइप आपके पट्टों की कार्यशील भार सीमा के भीतर अच्छी तरह आती है। माल सुरक्षा के संघीय न्यूनतम मानक को पूरा करने के लिए, इस एक पाइप पर आप कानूनी रूप से कम से कम कितने टाई-डाउन का उपयोग कर सकते हैं?","options":["2 टाई-डाउन","1 टाई-डाउन","3 टाई-डाउन","4 टाई-डाउन"],"explanation":"माल को हर 10 फीट लंबाई के लिए कम से कम 1 टाई-डाउन और 5 फीट से लंबी किसी भी वस्तु के लिए कम से कम 2 चाहिए, इसलिए 15 फीट के पाइप को 2 टाई-डाउन चाहिए।"},"263":{"q":"अपनी यात्रा-पूर्व जांच के दौरान आप अपने ट्रेलर पर सपाट लदी एक अकेली 25-फुट लंबी स्टील आई-बीम पाते हैं, जिसे केवल 2 चेन टाई-डाउन से बांधा गया है। बीम आपकी वजन सीमा के भीतर है और प्लेटफॉर्म अच्छी हालत में है। कानूनी रूप से चलने से पहले, इस वस्तु पर कम से कम कितने टाई-डाउन होने चाहिए?","options":["2 टाई-डाउन, क्योंकि 5 फुट से लंबी किसी भी वस्तु के लिए कानूनन कम से कम 2 सुरक्षा उपकरण आवश्यक हैं","3 टाई-डाउन, क्योंकि माल के प्रत्येक 10 फुट पर कम से कम एक टाई-डाउन चाहिए और 25 फुट को ऊपर की ओर 3 तक पूर्णांकित किया जाता है","4 टाई-डाउन, क्योंकि लंबे भारी स्टील को उसकी लंबाई के हर 5 फुट पर बांधना होता है","1 टाई-डाउन, क्योंकि बीम एक अकेली ठोस वस्तु है जो प्लेटफॉर्म पर मजबूती से टिकी है"],"explanation":"माल को हर 10 फीट लंबाई के लिए कम से कम 1 टाई-डाउन चाहिए और इसे ऊपर की ओर पूर्णांकित किया जाता है, इसलिए 25 फीट के बीम को 3 टाई-डाउन चाहिए।"},"264":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान आप फ्लैटबेड पर रखे 35 फुट लंबे एक स्टील बीम को बाँध रहे हैं। इस लंबाई के माल के लिए कितने टाई-डाउन (बाँधने वाली पट्टियाँ) चाहिए, यह नियम जानते हुए, इस बीम को कानूनी रूप से सुरक्षित करने के लिए आप कम से कम कितने टाई-डाउन का उपयोग कर सकते हैं?","options":["3 टाई-डाउन, क्योंकि 35 फुट को 10 से भाग देने पर तीन पूरे 10-फुट खंड मिलते हैं","2 टाई-डाउन, क्योंकि किसी भी एकल टुकड़े को बस हर सिरे पर एक की ज़रूरत होती है","4 टाई-डाउन, क्योंकि हर 10 फुट के लिए कम से कम एक चाहिए और 35 फुट ऊपर की ओर पूर्णांकित होता है","5 टाई-डाउन, क्योंकि इतनी लंबाई के बीम को सुरक्षा अंतर के लिए एक अतिरिक्त चाहिए"],"explanation":"माल को सुरक्षित करने के लिए हर 10 फुट लंबाई पर कम से कम एक टाई-डाउन चाहिए, और बचा हुआ हिस्सा ऊपर गिना जाता है, इसलिए 35 फुट के लिए 4 चाहिए।"},"265":{"q":"अपनी प्री-ट्रिप जांच के दौरान आप एक फ्लैटबेड पर 45 फुट लंबी एक स्टील बीम को बांध रहे हैं। बीम का वजन 9,000 पाउंड है और आपकी हर चेन की वर्किंग लोड लिमिट लोड की आवश्यकता से कहीं अधिक है, इसलिए यहां वजन रेटिंग आपकी चिंता नहीं है। केवल न्यूनतम टाई-डाउन संख्या के नियम के आधार पर, इस बीम को कानूनी रूप से ढोने के लिए आपको कम से कम कितने टाई-डाउन इस्तेमाल करने चाहिए?","options":["4 टाई-डाउन, क्योंकि आप लंबाई के हर पूरे 10 फुट के लिए एक गिनते हैं और बचे हुए 5 फुट को नजरअंदाज कर देते हैं","3 टाई-डाउन, क्योंकि वर्किंग लोड लिमिट पहले से ही लोड को थामने के लिए पर्याप्त ऊंची है","6 टाई-डाउन, सुरक्षा मार्जिन के रूप में लंबाई के नियम से एक अतिरिक्त जोड़ते हुए","5 टाई-डाउन, क्योंकि हर 10 फुट के लिए कम से कम एक चाहिए और 45 फुट ऊपर की ओर पूर्णांकित होकर 5 हो जाते हैं"],"explanation":"हर 10 फुट माल पर कम से कम एक टाई-डाउन चाहिए और बचा हुआ हिस्सा ऊपर गिना जाता है, इसलिए 45 फुट के माल के लिए 5 चाहिए।"},"266":{"q":"अपनी यात्रा-पूर्व जांच के दौरान आप एक फ्लैटबेड पर 55 फुट लंबे एक स्टील बीम को सुरक्षित कर रहे हैं। आप माल की लंबाई के आधार पर टाई-डाउन की संख्या के लिए न्यूनतम संघीय/टेक्सास सुरक्षा नियम को पूरा करना चाहते हैं। केवल लंबाई-आधारित आवश्यकता को गिनते हुए, इस बीम के लिए आप कानूनी रूप से कम से कम कितने टाई-डाउन का उपयोग कर सकते हैं?","options":["6 टाई-डाउन, क्योंकि प्रत्येक 10 फुट माल पर कम से कम एक की आवश्यकता है और 55 फुट को ऊपर की ओर पूर्णांकित करने पर 6 हो जाता है","5 टाई-डाउन, क्योंकि 55 को 10 से भाग देने पर 5 आता है और शेष को छोड़ दिया जाता है","7 टाई-डाउन, क्योंकि प्रत्येक 10 फुट पर एक और 5 फुट से लंबे किसी भी टुकड़े के लिए एक अतिरिक्त की आवश्यकता है","4 टाई-डाउन, क्योंकि प्रत्येक छोर पर दो टाई-डाउन किसी भी एकल बीम को स्थिर करने के लिए पर्याप्त हैं"],"explanation":"हर 10 फुट माल पर एक टाई-डाउन चाहिए और बचा हुआ हिस्सा ऊपर गिना जाता है, इसलिए 55 फुट के माल के लिए 6 चाहिए।"},"267":{"q":"अपनी प्री-ट्रिप जाँच के दौरान आप अपने फ्लैटबेड पर एक स्टील की बीम को सुरक्षित कर रहे हैं। यह लगभग 8 फुट लंबी है और इसका वजन करीब 3,000 पाउंड है। आप सोचते हैं कि चूँकि यह 10 फुट से काफी कम है, इसलिए 'हर 10 फुट पर एक टाई-डाउन' नियम के अनुसार एक ही टाई-डाउन पर्याप्त है। कौन-सा कथन उन टाई-डाउन की न्यूनतम संख्या को सही ढंग से बताता है जो आपको उपयोग करनी चाहिए?","options":["1 टाई-डाउन, क्योंकि बीम 10 फुट से छोटी है और प्रति-10-फुट नियम लागू होता है","2 टाई-डाउन, क्योंकि 5 फुट से लंबा कोई भी टुकड़ा प्रति-10-फुट गणना से स्वतंत्र रूप से कम से कम 2 टाई-डाउन की माँग करता है","1 टाई-डाउन, क्योंकि बीम का वजन एकल टाई-डाउन की 1,100 पाउंड सीमा से कम है","इतने छोटे एकल टुकड़े के लिए किसी टाई-डाउन की आवश्यकता नहीं है"],"explanation":"5 फुट से लंबे किसी भी एकल माल को प्रति 10 फुट गिनती से अलग, कम से कम 2 टाई-डाउन चाहिए।"},"268":{"q":"आप आमतौर पर ग्रामीण राजमार्ग के एक हिस्से पर 25 मील प्रति घंटे की रफ्तार से चलते हैं, और अनुभव से जानते हैं कि वहाँ ब्रेक लगने के बाद आपके लदे हुए ट्रक को लगभग 30 फीट की ब्रेकिंग दूरी चाहिए। आज रात आप उसी सड़क पर, उसी भार के साथ, उसी सूखी सतह पर, लेकिन 50 मील प्रति घंटे की रफ्तार से चल रहे हैं। 25 मील प्रति घंटे की अपनी सामान्य ब्रेकिंग दूरी की तुलना में, 50 मील प्रति घंटे पर आपकी ब्रेकिंग दूरी लगभग कितनी होगी:","options":["लगभग उतनी ही, क्योंकि भार और सतह नहीं बदले हैं","लगभग दोगुनी, क्योंकि आपने अपनी गति दोगुनी कर दी है","लगभग चार गुनी, क्योंकि ब्रेकिंग दूरी गति के वर्ग के अनुपात में बढ़ती है","लगभग आधी, क्योंकि पहिए तेज़ घूमते हैं और ऊर्जा को जल्दी बिखेर देते हैं"],"explanation":"ब्रेकिंग दूरी गति के वर्ग के अनुपात में बढ़ती है, इसलिए गति दोगुनी करने पर ब्रेकिंग दूरी लगभग चार गुना हो जाती है।"},"269":{"q":"अच्छे मौसम में आप एक सूखे, समतल हाईवे पर 55 मील प्रति घंटा की रफ़्तार से चल रहे हैं, तभी आपकी लेन में दूर आगे एक खराब कार अचानक दिखाई देती है। एक यात्री पूछता है कि जिस क्षण आपने पहली बार खतरा देखा, उसी समय से पूरी तरह रुकने तक वास्तव में कितनी सड़क लगेगी। प्रत्यक्षण (perception), प्रतिक्रिया (reaction) और ब्रेकिंग की दूरी को मिलाकर, आपकी कुल रुकने की दूरी का कौन सा अनुमान सबसे सही है?","options":["लगभग 60 फुट — केवल प्रतिक्रिया समय के दौरान आपका ट्रक जितनी दूरी तय करता है","लगभग 100 फुट — एक ट्रक की लंबाई से थोड़ा अधिक","लगभग 250 फुट — रात में आपकी लो बीम हेडलाइट जितनी दूरी तक रोशनी डालती है","लगभग 419 फुट — एक फुटबॉल मैदान और दोनों एंड ज़ोन की लंबाई के लगभग (लगभग 6 सेकंड की यात्रा)"],"explanation":"कुल रुकने की दूरी बोध, प्रतिक्रिया और ब्रेकिंग दूरियों का योग है, जो 55 मील/घंटा पर लगभग 419 फुट (करीब 6 सेकंड) बनती है।"},"270":{"q":"अपने शहर के डिलीवरी रूट पर आप आमतौर पर 30 मील प्रति घंटे की रफ्तार से चलते हैं, लेकिन आज एक चक्कर आपको उसी सूखी सड़क और उसी लदे हुए ट्रेलर के साथ 60 मील प्रति घंटे वाले हाईवे पर ले आता है। आपके साथ बैठा एक नया चालक मानता है कि चूँकि आपने रफ्तार सिर्फ दोगुनी की है, इसलिए रुकने में लगभग दोगुनी दूरी लगेगी। रफ्तार को लगभग दोगुना करने से आपकी ब्रेकिंग दूरी असल में कैसे बदलती है?","options":["ब्रेकिंग दूरी लगभग चार गुना बढ़ जाती है, क्योंकि यह रफ्तार के वर्ग के अनुपात में बढ़ती है","ब्रेकिंग दूरी सिर्फ लगभग दोगुनी होती है, रफ्तार के सीधे अनुपात में बढ़ती है","ब्रेकिंग दूरी लगभग वैसी ही रहती है क्योंकि लदा हुआ ट्रेलर पकड़ (ट्रैक्शन) बढ़ा देता है","ब्रेकिंग दूरी सिर्फ थोड़ी बढ़ती है, क्योंकि रफ्तार के साथ असल में प्रतिक्रिया दूरी बढ़ती है"],"explanation":"ब्रेकिंग दूरी गति के वर्ग के अनुपात में बढ़ती है, इसलिए गति दोगुनी करने पर यह दोगुनी नहीं बल्कि लगभग चार गुना हो जाती है।"},"271":{"q":"आप हाईवे की गति से गाड़ी चला रहे हैं, तभी आपसे काफी आगे एक हिरण अचानक सड़क पर आ जाता है. रुकने का सबसे पहला चरण है भांपना (परसेप्शन): वह समय जब हिरण पहली बार आपकी नज़र में आता है से लेकर जब आपका दिमाग वास्तव में उसे एक खतरे के रूप में पहचान लेता है. यह चरण तब होता है जब आप अपना पैर ब्रेक की ओर बढ़ाना भी शुरू नहीं करते. लगभग 55 मील प्रति घंटे की गति पर एक सतर्क चालक के लिए केवल यह भांपने का चरण अकेले लगभग कितना समय लेता है?","options":["लगभग 3/4 सेकंड, जो वास्तव में प्रतिक्रिया का समय है, यानी खतरा पहचान लिए जाने के बाद पैर को पेडल तक ले जाने में लगने वाला समय","लगभग 1.75 सेकंड, जो हैंडबुक के अनुसार हाईवे की गति पर किसी खतरे को भांपने और पहचानने में लगने वाला समय है, इससे पहले कि कोई प्रतिक्रिया शुरू हो","लगभग 6 सेकंड, जो असल में 55 मील प्रति घंटे से पूरी तरह रुकने में लगने वाला कुल समय है, सिर्फ भांपने का चरण नहीं","लगभग दसवां हिस्सा सेकंड, क्योंकि एक सतर्क पेशेवर चालक खतरों को लगभग तुरंत भांप लेता है"],"explanation":"बोध वह समय है जो आपके मस्तिष्क को खतरे को देखने और पहचानने में लगता है, राजमार्ग गति पर किसी प्रतिक्रिया से पहले लगभग 1.75 सेकंड।"},"272":{"q":"आप एक सूखे इंटरस्टेट पर 55 मील प्रति घंटा की रफ़्तार से चल रहे हैं जब दूर आगे आपकी लेन में अचानक एक खराब हुई कार दिखाई देती है। जब तक आप पूरी तरह रुकते हैं, आपका ट्रक लगभग एक फुटबॉल मैदान और दोनों एंड ज़ोन जितनी दूरी (लगभग 419 फीट) तय कर चुका होता है। प्रशिक्षक इस कुल रोकने की दूरी को तीन हिस्सों में बांटते हैं: जब आप खतरे को देखते हैं तब तक तय की गई दूरी (अनुभूति दूरी), जब आप अपना पैर पैडल पर ले जाते हैं तब तक तय की गई दूरी (प्रतिक्रिया दूरी), और एक और हिस्सा। कौन सा हिस्सा कुल रोकने की दूरी को पूरा करता है?","options":["स्टीयरिंग दूरी — बाधा के चारों ओर जाने के लिए स्टीयरिंग घुमाते समय तय की गई दूरी","सिग्नल दूरी — यातायात को चेतावनी देने के लिए हैज़ार्ड फ्लैशर चालू करते समय तय की गई दूरी","ब्रेकिंग दूरी — ब्रेक पकड़ने के बाद ट्रक के पूरी तरह रुकने तक तय की गई दूरी","पार्किंग दूरी — सुरक्षित रूप से किनारे रुकने के बाद आप किनारे पर छोड़ी गई अतिरिक्त जगह"],"explanation":"कुल रुकने की दूरी का तीसरा भाग ब्रेकिंग दूरी है, यानी ब्रेक लगाने के बाद ट्रक पूरी तरह रुकने तक जितनी दूरी तय करता है।"},"273":{"q":"आप अच्छे मौसम में एक समतल राजमार्ग पर अपना 20-फुट लंबा सीधा ट्रक चला रहे हैं, हल्के यातायात में लगातार 35 मील प्रति घंटे की गति बनाए हुए हैं। आप आगे चल रही कार के पीछे सही न्यूनतम अनुसरण दूरी छोड़ना चाहते हैं। वाहन की लंबाई के प्रत्येक 10 फुट के लिए 1 सेकंड के नियम का उपयोग करते हुए, इस गति पर आपको कितने सेकंड की अनुसरण दूरी रखनी चाहिए?","options":["4 सेकंड, क्योंकि ट्रक की लंबाई के प्रत्येक 10 फुट के लिए आपको हमेशा एक पूरा अतिरिक्त सेकंड जोड़ना चाहिए","3 सेकंड, लंबाई-आधारित आंकड़े में 1 सेकंड जोड़कर, क्योंकि राजमार्ग का यातायात अप्रत्याशित होता है","1 सेकंड, क्योंकि 35 मील प्रति घंटे पर आप 40 मील प्रति घंटे से नीचे हैं और अतिरिक्त सेकंड का नियम लागू नहीं होता","2 सेकंड, क्योंकि 20 फुट लंबाई 2 सेकंड देती है और 40 मील प्रति घंटे से नीचे कोई सेकंड नहीं जोड़ा जाता"],"explanation":"40 मील/घंटा से नीचे वाहन की हर 10 फुट लंबाई पर 1 सेकंड की दूरी चाहिए, इसलिए 20 फुट के वाहन को 2 सेकंड चाहिए।"},"274":{"q":"आप साफ मौसम में सूखे इंटरस्टेट हाईवे पर 55 मील प्रति घंटे की स्थिर गति से 20 फुट (लगभग 6 मीटर) लंबा सीधा ट्रक चला रहे हैं। यातायात कम है और आप आगे चल रही कार के पीछे सुरक्षित फॉलोइंग दूरी रखना चाहते हैं। वाहन की लंबाई और गति के आधार पर फॉलोइंग दूरी आंकने के नियम का उपयोग करते हुए, आपको कितने सेकंड की दूरी रखनी चाहिए?","options":["3 सेकंड","2 सेकंड","4 सेकंड","6 सेकंड"],"explanation":"वाहन की हर 10 फुट लंबाई के लिए 1 सेकंड की दूरी रखें, और 40 मील/घंटा से ऊपर की गति पर 1 सेकंड और जोड़ें।"},"275":{"q":"आप एक सीधा ट्रक चला रहे हैं जो बंपर से बंपर तक 30 फीट लंबा है। शहर में यातायात लगातार चल रहा है और आपका स्पीडोमीटर 35 मील प्रति घंटा दिखा रहा है। आगे सुरक्षित दूरी बनाए रखने के लिए, आगे चल रहे वाहन के पीछे आपको कम से कम कितनी अनुसरण दूरी रखनी चाहिए?","options":["2 सेकंड, क्योंकि सड़क समतल है और आप हाईवे गति से बहुत नीचे हैं","3 सेकंड, क्योंकि इस गति पर आप अपने वाहन की लंबाई के हर 10 फीट के लिए 1 सेकंड गिनते हैं","4 सेकंड, यातायात में होने के कारण लंबाई-आधारित दूरी में 1 अतिरिक्त सेकंड जोड़ते हुए","5 सेकंड, इस आकार के वाहन के लिए अधिक हाईवे गति पर उपयोग किए जाने वाले मार्जिन के बराबर"],"explanation":"वाहन की हर 10 फुट लंबाई के लिए 1 सेकंड की दूरी रखें; 40 मील/घंटा से कम गति पर कोई अतिरिक्त सेकंड नहीं जोड़ा जाता।"},"276":{"q":"आप एक सूखे इंटरस्टेट हाईवे पर 30 फुट लंबा एक सीधा (सिंगल-यूनिट) ट्रक चला रहे हैं और हल्के ट्रैफ़िक में स्थिर 55 मील प्रति घंटे की रफ़्तार बनाए हुए हैं। आगे चल रही कार के पीछे सुरक्षित दूरी बनाए रखने के लिए, आप सड़क किनारे एक स्थिर वस्तु चुनते हैं और तब तक सेकंड गिनते हैं जब तक आपका अगला बंपर उस तक नहीं पहुँच जाता। इस स्थिति में आपको कितने सेकंड की फ़ॉलोइंग दूरी रखनी चाहिए?","options":["3 सेकंड, क्योंकि नियम है कि वाहन की हर 10 फुट लंबाई के लिए 1 सेकंड","5 सेकंड, लंबाई और गति के नियम से जितना ज़रूरी है उससे 1 सेकंड अतिरिक्त जोड़ते हुए","4 सेकंड, क्योंकि 30 फुट से 3 सेकंड बनते हैं और 40 मील प्रति घंटे से ऊपर होने के कारण आप 1 सेकंड और जोड़ते हैं","2 सेकंड, वही न्यूनतम अंतराल जो एक यात्री कार हाईवे गति पर रखती है"],"explanation":"वाहन की हर 10 फुट लंबाई के लिए 1 सेकंड की दूरी रखें, और 40 मील/घंटा से ऊपर की गति पर 1 सेकंड और जोड़ें।"},"277":{"q":"आप एक सूखे, समतल राजमार्ग पर 40 फुट लंबा सीधा भार ले जा रहे हैं और हल्के यातायात में आपका स्पीडोमीटर 50 मील प्रति घंटे पर स्थिर हो जाता है। आगे चल रहे वाहन के पीछे सुरक्षित दूरी छोड़ने के लिए, इस स्थिति में आपको कितने सेकंड की अनुसरण दूरी बनाए रखनी चाहिए?","options":["4 सेकंड, क्योंकि आपके वाहन की लंबाई के प्रत्येक 10 फुट के लिए 1 सेकंड दिया जाता है","6 सेकंड, क्योंकि यह राजमार्ग की गति पर एक ट्रक को आवश्यक कुल रुकने की दूरी से मेल खाता है","3 सेकंड, मानक 3-सेकंड नियम के अनुसार जो सभी वाहनों पर लागू होता है","5 सेकंड, क्योंकि जब आप 40 मील प्रति घंटे से तेज़ चल रहे हों तो लंबाई-आधारित गणना में 1 अतिरिक्त सेकंड जोड़ा जाता है"],"explanation":"वाहन की हर 10 फुट लंबाई के लिए 1 सेकंड की दूरी रखें, और 40 मील/घंटा से ऊपर की गति पर 1 सेकंड और जोड़ें।"},"278":{"q":"आप एक सूखे अंतरराज्यीय राजमार्ग पर 60 फुट लंबा संयोजन वाहन चला रहे हैं और हल्के यातायात में स्थिर 50 मील प्रति घंटे की गति बनाए रखे हुए हैं। आगे चल रही एक छोटी कार आपकी गति तय कर रही है, और आप एक सुरक्षित दूरी छोड़ना चाहते हैं। पुस्तिका के बुनियादी अनुगमन-दूरी नियम का उपयोग करते हुए, आपको उस वाहन के पीछे कितने सेकंड की दूरी रखनी चाहिए?","options":["7 सेकंड, क्योंकि 60 फुट लंबाई से 6 सेकंड मिलते हैं, और 40 मील प्रति घंटे से अधिक गति के लिए 1 अतिरिक्त सेकंड जोड़ा जाता है","6 सेकंड, क्योंकि वाहन की हर 10 फुट लंबाई के लिए 1 सेकंड दिया जाता है","8 सेकंड, क्योंकि लंबाई के लिए 6 सेकंड के ऊपर राजमार्ग गति के लिए 2 सेकंड जोड़े जाते हैं","5 सेकंड, क्योंकि मध्यम गति पर 60 फुट के वाहन को हर 5 फुट के लिए लगभग आधा सेकंड चाहिए"],"explanation":"वाहन की हर 10 फुट लंबाई के लिए 1 सेकंड की दूरी रखें, और 40 मील/घंटा से ऊपर की गति पर 1 सेकंड और जोड़ें।"},"279":{"q":"आप एक साफ़ दिन के मौसम में सूखे अंतरराज्यीय राजमार्ग पर 70 फुट लंबे ट्रैक्टर-ट्रेलर को लगातार 55 मील प्रति घंटे की गति से चला रहे हैं। आपके आगे का चालक हल्के से ब्रेक लगाता है और आपको एहसास होता है कि आप जितना होना चाहिए उससे अधिक पास आ गए हैं। अनुसरण दूरी के सामान्य नियम का उपयोग करते हुए, उस वाहन के पीछे आपको कम से कम कितना अंतराल रखना चाहिए?","options":["7 सेकंड, क्योंकि आप अपने वाहन की लंबाई के प्रत्येक 10 फुट के लिए 1 सेकंड रखते हैं","8 सेकंड, क्योंकि आप प्रत्येक 10 फुट लंबाई के लिए 1 सेकंड रखते हैं और 40 मील प्रति घंटे से अधिक गति के लिए 1 सेकंड और जोड़ते हैं","6 सेकंड, क्योंकि 55 मील प्रति घंटे पर कुल रुकने की दूरी लगभग 6 सेकंड होती है","9 सेकंड, प्रत्येक 10 फुट के लिए 1 सेकंड और राजमार्ग गति के लिए 2 अतिरिक्त सेकंड रखते हुए"],"explanation":"वाहन की हर 10 फुट लंबाई के लिए 1 सेकंड की दूरी रखें, और 40 मील/घंटा से ऊपर की गति पर 1 सेकंड और जोड़ें।"},"280":{"q":"आप एक संयोजन ट्रक में, जो बंपर से बंपर तक 90 फुट लंबा है, 35 मील प्रति घंटे की गति सीमा वाले निर्माण क्षेत्र से माल ढो रहे हैं। यातायात समान रूप से चल रहा है, सड़क सूखी है, और आप वाहन की लंबाई के लिए सेकंड के नियम का उपयोग करके एक सुरक्षित अनुसरण दूरी तय करना चाहते हैं। इस स्थिति में आपको आगे चल रहे वाहन के पीछे कितने सेकंड की अनुसरण दूरी रखनी चाहिए?","options":["10 सेकंड, क्योंकि इतनी लंबाई के किसी भी संयोजन वाहन को गति की परवाह किए बिना एक अतिरिक्त सेकंड जोड़ने की आवश्यकता होती है","8 सेकंड, क्योंकि आप 90 फुट की लंबाई को निकटतम पूर्ण नियम अंतराल तक नीचे की ओर पूर्णांकित करते हैं","9 सेकंड, क्योंकि आप वाहन की लंबाई के प्रत्येक 10 फुट के लिए 1 सेकंड देते हैं और आपकी गति 40 मील प्रति घंटे से कम है","11 सेकंड, क्योंकि आप प्रत्येक 10 फुट के लिए 1 सेकंड देते हैं और निर्माण क्षेत्र के लिए एक पूरा अतिरिक्त सेकंड जोड़ते हैं"],"explanation":"वाहन की हर 10 फुट लंबाई के लिए 1 सेकंड की दूरी रखें; 40 मील/घंटा से कम गति पर कोई अतिरिक्त सेकंड नहीं जोड़ा जाता।"},"281":{"q":"आप एक समतल इंटरस्टेट राजमार्ग पर 90 फुट लंबा संयोजन वाहन चला रहे हैं और साफ, सूखे मौसम में आपका स्पीडोमीटर लगातार 60 मील प्रति घंटा दिखा रहा है। आगे का यातायात बिना रुकावट चल रहा है। सुरक्षित अनुसरण दूरी आंकने के लिए हैंडबुक नियम का उपयोग करते हुए, आपको अपने वाहन के अगले हिस्से और आगे वाले वाहन के बीच कितने सेकंड का अंतराल रखना चाहिए?","options":["8 सेकंड, क्योंकि 60 मील प्रति घंटा पर आप अधिक राजमार्ग गति को ध्यान में रखते हुए आधार आंकड़ा घटा देते हैं","11 सेकंड, 2 अतिरिक्त सेकंड जोड़ते हुए क्योंकि आप 40 मील प्रति घंटा से काफी ऊपर हैं","9 सेकंड, क्योंकि आप वाहन की हर 10 फुट लंबाई के लिए केवल 1 सेकंड गिनते हैं","10 सेकंड, हर 10 फुट लंबाई के लिए 1 सेकंड गिनते हुए और 40 मील प्रति घंटा से ऊपर की गति के लिए 1 सेकंड और जोड़ते हुए"],"explanation":"वाहन की हर 10 फुट लंबाई के लिए 1 सेकंड की दूरी रखें, और 40 मील/घंटा से ऊपर की गति पर 1 सेकंड और जोड़ें।"},"282":{"q":"आप एक समतल, सूखे ग्रामीण राजमार्ग पर 100 फुट लंबे संयोजन वाहन को चला रहे हैं और आपका स्पीडोमीटर स्थिर रूप से 35 मील प्रति घंटा दिखा रहा है। आपके आगे एक छोटी कार उसी गति से चल रही है, और आप एक सुरक्षित अनुसरण दूरी रखना चाहते हैं। आगे वाले वाहन ने अभी-अभी जिस निश्चित निशान को पार किया है, उस तक आपके अगले बंपर के पहुँचने में लगने वाले सेकंडों को गिनते हुए, आपको कम से कम कितनी अनुसरण दूरी रखनी चाहिए?","options":["10 सेकंड","11 सेकंड","9 सेकंड","7 सेकंड"],"explanation":"वाहन की हर 10 फुट लंबाई के लिए 1 सेकंड की दूरी रखें; 40 मील/घंटा से कम गति पर कोई अतिरिक्त सेकंड नहीं जोड़ा जाता।"},"283":{"q":"आप एक फ्लैटबेड खींच रहे हैं और आपका ट्रैक्टर-ट्रेलर बंपर से बंपर तक ठीक 100 फुट (लगभग 30 मीटर) लंबा है। ग्रामीण राजमार्ग पर यातायात स्थिर हो गया है और सूखी, साफ परिस्थितियों में आपका स्पीडोमीटर लगातार 45 मील प्रति घंटे पर टिका है। आगे चल रहा वाहन जब किसी स्थिर निशान को पार करे तब सेकंड गिनते हुए, आपको उस वाहन के पीछे कितने सेकंड की अनुवर्ती दूरी रखनी चाहिए?","options":["10 सेकंड, क्योंकि आप अपने वाहन की हर 10 फुट लंबाई के लिए 1 सेकंड रखते हैं","11 सेकंड, क्योंकि 100 फुट के लिए 10 सेकंड चाहिए और 40 मील प्रति घंटे से ऊपर होने के कारण आप 1 सेकंड और जोड़ते हैं","12 सेकंड, हर 10 फुट के लिए 1 सेकंड और राजमार्ग गति के लिए 2 अतिरिक्त सेकंड रखते हुए","9 सेकंड, सूखी सड़क के कारण 100 फुट के वाहन को नीचे की ओर पूर्णांकित करते हुए"],"explanation":"वाहन की हर 10 फुट लंबाई के लिए 1 सेकंड की दूरी रखें, और 40 मील/घंटा से ऊपर की गति पर 1 सेकंड और जोड़ें।"},"284":{"q":"आप एक सूखे इंटरस्टेट हाईवे पर 60 फीट लंबा संयोजन वाहन चला रहे हैं और हल्के यातायात में लगातार 60 मील प्रति घंटा की गति बनाए हुए हैं। हैंडबुक के अनुसरण-दूरी नियम को याद करते हुए, आगे चल रहे वाहन से आपको कम से कम कितनी दूरी बनाए रखनी चाहिए?","options":["6 सेकंड, क्योंकि 60 फीट लंबे वाहन को प्रत्येक 10 फीट लंबाई के लिए 1 सेकंड चाहिए","5 सेकंड, क्योंकि यातायात हल्का है और सड़क सूखी है","7 सेकंड: प्रत्येक 10 फीट लंबाई के लिए 1 सेकंड, और 40 मील प्रति घंटा से ऊपर होने के कारण 1 अतिरिक्त सेकंड","8 सेकंड, हाईवे गति होने के कारण आधार आंकड़े में 2 सेकंड जोड़ते हुए"],"explanation":"वाहन की हर 10 फुट लंबाई के लिए 1 सेकंड की अनुसरण दूरी रखें, और 40 मील प्रति घंटे से अधिक गति पर 1 सेकंड और जोड़ें।"},"285":{"q":"गोधूलि बेला में सूखी, दो-लेन वाली ग्रामीण सड़क पर आप राजमार्ग की गति से एक लदे हुए ट्रैक्टर-ट्रेलर को चला रहे हैं, तभी एक बड़ा हिरण पेड़ों की कतार से निकलकर आपके लेन में लगभग 150 फुट आगे जड़ हो जाता है। बायाँ लेन खाली दिखता है और आपकी दाईं ओर एक पक्का किनारा (शोल्डर) है। आमतौर पर सबसे सुरक्षित प्रतिक्रिया कौन-सी है?","options":["जानवर को बचाकर निकलने के लिए तेज़ी से बाएँ लेन में मुड़ जाएँ, क्योंकि वह खाली दिखता है","दाएँ किनारे की ओर मुड़ें और हिरण के हिलने से पहले गति बढ़ाकर उसके पास से निकल जाएँ","स्टीयरिंग व्हील से हाथ हटा लें और ट्रक को अपने आप सीधा चलने दें","दृढ़, नियंत्रित ब्रेक लगाएँ और अपने ही लेन में बने रहें"],"explanation":"दृढ़ता से ब्रेक लगाएं और अपनी लेन में रहें, क्योंकि अचानक तेज़ मोड़ ऊंचे गुरुत्व केंद्र वाले वाहन को पलटा या जैकनाइफ कर सकता है।"},"286":{"q":"आप एक विभाजित राजमार्ग पर लदा हुआ संयोजन (कॉम्बिनेशन) ट्रक चला रहे हैं, तभी लेन सिकुड़कर एक निर्माण/कार्य क्षेत्र (वर्क ज़ोन) में बदल जाती है। नारंगी संकेत निर्धारित गति सीमा को राजमार्ग की गति से काफी नीचे ले आते हैं, आगे एक झंडावाहक (फ्लैगर) खड़ा है, और श्रमिक खुली लेन के पास घूम रहे हैं। आपके आसपास का यातायात अभी भी लगभग राजमार्ग की गति से चल रहा है। सबसे सुरक्षित और कानूनी रूप से सही प्रतिक्रिया कौन सी है?","options":["अपनी गति को कार्य क्षेत्र की निर्धारित सीमा तक कम करें और श्रमिकों, उपकरणों तथा झंडावाहक के संकेतों के प्रति सतर्क रहें","अपना अनुसरण-दूरी अंतराल और राजमार्ग गति बनाए रखें क्योंकि आप पहले से ही अपने आगे 7 सेकंड की जगह छोड़ रहे हैं","आसपास के यातायात के साथ गति बनाए रखें ताकि वाहनों के बीच खतरनाक गति-अंतर पैदा न हो","तेज़ लेन में जाकर धीमे होते वाहनों को ओवरटेक करें ताकि कार्य क्षेत्र को जितनी जल्दी हो सके पार किया जा सके"],"explanation":"कार्य क्षेत्र की निर्धारित गति सीमा तक धीमे हों और कर्मचारियों, उपकरणों तथा यातायात नियंत्रित करने वाले फ्लैगर के प्रति सतर्क रहें।"},"287":{"q":"आप एक नम दो-लेन वाले राजमार्ग पर मोड़ से बाहर निकल रहे हैं और गति फिर से पाने के लिए एक्सेलरेटर दबाते हैं। तभी टैकोमीटर अचानक उछलता है और आप महसूस करते हैं कि ड्राइव पहिए पकड़ खोकर घूमने लगते हैं और ट्रैक्टर का पिछला हिस्सा बाहर की ओर झूलने लगता है। नियंत्रण वापस पाने का सबसे अच्छा मौका कौन-सी क्रिया देती है?","options":["घूमते ड्राइव पहियों को धीमा करने और मोड़ में अपनी रेखा को तंग करने के लिए ब्रेक को मजबूती से दबाएं","एक्सेलरेटर से पैर हटा लें ताकि ड्राइव पहिए धीमे हो जाएं, और ट्रक को उस दिशा में मोड़ें जिधर आप जाना चाहते हैं","झुलाव को जितनी जल्दी हो सके रोकने के लिए स्टीयरिंग को मोड़ की विपरीत दिशा में तेज़ी से घुमाएं","एक्सेलरेटर पर स्थिर दबाव बनाए रखें ताकि चालित पहिए आपको फिसलन से सीधा खींच लें"],"explanation":"ड्राइव-व्हील स्किड से उबरने के लिए एक्सेलेरेटर छोड़ें ताकि पहिए पकड़ वापस पा लें और ट्रक को जिस दिशा में ले जाना है उधर स्टीयर करें।"},"288":{"q":"आप एक ग्रामीण दो-लेन राजमार्ग पर ऊँचे गुरुत्व-केंद्र वाला आंशिक भार ढो रहे हैं। एक पहाड़ी से निकलते समय आपको एहसास होता है कि आगे आने वाला मोड़ चेतावनी संकेत से अधिक तीखा है, और आप उसमें आरामदायक गति से अधिक तेज़ी से प्रवेश कर चुके हैं। कौन-सा कदम आपको बिना फिसले या पलटे अपनी लेन में बने रहने का सबसे अच्छा मौका देता है?","options":["अतिरिक्त गति को जल्दी कम करने के लिए मोड़ के शीर्ष बिंदु पर ज़ोर से और मज़बूती से ब्रेक लगाएँ","ऊँचे गियर में डालें और ट्रक के पलटने से पहले उसे मोड़ से निकालने के लिए गति बढ़ाएँ","यह पहचानें कि आपको मोड़ से पहले ही गति कम करनी चाहिए थी, इसलिए एक्सेलरेटर से पैर हटाएँ और मोड़ के दौरान ट्रक को स्थिर रखते हुए केवल हल्का, क्रमिक ब्रेक लगाएँ","क्लच दबाएँ और मोड़ में न्यूट्रल में लुढ़कते हुए जाएँ ताकि चालक पहिये पकड़ न खोएँ"],"explanation":"मोड़ के भीतर थ्रॉटल छोड़ें और केवल हल्का, क्रमिक ब्रेक लगाएं, क्योंकि तेज़ ब्रेकिंग वजन को खिसकाती है और पकड़ तोड़ सकती है।"},"290":{"q":"आप एक सूखे इंटरस्टेट हाईवे पर 60 मील प्रति घंटे की रफ्तार से एक लदा हुआ संयोजन वाहन चला रहे हैं और एक बॉक्स ट्रक के एकदम पीछे चिपककर चल रहे हैं ताकि कोई कार आपके आगे न घुस सके। बॉक्स ट्रक की ब्रेक लाइटें जलती हैं और वह रुके हुए ट्रैफिक के लिए जोर से रुक जाता है; आप झटके से ब्रेक लगाते हैं और बस कुछ इंच के फासले पर रुक पाते हैं। बाद में इस बाल-बाल बचाव की समीक्षा करते हुए, कौन-सा कदम आपको वह समय और जगह देता जो सुरक्षित रूप से रुकने के लिए वास्तव में चाहिए थी?","options":["4 सेकंड की दूरी पर पीछा करना, क्योंकि 55 मील प्रति घंटे पर कुल रुकने की दूरी यही है (लगभग 419 फीट)","ठीक उसी जगह रहना पर ब्रेक लाइटें जलते ही आधा सेकंड पहले ब्रेक लगाना","फासले को और भी कम कर देना ताकि कोई कार बीच में न घुसे और आपको ब्रेक लगाने पर मजबूर न करे","इतना पीछे रहना कि एक सुरक्षित अनुसरण दूरी बनी रहे, जिससे आपको खतरा भांपने, प्रतिक्रिया देने और ट्रक तक पहुँचने से पहले ब्रेक लगाने का समय मिल जाए"],"explanation":"सुरक्षित अनुसरण दूरी रखें, क्योंकि कुल रुकने की दूरी बोध, प्रतिक्रिया और ब्रेकिंग दूरी का योग है, जो सैकड़ों फुट तक पहुंचती है।"},"291":{"q":"शाम ढले काफी समय बीत चुका है और आप एक संकरी, दो-लेन वाली ग्रामीण सड़क पर मुड़ गए हैं जिस पर आपने पहले कभी गाड़ी नहीं चलाई। कोई स्ट्रीटलाइट नहीं है, किनारे चिह्नित नहीं हैं, और आप अपनी हेडलाइट से आगे ज्यादा दूर नहीं देख सकते। इस हिस्से को सबसे सुरक्षित तरीके से पार करने के लिए आपको क्या करना चाहिए?","options":["अपनी गति इतनी कम करें कि आप हमेशा अपनी हेडलाइट से रोशन दूरी के भीतर रुक सकें, और जहाँ सामने से कोई वाहन न आ रहा हो वहाँ हाई बीम का उपयोग करें","आगे चल रही कुछ गाड़ियों की गति बनाए रखें ताकि आप यातायात के प्रवाह से धीमे न चलें","हाई बीम चालू कर दें और उन्हें लगातार जलाए रखें ताकि आप सड़क पर जितना दूर तक हो सके देख सकें","अपनी सामान्य दिन वाली गति बनाए रखें, क्योंकि रात में गति कम करना आपको तेज यातायात के लिए खतरा बना देता है"],"explanation":"अपने हेडलाइट से तेज़ कभी न चलें—गति इतनी कम रखें कि रोशन दूरी के भीतर रुक सकें, और सामने यातायात न हो तो हाई बीम का उपयोग करें।"},"293":{"q":"आप हल्के यातायात में लगभग 25 मील प्रति घंटे की गति से अपने ट्रैक्टर-ट्रेलर को शहर के मध्य व्यापारिक क्षेत्र से होकर चला रहे हैं। एक बिना चिह्न वाले ब्लॉक-मध्य क्षेत्र के पास पहुँचते समय, फुटपाथ पर खड़ा एक पैदल यात्री अचानक आपसे कुछ कार-लंबाई आगे सड़क पर उतर आता है, फोन की ओर देख रहा है और आपकी ओर नहीं। आपकी दाईं लेन खड़ी कारों से अवरुद्ध है और आपकी बाईं ओर सामने से आता यातायात है। सबसे सुरक्षित और कानूनी रूप से सही प्रतिक्रिया कौन-सी है?","options":["हॉर्न जोर से बजाएं और अपनी गति बनाए रखें, क्योंकि आपकी लेन में आपका रास्ते का अधिकार है और पैदल यात्री संभवतः पीछे हट जाएगा","एक्सेलरेटर से पैर हटाएं, ब्रेक पर पैर रखें, गति धीमी करें, और पैदल यात्री के लिए रुकने को तैयार रहें","पैदल यात्री के चारों ओर जाने के लिए हल्के से सामने वाली लेन में मुड़ें, फिर साफ होने पर अपनी लेन में लौट आएं","पैदल यात्री के आपके मार्ग में पूरी तरह आने से पहले क्षेत्र को पार करने के लिए कुछ देर तेज करें"],"explanation":"सड़क पर उतरे पैदल यात्री के लिए एक्सेलेरेटर छोड़ें, ब्रेक पर पैर रखें, धीमे हों और रुकने के लिए तैयार रहें।"},"294":{"q":"आप चार-लेन की इंटरस्टेट पर एक लदे हुए संयोजन वाहन (कॉम्बिनेशन व्हीकल) को चला रहे हैं और लगभग दो मील आगे एक निकास (एग्ज़िट) के लिए तैयार होने हेतु आपको एक लेन बाईं ओर जाना है। आप संकेत देते हैं, अपने बाईं ओर के दर्पण जाँचते हैं और खिसकना शुरू करते हैं, लेकिन ऐसा करते समय आपको पता चलता है कि एक कार आपके ट्रैक्टर के बगल में उस क्षेत्र में चल रही है जिसे आपके दर्पण पूरी तरह नहीं ढकते। सबसे अच्छी और सबसे सुरक्षित प्रतिक्रिया कौन-सी है?","options":["ब्रेक दबाते हुए लेन में खिसकना जारी रखें, क्योंकि आपकी ब्रेक लाइटें कार को सचेत कर देंगी कि वह पीछे हट जाए और आपके लिए जगह खोल दे","अपने ट्रैक्टर को कार से आगे निकालने के लिए दृढ़ता से गति बढ़ाएँ ताकि कार आपके ट्रेलर के पीछे आ जाए, और अगली दर्पण-जाँच से पहले लेन बदलना पूरा कर लें","लेन बदलना रद्द कर दें, अपनी स्थिति बनाए रखें, एक साफ़ जगह (गैप) की प्रतीक्षा करें, और दोबारा जाने का प्रयास करने से पहले दर्पण और उस ब्लाइंड-स्पॉट क्षेत्र को फिर से जाँचें","लेन बदलना जारी रखें क्योंकि आपने पहले ही समय से संकेत दे दिया था और दर्पण-जाँच पूरी कर ली थी, और बगल में चल रहे चालक का यह कर्तव्य है कि वह संकेत देते ट्रक को रास्ता दे"],"explanation":"आपके ब्लाइंड स्पॉट में कोई वाहन होना मतलब लेन साफ़ नहीं है, इसलिए लेन बदलना रद्द करें और हटने से पहले शीशा और ब्लाइंड स्पॉट फिर से जांचें।"},"296":{"q":"आप एक भरे हुए ट्रैक्टर-ट्रेलर को व्यस्त चार-लेन हाईवे की दाईं लेन में 55 मील प्रति घंटे की गति से चला रहे हैं। आपकी लेन में आगे एक धीमी गति से चलने वाला रखरखाव ट्रक दिखता है, और आप तय करते हैं कि अपनी गति बनाए रखने के लिए आपको बाईं लेन में जाना होगा। दोनों ओर यातायात घना है। इस लेन परिवर्तन को पूरा करने का सबसे सुरक्षित और सही क्रम कौन-सा है?","options":["तेज़ी से गति बढ़ाकर एक जगह बनाएं और इससे पहले कि कोई उसे भरे, बाईं लेन में घुस जाएं","पहले ज़ोर से ब्रेक लगाकर पीछे जगह बनाएं, फिर गति कम होने के बाद बाईं लेन में जाएं","बाएं शीशे में एक बार देखकर धीरे से सरक जाएं, क्योंकि व्यस्त सड़क पर संकेत देना दूसरे चालकों को केवल भ्रमित करता है","पहले से बायां सिग्नल चालू करें, अपने शीशे और बाएं ब्लाइंड स्पॉट ('No-Zone') की जांच करें, और लेन के साफ होने की पुष्टि के बाद ही लेन बदलें"],"explanation":"पहले से सिग्नल दें, अपने शीशे और बायां ब्लाइंड स्पॉट (नो-ज़ोन) जांचें, और लेन साफ़ होने की पुष्टि के बाद ही हटें।"},"297":{"q":"अपनी प्री-ट्रिप जाँच के दौरान आप पाते हैं कि पिछले चालक ने एक क्षतिग्रस्त टायर बदला था। नया टायर रेडियल है, लेकिन उसी एक्सल पर उसके बगल वाला दूसरा टायर बायस-प्लाई (bias-ply) है। एक्सल की बाकी दो स्थितियाँ आपस में मेल खाती हैं। इस ट्रक को कानूनी और सुरक्षित रूप से चलाने योग्य बनाने से पहले आपको कौन-सी स्थिति ठीक करनी होगी?","options":["एक ही एक्सल पर एक रेडियल टायर को बायस-प्लाई (bias-ply) टायर के बगल में लगा होना","स्टीयरिंग एक्सल का एक टायर जिसमें 4/32 इंच ट्रेड गहराई दिख रही है","एक पिछला (नॉन-स्टीयरिंग) टायर जिसमें 2/32 इंच ट्रेड गहराई दिख रही है","एक ही एक्सल पर एक ही ब्रांड के लेकिन अलग-अलग खरीद तिथियों वाले दो टायर होना"],"explanation":"रेडियल और बायस-प्लाई टायर कभी एक ही एक्सल पर नहीं लगाने चाहिए, क्योंकि उनकी अलग बनावट असमान और अप्रत्याशित पकड़ और हैंडलिंग पैदा करती है।"},"298":{"q":"अपनी प्री-ट्रिप जांच के दौरान आप पाते हैं कि आपके ड्राइव-एक्सल के किसी एक टायर में ट्रेड टायर के मुख्य भाग से अलग होकर छिल रहा है, साथ ही एक लंबा गहरा कट है जो अंदर की कॉर्ड को उजागर कर देता है। टायर अब भी हवा रोके हुए है और बाकी जगहों पर ट्रेड की गहराई 2/32 इंच से काफी ऊपर मापती है। इस टायर पर सही निर्णय क्या है?","options":["गाड़ी चलाना कानूनी है क्योंकि बची हुई ट्रेड गहराई गैर-स्टीयरिंग टायर के लिए 2/32 इंच की न्यूनतम सीमा से अब भी ऊपर है","टायर सेवा से बाहर (out of service) है और वाहन चलाने से पहले इसे बदलना ही चाहिए, चाहे ट्रेड गहराई या हवा का दबाव कुछ भी हो","किसी छोटी स्थानीय यात्रा के लिए यह स्वीकार्य है बशर्ते आप गति कम रखें और पहली रुकावट पर इसे दोबारा जांचें","यह केवल एक मामूली खराबी है क्योंकि टायर ड्राइव एक्सल पर है, स्टीयरिंग एक्सल पर नहीं"],"explanation":"ट्रेड का अलग होना या प्लाई को उजागर करने वाला गहरा कट टायर को सेवा से बाहर कर देता है, इसलिए ट्रेड गहराई या हवा के दबाव की परवाह किए बिना इसे चलाने से पहले बदलना होगा।"},"299":{"q":"अपनी प्री-ट्रिप जांच के दौरान आपको एक टायर मिलता है जिसकी सतह रिकैप्ड (रीट्रेडेड) है और दूसरा जिसके साइडवॉल पर रीग्रूव्ड के निशान हैं। आपके पास डिलीवरी की सख्त समय-सीमा है और आप इन टायरों को बदलने के बजाय अपने ट्रक पर कहीं चालू रखना चाहते हैं। किस एकमात्र पहिया स्थिति पर रीग्रूव्ड या रिकैप्ड टायर लगाना निषिद्ध होगा, जिससे आपको वहां एक उचित नया टायर लगाना पड़ेगा?","options":["पिछले ट्रेलर एक्सल पर, क्योंकि ट्रेलर टायर सबसे भारी भार उठाते हैं और सबसे तेजी से घिसते हैं","अंदरूनी ड्यूल स्थिति पर, क्योंकि वहां छिपा हुआ रिकैप जांचना सबसे कठिन होता है","आगे (स्टीयर) एक्सल की स्थिति पर, जहां रीग्रूव्ड या रिकैप्ड टायर की अनुमति नहीं है","स्पेयर पहिये पर, क्योंकि रिकैप किए गए टायर को कभी भी बैकअप के रूप में नहीं रखा जा सकता"],"explanation":"फिर से खाँचा बनाए गए या रीकैप किए गए टायर अगले स्टीयर एक्सल पर वर्जित हैं, क्योंकि वहाँ स्टीयर टायर के फेल होने से तुरंत स्टीयरिंग नियंत्रण खो जाता है।"},"300":{"q":"अपनी प्री-ट्रिप जांच के दौरान, आप अपने ट्रेलर के पिछले एक्सल पर लगे डुअल टायरों की जांच के लिए नीचे झुकते हैं। दोनों टायर एक ही आकार और ब्रांड के दिखते हैं, और उनकी ट्रेड गहराई भी अच्छी है। उनके बीच के अंतराल को ध्यान से देखते हुए, आपको यह तय करना होगा कि कौन सी स्थिति इस डुअल सेट को अवैध और चलाने के लिए असुरक्षित बना देगी। निम्नलिखित में से कौन सा वह दोष है जिसकी आपको अनुमति नहीं देनी चाहिए?","options":["दोनों टायर बिल्कुल एक ही आकार के हैं और उनके ट्रेड पैटर्न मेल खाते हैं","दोनों टायर मजबूती से फुलाए गए हैं और लगभग समान वायु दबाव बनाए रखते हैं","प्रत्येक टायर पिछले एक्सल पर 2/32 इंच के न्यूनतम से काफी अधिक ट्रेड दिखाता है","दोनों टायर अंदर की ओर उभरकर एक-दूसरे से संपर्क कर रहे हैं"],"explanation":"डुअल टायर कभी एक-दूसरे या वाहन के किसी हिस्से को नहीं छूने चाहिए, क्योंकि संपर्क कम हवा या गलत माउंटिंग दर्शाता है और रगड़ से उत्पन्न गर्मी ब्लोआउट कर सकती है।"},"301":{"q":"एक ठंडी सुबह अपने प्री-ट्रिप निरीक्षण के दौरान, आपको अपने ड्राइव एक्सल के एक पहिये के रिम पर एक दिखाई देने वाली दरार मिलती है। टायर हवा रोके हुए है, ट्रेड अच्छा है, और आप पहले से ही डिलीवरी के लिए देर से चल रहे हैं। कौन सी कार्रवाई सही है?","options":["वाहन को सेवा से बाहर (आउट ऑफ सर्विस) करें और जब तक दरार वाला रिम मरम्मत या बदला न जाए तब तक न चलाएं","सावधानी से डिलीवरी तक चलाएं क्योंकि टायर अभी भी हवा रोके हुए है और ट्रेड की गहराई ठीक है","रिम पर तनाव कम करने के लिए टायर से कुछ पाउंड हवा निकाल दें, फिर कम गति पर जारी रखें","यह केवल एक मामूली कॉस्मेटिक दरार है, इसलिए इसे सामान्य घिसाव के रूप में दर्ज करें और अपने पहले 50-मील कार्गो स्टॉप पर फिर से जांचें"],"explanation":"फटा या टूटा हुआ व्हील रिम स्वतः सेवा से बाहर की स्थिति है, क्योंकि यह भार के नीचे फेल होकर गति में टायर को पहिये से अलग कर सकता है।"},"302":{"q":"अपनी प्री-ट्रिप जांच के दौरान आप ट्रेलर के नीचे जाते हैं और पाते हैं कि पिछले सस्पेंशन की लीफ स्प्रिंग का एक पत्ती पूरी तरह दरक चुका है और एक दूसरा पत्ती अपने माउंटिंग से खिसक गया है। ट्रक अभी भी यार्ड में समतल खड़ा है और छोटे टेस्ट चक्कर में ठीक चलता है। अपनी यात्रा से पहले इस खराबी को सही ढंग से वर्गीकृत करने और निपटाने का सही तरीका क्या है?","options":["चूंकि ट्रक समतल खड़ा है और ठीक चलता है, दरका हुआ पत्ती केवल दिखावटी है और आप उस पर नजर रखते हुए यात्रा कर सकते हैं","यह सस्पेंशन का एक दोष है जिसे वाहन को सेवा में लगाने से पहले ठीक किया जाना चाहिए","यह तब तक स्वीकार्य है जब तक आप पहले 50 मील के भीतर कार्गो की बंधाई दोबारा जांच लेते हैं","यह एक सामान्य स्थिति है जो वास्तव में सवारी को बेहतर बनाती है और इसमें किसी कार्रवाई की आवश्यकता नहीं है"],"explanation":"दरार वाले, टूटे, ढीले, गायब या खिसके हुए लीफ स्प्रिंग एक सेवा-से-बाहर सस्पेंशन दोष हैं जिन्हें वाहन को सेवा में लाने से पहले ठीक करना होगा।"},"303":{"q":"सुबह जल्दी का समय है और आप प्री-ट्रिप निरीक्षण के दौरान अपने ट्रैक्टर-ट्रेलर के चारों ओर घूम रहे हैं। पिछले सस्पेंशन पर आप एक शॉक अब्ज़ॉर्बर पर लगी गीली, तैलीय परत और धूल-कवच तक बहती तरल की एक पतली धार देखते हैं। उस एक्सल पर बाकी सब कुछ सामान्य दिखता है। इस पुर्ज़े के बारे में सही निष्कर्ष क्या है और आपको क्या करना चाहिए?","options":["तैलीय परत बस टायरों से उछली सड़क की गंदगी है, इसलिए शॉक अब्ज़ॉर्बर जैसा है वैसा ठीक है और आप यात्रा जारी रख सकते हैं।","शॉक अब्ज़ॉर्बर इस तरह बनाए जाते हैं कि चिकनाई बनाए रखने के लिए थोड़ा तेल रिसने दें, इसलिए हल्की परत स्वीकार्य है और केवल भारी, टपकता हुआ रिसाव ही दोष माना जाएगा।","रिसता हुआ शॉक अब्ज़ॉर्बर एक दोष है; शॉक अब्ज़ॉर्बर सुरक्षित रूप से कसे हुए और रिसावमुक्त होने चाहिए, इसलिए वाहन को चलाने के लिए सुरक्षित बनाने से पहले इसे ठीक करना ज़रूरी है।","शॉक अब्ज़ॉर्बर कोई भार नहीं उठाते और केवल सवारी के आराम को प्रभावित करते हैं, इसलिए रिसाव एक मामूली दिखावटी समस्या है जिसे आप बस नोट कर सकते हैं और अगली 150-मील कार्गो जाँच पर ठीक कर सकते हैं।"],"explanation":"शॉक अब्ज़ॉर्बर मजबूती से लगे और रिसाव-मुक्त होने चाहिए, इसलिए रिसता शॉक एक दर्ज करने योग्य दोष है जिसे वाहन चलाने से पहले ठीक करना होगा।"},"304":{"q":"अपनी यात्रा-पूर्व जांच के दौरान आप ट्रैक्टर के नीचे जाते हैं और पाते हैं कि लीफ-स्प्रिंग हैंगर के पास एक फ्रेम रेल में से एक ताजा दरार गुजर रही है, और इंजन के एक माउंट में साफ तौर पर ढीलापन दिख रहा है। आप पहले से ही समतल शहरी सड़कों पर 40 मील की एक छोटी स्थानीय डिलीवरी के लिए देर से चल रहे हैं। कौन सी कार्रवाई सही है?","options":["चूंकि यह समतल सड़कों पर केवल एक छोटी, कम गति की यात्रा है, आप इसे डिलीवरी तक चला सकते हैं और दरार की सूचना बाद में दे सकते हैं","दरार वाले हिस्से को भारी-ड्यूटी टेप से कसकर लपेट दें और जो हाथ से कस सकें कस दें ताकि यह दिन के अंत तक टिक जाए","कम गति पर चलाएं और पहले 50 मील के भीतर फ्रेम और माउंट का दोबारा निरीक्षण करें, क्योंकि तभी माल की बंधाई जांची जाती है","वाहन को सेवा से बाहर कर दें और चलाने से पहले ही दरार वाले फ्रेम और ढीले माउंट की मरम्मत करवाएं"],"explanation":"फटा हुआ फ्रेम या ढीला माउंट एक संरचनात्मक सेवा-से-बाहर दोष है, क्योंकि फ्रेम हर भार को संभालता है और दरार बढ़कर विनाशकारी रूप से फेल हो सकती है।"},"305":{"q":"सुबह जल्दी की ढुलाई में तापमान हिमांक से थोड़ा नीचे है, इसलिए आप केबिन की खिड़कियां बंद रखते हैं और हीटर चालू रखते हैं। प्री-ट्रिप जांच में आपने देखा कि जहां एग्ज़ॉस्ट पाइप मफलर से जुड़ता है वहां एक छोटा रिसाव है, लेकिन इंजन ठीक चल रहा था, इसलिए आपने चलाने का फैसला किया। एक घंटे बाद आपको नींद और हल्का सिरदर्द महसूस होता है। उस एग्ज़ॉस्ट रिसाव का कौन सा परिणाम चलाने से पहले इसे ठीक करने का सबसे गंभीर कारण है?","options":["कार्बन मोनोऑक्साइड सहित एग्ज़ॉस्ट गैसें बंद केबिन में रिसकर आपको ज़हर दे सकती हैं","रिसाव केबिन में बाहर की ठंडी हवा आने देता है और हीटर पर अधिक भार डालता है","रिसता हुआ एग्ज़ॉस्ट इंजन की शक्ति घटाता है और चढ़ाई पर ईंधन बर्बाद करता है","रिसाव से इंजन ज़्यादा आवाज़ करता है और अन्य चेतावनी ध्वनियों को छिपा सकता है"],"explanation":"रिसने वाला एग्ज़ॉस्ट सिस्टम खतरनाक है, क्योंकि कार्बन मोनोऑक्साइड सहित निकास गैसें बंद केबिन में रिसकर चालक को विषाक्त कर सकती हैं।"},"306":{"q":"अपने प्री-ट्रिप निरीक्षण के दौरान, आप बैटरी बॉक्स खोलते हैं और पाते हैं कि बैटरी थोड़ी हिल रही है और उसके नीचे की ट्रे में तरल का एक छोटा सा गड्ढा बना है। केबल जुड़े हुए हैं और ट्रक ठीक से चालू हो जाता है। टेक्सास DPS निरीक्षण मानकों के अनुसार, इस वाहन को कानूनी रूप से सड़क पर ले जाने से पहले बैटरी को किस शर्त को पूरा करना चाहिए?","options":["उसे केवल इंजन चालू करने जितना चार्ज होना चाहिए, क्योंकि चालू होने की क्षमता यह साबित करती है कि बैटरी सड़क के योग्य है","उसे एक होल्ड-डाउन से मजबूती से अपनी जगह पर बंधा होना चाहिए ताकि वह हिल न सके, और उसमें रिसाव नहीं होना चाहिए","जब तक तरल का स्तर प्लेटों के ऊपर रहता है, तब तक इलेक्ट्रोलाइट का मामूली रिसाव स्वीकार्य है","छोटी यात्राओं में ढीली बैटरी ठीक है क्योंकि केवल केबल ही उसे हिलने से रोक देते हैं"],"explanation":"बैटरी को होल्ड-डाउन से मजबूती से जकड़ा होना चाहिए ताकि वह हिले नहीं और उसमें रिसाव न हो, क्योंकि खिसकती या रिसती बैटरी शॉर्ट हो सकती है, फट सकती है या संक्षारक अम्ल गिरा सकती है।"},"307":{"q":"एक लंबी यात्रा के अंत में आप एक ईंधन (फ्यूल) स्टेशन पर पहुँचते हैं। आपके ट्रेलर की रेफ्रिजरेशन (रीफर) यूनिट अभी भी चल रही है, आपके फोन की बैटरी 8% है इसलिए आप जल्दी से एक कॉल करना चाहते हैं, और पास में इंतज़ार कर रहे एक सह-चालक ने पंपों से लगभग 6 मीटर दूर अभी-अभी एक सिगरेट जलाई है। टैंक में डीज़ल भरना शुरू करने से पहले, निम्नलिखित में से कौन-सा सही कार्य है?","options":["इंजन को चालू (आइडल) रहने दें ताकि एयर सिस्टम और रीफर में दबाव और ठंडक बनी रहे, लेकिन ईंधन की नोज़ल को स्थिर रखें और धीरे-धीरे भरें","ट्रक को चालू रखें लेकिन टैंक भरते समय फोन कॉल के लिए दूर हट जाएँ, क्योंकि ऑटो शट-ऑफ नोज़ल प्रवाह को रोक देगी","इंजन बंद कर दें, धूम्रपान न करें और ईंधन भरने वाले स्थान के पास किसी को धूम्रपान न करने दें, और ईंधन भरते समय नोज़ल के पास रहें","सिगरेट को रहने दें क्योंकि वह 4.5 मीटर से अधिक दूर है, और भरने से पहले लाइनों को साफ करने के लिए इंजन को थोड़ा रेव कर लें"],"explanation":"डीज़ल के वाष्प आसानी से आग पकड़ लेते हैं, इसलिए इंजन बंद हो, ईंधन स्थल पर धूम्रपान न हो और भरते समय कोई हमेशा नोज़ल के पास रहे।"},"309":{"q":"सर्दियों की सुबह तापमान हिमांक से थोड़ा नीचे है और आप एक लंबी यात्रा से पहले अपनी प्री-ट्रिप जाँच कर रहे हैं। इंजन कंपार्टमेंट की जाँच करते समय, आप यह सुनिश्चित करना चाहते हैं कि ठंड में चलते समय आपका वाहन न तो अधिक गर्म हो और न ही जम जाए। कौन-सी जाँच आपके सामने आने वाली सर्दियों की परिस्थितियों से शीतलन प्रणाली की सीधे रक्षा करती है?","options":["पुष्टि करें कि विंडशील्ड वॉशर टंकी भरी हुई है ताकि आप शीशे से सड़क की कीचड़ साफ कर सकें","रेडिएटर में सादा पानी भरें ताकि साइट ग्लास पर शीतलक का स्तर पूरा दिखे","अतिरिक्त इंजन तेल डालें क्योंकि ठंड में तेल गाढ़ा होकर तेज़ी से जलता है","पुष्टि करें कि शीतलक में पर्याप्त एंटीफ्रीज़ है ताकि वह कम तापमान पर न जमे"],"explanation":"एंटीफ्रीज़ शीतलक का हिमांक घटाता है, इसलिए ठंड में यह पक्का करें कि शीतलक को जमने और इंजन को फटने से रोकने के लिए पर्याप्त एंटीफ्रीज़ हो।"},"310":{"q":"एक पहाड़ी दर्रे पर तापमान हिमांक से ठीक नीचे है, बर्फ गिर रही है, और एक लगा हुआ संकेत बताता है कि इस बिंदु के आगे जंजीरें (चेन) अनिवार्य हैं। आप रुककर अपने ड्राइव टायरों पर टायर चेन लगाते हैं। चढ़ाई पर सुरक्षित रूप से आगे बढ़ने में चेन आपकी मदद करने का मुख्य कारण क्या है?","options":["वे बर्फ और हिम में पकड़ बनाती हैं, जिससे आपके ड्राइव टायरों को फिसलन भरी सतह पर पकड़ बनाए रखने के लिए आवश्यक कर्षण (ट्रैक्शन) मिलता है","वे लुढ़कने के प्रतिरोध को कम करती हैं, जिससे लंबी चढ़ाई पर आपके ईंधन की खपत घटती है","वे बर्फ से ढकी सड़क पर ड्राइव एक्सल पर कानूनी रूप से अधिक वजन ढोने की अनुमति देती हैं","वे चाल को नरम बनाती हैं और जमी हुई बर्फ पर ट्रक को शांत चलाती हैं"],"explanation":"टायर चेन बर्फ और हिम में धंसकर ड्राइव टायरों को फिसलन भरी सतह पर पकड़ देती हैं ताकि वे बिना घूमे शक्ति पहुँचा सकें।"},"311":{"q":"आप रात में एक विभाजित राजमार्ग पर लदा हुआ संयोजन वाहन चला रहे हैं और देखते हैं कि आपके आगे चल रही कार अजीब तरह से व्यवहार कर रही है। कौन सा अवलोकन इस बात का सबसे प्रबल संकेत है कि आगे वाला चालक नशे में या प्रभावित हो सकता है, जो आपको बताता है कि अपनी अनुसरण दूरी बढ़ाएँ और उसे काफी आगे निकल जाने दें?","options":["कार एक स्थिर गति बनाए रखती है और हल्के मोड़ पर अपनी लेन के बीच में बनी रहती है","कार लेन की लाइनों को पार करते हुए इधर-उधर डगमगाती है और बिना किसी स्पष्ट कारण के बार-बार तेज़ और धीमी होती रहती है","कार लेन बदलने से पहले जल्दी संकेत देती है और हटने से पहले एक साफ़ अंतराल की प्रतीक्षा करती है","कार धीरे-धीरे गति कम करती है और अपनी आपातकालीन फ्लैशर लाइटें जलाकर दाहिने किनारे की ओर चली जाती है"],"explanation":"लेन की रेखाओं के आर-पार लहराना और बिना कारण अनियमित रूप से तेज़-धीमा होना नशे में धुत चालक के स्पष्ट संकेत हैं, इसलिए उससे काफी दूरी रखें।"},"313":{"q":"आप एक ग्रामीण राजमार्ग पर लदा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं, तभी आपका एक्सेलेरेटर पेडल अचानक फर्श से चिपक जाता है और पैर हटाने के बाद भी इंजन तेज़ चलता रहता है। यातायात कम है और आगे एक पक्का किनारा (शोल्डर) है। वाहन पर फिर से नियंत्रण पाने के लिए आपका पहला प्राथमिक कदम क्या होना चाहिए?","options":["इंजन ब्रेकिंग न खोने के लिए गियर लगे रखते हुए, पेडल को छुड़ाने की कोशिश में अपने पैर से एक्सेलेरेटर पेडल को तेज़ी से दबाएं","गियर लगे रहते हुए ही इग्निशन चाबी से तुरंत इंजन बंद कर दें ताकि ड्राइव पहिए ट्रक को आगे खींचना बंद कर दें","इंजन को ड्राइव पहियों से अलग करने के लिए गियर को न्यूट्रल में डालें, फिर वाहन को सुरक्षित रूप से धीमा करके रोकने के लिए ब्रेक लगाएं","गियर लगे रहने दें और किनारे तक पहुंचने तक इंजन पर काबू पाने के लिए केवल स्थिर, हल्के ब्रेक दबाव पर निर्भर रहें"],"explanation":"न्यूट्रल में डालने से इंजन ड्राइव पहियों से अलग हो जाता है, ताकि एक्सेलरेटर अटकने पर ब्रेक वाहन को धीमा कर रोक सकें।"},"314":{"q":"आपको कुछ जलने की गंध आती है और आप सुरक्षित रूप से किनारे रोक देते हैं। केबिन खोलने पर आप डैशबोर्ड के पीछे वायरिंग के पास से लपटें निकलती देखते हैं, और ऐसा लगता है कि बैटरी और अल्टरनेटर के सर्किट प्रभावित हैं। आपके केबिन में एक अग्निशामक यंत्र लगा है। इस आग को नियंत्रित करने का सबसे अच्छा और सबसे सुरक्षित मौका कौन-सा कार्य देता है?","options":["वायरिंग देखने के लिए बिजली चालू रखें, फिर लपटों को ठंडा करने के लिए उनके आधार पर पानी की एक स्थिर धार डालें","कुछ भी करने से पहले गर्मी और धुआं बाहर निकलने देने के लिए इंजन का हुड और पिछले दरवाजे पूरे खोल दें","इंजन चालू रखें ताकि अल्टरनेटर चार्ज करता रहे, और केबिन के एक गीले कपड़े से लपटों को दबा दें","यदि संभव हो तो बिजली बंद कर दें (बैटरी अलग करें / इग्निशन बंद करें), फिर B:C श्रेणी के अग्निशामक यंत्र से इसे बुझाएं"],"explanation":"बिजली की आग में, यदि सुरक्षित हो तो पहले बिजली बंद कर इग्निशन स्रोत हटाएँ, फिर पानी के बजाय B:C रेटेड अग्निशामक से इसे बुझाएँ।"},"315":{"q":"एक पहाड़ी की चोटी पार करते ही आपके इंजन की शक्ति घट जाती है और आप दो-लेन वाले ग्रामीण राजमार्ग की दाईं लेन में लुढ़ककर रुक जाते हैं। आप अपनी ख़तरे की चमकती बत्तियाँ (हैज़र्ड फ़्लैशर) चालू करते हैं और अपने आपातकालीन त्रिकोण उठाते हैं। आपका सह-चालक कहता है कि जल्दी की कोई बात नहीं क्योंकि यातायात कम है। सड़क पर रुकने के नियमों के अनुसार, अपने चेतावनी उपकरण लगाने से पहले आप अधिकतम कितनी देर तक प्रतीक्षा कर सकते हैं?","options":["रुकने के 10 मिनट के भीतर","रुकने के 1 घंटे के भीतर, जब तक फ़्लैशर चालू रहें","रुकने के 1 मिनट के भीतर","आपके चालन दिवस के अंत तक, क्योंकि हैज़र्ड बत्तियाँ पहले से ही यातायात को चेतावनी दे रही हैं"],"explanation":"सड़क या किनारे पर रुकने के बाद तुरंत खतरे की चेतावनी लाइटें चालू करें और 10 मिनट के भीतर अपने तीन परावर्तक चेतावनी त्रिकोण रखें।"},"316":{"q":"आपका ट्रक ग्रामीण दो-लेन सड़क पर जैकनाइफ हो गया है और जिस कार को आपने छुआ उसका चालक स्टीयरिंग पर झुका हुआ है - होश में है पर गर्दन में दर्द की शिकायत कर रहा है। यातायात कम है, मौसम साफ है, और आपको कूलेंट की गंध आ रही है पर धुआँ या आग नहीं दिख रही। टेक्सास DPS के दिशानिर्देशों के अनुसार, इस घायल व्यक्ति को वाहन से बाहर कब निकालना चाहिए?","options":["तुरंत, क्योंकि गर्दन का दर्द रीढ़ की चोट दर्शाता है और उसे ज़मीन पर सीधा लिटाना ज़रूरी है","केवल तभी जब आग जैसा कोई वास्तविक खतरा पैदा हो; अन्यथा उसे वहीं रहने दें और प्रशिक्षित सहायता का इंतज़ार करें","जैसे ही आप अपने तीन परावर्तक त्रिकोण 10, 100 और 200 फीट पर रख दें","जब यातायात जमा होने लगे, ताकि लेन खोली जा सके और अन्य चालक सुरक्षित रहें"],"explanation":"घायल व्यक्ति को तब तक न हिलाएँ जब तक आग जैसा कोई वास्तविक खतरा न हो, क्योंकि गर्दन या रीढ़ की चोट वाले को हिलाने से स्थायी लकवा हो सकता है।"},"317":{"q":"सुबह के 5:30 बजे हैं और आपकी डिलीवरी की समय-सीमा है। कल रात आपने कई बीयर पी थीं और लगभग चार घंटे पहले पीना बंद किया। गाड़ी चलाने के लिए तैयार महसूस करने के वास्ते आप दो बड़े कप काली कॉफी पीते हैं, ठंडी सुबह की हवा में तेज़ चहलकदमी करते हैं और केबिन का थर्मामीटर जाँचते हैं। इनमें से कौन-सा कदम वास्तव में आपके खून में बचे अल्कोहल को कम करेगा ताकि आप अपना वाणिज्यिक वाहन (CMV) सुरक्षित और कानूनी रूप से चला सकें?","options":["ठंडी सुबह की हवा, क्योंकि ताज़ी हवा को गहराई से साँस लेने से शरीर अल्कोहल को तेज़ी से बाहर निकालता है","दो बड़े कप काली कॉफी, क्योंकि कैफीन आपके चयापचय को तेज़ करती है और बचे हुए अल्कोहल को जला देती है","इनमें से कोई भी कदम नहीं; केवल पर्याप्त समय बीतने से ही अल्कोहल आपके खून से निकलेगा और आपका BAC 0.04% की सीमा से नीचे आएगा","तीनों मिलाकर, क्योंकि कॉफी, ठंडी हवा और सतर्क रहना मिलकर आपकी शिफ्ट से पहले आपको होश में ला देते हैं"],"explanation":"केवल समय ही लीवर को शराब पचाकर आपका BAC घटाने देता है; कॉफी, ताज़ी हवा या सतर्क महसूस करना इस प्रक्रिया को तेज़ नहीं कर सकते।"},"318":{"q":"आप एक लंबी यात्रा के 9 घंटे पूरे कर चुके हैं और आपको नींद आने लगी है। ट्रक स्टॉप पर एक साथी चालक आपको कैफीन की गोलियाँ और उत्तेजक दवाएँ (\"अपर्स\") देता है, यह दावा करते हुए कि ये आपको अपनी यात्रा सुरक्षित रूप से पूरी करने जितना सतर्क रखेंगी। इन्हें मना करके इसके बजाय रुककर आराम करने का सबसे अच्छा कारण निम्न में से कौन-सा है?","options":["उत्तेजक दवाएँ ठीक हैं, बशर्ते आप उनके असर को संतुलित करने के लिए साथ में कॉफी पिएँ और ताज़ी हवा लें","उत्तेजक दवाएँ आपकी प्रतिक्रिया तेज़ करती हैं और रात की दृष्टि सुधारती हैं, परंतु इन्हें केबिन में रखना अवैध है","उत्तेजक दवाएँ केवल 419 फीट से लंबी ढलानों पर स्वीकार्य हैं, जहाँ अतिरिक्त सतर्कता की आवश्यकता होती है","उत्तेजक दवाएँ आपको सुरक्षित चालक नहीं बनातीं; जब उनका असर खत्म होता है तो आप पहले से अधिक थके और खतरनाक हो सकते हैं"],"explanation":"उत्तेजक केवल थकान को अस्थायी रूप से छिपाते हैं और आपको सुरक्षित नहीं बनाते; इनका असर खत्म होने पर आप पहले से ज़्यादा थके और खतरनाक हो सकते हैं।"},"319":{"q":"आप चार-लेन वाले राजमार्ग की दाईं लेन में 55 मील प्रति घंटे की गति से चल रहे हैं। लगभग एक चौथाई मील आगे, आप दाईं ओर की शोल्डर पर खड़ी एक खराब कार देखते हैं जिसकी हैज़र्ड फ्लैशर लाइटें जल रही हैं, और एक व्यक्ति उसके पास डिक्की के निकट खड़ा है। आपको इसे खतरा क्यों मानना चाहिए और और करीब आने का इंतज़ार करने के बजाय अभी से समायोजन शुरू कर देना चाहिए?","options":["खड़ी कार या उसके पास खड़ा व्यक्ति अचानक आपकी लेन में आ सकता है, इसलिए आपको गति धीमी करनी चाहिए, अपनी अनुसरण दूरी बढ़ानी चाहिए और सुरक्षित हो तो बाईं ओर हट जाना चाहिए।","शोल्डर धीमे यातायात के लिए कानूनी रूप से चलने का क्षेत्र है, इसलिए आपको खराब कार को पूरी लेन देने के लिए उस पर चले जाना चाहिए।","यह केवल तभी खतरा है जब चालक ने तीन चेतावनी त्रिकोण 10, 100 और 200 फीट पर न रखे हों; अन्यथा आप अपनी गति बनाए रख सकते हैं।","शोल्डर पर खड़ी खराब कार तब तक कोई वास्तविक जोखिम नहीं है जब तक उसकी फ्लैशर लाइटें जल रही हैं, इसलिए गति या स्थिति में कोई बदलाव आवश्यक नहीं है।"],"explanation":"रुकी हुई कार या उसके पास खड़ा व्यक्ति अचानक आपकी लेन में आ सकता है, इसलिए गति कम करें, अनुसरण दूरी बढ़ाएँ और सुरक्षित होने पर बाईं ओर हट जाएँ।"},"320":{"q":"आप मार्ग के बीच में एक विश्राम स्थल पर रुकते हैं, और केबिन में वापस चढ़ने से पहले आप झुककर अपने ट्रैक्टर-ट्रेलर के नीचे एक त्वरित नज़र डालते हैं। यह पुष्टि करने के अलावा कि कुछ भी घिसट नहीं रहा, हैंडबुक किसी ठहराव पर वाहन के नीचे ज़मीनी स्तर की यह संक्षिप्त नज़र डालने की सलाह क्यों देती है, इसका मुख्य सुरक्षा कारण क्या है?","options":["यह आपको टायर ट्रेड गहराई मापक पढ़ने देता है ताकि पुष्टि हो सके कि स्टीयरिंग टायरों में अब भी कम से कम 4/32 इंच ट्रेड बचा है","यह चलने से पहले ताज़ा द्रव रिसाव, कम हवा वाले या पंक्चर टायर, और वाहन के नीचे या पीछे मौजूद लोगों या वस्तुओं को उजागर कर सकता है","यह यात्रा के पहले 50 मील के भीतर अपने माल का पुनः निरीक्षण और पुनः कसने की आवश्यकता को पूरा करता है","यही वह तरीका है जिससे आप चलने से पहले अपने तीन चेतावनी त्रिकोण 10, 100 और 200 फीट पर रखते हैं"],"explanation":"चलने से पहले ज़मीन-स्तर की जाँच ताज़ा तरल रिसाव, पंक्चर या कम हवा वाले टायर, और रिग के नीचे या पीछे मौजूद लोगों या वस्तुओं को उजागर करती है।"},"321":{"q":"आप एक भरा हुआ ट्रेलर खींच रहे हैं और एक लंबी, तीखी पहाड़ी ढलान की चोटी पर पहुँचते हैं। एक लगा हुआ संकेत आगे 6% ढलान की चेतावनी देता है। उतरते समय अपने ब्रेक को गर्म होकर कमज़ोर पड़ने (फेड होने) से बचाने के लिए, आपको उतराई के लिए जिस निचले गियर का उपयोग करना है, उसे कब चुनना चाहिए?","options":["जिस बिंदु पर आपको पहली बार महसूस हो कि ब्रेक गर्म होकर कमज़ोर पड़ने लगे हैं","ढलान के लगभग आधे रास्ते पर, जब आप अंदाज़ा लगा सकें कि यह वास्तव में कितनी तीखी है","ढलान उतरना शुरू करने से पहले, जब आप अभी भी चोटी पर हों","केवल तभी जब लदान खिसक जाए या आपकी गति सुरक्षित स्तर से ऊपर चली जाए"],"explanation":"लंबी, तीव्र ढलान उतरना शुरू करने से पहले, जब आप अभी भी ऊपर हों, तभी निचला गियर चुन लें।"},"322":{"q":"आप एक भरे हुए ट्रेलर के साथ एक लंबी, खड़ी पहाड़ी ढलान से नीचे उतर रहे हैं। उतराई के लगभग आधे रास्ते पर आपको गर्म ब्रेक की गंध आती है और पेडल ऊपर की तुलना में नरम महसूस होने लगता है। निम्नलिखित में से कौन-सी क्रिया शेष उतराई के लिए आपकी गति पर सबसे सुरक्षित नियंत्रण देती है?","options":["गति को स्थिर रखने के लिए पूरे रास्ते ब्रेक पेडल पर लगातार, दृढ़ दबाव बनाए रखें","इंजन को ठंडा होने देने के लिए न्यूट्रल में डालें, फिर नीचे तक हल्के से ब्रेक लगाते रहें","हवा का दबाव वापस बनाने और दृढ़ पेडल बहाल करने के लिए ब्रेक पेडल को तेजी से पंप करें","कम गियर में रहें ताकि इंजन आपको रोकने में मदद करे, और केवल हल्के, रुक-रुक कर ब्रेक लगाएं"],"explanation":"ढलान पर गति नियंत्रण मुख्यतः इंजन और गियर ब्रेकिंग से होता है, इसलिए निचले गियर में रहें और ब्रेक को ठंडा होने देने के लिए केवल हल्के, रुक-रुक कर ब्रेक लगाएँ।"},"323":{"q":"आप एक लदे हुए ट्रेलर के साथ एक लंबी, खड़ी पहाड़ी ढलान से नीचे उतर रहे हैं। अपनी गति को नियंत्रण में रखने के लिए, आप कम गियर का उपयोग करने के बजाय पूरे रास्ते नीचे तक सर्विस ब्रेक पर लगातार और स्थिर दबाव बनाए रखते हैं। जैसे ही आप ढलान के निचले सिरे के पास पहुँचते हैं, इस तरह ब्रेक का उपयोग करने का सबसे संभावित परिणाम क्या होगा?","options":["ब्रेक ज़्यादा गरम होकर अपनी पकड़ खो देंगे (ब्रेक फेड), और ठीक उसी समय रुकने की शक्ति खो देंगे जब आपको उसकी सबसे ज़्यादा ज़रूरत होगी","ब्रेक जितनी देर तक दबाए रखेंगे, उतनी ही मज़बूती से पकड़ेंगे, जिससे आपको अतिरिक्त नियंत्रण मिलेगा","ड्रम के ऊपर से बहती लगातार हवा ब्रेक को ठंडा रखेगी और वे सामान्य रूप से काम करते रहेंगे","ब्रेक एक समान घिसेंगे और अधिक समय तक चलेंगे क्योंकि दबाव सहज और स्थिर है"],"explanation":"लंबी ढलान पर लगातार, स्थिर ब्रेकिंग गर्मी को निकलने की तुलना में तेज़ी से बढ़ाती है, जिससे ब्रेक अधिक गर्म होकर फीके पड़ जाते हैं और रोकने की शक्ति खो देते हैं।"},"324":{"q":"आप पूरी तरह लदे ट्रेलर के साथ एक लंबी, तीखी पहाड़ी ढलान से नीचे उतर रहे हैं। आधे रास्ते में आपको हल्की जलने की गंध आती है, ब्रेक पेडल ढीला पड़ने लगता है, और ब्रेक दबाने के बावजूद ट्रक की रफ्तार बढ़ती जा रही है। आगे एक संकेत दिखता है \"रनअवे ट्रक रैंप 1 मील।\" उस रैंप का मुख्य उद्देश्य क्या है, और यहाँ आपको इसकी आवश्यकता क्यों पड़ सकती है?","options":["यह एक निर्धारित रुकने का स्थान है जहाँ आपको उतराई जारी रखने से पहले 30 मिनट तक रुककर ब्रेक ठंडे करने होते हैं।","यह उस बेकाबू वाहन को सुरक्षित रूप से रोकने के लिए बनाया गया है जो ब्रेक लगाने की क्षमता खो चुका है, जैसे जब लंबी ढलान पर ब्रेक अधिक गर्म होकर अपनी क्षमता खो देते हैं।","यह वजन-केंद्र को बायपास करने वाली लेन है जहाँ उतरते ट्रक ढलान के नीचे पहुँचने से पहले अपने एक्सल भार की जाँच करते हैं।","यह बड़े आकार के ट्रकों के मुड़ने का स्थान है जो तीखी ढलान का बाकी हिस्सा सुरक्षित रूप से पूरा नहीं कर सकते।"],"explanation":"एस्केप रैंप उस अनियंत्रित वाहन को सुरक्षित रूप से रोकने के लिए बनाया गया है जिसने ब्रेकिंग क्षमता खो दी हो, जैसे लंबी ढलान पर ब्रेक के अधिक गर्म होकर फीके पड़ने से।"},"327":{"q":"आप बिना गेट और सिग्नल वाले एक बहु-पटरी रेलवे क्रॉसिंग पर रुके हुए हैं। एक मालगाड़ी पास वाली पटरी से गड़गड़ाहट के साथ गुज़रती है और आखिरकार आपके बाईं ओर निकल जाती है। दोनों पटरियों के साथ दृश्य पेड़ों से आंशिक रूप से बाधित है, और आप देख सकते हैं कि आपके पास सभी पटरियों को, अपने वाहन की पूरी लंबाई और लगभग 15 फीट अतिरिक्त सहित, पूरी तरह पार करने की जगह है। ब्रेक छोड़कर पटरियों को पार करना शुरू करने से पहले सबसे महत्वपूर्ण क्या करना है?","options":["पटरियों को पार करते समय अधिकतम खिंचाव शक्ति पाने के लिए अपने सबसे निचले गियर में डालना","आगे बढ़ने से पहले यह पुष्टि करना कि क्रॉसिंग के रंगे हुए गेट हाथ पूरी तरह ऊपर उठे हैं","दूसरी पटरी को दोनों दिशाओं में जाँचना कि कहीं कोई दूसरी ट्रेन तो नहीं जिसे पहली ट्रेन ने छिपा दिया हो","ट्रेन के निकलने के बाद पूरे 15 सेकंड प्रतीक्षा करना, फिर बिना और जाँच किए आगे बढ़ना"],"explanation":"दूसरी ट्रेन अभी-अभी गुज़री ट्रेन के पीछे छिपी हो सकती है, इसलिए पार करने से पहले हर पटरी पर दोनों दिशाओं में देखें।"},"328":{"q":"आपके डिलीवरी क्षेत्र में लगभग तीन हफ्तों से बारिश नहीं हुई है, और जैसे ही आप एक व्यस्त दो-लेन वाली सड़क पर मुड़ते हैं, हल्की बारिश शुरू हो जाती है। हालाँकि सड़क मुश्किल से गीली दिखती है, फिर भी हल्के ब्रेक लगाने पर आप तुरंत महसूस करते हैं कि ट्रेलर अस्थिर हो रहा है। यह शुरुआती हल्की बारिश उसी तूफान में बाद में आने वाली तेज़ मूसलाधार बारिश की तुलना में आपकी पकड़ (ट्रैक्शन) के लिए ज़्यादा खतरनाक क्यों है?","options":["पानी की पतली परत सड़क को ठंडा कर देती है, जिससे टायरों का रबर सख्त हो जाता है और पकड़ कम हो जाती है","हल्की बारिश सड़क को धो नहीं सकती, इसलिए बाद में आने वाली तेज़ बारिश असल में आपको बेहतर टायर पकड़ देगी","हल्की बारिश टायर का दबाव बढ़ा देती है, और ज़्यादा हवा भरे टायर छोटे संपर्क क्षेत्र पर चलते हैं","पहला पानी सूखी सड़क पर जमा तेल और धूल के साथ मिल जाता है, और तेज़ बारिश के उसे धोने से पहले ही उन्हें एक फिसलन भरी परत के रूप में ऊपर उठा देता है"],"explanation":"सूखे के बाद पहली बारिश फिसलन भरी होती है क्योंकि हल्का पानी जमा तेल और धूल से मिलकर एक चिकनी परत बना देता है, इससे पहले कि तेज़ बारिश उसे धो सके।"},"329":{"q":"आपने अभी एक बाढ़ग्रस्त निचले जल क्रॉसिंग को पार किया है जहाँ पानी इतना गहरा था कि वह पहियों के हब तक पहुँच गया। जब आप सूखे राजमार्ग पर वापस गति बढ़ाते हैं और एक चौथाई मील आगे एक चौराहे के पास पहुँचते हैं, तो आपकी पहली रुकावट पर ब्रेक पेडल नरम और कमजोर महसूस होता है। गति में ब्रेक पर निर्भर होने से पहले ब्रेकिंग को बहाल करने के लिए सही कार्रवाई क्या है?","options":["धीमी गति से चलते हुए ब्रेक पर हल्का, कोमल दबाव डालें ताकि उन्हें घर्षण की गर्मी से जाँचा और सुखाया जा सके","अगली रुकावट से पहले ड्रम से पानी बाहर निकालने के लिए ब्रेक पेडल को जोर से और तेजी से पंप करें","राजमार्ग की गति तक तेज करें ताकि हवा और इंजन की गर्मी ब्रेक को जल्दी सुखा दे","आगे बढ़ने से पहले ब्रेक को प्राकृतिक रूप से हवा में सूखने देने के लिए इंजन बंद करके लुढ़कने दें"],"explanation":"गहरे पानी से ब्रेक लाइनिंग गीली होने के बाद, धीरे चलाते हुए हल्का, कोमल ब्रेक दबाव लगाएँ ताकि घर्षण की गर्मी उन्हें सुखाकर सामान्य ब्रेकिंग बहाल कर दे।"},"330":{"q":"आप लगातार बारिश में 50 मील प्रति घंटे की गति से एक अंतरराज्यीय राजमार्ग पर आंशिक भार ले जा रहे हैं। आगे की सड़क पानी की एक निरंतर परत जैसी दिखती है और आपको अपने टायरों और सड़क की सतह के बीच एक पतली परत बनती हुई महसूस होती है। अचानक स्टीयरिंग व्हील आपके हाथों में अलग महसूस होता है। कौन सा बदलाव यह सबसे स्पष्ट चेतावनी होगा कि आपके टायरों की पकड़ खत्म हो गई है और आप हाइड्रोप्लेनिंग शुरू कर रहे हो सकते हैं?","options":["स्टीयरिंग अचानक आपका विरोध करता है और भारी, कठोर और मोड़ने में मुश्किल महसूस होता है","स्टीयरिंग अचानक हल्का और आसानी से मुड़ने वाला महसूस होता है, मानो वह ढीला हो गया हो","आपकी गति स्थिर होने के बावजूद आप इंजन को स्पष्ट रूप से तेज आवाज करते हुए सुनते हैं","आप केबिन के वेंट से आती हुई तेज ईंधन की गंध महसूस करते हैं"],"explanation":"जब टायर गीली सतह पर पकड़ खो देते हैं और पानी की परत पर चलने लगते हैं, तो स्टीयरिंग अचानक हल्का और आसानी से घूमने वाला महसूस होता है।"},"331":{"q":"आप शाम 6:00 बजे ड्यूटी से बाहर हुए और पूरे 10 घंटे का विश्राम लिया, फिर सुबह 4:00 बजे ड्यूटी पर आए और बिना रुके गाड़ी चलाते रहे। एक डिस्पैचर आप पर दबाव डालता है कि आप चलते रहें, क्योंकि उसके अनुसार आपके 14-घंटे के विंडो में अभी भी घंटे बचे हैं। 14-घंटे के ड्यूटी विंडो को एक तरफ रखते हुए, इस कार्य पाली के दौरान आपको वास्तव में अधिकतम कितने घंटे गाड़ी चलाने की अनुमति है?","options":["8 घंटे गाड़ी चलाना, क्योंकि तभी 30 मिनट का विश्राम अनिवार्य हो जाता है और आपकी पाली व्यावहारिक रूप से समाप्त हो जाती है","14 घंटे गाड़ी चलाना, क्योंकि 14-घंटे का विंडो ही वास्तव में यह तय करता है कि आप कितनी देर स्टीयरिंग पर रह सकते हैं","11 घंटे गाड़ी चलाना, क्योंकि 10 लगातार घंटे ड्यूटी से बाहर रहने के बाद आप अधिकतम 11 घंटे गाड़ी चला सकते हैं","16 घंटे गाड़ी चलाना, बशर्ते आप 14-घंटे के ड्यूटी विंडो के भीतर रहें"],"explanation":"लगातार 10 घंटे ड्यूटी से बाहर रहने के बाद आप अधिकतम 11 घंटे गाड़ी चला सकते हैं, जो 14 घंटे की ड्यूटी अवधि की सीमा से अलग है।"},"332":{"q":"आपने सुबह 6:00 बजे ड्यूटी शुरू की। लदान और प्रतीक्षा के बाद, आपने आखिरकार सुबह 9:00 बजे गाड़ी चलाना शुरू किया। आपने कुल मिलाकर केवल लगभग 5 घंटे गाड़ी चलाई है और 30 मिनट का विश्राम लिया है, इसलिए आपको लगता है कि आज आपके पास अभी भी काफी कानूनी ड्राइविंग समय बचा है। जब घड़ी रात 8:00 बजे के करीब पहुँचती है, तो कौन सा कथन सही ढंग से बताता है कि इस कार्य-पाली में आपको गाड़ी चलाना कब बंद करना होगा?","options":["आप तब तक गाड़ी चला सकते हैं जब तक स्टीयरिंग के पीछे आपके 6 वास्तविक घंटे पूरे न हो जाएँ, क्योंकि असल में यही ड्राइविंग समय इस सीमा को नियंत्रित करता है।","आप तब तक गाड़ी चला सकते हैं जब तक आप 10 घंटे की ड्यूटी-समय सीमा पार न कर लें, क्योंकि आपको रोकने वाली असल चीज़ ड्यूटी-समय की घड़ी है।","आप रात 8:00 बजे के बाद भी गाड़ी चला सकते हैं क्योंकि आपके 30 मिनट के विश्राम ने घड़ी रोक दी और आपकी अंतिम समय-सीमा को शाम में और बाद तक खिसका दिया।","आप रात 8:00 बजे के बाद बिल्कुल भी गाड़ी नहीं चला सकते, क्योंकि यह ड्यूटी शुरू करने के बाद का 14वाँ घंटा है, चाहे आपने वास्तव में कितनी ही कम गाड़ी क्यों न चलाई हो।"],"explanation":"ड्यूटी पर आने के समय से 14वें घंटे के बाद आप गाड़ी नहीं चला सकते, चाहे आपने वास्तव में कितनी भी कम गाड़ी चलाई हो।"},"333":{"q":"आप 300 मील की यात्रा के लिए एक फ्लैटबेड लोड कर रहे हैं। आपने वजन को धुरियों (एक्सल) पर संतुलित कर लिया है, माल को सूखा रखने के लिए तिरपाल से ढक दिया है, और आपके टाई-डाउन कार्यशील भार सीमा (वर्किंग लोड लिमिट) को पूरा करते हैं। अंतिम बार वाहन का चक्कर लगाते समय, आप स्वयं को वह सबसे महत्वपूर्ण कारण याद दिलाते हैं कि हाईवे पर निकलने से पहले माल को ठीक से सुरक्षित क्यों किया जाना चाहिए। कौन-सा कथन उस कारण को सबसे अच्छी तरह बताता है?","options":["सुरक्षित किया गया माल खिसकने, गिरने, या आपके सड़क के दृश्य को अवरुद्ध करने से रोका जाना चाहिए","सुरक्षित किया गया माल पूरी तरह तिरपाल के नीचे छिपा रखा जाना चाहिए ताकि वह वाहन के बाहर से दिखाई न दे","सुरक्षित किया गया माल इस तरह व्यवस्थित होना चाहिए कि अगले निरीक्षण केंद्र पर उसे जल्दी तौला जा सके","सुरक्षित किया गया माल इस तरह लादा जाना चाहिए कि टाई-डाउन यात्री की ओर से अधिकारियों को दिखाई दें"],"explanation":"माल को इस तरह सुरक्षित करना चाहिए कि वह खिसक न सके, गिर न सके या सड़क का आपका दृश्य न रोके।"},"334":{"q":"आप अंतिम समय में एक माल उठाते हैं और शिपर उसे आपके मैनिफेस्ट में दिखाए गए वजन से अधिक भारी पैक कर देता है, जिससे आप अपने GVWR (सकल वाहन भार रेटिंग) से थोड़ा ऊपर चले जाते हैं। डिस्पैचर कहता है कि यह \"बस थोड़ा सा ज़्यादा\" है और आपको इसे ले जाने को कहता है। जब आप राजमार्ग पर चढ़ते हैं, तो सुरक्षा की दृष्टि से इस ओवरलोड का कौन सा प्रभाव आपको सबसे अधिक चिंतित करना चाहिए?","options":["अतिरिक्त वजन टायरों को सड़क पर और ज़ोर से दबाएगा, जिससे आपको अधिक पकड़ और कम रुकने की दूरी मिलेगी","वाहन को चलाना (स्टीयरिंग) कठिन हो जाएगा और उसे रुकने में अधिक समय लगेगा क्योंकि बढ़ा हुआ वजन आपके स्टीयरिंग और ब्रेक के विरुद्ध काम करता है","बढ़ा हुआ वजन गुरुत्वाकर्षण के केंद्र को नीचे कर देता है, इसलिए ट्रक अधिक स्थिर हो जाता है और पलटने की संभावना बहुत कम हो जाती है","ईंधन की बचत बेहतर हो जाती है क्योंकि ट्रक के पूरी तरह भरे होने पर इंजन अधिक स्थिर भार पर चलता है"],"explanation":"बहुत अधिक वजन वाहन को चलाना कठिन बनाता है और रुकने की दूरी बढ़ाता है, क्योंकि अतिरिक्त भार स्टीयरिंग और ब्रेक के विरुद्ध काम करता है।"},"335":{"q":"टेक्सास के एक लोडिंग डॉक पर अपनी यात्रा-पूर्व जांच के दौरान, आप पाते हैं कि स्टील पाइप के दो टुकड़े आपके फ्लैटबेड ट्रेलर के पिछले हिस्से से लगभग चार फुट बाहर निकले हुए हैं। लोड टाई-डाउन से ठीक से बंधा है, आपके कागजात सही हैं, और आप दिन की यात्रा पर निकलने वाले हैं। लोड का जो हिस्सा पीछे की ओर बाहर निकला है, उसके बारे में संघीय और टेक्सास नियम आपसे गाड़ी चलाने से पहले क्या करवाना अनिवार्य करते हैं?","options":["कुछ अतिरिक्त करने की जरूरत नहीं है, क्योंकि बाहर निकला हिस्सा पांच फुट से कम है और लोड पहले से ही सही संख्या में टाई-डाउन से बंधा है","बाहर निकले हिस्से पर एक अतिरिक्त टाई-डाउन लगाएं और बाहर निकले सिरों को गहरे रंग से रंगें ताकि वे यातायात का ध्यान कम भटकाएं","बाहर निकले लोड को दृश्यमान बनाने के लिए चिह्नित करें -- पीछे की ओर निकले हिस्से पर झंडे (और दृश्यता खराब होने पर या रात में रोशनी) लगाएं","पहले 50 मील के भीतर बंधन की दोबारा जांच करें, लेकिन बाहर निकले हिस्से को चिह्नित करने की जरूरत नहीं है क्योंकि लोड पूरी तरह बंधा है"],"explanation":"पीछे से बाहर निकले माल को दिखाई देने के लिए चिह्नित करना चाहिए — दिन में झंडों से और कम दृश्यता या रात में लाइटों से।"},"336":{"q":"एक शिपिंग डॉक पर, गोदाम का दल आपके लिए फ्लैटबेड पर स्टील पाइप लादकर जंजीरों से बाँधता है, डॉक पर्यवेक्षक बिल ऑफ लेडिंग पर हस्ताक्षर करता है, और पास ही संयोग से एक DOT अधिकारी खड़ा है। आपको लगता है कि कुछ टाई-डाउन ढीले दिख रहे हैं। संघीय और टेक्सास नियमों के अनुसार, रवाना होने से पहले यह सुनिश्चित करने के लिए कि यह भार ठीक से सुरक्षित है और कानूनी वजन सीमा के भीतर है, अंततः कौन जिम्मेदार है?","options":["शिपर और गोदाम का दल, क्योंकि उन्होंने भौतिक रूप से माल लादा और जंजीरों से बाँधा","डॉक पर्यवेक्षक, क्योंकि बिल ऑफ लेडिंग पर उसके हस्ताक्षर भार को प्रमाणित करते हैं","पास खड़ा DOT अधिकारी, क्योंकि सुरक्षण को लागू करना उसका काम है","आप, चालक, क्योंकि माल किसी ने भी लादा हो, सुरक्षित और कानूनी भार के लिए आप जिम्मेदार हैं"],"explanation":"माल को किसने लादा, इससे बेपरवाह, सुरक्षित और कानूनी भार के लिए चालक ही जिम्मेदार होता है।"},"337":{"q":"आपने यार्ड में स्टील के कॉइल लोड किए और अभी-अभी इंटरस्टेट हाईवे पर आए हैं। जब आपने सुरक्षित किया तो लोड मजबूत लग रहा था, लेकिन आप जानते हैं कि जब ट्रक चलने लगता है और जंजीरें कस कर बैठ जाती हैं, तो टाई-डाउन और माल खिसक सकते हैं। कानूनी और सुरक्षित बने रहने के लिए, माल की सुरक्षा को फिर से जांचने के लिए आपको अपना पहला रुकाव कितनी जल्दी करना चाहिए?","options":["यात्रा शुरू करने के बाद पहले 50 मील के भीतर","यात्रा शुरू करने के बाद पहले 150 मील के भीतर","दूरी की परवाह किए बिना, गाड़ी चलाने के पहले 3 घंटों के भीतर","केवल अपने पहले आराम विश्राम या ईंधन रुकाव के बाद"],"explanation":"यात्रा शुरू करने के बाद पहले 50 मील के भीतर आपको माल और उसकी सुरक्षा की जांच करनी चाहिए।"},"339":{"q":"यह एक चंद्रमाहीन रात है और आप बिना स्ट्रीटलाइट वाले ग्रामीण दो-लेन राजमार्ग पर एक खाली फ्लैटबेड चला रहे हैं। आपकी लो बीम लगभग 250 फीट आगे की सड़क को रोशन करती हैं, लेकिन सामने से लगातार वाहन आते रहने के कारण आप कानूनी रूप से हाई बीम का उपयोग नहीं कर सकते। सड़क से उतरने या किसी अनदेखे खतरे से टकराने से बचने के लिए, आपकी गति किस एकमात्र नियम से नियंत्रित होनी चाहिए?","options":["जब तक आपकी हेडलाइट और ब्रेक लाइट सही ढंग से काम कर रही हैं, आप निर्धारित गति सीमा बनाए रख सकते हैं","आपकी गति इतनी धीमी होनी चाहिए कि आप उस दूरी के भीतर रुक सकें जितनी दूरी आपकी हेडलाइट आगे रोशन करती हैं","आपको गति इतनी धीमी रखनी चाहिए कि आप हर सड़क संकेत को गुजरने से पहले पढ़ सकें","आप तेज चला सकते हैं क्योंकि एक खाली ट्रेलर लदे हुए की तुलना में कम रुकने की दूरी देता है"],"explanation":"अपनी हेडलाइट्स से आगे कभी न चलें — आपकी गति ऐसी हो कि लाइटें जितनी दूरी तक दिखाती हैं उसी के भीतर आप रुक सकें।"},"340":{"q":"आधी रात के ठीक बाद आप एक अंधेरे दो-लेन राजमार्ग पर लदा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं। सामने से आ रही एक कार अपनी हाई बीम जलाए रखती है और उसे मंद करने से इनकार करती है, और चकाचौंध आपकी दृष्टि को धुंधला कर रही है। आप पहले ही चालक को याद दिलाने के लिए अपनी लाइट जला चुके हैं, पर कोई असर नहीं हुआ। जब तक वह कार न गुज़र जाए, अपनी लेन पर नियंत्रण बनाए रखने के लिए अपनी आँखों के साथ करने के लिए सबसे अच्छी बात क्या है?","options":["सामने से आ रही हेडलाइट्स को सीधे घूरें ताकि आप ठीक-ठीक अंदाज़ा लगा सकें कि कार कब आपको पार करेगी","हेडलाइट्स के ऊपर आसमान की ओर नज़र उठाएँ ताकि तेज़ रोशनी आपकी सीधी दृष्टि-रेखा से हट जाए","अपनी नज़र नीचे और अपनी ही लेन के दाएँ किनारे की ओर ले जाएँ और कार के गुज़र जाने तक उसी किनारे के सहारे वाहन चलाएँ","अपनी आँखें डैशबोर्ड पर नीचे कर लें और हेडलाइट्स के सामने से हटने तक उपकरणों पर ध्यान दें"],"explanation":"सामने से आती हाई बीम से आंखें चौंधियाने पर, अपनी लेन के दाहिने किनारे की ओर देखें और वाहन के गुजरने तक उससे स्टीयर करें।"},"341":{"q":"आपने अभी-अभी अपना पूरा माल एक गोदाम में उतार दिया है और अब खाली ट्रक (बिना ट्रेलर, बॉबटेल) को यार्ड वापस ले जा रहे हैं। लाल बत्ती के पास पहुंचते समय आप उसी तरह ब्रेक लगाते हैं जैसे पूरी तरह भरे होने पर लगाते थे, और अचानक पहिए जाम (लॉक) होकर फिसलने लगते हैं। यह खाली ट्रक भरे हुए ट्रक की तुलना में ब्रेकिंग में अधिक खराब (WORSE) क्यों है?","options":["वाहन जितना भारी होगा, उसे रुकने में उतना ही अधिक समय लगेगा, इसलिए खाली ट्रक को भरे ट्रक की तुलना में अधिक आसानी से रुकना चाहिए","खाली ट्रकों में छोटे, कमजोर ब्रेक लगे होते हैं जो वाहन को धीमा करने के लिए पर्याप्त बल पैदा नहीं कर सकते","माल न होने पर, ऊंचा गुरुत्वाकर्षण केंद्र ट्रक को आगे की ओर झुका देता है और अगले ब्रेकों पर अधिक भार डाल देता है","बहुत कम वजन टायरों को सड़क पर दबाता है, इसलिए टायरों की पकड़ (ट्रैक्शन) कम हो जाती है और उनके जाम होकर फिसलने की संभावना अधिक होती है"],"explanation":"खाली ट्रक में टायरों को सड़क पर दबाने वाला वजन कम होता है, इसलिए उनकी पकड़ कम होती है और वे आसानी से लॉक होकर फिसलते हैं।"},"342":{"q":"लगातार बारिश हो रही है और सड़क की सतह साफ़ तौर पर गीली है, लेकिन अभी उस पर जमा हुआ पानी या बर्फ़ीला कीचड़ नहीं है। आपके आसपास का यातायात अब भी निर्धारित 60 मील प्रति घंटा की सीमा के करीब चल रहा है। इस गीली सतह पर नियंत्रण का सुरक्षित मार्जिन बनाए रखने के लिए, उसी सड़क पर सूखी हालत में जिस गति से आप सुरक्षित रूप से चलते, उसकी तुलना में आपको अपनी गति लगभग कितनी घटानी चाहिए?","options":["सूखी सड़क की आपकी सुरक्षित गति से लगभग एक-तिहाई धीमी","सूखी सड़क की आपकी सुरक्षित गति से लगभग आधी धीमी","सूखी सड़क की आपकी सुरक्षित गति से लगभग तीन-चौथाई धीमी","जब तक जमा पानी और बर्फ़ीला कीचड़ न बने, गति घटाने की कोई ज़रूरत नहीं"],"explanation":"गीली सड़क पर पर्याप्त पकड़ बनाए रखने के लिए अपनी सुरक्षित सूखी-सड़क गति से लगभग एक तिहाई गति कम करें।"},"343":{"q":"आप एक ग्रामीण दो-लेन राजमार्ग पर लदा हुआ रेफ्रिजरेटेड ट्रक चला रहे हैं, तभी तापमान गिरता है और लगातार बर्फबारी सड़क पर चिपकने लगती है, जिससे सड़क पर एक सख्त, दबी हुई सफेद परत बन जाती है। यातायात ठीक से चल रहा है, सड़क पर बर्फ की परत नहीं है, और आपको अब भी साफ दिखाई दे रहा है। इस दबी हुई बर्फ वाली सतह पर सुरक्षित अंतर बनाए रखने के लिए, आपको अपनी सामान्य सूखी-सड़क गति लगभग कितनी कम करनी चाहिए?","options":["अपनी गति लगभग एक-चौथाई कम करें","अपनी गति लगभग आधी कम करें","अपनी गति लगभग एक-दसवां हिस्सा कम करें","सामान्य गति बनाए रखें क्योंकि सड़क पर बर्फ की परत नहीं है और दृश्यता अच्छी है"],"explanation":"दबी हुई बर्फ पर अपनी गति लगभग आधी कर दें क्योंकि पकड़ बहुत घट जाती है और रुकने की दूरी बढ़ जाती है।"},"344":{"q":"भोर के समय तापमान हिमांक से थोड़ा नीचे है और आप एक भरे हुए संयोजन वाहन को एक पुल पर चला रहे हैं। आगे की सड़क गहरे रंग की, चिकनी और गीली दिखती है, लेकिन आप देखते हैं कि आपके आगे वाली कार के टायरों से पानी की कोई फुहार नहीं उड़ रही है। इस तरह की सतह को सर्दियों के सबसे खतरनाक खतरों में से एक क्यों माना जाता है?","options":["यह चमकीली और स्पष्ट होती है, इसलिए चालक बहुत ज़ोर से ब्रेक लगाते हैं और स्पष्ट रूप से बर्फीली सड़क पर पकड़ खो देते हैं","यह केवल गर्मियों की दोपहर के सबसे गर्म समय में बनती है, जब डामर के नीचे से तारकोल ऊपर रिसता है","यह एक हानिरहित गीली सड़क जैसी दिखती है, पर असल में यह बर्फ की एक पतली, पारदर्शी परत होती है जो लगभग कोई चेतावनी नहीं देती","यह अपने नीचे की सड़क के तारकोल को पिघला देती है, जिससे एक फिसलनदार तैलीय परत बनती है जिसे देखना और बचाकर निकलना आसान है"],"explanation":"ब्लैक आइस बर्फ की एक पतली, पारदर्शी परत होती है जो सड़क को केवल गीला दिखाती है और लगभग कोई चेतावनी नहीं देती।"},"345":{"q":"आप एक ग्रामीण दो-लेन राजमार्ग पर एक भरा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं, तभी एक अचानक तेज़ बगल की हवा का झोंका ट्रेलर के किनारे से टकराता है और स्टीयरिंग व्हील आपकी पकड़ में झटका खाता है। सबसे अच्छा नियंत्रण बनाए रखने और यदि हवा आपको किनारे की ओर धकेले तो विपरीत दिशा में स्टीयर करने के लिए तैयार रहने हेतु, आपके हाथ स्टीयरिंग व्हील पर कैसे होने चाहिए?","options":["सबसे अधिक लीवरेज के लिए एक हाथ व्हील के ऊपरी भाग पर रखें और दूसरा हाथ अपनी गोद में रखें","दोनों हाथ व्हील के ऊपरी भाग के पास एक-दूसरे के नज़दीक रखें ताकि आप किसी भी दिशा में तेज़ी से प्रतिक्रिया कर सकें","एक हाथ व्हील के निचले भाग के पास रखें और दूसरे का उपयोग केवल दरवाज़े के सहारे टिकाने के लिए करें","दोनों हाथ व्हील पर मज़बूती से, एक-दूसरे के विपरीत दिशाओं में रखें"],"explanation":"स्टीयरिंग को दोनों हाथों से विपरीत किनारों पर मजबूती से पकड़ें ताकि आप नियंत्रण बनाए रखें और अचानक खतरों में दिशा सुधार सकें।"},"346":{"q":"आप एक भीड़भाड़ वाले ट्रक स्टॉप में घुसते हैं और आपको अपने ट्रैक्टर-ट्रेलर को एक तंग पार्किंग जगह में पीछे करके लगाना है। कोई सहायक (स्पॉटर) उपलब्ध नहीं है और दूसरे ट्रक दोनों तरफ बहुत पास खड़े हैं। पैंतरेबाज़ी को यथासंभव सुरक्षित रखने के लिए, आपको किस तरफ की ओर पीछे करना चाहिए?","options":["चालक की ओर, ताकि आप ट्रेलर के साथ-साथ पीछे देख सकें और चालक की खिड़की से अपने रास्ते पर नज़र रख सकें","यात्री की ओर, क्योंकि उस तरफ ट्रेलर अधिक चौड़ा घूमता है और आपको ज़्यादा जगह देता है","जो भी तरफ आपको पार्किंग की ढलान पर सीधी रेखा में पीछे करने दे, उस ओर","अपने अंधे (ब्लाइंड) पक्ष की ओर, और फिर जो आप नहीं देख सकते उसे ढकने के लिए शीशों और एक तेज़ चक्कर लगाकर देखने पर भरोसा करें"],"explanation":"चालक की ओर पीछे जाएँ ताकि आप ट्रेलर के साथ सीधे पीछे देख सकें और साइड खिड़की से अपना रास्ता देख सकें।"},"348":{"q":"आपको अपने 53-फुट के ट्रेलर को अंधे (दाएं) तरफ से एक तंग लोडिंग डॉक में पीछे करना है, और पास में खड़ा एक सहकर्मी मदद की पेशकश कर रहा है। सुरक्षित बैकिंग प्रक्रियाओं के अनुसार, इस व्यक्ति को सहायक के रूप में उपयोग करने का एकमात्र सबसे महत्वपूर्ण कारण क्या है?","options":["वे आपको हाथ के संकेत दे सकते हैं ताकि आपको अपने शीशों का बिल्कुल भी उपयोग न करना पड़े","वे आपके ट्रेलर के पीछे और बगल के उन क्षेत्रों को देख सकते हैं जिन्हें आप केबिन से नहीं देख सकते","वे सड़क पर आ रहे ट्रैफिक को रोक सकते हैं ताकि आप बिना रुके पीछे कर सकें","यदि कोण बहुत कठिन हो जाए तो वे नियंत्रण ले सकते हैं और आपके लिए ट्रेलर को पीछे कर सकते हैं"],"explanation":"एक सहायक ट्रेलर के पीछे और बगल के उन ब्लाइंड-स्पॉट क्षेत्रों को देख सकता है जिन्हें आप केबिन से नहीं देख पाते।"},"349":{"q":"आप 53 फुट लंबा ट्रैक्टर-ट्रेलर चला रहे हैं और एक संकरी शहरी सड़क पर तीखे दाएं मोड़ के पास पहुंच रहे हैं। आप जानते हैं कि बहुत तीखा मुड़ने पर ट्रेलर भीतरी रास्ते से जाएगा और कर्ब पर चढ़ सकता है। अभी-अभी एक कार आपके दाईं ओर ठीक पीछे आकर सट गई है। इस मोड़ को सुरक्षित और नियमानुसार पूरा करने के लिए आपको क्या करना चाहिए?","options":["मुड़ना शुरू करने से पहले पहले बाईं ओर चौड़ा हटें ताकि ट्रेलर को कर्ब से बचने की जगह मिले","मोड़ के दौरान थोड़ा तेज चलें ताकि ट्रेलर ट्रैक्टर के और करीब चले","जितना सुरक्षित हो उतना दाईं ओर से मुड़ें, अपने वाहन के पिछले हिस्से को कर्ब के पास रखें ताकि कोई आपकी दाईं ओर से न निकल सके","पहले सबसे बाईं लेन में जाएं, फिर वहां से दायां मोड़ लें ताकि ट्रेलर को अधिकतम जगह मिले"],"explanation":"जितना सुरक्षित हो उतना दाईं ओर से मुड़ें और वाहन का पिछला हिस्सा कर्ब के पास रखें ताकि कोई आपके दाईं ओर से न निकल सके।"},"350":{"q":"आप 53 फुट का ट्रैक्टर-ट्रेलर चला रहे हैं और एक व्यस्त चार-तरफा चौराहे पर बाएं मुड़ना है। बत्ती हरी हो जाती है और सामने से आ रहा यातायात निकल चुका है। इस बाएं मोड़ को सुरक्षित रूप से पूरा करने और ट्रेलर के पिछले पहियों को उस लेन में कटने से रोकने के लिए जिससे आप मुड़ रहे हैं, सही तकनीक क्या है?","options":["चौराहे में घुसते ही ट्रैक्टर के अगले हिस्से को तुरंत बाईं ओर घुमाना शुरू करें ताकि ट्रेलर एक संकरे रास्ते पर चले","पूरे मोड़ के दौरान सबसे दाईं लेन में रहें ताकि ट्रेलर के पिछले पहिये चौड़ा घूमें और किनारे से दूर रहें","ट्रेलर को तय करनी पड़ने वाली दूरी को कम करने के लिए चौराहे के कोने को तिरछा काटें","स्टीयरिंग को बाईं ओर घुमाना शुरू करने से पहले अपने ट्रैक्टर को आगे बढ़ाएं और चौराहे के केंद्र तक पहुंचें"],"explanation":"पहिया बाईं ओर मोड़ने से पहले चौराहे के केंद्र तक आगे बढ़ें ताकि ट्रेलर के पिछले पहिये कोना न काटें।"},"351":{"q":"सुबह जल्दी का समय है और आप एक लंबी यात्रा शुरू करने के लिए अभी-अभी केबिन में चढ़े हैं। बैठते समय आपको पता चलता है कि दायाँ शीशा बहुत ऊपर की ओर झुका है और ट्रेलर का किनारा नहीं दिखा रहा, और आप इसे ठीक करना चाहते हैं। यह समायोजन करने का सही समय कब है?","options":["अभी, यात्रा शुरू करने से पहले, जब वाहन सुरक्षित रूप से खड़ा हो","हाईवे की गति पर पहुँचने के बाद, ताकि शीशा इस हिसाब से सेट हो कि ट्रेलर लोड के नीचे कैसे चलता है","अपनी पहली अनिवार्य कार्गो जाँच पर, यात्रा के पहले 50 मील के भीतर","केवल ड्राइविंग समाप्त करने और गंतव्य यार्ड में पहुँचने के बाद"],"explanation":"दर्पण यात्रा से पहले तब समायोजित करें जब वाहन सुरक्षित रूप से खड़ा हो, क्योंकि चलते समय ऐसा सुरक्षित रूप से नहीं किया जा सकता।"},"353":{"q":"आपने अभी-अभी कई लेन वाले राजमार्ग पर एक धीमे वाहन को ओवरटेक करने के लिए बायीं लेन में लेन बदली है। ओवरटेक पूरा हो गया है और अब आप नयी लेन में स्थिर रूप से चल रहे हैं। डैशबोर्ड पर नज़र डालने पर आप देखते हैं कि आपका बायाँ टर्न सिग्नल अब भी ब्लिंक कर रहा है, क्योंकि कार के विपरीत आपके ट्रक का सिग्नल अपने-आप बंद नहीं हुआ। आपको सबसे पहले क्या करना चाहिए?","options":["जिस वाहन को आपने अभी ओवरटेक किया है उससे और दूरी बनाने के लिए दृढ़ता से गति बढ़ाएँ, और सिग्नल बाद में देख लें","टर्न सिग्नल को हाथ से बंद कर दें ताकि आसपास के चालक आपके इरादों के बारे में गुमराह न हों","यह तय करने से पहले कि सिग्नल बंद करना है या नहीं, दर्पणों को दोबारा देखने के लिए ब्रेक लगाएँ","सिग्नल को अगली लेन बदलने तक चालू रहने दें, क्योंकि यह दिखाता है कि आप अब भी मैन्युवर कर रहे हैं"],"explanation":"अधिकांश बड़े ट्रकों में टर्न सिग्नल स्वतः बंद नहीं होते, इसलिए अन्य चालकों को भ्रमित होने से बचाने के लिए पैंतरे के बाद सिग्नल बंद कर दें।"},"355":{"q":"आप रात में एक अंधेरे दो-लेन वाले हाईवे पर अपनी हाई बीम चालू करके अपना ट्रैक्टर-ट्रेलर चला रहे हैं। आप विपरीत लेन में अपनी ओर आते हुए एक वाहन की हेडलाइट देखते हैं, जो अभी कुछ दूरी आगे है। सामने से आने वाले चालक को चौंधिया न देने के लिए आपको किस बिंदु पर अपनी हाई बीम को लो बीम में करना आवश्यक है?","options":["सामने से आते वाहन से 250 फीट के भीतर, क्योंकि इतनी दूरी तक आपकी लो बीम सड़क को रोशन करती है","सामने से आते वाहन से 200 फीट के भीतर, वही दूरी जहाँ आप अपना सबसे दूर वाला चेतावनी त्रिकोण रखते हैं","सामने से आते वाहन से 500 फीट के भीतर (और साथ ही जब आप किसी अन्य वाहन के पीछे 500 फीट के भीतर चल रहे हों)","केवल तभी जब सामने से आने वाला वाहन अपनी लाइटें चमकाकर संकेत दे कि आपकी बीम बहुत तेज है"],"explanation":"सामने से आ रहे वाहन से 500 फीट के भीतर और किसी अन्य वाहन के पीछे 500 फीट के भीतर चलते समय चकाचौंध से बचाने के लिए अपनी हाई बीम लाइट को कम कर दें।"},"356":{"q":"आप एक ग्रामीण दो-लेन राजमार्ग पर लदा हुआ ट्रेलर ले जा रहे हैं, तभी कूलेंट कम होने की चेतावनी आपको इंजन बंद करने पर मजबूर कर देती है। कई मील तक कोई निकास नहीं है, लेकिन आगे आपको एक चौड़ा बजरी वाला किनारा दिखता है। अपने चेतावनी त्रिकोण उठाने से पहले ही, रुकाव को यथासंभव सुरक्षित बनाने के लिए आपको सबसे पहले क्या करना चाहिए?","options":["अपनी ही लेन में रुक जाएं और तुरंत तीनों त्रिकोण 10, 100 और 200 फीट पर लगा दें ताकि सबसे पहले यातायात को चेतावनी मिल जाए","अगले मोड़ पर लुढ़कते हुए रुक जाएं ताकि आपका वाहन दोनों दिशाओं से दिखाई दे, और हेडलाइट चालू कर दें","गति धीमी करके लेन की रेखा पर खड़े हो जाएं ताकि ट्रक का कुछ हिस्सा पक्की सड़क पर रहे और किनारा आपातकालीन वाहनों के लिए खाली रहे","पूरी तरह पक्की सड़क से हटकर बजरी वाले किनारे पर उतर जाएं और अपनी चारों आपातकालीन फ्लैशर लाइट चालू कर दें"],"explanation":"वाहन को सड़क से पूरी तरह हटाकर किनारे पर ले जाएं और आने वाले यातायात को सचेत करने के लिए तुरंत अपनी चार-तरफा खतरे की चेतावनी लाइटें चालू करें।"},"357":{"q":"आप अपने माल की बंधाई जाँचने और एक त्वरित निरीक्षण के लिए हल्की ढलान वाली जगह पर एक विश्राम स्थल में गाड़ी रोकते हैं। इंजन अभी भी चालू है और आप केवल एक-दो मिनट के लिए ही केबिन से बाहर रहने की योजना बना रहे हैं। नीचे उतरकर बाहर जाने से पहले, वाहन को लुढ़कने से रोकने के लिए सबसे महत्वपूर्ण एकमात्र कार्य कौन-सा है?","options":["पार्किंग ब्रेक लगाना।","ट्रांसमिशन को सबसे निचले आगे वाले गियर में डालकर वैसे ही छोड़ देना।","आगे के पहियों को तेज़ी से किनारे (कर्ब) की ओर मोड़ना और चारों दिशा वाली खतरे की चेतावनी लाइटें चालू करना।","जब तक आप लौटने के लिए तैयार न हों, तब तक सर्विस (पैर वाले) ब्रेक को मज़बूती से दबाकर रखना।"],"explanation":"केबिन छोड़ने से पहले हमेशा पार्किंग ब्रेक लगाएं, क्योंकि यही एकमात्र उपकरण है जो चालक की अनुपस्थिति में खड़े वाहन को यांत्रिक रूप से रोकने के लिए बनाया गया है।"},"358":{"q":"आप एक लदे हुए ट्रैक्टर-ट्रेलर को ग्रामीण राजमार्ग पर 55 मील प्रति घंटे की रफ्तार से चला रहे हैं। यातायात कम है और सड़क सीधी है, इसलिए आप जानबूझकर अपनी नजर इतनी दूर के एक बिंदु पर टिकाने का फैसला करते हैं कि आप रुके हुए वाहनों, मलबे या मिलने वाले यातायात को समय रहते देख सकें और तेज ब्रेक लगाने के बजाय सहजता से प्रतिक्रिया दे सकें। इस गति पर समय के हिसाब से आपको कितना आगे देखना चाहिए?","options":["5 से 8 सेकंड आगे, जो वही अंतराल है जो आपको अपने शीशे (मिरर) जांचने के लिए इस्तेमाल करना चाहिए","12 से 15 सेकंड आगे, जो राजमार्ग की गति पर लगभग एक चौथाई मील के बराबर है","लगभग 6 सेकंड आगे, जो 55 मील प्रति घंटे पर आपकी कुल रुकने की दूरी है","केवल फुट में मापी गई पूरी एक चौथाई मील, गति के सेकंड में नहीं"],"explanation":"खतरों को जल्दी भांपने और घबराहट के बजाय आराम से प्रतिक्रिया देने के लिए 12 से 15 सेकंड आगे देखें, जो हाईवे की गति पर लगभग एक चौथाई मील है।"},"359":{"q":"आप एक व्यस्त इंटरस्टेट हाईवे पर फ्लैटबेड ट्रेलर में स्टील के कॉइल का भार लेकर हाईवे की गति से चल रहे हैं। यातायात घना है और वाहन लगातार आपके आसपास की लेनों में आते-जाते रहते हैं। आप अपने रिग के हर तरफ की स्थिति से अवगत रहना चाहते हैं ताकि आपके सामने कटकर आने वाली कार या अपने ट्रेलर के टायर की समस्या पर समय रहते प्रतिक्रिया दे सकें। दर्पणों के उपयोग का कौन-सा तरीका सुरक्षित वाणिज्यिक ड्राइविंग प्रथा के लिए सबसे उपयुक्त है?","options":["हर बार विलय या लेन बदलने के बाद अपने दर्पणों में एक बार देखें, क्योंकि तभी दूसरे वाहनों के आपके बगल में होने की सबसे अधिक संभावना होती है","ट्रेलर के खिंचाव को महसूस करने या कोई असामान्य आवाज़ सुनने तक प्रतीक्षा करें और तभी जाँचें, ताकि बाकी समय आप केवल आगे की सड़क पर नज़र रखें","अपने दर्पणों को नियमित रूप से, लगभग हर 5 से 8 सेकंड में स्कैन करें, ताकि आप अपने वाहन के हर तरफ के यातायात और स्थिति पर लगातार नज़र रख सकें","अपने दर्पणों को केवल यात्रा की शुरुआत और अंत में जाँचें, और बाकी समय पूरी तरह से 12 से 15 सेकंड आगे के रास्ते पर ध्यान केंद्रित करें"],"explanation":"यातायात, अंधे स्थानों और अपने वाहन व माल की स्थिति से अवगत रहने के लिए नियमित रूप से, लगभग हर 5 से 8 सेकंड में, अपने दर्पणों की जांच करें।"},"360":{"q":"आप एक विभाजित राजमार्ग की दाहिनी लेन में 55 मील प्रति घंटे की स्थिर गति से एक लदे हुए ट्रैक्टर-ट्रेलर को चला रहे हैं, तभी एक कार आपको आपकी बाईं ओर से ओवरटेक करना शुरू करती है। ओवरटेक के बीच में, कार आपके बाईं ओर के ब्लाइंड स्पॉट में रुकी रहती है और युक्ति पूरी करने में झिझकती हुई लगती है। ओवरटेक करने वाले चालक को सबसे सुरक्षित और सबसे अनुमानित स्थिति देने के लिए, आपको कौन-सी कार्रवाई करनी चाहिए?","options":["एक्सेलरेटर से पैर हटाएँ और हल्के से ब्रेक लगाएँ ताकि कार आपके अगले बंपर को जल्दी पार कर सके","चालक की ओर अधिक जगह खोलने के लिए अपनी लेन के दाहिने किनारे की ओर थोड़ा खिसकें","कार को ओवरटेक जल्दी पूरा करने और अपनी लेन में लौटने में मदद करने के लिए थोड़ी देर तेज़ करें","अपनी लेन के केंद्र में अपनी स्थिति बनाए रखें और स्थिर गति बनाए रखें जब तक कार पूरी तरह आपको पार कर आगे न लौट जाए"],"explanation":"जब कोई अन्य वाहन आपको ओवरटेक कर रहा हो, तो अपनी लेन और स्थिर गति बनाए रखें ताकि ओवरटेक करने वाला चालक अंतर का अनुमान लगाकर सुरक्षित रूप से पास पूरा कर सके।"},"361":{"q":"आप एक अनजान अंडरपास की ओर बढ़ रहे हैं जिस पर ऊँचाई सीमा (क्लीयरेंस) का साइन लगा है, और आपके ट्रेलर पर लकड़ी की पेटियों में पैक मशीनरी का ऊँचा ढेर लदा है। नीचे दिए गए आँकड़ों में से, उस पुल के नीचे से गुज़रने का निर्णय लेने से पहले आपको किसे निश्चित रूप से जानना SABSE अधिक आवश्यक है?","options":["आपके लदे हुए वाहन की कुल ऊँचाई, ज़मीन से उसके सबसे ऊँचे बिंदु तक मापी गई","तौल-काँटे पर लदे हुए संयोजन (कॉम्बिनेशन) का सटीक कुल वज़न","आपकी टंकियों में इस समय मौजूद ईंधन की मात्रा","ड्राइव एक्सल पर लगे टायरों का ब्रांड और मॉडल"],"explanation":"किसी पुल या अंडरपास के नीचे से गुजरने से पहले अपने लदे वाहन की जमीन से सबसे ऊंचे बिंदु तक की कुल ऊंचाई जानें और उसे दर्शाई गई क्लीयरेंस से मिलाएं।"},"362":{"q":"आप एक एक्सकेवेटर से लदे लो-बॉय ट्रेलर को एक पुराने औद्योगिक इलाके से होकर रूट कर रहे हैं। आगे सड़क एक पुराने रेल पुल के नीचे से गुजरती है और कई ढीले लटकते बिजली के तार सड़क के ऊपर से क्रॉस करते हैं। उनके नीचे से गुजरने का फैसला करने से पहले, गंभीर दुर्घटना से बचने के लिए लिखित और ज्ञात सीमाओं के मुकाबले किस माप की पुष्टि करना सबसे अहम है?","options":["आपके स्टीयरिंग-एक्सल (अगले) टायर का दबाव, क्योंकि कम हवा वाला अगला टायर रिग को नीचे झुका कर तारों में फँसा सकता है","आपकी ऊपरी क्लीयरेंस ऊँचाई, यानी लदे हुए रिग की कुल ऊँचाई को लिखी हुई पुल की क्लीयरेंस और ऊपर के तारों की ऊँचाई से मिलाकर देखना","आपकी सकल संयुक्त वजन रेटिंग (GCWR), यह पक्का करने के लिए कि पुल और सड़क लदे रिग का भार सुरक्षित रूप से सह सकें","आगे चल रहे वाहन से आपकी फॉलोइंग दूरी, ताकि आपको संरचना के नीचे जोर से ब्रेक न लगाना पड़े"],"explanation":"यह सुनिश्चित करने के लिए कि वाहन नीचे से सुरक्षित गुजर सके, अपनी कुल लदी हुई क्लीयरेंस ऊंचाई की तुलना दर्शाई गई पुल क्लीयरेंस और ऊपरी तारों की ऊंचाई से करें।"},"363":{"q":"आप अपने भरे हुए संयोजन वाहन में एक चार-तरफा चौराहे के पास पहुँच रहे हैं, तभी आपकी बाईं ओर की एक कार आगे बढ़ती है और आक्रामक रूप से उस रास्ते के अधिकार (राइट ऑफ वे) का दावा करती है जो कानूनी रूप से आपका है। आप पहले ही गति धीमी करने लगे हैं। इस स्थिति में सबसे अच्छा कदम कौन सा है?","options":["अपनी गति बनाए रखें और आगे बढ़ें, क्योंकि रास्ते का अधिकार कानूनी रूप से आपका है और कार को रास्ता देना चाहिए","बार-बार हॉर्न बजाएँ और अपनी स्थिति को मजबूती से बनाए रखते हुए चौराहे में आगे बढ़ते रहें","रास्ता दें और दूसरे चालक को जाने दें, भले ही कानूनी रूप से रास्ते का अधिकार आपका हो, ताकि टक्कर से बचा जा सके","कार के आपके रास्ते में आने से पहले चौराहा पार करने के लिए गति बढ़ाएँ"],"explanation":"एक पेशेवर चालक का पहला कर्तव्य टक्कर से बचना है, इसलिए भले ही कानूनी रूप से आपको रास्ते का अधिकार हो, रास्ता दें और दूसरे चालक को जाने दें।"},"364":{"q":"आप अपने लदे हुए संयोजन वाहन का मार्ग एक डिलीवरी की ओर तय कर रहे हैं और GPS आपको एक काउंटी पुल पर भेज रहा है जिस पर अंकित वज़न सीमा आपके वास्तविक सकल संयोजन वज़न से कम है। एक कानूनी वैकल्पिक मार्ग है जो 12 मील जोड़ता है। आपको क्या करना चाहिए?","options":["पुल पार करें लेकिन गति बढ़ा दें ताकि आपका पूरा वज़न संरचना पर कम से कम समय के लिए रहे","धीरे और स्थिर रेंगते हुए पार करें, क्योंकि पुलों पर अंकित वज़न सीमाएँ केवल सलाह हैं और तभी लागू होती हैं जब ट्रक खाली हो","आगे बढ़ने से पहले अपने एक्सल वज़न की जाँच करने के लिए पुल पर रुकें","पुल पार न करें; कानूनी वैकल्पिक मार्ग लें ताकि आप कभी भी अंकित वज़न सीमा से अधिक न हों"],"explanation":"पुल पर दर्शाई गई वजन सीमा एक सख्त कानूनी अधिकतम है, इसलिए यदि आपका सकल वजन इससे अधिक है, तो कभी पार न करें और इसके बजाय कानूनी वैकल्पिक मार्ग लें।"},"365":{"q":"आप एक लंबी, खड़ी पहाड़ी ढलान पर भारी माल लेकर नीचे उतर रहे हैं। हालाँकि दिन ठंडा है, कई मील के बाद जब आप ब्रेक पेडल दबाते हैं तो आप देखते हैं कि ट्रक मुश्किल से धीमा होता है और ब्रेक कमज़ोर तथा स्पंजी महसूस होते हैं। इस ब्रेकिंग शक्ति के नुकसान का सबसे संभावित कारण क्या है?","options":["उतराई पर बहुत अधिक और बहुत देर तक उपयोग किए जाने से ब्रेक अधिक गर्म हो गए, जिससे ब्रेक फेड (ब्रेक का कमज़ोर पड़ना) हुआ","बाहर की ठंडी हवा ने ब्रेक लाइनों में नमी को जमा दिया और उनकी पकड़ कम कर दी","ब्रेक लाइनिंग बहुत नई हैं और अभी तक ठीक से पकड़ने के लिए घिसी नहीं हैं","आपने बहुत हल्के और सावधानी से ब्रेक लगाए, इसलिए लाइनिंग कभी इतनी गर्म नहीं हुई कि पकड़ सके"],"explanation":"लंबी ढलान पर भारी और लगातार ब्रेकिंग से ब्रेक अधिक गरम हो जाते हैं, जिससे पेडल दबाने पर भी वे घर्षण और रोकने की शक्ति खो देते हैं।"},"367":{"q":"आप एक विभाजित राजमार्ग की दाईं लेन में निर्धारित गति सीमा पर एक लदा हुआ ट्रेलर चला रहे हैं। आपके पीछे का एक चालक कई मील तक बहुत पास से पीछा करता रहा, फिर तेज़ी से आपको ओवरटेक करके अचानक आपके आगे घुस गया, ब्रेक लगाया, और लगातार इशारे करके आपसे तेज़ चलने या हटने को कह रहा है। आगे यातायात मध्यम है। इस आक्रामक चालक से निपटने का सबसे सुरक्षित और सही तरीका कौन सा है?","options":["दूसरे चालक की गति के बराबर पहुँचने के लिए तेज़ चलें ताकि वह पास से पीछा करना बंद करके आपसे दूर हो जाए","एक्सेलरेटर छोड़ दें, अपनी पीछा करने की दूरी बढ़ाएँ, और आक्रामक चालक को काफ़ी आगे निकलकर आपसे दूर जाने दें","अपनी ठीक वही स्थिति बनाए रखें और चालक को पीछे हटने का संकेत देने के लिए हल्के से ब्रेक दबाएँ","बाईं ओर हटकर आक्रामक चालक को तब तक दोबारा ओवरटेक करने से रोकें जब तक वह शांत न हो जाए"],"explanation":"आक्रामक चालक के प्रति सबसे सुरक्षित प्रतिक्रिया है उसके रास्ते से हट जाना—एक्सेलेरेटर छोड़कर और अनुसरण दूरी बढ़ाकर उसे आगे निकलने देना।"},"368":{"q":"आपने अभी एक ट्रक स्टॉप पर 45 मिनट का भोजन अवकाश समाप्त किया है और आपका लदा हुआ ट्रैक्टर-ट्रेलर एक सेवा सड़क के दाहिने किनारे के साथ समानांतर खड़ा है। आपकी बाईं ओर से यातायात गुजर रहा है। आप फिर से यात्रा लेन में प्रवेश करने के लिए तैयार हैं। इस पार्क की गई स्थिति को छोड़ने का सबसे सुरक्षित और सही तरीका कौन सा क्रम है?","options":["यातायात के अंतराल में मिलने के लिए तुरंत सीधे निकल जाएं, और चलना शुरू करने के बाद ही अपना बायां संकेतक चालू करें","पास के चालकों को सचेत करने के लिए हॉर्न बजाएं, ब्रेक छोड़ें, और बिना देरी किए लेन में तेज़ी से बढ़ें","अपना बायां संकेतक चालू करें, यातायात और अंध बिंदुओं के लिए अपने दर्पण और वाहन के चारों ओर के क्षेत्र की जांच करें, और तभी निकलें जब रास्ता साफ हो","केवल चालक की ओर के दर्पण की जांच करें, और यदि साफ दिखे, तो अंतराल पर नज़र रखते हुए धीरे से लेन में निकल जाएं"],"explanation":"पार्क की हुई जगह से निकलने से पहले पहले सिग्नल दें, फिर शीशों और वाहन के चारों ओर के सभी क्षेत्रों में यातायात व ब्लाइंड स्पॉट जाँचें, और रास्ता साफ होने पर ही निकलें।"},"370":{"q":"आप एक लदे हुए ट्रैक्टर-ट्रेलर को हाईवे की गति पर बिना विभाजन वाली दो-लेन सड़क पर चला रहे हैं। सामने से आ रहा एक कार बीच की रेखा पार करके अब आंशिक रूप से आपकी लेन में आ गया है और तेज़ी से नज़दीक आ रहा है। टक्कर से पहले रुकने का समय नहीं है। आपके दाहिनी ओर एक पक्का किनारा (शोल्डर) और एक उथली घासदार खाई है; आपकी बाईं ओर यातायात वाली सामने की लेन है। आमने-सामने की टक्कर से बचने का सबसे अच्छा मौका कौन-सी क्रिया देती है?","options":["बहकी हुई कार के चारों ओर निकलने के लिए बाईं ओर सामने वाली लेन में मुड़ें","अपनी लेन बनाए रखें और जितना ज़ोर से हो सके ब्रेक लगाएं, ज़रूरत पड़े तो पहिए लॉक कर दें","लेन के बीच में रहें, हाई बीम जलाएं-बुझाएं और अपनी गति बनाए रखें","दाहिनी ओर शोल्डर की तरफ मुड़ें, भले ही इसके लिए पक्की सड़क से उतरना पड़े"],"explanation":"जब सामने से आ रहा वाहन आपकी लेन में आ जाए, तो दाईं ओर किनारे की ओर मुड़ें, क्योंकि वह चालक वापस अपनी लेन में आ सकता है और बाएँ मुड़ने पर आमने-सामने टक्कर का जोखिम होता है।"},"371":{"q":"जुलाई की एक गर्म दोपहर में आप भरे हुए ट्रक को हाईवे की गति पर चला रहे हैं, तभी अचानक आपको ट्रैक्टर के अगले हिस्से से एक तेज \"धमाके\" की आवाज सुनाई देती है। इससे पहले आपको सीट में कोई कंपन या थपथपाहट महसूस नहीं हुई थी। स्टीयरिंग को पकड़ते समय, निम्नलिखित में से कौन-सा संकेत सबसे स्पष्ट रूप से बताएगा कि फटने वाला टायर पिछला नहीं बल्कि अगला (फ्रंट) टायर था?","options":["स्टीयरिंग अचानक बहुत भारी हो जाती है और ट्रक जोर से एक तरफ खिंचने लगता है","आपको सीट और केबिन के फर्श से ऊपर की ओर आती हुई तेज कंपन या थपथपाहट महसूस होती है","ट्रेलर का पिछला हिस्सा इधर-उधर लहराने और झूलने लगता है","इंजन का तापमान गेज बढ़ने लगता है और ट्रक शक्ति खोने लगता है"],"explanation":"अगले टायर के फटने पर स्टीयरिंग अचानक बहुत भारी हो जाता है और ट्रक तेज़ी से खराब टायर की ओर खिंचता है।"},"372":{"q":"आप एक समतल, दो-लेन वाले राजमार्ग पर लगभग 50 मील प्रति घंटे की गति से लदे हुए वाहन के साथ चल रहे हैं, तभी अचानक आपको महसूस होता है कि आपके ट्रेलर का पिछला हिस्सा एक ओर से दूसरी ओर झूलने और लहराने लगा है, जबकि आपका स्टीयरिंग व्हील अभी भी सामान्य महसूस होता है और आपने ब्रेक को छुआ तक नहीं है। इन लक्षणों के आधार पर, सबसे संभावित रूप से क्या हुआ है, इसके बारे में कौन-सा निष्कर्ष सबसे सटीक है?","options":["अगला (स्टीयरिंग-एक्सल वाला) टायर हवा खो चुका है, इसीलिए अब पिछला हिस्सा लेन में इधर-उधर भटक रहा है","एक पिछला टायर फेल हो गया है, क्योंकि पिछले टायर के फटने से आमतौर पर वाहन झूलने या फिशटेल (पिछला हिस्सा लहराने) लगता है","आपके ट्रेलर के ब्रेक लॉक हो गए हैं, जो पिछले हिस्से को बगल की ओर घसीट रहे हैं","आपने त्वरण के कारण ड्राइव-व्हील स्किड शुरू कर दी है और आपको तुरंत दूसरी दिशा में जोर से स्टीयरिंग घुमाना चाहिए"],"explanation":"पिछले टायर के खराब होने पर वाहन झूलता या लहराता है जबकि स्टीयरिंग अपेक्षाकृत सामान्य महसूस होता है।"},"373":{"q":"आप एक गीले दो-लेन वाले राजमार्ग पर एक खाली ट्रेलर खींचते हुए जा रहे हैं, तभी आगे एक साइड रोड से अचानक एक कार निकल आती है। आप ब्रेक पेडल को जोर से दबाते हैं और महसूस करते हैं कि ABS (एंटीलॉक ब्रेकिंग सिस्टम) सक्रिय हो रहा है। इस समय आपका एंटीलॉक ब्रेकिंग सिस्टम आपके लिए क्या कर रहा है, इसका सबसे अच्छा वर्णन कौन-सा कथन करता है?","options":["यह आपकी कुल रुकने की दूरी को ABS के बिना होने वाली दूरी की लगभग आधी कर रहा है, ताकि आप कार से काफी पहले रुक सकें।","यह अपने आप गियर कम कर रहा है और इंजन ब्रेकिंग लगाकर रिग को नियंत्रित रूप से रोक रहा है।","यह आपके पहियों को लॉक होने से रोक रहा है ताकि जोर से ब्रेक लगाते समय आप स्टीयरिंग करते रह सकें और नियंत्रण बनाए रख सकें।","यह ब्रेक दबाव को नियंत्रित कर रहा है ताकि खाली ट्रेलर लदे हुए ट्रेलर की तुलना में कम दूरी में रुक जाए।"],"explanation":"ABS तेज़ ब्रेकिंग के दौरान पहियों को लॉक होने से रोकता है ताकि आप स्टीयरिंग जारी रख सकें और खतरे से बचने के लिए नियंत्रण बनाए रख सकें।"},"374":{"q":"आप एंटी-लॉक ब्रेक (ABS) से लैस एक लदे हुए ट्रैक्टर-ट्रेलर चला रहे हैं, तभी एक कार अचानक आपके सामने आ जाती है और एकाएक रुक जाती है। आपको सूखी सड़क पर अपनी लेन में एक सख्त आपातकालीन रोक लगानी है। ABS को किस तरह काम करने के लिए बनाया गया है, यह जानते हुए, कौन सी ब्रेकिंग क्रिया आपको सबसे अच्छा नियंत्रण और सबसे छोटी सुरक्षित रुकावट देती है?","options":["पहियों को लॉक होने से रोकने के लिए ब्रेक पैडल को तेज़ी से पंप करें, जैसा आप ABS के बिना करते","नियंत्रित स्टैब (रुक-रुक कर) ब्रेकिंग लगाएँ, हर बार जब पहिये लॉक होने लगें तो पैडल छोड़ दें","ब्रेक को केवल हल्का दबाएं और कार को मोड़कर बचाएँ, क्योंकि ABS आपकी रुकावट की दूरी को कम कर देता है","ब्रेक पैडल को मज़बूती से दबाएं, स्थिर लगातार दबाव बनाए रखें और ABS के काम करते समय आवश्यकतानुसार स्टियर करें"],"explanation":"ABS के साथ, पेडल को मज़बूती से दबाकर लगातार स्थिर दबाव बनाए रखते हुए ब्रेक लगाएँ और स्टीयर करें, सिस्टम को पहिए लॉक होने से रोकने दें।"},"375":{"q":"आप एक राज्य राजमार्ग पर एक आंशिक रूप से लदे ट्रेलर (बिना ABS के) को चला रहे हैं, तभी एक कार अचानक किसी बगल की सड़क से सीधे आपके सामने आ जाती है। यदि आप समय पर नहीं रुक पाते, तो खतरे के चारों ओर मुड़ने की अपनी क्षमता खोए बिना आपको शारीरिक रूप से जितनी जल्दी संभव हो उतनी जल्दी रुकना चाहिए। आपको कौन सी ब्रेकिंग विधि अपनानी चाहिए?","options":["नियंत्रित या स्टैब ब्रेकिंग लगाएं, पहियों को लॉक होने की कगार पर बनाए रखते हुए","ब्रेक को पूरा नीचे तक दबाएं और पहियों को लॉक करके सबसे छोटी दूरी के लिए मजबूती से पकड़े रखें","लंबी ढलान पर जैसे करते हैं वैसे ही ब्रेक को हल्के और स्थिर रूप से दबाएं","केवल ट्रेलर (हैंड) वाल्व लगाएं ताकि ट्रैक्टर के पहिए मुड़ने के लिए स्वतंत्र रहें"],"explanation":"ABS के बिना, नियंत्रित या स्टैब ब्रेकिंग जो पहियों को लॉक होने से ठीक पहले रखती है, स्टीयरिंग बनाए रखते हुए अधिकतम रोकने की शक्ति देती है।"},"376":{"q":"आप मानक (बिना ABS वाले) ब्रेक वाला एक लदा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं, तभी एक कार अचानक आपके सामने आ जाती है और टक्कर से बचने के लिए आपको ज़ोर से ब्रेक लगाना पड़ता है। आप ब्रेक पूरी तरह दबाते हैं और महसूस करते हैं कि पहिये जाम (लॉक) हो गए हैं। स्टैब ब्रेकिंग का सही उपयोग करने और वाहन पर नियंत्रण बनाए रखने के लिए, जिस पल पहिये लॉक हों उस पल आपको क्या करना चाहिए?","options":["पेडल पर पूरा, स्थिर दबाव बनाए रखें और पूरी तरह रुकने तक पहियों को लॉक रखें","ब्रेक को तब तक छोड़ें जब तक पहिये फिर से घूमने न लगें, फिर ब्रेक को दोबारा पूरी तरह दबाएँ","रुकने तक ब्रेक पेडल को जितनी तेज़ी से हो सके, प्रति सेकंड तीन-चार बार पंप करें","पैर ब्रेक से पूरी तरह हटा लें, इंजन बंद कर दें और रुकने तक वाहन को लुढ़कने दें"],"explanation":"स्टैब ब्रेकिंग में, लॉक हुए पहियों के दोबारा घूमने तक ब्रेक छोड़ें ताकि स्टीयरिंग वापस मिले, फिर पूरी तरह से ब्रेक दोबारा लगाएँ।"},"377":{"q":"आप एक सूखे चार-लेन राजमार्ग पर 55 मील प्रति घंटे की गति से एक लदे हुए कार-कैरियर के पीछे चल रहे हैं और आगे वाले ट्रक तथा अपने बीच कई सेकंड की खुली सड़क बनाए रखते हैं। अचानक एक मर्ज होती पिकअप उस जगह में घुस आती है और कार-कैरियर की ब्रेक लाइटें चमक उठती हैं। इस स्थिति को सुरक्षित रूप से संभालने के लिए वह स्पेस कुशन बनाए रखना आपका सबसे महत्वपूर्ण कदम क्यों था?","options":["इसने आपको एक्सीलरेटर से पैर हटाए बिना 55 मील प्रति घंटा बनाए रखने दिया, जिससे आपके पीछे का ट्रैफ़िक सुचारू रूप से चलता रहा","इसने लगभग 60 फीट में पूरी तरह रुकने की गारंटी दी, जो 55 मील प्रति घंटे पर कुल रुकने की दूरी है","इसने आपको खतरे को भांपने और कड़ी ब्रेक लगाने की नौबत आने से पहले प्रतिक्रिया देने के लिए अतिरिक्त जगह और समय दिया","इसने आपकी फॉलोइंग दूरी को एक सेकंड से कम रखा, जो हैंडबुक राजमार्ग गति के लिए अनुशंसित करती है"],"explanation":"स्पेस कुशन आपको खतरे को भांपने और जोर से ब्रेक लगाने से पहले प्रतिक्रिया देने के लिए अतिरिक्त जगह और समय देता है, क्योंकि तेज गति पर रुकने की दूरी दिखने से कहीं ज्यादा होती है।"},"378":{"q":"आप अच्छी, सूखी परिस्थितियों में 55 मील प्रति घंटे की रफ्तार से पूरी तरह लदा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं, तभी बगल की लेन में एक कार उसी खतरे के लिए जोर से ब्रेक लगाती है जिसे आप दोनों एक ही पल में देखते हैं। यह जानते हुए कि लदा हुआ ट्रक उस कार की तुलना में कैसा व्यवहार करता है, कौन सा कथन आपको यह तय करने में मार्गदर्शन देना चाहिए कि आप अपने लिए कितनी जगह छोड़ें?","options":["लदा हुआ ट्रक और कार लगभग समान दूरी में रुक जाएंगे, क्योंकि दोनों के ब्रेक अच्छे हैं","लदा हुआ ट्रक बहुत कम दूरी में रुक जाएगा क्योंकि उसका भारी वजन टायरों को जमीन पर दबाकर बेहतर पकड़ देता है","कोई फर्क नहीं पड़ता, क्योंकि 55 मील प्रति घंटे पर किसी भी वाहन को प्रतिक्रिया करने और रुकने के लिए लगभग 60 फीट चाहिए","लदे हुए ट्रक को कार की तुलना में रुकने के लिए बहुत अधिक दूरी चाहिए, इसलिए आपको कहीं अधिक जगह छोड़नी चाहिए और पहले ही ब्रेक लगाना शुरू करना चाहिए"],"explanation":"लदे हुए ट्रक का कहीं अधिक भार और गति-बल उसकी कुल रुकने की दूरी को कार से बहुत ज्यादा बना देता है, इसलिए अधिक जगह छोड़ें और पहले ही ब्रेक लगाना शुरू करें।"},"379":{"q":"आप दो-लेन वाली सड़क पर राजमार्ग की गति से चल रहे हैं और एक मोटरसाइकिल चालक आपके ठीक आगे उसी लेन में आ जाता है, लेन के दाहिने किनारे के पास चलते हुए। यातायात मध्यम है और आगे एक ओवरटेक करने का क्षेत्र आ रहा है। इस मोटरसाइकिल के पीछे अपनी अनुसरण दूरी को संभालने का सबसे सुरक्षित तरीका क्या है?","options":["मोटरसाइकिल को एक पूर्ण आकार के वाहन की तरह समझें: उसे पूरी लेन छोड़ें और अतिरिक्त दूरी रखते हुए पीछे चलें, क्योंकि वह आपसे बहुत कम दूरी में रुक सकती है","अपनी लेन में आगे बढ़ें और लेन के खाली बाएँ हिस्से को मोटरसाइकिल के साथ साझा करें, क्योंकि एक बाइक को लेन का केवल एक हिस्सा चाहिए","अपनी सामान्य कार-लंबाई की अनुसरण दूरी पर उसके पीछे लग जाएँ, क्योंकि मोटरसाइकिल छोटी होती है और उसे कार से कम जगह चाहिए","पास बने रहें और ओवरटेक क्षेत्र में तुरंत पास करने के लिए तैयार रहें, क्योंकि असली खतरा धीमी मोटरसाइकिल के पीछे रुके रहना है"],"explanation":"मोटरसाइकिल पूरी लेन की हकदार है और भारी ट्रक की तुलना में बहुत कम दूरी में रुक सकती है, इसलिए उसे पूरी लेन दें और अतिरिक्त दूरी रखकर पीछे चलें।"},"380":{"q":"आप अपने लदे हुए संयोजन वाहन (ट्रैक्टर-ट्रेलर) के साथ एक ग्रामीण चौराहे के पास पहुँच रहे हैं। ट्रैफिक सिग्नल बंद है (पूरी तरह से बेकार) और किसी भी दिशा में रुकने या रास्ता देने का कोई चिह्न नहीं है। चौराहे के पास पहुँचते समय आप देखते हैं कि एक पिकअप ट्रक आपसे एक पल पहले पहुँचा है और आपकी दाहिनी ओर वाली क्रॉस सड़क पर पहले से ही रुककर आगे बढ़ने का इंतज़ार कर रहा है। सही कार्रवाई क्या है?","options":["पहले स्वयं आगे बढ़ें, क्योंकि लदे हुए संयोजन वाहन को अधिक जगह चाहिए और हल्के वाहनों पर उसका रास्ते का अधिकार होता है","पिकअप ट्रक को रास्ता दें, क्योंकि वह चौराहे पर पहले पहुँचा है और आपकी दाहिनी ओर भी है","बंद सिग्नल को अपनी हरी बत्ती मानकर बिना गति कम किए आगे बढ़ते रहें","चौराहे के बीच में रुक जाएँ ताकि क्रॉस यातायात आपको मोड़ शुरू करने से पहले देख सके"],"explanation":"बिना नियंत्रण वाले चौराहे पर पहले पहुंचने वाले वाहन को रास्ता दें, और लगभग एक साथ पहुंचने पर अपनी दाईं ओर वाले वाहन को रास्ता दें।"},"381":{"q":"एक साफ़ कार्यदिवस की दोपहर 3:15 बजे हैं और आप एक लदे हुए सिंगल ट्रक को एक रिहायशी इलाके से चला रहे हैं, तभी आपको एक चमकती पीली बीकन लाइट और एक स्कूल-ज़ोन का लगा हुआ चिह्न दिखाई देता है। आपके आसपास का यातायात अब भी सामान्य 30 मील प्रति घंटे की सीमा पर चल रहा है और आगे की सड़क खुली दिख रही है। सबसे अच्छा कदम क्या है?","options":["लगी हुई 30 मील प्रति घंटे की सीमा बनाए रखें, क्योंकि आगे लेन खुली है और अन्य वाहन धीमे नहीं हो रहे हैं","बाईं लेन में जाकर धीमी कारों को तेज़ी से पार करें ताकि बच्चों के आने से पहले ज़ोन से निकल जाएँ","अपनी गति को लगी हुई सीमा से नीचे करें और फुटपाथों तथा क्रॉसवॉक पर ध्यान से देखें कि कहीं कोई बच्चा अचानक सड़क पर न आ जाए","अपनी गति बनाए रखें लेकिन अपनी हाई बीम चालू कर दें ताकि चालक और पैदल यात्री आपके ट्रक को अधिक स्पष्ट रूप से देख सकें"],"explanation":"टिमटिमाती बत्ती का मतलब है कि कम गति वाला स्कूल क्षेत्र सक्रिय है, इसलिए सीमा से कम गति करें और अचानक निकल आने वाले बच्चों के लिए फुटपाथ और क्रॉसिंग पर नजर रखें।"},"382":{"q":"आप एक राजमार्ग निर्माण क्षेत्र के पास पहुँच रहे हैं जहाँ ऊपर लगा लेन सिग्नल आपकी लेन के लिए हरा तीर दिखा रहा है, लेकिन सड़क पर खड़ा एक झंडीवाला (फ्लैगर) आपकी ओर STOP (रुको) का पट्टा दिखा रहा है। आपको क्या करना चाहिए?","options":["धीरे-धीरे क्षेत्र से गुज़र जाएँ, क्योंकि हरा तीर सिग्नल कानूनी रूप से आपकी लेन को आगे बढ़ने की अनुमति देता है","केवल तभी रुकें जब झंडीवाला सीटी भी बजाए या दोनों हाथ हिलाए, अन्यथा हरे तीर का पालन करें","इस विरोधाभास को खराबी मानें और सावधानी से अधिकतम 15 मील प्रति घंटे की गति से आगे बढ़ें","रुकें और झंडीवाले का पालन करें, क्योंकि झंडीवाले के निर्देश सामान्य सिग्नलों पर भी प्राथमिकता रखते हैं"],"explanation":"ध्वजवाहक के निर्देश सभी संकेतों और सिग्नलों पर प्राथमिकता रखते हैं, क्योंकि उसे कार्य-क्षेत्र के खतरों की वास्तविक समय की जानकारी होती है जो स्थिर सिग्नल नहीं दिखा सकता।"},"383":{"q":"आप एक चार-लेन वाले बिना डिवाइडर के राजमार्ग की दाईं लेन में अपना ट्रैक्टर-ट्रेलर चला रहे हैं, तभी आपको सायरन सुनाई देता है और पीछे से एक एम्बुलेंस अपनी आपातकालीन लाइटें जलाते हुए आती दिखती है। आगे यातायात कम है और दाईं ओर का किनारा चौड़ा और खाली है। कौन सी कार्रवाई सही है?","options":["संकेत दें, सड़क के दाएं किनारे की ओर जाएं और एम्बुलेंस के गुजर जाने तक वाहन को रोक दें","अपनी लेन और गति बनाए रखें ताकि एम्बुलेंस आपके रास्ते का अनुमान लगाकर आपके चारों ओर से निकल सके","बाईं लेन में जाकर वहीं रुक जाएं ताकि दाईं ओर एम्बुलेंस के लिए पूरी तरह खाली रहे","यातायात से आगे रहने के लिए गति बढ़ाएं और मुड़ने के लिए कोई बगल की गली ढूंढें"],"explanation":"जब कोई आपातकालीन वाहन बत्ती और सायरन के साथ पास आए, तो संकेत दें, सड़क के दाएं किनारे पर जाएं और उसके गुजरने तक रुकें।"},"384":{"q":"आपको एक भरा हुआ वैन ट्रेलर सौंपा जाता है जिसमें हल्के डिब्बे फर्श से छत तक ढेर किए गए हैं और ट्रेलर को ऊपर तक भर देते हैं। उसी ट्रेलर की तुलना में जो घने, भारी माल को फर्श पर केवल घुटने तक ऊंचाई तक ढेर करके ले जा रहा है, यह ऊंचा, ऊपर से भारी भार आपकी ड्राइविंग को कैसे प्रभावित करता है, इस बारे में सबसे सटीक कथन कौन सा है?","options":["ऊंची ढेराई गुरुत्वाकर्षण केंद्र को नीचे कर देती है, इसलिए आप रैंप और मोड़ों को ट्रकों के लिए निर्धारित गति पर सुरक्षित रूप से ले सकते हैं","ऊंचा गुरुत्वाकर्षण केंद्र ट्रेलर के मोड़ों और रैंप पर पलटने की संभावना बढ़ा देता है, इसलिए आपको उनमें प्रवेश करने से काफी पहले गति कम करनी चाहिए","चूंकि माल हल्का है, गुरुत्वाकर्षण केंद्र का पलटने के जोखिम पर कोई प्रभाव नहीं पड़ता और यह केवल ब्रेकिंग दूरी के लिए मायने रखता है","ऊंचा गुरुत्वाकर्षण केंद्र मुख्य रूप से आपकी रुकने की दूरी बढ़ाता है, इसलिए असली खतरा आगे वाले वाहन से पीछे से टकराना है"],"explanation":"ऊंचा लदा भार हल्का होने पर भी गुरुत्व केंद्र को बढ़ा देता है, जिससे मोड़ों और रैंप पर पलटने की संभावना बहुत बढ़ जाती है, इसलिए उनसे काफी पहले गति घटाएं।"},"385":{"q":"आप एक भरा हुआ टैंकर चला रहे हैं और 35 मील प्रति घंटे की अनुशंसित गति वाले क्लोवर-लीफ निकास रैंप के पास पहुंच रहे हैं। आपके पीछे यातायात घना है और आप चलते रहना चाहते हैं। यह याद करते हुए कि ट्रकों के पलटने का सबसे आम कारण क्या है, इस रैंप पर आपको सबसे अधिक किस एकमात्र सबसे बड़े कारक की चिंता करनी चाहिए?","options":["बहुत नीचे संतुलित किया गया भार, जो ट्रेलर के गुरुत्वाकर्षण केंद्र को सड़क की सतह के खतरनाक रूप से करीब रखता है","मोड़ में प्रवेश करते समय आगे वाले वाहन का पूरे एक सेकंड बहुत करीब से पीछा करना","रैंप के मोड़ में प्रवेश करने से पहले धीमा होने के बजाय मोड़ के दौरान अपनी गति बहुत अधिक रखना","रैंप से पहले सीधे पहुंच मार्ग पर रहते हुए ट्रेलर ब्रेक से बहुत हल्के से ब्रेक लगाना"],"explanation":"ट्रक के पलटने का सबसे आम कारण मोड़ या रैंप को बहुत तेज गति से लेना है, इसलिए मोड़ में घुसने से पहले सुरक्षित गति पर आएं, न कि मोड़ के भीतर।"},"386":{"q":"आप मशीन के बक्सों के ढेर वाला एक ऊँचा भार ले जा रहे हैं और इंटरस्टेट से 30 मील प्रति घंटा अंकित एक मुड़ी हुई प्रवेश/निकास रैंप पर उतरते हैं। आपका ट्रक भारी भरा हुआ है और उसका गुरुत्व केंद्र ऊँचा है। रैंप पर पलटने से बचाव के लिए कौन-सी क्रिया सबसे अच्छी सुरक्षा देती है?","options":["स्थिर 30 मील प्रति घंटा बनाए रखें क्योंकि यही अंकित रैंप गति है और संकेत पहले से ही ट्रकों का ध्यान रखता है","हाईवे की गति बनाए रखें जब तक आपको ट्रेलर झुकता महसूस न हो, फिर मोड़ में ज़ोर से ब्रेक लगाएँ","मोड़ से न्यूट्रल में निकलें ताकि इंजन आपको तेज़ न धकेले","मोड़ में प्रवेश करने से पहले अंकित रैंप गति से काफ़ी कम गति तक धीमे हों, क्योंकि संकेत कारों के लिए तय किया गया है, ऊँचे भारी भार के लिए नहीं"],"explanation":"रैंप गति संकेत कारों के लिए तय होते हैं, इसलिए ऊंचे, भारी भार के साथ पलटने से बचने के लिए मोड़ में घुसने से पहले बताई गई रैंप गति से काफी कम गति पर आएं।"},"387":{"q":"एक डिलीवरी पूरी करने के बाद आप अपने लदे हुए सीधे ट्रक को एक खड़ी ढलान वाली सड़क पर, दाहिनी ओर के किनारे (कर्ब) से सटाकर पार्क करते हैं। पार्किंग ब्रेक लगाकर केबिन से उतरने से पहले, आप अगले पहियों को इस तरह छोड़ना चाहते हैं कि अगर ब्रेक कभी छूट जाएं तो ट्रक कर्ब की ओर लुढ़ककर उसी से रुक जाए, न कि नीचे जाती यातायात लेन में चला जाए। अगले पहियों को किस दिशा में मोड़कर छोड़ना चाहिए?","options":["कर्ब की ओर (दाहिनी ओर) मुड़े हुए, ताकि लुढ़कने पर कर्ब अगले टायर को रोक दे","कर्ब से दूर (बाईं ओर) मुड़े हुए, ताकि ट्रक का पिछला हिस्सा कर्ब से सट जाए","सीधे छोड़े हुए, क्योंकि ढलान पर ट्रक को असल में लगा हुआ पार्किंग ब्रेक ही रोकता है","कर्ब की ओर मुड़े हुए केवल तभी जब कोई कर्ब न हो, अन्यथा सीधे"],"explanation":"कर्ब वाली ढलान पर नीचे की ओर पार्क करते समय आगे के पहिये कर्ब की ओर मोड़ें, ताकि लुढ़कने पर टायर कर्ब से टकराकर ट्रक रोक दे।"},"388":{"q":"आप अपना लोड जांचने के लिए एक खड़ी पहाड़ी सड़क पर रुकते हैं और ट्रक को चढ़ाई की ओर (ऊपर की दिशा में) मुंह करके खड़ा करते हैं, जिसमें दाहिनी ओर कर्ब (किनारा) है। चलने से पहले आप चाहते हैं कि अगर ब्रेक कभी छूट जाएं तो ट्रक पीछे लुढ़ककर कर्ब से टकराकर रुक जाए। 'चढ़ाई की ओर मुंह और कर्ब मौजूद' इस स्थिति में अगले पहियों को सही तरीके से सेट करने के लिए आपको:","options":["अगले पहियों को कर्ब की ओर (दाईं ओर) मोड़ें ताकि टायर का अगला हिस्सा उससे टकराए","अगले पहियों को कर्ब से दूर (बाईं ओर) मोड़ें ताकि पीछे लुढ़कने पर टायर का पिछला हिस्सा कर्ब से टकराए","अगले पहियों को सीधा रहने दें और केवल पार्किंग ब्रेक पर भरोसा करें","अगले पहियों को तेजी से दाईं ओर मोड़ें, ठीक वैसे जैसे कर्ब न होने पर करते"],"explanation":"कर्ब वाली ढलान पर ऊपर की ओर पार्क करते समय आगे के पहिये कर्ब से दूर मोड़ें, ताकि पीछे लुढ़कने पर टायर कर्ब से टकराकर वाहन रोक दे।"},"389":{"q":"आप सूखी शहरी सड़क पर एक मोटरसाइकिल के पीछे चल रहे हैं और सवार की अब तक की चाल के आधार पर अपनी अनुसरण दूरी तय करते हैं। उसे पीछे से न टकराने के लिए उस मोटरसाइकिल के बारे में किस धारणा की योजना बनाना सबसे महत्वपूर्ण है?","options":["यह हमेशा गति सीमा से काफी कम चलेगी, इसलिए कम दूरी सुरक्षित है","इसे दो पूरी लेन जितनी जगह चाहिए, इसलिए कभी इसके बगल में न आएं","इसे ट्रैफ़िक में देखना आसानी से छूट सकता है और यह आपके ट्रक की तुलना में बहुत तेज़ी से रुक सकती है","यह एक स्थिर गति बनाए रखेगी और अचानक धीमी नहीं होगी"],"explanation":"मोटरसाइकिल यातायात में देखना मुश्किल होती हैं और भारी ट्रक से बहुत कम दूरी में रुक सकती हैं, इसलिए अधिक फॉलोइंग दूरी रखें।"},"390":{"q":"आप एक लदी हुई ट्रेलर खींच रहे हैं और सूखे दिन की परिस्थितियों में एक लंबी, खड़ी ढलान पर उतरना शुरू करते हैं। आपके साथ बैठा एक नौसिखिया पूछता है कि यह उतराई आपके वाहन को पूरी तरह रुकने के लिए आवश्यक दूरी को समतल सड़क पर उसी गति से रुकने की तुलना में कैसे प्रभावित करती है। कौन सा कथन सही है?","options":["इससे आपकी रुकने की दूरी पर कोई फर्क नहीं पड़ता, क्योंकि सड़क की ढलान चाहे जो भी हो, 55 मील प्रति घंटे पर कुल रुकने की दूरी लगभग 419 फीट पर निश्चित होती है।","आपकी रुकने की दूरी बहुत कम हो जाती है, क्योंकि गुरुत्वाकर्षण ट्रक को नीचे की ओर खींचकर टायरों को सड़क पर अधिक जोर से दबाता है और ब्रेकिंग पकड़ को बेहतर बनाता है।","जैसे ही ढलान पर इंजन और गियर ब्रेकिंग संभाल लेते हैं, आपकी रुकने की दूरी थोड़े समय के लिए लगभग शून्य तक गिर जाती है।","आपकी रुकने की दूरी बढ़ जाती है, क्योंकि गुरुत्वाकर्षण ढलान पर आपके संवेग में जुड़ जाता है और वाहन को रोकने के लिए ब्रेक को अधिक दूरी तक अधिक मेहनत करनी पड़ती है।"],"explanation":"ढलान पर गुरुत्वाकर्षण आपकी गति में जुड़ जाता है, इसलिए ब्रेक को अधिक दूरी पर ज्यादा काम करना पड़ता है और रुकने की दूरी बढ़ जाती है।"},"391":{"q":"आप एक ग्रामीण राजमार्ग पर लदा हुआ ट्रेलर खींच रहे हैं और एक तीखे मोड़ के पास पहुँच रहे हैं जहाँ पीला सलाहकारी संकेत 'सुरक्षित गति 40 मील प्रति घंटा' लिखा है। सड़क सूखी है और यातायात हल्का है। एक CDL चालक के रूप में आपको इस निर्धारित सलाहकारी गति को कैसे लेना चाहिए, इसका सबसे अच्छा वर्णन कौन-सा कथन करता है?","options":["40 मील प्रति घंटा का आंकड़ा यात्री कारों के लिए निकाला गया है, इसलिए ऊँचे गुरुत्व केंद्र वाले लदे हुए ट्रक के रूप में आपको पलटने से बचने के लिए मोड़ में इससे कम गति पर प्रवेश करना चाहिए।","चूँकि यह संकेत एक आधिकारिक सलाह है, 40 मील प्रति घंटा सभी वाहनों के लिए अधिकतम कानूनी गति है, और जब तक सड़क सूखी है ट्रक ठीक 40 मील प्रति घंटा पर मोड़ ले सकते हैं।","यह सलाह केवल खाली ट्रेलरों पर लागू होती है; चूँकि आपका ट्रेलर लदा और स्थिर है, आप मोड़ में 40 मील प्रति घंटा से अधिक चल सकते हैं।","सलाहकारी गति विशेष रूप से ट्रकों के लिए दी जाती है, इसलिए 40 मील प्रति घंटा में पहले से ही ट्रक सुरक्षा मार्जिन शामिल है और आप बिना और धीमे हुए इसके बराबर चल सकते हैं।"],"explanation":"मोड़ की सलाह दी गई गति कारों के लिए तय होती है, इसलिए ऊंचे गुरुत्व केंद्र वाले लदे ट्रक को पलटने से बचने के लिए दर्शाई गति से कम पर मुड़ना चाहिए।"},"393":{"q":"आप एक लंबा डिलीवरी सफर पूरा करके यार्ड में पहुँचते हैं। आज सुबह यात्रा-पूर्व निरीक्षण से पहले सब कुछ ठीक था, और आपने पहले 50 मील के भीतर तथा रास्ते में हर 150 मील पर अपने माल की बंधाई फिर से जाँची थी। अब जब सफर खत्म हो गया है और ट्रक खड़ा है, तो DPS द्वारा अपेक्षित पूरा निरीक्षण चक्र पूरा करने के लिए आपको कौन-सा निरीक्षण करना चाहिए?","options":["किसी और निरीक्षण की जरूरत नहीं है क्योंकि हर 150 मील पर आपकी रास्ते की जाँचों ने पूरे दिन वाहन को पहले ही कवर कर लिया है","यात्रा-पश्चात निरीक्षण, ताकि सफर के दौरान उत्पन्न हुई कोई भी खराबी अगले चालक या आपकी अगली पाली से पहले दर्ज की जा सके","वार्षिक निरीक्षण, क्योंकि दैनिक ड्राइविंग समाप्त होने के बाद यही एकमात्र औपचारिक निरीक्षण आवश्यक है","सफर की टूट-फूट का हिसाब करने के लिए ब्रेक और टायरों का मासिक निरीक्षण"],"explanation":"पोस्ट-ट्रिप निरीक्षण यात्रा के अंत में किया जाता है ताकि चलाते समय आई किसी भी खराबी को अगली शिफ्ट से पहले रिपोर्ट में दर्ज किया जा सके।"},"395":{"q":"आपने अभी-अभी 11 घंटे की यात्रा पूरी की है और यार्ड में पहुँचे हैं। यात्रा के दौरान ब्रेक थोड़े ढीले महसूस हुए और आपने देखा कि एक मार्कर लाइट टिमटिमाकर बुझ रही है। अपनी यात्रा-पश्चात (पोस्ट-ट्रिप) जाँच को सही ढंग से पूरा करने के भाग के रूप में, निम्नलिखित में से कौन-सा दस्तावेज़ आपसे आमतौर पर भरवाने और, जहाँ आवश्यक हो, जमा करवाने की अपेक्षा की जाती है ताकि अगले चालक और वाहक को इन स्थितियों के बारे में चेतावनी मिल सके?","options":["ईंधन-खरीद और माइलेज रसीद लॉग जिसे आप IFTA कर रिपोर्टिंग के लिए रखते हैं","आपकी व्यक्तिगत यात्रा डायरी जिसमें आप लिखते हैं कि दिन कैसा रहा और आप आराम के लिए कहाँ रुके","एक चालक वाहन निरीक्षण रिपोर्ट (DVIR) जो किसी भी खराबी का दस्तावेज़ बनाती है, जैसे ढीले ब्रेक और खराब मार्कर लाइट","डिस्पैचर के रिकॉर्ड के लिए सड़क किनारे का मौसम और सड़क-स्थिति रिपोर्ट"],"explanation":"पोस्ट-ट्रिप निरीक्षण में चालक वाहन निरीक्षण रिपोर्ट (DVIR) भरना ज़रूरी है, जो कमज़ोर ब्रेक और खराब मार्कर लाइट जैसी सुरक्षा खराबियों को दर्ज करती है।"},"396":{"q":"एक ठंडी सुबह है और आपने यात्रा-पूर्व वार्म-अप शुरू करने के लिए अभी-अभी इंजन चालू किया है। निकलने से पहले यह सुनिश्चित करने के लिए कि सब कुछ ठीक से काम कर रहा है, आप डैशबोर्ड के गेज देख रहे हैं। तेल दबाव गेज के लिए निम्नलिखित में से कौन-सी सही अपेक्षा है, जो यह दर्शाती है कि इंजन चलाना सुरक्षित है?","options":["सुई को धीरे-धीरे चढ़ना चाहिए और तेल गर्म होने के बाद कई मिनट तक आइडलिंग के बाद सामान्य दबाव तक पहुँचना चाहिए","चूँकि सुबह ठंडी है, तेल दबाव विश्वसनीय होने से पहले आपको इसे लगभग एक घंटे तक आइडल पर चलने देना चाहिए","जब तक आप सड़क पर भार के साथ चल नहीं रहे होते, तब तक तेल दबाव का दर्ज होना ज़रूरी नहीं है","इंजन चालू होने के कुछ ही सेकंड के भीतर सुई को सामान्य संचालन दबाव तक पहुँच जाना चाहिए"],"explanation":"इंजन चालू होने के कुछ सेकंड में ही तेल का दबाव सामान्य कार्यशील दबाव तक पहुंच जाना चाहिए, वरना नुकसान से बचने के लिए इंजन बंद कर दें।"},"397":{"q":"आप एक ग्रामीण दो-लेन राजमार्ग पर अपनी यात्रा के 40 मिनट बाद हैं, तभी गेजों पर नज़र डालने पर आप देखते हैं कि तेल दबाव गेज शून्य पर गिर गया है, जबकि इंजन अभी भी सामान्य आवाज़ कर रहा है और सामान्य रूप से चल रहा है और अभी तक कोई चेतावनी बज़र नहीं बजा है। सही कार्रवाई क्या है?","options":["जैसे ही सुरक्षित हो, सड़क से किनारे हटें, रुकें और इंजन बंद कर दें","चूँकि इंजन अभी भी ठीक आवाज़ कर रहा है, अगले ट्रक स्टॉप तक सामान्य रूप से गाड़ी चलाते रहें","गति बनाए रखें लेकिन एक्सीलेटर हल्का कर दें और अपने निर्धारित ईंधन स्टॉप तक जारी रखें","इंजन का भार कम करने के लिए रेडियो और ए/सी जैसे गैर-आवश्यक उपकरण बंद कर दें और चलते रहें"],"explanation":"तेल के दबाव का गिरना मतलब इंजन में अब चिकनाई नहीं हो रही, इसलिए जैसे ही सुरक्षित हो सड़क से हटें और तुरंत इंजन बंद कर दें।"},"398":{"q":"गर्मी की एक तपती दोपहर में आप पूरी तरह लदे हुए, अपने GVWR के करीब, एक लंबी चढ़ाई चढ़ रहे हैं। जैसे ही आप शिखर के पास पहुँचते हैं, डैशबोर्ड का एक गेज लाल क्षेत्र की ओर चढ़ने लगता है। प्रतिक्रिया तय करने से पहले, वह कौन-सा गेज है जो विशेष रूप से आपको यह चेतावनी देने के लिए बना है कि इंजन स्वयं ज़्यादा गर्म हो रहा है?","options":["ऑयल प्रेशर गेज, क्योंकि गर्म मौसम में तेल पतला हो जाता है और सुई ऊपर चढ़कर इंजन के उच्च तापमान की चेतावनी देती है","कूलेंट तापमान गेज, क्योंकि यह इंजन कूलेंट का तापमान दर्शाता है और चेतावनी देता है कि इंजन ज़्यादा गर्म हो रहा है","पायरोमीटर, क्योंकि यह निकास गैस की गर्मी मापता है, जो गर्म दिन में इंजन के ज़्यादा गर्म होने के बराबर होती है","वोल्टमीटर, क्योंकि गर्म दिन में लंबी चढ़ाई चार्जिंग सिस्टम को ज़्यादा गर्म कर देती है और इंजन के ज़्यादा गर्म होने का संकेत देती है"],"explanation":"शीतलक तापमान गेज इंजन शीतलक का तापमान मापता है और इंजन के ज़्यादा गरम होने पर आपको चेतावनी देता है।"},"399":{"q":"अपनी यात्रा-पूर्व जांच के दौरान आप इंजन चालू करते हैं और ट्रक के निष्क्रिय (आइडल) रहते हुए डैशबोर्ड के गेज देखते हैं। आप देखते हैं कि एमीटर (या वोल्टमीटर) की सुई स्थिर रूप से सामान्य सीमा में टिकी है और न तो गिरती है और न ही अनियमित रूप से झूलती है। यह गेज आपके वाहन के बारे में वास्तव में आपको क्या बता रहा है?","options":["इंजन का तेल दबाव यात्रा सुरक्षित रूप से शुरू करने के लिए पर्याप्त ऊंचा है","शीतलक (कूलेंट) का तापमान सुरक्षित संचालन सीमा के भीतर है","चार्जिंग प्रणाली काम कर रही है और बैटरी को सही तरह से चार्ज रखे हुए है","बैटरी की कोशिकाओं में पर्याप्त पानी है और वह बोल्ट से मजबूती से कसी हुई है"],"explanation":"एमीटर या वोल्टमीटर का सामान्य रेंज में स्थिर रहना यह पुष्टि करता है कि अल्टरनेटर करंट बना रहा है और बैटरी को सही तरह से चार्ज रखे हुए है।"},"400":{"q":"अपनी प्री-ट्रिप जांच के दौरान, आप अपने ट्रैक्टर के स्टीयरिंग व्हील को पकड़कर आगे-पीछे हिलाते हैं और अगले पहिये नहीं हिलते। पहियों के प्रतिक्रिया देने से पहले आपको एक ध्यान देने योग्य ढीलापन महसूस होता है। यह तय करने के लिए कि यह फ्री प्ले सुरक्षित सीमा के भीतर है और वाहन चलाना कानूनी है, अगले पहिये मुड़ना शुरू होने से पहले स्टीयरिंग व्हील में अधिकतम कितनी हलचल होनी चाहिए?","options":["स्टीयरिंग व्हील के आधे घुमाव तक, क्योंकि भारी ट्रकों में कुछ ढीलापन सामान्य है","पहियों के प्रतिक्रिया देने से पहले स्टीयरिंग व्हील के एक पूरे घुमाव तक","90 डिग्री तक, जो व्हील का एक चौथाई घुमाव है","पहियों के प्रतिक्रिया देने से पहले लगभग 10 डिग्री से अधिक हलचल नहीं"],"explanation":"अगले पहिए प्रतिक्रिया देने से पहले स्टीयरिंग व्हील का फ्री प्ले लगभग 10 डिग्री से अधिक नहीं होना चाहिए; इससे ज्यादा होना घिसा या ढीला स्टीयरिंग दर्शाता है।"},"401":{"q":"अपनी प्री-ट्रिप जांच के दौरान आप क्लच पेडल दबाते हैं और पाते हैं कि उसमें सामान्य से काफी ज्यादा फ्री प्ले (प्रतिरोध से पहले ढीली गति) है। आप पहले से ही देर से चल रहे हैं और ट्रक अभी भी चल रहा है। कौन-सा कथन आपकी पाई गई स्थिति और आपको क्या करना चाहिए, इसका सबसे अच्छा वर्णन करता है?","options":["क्लच फ्री प्ले का बहुत ज्यादा या बहुत कम होना एक यांत्रिक खराबी है जिसे वाहन को सुरक्षित रूप से चलाने से पहले ठीक किया जाना चाहिए","अत्यधिक क्लच फ्री प्ले सामान्य घिसाव है जो केवल तभी मायने रखता है जब क्लच भार के नीचे फिसलने लगता है","यह एक समस्या है, लेकिन केवल स्टीयरिंग और ब्रेक ही ऐसे जांच आइटम हैं जो ट्रक को सेवा से बाहर रख सकते हैं","ढीला क्लच फ्री प्ले वास्तव में इस बात का अच्छा संकेत है कि लिंकेज अच्छी तरह से चिकनाई किया हुआ है और अटक नहीं रहा"],"explanation":"क्लच का फ्री प्ले बहुत ज्यादा या बहुत कम होना एक यांत्रिक खराबी है जिसे वाहन को सुरक्षित रूप से चलाने से पहले ठीक करना जरूरी है।"},"402":{"q":"आप एक भरे हुए ट्रेलर के साथ एक लंबी पहाड़ी ढलान से नीचे जा रहे हैं। ईंधन बचाने और घिसाव कम करने के लिए, एक साथी ड्राइवर सुझाव देता है कि आप गियर को न्यूट्रल में डाल दें और ट्रक को ढलान से नीचे लुढ़कने दें, ब्रेक का उपयोग केवल तब करें जब आपकी गति बहुत अधिक हो जाए। इस सलाह का पालन करना गलत विकल्प क्यों है?","options":["यह एक छोटी ढलान पर स्वीकार्य है क्योंकि केवल ब्रेक ही पूरे रास्ते नीचे तक ट्रक को सुरक्षित रूप से नियंत्रित कर सकते हैं","आप इंजन और गियर ब्रेकिंग तथा वाहन का नियंत्रण खो देते हैं, आपके सर्विस ब्रेक अधिक गर्म होकर प्रभावहीन हो सकते हैं, और न्यूट्रल में लुढ़कना अवैध है","यह केवल तभी समस्या बनता है जब ढलान उस निचले गियर से अधिक तीव्र हो जिसे आप उतरने से पहले सामान्यतः चुनते हैं","न्यूट्रल में लुढ़कने से इतना अधिक ईंधन बचता है कि नियंत्रण की थोड़ी हानि अधिकांश ढलानों पर एक स्वीकार्य समझौता है"],"explanation":"लंबी ढलान पर न्यूट्रल में डालने से इंजन और गियर ब्रेकिंग खत्म हो जाती है, सर्विस ब्रेक गर्म होकर फेल हो जाते हैं, और न्यूट्रल में लुढ़कना गैरकानूनी है।"},"403":{"q":"आप एक पुराने ट्रक में लदे हुए ट्रेलर के साथ एक लंबी चढ़ाई पर चढ़ रहे हैं, जिसके डैशबोर्ड पर कोई गियर संकेतक नहीं है। इंजन जोर लगाने और शक्ति खोने लगा है, और आप जानते हैं कि चढ़ाई जारी रखने के लिए आपको निचले गियर में आना होगा। किसी शिफ्ट चार्ट या गियर डिस्प्ले के बिना, इस समय कौन सा गियर सही है यह तय करने के लिए आपको वास्तव में किस जानकारी का उपयोग करना चाहिए?","options":["ट्रेलर को चढ़ाई पर चढ़ते देखते हुए केवल अपने दाहिनी ओर के दर्पण में दिखने वाली जानकारी","अपनी चालक सीट की ऊंचाई और केबिन से ढलान कितनी खड़ी दिखती है, यह","टैकोमीटर पर दिखाई गई इंजन की rpm के साथ अपनी वर्तमान सड़क गति का संयोजन","एक त्वरित संदर्भ के रूप में अपने कंधे के सापेक्ष सामने के दरवाज़े के हैंडल की स्थिति"],"explanation":"सही गियर सड़क पर अपनी गति को टैकोमीटर पर दिखाए गए इंजन के आरपीएम से मिलाकर चुना जाता है।"},"404":{"q":"आप पूरी तरह लदे हुए ट्रेलर के साथ एक तीव्र चढ़ाई वाली ढलान पर लाल बत्ती पर रुके हैं। बत्ती हरी होती है, और आपको रिग को आसानी से चलाना है बिना उसे पीछे, ठीक आपके पीछे खड़ी कार की ओर सरकने दिए। जब आप सर्विस (पैर) ब्रेक छोड़ने और इंजन की गति बढ़ाने की तैयारी करते हैं, तो कौन-सी तकनीक चलते समय वाहन को पीछे लुढ़कने से सबसे अच्छी तरह रोकती है?","options":["चलने से पहले अतिरिक्त हवा का दबाव बनाने के लिए सर्विस ब्रेक को कई बार तेज़ी से दबाएँ","ऊँचे गियर में डालें ताकि इंजन के पास ढलान पर चढ़ने के लिए अधिक खींचने की शक्ति हो","इंजन की गति बढ़ाएँ और क्लच को धीरे-धीरे छोड़ें ताकि ट्रक केवल टॉर्क के बल पर आगे बढ़े","पार्किंग ब्रेक को लगाए रखें, और उसे तभी छोड़ें जब इंजन भार को संभाल ले और वाहन आगे बढ़ने लगे"],"explanation":"चढ़ाई पर शुरू करते समय पार्किंग ब्रेक लगाए रखें और उसे तभी छोड़ें जब इंजन भार संभाल ले और आप आगे बढ़ने लगें, ताकि वाहन पीछे न लुढ़के।"},"405":{"q":"तापमान हिमांक से थोड़ा नीचे है और गोदाम के निकास पर रुकने के संकेत से जब आप अपना लदा हुआ कॉम्बिनेशन ट्रक आगे बढ़ाते हैं, तो आँगन पर बर्फ की एक पतली परत जमी है। आप महसूस करते हैं कि चालक (ड्राइव) पहिए पकड़ खोने लगे हैं। चालक पहियों को बिना घुमाए (स्पिन किए) और त्वरण स्किड पैदा किए बिना आगे बढ़ने का सबसे अच्छा मौका कौन सी क्रिया देती है?","options":["धीरे-धीरे एक्सेलरेटर दबाएँ और गति को क्रमशः बढ़ाएँ ताकि चालक टायर फिसलन भरी सतह पर अपनी पकड़ बनाए रखें","एक्सेलरेटर को मजबूती से फर्श तक दबाएँ ताकि अतिरिक्त शक्ति ट्रक को फिसलन भरे हिस्से से धकेल दे","आगे बढ़ने से पहले वाहन की हर 10 फीट लंबाई के लिए एक अतिरिक्त सेकंड की अनुसरण दूरी जोड़ें","क्लच को आंशिक रूप से दबाए रखें और इंजन को बहुत ऊँचा रेव करें, फिर ज़ोरदार शुरुआत के लिए उसे तेज़ी से छोड़ें"],"explanation":"फिसलन भरी, जमने के करीब वाली सतह पर थ्रॉटल धीरे से दबाएं और गति क्रमशः बढ़ाएं ताकि ड्राइव टायर पकड़ बनाए रखें और फिसलें नहीं।"},"406":{"q":"अभी-अभी भोर हुई है और आप अपना यात्रा-पूर्व निरीक्षण कर रहे हैं। बोनट खोलकर जब आप अल्टरनेटर और वॉटर पंप की ड्राइव बेल्ट देखते हैं, तो कौन-सी स्थिति बताती है कि ट्रक को सड़क पर सुरक्षित रूप से ले जाने से पहले बेल्ट पर ध्यान देने की ज़रूरत है?","options":["बेल्ट का रंग चमकदार, चमकीला होने के बजाय फीका और गहरा है","कोई बेल्ट फटी और रेशेदार हो गई है, या दबाने पर ज़रूरत से ज़्यादा झुकती है (गलत तनाव)","हॉर्न दबाने पर वह पर्याप्त तेज़ नहीं बजता","चाबी ऑन होने पर ईंधन गेज पूरा नहीं दिखाता"],"explanation":"ड्राइव बेल्ट फटी, उधड़ी या जरूरत से ज्यादा झुकने वाली हो तो बदल देनी चाहिए, क्योंकि गलत तनाव या घिसाव से बेल्ट टूट सकती है।"},"407":{"q":"अपनी प्री-ट्रिप जांच के दौरान आप हुड खोलते हैं और इंजन कक्ष में रेडिएटर और हीटर की नलियों (होज़) पर हाथ फेरते हैं। आप इन नलियों में मुख्य रूप से किस स्थिति की जांच कर रहे हैं?","options":["नलियां गर्म महसूस होती हैं या नहीं, जो दर्शाए कि इंजन कार्यशील तापमान तक पहुंच गया है","बेल्ट और पुली वाले हिस्से से आने वाली तेज़ सीटी या खटखट की आवाज़","नरम पड़े हिस्से, रिसाव और दरारें जो नली के फटने का कारण बन सकती हैं","चमकदार, चिकनी सतह जो दिखाए कि रबर को हाल ही में साफ और उपचारित किया गया है"],"explanation":"इंजन की नलियों को नरम जगहों, रिसाव और दरारों के लिए जांचना चाहिए, क्योंकि कमजोर नली गर्मी और दबाव में फट सकती है और शीतलक खत्म हो सकता है।"},"408":{"q":"सुबह की पूर्व-यात्रा जाँच के दौरान तापमान हिमांक से कुछ ही नीचे है, और जैसे ही आप इंजन कम्पार्टमेंट के चारों ओर घूमते हैं, आप पहाड़ी इलाके में लंबे दिन की ड्राइविंग से पहले पावर स्टीयरिंग प्रणाली की जाँच करने का निर्णय लेते हैं। निम्नलिखित में से कौन-सा पावर स्टीयरिंग प्रणाली में आपको क्या जाँचना चाहिए, इसका सबसे अच्छा वर्णन करता है?","options":["पहिए घूमने से पहले स्टीयरिंग व्हील में 10 डिग्री (20-इंच के व्हील पर लगभग 2 इंच) से अधिक मुक्त घुमाव न होना","पंप से तेज़ सीटी या कराहने जैसी आवाज़ें, क्योंकि ध्वनि ही पावर स्टीयरिंग समस्या का एकमात्र भरोसेमंद संकेत है","जलाशय और लाइनों पर ताज़ा, चमकीला पेंट जो पुष्टि करे कि प्रणाली की हाल ही में सर्विसिंग हुई थी","पावर स्टीयरिंग द्रव का स्तर और होज़, जलाशय तथा कनेक्शनों में रिसाव के कोई भी संकेत"],"explanation":"पावर स्टीयरिंग सिस्टम में सही द्रव स्तर और नलियों, टंकी व जोड़ों में किसी रिसाव की जांच करें, क्योंकि कम स्तर से अचानक पावर असिस्ट खत्म हो सकती है।"},"409":{"q":"एक ठंडी, चमकीली सुबह अपने यात्रा-पूर्व निरीक्षण के दौरान आप केबिन के पास जाते हैं और देखते हैं कि विंडशील्ड के निचले किनारे पर एक दरार चल रही है, साथ ही कांच के अधिकांश हिस्से पर सड़क की गंदगी और सूखे कीड़ों के दाग की परत जमी है। अपनी यात्रा के पहले घंटे में आपको नीचे उगते सुबह के सूरज की ओर गाड़ी चलानी होगी। गाड़ी चलाने से पहले विंडशील्ड को संभालने का सही तरीका क्या है?","options":["गाड़ी चलाने से पहले विंडशील्ड को अच्छी तरह साफ करें और सुनिश्चित करें कि दरार इतनी बड़ी या ऐसी जगह पर न हो कि आपकी दृष्टि को गंभीर रूप से बाधित करे","गंदगी को वैसे ही रहने दें क्योंकि गंदी, धुंधली विंडशील्ड वास्तव में नीचे उगते सुबह के सूरज की चकाचौंध को कम करती है और दृष्टि को बेहतर बनाती है","सूरज की चकाचौंध से निपटने के लिए पूरी विंडशील्ड पर गहरे रंग की टिंट फिल्म लगाएं, फिर कांच साफ किए बिना गाड़ी चलाएं","विंडशील्ड को पूरी तरह नज़रअंदाज़ करें क्योंकि कोई भी दरार, चाहे कितनी भी मामूली हो, वाहन को स्वतः सेवा से बाहर कर देती है और निरीक्षण समाप्त कर देती है"],"explanation":"गाड़ी चलाने से पहले विंडशील्ड साफ होनी चाहिए और उसमें ऐसी बड़ी या स्थिति की कोई दरार नहीं होनी चाहिए जो दृश्यता को बुरी तरह बाधित करे।"},"410":{"q":"बारिश वाली सुबह है और अपनी प्री-ट्रिप जाँच के दौरान आप पाते हैं कि चालक की ओर का वाइपर ब्लेड फटा हुआ है और वॉशर का जलाशय खाली है। आप पहले से ही समय से पीछे हैं और अभी बारिश हल्की है। इन्हें मामूली असुविधा मानने के बजाय गाड़ी चलाने से पहले ठीक करना क्यों ज़रूरी है, इसका सबसे अच्छा कारण कौन-सा है?","options":["ये मुख्य रूप से सड़क की गंदगी को पेंट से दूर रखने और ट्रक के पुनर्विक्रय मूल्य को बनाए रखने के लिए चाहिए होते हैं","काम करने वाले वाइपर और वॉशर बारिश में आपकी दृष्टि साफ़ रखते हैं, और साफ़ दृष्टि के बिना आप दूरी, यातायात और आगे के खतरों का सुरक्षित अनुमान नहीं लगा सकते","ये केवल इसलिए ज़रूरी हैं ताकि ट्रक वार्षिक राज्य सुरक्षा निरीक्षण पास कर ले, रोज़मर्रा की ड्राइविंग के लिए नहीं","ये विंडशील्ड को तेज़ी से डीफ़्रॉस्ट करने में मदद करते हैं, और यही असली कारण है कि ये आउट-ऑफ़-सर्विस वस्तु हैं"],"explanation":"वाइपर और वॉशर बारिश में आपकी दृश्यता साफ रखते हैं, और दूरी, यातायात व आगे के खतरों को आँकने के लिए साफ दृष्टि आवश्यक है।"},"411":{"q":"आप अपने ट्रैक्टर-ट्रेलर को एक तंग लोडिंग डॉक से पीछे की ओर निकाल रहे हैं, तभी पैदल चल रहा एक मज़दूर अचानक वाहन के पिछले हिस्से के पास आपके ब्लाइंड स्पॉट में आ जाता है। अपने प्री-ट्रिप निरीक्षण के दौरान आपने पुष्टि की थी कि आपका हॉर्न काम करता है। इस क्षण में, एक CDL चालक के रूप में चालू हॉर्न आपके लिए महत्वपूर्ण होने का मुख्य कारण क्या है?","options":["यह आपको सहकर्मियों को संकेत देने देता है कि आपका काम पूरा हो गया है और आप डॉक से निकलने के लिए तैयार हैं","यह पुष्टि करता है कि आपके विद्युत तंत्र में सहायक उपकरण चलाने के लिए पर्याप्त चार्ज है","यह आपको मज़दूर और अन्य लोगों को तत्काल खतरे के बारे में चेतावनी देने देता है ताकि वे हट सकें","यह एक आराम-और-सुविधा वाली विशेषता को पूरा करता है जिसे निरीक्षक सवारी की गुणवत्ता के लिए जाँचता है"],"explanation":"हॉर्न एक सुरक्षा चेतावनी उपकरण है जो श्रमिकों, पैदल यात्रियों और चालकों को तत्काल खतरे की चेतावनी देता है ताकि वे हट सकें।"},"412":{"q":"सुबह-सुबह तापमान जमाव बिंदु से थोड़ा नीचे है, और प्री-ट्रिप जांच के दौरान आपकी विंडशील्ड अंदर से बार-बार धुंधली हो रही है और उस पर पाला जम रहा है। आप पुष्टि करते हैं कि डिफ्रॉस्टर और हीटर सही से काम कर रहे हैं। सड़क पर निकलने से पहले इन प्रणालियों का काम करना ज़रूरी होने का मुख्य सुरक्षा कारण क्या है?","options":["ताकि लंबी, ठंडी पाली के दौरान केबिन पर्याप्त गर्म रहे और आप सतर्क व आरामदायक बने रहें","ताकि गाड़ी चलाने से पहले आप बाहरी शीशों और एंटीना पर जमी बर्फ को जल्दी पिघला सकें","ताकि गर्म हवा वाइपर ब्लेड को कांच से चिपकने और जमने से रोके","ताकि आप ठंडे या गीले मौसम में विंडशील्ड को साफ़ रखकर सड़क का बिना रुकावट वाला दृश्य बनाए रख सकें"],"explanation":"डीफ्रॉस्टर और हीटर ठंडे या गीले मौसम में विंडशील्ड साफ रखते हैं, जिससे सड़क का बिना रुकावट वाला दृश्य बना रहता है।"},"413":{"q":"तापमान हिमांक से थोड़ा नीचे है, आपको पास के एक ड्रॉप यार्ड तक केवल दो मील ही चलना है, और आपकी सर्दियों की जैकेट के ऊपर सीट बेल्ट सख्त और असुविधाजनक महसूस हो रही है। अपनी प्री-ट्रिप जाँच पूरी करके निकलने की तैयारी करते समय, सीट बेल्ट के संबंध में कौन-सी क्रिया सही है?","options":["दूरी कितनी भी कम हो या आप कितनी भी धीमी गति से चलाने की योजना बनाएँ, पूरी यात्रा के दौरान सीट बेल्ट बाँधें और पहनें","बेल्ट बिना बाँधे छोड़ दें क्योंकि यात्रा तीन मील से कम है और आप धीमी गति से चलेंगे","बेल्ट को ढीला करके अपनी पीठ के पीछे दबा दें ताकि चेतावनी की घंटी बंद हो जाए पर आपकी जैकेट आपकी हलचल को न रोके","बेल्ट छोड़ दें क्योंकि कम गति वाली यार्ड और लॉट ड्राइविंग के लिए कानूनी रूप से बेल्ट लगाना आवश्यक नहीं है"],"explanation":"व्यावसायिक चालक को वाहन चलते समय हमेशा सीट बेल्ट पहननी चाहिए, चाहे यात्रा कितनी भी छोटी या धीमी क्यों न हो।"},"414":{"q":"आप एक ग्रामीण दो-लेन वाले राजमार्ग पर माल ले जा रहे हैं, तभी इंजन की शक्ति खत्म हो जाती है और आप गाड़ी को दाहिने किनारे (शोल्डर) पर रोक देते हैं। आप अपनी खतरे की चेतावनी वाली लाइटें (हैज़र्ड फ्लैशर्स) चालू करते हैं और इंजन वाले हिस्से से धुएं की गंध आने लगती है, इसलिए आप अपना भरा हुआ अग्निशामक यंत्र पकड़ लेते हैं। चेतावनी उपकरण लगाने के लिए पीछे चलना शुरू करने से पहले, चेतावनी व्यवस्था पूरी करने के लिए इस ट्रक में कानूनन आपके पास और कौन-सा आपातकालीन उपकरण होना चाहिए?","options":["एक अतिरिक्त CB रेडियो ताकि आप मदद बुला सकें और दूसरे ट्रक चालकों को खतरे की चेतावनी दे सकें","परावर्तक (रिफ्लेक्टिव) चेतावनी त्रिकोण, जिन्हें सड़क पर रखकर आ रहे यातायात को सचेत किया जा सके","एक उच्च-दृश्यता वाली सुरक्षा जैकेट, जो नियमों के अनुसार रखने के लिए आवश्यक एकमात्र उपकरण है","केवल सड़क फ्लेयर (आग वाली मशालें) का एक थैला, क्योंकि फ्लैशर्स चालू होने के बाद त्रिकोण वैकल्पिक हो जाते हैं"],"explanation":"हर वाणिज्यिक वाहन में तीन परावर्तक चेतावनी त्रिकोण होने चाहिए, जिन्हें रुकने पर सड़क पर रखकर आते हुए यातायात को सतर्क किया जा सके।"},"415":{"q":"आप अपनी पाली पर पहुँचते हैं और एक ऐसे ट्रैक्टर में चढ़ते हैं जिसे दूसरे चालक ने दो घंटे पहले छोड़ा था। यार्ड से निकलने से पहले आप पुष्टि करना चाहते हैं कि ब्रेक, लाइटें और टायर सड़क पर चलने योग्य हैं। इस वाहन पर पहले से पाई गई किसी भी खराबी की सबसे विश्वसनीय शुरुआती तस्वीर आपको कौन सी एकल क्रिया देगी?","options":["वाहन को चलने योग्य मान लेना क्योंकि पिछले चालक ने स्पष्ट रूप से बिना खराबी के अपना सफर पूरा किया","सीधे एक रोड टेस्ट पर जाना, क्योंकि ट्रक को कुछ मील चलाना किसी असली समस्या को महसूस करने का सबसे तेज़ तरीका है","पिछले चालक की अंतिम वाहन निरीक्षण रिपोर्ट (DVIR) पढ़ना और सत्यापित करना कि दर्ज की गई किसी भी खराबी की मरम्मत प्रमाणित कर दी गई थी","डिस्पैच को फ़ोन करके पूछना कि क्या पिछले सप्ताह किसी अन्य चालक ने इस यूनिट की शिकायत की है"],"explanation":"गाड़ी चलाने से पहले पिछले चालक की अंतिम वाहन निरीक्षण रिपोर्ट (DVIR) पढ़ें और सुनिश्चित करें कि बताई गई खराबियाँ मरम्मत के रूप में प्रमाणित हैं।"},"417":{"q":"जल्दी शुरुआत करने के बाद आप एक लंबी, नीरस अंतरराज्यीय यात्रा के तीन घंटे पूरे कर चुके हैं। आपकी गति आपके ध्यान दिए बिना ही धीमी हो गई है, आपको पिछले कुछ मील ठीक से याद नहीं हैं, और आप खुद को आँखें मलते हुए पाते हैं। सुरक्षित ड्राइविंग दिशानिर्देशों के अनुसार, इनमें से कौन-सा सबसे स्पष्ट संकेत है कि आप सुरक्षित रूप से गाड़ी चलाते रहने के लिए बहुत अधिक नींद में आ रहे हैं?","options":["स्टीयरिंग व्हील पर आपके हाथ बेचैन महसूस होते हैं और आपका बार-बार अपने शीशे जाँचने का मन करता है","आप तेज़ी से सतर्क महसूस करते हैं और आपका ध्यान आगे की सड़क पर पूरी तरह केंद्रित है","ब्रेक पेडल पर आपकी प्रतिक्रिया का समय सामान्य से अधिक तेज़ और स्पष्ट महसूस होता है","आपकी पलकें भारी महसूस होती हैं और आपके विचार बार-बार सड़क से भटक जाते हैं"],"explanation":"भारी, झुकती पलकें और भटकते विचार चालक की खतरनाक थकान के विशिष्ट चेतावनी संकेत हैं।"},"418":{"q":"रात के 2 बजे हैं और आप एक लंबी यात्रा के तीन घंटे पूरे कर चुके हैं, तभी आपकी पलकें भारी होने लगती हैं, आप खुद को सड़क के किनारे की ओर बहता हुआ पाते हैं, और पिछले कुछ मील आपको याद नहीं रहते। टर्मिनल अभी भी 100 मील से अधिक दूर है। कौन-सा कदम वास्तव में आपकी सुरक्षित ड्राइविंग की क्षमता को वापस लाएगा?","options":["किसी सुरक्षित विश्राम स्थल पर रुककर आगे बढ़ने से पहले सोना या आराम करना","खिड़कियाँ खोलकर और रेडियो तेज़ करके सतर्क रहने की कोशिश करना","एक बड़ी कॉफ़ी के लिए रुकना और टर्मिनल पहुँचने के लिए चलते रहना","अपनी अनुसरण दूरी बढ़ाना और अधिक सावधानी से गाड़ी चलाते रहना"],"explanation":"उनींदेपन का एकमात्र असली इलाज नींद है, इसलिए सुरक्षित विश्राम स्थल पर रुकें और आगे बढ़ने से पहले आराम करें।"},"419":{"q":"सुबह के 4:30 बजे हैं और पिछली रात ठीक से न सो पाने के बाद आप 9 घंटे की यात्रा शुरू करने वाले हैं। आपको नींद आ रही है। इस लंबी यात्रा में थकान के कारण आप थके हुए होकर गाड़ी न चलाएं, यह सुनिश्चित करने के लिए निम्नलिखित में से कौन सा तरीका सबसे कम प्रभावी है?","options":["अपनी यात्राओं को इस तरह नियोजित करें कि अधिकांश ड्राइविंग उन घंटों में हो जब आप सामान्यतः जागते रहते हैं","सोने के बजाय जागते रहने के लिए एक बड़ा कॉफी पिएं और केबिन को ठंडा तथा रेडियो को तेज़ आवाज़ में रखें","यात्रा से पहले पूरी रात की नींद लें और जब नींद महसूस हो तो रुककर आराम करने की योजना बनाएं","नींद लाने वाली दवाओं से बचें और भारी पलकें या भटकते विचार जैसे चेतावनी संकेतों को पहचानें"],"explanation":"कॉफी, ठंडी हवा और तेज शोर उनींदेपन को केवल अस्थायी रूप से छिपाते हैं और थकान के एकमात्र असली इलाज नींद की जगह कभी नहीं ले सकते।"},"421":{"q":"दोपहर का तापमान 38 डिग्री (100 फ़ारेनहाइट) है और आप पश्चिमी टेक्सास से होकर एक लंबी यात्रा के लगभग तीन घंटे पूरे कर चुके हैं। आप अपने माल और टायरों की अनिवार्य रास्ते-में जाँच करने के लिए किनारे रुकते हैं। दो टायर अब आपकी ठंडी सुबह की प्री-ट्रिप जाँच की तुलना में काफ़ी अधिक दबाव दिखा रहे हैं। इसका सबसे संभावित कारण क्या है और यह आपके सामने आए जोखिम के बारे में क्या बताता है?","options":["गर्म सड़क ने टायरों के अंदर की हवा को ठंडा कर दिया है, जिससे दबाव घट गया और पंक्चर का जोखिम बढ़ गया","गर्म सड़क से रिसता हुआ तारकोल टायरों में सोख लिया गया है, जिससे उनमें वज़न और दबाव बढ़ गया","गर्मी ने टायरों के अंदर हवा का दबाव बढ़ा दिया है, जिससे टायर फटने (ब्लो-आउट) का जोखिम बढ़ जाता है","कोई गड़बड़ी नहीं है; गर्मी में टायर का दबाव स्वाभाविक रूप से घटता है, इसलिए अधिक रीडिंग का मतलब है कि आपका गेज खराब है"],"explanation":"गर्म मौसम में टायर के अंदर की हवा फैलती है और दबाव बढ़ता है, जिससे टायर फटने का खतरा बढ़ जाता है।"},"422":{"q":"टेक्सास में एक बहुत गर्म गर्मी के दिन की दोपहर है, और जब आप एक लदे हुए संयोजन वाहन (combination vehicle) को चला रहे हैं, तो आप आगे डामर (asphalt) की सतह पर चमकीले, गहरे रंग के तारकोल (tar) के धब्बे 'रिसते' हुए ऊपर आते देखते हैं। आपको इस रिसते हुए तारकोल से सड़क पर क्या असर होने की उम्मीद करनी चाहिए, और यह आपके वाहन के नियंत्रण के लिए क्यों मायने रखता है?","options":["तारकोल चिपचिपा होने के कारण टायरों को अतिरिक्त पकड़ देगा, इसलिए आप इन धब्बों के ऊपर से सुरक्षित रूप से अपनी हाईवे गति बनाए रख सकते हैं।","मुख्य खतरा यह है कि गर्मी आपके टायर के दबाव को सीमा से ऊपर बढ़ा देगी, इसलिए तारकोल का खुद टायरों के नीचे सड़क के एहसास पर कोई असर नहीं होता।","जब तक आपके स्टीयरिंग-एक्सल (आगे के) टायरों में कम से कम 4/32 इंच ट्रेड बचा है, तब तक इसका पकड़ (traction) पर कोई वास्तविक असर नहीं होता।","यह सड़क की सतह को फिसलन भरा बना देगा और आपके टायरों की पकड़ कम कर देगा, इसलिए आपको गति धीमी करनी चाहिए और इन धब्बों पर तेज़ स्टीयरिंग या ब्रेक लगाने से बचना चाहिए।"],"explanation":"सतह पर आया तारकोल सड़क को फिसलन भरा बना देता है और पकड़ कम कर देता है, इसलिए गति धीमी करें और उन हिस्सों पर तेज़ स्टीयरिंग या ब्रेकिंग से बचें।"},"423":{"q":"टेक्सास में जुलाई का मध्य है और आप पूरी तरह लदे हुए एक लंबी चढ़ाई चढ़ रहे हैं। केबिन गर्म है, इंजन ज़ोर से काम कर रहा है, और आप चाहते हैं कि फंसने या नुकसान होने से पहले आपको यह चेतावनी मिल जाए कि इंजन ज़्यादा गरम होने वाला है। कौन सा गेज आपको यह चेतावनी देता है?","options":["शीतलक तापमान गेज (कूलेंट टेम्परेचर)","तेल दबाव गेज (ऑयल प्रेशर)","ईंधन गेज (फ्यूल)","टैकोमीटर (इंजन आरपीएम)"],"explanation":"शीतलक तापमान गेज इंजन के ज़्यादा गरम होने का मुख्य और सीधा संकेतक है, जो कार्रवाई करने के लिए सबसे पहले चेतावनी देता है।"},"424":{"q":"आप भोर के तुरंत बाद दो-लेन वाले राजमार्ग पर एक भरा हुआ संयोजन वाहन चला रहे हैं, तभी आप इतने घने कोहरे के हिस्से में पहुँच जाते हैं कि आगे की लेन रेखाएँ मुश्किल से दिखती हैं। आप तय करते हैं कि अगले निकास तक धीरे-धीरे चलते रहना होगा। अपनी दृश्यता को और खराब किए बिना सड़क को यथासंभव अच्छी तरह देखने के लिए, कौन-सी हेडलाइट सेटिंग सबसे अच्छा विकल्प है?","options":["हाई बीम चालू करें, क्योंकि ये लगभग 350 से 500 फीट तक रोशनी फेंकती हैं और कोहरे में दूर तक देखने देती हैं","लो बीम का उपयोग करें, क्योंकि हाई बीम कोहरे से परावर्तित होकर आपकी आँखों में वापस आती है और दिखाई देना कम कर देती है","सभी आगे की लाइटें बंद कर दें और केवल चार-तरफा खतरा फ्लैशर पर निर्भर रहें ताकि सामने से आने वाले चालक आपको देख सकें","अभी हाई बीम चलाएँ और तभी मंद करें जब सामने से आता वाहन 500 फीट के भीतर आ जाए"],"explanation":"कोहरे में लो बीम का उपयोग करें, क्योंकि हाई बीम कोहरे से परावर्तित होकर चमक आपकी आँखों में लौटा देती है, जिससे दृश्यता कम हो जाती है।"},"425":{"q":"आप रात में दो-लेन वाले राजमार्ग पर एक भरा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं, तभी आप इतने घने कोहरे की पट्टी में घुस जाते हैं कि आपको अब लेन की रेखाएँ या आगे चल रहे वाहन की पिछली बत्तियाँ दिखाई नहीं देतीं। निम्नलिखित में से कौन-सा कदम सबसे सुरक्षित है?","options":["हाई बीम चालू कर लें ताकि तेज़ रोशनी कोहरे के पार आपको दूर तक देखने में मदद करे","कम गति पर लो बीम के साथ चलते रहें, क्योंकि कहीं भी रुकना आगे बढ़ते रहने से ज़्यादा खतरनाक है","सड़क से पूरी तरह बाहर निकल जाएँ, यात्रा-लेन से अच्छी तरह दूर, अपनी आपातकालीन फ्लैशर लाइटें चालू करें और कोहरा छँटने तक प्रतीक्षा करें","गति को लगभग शून्य तक धीमा करके अपनी ही लेन में चारों फ्लैशर जलाकर रुक जाएँ जब तक दृश्यता बेहतर न हो जाए"],"explanation":"जब कोहरा देखने के लिए बहुत घना हो, तो पूरी तरह सड़क से हटकर यातायात लेन से दूर रुकें, अपनी फ्लैशर लाइट चालू करें और कोहरा छँटने तक प्रतीक्षा करें।"},"426":{"q":"हवादार दिन में, हाईवे के खुले हिस्से पर लगातार बहती बगल की हवा (क्रॉसविंड) के झोंकों के बीच आपको रवाना किया जाता है। चार संयुक्त (कॉम्बिनेशन) वाहन आपके साथ ही यार्ड से निकल रहे हैं। हवा किसी वाहन को कैसे प्रभावित करती है, इसके आधार पर किस चालक को बगल की हवा से लेन से बाहर धकेले जाने या यहाँ तक कि पलट जाने की सबसे अधिक चिंता करनी चाहिए?","options":["पूरी तरह भरे टैंकर का चालक, क्योंकि हिलता-डुलता तरल हवा को सबसे बड़ा खतरा बना देता है","नीचे रखे, भारी और समान रूप से वितरित स्टील भार वाले फ्लैटबेड का चालक","कानूनी वजन सीमा पर चल रहे भरे हुए वैन ट्रेलर का चालक, क्योंकि भारी वाहन अधिक हवा पकड़ते हैं","ऊँचे बॉक्स ट्रेलर का चालक जो खाली या हल्का भरा है, क्योंकि वह हवा का विरोध करने के लिए कम वजन के साथ एक बड़ी सतह प्रस्तुत करता है"],"explanation":"खाली या हल्के भरे ऊँचे बॉक्स ट्रेलर को क्रॉसविंड में सबसे ज़्यादा खतरा होता है क्योंकि इसकी सतह बड़ी होती है पर हवा का प्रतिरोध करने के लिए वज़न कम होता है।"},"427":{"q":"आप टेक्सास के एक ग्रामीण दो-लेन राजमार्ग पर एक लदे हुए संयोजन वाहन (combination vehicle) को चला रहे हैं और अपनी यात्रा की योजना इस तरह बनाना चाहते हैं कि उन परिस्थितियों में सबसे कम समय बिताएँ जब हिरण और अन्य बड़े जानवर सड़क पर अचानक आने की सबसे अधिक संभावना रखते हैं। जानवरों के पार करने के लिए दिन के किस भाग में सबसे अधिक सतर्कता की आवश्यकता होती है?","options":["भोर और गोधूलि (शाम) के आसपास के कम-रोशनी वाले समय","दोपहर के आसपास दिन का मध्य भाग, जब जानवर भोजन की तलाश करते हैं","देर सुबह, सूरज के पूरी तरह उग आने के बाद","दोपहर बाद, दिन के सबसे गर्म हिस्से के दौरान"],"explanation":"हिरण और बड़े जानवर भोर और सांझ के समय सबसे अधिक सक्रिय होते हैं, ये कम रोशनी के समय होते हैं जब चालक की दृष्टि भी सबसे अधिक बाधित होती है।"},"429":{"q":"आप मध्यम यातायात वाले एक व्यस्त चार-लेन राजमार्ग पर एक भरा हुआ संयोजन वाहन चला रहे हैं। दाहिने किनारे पर लगा एक चमकीला और चलायमान डिजिटल बिलबोर्ड आपकी नज़र को कई सेकंड के लिए अपनी ओर खींच लेता है जब आप उसके पास से गुज़रते हैं। इस स्थिर टकटकी का कौन-सा परिणाम वह सबसे गंभीर सुरक्षा चिंता है जिसे एक CDL चालक को पहचानना चाहिए?","options":["आपकी आँखें चमक के अनुकूल हो जाएँगी और आप क्षण भर के लिए अपनी रात्रि दृष्टि खो देंगे","आप चारों ओर देखना बंद कर देते हैं और अपने दृष्टि-क्षेत्र के अन्य हिस्सों में उभरते खतरों को देख नहीं पाते","आप अनजाने में अपनी गति यातायात के प्रवाह से काफी नीचे कर देंगे और पीछे के वाहनों को बाधित करेंगे","आप साइन पर इतना तीखा ध्यान केंद्रित कर लेंगे कि आगे की सड़क वास्तव में अधिक स्पष्ट दिखाई देगी"],"explanation":"किसी एक वस्तु पर नज़र टिकाए रखने से आँखों का स्कैन करना रुक जाता है, जिससे दृष्टि क्षेत्र के अन्य हिस्सों में उभरते खतरे देर होने तक अनदेखे रह जाते हैं।"},"430":{"q":"आप दो-लेन वाले ग्रामीण राजमार्ग पर एक भरा हुआ संयोजन वाहन चला रहे हैं और एक धीमे ट्रैक्टर के पीछे पहुँच जाते हैं जो आपको गति सीमा से 15 मील प्रति घंटा कम पर रोके हुए है। आप ओवरटेक करना चाहते हैं, पर सड़क लगातार बदलती रहती है। निम्नलिखित में से किस स्थान पर ओवरटेक करने का प्रयास सबसे कम सुरक्षित होगा और सबसे अधिक संभावना है कि आप आमने-सामने की टक्कर में फँस जाएँ?","options":["एक लंबे, समतल सीधे रास्ते पर जहाँ आप कम से कम एक-चौथाई मील तक खाली सामने वाली लेन साफ़ देख सकते हैं","एक हल्की ढलान पर जहाँ आपकी गति स्वाभाविक रूप से बढ़ती है और आप ओवरटेक जल्दी पूरा कर सकते हैं","पहाड़ी की चोटी या मोड़ के निकट पहुँचते समय, जहाँ आगे की सड़क मुड़ जाती है या ऊपर उठकर नज़र से ओझल हो जाती है","एक सीधे हिस्से पर जहाँ बीच की रेखा टूटी हुई है और सामने कोई आता हुआ वाहन दिखाई नहीं देता"],"explanation":"पहाड़ी की चोटी या मोड़ के पास कभी ओवरटेक न करें, जहाँ सड़क नज़रों से ओझल होकर ऊपर उठती या मुड़ती है और सामने से आता यातायात छिपा हो सकता है।"},"431":{"q":"आप अपने लदे हुए ट्रैक्टर-ट्रेलर को दो-लेन वाले राजमार्ग पर चला रहे हैं और एक धीमी कार को ओवरटेक करना शुरू करते हैं। जैसे ही आप उसके बगल में आते हैं, आपको एहसास होता है कि आप कई सेकंड से कार के पिछले दरवाज़े के ठीक बराबर चल रहे हैं, सीधे चालक के अंधे क्षेत्र (ब्लाइंड स्पॉट) में। इस पैंतरे को DPS की आवश्यकता के अनुसार सुरक्षित ढंग से पूरा करने के लिए आपको क्या करना चाहिए?","options":["एक्सीलेटर से पैर हल्का करें और कार के बराबर बने रहें ताकि दूसरे चालक को आगे निकलने से पहले आपको देखने का पर्याप्त समय मिले","जब तक यह निश्चित न हो जाए कि सामने से कोई वाहन नहीं आ रहा, तब तक कार के बगल में समान गति से बने रहें, फिर अपनी लेन में लौट आएं","अपनी मौजूदा गति बनाए रखें और कार के बगल में रहते हुए ही धीरे-धीरे अपनी लेन की ओर खिसकें ताकि कुल ओवरटेक छोटा हो जाए","ज़रूरत के अनुसार गति बढ़ाकर दूसरे चालक के अंधे क्षेत्र से निकलें और ओवरटेक को बिना देरी के पूरा करें, फिर वाहन के बगल में रुके बिना अपनी लेन में लौट आएं"],"explanation":"ओवरटेक तुरंत पूरा करें और दूसरे चालक के ब्लाइंड स्पॉट से बाहर निकलें, फिर उसके बगल में रुके बिना अपनी लेन में लौट आएँ।"},"432":{"q":"आप एक ऐसे चौराहे के पास पहुँच रहे हैं जहाँ चिह्नित पैदल यात्री क्रॉसिंग है। आपके लिए हरी बत्ती है और आप दाएँ मुड़ना चाहते हैं, लेकिन एक पैदल यात्री पहले ही फुटपाथ से उतरकर उस क्रॉसिंग पर आ गया है जिसे आप पार करने वाले हैं। आपको क्या करना चाहिए?","options":["रास्ता दें और पैदल यात्री को पार करने दें, क्योंकि चिह्नित क्रॉसिंग पर पैदल यात्रियों को रास्ते का अधिकार होता है","अपना मोड़ पूरा करें क्योंकि हरी बत्ती आपको पैदल यात्री से अधिक रास्ते का अधिकार देती है","पैदल यात्री को सचेत करने के लिए हॉर्न बजाएँ और यदि वह न रुके तो मुड़ना जारी रखें","केवल तभी रुकें जब पैदल यात्री सीधे आपकी लेन में हो, अन्यथा चलते रहें"],"explanation":"चिह्नित क्रॉसवॉक में वैध रूप से चल रहे पैदल यात्रियों को हमेशा रास्ते का अधिकार होता है, इसलिए मुड़ने वाले चालक को हरी बत्ती होने पर भी रास्ता देना चाहिए।"},"433":{"q":"आप अपने ट्रैक्टर-ट्रेलर को दो-लेन वाली शहरी सड़क पर चला रहे हैं और एक साइकिल चालक आपके आगे आपकी लेन के दाहिने हिस्से में चल रहा है। यातायात मध्यम है और आप खड़ी कारों वाले क्षेत्र के पास पहुँच रहे हैं जहाँ साइकिल चालक को बाईं ओर हटना पड़ सकता है। कौन-सी कार्रवाई सबसे अच्छी तरह दर्शाती है कि आपको इस साइकिल चालक के साथ कैसा व्यवहार करना चाहिए?","options":["ठीक पीछे सटे रहें और लंबा हॉर्न बजाएँ ताकि साइकिल चालक समझ जाए कि उसे किनारे (शोल्डर) पर हट जाना है","साइकिल चालक के साथ वैसा ही व्यवहार करें जैसा आप किसी अन्य वाहन के साथ करते हैं, उसे पूरी जगह दें और आगे निकलने से पहले सुरक्षित दूरी छोड़ें","उसी लेन में दबाव डालकर निकल जाएँ, क्योंकि साइकिल कार की तुलना में बहुत कम जगह घेरती है","सबसे बाईं लेन में चले जाएँ और बाकी पूरे ब्लॉक तक वहीं बने रहें"],"explanation":"साइकिल चालक को सड़क पर किसी भी वाहन के समान अधिकार होता है, इसलिए उसे दबाने के बजाय पूरा स्थान और सुरक्षित दूरी देकर आगे निकलें।"},"434":{"q":"आप अपने लदे हुए संयोजन वाहन में एक बहु-लेन गोलचक्कर (राउंडअबाउट) के पास पहुंच रहे हैं। यातायात पहले से ही गोलचक्कर के अंदर घूम रहा है, और आपकी बाईं ओर एक अंतराल खुल रहा है लेकिन एक वाहन अभी भी उस अंतराल की ओर आ रहा है। प्रवेश करने का सही तरीका कौन सा है?","options":["जोर से गति बढ़ाएं और आने वाला वाहन आपके प्रवेश बिंदु तक पहुंचने से पहले विलय करें, क्योंकि बड़े वाहन को रास्ते का अधिकार होता है","गोलचक्कर में प्रवेश करें और अंदर पहुंचते ही पूरी तरह रुक जाएं, फिर वहीं रुककर तब तक प्रतीक्षा करें जब तक आपके चारों ओर का सारा यातायात साफ न हो जाए","गोलचक्कर में पहले से घूम रहे यातायात को रास्ता दें, और केवल तभी प्रवेश करें जब आपके वाहन की पूरी लंबाई के लिए पर्याप्त बड़ा अंतराल हो","तुरंत प्रवेश करें और यदि आवश्यक हो, तो सबसे छोटे रास्ते से अपने निकास तक पहुंचने के लिए प्रवाह के विपरीत दिशा में चलें"],"explanation":"गोल चक्कर में पहले से चल रहे यातायात को रास्ते का अधिकार होता है, इसलिए तभी प्रवेश करें जब आपके पूरे वाहन की लंबाई के लिए पर्याप्त जगह हो।"},"435":{"q":"पिछले बीस मिनट से लगातार बारिश हो रही है और सड़क पूरी तरह गीली है। आप सूखी सड़क की अपनी सामान्य हाईवे गति से चल रहे हैं और आगे वाली गाड़ी के पीछे अपना सामान्य 6-सेकंड का अनुसरण अंतराल बनाए हुए हैं। इसी हिस्से को सूखी सड़क पर चलाने की तुलना में, अभी आप जिस तरह से वाहन चला रहे हैं उसमें आपको किस बात का ध्यान रखना सबसे जरूरी है?","options":["रुकने के लिए कुछ नहीं बदलता; ट्रक के ब्रेक उतना ही बल लगाते हैं, इसलिए आपका सामान्य सूखी सड़क वाला अनुसरण अंतराल अब भी पर्याप्त है","आपकी प्रतिक्रिया दूरी बढ़ जाती है क्योंकि गीली सड़क आपकी धारणा को धीमा कर देती है, लेकिन एक बार ब्रेक पकड़ने के बाद वास्तविक ब्रेकिंग दूरी वही रहती है","रुकने की दूरी बहुत कम हो जाती है क्योंकि पानी की परत टायरों को अधिक स्वतंत्र रूप से लुढ़कने देती है और ट्रक का घर्षण घटा देती है","आपकी कुल रुकने की दूरी बढ़ जाती है क्योंकि कम पकड़ ब्रेकिंग दूरी को लंबा कर देती है, इसलिए आपको गति कम करनी चाहिए और अपनी अनुसरण दूरी बढ़ानी चाहिए"],"explanation":"गीली सड़क पकड़ कम कर देती है और ब्रेकिंग दूरी बढ़ा देती है, जिससे कुल रुकने की दूरी बढ़ती है, इसलिए गति घटाएँ और अपनी अनुसरण दूरी बढ़ाएँ।"},"437":{"q":"आपको रवाना हुए 90 मिनट हो चुके हैं, तभी डिस्पैचर रेडियो पर बताता है कि आपका डिलीवरी पता बदल गया है और आपको अपने GPS में नया रूट चाहिए। ट्रैफ़िक हल्का है और आप हाईवे की गति पर चल रहे हैं। नए गंतव्य को संभालने का सबसे सुरक्षित तरीका कौन-सा है?","options":["तब तक प्रतीक्षा करें जब तक आप सड़क से हटकर किसी सुरक्षित जगह पार्क न कर सकें, फिर दोबारा चलने से पहले नया रूट दर्ज करके सेट करें","अगली लाल बत्ती पर रुके रहने के दौरान नया पता दर्ज करें, और रूट लोड होते ही चल पड़ें","यूनिट को स्टीयरिंग के पास नीचे लगाएँ और वहीं पता टाइप करें ताकि आपकी नज़र सड़क के करीब बनी रहे","गाड़ी चलाते रहें और नया गंतव्य टाइप करते हुए नज़र GPS और सड़क के बीच आगे-पीछे घुमाते रहें"],"explanation":"GPS हमेशा गाड़ी चलाने से पहले सेट करें, चलते समय कभी नहीं, इसलिए सड़क से हटकर सुरक्षित जगह रुकें, नया रास्ता दर्ज करें, फिर चलना शुरू करें।"},"439":{"q":"आपका ट्रैक्टर-ट्रेलर अभी-अभी एक टक्कर में शामिल हुआ है और रुक गया है, जिससे दो-लेन वाले बिना विभाजन वाले ग्रामीण राजमार्ग का एक हिस्सा अवरुद्ध हो गया है। अन्य चालक दोनों दिशाओं से आ रहे हैं। अपनी खतरे की चेतावनी (हैज़र्ड फ्लैशर) लाइटें चालू करने के बाद, आने वाले यातायात को चेतावनी देने का सबसे अच्छा तरीका क्या है?","options":["केवल हैज़र्ड फ्लैशर लाइटें ही जलाए रखना, क्योंकि दुर्घटना में कानून केवल फ्लैशर की ही मांग करता है","10 मिनट के भीतर अपने परावर्तक चेतावनी त्रिकोण लगाएं -- एक वाहन के लगभग 30 मीटर (100 फीट) पीछे, एक लगभग 30 मीटर (100 फीट) आगे, और एक वाहन के लगभग 3 मीटर (10 फीट) पीछे की ओर","यातायात लेन में खड़े होकर अपनी बाहें हिलाना ताकि चालक आपको साफ देखें और गति धीमी करें","जब तक सभी आने वाले वाहन रुक न जाएं, तब तक लगातार हॉर्न बजाते रहना"],"explanation":"बिना विभाजित सड़क पर रुकने के 10 मिनट के भीतर चेतावनी त्रिकोण लगाएँ: वाहन के लगभग 30 मीटर पीछे, 30 मीटर आगे और 3 मीटर पीछे।"},"441":{"q":"आप एक ग्रामीण दो-लेन राजमार्ग पर 60 मील प्रति घंटे की रफ्तार से एक लदा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं, तभी आप अपने शीशों में देखते हैं कि एक पिकअप कई मील से आपके बहुत करीब पीछे-पीछे चल रहा है। आगे यातायात हल्का और स्थिर है। इस बहुत करीब चलने वाले वाहन से पैदा हुए खतरे को कम करने का सबसे अच्छा तरीका कौन सा है?","options":["पिकअप को पीछे हटने का संकेत देने और इतने करीब चलने से रोकने के लिए कई बार हल्के से ब्रेक दबाना","अपनी गति बनाए रखना लेकिन अपनी लेन के बाएं किनारे की ओर खिसकना ताकि पिकअप आगे काफी दूर तक देख सके और आपको सुरक्षित रूप से ओवरटेक कर सके","आगे वाले वाहन से अपनी अनुसरण दूरी धीरे-धीरे बढ़ाना ताकि जोर से ब्रेक लगाने के बजाय धीरे-धीरे गति कम करने के लिए आपके पास अतिरिक्त जगह हो","गति बढ़ाकर अपने और पिकअप के बीच फासला बनाना जब तक कि वह खतरा बनने लायक करीब न रह जाए"],"explanation":"जब कोई बहुत पास से पीछा कर रहा हो, तो आगे अधिक जगह रखें ताकि आप जोर से ब्रेक लगाने के बजाय धीरे-धीरे गति घटा सकें और पीछे वाले चालक को प्रतिक्रिया का अधिक समय मिले।"},"442":{"q":"आप एक सूखे दो-लेन वाले राजमार्ग पर 55 मील प्रति घंटे की गति से एक भरा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं, तभी एक कार आपके बहुत करीब आकर पीछे चिपककर चलने लगती है। चालक अधीर है और स्पष्ट रूप से चाहता है कि आप रास्ते से हट जाएँ। आप स्थिति को बिगाड़े बिना इस पीछे चिपकने वाले चालक से उत्पन्न खतरे को कम करना चाहते हैं। निम्नलिखित में से कौन-सा आपका सबसे खराब (WORST) कदम होगा?","options":["एक स्थिर, समान गति बनाए रखें ताकि पीछे वाली कार एक सुरक्षित अंतराल का अनुमान लगा सके और अंततः आगे निकल सके","धीरे-धीरे एक्सेलेरेटर से पैर हटाएँ ताकि अपने आगे एक सुरक्षा-गुंजाइश के रूप में अधिक जगह खुल सके","दाईं ओर रहें और अचानक हरकतों से बचें ताकि पीछे चिपकने वाले को आपको पार करने की जगह मिल सके","पीछे वाले से दूर खिंच जाने और आप दोनों के बीच अधिक दूरी बनाने के लिए अपनी गति बढ़ा दें"],"explanation":"पीछा करने वाले से बचने के लिए गति बढ़ाना गलत है, क्योंकि वह फिर भी पास से पीछा करता रहेगा जबकि दोनों वाहनों की गति और रुकने की दूरी बढ़ जाएगी।"},"443":{"q":"साफ़ सुबह है, तापमान हिमांक से थोड़ा ही नीचे है और आप एक ग्रामीण राजमार्ग पर माल ढो रहे हैं। आगे की सड़क बस गीली दिखती है, लेकिन आप एक नदी पर बने लंबे ओवरपास के पास पहुँच रहे हैं। ओवरपास को कैसे पार करें, इस पर कौन-सा कथन सबसे अधिक प्रभाव डालना चाहिए?","options":["ओवरपास की सतह आसपास की सड़क से पहले जम सकती है और बर्फीली हो सकती है, क्योंकि वह ऊपर और नीचे दोनों ओर से गर्मी खो देती है।","ओवरपास सबसे आखिर में जमेगा, इसलिए ज़रूरत पड़ने पर ज़ोर से ब्रेक लगाने के लिए यह सबसे सुरक्षित जगह है।","पुल और ओवरपास की सतहें केवल गर्मियों में फिसलन भरी होती हैं, जब पक्की सड़क से तारकोल ऊपर रिसता है।","जब तक पहुँच-मार्ग सफ़ेद के बजाय गीला दिखता है, तब तक ऊँचे डेक कभी नहीं जमते।"],"explanation":"पुल और ओवरपास सड़क से पहले जम जाते हैं क्योंकि वे ऊपर और नीचे दोनों ओर से गर्मी खो देते हैं, इसलिए सड़क केवल गीली होने पर भी वे बर्फीले हो सकते हैं।"},"444":{"q":"एक ठंडी, नम शरद ऋतु की सुबह है और आप दो-लेन वाली ग्रामीण सड़क पर एक लदा हुआ संयोजन वाहन (कॉम्बिनेशन वाहन) चला रहे हैं। एक मोड़ से बाहर निकलते समय, आप देखते हैं कि आगे की सड़क गीली, गिरी हुई पत्तियों की एक मोटी परत से ढकी है जो दोनों लेनों तक फैली हुई है। कौन-सा कथन सबसे अच्छी तरह बताता है कि आपको सड़क के इस हिस्से पर कैसे चलना चाहिए?","options":["पत्तियाँ गीली रेत की तरह पकड़ बढ़ाती हैं, इसलिए आप इस हिस्से से गुजरते समय अपनी वर्तमान गति सुरक्षित रूप से बनाए रख सकते हैं।","पत्तियों से ढकी सड़क को फिसलन भरी सतह मानें, धीरे-धीरे एक्सेलरेटर से पैर हटाएँ और इस हिस्से को पार करने तक तेज़ ब्रेक लगाने या तेज़ी से मोड़ने से बचें।","चूँकि पत्तियाँ जैविक और मुलायम होती हैं, वे टायरों को गद्दी देती हैं और पकड़ या रुकने की दूरी पर कोई वास्तविक असर नहीं डालतीं।","पत्तियों पर केवल आगे के (स्टीयरिंग-एक्सल) टायर पकड़ खोते हैं, इसलिए ड्राइव पहियों से हल्का ब्रेक लगाने पर आप पूरी तरह नियंत्रण में रहते हैं।"],"explanation":"गीली पत्तियाँ बर्फ की तरह फिसलन भरी, कम पकड़ वाली परत बना देती हैं, इसलिए एक्सेलरेटर छोड़ें और उन्हें पार करने तक जोर से ब्रेक या स्टीयरिंग से बचें।"},"445":{"q":"तापमान हिमांक से ठीक नीचे है और धूप निकली हुई है, जब आप एक ग्रामीण दो-लेन वाली सड़क पर वाहन चला रहे हैं। खुले, धूप वाले सड़क के हिस्से सूखे दिखते हैं, लेकिन सड़क बार-बार पेड़ों की छाँव के नीचे से और उत्तर-मुखी ऊँचे तटबंधों के साथ-साथ गुज़रती है जो छाया में रहते हैं। ऐसे ही एक छायादार हिस्से के पास पहुँचते समय, छाया जिस चीज़ को छिपा रही है, उसमें आपको किस सबसे बड़े खतरे की अपेक्षा करनी चाहिए?","options":["रिसता हुआ तारकोल जो धूप में नरम होकर सतह को फिसलन भरा बना देता है","ढीली बजरी जिसे यातायात ने छायादार निचले हिस्सों में धकेल दिया है","बर्फ का एक टुकड़ा, क्योंकि धूप वाले हिस्से सूखे होने के बावजूद छायादार सड़क कभी हिमांक से ऊपर गर्म नहीं हुई","ताज़ा सड़क-चिह्न पेंट जो ठंड में अभी पूरी तरह सूखा नहीं है"],"explanation":"छायादार सड़क को सीधी धूप नहीं मिलती, इसलिए वहाँ नमी जमी रहती है, भले ही धूप वाले सूखे हिस्से हिमांक से ऊपर गर्म हो गए हों।"},"446":{"q":"आप लगातार बारिश में एक गीले इंटरस्टेट हाईवे पर अपना ट्रैक्टर-ट्रेलर चला रहे हैं। ट्रकों की एक कतार बाईं लेन से आपको ओवरटेक कर रही है, और हर एक गुजरते समय आपकी विंडशील्ड पर सड़क के पानी की भारी फुहार फेंकता है। यह सोचते हुए कि यह फुहार आप पर और आपकी सुरक्षित ड्राइविंग क्षमता पर कैसे असर डालती है, कौन सा कथन इसके मुख्य प्रभाव का सबसे अच्छा वर्णन करता है?","options":["यह आपके ब्रेक ड्रम को ठंडा करती है, इसलिए अगली लंबी ढलान पर आप उन पर अधिक भरोसा कर सकते हैं","यह आपके टायर की चूड़ी की गहराई बढ़ाती है, जिससे आप सामने के टायरों की 4/32 इंच न्यूनतम सीमा से ऊपर रहते हैं","यह सड़क से गंदगी धो देती है, जिससे आपके टायरों और सड़क के बीच पकड़ बेहतर होती है","यह आपकी दृश्यता घटाकर आपको पल भर के लिए अंधा कर देती है, इसलिए आपको धीमा होना चाहिए और अपनी अनुसरण दूरी बढ़ानी चाहिए"],"explanation":"गुज़रते ट्रकों से उड़ता पानी पल भर के लिए विंडशील्ड को ढक देता है और दृश्यता को बहुत कम कर देता है, इसलिए गति घटाएँ और पीछा करने की दूरी बढ़ाएँ।"},"447":{"q":"आप 53 फुट लंबे ट्रैक्टर-ट्रेलर को चला रहे हैं और आपको शहर की सड़क से एक संकरी गली में तीखा दायाँ मोड़ लेना है। आप मोड़ के भीतरी (दाएँ) हिस्से में एक खड़ी कार और एक कर्ब (किनारा) देखते हैं। ऑफ-ट्रैकिंग (मुड़ते समय पिछले पहियों का अलग रास्ता) के कारण, इस मोड़ से वाहन को निकालते समय आपको किसकी योजना बनानी चाहिए, इसे निम्नलिखित में से कौन सा सबसे अच्छी तरह बताता है?","options":["आपके ट्रेलर के पिछले पहिये आगे के पहियों के रास्ते के भीतर वाले रास्ते पर चलेंगे, इसलिए पिछले टायर मोड़ के भीतरी हिस्से में कर्ब पर चढ़ सकते हैं या खड़ी कार से टकरा सकते हैं","आपके ट्रेलर के पिछले पहिये आगे के पहियों के बाहर एक चौड़े रास्ते पर चलेंगे, इसलिए ट्रेलर का पिछला हिस्सा बाईं ओर सामने से आने वाले ट्रैफ़िक की ओर झूल जाएगा","आपके आगे और पीछे के पहिये बिल्कुल एक ही रास्ते पर चलेंगे, इसलिए यदि आपके स्टीयरिंग टायर कर्ब से बच जाते हैं तो ट्रेलर के पहिये भी बच जाएँगे","ऑफ-ट्रैकिंग केवल हाईवे की गति पर मायने रखती है, इसलिए इस कम मोड़ गति पर चारों पहिया-समूह लगभग एक ही रेखा पर चलते हैं"],"explanation":"ऑफ-ट्रैकिंग के कारण लंबे ट्रेलर के पिछले पहिये आगे के पहियों के अंदर की ओर चलते हैं, इसलिए इतना चौड़ा मुड़ें कि पिछले टायर अंदरूनी किनारे या वाहनों से न टकराएँ।"},"448":{"q":"आप 53 फुट लंबा ट्रैक्टर-ट्रेलर चला रहे हैं और एक संकरी दो-लेन वाली सड़क से दूसरी संकरी सड़क पर तीखा दायाँ मोड़ लेना है। आप जानते हैं कि ट्रेलर के पिछले पहिये ट्रैक्टर के अगले पहियों की तुलना में छोटे और तीखे रास्ते पर चलते हैं (ऑफ-ट्रैकिंग), इसलिए मोड़ को सावधानी से योजना बनानी होगी। ट्रेलर के पिछले पहियों को फुटपाथ (कर्ब) पर चढ़ाए बिना इस दाएँ मोड़ को सुरक्षित रूप से पूरा करने के लिए आपको किस बात का ध्यान रखना चाहिए?","options":["ऑफ-ट्रैकिंग के कारण ट्रेलर का पिछला हिस्सा बाहर की ओर झूलता है, इसलिए आपको केवल मोड़ के बाहरी (बाईं) ओर अतिरिक्त जगह की ज़रूरत है","ऑफ-ट्रैकिंग के कारण ट्रेलर के पिछले पहिये ट्रैक्टर के रास्ते के अंदर की ओर कट जाते हैं, इसलिए आपको मोड़ के अंदर की ओर अतिरिक्त जगह की ज़रूरत होती है","इतने तीखे मोड़ पर ऑफ-ट्रैकिंग का कोई असर नहीं होता, इसलिए किसी भी दिशा में अतिरिक्त जगह की ज़रूरत नहीं है","चूँकि वाहन लंबा है, इसलिए अंदर की ओर कम जगह चाहिए क्योंकि ट्रेलर ट्रैक्टर के पीछे सीधी रेखा में चलता है"],"explanation":"ऑफ-ट्रैकिंग के कारण ट्रेलर के पिछले पहिये ट्रैक्टर के रास्ते के अंदर की ओर कट जाते हैं, इसलिए मोड़ के अंदरूनी हिस्से में अतिरिक्त जगह रखें।"},"449":{"q":"आप अपने ट्रैक्टर-ट्रेलर में एक व्यस्त इंटरस्टेट पर मर्ज कर रहे हैं और एक छोटी कार आपके दाईं ओर के शीशे के ठीक पीछे नज़रों से ओझल हो जाती है, जहाँ अब आप उसे बिल्कुल नहीं देख सकते। लेन बदलने से पहले, आपको अपने ट्रक के चारों ओर इस विशेष क्षेत्र का सही वर्णन और उपचार कैसे करना चाहिए?","options":["यह कम पकड़ (low-traction) वाला क्षेत्र है, इसलिए लेन में मुड़ने से पहले मुझे धीरे से ब्रेक लगाना चाहिए।","यह एक सुरक्षा गद्दी (बफर) है जिसे मेरे ट्रेलर से दूर रखने की ज़िम्मेदारी दूसरे चालकों की है।","यह मेरे ब्लाइंड स्पॉट्स में से एक है, जिसे No-Zone भी कहते हैं, जहाँ दूसरे चालकों को देखना मेरे लिए कठिन होता है, इसलिए लेन बदलने से पहले मुझे इसे सावधानी से जाँचना चाहिए।","यह केवल तभी बनने वाला खतरे का क्षेत्र है जब ट्रेलर लदा हो और मेरा गुरुत्व केंद्र ऊँचा हो।"],"explanation":"ट्रक के आसपास के वे क्षेत्र जहाँ दूसरे चालकों को देखना मुश्किल होता है, ब्लाइंड स्पॉट यानी No-Zone कहलाते हैं, जिन्हें लेन बदलने से पहले ध्यान से जाँचना चाहिए।"},"450":{"q":"आप अपने ट्रैक्टर-ट्रेलर को एक व्यस्त फ्रीवे पर मर्ज कर रहे हैं। एक कार जो थोड़ी देर पहले आपको अपने दाहिने साइड मिरर में साफ़ दिख रही थी, अब उस मिरर से पूरी तरह गायब हो गई है, और वह आपको आगे भी नहीं दिख रही। लेन बदलना जारी रखने से पहले, इस गायब होने का सबसे संभावित अर्थ क्या है?","options":["कार तेज़ होकर अब आपसे बहुत पीछे दूर चली गई है, इसलिए लेन खाली है","कार ने ज़ोर से ब्रेक लगाकर दाहिने किनारे (शोल्डर) पर गाड़ी रोक ली है और पूरी तरह सड़क से बाहर है","आपका मिरर गलत सेट हो गया है और अगली बार रुकने पर उसे फिर से सही करना होगा","कार आपके ट्रेलर के बगल वाले ब्लाइंड स्पॉट ('No-Zone') में चली गई है, जहाँ आपका मिरर अब उसे नहीं दिखा सकता"],"explanation":"जो वाहन आपके शीशे से गायब हो जाता है वह संभवतः आपके ट्रेलर के बगल वाले ब्लाइंड स्पॉट (No-Zone) में चला गया है, इसलिए जब तक उसे दोबारा न देख लें तब तक लेन न बदलें।"},"451":{"q":"आप चार-लेन वाले राजमार्ग पर एक भरा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं और एक धीमे वाहन को पास करने के लिए दाएं लेन से बाएं लेन में जाने का निर्णय लेते हैं। आप अपने सपाट और उत्तल (स्पॉट) दोनों दर्पण जांचते हैं, देखते हैं कि वे साफ दिखते हैं, और जल्दी संकेत देते हैं। जैसे ही आप लेन बदलना शुरू करते हैं, आपके लिए सबसे बड़ा खतरा कहां स्थित वाहन है?","options":["आपके ट्रेलर के साथ वाले ब्लाइंड स्पॉट में, एक ऐसा क्षेत्र जो आपके दर्पण नहीं दिखाते","दो लेन दूर सबसे बाईं लेन में, आपके उत्तल दर्पण में आंशिक रूप से दिखाई देता है","सीधे आपके ट्रेलर के पीछे जहां आपकी ब्रेक लाइटें दिखाई देती हैं","आपके आगे आपकी अपनी लेन में, वह धीमा वाहन जिसे आप पास करना चाहते हैं"],"explanation":"बड़े ट्रकों के किनारों और पीछे ब्लाइंड स्पॉट (No-Zone) होते हैं जिन्हें शीशे नहीं दिखाते, इसलिए लेन बदलने से पहले सिर घुमाकर जाँच करना ज़रूरी है।"},"453":{"q":"आप एक पहाड़ी दर्रे से गुज़रने वाले 400 मील के सफर के लिए टर्मिनल से निकलने वाले हैं, और निकलने से पहले आप यात्रा की सही ढंग से योजना बनाना चाहते हैं। यात्रा की योजना बनाते समय जाँचने के लिए निम्नलिखित में से सबसे महत्वपूर्ण बात कौन-सी है?","options":["क्या आपकी पसंदीदा संगीत प्लेलिस्ट डाउनलोड है ताकि लंबे सफर में आप सतर्क रहें","आपका नियोजित मार्ग और रास्ते भर की मौजूदा मौसम स्थितियाँ","कि आपकी अनुसरण दूरी वाहन की लंबाई के हर 10 फीट के लिए 1 सेकंड होगी","क्या आपके मार्ग के ट्रक स्टॉप दोपहर के भोजन के लिए आपकी पसंद का खाना परोसते हैं"],"explanation":"अच्छी यात्रा योजना का अर्थ है अपने मार्ग और रास्ते के मौसम को पहले से जानना, ताकि आप अनियंत्रित परिस्थितियों के अनुसार गियर, गति और समय चुन सकें।"},"454":{"q":"तापमान हिमांक से ठीक नीचे है, शुरू हुई हल्की बारिश आपके मार्ग के पुलों पर बर्फ की परत जमा रही है, और निर्धारित गति सीमा 55 मील प्रति घंटा है। यातायात कम है और सड़क की सतह अभी भी सिर्फ़ गीली दिखती है। टेक्सास DPS नियमों के अनुसार, इनमें से किस स्थिति में आपको निर्धारित सीमा से कम गति पर चलाना अनिवार्य है?","options":["जब आगे की सड़क साफ़ और सूखी हो, क्योंकि खाली लेन आपको पूरी निर्धारित 55 मील प्रति घंटा सुरक्षित रूप से उपयोग करने देती है","जब आपके आसपास यातायात कम हो, क्योंकि कम वाहनों का मतलब है गति घटाने का कम कारण","जब परिस्थितियाँ खराब हों — जैसे अभी आपके सामने मौजूद गीली, लगभग जमी हुई सतह और संभावित रूप से बर्फीले पुल — क्योंकि सुरक्षित गति को कर्षण (ट्रैक्शन) और दृश्यता तय करती है, बोर्ड पर लिखा अंक नहीं","जब आप समय से पीछे चल रहे हों, क्योंकि खराब मौसम में जल्दी करने से खोया हुआ समय पूरा हो जाता है"],"explanation":"सुरक्षित गति पकड़ और दृश्यता से तय होती है, न कि लगे हुए सीमा-चिह्न से, इसलिए गीली, हिमांक के पास वाली सड़कों और बर्फीले पुलों पर गति घटाएँ जहाँ ब्लैक आइस छिपी हो सकती है।"},"455":{"q":"आप एक ग्रामीण राजमार्ग पर 55 mph की निर्धारित गति सीमा वाले मार्ग पर एक लदा हुआ ट्रेलर खींच रहे हैं। ठंडी बूंदाबांदी शुरू हो गई है और सड़क गीली होकर चमक रही है। आप सहज महसूस कर रहे हैं और यातायात कम है। निम्न में से कौन-सा कथन सबसे अच्छी तरह बताता है कि इस समय 55 mph की निर्धारित सीमा आप पर कैसे लागू होती है?","options":["55 mph की सीमा कानूनी रूप से न्यूनतम और अधिकतम दोनों है, इसलिए इन परिस्थितियों में इससे काफी कम गति पर चलना अपने आप में एक उल्लंघन होगा","चूंकि आपका ट्रक लदा हुआ है और इसकी पकड़ अच्छी है, इसलिए गीली सड़क पर भी निर्धारित 55 mph एक सुरक्षित लक्ष्य गति बनी रहती है","निर्धारित सीमाओं में बारिश के लिए पहले से ही एक अंतर्निहित सुरक्षा मार्जिन शामिल होता है, इसलिए जब तक सड़क पूरी तरह जलमग्न न हो जाए, 55 mph उपयुक्त रहती है","55 mph का बोर्ड केवल आदर्श परिस्थितियों के लिए अधिकतम है, इसलिए गीली सड़क पर सुरक्षित गति निर्धारित सीमा से कम होती है"],"explanation":"लगी हुई गति सीमा केवल आदर्श परिस्थितियों के लिए कानूनी अधिकतम है, इसलिए गीली सड़क पर, जहाँ पकड़ कम होती है और रुकने की दूरी बढ़ती है, लगी हुई गति से कम चलाएँ।"},"456":{"q":"आप व्यस्त समय में एक भीड़भाड़ वाले इंटरस्टेट हाईवे पर लदे हुए ट्रेलर को चला रहे हैं। यातायात घना है लेकिन एक समान गति से चल रहा है, और दोनों तरफ से वाहन आपको घेरे हुए हैं। आप अपनी डिलीवरी समय पर पहुंचाना चाहते हैं, पर आप यह भी जानते हैं कि आपकी रुकने की दूरी लंबी है। इस भारी यातायात में कौन-सा कदम आपको सबसे अच्छा नियंत्रण और सबसे कम दुर्घटना का जोखिम देता है?","options":["यातायात के प्रवाह से मेल खाती एक समान गति बनाए रखें और आगे पर्याप्त दूरी रखें ताकि रुकने के लिए जगह हो","खोया हुआ समय पूरा करने के लिए सबसे तेज़ चलने वाला रास्ता खोजने हेतु बार-बार लेन बदलें","आगे वाले वाहन के बहुत करीब चलें ताकि दूसरी गाड़ियां आपकी जगह में न घुस सकें","अपनी गति को यातायात के प्रवाह से काफी कम रखने के लिए जोर से और बार-बार ब्रेक लगाएं"],"explanation":"घने ट्रैफ़िक में प्रवाह के अनुरूप स्थिर गति रखें और अपनी लंबी रुकने की दूरी के लिए आगे पर्याप्त जगह बनाए रखें।"},"458":{"q":"आप एक पहाड़ी, दो-लेन वाले बिना विभाजन वाले राजमार्ग पर अपना ट्रैक्टर-ट्रेलर चला रहे हैं। आप एक धीमे खेती के ट्रैक्टर के पास पहुँच जाते हैं और उसे ओवरटेक करना चाहते हैं, लेकिन आगे सड़क एक पहाड़ी की चोटी की ओर चढ़ती है, इसलिए आप नहीं देख सकते कि ऊपर से क्या आ रहा है। निम्नलिखित में से कौन सा सबसे अच्छा बताता है कि आपको ओवरटेक कब शुरू नहीं करना चाहिए?","options":["जब आपके सामने एक लंबा, साफ सीधा रास्ता हो और सामने वाली लेन एक चौथाई मील तक खाली हो","जब सड़क किसी पहाड़ी की चोटी या मोड़ की ओर चढ़ती हो और आप ओवरटेक को सुरक्षित रूप से पूरा करने के लिए पर्याप्त दूर तक न देख सकें","जब सामने बहुत खुली सड़क और अच्छी दृश्यता हो लेकिन आगे का वाहन धीरे चल रहा हो","केवल तब जब सामने से आ रहा वाहन पहले से ही 500 फीट के भीतर हो और अपनी हाई बीम लाइट जला-बुझा रहा हो"],"explanation":"जब चढ़ाई का शिखर या मोड़ दृश्य रोके तब कभी ओवरटेक न करें, क्योंकि आप नहीं देख सकते कि पूरे युद्धाभ्यास के लिए सामने वाली लेन साफ़ है या नहीं।"},"459":{"q":"आपने अभी-अभी एक तंग, अनजान यार्ड में किसी ग्राहक के लोडिंग डॉक पर अपना ट्रेलर लगाया है। डॉक आंशिक रूप से आपके ट्रेलर के पीछे छिपा है, पास में पैलेट के ढेर लगे हैं, और आपके दर्पण ट्रक के ठीक पीछे के निचले कुछ फुट नहीं दिखाते। ट्रक को रिवर्स में डालने से पहले, सुरक्षित रूप से पीछे करने के लिए आपको सबसे पहले क्या करना चाहिए?","options":["अपने दर्पणों पर भरोसा करते हुए धीरे-धीरे पीछे करना शुरू करें, क्योंकि वे ट्रेलर के पीछे के क्षेत्र का सबसे चौड़ा और भरोसेमंद दृश्य देते हैं","हॉर्न तीन बार बजाएँ और फिर एक समान गति से पीछे करें, यह भरोसा करते हुए कि हॉर्न आपके पीछे रास्ते में मौजूद किसी को भी चेतावनी दे देगा","केबिन से बाहर निकलें और पीछे की ओर चलकर जाएँ ताकि हिलने से पहले रास्ते, खाली जगह और किसी भी अंधे क्षेत्र की जाँच कर सकें","किसी पैदल यात्री या फोर्कलिफ्ट के आपके रास्ते में आने से पहले अंधे क्षेत्र से निकलने के लिए तेज़ी से पीछे करें"],"explanation":"पीछे जाने से पहले हमेशा उतरकर देखें (G.O.A.L.) और रास्ता, क्लीयरेंस तथा शीशों में न दिखने वाले अंधे क्षेत्र जाँचें।"},"460":{"q":"आप एक तंग लोडिंग यार्ड में अकेले हैं और अपने ट्रैक्टर-ट्रेलर को पीछे की ओर ले जाकर उस डॉक में लगाना है जो यात्री (दाहिनी) ओर स्थित है। ट्रेलर के पिछले हिस्से को उस दाहिनी ओर के डॉक की ओर घुमाने के लिए, आप स्टीयरिंग व्हील को दाहिनी ओर घुमाना शुरू करते हैं। व्हील को दाहिनी ओर घुमाकर पीछे जाना शुरू करने के पहले ही क्षण में, किसी बड़े सुधार से पहले, ट्रेलर का पिछला हिस्सा सबसे पहले किस ओर जाता है?","options":["ट्रेलर का पिछला हिस्सा तुरंत दाहिनी ओर मुड़ जाता है, उसी दिशा में जिधर आपने व्हील घुमाया, इसलिए आप सीधे डॉक की ओर चलाते हैं।","ट्रेलर ट्रैक्टर के साथ सीधी रेखा में पीछे जाता है और तभी मुड़ना शुरू करता है जब आप गैस देते हैं।","जैसे-जैसे ट्रैक्टर उसे धकेलता है, ट्रेलर का पिछला हिस्सा डॉक के पास ऊपर और दाहिनी ओर चढ़ जाता है।","ट्रेलर का पिछला हिस्सा पहले बाईं ओर जाता है, यानी व्हील घुमाने की दिशा के विपरीत, इससे पहले कि आप उसे दाहिनी ओर लाने के लिए विपरीत स्टीयरिंग करें।"],"explanation":"पीछे जाते समय ट्रेलर का पिछला हिस्सा पहले स्टीयरिंग के विपरीत जाता है; पहिया दाएँ घुमाने पर पिछला भाग पहले बाएँ जाता है, फिर आप काउंटर-स्टीयर करते हैं।"},"461":{"q":"आप एक व्यस्त तीन-लेन वाले इंटरस्टेट पर 53-फुट का बंद ट्रेलर चला रहे हैं और बगल वाली लेन की ओर खिसकने लगते हैं। अपने शीशों में देखने पर आपको दो कारें नहीं दिखतीं जो आपके साथ-साथ उसी गति से चल रही हैं। ट्रक की No-Zones (अंध-क्षेत्रों) के आधार पर, ये वाहन अभी सबसे अधिक संभावना से किस खतरे वाले क्षेत्र में छिपे हुए हैं?","options":["ट्रेलर के दाएँ और बाएँ किनारों के साथ-साथ चलने वाले अंध-क्षेत्रों में","केबिन के ठीक सामने, जहाँ हुड आपकी दृष्टि को रोक देता है","ट्रेलर के पिछले हिस्से के ठीक पीछे, जहाँ आपके शीशे नहीं पहुँचते","बहुत ऊपर, ट्रेलर की छत के ऊपर वाले क्षेत्र में"],"explanation":"साथ-साथ चलने वाले वाहन ट्रेलर के दाएँ और बाएँ किनारों पर फैले साइड नो-ज़ोन अंधे क्षेत्रों में छिप सकते हैं, जहाँ दायाँ हिस्सा सबसे बड़ा होता है।"},"462":{"q":"आप एक व्यस्त चार-लेन वाले अंतरराज्यीय राजमार्ग पर 60 मील प्रति घंटे की गति से एक लदा हुआ ट्रेलर चला रहे हैं। दाहिनी लेन में आपके पीछे कारों की एक कतार जमा होने लगी है, और आपको लगता है कि उनमें से कुछ ओवरटेक करने की तैयारी कर रही हैं। अपने वाहन के पीछे की जगह को सही ढंग से संभालने और इन वाहनों के प्रति सजग रहने के लिए, आपको क्या करना चाहिए?","options":["अपने शीशों का उपयोग करना बंद कर दें और केवल बहुत आगे की सड़क पर ध्यान दें, क्योंकि पीछे जो है वह आपके वाहन चलाने को प्रभावित नहीं कर सकता","अपने पीछे और बगल से आ रहे वाहनों पर नज़र रखने के लिए नियमित रूप से (लगभग हर 5 से 8 सेकंड में) अपने शीशों में देखें","60 मील प्रति घंटे से काफी अधिक तेज़ करें ताकि पीछे की कारें पिछड़ जाएं और जगह अपने आप खुल जाए","पीछे चिपककर चलने वालों को पीछे हटने के लिए मजबूर करने और अपने पीछे एक कुशन बनाने के लिए बार-बार ब्रेक लगाएं"],"explanation":"पीछे की जगह आप नियंत्रित नहीं कर सकते, इसलिए नियमित रूप से लगभग हर 5 से 8 सेकंड में शीशे देखें और पीछे व बगल से आते वाहनों पर नज़र रखें।"},"463":{"q":"आप एक समतल अंतरराज्यीय राजमार्ग पर 55 मील प्रति घंटे की रफ़्तार से एक लदा हुआ ट्रैक्टर-ट्रेलर चला रहे हैं, तभी आप देखते हैं कि एक चौथाई मील आगे लेनों में ब्रेक लाइटें लहर की तरह जल रही हैं और ट्रैफ़िक का झुंड आपकी ओर सिमटने लगता है। आगे वाले वाहन से दूरी घट रही है। इस विकसित होती स्थिति में आपकी जगह और गति-ऊर्जा को सबसे अच्छी तरह कौन-सा कदम संभालता है?","options":["अपनी गति बनाए रखें और वाहन को किनारे वाली लेन की ओर मोड़ें ताकि धीमे होते झुंड के पूरी तरह रुकने से पहले उसके इर्द-गिर्द निकल सकें","अभी मज़बूती से कड़ा ब्रेक लगाकर गति तेज़ी से घटाएँ, क्योंकि 55 मील प्रति घंटे पर रुकने में पहले से ही लगभग 419 फ़ुट लगते हैं","एक्सेलरेटर से पैर हटा लें और आगे वाले वाहन से अपनी दूरी फिर से बढ़ने दें, आगे का अंतर विकसित होते ही केवल ज़रूरत पड़ने पर हल्का ब्रेक लगाएँ","फ़िलहाल अपनी गति बनाए रखें और जब तक प्रतिक्रिया देने को मजबूर न हों, वाहन की लंबाई के हर 10 फ़ुट के लिए कम से कम एक सेकंड की दूरी रखें"],"explanation":"जब आगे का ट्रैफ़िक धीमा हो तो एक्सेलेरेटर छोड़ दें ताकि आपकी फॉलोइंग दूरी फिर से बढ़ जाए, और ज़रूरत पड़ने पर ही हल्के से ब्रेक लगाएँ।"},"464":{"q":"आप बिना किनारे (शोल्डर) वाली एक संकरी, दो-लेन वाली ग्रामीण सड़क पर एक अति-चौड़ा (ओवर-विड्थ) भार ले जा रहे हैं। सामने से आने वाली पिकअप बार-बार बीच की रेखा की ओर सरक रही हैं, आपके दाईं ओर सड़क का किनारा तेजी से नीचे गिरता है, और लेटरबॉक्स तथा खड़ी गाड़ियाँ यातायात लेन के बहुत पास हैं। यहाँ आपके चौड़े वाहन से उत्पन्न सबसे बड़े खतरे को संभालने के लिए, आपको अपना अधिकांश ध्यान कहाँ केंद्रित करना चाहिए?","options":["बहुत आगे की सड़क सतह पर, ताकि आपके अगले पहिये गड्ढों तक पहुँचने से पहले आप उन्हें देख सकें","ट्रेलर के ऊपर की जगह पर, नीची शाखाओं और ऊपरी तारों पर नजर रखते हुए","ट्रेलर के नीचे की जगह पर, यह जाँचते हुए कि चेसिस के नीचे कुछ घिसट तो नहीं रहा","अपने बगल (साइड) की जगह पर, क्योंकि आपके वाहन की चौड़ाई के कारण सामने से आने वाले यातायात, किनारे के गिरावट और सड़क किनारे की वस्तुओं से बहुत कम जगह बचती है"],"explanation":"बिना किनारे वाली संकरी सड़क पर चौड़े वाहन में सबसे अधिक अपनी साइड क्लीयरेंस देखें, क्योंकि सामने का ट्रैफ़िक, ढलान और किनारे की वस्तुएँ दोनों ओर से जगह घेरती हैं।"},"465":{"q":"आप एक लंबी डिलीवरी यात्रा समाप्त करके सड़क किनारे के तौल केंद्र पर रुकते हैं। एक अधिकारी आपसे सांस की जांच (ब्रेथ टेस्ट) करवाने को कहता है। लगभग एक घंटे पहले रात के खाने के साथ आपने दो बीयर पी थीं, आप खुद को पूरी तरह से होश में महसूस करते हैं, और आप जानते हैं कि आपके राज्य में सामान्य यात्री कार चालक के लिए सीमा 0.08 है। अपने CDL वाहन को चलाते समय आप किस सबसे कम रक्त अल्कोहल सांद्रता (BAC) पर अयोग्य घोषित किए जाएंगे?","options":["0.04 या अधिक","0.08 या अधिक","0.10 या अधिक","0.02 या अधिक"],"explanation":"वाणिज्यिक वाहन चलाने वाले CDL चालक के लिए कानूनी सीमा रक्त में अल्कोहल सांद्रता 0.04 प्रतिशत या अधिक है, जो सामान्य चालकों की सीमा से आधी है।"},"466":{"q":"अपना वाणिज्यिक मोटर वाहन (CMV) चलाते समय आपको सड़क किनारे जांच के लिए रोका जाता है, और अधिकारी के पास आपके रक्त में अल्कोहल की मात्रा मापने वाली जांच कराने को कहने का उचित कारण है। आपको पूरा विश्वास है कि आप कानूनी सीमा 0.04% से नीचे हैं और आपको चिंता है कि जांच गलत हो सकती है, इसलिए आप अधिकारी से कहते हैं कि आप इसे बस मना करना पसंद करेंगे। CDL नियमों के तहत, उस इनकार का परिणाम क्या होता है?","options":["जब तक आपका वास्तविक रक्त अल्कोहल स्तर 0.04% से नीचे निकलता है, तब तक आपके CDL के साथ कुछ नहीं होता","आपको CMV चलाने से अयोग्य ठहराया जाता है, ठीक वैसे ही जैसे आप जांच में विफल हो गए हों","आपको केवल एक छोटा प्रशासनिक जुर्माना मिलता है लेकिन आपके सभी ड्राइविंग अधिकार बने रहते हैं","पहली बार इनकार पर आपको लिखित चेतावनी मिलती है और दंड केवल तभी मिलता है जब आप दोबारा इनकार करें"],"explanation":"कानूनन आवश्यक अल्कोहल परीक्षण से इनकार करने पर आप वाणिज्यिक वाहन चलाने से अयोग्य हो जाते हैं, जो परीक्षण में विफल होने के समान ही दंड है।"},"467":{"q":"रात भर चलने वाली ढुलाई के दौरान रात के खाने के बाद आप अपने ट्रैक्टर की ओर लौट रहे हैं, तभी सड़क किनारे एक चेकपॉइंट पर एक राज्य पुलिस अधिकारी आपको रोकता है। रासायनिक जांच में आपके रक्त में अल्कोहल की मात्रा 0.06% पाई जाती है, जो CDL की 0.04% सीमा से अधिक है, और आपको नशे की हालत में वाणिज्यिक वाहन चलाने का दोषी ठहराया जाता है। यह आपके रिकॉर्ड में इस तरह की पहली सजा है। यह मानते हुए कि कोई खतरनाक सामग्री नहीं थी, आपके CDL को अयोग्य ठहराए जाने की न्यूनतम अवधि क्या होगी?","options":["60 दिन, गंभीर यातायात उल्लंघनों के पैटर्न के लिए लागू अवधि के समान","90 दिन, लॉगबुक में जालसाजी के लिए न्यूनतम सेवा-से-बाहर अवधि","एक वर्ष की अयोग्यता","तीन वर्ष, खतरनाक सामग्री ढोते समय किए गए पहले अपराध के समान"],"explanation":"जब कोई खतरनाक सामग्री शामिल न हो, तो 0.04% या उससे अधिक रक्त अल्कोहल स्तर के साथ वाणिज्यिक वाहन चलाने की पहली सजा पर कम से कम एक वर्ष के लिए CDL अयोग्यता होती है।"},"469":{"q":"आप एक सड़क किनारे निरीक्षण के दौरान टेक्सास DPS के वजन केंद्र पर रोके गए हैं। अधिकारी ने पहले ही पुष्टि कर ली है कि आपका वाणिज्यिक चालक लाइसेंस (CDL) वैध है और आपकी लॉगबुक सही है। फिर वह आपसे एक और दस्तावेज़ मांगता है जिसे संघीय नियमों के अनुसार आपको वाहन चलाते समय हमेशा अपने साथ रखना अनिवार्य है, ताकि यह साबित हो सके कि आप शारीरिक रूप से गाड़ी चलाने के योग्य हैं। आपको उसे कौन-सा दस्तावेज़ देना चाहिए?","options":["आपका CDL प्रशिक्षण-स्कूल स्नातक प्रमाणपत्र, जो साबित करता है कि आपने आवश्यक प्रवेश-स्तरीय चालक प्रशिक्षण पूरा किया है","आपके वाहन का स्वामित्व प्रमाणपत्र (टाइटल), जो साबित करता है कि ट्रक कानूनी रूप से पंजीकृत और सड़क पर चलने के लिए अधिकृत है","आपका मूल जन्म प्रमाणपत्र, जो आपकी पहचान और वाणिज्यिक लाइसेंस रखने की कानूनी पात्रता स्थापित करता है","आपका मेडिकल एग्ज़ामिनर प्रमाणपत्र (मेडिकल कार्ड), जो साबित करता है कि आप वर्तमान में वाणिज्यिक वाहन चलाने के लिए शारीरिक रूप से योग्य हैं"],"explanation":"आपको अपने CDL के साथ चिकित्सा परीक्षक प्रमाणपत्र (मेड कार्ड) रखना चाहिए, क्योंकि यह साबित करता है कि आप वर्तमान में वाणिज्यिक वाहन चलाने के लिए शारीरिक रूप से योग्य हैं।"},"470":{"q":"चार-लेन वाले विभाजित राजमार्ग पर आप अपने निर्धारित समय से लगभग 30 मिनट पीछे चल रहे हैं। आपके आगे का चालक आपकी इच्छा से धीमा चल रहा है, इसलिए आप अपने विकल्पों पर विचार कर रहे हैं। टेक्सास DPS नियमों के अनुसार, निम्नलिखित में से कौन-सी कार्रवाई एक बड़ा (MAJOR) यातायात उल्लंघन मानी जाएगी जो आपके CDL को खतरे में डाल सकती है?","options":["धीमे वाहन के पीछे सुरक्षित दूरी पर चलना और ओवरटेक करने के वैध अवसर की प्रतीक्षा करना","लेन बदलने से पहले अपने शीशे जाँचने के लिए थोड़ी देर के लिए निर्धारित न्यूनतम गति से नीचे आ जाना","यातायात में आक्रामक ढंग से इधर-उधर काटते हुए और बहुत पास से पीछा करते हुए धीमे चालक को रास्ता छोड़ने के लिए मजबूर करना","अपने ठीक आगे वाले वाहन की अपेक्षा से थोड़ा पहले लेन बदलने का संकेत देना"],"explanation":"यातायात में आक्रामक तरीके से लेन बदलना और दूसरे चालक पर दबाव डालने के लिए बहुत पास चलना लापरवाह ड्राइविंग है, जो एक बड़ा उल्लंघन है और CDL रद्द करवा सकता है।"},"471":{"q":"आपका ट्रैक्टर-ट्रेलर एक समतल, सीधे, दो-लेन वाले अविभाजित राजमार्ग की दाहिनी शोल्डर पर बंद हो जाता है। आप अपनी खतरे की चेतावनी (हैज़र्ड) लाइटें चालू करते हैं और 10 मिनट की समय-सीमा समाप्त होने से पहले परावर्तक त्रिकोण लगाने के लिए उन्हें उठाते हैं। पहला (सबसे नज़दीकी) त्रिकोण रखने के लिए जब आप अपने वाहन के पिछले हिस्से की ओर चलते हैं, तो उसे वाहन से लगभग कितनी दूरी पीछे रखना चाहिए?","options":["वाहन से लगभग 10 फीट पीछे, यातायात वाली ओर","वाहन से लगभग 100 फीट पीछे","वाहन से लगभग 200 फीट पीछे","बिल्कुल पिछले बंपर के पास, वाहन से सटाकर"],"explanation":"सबसे नज़दीकी चेतावनी त्रिकोण वाहन के तुरंत पिछले हिस्से को चिह्नित करने के लिए यातायात की ओर वाहन से लगभग 10 फीट पीछे रखा जाता है।"},"472":{"q":"एक पहिये का बेयरिंग खराब हो जाता है और आप अपने ट्रैक्टर-ट्रेलर को बिना डिवाइडर वाले, समतल, सीधे दो-लेन वाले राजमार्ग के किनारे (शोल्डर) पर लुढ़काकर रोक देते हैं। चारों दिशाओं के फ्लैशर चालू करने के बाद, आप अपने आपातकालीन त्रिकोण उठाते हैं और उन्हें आने वाले यातायात की ओर लगाना शुरू करते हैं। पहला त्रिकोण आप सही ढंग से वाहन से 10 फीट पीछे रखते हैं। इस तरह की सड़क पर, अपने वाहन के पीछे रखे जाने वाले दूसरे त्रिकोण को वाहन से लगभग कितनी दूरी पीछे रखना चाहिए?","options":["लगभग 200 फीट पीछे, और तीसरा उससे 200 फीट और आगे","वाहन से लगभग 100 फीट पीछे","वाहन से लगभग 50 फीट पीछे","वाहन से लगभग 100 फीट आगे, सामने से आने वाली लेन में"],"explanation":"दो-लेन या अविभाजित सड़क पर, दूसरा त्रिकोण वाहन से लगभग 100 फीट पीछे रखा जाता है क्योंकि यातायात दोनों दिशाओं से आ सकता है।"},"473":{"q":"अच्छी दृश्यता में एक सीधे, समतल, विभाजित (डिवाइडेड) राजमार्ग — विपरीत यातायात को अलग करने वाली मीडियन के साथ एक-दिशा वाला मार्ग — की दाहिनी लेन में आपका ट्रैक्टर-ट्रेलर खराब हो जाता है। आप अपनी हैज़र्ड फ्लैशर लाइटें चालू करते हैं और अपना आपातकालीन त्रिकोण किट उठाते हैं। जब आप उस त्रिकोण को रखने के लिए पीछे चलते हैं जिसे वाहन के पिछले हिस्से से सबसे दूर रखा जाना चाहिए, तो उसे लगभग कितनी दूरी पर रखना चाहिए?","options":["लगभग 100 फीट पीछे, क्योंकि बीच वाला त्रिकोण वहीं रखा जाता है","लगभग आधा मील पीछे, ताकि तेज़ यातायात को अधिकतम चेतावनी मिल सके","वाहन से लगभग 200 फीट पीछे","लगभग 10 फीट पीछे, ठीक पिछले बंपर के बाद"],"explanation":"एकतरफा या विभाजित राजमार्ग पर, तीनों त्रिकोण वाहन के पीछे रखे जाते हैं, जिसमें सबसे दूर वाला आने वाले यातायात की ओर लगभग 200 फीट पीछे रखा जाता है।"},"474":{"q":"आप एक एकतरफ़ा (विभाजित) राजमार्ग के दाहिने किनारे पर, एक पहाड़ी की चोटी पार करते ही रुक गए हैं, जहाँ पीछे से आ रहे वाहन आखिरी क्षण तक आपके ट्रक को नहीं देख पाते। आप अपनी ख़तरे की चेतावनी लाइटें (हैज़र्ड फ़्लैशर) चालू करते हैं और तीन परावर्तक त्रिकोण लगाना शुरू करते हैं। जब पीछे से आ रहे यातायात से आपके पिछले हिस्से की रक्षा करने वाला सबसे दूर का त्रिकोण लगाने की बारी आए, तो पहाड़ी के दृश्य को रोकने की भरपाई के लिए आपको क्या करना चाहिए?","options":["तीनों त्रिकोणों को ट्रक के 10 फ़ुट के भीतर रखें ताकि वे एक साथ समूह में और मिलकर दिखाई दें","दूर वाले त्रिकोण को ठीक 200 फ़ुट पीछे रखें, जैसे किसी समतल खुले हिस्से पर, क्योंकि यही दूरी क़ानूनी मानक है","दूर वाला त्रिकोण बिल्कुल न लगाएँ और अपनी ख़तरे की लाइटों पर भरोसा करें, जो पहाड़ी पर त्रिकोण से ज़्यादा चमकीली होती हैं","दूर वाले त्रिकोण को उसकी सामान्य 200 फ़ुट की जगह से और आगे (500 फ़ुट तक) पीछे खिसकाएँ, ताकि पहाड़ी की चोटी पार करते ही चालकों को प्रतिक्रिया देने के लिए पर्याप्त चेतावनी मिले"],"explanation":"दृष्टि रेखा को बाधित करने वाली पहाड़ी या मोड़ के पास, दूर वाले त्रिकोण को उसके सामान्य स्थान से और पीछे (500 फीट तक) ले जाएं ताकि आने वाले चालकों को पर्याप्त चेतावनी मिले।"},"475":{"q":"एक विश्राम स्थल पर अपनी प्री-ट्रिप जांच के दौरान, आपको धुएं की गंध आती है और आपको एक छोटी आग दिखती है जो आपके ट्रेलर के पिछले दरवाजों के पास फेंके गए गत्ते के डिब्बों, पैकिंग कागज और मूविंग कंबलों के ढेर में शुरू हुई है। कार्रवाई करने से पहले आप अपना अग्निशामक यंत्र उठाते हैं और उसकी श्रेणी जांचते हैं। यहां जल रही सामग्री के प्रकार के लिए विशेष रूप से कौन सी श्रेणी का अग्निशामक यंत्र बनाया गया है?","options":["श्रेणी A, जो लकड़ी, कागज और कपड़े जैसी साधारण ज्वलनशील वस्तुओं के लिए रेटेड है","श्रेणी B, जो ईंधन, तेल और ग्रीस जैसे जलते तरल पदार्थों के लिए रेटेड है","श्रेणी C, जो जीवित बिजली के तारों और ऊर्जावान उपकरणों में लगी आग के लिए रेटेड है","श्रेणी D, जो मैग्नीशियम और टाइटेनियम जैसी ज्वलनशील धातुओं के लिए रेटेड है"],"explanation":"लकड़ी, कागज और कपड़े जैसी सामान्य ज्वलनशील सामग्री की आग के लिए क्लास A अग्निशामक उपयुक्त है।"},"476":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान आप अपनी कैब में लगे अग्निशामक यंत्र की जाँच करते हैं। आप डीज़ल ईंधन के ड्रम ढो रहे हैं, और सुनिश्चित करना चाहते हैं कि यह यंत्र इस माल के लिए सबसे संभावित आग को वास्तव में संभाल सके। एक छोटा ईंधन रिसाव ड्रमों के पास आग पकड़ लेता है। इस जलते हुए तरल की आग से लड़ने के लिए किस श्रेणी का अग्निशामक यंत्र उपयुक्त है?","options":["श्रेणी A का यंत्र, क्योंकि यह सबसे आम प्रकार है और ट्रेलर में रखे लकड़ी के पैलेट और कागज़ की परचियों पर भी काम करता है","श्रेणी B का यंत्र, क्योंकि यह ईंधन, तेल और ग्रीस जैसे जलते हुए तरल पदार्थों के लिए उपयुक्त है","श्रेणी C का यंत्र, क्योंकि आग ट्रक की विद्युत और बैटरी प्रणाली के पास शुरू हुई","श्रेणी D का यंत्र, क्योंकि यह ज्वलनशील कपड़े, चिथड़े और वर्कशॉप के पोंछों वाली आग के लिए है"],"explanation":"ईंधन, तेल और ग्रीस जैसे ज्वलनशील तरल पदार्थों की आग के लिए क्लास B अग्निशामक उपयुक्त है।"},"477":{"q":"अपनी प्री-ट्रिप जांच के दौरान आपको डैशबोर्ड के पास कुछ गर्म जलने जैसी गंध आती है और आप अपने ट्रैक्टर की विद्युत प्रणाली के विद्युत-प्रवाहित (एनर्जाइज़्ड) वायरिंग पैनल के पीछे से धुआं निकलते हुए पाते हैं। आप कैब में लगे अग्निशामक यंत्र की ओर हाथ बढ़ाते हैं। इस आग से सुरक्षित रूप से निपटने के लिए आपको किस श्रेणी (क्लास) के अग्निशामक का उपयोग करना चाहिए?","options":["क्लास A अग्निशामक, क्योंकि यह पैनल के चारों ओर की लकड़ी और कागज की फिनिश के लिए बना है","क्लास B अग्निशामक, क्योंकि यह उन ज्वलनशील तरल पदार्थों के लिए बना है जो अधिकांश ट्रक आगों का कारण बनते हैं","क्लास C अग्निशामक, क्योंकि यह विद्युत-प्रवाहित (लाइव) विद्युत उपकरणों की आग के लिए बना है","कोई भी क्लास काम करेगी, बशर्ते आप पहले बैटरी डिस्कनेक्ट कर दें"],"explanation":"जीवित विद्युत उपकरण की आग के लिए क्लास C अग्निशामक आवश्यक है क्योंकि इसका गैर-संवाहक पदार्थ करंट को वापस संचालक तक नहीं ले जाता।"},"478":{"q":"तापमान जमाव बिंदु से थोड़ा नीचे है और आप बर्फ की परत से ढकी, फिसलन भरी रैंप पर रुकने के बाद आगे बढ़ रहे हैं। आपको ट्रक हिलता हुआ महसूस होता है और टैकोमीटर अचानक बढ़ जाता है क्योंकि आपके ड्राइव पहिये वाहन को आगे बढ़ाए बिना घूमने (स्पिन) लगते हैं। आगे बढ़ने और पकड़ (ट्रैक्शन) वापस पाने के लिए सबसे अच्छा कदम क्या है?","options":["घूमते पहियों को बर्फ के पार धकेलने के लिए एक्सेलेरेटर पर और जोर से दबाएं","ड्राइव पहियों को सतह पर पकड़ बनाने के लिए ब्रेक पेडल को तेजी से पंप करें","टायरों के किनारों को पकड़ दिलाने के लिए स्टीयरिंग को तेजी से एक ओर से दूसरी ओर घुमाएं","एक्सेलेरेटर से पैर हटा लें ताकि ड्राइव पहिये धीमे होकर फिर से ट्रैक्शन पा लें"],"explanation":"ड्राइव-व्हील स्किड में, गति पैडल से पैर हटाकर शक्ति कम करें ताकि घूमते पहिए वाहन की गति तक धीमे होकर पकड़ पुनः प्राप्त कर लें।"},"479":{"q":"आप एक लंबी ढलान से नीचे उतर रहे हैं और देखते हैं कि आपके ट्रेलर के दोहरे टायरों में से एक से धुआँ और फिर आग की लपटें निकल रही हैं। आप सुरक्षित रूप से किनारे पर रुकते हैं, अपने चेतावनी त्रिकोण रखते हैं और अपना सामान लेते हैं। टायर के सक्रिय रूप से जलते समय, आग को ठंडा करने और बुझाने का सबसे अच्छा तरीका निम्नलिखित में से कौन सा है?","options":["उस पर खूब सारा पानी डालें, क्योंकि पानी जलते हुए टायर को ठंडा करता है","लपटों पर सीधे सूखी रेत डालकर उसे दबा दें","किनारे पर धीरे-धीरे चलते रहने से हवा के बहाव को टायर ठंडा करने दें","टायर की सतह को ऑक्सीजन से सील करने के लिए इंजन ऑयल का छिड़काव करें"],"explanation":"जलते टायर पर खूब पानी डालें, क्योंकि पानी उस रबर और कैसिंग को ठंडा करता है जहाँ गर्मी जमा होती है और दोबारा आग लगने से रोकता है।"},"480":{"q":"ठंडी सुबह है और आप अपनी प्री-ट्रिप जांच से पहले इंजन गर्म करने के लिए अपने ट्रक को एक बंद लोडिंग डॉक में चालू (आइडल) छोड़ देते हैं। कुछ मिनटों बाद आपको चक्कर आने लगते हैं और सिरदर्द होने लगता है, लेकिन आपको हवा में कुछ भी असामान्य न तो दिखता है और न ही महकता है। कार्बन मोनोऑक्साइड के व्यवहार के आधार पर, इन लक्षणों के शुरू होने से पहले आपको बहुत कम या कोई चेतावनी न मिलने का सबसे संभावित कारण क्या है?","options":["यह गैस पहले एक तीखी, मीठी गंध देती, इसलिए एग्ज़ॉस्ट सिस्टम सीलबंद होगा और यही कारण नहीं है","कार्बन मोनोऑक्साइड रंगहीन और गंधहीन होती है, इसलिए आपकी इंद्रियाँ इसके प्रभाव डालने से पहले इसका पता नहीं लगा सकतीं","जमा होने पर यह गैस दिखाई देने वाली चमकीली लाल हो जाती है, लेकिन डॉक की मंद रोशनी ने इसे आपसे छिपा दिया","कार्बन मोनोऑक्साइड हवा से भारी होती है और फर्श के पास रहती है, इसलिए खड़े होने पर आपको समय रहते चेतावनी मिल जाती"],"explanation":"कार्बन मोनोऑक्साइड रंगहीन और गंधहीन होती है, इसलिए बंद जगहों में आप पर असर करने से पहले आपकी इंद्रियाँ इसे पहचान नहीं सकतीं।"},"481":{"q":"आप टेक्सास के एक ग्रामीण राजमार्ग पर एक लदे हुए संयोजन वाहन को चला रहे हैं, तभी आगे आपको एक वज़न स्टेशन दिखता है जिसका \"OPEN\" (खुला) चिह्न जल रहा है और कुछ छोटी कारें बिना रुके उसके पास से गुज़र रही हैं। आप थके हुए हैं और अपनी डिलीवरी से केवल दो-तीन मील की दूरी पर हैं। कौन-सा कार्य कानूनी रूप से सही है?","options":["छोटी कारों की तरह आगे निकल जाना, क्योंकि स्टेशन आज स्पष्ट रूप से केवल यात्री कारों की जाँच कर रहा है","स्टेशन को वैकल्पिक मानना और केवल तभी अंदर जाना जब कोई अधिकारी आपको इशारा करे या आपका सकल वज़न आपको ज़्यादा लगे","खुले वज़न स्टेशन में प्रवेश करना, क्योंकि ट्रकों को कानूनन हर उस खुले वज़न स्टेशन पर रुकना आवश्यक है जिसके पास से वे गुज़रते हैं","इसे छोड़ देना क्योंकि आप अपनी अंतिम डिलीवरी से दो-तीन मील की दूरी पर हैं और आपका माल पहले से सुरक्षित है"],"explanation":"कानून के अनुसार ट्रकों को हर खुले वेट स्टेशन पर रुकना अनिवार्य है, चाहे थकान, लोड या कारों का व्यवहार कुछ भी हो।"},"482":{"q":"सड़क किनारे के वजन-कांटे पर अपनी प्री-ट्रिप जांच के दौरान, एक टेक्सास DPS निरीक्षक आपके ट्रैक्टर में ब्रेक की खराबी पाता है, उसका लिखित रिकॉर्ड बनाता है, और वाहन पर आउट-ऑफ-सर्विस (OOS) आदेश लगा देता है। मरम्मत की दुकान 8 मील दूर है और आपकी डिलीवरी की समय-सीमा एक घंटे में समाप्त हो रही है। कौन सी कार्रवाई कानूनी रूप से सही है?","options":["चूंकि माल समय-संवेदनशील है, आप कम गति पर सीधे मरम्मत की दुकान तक 8 मील चला सकते हैं","जब तक आप 55 मील प्रति घंटे से नीचे रहते हैं और केवल हल्का, स्थिर ब्रेक लगाते हैं, तब तक आप अपना मार्ग जारी रख सकते हैं","ईंधन भरवाने और एयर-ब्रेक गेज पर पूरा दबाव दिखने के बाद आप चला सकते हैं","जब तक खराबी की मरम्मत नहीं हो जाती और आदेश हटा नहीं दिया जाता, तब तक आप वाहन को बिल्कुल नहीं चला सकते"],"explanation":"आउट-ऑफ-सर्विस आदेश कानूनी रूप से आपको सार्वजनिक सड़क पर वाहन चलाने से रोकता है जब तक खराबी ठीक न हो और आदेश हट न जाए।"},"483":{"q":"एक तौल केंद्र (weigh station) पर सड़क निरीक्षक आपके ELD से आपके ड्यूटी स्थिति रिकॉर्ड (records of duty status) देखना चाहता है। आपका डिस्पैचर दावा करता है कि यह उपकरण मुख्य रूप से कर विभाग और आपके बेड़े के लेखा विभाग को संतुष्ट करने के लिए है। इस निरीक्षण के लिए आपके ड्यूटी स्थिति रिकॉर्ड वास्तव में क्या दर्ज करने के लिए बनाए गए हैं, इसका सबसे अच्छा वर्णन कौन सा कथन करता है?","options":["आपके द्वारा चलाए गए और ड्यूटी पर बिताए गए घंटों की संख्या, ताकि अधिकारी पुष्टि कर सके कि आप अपनी कानूनी सेवा-घंटे (hours of service) सीमा के भीतर हैं","राज्य के अनुसार ईंधन खरीद और माइलेज, ताकि अधिकारी सत्यापित कर सके कि आपकी IFTA कर रिपोर्टिंग सही है","वाहन का रखरखाव और मरम्मत इतिहास, ताकि अधिकारी पुष्टि कर सके कि आवश्यक निरीक्षण किए गए थे","माल का वजन और सुरक्षा जांच, ताकि अधिकारी पुष्टि कर सके कि आपने हर 150 मील पर अपने माल की दोबारा जांच की"],"explanation":"ड्यूटी स्टेटस रिकॉर्ड आपके ड्राइविंग और ऑन-ड्यूटी घंटों को दर्ज करते हैं ताकि निरीक्षक पुष्टि कर सके कि आप कानूनी सेवा-घंटे सीमा के भीतर हैं।"},"484":{"q":"आप अपने लदे हुए ट्रैक्टर-ट्रेलर के साथ राजमार्ग पर मर्ज कर रहे हैं और तेज़ी से गति बढ़ाना चाहते हैं। टैकोमीटर की सुई तेज़ी से ऊपर चढ़ रही है और अब लाल क्षेत्र के शीर्ष को छू रही है, लेकिन आप यातायात के साथ चलने के लिए और अधिक शक्ति चाहते हैं। डीज़ल इंजन की रक्षा के लिए, निम्नलिखित में से आपको क्या नहीं करना चाहिए?","options":["इंजन से भारी शक्ति की मांग करने से पहले उसे आइडल पर गर्म होने देना","अधिक त्वरण निकालने के लिए इंजन को टैकोमीटर पर लाल रेखा से आगे धकेलना","थ्रॉटल बढ़ाने से पहले ऊपरी गियर में शिफ्ट करना ताकि इंजन की गति लाल क्षेत्र से नीचे आ जाए","धीरे-धीरे गति बढ़ाने के लिए इंजन की सामान्य परिचालन RPM सीमा का उपयोग करना"],"explanation":"इंजन को कभी टैकोमीटर की लाल रेखा से आगे न ले जाएँ, क्योंकि लाल रेखा अधिकतम सुरक्षित RPM दर्शाती है और अधिक रेविंग से इंजन को गंभीर नुकसान होता है।"},"485":{"q":"आप अपने लदे हुए ट्रैक्टर-ट्रेलर को ग्राहक के डॉक पर हल्की ढलान वाली उतराई पर खड़ा करते हैं, पार्किंग ब्रेक लगाते हैं, और उतराई शुरू करने के लिए केबिन से बाहर निकलते हैं। जगह पूरी तरह समतल नहीं है और आप काफी देर तक केबिन से दूर रहेंगे। इन परिस्थितियों में, ट्रक को बिना निगरानी छोड़ने से पहले एकमात्र सर्वोत्तम अभ्यास कौन सा है?","options":["कुछ अतिरिक्त की आवश्यकता नहीं क्योंकि स्प्रिंग पार्किंग ब्रेक किसी भी ढलान पर लदे ट्रेलर को अनिश्चित काल तक रोके रखेगा","पहियों के नीचे चॉक लगाने के बजाय ट्रांसमिशन को निचले गियर में छोड़ दें, क्योंकि गियर लगा होना ढलान पर चॉक की जगह पूरी तरह ले लेता है","पहियों के नीचे चॉक लगाएं, क्योंकि असमान, ढलान वाली सतह पर ट्रक के लुढ़कने की संभावना है","चॉक छोड़ दें क्योंकि ढलान केवल हल्की है, और चॉक केवल तीव्र पहाड़ी उतराई पर ही आवश्यक होते हैं"],"explanation":"जब भी ट्रक के लुढ़कने की कोई संभावना हो, जैसे ढलान वाली असमतल सतह पर जहाँ वह लदा और बिना निगरानी खड़ा हो, पहियों के नीचे चॉक लगाएँ।"},"486":{"q":"आप एक डिलीवरी पूरी करते हैं और अपने ट्रैक्टर-ट्रेलर को एक ग्रामीण किनारे (शोल्डर) पर ढलान की ओर नीचे (DOWNHILL) मुंह करके पार्क करना है। सड़क के इस हिस्से पर कोई कर्ब (किनारे की मेंड़) नहीं है। वाहन छोड़ने की तैयारी करते समय, आपको आगे के (स्टीयरिंग-एक्सल) पहियों को कैसे रखना चाहिए ताकि अगर वाहन लुढ़के तो वह गुज़रते ट्रैफ़िक से दूर जाए, न कि चलने वाली लेन में?","options":["आगे के पहियों को सीधा रहने दें, क्योंकि ढलान पर पार्किंग ब्रेक और चॉक ही पूरा वाहन रोक लेते हैं","आगे के पहियों को ज़ोर से बाईं ओर (LEFT) घुमाएँ, ठीक वैसे ही जैसे कर्ब के सहारे चढ़ाई पर पार्क करते समय करते हैं","पहियों को सीधा रखें और ऐसा तभी करें जब आप जाँच लें कि स्टीयरिंग एक्सल का टायर ट्रेड कम से कम 4/32 इंच है","आगे के पहियों को सड़क के किनारे की ओर घुमाएँ, ताकि लुढ़कता वाहन पक्की सड़क से उतरकर ट्रैफ़िक से दूर चला जाए"],"explanation":"बिना कर्ब वाली ढलान पर नीचे की ओर पार्क करते समय अगले पहिये सड़क के किनारे की ओर मोड़ें ताकि लुढ़कता वाहन ट्रैफ़िक से दूर सड़क से हटकर चला जाए।"},"487":{"q":"आपकी प्री-ट्रिप जांच के दौरान तापमान हिमांक से थोड़ा नीचे है, और आप देखते हैं कि आपके ट्रैक्टर की सीढ़ियां और हैंडहोल्ड बर्फ की पतली परत और सड़क की गंदगी से ढके हुए हैं। संघीय और टेक्सास नियम आपको इन वस्तुओं की जांच करने के लिए बाध्य करते हैं। हैंडबुक के अनुसार, गाड़ी चलाने से पहले सीढ़ियों और हैंडहोल्ड की स्थिति जांचने का मुख्य कारण क्या है?","options":["ताकि आप केबिन में सुरक्षित रूप से चढ़ और उतर सकें, खासकर सतह फिसलन भरी होने पर तीन संपर्क बिंदु बनाए रखते हुए","ताकि आप पुष्टि कर सकें कि केबिन का ढांचा GVWR प्लेट पर दर्ज निर्धारित कार्गो वजन को सहन कर सकता है","ताकि आप जांच सकें कि फ्रेम और माउंटिंग ब्रैकेट में दरार नहीं है, वरना वाहन सेवा से बाहर कर दिया जाएगा","ताकि आप अपने जूते साफ रख सकें और केबिन के फर्श व पैडल पर कीचड़ न लगाएं"],"explanation":"मजबूत और सही सीढ़ियाँ व हैंडहोल्ड आपको केबिन में सुरक्षित रूप से चढ़ने-उतरने देते हैं, फिसलन वाली सतहों पर तीन संपर्क बिंदु बनाए रखते हुए।"},"488":{"q":"आपकी पाली की शुरुआत है और आप अपनी यात्रा-पूर्व जांच पूरी कर रहे हैं। आज के मार्ग पर किसी भी बिंदु पर एक DOT अधिकारी आपको सड़क किनारे जांच पर रोक सकता है और आपके वाहन पंजीकरण तथा बीमा प्रमाण को देखने के लिए कह सकता है। नियमों का पालन करने और उस जांच के लिए तैयार रहने के लिए, इस समय ये दस्तावेज़ कहां होने चाहिए?","options":["आपके घर या टर्मिनल कार्यालय की एक अलमारी में दाखिल किए गए ताकि वे सड़क पर खो या चोरी न हो सकें","आपके साथ वाहन के अंदर, ताकि आप सड़क किनारे जांच के दौरान किसी भी अधिकारी को इन्हें प्रस्तुत कर सकें","टेक्सास DPS को डाक से भेजे गए ताकि राज्य आपके लिए आधिकारिक प्रति रिकॉर्ड में रखे","एक ऑनलाइन राज्य पोर्टल पर अपलोड किए गए, क्योंकि एक डिजिटल रिकॉर्ड कागज़ी प्रतियां साथ रखने की आवश्यकता को बदल देता है"],"explanation":"अपना रजिस्ट्रेशन और बीमा प्रमाण वाहन के अंदर रखें ताकि किसी भी रोडसाइड निरीक्षण या रुकावट के दौरान आप उन्हें अधिकारी को दिखा सकें।"},"489":{"q":"रात में अपने लदे हुए संयोजन वाहन से आप एक ग्रामीण चौराहे के पास पहुँच रहे हैं, तभी आप देखते हैं कि आपकी दिशा में ऊपर लगा ट्रैफ़िक सिग्नल लाल रंग में चमक रहा है, जबकि क्रॉस ट्रैफ़िक के सामने पीला रंग चमक रहा है। यह देखते हुए कि ये सिग्नल कानूनी रूप से कैसे भिन्न हैं, आपके लिए सही कार्रवाई क्या है?","options":["गति धीमी करें और बिना रुके सावधानी से निकल जाएँ, क्योंकि चमकता सिग्नल केवल सतर्क रहने की चेतावनी देता है","गति बनाए रखें पर रुकने के लिए तैयार रहें, क्योंकि पीला चमकता क्रॉस ट्रैफ़िक आपको रास्ता देने के लिए बाध्य है","स्टॉप साइन की तरह पूरी तरह रुकें, फिर तभी आगे बढ़ें जब चौराहा साफ़ हो","इसे अटका हुआ सिग्नल मानें, थोड़ी देर रुकें और स्थिर लाल होने से पहले निकल जाएँ"],"explanation":"चमकती लाल बत्ती का अर्थ रुकने के संकेत (stop sign) जैसा होता है: पूरी तरह रुकें, रास्ता दें, और चौराहा साफ होने पर ही आगे बढ़ें।"},"490":{"q":"रात में आप एक व्यस्त चौराहे के पास पहुँच रहे हैं जब आपकी लेन के ऊपर लगा ट्रैफिक सिग्नल लगातार चमकती पीली बत्ती में बदल जाता है, जबकि क्रॉस-स्ट्रीट पर चमकती लाल बत्ती है। क्रॉस-स्ट्रीट पर कई कारें प्रवेश करने के लिए प्रतीक्षा कर रही हैं। इस चौराहे से गुज़रने का सही तरीका क्या है?","options":["चमकती पीली बत्ती को बिल्कुल स्थिर लाल बत्ती की तरह मानें: पूरी तरह रुकें, फिर चौराहा साफ़ होने पर आगे बढ़ें","अपनी हाईवे गति बनाए रखें क्योंकि चमकती पीली बत्ती आपको पूर्ण रास्ते का अधिकार देती है और क्रॉस-ट्रैफिक को रुके रहना ही होगा","रुकें और पहले क्रॉस-स्ट्रीट के चालकों को निकलने दें, क्योंकि उनकी चमकती लाल बत्ती एक चार-तरफ़ा स्टॉप की तरह काम करती है जो उन्हें रास्ता देती है","अपनी गति कम करें और सावधानी से चौराहे से गुज़रें, चमकती लाल बत्ती पर रुके क्रॉस-ट्रैफिक के प्रति सतर्क रहते हुए"],"explanation":"चमकती पीली बत्ती सावधानी का संकेत है, रुकने का नहीं: गति धीमी करें और चौराहे से सावधानी से गुजरें।"},"491":{"q":"अपने लदे हुए संयोजन वाहन (combination vehicle) में आप एक व्यस्त चौराहे के पास पहुँच रहे हैं, तभी आप देखते हैं कि आपके सामने वाला ट्रैफ़िक सिग्नल बिजली कटौती के कारण पूरी तरह बुझा हुआ है, कोई भी बत्ती नहीं जल रही। आड़ी दिशा का यातायात भी धीमा हो रहा है। कानूनी और सुरक्षित रूप से आगे बढ़ने के लिए आपको इस चौराहे को कैसे मानना चाहिए?","options":["चार-तरफ़ा स्टॉप (four-way stop) के रूप में: पूरी तरह रुकें, फिर वाहनों के पहुँचने के क्रम के अनुसार बारी-बारी से आगे बढ़ें, और जो पहले पहुँचे उन्हें पहले जाने दें","यील्ड (रास्ता दें) के रूप में: गति कम करें और केवल तभी रुकें जब कोई दूसरा वाहन पहले से चौराहे में हो, अन्यथा बिना रुके निकल जाएँ","मुख्य सड़क के लिए हरी बत्ती के रूप में, क्योंकि बड़े व्यावसायिक वाहन को आड़ी दिशा के यातायात पर रास्ते का अधिकार होता है","मुफ़्त रास्ते के रूप में: अपनी गति बनाए रखते हुए चौराहा पार करें, क्योंकि बुझा हुआ सिग्नल एक नियंत्रित चौराहा नहीं है"],"explanation":"बंद या खराब ट्रैफिक सिग्नल को चार-तरफा स्टॉप मानें, और वाहन आने के क्रम के अनुसार आगे बढ़ें।"},"492":{"q":"आप एक धीमे कृषि ट्रैक्टर के पीछे दो-लेन के राजमार्ग पर एक लदा हुआ ट्रेलर चला रहे हैं। सड़क के बीच में दोहरी ठोस पीली रेखा अंकित है। आपका समय बर्बाद हो रहा है और आप ट्रैक्टर को ओवरटेक करना चाहते हैं। इस सड़क चिह्न के आधार पर, निम्नलिखित में से कौन सी सही कार्रवाई है?","options":["आप ओवरटेक करने के लिए रेखा पार कर सकते हैं क्योंकि आपकी ओर की लेन तेज़ लेन है","आपको ओवरटेक नहीं करना चाहिए, क्योंकि दोहरी ठोस पीली केंद्र रेखा दोनों दिशाओं के यातायात के लिए ओवरटेक करना प्रतिबंधित करती है","जब तक 500 फीट के भीतर सामने से आता हुआ कोई यातायात दिखाई न दे, तब तक आप ओवरटेक कर सकते हैं","यह चिह्न केवल पार्किंग को प्रतिबंधित करता है, इसलिए सड़क साफ़ होने पर ओवरटेक करने की अनुमति है"],"explanation":"दोहरी ठोस पीली केंद्र रेखा दोनों दिशाओं के लिए ओवरटेक करना मना करती है, इसलिए पास करने के लिए इसे पार न करें।"},"493":{"q":"आप टेक्सास के एक बहु-लेन राजमार्ग पर मध्यम यातायात में गाड़ी चला रहे हैं, तभी लेन की निशानदेही बदल जाती है: आपकी लेन और दाईं ओर की लेन के बीच की टूटी हुई सफेद रेखा एक लंबे हिस्से तक चलने वाली एकल ठोस (सॉलिड) सफेद रेखा में बदल जाती है। आपकी लेन का यातायात बगल वाली लेन की तुलना में थोड़ा धीमा चल रहा है। यह ठोस सफेद रेखा क्या बताती है और आपको कैसे प्रतिक्रिया देनी चाहिए?","options":["यह सड़क के किनारे को दर्शाती है, इसलिए आपको किनारे (शोल्डर) की ओर सरकना चाहिए ताकि तेज़ यातायात आपके बाईं ओर से निकल सके","यह टूटी हुई रेखा के समान ही है, इसलिए तेज़ लेन के साथ चलते रहने के लिए जब भी जगह मिले आप दाईं ओर जा सकते हैं","यह रेखा पार करने को हतोत्साहित करती है, इसलिए आपको अपनी लेन में बने रहना चाहिए और लेन तभी बदलनी चाहिए जब यह वास्तव में आवश्यक और सुरक्षित हो","इसका मतलब है कि सभी के लिए ओवरटेक करना प्रतिबंधित है, इसलिए आपको अपनी ठीक स्थिति बनाए रखनी होगी और किसी भी परिस्थिति में लेन नहीं बदल सकते"],"explanation":"एकल ठोस सफेद रेखा एक ही दिशा की लेनों को अलग करती है और लेन बदलने को हतोत्साहित करती है, इसलिए केवल आवश्यक और सुरक्षित होने पर ही पार करें।"},"494":{"q":"आप दिन के उजाले में एक दो-लेन वाली बिना विभाजित सड़क पर अपना ट्रैक्टर-ट्रेलर चला रहे हैं, तभी आपके आगे चल रही स्कूल बस अपनी बारी-बारी से चमकने वाली लाल बत्तियाँ जलाती है और अपना स्टॉप आर्म (रुकने का संकेतक) बाहर निकालती है। आप कानूनी दूरी पर चल रहे हैं और पीछे यातायात कम है। आपको क्या करना आवश्यक है?","options":["लगभग 15 मील प्रति घंटे की गति तक धीमे हों, ब्रेक पर पैर रखें और चूँकि सड़क बिना विभाजित है, बस को केवल उसकी बाईं ओर से सावधानी से पार कर लें","बच्चों पर नज़र रखते हुए बहुत धीमी रेंगने वाली गति से चलते रहें, क्योंकि पूरी तरह रुकना केवल तब आवश्यक है जब बस पीली (अंबर) चेतावनी बत्तियाँ दिखाए","किनारे पर रुकें, अपने परावर्तक त्रिकोण रखें और बस चालक द्वारा आगे बढ़ने का इशारा करने तक प्रतीक्षा करें","पूरी तरह रुक जाएँ और तब तक रुके रहें जब तक लाल बत्तियाँ चमकना बंद न कर दें और स्टॉप आर्म वापस अंदर न हो जाए"],"explanation":"स्टॉप आर्म फैले होने पर चमकती लाल बत्तियों का अर्थ है कि बिना विभाजित सड़क पर दोनों दिशाओं का यातायात तब तक रुके जब तक बत्तियाँ बंद और आर्म वापस न हो जाए।"},"495":{"q":"अपने मार्ग पर आप स्टील की प्लेटों वाले सड़क मरम्मत खंड और धातु की जाली वाले पुल के डेक के पास पहुँच रहे हैं। आज परिस्थितियाँ कई बार बदल चुकी हैं। निम्नलिखित में से किस स्थिति में आपको इन धातु सतहों से सबसे कम पकड़ (traction) मिलने और लगभग बर्फ की तरह व्यवहार करने की उम्मीद करनी चाहिए?","options":["हल्की बारिश अभी-अभी शुरू हुई है और स्टील की प्लेटें तथा पुल की जाली गीली हैं","तेज़ दोपहर की धूप में सड़क और धातु की सतहें पूरी तरह सूखी हैं","स्टील की प्लेटें कल ही बिछाई गई थीं और अभी भी बिल्कुल नई दिखती हैं","एक मरम्मत दल ने अभी-अभी प्लेटों से ढीली बजरी और धूल झाड़कर साफ़ की है"],"explanation":"स्टील की प्लेटें और धातु के पुल की सतह कम पकड़ देती हैं और गीली होने पर बर्फ जितनी फिसलन भरी हो जाती हैं।"},"496":{"q":"आप एक विभाजित राजमार्ग से निकलकर दोपहर में शहर के व्यस्त वाणिज्यिक मार्ग पर मुड़ते हैं। यातायात घना है, दोनों किनारों पर वाहन खड़े हैं, डिलीवरी वैन दोहरी पंक्ति में खड़ी हैं, और आप एक बस स्टॉप तथा कई दुकानों के पास से गुजरते हैं। जिस खुले राजमार्ग को आपने अभी छोड़ा, उसकी तुलना में अब आपको किस खतरे पर सबसे अधिक ध्यान देना चाहिए?","options":["लंबे, खाली सीधे रास्ते जहाँ आप सुरक्षित रूप से अपनी अनुगमन दूरी बढ़ा सकते हैं","पैदल यात्री जो खड़े वाहनों, बसों या दुकानों के बीच से अचानक निकल सकते हैं","सड़क किनारे खुले मैदान जो फिसलन से उबरने के लिए अतिरिक्त जगह देते हैं","इस क्षेत्र से दूर ग्रामीण किनारों पर पाई जाने वाली ढीली बजरी और मलबा"],"explanation":"शहर में उन पैदल यात्रियों पर बारीकी से नजर रखें जो खड़ी कारों, बसों या दुकानों के बीच से अचानक निकल सकते हैं।"},"497":{"q":"अभी सुबह का अंतिम पहर है और आप खेती वाले इलाके से गुज़रते एक संकरे दो-लेन ग्रामीण राजमार्ग पर एक भरे हुए संयोजन वाहन को चला रहे हैं। निर्धारित गति 55 मील प्रति घंटा है, लेकिन एक छोटी चढ़ाई पार करते ही आपका दृश्य लगभग एक चौथाई मील आगे तक खुल जाता है। निम्नलिखित खतरों में से किससे आपका सामना होने की सबसे अधिक संभावना है, जो निर्धारित गति से बहुत धीमा चल रहा हो और आपको अपनी अनुसरण दूरी समायोजित करने तथा संभवतः ओवरटेक करने के लिए लेन बदलने पर मजबूर कर दे?","options":["चिह्नित यात्री शेड पर रुकती हुई एक शहरी परिवहन बस","फ्रीवे के ऑन-रैंप से मिलती हुई हल्की यात्री कारें","धीमी गति से चलने वाले कृषि उपकरण जैसे ट्रैक्टर या कंबाइन","सड़क के समानांतर चलती हुई एक उपनगरीय मेट्रो ट्रेन"],"explanation":"ग्रामीण दो-लेन राजमार्गों पर ट्रैक्टर और कंबाइन जैसी धीमी कृषि मशीनरी पर नजर रखें जो निर्धारित गति से काफी कम चलती है।"},"498":{"q":"आप अपने लदे हुए संयुक्त वाहन (कॉम्बिनेशन व्हीकल) में चौराहे के सबसे आगे रुके हुए हैं, सामने से आ रहे ट्रैफ़िक की दो लेन को पार करके बाएँ मुड़ने का इंतज़ार कर रहे हैं। जो ठोस लाल तीर आपको रोके हुए था, वह लगातार झपकते (फ़्लैशिंग) पीले बाएँ-मोड़ तीर में बदल जाता है। सामने से आने वाले वाहन अब भी तेज़ गति से चौराहे की ओर बढ़ रहे हैं। आपके आकार और लंबाई के वाहन के चालक के लिए कौन-सी प्रतिक्रिया कानूनी रूप से सही और सबसे सुरक्षित है?","options":["तुरंत मुड़ना शुरू कर दें, क्योंकि झपकता पीला तीर बिल्कुल हरे तीर की तरह काम करता है और आपको रास्ते के अधिकार वाला सुरक्षित (प्रोटेक्टेड) मोड़ देता है","पूरी तरह रुके रहें और झपकते पीले तीर को ठोस लाल तीर की तरह मानें, चलने से पहले ठोस हरे तीर का इंतज़ार करें","मोड़ में आगे बढ़ें लेकिन चौराहे के बीच में रुककर तब तक खड़े रहने की योजना बनाएँ जब तक सामने के ट्रैफ़िक में जगह न बन जाए","आप मुड़ना शुरू कर सकते हैं, लेकिन आपको सामने से आने वाले ट्रैफ़िक को रास्ता देना होगा और मोड़ तभी पूरा करें जब इतनी बड़ी जगह हो कि आपके वाहन की पूरी लंबाई सुरक्षित रूप से चौराहा पार कर सके"],"explanation":"चमकता पीला तीर मुड़ने की अनुमति देता है पर रास्ते का अधिकार नहीं देता, इसलिए आती हुई यातायात को रास्ता दें और तभी मुड़ें जब सुरक्षित रूप से निकलने योग्य पर्याप्त जगह हो।"},"499":{"q":"एक फिटिंग के खराब हो जाने के बाद आपको शोल्डर पर रुकना पड़ता है और आपके ट्रेलर के पिछले हिस्से के आसपास सड़क पर डीज़ल जमा होने लगता है। फिर भी आपको आ रहे ट्रैफ़िक के लिए अपने रुके हुए वाहन को चिह्नित करना है। ज़मीन पर पड़े ईंधन को ध्यान में रखते हुए, बाहर रखने के लिए सबसे सुरक्षित चेतावनी उपकरण कौन सा है?","options":["एक परावर्तक त्रिकोण, क्योंकि यह बिना किसी लौ या गर्मी के ट्रैफ़िक को चेतावनी देता है, जो गिरे हुए ईंधन को नहीं जला सकता","एक जलती हुई फ्लेयर, क्योंकि फ्लेयर सबसे अधिक दिखने वाला मानक चेतावनी उपकरण है और आपके ट्रक में अनिवार्य उपकरण है","एक जलती हुई सिग्नल फ्लेयर जो रिसाव से हवा की ओर वाली दिशा में रखी गई हो ताकि लौ डीज़ल के वाष्प से दूर रहे","सड़क पर रखी एक छोटी जलती हुई मोमबत्ती, क्योंकि इसकी लौ इतनी नीची है कि ईंधन तक नहीं पहुँच सकती"],"explanation":"परावर्तक त्रिकोण कोई लौ, चिंगारी या गर्मी पैदा नहीं करता, इसलिए यह गिरे हुए ईंधन में आग लगने का खतरा पैदा किए बिना यातायात को सुरक्षित रूप से चेतावनी देता है।"},"500":{"q":"ट्रिप-पूर्व जांच में आप पाते हैं कि आगे के स्टीयरिंग टायर असमान रूप से घिसे हैं। सबसे कम जगह पर ट्रेड लगभग 3/32 इंच है। सही निर्णय क्या है?","options":["न चलाएँ — स्टीयरिंग-एक्सल टायरों में कम से कम 4/32 इंच ट्रेड होना चाहिए","चलाएँ — 3/32 इंच, टायरों के 2/32 इंच न्यूनतम से ऊपर है","चलाएँ — असमान घिसाव केवल ड्राइव और ट्रेलर टायरों में मायने रखता है","न चलाएँ — 6/32 इंच से कम कोई भी टायर वाणिज्यिक वाहन पर अवैध है"],"explanation":"स्टीयरिंग-एक्सल के टायरों में कम से कम 4/32 इंच ट्रेड होना चाहिए — जो बाकी सभी टायरों के लिए आवश्यक 2/32 इंच से ऊँचा मानक है।"},"501":{"q":"आपने पूरी ट्रिप-पूर्व जांच की, माल बांधा, और हाईवे पर 45 मील चला लिए — सब ठीक लग रहा है। माल-निरीक्षण नियमों के तहत आपको क्या करना है?","options":["अभी कुछ नहीं — माल की पहली दोबारा जांच 150 मील या 3 घंटे पर होती है","कुछ नहीं — एक बार बांधने और जांचने के बाद ईंधन भरने तक जांच नहीं चाहिए","अगले कुछ मील में रुकें — पहली जांच पहले 50 मील के भीतर ज़रूरी है","अभी रुकें — माल की हर 25 मील पर दोबारा जांच होनी चाहिए"],"explanation":"माल और बांधने वाले उपकरणों की पहली पुनः-जाँच पहले 50 मील के भीतर ज़रूरी है, क्योंकि शुरुआती मीलों में बंधन ढीले होते हैं और भार सबसे अधिक खिसकता है।"},"502":{"q":"स्टीयरिंग जांचते समय आप पाते हैं कि आगे के टायर मुड़ने से पहले स्टीयरिंग 10 डिग्री से अधिक (20-इंच पहिये के किनारे पर लगभग दो इंच ढीलापन) घूम जाता है। इसका क्या मतलब है?","options":["हर भारी ट्रक में रहने वाला सामान्य ढीलापन — कुछ करने की ज़रूरत नहीं","स्टीयरिंग में अत्यधिक ढीलापन — मरम्मत होने तक वाहन चलाना असुरक्षित है","पावर स्टीयरिंग बस गर्म हो रहा है; चलाने पर कस जाएगा","एक छोटी बात — ट्रिप के बाद रिपोर्ट में लिख दें और चलाते रहें"],"explanation":"स्टीयरिंग में लगभग 10 डिग्री से अधिक खाली घुमाव वाहन को नियंत्रित करना कठिन बना देता है और मरम्मत होने तक चलाना असुरक्षित होता है।"},"503":{"q":"शिफ्ट के अंत में आपको ब्रेक-एडजस्टमेंट की समस्या मिलती है। ड्राइवर वाहन निरीक्षण रिपोर्ट (DVIR) के बारे में कौन-सा कथन सही है?","options":["DVIR केवल ट्रिप से पहले चाहिए, बाद में कभी नहीं","अगर उसी सुबह ट्रिप-पूर्व जांच की थी तो पोस्ट-ट्रिप रिपोर्ट वैकल्पिक है","दोष केवल मौखिक रूप से बता सकते हैं; लिखित रिकॉर्ड की ज़रूरत नहीं","दोष को लिखित पोस्ट-ट्रिप रिपोर्ट में दर्ज करें ताकि वाहन दोबारा इस्तेमाल से पहले ठीक हो"],"explanation":"यात्रा के दौरान मिली खराबियाँ लिखित पोस्ट-ट्रिप निरीक्षण रिपोर्ट में दर्ज करनी चाहिए ताकि वाहन के दोबारा उपयोग से पहले उन्हें ठीक किया जा सके।"},"504":{"q":"तापमान बस जमाव बिंदु से नीचे है। सड़क गीली और चमकदार दिखती है, फिर भी आप देखते हैं कि आगे के वाहनों से जो टायर-छींटे आम तौर पर दिखते हैं, वे बंद हो गए हैं। सबसे सुरक्षित व्याख्या और कार्रवाई क्या है?","options":["संभवतः ब्लैक आइस बन रही है — गति घटाएँ और अचानक स्टीयरिंग या ब्रेकिंग से बचें","सड़क बस पहले की बारिश से गीली है — अपनी गति बनाए रखें","आपके अपने टायर हवा खो रहे हैं — किनारे लगाकर दबाव जांचें","यह केवल विंडशील्ड पर पाला है — डिफ़्रॉस्टर चालू करें और चलते रहें"],"explanation":"जमाव के पास के तापमान पर गीली, चमकीली सड़क जहाँ टायरों से छींटे न उड़ें, ब्लैक आइस का संकेत है, इसलिए गति कम करें और अचानक स्टीयरिंग या ब्रेकिंग से बचें।"},"505":{"q":"आपका वाहन हाईवे के जलमग्न हिस्से पर हाइड्रोप्लेन करने लगता है। आपको निम्न सभी करने चाहिए, सिवाय:","options":["पहियों को धीमा होने देने के लिए एक्सेलेरेटर छोड़ दें","क्लच दबाएँ ताकि पहिये स्वतंत्र रूप से घूमें","टायरों को वापस सड़क पर लाने के लिए ज़ोर से ब्रेक लगाएँ","जब तक पकड़ वापस न आए, स्टीयरिंग सीधा रखें"],"explanation":"हाइड्रोप्लेनिंग के दौरान कभी जोर से ब्रेक न लगाएँ, क्योंकि इससे टायर लॉक होकर फिसलन बढ़ जाती है; इसके बजाय एक्सेलरेटर छोड़ें और पकड़ लौटने तक स्टीयरिंग सीधा रखें।"},"506":{"q":"आप सूखी सड़क पर अच्छी परिस्थितियों में 60-फुट का कॉम्बिनेशन 60 मील/घंटा पर चला रहे हैं। टेक्सास की फॉलोइंग-डिस्टेंस नियम के अनुसार न्यूनतम अंतराल लगभग कितना होना चाहिए?","options":["लगभग 6 सेकंड","लगभग 7 सेकंड","लगभग 4 सेकंड","लगभग 10 सेकंड"],"explanation":"40 मील/घंटे से कम पर हर 10 फुट लंबाई के लिए एक सेकंड और 40 मील/घंटे से ऊपर एक अतिरिक्त सेकंड जोड़ें, इसलिए 60 फुट के वाहन को लगभग 7 सेकंड की अनुसरण दूरी चाहिए।"},"507":{"q":"कई सूखे हफ़्तों के बाद तेज़ बारिश शुरू होती है। बारिश का पहला हिस्सा विशेष रूप से खतरनाक क्यों है, और आपको क्या करना चाहिए?","options":["बारिश इंजन को ठंडा करती है, इसलिए आप थोड़ा तेज़ चल सकते हैं","एकमात्र असली खतरा विंडशील्ड है — वाइपर चलाएँ और गति बनाए रखें","ताज़ा बारिश तुरंत पकड़ सुधारती है; केवल गहरा खड़ा पानी चिंता है","सड़क पर तेल और धूल धुलने से पहले एक फिसलनदार परत बन जाते हैं — गति घटाएँ और दूरी बढ़ाएँ"],"explanation":"जब बारिश शुरू होती है, तेल और धूल ऊपर उठकर फिसलन भरी परत बना देते हैं जिससे सड़क सबसे अधिक फिसलनभरी हो जाती है, इसलिए गति कम करें और अनुसरण दूरी बढ़ाएँ।"},"508":{"q":"रात में बिना रोशनी वाले हाईवे पर लो-बीम के साथ चलते हुए आप समझते हैं कि हेडलाइट जितनी दूरी दिखाती है, उसमें आप रुक नहीं सकते। सही प्रतिक्रिया है:","options":["गति इतनी घटाएँ कि जितना दिखता है उतनी दूरी में रुक सकें","हाई-बीम पर जाएँ और समय पर पहुँचने के लिए गति बनाए रखें","किसी दूसरे ट्रक के पीछे करीब आकर उसकी रोशनी से चलें","गति बनाए रखें पर दाएँ किनारे की रेखा को अधिक ध्यान से देखें"],"explanation":"अपनी हेडलाइट की पहुँच से तेज़ कभी न चलें — गति ऐसी हो कि आप दिखने वाली दूरी के भीतर रुक सकें, यानी लो बीम पर गति कम करना।"},"509":{"q":"आप घने कोहरे के क्षेत्र में घुसने वाले हैं। निम्न में से कौन-सा अभ्यास अनुशंसित नहीं है?","options":["कोहरे तक पहुँचने से पहले ही गति घटाना","हाई-बीम के बजाय लो-बीम का उपयोग करना","विंडशील्ड साफ़ रखने के लिए वाइपर और डिफ़्रॉस्टर चलाना","हाई-बीम जलाना ताकि तेज़ रोशनी कोहरे को चीर सके"],"explanation":"कोहरे में लो बीम का उपयोग करें, क्योंकि हाई बीम पानी की बूँदों से परावर्तित होकर चकाचौंध वापस आपकी ओर भेजती है और दृश्यता घटा देती है।"},"510":{"q":"तापमान बिलकुल जमाव बिंदु पर है और सड़कें ज़्यादातर साफ़ दिखती हैं। बाकी सड़क ठीक लगने पर भी किस सतह को पहले बर्फीली मानें?","options":["पूरी धूप में पड़े सीधे, खुले हिस्से","चढ़ाई वाले हिस्से, क्योंकि इंजन सतह को गर्म करता है","सुरंगें, जो गर्म हवा रोकती हैं और सबसे देर तक फिसलन भरी रहती हैं","पुल और ओवरपास, जो आसपास की सड़क से पहले जमते हैं"],"explanation":"पुल और ओवरपास ऊपर और नीचे दोनों से गर्मी खोते हैं, इसलिए बाकी सड़क साफ होने पर भी वे ठोस ज़मीन की सड़क से पहले बर्फ़ से जम जाते हैं।"},"511":{"q":"बहुत गर्म दिन पर आप रुकते हैं और पाते हैं कि टायर काफ़ी गर्म हैं और दबाव सामान्य ठंडे दबाव से अधिक है। सही कार्रवाई क्या है?","options":["हवा निकालें जब तक दबाव सामान्य ठंडे मान पर न आ जाए","तेज़ चलाएँ ताकि हवा का बहाव टायरों को ठंडा करे","जल्दी ठंडा करने के लिए टायरों पर पानी डालें","टायरों को न छेड़ें; अगर कोई छूने में बहुत गर्म है तो ठंडा होने तक चलाना बंद करें"],"explanation":"गर्मी से आम तौर पर टायर का दबाव बढ़ता है, इसलिए टायरों को न छेड़ें; पर छूने में बहुत गर्म टायर समस्या का संकेत है, इसलिए ब्लोआउट से बचने के लिए ठंडा होने तक गाड़ी रोक दें।"},"512":{"q":"आप मैनुअल ट्रांसमिशन और भारी लोड के साथ रेलवे ट्रैक पार कर रहे हैं। क्रॉसिंग पर गियर चुनने का सबसे ज़रूरी नियम है:","options":["ट्रैक से पहले गियर चुनें और जब तक वाहन का कोई भी हिस्सा क्रॉसिंग पर है, गियर न बदलें","पर्याप्त इंजन शक्ति के लिए लगभग आधे रास्ते पर गियर नीचे करें","कंपन घटाने के लिए न्यूट्रल में डालकर पार करें","ट्रैक जल्द से जल्द पार करने के लिए सबसे ऊँचा गियर इस्तेमाल करें"],"explanation":"पटरियों तक पहुँचने से पहले ऐसा गियर चुनें जो आपको पूरे पार ले जाए और जब तक वाहन का कोई हिस्सा क्रॉसिंग पर हो तब तक गियर न बदलें, ताकि आप पटरियों पर रुक न जाएँ।"},"513":{"q":"आप एक लंबी, तीखी ढलान के पास पहुँच रहे हैं। गियर कब और कैसे चुनें?","options":["ब्रेक फेल होने लगें तब तक रुकें, फिर नीचे गियर में जाएँ","ईंधन बचाने के लिए न्यूट्रल में डालें और गति केवल ब्रेक से नियंत्रित करें","ऊँचे गियर में रहें और पूरे रास्ते हल्का-हल्का ब्रेक लगाते रहें","उतरने से पहले ही नीचा गियर चुनें — आमतौर पर उसी पहाड़ी पर चढ़ने वाले गियर से भी नीचा"],"explanation":"उतराई से पहले लो गियर चुनें ताकि इंजन और कम्प्रेशन ब्रेकिंग आपकी गति को थामे रखे; आधुनिक ट्रकों में सुरक्षित उतराई गियर अक्सर चढ़ाई के गियर से कम होता है।"},"514":{"q":"एक लंबी ढलान पर आप पहले से सही नीचे गियर में हैं और सुरक्षित गति 35 मील/घंटा है। कौन-सी ब्रेकिंग तकनीक गति को सही ढंग से नियंत्रित करती है?","options":["पूरी ढलान भर हल्का, स्थिर ब्रेक दबाव लगातार लगाएँ","ब्रेक को ठंडा रखने के लिए तेज़ी और लगातार पंप करें","नीचे तक पूरे रास्ते ब्रेक ज़ोर से दबाए रखें","लगभग 40 मील/घंटा पर ज़ोर से ब्रेक लगाकर ~30 तक लाएँ, छोड़ें, और दोहराएँ"],"explanation":"सही स्नब ब्रेकिंग का मतलब है गति को सुरक्षित गति से लगभग 5 mph ऊपर जाने देना, फिर मज़बूती से लगभग 5 mph नीचे तक ब्रेक लगाना, छोड़ना और दोहराना ताकि ब्रेक ठंडे हों।"},"515":{"q":"पहाड़ी ढलान पर आपके ब्रेक बुरी तरह फेल हो गए हैं और गति बढ़ रही है। आपको निम्न सभी करने चाहिए, सिवाय:","options":["उपलब्ध हो तो एस्केप रैंप ढूँढें और उसका उपयोग करें","न्यूट्रल में डालें ताकि ट्रक अधिक सहजता से लुढ़क सके","रैंप न हो तो खुला खेत या साइड रोड जैसा बचाव मार्ग ढूँढें","सबसे नीचे गियर में रहें और बचे हुए किसी भी ब्रेक से जितना हो सके धीमा करें"],"explanation":"ढलान पर कभी न्यूट्रल में न डालें क्योंकि इससे इंजन ब्रेकिंग खत्म हो जाती है और गति बढ़ने लगती है; इसके बजाय वाहन को लो गियर में रखें।"},"516":{"q":"फिसलन भरी सड़क पर आपके ड्राइव पहिये स्किड करने लगते हैं और ट्रैक्टर का पिछला हिस्सा दाईं ओर खिसकने लगता है। नियंत्रण वापस पाने के लिए पहले आपको:","options":["एक्सेलेरेट करना बंद करें (और क्लच दबाएँ), फिर वाहन के अगले हिस्से को जिधर ले जाना है उधर स्टीयर करें","स्किड तुरंत रोकने के लिए ज़ोर से ब्रेक लगाएँ","स्किड की विपरीत दिशा में तेज़ी से बाईं ओर मोड़ें","ट्रेलर को सीध में लाने के लिए एक्सेलेरेट करें"],"explanation":"ड्राइव-व्हील स्किड में पहले कारण हटाएँ—एक्सेलरेटर छोड़ें और क्लच दबाएँ ताकि पहिए फिर से पकड़ पाएँ, फिर जहाँ वाहन का अगला हिस्सा जाए वहाँ स्टीयर करें।"},"517":{"q":"एक तीखे मोड़ पर आपके अगले पहिये पकड़ खो देते हैं और पहिये मुड़े होने के बावजूद ट्रक सीधा चलता रहता है। सामान्य कारण और सही प्रतिक्रिया है:","options":["कारण: बहुत कम गति — स्टीयरिंग वापस पाने के लिए एक्सेलेरेट करें","कारण: पिछले टायर अधिक फूले हुए — किनारे लगाकर कुछ हवा निकालें","कारण: परिस्थितियों के लिए बहुत तेज़ गति — गति छोड़ें, धीमे होते ही अगले पहिये फिर पकड़ लेंगे","कारण: ट्रेलर धकेल रहा है — ट्रेलर हैंड वाल्व ज़ोर से लगाएँ"],"explanation":"फ्रंट-व्हील स्किड आम तौर पर हालात के लिए बहुत तेज़ चलाने से होता है, और चूँकि स्टीयरिंग काम नहीं करती, गति धीमी करने के लिए गैस छोड़ें ताकि अगले टायर फिर से पकड़ें।"},"518":{"q":"आपकी लेन में एक कार अचानक रुक जाती है और समय रहते रुकने की जगह नहीं है। ज़्यादातर मामलों में सुरक्षित आपातकालीन कार्रवाई है:","options":["जितना हो सके ज़ोर से ब्रेक लगाएँ और बस उससे पहले रुकने की उम्मीद करें","बाधा के चारों ओर से मोड़ें — आमतौर पर रुकने की तुलना में कम दूरी में मोड़कर बच सकते हैं","ब्रेक लॉक करें और स्टीयरिंग को सख्ती से सीधा पकड़े रखें","अधिकतम प्रभाव के लिए एक साथ ज़ोर से ब्रेक और स्टीयर करें"],"explanation":"हाईवे की गति पर आप आम तौर पर रुकने में लगने वाली दूरी से कम में दिशा बदल सकते हैं, इसलिए खतरे के इर्द-गिर्द स्टीयर करके फिर वापस मोड़ना अक्सर टक्कर टाल देता है जब रुकना नहीं टाल सकता।"},"519":{"q":"हाईवे की गति पर आप एक ज़ोरदार धमाका सुनते हैं, स्टीयरिंग अचानक एक ओर ज़ोर से खिंचता है और वाहन उछलता है — आगे के टायर फटने के संकेत। आपकी तत्काल प्रतिक्रिया होनी चाहिए:","options":["नियंत्रण खोने से पहले धीमा होने के लिए तुरंत ज़ोर से ब्रेक लगाएँ","स्थिरता पाने के लिए थोड़ा एक्सेलेरेट करें, फिर ब्रेक लगाएँ","ज़ोर से ब्रेक लगाते हुए तेज़ी से शोल्डर पर मोड़ें","स्टीयरिंग को मज़बूती से पकड़ें, ब्रेक से दूर रहें, वाहन को धीमा होने दें, फिर किनारे लगाएँ"],"explanation":"टायर फटने के बाद स्टीयरिंग व्हील को मज़बूती से पकड़ें और ब्रेक से दूर रहें, वाहन को अपने आप धीमा होने दें, फिर हल्के से ब्रेक लगाकर किनारे पर ले जाएँ।"},"520":{"q":"आप 9 फुट का एक स्टील पाइप ले जा रहे हैं। माल-सुरक्षा नियमों के अनुसार न्यूनतम कितने टाई-डाउन ज़रूरी हैं?","options":["दो — माल कितना भी छोटा हो, कम से कम दो टाई-डाउन ज़रूरी हैं","एक — यह 10 फुट से कम है, तो प्रति-10-फुट नियम के लिए एक टाई-डाउन काफी है","कोई नहीं — 10 फुट से छोटा माल टाई-डाउन नियमों से छूट है","चार — माल के हर कोने के लिए एक टाई-डाउन"],"explanation":"माल कितना भी छोटा क्यों न हो, हर वस्तु के लिए हमेशा कम से कम दो टाई-डाउन जरूरी होते हैं, साथ ही हर 10 फीट लंबाई के लिए एक टाई-डाउन।"},"521":{"q":"आपका माल 40,000 पाउंड का है। आप जितने टाई-डाउन इस्तेमाल करते हैं उनकी संयुक्त वर्किंग लोड लिमिट (WLL) कम से कम कितनी होनी चाहिए?","options":["10,000 पाउंड","20,000 पाउंड","40,000 पाउंड","80,000 पाउंड"],"explanation":"आपके टाई-डाउन की संयुक्त कार्य भार सीमा सुरक्षित किए जा रहे माल के वजन की कम से कम आधी होनी चाहिए।"},"522":{"q":"आप भारी माल को या तो नीचे और ट्रेलर के फर्श पर फैलाकर, या ऊँचा और बीच में स्टैक करके रख सकते हैं। क्या सही है और क्यों?","options":["ऊँचा और बीच में स्टैक करें ताकि वज़न एक्सल के किनारों से दूर रहे","ऊँचा स्टैक करें ताकि मोड़ों में माल कम खिसके","जब तक कुल वज़न कानूनी सीमा में है, कोई फ़र्क नहीं पड़ता","नीचे और फैलाकर लादें ताकि गुरुत्व केंद्र नीचा रहे और पलटने का जोखिम घटे"],"explanation":"माल को नीचे और समान रूप से फैलाकर रखने से गुरुत्व केंद्र नीचा रहता है, जो पलटने से बचने और स्थिर रहने का सबसे बड़ा कारक है।"},"523":{"q":"वज़न का खराब वितरण दोनों चरम पर समस्या पैदा करता है। वज़न और वाहन-नियंत्रण के बारे में कौन-सा कथन सही है?","options":["ड्राइव एक्सल को अधिक लादना हमेशा बिना किसी नुकसान के पकड़ बढ़ाता है","वज़न वितरण केवल ईंधन खपत को प्रभावित करता है, चालन को नहीं","स्टीयरिंग एक्सल पर बहुत कम वज़न से अगले टायरों की पकड़ और स्टीयरिंग नियंत्रण कमज़ोर हो सकता है","अधिक एक्सल भार हमेशा आपकी रुकने की दूरी घटाता है"],"explanation":"स्टीयरिंग एक्सल पर बहुत कम वजन आगे के टायरों की पकड़ घटाता है और स्टीयरिंग नियंत्रण कमजोर करता है, इसलिए सही संतुलन कुल वजन जितना ही जरूरी है।"}}};
  Object.keys(REPL).forEach(function(i){ cat.questions[+i]=REPL[i]; });
  APPEND.forEach(function(a){ cat.questions[a.idx]=a.obj; });
  ["ru","tr","es","hi"].forEach(function(L){ var m=TR[L]||{}; Object.keys(m).forEach(function(i){ I.q[L][SUBJ][+i]=m[i]; }); });
})();
